window.MOCK={"blueprint":{"Physical Health":{"pct":29,"subs":{"Infectious Disease":12,"Sanitation & Biosecurity":12,"Surgery & Anesthesia":12,"Vaccination":12,"Facility/Environment":11,"Euthanasia":11,"Medical (Non-Infectious)":10,"Nutrition & Husbandry":10,"Parasites":10}},"Shelter Management":{"pct":18,"subs":{"Population Management":14,"Animal ID & Stats":12,"Management & Leadership":12,"Record Keeping":12,"Data & Analysis":11,"Regulatory":11,"Mental Health & Self-Care":11,"Resource Allocation":9,"Liability":8}},"Behavioral Health":{"pct":16,"subs":{"QOL & Needs Assessment":14,"Animal Handling":13,"Assessment & Decision":13,"Body Language":13,"Common Behavior Problems":13,"Stress":13,"Facility/Environment":12,"Learning Theory":9}},"Companion Animal Homelessness":{"pct":12,"subs":{"Spay-Neuter":16,"Shelter Diversion":14,"Adoption & Placement":13,"Epidemiology of Homelessness":13,"Transfer Programs":13,"Disaster":12,"Reunification":12,"Non-Surgical Sterilization":7}},"Community & Public Health":{"pct":11,"subs":{"Animal Cruelty":21,"Zoonotic Disease":21,"Animals & Public Safety":20,"Rabies":20,"Reportable & Emerging":18}},"Animals & Public Policy":{"pct":7,"subs":{"Ethics":28,"Regulatory":27,"Legislation":25,"Animal Shelter History":20}},"Research & Biostats":{"pct":6,"subs":{"Epidemiology & Biostats":54,"Study Design":46}}},"mcqs":[{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CPV-2 is best classified as a:","o":["Enveloped double-stranded RNA virus","Non-enveloped single-stranded DNA protoparvovirus","Enveloped single-stranded RNA coronavirus","Non-enveloped double-stranded DNA herpesvirus"],"a":1,"e":"Non-enveloped ssDNA virus, genus Protoparvovirus. The missing envelope is why it is environmentally hardy and resists many disinfectants."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which CPV variant can produce severe panleukopenia-like leukopenia and diarrhoea in cats?","o":["CPV-1 (minute virus of canines)","Original CPV-2","CPV-2c","None infect cats"],"a":2,"e":"CPV-2a, 2b and 2c can infect cats; 2a/2b are usually mild, but CPV-2c can cause severe FPV-like disease. Original CPV-2 did not infect cats."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CPV causes its intestinal lesions primarily by destroying:","o":["Villous tip enterocytes only","The crypt germinal epithelium, preventing villous renewal","Submucosal ganglia","Brush-border disaccharidases directly"],"a":1,"e":"Crypt germinal epithelium destruction halts villous renewal, causing villous atrophy, malabsorption and barrier loss with bacterial translocation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The incubation period of CPV is approximately:","o":["1 to 2 days","4 to 14 days","3 to 4 weeks","6 to 8 weeks"],"a":1,"e":"Incubation is 4 to 14 days; shedding begins around day 4 to 5 (lit review: 4 to 7) and can precede clinical signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is the subclinical form of CPV especially dangerous in a shelter?","o":["It is resistant to all disinfectants","Affected animals appear healthy but still shed virus","It only affects vaccinated dogs","It cannot be detected by any test"],"a":1,"e":"Subclinical pups (maternal antibody) or low-titre adults shed virus while looking well, driving silent transmission."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The myocardial form of CPV is now rare mainly because:","o":["The variant that causes it went extinct","Breeding bitches are vaccinated, protecting neonates","Antibiotics prevent it","It only ever occurred in cats"],"a":1,"e":"Myocardial disease follows in-utero or very early infection; maternal vaccination and maternal antibody have made it rare."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A 4-month unvaccinated pup has haemorrhagic diarrhoea and a negative faecal ELISA (SNAP). Best next step?","o":["Rule out CPV; the test is 100% accurate","Keep in general housing; false negatives are rare","Isolate and pursue qPCR; POCT sensitivity can be ~23 to 34%","Repeat the ELISA on a blood sample"],"a":2,"e":"POCT specificity is high but sensitivity is low (false negatives common from low viral load or antibody binding). Isolate and confirm with qPCR."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Reported performance of the IDEXX SNAP faecal antigen test includes:","o":["Sensitivity 100%, specificity 50%","Specificity ~100%, false-negative rate up to ~51%","Specificity 60%, sensitivity 99%","No published performance data"],"a":1,"e":"Specificity ~100% but false negatives up to 51.3%; sensitivity rises to 77 to 80% only at very high faecal viral loads."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The reference (gold standard) diagnostic test for CPV is:","o":["Faecal ELISA antigen","qPCR","Haemagglutination","Faecal flotation"],"a":1,"e":"qPCR has ~94% sensitivity and ~100% specificity. Caveat: recent MLV vaccination can yield a positive result."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A healthy dog vaccinated with MLV core on intake tests qPCR-positive on day 10. This most likely reflects:","o":["Active clinical parvovirus","Vaccine-derived virus shedding (up to ~28 days)","Laboratory contamination only","Immediate vaccine failure"],"a":1,"e":"Up to ~23% of recently MLV-vaccinated dogs are qPCR-positive between days 3 and 28, so interpret intake-vaccinated dogs cautiously."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which trend within the first 24 hours of admission has a 100% positive predictive value for survival?","o":["Rising serum cortisol","A measurable rise in absolute lymphocyte count","Stable hypermagnesaemia","Falling haematocrit"],"a":1,"e":"An early lymphocyte rebound carries a 100% positive predictive value for survival in the cited data."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which is a recognised POOR prognostic indicator in CPV?","o":["Lymphocyte count rising at 24h","Marked leukopenia under 4.05 x 10^3/uL","Normal albumin","Normal cortisol at 72h"],"a":1,"e":"Poor prognosis: marked persistent leukopenia, severe hypoalbuminaemia, high CK-MB, persistently elevated 72h cortisol, low HCT, hypoglycaemia, hypermagnesaemia."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A colleague proposes single-agent cefovecin for all CPV sepsis. The key counter-evidence is:","o":["Cefovecin has no Gram-positive activity","Up to 72% of Gram-negative isolates resisted 3rd/4th-gen cephalosporins and metronidazole","Cefovecin causes bone-marrow hypoplasia","Cefovecin is inactivated by hydrogen peroxide"],"a":1,"e":"High Gram-negative resistance to 3rd/4th-gen cephalosporins and metronidazole argues for an ampicillin-plus-aminoglycoside backbone once rehydrated."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which antibiotic pairing is favoured for CPV sepsis after rehydration?","o":["Metronidazole alone","Ampicillin plus amikacin (after rehydration)","Cefovecin plus metronidazole","Doxycycline alone"],"a":1,"e":"Ampicillin plus an aminoglycoside gives broad cover; give the aminoglycoside only after rehydration to limit nephrotoxicity."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Maropitant should be used cautiously in which group?","o":["Geriatric dogs","Puppies under 8 weeks (bone-marrow hypoplasia risk)","Vaccinated adults","Pregnant queens"],"a":1,"e":"Maropitant carries a bone-marrow hypoplasia caution in puppies under 8 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Best-supported statement about nutrition in CPV?","o":["Withhold all food until vomiting stops 48h","Early enteral nutrition before vomiting resolves improves outcomes","Only total parenteral nutrition works","Feeding worsens diarrhoea and should be delayed a week"],"a":1,"e":"Early enteral feeding (start ~25% RER, build to 100% by day 2 to 4) shortens recovery; NG/NE tubes can stay up to 7 days."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Canine parvovirus monoclonal antibody (CPMA, 2024) is best described as:","o":["An oral antiviral given for 10 days","A single IV dose raising titres within 24h, with 0% mortality in studies","A vaccine adjuvant","A disinfectant"],"a":1,"e":"A single IV dose rapidly raises antibody titres and showed 0% mortality with faster clinical resolution in reported studies."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which adjunctive therapy has randomised evidence of NO significant survival benefit?","o":["Early enteral nutrition","Immune / hyperimmune plasma","Balanced crystalloid fluids","Antiemetics"],"a":1,"e":"Randomised data show immune plasma gives no significant survival or clinical benefit; hyperimmune plasma lowered 24h shock index and lactate but did not change survival."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For hypovolaemic shock in a CPV pup, the crystalloid bolus approach is:","o":["1 mL/kg over an hour","15 to 20 mL/kg over ~15 min, repeated to ~80 to 90 mL/kg total","100 mL/kg as one push","Subcutaneous fluids only"],"a":1,"e":"Give 15 to 20 mL/kg boluses over ~15 min, repeated to a total of about 80 to 90 mL/kg, until perfusion is restored."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A CPV pup is under 10% dehydrated, BCS 4/9 and responsive. The hybrid model means:","o":["Outpatient subcutaneous care only from the start","IV fluids for the first 24h, then step down to SQ/oral care","Immediate euthanasia","Inpatient IV care for a full week"],"a":1,"e":"Hybrid: IV fluids first 24h to correct dehydration, hypokalaemia and hypoglycaemia, then SQ and oral care in shelter or foster. Outpatient survival ~80 to 83%."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A resource-limited shelter weighs euthanasia. Which finding meets the cited welfare threshold?","o":["BCS 5/9 and alert","Mild single episode of vomiting","BCS under 3/9, recumbent and non-responsive","A positive SNAP test alone"],"a":2,"e":"Cited thresholds for considering euthanasia: BCS under 3/9, recumbency, or non-responsiveness, plus inability to isolate or treat safely."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"During an outbreak, pups under 5 months in the exposed group should be:","o":["Placed for adoption immediately","Given an MLV DAPP booster and quarantined 14 days","Euthanised","Titre-tested and released if positive"],"a":1,"e":"Pups under 5 months are high risk regardless of history: booster MLV DAPP and quarantine 14 days, testing any that develop signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An exposed dog over 5 months with no vaccination history is moderate risk. The key triage tool is:","o":["Immediate adoption","Antibody titre testing","A second ELISA","Depopulation"],"a":1,"e":"Titre-test moderate-risk dogs; an adequate titre lets you reclassify them as low risk and place them."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Regarding foot baths for CPV control:","o":["They are the most effective single measure","They are not an effective strategy","They replace hand hygiene","They sterilise footwear in 30 seconds"],"a":1,"e":"Foot baths are unreliable (organic-matter accumulation, inadequate contact time) and can spread pathogens. Use dedicated footwear and barrier flooring."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which disinfectant is NOT reliably effective against CPV?","o":["Accelerated hydrogen peroxide","Quaternary ammonium compounds","Potassium peroxymonosulfate","Sodium hypochlorite (bleach)"],"a":1,"e":"Quats are unreliable against non-enveloped CPV. Effective options: accelerated H2O2 (1:32, 10 min), potassium peroxymonosulfate (1%, 10 min), bleach (1:32, 10 min)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CPV preferentially targets:","o":["Terminally differentiated cells","Rapidly dividing cells (crypts, lymphoid, marrow, neonatal myocardium)","Mature erythrocytes","Hepatocytes"],"a":1,"e":"Rapidly dividing populations are most vulnerable, explaining the intestinal, lymphoid, marrow and neonatal myocardial lesions."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Disruption of the intestinal mucosal barrier in CPV leads to:","o":["Improved absorption","Bacterial translocation, endotoxaemia and bacteraemia","Lymphocytosis","Hypercoagulability only"],"a":1,"e":"Barrier loss allows gut bacteria to translocate, driving endotoxaemia, bacteraemia and potential sepsis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Viral shedding typically begins after infection at about:","o":["24 hours","4 to 7 days","21 days","6 weeks"],"a":1,"e":"Shedding starts roughly 4 to 7 days post-infection and can precede clinical signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The primary route of CPV transmission is:","o":["Faecal-oral and oronasal, plus fomites","Sexual contact","Tick-borne","Long-distance aerosol"],"a":0,"e":"Faecal-oral and oronasal spread predominate, with heavy fomite transmission because the virus is environmentally stable."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Under optimal conditions, CPV can persist in the environment for:","o":["Minutes","A few hours","Over a year","Exactly 5 months"],"a":2,"e":"CPV can remain viable for over a year in cool, shaded, organic-rich conditions, making fomite control critical."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The three recognised clinical forms of CPV are:","o":["Wet, dry, neurologic","Subclinical, gastroenteric, myocardial","Acute, peracute, chronic","Hepatic, renal, cardiac"],"a":1,"e":"Subclinical, gastroenteric and myocardial; the gastroenteric form is by far the most common."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most common clinical form of CPV is:","o":["Myocardial","Gastroenteric","Subclinical","Neurologic"],"a":1,"e":"The gastroenteric form predominates, mainly in pups aged 1 to 6 months."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The hallmark haematologic finding of the gastroenteric form is:","o":["Eosinophilia","Severe leukopenia","Thrombocytosis","Polycythaemia"],"a":1,"e":"Severe leukopenia from marrow and lymphoid destruction is the hallmark."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Improvement in which sign generally indicates reduced viral shedding?","o":["Diarrhoea","Fever only","Heart rate","Coat quality"],"a":0,"e":"Resolving diarrhoea is generally associated with declining viral shedding."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Pale mucous membranes and prolonged CRT in a CPV pup most directly reflect:","o":["Anaemia from haemorrhagic diarrhoea or reduced erythrocyte production","Dehydration only","Sepsis only","Hyperthermia"],"a":0,"e":"Anaemia (gut blood loss plus suppressed erythropoiesis) causes pallor and prolonged CRT, though dehydration and sepsis can coexist."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The first-line fluid for a CPV patient is:","o":["Hypotonic saline","A balanced isotonic crystalloid (Lactated Ringer's)","Colloid alone","5% dextrose in water alone"],"a":1,"e":"A balanced isotonic crystalloid such as Lactated Ringer's is first line; add dextrose and potassium as indicated."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An effective CPV disinfectant and contact time is:","o":["Quaternary ammonium for 1 min","Accelerated hydrogen peroxide 1:32 for 10 min, or bleach 1:32 for 10 min","70% alcohol wipe","Plain detergent"],"a":1,"e":"AHP 1:32 (10 min) or bleach 1:32 (10 min) are effective; quats and alcohol are not reliable against non-enveloped CPV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Before applying disinfectant to a contaminated surface you must first:","o":["Increase the disinfectant concentration","Remove organic matter and clean the surface","Skip any rinsing","Apply heat"],"a":1,"e":"Organic matter inactivates disinfectants, so physical cleaning must precede disinfection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Heavily contaminated bedding and toys from a CPV case are:","o":["Always salvageable with one wash","Often best disposed of","Never disposed of","Safe to share between cages"],"a":1,"e":"Communal washing can spread virus; disposing of heavily contaminated soft items is frequently more practical."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Spot cleaning an infected dog's cage is acceptable when:","o":["The cage is not visibly soiled","Always, regardless of soiling","Never","Only on the day of discharge"],"a":0,"e":"Spot cleaning reduces handling stress and is acceptable if the cage is not visibly soiled; full clean when soiled and after the animal vacates."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Outpatient treatment is appropriate for a CPV patient that is:","o":["In hypovolaemic shock","Less than 10% dehydrated, BCS above 3/9, and responsive","Recumbent and non-responsive","Any patient regardless of status"],"a":1,"e":"Outpatient or hybrid care suits stable patients: under 10% dehydrated, BCS above 3/9, responsive."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The more reliable test for ongoing viral shedding in a clinically recovered dog is:","o":["A single negative ELISA","Resolution of clinical signs","qPCR","Body temperature"],"a":2,"e":"Animals can shed detectable viral DNA after signs resolve and ELISA turns negative, so qPCR is more reliable for confirming cessation of shedding."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"If qPCR is unavailable, a clinically recovered CPV dog should be isolated for at least:","o":["No isolation needed","2 days","2 weeks","6 months"],"a":2,"e":"A minimum 2-week post-recovery isolation is advised when qPCR is unavailable, with bathing before release to reduce fomite spread."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Untreated CPV mortality can reach approximately:","o":["10%","50%","91%","100%"],"a":2,"e":"Untreated mortality can reach around 91%; treated survival is typically 80 to 90%."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In non-survivors, serum cortisol at 72 hours post-treatment tends to be:","o":["Persistently elevated","Low","Undetectable","Normal"],"a":0,"e":"Non-survivors show persistently elevated cortisol at 72 hours, whereas survivors show a decline."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Survival in CPV patients receiving appropriate treatment is typically:","o":["20%","50%","80 to 90%","Always 100%"],"a":2,"e":"Treated survival is generally 80 to 90%, with the first 3 to 5 days most critical."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CDV is classified as:","o":["A non-enveloped DNA parvovirus","An enveloped RNA morbillivirus (Paramyxoviridae)","A gram-negative bacterium","An enveloped DNA herpesvirus"],"a":1,"e":"CDV is an enveloped single-stranded RNA morbillivirus; the envelope makes it labile and easy to inactivate."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccines developed in the 1950s to 60s remain effective because CDV has:","o":["No envelope","One serotype","A bacterial capsule","Rapid antigenic drift"],"a":1,"e":"Only one serotype exists, so cross-protective MLV vaccines remain effective; outbreaks reflect coverage gaps, not antigenic escape."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The earliest immunologic effect of CDV infection is:","o":["Neutrophilia","Severe T and B lymphocytopenia with immunosuppression","Eosinophilia","Thrombocytosis"],"a":1,"e":"Early infection causes marked T and B lymphocytopenia and immunosuppression that can last weeks."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Recently MLV-vaccinated dogs that test RT-PCR positive can be distinguished from field infection because the only undetected vaccine is:","o":["MLV DAPP","The canarypox-vectored recombinant CDV vaccine","Killed CDV","Intranasal Bordetella"],"a":1,"e":"MLV CDV replicates in the same cells as wild virus and can be PCR-positive ~2 weeks; the canarypox recombinant is the one not detected."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most common route of CDV transmission is:","o":["Faecal-oral via a hardy virus","Direct contact and aerosol between sick and susceptible dogs","Insect vectors","Sexual contact"],"a":1,"e":"Direct contact and droplet/aerosol inhalation dominate, so isolating respiratory cases is essential."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CDV environmental stability is best described as:","o":["Hardy, persisting months outdoors","Labile, minutes to a few hours when warm","Spore-forming","Stable for over a year"],"a":1,"e":"As an enveloped virus it is labile; survival is temperature-dependent and short at warm temperatures."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which dogs most help maintain CDV transmission cycles in a shelter?","o":["Only severely ill dogs","Mildly affected and recovering dogs","Vaccinated dogs with adequate antibody","Dogs in strict isolation"],"a":1,"e":"Mildly affected and recovering dogs shed while looking well, sustaining the smouldering cycle."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Greater transmission potential on RT-PCR is suggested by:","o":["Higher Ct, lower load","Lower Ct, higher viral load","A negative result","Any positive regardless of value"],"a":1,"e":"A lower Ct means a higher viral load, indicating greater shedding and transmission potential."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An asymptomatic dog vaccinated with MLV 5 days ago tests RT-PCR positive with a very low Ct (high load). Best interpretation?","o":["Expected vaccine effect; MLV routinely gives high loads","High load points to wild-type field infection, not vaccine","The dog is immune and can join the adoption ward","Certain false positive; re-run on serum"],"a":1,"e":"Vaccine virus gives only low load (high Ct); a low Ct (high load) is highly suggestive of active field infection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The CDV clinical course is classically:","o":["Peracute monophasic","Biphasic","Always subclinical","Chronic from onset"],"a":1,"e":"Biphasic: an early febrile/respiratory phase, then systemic and potentially neurologic disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The frequently missed earliest sign of CDV is:","o":["Pyrexia","Grand mal seizures","Hyperkeratosis","Blindness"],"a":0,"e":"Early pyrexia (within days to a week) is commonly missed, especially in shelters."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CDV neurologic signs:","o":["Only occur alongside systemic signs","Can appear 1 to 3 weeks or longer after systemic signs resolve","Never occur","Always precede respiratory signs"],"a":1,"e":"Neurologic disease can develop with systemic signs or weeks after they resolve, and carries a poor prognosis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A classic dermatologic sign of CDV is:","o":["Digital and nasal hyperkeratosis (hard pad)","Alopecia universalis","Icterus","Symmetric truncal alopecia"],"a":0,"e":"Digital and nasal hyperkeratosis (hard pad) is described and often linked to neurologic disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which examination is recommended in all suspected CDV cases?","o":["Abdominal ultrasound","A careful ocular examination","Echocardiography","Bronchoscopy"],"a":1,"e":"Ocular signs are common (discharge, KCS, retinal lesions, optic neuritis), so an ocular exam is indicated in all suspects."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For CDV there is:","o":["A licensed antiviral","No antiviral, so care is supportive and treats secondary infection","A single curative antibiotic","A curative antitoxin"],"a":1,"e":"No antiviral exists; management is supportive with treatment of secondary bacterial infection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"When GI signs are present in CDV, the notes recommend:","o":["Oral antifungals","Broad-spectrum parenteral antibiotics and B vitamins","No treatment","Corticosteroids alone"],"a":1,"e":"Broad-spectrum parenteral antibiotics are advised for GI signs, with B vitamins."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Compared with respiratory and systemic signs, treatment of CDV neurologic disease is:","o":["More successful","Commonly less successful","Curative","Identical in outcome"],"a":1,"e":"Neurologic disease is often progressive and irreversible, and responds less well than supportive care for other signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"At 56&deg;C, the half-life of CDV is approximately:","o":["4 to 5 minutes","5 hours","9 to 11 days","2 weeks"],"a":0,"e":"Half-life is ~4 to 5 minutes at 56&deg;C; survival lengthens at lower temperatures."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CDV persists longest at which temperature?","o":["56&deg;C","Body temperature","Room temperature","4&deg;C (9 to 11 days)"],"a":3,"e":"At 4&deg;C the virus can persist 9 to 11 days, so cold conditions make sanitation lapses riskier."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Outbreak sanitation for CDV should especially target:","o":["The isolation ward only","Common-contact surfaces such as vehicles, intake pens and staff clothing","Outdoor soil for months","Adoption paperwork"],"a":1,"e":"Because spread is largely contact/fomite over short survival times, target high-traffic shared surfaces."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The single most important measure to prevent CDV in shelters is:","o":["Footbaths","Vaccinate all dogs at or before intake","Quarterly serology","Monthly deworming"],"a":1,"e":"Intake vaccination is the most important control measure, paired with management that lowers exposure."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The preferred shelter CDV vaccine type is:","o":["Killed","Modified-live (MLV)","Autogenous","None"],"a":1,"e":"MLV is preferred (lower cost, can occupy binding sites and protect before humoral immunity); rCDV helps against maternal antibody."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Given CDV's long incubation, the key alternative to prolonged quarantine of an exposed asymptomatic dog is:","o":["A single faecal antigen test","Antibody (titre) testing","Thoracic radiographs","Urinalysis"],"a":1,"e":"Antibody testing can identify protected dogs and shorten or avoid quarantine."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An exposed asymptomatic adult has a positive antibody titre and a negative RT-PCR. Correct categorisation?","o":["High risk; 6-week quarantine","Incubating/infectious; isolate","Low risk/protected; clear for adoption or transfer","Euthanise; paired testing is unreliable"],"a":2,"e":"Positive titre plus negative PCR means immune and not shedding: low risk, clear for adoption or transfer."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An exposed asymptomatic dog has a negative antibody titre and a negative RT-PCR. This dog is:","o":["Protected; no action","Susceptible; vaccinate and quarantine away from the outbreak footprint","Infectious; isolate","A confirmed recovered carrier"],"a":1,"e":"Negative titre plus negative PCR means no current infection but no immunity: susceptible, so vaccinate and quarantine separately."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A CDV clean break during an outbreak includes:","o":["Mixing new and exposed dogs to build immunity","Vaccinating all incoming dogs at entry, separate housing ~25 ft away, with separate staff and supplies","Stopping vaccination to avoid PCR confusion","Holding all intake in one shared ward"],"a":1,"e":"Clean break: vaccinate every incoming dog at entry, house ~25 ft (ideally a separate ward/building) from exposed dogs, with separate staff and supplies."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is the puppy CDV booster series extended to 20 weeks of age in shelters?","o":["Recombinant vaccines fail under 20 weeks","Puppies cannot process antigen until 5 months","High maternal antibody from field-strain-recovered dams can block MLV past 16 weeks","Cold shelters slow vaccine absorption"],"a":2,"e":"Exceptionally high maternal antibody (dams recovered from field strains) blocks MLV beyond the usual 16 weeks, widening the susceptibility window."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which cytologic/histologic finding confirms CDV?","o":["Intranuclear basophilic inclusions in hepatocytes only","Both intracytoplasmic and intranuclear eosinophilic inclusion bodies in epithelial cells or astrocytes","Gram-negative spirilla in gastric mucosa","Multinucleated giant cells with no inclusions"],"a":1,"e":"CDV produces both intracytoplasmic and intranuclear eosinophilic inclusions in epithelial cells and astrocytes, a classic board distinction."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Regarding a carrier state, CDV:","o":["Has a lifelong carrier state","Has no true carrier state but may shed up to 16 weeks","Never sheds after recovery","Is shed only by vaccinated dogs"],"a":1,"e":"There is no true carrier state, though shedding can persist up to 16 weeks and some dogs stay low-level PCR-positive for months with intermittent shedding."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A recovered dog that stays low-level RT-PCR positive for months should be:","o":["Euthanised","Returned to the general population","Housed away from susceptibles, ideally with immunised dogs","Re-vaccinated weekly"],"a":2,"e":"Manage rare persistent low-level positives by keeping them away from susceptibles, ideally in homes with immunised dogs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIRD is best described as:","o":["A single-pathogen disease","A multifactorial complex of host, agent and environment","A non-infectious condition","A purely bacterial pneumonia"],"a":1,"e":"CIRD is multifactorial: multiple pathogens plus host and environmental stressors drive disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The only non-enveloped, environmentally stable CIRD virus is:","o":["CPiV","CAV-2","CRCoV","CIV"],"a":1,"e":"CAV-2 is the lone non-enveloped (DNA) CIRD virus; it is stable and resists alcohol and quats."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CRCoV is nicknamed the lawnmower virus because it:","o":["Denudes respiratory cilia","Causes GI signs","Infects birds","Forms spores"],"a":0,"e":"CRCoV denudes respiratory cilia, removing mucociliary clearance and producing classic CIRD signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For respiratory mucosal protection, the most important element is:","o":["Serum IgG","Mucosal IgA and intact barriers / innate immunity","Complement alone","Platelet count"],"a":1,"e":"Intact respiratory barriers, mucociliary function and mucosal IgA matter more than serum IgG/IgM for mucosal pathogens."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Mycoplasma cynos virulence is aided by:","o":["A thick cell wall","Sialidase activity enabling adherence","Spore formation","An envelope"],"a":1,"e":"M. cynos (a wall-less bacterium) uses sialidase to adhere to and damage respiratory epithelium."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIRD pathogens spread mainly by:","o":["Faecal-oral","Aerosolised droplets from coughing and sneezing, plus fomites","Arthropod vectors","Sexual contact"],"a":1,"e":"Spread is largely by respiratory droplets plus fomites (hands, clothing, tools)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Coughing and sneezing can propel CIRD pathogens up to about:","o":["6 metres","6 centimetres","60 metres","600 metres"],"a":0,"e":"Droplets travel up to ~6 m, contaminating open kennels and shared spaces."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which CIRD agents are zoonotic and warrant staff PPE?","o":["CAV-2 and CPiV","Bordetella bronchiseptica and Streptococcus zooepidemicus","CRCoV and CHV","CnPnV only"],"a":1,"e":"Both Bordetella and Strep zoo are zoonotic; wear protective clothing, gloves and eye/face protection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Classic uncomplicated CIRD is characterised by:","o":["A hacking honking cough with mild nasal discharge, dog usually bright and appetent","Profuse bloody diarrhoea","Sudden blindness","Generalised seizures"],"a":0,"e":"Typical CIRD is a paroxysmal honking cough with mild discharge; most dogs stay bright, active and appetent."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Anorexia and malaise in a CIRD dog most suggest:","o":["Routine kennel cough","Advancing or lower-airway disease","Imminent recovery","Vaccine reaction"],"a":1,"e":"Anorexia and malaise are red flags for advancing or lower respiratory tract disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Streptococcus zooepidemicus can progress to:","o":["Mild self-limiting cough only","Peracute haemorrhagic pneumonia and sudden death in 24 to 48 hours","Chronic dermatitis","A latent neonatal infection"],"a":1,"e":"Strep zoo can cause peracute, haemorrhagic, fibrinosuppurative pneumonia with sudden death over 24 to 48 hours."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which CBC pattern points to descending bacterial pneumonia rather than uncomplicated viral URI?","o":["Stress leukogram (mild neutrophilia, lymphopenia, eosinopenia)","Marked leukocytosis with a left shift (band neutrophils) plus fever","Eosinophilia","Normal CBC"],"a":1,"e":"An inflammatory leukogram with a left shift plus pyrexia indicates lower-airway bacterial pneumonia; a stress leukogram fits uncomplicated viral URI."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For CIRD PCR, the highest-yield dogs to sample are:","o":["Dogs coughing for 7 to 10 days","Asymptomatic dogs in the shelter over 6 weeks","Acutely ill dogs within 1 to 2 days of onset","Recovered dogs that stopped coughing"],"a":2,"e":"Sample acutely ill dogs within 1 to 2 days; after 5 to 7 days the shedding window closes and PCR loses value (use paired serology)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"When testing a population during a CIRD outbreak, a reasonable target is:","o":["Every dog in the shelter","A small representative group of acutely ill dogs (about 5 to 10, or 10 to 30%)","One asymptomatic dog","Only euthanised dogs"],"a":1,"e":"Test a small representative group of acutely ill dogs (about 5 to 10, or 10 to 30% of the population), interpreted with clinical context."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"All CIRD pathogens are inactivated by:","o":["Water alone","Bleach, accelerated hydrogen peroxide and potassium peroxymonosulfate","Freezing","Quaternary ammonium alone"],"a":1,"e":"Sodium hypochlorite, accelerated hydrogen peroxide and potassium peroxymonosulfate inactivate all CIRD pathogens."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Alcohol sanitiser over 60% works against CIRD agents except:","o":["CAV-2","CPiV","Bordetella","CRCoV"],"a":0,"e":"Non-enveloped CAV-2 resists alcohol; enveloped agents are susceptible."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Quaternary ammonium is less reliable against CIRD because it:","o":["Is too corrosive","Misses Gram-negative Bordetella and non-enveloped CAV-2 and is inactivated by organic matter","Kills every pathogen too fast","Damages stainless steel"],"a":1,"e":"Quats have limited Gram-negative and non-enveloped-virus activity and are inactivated by hard water, organic debris and detergent."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The essential first step for any disinfectant to work is:","o":["Raising the concentration","Removal of organic debris (clean first)","Skipping the rinse","Increasing contact temperature"],"a":1,"e":"Organic debris must be physically removed; disinfectants do not work through organic matter."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Cleaning equipment in CIRD wards should:","o":["Be high-pressure hoses for speed","Limit aerosolisation, such as hose-end foamers","Be shared between wards","Maximise water volume"],"a":1,"e":"Limit aerosolisation (hose-end foamers, not pressure sprayers); aerosolisation and humidity spread pathogens."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The only CIRD vaccine that induces sterilising immunity is:","o":["Bordetella","CDV","CPiV","CAV-2"],"a":1,"e":"Only the CDV vaccine gives sterilising immunity; the others reduce infection, shedding and severity but do not prevent colonisation or signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For respiratory mucosal pathogens, the generally more effective vaccine route is:","o":["Intranasal, except CAV-2 where parenteral gives prolonged immunity","Parenteral for all agents","Oral for all agents","Topical"],"a":0,"e":"Intranasal (mucosal) vaccination is generally superior for respiratory agents; CAV-2 is the exception, with parenteral giving 4+ year immunity."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most significant CIRD vaccination error, and its severe systemic risk, is:","o":["Giving CAV-2 orally; causes diarrhoea","Injecting a live intranasal Bordetella vaccine SQ; can cause hepatocellular necrosis and liver failure","Freezing the vaccine; causes anaphylaxis","Double-dosing CPiV; causes seizures"],"a":1,"e":"An IN Bordetella vaccine given SQ can cause cellulitis, abscessation and acute hepatocellular necrosis/liver failure; treat with doxycycline."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Recommended air changes per hour in shelter housing are about:","o":["1 to 2","10 to 12","30 to 40","None needed"],"a":1,"e":"Aim for 10 to 12 air changes per hour, ideally 100% outdoor air, with separately zoned HVAC for isolation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Healthy dogs with no exposure or signs should be:","o":["Routinely quarantined for 6 weeks","Not routinely quarantined","Euthanised","Vaccinated then released same day without exam"],"a":1,"e":"Routine quarantine of healthy unexposed dogs is avoided; prolonged LOS is itself the greatest CIRD risk factor."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Typical isolation for an uncomplicated, improving CIRD case is:","o":["7 to 10 days with clinical improvement","6 weeks minimum","24 hours","No isolation"],"a":0,"e":"Most improving cases release at 7 to 10 days; decisions weigh resolution of signs, agent shedding and housing risk."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Antitussives in CIRD should be:","o":["Used routinely in all coughers","Reserved for severe or debilitating dry cough, with antibiotic cover, and avoided if pneumonia is suspected","Never used under any circumstance","Used instead of antibiotics"],"a":1,"e":"Reserve antitussives for severe, non-productive cough with antibiotic cover; avoid them with an inflammatory leukogram, fever or consolidation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Long shedders warranting caution before mixing with susceptibles include:","o":["CAV-2 only","CDV, CIV H3N2, Bordetella and Mycoplasma","CPiV only","None of the CIRD agents"],"a":1,"e":"CDV, CIV H3N2, Bordetella and Mycoplasma have prolonged shedding, so use caution before mixing recovered dogs with susceptibles."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Streptococcus zooepidemicus requires which antibiotic class, being resistant to doxycycline?","o":["Penicillins (penicillin, ampicillin, amoxicillin)","Aminoglycosides only","Macrolides only","Tetracyclines"],"a":0,"e":"Strep zoo needs penicillins/beta-lactams and is resistant to doxycycline."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In a Streptococcus zooepidemicus outbreak, the recommended approach is to:","o":["Wait for signs in each dog before treating","Prophylactically treat all exposed dogs with a beta-lactam","Withhold antibiotics for stewardship","Use doxycycline for all dogs"],"a":1,"e":"Because disease is rapid and deadly, prophylactically treat all exposed dogs with a beta-lactam (penicillin G or cefovecin)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"First-line empirical antibiotics for shelter CIRD, under stewardship, should be:","o":["Azithromycin or a fluoroquinolone","Doxycycline or amoxicillin-clavulanate","An aminoglycoside","No antibiotic ever"],"a":1,"e":"Keep first-line to doxycycline or amoxicillin-clavulanate; reserve macrolides and fluoroquinolones for culture-confirmed resistant lower-airway disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV is best classified as:","o":["A herpesvirus","Influenza A (enveloped RNA), subtypes H3N8 and H3N2","A coronavirus","A non-enveloped parvovirus"],"a":1,"e":"CIV is an enveloped RNA influenza A virus; the canine subtypes are H3N8 and H3N2."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV subtypes are defined by:","o":["Haemagglutinin and neuraminidase surface proteins","Capsid colour","Host species only","Genome size"],"a":0,"e":"Influenza A is subtyped by its H and N surface glycoproteins (18 H, 11 N identified)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"H3N2 is notable for:","o":["Equine origin, dogs only","Avian origin and a broader host range including cats, ferrets and guinea pigs","Infecting humans only","Being non-infectious to dogs"],"a":1,"e":"H3N2 is avian-origin (Korea 2007, US 2015) with a wider host range than dogs-only H3N8."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV replicates primarily in:","o":["Intestinal crypts","Respiratory epithelium","Bone marrow","Hepatocytes"],"a":1,"e":"CIV replicates in respiratory epithelium, sloughing cells and exposing tissue to secondary bacteria."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV spreads by:","o":["Aerosols, droplets, direct contact and fomites","Faecal-oral only","Tick vectors","Sexual contact"],"a":0,"e":"Spread is respiratory (aerosol/droplet), with direct contact and fomite routes important in shelters."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The CIV incubation period is:","o":["2 to 5 days","3 weeks","6 weeks","12 hours"],"a":0,"e":"Incubation is 2 to 5 days; peak shedding at 2 to 4 days can precede signs."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Peak CIV shedding occurs:","o":["2 to 4 days post-infection, overlapping incubation","Only after recovery","At 3 weeks","Never"],"a":0,"e":"Peak shedding is 2 to 4 days post-infection, so outwardly healthy dogs can be highly contagious early."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Regarding a carrier state, CIV:","o":["Has none; once shedding stops the dog is not contagious","Has a lifelong carrier state","Never stops shedding","Sheds only after vaccination"],"a":0,"e":"There is no true carrier state; once replication and shedding cease the dog is no longer contagious (H3N2 shedding can be prolonged though)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Subclinical shedders make up about what fraction of infected dogs?","o":["0%","10 to 20%","50%","100%"],"a":1,"e":"About 80 to 90% develop signs and 10 to 20% are subclinical shedders, so all exposed dogs are an infectious risk."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV cannot be reliably distinguished from other CIRD by:","o":["Clinical signs alone, so lab testing is needed","Breed","Age","Coat colour"],"a":0,"e":"Signs overlap other CIRD agents; only laboratory testing confirms CIV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Severe CIV disease usually results from:","o":["The virus alone in every case","Co-infection or comorbidity, progressing to pneumonia","Vaccination","Antibiotic therapy"],"a":1,"e":"Severe manifestations typically reflect co-infection with other CIRD agents or patient comorbidity."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Pneumonia-related CIV fatality is approximately:","o":["5 to 8%","25%","50%","0%"],"a":0,"e":"Mortality is low overall; pneumonia-related fatality is about 5 to 8%, depending on rapid diagnosis and aggressive care."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In severe CIV pneumonia, what is the primary mechanism enabling secondary bacterial invasion?","o":["Destruction of alveolar macrophages causing hypoxaemia","Necrosis of ciliated columnar epithelium, neutralising the mucociliary escalator","Destruction of circulating B-lymphocytes","Viral replication in pulmonary capillary endothelium causing DIC"],"a":1,"e":"CIV destroys ciliated epithelium and the mucociliary escalator, allowing colonisation by Bordetella, Strep zoo and Pasteurella."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV treatment is mainly:","o":["Supportive care while the infection runs its course","A specific curative antiviral","A single curative antibiotic","No treatment is ever given"],"a":0,"e":"Care is supportive; antibiotics target secondary bacterial infection or pneumonia."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Antibiotics in CIV are warranted:","o":["In all cases","For secondary bacterial infection or pneumonia","Never","Only for fungal disease"],"a":1,"e":"Reserve antibiotics for secondary bacterial infection or pneumonia, though shelters often treat empirically."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Antitussives in CIV are:","o":["First-line therapy","Of little evidence and contraindicated with a productive cough","Curative","Required in every case"],"a":1,"e":"Antitussives have little evidence in CIV and are contraindicated with a productive cough."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For CIV PCR, the correct swab choice and reason is:","o":["Cotton-tipped, because virus binds cotton for easier isolation","Synthetic polyester/dacron with plastic shafts, because cotton and wood inhibit PCR","Calcium alginate with wooden shafts, to preserve RNA","Gel-agar swabs, to protect the envelope"],"a":1,"e":"Cotton fatty acids and wood resins/tannins inhibit PCR and viral assays; use polyester or dacron on plastic/aluminium shafts."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A human influenza A patient-side antigen kit is used on a CIV-suspect dog and is negative. This means:","o":["The dog is cleared and can leave quarantine","The result is uninformative; a negative cannot clear the dog","CIV is definitively ruled out","The dog is immune"],"a":1,"e":"These kits have poor canine sensitivity: a positive is reliable, but a negative is uninformative and cannot clear an animal from quarantine."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Serology (haemagglutination inhibition) for CIV is reliably interpretable:","o":["From day 1","Only after about 10 days of clinical signs","Only after 6 weeks","Never"],"a":1,"e":"Reliable HI detection occurs after ~10 days of signs; a negative before day 10 does not rule out infection. A 4-fold paired-titre rise confirms recent infection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"CIV survives on non-porous surfaces for about:","o":["24 to 48 hours","5 months","Seconds","Over a year"],"a":0,"e":"As an enveloped virus, CIV survives ~24 to 48 h on non-porous surfaces, 8 to 12 h on porous surfaces, and minutes on hands."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Effective CIV disinfectants include:","o":["Water alone","Accelerated hydrogen peroxide, bleach, quaternary ammonium and potassium peroxymonosulfate","Only autoclaving","None"],"a":1,"e":"Being enveloped, CIV is readily inactivated by AHP, bleach, quats and potassium peroxymonosulfate."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Compared with parvovirus, CIV environmental control is:","o":["Easier, being a labile enveloped virus","Harder, being environmentally stable","Identical","Impossible"],"a":0,"e":"CIV is enveloped and labile, so it is far easier to inactivate than the hardy non-enveloped parvovirus."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Once a CIV case is suspected, all dogs present should be considered:","o":["Safe","Exposed or at risk, given high transmissibility","Immune","Carriers for life"],"a":1,"e":"High transmissibility and pre-clinical shedding mean all dogs present should be treated as exposed or at risk."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Recommended quarantine for exposed dogs is at least:","o":["14 days","2 days","No quarantine","6 weeks"],"a":0,"e":"Quarantine exposed dogs a minimum of 14 days, with PCR at days 4 to 7 to release negatives."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Subtype-specific isolation for sick dogs is approximately:","o":["H3N8 about 7 days, H3N2 about 21 to 28 days","Both 1 day","Both 6 weeks","H3N2 shorter than H3N8"],"a":0,"e":"H3N8 isolation ~7 to 10 days; H3N2 ~21 to 28 days due to prolonged intermittent shedding."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The CIV vaccine is best described as:","o":["Core and sterilising","Non-core, killed, partial protection that does not prevent infection","Intranasal modified-live","A single-dose lifelong vaccine"],"a":1,"e":"CIV vaccines are killed, non-core, and non-sterilising; two doses 2 to 3 weeks apart with immunity 1 to 2 weeks after the second."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs imported from South Korea or China warrant extra precautions because of:","o":["High H3N2 prevalence","Rabies risk","Low vaccination rates","Heartworm"],"a":0,"e":"High regional H3N2 prevalence justifies aggressive 14-day quarantine and testing for imports from these areas."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is mass vaccination a flawed strategy to halt an active shelter CIV outbreak?","o":["The vaccine is modified-live and causes disease","Killed CIV vaccine needs two doses 2 to 3 weeks apart, with immunity only 1 to 2 weeks after the second","It protects only cats and ferrets","CIV undergoes instant antigenic shift against the vaccine"],"a":1,"e":"The two-dose killed series with delayed protection cannot stop an outbreak already underway."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The overall CIV pattern is:","o":["High morbidity, low mortality","Low morbidity, high mortality","Both low","Both high"],"a":0,"e":"CIV is high-morbidity, low-mortality; most dogs recover with supportive care."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A key limitation of CIV recovery immunity is that:","o":["It prevents all future infection","CIV mutates quickly, so protection is strain-specific","It is sterilising across strains","It lasts only 2 weeks"],"a":1,"e":"Post-infection antibody persists 5 to 6 years but is strain-specific, and rapid mutation limits cross-protection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most important feline dermatophyte is:","o":["Microsporum gypseum","Microsporum canis (over 90% of feline cases)","Trichophyton mentagrophytes","Epidermophyton"],"a":1,"e":"M. canis causes 90%+ of feline dermatophytosis; M. gypseum and Trichophyton are seen more in dogs and rodents."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"To establish infection, dermatophyte spores require:","o":["Microtrauma to the skin","Completely intact skin","Systemic immunosuppression only","An alkaline coat pH"],"a":0,"e":"Spores need microtrauma (humidity maceration, parasites) to breach defences and infect the follicle."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Relative to normal feline flora, M. canis:","o":["Is part of normal flora","Is NOT part of normal flora, so a positive culture always needs action","Is a commensal yeast","Colonises only claws"],"a":1,"e":"M. canis is never normal flora; a positive culture means lesions, subtle lesions or mechanical fomite carriage, all requiring action."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Recovery from dermatophytosis depends mainly on:","o":["Humoral antibody","A strong cell-mediated immune response","Complement","Maternal antibody"],"a":1,"e":"Protection is cell-mediated, so antibody titres are clinically useless and immunosuppressed cats may fail to clear infection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Transmission of dermatophytosis occurs by:","o":["Direct contact, fomites and sometimes fleas","Faecal-oral route","Sexual contact","Mosquito vectors"],"a":0,"e":"Spread is by contact, contaminated fomites and occasionally fleas; staff can mechanically move spores between cats."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Airborne transmission of dermatophytes is:","o":["The main route","Possible but minimal when husbandry and disinfection are adequate","Impossible","More important than fomites"],"a":1,"e":"Airborne spread is minor with good sanitation; separate air handling is not required if treatment and cleaning are adequate."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Dermatophyte spores persist in the environment for:","o":["Minutes","Hours","Weeks to months","Over a decade"],"a":2,"e":"Spores remain infectious for weeks to months unless the area is thoroughly cleaned."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The incubation period for dermatophytosis is:","o":["2 to 4 days","2 to 4 weeks","2 to 4 hours","6 months"],"a":1,"e":"Incubation is 2 to 4 weeks, with follicle infection preceding lesions."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Quarantining exposed animals simply to watch for lesions is:","o":["Recommended","NOT recommended; use active diagnostic screening","Mandatory for 6 weeks","Required only for dogs"],"a":1,"e":"The long incubation makes watch-and-wait quarantine impractical; active screening is preferred."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The classic dermatophyte lesion is:","o":["Circular alopecia with scaling and inflammation","Fluid-filled vesicles only","Symmetric truncal alopecia","Ulcerated nodules"],"a":0,"e":"Classic lesions are circular alopecia with scaling and inflammation, though presentation is highly variable."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In dogs, lesions that look like classic ringworm are more often:","o":["Bacterial pyoderma or demodicosis","Always dermatophytosis","Neoplasia","Immune-mediated only"],"a":0,"e":"Classic ringworm-looking lesions in dogs are more commonly pyoderma or demodicosis than true dermatophytosis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Juvenile animals (under 1 year) with dermatophytosis tend to have:","o":["More severe, generalised infection","No clinical signs","Only focal lesions","Self-limiting nasal disease"],"a":0,"e":"Young animals more often get severe generalised lesions; adults tend to focal disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The Wood's lamp examination uses what wavelength, and which pathogen fluoresces apple-green?","o":["254 nm; all dermatophytes","365 nm; M. canis (only ~50% of cases)","450 nm; Trichophyton","365 nm; M. gypseum"],"a":1,"e":"365 nm UV; only M. canis fluoresces apple-green among important veterinary pathogens, and only about half of cases do."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A negative Wood's lamp examination:","o":["Rules out ringworm","Does NOT rule out ringworm","Confirms a fomite carrier","Means the cat is cured"],"a":1,"e":"A positive is strongly indicative, but a negative never rules out dermatophytosis (Trichophyton and ~50% of M. canis do not fluoresce)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"On direct microscopy, infected hairs show:","o":["Narrow, smooth hairs","Cuffs of refractile ectothrix spores on wider, irregular hairs","Intracellular inclusion bodies","Acid-fast rods"],"a":1,"e":"Infected hairs are wider, irregular and filamentous with ectothrix spore cuffs; 10x confirms hairs, 40x for spores."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The gold-standard diagnostic test is:","o":["Wood's lamp","Fungal culture on DTM","Serology","Skin biopsy"],"a":1,"e":"Fungal culture on dermatophyte test medium is the gold standard, typically via the toothbrush technique."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The CFU-based P-score is defined as:","o":["P1 1-4, P2 5-9, P3 10 or more CFU per plate","P1 10+, P2 5-9, P3 1-4","P1 by lesion only","P1 = Wood's positive"],"a":0,"e":"P-score is colony count: P1 = 1 to 4, P2 = 5 to 9, P3 = 10 or more CFU per plate, overlaid with lesion status."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A lesion-free, Wood's-negative cat with a P1 (2 CFU) M. canis culture is best classified and managed as:","o":["Truly infected; 21-day systemic course","Fomite (dust-mop) carrier; safeguard re-culture, single lime sulfur dip and adopt","Permanent latent carrier; chronic isolation","Uninterpretable; quarantine the foster home 6 weeks"],"a":1,"e":"This is a mechanical fomite carrier: re-culture as a safeguard, do one lime sulfur dip and proceed to adoption (dip-and-go)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"P3 cats should be:","o":["Left in the general population","Immediately removed from the general population regardless of lesions","Adopted immediately","Dipped once and released"],"a":1,"e":"P3 (high count, confirmed infection) cats are removed from the general population for strict isolation and full treatment."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Over 95% of positive fungal cultures are identified by:","o":["Day 1","Day 10 to 14 (day 10 is a key read point)","Day 30","Day 60"],"a":1,"e":"Most positives appear by day 10 to 14; hold cultures (not animals) for the full 21 days for slower Trichophyton."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"By day 5, a toothbrush DTM plate from a crusted stray is fully red and covered in heavy, dark, pigmented fuzzy colonies. This is:","o":["A true M. canis positive; move to P3 isolation","Trichophyton, because it grew fast","Saprophytic overgrowth; record HC and reculture","Media mites; spray the incubator"],"a":2,"e":"Pathogens are pale and turn DTM red as they grow; heavy pigmented overgrowth is saprophytic contamination that masks positives. Record HC and reculture."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The shelter systemic treatment of choice is:","o":["Itraconazole PO SID for 21 to 28 days","Griseofulvin","Ketoconazole","Lufenuron"],"a":0,"e":"Itraconazole 5 to 10 mg/kg PO SID for 21 to 28 days, paired with topical therapy; terbinafine for azole-resistant strains."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The first-line topical adjunct is:","o":["Twice-weekly lime sulfur, not rinsed","Chlorhexidine shampoo alone","A dilute bleach bath","Topical iodine"],"a":0,"e":"Lime sulfur twice weekly (8 oz/gallon), applied to the skin base and not rinsed, is first-line topical therapy."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The terbinafine dose range for cats is approximately:","o":["1 mg/kg","10 to 40 mg/kg PO SID","100 mg/kg","0.1 mg/kg"],"a":1,"e":"Terbinafine 10 to 40 mg/kg PO SID (cats toward the higher end), useful for azole-resistant M. canis; monitor ALT."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is griseofulvin avoided in shelter cats beyond its long cure time and teratogenicity?","o":["It causes oral ulcers with lime sulfur","Idiosyncratic, irreversible bone-marrow suppression, lethal in FeLV/FIV-positive cats","It precipitates calcium oxalate stones","It raises urinary pH"],"a":1,"e":"Griseofulvin can cause idiosyncratic irreversible marrow suppression, accelerated and potentially fatal in retrovirus-positive cats; test FeLV/FIV first."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Mycological cure is defined as:","o":["One negative Wood's lamp","Three consecutive weekly negative cultures (two only with lime sulfur plus itraconazole)","Clinical resolution alone","A single negative culture"],"a":1,"e":"Three consecutive weekly negative cultures define cure; two suffice only with combined lime sulfur and continuous oral itraconazole."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The cornerstone of environmental decontamination is:","o":["Disinfectant alone","Mechanical cleaning and removal of spores and hair","UV light only","Sealing the room for a month"],"a":1,"e":"Mechanical removal (vacuuming, sweeping, Swiffering) is the single most critical step; disinfect only after thorough cleaning."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which disinfectant set is effective against ringworm spores?","o":["Quaternary ammonium and chlorhexidine","Bleach 1:10 or 1:32 (10 min), AHP 1:16, or 2% potassium peroxymonosulfate","Calcium hypochlorite and 1% potassium peroxymonosulfate","Iodine and captan"],"a":1,"e":"Effective: bleach (>=10 min), AHP 1:16, 2% potassium peroxymonosulfate, enilconazole 1:100. Quats, chlorhexidine, calcium hypochlorite and 1% KPMS are ineffective."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For potassium peroxymonosulfate against ringworm, the effective concentration is:","o":["1% (same as for parvovirus)","2%; 1% is unreliable against spores","0.5%","Any concentration works"],"a":1,"e":"Ringworm needs a 2% solution; 1% is unreliable (unlike parvovirus, where 1% works). Quats fail for both."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Cats under treatment are released for adoption when:","o":["Clinical signs resolve","All co-housed animals reach mycological cure simultaneously","The first negative culture returns","The Wood's lamp turns negative"],"a":1,"e":"Release only when every co-housed animal has reached mycological cure; a negative cat cannot leave if a cage mate is still positive."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FPV is best classified as:","o":["An enveloped RNA virus","A non-enveloped single-stranded DNA parvovirus","A gram-negative bacterium","A retrovirus"],"a":1,"e":"FPV is a non-enveloped ssDNA parvovirus with a single serotype, closely related to CPV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FPV preferentially infects:","o":["Terminally differentiated neurons","Rapidly dividing cells (marrow, lymphoid, intestinal crypts, fetal cerebellum)","Mature erythrocytes","Skeletal muscle"],"a":1,"e":"FPV needs the S-phase of division, so it targets marrow, lymphoid tissue, crypts and fetal/neonatal tissue."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FPV enters host cells using the:","o":["Transferrin receptor","ACE2 receptor","CD4 receptor","Sialic-acid receptor only"],"a":0,"e":"FPV uses the transferrin receptor to enter and replicate in lymphoid tissue of the oropharynx and gut."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Cerebellar hypoplasia in kittens arises from:","o":["Adult infection","In-utero or perinatal infection of cerebellar Purkinje cells","Vaccination of adult cats","Postnatal trauma"],"a":1,"e":"Perinatal or in-utero Purkinje cell infection produces nonprogressive cerebellar hypoplasia."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The leukopenia of FPV results from:","o":["Marrow suppression plus neutrophil loss into the gut and lymphoid depletion","Increased peripheral demand alone","Splenic sequestration","Antibody-mediated destruction only"],"a":0,"e":"Marrow suppression, neutrophil losses into the damaged gut, and lymphoid depletion together cause the panleukopenia."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The primary transmission route of FPV is:","o":["Faecal-oral (direct or fomite)","Sexual","Tick-borne","Respiratory droplet only"],"a":0,"e":"Faecal-oral is primary; transplacental, droplet (with URT co-infection) and fly/flea mechanical spread also occur."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FPV environmental survival is approximately:","o":["A few hours","Infective at 4 to 25 C for about 13 months","Inactivated by drying within a day","About a week"],"a":1,"e":"FPV is exceptionally hardy, infective at 4 to 25 C for around 13 months and persisting over a year in organic matter."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Vertical transmission of FPV occurs by:","o":["Fetal infection via maternal circulation in mid-gestation","Ingestion of milk only","It does not occur","Only during parturition"],"a":0,"e":"The virus crosses the placenta in mid-gestation, infecting the fetus via maternal circulation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most common clinical form of FPV is:","o":["Peracute","Acute","Subacute","Perinatal"],"a":1,"e":"The acute form is most common: biphasic fever, vomiting and fetid/haemorrhagic diarrhoea with severe leukopenia."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The peracute form of FPV is characterised by:","o":["Mild self-limiting disease","Sudden death within hours, sometimes mistaken for poisoning","Chronic wasting","Isolated neurological signs"],"a":1,"e":"Peracute disease kills kittens under 6 months in hours (lethargy to coma to death), often resembling poisoning; near 100% mortality."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A leukopenia value indicating a very guarded prognosis is:","o":["Under 2000/uL","Under 8000/uL","Under 12000/uL","Under 15000/uL"],"a":0,"e":"A WBC under 2000/uL, especially if persistent, carries a very guarded prognosis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Perinatal cerebellar disease in surviving kittens produces:","o":["Progressive blindness","Nonprogressive ataxia and hypermetria with normal mentation","Seizures only","Progressive paralysis"],"a":1,"e":"Cerebellar hypoplasia gives nonprogressive ataxia, hypermetria and a wide-based stance, with normal mentation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most serious secondary bacterial invader in FPV is:","o":["E. coli","Pseudomonas","Bordetella","Streptococcus"],"a":0,"e":"E. coli is the worst secondary invader once the gut barrier fails, driving bacteraemia and sepsis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The listed alternative antibiotic combination for FPV is:","o":["Ampicillin 6.6 mg/kg IM q8h plus gentamicin 4.4 mg/kg q12h","Doxycycline alone","Metronidazole alone","Azithromycin alone"],"a":0,"e":"Broad-spectrum Gram-negative and anaerobic cover is needed; the listed alternative is ampicillin plus gentamicin."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Transfusion in FPV is indicated when:","o":["Plasma protein is under 2 g/dL or WBC under 2000/uL","Plasma protein is over 5 g/dL","Only if anaemia is absent","Never"],"a":0,"e":"Whole blood or plasma at 20 mL/kg/day is indicated when plasma protein is under 2 g/dL or WBC under 2000/uL, monitoring for DIC."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Metoclopramide in feline FPV is:","o":["First-line","Avoided (CTZ receptors are less important in cats and it is contraindicated with GI haemorrhage)","Curative","Preferred over maropitant"],"a":1,"e":"Avoid metoclopramide in cats; prefer maropitant or ondansetron. Phenothiazines are also avoided (hypotension in dehydrated cats)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Feline recombinant interferon-omega in FPV:","o":["Consistently improves survival","Inhibits FPV in culture but leaves clinical signs and survival unchanged","Is a core vaccine","Replaces fluid therapy"],"a":1,"e":"It inhibits FPV in cell culture but has not changed signs or survival, so it is not cost-effective for routine shelter use."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which set of agents reliably inactivates FPV?","o":["Quaternary ammonium and alcohol","Bleach, potassium peroxymonosulfate, accelerated hydrogen peroxide and calcium hypochlorite","Alcohol hand sanitiser alone","Chlorhexidine"],"a":1,"e":"Bleach, KPMS, AHP and calcium hypochlorite work; quaternary ammonium and alcohol are ineffective against this hardy non-enveloped virus."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Quaternary ammonium against FPV is:","o":["Highly effective","Ineffective","The preferred agent","Effective only when warmed"],"a":1,"e":"Quats (and alcohol) are ineffective against FPV; use bleach, AHP, KPMS or calcium hypochlorite after removing organic matter."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Quarantine of apparently healthy, unexposed cats in shelters is:","o":["Routinely recommended","Not recommended, since it increases length of stay","Mandatory for 6 weeks","Required only for adults"],"a":1,"e":"Routine quarantine of healthy unexposed cats is avoided; prolonged length of stay is itself a major risk factor."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The high-risk exposed category for FPV is:","o":["Vaccinated adults","Kittens under 4 months (some say 5) regardless of vaccine status, and unvaccinated cats","Cats over 5 months vaccinated a week prior","Cats with a documented titre over 80"],"a":1,"e":"Kittens under 4 months and unvaccinated cats are high risk; low risk is over 5 months and vaccinated 5 to 7 days prior."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The standard shelter FPV vaccine is:","o":["Inactivated intranasal","MLV FVRCP given SC","A killed injectable only","No vaccine is used"],"a":1,"e":"MLV FVRCP given SC is the shelter standard: fast onset and better at overriding maternal antibody than killed vaccine."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Successful FPV vaccination produces what kind of immunity?","o":["Non-sterilising immunity that only reduces signs","Sterilizing immunity that prevents infection","Immunity lasting only 2 weeks","Purely cell-mediated immunity with no antibody"],"a":1,"e":"Unlike most CIRD agents and CIV, the FPV vaccine produces sterilizing immunity (like CDV), preventing infection of the host."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIV-positive cats requiring FPV protection should receive:","o":["MLV FPV vaccine","Inactivated FPV vaccine, since MLV can cause vaccine-induced panleukopenia","No vaccine ever","Intranasal MLV"],"a":1,"e":"FIV-positive cats get inactivated vaccine because MLV can precipitate vaccine-induced panleukopenia; FeLV-positive cats are given inactivated by default but the choice is balanced."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For an FPV outbreak, exposed unvaccinated adult cats and the booster choice should be:","o":["Canine MLV DAPP booster","MLV FVRCP booster (DAPP is the canine vaccine), if not vaccinated within the prior 14 days","No booster; rely on titres","An intranasal-only booster"],"a":1,"e":"Cats receive MLV FVRCP, not the canine DAPP; exposed adults are boosted with MLV FVRCP unless vaccinated in the previous 14 days."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"For FPV antibody titre risk assessment, the correct assay is:","o":["A canine CPV antibody kit","A validated feline-specific assay (e.g. Feline VacciCheck); HI titre 80 or higher is protective","Any parvovirus PCR","Fecal antigen ELISA"],"a":1,"e":"Canine CPV antibody kits cannot reliably detect FPV antibody in cats; use a feline-specific assay, with an HI titre of 80 or higher considered protective."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Passive immunisation for FPV provides protection lasting about:","o":["2 to 4 weeks, with active vaccination delayed 3 to 4 weeks afterward","Lifelong","24 hours","6 months"],"a":0,"e":"Anti-FPV (or hyperimmune CPV) serum gives 2 to 4 weeks of protection; delay active vaccination 3 to 4 weeks to avoid neutralisation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Kitten mortality with FPV is approximately:","o":["Under 10%","Over 90%","About 50%","Zero"],"a":1,"e":"Kitten mortality exceeds 90%, peaking at 3 to 5 months as maternal immunity wanes; peracute disease approaches 100%."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A haematologic poor-prognosis indicator in FPV is:","o":["Hypoalbuminaemia under 30 g/L","Mild eosinophilia","A normal WBC","Mild reticulocytosis"],"a":0,"e":"Hypoalbuminaemia under 30 g/L (with thrombocytopenia and hypokalaemia under 4 mmol/L) signals a poor prognosis and DIC risk."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Immunity after recovery from natural FPV infection is:","o":["Absent","Lifelong","About 2 weeks","Strain-specific and short"],"a":1,"e":"Recovery confers lifelong immunity to reinfection; a single serotype means broad, durable protection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV and FIV are classified as:","o":["FeLV oncornavirus and FIV lentivirus, both Retroviridae","Both herpesviruses","Both parvoviruses","Both coronaviruses"],"a":0,"e":"Both are retroviruses: FeLV is a gammaretrovirus (oncornavirus) and FIV is a lentivirus. Neither is zoonotic."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The three outcomes of FeLV infection are:","o":["Abortive, regressive, progressive","Wet, dry, latent","Acute, peracute, chronic","Primary, secondary, tertiary"],"a":0,"e":"FeLV resolves to abortive (cleared), regressive (provirus latent in marrow) or progressive (systemic, shedding)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Abortive FeLV infection shows:","o":["Antigen, IFA and PCR all negative","All tests positive","IFA only positive","Antigen positive, PCR negative"],"a":0,"e":"A robust immune response clears the virus before dissemination, so antigen, IFA and PCR are all negative; antibody is the only positive marker."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Regressive FeLV infection features:","o":["Provirus in marrow and organs, IFA negative, possible later reactivation","Continuous high shedding","No provirus present","Universally positive tests"],"a":0,"e":"Transient viraemia is suppressed but provirus persists in marrow; IFA is negative, PCR variable/low-copy, with low disease risk unless reactivated."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Progressive FeLV infection features:","o":["Spread to multiple organs with shedding; antigen, IFA and PCR generally positive","Viral elimination","IFA negative throughout","No shedding"],"a":0,"e":"The immune response fails; viraemia spreads, the cat sheds and is continuously infectious, and antigen, IFA and PCR are generally positive."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The primary FeLV transmission route is:","o":["Oronasal (grooming, shared dishes, nursing)","Bite wounds","Sexual","Aerosol over long distance"],"a":0,"e":"FeLV is the 'friendly-cat' virus, spread by social oronasal contact and efficient maternal/nursing transmission."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The primary FIV transmission route is:","o":["Deep bite wounds","Oronasal grooming","Aerosol","Fomites"],"a":0,"e":"FIV is the 'fighting-cat' virus, spread by deep bite wounds inoculating saliva into tissue."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIV-positive and FIV-negative cats can cohabit if:","o":["There is no fighting (compatible, non-aggressive)","They are vaccinated only","Never, under any circumstance","They share food bowls"],"a":0,"e":"Because FIV needs bite-wound inoculation, compatible non-aggressive cats can cohabit with little risk."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The zoonotic potential of FeLV and FIV is:","o":["None, neither is zoonotic","High for both","FeLV only","FIV only"],"a":0,"e":"Neither feline retrovirus is zoonotic."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIV infectivity in milk is counteracted by:","o":["Concurrent FIV antibody that protects nursing neonates","Heat denaturation","Stomach acid","Nothing; milk is highly infective"],"a":0,"e":"FIV antibody shed concurrently in milk neutralises the virus and protects most nursing neonates, unlike FeLV where nursing is a major route."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Pathognomonic signs of feline retroviral infection are:","o":["None; many cats are asymptomatic for long periods","Oral ulcers only","Cerebellar ataxia","A characteristic rash"],"a":0,"e":"There are no pathognomonic signs; disease comes from chronic effects (anaemia, neoplasia, inflammation, opportunistic infection)."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In neonatal cats, FeLV can cause:","o":["Fading kitten syndrome","Cerebellar hypoplasia","A limping syndrome only","Sterilising immunity"],"a":0,"e":"FeLV can cause fading kitten syndrome; most signs otherwise reflect chronic retroviral disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A 2-year-old cat with dyspnoea and a cranial mediastinal mass with pleural effusion most suggests:","o":["Progressive FeLV driving mediastinal/thymic T-cell lymphoma","Abortive FeLV with bacterial pyothorax","FIV-associated GI B-cell lymphoma","Regressive FIV with a mast cell tumour"],"a":0,"e":"FeLV classically causes mediastinal/thymic T-cell lymphoma in young cats; FIV is linked to B-cell lymphoma (GI/nasal) in older cats."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Point-of-care screening detects:","o":["Soluble FeLV p27 antigen and FIV antibody","FeLV antibody and FIV antigen","Virus culture for both","Proviral DNA for both"],"a":0,"e":"POC tests detect FeLV p27 antigen and FIV antibody; whole blood is more sensitive than serum/plasma for p27."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most sensitive sample for FeLV p27 detection is:","o":["Whole blood","Serum","Plasma","Saliva"],"a":0,"e":"Whole blood is more sensitive than serum or plasma for p27 antigen detection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"IFA for FeLV is:","o":["Negative in regressive and positive in progressive infection","Always positive once exposed","Always negative","Positive only in abortive infection"],"a":0,"e":"IFA detects p27 in leukocyte/platelet cytoplasm: negative in regressive infection, positive in progressive (marrow-infected) disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A low proviral copy number on quantitative FeLV PCR indicates:","o":["Regressive infection and prolonged survival","Progressive infection","Abortive infection","Vaccine interference"],"a":0,"e":"Low copy number marks regressive infection (prolonged survival); high copy number marks progressive infection with higher morbidity/mortality."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A kitten with a positive FIV antibody test should be:","o":["Retested until 5 to 6 months, when maternal antibody is gone","Euthanised","Adopted without retesting","Started on antivirals"],"a":0,"e":"Under 6 months a positive is almost always maternal antibody (vertical FIV is rare); retest until 5 to 6 months before calling it infected."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"After a known recent exposure, the recommended retest windows are:","o":["30 days for FeLV and 60 days for FIV","Same day for both","6 months for both","No retest is needed"],"a":0,"e":"FeLV p27 antigenaemia can take up to 30 days and FIV antibody up to 60 days; testing too early gives false negatives."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An unweaned kitten tests whole-blood FeLV-antigen positive at intake. The best action is:","o":["Euthanise immediately to protect the population","Isolate from unrelated litters and retest at adoption age","Declare abortive infection and clear it","Treat with an antiviral"],"a":1,"e":"Many FeLV-antigen-positive neonates revert by adoption age as early transient antigenaemia transitions to regressive infection (typically within ~16 weeks); never euthanise a healthy unweaned kitten on a single intake positive."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In the environment, FeLV and FIV are:","o":["Short-lived, not airborne, not spread by casual handling","Extremely hardy for months","Spore-forming","Spread readily by HVAC"],"a":0,"e":"Both are fragile retroviruses; no special sanitation is needed, and they are not airborne or spread by casual contact."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A key iatrogenic transmission route to prevent for FeLV/FIV is:","o":["Blood transfusion and contaminated invasive instruments","Shared air","Clean-glove handling","Sunlight exposure"],"a":0,"e":"Both transmit efficiently via transfusion and cross-contaminated invasive instruments."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Pooling samples or testing one cat as a proxy for a group is:","o":["Not appropriate; it reduces test sensitivity","Cost-effective and recommended","Required for group housing","Equivalent to individual testing"],"a":0,"e":"Pooling lowers sensitivity and proxy testing is invalid; test cats individually."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Before entering group housing, cats must be:","o":["FeLV-negative","FIV-positive","Untested but vaccinated","Older than 1 year"],"a":0,"e":"A negative FeLV result is required before group housing; FIV testing may be optional if cats are compatible and stress is low."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The FeLV vaccine is best described as:","o":["Non-core, for at-risk cats, given after determining status, from 8 weeks, 2 doses 3 to 4 weeks apart","Core for all cats","A treatment for infected cats","An intranasal modified-live product"],"a":0,"e":"FeLV vaccine is non-core for at-risk cats; determine status first (no value vaccinating infected cats), from 8 weeks, 2 doses 3 to 4 weeks apart."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The FeLV vaccine is given low on the left hind limb because:","o":["It absorbs faster there","A later injection-site sarcoma can be removed with clean margins by hindlimb amputation","It is less painful","It avoids lymph nodes"],"a":1,"e":"Distal-limb placement means an adjuvant-associated feline injection-site sarcoma can be excised with clean margins via amputation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIV vaccination in shelters is:","o":["Not recommended","Mandatory","Core for all cats","Required before adoption"],"a":0,"e":"FIV vaccine is non-core and not recommended in shelters: it covers only subtypes A and D and induces antibody indistinguishable from infection on common POC tests."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Outbreaks of FeLV or FIV in a shelter are:","o":["Not expected, given chronic infection and low transmission","Explosive and common","More likely than parvovirus","Seasonal"],"a":0,"e":"Both are chronic, low-transmission infections, so epidemic outbreaks are not expected; management focuses on testing and segregation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The effect of FeLV versus FIV on lifespan is:","o":["FeLV shortens lifespan; FIV is variable and often normal","Both always normal","Both always fatal within a year","FIV shortens lifespan; FeLV is normal"],"a":0,"e":"FeLV typically shortens lifespan (many die within ~5 years); FIV is variable and frequently normal."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is routine FeLV/FIV testing not recommended for TNR community cats?","o":["Retroviruses are zoonotic to trappers","Community seroprevalence mirrors owned cats, screening wastes resources, and sterilisation itself curbs transmission behaviours","Community cats cannot be infected","Testing always gives false positives outdoors"],"a":1,"e":"Positives do not add to the threat if cats remain outdoors; resources are better spent on sterilisation, which removes nursing (FeLV) and fight-bite (both) transmission."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIP is caused by:","o":["A non-enveloped DNA parvovirus","An enveloped RNA alphacoronavirus (FCoV)","A herpesvirus","A retrovirus"],"a":1,"e":"FIP is a complication of feline coronavirus, a large enveloped RNA alphacoronavirus prone to mutation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The prevailing explanation for how FIPV arises is:","o":["Horizontal transmission of FIPV between cats","Internal mutation of FECV to FIPV within an individual cat","A separate environmental virus","Vaccine reversion"],"a":1,"e":"The internal mutation theory: FECV mutates to macrophage-tropic FIPV within an individual cat, commonly involving the S gene and 3c/7a/7b."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most commonly implicated mutation site for the FECV-to-FIPV switch is:","o":["The spike (S) protein gene","The nucleocapsid gene only","No mutation occurs","The polymerase gene exclusively"],"a":0,"e":"The spike (S) protein gene (with accessory genes 3c, 7a, 7b) is most commonly implicated; S protein governs cell entry."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Primarily effusive (wet) FIP results from:","o":["Strong cell-mediated immunity","Strong humoral with weak or absent cellular immunity, via Type III hypersensitivity","Complete immunity","An IgE allergic response"],"a":1,"e":"Strong humoral plus weak cellular immunity produces immune-complex vasculitis (Type III hypersensitivity) and effusion; a strong cell-mediated response can prevent disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The proportion of FCoV-seropositive cats that develop FIP is:","o":["Under 3%","About 25%","About 50%","Over 90%"],"a":0,"e":"FIP is uncommon: under 3% of seropositive cats and fewer than 5% of shedders develop it."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FECV is transmitted mainly by:","o":["The oro-nasal/faecal-oral route, especially shared litter boxes","Aerosol over long distances","Biting insects","Sexual contact"],"a":0,"e":"FECV spreads oro-nasally via infected faeces, with shared litter boxes a key route in multi-cat settings."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Compared with adults, kittens 8 to 16 weeks shed FECV at levels about:","o":["The same","10,000 times higher","Ten times lower","Negligible"],"a":1,"e":"Primary shedding in kittens 8 to 16 weeks averages ~10,000 times that of adults, so mixing unrelated litters is discouraged."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIPV itself is:","o":["Readily transmitted cat to cat faecal-orally","Not transmitted faecal-orally (it cannot replicate in epithelial cells); horizontal spread is extremely rare","Airborne","Spread by fleas"],"a":1,"e":"FIPV has lost epithelial tropism, so it is not spread faecal-orally and is essentially non-contagious between cats."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A shelter FIP cluster usually reflects:","o":["A novel mutant virus spreading between cats","Husbandry and housing creating high FCoV loads and amplified risk factors","Vaccine failure","Contaminated food"],"a":1,"e":"Clusters reflect conditions that amplify FCoV exposure and host risk, not a contagious mutant virus."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A young cat has a classic FIP effusion (A:G 0.42) and a standard FCoV RT-PCR on the fluid is positive. The best interpretation is:","o":["Definitive for FIP, since FECV never leaves the gut","It confirms FCoV but does not prove mutation to FIPV, because FECV circulates in monocytes and reaches effusions","A guaranteed false positive from maternal antibody","Invalid, since RT-PCR detects only Type II"],"a":1,"e":"Because enteric FECV circulates in monocytes and reaches extra-intestinal sites, a positive standard FCoV PCR confirms exposure, not mutated FIPV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The RT-PCR plus S-gene-mutation assay has high specificity but low sensitivity mainly because:","o":["It detects only antibodies","The mutation is an individual, variable event (3c/7a/7b escape the primers) and it misses Type II FCoV","It cannot run on effusions","It requires whole blood"],"a":1,"e":"FIP mutations are individual and variable, so novel point mutations escape the S-gene primers, and the assay does not capture Type II FCoV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The definitive antemortem diagnostic test for FIP is:","o":["FCoV serology titre","Immunohistochemistry showing FCoV antigen within macrophages in pyogranulomatous lesions","A single positive blood RT-PCR","Rivalta test alone"],"a":1,"e":"Demonstrating viral antigen inside macrophages within classic lesions (IHC or direct immunofluorescence) is the gold standard, ruling out bystander enteric FCoV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The two clinical forms of FIP are:","o":["Acute and chronic","Effusive (wet) and non-effusive (dry)","Cardiac and renal","Ocular and neural only"],"a":1,"e":"FIP presents as effusive (wet) or non-effusive (dry), often with mixed features; the form reflects the immune response."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Neurologic signs in FIP occur primarily with the:","o":["Effusive form","Non-effusive form","Subclinical form","Carrier state"],"a":1,"e":"Neurological disease is mainly a non-effusive manifestation; ocular lesions occur in both forms."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A classic FIP effusion is:","o":["Thin, watery, highly cellular","Straw-yellow, viscous, high-protein, frothing when shaken, low cellularity","Frankly purulent","Chylous and milky"],"a":1,"e":"A modified-transudate/non-septic exudate: straw-yellow, viscous, protein over 3.5 g/dL, low cellularity, frothing on shaking."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"On FIP effusion analysis, which statement about the A:G ratio is correct?","o":["A:G over 1 confirms FIP","A:G under 0.5 has ~89% positive predictive value; A:G over 1 has ~91% negative predictive value","A:G is not useful in effusions","A:G under 0.5 rules out FIP"],"a":1,"e":"An effusion A:G under 0.5 has ~89% PPV for FIP; an A:G over 1 has ~91% NPV against it."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The Rivalta test for FIP effusions is best described as:","o":["High specificity, low sensitivity","High sensitivity (91-98%) but low specificity (66-80%), so a negative is reassuring but false positives occur with sepsis/neoplasia","Diagnostic on its own","Useless in cats"],"a":1,"e":"Rivalta is sensitive but not specific; a negative reliably lowers suspicion, while positives also occur in septic or neoplastic effusions."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Ocular signs in FIP include:","o":["Cataracts only","Uveitis, iritis, retinitis and keratic precipitates","No ocular involvement","Glaucoma only"],"a":1,"e":"Uveitis, iritis, retinitis and keratic precipitates occur, and ocular lesions are seen in both effusive and non-effusive forms."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Once clinical signs appear, untreated FIP mortality is:","o":["About 10%","Approaching 100%","About 50%","Zero with supportive care"],"a":1,"e":"Untreated FIP is nearly always fatal once signs appear, often within days to weeks."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The two antiviral agents central to modern FIP therapy are:","o":["GS-441524 (nucleoside analog) and GC376 (protease inhibitor)","Amoxicillin and gentamicin","Maropitant and ondansetron","Itraconazole and terbinafine"],"a":0,"e":"GS-441524 is a nucleoside analog and GC376 is a 3C-like protease inhibitor (your notes' 'GS-376' is a typo for GC376); remdesivir is the GS-441524 prodrug."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Historical prednisolone and cyclophosphamide therapy for FIP:","o":["Cures FIP","Slows progression without altering the ultimate outcome","Prevents infection","Provides sterilising immunity"],"a":1,"e":"These palliative drugs may slow progression but do not change the fatal outcome; modern antivirals do."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Per the most current status, FIP treatment in the US is:","o":["A fully FDA-approved drug","No FDA-approved drug exists, but compounded oral GS-441524 is legally obtainable under FDA enforcement discretion since June 2024","Banned entirely","Available only as a vaccine"],"a":1,"e":"There is still no FDA-approved FIP drug, but since 1 June 2024 the FDA exercises enforcement discretion allowing veterinary-prescribed compounded GS-441524. Confirm current status."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FCoV survives in a dry environment for up to:","o":["7 weeks","13 months","A few hours","A year"],"a":0,"e":"FCoV survives up to ~7 weeks dry, which underpins the conservative 2-month wait before introducing a new cat to a home where an FIP cat lived."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Because FCoV is an enveloped virus, shelter sanitation:","o":["Requires closing rooms for 7 weeks","Uses standard detergents/disinfectants that inactivate it immediately, so rooms are cleaned and reused promptly","Needs only sunlight","Is impossible"],"a":1,"e":"Enveloped FCoV is readily inactivated by standard shelter disinfectants; unlike the home 2-month rule, shelters clean, disinfect and reuse the space promptly."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most important sanitation focus for limiting FCoV load is:","o":["Air filtration","Litter-box management (frequent scooping and cleaning of scoops) and not mixing litters","Footbaths","UV lamps"],"a":1,"e":"Faecal-oral FECV load is controlled by litter-box hygiene, one litter per enclosure, and avoiding mixing of unrelated litters."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A shelter FIP outbreak (genetically unrelated cats) is defined as incidence greater than:","o":["1%","10%","25%","50%"],"a":0,"e":"In an unrelated shelter population, over 1% is an outbreak; a cattery threshold is over 10%, hoarding 5 to 10%."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"In a breeding cattery, an FIP outbreak is defined as incidence greater than:","o":["1%","10%","30%","50%"],"a":1,"e":"Related, densely housed cattery cats tolerate a higher baseline, so the outbreak threshold is over 10%."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FIP vaccination in shelters is:","o":["A core, effective control measure","Not useful; the one intranasal product shows minimal efficacy","Mandatory at intake","Required before group housing"],"a":1,"e":"The available intranasal FIP vaccine shows minimal efficacy and is not a useful shelter control measure; titres are also unhelpful."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The cornerstone of FIP outbreak management is:","o":["Mass antiviral treatment of every cat","Risk assessment, reducing environmental pathogen load, and a clean break","Permanent closure","Mass fecal RT-PCR with euthanasia of shedders"],"a":1,"e":"Management is risk assessment, lowering environmental FCoV, and a clean break between affected and new populations; mass PCR is not useful."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Greatest FIP risk is in cats aged:","o":["Up to 3 years, especially 4 to 16 months","Over 10 years","Any age equally","Only neonates"],"a":0,"e":"Risk concentrates under 3 years, especially 4 to 16 months; in Australia 80% of cases were under 2 years."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FHV-1 establishes latency primarily in the:","o":["Trigeminal ganglia and cool URT sites","Bone marrow","Intestinal crypts","Renal cortex"],"a":0,"e":"FHV-1 becomes latent in the trigeminal ganglia and cool URT tissues, reactivating with stress."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FCV is best described as:","o":["An enveloped DNA virus","A non-enveloped RNA virus with many strains in one serotype","A bacterium","A retrovirus"],"a":1,"e":"FCV is a non-enveloped, rapidly mutating ssRNA virus; one serotype but many antigenically distinct strains."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"After infection, the proportion of cats that become latent FHV-1 carriers is at least:","o":["20%","50%","80%","5%"],"a":2,"e":"At least 80% of infected cats become lifelong latent carriers, underlying the 50 to 97% seroprevalence."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Bordetella bronchiseptica predisposes to co-infection mainly by:","o":["Destroying respiratory cilia","Causing oral ulcers","Suppressing bone marrow","Inducing fever only"],"a":0,"e":"Bordetella destroys respiratory cilia, removing a key mucosal defence and predisposing to secondary infection."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A pathophysiologic reason perfect biosecurity cannot eliminate shelter URTD is:","o":["The virus is airborne over long distances","Stress reactivates latent FHV-1","Vaccines cause disease","Fomites are harmless"],"a":1,"e":"Stress-induced recrudescence of latent FHV-1 means new cases arise even with flawless biosecurity."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The most common route of URTD spread in shelters is:","o":["True long-distance aerosol","Fomites (surfaces, objects, hands, clothing)","Faecal-oral","Sexual"],"a":1,"e":"Fomite transmission dominates (other than FHV-1 recrudescence); true aerosol is unlikely."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Sneezed respiratory droplets travel approximately:","o":["1 to 1.3 metres","6 metres","10 metres","100 metres"],"a":0,"e":"Droplets travel ~1 to 1.3 m, so facing cage banks should be at least 1.3 m apart."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Regarding ventilation, feline URTD is:","o":["Airborne, needing separate per-cage ventilation","Not airborne, so separate per-cage ventilation is not necessary","Spread only through ducts","Eliminated by HEPA filtration"],"a":1,"e":"URTD is not airborne; good air quality matters but separate per-cage ventilation is not required."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FHV-1 survives in a damp environment for up to about:","o":["18 hours","28 days","13 months","1 year"],"a":0,"e":"FHV-1 is fragile, surviving ~18 h in damp conditions and less when dry; it is easily disinfected."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"FCV survives at room temperature for at least:","o":["18 hours","28 days","A few minutes","13 months"],"a":1,"e":"FCV is hardy, surviving at least 28 days at room temperature, which drives its fomite spread."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Oral and tongue ulcers are most characteristic of:","o":["FHV-1","FCV","Bordetella","Mycoplasma"],"a":1,"e":"Tongue and oral ulcers are classic for FCV; FHV-1 favours corneal/dendritic ulcers."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Dendritic corneal ulcers point to:","o":["FHV-1","FCV","Chlamydia","Influenza"],"a":0,"e":"Dendritic corneal ulceration is characteristic of FHV-1 keratitis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Chemosis with conjunctivitis progressing from unilateral serous to bilateral mucopurulent suggests:","o":["Chlamydia felis","Streptococcus canis","Influenza","FCV"],"a":0,"e":"Chemosis with that progression is characteristic of Chlamydia felis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Febrile limping syndrome is uniquely associated with:","o":["FHV-1","FCV","Mycoplasma","Bordetella"],"a":1,"e":"Self-limiting febrile lameness after infection or vaccination is unique to FCV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Virulent systemic FCV is presumptively diagnosed by the triad of:","o":["Mild sneezing, normal temperature, single case","High mortality, severe vasculitis/cutaneous oedema (head/paws), and rapid in-enclosure transmissibility","Cerebellar ataxia, low WBC, and chronic course","Oral ulcers alone"],"a":1,"e":"VS-FCV needs high mortality, severe vasculitis with head/paw oedema, and rapid spread; routine FCV vaccine does not protect."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The antiviral and dose used for FHV-1 is:","o":["Famciclovir 90 mg/kg PO q8h","Amoxicillin 22 mg/kg q12h","Gentamicin 4.4 mg/kg q12h","Itraconazole 10 mg/kg SID"],"a":0,"e":"High-dose famciclovir (90 mg/kg PO q8h) outperforms low dose for FHV-1; topical idoxuridine/cidofovir treat keratitis."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The first-choice antibiotic for M. felis, Bordetella and C. felis is:","o":["Doxycycline 5 mg/kg q12h or 10 mg/kg q24h","Amoxicillin alone","Cefovecin","Gentamicin"],"a":0,"e":"Doxycycline is first-line empiric therapy for acute bacterial feline URTD; give liquid with a water/food flush."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Penicillins and cephalosporins are ineffective against Mycoplasma because:","o":["Mycoplasma is a virus","Mycoplasma has no cell wall, so beta-lactams that target peptidoglycan cannot work","They are inactivated by feline saliva","Mycoplasma is intracellular only"],"a":1,"e":"Mycoplasma lacks a cell wall, so peptidoglycan-targeting beta-lactams fail; use doxycycline or a fluoroquinolone."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Amoxicillin is an acceptable first-line URTD choice only when:","o":["Mycoplasma or Chlamydia are not suspected","The cat has oral ulcers","Always, it covers everything","The cat is febrile"],"a":0,"e":"Amoxicillin (or amoxicillin-clavulanate) is acceptable only when Mycoplasma and Chlamydia are not suspected."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"To prevent oesophageal stricture, doxycycline should be:","o":["Given as a dry tablet","Given as a liquid followed by water or food","Given on an empty stomach with no follow-up","Crushed into dry food only"],"a":1,"e":"Doxycycline hyclate tablets can cause feline oesophageal strictures; use the liquid and follow with water or food."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Lack of response to URTD treatment within 5 to 7 days indicates:","o":["The protocol is working","The need for further diagnostic workup","Immediate euthanasia","Doubling every drug dose"],"a":1,"e":"No response in 5 to 7 days suggests additional medical or drug-related problems needing further workup."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Effective disinfectants against FCV are:","o":["Quaternary ammonium","1:32 bleach, potassium peroxymonosulfate or accelerated hydrogen peroxide","Alcohol sanitiser alone","Chlorhexidine"],"a":1,"e":"Non-enveloped FCV resists quats and alcohol; use 1:32 bleach, KPMS or AHP."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Alcohol-based hand sanitiser in feline URTD is:","o":["Fully effective against all agents","Ineffective against FPV and of limited efficacy against FCV (non-enveloped capsids resist alcohol)","The preferred method over handwashing","Effective only when warmed"],"a":1,"e":"Alcohol cannot disrupt non-enveloped capsids; soap-and-water washing or AHP wipes are mandatory for FCV/FPV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A cat given an intranasal MLV FVRCP vaccine 5 days ago has a positive FHV-1 and Mycoplasma PCR. The best interpretation is:","o":["Definitive active FHV-1 field infection requiring antivirals","The FHV-1 positive may be recent IN vaccine shedding (false-positive for 1 to 3 weeks), and Mycoplasma is often normal flora, so PCR does not prove causation","Mycoplasma is the sole primary pathogen, start amoxicillin for 4 weeks","The swab type invalidated the test"],"a":1,"e":"IN MLV vaccination causes false-positive FHV-1/FCV PCR for 1 to 3 weeks, and a Mycoplasma-positive does not prove primary disease."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The single greatest risk factor for URTD in shelter cats is:","o":["Length of stay","Coat colour","Microchip status","Sex"],"a":0,"e":"Length of stay is the single greatest risk factor; URTD risk rises over the first 2 weeks then stabilises around 3 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A staff workflow that lowers clinical URTD rates is:","o":["One person doing all wards","Separating staff by section","Rotating staff hourly between wards","Sharing equipment between wards"],"a":1,"e":"Dedicating/separating staff by section reduces fomite spread and was associated with significantly lower URTD rates."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Group housing of cats should use groups of:","o":["5 or fewer, stable","20 or more","Any size","Singletons only"],"a":0,"e":"Keep groups small (5 or fewer) and stable; regrouping is associated with FHV-1 reactivation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"The ideal management of kittens too young for adoption is:","o":["Group housing in the shelter","Foster care, bypassing the shelter environment","Prolonged quarantine","Co-housing with adults"],"a":1,"e":"Kittens too young to adopt should go directly to foster, avoiding the high-shedding shelter environment."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Routine vaccination of shelter cats against Bordetella and Chlamydia is:","o":["Recommended for all","Not recommended","Mandatory at intake","Required before group housing"],"a":1,"e":"Routine Bordetella and Chlamydia vaccination is not recommended for shelter cats; core MLV FVRCP is given at intake."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Why is routine 14-day quarantine of healthy incoming cats generally advised against?","o":["It is too cheap to bother with","It increases length of stay, the single greatest URTD risk factor; prioritise intake vaccination, good housing and low LOS instead","Quarantine spreads disease faster","It prevents adoption permanently"],"a":1,"e":"Routine quarantine raises LOS (the top risk factor); better to vaccinate at intake, house well and minimise LOS."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A dog imported from Mexico has a history of late-term abortion. An in-clinic rapid slide agglutination test (RSAT) returns positive for Brucella canis. What is the correct next step?","o":["Euthanize immediately based on the RSAT result","Isolate the dog and run a confirmatory test (AGID or culture/PCR) before making a disposition decision","Treat with doxycycline for 7 days and retest","Move the dog to the general population and observe for 30 days"],"a":1,"e":"The RSAT has a HIGH false-positive rate. Isolation is required, but euthanasia or definitive management decisions require confirmation by AGID, culture, or PCR. Never euthanize based on RSAT alone."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which statement about Brucella canis transmission in a shelter is correct?","o":["B. canis is airborne and can spread between kennels via the HVAC system","Transmission requires contact with infectious secretions (semen, vaginal discharge, aborted fetuses, urine); it is NOT airborne under typical shelter conditions","B. canis is transmitted by fleas and requires flea control as the primary intervention","B. canis is not zoonotic and poses no staff risk"],"a":1,"e":"B. canis is NOT airborne. Transmission requires direct contact with reproductive secretions, aborted material, or blood. It IS zoonotic — staff who handled aborted fetuses or vaginal discharge should be referred to occupational health."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A shelter dog confirmed positive for Brucella canis is presented for disposition. Which statement about treatment and outcomes is correct?","o":["B. canis is reliably cured by a 7-day course of amoxicillin-clavulanate","Treatment with doxycycline + rifampin for 4–6 weeks is often recommended, but B. canis is intracellular and not reliably cleared — relapses are common and euthanasia is often recommended in a shelter context","The dog can be spayed/neutered and immediately cleared for adoption","B. canis is a notifiable disease nationally, requiring immediate USDA reporting"],"a":1,"e":"B. canis is intracellular and not reliably eliminated by any antibiotic protocol; relapse rates are high. In the shelter setting, euthanasia is often the recommended outcome given the zoonotic risk and difficulty of maintaining a lifetime-carrier quarantine. Spay/neuter reduces but does not eliminate shedding."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which diagnostic test is the gold standard for detecting Mycoplasma haemofelis infection?","o":["Direct blood smear showing organisms on RBC surfaces","PCR for hemoplasma (blood); most sensitive and specific; can speciate","Routine fecal flotation","In-house slide agglutination test"],"a":1,"e":"PCR is the gold standard. Blood smear sensitivity is LOW — parasitemia is cyclic and organisms are absent on the smear during non-parasitemic phases. Howell-Jolly bodies and stain artifacts can also mimic hemoplasma on smear."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A 3-year-old FIV-positive cat presents with severe lethargy, pale mucous membranes, PCV of 12%, and PCR-confirmed Mycoplasma haemofelis. Which treatment approach is correct?","o":["Prednisone alone; antibiotics are ineffective against Mycoplasma","Doxycycline 10 mg/kg PO once daily × 28 days; add prednisolone if immune-mediated hemolysis is suspected; consider blood transfusion if PCV <15%","Metronidazole for 7 days","Ronidazole 30 mg/kg once daily for 14 days, as for Tritrichomonas"],"a":1,"e":"Doxycycline (once daily in cats to reduce esophageal stricture risk from twice-daily) is first-line. Prednisolone is added if an immune-mediated component is present. Blood transfusion is indicated for severe anemia (PCV <15%). Ronidazole is for Tritrichomonas foetus, not hemoplasma."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which statement about Mycoplasma haemofelis and flea control in shelters is correct?","o":["Fleas are not a significant route of hemoplasma transmission — bite wounds are the primary route","Fleas (Ctenocephalides felis) are the primary transmission vector; strict flea control is the most important prevention measure in a shelter","Hemoplasma is transmitted by ticks, not fleas","Hemoplasma vaccination is available and provides complete protection"],"a":1,"e":"Ctenocephalides felis (cat flea) is the primary vector for M. haemofelis. Flea-free shelter status substantially reduces hemoplasma transmission. Blood donor cats must also be PCR-screened before use."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An unvaccinated 8-week-old puppy presents with acute, hemorrhagic diarrhea, vomiting, lethargy, and a CBC showing leukopenia. What is the highest-priority first action?","o":["Run a Giardia ELISA and treat empirically with fenbendazole","Immediately isolate the puppy and run a CPV fecal antigen ELISA — treat as CPV until proven otherwise","Move the puppy to the general population pending culture results","Administer oral metronidazole and observe for 48 hours before testing"],"a":0,"e":"An unvaccinated puppy with hemorrhagic diarrhea, vomiting, leukopenia, and lethargy is CPV until proven otherwise. Immediate isolation and CPV fecal antigen test are the first steps — delay in isolation allows exposure of susceptible animals in the population."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A recently vaccinated dog tests positive on the IDEXX SNAP CPV fecal antigen test 3 days after receiving an MLV DAPP vaccine. How should this result be interpreted?","o":["This confirms active CPV infection; begin intensive treatment immediately","This is likely a vaccine-induced false positive; MLV CPV vaccine virus is shed in feces for up to 2 weeks post-vaccination; clinical signs and CBC (leukopenia) are needed to distinguish from true CPV","The test is unreliable and should be discarded","Transfer to an emergency hospital immediately"],"a":1,"e":"MLV CPV vaccine virus is shed in feces for up to 5 days and occasionally up to 2 weeks after vaccination, causing false-positive antigen tests. Clinical signs (severity of GI illness, leukopenia on CBC) and PCR confirmation are needed when the result is ambiguous."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"During a shelter diarrhea cluster affecting 5 dogs in the same intake ward, which disinfectant is appropriate for both Salmonella and CPV contamination?","o":["Quaternary ammonium compounds (quats) at standard dilution","Accelerated hydrogen peroxide (AHP) 1:32 with 10 min contact time","Bleach 1:100 with 5 min contact time","Isopropyl alcohol 70%"],"a":1,"e":"AHP 1:32 with ≥10 min contact is effective against both CPV (non-enveloped) and Salmonella. Quats FAIL against CPV. Bleach at 1:100 is too dilute for CPV (1:32 required). Alcohol does not reliably kill non-enveloped viruses like CPV."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Which pathogen causing feline diarrhea requires 6% hydrogen peroxide or steam cleaning because standard bleach dilutions are ineffective?","o":["Tritrichomonas foetus","Campylobacter jejuni","Giardia duodenalis","Cryptosporidium spp."],"a":3,"e":"Cryptosporidium oocysts are highly resistant to chlorine disinfectants including standard bleach dilutions. Steam (≥60°C) or 6% hydrogen peroxide (30 min contact) are required. This is the most challenging pathogen to decontaminate in a shelter."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A long-term cat ward sees an abrupt URI spike during a winter intake surge. Sanitation is unchanged and no new pathogen entered, but major construction (daily drilling, vibrations) just began next door. The primary driver is:","o":["Increased agent virulence from structural shifting of the building","Environmental stressors (loud, unfamiliar noise; unpredictable events) triggering host immunosuppression and recrudescence of latent carriers such as FHV-1","Mechanical vectors (fleas, mosquitoes) failing to circulate fresh air","Mutation of Mycoplasma into cell-wall-producing bacteria from vibration"],"a":1,"e":"Stress is a host factor in the epidemiological triad. Noise and unpredictability immunosuppress the resident population, recrudescing latent FHV-1 — an 'outbreak' with no new pathogen and identical sanitation."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"Thirty cats from a hoarding case arrive; 80% have severe painful chronic stomatitis and suspected FCV carriage. Before committing to long-term on-site mass treatment, the most critical questions are:","o":["Which chew toys are safe, and can nail trims precede antibiotic choice?","How hard is the agent to kill with alcohol, and will the cats need intensive grooming?","Welfare during prolonged treatment, prognosis for recovery, and whether resources and funds allow treatment without compromising basic care for the general population","Can the whole cohort go straight to general adoption to cut length of stay?"],"a":2,"e":"Capacity for Care is dynamic: if treating the infected cohort drops baseline care of the general population below minimum standards, C4C is exceeded. Welfare, prognosis and resource impact are the decisive questions."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An intake room is contaminated with feline calicivirus (non-enveloped) and feline panleukopenia virus. A technician proposes a quaternary ammonium compound because it is cheap and pleasant-smelling. You should:","o":["Approve — quats reliably disrupt the capsids of non-enveloped shelter pathogens","Deny — non-enveloped viruses resist quats; use an oxidizing disinfectant (accelerated hydrogen peroxide or 1:32 bleach)","Switch to an alcohol hand-rub wipe-down, which sterilizes against parvovirus","Skip chemical disinfection and rely on daily brushing/grooming"],"a":1,"e":"Non-enveloped viruses (FCV, FPV/parvo) lack a lipid envelope and resist quats and alcohol. Effective decontamination requires an oxidizing agent — AHP or 1:32 bleach."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An FPV epidemic curve shows a massive sharp peak on Day 1 with gradual decline, then from Day 8 a series of successively higher peaks ~3–4 days apart. Interpretation:","o":["Continuous common source that has mutated into an airborne pathogen","Began as a point source (e.g., one infectious litter admitted together) and, from an isolation/sanitation failure, transitioned to a propagated, animal-to-animal outbreak","Data error — FPV never causes multiple peaks because of maternal antibody","Steady-state fluctuations proving the quat disinfectant neutralized the virus"],"a":1,"e":"A point-source spike followed by successive incubation-spaced peaks signals transition to a propagated outbreak — isolation or sanitation has broken down."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"During a CDV outbreak, an asymptomatic 6-month-old dog housed with a shedding puppy has a strongly positive point-of-care CDV antibody titer. Best management:","o":["14-day quarantine, because positive titers over 5 months are usually false positives","Immediate euthanasia under depopulation guidelines","Because he is over 5 months and clinically normal, the positive titer correlates strongly with protection — categorize low risk and move toward adoption without mandatory quarantine","Invalid test — redraw blood only 14 days after exposure ends so maternal antibody wanes"],"a":2,"e":"In asymptomatic animals over 5 months, a positive CDV/CPV/FPV titer correlates with near-sterilizing protection. Maternal-antibody skew is the concern only in animals under 5 months."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"During concurrent S. zooepidemicus and FCV outbreaks, the supervisor orders accelerated hydrogen peroxide mixed at triple label concentration. Why intervene?","o":["Tripling concentration converts non-enveloped calicivirus into a point-source pathogen","Chemical agents lose all efficacy against Gram-positives at higher concentration","Stronger-than-label disinfectant is not more effective and causes harm — caustic residues irritate the respiratory tract and mucosa, increasing host susceptibility","Changing concentration is only permitted for vector-borne mange"],"a":2,"e":"Over-concentrating disinfectant adds no benefit and leaves caustic residues that damage respiratory and ocular mucosa and paw pads, raising susceptibility and mimicking a URTD/CIRD outbreak."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A county shelter legally obligated to accept strays has a VS-FCV outbreak (50% mortality), exceeded isolation capacity, and maxed staff hours. The director demands total depopulation of all cats. Per ASV standards:","o":["Approve immediate building-wide depopulation as the standard response to high-morbidity outbreaks","Deny depopulation as the initial response — implement cohort risk stratification, create a clean break, use titers where appropriate, and consult municipal/legal counsel to temporarily restrict or divert intake while arranging offsite options","Stop all data collection and run PCR panels on healthy dogs","Open communal rooms to the public to speed adoptions and reduce crowding"],"a":1,"e":"Depopulation is a last resort. The alternative is cohort stratification (affected/exposed/unexposed), a clean break, titer triage, and — given a legal intake mandate — working with administrators and counsel to restrict or divert intake."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A vet uses an FDA-approved human antibiotic extra-label for deep pyoderma in 45 confiscated dogs (no veterinary alternative). Which statement on records/labeling is accurate?","o":["Shelter ownership exempts the vet from any individual drug records","ELDU records (condition treated, species, dosage, duration, number of animals) must be kept at least 2 years and made available to the FDA on request","Any volunteer may initiate the extra-label regimen without veterinary authorization","An NPI number must first be obtained from the DEA before dispensing"],"a":1,"e":"AMDUCA requires a valid VCPR, 2-year ELDU record-keeping (species, condition, dosage, duration, animal counts) available to the FDA, and proper labeling. Laypersons cannot initiate ELDU."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A technician asks to give the full daily dose of an oral beta-lactam as one large q24h bolus to save handling. You should:","o":["Approve — beta-lactams are concentration-dependent and best when peak is 8–10× MIC","Approve — penicillin frequency does not affect efficacy as long as AUC/MIC is 30–100","Deny — beta-lactams are time-dependent (Time > MIC); efficacy needs unbound drug above MIC for ~half the dosing interval, so consolidating doses causes failure","Deny — beta-lactams use oxygen-dependent transport active only in early morning"],"a":2,"e":"Beta-lactams are time-dependent: keep unbound concentration above MIC for ≥40–50% of the interval. A single large bolus lets levels fall below MIC and fails. Concentration-dependent (high peak) killing is the aminoglycoside pattern."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"A director wants to replace an FDA-approved ophthalmic ointment with a paste mixed by a volunteer from bulk raw drug powders bought online. The primary hazard is:","o":["Bulk-compounded products skip standard manufacturing requirements, risking improper potency/safety that prolongs suffering, lengthens treatment and raises total costs","Bulk compounding is legal for food animals but banned for cats","Mixing bulk drugs converts acquired resistance into innate structural resistance","The FDA requires bulk-compounded drugs to be exact copies of commercial products"],"a":0,"e":"Compounding from bulk raw ingredients bypasses FDA manufacturing/potency standards. Poor potency causes treatment failure and more suffering, ultimately driving costs up — the opposite of the intended saving."},{"type":"mcq","domain":"Physical Health","sub":"Infectious Disease","q":"An isolate's MIC is well below the fluoroquinolone breakpoint, yet dogs with hemorrhagic pneumonia fail to improve on correct dosing. The most logical explanation is:","o":["Susceptibility testing has 0% true correlation with in vivo response","Fluoroquinolones lose all activity if given more often than every 48 h","The drug fails to penetrate the consolidated lung tissue, or is inactivated within the purulent microenvironment of the lesions","Innate resistance from an unmapped lack of cell walls"],"a":2,"e":"Susceptible-in-vitro can still fail in vivo: anatomical barriers (poor penetration of consolidated lung/sanctuary sites) and microenvironmental inactivation (purulent debris, low-O2/acidic foci) are the classic reasons."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Why must visible organic matter be removed before any soap or disinfectant is applied?","o":["It preserves the stainless appearance for public viewing","Most detergents and disinfectants are completely or partly inactivated by organic material such as feces, urine, food and soil","Mechanical removal forces bacteria into resistant spores","Organic debris changes ward humidity and accelerates viral mutation"],"a":1,"e":"Organic matter physically shields microbes and chemically neutralizes many products, so gross removal must come first."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Sanitation is best defined as:","o":["Destruction of all pathogens including spores","The manual removal of debris only","The combination of cleaning and disinfection","Application of ultraviolet light to surfaces"],"a":2,"e":"ASV defines sanitation as cleaning plus disinfection, two separate steps even with a combination product."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"According to the ASV, true sterilization of cage and kennel surfaces:","o":["Is achieved with 1:32 bleach","Does not occur","Occurs only with steam","Is the goal of routine daily cleaning"],"a":1,"e":"The ASV states plainly that true sterilization of cage and kennel surfaces does not occur; that language belongs to autoclaved instruments."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Detergents and degreasers can remove up to what proportion of environmental pathogens before any disinfectant is applied?","o":["About 50%","About 75%","Up to 90%","99.9%"],"a":2,"e":"Detergents break down oil and grime so debris can be rinsed away, removing up to 90% of environmental pathogens."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The recommended ASV order of cleaning, from first to last, is:","o":["Unhealthy animals, then healthy adults, then puppies and kittens","Healthy puppies and kittens, then healthy adults, then unhealthy animals","Newest intakes, then oldest residents","By proximity to the front intake office"],"a":1,"e":"Move from least likely to shed toward most likely, protecting the most susceptible animals."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Adequate sanitation CANNOT be accomplished by:","o":["Cleaning then disinfecting for the full contact time","Using water alone, or spraying and quickly wiping off a disinfectant","Removing organic matter first","Following the label dilution"],"a":1,"e":"Water alone, spray-and-wipe, or a no-detergent disinfectant used without cleaning first all fail to sanitize."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Industry guidelines recommend a minimum of how much time per animal per day for routine enclosure cleaning?","o":["About 3 minutes","About 9 minutes","About 20 minutes","About 45 minutes"],"a":1,"e":"NACA guidelines cite a minimum of about 9 minutes per animal per day, useful for staffing calculations."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Even with a labeled detergent-disinfectant combination product, cleaning and disinfection:","o":["Become a single combined step","Remain two separate steps","Become unnecessary","No longer require contact time"],"a":1,"e":"Cleaning and disinfection are conceptually and practically separate steps regardless of the product used."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The key shelter limitation of quaternary ammonium compounds is that they:","o":["Are corrosive to metal","Do not reliably eliminate non-enveloped viruses (parvo, panleukopenia, calici) despite label claims","Have no detergent activity","Are unstable after 10 minutes"],"a":1,"e":"Multiple independent studies show quats fail against non-enveloped viruses even when the label claims otherwise."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Which statement about sodium hypochlorite (bleach) is accurate?","o":["It is ineffective against parvovirus","It is effective against FPV, CPV, FCV and ringworm but is inactivated by organic matter and has no detergent action","It is a strong detergent","It stays stable for about 90 days once diluted"],"a":1,"e":"Bleach is broadly virucidal and fungicidal but has no detergent action and is readily inactivated by organic matter, so cleaning must come first."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Once diluted, bleach and calcium hypochlorite remain stable for about:","o":["90 days","7 days","24 hours","1 hour"],"a":2,"e":"Chlorine dilutions are short-lived (about 24 hours) versus 7 days for potassium peroxymonosulfate and about 90 days for accelerated hydrogen peroxide."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Regarding ringworm, potassium peroxymonosulfate (Virkon, Trifectant) is best described as:","o":["Never effective against dermatophytes","Effective at about 2% concentration with appropriate contact time","Effective only at a 1:10 dilution","Effective only when used as a footbath"],"a":1,"e":"The ASPCA Pro reference and ASV list it as effective against dermatophytes at about 2%, correcting the common note that it is ringworm-negative."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Which group of products is EFFECTIVE against non-enveloped viruses per the ASPCA Pro reference?","o":["Quats and chlorhexidine","Accelerated hydrogen peroxide, potassium peroxymonosulfate, calcium hypochlorite and bleach","Phenols and alcohols","Aldehydes only"],"a":1,"e":"The oxidizers and chlorine-releasing products clear non-enveloped viruses; quats, biguanides, phenols and alcohols do not reliably do so."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Cats are particularly sensitive to which class, which must not be used where cats are housed?","o":["Quaternary ammonium compounds","Phenols such as Lysol and Pine-Sol","Accelerated hydrogen peroxide","Bleach at 1:32"],"a":1,"e":"Phenolic disinfectants are toxic to cats (feline glucuronyl transferase deficiency slows clearance) and are excluded from cat-housing areas."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Which products require NO rinse after the contact time per the ASPCA Pro reference?","o":["Bleach and calcium hypochlorite","Accelerated hydrogen peroxide and potassium peroxymonosulfate","Quats","All chlorine products"],"a":1,"e":"AHP and potassium peroxymonosulfate are listed as no-rinse, whereas quats, calcium hypochlorite and bleach require rinsing."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Several cats develop fever, oral and skin ulceration, ocular lesions and respiratory signs after cage disinfection. The first operational cause to rule out is:","o":["Virulent systemic calicivirus only","Quaternary ammonium compound toxicity from improper dilution or inadequate rinsing","Bleach used at 1:32","Ringworm"],"a":1,"e":"Quat toxicity mimics virulent calicivirus; the clue is the cleaning process, and revising it resolves new cases quickly."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"An enclosure must be completely sanitized (deep cleaned) between different occupants:","o":["Only if visibly soiled","Even after brief use, even if not visibly soiled, and even if the animal seemed healthy","Only weekly","Only during a declared outbreak"],"a":1,"e":"Animals shed pathogens without signs, so a full deep clean is required between occupants regardless of appearance."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"A documented advantage of spot cleaning for cats is that it:","o":["Guarantees daily sterilization","Reduces handling and stress, saves time and chemical, lowers fomite transmission and preserves familiar scent","Eliminates the need for clean bowls","Forces the cat to live in a carrier"],"a":1,"e":"Spot cleaning is less stressful and lower-risk, and is especially valuable for shy cats and stress-worsened disease such as feline respiratory infection."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"It is unacceptable to:","o":["Use a detergent before disinfecting","Spray or hose a primary enclosure while the animal is inside it","Dry the cage before returning the animal","Place a cat in a carrier during deep cleaning"],"a":1,"e":"Spraying enclosures with animals inside causes distress and contamination; remove animals from nearby compartments when overspray is likely."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Mop heads must be:","o":["Reused across rooms as long as they stay wet","Disposed of, or sanitized and dried, between uses, including between products and housing areas","Stored inside food bins","Used as the main tool inside cat cages"],"a":1,"e":"Mops harbor pathogens; ideally mopping is avoided, and mop heads are decontaminated between products and areas."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"A biological limitation of dishwashers for bowls is that they:","o":["Reliably kill parvovirus","Reach high temperatures that destroy most pathogens but may not destroy non-enveloped viruses, so apply a disinfectant after the cycle","Warp all stainless bowls","Increase pathogen mutation rates"],"a":1,"e":"Heat destroys most pathogens but parvovirus may survive, so a disinfectant step after the cycle is recommended."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Recent dermatophyte laundering evidence (Moriello) indicates the most decisive factor for removing Microsporum canis spores from fabric is:","o":["Very hot water alone","Washing twice (mechanical washing and rinsing) without overloading the machine","Bleach alone in cold water","A single short cycle"],"a":1,"e":"The mechanical double wash is decisive; water temperature and bleach were not the critical variables when items were washed twice."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Recommended flooring for the interior of dog kennels is:","o":["Carpet","Resinous epoxy or urethane coatings over concrete (polished sealed concrete suits corridors but not kennels)","Unsealed asphalt","Porous tile with sand grout"],"a":1,"e":"Epoxy or urethane coatings give a durable, non-porous, disinfectable kennel surface; polished sealed concrete is for high-traffic corridors."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Food and water bowls should be sanitized:","o":["In the same basin as litter pans to save time","At a different location or time than litter pans to prevent cross-contamination","Only once weekly","Without any rinse"],"a":1,"e":"Separating bowl and litter-pan sanitation prevents fecal cross-contamination of feeding items."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"A fomite is:","o":["A type of non-enveloped virus","An inanimate object (hands, clothing, bowls, equipment) that can carry pathogens and transmit disease","A class of disinfectant","A vaccine adjuvant"],"a":1,"e":"Fomites are contaminated objects; hands, clothing, bowls, litter boxes, toys and equipment are the everyday shelter examples."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The current ASV position on footbaths is that they:","o":["Are a reliable primary biosecurity control","Must not be relied on for infectious disease control, because adequate contact time is impractical and organic debris inactivates the disinfectant","Sterilize boots in two seconds","Should replace boot changes in isolation"],"a":1,"e":"The 2022 ASV standard is that footbaths are unreliable and should not be depended on; dedicated boots or disposable covers are preferred."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The minimum acceptable hand hygiene station provides:","o":["A shared cloth towel only","Hand sanitizer with at least 60% alcohol (a sink with soap, water and single-use towels is ideal)","Plain water only","A footbath"],"a":1,"e":"At minimum, at least 60% alcohol sanitizer; ideally a sink with soap, running water and single-use towels."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Hand sanitizer (more than 60% alcohol) should be used:","o":["On heavily soiled hands during cleaning","Only on hands that are visibly clean, and never as the sole means of hand hygiene","As a substitute for handwashing in all cases","Only between low-risk rooms"],"a":1,"e":"Alcohol gels fail on soiled hands and against parvovirus, calicivirus and ringworm, so they are for visibly clean hands and not the sole method."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Within the shelter, who is most likely to move pathogens around during daily tasks?","o":["Visitors","Shelter personnel performing daily care","Adopters","Delivery drivers"],"a":1,"e":"Staff handle many animals during care, so their protocols (PPE, hand hygiene) matter most for transmission."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Outdoor surfaces such as gravel, dirt and grass:","o":["Are easily disinfected with 1:32 bleach","Cannot be disinfected, so covers are rotated or replaced and access is managed","Require daily bleaching","Are inherently sterile in sunlight"],"a":1,"e":"These surfaces cannot be disinfected; manage them by rotating covers and restricting access to vaccinated, dewormed, healthy adults."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The recommended approach to rodents and insects in the shelter is:","o":["Maximal routine pesticide use","An integrated pest management plan, with all food protected in sealed bins and spills cleaned promptly","Ignoring them unless animals get sick","Traps only in summer"],"a":1,"e":"Pests harbor pathogens; IPM plus protected food storage reduces both infestation and chemical use."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Even with excellent sanitation and facility design, disease control still fails if:","o":["Staff wear PPE","The population is not well managed (capacity and flow)","Bowls are washed daily","Floors are epoxy-coated"],"a":1,"e":"Population management underpins biosecurity; no amount of cleaning compensates for crowding and poor flow."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The routine contact time for accelerated hydrogen peroxide (AHP, e.g. Rescue) against most shelter pathogens is:","o":["30 minutes","10 minutes","1 minute","5 seconds"],"a":2,"e":"AHP's key advantage is a 1-minute contact time for most pathogens (extend to 5 minutes for ringworm). This makes it practical for high-turnover shelter environments where long contact times are not feasible."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"The correct bleach dilution and contact time for a confirmed CPV (parvovirus) outbreak in a shelter enclosure is:","o":["1:100 for 1 minute","1:32 for 30 seconds","1:10 for 10 minutes","1:64 for 5 minutes"],"a":2,"e":"For CPV/FPV outbreaks, bleach should be used at 1:10 (rather than the routine 1:32) with a 10-minute contact time on a pre-cleaned, organic-matter-free surface."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"A shelter uses bleach at the correct 1:32 dilution but the water temperature in the ward is 5 °C in winter. Why might disinfection still fail?","o":["Cold water inactivates bleach chemically","Low temperatures can approximately double the contact time needed for disinfectants to achieve their claimed kill, so the standard 10-minute contact becomes inadequate","Cold water prevents bleach from diluting correctly","Bleach must be stored at room temperature or it crystallizes"],"a":1,"e":"Disinfectant contact times on labels are tested at approximately 20 °C. In cold environments (< 10 °C), effective kill may require approximately double the stated contact time."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"Which single step in the terminal disinfection sequence is most commonly skipped but cannot be omitted?","o":["Depopulating the area before starting","Applying the disinfectant at the correct dilution","Completing the detergent wash and thorough rinse before applying disinfectant","Replacing bedding after disinfection"],"a":2,"e":"Organic debris on surfaces will neutralize disinfectants regardless of concentration or contact time. The detergent wash and rinse step must precede disinfectant application — skipping it is the most common reason terminal disinfection fails."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"What is the required contact time for potassium peroxymonosulfate (Trifectant/Virkon-S) to be effective against Microsporum canis (ringworm)?","o":["1 minute","5 minutes","10 minutes","30 minutes"],"a":2,"e":"Potassium peroxymonosulfate requires 10 minutes at 1% concentration for ringworm efficacy. The 5-minute contact time covers general pathogens but is insufficient for dermatophytes."},{"type":"mcq","domain":"Physical Health","sub":"Sanitation & Biosecurity","q":"After confirmed CPV in a dog ward, the minimum holding period before reintroducing animals to the cleaned area should be:","o":["24 hours after the last case departs","48 hours","At least 2 full incubation periods (approximately 14 days for CPV) after the last confirmed case leaves the area","No hold needed if terminal disinfection was performed correctly"],"a":2,"e":"Terminal disinfection alone does not eliminate all risk; a waiting period of at least 2 full incubation periods (CPV incubation 3–7 days → hold 14+ days) confirms no residual transmission before reintroducing animals."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Non-sterilization surgeries in the shelter, including dentistry, must adhere to:","o":["Relaxed biosecurity, given the high bacterial load of shelter populations","Local animal-control rules only","The ASV spay-neuter guidelines for surgical suite, anesthesia, analgesia and sterility","No particular standard if done in the medical wing"],"a":2,"e":"All shelter surgery, including dentistry, must meet the ASV spay-neuter standards for suite, anesthesia, analgesia and aseptic technique."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Why is non-anesthetic dental probing, scaling and polishing considered unacceptable?","o":["It alters the oral microbiome and spreads infection between species","Significant disease can be missed and the restraint causes severe stress and risk of serious injury from sharp instruments or bites","It needs intraoral radiographs that only work on awake patients","It breaches commercial dishwasher sanitation standards"],"a":1,"e":"Without sedation, pathology is missed and the patient and staff are placed at real risk; sedation is required."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A hoarding-case cat has a painful mouth but the shelter has no intraoral radiography. The correct approach is:","o":["Defer all dental care until imaging is acquired","Treat the painful mouth even without radiology, because dental disease has serious welfare implications","Give long-term steroids and avoid surgery to reduce length of stay","Perform non-anesthetic scaling instead"],"a":1,"e":"Welfare comes first; a painful mouth is treated even when advanced imaging is unavailable."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The overarching goal of balanced anesthesia, optimal perioperative care and low-stress handling is to ensure:","o":["Lower disinfectant costs in the surgical suite","Not only survival but the long-term health and vitality of the patient","Automated decision-making during outbreaks","Elimination of the preoperative physical exam"],"a":1,"e":"The aim is durable health and vitality, so the animal enters adoption resilient, not merely survival of the procedure."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Before GA or surgery, the correct examination sequence is:","o":["The technician's assessment alone is sufficient; the vet reviews logs afterward","A trained technician performs the initial vital-parameter assessment, then the veterinarian performs a complete PE before any drugs are given","The vet may skip the PE when a signed intake form exists","The exam is deferred to the recovery period"],"a":1,"e":"A tiered approach is used, but a veterinary PE must precede administration of any GA or analgesic agent."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A cat has moderate anemia, about 6% dehydration and an asymptomatic low-grade heart murmur. The ASA class is:","o":["I","II","III","IV"],"a":2,"e":"Moderate systemic disturbance with clinical signs the animal cannot fully compensate for is ASA III."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A dog has severe uremia, acute renal failure, clinical pulmonary disease and recent trauma but is not moribund. The ASA class is:","o":["II","III","IV","V"],"a":2,"e":"Significant illness with significant compromise (uremia, renal failure, clinical pulmonary disease, trauma) is ASA IV; ASA V is reserved for moribund or comatose animals."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Regarding routine preoperative blood work, the best stance is:","o":["It changes the surgical technique in more than half of shelter cases","Age should not be the sole determinant; in the cited data the anesthetic protocol changed in only 0.2% of dogs, so health status and disease potential drive testing","The ASV mandates it for every animal over 5 years of age","Point-of-care testing is useless and should be replaced by full electrolyte panels"],"a":1,"e":"Routine screening rarely alters management in healthy animals; clinical status, not age, guides whether to test."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which presentation is an explicit reason to defer elective sterilization?","o":["Asymptomatic ear mites","Known or suspected intestinal or urinary obstruction","Mild, non-painful flea-allergy dermatitis","Having missed a single meal"],"a":1,"e":"Obstructive disease is a serious problem that defers elective surgery; the other items do not."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which must a standardized intake form capture before GA or surgery?","o":["Pedigree and registration status","Current or recent medications (including parasiticides) and satisfaction of post-operative fasting requirements","The surrenderer's income bracket","The transport route to the shelter"],"a":1,"e":"Medication history and fasting status are essential to avoid drug interactions and aspiration risk."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A feral cat is lunging in the trap. How does the preoperative PE requirement apply?","o":["Pin the cat without sedation to auscultate the thorax","A volunteer performs a full unsedated PE first","A preoperative PE is required before GA except when the animal is fearful, aggressive or feral","Surgery is permanently cancelled"],"a":2,"e":"The PE-before-GA rule has an explicit exception for fearful, aggressive or feral animals, where an unsedated exam is unsafe."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Chamber induction with inhalant gas should be avoided at all costs because it:","o":["Causes severe waste-gas accumulation, prolonged sympathomimetic windup and lethal high inhalant concentrations","Drops intraocular pressure and invalidates ophthalmic screening","Degrades plastic or glass containment tanks","Makes capnography hypersensitive"],"a":0,"e":"Chambers produce dangerous gas accumulation, excessive sympathetic windup and the risk of lethal inhalant concentrations."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A direct drawback of mask induction is that it:","o":["Is non-sympathomimetic and drops heart rate","Causes unnecessary stress, uncontrolled loss of consciousness, gas waste, and bronchoirritation with risk of gastric aspiration via an unprotected airway","Takes at least 45 minutes to reach a surgical plane","Is only compatible with ASA V patients"],"a":1,"e":"Masking forces the animal through an agitated phase, wastes gas, and leaves the airway unprotected against aspiration."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"If mask maintenance is being required too often, an appropriate corrective strategy is to:","o":["Increase the inhalant concentration to speed up surgery","Switch the whole population to chamber induction","Use a protocol that requires intubation rather than masking, or one with better analgesics and sedatives","Stop performing preoperative vital assessments"],"a":2,"e":"Frequent masking signals an unstable protocol; move to intubation or improve the injectable sedation and analgesia."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which dogs should be prioritized for endotracheal intubation?","o":["Lean athletic dogs with confirmed 12-hour fasts","Most unfasted dogs or those with unknown fasting status, overweight dogs, and brachycephalic dogs","Puppies under 6 weeks for suture removal","Dogs with normal airways and low vagal tone"],"a":1,"e":"Aspiration and airway-occlusion risk is highest in unfasted, overweight and brachycephalic dogs, so intubation is prioritized."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"An explicit drawback of endotracheal intubation listed in your notes is:","o":["Coagulative necrosis of the pinnae","Regurgitation or vomiting, increased intracranial and ocular pressure, and increased vagal tone","False-positive calicivirus titers","Breakdown of epoxy flooring in the suite"],"a":1,"e":"Laryngeal stimulation can trigger vagal responses, raise intracranial and ocular pressure, and provoke regurgitation."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A capnograph shows a low end-tidal CO2 (ETCO2). A primary cause is:","o":["Hypoventilation","Build-up of CO2 within the anesthetic machine","Hyperventilation, low perfusion states or hypothermia","Excessive metabolism or systemic heat"],"a":2,"e":"Low ETCO2 reflects either rapid clearance (hyperventilation) or reduced delivery of CO2 to the lungs (low perfusion, hypothermia)."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A high ETCO2 reading indicates:","o":["Severe hyperventilation from deep CNS depression","Hypoventilation, excessive metabolism or heat, or build-up of CO2 within the machine","High perfusion combined with extreme hypothermia","Failure of the airway-patency monitor"],"a":1,"e":"High ETCO2 points to CO2 retention from hypoventilation, increased production, or spent absorbent in the circuit."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The risk of relying on a single monitoring variable is that it:","o":["Increases capnograph sensitivity","Can lead to an inadequate plane of anesthesia, or to excessive depth with risk of emergencies","Removes the need for chest auscultation","Forces the patient into ASA IV status"],"a":1,"e":"No single parameter is reliable alone; multi-parameter monitoring prevents an undetected depth crisis."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The primary benefit of anesthetic monitoring is that it:","o":["Accelerates metabolism during hypothermia","Enhances recognition of worrisome trends and provides a legal record of significant events","Lets technicians bypass veterinary supervision","Converts ASA status into an epidemic curve"],"a":1,"e":"Monitoring catches dangerous trends early and documents significant events for the medical and legal record."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Per RECOVER 2024, the correct epinephrine dose during CPR is:","o":["0.1 mg/kg IV every cycle","0.01 mg/kg IV or IO every 3–5 minutes","1 mg/kg IV once","0.05 mg/kg IM"],"a":1,"e":"RECOVER 2024: epinephrine 0.01 mg/kg IV or IO, repeated every 3–5 minutes (approximately every other CPR cycle). The ET dose is 0.1 mg/kg."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"An anesthetized dog's MAP drops to 52 mmHg. The first intervention is:","o":["Start dopamine CRI at 10 mcg/kg/min immediately","Increase the isoflurane to stabilize the plane","Reduce inhalant concentration and give an isotonic crystalloid bolus (5–10 mL/kg)","Give atropine 0.04 mg/kg IV"],"a":2,"e":"The treatment ladder starts with reducing inhalant (vasodilation is dose-dependent) and a fluid bolus. Vasopressors come after fluids fail."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For ventricular fibrillation in a dog unresponsive to CPR, the preferred anti-arrhythmic per RECOVER is:","o":["Atropine","Amiodarone 5 mg/kg IV","Lidocaine 2 mg/kg IV","Vasopressin"],"a":1,"e":"RECOVER recommends amiodarone as first-line for VF/pulseless VT. Lidocaine is an alternative in dogs but not preferred. Lidocaine is not recommended at this dose in cats."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Per RECOVER 2024, the correct compression rate during CPR is:","o":["60 per minute","80 per minute","100–120 per minute","150 per minute"],"a":2,"e":"RECOVER 2024: 100–120 compressions per minute, compressing 1/3 to 1/2 of the chest width. Rotate compressor every 2 minutes."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"An anesthetized cat has apnea for 40 seconds. The correct immediate action is:","o":["Administer doxapram 10 mg/kg IV","Begin manual IPPV at 10–15 mL/kg tidal volume, 8–12 breaths/min","Increase isoflurane concentration","Give atropine 0.04 mg/kg"],"a":1,"e":"Apnea over 30 seconds requires immediate manual ventilation. Reduce inhalant and check tube position simultaneously."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Biphasic external defibrillation energy in dogs and cats per RECOVER 2024 is:","o":["1–2 J/kg","2–4 J/kg","4–6 J/kg","8–10 J/kg"],"a":1,"e":"Biphasic external defibrillation is 2–4 J/kg; monophasic requires more (4–6 J/kg). Always start at the lower end."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Why is lidocaine used with caution in cats during CPR?","o":["Cats lack cardiac sodium channels","Cats are sensitive to lidocaine toxicity; the 2 mg/kg anti-arrhythmic dose used in dogs is not recommended in cats","Lidocaine is not a RECOVER-approved drug","Lidocaine prolongs the QT interval only in cats"],"a":1,"e":"Cats are more sensitive to lidocaine toxicity; amiodarone is the preferred anti-arrhythmic in both species."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The CMPS-SF (Glasgow Composite Measure Pain Scale Short Form) intervention threshold for dogs is:","o":["3/20","6/20","10/20","15/20"],"a":1,"e":"CMPS-SF intervention threshold is 6/20. At this score or above, rescue analgesia is indicated for dogs."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which validated pain scale is designed and validated specifically for cats?","o":["CMPS-SF","UNESP-Botucatu Multidimensional Composite Pain Scale","CSU canine scale","AAEP numerical scale"],"a":1,"e":"UNESP-Botucatu was validated for acute post-operative feline pain (threshold 8/27). CMPS-SF is validated for dogs."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A cat's UNESP-Botucatu pain score is 9/27 post-OHE. The intervention threshold is 8. The correct action is:","o":["Re-assess in 4 hours","Administer rescue analgesia now","Remove the E-collar to reduce stress","Increase IV fluids only"],"a":1,"e":"9/27 exceeds the 8/27 intervention threshold; rescue analgesia is indicated immediately."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which pain scale is most recommended for shelter settings due to ease of staff training?","o":["CMPS-SF","UNESP-Botucatu","CSU (Colorado State University) scale","AAEP scale"],"a":2,"e":"The CSU scale trains quickly and is widely used in shelter and high-volume settings, though CMPS-SF and UNESP-Botucatu provide the validated thresholds for ABVP exam purposes."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Standard activity restriction after routine soft-tissue surgery is:","o":["No restriction; normal activity immediately","Leash walks only; no running, jumping, rough play, or swimming for 10–14 days","Cage rest for 48 hours only","No restriction for cats; dogs restricted 3 days"],"a":1,"e":"Standard restriction is 10–14 days of limited activity to allow incision healing."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When should the E-collar be applied after surgery?","o":["After the animal is ambulatory and aware","Only if the animal tries to lick","Before full recovery from anesthesia, while still in the immediate post-op period","At suture removal"],"a":2,"e":"E-collar must be on before the animal is fully awake; a recovering animal can traumatize a fresh incision in seconds."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which post-surgical finding requires immediate attention?","o":["Mild bruising at 24 hours","Dehiscence — any gap in the suture line","Mild swelling at 48 hours","Small amount of clear serous fluid in the first hour"],"a":1,"e":"Dehiscence requires immediate attention due to risk of contamination, herniation, and serious complications."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Discharge criteria after surgery include all of the following EXCEPT:","o":["Pain score below intervention threshold","Alert and ambulatory without assistance","Urinated at least once post-op","Has eaten a full meal immediately after anesthesia"],"a":3,"e":"Eating immediately post-anesthesia is not a discharge criterion and risks vomiting. The other three are standard criteria."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which chronic medication should be withheld on the morning of anesthesia?","o":["Levothyroxine","An ACE inhibitor such as enalapril or benazepril","Pimobendan","The patient's antibiotic"],"a":1,"e":"ACE inhibitors are discontinued the day of anesthesia because inhalant vasodilation plus ACE blockade can cause hypotension refractory to fluids and pressors. Thyroid, cardiac (pimobendan/furosemide) and antibiotic meds are continued."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A herding-breed dog carries the MDR1 (ABCB1) mutation. Anesthetic adjustment is to:","o":["Increase all drug doses for faster effect","Reduce acepromazine and potentially butorphanol doses","Avoid all opioids permanently","Use only mask induction"],"a":1,"e":"MDR1/ABCB1 mutation alters CNS drug handling; reduce acepromazine and potentially butorphanol. The mutation is classic in Collies and Australian Shepherds."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The induction agent of choice for a patient with significant cardiovascular disease is:","o":["Propofol","Alfaxalone","Etomidate","Thiopental"],"a":2,"e":"Etomidate has minimal cardiovascular effects, making it ideal for cardiac patients; the trade-off is myoclonus, pain on injection, and adrenocortical suppression. Co-induce with a benzodiazepine."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Preoxygenation with 100% O2 for ~3 minutes before induction provides approximately:","o":["30 seconds of saturation buffer","6 minutes of adequate hemoglobin saturation during apnea","No measurable benefit","An hour of apnea tolerance"],"a":1,"e":"About 3 minutes of preoxygenation buys ~6 minutes of adequate saturation during apnea/intubation — critical in airway disease, difficult intubation, and pregnancy."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For a feline castration testicular block, many clinicians prefer lidocaine over bupivacaine because:","o":["Lidocaine lasts longer","Lidocaine has a higher safety margin if accidentally injected IV into the vascular testis","Bupivacaine is not effective in cats","Lidocaine cannot be overdosed"],"a":1,"e":"The testes are highly vascular; lidocaine's wider safety margin on inadvertent IV injection makes it the pragmatic choice despite its shorter duration."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"AAHA's headline recommendation for surgical analgesia is to:","o":["Rely on a single full mu opioid","Use local anesthetics, insofar as possible, with every surgical procedure","Avoid NSAIDs in all patients","Reserve analgesia until pain is observed"],"a":1,"e":"AAHA stresses multimodal, pre-emptive analgesia and specifically recommends using local anesthetics with every surgical procedure; local blocks completely interrupt pain transmission and lower inhalant needs."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"An anesthetized dog is hypotensive from inhalant-induced vasodilation with good contractility. The most rational support drug is:","o":["Dobutamine (a positive inotrope)","Phenylephrine or norepinephrine (a vasoconstrictor)","Atropine","Additional inhalant"],"a":1,"e":"Match the drug to the cause: vasodilation calls for a vasoconstrictor (phenylephrine/norepinephrine). Inotropes (dopamine/dobutamine) are for poor contractility; ephedrine does both."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"A surgical plane of anesthesia is best indicated by:","o":["A brisk palpebral reflex and strong jaw tone","Absent palpebral reflex, mild jaw tone, a central-to-ventromedial eye position, and no purposeful movement","Tachypnea with a dorsomedial eye","Spontaneous swallowing"],"a":1,"e":"Surgical depth: absent palpebral reflex, mild jaw tone, ventromedial eye position, no purposeful movement — combined with electronic monitoring, not either alone."},{"type":"mcq","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Regarding the timing of anesthetic deaths, AAHA reports that most occur:","o":["During induction","During the maintenance phase","In the postoperative period, most within the first 3 hours","More than 48 hours after recovery"],"a":2,"e":"Roughly 47–60% of anesthetic deaths occur postoperatively, most within the first 3 hours — so recovery monitoring must be as vigilant as maintenance."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"What is the primary operational advantage of an MLV core vaccine over a killed vaccine in a congregate shelter?","o":["MLV is stable at room temperature for months","MLV gives a faster onset of protective immunity (hours to days), whereas killed needs a booster 2 to 4 weeks later to protect","MLV can be mixed in one syringe with antibiotics","MLV faces no maternal antibody interference"],"a":1,"e":"MLV replicates in the host for rapid immunity; killed vaccines need a primary plus booster to protect, which is too slow for shelter disease control."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A shelter core combination product should contain:","o":["Only MLV core components","Core plus Leptospira and Bordetella for broad cover","Whatever the manufacturer will combine on request","Rabies mixed with the core MLV"],"a":0,"e":"Shelter core combos should be MLV core only; rabies is monovalent killed and not mixed, and non-core agents are not routinely included."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Roughly what proportion of dogs are unprotected against CPV-2, CDV or both on shelter intake?","o":["About 10%","About 30%","About 64.5%","Over 95%"],"a":2,"e":"About 64.5% of dogs are unprotected against CPV-2, CDV or both on intake, which is why vaccinating at entry matters."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Mucosal (intranasal or oral) vaccines are recommended for respiratory pathogens because they:","o":["Produce systemic IgG only, lasting years","Develop local URT humoral and cellular immunity within 3 to 7 days","Cannot be given to naive animals","Are always killed products"],"a":1,"e":"Mucosal products generate rapid local respiratory-tract immunity (3 to 7 days), useful against respiratory pathogens, especially in naive animals."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A distinct advantage of recombinant (vectored) vaccines is that they:","o":["Replicate fully in the host like MLV","Express the target antigen without replicating the pathogen, may work better through MDA, and (being non-adjuvanted) carry reduced injection-site sarcoma risk","Require no cold chain","Provide lifelong immunity after one dose for all diseases"],"a":1,"e":"Recombinant vaccines present antigen without pathogen replication, can perform better against MDA, and avoid adjuvant-related sarcoma risk in cats."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Which is a recognized cause of vaccine failure?","o":["Administering MLV core on intake","Maternal antibody interference, improper storage or handling, exposure before full immunization, or waning immunity","Using the labeled volume","Vaccinating a healthy adult"],"a":1,"e":"Failure stems from host non-response, pre-immunization exposure, MDA, cold-chain or handling errors, waning immunity, and manufacturing faults."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A 5-week-old stray puppy enters during a parvovirus outbreak. The correct core schedule while in the shelter is:","o":["A single MLV dose at intake, then boosters every 6 months","An MLV core vaccine at intake, repeated every 3 to 4 weeks until 16 to 20 weeks of age","Wait until 12 weeks so maternal antibody clears, then vaccinate once","Two killed doses 14 days apart, then stop"],"a":1,"e":"Serial MLV boosting every 3 to 4 weeks to 16 to 20 weeks closes the window of vulnerability as maternal antibody wanes."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Why are juveniles revaccinated at short intervals until 16 to 20 weeks?","o":["To exhaust the bone marrow of inflammatory cells","So that as soon as maternal antibody falls below the blocking threshold in an individual, the next dose can immunize","Because juveniles clear vaccine antigen within 48 hours","To prevent lifelong environmental allergies"],"a":1,"e":"Maternal antibody declines at individual rates; frequent dosing ensures a dose lands once the animal becomes immunizable."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"The window of vulnerability is best defined as the period when maternal antibody is:","o":["High enough to protect and to allow immunization","Too low to protect against virulent virus but still high enough to block vaccine immunization","Absent, so the animal is fully protected","Only relevant to killed vaccines"],"a":1,"e":"A virulent virus overcomes maternal antibody more readily than vaccine virus, creating a gap where the animal is susceptible yet not immunizable."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Regarding vaccination of very young neonates:","o":["MLV should be given on day 1 of life","Neither MLV nor killed vaccine should be given in the first 2 weeks of life","Killed vaccine is safe from birth","Colostrum has no effect on early vaccine response"],"a":1,"e":"Before 2 weeks the immune system cannot respond well and vaccine virus can cause disease; colostral IgG also blocks active immunity in the first days."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"To conserve maternal antibody, a shelter considers delaying puppy vaccination. The correct guidance is:","o":["Delay until 16 weeks to preserve passive immunity","Do not delay vaccination to conserve maternal antibody; vaccinating while it is present does not speed its decline","Vaccinate the nursing dam instead to protect the litter","Give a single dose and skip boosters"],"a":1,"e":"Vaccination should not be delayed to spare maternal antibody, and vaccinating the dam does not protect nursing juveniles."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"The canine core vaccines for a shelter are:","o":["Leptospira, Borrelia and rattlesnake toxoid","Canine parvovirus, distemper, adenovirus-2 and rabies","Microsporum canis, Giardia and Malassezia","Tetanus toxoid, Streptococcus equi and CIV"],"a":1,"e":"Core protects against the severe, contagious pathogens (CPV, CDV, CAV-2 and rabies); the others are non-core or not vaccine targets."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"The shelter MLV DA2PP schedule for pups is:","o":["A single dose at 12 weeks only","At or before entry from 4 weeks, with boosters every 2 to 3 weeks until 18 to 20 weeks","One dose at intake and one at 1 year","Killed product every 6 weeks"],"a":1,"e":"MLV DA2PP starts at 4 weeks at intake and boosts every 2 to 3 weeks to 18 to 20 weeks; adults get an intake dose plus a 2 to 3 week booster."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Rabies vaccination of shelter dogs should be given:","o":["To every dog on intake regardless of age","As a single parenteral dose to all dogs over 12 weeks before release (on entry only if a long stay is anticipated)","Only if the dog shows respiratory signs","Mixed into the DA2PP syringe"],"a":1,"e":"In-shelter rabies exposure is low, so it is timed to release for public health, given to dogs over 12 weeks, and not combined with core MLV."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Why is an intranasal Bordetella-only product discouraged in favor of a two-way intranasal Bordetella and CPIV vaccine?","o":["Bordetella-only products are not refrigerated","A dog at risk for Bordetella is also at risk for CPIV, so both should be covered","Intranasal routes are blocked by maternal antibody","CPIV is not a shelter concern"],"a":1,"e":"Risk overlaps, and intranasal products avoid maternal antibody interference while giving rapid local immunity, so the two-way product is preferred."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Regarding parvovirus susceptibility in puppies, which statement is correct?","o":["All pups are protected once they receive any single dose","Maternal antibody can persist 13 to 15 weeks, so all pups under 18 to 20 weeks should be considered susceptible regardless of vaccines received","Parvovirus immunity is always partial like distemper","Pups over 8 weeks need no further doses"],"a":1,"e":"Maternal antibody can block vaccine for 13 to 15 weeks; parvovirus immunity is all-or-none, so young pups remain potentially susceptible until 18 to 20 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Which vaccines are generally NOT recommended for routine shelter use?","o":["MLV DA2PP and rabies","Leptospira, canine influenza and Lyme","Intranasal Bordetella and CPIV","Parenteral rabies"],"a":1,"e":"Leptospirosis, canine influenza and Lyme pose minimal in-shelter risk and are not part of the routine shelter program."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Why is a standard MLV FPV vaccine contraindicated in a pregnant queen?","o":["It causes anaphylaxis in most pregnant cats","The live virus can cross the placenta and damage the fetal cerebellum, causing cerebellar hypoplasia","It permanently stops colostrum production","It turns the coat white"],"a":1,"e":"MLV panleukopenia virus targets rapidly dividing fetal cerebellar cells; in an outbreak the maternal and litter risk may still outweigh this, but a killed product is safer in pregnancy."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"To mitigate injection-site sarcoma consequences, feline vaccines should be given:","o":["Into the interscapular scruff for comfort","Into the flank midway between ribs and hip","As distally on a limb as possible, or in the tail, to allow complete surgical margins if a sarcoma develops","Into the jugular furrow"],"a":2,"e":"Distal-limb or tail placement permits curative amputation with clean margins; scruff and flank are no longer recommended."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A 2.5 cm firm nodule is found at a rabies vaccine site 6 weeks after injection. By the 1-2-3 rule the next step is:","o":["Re-check in 6 months with warm compresses","Biopsy or aspirate now, because the mass is 2 cm or larger","Massage with isopropyl alcohol","Start oral corticosteroids and assume it is benign"],"a":1,"e":"The 1-2-3 rule triggers biopsy if a post-vaccinal mass is 2 cm or larger, persists 3 months, or is still growing at 1 month; 2.5 cm meets the size criterion."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"The shelter FVRCP schedule for kittens is:","o":["A single dose at 8 weeks only","A dose at intake as early as 4 weeks, then boosters every 2 weeks until 16 to 20 weeks","Killed FVRCP every 6 months","Intranasal FPV preferred over parenteral"],"a":1,"e":"Kittens get FVRCP from 4 weeks at intake with boosters every 2 weeks to 16 to 20 weeks; intranasal FPV is not preferred for panleukopenia protection."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Which statement about FCV and FHV-1 vaccination is correct?","o":["It prevents infection completely","Immunity develops in about 7 days, but vaccination does not prevent infection and instead reduces disease severity","It eliminates latent FHV-1 infection","It is a core vaccine only for cats over 5 years"],"a":1,"e":"Respiratory core immunity is partial: it lessens severity but does not prevent infection, and FHV-1 latency persists."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Correct use of the feline FeLV vaccine includes:","o":["A single dose gives full protection","Testing FeLV status first and giving 2 doses 3 to 4 weeks apart, since a single dose provides no protection","Giving it only to FeLV-positive cats","Mixing it with FVRCP in one syringe"],"a":1,"e":"FeLV status is checked first; two doses 3 to 4 weeks apart are required because a single dose does not protect (it is core for cats under 1 year)."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"After rabies vaccination, protective immunity is induced and lasts:","o":["Within hours, lasting 6 months","As early as 2 to 3 weeks, with a minimum DOI of 3 years for most products","Only after three doses, lasting 1 year","Immediately, lasting 10 years"],"a":1,"e":"Killed adjuvanted rabies vaccine induces immunity in 2 to 3 weeks with a minimum 3-year DOI (up to 4 years for one feline product)."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Comparing 1-year and 3-year rabies products in shelters:","o":["The 1-year product is always safer","The 3-year product is as safe or safer and is recommended, especially in shelters","Only the 1-year product is legal","They cannot be used in cats"],"a":1,"e":"The 3-year product is as safe or safer and is preferred; it is acceptable for cats, as is the non-adjuvanted 1-year recombinant feline vaccine."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"For shelter dogs, rabies vaccine should be administered:","o":["To all dogs on intake regardless of age","As a single parenteral dose to all dogs over 12 weeks before release","Only to dogs staying under 48 hours","By any volunteer"],"a":1,"e":"Because in-shelter exposure is limited, rabies is timed to release for dogs over 12 weeks, with on-entry use only for long stays."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"An adult dog with no prior rabies history receives its first rabies dose at the shelter. Legally it must be:","o":["Never revaccinated if a 3-year product was used","Revaccinated within the year in most communities, regardless of whether a 1-year or 3-year product was used","Titer-tested instead of revaccinated","Revaccinated only if it bites someone"],"a":1,"e":"Animals without prior rabies vaccination must be revaccinated within a year in most jurisdictions; staff should communicate this to adopters."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Rabies is an exception to which general core-vaccine rule?","o":["It must be MLV","Although killed, it protects after a single dose and may be given at an interval under 2 weeks from other cores","It must be given on intake","It cannot be given to cats"],"a":1,"e":"Rabies breaks the killed 2-dose-within-6-weeks rule and the 2-week minimum spacing, protecting most animals over 3 months after one dose."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A box of MLV FVRCP was left on a counter at room temperature for about 36 hours. The correct action is:","o":["Refrigerate and use as normal","Discard it, because live attenuated virus degrades out of the cold chain and the vaccine is now ineffective","Combine two doses per syringe to compensate","Autoclave and use as a killed product in pregnancy"],"a":1,"e":"MLV is heat-sensitive; reconstituted or warmed product out of the cold chain (over an hour at room temperature) must be discarded."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A healthy dog with no clinical signs has a negative CDV and CPV titer during an outbreak. It should be classified and managed as:","o":["Low risk, kept in the general population","High risk, removed from the general population immediately","Indeterminate, no action needed","Immune, adopted at once"],"a":1,"e":"A negative titer with no signs means likely susceptibility, so the animal is high risk and is separated from the population."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"For risk assessment in puppies and kittens, the better testing approach is:","o":["A qualitative in-house kit, because the cut-off is set for juveniles","Quantitative (lab) titer testing, because it can distinguish active immunity from passive maternal antibody","No testing, since juveniles are always low risk","Antigen testing rather than antibody testing"],"a":1,"e":"Qualitative kits cannot separate active from passive immunity in juveniles, so quantitative titers are the gold standard, and passive low-risk status can change as maternal antibody wanes."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"How does recent vaccination affect FeLV versus FIV point-of-care testing?","o":["Both become unreliable for 2 weeks","FeLV antigen testing is unaffected, but FIV antibody testing cannot reliably distinguish vaccine from infection","FIV testing is unaffected, but FeLV becomes falsely positive","Neither test is ever affected by vaccination"],"a":1,"e":"FeLV tests detect antigen and are unaffected, while FIV tests detect antibody that vaccination also produces, so vaccinated and infected cats are hard to distinguish (PCR may help)."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A mild to moderately ill but stable dog needs core vaccination on intake. The guidance is:","o":["Never vaccinate any ill animal","Vaccinate now, since vaccines are unlikely to harm while virulent exposure is the greater danger, and repeat no less than 2 weeks after recovery","Wait 8 weeks regardless of recovery","Vaccinate only after a full chemistry panel"],"a":1,"e":"For mild to moderate illness, vaccinate on intake (virulent exposure is the bigger risk) and repeat at least 2 weeks after recovery; only animals too ill to vaccinate safely are handled separately in isolation."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"During a canine parvovirus outbreak, which statement about vaccinating already-exposed dogs is correct?","o":["Vaccinating infected dogs worsens disease severity","Vaccinating does not worsen disease; all dogs should receive MLV DA2PP immediately regardless of exposure status","Exposed dogs should be quarantined for 14 days before vaccinating","Vaccination during an outbreak is contraindicated until the outbreak resolves"],"a":1,"e":"Vaccinating an already-infected animal does NOT worsen disease. All animals should be vaccinated at entry during a CPV outbreak regardless of exposure history."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"During a CPV outbreak, a healthy 12-week-old pup received two DA2PP doses (at 6 and 9 weeks). How should this pup be managed?","o":["It is fully protected — keep in the general population","It should be treated as potentially susceptible; maternal antibody can persist to 13–15 weeks and may have blocked both prior doses","Place in isolation as it is definitely infected","Vaccinate once more then consider immune"],"a":1,"e":"All pups under 18–20 weeks must be treated as potentially susceptible regardless of vaccination history, because MDA can persist to 13–15 weeks and block vaccine response."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Which CDV outbreak characteristic makes early vaccination uniquely valuable compared to CPV or FPV?","o":["CDV vaccines take 6 weeks to produce any immunity","Partial CDV immunity can develop within days of a single MLV dose, unlike CPV/FPV where immunity is all-or-none and takes longer","CDV is only spread by contact so vaccination is not urgent","CDV vaccines must be killed products to avoid outbreak interference"],"a":1,"e":"CDV is unique in providing early partial immunity within days of a single MLV dose. CPV and FPV immunity is all-or-none and takes longer to develop. This makes fast CDV vaccination especially impactful."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"During a feline panleukopenia outbreak, which vaccine product is preferred for all cats ≥4 weeks?","o":["Killed (inactivated) FVRCP, because it is safest for all cats including pregnant queens","Intranasal MLV FVRCP, because mucosal immunity develops within 24 hours","Parenteral MLV FVRCP, because it provides the best protection against FPV in an outbreak","Any available FPV product — efficacy is equivalent across all formulations"],"a":2,"e":"Parenteral MLV FVRCP is the preferred product in an FPV outbreak. Intranasal MLV and killed FVRCP provide less reliable panleukopenia protection. Killed products are safer in pregnancy but used only if parenteral MLV is unavailable."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"Which disinfectant FAILS against both CPV and FPV outbreaks?","o":["Accelerated hydrogen peroxide (AHP) 1:32","Potassium peroxymonosulfate (Virkon) 1%","Quaternary ammonium compounds (quats)","Sodium hypochlorite 1:32"],"a":2,"e":"Quaternary ammonium compounds fail against both CPV and FPV (non-enveloped viruses). AHP, potassium peroxymonosulfate, and bleach (1:32) are effective with adequate contact time."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"What is the primary advantage of the recombinant canarypox-vectored CDV vaccine (rCDV) over MLV CDV in an outbreak setting?","o":["It requires no refrigeration","It does not contain live CDV so it does not interfere with PCR diagnostics, and it may perform better through maternal antibody","It provides lifetime immunity after a single dose","It can be mixed with MLV DA2PP in the same syringe for efficiency"],"a":1,"e":"rCDV does not contain replicating CDV, so PCR tests remain interpretable for outbreak diagnosis. It may also perform better through maternal antibody, making it useful for young pups in outbreak settings."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"The minimum temperature monitoring equipment required in a vaccine storage refrigerator is:","o":["A standard dial thermometer mounted on the fridge door","A min/max thermometer placed in the center of the fridge","A digital display built into the fridge itself","Daily staff visual inspection of the fridge without a dedicated thermometer"],"a":1,"e":"A min/max thermometer (not a dial gauge or built-in display) is the minimum standard — it records the highest and lowest temperature since last reset, capturing excursions that a point-in-time reading would miss."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"A shelter discovers on Monday morning that the vaccine fridge alarm shows a high-temperature excursion over the weekend. The correct immediate action is:","o":["Discard all vaccines immediately to prevent liability","Quarantine the affected stock with a 'Do Not Use' label and contact the vaccine manufacturer for lot-specific guidance before discarding or using","Vaccinate all animals in the queue immediately before the vaccines degrade further","Move vaccines to the freezer to preserve them"],"a":1,"e":"Contact the manufacturer — do not discard immediately. Manufacturers have stability data for specific time-temperature combinations; the vaccines may still be viable depending on duration and temperature reached. Moving vaccines to a freezer can damage killed-product adjuvants and MLV components."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"What is the correct use-time limit for a reconstituted MLV vaccine at room temperature?","o":["4 hours, same as killed vaccines","24 hours if kept covered and away from light","30–60 minutes; discard any unused portion after this time","The entire working day if kept capped and refrigerated after use"],"a":2,"e":"Reconstituted MLV vaccine must be used within 30–60 minutes and discarded. Killed vaccines are more thermostable (use within 4 hours out of the fridge), but reconstituted MLV cannot be returned to the refrigerator for later use."},{"type":"mcq","domain":"Physical Health","sub":"Vaccination","q":"During a power failure, vaccines should be immediately transferred to:","o":["A regular household freezer to slow vaccine degradation","An insulated cooler with ice packs (not loose ice), targeting 2–8°C","A warm environment so vaccines are ready for immediate use","A second fridge in a different building with the same temperature setting"],"a":1,"e":"Ice packs (not direct loose ice) in an insulated cooler maintain 2–8°C. Loose ice can freeze and damage vaccines. Freezing kills adjuvants in killed products and damages MLV components."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"A new feline holding wing is comparing ventilation targets. What is the ASV standard for room air exchange and composition in animal housing?","o":["8 to 12 ACH with up to 30% recirculated air","10 to 20 room air exchanges per hour with fresh air","20 to 25 ACH with mandatory facility-wide HEPA","5 to 10 ACH with industrial ozone generators"],"a":1,"e":"ASV 2022 sets 10 to 20 room air exchanges per hour with fresh, non-recirculated air."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Fractious cats are housed so staff must use squeeze boards and feral dens forcefully every morning to clean. How is this categorized?","o":["Acceptable if length of stay is under 7 days","Conditionally acceptable with Level 2 PPE","Unacceptable to house animals where daily care requires forceful handling equipment","Recommended, as it optimizes biosecurity"],"a":2,"e":"ASV: it is unacceptable to house animals in enclosures that require forceful handling equipment for daily care; use multi-compartment touch-free housing."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"During a surge, staff house four friendly healthy dogs in an admin hallway and a restroom. Which is true?","o":["Acceptable because the dogs are friendly and low risk","Unacceptable; except for a brief emergency, housing in spaces not intended for housing is forbidden","Acceptable if vaccinated and dewormed within 2 hours","Acceptable with a temporary visual barrier"],"a":1,"e":"ASV: except for brief emergencies, housing animals in spaces not intended for housing (bathrooms, hallways) is unacceptable."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What are the minimum and ideal individual floor-space figures for an adult cat?","o":["Under 6 sq ft is fine for short stays","Under 8 sq ft (0.75 sq m) is unacceptable; 11 sq ft (1.0 sq m) or more is ideal","Exactly 4 sq ft regardless of stay","16 to 18 sq ft minimum for any individual cat"],"a":1,"e":"ASV: individual adult cat housing under 8 sq ft (0.75 sq m) is unacceptable; 11 sq ft (1.0 sq m) or more is ideal."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"For a group cohousing room of healthy adult cats, what is the minimum floor space per cat and the maximum number of adult cats?","o":["8 sq ft per cat; maximum 12 cats","12 sq ft per cat; maximum 10 cats","18 sq ft (1.7 sq m) per cat; maximum 6 adult cats","25 sq ft per cat; maximum 4 cats"],"a":2,"e":"ASV: minimum 18 sq ft (1.7 sq m) per adult cat, and no more than six adult cats per enclosure (corrected from a draft 6 to 8)."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"A row of single-sided kennels holds alert, healthy dogs. Which practice is a critical welfare violation that must be halted?","o":["Walking the dogs out during cleaning","Placing a dog on a secure tie-out in front of its pen while scrubbing","Hosing the kennel floors and walls while dogs remain inside","Restocking cleaning supplies weekly from central storage"],"a":2,"e":"Dogs must never be hosed down while inside the enclosure; remove animals from areas where overspray and stress occur."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"To prevent droplet transmission when cats sneeze, what is the minimum spacing required between opposing rows of cat cages that face each other?","o":["Greater than 2 ft (0.6 m)","Greater than 3 ft (0.9 m)","Greater than 4 ft (1.2 m)","Greater than 6 ft (1.8 m)"],"a":2,"e":"ASV: cat cages should face away or be spaced more than 4 ft (1.2 m) apart to prevent respiratory droplet transmission."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"A draft proposes 4 ft wide by 16 ft long dog runs; the consultant recommends 8 ft by 8 ft. What metric supports housing wider than 4 ft?","o":["It raises room temperature from 60 to 80 F automatically","It maximizes ceiling-vent air velocity","It minimizes a dog's nose and tail hitting the side walls when turning","It removes the need for a double-compartment door"],"a":2,"e":"Design guidance: housing wider than 4 ft prevents the nose and tail from hitting walls as the dog turns."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"How should a large shelter structurally segregate its isolation wing to avoid coinfections?","o":["One open ward with a central exhaust pulling air across all species","Separate isolation areas by syndrome and species (for example dermatology, respiratory, gastrointestinal)","Housing contagious animals in admin offices for observation","Shared indoor/outdoor runs with interconnected drainage"],"a":1,"e":"ASV requires species separation and separate areas for different contagious diseases; the textbook operationalizes this as syndrome-grouped rooms."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"A shelter weighs reactivating overnight public drop boxes. How are drop boxes classified?","o":["Highly recommended for 24-hour access","Conditionally acceptable with internal video monitoring","Entirely unacceptable due to safety risks, suffering, pathogen exposure, or death","Acceptable for adult cats if kept at 65 to 80 F"],"a":2,"e":"ASV: unmonitored drop boxes are unacceptable; use on-call numbers, police drop-off, or vet ER agreements instead."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Which design choice best reduces chronic stress, frustration, and barking in a canine adoption ward?","o":["Direct face-to-face room alignment for constant visual stimulation","Open warehouse housing with chain-link throughout","Enclosed individual rooms, walls continuous to the ceiling, laminated glass doors with a sniff hole","Plexiglass doors with no openings to isolate dogs from airflow cues"],"a":2,"e":"Enclosed rooms with continuous walls and laminated glass plus a sniff hole reduce noise transmission; note they then need mechanical ventilation."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What are the absolute prerequisites for a cat before entering a cohousing group?","o":["Length of stay over 14 days and an indoor-only history","Individual health and behavior assessment, free of contagious disease signs, and negative FeLV and FIV","Mandatory 30-day quarantine regardless of exam","Documentation that the cat is over 10 years old"],"a":1,"e":"ASV: assess health and behavior, confirm freedom from contagious disease, and require negative FeLV and FIV before group entry."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"For a heavy-duty wash-down run with daily heated water and disinfectants, which flooring is explicitly unacceptable?","o":["Fluid-applied resinous epoxy or urethane","Polished sealed concrete","Paint, epoxy paint, wood, or vinyl","Slip-resistant porcelain tile with minimal grout"],"a":2,"e":"Paint, epoxy paint, wood, and vinyl cannot withstand industrial sanitation and are unacceptable for shelter floors."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What are the primary drawbacks of indoor/outdoor kennel units with guillotine doors?","o":["Banned outright under ASV guidelines","Costly to build, waste energy, can freeze shut in cold climates, and trap humidity and mold in hot humid climates","They increase stereotypies versus small single rooms","They prevent any fresh-air ventilation system"],"a":1,"e":"Indoor/outdoor units are ideal for welfare but costly, energy-hungry, prone to freezing shut, and to humidity and mold in hot climates."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What is the correct directional workflow for daily cleaning and husbandry to limit fomite transmission?","o":["Least healthy to healthiest (isolation to intake to adoption)","Storage to isolation to public lobby","Healthiest to least healthy (adoption to intake to isolation)","All dog pods first, felines left until evening"],"a":2,"e":"Begin with the healthiest and most susceptible and finish with the least healthy: adoption toward isolation."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"On a restricted budget, which lighting strategy meets sustainability goals without harming circadian welfare?","o":["High-intensity lights on 24 hours to prevent shedding","Removing all windows to stabilize heat transfer","Limit loads to under 1 watt per sq ft and use photosensors to dim lights near windows when daylight suffices","Legacy un-ballasted fluorescent fixtures only"],"a":2,"e":"Keep lighting under 1 W per sq ft and use photosensors near windows; preserve natural light for circadian rhythm."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"In the needs-assessment process, what is the objective of developing the animal intake profile (Step 3)?","o":["Track the volunteer-to-staff payroll ratio","Designate intake by mode of entry and animal type monthly for at least 2 years to optimize C4C and prevent over- or under-building","Map the ratio of urethane to tile grout","Eliminate all double-compartment enclosures"],"a":1,"e":"Step 3 records intake by mode and type monthly for at least 2 years to size housing to real demand and protect Capacity for Care."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Can a litter of four 8-week-old puppies be cohoused with three unrelated 10-week-old strays?","o":["Yes, mixing unrelated puppies under 5 months maximizes socialization","Yes, with a prophylactic NSAID protocol","No; puppies and kittens under 20 weeks should not be cohoused with unfamiliar animals unless benefits clearly outweigh risks","No; pediatrics cannot be cohoused until spayed or neutered"],"a":2,"e":"ASV: under 20 weeks, do not cohouse with unfamiliar animals unless benefits outweigh risks due to infectious-disease susceptibility."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"How is feline upper respiratory infection most effectively managed through infrastructure?","o":["Convert feline rooms to outdoor wire cages for airflow","Through proper shelter design and air systems plus appropriate management, even with few isolation rooms","Lower exhaust vents to floor level by the public entrance","Increase group rooms to over 12 cats for herd immunity"],"a":1,"e":"FURI is best controlled by design, air systems, and management policies, not by crowding or exposure-increasing fixes."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Where should exhaust vents be positioned in a feline intake ward to minimize air cross-contamination?","o":["Centrally on the ceiling over the hallway","At the rear of individual cat units","Low to the floor by the room's front door","Omitted to preserve a tight humidity zone"],"a":1,"e":"Place exhaust at the rear of individual cat units to reduce air cross-contamination between animals."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"In the facility space-usage mix, what share goes to Animal Areas, and which sub-category is largest?","o":["Public/Support 35%; Lobby 11% largest","Animal Areas 65%; Animal Housing 45% largest","Animal Areas 65%; Training 15% largest","Medical 5%; Support 7% largest"],"a":1,"e":"Animal Areas are about 65% of the building, with Animal Housing the single largest share at about 45%."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Why are off-centre drains recommended in a primary canine enclosure floor?","o":["They raise ventilation from 10 to 20 ACH","They keep a dry space for the dog to rest while the floor finishes drying","They enable continuous pacing without wet paws","They remove the need for coved wall-floor junctions"],"a":1,"e":"Off-centre drains leave a dry resting area for the dog while wash-down water drains away."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"On a tight retrofit budget, which filtration standard is sufficient for standard shelter HVAC units?","o":["Industrial HEPA across all spaces","A pleated MERV 6 or 8 filter","Remove all filters if using barred doors","Activated carbon beds in feline zones only"],"a":1,"e":"MERV 6 or 8 pleated filters suffice for retrofits; HEPA is reserved for surgery. Filtration is an adjunct, not the sole control."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"How should a highly fearful stray cat be transported and placed to optimize security?","o":["Open wire crate at floor level past dog runs","Hand-carried by several volunteers for fast acclimation","Covered carrier or trap so it feels hidden, then transferred quickly to the highest available cage","Straight into a group room with 6 to 8 cats"],"a":2,"e":"Use covered carriers or traps and transfer to the highest available cage, consistent with the feline preference for elevation."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Which materials are explicitly unacceptable for shelter walls in a high-moisture, high-impact zone?","o":["Solid surfaces and laminated glass","Sealed hard-trowelled cement plaster","Wood, painted wallboard, vinyl wall coverings, and standard concrete block","Polished-face block or large porcelain tile"],"a":2,"e":"Unacceptable walls: wood, painted wallboard, vinyl wall coverings, and standard concrete block."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What is the maximum number of adult dogs cohoused in one primary enclosure, and the preferred arrangement?","o":["No more than 2 dogs under any circumstance","No more than 4 adult dogs, ideally paired","Up to 6 if all under 20 weeks from different sources","Up to 8 if fed from one communal bowl"],"a":1,"e":"ASV: two to four adult dogs per enclosure, with pairs preferred for safety and biosecurity."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"What behavioral changes were documented when shelter dogs were given 9 sq m or larger pens?","o":["More fence-pacing and vocalization","Increased general activity and visual exploration, less stereotypy, and more positive interactions","Ceased all vocalization and needed no walks","Preferred single-compartment stainless housing"],"a":1,"e":"Dogs in 9 sq m or larger pens showed more activity and exploration, less stereotypy, and more positive interactions."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Where should surgery and recovery rooms sit relative to other zones?","o":["Inside the public lobby to showcase operations","At a distance from isolation areas but close to animal housing to minimize patient movement","Connected to the intake sally port to save space","Inside the feline cohousing room for a home-like recovery"],"a":1,"e":"Place surgery and recovery away from isolation yet near housing to minimize transport of surgical patients."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Why must a feline litter box accommodate the cat's entire body?","o":["So 4 kittens from different litters can share it","To help the HVAC reach 10 to 20 ACH","Because a too-small box harms welfare and can cause house soiling","To remove the need for a connecting portal"],"a":2,"e":"ASV: the litter box must fit the whole body and allow posturing; too small harms welfare and risks house soiling."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"For cats that fight at the moment of initial introduction, what is the documented long-term risk?","o":["10 times more likely to have panleukopenia vaccine failure","Nearly 40 times more likely to keep fighting in following weeks and months","Automatically a length of stay under 5 days","50 times more likely to guard elevated perches"],"a":1,"e":"Cats that fight at introduction are nearly 40 times more likely to continue fighting later, a strong signal to separate."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"ASV cautions that attention to ventilation and air quality will NOT overcome which problems?","o":["Inadequate housing, poor sanitation, or lax population management","Seasonal shedding and coat changes","Staff scheduling conflicts","High adoption demand"],"a":0,"e":"ASV: good air quality cannot compensate for inadequate housing, poor sanitation, or lax population management."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Capacity for Care (C4C) is best described as:","o":["The number of cages physically present in the building","The maximum animals a shelter can house while still meeting each animal's full standard of care","The annual live release rate","The square footage of the medical suite"],"a":1,"e":"C4C is a welfare ceiling: the most animals that can be housed while still meeting the full standard of care, not a raw cage count."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"How must isolation rooms relate to the rest of the housing, and what supports PPE use?","o":["Open directly into the nearest ward for quick access","Not open directly into another housing area; use a corridor or vestibule that also serves for donning and doffing PPE","Share an open doorway with intake to speed transfers","Connect to the lobby for public viewing"],"a":1,"e":"ASV: isolation must not open directly into another housing area; a corridor or vestibule provides separation and a PPE space."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Where should animal intake occur within the facility?","o":["In the busiest part of the public lobby","In a designated quiet space away from the main foot traffic, with elevated surfaces for carriers","In the surgery suite to centralize handling","In the isolation corridor"],"a":1,"e":"ASV: intake should occur in a quiet space away from foot traffic, with elevated surfaces to keep carriers off the floor."},{"type":"mcq","domain":"Physical Health","sub":"Facility/Environment","q":"Why are smaller cohousing spaces that allow an all-in/all-out approach advantageous?","o":["They permit constant addition of new animals","They let enclosures be fully sanitized between groups and eliminate repeated new-introduction risk","They remove the need for monitoring","They allow more than six cats safely"],"a":1,"e":"All-in/all-out lets the space be sanitized between groups and avoids the stress and disease risk of repeated introductions."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A stray dog presents with a compound femoral fracture and severe internal hemorrhage, wearing a collar with a rabies tag and a legible microchip. The legal stray hold is 5 days. What is the correct protocol?","o":["Euthanize immediately without documentation to save costs","Provide palliative stabilization, attempt to contact the owner, and perform immediate humane euthanasia only if a licensed vet documents irremediable suffering in writing and with photos","Wait out the 5-day hold with no analgesia to preserve bloodwork","Move the dog to the adoption floor for 2 hours to see if a rescue claims it"],"a":1,"e":"A vet must document irremediable suffering in writing (photos advisable) to euthanize before the hold; ID triggers owner tracking and interim palliative care."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Why do manufacturers add phenytoin to sodium pentobarbital in some euthanasia formulations?","o":["It acts as a local anesthetic to prevent stinging during SC injection","It causes skeletal muscle paralysis before loss of consciousness","It speeds cardiac arrest and, as a combination product, is DEA Schedule III rather than Schedule II, increasing shelter accessibility","It neutralizes the drug's toxicity on human skin contact"],"a":2,"e":"Phenytoin is a cardiotoxic adjunct; the combination product is Schedule III (vs Schedule II for pentobarbital alone), which improves shelter access."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Giving IV sodium pentobarbital to a calm adult dog, what is the operational sequence of stages?","o":["Medullary paralysis, involuntary excitement, surgical anesthesia, voluntary excitement","Sedation, involuntary excitement, light anesthesia, deep anesthesia, apnea then cardiac arrest","Apnea, surgical anesthesia, involuntary excitement, deep sedation","Voluntary excitement, medullary paralysis, light anesthesia, deep sedation"],"a":1,"e":"The operational IV sequence is sedation, involuntary excitement, light anesthesia, deep anesthesia, then apnea followed by cardiac arrest."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A technician euthanizing feral kittens by IP pentobarbital makes which critical error?","o":["Dosing at 3 mL per 10 lb","Inserting the needle into the upper left quadrant to target the spleen","Aspirating before injection to confirm the needle is not in bladder or bowel","Placing kittens in a dark, quiet space after injection"],"a":1,"e":"IP injection must go into the right lower quadrant to avoid liver, spleen, and kidney; aiming at the spleen is the error."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which constellation is specifically diagnostic of compassion fatigue (secondary traumatic stress)?","o":["Boredom with tasks, feeling underpaid, and a clean facility","Feeling powerless, intrusive thoughts, guilt, paranoia, sleep disturbance, plus stomach ulcers and high blood pressure","A desire for professional development and extra shifts","Switching from humor to more regular exercise"],"a":1,"e":"Compassion fatigue presents with powerlessness, guilt, intrusive thoughts, paranoia, sleep disturbance, and physical signs like ulcers and high BP."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A premix of acepromazine and ketamine is used to sedate an aggressive dog. What is a key limitation of acepromazine?","o":["It provides profound analgesia and fully protects the handler","It can cause paradoxical CNS stimulation or aggression and lowers blood pressure, making venipuncture difficult","It converts the compound from Schedule III to Schedule I","It is a neuromuscular blocker causing paralysis while conscious"],"a":1,"e":"Acepromazine gives no analgesia and no protection from aggression, can cause paradoxical stimulation, and lowers BP, complicating venipuncture."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A near-term pregnant dog undergoes a population-control ovariohysterectomy. What is the most humane fetal handling?","o":["Cut the uterus open immediately to expose fetuses to air and light","Remove the uterus en bloc, keep it intact and unopened, and wrap it so the fetuses pass away undisturbed via hypoxia in a closed system","Perform chest compressions on each fetus through the abdominal wall","Submerge the intact uterus in a chilled water bath"],"a":1,"e":"Keeping the uterus intact and wrapped lets fetuses pass undisturbed; opening it can transition a near-term fetus to air-breathing and a struggle to breathe."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which pair of tools is used to definitively confirm death in a dog or cat before disposal?","o":["Microchip scanner and calculator","Stethoscope (cardiac arrest) and penlight (loss of corneal reflex)","Pulse oximeter and leather gloves","Thermometer and blood pressure cuff"],"a":1,"e":"Confirm death with cardiac auscultation by stethoscope and loss of the corneal reflex checked with a penlight, regardless of method."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Regarding snake euthanasia, which statement is correct?","o":["Place the snake in a freezer overnight","The heart is about one-third of the distance from head to tail and can be located by palpation or Doppler for IC injection once anesthesia is verified","Pentobarbital can be given SC along the dorsal midline","The body can be disposed of immediately after injection"],"a":1,"e":"Freezing is unacceptable; the snake heart sits about one-third from the head, and IC is used only after verified anesthesia, with a 24 to 48 h observation hold."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which layout is recommended for a dedicated euthanasia room?","o":["A large room in a high-traffic hallway with upbeat music","A quiet, well-lit, well-ventilated room away from foot traffic, with a lockable door, counter-height surfaces, and access to body storage","A dark, unventilated closet next to the dog runs","A communal room where up to three animals are euthanized in view of each other"],"a":1,"e":"The euthanasia room should be quiet, well-lit, well-ventilated, low-traffic, lockable, with paperwork and procedure surfaces and morgue access."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which protocol aligns with standard equine euthanasia?","o":["One person using oral pentobarbital in grain","Two experienced handlers, a pre-euth tranquilizer (eg xylazine or detomidine), then IV jugular pentobarbital at 1 mL per 10 lb (often 60 to 120 mL)","Intrahepatic T61 with no sedation","Rapid cervical dislocation with heavy restraint"],"a":1,"e":"Equine euthanasia uses two experienced handlers, pre-euth tranquilizer, and IV jugular pentobarbital at 1 mL per 10 lb."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Why is intrahepatic injection of pentobarbital classified as unacceptable?","o":["The liver has no blood vessels, so absorption is impossible","The liver capsule has stretch receptors that are exquisitely painful when stimulated","It instantly denatures pentobarbital into a non-lethal compound","It requires at least 50 mL of solution"],"a":1,"e":"The liver capsule's stretch receptors make intrahepatic injection exquisitely painful, so the route is unacceptable."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"How does the commercial label dose of pentobarbital compare to the true lethal dose?","o":["Exactly equal to the lethal dose","10% lower to preserve stock","30 to 50% higher than the lethal dose, as a safety cushion for a humane death","Five times lower, so technicians must triple the directions"],"a":2,"e":"The label dose runs 30 to 50% above the lethal dose as a cushion to guarantee a humane death when given correctly."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A euthanasia-team member shows belligerence, chronic absenteeism, and callous animal handling. How are these categorized?","o":["Mature defenses to encourage","Negative coping mechanisms or immature defenses from euthanasia-related stress","Operational efficiencies indicating good boundaries","Burnout fully resolved by quieter clippers"],"a":1,"e":"Belligerence, absenteeism, and callous handling are negative or immature defenses arising from euthanasia-related stress."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which is a positive, mature coping strategy for euthanasia staff?","o":["Displacing frustration onto the surrendering public","Mature defenses such as altruism, sublimation, anticipation, and humor","Withdrawing from peers and denying distress","Increasing length-of-stay metrics"],"a":1,"e":"Altruism, sublimation, anticipation, and humor are the mature defenses; the others are negative coping or unrelated."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A facility must euthanize fish and amphibians. Which agent and protocol is correct per the AVMA 2020 edition?","o":["Oral pentobarbital paste","MS-222 (tricaine methanesulfonate) by immersion, maintained at least 30 minutes after opercular movement ceases, followed by an adjunctive method to confirm death","Carbon monoxide via a sealed aquatic chamber","Acepromazine poured into the holding tank"],"a":1,"e":"MS-222 is the only FDA-approved fish agent; AVMA 2020 raised immersion to at least 30 min after opercular movement stops, plus an adjunctive confirmatory method."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Why is the absence of written euthanasia criteria an operational and emotional hazard?","o":["It raises municipal licensing fees","It burdens staff, lets bias and inconsistency drive decisions, and makes choices look arbitrary to stakeholders","It invalidates the DEA license automatically","It prevents using the IV route"],"a":1,"e":"Without written criteria, decisions become inconsistent and biased, burden staff, and appear arbitrary to stakeholders."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which statement reflects the national landscape of shelter euthanasia regulation?","o":["Every state requires a vet to press the plunger","Regulations vary; some states allow certified technicians direct access to pentobarbital, others require indirect access or veterinary oversight","Pentobarbital is unregulated in municipal facilities","All states ban pre-euth sedatives"],"a":1,"e":"State rules vary widely on technician access and veterinary oversight of pentobarbital."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Why does the ASV deem CO gas chambers unacceptable for shelter euthanasia?","o":["It cannot be made from commercial cylinders","It poses severe human safety hazards, can explode and leak, and causes inconsistent, prolonged distress, especially in young, old, sick, or pregnant animals","It turns the coat bright red, blocking skin testing","It reacts with pentobarbital to corrode kennels"],"a":1,"e":"CO is unacceptable on humane, operational, and safety grounds: operator hazard, explosion and leak risk, and prolonged distress in vulnerable animals."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A feral queen and her four 3-week-old kittens are presented for euthanasia. How should this unit be processed?","o":["Move kittens away and euthanize them 24 hours apart","Euthanize the mother first so she is not distressed by separation or seeing dead offspring, then the neonates immediately after","Euthanize the kittens first while restraining the mother nearby","Place them in a group room with unfamiliar adult cats first"],"a":1,"e":"The pediatric exception: euthanize the mother first, then the neonates immediately after."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"After euthanizing a dog with sarcoptic mange, what sanitation step is required before the next animal?","o":["Wipe with a dry paper towel to remove fur","Thoroughly clean all blood, urine, feces, and residue with a neutral deodorizing solution to remove alarm pheromones","Leave the table uncleaned for two hours to air-dry","Cover the residue with newspaper"],"a":1,"e":"Clean all residue with a neutral deodorizing solution to remove alarm pheromones before the next animal."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"What is the mechanism by which CO induces hypoxia and death?","o":["It is a neuromuscular blocker freezing the intercostals while the animal stays alert","It binds hemoglobin to form carboxyhemoglobin, blocking red cells from taking up and transporting oxygen","It causes medullary paralysis within 2 to 3 seconds of skin contact","It drops gastrointestinal pH and stimulates liver stretch receptors"],"a":1,"e":"CO forms carboxyhemoglobin, blocking oxygen uptake and transport, producing hypoxia."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"A painful dog is sedated with xylazine. What side effect can lower the quality of the euthanasia if the animal is not fasted or combined with other drugs?","o":["It frequently causes vomiting in dogs and cats and lowers blood pressure, making venipuncture difficult","It permanently expands the liver capsule","It completely blocks pentobarbital at the brain","It converts the barbiturate into a Schedule I hallucinogen"],"a":0,"e":"Xylazine often causes vomiting and lowers BP (harder venipuncture, delayed pentobarbital); fast the animal or combine with ACE or ketamine."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"How should a technician manage body language and voice with a fearful dog?","o":["Shout commands and lean over the dog's head","Remain calm, quiet, and composed, work slowly, and avoid leaning over the dog, which is a threatening posture","Move fast without speaking, using maximum control-pole pressure","Let the public and media in to create a distracting crowd"],"a":1,"e":"Stay calm and slow and avoid leaning over the dog, which is intimidating and heightens fear."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which scheduling strategy mitigates burnout and compassion fatigue on the euthanasia team?","o":["Assign one technician to all euthanasia permanently","Rotate duties among trained staff and let technicians choose trusted coworkers or decline animals they are attached to","Restrict euthanasia to the final 10 minutes of a 12-hour shift, alone","Eliminate regular training"],"a":1,"e":"Rotate duties, allow trusted teammates, and let staff opt out of animals they are attached to."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Physical avian methods (thoracic compression, decapitation, cervical dislocation) are conditionally acceptable. Why does the guide advise against them?","o":["They need gas chambers banned in 50 states","More humane methods exist and several experts consider these physical methods inhumane","They cause chemical explosions endangering staff","They prevent verifying death via corneal reflexes"],"a":1,"e":"They are discouraged because more humane methods are available and some experts consider them inhumane."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"What is the primary site of action of IV pentobarbital, and how long to cross into it?","o":["The liver capsule; 15 to 30 minutes","The brain; 45 to 90 seconds","The renal cortex; 5 to 15 minutes","The myocardium; exactly 4 minutes"],"a":1,"e":"Pentobarbital acts primarily on the brain, crossing in about 45 to 90 seconds after IV injection."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Why is the IP route favored in shelters for a 4-pound stray kitten?","o":["It bypasses the brain and stops the heart in 2 seconds","It gives a humane, smooth death for fearful, feral, or small animals under 10 lb when IV access is impractical and chemical restraint is limited","It needs only 10% of the IV dose volume","It triggers voluntary excitement that clears the room of virus"],"a":1,"e":"IP is humane for small (<10 lb), feral, or fearful animals when IV is impractical and sedation options are limited."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"In progressive shelter legislation and organizational mandates, what does EBI stand for?","o":["External Body Inspection","Euthanasia By Injection","Emergency Barbiturate Intake","Environmental Biosecurity Isolation"],"a":1,"e":"EBI is euthanasia by injection, the preferred shelter method; AHA, HSUS, and NACA offer EBI training."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"To avoid euthanizing the wrong animal, what verification sequence is required before injecting?","o":["Double-check ID against paperwork, verify authorization, search the database and photos for recent reclaim calls, and re-scan for a microchip","Ask a volunteer in the hallway if they recognize the animal","Check only the cage card, assuming it is accurate","Proceed if the coat color matches a breed description"],"a":0,"e":"Confirm ID against paperwork, verify authorization, check for reclaim calls, and re-scan the microchip before any injection."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"If CO is used despite ASV opposition, the AVMA contingencies require which gas concentration target?","o":["A uniform concentration of at least 6% after animals are placed in the chamber","A maximum of 2% to keep animals calm","Exactly 12% to ensure an explosion-free margin","Any concentration as long as the chamber is indoors"],"a":0,"e":"The AVMA contingency is a flow rate adequate to rapidly reach a uniform concentration of at least 6% after loading; death still takes 10 to 20 minutes."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Which animals are most likely to have delayed CO uptake, prolonging time to death?","o":["Only large adult dogs","Animals under 16 weeks, geriatric, sick, injured, or pregnant","Only animals over 10 years","None; CO acts uniformly across all animals"],"a":1,"e":"Animals under 16 weeks, geriatric, sick, injured, or pregnant have delayed CO uptake; CO is also explosive above 10%."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"How does depopulation differ from euthanasia in the shelter context?","o":["They are identical terms","Depopulation is the rapid destruction of a whole population in extraordinary emergencies and is a last resort, not a routine outbreak response; EBI per AVMA 2020 is preferred when feasible","Depopulation only applies to healthy animals","Euthanasia is for populations and depopulation is for individuals"],"a":1,"e":"Depopulation is population-scale and emergency-driven, a last resort; in shelters EBI per AVMA 2020 is preferred over depopulation methods when feasible."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"Under what condition may an intracardiac injection be performed?","o":["On any conscious animal if performed quickly","Only on a heavily sedated, anesthetized, unconscious, or comatose animal","On conscious cats but not dogs","Only when IV access has failed twice"],"a":1,"e":"Per ASV, IC injection may be performed only on anesthetized or unconscious animals; on a conscious animal it is unacceptable."},{"type":"mcq","domain":"Physical Health","sub":"Euthanasia","q":"What does the ASV say about staffing for administering injectable euthanasia?","o":["A single person should always work alone for consistency","Administration may require two trained people for safe and humane handling","Only a licensed veterinarian may be present","No training is needed if pentobarbital is pre-measured"],"a":1,"e":"The ASV notes that injectable euthanasia may require two trained people for safe and humane handling."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Reviewing baseline data, which finding confirms a healthcare-program deficiency under the explicit ASV indicators?","o":["Disease rates are tracked in manual logs rather than a database","An animal shows a measurable decline in physical, mental, or social welfare after intake","A treatment protocol is set for an animal with low live-outcome potential","The facility runs at 95% of capacity during a summer surge"],"a":1,"e":"A decline in animal health and welfare after intake is a listed deficiency indicator; the others are preferences, decisions, or capacity strain."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which area is NOT an explicitly required core component of shelter medical protocols?","o":["Animal housing and sanitation","Clinical diagnosis and treatment","Public relations, volunteer onboarding, and donor communication","Decision-making and internal communication"],"a":2,"e":"Protocols must include diagnosis, treatment, housing, sanitation, decision-making, and communication; PR, fundraising, and onboarding are not listed."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What risk does inappropriate antibiotic use (for example to prevent a viral infection) create?","o":["It invalidates population-level VCPRs","It can cause harmful side effects and promote antibiotic resistance","It causes a rapid drop in body condition score","It forces transfer to an outside emergency plan"],"a":1,"e":"Giving antibiotics when not indicated causes harmful side effects and promotes antibiotic resistance."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A dog has been in the shelter's foster network for 7 months. Which evaluations are overdue?","o":["A daily check by a veterinarian and a weekly CBC","A monthly reweigh and BCS update, and a semi-annual comprehensive exam","An intake capacity assessment and a quarterly behavioral review","A weekly weight check and an annual physical exam"],"a":1,"e":"Monthly reweigh and BCS are required, and a comprehensive exam is due at least every 6 months including foster; at 7 months the exam is overdue."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the maximum permissible interval between visual health observations for any individual animal?","o":["At least every 12 hours","At least every 24 hours","At least every 48 hours","At least every 7 days"],"a":1,"e":"Trained personnel must visually observe every animal at least once every 24 hours."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which set must appear on a compliant prescription drug label?","o":["Client income bracket and manufacturer lot code","Prescribing vet, shelter name and address, patient ID and species, drug details, directions, and cautionary statements","Historical BCS and the next exam date","A liability waiver and the emergency clinic phone number"],"a":1,"e":"The seven label components are prescriber, clinic/shelter contact, patient ID and species, dates, drug details, directions, and cautionary statements."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which combination of non-pharmacological pain modalities is explicitly approved?","o":["High-protein treats, background music, cold laser, and fluids","Presence of littermates, a quiet environment, massage, physical therapy, heat, and deep bedding","Isolation from conspecifics, outdoor runs, acupuncture, and visual barriers","Increased calories, scent enrichment, and extended exercise"],"a":1,"e":"The approved adjuncts are littermates, a quiet environment, massage, physical therapy, heat, and deep bedding."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"An after-hours polytrauma case cannot be stabilized and interventions fail to relieve distress. What is the directive?","o":["Place on deep bedding and monitor every 24 hours","Euthanize the animal to relieve suffering","Suspend protocols until the 6-month exam","Apply a prescription label with only the shelter name and phone"],"a":1,"e":"If the emergency plan cannot be implemented or fails to relieve suffering, the animal should be euthanized."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which is NOT one of the six factors that impact a shelter's capacity to provide individual medical care?","o":["The number of animals requiring treatment","The likelihood and consequences of pathogen transmission","The animal's breed, coat length, and pedigree registration","The animal's potential for a live outcome"],"a":2,"e":"The six factors are resources, duration, number needing treatment, transmission likelihood and consequences, recovery likelihood, and live-outcome potential; breed and pedigree are not among them."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"During daily visual checks, what must personnel record alongside food intake?","o":["BCS, body weight, and drug expiration date","The prescribing vet's name and treatment protocols","Enclosure conditions, including the presence of feces, urine, or vomit","Handling techniques and the nearest emergency clinic location"],"a":2,"e":"Alongside food intake, note enclosure condition including feces, urine, or vomit."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"How does the ASV (after the WHO) define health?","o":["The absence of clinical disease on physical exam","A state of complete physical, mental, and social well-being, not merely the absence of disease or infirmity","A passing score on a standardized welfare audit","Normal vital signs and a body condition score of 5 out of 9"],"a":1,"e":"Health is complete physical, mental, and social well-being, not merely the absence of disease or infirmity."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When must shelter medical care begin?","o":["After the legal stray hold expires","At or before intake, continuing throughout the stay","Only once an animal shows clinical signs","At the first comprehensive exam at 6 months"],"a":1,"e":"Shelter medical care must begin at or before intake and continue throughout the stay."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Population health is most threatened when:","o":["Every animal receives an individual comprehensive exam","Disease spread is likely, long stays push the shelter over capacity for care, and one animal's costs drain resources for others","The shelter tracks morbidity and mortality trends","Animals are vaccinated at intake"],"a":1,"e":"Likely spread, over-capacity from long stays, and resource-draining costs are the population-health threats ASV identifies."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the purpose of a written treat-versus-cannot-treat protocol?","o":["To guarantee every animal is treated regardless of resources","To pre-define which animals and conditions the shelter can and cannot responsibly treat, supporting consistent, transparent decisions","To replace the need for a veterinarian","To set adoption fees by diagnosis"],"a":1,"e":"A pre-set protocol defines what the shelter can and cannot treat, supporting consistent and transparent decision-making."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Under the ASV definitions, what distinguishes indirect from direct veterinary supervision?","o":["Indirect supervision requires the vet to be physically present","In indirect supervision the vet need not be on the premises but gives instructions, is reachable immediately, and has assumed responsibility","Indirect supervision means no veterinarian is involved at all","Direct supervision is performed only by telemedicine"],"a":1,"e":"Indirect supervision: the vet is off-site but has given instructions, is immediately reachable, and has assumed responsibility; direct means readily available on the premises."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What does 'direct knowledge' of a shelter population mean in the ASV supervision framework?","o":["The vet has read the shelter's written protocols once","The vet regularly visits and examines the shelter population in person","The vet holds a license in the same state","The vet has telephoned the shelter at least monthly"],"a":1,"e":"Direct knowledge means the veterinarian regularly visits and examines the shelter population in person."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the ASV position on telemedicine and the VCPR?","o":["A VCPR can never be created remotely","Telemedicine can broaden access, and the ASV supports allowing VCPRs to be created and prescriptions made through electronic communication","Telemedicine replaces all in-person veterinary care","Prescribing through telemedicine is prohibited in all jurisdictions"],"a":1,"e":"The ASV supports creating VCPRs and prescribing through telephone, digital, or electronic communication, within jurisdictional limits."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Before a medication is prescribed, the ASV prescribing standard requires:","o":["Only that the drug is in stock","A reasonable presumptive diagnosis, the ability to administer as directed, and a plan to monitor the course","Approval from the board of directors","That the animal has been in care at least 30 days"],"a":1,"e":"Prescribe only with a reasonable presumptive diagnosis, ability to administer as directed, and a monitoring plan."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When should a comprehensive physical examination ideally be performed at intake?","o":["Within 24 hours of intake","Only at the 6-month mark","After the stray hold expires","Within 7 days of intake"],"a":0,"e":"A comprehensive physical exam is ideally performed within 24 hours of intake, after at least a cursory assessment on arrival."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the ASV general recommendation on FeLV and FIV screening?","o":["Never test any shelter cat","In general, screen all cats for retroviruses, while assessing each cat's individual risk","Test only cats over 10 years old","Test only cats that are being euthanized"],"a":1,"e":"In general all cats should be screened for retroviruses, with individual risk assessment guiding decisions."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which cats should be tested for FeLV and FIV per the ASV position statement?","o":["Healthy feral cats in TNR programs","High-risk cats, including those entering group housing and those who are ill","Only cats already confirmed positive","No cats, since testing is never cost-effective"],"a":1,"e":"High-risk cats, including those entering group housing and ill cats, should be tested; healthy feral TNR cats are not recommended for testing."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A clinically healthy shelter cat has a single positive point-of-care FeLV test. What does the ASV recommend?","o":["Immediate euthanasia","Do not euthanize on a single positive; confirm per AAFP guidelines and seek informed placement","Release without any record of the result","Place directly into group housing"],"a":1,"e":"The ASV does not recommend euthanizing a clinically healthy cat on a single positive; confirm per AAFP guidelines and seek informed placement."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the ASV stance on quarantining healthy animals at intake?","o":["It is mandatory for every animal for 30 days","It is not generally recommended; reserve quarantine for animals with high-risk infectious-disease exposure","It replaces the need for isolation","It is required only for cats"],"a":1,"e":"Quarantining healthy animals at intake is not generally recommended; unnecessary holds lengthen stays and harm welfare."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the ASV stance when pain cannot be adequately relieved?","o":["Withhold all analgesia to avoid masking signs","Failure to treat pain is unacceptable, and euthanasia is a legitimate part of treatment when suffering cannot be relieved","Pain is acceptable if the animal is adoptable","Defer treatment until the 6-month exam"],"a":1,"e":"Failure to treat pain is unacceptable; treatment of pain can include euthanasia when suffering cannot be relieved."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When pain can be anticipated, such as before surgery, when should analgesia be given?","o":["Only after the animal shows overt pain","Before the painful event (pre-emptive), at an appropriate strength and duration","Never, to avoid drug interactions","Only if the animal is over 6 months old"],"a":1,"e":"Provide pain control before an anticipated painful event, at an appropriate strength and duration."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which is a documented consequence of unrelieved pain?","o":["Improved appetite and faster adoption","Weight loss, muscle breakdown, increased blood pressure, and prolonged recovery","Increased resistance to infectious disease","A lower body temperature with no welfare impact"],"a":1,"e":"Unrelieved pain can cause weight loss, muscle breakdown, increased blood pressure, prolonged recovery, and distress."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"How does the ASV say an animal's legal status affects medical treatment?","o":["Legal-hold animals may not be treated until released","Legal status must never interfere with necessary care or treatment of painful or significant conditions","Only the court can authorize analgesia","Evidence animals receive no preventive care"],"a":1,"e":"Legal status must never interfere with necessary preventive care or treatment of painful injuries, illness, debilitating conditions, or urgent behavioral needs."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A shelter is legally required to hold an injured animal whose suffering cannot be alleviated. What does the ASV advise?","o":["Continue the hold without treatment until the case closes","Seek permission to euthanize the animal","Transfer the animal to adoption immediately","Withhold analgesia to preserve evidence"],"a":1,"e":"If suffering cannot be alleviated, the shelter should seek permission to euthanize the legally held animal."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What defines a disease outbreak in a shelter?","o":["Any single sick animal","More than the usual number of animals affected, or an increase in case severity","Only laboratory-confirmed zoonoses","A failed sanitation audit"],"a":1,"e":"An outbreak is more than the usual number of affected animals, or an increase in the severity of cases."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"How should an animal with suspected infectious disease be managed on arrival?","o":["Placed directly into the general adoption ward","Isolated until a veterinarian or treatment determines it low-risk to the population","Returned to the community immediately","Cohoused with other sick animals of any species"],"a":1,"e":"Isolate suspected infectious animals until determined low-risk; leaving severe infectious disease in the general population is unacceptable."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Which is a mandatory component of a shelter's emergency medical plan under the ASV guidelines?","o":["A staff veterinarian must be physically on-site 24 hours a day","Non-veterinary staff must be trained to recognize distress, injury, or significant illness so they can initiate prompt care or humane euthanasia","All emergencies must be treated on-site to minimize transfer costs","Expired emergency drugs may be used within 6 months of the stamped date"],"a":1,"e":"The ASV requires care staff to be trained to recognize emergencies so timely care or humane euthanasia can be enacted without delay."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A 3-week-old orphaned puppy is obtunded, hypothermic, and weak. After stabilizing core temperature, what is the highest-priority diagnostic and treatment pairing?","o":["Run a urine dipstick and give IV furosemide","Check blood glucose; if low, give a diluted 50% dextrose solution IV or IO","Check PCV and give IM methocarbamol","Percuss the chest and start a lidocaine infusion"],"a":1,"e":"Neonates have minimal glycogen reserves; check blood glucose and correct hypoglycemia with diluted dextrose (rewarm before feeding)."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A dyspneic cat has an orthopneic posture, open-mouth breathing, and dull or absent lung sounds ventrally. How is this prioritized and interpreted?","o":["Upper-airway stridor; prepare an emergency tracheostomy","Severe diaphragmatic hernia requiring abdominal palpation","Pleural effusion; give oxygen and prepare for thoracocentesis","Normal feline compensation for a high-stress environment"],"a":2,"e":"Muffled or absent ventral lung sounds in a dyspneic cat suggest pleural effusion; provide oxygen and prepare thoracocentesis."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A hit-by-car dog has pale-to-muddy mucous membranes, a CRT over 2.5 seconds, and weak peripheral pulses. Which state is this?","o":["Hyperdynamic phase of distributive shock","Decompensatory hypovolemic shock","Normal post-exercise physiology","Increased intracranial pressure"],"a":1,"e":"Pale/muddy MM, prolonged CRT, and weak pulses indicate decompensatory hypovolemic shock as blood pressure can no longer be sustained."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A stray cat is in active generalized status epilepticus. Which sequence is the standard of care to halt the seizure?","o":["IV mannitol then atropine","IV or rectal diazepam; if seizures persist, an induction agent such as propofol or alfaxalone to effect","IM methocarbamol with SC dexamethasone","Hypertonic saline bolus then oral phenobarbital"],"a":1,"e":"Benzodiazepines are first-line to stop active seizures, followed by an injectable anesthetic if refractory."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A cat with massive topical permethrin exposure has severe continuous muscle tremors. Which drug specifically addresses the tremors?","o":["Epinephrine","Furosemide","Methocarbamol","Atropine"],"a":2,"e":"Methocarbamol is a centrally-acting muscle relaxant used to control the tremors of feline permethrin toxicosis."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A dog with head trauma is stuporous with asymmetric pupils, bradycardia, and rising blood pressure (Cushing reflex). Which drug is indicated for the suspected raised intracranial pressure?","o":["Lidocaine","Mannitol","Dopamine","Apomorphine"],"a":1,"e":"Mannitol is an osmotic diuretic that draws fluid from the cerebral interstitium into the vasculature, lowering intracranial pressure."},{"type":"mcq","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"A shelter dog arrests during stabilization and the ECG shows asystole. Which drug is given first in advanced life support?","o":["Lidocaine","Atropine","Epinephrine","Diazepam"],"a":2,"e":"Epinephrine is the first drug for asystole, causing vasoconstriction to direct blood to the coronary and cerebral circulation during CPR."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A 200 g orphaned kitten needs tube feeding. What is the maximum safe single-feeding volume, given neonatal stomach capacity?","o":["2 mL","9 mL","22 mL","40 mL"],"a":1,"e":"Stomach capacity is about 40 to 50 mL/kg; 0.2 kg x 45 mL/kg is roughly 9 mL. Exceeding it risks reflux and fatal aspiration."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A 10-day-old kitten is hypothermic (91 F), hypoglycemic, and recumbent. What is the correct initial sequence?","o":["Immediately tube-feed 10 mL of warm milk replacer","Rewarm to near-normothermia first, then give warm fluids with dextrose (SC or IO), withholding oral intake until normothermic","Give a cold SC dextrose bolus and a warm water bath","Inject enrofloxacin and place in a 105 F incubator"],"a":1,"e":"A cold gut has ileus; feeding ferments milk and causes endotoxemia. Rewarm first, then warm dextrose-containing fluids; feed only once normothermic."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A litter of 4-week-old kittens is ready to wean. Which method is correct?","o":["Abruptly remove the queen and offer dry adult kibble in a deep bowl","Offer a warm semisolid slurry of kitten food in a shallow pan, completing weaning from formula by 5 to 6 weeks","Bottle-feed formula exclusively until 8 weeks","Feed ground raw beef with cow's milk by syringe pump"],"a":1,"e":"Weaning starts at 3 to 4 weeks with a warm semisolid slurry in a shallow pan; complete weaning from formula by 5 to 6 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Cats in a ward cleaned with a quaternary ammonium disinfectant at 4x the correct dilution develop hypersalivation, anorexia, and tongue ulcers. What is the cause?","o":["An immune reaction to DA2PP antigens","Caustic mucosal injury from grooming residual quaternary ammonium compound off the fur","Systemic organophosphate toxicity from run-off","Permethrin neurotoxicity of cranial nerves"],"a":1,"e":"Improperly diluted quaternary ammonium compounds are caustic; cats groom the residue off and develop glossal ulceration and hypersalivation."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why are cats uniquely sensitive to permethrin?","o":["No functional renal filtration of lipophilic compounds","A genetic deficiency of hepatic glucuronosyltransferase (UGT1A6 is a pseudogene), impairing conjugation and prolonging exposure","High density of dermal nicotinic receptors","Structural fragility of feline hemoglobin"],"a":1,"e":"Cats have a UGT (glucuronidation) deficiency, not a complete absence; this contributes to permethrin sensitivity through accumulation of potent metabolites."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An 11-year-old arthritic dog at 5 months in the shelter is reactive, anorexic, and curled in the back corner 90% of the time. Which finding confirms an unlivable QOL state?","o":["Greeting a familiar caretaker who brings high-value treats","Constant hyper-vigilance, inability to rest relaxed, and a persistent shift toward unpleasant over pleasant states","Occasional vocalization when neighboring dogs are moved","Stable body weight and BCS on monthly audits"],"a":1,"e":"QOL is the balance of feelings; persistent hyper-vigilance, no relaxed rest, and dominance of unpleasant states indicate an unlivable state."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"How does McMillan's model define quality of life?","o":["A checklist of normal vital signs","The animal's affective and cognitive assessment of its life as a balance of pleasant and unpleasant feelings","The number of enrichment items in the enclosure","The veterinarian's prognosis score"],"a":1,"e":"QOL is the animal's affective and cognitive self-assessment, driven by the balance of pleasant versus unpleasant feelings."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which is a recognized stress indicator in shelter cats?","o":["Increased exploratory play in the first 24 hours","Hiding, apathy, low activity, and feigned sleep, with hiding negatively correlated with cortisol","A rising body weight in week one","Eager approach to unfamiliar handlers"],"a":1,"e":"Hiding, apathy, low activity, and feigned sleep indicate feline stress; hiding negatively correlates with cortisol and aids coping."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which set of signs indicates stress in a newly admitted shelter dog?","o":["Relaxed posture and steady appetite","Displacement behaviors, looking back at the handler, lip licking, body shaking, and yawning","A single bark at intake then settling","Immediate solicitation of play"],"a":1,"e":"Displacement behaviors, lip licking, yawning, body shaking, and looking back at the handler are early canine stress signs."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"On the Villalobos HHHHHMM (H5M2) scale, what cumulative score generally indicates that quality of life has become unacceptable?","o":["Below 35 out of 70","Above 60 out of 70","Exactly 50 out of 70","Any score with mobility above 5"],"a":0,"e":"Each of the seven variables is scored 0 to 10; a total above 35 suggests acceptable QOL, and below 35 suggests it has become unacceptable."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What does the AAFCO statement of nutritional adequacy on a pet-food label indicate?","o":["The product is organic and grain-free","How the diet meets nutritional requirements and for which life stage; it should not be expired","The wholesale price of the product","That the food was made in the United States"],"a":1,"e":"The AAFCO statement indicates nutritional adequacy and life stage; AAFCO sets pet-food standards, and the statement should not be expired."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which nutrients must cats obtain pre-formed because they cannot synthesize them adequately?","o":["Vitamin C and fiber","Taurine, arginine, and vitamin A","Calcium and phosphorus only","Omega-9 fatty acids and starch"],"a":1,"e":"As obligate carnivores, cats require pre-formed taurine, arginine, and vitamin A, which a meat-derived diet supplies."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the standard ceiling for treats as a fraction of an animal's daily caloric intake?","o":["Up to 50%","No more than 10%","Between 25 and 40%","Unlimited if the diet is complete and balanced"],"a":1,"e":"The standard is the 10% rule: treats should not exceed 10% of daily calories (correcting the 10 to 25% figure in the dog notes)."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why are raw diets discouraged for shelter cats and dogs?","o":["They are too expensive to source","They are seldom nutritionally balanced and carry bacterial contamination and public-health risk","They cause immediate vitamin A toxicity","They are banned by AAFCO in all states"],"a":1,"e":"Raw and home-cooked diets are seldom balanced and carry contamination and zoonotic risk (for example salmonella)."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the difference between RER and MER?","o":["RER is for cats and MER is for dogs","RER is baseline resting energy; MER applies a life-stage and activity factor to RER","They are identical terms","MER is only used for neonates"],"a":1,"e":"RER is the resting energy requirement; MER multiplies RER by a life-stage and activity factor for maintenance."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why are large, deep-chested dogs fed twice daily or more often?","o":["To increase their treat allowance","To help reduce the risk of gastric dilatation-volvulus (GDV)","Because they cannot digest dry food","To speed weight gain for adoption photos"],"a":1,"e":"Splitting feeding across the day helps reduce GDV risk in large, deep-chested dogs."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which feeding method is most appropriate for a group-housed room of healthy cats?","o":["A single communal bowl of canned food refilled weekly","Free-choice dry food kept fresh and topped up, with monitoring since non-eaters can be missed","Withholding food except for one supervised meal per week","Raw meat left out at room temperature"],"a":1,"e":"Free-choice dry food suits group-housed cats (canned spoils), but monitor because animals not eating can go unnoticed."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An adult cat in the shelter has refused all food for 4 days. Why is prompt examination important?","o":["Risk of immediate rabies shedding","Risk of hepatic lipidosis","It will void the cat's AAFCO warranty","It indicates the cat is pregnant"],"a":1,"e":"Adult cats not eating for 3 to 5 days risk hepatic lipidosis and need prompt examination."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"When refeeding a chronically starved animal, what is the principal danger?","o":["Immediate obesity","Refeeding syndrome from electrolyte shifts (phosphate, potassium, magnesium), causing weakness, seizures, and death","Permanent taurine depletion","Food aversion to all future diets"],"a":1,"e":"Rapid refeeding causes dangerous electrolyte shifts (refeeding syndrome); reintroduce nutrition gradually with monitoring."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"How often must uneaten food be discarded in shelter feeding protocols?","o":["Once per week","At least every 24 hours, and immediately if contaminated or pest-infested","Only when visibly moldy","Never, to reduce waste"],"a":1,"e":"Discard uneaten food at least every 24 hours, and immediately if contaminated or pest-infested."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the recommended feeding interval for neonates during the first few days of life?","o":["Every 8 hours","Every 2 to 3 hours","Once daily","Free-choice dry food"],"a":1,"e":"Neonates are fed every 2 to 3 hours for the first few days, then every 4 to 5 hours until 3 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What environmental temperature is appropriate for orphaned neonates in the first week of life?","o":["60 to 65 F","85 to 95 F (29 to 35 C), dropping about 5 F per week","100 to 105 F","Room temperature is sufficient"],"a":1,"e":"First-week neonatal environmental temperature is about 85 to 95 F, dropping roughly 5 F per week to 70 to 75 F by week 4."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A litter shows fading kitten syndrome. Which is part of correct supportive care?","o":["Feed the cold kittens immediately to correct energy deficit","Rewarm first, then provide tube feeding, SC fluids, and active warming, treat littermates, and rule out panleukopenia","Place all kittens in a freezer to slow metabolism","Give a single oral NSAID and observe"],"a":1,"e":"Rewarm before feeding, then supportive care (tube feeding, SC fluids, warming), treat littermates, and rule out FPV."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the approximate gestation length in the cat?","o":["About 42 days","About 65 days","About 90 days","About 115 days"],"a":1,"e":"Feline gestation is about 65 days, typically producing 3 to 5 kittens."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"By which day of feline pregnancy is serum relaxin typically elevated enough to support a diagnosis?","o":["Day 5","Day 25","Day 50","Day 60"],"a":1,"e":"Serum relaxin is elevated by about day 25; ultrasound can detect pregnancy as early as day 10, and palpation from day 14 to 17."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Using dentition, a male cat with permanent canines but small testes is approximately what age?","o":["6 to 9 months","Under 8 weeks","18 to 24 months","Over 5 years"],"a":0,"e":"Permanent canines with small testes suggest about 6 to 9 months; mature testes suggest 12 to 14 months."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An orphan kitten weighs 100 g at birth. What daily weight gain should prompt concern?","o":["A gain of 10 to 15 g per day","A gain under 7 g per day","Any gain at all","A gain over 5 g per day"],"a":1,"e":"Neonatal kittens should gain 10 to 15 g/day; under 7 g/day is inadequate and signals supplemental feeding or a health problem."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why should kittens under 6 to 8 weeks of age generally not be housed in the shelter?","o":["They cannot be microchipped at that age","High infection risk; foster care is strongly preferred","A legal hold requires it","They are too young to be photographed for adoption"],"a":1,"e":"Kittens under 6 to 8 weeks are at high infection risk and are best placed in foster care rather than housed in the shelter."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Feline acetaminophen toxicity (methemoglobinemia, Heinz-body anemia) is best explained by:","o":["Glucuronidation deficiency alone","Both deficient glucuronidation (UGT1A6) and a lack of N-acetyltransferase 2, with the p-aminophenol pathway driving methemoglobinemia","A receptor mutation in erythrocytes","Excess hepatic glucuronidation"],"a":1,"e":"Feline acetaminophen toxicity is multifactorial: deficient UGT glucuronidation plus NAT2 deficiency, with p-aminophenol producing methemoglobinemia."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which household or shelter item is a recognized feline toxicant to avoid?","o":["Plain fresh water","Baby food containing onion powder, and lilies","A complete and balanced commercial cat diet","A clean stainless steel bowl"],"a":1,"e":"Onion (including onion-powder baby foods) causes hemolytic anemia and lilies are nephrotoxic; both must be avoided in cats."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"The approximate daily water requirement for a healthy adult cat eating dry food is:","o":["5 mL/kg/day","50 mL/kg/day (approximately double what a wet-food cat needs)","200 mL/kg/day","Water requirements are the same regardless of diet type"],"a":1,"e":"Cats need approximately 50 mL/kg/day; dry-food cats must drink nearly twice as much as wet-food cats because wet food provides 70–80% water content."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter cat on an exclusively dry diet develops recurrent urinary crystals. The most likely contributing nutritional factor is:","o":["Excess dietary taurine","Insufficient voluntary water intake, producing chronically concentrated urine","Excessive wet-food supplementation","Overfeeding of treats"],"a":1,"e":"Dry-only diets increase urine concentration; cats have a low thirst drive relative to water needs, making urinary tract disease a real risk when only dry food is offered."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Signs of ≥ 5% dehydration on physical examination include:","o":["Normal skin tent and moist mucous membranes","Skin tent persisting > 1–2 seconds, tacky or dry mucous membranes, and sunken eyes","Increased urination and drooling","Bounding pulse and hyperactivity"],"a":1,"e":"At ≥ 5% dehydration: persistent skin tent, tacky/dry mucous membranes, and sunken eyes. At ≥ 10%: depression, weak pulse, prolonged CRT."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"The preferred water delivery method in a shelter with biosecurity concerns is:","o":["Communal water troughs shared among multiple animals","Individual water bowls per animal or per enclosure, cleaned daily","Weekly water bucket changes","Standing pans refilled monthly"],"a":1,"e":"Community troughs are fomite transmission risks. Individual water bowls per enclosure, scrubbed and sanitized on the same schedule as food bowls, are the biosecurity-correct approach."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Per ASV guidance, raw meat diets are NOT recommended in shelter settings primarily because:","o":["They are too expensive for non-profit organizations","They carry Salmonella and Campylobacter shedding risk to immunocompromised animals and staff, are seldom nutritionally balanced, and pose regulatory concerns in multi-animal facilities","They are incompatible with AAFCO labeling requirements","They cause taurine deficiency in cats"],"a":1,"e":"The ASV advises against raw diets in shelters due to zoonotic risk, nutritional imbalance, and regulatory concerns. Multiple Salmonella outbreaks have been linked to raw feeding in shelters."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Wet or canned food left in an open can at room temperature should be discarded after:","o":["72 hours","24 hours","2 hours","1 week"],"a":2,"e":"Opened wet food should be refrigerated and discarded after 2 hours at room temperature to prevent bacterial growth. Feral cat protocol extends this to 4–6 hours maximum under careful monitoring."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"The safe target rate of weight loss in an obese shelter cat is:","o":["5–10% of body weight per week","1–2% of body weight per week","0.1% of body weight per week","As fast as possible to reduce length of stay"],"a":1,"e":"Safe weight loss is 1–2% of body weight per week. Faster loss in cats triggers peripheral fat mobilization faster than the liver can process, risking hepatic lipidosis."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An obese cat (BCS 8/9, 7 kg) has not eaten for 4 days in the shelter. The highest-priority concern is:","o":["The cat needs more environmental enrichment","Hepatic lipidosis from fat mobilization into the liver during voluntary anorexia","The cat is on a successful self-imposed weight-loss fast","The BCS will normalize without intervention"],"a":1,"e":"Obese cats mobilizing peripheral fat rapidly when anorexic are at high risk of hepatic lipidosis. Veterinary exam and assisted feeding are indicated within 48–72 hours of anorexia."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"The correct dietary approach for an obese cat (BCS 9/9) requiring weight loss is:","o":["Abrupt caloric restriction to 50% of maintenance to produce rapid weight loss","Gradual reduction targeting 1–2% body weight loss per week, maintaining adequate protein, with veterinary oversight","Withholding all food for 3 days then resuming a normal diet","Switching immediately to a low-fat raw diet"],"a":1,"e":"Gradual restriction at 1–2%/week with protein maintenance prevents hepatic lipidosis. Rapid caloric reduction is dangerous in obese cats and can trigger the exact hepatic crisis the diet change is trying to prevent."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"For a 30 kg obese dog, the target weekly weight loss at the safe 1–2% rate is approximately:","o":["3–6 kg per week","300–600 g per week","30–60 g per week","1–2 g per week"],"a":1,"e":"1–2% of 30 kg = 300–600 g per week. This rate allows meaningful progress while avoiding the metabolic complications of crash dieting."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"According to the 2026 ASV Guidelines for Humane Rabbit Housing, what is the 'rabbit comfort zone' temperature range?","o":["40–55°F (5–13°C)","59–72°F (15–22°C)","75–90°F (24–32°C)","32–45°F (0–7°C)"],"a":1,"e":"The rabbit comfort zone is 59–72°F (15–22°C). Rabbits are very sensitive to heat stress above 86°F (30°C) and have limited thermoregulatory capacity in warm environments."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the minimum acceptable primary enclosure floor area for a single rabbit in a shelter, and for how long may this size be used?","o":["33 ft²/3 m²; no time limit","8–11 ft²/0.8–1 m²; less than 2 weeks only","5 ft²/0.5 m²; indefinitely if enrichment is provided","18 ft²/1.7 m²; up to 1 month"],"a":1,"e":"Minimum acceptable size is 8–11 ft²/0.8–1 m² and is a temporary measure only — does not include integrated exercise space and may only be used for stays under 2 weeks."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rabbit has been housed in a minimum acceptable enclosure (0.9 m²) for 3 weeks awaiting surgery. What does this represent and what action is required?","o":["No concern; the enclosure meets ASV minimum acceptable standards","Welfare compromise — the minimum acceptable enclosure may only be used for stays under 2 weeks; the rabbit must be moved to a larger enclosure, foster care, or an adoptive home","The enclosure is adequate as long as enrichment items are provided daily","The rabbit should be moved to a wire-floor surgical recovery cage for hygiene"],"a":1,"e":"Minimum acceptable enclosures are for stays under 2 weeks only. Rabbits housed longer develop musculoskeletal and GI problems, elevated corticosterone, and activity rebound — all welfare compromise indicators."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the minimum recommended primary enclosure size for a single rabbit on a long-term shelter stay, per ASV 2026?","o":["8–11 ft² / 0.8–1 m²","33 ft² / 3 m², length 9–10 ft/3 m, width ≥ 3 ft/0.9 m","45 ft² / 4 m² with width ≥ 5 ft/1.5 m","5 ft² / 0.5 m² with daily supplemental exercise"],"a":1,"e":"33 ft²/3 m² with an unobstructed run of 3 m is the minimum recommended for long-stay single rabbits — includes integrated exercise space accessible at all times."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why are motion-activated lighting systems specifically contraindicated in rabbit housing areas?","o":["They produce excess heat that disrupts the rabbit comfort zone","Rabbits active at night trigger the system, disrupting the critical dark phase of their circadian rhythm","They emit UVB radiation harmful to rabbit retinas","They are too loud and exceed the 50 dB noise threshold"],"a":1,"e":"Motion-activated systems are triggered by rabbit activity at night, disrupting the dark phase of the light/dark cycle. Disruption causes reduced stress adaptation, altered immune function, and shortened lifespan."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the minimum ambient light intensity specified for rabbit housing by the ASV 2026 guideline?","o":["1 footcandle (10 lux)","3–5 footcandles (30–50 lux)","30–50 footcandles (300–500 lux)","0 footcandles; rabbits need full darkness at all times"],"a":1,"e":"Minimum resting light intensity is 3–5 FC (30–50 lux). Higher levels (30–50 FC) are needed only for observation and cleaning. Constant high-intensity light is stressful for rabbits."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Prolonged exposure to what decibel range is specifically identified as detrimental to rabbit hearing by the ASV 2026 guideline?","o":["10–20 dB","50–70 dB","90–110 dB","120–140 dB"],"a":1,"e":"50–70 dB — equivalent to normal conversation through vacuum cleaner level — is specifically detrimental to rabbit hearing. Shelters regularly exceed 100 dB; rabbit housing must be in the quietest area available."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rabbit released from a minimum acceptable enclosure after 3 weeks launches across the room in explosive locomotor bursts. What does this behavior most likely represent?","o":["Normal energetic play appropriate for the rabbit's age and breed","Activity rebound from behavioral deprivation in an undersized enclosure — a recognized welfare indicator","An emerging neurological disorder requiring a workup","Aggression directed at enrichment items"],"a":1,"e":"Activity rebound (explosive locomotion when given space) is a specific indicator of prior behavioral deprivation. It signals that the rabbit was housed below welfare standards and is a recognized welfare outcome measure in rabbit husbandry research."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which flooring type is specifically contraindicated for rabbit primary enclosures per the ASV 2026 guideline?","o":["Rubber matting","Slatted, grid, or wire flooring","Vinyl tile","Woven grass mats"],"a":1,"e":"Wire and slatted floors cause pododermatitis (sore hocks) from pressure and abrasion. Solid flooring covered with appropriate bedding is required. This is one of the most common housing welfare failures in rabbit care."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What are the four components of a complete rabbit primary enclosure per ASV 2026?","o":["Sleeping area, food station, grooming area, and play tunnel","Hiding/resting space, elimination area (litter box), eating/drinking area, and exercise/play space","Feeding station, water source, UV light panel, and outdoor run","Nest box, squeeze panel, food puzzle, and climbing structure"],"a":1,"e":"The 4 required components are: (1) hiding/resting space, (2) elimination area/litter box, (3) eating/drinking area, (4) exercise/play space. All four must be present in the primary enclosure."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the recommended litter box configuration for shelter rabbits per ASV 2026?","o":["Small corner litter box with clay litter, one shared per three rabbits","At least one large litter box per rabbit, placed in a corner or periphery, with hay accessible from inside the box; avoid small corner-style litter boxes even for small rabbits","A single large communal litter tray in the center of the enclosure","Newspaper sheets on the floor replacing traditional litter boxes"],"a":1,"e":"One large litter box per rabbit is required, placed in the corner or periphery, and hay must be accessible from inside the box. Corner litter boxes are specifically identified as too small even for small rabbits."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What water delivery method is preferred for rabbits per ASV 2026?","o":["Water bottles, because they prevent contamination and drowning","Open water dishes, because rabbits prefer to drink from open water surfaces; water bottles are acceptable only under specific circumstances","Water provided only at mealtimes to monitor intake","Shared community water bowls changed twice weekly"],"a":1,"e":"Rabbits prefer to drink from open water surfaces. Open dishes are preferred; water bottles may be used under specific circumstances. For unknown intake rabbits, offer both until preference is established."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is acetic acid (vinegar) specifically useful in rabbit housing sanitation?","o":["It is an effective disinfectant against RHDV","It dissolves alkaline mineral deposits from rabbit urine that standard alkaline soaps cannot remove","It neutralizes cecotroph odor","It is a topical antiseptic for pododermatitis lesions"],"a":1,"e":"Rabbit urine is alkaline and mineral-rich. Alkaline soaps cannot dissolve these mineral deposits. Acetic acid (pH 2–3) breaks down calcium and mineral buildup on caging and litter boxes before or in place of standard disinfection."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rabbit's urine appears red-orange. What is the most appropriate next step to distinguish porphyrinuria from hematuria?","o":["Renal ultrasound","Wood's lamp examination — porphyrins fluoresce pink/orange under UV while blood does not","Urine culture and sensitivity","Abdominal radiographs"],"a":1,"e":"Rabbit urine contains porphyrins that can cause red/orange/brown discoloration mimicking hematuria. A Wood's lamp rapidly differentiates porphyrinuria from true hematuria without invasive diagnostics."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the correct order for cleaning rabbit housing when both healthy rabbits and RHDV-quarantine animals are present in the shelter?","o":["RHDV quarantine rabbits first to allow maximum drying time, then healthy adults, then kits","Healthy kits → healthy adults → unhealthy rabbits; RHDV quarantine animals are cleaned AFTER the healthy population, with separate supplies","All rabbits cleaned simultaneously with designated staff assigned to each group","Unhealthy rabbits first, then healthy, then kits"],"a":1,"e":"Clean from most vulnerable to most infectious: healthy kits → healthy adults → unhealthy. RHDV quarantine animals are cleaned last to prevent environmental contamination spreading to the healthy population."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What co-housing requirement applies to all group-housed rabbits per ASV 2026?","o":["Intact adult rabbits can be co-housed if well-socialized and monitored closely","All group-housed rabbits must be spayed/neutered; co-housing intact adult rabbits risks serious fighting causing injury or death","Males and females of any reproductive status can share exercise space freely","Group housing is permitted only for same-sex bonded pairs adopted together"],"a":1,"e":"All rabbits in group housing must be spayed/neutered. Co-housing intact adult rabbits risks serious injury and death from fighting. Rabbits of opposite sex should be separated for a minimum of 2 weeks following sterilization."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter rabbit is scheduled for spay surgery next week. What is the ideal perioperative housing arrangement?","o":["Housed with other surgical patients of all species for mutual comfort","Quiet, low-stress housing separated from dogs, cats, and ferrets; rabbit surgeries scheduled on days when cat/dog surgeries are not occurring; bonded companions kept together","In the main rabbit ward with conspecifics","Darkened isolation unit without enrichment to minimize stimulation"],"a":1,"e":"Perioperative rabbit housing must be quiet and separated from predator species. Scheduling rabbit surgeries on non-dog/cat days minimizes shared-space stress. Bonded pairs are kept together to reduce perioperative stress."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why does housing more rabbits not result in proportionally more adoptions, per ASV 2026 capacity planning?","o":["Rabbits compete with each other for adopter attention, reducing individual placement rates","Doubling the population with the same adoption rate doubles average length of stay and care demands while potentially overwhelming adopters with choice","Shelters have legal limits on rabbit numbers unrelated to care capacity","More rabbits always require larger staff ratios that reduce overall productivity"],"a":1,"e":"With a fixed adoption rate (e.g., 10/month), doubling housed rabbits from 10 to 20 doubles ALOS from 1 to 2 months, doubles enrichment and care demands, and can paradoxically reduce adoptions by overwhelming adopters with choice."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What disinfectant properties are specifically required for RHDV disinfection in rabbit housing?","o":["Disinfectants effective against enveloped viruses only (standard QAC) are sufficient","Disinfectants effective against non-enveloped viruses are required because RHDV is a non-enveloped calicivirus; options include accelerated hydrogen peroxide, potassium peroxymonosulfate, and 0.5% sodium hypochlorite","Any hospital-grade product is suitable regardless of viral spectrum","Bleach is specifically contraindicated in rabbit areas due to respiratory toxicity"],"a":1,"e":"RHDV is a non-enveloped calicivirus resistant to many disinfectants that work against enveloped viruses. Shelters must use agents with proven non-enveloped virus efficacy: accelerated hydrogen peroxide, potassium peroxymonosulfate, or 0.5% NaOCl."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the minimum enclosure width recommended when co-housing two rabbits, and why?","o":["0.6 m (2 ft)","1.5 m (5 ft), because rabbits naturally rest 2–5 body lengths apart","2.4 m (8 ft)","0.9 m (3 ft), equivalent to single rabbit minimum width"],"a":1,"e":"Co-housed rabbits naturally maintain a distance of 2–5 body lengths during rest. A minimum width of 1.5 m accommodates this natural spacing behavior and reduces stress-related conflict in paired housing."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A ferret is vaccinated against canine distemper at shelter intake. Twenty minutes later it becomes lethargic with vomiting and collapse. What is the most likely diagnosis and appropriate first-line treatment?","o":["Systemic CDV infection present at intake; antiviral therapy","Anaphylaxis to the CDV vaccine; diphenhydramine 2–4 mg/kg IM/IV and supportive care, with epinephrine for severe cases","Hypoglycemia from a missed meal; oral dextrose","Ear mite-induced vestibular crisis; aural ivermectin"],"a":1,"e":"Ferrets have a high prevalence of anaphylactic reactions to CDV and rabies vaccines, typically within 25 minutes of vaccination. Diphenhydramine 2–4 mg/kg IM/IV is first-line; epinephrine, dexamethasone, and oxygen support may be needed."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Canine distemper virus (CDV) is confirmed in a shelter ferret. What is the most appropriate management?","o":["Isolate and treat with supportive care; prognosis is guarded but some ferrets recover","Humane euthanasia is recommended — CDV is 100% fatal in ferrets; separate all exposed animals and vaccinate all healthy unvaccinated ferrets","Transfer immediately to a specialty ferret hospital for antiviral therapy","Administer anti-canine distemper hyperimmune serum and monitor for 4 weeks"],"a":1,"e":"CDV is uniformly fatal in ferrets — 100% case fatality rate with no effective treatment. Euthanasia minimizes suffering and outbreak risk. All healthy unvaccinated shelter ferrets in contact should be immediately vaccinated."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A 2-year-old spayed female ferret in a shelter develops bilateral symmetrical alopecia starting at the tail base progressing rostrally, plus vulvar swelling. What is the most likely diagnosis?","o":["Dermatophytosis (ringworm)","Adrenocortical disease","Aleutian disease virus (ADV)","Normal seasonal weight fluctuation"],"a":1,"e":"Adrenocortical disease: bilateral symmetrical alopecia (tail-to-head progression) plus vulvar swelling in a spayed female is the classic presentation. This condition is strongly associated with early-age spay/neuter and is almost exclusively described in US ferret populations."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A guinea pig presents with severe pruritus, excoriations, and seizure-like scratching episodes. Skin scraping confirms a mite infestation. What is the causative mite and its zoonotic status?","o":["Psoroptes cuniculi; not zoonotic","Trixacarus caviae; ZOONOTIC — can temporarily infect humans causing pruritic skin lesions","Demodex caviae; no zoonotic risk","Cheyletiella parasitovorax; high zoonotic risk requiring immediate isolation"],"a":1,"e":"Trixacarus caviae (sarcoptic mite of guinea pigs) causes severe pruritus that can mimic seizure activity. It is ZOONOTIC — can cause a temporary pruritic skin reaction in humans. Treatment: ivermectin 0.2–0.4 mg/kg SQ q10–14d × 3 doses."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is vitamin C supplementation critical for guinea pigs in shelter care?","o":["Guinea pigs have a very high metabolic rate requiring vitamin C as an antioxidant cofactor","Guinea pigs cannot synthesize vitamin C endogenously and will develop scurvy without dietary supplementation","Vitamin C is required for normal cecotroph production","Guinea pigs excrete vitamin C unusually rapidly through alkaline urine"],"a":1,"e":"Guinea pigs lack L-gulonolactone oxidase and cannot synthesize vitamin C. Deficiency causes scurvy. Supplement via species-formulated guinea pig pellets and fresh vegetables (kale, bell peppers, oranges)."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter coordinator proposes using pine shavings as bedding for guinea pigs. The correct response is:","o":["Pine shavings are the preferred substrate for guinea pigs","Pine and cedar shavings are contraindicated — aromatic hydrocarbons cause respiratory and skin disease; use paper-based substrates, recycled newspaper pellets, or hardwood shavings instead","Pine is acceptable; only cedar is contraindicated","Both are acceptable if changed at least once weekly"],"a":1,"e":"Pine and cedar shavings contain aromatic hydrocarbons causing respiratory irritation and health problems in guinea pigs and small rodents. Paper-based bedding (shredded paper, newspaper pellets) is recommended."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which of the following shelter animal species can be an asymptomatic carrier of Bordetella bronchiseptica capable of infecting guinea pigs?","o":["Only other guinea pigs","Rabbits, dogs, cats, and non-human primates — all can carry B. bronchiseptica asymptomatically","Only dogs and cats","Only wild birds and mice"],"a":1,"e":"B. bronchiseptica has a very broad host range. Rabbits, dogs, cats, and non-human primates can all be asymptomatic carriers that infect guinea pigs — even sharing the same airspace can be sufficient for transmission."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which disinfectant is specifically contraindicated for use in reptile and amphibian enclosures?","o":["Dilute bleach (1:32 dilution)","Quaternary ammonium compounds (QAC)","Phenolic compounds and glutaraldehyde","Accelerated hydrogen peroxide"],"a":2,"e":"Phenolic compounds and glutaraldehyde are specifically toxic to reptiles and amphibians and must never be used in their enclosures. Dilute bleach (1:32) and QAC are recommended disinfectants, followed by thorough rinsing."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rat develops progressive respiratory noise, sneezing, and chronic bronchopneumonia. Doxycycline plus enrofloxacin reduces clinical signs but the rat relapses when antibiotics are discontinued. What is the most likely diagnosis?","o":["Sendai virus — self-limiting infection resolving within 2 weeks","Mycoplasma pulmonis — the most common major respiratory pathogen in rats; infection is lifelong and cannot be eradicated, only managed with ongoing antibiotic therapy","Streptococcus pneumoniae — recurrence means the treatment course was too short","Bordetella bronchiseptica — completely eliminated with a full 4-week antibiotic course"],"a":1,"e":"M. pulmonis is an obligate intracellular bacterium — infection is lifelong and incurable. Doxycycline plus enrofloxacin controls clinical signs but does not eliminate infection. Recrudescence on cessation of antibiotics is the norm. Affected rats should be segregated."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is 'wet tail' in hamsters, which age group is most affected, and what is the approximate mortality rate without treatment?","o":["Bordetella bronchiseptica infection in adult hamsters; mortality 10%","Lawsonia intracellularis proliferative ileitis in young weanling hamsters (4–8 weeks); mortality approaches 90%","Rotavirus gastroenteritis in neonatal hamsters under 2 weeks; mortality 5%","Helicobacter-associated gastritis in adult hamsters; chronic low-grade disease with rare acute mortality"],"a":1,"e":"Wet tail is caused by Lawsonia intracellularis (obligate intracellular bacterium) and occurs in stressed weanling hamsters. Mortality approaches 90% without aggressive treatment: IV/SC fluids, antibiotics (metronidazole, tetracycline, enrofloxacin, TMS), and nutritional support."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is oral (enteral) penicillin contraindicated in rabbits, and what is the correct route for treating rabbit syphilis (Treponema)?","o":["It is inactivated by gastric acid; give it with food instead","It disrupts the cecal microbiome causing fatal Clostridium overgrowth (enterotoxaemia); use injectable penicillin G instead","Rabbits are allergic to all penicillins; use oral amoxicillin","It is nephrotoxic orally; give it intravenously"],"a":1,"e":"Enteral penicillin disrupts the cecal flora and causes fatal Clostridium overgrowth (antibiotic-associated enterotoxaemia). Rabbit syphilis (Treponema paraluiscuniculi) is treated with INJECTABLE penicillin G in all exposed rabbits; oral penicillin must never be given."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter rabbit with fleas needs treatment. Which product is specifically contraindicated in rabbits?","o":["Imidacloprid","Selamectin","Fipronil","Lufenuron"],"a":2,"e":"Fipronil is contraindicated in rabbits (associated with toxicity and death). Imidacloprid, lufenuron and selamectin are generally safe (selamectin is metabolized faster than in cats, needing a different regimen). Dog/cat tick products, flea/tick collars and insecticide dips must also be avoided in rabbits."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which set of properties correctly characterizes Rabbit Hemorrhagic Disease Virus (RHDV) for shelter management?","o":["Enveloped togavirus, not reportable, killed by any hospital disinfectant","Non-enveloped calicivirus, REPORTABLE, requires non-enveloped-virus disinfectants (0.5% sodium hypochlorite or 1% formalin); neonates are resistant","Enveloped coronavirus, reportable, neonates most susceptible","Non-enveloped parvovirus, not reportable, only affects wild hares"],"a":1,"e":"RHDV is a non-enveloped calicivirus and a reportable disease affecting domestic/European rabbits over 2 months (neonates are resistant). Being non-enveloped it resists many disinfectants — use 0.5% sodium hypochlorite or 1% formalin. Absence of orifice bleeding does not rule it out."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A dwarf-breed shelter rabbit develops head tilt, nystagmus and hind-limb paresis. Which intracellular organism (a microsporidian fungus) is the most likely cause?","o":["Pasteurella multocida","Encephalitozoon cuniculi","Treponema paraluiscuniculi","Eimeria stiedae"],"a":1,"e":"In dwarf breeds, vestibular disease (head tilt) is most often Encephalitozoon cuniculi — an intracellular microsporidian (fungus) with seroprevalence 7.5–84.7% that targets brain, kidney, lens and myocardium. In standard breeds, Pasteurella/otitis is the more likely cause. Serology does not correlate with severity; no treatment reliably clears it."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which rodent-associated organism is the primary cause of rat-bite fever in humans?","o":["Leptospira interrogans","Streptobacillus moniliformis","Mycoplasma pulmonis","Lawsonia intracellularis"],"a":1,"e":"Streptobacillus moniliformis is the primary cause of rat-bite fever. Wild and pet rats are asymptomatic carriers (nasopharynx, middle ear, respiratory tract; present in urine and blood). Transmission via bites, scratches, handling excreta, or contaminated food/water — handle with PPE and good hygiene."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Canine distemper virus is confirmed in a shelter ferret. What is the appropriate management?","o":["Isolate and treat with supportive care; some ferrets recover","Humane euthanasia — CDV is 100% fatal in ferrets — then separate exposed animals and vaccinate all healthy unvaccinated ferrets","Transfer to a specialty hospital for antiviral therapy","Give anti-canine-distemper hyperimmune serum and monitor 4 weeks"],"a":1,"e":"CDV has a 100% case-fatality rate in ferrets with no successful treatment. Euthanasia minimizes suffering and outbreak risk; vaccinate all healthy unvaccinated in-contact ferrets and separate exposed animals."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Twenty minutes after a CDV vaccine at intake, a ferret becomes lethargic with vomiting and collapse. Best first-line treatment?","o":["IV antivirals for presumed active CDV","Diphenhydramine 2–4 mg/kg IM/IV and supportive care; epinephrine for severe cases","Oral dextrose for hypoglycaemia","Aural ivermectin for a vestibular crisis"],"a":1,"e":"Ferrets have a high prevalence of vaccine anaphylaxis, typically within ~25 minutes of CDV or rabies vaccination. Diphenhydramine 2–4 mg/kg IM/IV is first-line; severe cases need epinephrine, dexamethasone and oxygen."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A 2-year-old spayed jill develops bilateral symmetrical alopecia starting at the tail base and progressing rostrally, plus vulvar swelling. Most likely diagnosis?","o":["Dermatophytosis","Adrenocortical disease","Aleutian disease","Normal seasonal weight fluctuation"],"a":1,"e":"Tail-base-to-head symmetrical alopecia plus vulvar swelling in a spayed female is classic adrenocortical disease — strongly associated with early-age spay/neuter and almost exclusive to US ferret populations."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why does an unbred jill develop life-threatening anaemia if not spayed?","o":["Chronic blood loss from uterine adenocarcinoma","Ferrets are induced ovulators — persistent oestrus causes hyperestrogenism and bone-marrow suppression","Iron deficiency from an all-meat diet","Aleutian-disease-induced haemolysis"],"a":1,"e":"Ferrets are induced ovulators; an unbred jill stays in oestrus, and chronic hyperestrogenism causes non-regenerative anaemia and bone-marrow suppression. This is a key reason to spay shelter jills."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A ferret coronavirus enteritis (ECE) outbreak is suspected. Which statement is correct?","o":["A feline coronavirus PCR will reliably detect ferret coronavirus","Feline coronavirus PCR will NOT detect ferret coronavirus; diagnosis needs RT-PCR plus IHC of jejunum/ileum","ECE is uniformly fatal like FRSCV","Older ferrets are protected; only neonates get sick"],"a":1,"e":"Feline coronavirus PCR does not detect ferret coronavirus. ECE diagnosis requires ferret-specific RT-PCR and IHC of jejunum/ileum, since presence of virus alone isn't confirmatory. Older ferrets get sick after exposure to young asymptomatic carriers."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"In which US-endemic regions should systemic fungal disease be on the ddx for a ferret with respiratory signs?","o":["Blastomyces in the SE/Mississippi-Ohio valleys and Coccidioides in the SW US","Only the Pacific Northwest","Anywhere — these fungi are contagious between ferrets","Only tropical climates"],"a":0,"e":"Blastomyces dermatitidis is endemic in the SE US and Mississippi/Ohio river valleys; Coccidioides immitis in the SW US. These fungi are NOT contagious between ferrets and are unlikely to arise in a shelter unless the ferret was exposed before entry."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A young shelter ferret has chronic mucoid/bloody diarrhoea, thickened intestinal loops and partial rectal prolapse. Which agent — also the cause of hamster wet tail — is most likely?","o":["Helicobacter mustelae","Lawsonia intracellularis (proliferative bowel disease)","Clostridium botulinum","Eimeria furonis"],"a":1,"e":"Lawsonia intracellularis causes proliferative bowel disease in young ferrets and is the same agent behind wet tail in hamsters (and disease in swine and rabbits). Treat with chloramphenicol or metronidazole plus stress reduction."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is oral (enteral) penicillin contraindicated in rabbits?","o":["It is inactivated by rabbit gastric acid","It disrupts the cecal microbiome causing fatal Clostridium overgrowth (enterotoxaemia)","Rabbits are allergic to all beta-lactams","It causes irreversible renal failure"],"a":1,"e":"Enteral penicillin disrupts the cecal flora and causes fatal Clostridium overgrowth (antibiotic-associated enterotoxaemia). For rabbit syphilis, injectable penicillin G is used; oral penicillin must never be given."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which ectoparasiticide must NOT be used on rabbits?","o":["Imidacloprid","Selamectin","Fipronil","Ivermectin"],"a":2,"e":"Fipronil is contraindicated in rabbits (associated with toxicity/death). Imidacloprid, lufenuron and selamectin are generally safe; ivermectin is used for mites. Dog/cat flea-and-tick collars and insecticide dips must also be avoided."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which statement about RHDV is correct?","o":["It is an enveloped virus easily killed by standard QAC alone","It is a reportable, non-enveloped calicivirus; disinfect with 0.5% sodium hypochlorite or 1% formalin","Neonatal rabbits are the most susceptible age group","Absence of blood from the orifices reliably rules it out"],"a":1,"e":"RHDV is a reportable, non-enveloped calicivirus affecting rabbits >2 months (neonates are resistant). Because it is non-enveloped it resists many disinfectants — use 0.5% sodium hypochlorite or 1% formalin. Lack of orifice bleeding does NOT rule it out."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter is 300 miles from an area with RHD reported last year; its rabbits are unvaccinated and a new arrival had outdoor exposure 5 days ago. Per the algorithm, what applies?","o":["No quarantine — single domestic animals never need it","The rabbit is 'at risk' → 10-day quarantine of the incoming rabbit, plus risk-mitigation","Immediate euthanasia of the incoming rabbit","Vaccinate and place directly into the general population with no quarantine"],"a":1,"e":"Within 500 miles/800 km of recent RHD, do an individual risk assessment: outdoor exposure in the last 10 days, an unvaccinated general population, or no proof of RHDV2 vaccination each make a rabbit 'at risk' → 10-day quarantine of incoming at-risk rabbits plus risk-mitigation."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A dwarf-breed rabbit presents with head tilt and nystagmus. Which is the MOST likely cause, versus a standard-breed rabbit?","o":["Pasteurella otitis in both breeds equally","Encephalitozoon cuniculi in the dwarf breed; Pasteurella/otitis is more likely in standard breeds","RHDV in both","Rabbit syphilis"],"a":1,"e":"In dwarf breeds, vestibular signs (head tilt) are most often caused by E. cuniculi; in standard breeds the cause is more likely Pasteurella multocida or otitis. E. cuniculi is an intracellular microsporidian (a fungus) with seroprevalence 7.5–84.7%."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Routine antibiotic choices considered appropriate for rabbits include:","o":["Oral penicillin, lincomycin and clindamycin","Doxycycline, trimethoprim-sulfa and fluoroquinolones","Amoxicillin and ampicillin","Erythromycin and oral cephalexin"],"a":1,"e":"Doxycycline, TMS and fluoroquinolones are appropriate in rabbits. Narrow-spectrum oral antibiotics targeting Gram-positives (penicillins, lincomycin, clindamycin) risk fatal dysbiosis/enterotoxaemia."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rabbit's urine is red-orange. Best next step to distinguish porphyrinuria from true hematuria?","o":["Abdominal radiographs","Wood's lamp — porphyrins fluoresce while blood does not","Urine culture","Renal biopsy"],"a":1,"e":"Rabbit urine often contains porphyrins causing red/orange discoloration (intermittent, lasting 3–4 days). A Wood's lamp rapidly differentiates fluorescing porphyrinuria from true hematuria."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is routine spaying recommended in shelter does by 6–9 months of age?","o":["To prevent rabbit syphilis","Because 50–80% of intact does over 3–4 years develop uterine adenocarcinoma","To eliminate Pasteurella carriage","To prevent E. cuniculi shedding"],"a":1,"e":"Uterine adenocarcinoma develops in 50–80% of intact does over 3–4 years, so ovariectomy/OVH is recommended in all non-breeding does at 6–9 months."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why is vitamin C supplementation essential for guinea pigs?","o":["They have an unusually high metabolic demand for it as an antioxidant","They cannot synthesize vitamin C (lack L-gulonolactone oxidase) and develop scurvy without dietary supply","They excrete it rapidly in alkaline urine","It is needed for cecotroph production"],"a":1,"e":"Guinea pigs lack L-gulonolactone oxidase and cannot make ascorbic acid, so it must come from the diet (guinea-pig-formulated pellets plus vegetables like kale, peppers, oranges). Deficiency causes scurvy."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A guinea pig has severe pruritus with scratching so intense it mimics seizures. Skin scrape confirms a mite. Agent and zoonotic status?","o":["Psoroptes cuniculi; not zoonotic","Trixacarus caviae; ZOONOTIC — temporarily infects humans","Demodex caviae; no zoonotic risk","Cheyletiella; high zoonotic risk"],"a":1,"e":"Trixacarus caviae (sarcoptic mite) causes intense pruritus that can be confused with seizure activity and is zoonotic (temporary human skin lesions). Treat ivermectin 0.2–0.4 mg/kg SQ q10–14d ×3 and decontaminate the environment."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which species can asymptomatically carry Bordetella bronchiseptica and infect guinea pigs?","o":["Only other guinea pigs","Rabbits, dogs, cats and non-human primates","Only wild birds","Only reptiles"],"a":1,"e":"Bordetella has a broad host range; rabbits, dogs, cats and non-human primates can be asymptomatic carriers, and sharing airspace can be enough to infect guinea pigs. Prevent exposure of guinea pigs to these species."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"By 5 years of age, what proportion of guinea pigs develop ovarian cysts, and what is a classic sign?","o":["~10%; pruritus","~76%; bilateral symmetrical truncal alopecia with abdominal distension","~30%; head tilt","~50%; polyuria"],"a":1,"e":"About 76% of guinea pigs develop ovarian cysts by 5 years. Space-occupying cysts cause decreased fertility, anorexia, abdominal distension and bilateral symmetrical truncal (non-pruritic) alopecia."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A guinea-pig coordinator proposes pine shavings as bedding. The correct response is:","o":["Pine is the preferred substrate","Pine and cedar are contraindicated (aromatic compounds) — use paper-based bedding or hardwood shavings","Pine is fine; only cedar is a problem","Both are fine if changed weekly"],"a":1,"e":"Pine and cedar shavings release aromatic compounds causing respiratory and skin disease in guinea pigs and small rodents. Use shredded/recycled paper or hardwood shavings."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is 'wet tail', which hamsters are most affected, and the approximate untreated mortality?","o":["Bordetella in adults; 10%","Lawsonia intracellularis proliferative ileitis in weanlings (4–8 wk); ~90%","Rotavirus in neonates; 5%","Helicobacter gastritis in adults; rare mortality"],"a":1,"e":"Wet tail is Lawsonia intracellularis proliferative ileitis, classically in stressed weanling hamsters (4–8 weeks). Mortality approaches 90%; symptomatic hamsters may die within 48 h. Treat aggressively with fluids, electrolytes, bismuth and empiric antibiotics, or euthanise."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A rat has chronic respiratory noise and bronchopneumonia; enrofloxacin + doxycycline help but it relapses when stopped. Most likely agent?","o":["Sendai virus — self-limiting","Mycoplasma pulmonis — intracellular, lifelong, incurable; controlled but not eliminated","Streptococcus pneumoniae — cured by a longer course","Bordetella — eliminated by a 4-week course"],"a":1,"e":"M. pulmonis is the most common major respiratory pathogen of rats — an intracellular bacterium causing lifelong infection. Enrofloxacin + doxycycline controls signs but does not eliminate it; recrudescence on stopping antibiotics is the norm."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which rodent-associated zoonosis is the primary cause of rat-bite fever in humans?","o":["Leptospira interrogans","Streptobacillus moniliformis","Yersinia pestis","Bordetella bronchiseptica"],"a":1,"e":"Streptobacillus moniliformis is the primary cause of rat-bite fever. Wild and pet rats are asymptomatic carriers (nasopharynx/middle ear/respiratory tract; present in urine and blood). Transmission via bites, scratches, excreta or contaminated food/water."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which zoonoses are specifically flagged as risks when handling small rodents at wellness exam?","o":["Rabies, FIV and FeLV","Hantavirus, LCMV and Streptobacillus moniliformis (rat-bite fever)","Brucella and Q fever","Toxoplasma and Echinococcus"],"a":1,"e":"The chapter flags hantavirus, LCMV and S. moniliformis (rat-bite fever) as the zoonotic risks for small rodents. No routine vaccination or diagnostic testing is performed at the wellness exam."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which disinfectants are specifically contraindicated in reptile and amphibian enclosures?","o":["Dilute bleach (1:32)","Quaternary ammonium compounds","Phenolic compounds and glutaraldehyde","Accelerated hydrogen peroxide"],"a":2,"e":"Phenolic compounds and glutaraldehyde are toxic to reptiles and amphibians and must never be used. Dilute bleach (1:32) and QAC are recommended, followed by thorough rinsing because their skin is highly absorptive."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which statement about reptile UVB lighting is correct?","o":["UVB can be delivered through glass to reduce burns","UVB (290–320 nm) must not be filtered through glass/acrylic, sits 12–18 inches away, and the bulb is replaced every 12 months","UVB is most important for carnivorous snakes","Output stays constant until the visible light fails"],"a":1,"e":"UVB (290–320 nm) is essential mainly for herbivorous/omnivorous reptiles to synthesize active vitamin D. It must not pass through glass or acrylic (which block it), should be 12–18 inches from the animal, and the bulb replaced every 12 months because output declines before visible light does."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What thermal arrangement do reptiles require in a shelter enclosure?","o":["A single uniform temperature throughout","Ambient 80–85 °F with a secondary focal heat source ~10 °F warmer, so the animal can choose its temperature from a gradient","As hot as possible to speed metabolism","Room temperature with no supplemental heat"],"a":1,"e":"Reptiles thermoregulate behaviourally and need a gradient: ambient 80–85 °F (27–29 °C) plus a focal basking source ~10 °F warmer. Too cold causes immunosuppression and GI stasis; too hot causes thermal burns and acute death."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"For record-keeping and intake of reptiles in a shelter, which is correct?","o":["Group several reptiles under one ID to save records","Individualize ID and records; use temporary non-toxic paint or nail polish; review local ownership laws before accepting","Reptiles are social and should be co-housed for comfort","Cat litter is the preferred substrate"],"a":1,"e":"Records must be individualized (never group multiple reptiles under one ID); temporary marking uses non-toxic paint or nail polish. Local laws must be reviewed before accepting reptiles, which are non-social and should not be co-housed or kept with carnivorous mammals. Cat litter must never be used."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the reported prevalence of equine squamous gastric ulcer disease in horses in training/competition versus untrained horses?","o":["Under 5% in both groups","17–39% in untrained/unworked horses rising to 66–100% in those in training/competition","Always 100% regardless of work","Higher in untrained horses"],"a":1,"e":"Squamous gastric ulcer disease affects roughly 17–39% of untrained/unworked horses and 66–100% of horses in training or competition, reflecting the impact of management and intermittent feeding on a trickle-feeding species."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which pathogens are the priority concern during equine intake quarantine (2–3 weeks)?","o":["Rabies and West Nile only","EHV (equine herpes myeloencephalopathy), Salmonella and strangles (S. equi)","FeLV and FIV","RHDV and myxomatosis"],"a":1,"e":"Quarantine runs 2–3 weeks. EHV and Salmonella have large numbers of latently infected shedders stressed by transport, and strangles (Streptococcus equi) is common in the auction/holding facilities rescue horses pass through."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An orphan foal follows people like a dog, suckles clothing and initiates rearing/mounting play with humans. What is this and how is it managed?","o":["Normal foal play; no intervention needed","Overhandled foal syndrome — limit human interaction, bucket-feed rather than bottle-feed, disassociate humans from mealtime, and provide equine companionship","Colic — refer for surgery","Strangles — isolate and treat"],"a":1,"e":"Overhandled foal syndrome arises when orphan foals over-bond to humans, producing unsafe behaviour and limited trainability. Management: minimize human interaction, bucket-feed (not bottle), use remote bucket filling to disassociate humans from feeding, and provide equine companionship."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter horse paces and weaves in its stall. The correct interpretation/response is:","o":["Punish the behaviour to extinguish it","These are locomotor stereotypies — natural responses to physical/psychological discomfort that should not be punished; address the underlying cause and provide turn-out and forage","Confine the horse 24/7 to limit movement","Increase grain meals to provide more energy"],"a":1,"e":"Pacing, circling, weaving and pawing are locomotor stereotypies reflecting physical or psychological discomfort and should not be punished. Management addresses the underlying cause: continuous forage, turn-out (not 24/7 stalling), and equine company. Cribbing (an oral stereotypy) affects 2–10% of horses."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A horse is chewing wood and licking objects. What deficiency does this most suggest?","o":["Protein deficiency","Salt/mineral deficiency","Vitamin C deficiency","Taurine deficiency"],"a":1,"e":"Wood chewing and object licking are signs of salt/mineral deficiency. Horses should have continuous access to an all-forage diet plus salt/trace-mineral licks."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which avian zoonosis is caused by an obligate intracellular bacterium that remains stable in dried droppings for months, making daily feces removal the single best control?","o":["Avian mycobacteriosis","Psittacosis (Chlamydophila psittaci)","Aspergillosis","Newcastle disease"],"a":1,"e":"Psittacosis (Chlamydophila psittaci) is an obligate intracellular bacterium stable in dry feces for months; people are infected mainly by inhaling/ingesting dried droppings. Best protection is sanitation (remove feces daily); treat birds with doxycycline for 45 days."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A shelter receives a parrot for an avian-friendly disinfection protocol. Which is correct for the bird's respiratory health?","o":["Use a strongly scented aerosol disinfectant for thorough coverage","Use an unscented, non-aerosol disinfectant such as dilute bleach; avoid household odours, chemicals, and aerosols","Phenolic compounds are ideal for birds","Glutaraldehyde fogging is recommended"],"a":1,"e":"Avian respiratory tracts are highly sensitive. Use an unscented, non-aerosol disinfectant (dilute bleach) and avoid household odours, aerosols, and harsh chemicals."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Why must intracoelomic (intraperitoneal) fluids be avoided in birds?","o":["Birds have no peritoneal cavity","Birds lack a diaphragm and their air sacs connect directly to the lungs, so intracoelomic fluid can drown the bird","It is too painful without anaesthesia","Birds cannot absorb fluid from the coelom"],"a":1,"e":"Birds lack a diaphragm and their air sacs connect directly with the lungs, so intracoelomic fluids can flow into the pulmonary parenchyma and drown the bird. Give fluids orally, SC, or IO instead."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"In a psittacine, how should organisms cultured from the droppings be interpreted?","o":["Gram-negative organisms are normal flora; gram-positive are pathogens","Gram-positive flora is normal; gram-negative organisms are considered potential pathogens","All bacteria in droppings are abnormal","Only fungi are significant; bacteria are irrelevant"],"a":1,"e":"In psittacines, normal GI flora is predominantly gram-positive. Gram-negative organisms in the droppings are regarded as potential pathogens. Rare contagious bacterial disease is usually Salmonella, Mycobacterium, or Chlamydophila psittaci."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"What is the most common fungal disease of psittacines, and what is a key preventive measure?","o":["Candidiasis; avoid antibiotics entirely","Aspergillosis; clean daily and avoid corncob and walnut-shell bedding","Cryptococcosis; use UVB lighting","Histoplasmosis; feed only pelleted diets"],"a":1,"e":"Aspergillosis is the most common fungal disease of psittacines — a ubiquitous, non-contagious soil fungus causing severe respiratory disease via spore inhalation, with high incidence tied to poor management. Prevent with daily cleaning and by avoiding corncob and walnut-shell bedding; immunocompromised raptors/seabirds get prophylactic itraconazole."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Under the federal Migratory Bird Treaty Act, which birds are EXCEPTIONS that do not require a USFWS permit to possess?","o":["Hawks, owls, and eagles","Pigeons, European starlings, English (house) sparrows, and game species","Songbirds and doves","All native waterfowl"],"a":1,"e":"The Migratory Bird Treaty Act prohibits possessing any part of native migratory birds without a USFWS permit. The exceptions are pigeons, European starlings, English (house) sparrows, and game species (which may still carry state restrictions)."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A wild raccoon is brought to your clinic. Legally, what may a veterinary hospital do?","o":["Provide indefinite long-term care without any permit","Provide emergency care but, in most states, possess it only ~48 hours before transferring to a permitted rehabilitator — and rabies vector species need a special permit","Immediately release it back to where it was found","Keep it as a clinic mascot once healthy"],"a":1,"e":"A vet may give emergency care, but long-term care requires a state rehabilitator's permit; most states allow possession only up to ~48 hours before transfer. Rabies vector species (like raccoons) require a separate special permit, and relocating RVS for release is illegal in most states."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which group correctly lists the principal rabies vector species relevant to a shelter, plus the one rodent of higher concern?","o":["Squirrels, chipmunks, rabbits, and opossums","Raccoons, skunks, foxes, and bats — plus woodchucks (the one rodent group with higher rabies susceptibility)","Mice, rats, gerbils, and hamsters","Deer, horses, and cattle"],"a":1,"e":"Rabies vector species are raccoons, skunks, foxes, and bats; woodchucks are the one rodent group with notably higher rabies susceptibility. Squirrels, chipmunks, other rodents, rabbits, and opossums rarely have rabies."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A staff member without rabies pre-exposure vaccination offers to examine an infant raccoon ('it's just a baby'). The correct response is:","o":["Allow it — infants are too young to carry rabies","No one without rabies pre-exposure prophylaxis may handle potential rabies vector species, and age has no bearing on whether the animal carries the virus","Allow it if gloves are worn","Allow it only if the raccoon appears healthy"],"a":1,"e":"No veterinary staff member may handle wildlife — especially potential rabies vector species — without rabies pre-exposure prophylaxis (a liability mandate). Age has no bearing on whether an animal carries the virus; an infant raccoon can carry rabies. Always use gloves regardless."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A caller asks if they can catch rabies from grass a rabid fox drooled on last night. The correct answer is:","o":["Yes — dried saliva on surfaces is highly infectious","No — rabies cannot penetrate intact skin and the virus is not viable once saliva dries; it spreads via saliva into bites, fresh cuts/abrasions, or mucous membranes","Yes — rabies is airborne in the environment","Only if the grass is still wet with dew"],"a":1,"e":"Rabies cannot penetrate intact skin and the virus is not viable after saliva dries. It is transmitted by saliva entering a bite wound, fresh scratch/abrasion, or mucous membrane — not by blood, urine, feces, or the open environment."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Which wildlife zoonosis has roundworm eggs that resist common disinfectants, survive in the environment for years, and can only be reliably destroyed by high-heat sterilization?","o":["Leptospirosis","Baylisascaris procyonis (raccoon roundworm)","Tularemia","Brucellosis"],"a":1,"e":"Baylisascaris procyonis eggs are not killed by common disinfectants and survive years — only high-heat sterilization (flame/propane torch, boiling lye water) works. In humans the larvae cause neural larva migrans (blindness, neuro damage, death). Designate cages 'raccoon only,' treat raccoon feces as infective waste, and don't house raccoons on dirt."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"A fledgling songbird arrives after being caught by a house cat, with no visible wounds. What is the priority?","o":["No treatment needed since there are no visible wounds","Start antibiotics (e.g., Clavamox) immediately — cat saliva carries virulent bacteria, including Pasteurella, that cause rapid fatal septicaemia; assume invisible puncture wounds","Release it immediately to reduce stress","Withhold all treatment until a rehabilitator arrives"],"a":1,"e":"Cat-caught wildlife must be started on antibiotics as soon as possible. Cat saliva carries highly virulent bacteria (including Pasteurella) that quickly cause septicaemia and death in small prey; assume invisible puncture wounds even with no visible injury. Clavamox is the most effective choice for cat bites."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"An opossum brought in is hissing, drooling, and swaying. What does this most likely indicate?","o":["Classic rabies — euthanise and submit for testing","A normal defensive bluff routine; opossums are remarkably rabies-resistant due to their low body temperature","Baylisascaris infection","Distemper"],"a":1,"e":"Opossums are remarkably resistant to rabies (their low body temperature does not support the virus well). Hissing, drooling, and swaying are part of their bluff/threat routine, not rabies. Standard precautions still apply when handling any wild mammal."},{"type":"mcq","domain":"Physical Health","sub":"Nutrition & Husbandry","q":"Per federal rules for migratory birds, which finding mandates euthanasia (absent special permits)?","o":["A bird with a single broken blood feather","A bird that cannot feed itself, perch upright, or ambulate where care won't reverse it; complete blindness; or a wing injury requiring amputation at or above the elbow (humero-ulnar joint)","Any bird that is underweight on intake","A bird with external parasites"],"a":1,"e":"Federal requirements for migratory birds mandate euthanasia of any bird that cannot feed itself, perch upright, or ambulate where care won't reverse it; any completely blind bird; and any bird needing amputation of a leg, foot, or a wing at or above the elbow (humero-ulnar joint) — unless special permits are granted."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A Gulf Coast shelter intakes 14 feral cats. Which statement correctly differentiates endoparasite transmission dynamics in the shelter?","o":["Dirofilaria immitis spreads cage-to-cage via aerosolized respiratory droplets","Direct-transmission parasites like Giardia and Cryptosporidium are immediately infective when shed, enabling rapid fomite spread","Toxocara and coccidia are instantly infective on excretion, so sanitation cannot help","Indirect parasites cause widespread outbreaks even without their vector"],"a":1,"e":"Giardia and Cryptosporidium are shed already infective; Toxocara/coccidia need environmental development; indirect parasites need their vector."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"An asymptomatic 2-year-old cat is heartworm antigen-positive at intake. What is the most appropriate action?","o":["Start the canine three-dose melarsomine protocol","Surgically extract worms via the jugular as first-line for all positive cats","Avoid adulticide (melarsomine is unsafe in cats), manage supportively and monitor, and counsel adopters about the real risk of acute decompensation","Permanently isolate the cat from other cats to prevent direct cat-to-cat worm transmission"],"a":2,"e":"Melarsomine is not recommended in cats; manage supportively. Feline heartworm can cause sudden death, so adopters need honest counseling."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A Midwest ferret has lethargy, open-mouth breathing, muddy-blue mucous membranes, and bilirubinuria. Most likely diagnosis?","o":["Sarcoptes scabiei anaphylaxis","Heartworm disease, even with a low adult worm burden","Quaternary ammonium disinfectant toxicosis","Trichodectes canis-induced anemia"],"a":1,"e":"Ferrets are exquisitely susceptible; even one worm can obstruct the tiny heart, and bilirubinuria is the most consistently reported clinicopathologic change."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Why is a heartworm antigen test prone to false-negatives in a ferret with clear right-sided heart failure?","o":["Ferrets cannot make antibodies against microfilariae","Ferret red cells denature heartworm antigens within 2 hours","Ferrets often harbor very low burdens or single-sex (male) infections, so antigen falls below detection","Antigen tests cross-react with Demodex proteins"],"a":2,"e":"Antigen tests detect adult female antigen; low burdens or male-only infections drop the antigenic load below the detection threshold."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A 3-week-old orphan puppy has a heavy flea infestation and is too young for most systemic products. Safest validated plan?","o":["Concentrated organophosphate garden-insecticide dip","Fipronil-based spray (noted safe for neonatal kittens and puppies), with mechanical flea combing and warmth as adjuncts","High-dose oral ivermectin plus a sulfur dip","A 45% permethrin spot-on for extra-large dogs at a micro-dose"],"a":1,"e":"Fipronil spray is the safe, validated option for neonates; mechanical removal and warmth matter, and the other options risk fatal neurotoxicity."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Twelve dogs in a hoarding case have pruritus and hyperkeratosis on the ventrum, pinnae, and elbows; scraping confirms Sarcoptes scabiei var. canis. Required measure?","o":["No isolation, since Sarcoptes is strictly host-specific","Immediate isolation and PPE due to high cross-contagion and zoonotic potential for staff","House affected dogs in the feline ward","Bathe in cow's milk and withhold macrocyclic lactones until age 2"],"a":1,"e":"Canine scabies is highly contagious and zoonotic; isolate and use PPE for the first 3 to 5 days of treatment."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"An asymptomatic Pit Bull mix is PCR-positive for Babesia gibsoni and completes triple antibiotic therapy. What must adopters be told?","o":["The dog is fully cured and needs no preventives","Therapy reduces parasitemia but does not clear the organism; the dog is a permanent subclinical carrier needing lifelong tick prevention","The dog is contagious to humans via saliva and must be euthanized","The dog will develop right-sided heart failure if it meets a cat"],"a":1,"e":"B. gibsoni is rarely cleared; treated dogs remain carriers at risk of relapse and need lifelong tick prevention (atovaquone-azithromycin is the more effective protocol)."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"An 11-day-old stray-litter puppy has mucosal pallor, lethargy, and tarry feces, with high hookworm egg counts on flotation. How did patent infection arise so early?","o":["Percutaneous L3 penetration 24 hours earlier","Transmammary transmission of A. caninum via milk, with a ~2-week prepatent period allowing egg shedding and anemia by 14 days","Ingestion of an infected rodent in the whelping box","Mutation of gut flora into hookworm oocysts"],"a":1,"e":"A. caninum is transmitted in the bitch's milk; its ~2-week prepatent period lets neonates shed eggs and become anemic by ~14 days."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Dogs in a Texas outdoor pen develop acute myocarditis and right-sided cardiomegaly. Which vector and mechanism should biosecurity target?","o":["Ixodes ticks injecting the pathogen in saliva","Triatomine (kissing) bugs depositing infective stages in feces near the bite, or being ingested by the dog","Anopheles mosquitoes transmitting microfilariae","Rodent nests aerosolizing Francisella tularensis"],"a":1,"e":"Trypanosoma cruzi (Chagas) is spread by triatomine bugs via fecal (stercorarian) contamination of the bite or by ingestion of the bug."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A feline-only shelter has juvenile cats with intense pruritus and scaling on heads and faces; scraping shows a sarcoptid mite. Organism and transmissibility?","o":["Demodex gatoi, strictly non-contagious, no zoonotic risk","Notoedres cati, highly contagious among cats with zoonotic potential for staff","Linognathus setosus, a sucking louse of dogs only","Cheyletiella, which only infests rabbits"],"a":1,"e":"Notoedres cati (feline scabies) starts on the head and face, is highly contagious among cats, and is zoonotic."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What is the ASV intake mandate for intestinal parasites in dogs and cats?","o":["Treat only animals with diarrhea","Treat all dogs and cats for roundworms and hookworms at intake, starting at 2 weeks of age, because of zoonotic risk","Treat for whipworms and tapeworms first, since they are most dangerous","Delay all deworming until after the stray hold"],"a":1,"e":"All dogs and cats must be treated for roundworms and hookworms at intake from 2 weeks of age due to the zoonotic risk."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Why should a broad-spectrum heartworm and flea spot-on not replace a primary dewormer at intake?","o":["Spot-ons are more expensive than tablets","They should not be used in place of a primary deworming product effective against hookworms and roundworms","They are illegal in shelters","They only work on cats"],"a":1,"e":"Broad-spectrum parasiticide spot-ons should not substitute for a primary hookworm-and-roundworm dewormer."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which drug covers hookworms, roundworms, whipworms, and Giardia, but NOT Dipylidium or Echinococcus?","o":["Praziquantel","Fenbendazole","Pyrantel pamoate alone","Selamectin"],"a":1,"e":"Fenbendazole (50 mg/kg PO for 3 to 5 days) is broad but misses Dipylidium and Echinococcus; praziquantel is used for those."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which statement about parasite egg environmental persistence is correct?","o":["Hookworm eggs are the hardiest and survive years on dry surfaces","Ascarid eggs are extremely resistant and become nearly impossible to destroy once in soil, whereas hookworm eggs are killed fairly rapidly by desiccation","All parasite eggs are killed instantly by routine disinfectants","Whipworm eggs cannot survive outside the host"],"a":1,"e":"Ascarid eggs are highly resistant (impossible to clear from soil); hookworm eggs are fragile and desiccate readily on dry surfaces."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"For nematode infections detected at intake, what is the recommended approach to isolation?","o":["Strict isolation of all infected animals for 30 days","No need to isolate or quarantine, because the eggs are not immediately infective; prioritize prompt post-treatment sanitation","Euthanize to prevent environmental contamination","Quarantine only the cats"],"a":1,"e":"Ascarid/hookworm/whipworm eggs are not immediately infective, so no isolation is needed; thorough post-treatment cleanup is the priority."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which roundworm is the deadliest zoonotic agent, causing fatal neural larva migrans in humans?","o":["Toxocara canis","Toxascaris leonina","Baylisascaris procyonis","Toxocara cati"],"a":2,"e":"Baylisascaris procyonis (raccoon ascarid) causes severe, often fatal neural larva migrans; T. canis is the most common cause of larva migrans overall."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which hookworm species causes the majority of cutaneous larva migrans cases in the US?","o":["Ancylostoma caninum","Ancylostoma braziliense","Uncinaria stenocephala","Ancylostoma tubaeforme"],"a":1,"e":"A. braziliense lingers in the dermis and causes most human cutaneous larva migrans cases."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What is the diagnostic test of choice for intestinal nematode eggs?","o":["Direct saline smear only","Zinc sulfate centrifugation fecal examination","Blood antigen test","Urine sediment cytology"],"a":1,"e":"Zinc sulfate centrifugation is the test of choice; intermittent shedding means a single negative does not rule out infection."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"How is Dipylidium caninum most effectively controlled in a shelter?","o":["Strict isolation of infected animals","A robust flea-control program, since the flea is its intermediate host","Routine fenbendazole for all animals","Environmental bleach alone"],"a":1,"e":"Dipylidium uses the flea as its intermediate host, so good flea control prevents it; visible segments mean flea control needs review."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"For Toxocara canis, which transmission route allows puppies to be infected before birth?","o":["Percutaneous only","Transplacental (in utero) transmission, so pups can shed eggs by about 3 weeks of age","Fomite transmission via bedding","There is no vertical transmission of T. canis"],"a":1,"e":"T. canis crosses the placenta; in-utero-infected pups can shed eggs by ~3 weeks despite a ~5-week prepatent period after egg ingestion."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which best characterizes whipworm (Trichuris vulpis)?","o":["A flea-borne tapeworm with high zoonotic risk","A direct-life-cycle nematode of the cecum and colon with a ~3-month prepatent period and a barrel-shaped bipolar-plugged egg","An obligate intermediate-host parasite","A protozoan diagnosed by ELISA only"],"a":1,"e":"Trichuris vulpis has a direct cycle, ~3-month prepatent period, lives in cecum/colon, and has a hardy barrel-shaped bipolar-plugged egg."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"After deworming a heavily infected dog, why is prompt sanitation critical?","o":["The dewormer makes the dog contagious by air","The feces will contain massive numbers of eggs that can contaminate the environment","The dog must be isolated for 30 days","Eggs become airborne after treatment"],"a":1,"e":"Post-treatment feces shed huge egg numbers; prompt, thorough cleanup prevents environmental contamination."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A cat presents with diarrhea. What is the appropriate diagnostic sequence before empiric treatment?","o":["Immediate euthanasia","Fecal flotation, direct smear and cytology, and a Giardia ELISA as needed; if negative, treat with a broad-spectrum anthelmintic","Blood heartworm antigen test only","Skin scrape"],"a":1,"e":"Work up feline diarrhea with flotation, direct smear/cytology, and Giardia ELISA; treat empirically with a broad-spectrum dewormer if negative."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What does a commercial heartworm antigen test actually detect, and how are microfilariae detected?","o":["It detects microfilariae directly; adults are found by ELISA","It detects circulating antigen of adult female worms; microfilariae are detected by concentration tests such as the Modified Knott","It detects larval L3 in the skin; adults are found on radiographs","It detects Wolbachia DNA; microfilariae are found by antigen test"],"a":1,"e":"Antigen tests detect adult female worm antigen; microfilariae are found by concentration tests (Modified Knott), which is why both tests are run."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"At what minimum age should dogs be screened for heartworm, and why?","o":["6 weeks, because larvae are present at birth","About 7 months, because the prepatent period is roughly 6 months","12 months, because antigen appears only in adults over a year old","Any age, since tests detect L3 immediately"],"a":1,"e":"Do not test before about 7 months; the ~6-month prepatent period means earlier testing wastes resources."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A dog on preventives is antigen-negative but heartworm is strongly suspected. What technique can unmask antigen?","o":["Repeating the same in-clinic test twice","Heat treatment of the serum sample to break antigen-antibody complexes","Switching to a microfilaria smear only","Waiting 2 years and retesting"],"a":1,"e":"Heat treatment of serum breaks antigen-antibody complexes and can convert a false-negative to a true positive."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which describes the AHS-preferred adulticidal protocol?","o":["Macrocyclic-lactone-only slow kill for all dogs","Doxycycline plus a macrocyclic lactone, then the three-dose melarsomine protocol (one dose, then two doses 24 hours apart about a month later)","A single melarsomine injection with no doxycycline","Surgical extraction as the routine first-line treatment"],"a":1,"e":"AHS recommends doxycycline and an ML, then three-dose melarsomine; the three-dose protocol is safest and ~99% effective."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What is the role of doxycycline in heartworm treatment?","o":["It is the adulticide of choice","It suppresses Wolbachia, reduces post-treatment pulmonary pathology and microfilarial counts, and renders microfilariae non-infective to mosquitoes","It replaces the need for exercise restriction","It is given only to cats"],"a":1,"e":"Doxycycline (10 mg/kg BID x 28 days) targets the Wolbachia endosymbiont, cutting pathology and transmission."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"When is a macrocyclic-lactone-only 'slow-kill' approach appropriate?","o":["As the routine first choice for all shelter dogs","Only when melarsomine is contraindicated or unavailable (for example anaphylaxis to melarsomine or a grave non-heartworm prognosis), and not in dogs that cannot be exercise-restricted","Whenever the dog has caval syndrome","For performance dogs to keep them working"],"a":1,"e":"Slow-kill is not recommended except in specific situations; it is contraindicated in performance dogs and those that cannot be activity-restricted."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A heavily infected dog acutely develops collapse from worms obstructing the tricuspid valve. What is this, and the prognosis?","o":["Caval syndrome, usually fatal within about 2 days unless worms are surgically extracted","Simple pulmonary hypertension, resolves with rest","Anaphylaxis to doxycycline, self-limiting","Microfilarial dermatitis, treated topically"],"a":0,"e":"Caval syndrome is acute tricuspid obstruction by worms, usually fatal within ~2 days without prompt surgical extraction."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What does the ASV Heartworm Management position statement (2024) recommend for shelter prevention?","o":["Prevention only during summer in endemic states","Year-round heartworm prevention for dogs, cats, and ferrets, since some transmission risk exists everywhere","Prevention only for dogs that test positive","No prevention until adoption"],"a":1,"e":"The ASV urges year-round prevention for dogs, cats, and ferrets because transmission risk exists year-round regardless of geography."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A shelter cannot afford to treat a heartworm-positive dog. What does the ASV position statement support?","o":["Mandatory euthanasia of all positive dogs","Transfer to a partner with treatment capacity, or release to an informed adopter with clear follow-up expectations","Indefinite housing without prevention","Withholding the diagnosis from adopters"],"a":1,"e":"The ASV supports transfer to a capable partner or informed-adopter release with follow-up, and notes resources should not be diverted from other animals."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"How do sucking lice (Anoplura) differ structurally from chewing lice (Mallophaga)?","o":["Sucking lice have a head wider than the thorax","Sucking lice have a head about as wide as the thorax and feed on blood, while chewing lice have a head wider than the thorax and eat skin debris","They are indistinguishable without PCR","Chewing lice suck blood; sucking lice eat debris"],"a":1,"e":"Anoplura (blood-sucking) have a head about as wide as the thorax; Mallophaga (chewing) have a head wider than the thorax."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which statement about Demodex is correct?","o":["All Demodex species are highly contagious between dogs and cats","Demodex is generally non-contagious (acquired from the dam while nursing); generalized demodicosis reflects immunosuppression and is heritable, and isoxazolines are often the treatment of choice","Demodex has no host specificity","Amitraz is the only effective option and isoxazolines do not work"],"a":1,"e":"Demodex is host-specific and generally non-contagious; generalized disease signals immunosuppression, is heritable, and isoxazolines are now often preferred."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"How are fleas most commonly acquired, and which stage is hardiest?","o":["Adult fleas jumping directly from one animal to another; the egg is hardiest","From a contaminated environment where eggs, larvae, and pupae have developed; the pupa is the hardiest stage and persists for months","Only by ingestion of infected prey; the larva is hardiest","By aerosol; the adult is hardiest"],"a":1,"e":"Animals pick up fleas from the environment, not host-to-host; the pupa is the hardiest stage, persisting for months awaiting a host."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"What distinguishes primary from secondary myiasis?","o":["Primary myiasis only affects cats","Primary myiasis (for example the reportable screwworm Cochliomyia hominivorax) requires living tissue, whereas secondary myiasis is opportunistic invasion of devitalized tissue on soiled or wounded animals","Secondary myiasis is always fatal","They are the same condition"],"a":1,"e":"Primary myiasis needs living tissue (screwworm is reportable); secondary myiasis is opportunistic on devitalized tissue of debilitated animals."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which pathogen is correctly paired with its vector?","o":["Borrelia burgdorferi (Lyme) transmitted by fleas","Bartonella spp. transmitted by ticks only","Rickettsia rickettsii (Rocky Mountain spotted fever) transmitted by ticks","Yersinia pestis (plague) transmitted by sandflies"],"a":2,"e":"Rocky Mountain spotted fever (R. rickettsii) is tick-borne; Lyme is tick-borne, Bartonella is flea-associated, and plague is flea/aerosol."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which arthropods have strict host specificity and so cannot establish infestation across different host species?","o":["Fleas and ticks","Only lice and Demodex mites","Mosquitoes and sandflies","All mites and all lice"],"a":1,"e":"Only lice and Demodex mites are strictly host-specific; all other arthropods of concern are opportunistic feeders."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A shelter wants to reduce environmental vector burden. Which measure is most appropriate?","o":["Routinely use footbaths as the primary control","Remove standing water, garbage, decaying organic matter, and long grass to limit vector breeding","House all animals outdoors to dilute exposure","Stop tick prevention to avoid resistance"],"a":1,"e":"Eliminating standing water, refuse, decaying matter, and long grass reduces vector breeding sites around the shelter."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A 10-month-old shelter cat has had intermittent large-bowel diarrhea (fresh blood, mucus, tenesmus) for 6 weeks but is bright and eating well. Which pathogen is most consistent with this presentation?","o":["Toxocara cati (roundworm)","Tritrichomonas foetus","Cryptosporidium felis","Dirofilaria immitis"],"a":1,"e":"T. foetus causes chronic large-bowel diarrhea with normal systemic signs in young cats in congregate settings. Cryptosporidium affects the small bowel. Toxocara and heartworm present differently."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A direct fecal smear on a symptomatic cat reveals motile, pear-shaped organisms. Which morphologic feature best distinguishes Tritrichomonas foetus from Giardia?","o":["Two nuclei (owl-eyes) and a concave ventral disc","One nucleus, a visible axostyle (stiff posterior rod), and a forward rolling movement","Backward tumbling ('falling leaf') motility and multiple flagella","Absence of any motility with refractile walls"],"a":1,"e":"T. foetus has one nucleus and a prominent axostyle with forward rolling movement. Giardia has two nuclei (owl-eye appearance), a concave ventral disc, and falling-leaf motility."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which treatment is effective for Tritrichomonas foetus infection in cats?","o":["Metronidazole 25 mg/kg PO BID × 7 days","Ronidazole 30 mg/kg PO once daily × 14 days","Fenbendazole 50 mg/kg PO × 5 days","Praziquantel 5 mg/kg PO single dose"],"a":1,"e":"Ronidazole is the drug of choice for T. foetus. Metronidazole has poor efficacy against Tritrichomonas and will NOT resolve the infection — a high-frequency exam trap."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which statement about Tritrichomonas foetus in shelter cats is correct?","o":["It is transmitted by fleas and requires immediate adulticide treatment","Transmission is fecal-oral via shared litter boxes; many cats will self-cure over months to years without treatment","It responds to standard metronidazole treatment given for 5 days","It exclusively causes small bowel diarrhea with vomiting and weight loss"],"a":1,"e":"T. foetus is fecal-oral via litter box contamination and causes large-bowel diarrhea; many cats self-cure, making ronidazole for shortening the course rather than a cure-or-die necessity."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which disinfectant is most commonly used in shelters but FAILS against Cryptosporidium oocysts?","o":["6% hydrogen peroxide","Steam cleaning over 60°C","Sodium hypochlorite (bleach) at standard dilutions","Desiccation (drying)"],"a":2,"e":"Cryptosporidium oocysts are highly resistant to chlorine. Bleach at standard shelter dilutions does NOT reliably kill them. This is a critical practical exam trap — steam and high-concentration H₂O₂ are needed."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A shelter cat is diagnosed with Cryptosporidium felis infection. Regarding transmission timing, which statement is correct?","o":["Oocysts require a 1–2 week sporulation period before becoming infective","Oocysts are immediately infective when shed — no external development required","Oocysts can only be transmitted through an arthropod vector","Oocysts require ingestion by a rodent intermediate host before infecting cats"],"a":1,"e":"Cryptosporidium oocysts are immediately infective when shed (autoinfective sporulated oocysts), enabling rapid fecal-oral spread without any external development period."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"The recommended staining technique for detecting Cryptosporidium oocysts on fecal smear is:","o":["Gram stain","Modified Ziehl-Neelsen (acid-fast) stain — oocysts stain pink-red","Giemsa stain","Romanowsky stain"],"a":1,"e":"Modified Ziehl-Neelsen (acid-fast) stain is the reference method; oocysts stain pink to red against a blue-green background. Routine fecal flotation has poor sensitivity because oocysts are very small (~4–5 μm)."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which statement about zoonotic risk from Cryptosporidium in a shelter is correct?","o":["Only C. felis poses significant zoonotic risk to humans","C. parvum is the most important zoonotic species; immunocompromised staff are at high risk; handwashing is the primary protective measure","Cryptosporidium poses no zoonotic risk when the animal shows no clinical signs","Zoonotic risk is eliminated by standard bleach disinfection of kennels"],"a":1,"e":"C. parvum is a significant human pathogen, especially for immunocompromised individuals. Bleach fails against oocysts, so handwashing and steam/H₂O₂ disinfection are essential safeguards."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"An adult shelter dog (3 years old) develops diffuse alopecia and skin thickening with deep scrape confirming generalized Demodex canis. What is the most appropriate next step after initiating treatment?","o":["Dismiss as cosmetic; no further workup needed","Investigate for underlying systemic disease (hypothyroidism, hyperadrenocorticism, neoplasia, or immunosuppressive drugs), because adult-onset generalized demodicosis is always a flag for an underlying cause","Quarantine the dog as highly contagious and contact trace all kennel neighbors","Recommend euthanasia due to the heritable nature of all demodicosis cases"],"a":1,"e":"Adult-onset generalized demodicosis (>18 months) requires investigation of an underlying cause. Juvenile-onset (<18 months) is heritable; adult-onset is acquired due to immunosuppression from systemic disease or drugs."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which statement correctly distinguishes Demodex canis from Demodex gatoi regarding contagiousness?","o":["Both species are non-contagious and only passed from dam to offspring","D. canis is highly contagious between dogs; D. gatoi is non-contagious","D. canis is non-contagious except dam-to-pup during nursing; D. gatoi IS contagious between cats","Both species are zoonotic and require strict isolation"],"a":2,"e":"D. canis is NOT contagious between adult dogs (only transmitted dam-to-pup while nursing). D. gatoi IS contagious between cats. This distinction is a high-frequency exam trap."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"Which treatment is now considered first-line for generalized Demodex canis in a shelter dog?","o":["Amitraz whole-body dips every 2 weeks (FDA-approved protocol)","Daily oral ivermectin in all breeds","Isoxazolines (fluralaner, afoxolaner, sarolaner, or lotilaner) — simple, effective, monthly or single-dose oral treatment","Lime sulfur dips as for ringworm"],"a":2,"e":"Isoxazolines are now the treatment of choice for generalized demodicosis: easy to administer, highly effective, safe. Amitraz remains FDA-approved but is labor-intensive and has toxicity concerns for staff. Ivermectin is effective but not FDA-approved and risky in MDR1-affected breeds."},{"type":"mcq","domain":"Physical Health","sub":"Parasites","q":"A 6-month-old shelter dog develops generalized demodicosis. Which action is critical before adoption beyond starting treatment?","o":["No additional action beyond treating the mites","Neuter the dog before adoption, because juvenile-onset generalized demodicosis indicates a heritable immune defect that should not be passed to offspring","Place in permanent isolation as all demodicosis is highly contagious","Start lifelong immunosuppressive therapy to manage the immune defect"],"a":1,"e":"Juvenile-onset generalized demodicosis indicates a heritable T-cell immune defect. Neuter before adoption and counsel the adopter not to breed related animals."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter team is implementing data collection models based on the Asilomar Accords. A community is heavily underfunded and lacks veterinary specialists. How might an animal with a chronic complex medical condition be categorized compared to the same animal presenting in a well-resourced metropolitan shelter?","o":["It must be classified as Healthy in all American jurisdictions under federal welfare mandates.","Its category could change from Treatable-Manageable to Unhealthy-Untreatable, because the matrix is pegged to what a caring owner with realistic community resources can provide.","It must automatically be assigned to an immediate fast-track adoption pathway.","It is legally exempt from the shelter's calculation of Average Length of Stay."],"a":1,"e":"The Asilomar matrix is explicitly community-referenced. Categorization reflects what a reasonable, caring owner in that specific community can realistically provide. The same condition may yield a different category in an under-resourced rural community versus a well-resourced urban one."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"Which age requirement must be met before an animal can be classified as 'Healthy' under the Asilomar Accords?","o":["The animal must be at least 12 weeks old.","The animal must be at least 8 weeks old.","Any age is acceptable provided the animal shows no clinical signs of disease.","The animal must have completed a full primary vaccination series."],"a":1,"e":"The Asilomar framework explicitly requires that an animal be at or above 8 weeks of age to qualify for the Healthy category. Animals under 8 weeks are classified separately regardless of clinical appearance."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A private practitioner argues that a shelter's Treatable-Manageable classification is wrong because the shelter cannot afford to treat the condition. Which statement correctly addresses this argument?","o":["The practitioner is correct; Treatable status requires the shelter itself to be able to provide treatment.","The practitioner is incorrect; Treatable status is based on community standard, specifically what a caring owner in that community can realistically provide, not what the shelter can afford.","The practitioner is correct; shelters with limited budgets must reclassify animals to Unhealthy-Untreatable automatically.","The practitioner is incorrect; Treatable status is determined solely by the attending veterinarian's opinion."],"a":1,"e":"Treatability under Asilomar is determined by the community standard, not by any individual shelter's resources. A shelter being unable to treat a condition does not reclassify the animal as untreatable if a caring owner in that community could realistically manage the condition."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter director tells their board that all animals classified as 'Unhealthy and Untreatable' are unsavable. Is this accurate?","o":["Yes; Unhealthy and Untreatable is synonymous with 'no possible outcome other than euthanasia' under the Asilomar framework.","No; the category means care is beyond community-standard resources, but a specialty organization with greater resources could still save such an animal.","Yes; the Asilomar framework prohibits any rescue organization from accepting Unhealthy and Untreatable animals.","No; Unhealthy and Untreatable means the animal is healthy but exhibiting dangerous behavior."],"a":1,"e":"Unhealthy and Untreatable means the level of care required exceeds what a community-standard caring owner can provide. It does not mean the animal is biologically unsavable. A specialty rescue with greater resources may still be able to treat or manage the condition."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"An open-admission facility is facing severe overcrowding due to an unexpected cruelty seizure. The shelter is already at 100% C4C. Which response to this crisis is explicitly defined as unacceptable by the ASV?","o":["Initiating emergency transport to regional rescue partners.","Compromising the baseline welfare of existing residents and personnel to absorb the additional intake.","Issuing an emergency foster appeal to the community.","Temporarily suspending scheduled owner-surrender appointments."],"a":1,"e":"Compromising existing animal welfare to absorb additional intake is explicitly defined by the ASV as unacceptable. Operating beyond C4C cannot be justified by emergency circumstances. Appropriate responses include transport, foster, intake holds, and rescue partnerships."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter has 200 physical cages. 60 of them are undersized and lack proper drainage. How many cages can be counted toward the shelter's true Capacity for Care?","o":["200, because physical presence determines capacity.","140, because only Humane Housing Units that meet welfare standards can be counted.","60, because only the substandard cages are available for general population housing.","200, but only if staffing is adequate."],"a":1,"e":"Only Humane Housing Units (HHUs) that meet welfare standards can be counted toward C4C. Enclosures that are too small or structurally inappropriate cannot be included regardless of their physical existence. The true HHU count here is 140."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter director frequently finds the facility operating above its C4C. According to the ASV, what long-term administrative process should be initiated?","o":["Immediately reducing the daily care time standard from 15 to 5 minutes per animal.","A structured strategic planning process to align shelter capacity with community needs.","Hiring untrained volunteers to supplement medical rounds.","Reclassifying all slow-track animals as fast-track to increase throughput."],"a":1,"e":"Chronic operation above C4C signals a structural mismatch. The ASV recommends initiating a formal strategic planning process to identify root causes and develop durable solutions rather than reducing care standards."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter veterinarian calculates the Required Holding Capacity (RHC) for the stray ward. The legal stray hold is 4 days. The Monthly Daily Average (MDA) stray intake is 15 dogs per day. What is the RHC?","o":["15 units","30 units","60 units","120 units"],"a":2,"e":"RHC = MDA Intake x Holding Period = 15 x 4 = 60 housing units. Each animal needs its own unit for each day of the mandatory hold period."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter manager is sizing the cat adoption floor. The Monthly Daily Average (MDA) for cat adoptions is 4 per day and the target ALOS for adoptable cats is 5 days. What is the Adoption-Driven Capacity (ADC) needed?","o":["9 units","20 units","40 units","80 units"],"a":1,"e":"ADC = Target ALOS x MDA Adoptions = 5 x 4 = 20 adoption-floor units. This is the number of spaces needed to sustain the target adoption throughput without overflow."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A facility houses an average daily population of 80 dogs. Using the NACA minimum of 15 minutes of basic care per animal per day, how many total staff hours must be scheduled for daily basic care?","o":["10 hours","15 hours","20 hours","40 hours"],"a":2,"e":"Staff Hours = (15 min x 80 dogs) / 60 = 1,200 / 60 = 20 staff hours per day for basic care (feeding and cleaning) alone."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter has 2,400 minutes of total daily staff care time available. Using the NACA 15-minute minimum, what is the Staff Capacity for Daily Care (SCDC)?","o":["80 animals","160 animals","240 animals","360 animals"],"a":1,"e":"SCDC = 2,400 / 15 = 160 animals. If the shelter's census exceeds 160, the staffing C4C has been breached regardless of physical cage availability."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter currently admits 10 dogs per day with an ALOS of 12 days (daily population of 120). If ALOS is reduced to 6 days, what is the new daily population?","o":["120 animals","60 animals","90 animals","30 animals"],"a":1,"e":"Avg Daily Population = Admissions x ALOS = 10 x 6 = 60 animals. Halving ALOS halves the daily population at the same intake rate. This is the most powerful lever for reducing overcrowding."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter supervisor is structuring a Fast Track protocol. Which animal profile should be placed in this stream to minimize ALOS?","o":["A 12-year-old diabetic cat requiring twice-daily insulin injections.","Highly adoptable kittens, puppies, and friendly small-to-medium sized dogs.","An aggressive large-breed dog requiring formal counter-conditioning behavioral modification.","A feral cat colony held for a 10-day legal quarantine period."],"a":1,"e":"Fast-track populations consist of high-adoption-probability animals: kittens, puppies, and friendly small-to-medium dogs. Rapid throughput for these animals frees critical resources for animals with greater needs."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"An adult dog assigned to the Fast Track has been in the shelter for 2.5 weeks without any adoption applications. What operational action is required?","o":["The animal must be euthanized immediately for space constraints.","The animal must be formally reassigned to the Slow Track, triggering larger housing, more enrichment, and a long-term care plan.","The animal must be placed into mandatory disease quarantine for 14 days.","The animal's daily care time must be reduced to 5 minutes to conserve resources."],"a":1,"e":"Any fast-track animal not adopted within 2 to 3 weeks must be formally reassigned to slow track. Remaining in fast-track housing is inappropriate for animals requiring longer stays and more complex care."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter's slow-track housing units are 100% full. An intake technician wants to move a dog with complex behavioral needs from holding into the slow track. What is the correct protocol?","o":["Double-house the dog in an existing full unit.","No additional animals may be assigned to slow track until existing residents have been adopted or transferred.","Demote a highly adoptable puppy from fast track to create space.","Remove all enrichment items from slow track to fit additional crates."],"a":1,"e":"When slow-track units are full, no additional slow-track assignments can occur until a unit opens. Doubling housing compromises welfare and violates C4C standards. The solution is to work on accelerating slow-track exits."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter implements an Open Selection program for stray animals on hold. How does this program reduce length of stay without bypassing legal protections?","o":["It eliminates the need to scan animals for microchips during intake.","It allows prospective adopters or rescue partners to select an animal during its legal hold period, converting waiting time into live-release preparation.","It mandates that selected animals bypass spay/neuter surgery.","It opens isolation wards to public viewing without PPE requirements."],"a":1,"e":"Open Selection productively utilizes mandatory stray-hold periods. Adopters or rescuers can select an animal before the hold expires and are told an owner reclaim is still possible. This minimizes LOS without circumventing the owner's legal right to reclaim."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A municipality proposes that all RTF community cats be counted the same way as TNR community cats in the shelter's intake statistics. Why would this be incorrect?","o":["RTF and TNR cats are biologically identical and should always be counted the same way.","RTF cats are admitted to the shelter and counted in the BasicDataMatrix intake; TNR cats are not admitted and are only tracked in the Community Services Matrix.","TNR cats must be admitted and counted because they receive shelter services.","RTF cats are not admitted; they go directly to foster homes without shelter processing."],"a":1,"e":"RTF cats enter the shelter system and are counted in intake statistics. TNR cats are managed entirely by community organizations without shelter admission; they appear only in the Community Services Matrix. Conflating the two distorts intake and live release statistics."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"The ASV emphasizes that minimizing LOS is critical for kittens and puppies under 5 months. What is the primary biological rationale?","o":["They consume twice as many financial resources per day as geriatric animals.","They are highly susceptible to infectious disease and prolonged stays can permanently impair their critical socialization window.","They are legally exempt from daily visual health observations.","They cannot be safely handled by anyone other than a board-certified veterinary surgeon."],"a":1,"e":"Pediatric animals under 5 months have immature immune systems and are highly vulnerable to shelter-acquired disease. Prolonged shelter stays also occur during a critical developmental window where lack of appropriate socialization causes permanent behavioral deficits."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A cross-departmental team performs Population Rounds. Which three questions must be answered for every animal?","o":["What breed are you? How much do you weigh? When is your next vaccine due?","Who surrendered you? What was your intake fee? Is your cage card in color?","How are you doing? What is your pathway and are there updates or concerns? What are your next steps?","Are you fast or slow track? Can you sit on command? Do you prefer wet or dry food?"],"a":2,"e":"Population rounds require three precise collaborative questions for every animal: (1) How are you doing? (2) What is your pathway and are there updates or concerns? (3) What are your next steps? These questions drive welfare assessment, pathway management, and outcome planning simultaneously."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A fearful dog identified in population rounds has stopped eating due to stress, threatening to extend its shelter stay. How must this finding be handled?","o":["Log the issue and re-evaluate during the animal's semi-annual examination.","The need must be addressed promptly; any welfare-compromising or stay-extending finding from rounds cannot be deferred.","Immediately reassign the dog to an unventilated quarantine stall.","Fast-track the dog to the adoption floor without behavioral intervention."],"a":1,"e":"The ASV mandates that any welfare-compromising or stay-extending need identified during population rounds must be addressed promptly, not deferred. Prompt action protects the animal and prevents LOS extension, which would compound the population problem."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter technician is explaining the difference between the Isolation Ward and the Quarantine Ward to a new volunteer. Which statement is correct?","o":["Isolation is for healthy animals; quarantine is for animals undergoing spay/neuter recovery.","Isolation is for actively sick animals; quarantine is for apparently healthy animals with known or suspected disease exposure who are being monitored through the incubation window.","Both areas can house sick and healthy animals together to maximize space.","Isolation is exclusively for geriatric animals; quarantine is exclusively for nursing mothers."],"a":1,"e":"Isolation targets actively sick animals. Quarantine targets apparently healthy animals with exposure risk, holding them through the incubation period for observation. The defining distinction is current health status at time of placement."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"An intake supervisor performs a physical exam on a 9-year-old stray dog. According to geriatric minimum database guidelines, which screening panel should be added to the standard intake exam?","o":["Full-body CT and skin scrape.","PCV/TP, urine specific gravity (USG), and a urine dipstick.","12-lead ECG and liver biopsy.","Immediate FeLV/FIV testing."],"a":1,"e":"The geriatric shelter patient minimum database includes PCV/TP to screen for anemia and protein abnormalities, USG to evaluate renal concentrating ability, and a urine dipstick to screen for glucosuria and proteinuria. These are efficient, low-cost, high-yield screens for common geriatric conditions."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A long shelter stay is identified as a direct risk factor in population management. What is the most significant health risk correlated with an extended LOS?","o":["An automatic increase in the manufacturer's drug expiration date.","An increased risk of developing a shelter-acquired illness due to prolonged pathogen exposure and stress.","An immediate reduction in the required holding capacity of the stray ward.","A transition from Schedule II to Schedule III controlled substance status."],"a":1,"e":"Risk management data shows a direct correlation between extended LOS and increased risk of shelter-acquired disease. Prolonged pathogen exposure combined with immunosuppressive stress increases susceptibility significantly."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter analysis shows large dogs have an ALOS 15 days longer than small dogs. What is the correct management response to this data?","o":["Ban the intake of all large dogs to protect the average daily population metrics.","Focus on improved housing, advanced enrichment, and targeted marketing programs to help large dogs achieve positive live outcomes more quickly.","Reduce daily care time for large dogs to offset their resource consumption.","Move all large dogs into the fast-track kitten socialization ward."],"a":1,"e":"When a subpopulation has elevated ALOS, risk management calls for both improving welfare during the longer stay (appropriate housing, enrichment) and accelerating outcomes through targeted marketing, offsite events, and foster networks. Banning intake or reducing care are not appropriate responses."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"According to the problem-oriented approach to shelter medicine, what is the correct sequence for initial case progression?","o":["Plan formulation > Diagnostic testing > Live release > History collection.","Data collection (history, PE, behavioral observation) > Problem identification > Plan formulation > Assessment and follow-up.","Euthanasia review > Open selection tagging > Daily care calculation.","Fast-track assignment > Slow-track demotion > Monthly BCS reweigh."],"a":1,"e":"The problem-oriented approach follows a strict sequence: Data collection first (history, physical exam, behavioral observation), then Problem identification, then Plan formulation (diagnostics and initial therapy), then Assessment and follow-up. Skipping to treatment before data collection is incorrect."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"An animal control officer finds a healthy stray dog two blocks from its home. What is the most efficient approach for this animal?","o":["Immediately transport the dog to a regional isolation ward.","Scan for microchip in the field; lost pets are statistically close to home and may be returned directly to the owner without shelter admission.","Admit the dog and place it on a mandatory 14-day quarantine.","Immediately assign the dog to the slow track."],"a":1,"e":"Lost pets are statistically found close to home. Field scanning and direct owner reunification prevents any shelter LOS, preserves a housing unit for an animal that genuinely needs sheltering, and is the most efficient outcome for this animal."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter's new adoption policy requires strict income verification, mandatory home visits, and a ban on renting families. What is the primary operational consequence according to the ASV?","o":["Decreases disease transmission by 50%.","The exclusionary policies are discriminatory, prolong LOS by shrinking the adopter pool, and prevent future adoptions without improving outcomes.","Automatically increases the SCDC.","Converts slow-track animals to fast-track within 48 hours."],"a":1,"e":"Restrictive, exclusionary adoption requirements directly prolong LOS by reducing the available adopter population. Evidence consistently shows these barriers do not improve adoption success rates or animal welfare outcomes while creating significant welfare harm through extended shelter stays."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter manages two intake pathways: scheduled owner surrenders (controlled) and stray intakes (uncontrolled but predictable). How should leadership manage the uncontrolled pathway?","o":["Close it entirely, refusing all emergency or municipal stray admissions.","Monitor it continuously to evaluate its impact on total facility capacity and make necessary adjustments to the controlled pathway to compensate.","Automatically assign every animal from this pathway to immediate euthanasia.","Skip all initial data collection for animals entering through this pathway."],"a":1,"e":"Uncontrolled but predictable pathways (strays, animal control intakes) cannot simply be refused. They require ongoing evaluation of their impact on total capacity so that management can adjust the controlled pathway (e.g., reduce scheduled owner surrender appointments) to maintain C4C."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"What is the primary purpose of a Return-to-Field (RTF) program for healthy unowned community cats in an open-admission shelter?","o":["It dramatically increases the ALOS for healthy kittens in the shelter.","It minimizes euthanasia for space constraints and maximizes intake capacity for owned animals requiring sheltering.","It transitions the shelter from a Schedule III to a Schedule II DEA licensing tier.","It requires all community cats to undergo a mandatory 6-month physical exam before release."],"a":1,"e":"RTF programs divert healthy unowned community cats back to their outdoor home ranges, freeing shelter space and reducing space-related euthanasia. This preserves intake capacity for owned animals, lost pets, and animals that genuinely require the shelter's services."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter tracks its Asilomar data monthly. Which outcome metric should be monitored within each category separately to evaluate progress toward elimination of preventable euthanasia?","o":["Total intake numbers and average weight gain.","Live release percentage and euthanasia percentage within each of the four categories over time.","Spay/neuter surgery count and average length of stay for fast-track animals only.","Staff hours spent in population rounds per week."],"a":1,"e":"Tracking live release and euthanasia percentages within each category separately is the Asilomar framework's intended monitoring mechanism. Healthy and Treatable euthanasia indicates unmet goals; Unhealthy and Untreatable euthanasia may be appropriate. Aggregate numbers obscure this critical distinction."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter director wants to confirm that population management begins at the correct point in an animal's trajectory. At what stage must population management officially start?","o":["Only after the animal has completed mandatory spay/neuter surgery.","Before admission; an animal should only be admitted if the shelter has capacity and resources to provide the specific care that animal requires.","At the exact moment the animal is transitioned from fast track to slow track.","After the first 6 months of continuous residency in an off-site foster network."],"a":1,"e":"Population management begins before admission. Admitting an animal when C4C is already exceeded compounds the overcrowding problem. Intake decisions must account for current capacity and the specific needs of the incoming animal before the admission occurs."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter takes in 90 kittens during June, a peak kitten season month. Using the standard foster home planning formula, how many foster homes should the program target for that month?","o":["45 homes","30 homes","90 homes","15 homes"],"a":1,"e":"Peak season formula: monthly kitten intake divided by 3. 90 divided by 3 = 30 homes. Winter formula uses a divisor of 2. Always recruit above the calculated number to buffer for attrition."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter wants to verify its foster census on February 1st. On January 1st there were 12 animals in foster care. During January, 28 animals were sent to foster and 20 were returned. What is the February 1st census?","o":["40 animals","20 animals","28 animals","8 animals"],"a":1,"e":"Census audit formula: Feb 1 = Jan 1 count + sent to foster in Jan minus returned from foster in Jan. 12 + 28 - 20 = 20 animals."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A foster coordinator notices that their calculated home need is 40 homes per month, but average LOS in foster is 6 weeks rather than the 2 to 3 weeks assumed by the formula. What adjustment is necessary?","o":["More foster homes than the formula suggests are needed, because animals stay longer and homes fill up faster","Fewer homes are needed because longer stays mean animals spend less time in the shelter","The formula accounts for LOS automatically, so no adjustment is needed","Reduce intake to match the formula output"],"a":0,"e":"The standard formula assumes a typical LOS. When animals stay in foster longer than assumed, homes become occupied for longer periods, reducing availability. The program must recruit more homes than the raw formula indicates to maintain the same throughput."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter receives a large orphaned litter of 12 kittens. Which management strategy best limits disease transmission risk among the litter?","o":["House all 12 together so cohort immunity develops quickly","Divide into smaller groups of 3 to 4 kittens placed in separate foster homes","Place all 12 with one experienced carer to centralize monitoring","Keep all 12 in the shelter until weaned before placing in foster"],"a":1,"e":"Dividing large litters into smaller groups placed in separate homes limits accumulated infectious risk and reduces the severity of any disease outbreak within a group. Each smaller group becomes its own low-risk family unit."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter approaching capacity has a large cohort of neonatal kittens about to arrive from a hoarding case. Which foster program approach is most consistent with best practice?","o":["Wait until the shelter reaches maximum capacity before activating foster appeals","Run proactive recruitment programs ahead of anticipated need, particularly before kitten season","Restrict foster to medical cases only to conserve training resources","Require all neonates to complete a 7-day shelter observation period before foster placement"],"a":1,"e":"Proactive recruitment ahead of anticipated high-intake periods is essential for capacity management. Reactive appeals during peak need are less effective because recruiting and onboarding carers takes time. Pre-kitten season campaigns are standard best practice."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A 16-year-old applicant wants to become a foster carer. Which statement correctly describes program eligibility?","o":["Any age is acceptable as long as a parent is aware of the arrangement","Minimum age 18 is required to sign a legally binding foster agreement; a younger person may participate with an adult primary carer","Minimum age is 21 in all jurisdictions for animals requiring medical care","There is no age requirement; individual shelter policy governs eligibility"],"a":1,"e":"A legally binding foster contract requires the signatory to be at least 18 years old. Younger individuals may participate in the care of animals, but an adult must be the primary carer and contract signatory."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter director proposes encouraging staff members to take foster animals home over the weekend to reduce shelter census. What is the primary compliance risk of this arrangement?","o":["It violates HSUS national standards for foster care","State labor laws and overtime regulations may be triggered when employees care for employer-owned animals outside work hours, and this has resulted in fines","Staff are prohibited from fostering under all ASV guidelines","It creates conflict of interest because staff make placement decisions about their own foster animals"],"a":1,"e":"Staff fostering their employer's animals activates state labor law provisions around hours worked and overtime compensation. This specific arrangement has resulted in regulatory fines for shelters. It should be avoided or reviewed carefully with employment legal counsel."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A foster program conducts criminal background checks on all applicants before placement. This is best described as which type of screening measure?","o":["A universal regulatory mandate required by federal law","A common but not universally mandated regulatory requirement that varies by jurisdiction","An ASV Guideline requirement for all programs placing medical cases","A voluntary best practice with no legal basis"],"a":1,"e":"Police or criminal background checks are a commonly applied regulatory or program requirement for foster carers, but they are not universally mandated by federal or national law. Requirements vary by jurisdiction and shelter policy."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter implements a policy requiring an in-home inspection visit for every foster applicant before any placement. What is the primary operational drawback of this approach?","o":["Home visits are prohibited by privacy laws in most states","The visits are labor intensive, can create mistrust with applicants, and the environment may change after the visit, limiting predictive value","Home visits dramatically increase zoonotic disease transmission to staff","Home visits are only useful for medical foster cases, not routine placements"],"a":1,"e":"Mandatory universal home visits are resource intensive and can deter well-qualified applicants. The environment at the time of the visit may not reflect how it will look once animals are present. Risk-stratified or targeted visits are preferred over blanket requirements."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A foster program is experiencing high carer attrition. Which retention strategy is most strongly supported by volunteer management principles?","o":["Increase stipends to all carers regardless of experience level","Match case complexity to carer skills, provide rest breaks between placements, and offer growth opportunities through mentorship or level advancement","Reduce communication frequency to avoid burdening carers","Assign all new carers to the most challenging cases to accelerate skill development"],"a":1,"e":"Effective volunteer retention requires matching the difficulty of cases to the carer's skill level so they feel competent but not overwhelmed. Providing breaks between placements prevents burnout. Creating visible growth pathways through level systems and mentorship increases engagement and retention."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A foster carer has had 1 resident cat and 4 foster kittens in their home. The 4 kittens are all adopted. A new single kitten is then placed in the home. What is the accumulated infectious risk level?","o":["1 (only the resident cat)","5 (4 kittens plus resident cat, carries forward)","4 (only the kittens who were present)","6 (5 previous animals plus the new kitten)"],"a":3,"e":"Accumulated infectious risk is cumulative and does not reset when animals leave. After the initial placement: 1 cat + 4 kittens = risk 5. The 4 kittens leave but risk remains at 5. Adding one new kitten raises risk to 6. The number only ever increases."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"Which management strategy is most effective at breaking the cycle of accumulated infectious risk in a foster home?","o":["Treating all incoming animals prophylactically with antibiotics","Periodically emptying the home completely for an interval before any new placements","Increasing vaccination frequency in resident animals","Restricting all placements to animals of the same species"],"a":1,"e":"The only way to reset accumulated infectious risk is to completely empty the foster home for a period between cohorts. This allows the environment to be cleaned and the pathogen load to diminish before any new animals are introduced."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"Why are young animals placed in an easily disinfectable area of the foster home for the first 2 weeks of placement?","o":["Because neonates are at highest behavioral risk during the first 2 weeks","Because the 2-week period is calibrated to the incubation period of core shelter pathogens, allowing disease to declare itself before the animal has full home access","Because shelter transport containers may leave chemical residues that require a decontamination window","Because most foster carers cannot adequately supervise animals during this initial period"],"a":1,"e":"The 2-week quarantine in an easily disinfectable area corresponds to the incubation window of the most common core shelter pathogens (including parvovirus and panleukopenia). If disease is incubating, it will declare within this window, and containment to a cleanable area limits spread."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"Which factor most directly explains why high-traffic foster environments increase the risk of FIP in cats?","o":["Repeated exposure to novel, potentially mutating feline coronavirus strains from multiple unrelated animals increases the probability of a virulent mutation arising","High-traffic environments have lower vaccination rates","Foster carers in high-traffic homes rarely provide adequate nutrition","FIP risk is not related to housing density or traffic"],"a":0,"e":"FIP arises from mutation of feline enteric coronavirus (FCoV). High-traffic environments with frequent introduction of unrelated cats increase the probability of exposure to novel FCoV strains and raise the overall viral burden, increasing the likelihood of a virulent mutation occurring. This is a recognized risk in intensive foster programs."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter screens all foster cats for heartworm before placement. A cat tests negative. Which statement is most accurate?","o":["The cat can be confirmed free of heartworm infection based on the negative result","A negative test result does not rule out infection in cats, due to limitations in current feline HW testing methodology","The cat must be retested in 6 months before foster placement","HW testing in cats is not recommended and should not be part of foster screening"],"a":1,"e":"Feline heartworm serology has significant sensitivity limitations. Cats can harbor single-sex infections that are undetectable by antigen tests, and antibody tests are also imperfect. A negative result provides some reassurance but cannot definitively exclude infection. Foster carers should be informed of this limitation."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"What is the recommended frequency for examination, weighing, deworming, and core revaccination in foster puppies and kittens?","o":["Monthly, with a final booster at 6 months","Every 2 weeks until 18 to 20 weeks of age","Every 4 weeks until 12 weeks of age","Every week until adoption, then transfer to adopter's vet"],"a":1,"e":"The standard protocol is examination, weight check, deworming, and core revaccination (DHPP or FVRCP) every 2 weeks until 18 to 20 weeks of age. This schedule ensures adequate protection during the window when maternal antibody interference is waning."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A 3-week-old litter of kittens is being prepared for foster placement. They have not been treated for coccidia. Which treatment protocol is recommended?","o":["Ponazuril administered at 2 to 3 weeks of age, with a repeat dose 7 to 14 days later","Metronidazole for 5 days starting at 4 weeks of age","No treatment unless oocysts are confirmed on fecal float","Sulfadimethoxine daily for 21 days starting at 6 weeks"],"a":0,"e":"Ponazuril is the recommended anticoccidial for shelter kittens. The protocol is administration at 2 to 3 weeks of age with a repeat dose 7 to 14 days later. Treatment is recommended prophylactically given the high prevalence of coccidia in shelter kittens."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"At what age should rabies vaccination be administered to neonatal foster puppies and kittens?","o":["6 weeks of age","8 weeks of age","3 months (12 weeks) of age","6 months of age"],"a":2,"e":"Rabies vaccination is administered at 3 months (12 weeks) of age in puppies and kittens. This is the minimum age for rabies vaccination under most jurisdictional licensing requirements and aligns with label indications for most rabies vaccines."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"To minimize biosecurity risk, who should conduct recheck appointments for foster animals?","o":["The primary attending veterinarian who also works the main shelter intake area","Staff or volunteers not in frequent contact with the main shelter animal population","Any available staff member to maximize scheduling flexibility","The foster carer themselves, to reduce shelter visits"],"a":1,"e":"Foster recheck appointments carry risk of disease introduction to or from the shelter population. Assigning these appointments to staff or volunteers who are not in frequent contact with the main shelter population reduces bidirectional transmission risk."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A foster carer is placed with a dog recovering from a spay. Which competency set is most important for this medical foster placement?","o":["Advanced behavioral modification techniques and aggression management","Wound care monitoring, enforcing exercise restriction, environmental enrichment for confinement, pain management recognition, and identifying post-surgical complications","Knowledge of cat-specific infectious diseases only","Ability to administer intravenous fluids and run in-clinic diagnostics"],"a":1,"e":"Medical fosters require carers to monitor surgical wounds, enforce activity restriction, provide appropriate low-stimulation enrichment, recognize signs of pain, and identify early complications such as dehiscence, infection, or seroma. These are the core competency requirements for this pathway."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A singleton 5-week-old kitten has been placed in foster care. The carer reports the kitten is fearful and not socializing well. What is the most appropriate management strategy?","o":["Return the kitten to the shelter for professional behavioral evaluation","Pair the singleton with another well-screened singleton to provide social stimulation; the behavioral benefit generally outweighs the infectious risk in this case","Isolate the kitten completely and allow natural desensitization over time","Increase human handling to compensate for lack of feline social contact"],"a":1,"e":"Singleton kittens under 4 months benefit from pairing with another well-screened singleton. The behavioral benefit (normal feline socialization, play behavior, and emotional development) generally outweighs the incremental infectious risk when the pairing kitten has been properly screened."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A kitten is 12 weeks old and has received no socialization or positive human handling since birth. What is the most likely long-term outcome?","o":["Normal socialization will occur naturally during adolescence with no intervention","The kitten is likely to develop chronic fear, anxiety, and difficulty adjusting to normal household stimuli","The kitten will benefit from more intensive play sessions starting at 16 weeks","No intervention is needed; socialization windows extend to 6 months in kittens"],"a":1,"e":"The primary socialization window in kittens closes at approximately 7 weeks and secondary socialization continues to about 14 weeks. Animals not adequately handled and exposed to positive novel stimuli during this period are at high risk of developing chronic fear, anxiety, and an inability to adjust to normal household environments."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter's foster coordinator proposes placing a dog with a documented bite history resulting in significant injury into a foster home for behavioral rehabilitation. Which ASV guideline is most directly relevant?","o":["Dogs with bite histories are automatically eligible for behavioral foster if the carer is experienced","Dangerous animals should not be rehomed; behavioral modification for dangerous animals poses unacceptable safety and liability risks","All bite history dogs require a 10-day hold before foster placement","Behavioral foster is prohibited for dogs with any aggression history"],"a":1,"e":"The ASV Guidelines state that dangerous animals should not be rehomed. Placing an animal with a documented significant bite history in a foster home for behavioral rehabilitation creates safety risks for the carer, household members, and the community, as well as serious liability exposure for the shelter."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A shelter develops a behavioral treatment plan for a dog displaying barrier frustration in foster care. Which elements are required in a properly constructed behavioral treatment plan?","o":["A general description of the problem behavior and a target adoption date","Specific training goals, target dates for each goal, written behavioral guidelines for the carer, and a schedule for regular re-evaluation","A single assessment by a certified behaviorist with a written summary","A medication plan and monthly follow-up with a shelter veterinarian"],"a":1,"e":"A complete behavioral treatment plan requires specific and measurable training goals, defined target dates for achieving each goal, written behavioral guidelines the carer can follow consistently, and a structured re-evaluation schedule to assess progress and adjust the plan. Vague descriptions or outcome targets without behavioral specificity are insufficient."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A dog is placed in behavioral foster care with a carer who wants to teach basic manners. What is the primary benefit of basic manners training in the foster context?","o":["It reduces the legal liability of the shelter if the dog bites","It enriches the animal's daily life, builds the human-animal bond, and increases adoptability and adoption success","It is required under state veterinary licensing law for dogs in behavioral placement","It eliminates the need for a behavioral assessment before adoption"],"a":1,"e":"Basic manners and house training provide daily mental stimulation and enrichment, strengthen the bond between the carer and the animal, and make the animal more appealing and manageable for adopters. This is the primary purpose of behavioral training in the foster context, distinct from treatment of serious behavioral pathology."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A cat in fospice foster care is declining. The carer disagrees with the shelter's assessment and wants to pursue further treatment rather than euthanasia. What is the correct process?","o":["The foster carer has decision-making authority because the animal is living in their home","The shelter administration and veterinary team retain final authority over the euthanasia decision, regardless of the carer's wishes","The carer may delay euthanasia indefinitely as long as the animal is eating","Euthanasia decisions must be made by the attending private practitioner, not the shelter"],"a":1,"e":"In a fospice arrangement, the shelter retains ownership of the animal and therefore retains final authority over all medical decisions, including euthanasia. The foster carer is caring for the animal on behalf of the shelter, not as an owner. This must be stated clearly in the fospice agreement."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A fospice carer has experienced the death of three animals in one month. Which support measure is most important for preventing carer burnout and ensuring continued program participation?","o":["Immediately assigning three new animals to keep the carer occupied","Providing access to compassion fatigue resources and encouraging rest breaks between placements","Requiring the carer to attend a debriefing session before taking any more animals","Transitioning the carer to space foster to reduce emotional burden"],"a":1,"e":"Repeated animal loss is a primary cause of compassion fatigue in fospice carers. The evidence-based response is to provide access to compassion fatigue support resources (counseling, peer support, grief support groups) and encourage breaks between placements. Immediate reloading without recovery time increases attrition."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A DV survivor contacts the shelter asking to place her two cats temporarily while she seeks safe housing. What legal document is essential before placement?","o":["A police report confirming the DV situation","A written agreement stating the animals will be returned to the owner when her circumstances resolve, or as ordered by a court","A surrender form transferring ownership to the shelter during the temporary period","A veterinary health certificate showing the animals are current on vaccines"],"a":1,"e":"Temporary foster for DV, disaster, or displacement situations requires a written agreement that clearly defines the temporary nature of the arrangement and stipulates the conditions under which the animal will be returned: when the owner's circumstances resolve, or as directed by a court. Without this, ownership and return rights may be ambiguous."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"A couple is interested in fostering a dog currently in the shelter's mandatory stray hold period. They would like to adopt the dog once the hold period ends. Which statement best describes the foster-to-adopt pathway in this situation?","o":["The couple can be listed as owners immediately to simplify paperwork","The couple may foster the dog, but must be clearly informed that the original owner retains the legal right to reclaim the animal until the end of the mandatory stray hold period","The dog cannot leave the shelter until the stray hold period is fully complete","The stray hold period is waived if the couple signs an adoption intent form"],"a":1,"e":"Foster-to-adopt is designed for situations where legal ownership transfer is not yet possible, such as during a mandatory stray hold period. The prospective adopter must be clearly informed in writing that the original owner retains full reclaim rights until the hold expires. Placement before the hold ends does not affect those rights."},{"type":"mcq","domain":"Shelter Management","sub":"Population Management","q":"Before placing a dog in a foster-to-adopt arrangement, which condition must be met regarding the animal's medical status?","o":["The animal must have completed spay or neuter surgery","The animal must have received all appropriate preventive care before placement","The animal must have passed an advanced behavioral assessment","The animal must have been in the shelter for at least 7 days"],"a":1,"e":"Before any foster-to-adopt placement, the animal must have received all appropriate preventive care: age-appropriate vaccinations, deworming, and relevant disease screening. This protects the household, the resident pets, and ensures the prospective adopter receives an animal in appropriate health condition."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"During a large emergency rescue, when must a unique identifier and individual record be formally established for each incoming animal?","o":["Within 72 hours of entering the adoption gallery","At or prior to admission, ensuring consistency and accuracy in care and record-keeping from the start","Only after the animal has been scanned for a microchip three separate times","After the first scheduled population round"],"a":1,"e":"The ASV mandate is clear: unique ID and individual record must be established at or prior to admission. Any care provided before this point cannot be reliably attributed to the correct animal, creating both clinical and legal risk."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"Which list correctly identifies all nine mandatory fundamental intake information items required for an individual record?","o":["Unique ID, intake type, intake date, species, age/category, sex, spay-neuter status, physical description, and weight or BCS","Microchip brand, behavior score, adult weight, rabies tag color, crate location, donor name, and diet type","Breed purity percentage, zip code, surrender fee status, coat length, and adopter restrictions","Pathogen exposure risk index, target length of stay, and slow-track pathway number"],"a":0,"e":"All nine Phase A items are: unique identifier, intake type, intake date, species, age or age category, sex, spay-neuter status, physical description, and weight or BCS. Any other combination is incomplete."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake technician is reviewing a dog's record for the identification triad. Which three assets must be present to meet the mandatory identification standard?","o":["Owner's driver's license copy, a rabies certificate, and pedigree papers","A photograph of the animal, microchip scan results, and specific identifying markings","Weight chart, body condition score, and a dental aging chart","Map of the intake location, cage card color, and behavioral profile score"],"a":1,"e":"The identification triad consists of: (1) a photograph of the animal taken at intake, (2) microchip scan results (positive with chip number, or negative), and (3) identifying markings. Together, these legally bind the physical animal to its digital record."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An owned cat is being surrendered due to a housing change. Which element of the cat's vaccination history must be explicitly sought and documented?","o":["The manufacturer name of the first feline herpesvirus vaccine","The rabies vaccination history","The exact time the last feline panleukopenia booster was administered","A signed affidavit confirming no bordetella exposure"],"a":1,"e":"The ASV framework specifically names rabies vaccination history as a mandatory history item. This is because rabies status directly drives quarantine decisions and legal obligations in bite cases. General vaccine history is required, but rabies is the one explicitly called out by name."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter encounters a canine influenza outbreak. The epidemiological team needs to identify which animals shared airspace with the index case over the past 14 days. Which tracking parameter provides this data?","o":["The nine fundamental intake information items","Housing locations by time recorded under in-shelter care activities","The unique identification number and name","The animal's historical home environment details"],"a":1,"e":"Housing locations logged by time is the only record parameter that allows the team to reconstruct which animals occupied the same area as the index case during the relevant incubation window. This is why real-time housing tracking is mandated, not just a best practice."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An animal is being transferred to an outside rescue organization. Which two data points must be added to the record to officially document this outcome?","o":["The recipient organization's annual budget and the transport vehicle's license plate","Outcome type (Transfer to Rescue) and the exact date of the outcome","Total weight change during the stay and the final behavioral assessment grade","Name of the transfer coordinator and total days in foster care"],"a":1,"e":"Every shelter stay must conclude with two mandatory outcome fields: the outcome type (in this case, Transfer to Rescue) and the exact date of the outcome. Both must be recorded to close the file and enable accurate live release rate and ALOS calculations."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter supervisor audits the database and finds five kittens housed together under one collective file labeled 'Litter 404B' with no individual records. What rule does this violate?","o":["Litters must only be tracked individually if assigned to a slow-track behavioral pathway","Every animal must have a unique identification number and an individual record, regardless of housing arrangement","Group files are permitted if all animals in the group share an identical physical description","Individual records are required only for animals older than 5 months of age"],"a":1,"e":"The fundamental mandate requires one unique ID and one individual record per animal, with no exceptions. Group housing does not permit group records. Each of the five kittens requires a separate file from the point of admission."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake clerk logs a dog as 'Stray, found at 5th and Main Street.' Which of the nine fundamental intake items does the word 'Stray' fulfill?","o":["Unique identifier","Physical description","Intake type","Age category"],"a":2,"e":"'Stray' identifies the intake type, one of the nine mandatory Phase A items. It distinguishes this animal from owner surrenders, transfers, OIE admissions, returns, and animals born in care, which have different holding period and outcome implications."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake technician photographs a dog's unique facial scars and cropped ears at admission. Under which record category do these images fall?","o":["Historical home environment details","In-shelter behavioral findings","Photograph of the animal and identifying markings (the ID triad)","Outcome type metadata"],"a":2,"e":"Intake photographs and documentation of specific physical markings are components of the identification triad (Phase B). They legally bind the physical animal to the digital record. Behavioral findings are a separate in-shelter care activity category."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter manager wants to analyze the relationship between an animal's physical condition at intake and its ultimate length of stay. Which specific Phase A item must be reviewed?","o":["Medical treatments and procedures received in shelter care","Weight or Body Condition Score (BCS)","The precise date of the outcome","Historical data on people and animals lived with"],"a":1,"e":"Weight or Body Condition Score (BCS) is the Phase A item that captures physical condition status at intake. It is the ninth of the nine mandatory fundamental intake items and is the one most commonly omitted in non-compliant records."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A surrendered cat's history notes that she hid under furniture during thunderstorms and lived with two young children. Under which history category do these details belong?","o":["Fundamental intake physical description","Behavioral events and experiences, people and animals lived with, and home environment","In-shelter care housing locations by time","Microchip scan results and unique identifier fields"],"a":1,"e":"Hiding behavior (behavioral event), child household members (people lived with), and noise sensitivity (home environment) all fall under Phase C historical context. These three of the five history sub-items capture the animal's pre-shelter life experiences."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A technician administers core vaccines and an anthelmintic to a puppy in the intake room. Where in the individual record must these clinical actions be documented?","o":["Vaccination history from the previous owner (Phase C history)","In-shelter care activities: medical findings, treatments, and procedures","Fundamental intake type and date metadata (Phase A)","Phase C historical context data fields"],"a":1,"e":"Any clinical action performed by shelter staff during the animal's stay is documented under in-shelter care activities, specifically under medical findings, treatments, and procedures. Owner-provided vaccination history is a different and separate Phase C field."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog develops barrier frustration in Run 12 and is moved to a behavioral rehab ward. The behavior team modifies its daily management plan. Which combination of record fields must be updated?","o":["Primary unique identifier and intake type","Behavioral findings, plans, and treatments, plus housing locations by time","Rabies vaccination history and physical description","Microchip scan brand and final outcome date"],"a":1,"e":"Two in-shelter tracking fields require updating: (1) behavioral findings and updated management plan under behavioral findings and plans, and (2) the housing location record showing the move from Run 12 to the rehab ward with the date of transfer."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A senior cat passes away naturally overnight in her enclosure. The care team records 'Died in Kennel' in her file. This entry satisfies which mandatory record category?","o":["In-shelter medical procedure log","Phase A fundamental physical description","Outcome type","Behavioral history event log"],"a":2,"e":"'Died in Kennel' is the outcome type. Natural death, euthanasia, adoption, transfer, and RTO are all documented as outcome types paired with the exact date of the outcome to close the record."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A volunteer asks why two dogs of the same breed and color cannot share an ID number. What is the core reason for requiring a unique ID for each animal?","o":["To enable the shelter to charge higher adoption fees for rare physical descriptions","To ensure consistency and accuracy in care and record-keeping for each specific individual","To automatically calculate the shelter's total staffing capacity hours","To eliminate the need for intake photographs"],"a":1,"e":"Unique IDs are mandated to guarantee that every piece of clinical, behavioral, and logistical information is reliably attributed to the correct individual animal. Shared IDs corrupt medical records, outbreak investigations, and outcome statistics."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An inspector finds a dog's file with a name, intake date, species, age, physical description, and weight recorded, but no documentation of sex or spay-neuter status. What type of compliance failure has occurred?","o":["Sex and spay-neuter status are among the nine mandatory Phase A items; their absence is a record compliance failure","Missing sex data automatically invalidates the microchip scan results","Spay-neuter status is only required for slow-track behavioral candidates","The inspector cannot calculate required holding capacity without this information"],"a":0,"e":"Sex and spay-neuter status are items 6 and 7 of the nine mandatory Phase A items. Their omission from the record is a direct compliance failure under the ASV record-keeping standard, regardless of any other information present."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A stray dog arrives with completely unknown background. What is the correct approach to the vaccination history field in its individual record?","o":["Invent a placeholder rabies vaccination date to satisfy the software","Document that history is unknown for each applicable field, maintaining individual records for tracking purposes","Immediately assign an outcome type of euthanasia to simplify the record","Delete the record entirely until an owner arrives to verify details"],"a":1,"e":"Unknown history must be explicitly documented as 'unknown' in the relevant fields. Leaving fields blank implies the information was not collected (a compliance failure). Documenting 'unknown' accurately reflects what is known and maintains a compliant individual record."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog's record shows: Intake Kennel 1A, June 1 to June 3; Foster Home B, June 4 to June 10; Adoption Ward Run 5, June 11 onward. This detailed entry fulfills which tracking mandate?","o":["Fundamental intake description metrics","Housing locations tracked by time under in-shelter care activities","Outcome type and date metadata matching","Phase B microchip triad scanning protocol"],"a":1,"e":"This is a compliant housing location by time entry, one of the three in-shelter care activity tracking requirements. It allows the shelter to reconstruct exactly where the animal was at any point during its stay, which is essential for outbreak contact tracing."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A data analyst needs historical information about the types of environments and cohabitants animals lived with before entering the shelter. Which record section should they review?","o":["In-shelter care activities and medical procedures log","History: people and animals lived with, and home environment","Fundamental intake weight and body condition scores","Outcome type and outcome date records"],"a":1,"e":"Previous cohabitants (people and animals lived with) and home environment are two of the five Phase C history items. They are collected at intake from the surrendering owner or transfer paperwork and are not updated during the shelter stay."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake team scans a dog and records a positive microchip number in the file, then documents a distinctive white spot on the dog's left shoulder. These entries satisfy which record component?","o":["In-shelter behavioral plans","Microchip scan results and identifying markings (the ID triad, Phase B)","Fundamental intake age category and sex data (Phase A)","Outcome type and date metadata"],"a":1,"e":"Microchip scan results (the specific chip number found on scanning) and identifying markings (the white shoulder spot) are two of the three components of the identification triad. Together with the intake photograph, they form Phase B of the record."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter database shows an entry: 'ID: Cat #992, Intake Type: Owner Surrender, Date: Jan 20, Species: Feline, Age: 3 Years, Sex: Female, Status: Spayed, Description: Calico.' Which of the nine Phase A items is missing?","o":["Date of intake","Spay-neuter status","Weight or BCS","Unique identifier"],"a":2,"e":"The entry contains 8 of the 9 mandatory items: unique ID, intake type, date, species, age, sex, spay-neuter status, and physical description. The missing item is weight or Body Condition Score (BCS), item 9 of 9."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog displayed high levels of fear and avoidance during novel stimulus exposure on day 2 of its stay. Where does this behavioral observation belong in the record?","o":["Phase C historical background context from previous owners","In-shelter care activities: behavioral findings, plans, and treatments","Phase A fundamental intake description","Identifying markings and microchip triad results"],"a":1,"e":"Behavioral observations made during the shelter stay are documented under in-shelter care activities, specifically under behavioral findings, plans, and treatments. This is distinct from the animal's pre-shelter behavioral history, which is documented in Phase C."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"Why must a unique identifier be assigned at or prior to admission rather than after a few days of intake processing?","o":["To lock the animal's live outcome potential score into the system","To ensure consistency and accuracy in care and record-keeping from the absolute start of the animal's stay","To bypass the requirement for housing location tracking","To eliminate the need for rabies vaccination history documentation"],"a":1,"e":"ID assignment at or before admission guarantees that every clinical action, housing move, and behavioral observation during the animal's entire stay is reliably linked to the correct individual. Delays create a window where care cannot be accurately attributed."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog is reclaimed by its owner on March 5. The owner pays the fee and leaves with the dog. Which fields must be completed to officially close this shelter stay?","o":["In-shelter medical findings and housing locations by time","Outcome type (Return to Owner) and the exact date March 5","Historical vaccination data and previous home environment records","Fundamental intake weight and body condition score"],"a":1,"e":"Closing a shelter stay record requires two outcome fields: the specific outcome type (Return to Owner) and the exact date of that outcome (March 5). Together, these entries close the file and feed into ALOS and live release rate calculations."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An auditor finds that for multiple owner surrenders, the 'medical conditions and services received' history field was left blank even though owners provided this information at surrender. What type of non-compliance has occurred?","o":["Failure to record in-shelter care activities","Failure to fully populate the mandatory history items with available information","Violation of the Phase B microchip scanning triad requirement","Omission of fundamental outcome metadata fields"],"a":1,"e":"History items must be populated with available information provided by the owner. Leaving a field blank when the information was available (not genuinely unknown) is non-compliance with the history documentation requirement, specifically the medical conditions and services received sub-item."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter adopts a policy to stop requiring intake photographs to save digital storage space. Why does this policy violate record-keeping standards?","o":["A photograph is an explicitly mandated component of the identification dataset for every individual record","Photographs are the only mechanism for calculating daily body condition scores","Removing photographs automatically deletes the rabies vaccination history","Individual files are completely illegal without photographs"],"a":0,"e":"The photograph is one of the three mandatory components of the Phase B identification triad. It is not optional. A policy that eliminates photographs fails to meet the mandatory identification standard regardless of storage cost justifications."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A stray dog undergoes emergency orthopedic surgery. Where must the pre-surgical findings, procedure, anesthetic protocol, and post-operative medications be documented?","o":["In the Phase C history log under past medical conditions","In-shelter care activities: medical findings, treatments, and procedures","In the Phase A fundamental intake age and sex metadata fields","In the final outcome type and date parameters"],"a":1,"e":"All clinical actions performed during the shelter stay, including emergency surgeries, are documented under in-shelter care activities: medical findings, treatments, and procedures. Pre-shelter medical history (Phase C) covers what happened before admission, not during."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake clerk enters 'Adult' for age/age category for a rabbit. Which component of the core dataset does this entry fulfill?","o":["One of the five Phase C historical context items","One of the nine Phase A mandatory fundamental intake items","The in-shelter care behavioral plan","The Phase B identification triad framework"],"a":1,"e":"Age or age category is item 5 of the nine mandatory Phase A fundamental intake items. 'Adult' is an appropriate age category entry. For SAC reporting purposes, the relevant cutoff is under 5 months (pediatric) versus 5 months and older (adult)."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog transferred from an out-of-state shelter arrives with extensive documentation of its pre-shelter behavioral history. In which record section must this information be preserved?","o":["Outcome type metadata fields","Phase C history","In-shelter care location logs","Phase A fundamental intake physical descriptions"],"a":1,"e":"Historical behavioral information documented before the animal entered this shelter belongs in Phase C history, specifically under behavioral events and experiences. Transfer paperwork from another organization is treated the same as an owner-provided history."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter manager wants to calculate how many times animals are moved between housing areas during their stay, to assess operational stress. Which record metric provides this timeline?","o":["Unique identifier and intake type","Housing locations by time, recorded under in-shelter care activities","Intake photographs paired with microchip scan results","Outcome type combined with the date of outcome"],"a":1,"e":"Housing locations by time is the only metric that records each move between areas with associated dates. Analyzing the frequency and pattern of housing moves from this field allows managers to assess operational disruption and its welfare impact on residents."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A shelter uses a 125 kHz legacy scanner for all intake microchip scans. A stray dog reads as 'no chip detected.' The dog is later claimed by its owner who provides documentation of a 134.2 kHz ISO microchip implanted last year. What went wrong?","o":["The chip deactivated during impoundment stress","The shelter's legacy scanner cannot read ISO 134.2 kHz chips, producing a false negative","ISO chips are undetectable for the first 24 hours after a stressful event","The chip migrated to the tail and requires ultrasound localization"],"a":1,"e":"ISO microchips operate at 134.2 kHz. A 125 kHz legacy scanner cannot detect this frequency and returns a false negative. Universal (ISO-compatible) scanners reading both 125 kHz and 134.2 kHz are required in all shelters to prevent this failure."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"An intake technician performs one forward pass over a stray cat with a universal scanner, gets no reading, and records 'no chip.' Why is this documentation non-compliant?","o":["One forward pass is the required protocol; backward passes are optional","At minimum two passes (forward and backward) are required before documenting 'no chip detected,' since chips frequently migrate from the interscapular implant site","Only credentialed staff may perform microchip scans, making any technician scan non-compliant","The scan must occur in a shielded room before the result can be documented"],"a":1,"e":"Chips commonly migrate from the standard interscapular implant site to the neck, flank, or limbs. A single-direction pass may miss a migrated chip. At minimum two passes in opposite directions are required before documenting 'no chip detected.'"},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"After scanning a stray dog twice and reading a 15-digit number, the number returns no matches across three microchip registries. What is the correct documentation?","o":["Record 'no chip' since the number is unregistered and therefore useless","Record the exact 15-digit chip number and note that it returned no match in the specific registries searched","Delete the entry and flag the dog as unidentified","Contact the DEA to report an unregistered implant"],"a":1,"e":"The chip number must be recorded exactly as read even if no registry match is found. No single registry is comprehensive. The owner may recognize the number, and documenting the registries searched creates a defensible intake record supporting owner reclaim."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"During an intake shift, a dog is moved from Run 3 to Run 7 for cleaning but the cage card is left on Run 3. A second worker later medicates the new occupant of Run 3 using the card's instructions. What ID failure occurred?","o":["ISO chip frequency mismatch between the two dogs","Cage card identity mismatch — the card remained with the enclosure instead of traveling with the animal, causing medication to reach the wrong individual","Phase C history was not transferred between kennel runs","Phase A intake type was not updated to reflect the housing move"],"a":1,"e":"Cage cards identify the enclosure, not the animal. When an animal moves without its card, the card associates with the new occupant — a potentially dangerous error. Cage cards must travel with the animal through every housing move, with simultaneous digital housing location update."},{"type":"mcq","domain":"Shelter Management","sub":"Animal ID & Stats","q":"A dog's ISO microchip number begins with '985.' What does this prefix signify?","o":["The dog was chipped with a 125 kHz legacy North American chip","'985' is a common ISO 11784 country-manufacturer prefix for chips implanted in the United States; the 15-digit format confirms this is an ISO-standard chip","The chip was implanted before 2005 and may be unreadable on modern scanners","It indicates a canine-specific encoding distinct from feline chips"],"a":1,"e":"The ISO 15-digit format includes a 3-digit country or manufacturer prefix. '985' and '900' are common prefixes for ISO chips implanted in the US. A 15-digit number beginning with 985 indicates an ISO 11784/11785-compliant chip requiring a universal 134.2 kHz-capable scanner."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter manager faces an acute staffing shortage in the canine care department. According to management principles, what is the most appropriate response?","o":["Lower the hiring standard to fill the slots within 48 hours","Work short-staffed for a longer period if that is what it takes to find the right person","Hire the first available applicant without checking references","Outsource daily cleaning to untrained temporary volunteers"],"a":1,"e":"The principle is clear: time spent being thorough is time well spent. The pressure to fill a slot quickly leads to short-sighted decisions. It is worth working short-staffed for a longer period to find the right person."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"When checking references for a shelter technician candidate, which specific question is most effective for revealing true past performance?","o":["What were this person's exact daily working hours?","If given the chance, would you hire this person again?","Can you list every mistake this person made?","Did this person ever experience compassion fatigue?"],"a":1,"e":"Past employers rarely disclose poor performance directly, but they will enthusiastically praise excellent employees when asked directly. The question 'Would you hire this person again?' bypasses superficialities and reveals genuine performance history through the enthusiasm (or absence of it) in the response."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"During an interview for a shelter technician position, the supervisor conducts a facility tour. What is the primary purpose of this tour from the interviewer's perspective?","o":["To have the applicant perform uncompensated cleaning tasks during the visit","To observe how the applicant interacts with the animals and the types of questions the tour generates","To test whether the applicant can memorize the building layout in one pass","To verify the applicant is wearing appropriate safety gear"],"a":1,"e":"The facility tour is an active diagnostic tool. The astute interviewer observes how naturally the applicant interacts with the animals and what the tour reveals about the applicant's intellectual curiosity and depth of interest through the questions it generates."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"An employee hired two weeks ago on a probationary basis is causing interpersonal friction and showing a poor attitude. What is the correct management action?","o":["Wait until the full probationary period ends before addressing the behavior","Terminate the employee promptly, even before the probationary period ends, listening to gut feelings","Promote the individual to a remote role to minimize team contact","Suspend all performance evaluations for the rest of the year"],"a":1,"e":"If things are not feeling right during a probationary period, the employee should be terminated promptly, even if the probationary period is not yet complete. Gut feelings are explicitly worth listening to. Waiting out the probationary period is the wrong answer."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A director is choosing between a candidate with excellent common sense and teamwork skills but limited technical knowledge, and a technically strong candidate with a difficult personality. Which candidate should be prioritized and why?","o":["The technically strong candidate, because personality can be improved through counseling","The candidate with good common sense and personality, because skills can be trained but personality and common sense cannot","Both candidates are equally suitable","Neither candidate should be hired; re-advertise the role"],"a":0,"e":"Common sense is one of those assets a person either has or does not have. It cannot be taught. Skills can be honed with proper training. The candidate with the right personality and common sense who lacks technical skills is the superior hire, as the technical gaps can be closed through training."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A supervisor is completing an annual performance evaluation for an exemplary animal care worker. What is the primary purpose of providing a high-quality evaluation to an excellent employee?","o":["To create a legal waiver preventing the employee from requesting raises","To ensure the employee realizes they are valued and appreciated for what they do for the organization and the animals","To transition the employee from an hourly rate to a volunteer-based role","To update their training record with mandatory bite prevention hours"],"a":1,"e":"Good evaluations are worth their weight in gold. An excellent employee needs to know they are valued and appreciated. This is the primary retention function of performance evaluations for high performers: recognition, not documentation."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"An animal care worker has been consistently failing to follow cleaning protocols. The supervisor is preparing to terminate the employee. What is essential for a legally defensible termination?","o":["Firing the employee immediately via text message without prior documentation","The case must be carefully and professionally built on previously documented poor performance in evaluations","Waiting until the next quarterly strategic plan review","Reassigning the employee to report directly to the Board of Directors"],"a":1,"e":"If an employee must be terminated, the case must be carefully built professionally. A pattern of poor performance previously documented in evaluations greatly reduces the risk of a lawsuit or union intervention. Undocumented termination creates serious legal vulnerability."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A newly appointed Board member instructs the kennel staff to change the daily canine feeding schedule. Why does this action represent a governance violation?","o":["The Board is only permitted to communicate with the media point person","It is not the Board's role to be involved in the shelter's day-to-day operations","Feeding schedules can only be modified during an active disease outbreak","The Board's authority is limited solely to conducting facility tours"],"a":1,"e":"Day-to-day shelter operations fall entirely outside the scope of the Board of Directors. The Board's role is high-level governance: mission, finances, long-range planning, and operating budgets. Directing kennel staff on daily tasks is an institutional boundary violation."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"Which of the following activities represents a core legal function of a shelter's Board of Directors?","o":["Performing daily visual health observations in the isolation ward","Overseeing finances, ensuring adequate resources, long-range planning, and reviewing and approving operating budgets","Administering core vaccines to animals at intake","Signing individual euthanasia certificates for each animal"],"a":1,"e":"The Board is legally responsible for governance, which includes overseeing finances, ensuring adequate resources, long-range planning, and reviewing and approving operating budgets. These are strategic and fiduciary functions, not clinical or operational ones."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A staff member is unhappy with a decision made by the Executive Director and emails the Board President directly to complain. Why is this inappropriate?","o":["The Board President is legally barred from reading internal staff communications","The ED is the staff's interface with the Board; going over the head of the ED to the Board is never appropriate","It triggers an automatic external inspection by the local police department","Operational complaints must be routed exclusively through private practitioners"],"a":1,"e":"The Executive Director is the staff's exclusive interface with the Board. Bypassing the ED to go directly to the Board undermines the chain of command and the ED's authority. This is true even when the staff member genuinely disagrees with an ED decision."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"An animal control agency operates under a municipal police department. What is the most common management challenge in this structure?","o":["The facility is legally barred from using strategic planning","The individuals in authority are not necessarily animal people and may be ignorant of animal welfare issues","Staff are required to pass police academy training before cleaning kennels","The facility is exempt from national zoonotic disease regulations"],"a":1,"e":"Municipal structures present a recurring challenge: the people in positions of authority over the shelter are not necessarily 'animal people.' The main problems concern money, bureaucracy, and ignorance of animal welfare issues. Those in authority need to be educated on animal welfare and, critically, on what is in it for them and their organization."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A local reporter contacts the shelter veterinarian directly about an ongoing hoarding investigation. What is the correct protocol?","o":["Give an immediate off-the-record interview sharing all medical findings","Refer all inquiries to the designated media point person; only make statements if explicitly authorized","Say 'no comment' and end the call","Invite the reporter into the isolation ward for an unannounced tour"],"a":1,"e":"In cruelty, hoarding, or other sensitive cases, there must be one designated media point person for the agency. All inquiries must be referred to this person. The shelter vet makes public statements only if explicitly authorized by the point person. All other responses are wrong."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"During a media interview, the reporter asks a highly technical question the shelter veterinarian cannot answer. What is the most appropriate response?","o":["Invent a plausible statistic to preserve institutional credibility","Acknowledge that you do not know, and offer to find the answer and report back before the reporter's deadline","Repeat the interviewer's negative framing back to them to deflect","Stop the interview immediately"],"a":1,"e":"There is no shame in not knowing the answer to a question. The correct response is to acknowledge this, then make a genuine effort to find the answer and get it to the reporter before their deadline. This approach preserves both honesty and credibility. Inventing information is both unethical and dangerous."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter vet is interviewed on television about a local parvovirus spike. Which communication strategy is most important for ensuring the shelter's key message is conveyed?","o":["Save the most important information for the very end of the interview","State the most important point first and weave 2 to 3 core messages into the interview throughout, regardless of what is asked","Respond with long technical explanations to fill all available airtime","Use humor to minimize perceived severity"],"a":1,"e":"Consistency counts. The most important thing must be said first because editors cut from the end. Two to three core messages should be woven into the entire interview no matter what the questions are. This ensures the intended message survives editing and reaches the audience."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A reporter asks a shelter representative: 'Why is your shelter failing so badly to control pit bull abuse in this city?' Which communication rule must be applied?","o":["Say 'no comment' to shut down the line of questioning","Do not repeat the interviewer's negative words; pivot immediately to a proactive, positive message","Agree with the negative premise to build rapport with the reporter","Remain completely silent until a different question is asked"],"a":1,"e":"Repeating an interviewer's negative words reinforces that negative framing in print and on video. The rule is explicit: never repeat negative words. Instead, pivot directly to a positive message about what the shelter is actively doing. 'No comment' is also explicitly wrong."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"What is the primary strategic benefit of proactively pitching a positive news story to the media rather than waiting for a crisis?","o":["It eliminates the need for an Executive Director","It allows the shelter to establish a positive narrative first, rather than playing defense against someone else's negative spin","It legally exempts the facility from public records requests","It guarantees pro bono care from all local private practitioners"],"a":1,"e":"The objective should always be to hit the papers first with a positive story rather than play defense and react to someone else's negative spin. Organizations that establish their own narrative are in a fundamentally stronger position than those who only respond to external criticism."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter veterinarian wants to strengthen relationships with local general practitioners. Which human-relations principle should guide this process?","o":["Local vets will only cooperate if given a vote on the shelter's cleaning schedules","Every decision a person makes is based on the underlying question 'What's in it for me?'; building rapport starts with small collaborative agreements","Private practitioners must be required to accept protocol changes without prior consultation","Relationships are best formalized through legal agreements drafted by the local VMA"],"a":1,"e":"The guiding principle is the 'What's in it for me?' framework. Every person, including private practitioners, evaluates relationships and commitments through this lens. Working together on small projects, coming to a consensus on small issues, and making early agreements build affinity and rapport that enables larger future collaboration."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter team wants to increase attendance at an after-hours educational tour for local private veterinarians. What simple addition to the event is explicitly recommended to boost attendance?","o":["Requiring all attendees to pass a written exam before entry","Providing food, especially because people are being asked to attend after a full workday","Restricting the tour to board-certified specialists only","Scheduling the event at 5 AM on a Sunday"],"a":1,"e":"Providing food is explicitly noted as an effective way to increase attendance at events where people are being asked to come after work. This respects participants' personal time and signals appreciation for their effort, making attendance more likely."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter veterinarian invites a local internist to give a public seminar on geriatric pet care at the shelter. What is the main strategic benefit of this invitation?","o":["It transfers all legal liability for shelter animal health to the visiting specialist","The more time individuals donate, the more invested and loyal they become to the organization","It allows the shelter to stop providing daily care to its own geriatric animals","It fulfills a national training documentation requirement"],"a":1,"e":"One investment leads to another. The more time that individuals donate to an organization, the more invested and loyal they become. Inviting a local practitioner to teach converts a passive mailing-list contact into an active stakeholder who has a personal stake in the shelter's success."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"Which of the following correctly describes the composition of a shelter Liaison Committee?","o":["Board members and local police chiefs","A few local VMA members and relevant shelter staff","Media reporters, adopters, and former employees","Shelter volunteers and public health attorneys"],"a":1,"e":"Liaison committees consist of a few local Veterinary Medical Association (VMA) members and relevant shelter staff. This cross-sectional composition creates a bridge between the shelter's internal perspective and the broader veterinary community, benefiting both organizations."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter vet is planning a major update to the pediatric spay/neuter protocol and is deciding whether to consult local veterinary colleagues. What is the key risk in seeking input?","o":["Local colleagues must legally approve all protocol changes before implementation","Soliciting opinions builds trust, but veterinarians may become resentful if their advice is solicited and then seemingly ignored","Consulting colleagues automatically bypasses industry-specific professional organizations","Colleague feedback guarantees no 'gray zones' will remain in the new protocol"],"a":1,"e":"It is always wise to solicit the opinions of experienced colleagues, but this carries an important obligation: if advice is sought, it must be genuinely considered. Veterinarians who feel their input was requested as a formality and then ignored will become resentful, damaging the relationship. Seeking input creates an implicit commitment to engage with the feedback."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"An outside veterinary surgeon agrees to perform a complex orthopedic repair on a shelter dog. According to management guidelines, what must happen before the procedure?","o":["The shelter must wait until after adoption to negotiate a fee","Fee expectations must be discussed upfront, including whether services are full price, reduced, at cost, or pro bono","The shelter is legally required to pay full retail price","The specialist must submit a budget request to the Board of Directors"],"a":1,"e":"Whenever a colleague will provide a service for a shelter case, fees must be discussed before the service is rendered. This includes whether services will be reimbursed at full price, a reduced fee, at cost, or pro bono. Resolving financial terms after the fact creates awkwardness and potential conflict."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A veterinary ophthalmologist donates their time to perform cataract surgery on a shelter cat. Which form of recognition is specifically noted as highly valued by recipients of such donations?","o":["A voucher exempting the specialist from mandatory training sessions","A thank-you note signed by shelter staff, or a framed photograph of the patient with their new adoptive family","An announcement at the quarterly strategic planning meeting","A lifetime waiver from attending zoonotic disease training"],"a":1,"e":"It is vital to recognize generous donations of specialist time and expertise. A thank-you note signed by shelter staff is noted as being highly valued by recipients even though it may not seem like much. A framed photograph of the patient with their adoptive family is specifically called out as a deeply meaningful token of appreciation."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter management team is systematically defining essential programs, setting benchmarks, and allocating resource streams toward specific goals. What administrative process are they performing?","o":["Daily population rounds","Strategic planning","Performance evaluation","Liaison committee auditing"],"a":1,"e":"Strategic planning is defined as the organizational process used to define the shelter's essential programs and goals, and then purposefully allocate resources toward achieving those goals. The key elements in this scenario (defining programs, setting benchmarks, allocating resources) are the hallmarks of strategic planning."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"How frequently should a shelter's strategic plan ideally be reviewed to ensure progress and relevance?","o":["Once every five years during municipal contract renewals","Regularly, often quarterly","Every morning during medical rounds","Only during an active infectious disease outbreak"],"a":1,"e":"Strategic plans are most effective when reviewed regularly, often quarterly, to ensure progress is being made and that goals remain relevant. Annual reviews are insufficient; circumstances and community needs change faster than that."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter administrator is drafting high-level rules about which medical conditions the facility has the resources to treat. What is the primary function these policies serve?","o":["To prevent animal needs from overwhelming the resources available, since operating beyond C4C is unacceptable","To eliminate the need for creating detailed daily protocols","To allow non-credentialed volunteers to make resource allocation decisions","To satisfy media inquiries about cruelty investigations"],"a":0,"e":"Policies function as an organizational safeguard: they ensure that animal needs do not overwhelm the resources available to meet those needs. Operating beyond C4C is explicitly unacceptable, and high-level policies are the administrative mechanism that prevents this from happening."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"What is the correct distinction between a shelter's Policies and its Protocols?","o":["Policies are written by private practitioners; protocols are written by the Board","Policies are the high-level decision framework; protocols are the detailed daily operational steps that maintain those policies","Protocols govern financial allocations; policies govern how to clean a kennel","Policies must be confidential; protocols must be shared with the media"],"a":1,"e":"Policies provide a framework of high-level decisions that ensure operations remain consistent with the shelter's mission. Protocols provide the highly detailed, documented operational instructions that ensure consistent daily execution of those policies. Policies set what; protocols define how."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter's intake department frequently generates staff conflict because of ambiguous decisions about which animals can be accepted. What is the recommended solution?","o":["Eliminate all written protocols and rely on individual gut feelings","Apply intake and euthanasia criteria consistently, removing the gray zones that cause conflict and bad feelings","Delegate all intake decisions to the Board of Directors","Never discuss euthanasia policies with new hires during onboarding"],"a":1,"e":"Gray zones in intake and euthanasia criteria are the primary source of conflict and bad feelings in shelter environments. The solution is consistent, clearly documented criteria applied uniformly by all staff. Removing the gray zone removes the burden of individual decision-making and the associated emotional distress."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"An audit reveals that multiple staff members have never received information about ringworm or rabies exposure risks. Which administrative mandate has been violated?","o":["The requirement to provide strategic planning documentation to volunteers","The absolute requirement to provide comprehensive zoonotic disease information to all staff members","A national regulation on DEI budget allocations","The protocol requiring all staff to hold active veterinary licenses"],"a":1,"e":"Providing comprehensive zoonotic disease information to all staff members is an absolute administrative requirement. Ringworm (dermatophytosis) and rabies are both zoonotic diseases with direct occupational health implications for shelter workers. This training is not optional."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A supervisor completes a bite prevention training session with three new animal care workers. What administrative step must follow immediately?","o":["Send a press release to the media point person","Formally document the completed training and maintain the record as part of professional development and performance review","Submit the attendees' names to the VMA","Update the high-level transport policy to include the trainees' signatures"],"a":1,"e":"Documentation of all completed training must be maintained and reviewed regularly as part of professional development and performance reviews. Undocumented training creates the same administrative gap as no training at all. The documentation is what makes the training defensible in an audit or legal review."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter is onboarding a new volunteer cohort. At what point must zoonotic disease training be completed relative to the start of independent animal contact?","o":["Within 30 days of the volunteer's first shift","Before independent work with animals begins — during orientation, not after a trial period","At the end of the first quarter of volunteering","Only when the volunteer is assigned to a high-risk species such as reptiles"],"a":1,"e":"Zoonotic disease training must be completed before the volunteer has independent contact with shelter animals. Delaying training until after a trial period creates a window during which the volunteer is unprotected and the shelter is liable for any exposure-related incident."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A longtime shelter volunteer with seven years of experience begins administering intramuscular medications to cats after watching staff do it routinely. The shelter has no written protocol authorizing volunteers to administer injections. What has occurred?","o":["An example of acceptable informal delegation since the volunteer has sufficient experience","A scope-of-practice violation — volunteers may only perform tasks they have been explicitly trained and authorized for; internal experience does not confer authorization","A breach of the WIIFM engagement principle","A DEA controlled substance violation since injections require a registration number"],"a":1,"e":"Volunteer scope of practice is defined by explicit training and authorization from credentialed staff — not by observed experience, personal comfort, or tenure. Performing a task outside your authorized scope exposes both the volunteer and the shelter to liability regardless of how familiar the task looks."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A volunteer is asked to leave the program after repeatedly sharing sensitive case details on social media. The shelter manager verbally tells them not to return but documents nothing. What risk does this create?","o":["No risk — verbal dismissal is legally sufficient for volunteers since they are not employees","Legal vulnerability if the volunteer disputes dismissal; undocumented volunteer exits have the same exposure as undocumented employee terminations","A violation of the Board's authority since only the Board can remove volunteers","A DEA compliance issue if the volunteer had access to controlled substance storage areas"],"a":1,"e":"Volunteer exits, like employee terminations, require documented progressive process. An undocumented verbal dismissal creates the same legal exposure as an undocumented employee termination: the shelter cannot demonstrate what occurred, what warnings were given, or what the grounds for removal were if the volunteer disputes the decision."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A pregnant volunteer requests to continue working in the cat ward during her second trimester. What is the management obligation?","o":["Immediately terminate her volunteer agreement for safety reasons","Counsel her specifically about toxoplasmosis risk from cat feces, ringworm, and salmonella — the shelter must ensure informed consent before she continues working in that environment","Reassign all pregnant staff and volunteers to administrative tasks without discussion","No special action is required; zoonotic risk briefings are for paid staff only"],"a":1,"e":"Pregnant individuals are a defined high-risk category for zoonotic disease exposure in shelters. The management obligation is not automatic reassignment but informed consent: the shelter must provide specific counseling on the relevant risks (toxoplasmosis from cat feces, ringworm, salmonella) so the volunteer can make an informed decision about her continued participation."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A shelter is comparing two approaches to volunteer retention: (A) assign all new volunteers to the most challenging behavioral cases to fast-track skill development, or (B) match case complexity to each volunteer's current skill level and provide mentorship pathways. Which approach is supported by management principles?","o":["Approach A — challenge drives engagement and rapid skill development","Approach B — matching complexity to skill level produces competence without overwhelm, and visible growth pathways increase long-term retention","Neither approach matters since most volunteers leave within 60 days regardless","Approach A for dog volunteers, Approach B for cat volunteers"],"a":1,"e":"Volunteers who are overwhelmed by cases beyond their skill level experience reduced confidence and higher attrition. Approach B — matching complexity to capability and providing visible growth pathways through mentorship or level advancement — is explicitly recommended for sustainable volunteer retention."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A new ringworm outbreak is confirmed in the cat ward. Which zoonotic training action is required at the management level?","o":["No action required since all staff completed general zoonotic training at hire","Trigger a refresher or targeted training session specifically addressing ringworm transmission, PPE requirements, and exposure protocols for the current outbreak","Immediately close the shelter to volunteers until the outbreak resolves","Notify the Board of Directors and await their approval before informing staff"],"a":1,"e":"Annual zoonotic training is a baseline. When a new or elevated zoonotic risk is identified — such as a confirmed ringworm outbreak — targeted refresher training is required. Staff and volunteers must be specifically informed about the current risk, updated PPE expectations, and what to do if personal exposure occurs."},{"type":"mcq","domain":"Shelter Management","sub":"Management & Leadership","q":"A staff member sustains a cat scratch in the cat ward during routine handling. What is the management-level protocol obligation immediately following a potential zoonotic exposure?","o":["Document the scratch in the equipment maintenance log only","Ensure the staff member knows the wound care protocol, who to notify in the shelter hierarchy, and whether the exposure triggers mandatory occupational health or public health reporting","Issue the staff member a verbal warning for unsafe handling technique","Quarantine the cat for 30 days under rabies observation regardless of vaccination status"],"a":1,"e":"The management obligation after a zoonotic exposure event includes: (1) wound care protocol awareness, (2) internal notification pathway, and (3) determining if the exposure triggers mandatory occupational health or public health reporting — such as a rabies post-exposure assessment. Simply treating the wound without following the reporting chain is non-compliant."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter director is auditing the facility's administrative infrastructure. Which medium represents the preferred system for maintaining modern shelter data?","o":["Handwritten paper ledgers organized by month","Digital software systems designed specifically for animal shelters","Storing data via verbal tradition among senior personnel","A physical whiteboard in the intake lobby"],"a":1,"e":"The standard is explicit: digital systems should be used for record keeping, with a strong preference for software platforms designed specifically for animal shelter environments. Paper-based systems and informal verbal traditions are non-compliant."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An intake supervisor is justifying the purchase of a new dedicated data platform. What do shelter software or spreadsheet programs allow organizations to better manage?","o":["DEA registration numbers and veterinary license renewals","Resources, schedules, and shelter processes","Media relationships and GP fee schedules","Volunteer background checks and Board voting schedules"],"a":1,"e":"Shelter software or spreadsheet programs allow organizations to better manage three specific operational domains: resources, schedules, and shelter processes. This is the direct operational benefit stated in the record-keeping standard."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter database must perform two distinct types of data reporting. The system must be capable of generating individual animal records as well as which other output?","o":["Automatic public relations press releases","Basic population-level reports","Genetic breed-purity certificates","Financial invoices for outside specialists"],"a":1,"e":"The dual reporting requirement mandates that shelter software generate both individual animal records and basic population-level reports. A system capable of only one of the two is functionally deficient."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter medicine team wants to evaluate whether they met their targeted live release percentage over the past year. Why must the digital record system actively support this inquiry?","o":["To allow individual animal files to be deleted every 12 months","To allow regular assessment and reporting of organizational goals and activities","To automatically reduce care time to 5 minutes per animal","To eliminate the rabies vaccination history tracking requirement"],"a":1,"e":"The record-keeping infrastructure must allow regular assessment and reporting of organizational goals and activities. This is an explicit function required of shelter databases, not an optional feature. Without this capability, the organization cannot evaluate whether its strategic targets are being met."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A high-volume facility is transitioning from paper kennel cards to a digital tablet database. This shift directly satisfies which record-keeping directive?","o":["The policy to keep all data hidden from private practitioners","The directive that digital systems should be used for record keeping","The requirement to outsource data management to the police department","The rule limiting intake processing to a 48-hour window"],"a":1,"e":"Moving from paper to digital satisfies the explicit standard that digital systems should be used for record keeping. This applies regardless of the specific digital platform chosen, as long as it supports both individual records and population-level reporting."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An analyst pulls a report showing the total number of cats admitted, the average feline length of stay, and the total euthanasia percentage for the month. What type of report has been generated?","o":["An individual animal record","A population-level report","A historical owner summary","A strategic board budget proposal"],"a":1,"e":"Aggregate, shelter-wide metrics compiled across a group of animals represent a population-level report. This is distinct from an individual animal record, which documents the journey of a single specific animal. Monthly metrics such as total intakes and LRR are always population-level data."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A technician needs to find the exact vaccine dates, initial BCS, and current housing location for a specific dog. Which database asset should they access?","o":["A macro population-level trend analysis","The individual animal record","The shelter's quarterly strategic plan","The VMA newsletter archive"],"a":1,"e":"Data specific to one animal (vaccine dates, BCS at intake, current housing location) is found in that animal's individual record. This is the personal file that tracks a single resident's complete journey from intake to outcome."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter uses its digital system to balance personnel shifts, track cleaning rotations, and monitor surgical suite availability. This directly supports management of which operational element?","o":["Community cat grant funding","Schedules, resources, and shelter processes","Media point person press release coordination","Legal disputes with municipal police"],"a":1,"e":"Using a digital system to balance staff shifts, track cleaning schedules, and monitor surgical availability represents the direct use of shelter software for managing schedules, resources, and shelter processes."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"Leadership notes they cannot evaluate mission milestones because their software cannot compile shelter-wide metrics. Which explicit capability is missing?","o":["The ability to verify volunteer DEI training hours","The generation of basic population-level reports to allow regular assessment of organizational goals","An automated link to private practitioner medical records","A photography portal for identifying facial markings"],"a":1,"e":"The missing capability is the ability to generate basic population-level reports. Without this, the organization cannot perform regular macro-assessments of whether its stated organizational goals are being achieved. Both individual records and population reports are required."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter manager compares a generic retail inventory program against software designed specifically for animal welfare organizations. Why is the animal shelter software preferred?","o":["It is mandated to be approved by the local police department","It is designed specifically to manage shelter-specific resources, schedules, processes, and population reporting","It eliminates housing-location-by-time tracking requirements","It automatically assigns pediatric animals to slow track"],"a":1,"e":"Shelter-specific software is preferred because it is engineered for the specific operational needs of animal welfare organizations: managing resources, schedules, and processes while also generating individual animal records and population-level reports. Generic inventory software cannot fulfill the dual reporting requirement."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A municipal shelter must submit monthly metrics to the city council to justify its operating budget. Which data output should be presented to summarize the overall flow of animals through the facility?","o":["A single individual record for a highly adoptable puppy","A compilation of population-level reports reflecting overall shelter activities and goals","Intake photography files for all geriatric cats","A single staff member's bite prevention training log"],"a":1,"e":"Presenting shelter-wide trends and throughput to a municipal oversight body requires population-level reports that reflect aggregate organizational activities and outcomes. A single individual record or a staff training log cannot represent the overall flow of animals through the facility."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An auditor discovers a shelter is tracking its entire animal population using loose sticky notes on a corkboard. Which core record-keeping guideline does this directly violate?","o":["The rule requiring all data to be routed through the Board","The standard that digital systems should be used for record keeping","The mandate to consult a liaison committee before moving an animal","The requirement for a 14-day quarantine for all strays"],"a":1,"e":"A sticky-note corkboard system is a paper-based system. It directly violates the explicit standard that digital systems should be used for record keeping. This system also cannot generate population-level reports or support regular goal assessment, compounding the non-compliance."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A medical director wants to monitor the incidence rate of URI across the entire feline ward over three months. What feature must the shelter software possess to enable this review?","o":["The ability to link a cat's file to a private practitioner's social media","The capacity to generate basic population-level reports","An automated mechanism to increase adoption fees for healthy cats","A portal that restricts file access to the Executive Director"],"a":1,"e":"Tracking disease incidence across an entire ward or population over time requires the ability to generate population-level reports. Individual records can tell you that one cat had URI; a population report tells you how many cats across the whole ward were diagnosed in a given period."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A management team sets a target to reduce large-dog ALOS by 10% in the next quarter. Which function of the digital system is required to monitor whether this target is being achieved?","o":["The intake photography module","Regular assessment and reporting of organizational goals and activities","The pro bono specialist billing feature","The automated bite prevention training log"],"a":1,"e":"Monitoring progress toward a specific performance benchmark requires the system's ability to support regular assessment and reporting of organizational goals and activities. This function allows leadership to generate quarterly comparisons of ALOS data against the stated target."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"Why are spreadsheet programs or dedicated shelter software valuable assets for animal welfare organizations?","o":["They eliminate the need to consult professional organizations","They allow organizations to better manage resources, schedules, and shelter processes","They automatically convert slow-track behavioral cases to fast track","They act as the primary media spokesperson during cruelty investigations"],"a":1,"e":"The explicit benefit stated in the record-keeping notes is that shelter software or spreadsheet programs allow organizations to better manage resources, schedules, and shelter processes. This is the foundational operational rationale for adopting digital tools."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter supervisor reviews a digital file containing a cat's intake date, physical description, rabies vaccination history, and daily medical treatments. This document is best described as a(n):","o":["Population-level report","Individual animal record","Strategic plan quarterly summary","Liaison committee policy brief"],"a":1,"e":"A comprehensive file tracking the specific clinical and procedural journey of one distinct animal (with intake data, vaccination history, and daily treatments) is an individual animal record. It is distinguished from a population report by its focus on a single specific animal rather than an aggregated cohort."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter is selecting a digital platform and wants to ensure it meets all standard requirements. The system must natively generate which pair of data outputs?","o":["Press releases and donor tax receipts","Basic population-level reports and individual animal records","Police department rosters and GP newsletters","Strategic plans and pro bono legal waivers"],"a":1,"e":"The dual reporting requirement states that a shelter's software system must be able to generate both basic population-level reports and individual animal records. These are the two mandatory data outputs for a compliant system."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An administrative assistant builds a spreadsheet to log daily cleaning schedules for the feline isolation room. According to the record-keeping standard, is this use of a digital tool appropriate?","o":["No; only police-department-approved software can be used","Yes; spreadsheet programs help better manage schedules and shelter processes","No; spreadsheets are prohibited under the individual record mandate","Yes; but only if the spreadsheet is reviewed by a liaison committee every 24 hours"],"a":1,"e":"Using a spreadsheet to track cleaning schedules is an appropriate and compliant use of digital tools. The record-keeping standard explicitly states that shelter software or spreadsheet programs allow organizations to better manage schedules and shelter processes."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter's strategic plan outlines an objective to increase live outcomes by partnering with regional rescue groups. To evaluate this program's effectiveness regularly, what must the record-keeping system permit?","o":["Deleting historical data to optimize server space","Regular assessment and reporting of organizational goals and activities","Restricting all outcome logging to one day per month","Transferring data oversight to an outside VMA"],"a":1,"e":"Evaluating the effectiveness of a programmatic initiative requires the system to allow regular assessment and reporting of organizational goals and activities. Without this function, the shelter cannot determine whether the rescue partnership is actually improving live release rates."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A veterinary team updates an animal's digital file to record that surgery was completed today. This real-time update ensures accuracy in which operational category?","o":["Population-level disease charting","Individual care and record keeping for that specific animal","High-level strategic goal formulation","Board-directed long-range financial planning"],"a":1,"e":"Updating an individual animal's file with a specific clinical event (surgery completion) is an act of individual care record keeping. It ensures that the single animal's record accurately reflects its clinical history, supporting continuity of care and legal compliance."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter database can look up one animal at a time but cannot aggregate data or generate total intake or outcome numbers. Why does this represent a record-keeping standard failure?","o":["It fails to provide individual animal records for veterinary staff","The software system must be able to generate basic population-level reports, and this one cannot","It automatically invalidates zoonotic disease training documentation","It prevents the Executive Director from speaking to the media"],"a":1,"e":"A system that can only look up individual animals but cannot aggregate data fails the mandatory dual reporting requirement. The standard explicitly requires that the system be able to generate basic population-level reports alongside individual records."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An operations manager uses a software dashboard to determine whether the shelter has the physical space and staffing hours to accept a transport of 20 dogs. This represents digital record keeping supporting management of which asset?","o":["Media spokesperson authorization","Resources and shelter processes","Local private practitioner wait times","Board budget approval timelines"],"a":1,"e":"Using a data dashboard to check available housing capacity and staffing hours before accepting a transport is a direct example of using digital record keeping to manage resources and shelter processes. This is one of the three core operational domains that shelter software is designed to support."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A Board of Directors wants to review whether the organization is systematically reducing intake numbers per its five-year plan. What digital output must leadership pull to demonstrate this macro-trend?","o":["A single individual animal record","A population-level report that allows assessment of organizational goals over time","A newsletter left in a local clinic's waiting room","A signed training log on feline body language"],"a":1,"e":"Monitoring a high-level organizational trend over multiple years requires population-level reports linked to regular goal assessment. Individual records cannot answer questions about organizational trends. A population report comparing annual intake totals across multiple years directly addresses the Board's question."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A clerk wants to know if a standard cloud-based spreadsheet can be used to track veterinary supply inventory and surgery schedules. Is this acceptable?","o":["No; only specialized police-department-approved software can be used","Yes; shelter software or spreadsheet programs allow organizations to better manage resources, schedules, and processes","No; spreadsheet programs are prohibited under the individual animal record mandate","Yes; but only if the spreadsheet is reviewed by a liaison committee every 24 hours"],"a":1,"e":"Spreadsheet programs are explicitly recognized as an acceptable digital tool for managing resources, schedules, and shelter processes. Tracking supply inventory (resources) and surgery schedules (schedules) using a spreadsheet is fully compliant with the record-keeping standard."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"Which of the following represents an explicit operational benefit of digital records over paper-based systems?","o":["Removing the legal obligation to comply with local regulations","Better management of resources, schedules, and processes, alongside population-level reporting","Eliminating zoonotic disease training requirements","Transferring day-to-day authority to the Board of Directors"],"a":1,"e":"The explicit operational benefits of digital systems are: better management of resources, schedules, and shelter processes; generation of individual animal records; generation of population-level reports; and support for regular goal assessment. Paper systems cannot reliably deliver any of these functions at scale."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A data entry volunteer is being trained to pull a list of all animals in the shelter for longer than 30 days. What type of data asset is this?","o":["A historical owner behavioral profile","A basic population-level report","An individual surgical procedure log","A strategic policy framework"],"a":1,"e":"Compiling a list of animals meeting a shared criterion (LOS greater than 30 days) across the entire shelter population is a population-level report. It aggregates data from individual records into a cohort view, which is the defining characteristic of population-level reporting."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter veterinarian investigating a parvovirus spike uses the software to generate a report tracking movement patterns of all dogs across specific kennels over two weeks. This utilizes the database's capacity for:","o":["Individual owner history tracking","Population-level assessment and reporting","Pro bono specialist financial reconciliation","High-level board governance review"],"a":1,"e":"Mapping multi-animal movement patterns during an outbreak investigation utilizes the system's population-level assessment and reporting capability. Individual records contain the housing-by-time data for each dog; the population report aggregates that data across all affected animals to identify the exposure chain."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter adopts a policy requiring quarterly review of internal metrics against their mission of reducing feline length of stay. What function must the record system actively perform to support this policy?","o":["Generate automated media releases after every adoption","Allow regular assessment and reporting of organizational goals and activities","Restrict individual records to paper backup folders","Automatically delete stray animal vaccination histories"],"a":1,"e":"Supporting a quarterly metrics review against a stated strategic target requires the system to allow regular assessment and reporting of organizational goals and activities. This is exactly what this function is designed for: enabling leadership to compare real-time data against stated mission objectives."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"An audit reveals the shelter's software perfectly tracks individual animals but cannot calculate or display collective shelter-wide data over time. Which core recommendation does this fail?","o":["The recommendation to provide newsletters to local GPs","The standard that the system must be able to generate basic population-level reports","The requirement to document staff bite prevention training","The mandate to maintain an active VMA liaison committee"],"a":1,"e":"A system that tracks individual animals but cannot generate collective, shelter-wide data fails the dual reporting standard. The system must be able to produce population-level reports that allow aggregate analysis of shelter metrics over time. Individual tracking alone is insufficient."},{"type":"mcq","domain":"Shelter Management","sub":"Record Keeping","q":"A shelter uses its digital tracking software to coordinate the surgery schedules of three high-volume spay/neuter veterinarians across multiple incoming transport groups. This is an example of software managing which parameter?","o":["Board-directed long-range endowments","Resources, schedules, and shelter processes","Media relations during a cruelty investigation","Drafting of high-level community animal service policies"],"a":1,"e":"Coordinating multiple surgeons and transport groups represents direct use of shelter software to manage resources (veterinary personnel time) and schedules (surgery appointment blocks and transport timing). This is one of the core operational functions shelter software is designed to support."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"Which of the following correctly describes the formal definition of disease surveillance within a shelter population?","o":["Random sampling of healthy animals prior to community adoption events","The ongoing systematic collection, orderly consolidation, analysis and interpretation of health data, and its prompt dissemination to those who can act on it","Immediate euthanasia of any animal exhibiting signs of an endemic respiratory condition","Retrospective evaluation of historical medical bills by the Board of Directors"],"a":1,"e":"Disease surveillance requires both components: (1) ongoing systematic collection, consolidation, analysis and interpretation of health data AND (2) prompt dissemination to people in a position to act. A system that collects without communicating does not meet the full definition."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter veterinarian calculates the number of newly diagnosed cases of canine parvovirus divided by the total number of susceptible dogs in the facility during May. What specific metric is being calculated?","o":["Prevalence percentage","Incidence rate","Crude mortality frequency","Case-fatality proportion"],"a":1,"e":"Incidence rate is newly diagnosed cases divided by the susceptible population at risk during a specified period. It is a rate over time, not a point-in-time proportion. Prevalence would measure all current cases at a single moment."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"On October 1st, a medical team examines all 100 resident cats and notes 15 currently display signs of upper respiratory infection. What epidemiological metric does this 15% figure represent?","o":["Incidence rate","Prevalence","Attack rate","Morbidity distribution"],"a":1,"e":"Prevalence measures the proportion of active disease cases present in the population at a single point in time. This October 1st snapshot is point prevalence, not incidence, which would require tracking new cases over a defined period."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"An open-admission facility experiences a sudden sharp increase in feline panleukopenia incidence. What does a sudden escalation in disease frequency almost always indicate?","o":["A successful expansion of physical housing capacity","A breakdown in health-management protocols or the need for new ones","An automatic reduction in average length of stay for all felines","A shift from digital to paper record-keeping"],"a":1,"e":"Increased disease frequency almost always signals a protocol breakdown or the need for additional protocols. Even when incidence is stable, quantifying the endemic level helps prioritize which diseases deserve special attention."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A veterinary epidemiologist investigating a Bordetella outbreak at a shelter must analyze disease frequency across which three axes to generate actionable transmission hypotheses?","o":["Breed type, intake source, and funding stream","Host, location, and time of the year","Microchip status, volunteer availability, and weather patterns","Body condition score, weight, and adopter demographics"],"a":1,"e":"The three required axes are: Host (who is getting sick, e.g., kittens vs. adults), Location (where disease occurs, e.g., holding vs. adoption), and Time (when disease peaks, e.g., spring vs. fall). All three together generate hypotheses about causes and transmission factors."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"When configuring a disease surveillance database, why is it essential to maintain separate data fields for clinical signs and definitive diagnoses?","o":["To satisfy bureaucratic police department reporting requirements","To avoid double-counting individual disease episodes","To allow non-credentialed volunteers to alter veterinary records","To artificially lower the calculated average length of stay"],"a":1,"e":"If clinical signs and diagnoses are stored in the same field, a single disease episode can be counted twice: once when signs are noted and again when a diagnosis is confirmed. Separate fields prevent this double-counting, which would inflate disease frequency metrics."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter dog recovers from a URI episode in week 1 but develops a second identical bout two weeks later within the same monitoring period. For calculating incidence rate, how is the second episode handled?","o":["It is added to the denominator as a new susceptible host","Only the first episode during a particular timeframe counts as a new or incident case","It is multiplied by the overall prevalence to calculate a new mortality risk","It triggers mandatory recalculation of the staff-to-animal ratio"],"a":1,"e":"For diseases that can occur more than once in the same animal, only the first episode within the monitoring period counts as an incident case. Counting subsequent episodes would inflate the incidence rate and misrepresent new disease burden in the population."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter manager wants to calculate disease incidence metrics. Which data sources must provide the denominators and numerators respectively?","o":["Volunteer hours for denominators; financial grant lines for numerators","Shelter intake data for denominators; medical data for numerators","Board of Directors rosters for denominators; media inquiries for numerators","Euthanasia percentages for denominators; adoption rates for numerators"],"a":1,"e":"Intake data provides the denominator (total animals at risk of developing the disease). Medical records provide the numerator (animals diagnosed with the disease). Movement and outcome data supplement these for additional analyses."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"Why is directly comparing crude, unadjusted incidence rates between two regional shelters often epidemiologically misleading?","o":["Shelters are legally barred from sharing population-level data with outside veterinarians","Baseline circumstances that cannot be changed between shelters may be entirely different","Incidence can only be calculated for individual animals, not shelter populations","One facility may use spreadsheets while the other uses specialized software"],"a":1,"e":"Raw cross-shelter incidence comparisons are misleading when unalterable baseline variables (intake profile, geography, facility design, species mix) differ substantially between facilities. These confounders can make a well-run shelter appear worse than it truly is."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter medicine team is establishing a disease surveillance program. What is the initial, foundational step?","o":["Procure advanced PCR equipment for every individual stall","Create a short, manageable list of important infectious diseases to monitor","Request copies of all medical records from private practitioners in the county","Mandate Board of Directors training on daily sanitation"],"a":1,"e":"Surveillance must begin with a realistic, manageable disease list focused on those that are common, particularly problematic, or tied to the shelter's medical goals. The list should be short enough that collected data will actually influence decision-making and action."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter monitors feline URI (FURI) and rabies. How should monitoring frequency differ between these two diseases under standard surveillance guidelines?","o":["Low-frequency severe diseases must be reviewed daily; high-frequency diseases reviewed annually","High-incidence diseases like FURI should be monitored more frequently (monthly) than lower-frequency diseases","All monitored diseases must be reviewed on an identical quarterly schedule","Frequency is determined exclusively by police department administrative timelines"],"a":1,"e":"Monitoring frequency tracks with disease incidence and severity. High-incidence endemic diseases like FURI require at minimum monthly monitoring to detect shifts. Lower-incidence diseases can be reviewed less frequently. Active outbreaks trigger more frequent monitoring than any baseline schedule."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"Which of the following is a direct operational consequence of allowing an animal's length of stay to unnecessarily increase within a shelter?","o":["It decreases the overall workload for basic animal care staff","It increases disease risk, amplifies animal stress, and leads to overcrowding","It automatically maximizes the shelter's daily intake capacity","It eliminates the need for routine disease surveillance"],"a":1,"e":"Prolonged LOS has three compounding consequences: increased disease risk from longer pathogen exposure, increased animal stress and behavioral deterioration, and overcrowding as incoming animals fill housing occupied by long-stay residents. Reducing ALOS addresses all three simultaneously."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter tracks 500 dogs over the summer. How is Average Length of Stay (ALOS) mathematically calculated for this population?","o":["Multiplying total available humane housing units by 15 minutes of care","Summing the LOS of all animals of interest and dividing by the total number of animals contributing to LOS in that period","Dividing the number of available housing units by monthly intake capacity","Subtracting total mortality count from total live adoptions"],"a":1,"e":"ALOS is the arithmetic mean: sum of individual LOS values for all animals of interest, divided by the total count of animals contributing to the LOS calculation during the specified period (month, season, or year)."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter finds court-ordered protective custody animals have an ALOS of 45 days compared to 5 days for owner surrenders. How should leadership use this finding?","o":["Erase the data field to keep the overall population average low","Focus efforts on identifying and addressing the specific impediments causing delays in that subgroup's transit","Stop accepting all owner-surrendered animals to balance the overall average","Demote care staff responsible for housing protective custody animals"],"a":1,"e":"Elevated ALOS in a specific subgroup is an actionable signal. Leadership should investigate and address the specific legal, procedural, or operational impediments causing delays for that subgroup. The goal is targeted intervention, not changing intake policy."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter has 50 humane housing units and an ALOS of 5 days. How many new animals can be sustainably housed over a 30-day period?","o":["300 animals (50 spaces x 30 days / 5 day ALOS)","55 animals (50 + 5)","150 animals (50 x 5 days / 30 days)","7500 animals (50 x 5 x 30)"],"a":0,"e":"Intake capacity = (humane housing spaces x number of days) / ALOS. (50 x 30) / 5 = 300 animals. This formula calculates how many animals can cycle through fixed housing over a defined period given the current ALOS."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter has 60 humane canine housing units and an ALOS of 6 days. To avoid overcrowding, how many dogs can be safely admitted daily?","o":["360 dogs","10 dogs","15 dogs","2 dogs"],"a":1,"e":"Daily admissions target = humane housing units / ALOS. 60 / 6 = 10 dogs per day. Admitting more than this without reducing ALOS will cause the housing census to exceed capacity."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter demonstrates that reducing canine ALOS from 10 days to 5 days will have what predictive effect on capacity?","o":["It doubles the number of staff needed to clean each cage","It increases the number of animals that can be admitted in a period without causing overcrowding","It automatically causes a breakdown in biosecurity protocols","It completely eliminates baseline infectious disease transmission risk"],"a":1,"e":"Shorter ALOS means each housing unit cycles through animals faster. Halving ALOS from 10 to 5 days doubles the intake capacity for the same fixed housing count. This is why ALOS reduction is one of the most powerful capacity interventions available."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"Which term defines the absolute ability of an animal welfare organization to comprehensively meet the physical, medical, and behavioral needs of its resident animals?","o":["Morbidity index","Capacity for Care (C4C)","Prevalence coefficient","Data surveillance margin"],"a":1,"e":"C4C is the structural equilibrium between a shelter's physical and human resources and the baseline needs of its animal population. When C4C is exceeded, whether by too many animals or too few staff, conditions adverse to animal wellbeing result."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter is severely understaffed, leaving one technician responsible for 80 cages. What direct health risk does this understaffing create?","o":["An artificial reduction in the prevalence of endemic diseases","Breaches in shelter biosecurity, increased infectious agent exposure, and rising disease frequency","An automatic decrease in average length of stay for all sick animals","A legal challenge regarding board of directors financial governance"],"a":1,"e":"When staffing is inadequate, cleaning and feeding times are compressed, cross-contamination risks rise, and infectious disease frequency increases. Biosecurity depends on consistent, timely cage cleaning: understaffing directly undermines the basic infection control framework."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"What is the minimum amount of daily time per animal that the National Animal Control Association (NACA) recommends staff spend providing basic care?","o":["5 minutes","15 minutes","45 minutes","60 minutes"],"a":1,"e":"NACA explicitly recommends a minimum of 15 minutes per animal per day for basic care. This is a minimum baseline for feeding and cleaning only, not a comprehensive care standard. Shelters should strive to exceed this minimum."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"The NACA-recommended 15 minutes per animal per day is strictly intended to cover which two basic tasks?","o":["Behavioral modification and public adoption counseling","Feeding and cleaning","Venipuncture and diagnostic PCR testing","Media training and record-keeping entry"],"a":1,"e":"The 15-minute NACA standard covers only feeding and cleaning. Medical care, enrichment, behavioral assessment, training, and socialization all require additional staff time beyond this minimum floor."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter currently meets the NACA 15-minute basic care minimum. What is the explicit recommendation regarding this standard?","o":["Maintain this exact ceiling to prevent over-budget expenditure on personnel","Strive to increase available staff time per animal beyond this minimum to maximize animal welfare","Reduce time to 5 minutes if the facility uses digital record-keeping","Outsource remaining cleaning duties to a liaison committee"],"a":1,"e":"Meeting the 15-minute standard means meeting only the bare minimum survival floor for feeding and cleaning. The explicit recommendation is that shelters should strive to increase available staff time per animal above this minimum to maximize the welfare of their resident population."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"To audit a shelter's staffing capacity to provide basic care, which two metrics must be estimated and compared?","o":["Required daily basic care time (census x minimum time per animal) compared to actual daily hours staff spend in basic care","Volunteer orientation hours vs. hours spent in executive board meetings","Time spent processing intake files vs. time spent on media interviews","Minutes spent performing euthanasia vs. hours spent on public training classes"],"a":0,"e":"The three-step audit: (1) estimate total time staff SHOULD spend in basic care daily (census x 15 min minimum), (2) calculate actual hours staff spend in basic care daily, (3) compare the two. The gap reveals the staffing shortfall."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter medicine department publishes a yearly summary of all monitored infectious disease occurrence. What is this standard document called?","o":["A quarterly strategic plan memo","An annual medical profile","A general practitioner liaison brief","A public relations press kit"],"a":1,"e":"The annual medical profile is the recommended standard tool for organizing and summarizing disease occurrence trends over a calendar year. It provides a longitudinal view of disease burden and progress toward control goals."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"Which data issue most commonly causes failure or inaccuracy in shelter disease surveillance collection?","o":["Using specialized shelter software instead of spreadsheets","Failure to reach a definitive diagnosis","Documenting bite prevention training hours in a digital file","Providing food during after-hours facility tours"],"a":1,"e":"If an animal's illness never receives a standardized definitive diagnosis, the case cannot be classified or counted in the surveillance system. Undiagnosed cases are invisible to the surveillance framework. This is explicitly identified as the primary systemic cause of surveillance data failure."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"When staff members fully understand the rationale for complete and accurate data collection, what is the direct operational result?","o":["Physical housing capacity instantly doubles","Data quality rises, preventing wasted resources and misleading analyses","Average length of stay drops to zero for all sick animals","The shelter is legally exempted from tracking natural mortality"],"a":1,"e":"Staff who understand WHY accurate data collection matters produce better data. Poor-quality data wastes collection resources and produces misleading analyses that can misdirect interventions and harm population health outcomes."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter's medical staff provides a monthly data packet to the executive director. What is the primary benefit of this monthly review cadence?","o":["It eliminates the need for written protocols","It maintains interest in surveillance, ensures data quality, and allows timely notification of health changes to administration","It automatically ensures compliance with municipal law enforcement codes","It fulfills the board's requirement to manage day-to-day kennel operations"],"a":1,"e":"Monthly reviews provide three reinforcing benefits: they keep staff engaged in data quality, they allow timely detection of health trends before they become crises, and they ensure medical staff can promptly inform administration when population health changes."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter veterinarian selects variables to monitor alongside ALOS to identify procedural impediments. Which of the following is explicitly listed as an appropriate tracking variable?","o":["The name of the board of directors president","Source of the animal (such as seized vs. stray)","The brand of digital spreadsheet software used","Distance from the shelter to the nearest police department"],"a":1,"e":"Animal source (seized vs. stray vs. owner surrender) is one of five explicitly listed factors to stratify ALOS by. Others include general health status, breed type, seasonal intake, and volunteer availability. Stratifying by source often reveals legal hold periods or procedural delays specific to that intake pathway."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"To ensure an effective surveillance program, which document must specify what, where, when, and by whom each data collection component is performed?","o":["Verbal agreements during shift changes","Written protocols","Media press releases","Invoices from local private general practitioners"],"a":1,"e":"Written protocols are explicitly required for an effective surveillance program. They provide the standardized framework ensuring consistency across staff, shifts, and time. Verbal agreements are not accountable, not auditable, and not durable."},{"type":"mcq","domain":"Shelter Management","sub":"Data & Analysis","q":"A shelter records 20 natural deaths among its resident canine population during a canine influenza outbreak. This figure represents the population's:","o":["Morbidity rate","Mortality due to natural causes","Prevalence index","Capacity for care coefficient"],"a":1,"e":"Mortality tracks the frequency of death due to natural causes within the population. Natural deaths are tracked separately from euthanasia, which is a managed outcome. Both metrics appear in the required population health snapshot alongside incidence and prevalence of major infectious diseases."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A high-volume spay-neuter clinic wants to systematically address injuries resulting from animal bites, heavy lifting, and sharps prick injuries. According to the hierarchy of risk control, which strategy represents the absolute most effective initial tier of defense?","o":["Mandate the use of thick canvas protective gloves (PPE)","Complete elimination of the hazard","Implement a mandatory 2-hour administrative lecture on low-stress handling","Install active scavenging engineering control lines in the pre-op suite"],"a":1,"e":"The hierarchy of risk control ranks elimination as the most effective tier: removing the hazard entirely from the workplace. PPE is the least effective tier and is used only when higher-tier controls cannot adequately manage the hazard."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A clinic supervisor encourages veterinary technicians to directly design the restraint protocols for the facility's feral cat intake trap lines. What concept from the text describes this collaborative problem-solving approach?","o":["Psychosocial stress stratification","Participatory ergonomics","Decision latitude isolation","Administrative substitution"],"a":1,"e":"Participatory ergonomics actively engages the staff who execute a task in designing the solutions to their own workplace challenges. This approach yields more practical and creative solutions while fostering staff ownership and engagement with the resulting protocols."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"Exposure to waste anesthetic gas (WAG) inside an unventilated surgical prep room presents severe health risks to veterinary personnel. Which clinical consequence is explicitly associated with chronic WAG exposure?","o":["Presbyopia before the age of 40","Miscarriage and pre-term delivery","Ligament inflammation from high force application","Severe color rendering index discrepancies"],"a":1,"e":"Chronic exposure to waste anesthetic gas is directly associated with reproductive and genotoxic outcomes including miscarriages, pre-term delivery, balance and proprioceptive deficits, hematologic alterations, and genotoxicity. Presbyopia is a separate age-related vision issue unrelated to WAG."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An environmental auditor calculates the global warming footprint of an HQHVSN facility's anesthetic vaporizers. What is the global warming potential of commonly released waste anesthetic gases?","o":["Equal to the baseline potential of ambient CO2","Over a thousand times that of CO2","Negligible due to rapid atmospheric neutralization","Completely eliminated by the use of inline HEPA filters"],"a":1,"e":"Modern inhalant anesthetic agents (isoflurane, sevoflurane) have global warming potentials exceeding the baseline of carbon dioxide by more than a thousandfold. HEPA filters have no effect on gas molecules and cannot reduce the environmental release of waste anesthetic gases."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A high-volume surgery clinic relies solely on activated charcoal canisters attached to the exhalation limbs of their anesthesia circuits. What unique property and operational limitation do these canisters possess?","o":["They vent gas safely to the outside environment but require high-flow non-recirculating ventilation","They adsorb the gas rather than releasing it into the atmosphere, but they are among the least effective and most inconsistent protection methods","They function as an effective engineering control only if paired with standard surgical masks","They offer complete protection for pregnant personnel during vaporizer refills"],"a":1,"e":"Charcoal canisters capture gas molecules via adsorption rather than venting, which is environmentally better than releasing gas to the atmosphere. However, they yield inconsistent performance, have a finite capacity, and are among the least effective scavenging methods. They do not protect pregnant personnel during filling."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A technician has weighed a charcoal scavenging canister at the end of a long surgical shift. To maintain safety when using these specific canisters, what daily administrative practice must be performed?","o":["The canister must be flushed with water to dissolve the adsorbed gas","Canister weight gain must be monitored and usage recorded daily so they can be exchanged when exhausted","The canister must be placed directly beneath a HEPA filter overnight","The weight data must be reported to the local regulatory body quarterly"],"a":1,"e":"Charcoal has a finite adsorption capacity. Daily monitoring of weight gain is mandatory to detect the exact threshold of canister exhaustion so it can be exchanged before releasing gas back into the environment. This is an administrative control that supports the use of an already low-efficacy scavenging method."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A clinic manager wants to choose personal protective equipment to block waste anesthetic gases from being inhaled by recovery room personnel. Which option is explicitly stated to protect workers?","o":["Standard surgical paper masks","Activated charcoal cloth face masks","Inline HEPA filtration masks","None of the above; surgical masks, charcoal masks, and HEPA filters do not protect against WAG"],"a":1,"e":"The textbook explicitly states that standard surgical masks, charcoal face masks, and HEPA filtration masks are all ineffective at filtering waste anesthetic gas molecules from inhaled air. Gas molecules are too small to be blocked by any of these filtration mechanisms. Engineering controls (scavenging, ventilation) are required."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An anesthetic protocol is being updated to minimize ambient contamination in a high-volume suite. Which protocol setting directly minimizes WAG release while maintaining patient safety?","o":["Utilizing the highest possible flow rate to ensure circuit pressure","Choosing the lowest appropriate gas flow rates consistent with patient safety and proper equipment function","Deactivating the active scavenging system during induction","Overfilling the liquid vaporizer chambers twice per shift"],"a":1,"e":"Balancing environmental protection with anesthesia safety requires setting the minimum viable flow rate that keeps the circuit functional while minimizing gas escape into the workspace. High flow rates increase WAG exposure without clinical benefit once minimum safe levels are achieved."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"During the morning setup, a veterinary assistant is preparing the anesthesia machines. Which mechanical step must always be executed before using the systems to minimize room contamination?","o":["Color rendering index evaluation","Leak testing of the anesthesia circuit","Pedicle tie force assessment","Activated charcoal canister venting"],"a":1,"e":"A daily, universal pressure check (leak test) is a baseline requirement that must precede any anesthesia use. Catching system leaks before gas escapes into the workspace is an administrative control that prevents unnecessary staff exposure throughout the entire surgical day."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A clinic is updating its liquid anesthesia filling protocols. To minimize spills during vaporizer filling, what specific equipment configuration should be utilized?","o":["Open plastic funnels held by two staff members","A keyed vaporizer filling system or a drip-free bottle adapter","A non-recirculating wide-mouth beaker line","Standard surgical suction lines routed through a HEPA filter"],"a":1,"e":"Keyed fill ports and drip-free neck adapters specifically target liquid handling vulnerabilities to prevent spills during liquid anesthetic transfer. These engineering controls reduce the risk of large liquid spills that would create immediate high-concentration WAG exposure for all personnel in the area."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A veterinary technician is assigned to refill the liquid isoflurane vaporizers at the end of the day. Which administrative parameter must be strictly enforced during this task?","o":["Fill the vaporizers when as many staff as possible are present to observe the process","Fill vaporizers when as few staff as possible are present, and pregnant personnel must not be present","Perform the filling directly over a large absorbent mat of dry cat litter","Ensure the room's non-recirculating ventilation system is completely turned off during filling"],"a":1,"e":"Minimizing the number of personnel in the room during filling reduces collective exposure. The absolute exclusion of pregnant personnel and those attempting to conceive is a mandatory administrative rule. Running non-recirculating ventilation during filling further reduces ambient WAG concentration."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A bottle of liquid anesthetic breaks on the operating room floor creating a large liquid spill. What is the correct documented method for resolving a large liquid spill?","o":["Wait for it to evaporate naturally without altering room ventilation","Ventilate the area, apply an absorbent material like cat litter, sweep it into a sealable container, or use surgical suction if available in the room","Cover the spill with a damp surgical drape and continue with the next scheduled surgery","Evacuate the entire building for 48 hours to prevent genotoxicity"],"a":1,"e":"Large liquid spills require: first, increasing ventilation; then applying a granular absorbent (cat litter) to capture the liquid; sweeping the saturated absorbent into a sealable container for proper disposal. In an OR, surgical suction can also be used. Waiting for evaporation without additional ventilation results in maximum staff exposure as the liquid vaporizes."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A clinic director wants to evaluate individual cumulative exposure to waste gases among the surgery team over a two-week period. Which monitoring tool should be employed periodically for this purpose?","o":["Inline HEPA filter sensors","Individual anesthetic monitoring badges worn by each staff member","Daily charcoal canister weight logs","Table height metric calipers"],"a":1,"e":"Wearable badge dosimeters (anesthetic monitoring badges) provide accurate, individual-level cumulative data on each staff member's WAG exposure over a defined period. This is distinct from daily charcoal canister weight logs (which measure canister exhaustion, not personal exposure) and daily leak tests (which check equipment integrity)."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgery team frequently handles large dogs weighing over 35 kg. To reduce the ergonomic strain of lifting these animals onto prep tables, what lifting strategy should be practiced?","o":["A rapid single-person lift using back muscles to ensure speed and minimize handling time","A coordinated two-person lift using bent knees and a straight back","Lifting the animal exclusively by its front limbs while keeping the legs straight","Requiring the surgeon to perform all lifts to maintain clinical isolation of the patient"],"a":1,"e":"Proper biomechanical lifting mechanics for heavy patients require a multi-person effort (to distribute load) focusing force generation through the legs (bent knees) while maintaining a neutral, straight spinal column. Single-person lifts using back muscles in a bent position are the primary cause of acute lumbar injury."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An HQHVSN surgeon reports chronic musculoskeletal discomfort in the lower back, neck, and shoulders. Aside from biomechanical strain, which psychosocial risk factors are highly correlated with MSK discomfort in veterinarians?","o":["Low work demands paired with high decision latitude","Low job satisfaction and high work-related stress","High usage of active scavenging systems","Frequent participation in ergonomics committees"],"a":1,"e":"Somatic pain perception and structural musculoskeletal deterioration are heavily influenced by psychological markers. Low job satisfaction and systemic career stress are independently correlated with higher rates of reported MSK discomfort in veterinarians. The biomechanical and psychosocial risk categories interact and amplify each other."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgeon is adjusting the hydraulic surgery table prior to starting a long row of cat spays. To optimize physical ergonomics, what is the ideal table height relative to the surgeon's body?","o":["Exactly parallel with the surgeon's shoulder joints","5 to 10 cm below the surgeon's elbow height","20 cm above the surgeon's waistline","Level with the surgeon's right thumb and wrist joints"],"a":1,"e":"Placing the working surface 5 to 10 cm below elbow level minimizes shoulder elevation and neutralizes awkward spinal flexion. Tables set too high force the surgeon to elevate their shoulders and flex their elbows acutely; tables set too low force the surgeon to lean forward, loading the lumbar spine."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgeon is preparing to spay a 1.5 kg pediatric kitten on a standard-sized surgical table. How should the patient be positioned to reduce unnecessary ergonomic strain?","o":["Placed directly dead-center on the table regardless of distance from the surgeon","Placed to the side of the surgery table closer to the surgeon","Placed at the far diagonal corner of the table to maximize lighting exposure","Elevated on a pedestal directly above the surgeon's elbow height"],"a":1,"e":"Moving lightweight or small patients to the near lateral boundary of the workspace reduces the radius of forward reach. Extended forward reaching loads the lower back and shoulder muscles in a disadvantaged mechanical position. Centering the patient on a large table unnecessarily forces a forward lean for every instrument pass."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An HQHVSN facility is evaluating different seating options for its surgical staff. Why are saddle chairs explicitly recommended for high-volume surgeons?","o":["They require the surgeon to stand continuously, maximizing lower limb strength","They generate a more upright posture and allow the surgeon to position close to the table without pedestal or table interference against the thighs","They feature integrated active scavenging systems that adsorb WAG","They eliminate the need for surgeons to use corrective lenses after the age of 40"],"a":1,"e":"Saddle seats position the pelvis to tilt naturally upright, promoting a neutral lumbar curve. Their narrow footprint allows close physical proximity to the table edge without the thighs pressing against the table underside or the seat pedestal intruding. This allows fine-motor surgical work from a sitting position."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgeon experiences repetitive motion strain in the right wrist and thumb while practicing in a high-volume shelter environment. Which modification to surgical technique is recommended to mitigate repetitive motion risk?","o":["Implement hand ties exclusively for every closure to standardize technique","Implement pedicle ties and create smaller incisions if the surgical technique permits","Increase incision length to allow a full palm grip on all instruments","Standardize on the thickest available suture size for all ligations"],"a":1,"e":"The intense repetition of high-volume settings requires adapting techniques to minimize cumulative strain per procedure. Pedicle ties complete the ligation step with fewer motion repetitions; smaller incisions reduce the amount of tissue manipulation required per case. Together, these reduce the total motion load over a surgical day."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgeon wants to vary physical movements between surgeries to decrease static musculoskeletal load. Which instrument handling habit directly supports this ergonomic goal?","o":["Maintaining a rigid tripod grip throughout the entire workday to maximize consistency","Varying techniques such as alternating between hand ties and instrument ties, and alternating between tripod and palm grips","Standardizing on a single unvarying palm grip to maximize closing force","Avoiding the use of new instruments to prevent unfamiliar motion patterns"],"a":1,"e":"Alternating grip configurations (tripod vs. palm) and switching closure mechanics (hand tie vs. instrument tie) distributes the kinetic load across distinct muscle fiber groups and tendon pathways. This prevents any single structure from bearing the full cumulative load of hundreds of repetitions over a surgical day."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A resident is selecting suture materials for a large volume of canine neuters. How does suture gauge (thickness) directly affect physical strain on the surgeon's hands according to ergonomic guidelines?","o":["Thicker suture sizes require less force to secure, reducing wrist excitability","The thicker the suture gauge, the more force required to secure the knot, which can lead to ligament inflammation and muscle excitability","Suture gauge has no biomechanical relationship with hand or wrist load","Thicker suture material automatically increases the tensile strength of the surgeon's ligaments"],"a":1,"e":"High-diameter suture strands require significantly greater tensile force to seat and secure the knot. Over hundreds of repetitions, this intense, repeated force application generates tendon inflammation (particularly of the thumb and wrist flexors) and increases localized nerve and muscle excitability, contributing to repetitive strain injury."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An HQHVSN surgeon integrates brief 15 to 30 second breaks multiple times per hour into their surgical schedule. What is the term for these breaks and what is their documented physical benefit?","o":["Macro-intervals; they increase the collagen content of hand ligaments","Micropauses; they are shown to reduce MSK discomfort, especially when combined with stretching or movement exercises","Administrative controls; they allow for daily leak testing of anesthesia machines","Decision latitude windows; they reduce the global warming potential of the surgical suite"],"a":1,"e":"Micropauses are intentional 15 to 30 second interruptions to sustained static muscle loading, implemented multiple times per hour. When combined with physical movement such as stretching, yoga, or gentle exercises, they provide tissues with brief recovery windows that reduce cumulative musculoskeletal discomfort measured at end-of-shift evaluations."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A clinic manager is renovating a surgical suite's lighting infrastructure. What are the explicit requirements for lighting quality and wavelength spectrum in a shelter surgical suite?","o":["A color rendering index under 50, focused entirely on blue-spectrum wavelengths","A color rendering index greater than 90, including a broad spectrum with wavelengths in the red spectrum above 600 nm","Monochromatic green lighting to minimize patient handling stress","Variable fluorescent bulbs that maximize lens fogging for surgeons over 40"],"a":1,"e":"Accurate clinical tissue differentiation requires high-fidelity illumination (CRI greater than 90) that faithfully reproduces the full visible spectrum, explicitly including long red wavelengths above 600 nm. The red spectrum is essential for identifying blood vessels, hemorrhage, and tissue type differentiation during fine surgical work."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A 44-year-old high-volume surgeon introduces new prescription reading glasses while performing flank ovariohysterectomies. When introducing glasses into the surgical environment, what critical postural check must the surgeon perform?","o":["Ensure the glasses completely block the red spectrum of light above 600 nm","Verify that the glasses do not adversely affect posture by influencing head or neck position","Verify that the lenses eliminate the need for adhesive tape over the mask nose bridge","Check that the frame forces a tilted head angle to provide a cervical stretch during surgery"],"a":1,"e":"Visual corrections must be checked to confirm they do not require the surgeon to tilt, flex, or extend the neck to find the focal point. Incorrectly fitted lenses that force a postural compensation introduce sustained cervical MSK loading that accumulates over a high-volume surgical day and can contribute to chronic neck and shoulder injury."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A surgeon struggles with constant condensation forming on their corrective lenses during surgery. What simple physical modification is documented as the recommended solution to this problem?","o":["Increase the room temperature to match the surgeon's body temperature","Apply adhesive tape over the nose bridge of the surgical mask to reduce upward fogging","Switch from an instrument tie to a hand tie technique","Remove the surgical mask entirely during pediatric spays"],"a":1,"e":"Applying an adhesive seal across the upper margin of the surgical mask creates a physical barrier that redirects warm exhaled breath downward instead of upward into the lens surface. This eliminates condensation without requiring mask removal or specialized anti-fog lens coatings. It is the standard recommended technique."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"According to sociological models of workplace strain, which specific combination of operational factors represents a primary recognized source of severe occupational strain for high-volume shelter veterinarians?","o":["Low work demands combined with high decision latitude and strong managerial support","High work demands paired with low control or low decision latitude over work processes","High managerial communication paired with excessively low surgery throughput targets","Practicing in large team settings with an abundance of available medical resources"],"a":1,"e":"The classic job demand-control model identifies the most damaging occupational conditions as high systemic demands (workload, time pressure, emotional weight) combined with minimal personal control (low decision latitude over schedule, protocols, and outcomes). This combination drives the highest levels of psychological strain in professional settings."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"An epidemiological survey reviews mental health risks across various veterinary practice cohorts. Which demographic subgroups of veterinarians are statistically identified as being at significantly elevated risk for suicidal ideation?","o":["Older male clinicians who practice in large multi-doctor corporate hospital settings","Young female practitioners and those who practice alone rather than within a team","Mid-career veterinarians who serve exclusively on liaison and committee roles","Safe-handling instructors who coordinate participatory ergonomics programs"],"a":1,"e":"Statistical health reviews consistently show that young age, female gender, and geographic or operational isolation (solo practice) are independently associated with elevated suicidal ideation risk in veterinarians. Shelter veterinarians as a group face elevated psychological distress compared to other veterinary cohorts."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"Following a sudden perioperative death during a routine spay at a high-volume shelter clinic, a veterinarian experiences self-blame, guilt, and grief. Why is resolving this emotional response uniquely challenging in HQHVSN environments?","o":["Shelter software prevents the electronic logging of perioperative fatalities","The unyielding schedule of HQHVSN clinics makes it difficult or impossible to interrupt the workday for debriefing and time away","Veterinarians are legally barred from seeking support from external professional colleagues","Technical learning cannot occur following a natural or unexpected animal death"],"a":1,"e":"The fixed, high-volume operational flow of HQHVSN environments leaves little to no systemic space to pause for clinical debriefing, error discussion, or emotional processing after an adverse event. The scheduling barrier is the primary structural impediment, not legal restrictions or technical limitations."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A veterinary team meets to analyze a technical error that occurred during a cryptorchid neuter, discussing how they recovered intraoperatively and how to improve future technique. This debrief session directly engages which of the four pillars of successful coping?","o":["Emotional learning","Technical learning","Finding perspective","Seeking support via social isolation"],"a":1,"e":"Technical learning is defined as analyzing adverse events to extract specific improvements to surgical skills, decision-making, and team mechanics. This directly rebuilds the team's confidence in their clinical competence by converting a negative experience into actionable knowledge that reduces the probability of future occurrence."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A shelter manager wants to integrate psychological resilience training into the veterinary team's continuing education program. Which specific modalities are explicitly recommended by the text to help staff manage stress and compassion fatigue?","o":["High-flow ventilation auditing and non-recirculating ventilation training","Mindfulness training, psychotherapy, and compassion fatigue training programs","Forced ergonomics compliance drills and static posture isolation protocols","Standard PPE utilization certification and mandatory colleague isolation"],"a":1,"e":"Building long-term psychological resilience against compassion fatigue requires formal cognitive and emotional support structures. The three explicitly recommended modalities are: mindfulness training (present-moment awareness practices), professional psychotherapy (structured therapeutic support), and compassion fatigue training (specific educational programs designed for healthcare workers in high-emotional-impact roles)."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A shelter veterinarian reports distress because she is required to euthanize healthy, adoptable animals daily due to space constraints, even when she believes alternative placements could be found. She does not describe emotional exhaustion from caring for sick animals. Which construct best describes her experience?","o":["Compassion fatigue from high volume of care exposure","Moral distress from institutional constraints preventing ethical action","Secondary traumatic stress from vicarious trauma","Burnout from insufficient decision latitude"],"a":1,"e":"Moral distress arises specifically when a practitioner knows the right ethical action but is prevented from taking it by institutional, resource, or policy constraints. This veterinarian's distress is not from care exposure volume but from the ethical conflict of euthanizing animals she could otherwise save. This is the defining feature of moral distress, distinct from compassion fatigue."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A shelter medicine team responds to a large-scale cruelty seizure involving 60 severely malnourished animals. One week later, several staff members report intrusive thoughts, nightmares, and emotional numbing — not general fatigue. Which construct best explains this sudden onset?","o":["Burnout from cumulative workload over many months","Secondary traumatic stress triggered by a single high-impact cruelty case","Compassion satisfaction deficit from inadequate recognition","Perioperative fatality-specific grief response"],"a":1,"e":"Secondary traumatic stress (STS) is indirect trauma arising from exposure to the traumatic experiences of others. Unlike burnout (which is cumulative and gradual), STS can arise suddenly following a single traumatic case or event such as a severe cruelty seizure. Intrusive thoughts, nightmares, and numbing are hallmark STS symptoms. Burnout presents as chronic depletion rather than acute traumatic symptoms."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"According to the Professional Quality of Life (ProQOL) model, which positive construct counterbalances compassion fatigue and reduces burnout risk even under high-workload conditions?","o":["Compassion endurance","Compassion satisfaction","Secondary resilience coefficient","Decision latitude expansion"],"a":1,"e":"The ProQOL model is bidirectional: it includes both negative dimensions (compassion fatigue, secondary traumatic stress, burnout) and the positive dimension of compassion satisfaction — the fulfillment derived from effective caring work. High compassion satisfaction acts as a protective buffer, reducing burnout risk even among practitioners with high workloads."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"A shelter leadership team implements a program that celebrates live-release milestones, shares positive outcome stories in team meetings, and explicitly thanks staff for meaningful contributions. Which ProQOL dimension are they primarily building?","o":["Secondary traumatic stress resilience","Compassion satisfaction","Burnout compliance","Moral distress tolerance"],"a":1,"e":"Actively cultivating compassion satisfaction — through recognition of successful outcomes, sharing positive stories, and connecting individual work to population-level impact — is the primary institutional strategy for building the positive dimension of the ProQOL model. This is distinct from reducing compassion fatigue, which focuses on limiting negative exposure."},{"type":"mcq","domain":"Shelter Management","sub":"Mental Health & Self-Care","q":"When developing an institutional response to occupational distress, which approach reflects the complete ProQOL framework?","o":["Reduce workload only, since lower volume means less fatigue","Address both the negative dimensions (compassion fatigue, moral distress, STS) AND actively build the positive dimension (compassion satisfaction)","Focus exclusively on compassion satisfaction as the positive-psychology primary intervention","Prioritize STS support only, since cruelty cases are the highest-impact exposure"],"a":1,"e":"The ProQOL model requires addressing both poles: reducing negative occupational health drivers (compassion fatigue, STS, moral distress) AND building compassion satisfaction. A program that only addresses fatigue without building positive meaning will plateau. A complete program cultivates satisfaction while managing exposure."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A newly hired shelter veterinarian notices a specific provision in the state's practice act that permits out-of-state licensed veterinarians to practice medicine inside registered shelter facilities. What is the legal term for this type of provision?","o":["Civil service exemption","Voter or state exemption","Delegated task clause","Restricted mandate waiver"],"a":1,"e":"State veterinary boards write voter or institutional exemptions into practice acts to ensure shelters can attract qualified staff across state lines. These are shelter-specific carve-outs within the broader state practice act framework."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter veterinarian wants to train non-licensed shelter assistants to perform microchipping and administer subcutaneous core vaccines at intake. What document dictates whether these tasks can be legally delegated?","o":["The individual shelter's internal standard operating procedures","The state's Veterinary Medicine Practice Act","The DEA practitioner manual","The municipal contract agreement"],"a":1,"e":"State practice acts establish the exact legal boundaries regarding what veterinary tasks can be delegated to non-licensed personnel and under what level of supervision. Internal SOPs cannot expand legal authority beyond what the practice act permits."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A veterinary technician auditing the shelter's controlled substance logs notes that the volume of sodium pentobarbital logged for usage does not match the volume remaining in the safe. Which federal agency regulates and audits these records?","o":["Food and Drug Administration (FDA)","Environmental Protection Agency (EPA)","Drug Enforcement Administration (DEA)","Department of Agriculture (USDA)"],"a":2,"e":"The DEA holds absolute statutory authority over the manufacturing, distribution, logging, and security of controlled substances including sodium pentobarbital and chemical immobilization agents. Discrepancies in controlled substance records are a DEA regulatory matter."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter's medical director leaves suddenly. The facility's controlled substance registration was filed under that specific veterinarian's individual DEA license number. What must happen to the shelter's ability to order and use controlled substances?","o":["Usage may continue under the shelter manager's supervision for 60 days","The registration automatically transfers to the senior veterinary technician","All ordering and usage under that registration must cease immediately at that location","The departing veterinarian can sign a waiver leaving their DEA number with the facility"],"a":2,"e":"An individual DEA registration is tied specifically to that practitioner at their specific registered location. Once they terminate employment, the facility cannot use their registration. There is no grace period and no transfer mechanism. A new registration must be obtained."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A stray dog is admitted to a municipal shelter. The local municipal code mandates a 4-day stray hold period. Legally, what is the status of the animal during this hold?","o":["It is the unconditional legal property of the shelter","It is considered public property with no legal protections","It is legally the property of its unknown owner, held in trust by the shelter","It is an unowned entity with no legal status"],"a":2,"e":"During a statutory hold, the shelter acts as a legal custodian or bailee. Title to the animal remains with the original owner until the hold expires. The shelter cannot permanently alter the animal during this period except in emergencies."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"On day 2 of a mandated 5-day stray hold, a shelter veterinarian notes a stray cat has a fractured, non-painful left hind claw that will eventually need removal but is not systemically compromised. What is the legally sound course of action?","o":["Perform both neuter and claw repair immediately","Neuter the cat now but delay the claw repair until hold expires","Perform the claw repair immediately but delay the neuter until hold expires","Provide appropriate palliative care and delay both elective procedures until the stray hold expires"],"a":3,"e":"Because the animal is still the legal property of an unknown owner, irreversible elective and non-emergency surgical procedures must be delayed until the hold concludes. Non-painful chronic conditions are not emergencies. Palliative care can be provided in the interim."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A stray dog on day 1 of a 3-day hold presents with a compound femoral fracture, active severe hemorrhage, and traumatic shock. The owner is unknown. What legal right does the shelter veterinarian have?","o":["No right; must wait for the hold to expire before any surgical intervention","Legal authority to provide emergency triage, surgical stabilization, or humane euthanasia to alleviate suffering","Must transfer the animal to a private practice to avoid shelter liability","Must obtain a court order before administering pain relief"],"a":1,"e":"Shelter laws universally grant veterinarians emergency authority to provide diagnostic and palliative intervention, stabilizing surgery, or humane euthanasia to resolve severe pain or life-threatening trauma during the stray hold. The standard is whether immediate intervention is necessary to prevent death or acute suffering."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A veterinarian is prosecuted under a state practice act for allowing an assistant to perform surgeries. The shelter manager argues that internal SOPs permitted it. Why does this defense fail?","o":["Internal shelter policies cannot supersede statutory state law or the state practice act","The shelter manager does not hold a 501(c)(3) certification","The assistant was not a board member","The surgery was performed on an open-admission animal"],"a":0,"e":"Statutory state laws and veterinary board rules always supersede internal corporate policies or standard operating guidelines. An SOP that permits something the state practice act prohibits is legally void. The practice act governs regardless of internal documentation."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"What is the primary legal mechanism that transfers ownership of a stray animal from the original owner to an animal shelter?","o":["Payment of an intake fee by the finder","Expiration of the legally mandated stray hold period","Implantation of a new microchip at intake","Administration of a core modified-live vaccine"],"a":1,"e":"The legal expiration of the stray hold period acts as an automatic statutory forfeiture of the original owner's property rights, transferring clean title to the shelter. No other action (microchipping, vaccination, intake fee) changes ownership status."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A state regulatory board visits a shelter to inspect controlled substance records. Which storage arrangement is a mandatory DEA requirement?","o":["A standard unlocked plastic cabinet in the main hallway","A securely locked, substantially constructed cabinet or safe anchored to the building structure","The personal vehicle trunk of the shelter manager","Clear glass containers on open shelving for visual auditing"],"a":1,"e":"DEA regulations specify that controlled substances must be stored in a securely locked, substantially constructed cabinet or safe that is permanently affixed to the premises structure. Personal vehicles and unlocked storage are explicit violations."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter clerk accidentally logs a dog's microchip number incorrectly at intake, preventing the original owner from locating the animal during its stray hold. The animal is subsequently adopted out. This scenario highlights the importance of which administrative factor?","o":["Utilizing restricted grant protocols for intake","Data integrity and accurate record-keeping to protect property rights","Bypassing the state practice act for microchip verification","Maximizing length of stay metrics"],"a":1,"e":"Accurate intake data entry is a property rights protection mechanism. An error in the microchip number prevents the legal owner from exercising their reclaim right during the hold period. This administrative failure creates serious shelter liability for violating an owner's property rights."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Once a non-profit animal shelter successfully achieves federal 501(c)(3) tax-exempt status, which dual state-level entities must it register with next?","o":["The state department of health and the municipal sanitation division","The state agency that licenses shelters and the state's attorney general's office of charitable trusts","The local police department and the state veterinary medical board","The DEA and the state department of labor"],"a":1,"e":"Post-federal-exemption, the shelter must register with the state agency that licenses shelters (typically the Department of Agriculture) and the state attorney general's office of charitable trusts. Both registrations are required; the federal exemption alone does not complete the process."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Which state-level entity is statutorily empowered to license, inspect, and write operational regulations for both private and government animal shelters?","o":["The State Department of Health","The State Department of Agriculture","The State Veterinary Medical Board","The Attorney General's Office of Charitable Trusts"],"a":1,"e":"The state Department of Agriculture holds the statutory mandate to license, inspect, and write regulatory frameworks for both private non-profit and government (municipal) shelters. This applies to both types uniformly, not exclusively to private facilities."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A private shelter operates in a jurisdiction with no established municipal procedures for stray hold management. How does the text characterize its legal position when handling stray animals?","o":["Automatically granted charitable immunity from civil lawsuits","Operates entirely at its own legal risk","Legally designated as a municipal public health department extension","Exempted from state veterinary practice act requirements"],"a":1,"e":"Without an established municipal framework or government contract, a private shelter handling strays has no legal protection from property rights claims by the original owner. The recommendation is to process strays through a government shelter or one with a government contract."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Due to unsettled ownership liability, what explicit recommendation does the text provide for how private shelters should process stray animals?","o":["Process all strays through either a government shelter or a shelter with a government contract","Perform immediate elective surgeries to increase adoption speed","Transfer ownership to a trial adoption home within the first 48 hours","Keep animals in offsite foster homes without notifying local animal control"],"a":0,"e":"The text explicitly recommends routing stray animals through a government shelter or a shelter with a government contract to legally settle the ownership question through the governmental process, shifting liability appropriately."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"An animal control act dictates that a stray animal carrying an explicit marker of ownership (microchip or rabies tag) must be held for a minimum of how many days, and what medical restriction applies?","o":["Held for 3 days; no vaccinations may be given","Held at least 7 days; no elective surgery should be performed","Held for 17 days; must be under direct lighting continuously","Held for 14 days; cannot be handled without a control pole"],"a":1,"e":"An animal with identification markers indicating a known owner must be held a minimum of 7 days to allow the owner adequate time to reclaim. During this extended hold, elective surgery (spay, neuter) must not be performed. Vaccines, deworming, and flea treatment remain permitted."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"During a mandatory stray hold period, which medical treatments are legally permissible for the shelter to perform?","o":["Routine elective neutering, dental prophylaxis, and cosmetic grooming","Vaccinations, deworming, and flea treatments, but not routine surgeries unless life-saving","Complete diagnostic biopsy panels and behavioral temperament evaluation batteries","No medical treatments of any kind may be administered prior to ownership transfer"],"a":1,"e":"The stray hold permits preventive care (vaccines, deworming, flea treatment) and emergency interventions. It prohibits irreversible elective procedures such as spay, neuter, and non-emergency surgery. Supportive and palliative care is permitted throughout."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Some state veterinary practice acts include exemptions that allow unlicensed shelter employees to administer vaccines and microchips. Under what supervisory condition is this typically permitted?","o":["Only if board members are physically present in the room","Under the indirect supervision of a licensed veterinarian, following established protocols","Only if the animal was owner-surrendered, not a stray","Only if no Form 990 is currently on public display"],"a":1,"e":"Practice act exemptions for shelter environments most commonly permit delegated tasks under indirect supervision, where the veterinarian has provided written or oral instructions and is available by phone but need not be on premises."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"How does the text define indirect supervision of a licensed veterinarian regarding shelter staff administering treatments?","o":["The veterinarian must be physically standing next to the staff member inside the facility","The veterinarian does not need to be on the premises, but has given instructions and is available by telephone","The veterinarian reviews records once every 2 months","The veterinarian operates an off-site mobile clinic with no formal relationship to the shelter"],"a":1,"e":"Indirect supervision is defined as: the veterinarian is not on premises but has given written or oral instructions to the staff performing the task, and is immediately available by telephone or other communication. Physical presence is not required."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"For stray animals where ownership remains legally unsettled, what does the text define as the absolute best practice standard for delivery of veterinary medical care?","o":["Administer care exclusively via a certified euthanasia technician","Administer care only under the direct supervision of a licensed veterinarian","Delegate all diagnostic and treatment protocols to trained volunteers","Suspend all medical care until a newspaper advertisement has expired"],"a":1,"e":"Because stray animals are legally owned by an unknown third party during the hold period, direct supervision (the veterinarian physically present) is the best practice standard for care delivery. This is a higher bar than indirect supervision, which may otherwise suffice for owned animals."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Which specific preventive treatment must, according to statutory regulation, be administered exclusively by a licensed veterinarian?","o":["Polyvalent core feline vaccines","Topical flea and tick preventatives","Broad-spectrum anthelmintic dewormers","Rabies vaccination"],"a":3,"e":"Rabies vaccination is a statutory mandate in virtually all jurisdictions that requires a licensed veterinarian to administer and certify the vaccination. It cannot be delegated to unlicensed staff under indirect supervision, even in states with broad shelter practice act exemptions."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A registered off-site veterinarian orders euthanasia solution and has it shipped directly to a shelter facility's address for the shelter's independent use. How is this action categorized under federal drug regulations?","o":["Fully permissible under standard veterinary practice act exemptions","A violation of controlled substance regulations; drugs must be shipped to and stored at the address on the vet's DEA license","Legal as long as the shelter board reviews the shipment budget","Permissible provided the shelter is registered with the office of charitable trusts"],"a":1,"e":"Federal controlled substance regulations require that all drugs be shipped to and stored at the exact address listed on the ordering registrant's DEA license. An off-site vet ordering drugs for a different facility's use violates this requirement regardless of any other authorization."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"If a shelter lacks a registered staff veterinarian but performs euthanasia, how can it legally procure, store, and use controlled substances?","o":["Purchase drugs from farm supply stores under standard exemptions","The DEA may issue permits directly to the facility, subject to specific facility certification and euthanasia technician training requirements","Operate without a permit as long as the local health department inspects annually","Rely on an off-site veterinarian transferring substances via an umbrella liability policy"],"a":1,"e":"The DEA can issue direct facility procurement permits to shelters that lack a staff veterinarian. These permits come with specific facility certification requirements, mandatory euthanasia technician training, and defined permitted methods of euthanasia under the facility's authorization."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"If a regulatory agency launches an investigation into a shelter's controlled substance record-keeping, what immediate enforcement action can it take?","o":["The shelter is automatically converted into a municipal police division","The agency may temporarily suspend the shelter's permits pending investigation and prosecution","The board is required to take over day-to-day kennel cleaning","All animals are instantly transferred to another shelter"],"a":1,"e":"Regulatory agencies have authority to temporarily suspend a shelter's controlled substance permits pending the outcome of an investigation. This means the shelter cannot legally order, use, or store controlled substances during the suspension period, effectively halting euthanasia operations until the matter is resolved."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter's quality control program for controlled substances must maintain strict supervision and oversight over which groups of personnel?","o":["Adopters executing a trial adoption only","Everyone who has access, including board members, veterinarians, and personnel unaccustomed to taking direction from others in the shelter hierarchy","External inspectors from the state department of agriculture only","Patrons who have signed a standard waiver and photo release"],"a":1,"e":"The DEA quality control mandate extends to all personnel with any access to controlled substances, regardless of role, title, or employment status. This explicitly includes board members, veterinarians, and any individuals who may not be accustomed to the shelter's standard hierarchy of authority."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"Who bears the final legal and professional duty for the disposition of all controlled drugs used within a shelter facility?","o":["The Chief Executive Officer","The Board of Directors' Risk Management Committee","The veterinarian","The licensed state department of agriculture inspector"],"a":2,"e":"The veterinarian bears final professional responsibility for controlled substance disposition. This is a non-delegable duty under federal and state law. Even when a facility DEA permit exists, the veterinary professional remains accountable for how all controlled substances are used, stored, and disposed of."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter veterinarian confirms a case of canine rabies in a stray dog. A kennel technician had direct unprotected mucous membrane exposure the prior day. To which authority must this exposure event be reported?","o":["The state veterinary medical board, which manages all animal health reportable conditions","The state or local public health department, which will coordinate PEP assessment and epidemiological investigation","The DEA, since sodium pentobarbital was used to euthanize the animal","The shelter's Board of Directors exclusively, since this is an internal personnel matter"],"a":1,"e":"Rabies-suspect animal cases and any potential human exposure events must be reported to the state or local public health department — not the vet board. The health department coordinates post-exposure prophylaxis (PEP) assessment and manages the epidemiological investigation. The vet board governs licensure, not disease surveillance."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A shelter technician sustains a needle-stick injury while drawing blood from a dog that subsequently tests AGID-positive for Brucella canis. What is the mandatory regulatory action?","o":["File an incident report internally and monitor the technician for 30 days","Report the human exposure to the state or local public health department immediately, since Brucella is a reportable condition with zoonotic transmission potential via needle stick","Contact the DEA since brucellosis reporting is managed through the controlled substance chain","No external reporting required — brucellosis is not a notifiable condition in any US state"],"a":1,"e":"Confirmed Brucella canis with potential human exposure via needle-stick or mucous membrane contact requires immediate public health department notification in most states. Brucellosis is reportable in the US, and needle-stick exposure to infected blood carries documented transmission risk. Internal incident reporting alone is non-compliant."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A county health department contacts a shelter after three adopters independently develop confirmed Salmonella infection linked epidemiologically to animals adopted from that shelter. What is the shelter's regulatory obligation?","o":["Deny involvement until the health department provides written proof","Cooperate fully with the health department investigation; the shelter is the investigated source, not the primary reporter in this scenario","Immediately report the cases directly to the CDC to establish independent documentation","Issue a press release before the health department interviews staff"],"a":1,"e":"For foodborne zoonoses like Salmonella, reporting is triggered by confirmed human cases identified through clinical labs — not by the shelter. The shelter's role shifts from reporter to cooperating source under investigation. Full cooperation with the health department is legally mandatory; obstruction is a criminal offense in most jurisdictions."},{"type":"mcq","domain":"Shelter Management","sub":"Regulatory","q":"A public health department determines that a shelter is the source of a confirmed Salmonella outbreak affecting five adopters. The health department issues an order restricting animal movement from the facility. Can the shelter director refuse this order on the grounds of exceeding Capacity for Care?","o":["Yes — C4C protections in the ASV Standards supersede local health orders","No — public health authority can supersede shelter operational authority when a confirmed zoonotic outbreak is identified; compliance is legally mandatory","Yes — only a court order can restrict animal movement from a licensed shelter","No — but the shelter may delay compliance for up to 72 hours during an internal review"],"a":1,"e":"When a public health authority determines a shelter is a confirmed zoonotic outbreak source, it may legally inspect, restrict animal movement, mandate testing protocols, or temporarily suspend operations. This authority can supersede shelter operational decisions. The shelter director cannot refuse a public health order on operational grounds; non-compliance is a criminal violation, not just a regulatory one."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter transitions an adoptable dog into a temporary foster home while it undergoes heartworm treatment. Legally, who retains ownership of the dog while it resides at the foster parent's home?","o":["The foster parent","The state veterinary medical board","The animal control officer who brought the dog in","The shelter organization"],"a":3,"e":"A foster care agreement is a bailment contract where the shelter delegates physical care but retains full legal ownership and title. The foster parent is a caregiver acting on behalf of the shelter, not the owner. The shelter retains authority over major decisions including euthanasia."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter adopts out a dog with a disclosed history of mild separation anxiety. Three weeks later, the adopter sues because the dog destroyed property. Why does the shelter have strong legal protection?","o":["Shelters are completely immune to all civil lawsuits by federal law","The shelter fully disclosed the known behavioral history prior to adoption","Adopters waive all constitutional rights when signing an adoption contract","Separation anxiety is not recognized as a behavioral condition under property law"],"a":1,"e":"Full legal disclosure of known behavioral or medical history before adoption shifts risk awareness to the adopter and protects the shelter from claims of fraudulent concealment. The adopter was informed and chose to proceed."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter veterinarian examines a dog with symmetric hair loss, cigarette burns on the dorsum, and multiple fractured ribs in various healing stages. What is the veterinarian's legal and ethical obligation?","o":["Maintain confidentiality and treat without documenting the history","Report suspected animal abuse to law enforcement and maintain strict documentation","Return the dog to the owner immediately to avoid civil liability","Erase the medical record to prevent public record requests"],"a":1,"e":"Veterinarians have a legal and ethical obligation to report clear indicators of animal cruelty to law enforcement and to document all findings meticulously. Symmetric burns, healing rib fractures, and history inconsistencies are classic indicators of deliberate harm."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"During a large-scale cruelty seizure involving 80 dogs, what administrative protocol must be meticulously maintained to ensure findings are admissible in court?","o":["The Capacity for Care index","Public relations non-disclosure agreements","The chain of custody for all physical evidence and animals","The income-qualification verification roster"],"a":2,"e":"Chain of custody documentation tracks every individual who handles a cruelty case animal or piece of evidence, preventing legal challenges regarding tampering. Without an intact chain of custody, forensic findings may be inadmissible regardless of their clinical strength."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter veterinarian completes a forensic exam on a deceased cat suspected of intentional poisoning. Where must the chain of custody documentation be logged?","o":["In the general public relations newsletter","In a secure, unalterable medical-legal record attached to the case file","On a whiteboard in the breakroom for staff transparency","In the municipal budget proposal file"],"a":1,"e":"Forensic data and chain of custody records must be kept in secure, legally protected case files to maintain their integrity for potential trial use. Informal or alterable documentation (whiteboards, newsletters) compromises the legal chain and renders findings inadmissible."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter adopts out a dog known by staff to have severely aggressive tendencies toward children without disclosing this history. The dog bites a child. What legal vulnerability does the shelter face?","o":["Absolute statutory immunity","Liability for negligence and failure to disclose known dangerous traits","No liability because the dog is legally property","A violation of the federal Controlled Substances Act"],"a":1,"e":"Failing to disclose a documented, severe behavioral hazard exposes the shelter to serious civil tort liability for negligence. The shelter's prior knowledge (scienter) is key: they knew the animal was dangerous and placed it without warning the new family."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Why is the ASV Guidelines for Standards of Care in Animal Shelters highly relevant to legal liability cases?","o":["It is a federal statute signed into law by Congress","It establishes the industry-accepted professional standard of care used by courts to evaluate negligence","It automatically exempts shelters from local municipal codes","It defines criminal penalties for DEA logging violations"],"a":1,"e":"Expert industry guidelines like ASV Standards are used by courts to define what a reasonable, prudent shelter professional would do under similar circumstances. They are not federal law but carry significant legal weight as the benchmark against which shelter conduct is measured in negligence cases."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A private shelter veterinarian is asked by law enforcement to hold an animal indefinitely as evidence during a prolonged domestic violence trial. Which chapter of Shelter Medicine for Veterinarians and Staff addresses the legalities of holding protective custody animals?","o":["Chapter 2: Population Statistics","Chapter 5: Administrative Issues","Chapter 6: Legal Issues for Shelters","Chapter 12: Feline Retroviruses"],"a":2,"e":"Chapter 6 is dedicated to structural legal issues for shelters, including custody hold dynamics, the liability of holding evidence animals, and risk management parameters for shelters navigating law enforcement requests."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Some states allow shelters to adopt out animals with known infectious diseases. What legal condition must be fulfilled to execute these transfers lawfully?","o":["Invoke a state-level charitable immunity clause","Execute the transfer under full disclosure to the adopter","Process the animal through an off-site mobile clinic","Alter the shelter's primary mission statement on its Form 990"],"a":1,"e":"Even where adoption-out of infectious disease-carrying animals is permitted by state law, the transfer must be executed under full disclosure. The adopter must be informed of the health status before they take custody. Disclosure is the legal condition that makes the transfer permissible."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"If a newly adopted animal requires a medical evaluation or treatment under a shelter's health guarantee, who is legally authorized to perform that care?","o":["Any certified euthanasia technician working under indirect supervision","A licensed veterinarian","The shelter's CEO following board policies","An experienced volunteer using farm supply medications"],"a":1,"e":"Health guarantee evaluations and treatments must be performed by a licensed veterinarian. This requirement protects both the adopter (ensuring quality care) and the shelter (ensuring the evaluation meets professional standards that can be legally defended)."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Why are trial adoptions characterized as 'a shelter lawyer's nightmare' in the text?","o":["The IRS automatically revokes 501(c)(3) status if an animal enters a trial home","The shelter retains legal ownership (and liability) but has no custody or control of the animal","Homeowner's insurance universally refuses to cover shelter-owned property","State departments of agriculture require daily inspections of all trial homes"],"a":1,"e":"Trial adoptions create a liability mismatch: the shelter remains the legal owner (with all associated liability) while having no ability to monitor or control the animal's environment. If an incident occurs, the shelter may be named in both civil and criminal proceedings despite having no physical custody."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"If a public safety incident occurs during a trial adoption and law enforcement takes action, who may potentially be charged?","o":["The shelter's board of directors exclusively","Both the entity with physical control (trial home) and the actual legal owner (the shelter)","Only the off-site veterinarian who certified the animal's baseline health","The state department of agriculture inspector who licensed the facility"],"a":1,"e":"Because the trial home has physical control and the shelter has legal ownership, both parties can be implicated when an incident occurs. Physical control = operational responsibility; legal ownership = liability for the property's behavior. Both exist simultaneously in a trial adoption."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"What specific insurance-related mandate should a shelter require from a dog trial adopter before allowing physical custody transfer?","o":["Confirmation that homeowner's insurance has been notified and the adopter agrees to indemnify the shelter","A copy of their personal veterinary malpractice insurance","Proof of worker's compensation coverage for the trial period","An umbrella liability policy covering off-site DEA controlled substance storage"],"a":0,"e":"The shelter should require confirmation that the trial adopter's homeowner's insurance carrier has been informed of the new animal, and that the trial adopter agrees to indemnify the shelter against claims arising from incidents during the trial period."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"If a resident pet in a trial adoption home contracts an infectious disease from the incoming trial shelter animal, how should financial liability be allocated?","o":["The shelter covers 100% of medical costs under its veterinary malpractice policy","This is a matter of the trial home's own risk, and should be explicitly stated in the written agreement","The shelter's board must vote to adjust its long-range fiscal boundaries","Expenses are billed to the state attorney general's office"],"a":1,"e":"The trial home assumes the risk of disease transmission to resident animals when they accept a trial animal into their home. This risk allocation must be stated explicitly in the written trial adoption agreement. The shelter cannot be held liable for an event it could not control in an environment it cannot monitor."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Depending on state jurisdiction, what structural and legal requirements may apply to a shelter's network of foster homes?","o":["They must be organized as independent 501(c)(3) entities","They may have to be individually licensed as shelter affiliates, subject to inspections, and follow strict animal density limits","They must be operated under the direct auspices of the local sanitation department","They must maintain a full-time certified euthanasia technician on premises"],"a":1,"e":"State licensing laws may require that individual foster homes be licensed as affiliates of the shelter, be subject to periodic inspections, and comply with strict limits on the number of shelter animals housed simultaneously. The shelter's liability for animals in these homes makes oversight a legal necessity."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"How frequently are shelter personnel required to maintain contact with individual foster homes, and what additional type of contact is mandated?","o":["Bi-monthly contact during fight kit inventories","Regular (weekly) contact with each foster home, plus periodic in-person visits","Contact only if a bite incident occurs","Annual contact via the digital display of the Form 990"],"a":1,"e":"The text mandates weekly contact with each foster home AND periodic in-person visits. This oversight requirement reflects the shelter's continued legal ownership of the animals and its obligation to monitor their welfare even when they are off-site."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter operates a mobile clinic unit for community outreach. What insurance provisions must the shelter maintain to protect its personnel?","o":["A standard D&O policy requiring staff to use personal insurance for transit accidents","Adequate vehicle insurance so staff do not have to use personal insurance in the event of an accident","A specialized DEA permit covering off-site controlled substance shipping in vehicles","A charitable immunity waiver signed by all municipal health department employees"],"a":1,"e":"Mobile clinic operations require adequate vehicle insurance so that staff members involved in transit accidents are covered by the shelter's policy, not their personal auto insurance. Requiring staff to use personal insurance for shelter business activity exposes them to personal liability."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"According to the text, which type of harm represents a severe, un-insurable risk that can permanently compromise a shelter's operational viability?","o":["Purchasing a general liability policy that overlaps with a worker's compensation policy","Harm to a shelter's reputation from an animal accident, disease outbreak, or controlled substance mishap","Registering the non-profit's bylaws with the state attorney general's office","Requiring patrons to complete a photo release form at public events"],"a":1,"e":"Reputational harm is characterized as un-insurable and potentially catastrophic. Unlike property damage or medical malpractice, reputation cannot be restored by an insurance payment. A disease outbreak at an adoption event, a fatal dog bite, or a controlled substance scandal can permanently erode public trust and donor support in ways no financial instrument can repair."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Under the One Bite Rule, how is a shelter's liability determined if it adopts out a dog with a documented bite history to an adopter who was not informed of the history, and the dog bites again?","o":["The shelter is completely exempted from civil liability by charitable immunity","The shelter is held liable because it had knowledge of the animal's propensity to bite (scienter) prior to transfer","The liability transfers entirely to the state veterinary board at the moment of adoption","The shelter is liable only if it performed a pre-adoption temperament test"],"a":1,"e":"Under the One Bite Rule, any owner (including a pre-adoption shelter) who has documented knowledge of an animal's propensity to bite is held liable for subsequent incidents. The shelter's knowledge of the bite history constitutes scienter. Failure to disclose that history before transfer creates direct negligence liability."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"What proactive documentation strategy provides shelters the strongest legal protection against negligence lawsuits related to adopted animal behavior?","o":["Rely on verbal agreements and destroy records to protect client privacy","Observe, document, and fully disclose all known health and behavioral information before transfer","Perform routine elective surgeries during the stray hold period to improve temperament","Use a signed waiver and release form as an absolute, unbreachable shield against all liability"],"a":1,"e":"The documentation-disclosure pathway is the foundation of adoption liability defense. Observation and documentation demonstrate the shelter exercised professional diligence. Full disclosure shifts risk awareness to the adopter. Signed documentation proves disclosure occurred. Together, these constitute a legally defensible adoption process."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter conducts behavioral assessments on all dogs but records only a 'pass' or 'fail' label in each animal's file. Six months after adoption, an adopter sues following a bite incident. Why does this documentation inadequately support the shelter's defense?","o":["Standardized behavioral assessment tools require a federal certification number in the record","'Pass/fail' labels without specific behavioral observations cannot demonstrate what the shelter actually knew about the animal's behavior — specific findings are required to establish a defensible record","Behavioral assessment records are sealed under the Freedom of Information Act","The assessment is only defensible if it was performed within 24 hours of adoption"],"a":1,"e":"A 'pass/fail' label is a conclusion without evidence. If challenged in court, the shelter cannot show what specific behaviors were observed, whether the assessor was trained, or what the animal actually did during evaluation. Specific dated observations — documented by a trained assessor — are the defensible standard. Labels alone are insufficient."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"Which element of behavioral assessment documentation most directly establishes what the shelter 'knew' about an animal's behavior at the time of adoption, for purposes of negligence liability?","o":["The number of behavioral assessments performed, regardless of their content","Contemporaneous, specific behavioral observations documented by a trained evaluator, with date and assessor identity","The number of days the animal was in care before being assessed","The breed classification entered in the Phase A intake form"],"a":1,"e":"Negligence liability turns on what the shelter knew and when. Contemporaneous documentation — specific behavioral descriptions, recorded at the time of the assessment, by a named trained evaluator — establishes the knowledge timeline. Without this, the shelter cannot demonstrate diligence regardless of how many assessments were performed."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter completes verbal behavioral counseling for an adopter about a dog's known leash reactivity but does not obtain a signed acknowledgment. Three months later the adopter sues claiming they were never warned. How does the absence of a signed disclosure affect the shelter's position?","o":["It has no effect — verbal disclosure is legally equivalent to written disclosure","The shelter's position is weakened; undocumented verbal disclosure has the same legal weight as no disclosure — the adopter's denial cannot be rebutted","The shelter is automatically protected because the behavioral evaluation was conducted","The lack of a signature shifts liability to the treating veterinarian"],"a":1,"e":"A disclosure that cannot be proven provides no legal protection. Without a signed acknowledgment, the shelter cannot rebut the adopter's claim that no warning was given. Documentation of the disclosure — not just the assessment — is what makes the legal defense complete. Both the finding AND the fact of disclosure must be documented."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A volunteer sustains a severe bite while handling an animal at a shelter. The shelter has standard workers' compensation coverage for its paid staff. Does this cover the volunteer's medical expenses?","o":["Yes — workers' compensation automatically extends to all individuals working on premises","No — volunteers are generally excluded from workers' compensation coverage; the shelter should carry separate volunteer accident insurance","Yes — if the volunteer had been active for more than 90 days, they qualify as a de facto employee","No — bite injuries are categorically excluded from all workers' compensation policies"],"a":1,"e":"Workers' compensation is a benefit for paid employees; volunteers are typically excluded. A shelter without separate volunteer accident insurance or general liability coverage that extends to volunteer injuries leaves injured volunteers with potential costs the shelter cannot cover through workers' comp. Separate volunteer accident insurance is specifically recommended for shelters with active volunteer programs."},{"type":"mcq","domain":"Shelter Management","sub":"Liability","q":"A shelter requires all volunteers to sign a liability waiver before beginning work. A volunteer is subsequently injured during an activity the shelter knew carried unreasonable risk — handling a dog with an undisclosed severe bite history without trained supervision. Is the waiver fully protective?","o":["Yes — a signed waiver is an absolute release from all shelter liability regardless of circumstances","No — courts may void waivers when injuries result from gross negligence, particularly when the shelter had knowledge of the specific hazard and failed to manage it","Yes — as long as the waiver was signed within 30 days of the incident","No — waivers are invalid for volunteers because they are not employees under labor law"],"a":1,"e":"Liability waivers reduce but do not eliminate shelter exposure. Courts routinely void waivers when gross negligence is demonstrated — specifically, when the shelter had knowledge of a specific, unreasonable danger and failed to mitigate it. A shelter that assigns an untrained volunteer to handle a known dangerous animal cannot rely on a waiver to avoid liability for the resulting injury."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A municipal animal control facility operates under local ordinances that require it to accept every stray, abandoned, or seized animal brought to its doors within county lines. Which term correctly defines this operational mandate?","o":["Limited-admission shelter","Managed-intake facility","Open-admission shelter","Semiautonomous sanctuary"],"a":2,"e":"Open-admission facilities are structurally and legally bound by local ordinances to accept every animal from their designated jurisdiction. This is a legal mandate, not a policy choice. Private non-profit shelters have the flexibility to be limited-admission."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A private 501(c)(3) shelter establishes strict criteria for owner surrenders, capping intake based on current kennel availability. What primary management concept justifies this limited-admission framework?","o":["Civil service protection rules","Public purchasing policies","Maintaining Capacity for Care (C4C)","Municipal contract optimization"],"a":2,"e":"Limited-admission shelters control their intake to match population size with available staff, space, and medical resources. Capacity for Care is the structural justification: a shelter that cannot meet the welfare needs of its animals should not admit more animals than it can humanely house."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter veterinarian requests funds to overhaul a quarantine ward's air-handling system. The executive director denies the request, stating the board has restricted all foundation grant payouts to a public TNR program. Which statement correctly describes the board's role?","o":["The board is overstepping by managing day-to-day medical logistics","The board is executing its legal role of fiscal oversight and strategic donor-intent compliance","The board has authority to change donor intent without notifying the foundation","The board must defer all financial allocation choices to veterinary staff"],"a":1,"e":"Boards focus on governance and fiscal stewardship, including ensuring restricted funds are used exactly as designated by the donor. Denying a medical resource request because restricted funds are committed elsewhere is the board executing its fiduciary duty correctly, not overstepping into operations."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter medicine department experiences severe friction between care technicians and leadership due to repetitive tasks, high euthanasia rates, and emotional exhaustion. What organizational hazard must management address?","o":["Civil service bureaucracy","High decision latitude","Compassion fatigue","Public relations restrictions"],"a":2,"e":"Long-term exposure to animal suffering, high-stakes decisions, and euthanasia performance directly drives compassion fatigue in shelter environments. It is a predictable organizational hazard that must be addressed proactively through workload management, support systems, and mental health resources."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A regional veterinary medical association expresses concern that a shelter's low-cost public wellness clinic is competing unfairly with local private practices. To balance mission with community relations, which operational strategy is most commonly evaluated?","o":["Broadening public wellness services to all zip codes regardless of income","Establishing income-qualified restrictions or means-testing for public-facing clinics","Mandating that all private practitioners volunteer weekly at the shelter","Stopping all shelter medical procedures including care for adoptable animals"],"a":1,"e":"Restricting subsidized public services to income-qualified clients fulfills the shelter's humanitarian mission while minimizing competitive friction with private clinics. By limiting eligibility to clients who cannot otherwise afford care, the shelter serves the population private practices cannot economically serve."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter operates an intake system where denominators are pulled from intake logs and numerators from medical diagnostics. Which reference text is explicitly dedicated to using these statistical metrics to optimize population flow?","o":["Veterinary Forensics: Animal Cruelty Investigations","Every Nose Counts: Using Metrics in Animal Shelters","Infectious Disease Management in Animal Shelters","High-Quality, High-Volume Spay and Neuter"],"a":1,"e":"Every Nose Counts is the primary operational text dedicated to using statistical metrics (denominators from intake data, numerators from medical data) to optimize shelter population flow and operational resource deployment. It translates data collection into actionable management decisions."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"Which key structural limitation distinguishes municipal animal control agencies from private non-profit shelters?","o":["Municipal agencies cannot utilize controlled substances","Municipal agencies are heavily constrained by civil service rules and public purchasing mandates","Municipal agencies are completely exempt from state veterinary practice acts","Municipal agencies are funded entirely by private foundation grants"],"a":1,"e":"Publicly funded municipal agencies must comply with civil service labor regulations governing hiring, firing, and compensation, as well as competitive public procurement laws. These constraints significantly limit operational flexibility compared to private non-profits."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A private shelter board wants to ensure its organization maintains federal tax-exempt status. Under which section of the Internal Revenue Code must it comply?","o":["Section 401(k)","Section 501(c)(3)","Section 506(c)","Section 1099"],"a":1,"e":"Section 501(c)(3) is the specific IRS tax classification that grants federal tax exemption to charitable non-profit entities. Organizations must operate exclusively for their exempt purpose, avoid private inurement, and limit lobbying activities to maintain this status."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A non-profit shelter receives a $50,000 grant restricted for construction of a new outdoor canine play yard. The shelter faces an immediate shortfall for utility bills. Can the executive director use this grant for utilities?","o":["Yes, if the utility bill threatens facility operations","No, using restricted funds for general operations violates non-profit law and donor intent","Yes, because utilities indirectly benefit the canine play yard","Yes, if the board of directors signs an internal operational waiver"],"a":1,"e":"Diverting restricted donor funds to unrelated operational needs violates trust law and non-profit fiduciary obligations, and can result in revocation of 501(c)(3) status. There is no emergency exception and no internal governance mechanism (including board vote) that can override legally restricted grant terms."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter manager wants to optimize kennel staff scheduling to ensure every animal is cleaned and fed within available human resource constraints. Which core management concept maps directly to this administrative goal?","o":["Veterinary Practice Act exemptions","Restricted funding optimization","Resource allocation and staff utilization","Forensic chain of custody"],"a":2,"e":"Aligning personnel hours with operational care mandates is the definition of resource allocation and workforce asset optimization. Scheduling staff to meet the animal care requirements within available labor capacity is a direct application of resource allocation principles."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"An open-admission shelter faces severe overcrowding during the summer, driving disease rates up. From an administrative perspective, this situation represents a failure to balance population size with which operational metric?","o":["The restricted grant ratio","The state practice act exemption limit","Capacity for Care (C4C)","The forensic chain index"],"a":2,"e":"Operating a facility beyond its physical and human infrastructure capacity breaks biosecurity, drives disease transmission, and compromises animal welfare by definition. This is a Capacity for Care failure: the shelter has more animals than it can humanely house and care for with available resources."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"Once a non-profit animal shelter achieves federal 501(c)(3) tax-exempt status, which dual state-level entities must it also register with?","o":["The state department of health and the municipal sanitation division","The state agency that licenses shelters and the state's attorney general's office of charitable trusts","The local police department and the state veterinary medical board","The DEA and the state department of labor"],"a":1,"e":"Post-federal-exemption, the non-profit must register with the state agency that licenses animal shelters (typically the State Department of Agriculture) AND the state attorney general's office of charitable trusts. Both registrations are required. The federal exemption alone does not complete the regulatory pathway."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"Which state-level entity is statutorily empowered to license, inspect, and write operational regulations for BOTH private and government animal shelters?","o":["The State Department of Health","The State Department of Agriculture","The State Veterinary Medical Board","The Attorney General's Office of Charitable Trusts"],"a":1,"e":"The State Department of Agriculture holds the statutory mandate to license, inspect, and write regulatory frameworks for both private non-profit AND government (municipal) shelters. This authority applies uniformly to both types of shelters, not exclusively to private facilities."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A non-profit shelter's board of directors is establishing its operational boundaries. Which of the following correctly reflects a limitation on the board's direct duties?","o":["The board must personally manage day-to-day shelter operations","The board is legally required to hire all shelter staff members including individual caretakers","The board does not need to engage in day-to-day operations, hire staff other than the CEO, or make detailed programmatic decisions without staff consultation","The board must personally execute all daily medical treatments and intake diagnostics"],"a":2,"e":"The board governs; it does not manage. The explicit limitations on board duties include: not engaging in day-to-day operations, not hiring any staff other than the CEO, and not making detailed programmatic decisions without staff input. These boundaries prevent board members from undermining staff authority and management effectiveness."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A non-profit shelter's IRS Form 990 is requested by a member of the public at the front desk. What is the legally correct response?","o":["Keep it sealed and only reveal it under a court subpoena","Submit it exclusively to the State Department of Agriculture every 2 months","Provide it immediately, as it must by law be on display and available to the public at all times","Share it only with board members during long-range planning sessions"],"a":2,"e":"IRS regulations require that a non-profit organization's Form 990 be on public display and available to the public at all times. This is a legal requirement, not a discretionary transparency policy. The shelter must provide a copy or direct the individual to where the public display copy is maintained."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter receives a restricted grant specifically earmarked for a pediatric feline spay-neuter program. The following month, a canine parvovirus outbreak exhausts the shelter's disinfection supply budget. How should the restricted grant funds be handled?","o":["Temporarily reallocate the grant under the emergency Capacity for Care clause","Keep the funds allocated to the pediatric feline program and seek separate emergency funding for the parvo outbreak","The veterinarian can autonomously reallocate up to 25% of any restricted grant for disease control","The board can permanently redirect the grant if animal welfare is acutely compromised"],"a":1,"e":"Restricted grants are legally binding agreements. No emergency exception exists. The shelter must honor the grant's designated purpose and pursue separate funding for the outbreak response. Internal authority figures (vet, board, ED) cannot unilaterally redirect restricted funds regardless of the urgency."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter plans to replace its entire HVAC system at a cost of $60,000. The shelter manager wants to record this in the annual operating budget as an operational expense. Why is this classification incorrect?","o":["HVAC systems are a variable cost and should scale with intake volume","HVAC replacement is a capital expenditure — a large, infrequent purchase that extends beyond one budget cycle and must be classified separately from operating costs","Utility-related expenses are always restricted grant items and cannot appear in the operating budget","HVAC expenses are classified as in-kind donations if a local contractor offers a discount"],"a":1,"e":"A $60,000 HVAC replacement is a capital expenditure — a substantial, one-time investment in a long-lived asset. Classifying it as an operating expense distorts the operating budget, misrepresents the shelter's true ongoing operating costs, and may violate grant restrictions that separate capital and operating funds. Capital expenditures typically require separate board approval above a defined threshold."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A local veterinarian donates 20 hours of spay surgeries to the shelter per month. What financial management obligation does this in-kind donation create?","o":["None — only cash donations require documentation","The shelter must document the fair market value of the donated surgical time for IRS Form 990 reporting and grant matching purposes","The donation is classified as a restricted grant and cannot be used for any purpose other than spay surgeries","The donated labor must be recorded as a capital expenditure since it involves specialized equipment"],"a":1,"e":"In-kind donations of skilled professional services (veterinary surgery, legal counsel, accounting) have real fair market value. This value must be documented for IRS Form 990 disclosure and may qualify for grant-matching credit. Failing to document significant in-kind donations is a non-profit compliance gap."},{"type":"mcq","domain":"Shelter Management","sub":"Resource Allocation","q":"A shelter calculates that its total operational costs last year were $450,000 and it achieved 900 live outcomes. What is the cost-per-live-outcome (CPLO), and what does a 20% increase in CPLO the following year (without a corresponding increase in outcomes) indicate?","o":["$500/outcome; increasing CPLO without increasing outcomes suggests the program is scaling well","$500/outcome; rising CPLO without rising outcome volume suggests cost inflation without proportional impact — an efficiency concern worth investigating","$450/outcome; this level triggers automatic DEA permit suspension","$45/outcome; this is calculated by dividing operational costs by staff headcount"],"a":1,"e":"CPLO = $450,000 / 900 = $500 per live outcome. If the following year's CPLO rises to $600 without a proportional increase in live outcomes, operational costs have grown faster than impact — a signal to investigate which cost categories are inflating relative to output. Rising CPLO alone is not a reason to cut care quality, but it warrants operational efficiency review."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"According to the ASV-based notes, an animal's emotional and behavioural needs are determined by which combination of factors?","o":["Environment, species, genetics, personality, prior socialisation, and life experiences","Body condition score, caloric intake, and kennel temperature","Length of stay, adoption demand, and population manager presence","Baseline cortisol, plasma volume, and leukocyte counts"],"a":0,"e":"The six determinants are environment, species, genetics, personality, prior socialisation, and life experiences, treated as an overlapping, non-hierarchical set."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which statement best captures the relationship between physical and emotional health?","o":["Behavioural health is independent of physical disease","Emotional and behavioural health affect physical health, and vice versa","Physical health dictates welfare and renders genetics irrelevant","Emotional factors only matter once disease is resolved"],"a":1,"e":"Physical and emotional health are bidirectional: each can degrade or support the other."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"QOL is described as an array of affective states. How are these broadly classified?","o":["Active-arousal and passive-avoidance states","Fight-or-flight vectors and somatosensory inputs","Comfort-discomfort and pleasure states","Socially desirable tendencies and predatory drives"],"a":2,"e":"Affective states are broadly classified along comfort-discomfort and pleasure axes."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What general principle determines whether an animal has a higher quality of life?","o":["Eliminating all species-typical behaviours in the enclosure","A static baseline cortisol for 17 consecutive days","Relying only on passive human-presence scans","The greater the pleasant and the lesser the unpleasant effects, the higher the QOL"],"a":3,"e":"More pleasant and fewer unpleasant affective states mean higher QOL; it is a general principle, not a precise formula."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Why does the text describe welfare factors as very individual?","o":["Because animals of one breed always respond identically to stress","Because an environment that gives one animal pleasure may cause another fear or discomfort","Because behaviour can only be measured by qualitative analysis","Because personality always overrides species traits"],"a":1,"e":"Needs are individual, so the same environment can be pleasant for one animal and distressing for another."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What are the three pillars of staff competency required of all relevant personnel?","o":["Read body language, describe behaviour objectively, and interpret and respond to it","Squeeze-cage mechanics, control-pole maintenance, and fight-kit inventory","Psychopharmacological dosing, body condition scoring, and intake scheduling","Open-ended questioning, active listening, and social-desirability management"],"a":0,"e":"Personnel must read body language, describe it objectively, and interpret and respond to modify care or handling."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which is an objective behavioural description rather than an anthropomorphic label?","o":["The dog is acting spiteful because it missed its walk","The cat is furious and planning to attack the next handler","The dog is cowering in the back corner with its tail tucked below the pelvic midline","The kitten is feeling sad about its environment"],"a":2,"e":"Objective notes describe observable posture and action; spiteful, furious, and sad are anthropomorphic interpretations."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Why must all relevant personnel, not only behaviour specialists, be trained to interpret and respond to behaviour?","o":["So daily routines can be disrupted randomly without stress","To let care volunteers administer behaviour medications","To remove the need for objective behaviour records","So that every interaction any staff member has with an animal protects its QOL"],"a":3,"e":"Welfare is protected only if every interaction, by any staff member, is informed by accurate reading and response."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A shelter dog has undiagnosed chronic pain. How does this physical state affect its behavioural or emotional health?","o":["No effect, since emotional health depends only on enrichment","It degrades its affective state, because physical and emotional health are interconnected","It freezes its personality until a training hierarchy is applied","It improves pleasure states by prompting more human contact"],"a":1,"e":"Through the bidirectional link, chronic pain degrades affective state and overall welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What operational standard does the text set for QOL, despite QOL being hard to define?","o":["Every attempt must be made to sustain QOL for shelter animals","QOL is optional and subordinate to medical treatment","QOL monitoring stops after a two-week stay","QOL is assessed only by outside consultants"],"a":0,"e":"Sustaining QOL is a non-negotiable mandate even though QOL, like happiness, is hard to define universally."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which set correctly lists the Five Freedoms?","o":["Nutrition, environment, health, opportunity, and mental state","The freedoms to hunt, roam, breed, socialise, and rest","Freedom from hunger and thirst; from discomfort; from pain, injury, or disease; to express normal behaviour; and from fear and distress","Unacceptable, must, should, ideal, and exemplary"],"a":2,"e":"The Five Freedoms are from hunger and thirst, from discomfort, from pain, injury, or disease, to express normal behaviour, and from fear and distress."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What is the main limitation of the Five Freedoms that prompted a newer model?","o":["They apply only to dogs","They require expensive equipment to measure","They are too numerous to remember","They focus on avoiding negative experiences, so positive welfare is also needed for a life worth living"],"a":3,"e":"The Five Freedoms emphasise avoiding harm; promoting positive experiences is also essential, which the Five Domains addresses."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What are the five domains in the Five Domains model?","o":["Nutrition, Environment, Health, Opportunity, and Mental State","Hunger, Hydration, Hygiene, Happiness, and Mobility","Genetics, Species, Personality, Socialisation, and Experience","Intake, Housing, Medical, Behaviour, and Outcome"],"a":0,"e":"The domains are Nutrition, Environment, Health, Opportunity (agency), and Mental State."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How are the domains structured in the Five Domains model?","o":["All five domains are independent and equally weighted","The four functional domains (nutrition, environment, health, opportunity) inform the mental-state domain, which determines overall welfare","Mental state is irrelevant once the physical domains are met","Welfare is the average of the first four domains only"],"a":1,"e":"The functional domains feed into mental state, and mental state determines the overall welfare status."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What two things does the Five Domains model add beyond the Five Freedoms?","o":["A legal mandate and a fixed scoring rubric","A species list and an age cutoff","A spectrum per domain (including positive experiences), and the insight that positive welfare can exist with an unmet need while negative welfare can arise from a single unmet need","A requirement for daily cortisol sampling"],"a":2,"e":"It adds a positive-to-negative spectrum per domain and shows welfare can tip either way from a single domain."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which scenario is the ASV example of net-positive welfare despite an unmet need?","o":["A dog left in a barren kennel with food only","A cat denied any veterinary care","A group of cats in a chaotic, unpredictable ward","A stray cat on cage rest with a healing pelvic fracture that is appropriately treated and housed in an enriched foster home"],"a":3,"e":"Despite restricted agency and pain, appropriate treatment and an enriched foster can yield net-positive welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which scenario is the ASV example of net-negative welfare from a single unmet need?","o":["A well-fed, physically healthy dog confined long-term to a kennel with restricted agency","A cat with daily enrichment and choice","A dog in a well-run playgroup","A kitten socialised with its littermates"],"a":0,"e":"Restricted agency alone, in long-term kennelling, can produce profound distress and net-negative welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What does the Opportunity domain primarily capture?","o":["Caloric intake and hydration","Disinfectant choice and contact times","Choice of environment and interaction, behavioural variety such as play and foraging, and novelty, reflecting agency","Staff scheduling and rounds order"],"a":2,"e":"Opportunity is about agency: choice, behavioural variety, and novelty."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What is the ASV ranking format for its key statements?","o":["Low, medium, high, critical","Unacceptable, must, should, ideal","Optional, preferred, mandatory, legal","Bronze, silver, gold, platinum"],"a":1,"e":"ASV statements are ranked unacceptable, must, should, and ideal."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How do the ASV terms must and should differ?","o":["Must applies to cats and should to dogs","They are interchangeable","Must means optional; should means required by law","Must is necessary for humane care; should is strongly recommended and expected in most circumstances"],"a":3,"e":"Must is required for humane care; should is strongly recommended with expected compliance in most situations."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How does a behaviour assessment differ from a behaviour evaluation?","o":["Assessment is ongoing observation and interpretation across the stay; evaluation is a structured test battery of subtests (for example SAFER)","They are the same process","Assessment is a one-time test; evaluation is continuous","Evaluation is done only by volunteers; assessment only by veterinarians"],"a":0,"e":"Assessment is the ongoing, interpretive process; evaluation is a formal, structured subtest battery."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"When is behavioural information about a newly admitted animal most reliable?","o":["Within the first hour of arrival","Only during sleep","After acute intake stress has settled, rather than in the first 24 to 48 hours","Never, as shelter behaviour is meaningless"],"a":2,"e":"Acute intake stress distorts behaviour, so early testing in the first 24 to 48 hours is unreliable."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How is Capacity for Care defined?","o":["The maximum number of cages a building can physically hold","The total resources needed to promote positive welfare, as described by the Five Domains, for all animals in or coming into care","The number of staff on the daily rounds team","The square footage of the adoption floor"],"a":1,"e":"Capacity for Care is resource-based and welfare-based, defined through the Five Domains for the whole population."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What does the HHHHHMM (Villalobos Pawspice) scale assess?","o":["Intake throughput and length of stay","Disinfectant efficacy across surfaces","Genetic predisposition to disease","End-of-life quality of life, scoring Hurt, Hunger, Hydration, Hygiene, Happiness, Mobility, and More good days than bad"],"a":3,"e":"HHHHHMM is an end-of-life QOL scale scoring those seven items, each out of 10."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"An animal shows a prolonged, severe negative emotional state that cannot be mitigated. What does the mandate to sustain QOL imply?","o":["The care or outcome pathway must be re-evaluated, and euthanasia may be appropriate to prevent unresolvable suffering","The shelter is meeting guidelines simply by continuing to house the animal","Staff should stop recording objective behaviour to reduce distress","The animal should be co-housed with an aggressive companion"],"a":0,"e":"Unresolvable, profound compromise of QOL requires reconsidering the outcome pathway, including euthanasia to prevent suffering."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which QOL tool is the end-of-life scale, and how does it relate to McMillan's work?","o":["McMillan is the end-of-life scale; HHHHHMM is unrelated","Both are identical end-of-life scales","HHHHHMM (Villalobos) is the end-of-life scale, distinct from McMillan's broader mental-wellness framework","Neither is used for animals"],"a":2,"e":"HHHHHMM (Villalobos) targets end-of-life QOL; McMillan's framework is a broader mental-wellness model."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Why must shelter staff record behaviour objectively rather than with anthropomorphic labels?","o":["To make the records longer","So that observations can be interpreted and acted on consistently by anyone reading the record","Because subjective labels are faster to write","To avoid training staff at all"],"a":1,"e":"Objective, factual descriptions preserve data integrity so any team member can interpret and respond consistently."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Why is the absence of physical disease insufficient to judge an animal's welfare?","o":["Because disease has no effect on behaviour","Because welfare is broad, complex, and heavily comprised of emotional and affective factors","Because the Five Domains exclude physical health","Because emotional factors are purely genetic"],"a":2,"e":"Welfare includes affective experience; a disease-free animal can still have poor welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"In which additional context is the Five Domains model now applied?","o":["As a framework for assessment in animal cruelty and neglect legal cases","As a vaccine scheduling tool","As a disinfectant selection chart","As a transport route planner"],"a":0,"e":"The Five Domains model is increasingly used as a welfare-assessment framework in animal legal cases."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Why are pleasure states, not just the absence of discomfort, considered necessary for QOL?","o":["Because pleasure states reduce length of stay automatically","Because they are the only measurable metric","Because they prevent physical disease directly","Because the mere absence of discomfort is insufficient for an optimal mental state"],"a":3,"e":"A life worth living requires positive experiences, not just the removal of negatives, which is the core advance of the Five Domains."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A shelter dog that was highly reactive on intake now lies flat in the back of the cage and does not respond when approached. A volunteer reports the dog has settled in. What is the correct interpretation?","o":["The dog has habituated normally and welfare has improved","The dog is demonstrating a polite decline posture indicating readiness for adoption","This may represent behavioural depression or learned helplessness, and welfare has likely deteriorated","Lying flat with no response is normal for shelter dogs after 48 hours"],"a":2,"e":"A sudden transition from reactive to non-responsive is not settling — it is a welfare deterioration signal consistent with learned helplessness or behavioural depression. Positive engagement indicators must be tracked alongside absence of reactive behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which behavioural observation is the most reliable real-time indicator of positive welfare in a shelter cat?","o":["Hiding in the hide box for most of the day","Absence of vocalisation for more than 24 hours","Voluntary food intake and willingness to approach familiar staff for interaction","Lateral sleeping position during the first four hours post-intake"],"a":2,"e":"Voluntary appetite and social responsiveness are positive welfare indicators. Hiding and silence indicate coping or stress, not positive welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A cat has been stereotypically pacing the back of its cage for three days. What does this behaviour indicate, and what is the most appropriate initial response?","o":["Normal exploratory behaviour; this resolves within one week without intervention","Excess energy from overfeeding; decrease caloric intake","A positive-valence play behaviour directed at the cage door; no action required","Chronic stress or frustration exceeding the animal's coping capacity; initiate welfare review, provide enrichment, and consider environment change or foster placement"],"a":3,"e":"Stereotypies are not shelter boredom — they indicate that chronic stress or frustration has exceeded coping resources, and welfare intervention is required."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which statement best illustrates the principle that absence of negative indicators does not equal good welfare?","o":["A cat that hisses when approached is showing acceptable defensive communication","A dog that stops pacing and becomes non-responsive after five days may be deteriorating, not improving","A dog that barks on the first day of arrival has poor welfare","All animals that consume their full ration have good welfare"],"a":1,"e":"Behavioural depression produces apparent calm that masks welfare deterioration. Monitoring positive indicators including appetite, play, and social engagement is essential alongside tracking negative behaviours."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"When extracting a fearful or difficult dog from a kennel using a long slip lead, which mechanical action avoids throwing the lead over the dog's head?","o":["Position a bite stick between the door frame and the dog's maxilla","Slide a long sausage treat through the door from the outside to let the dog put her head into the loop","Use a press gate to force the dog's pelvic limbs against the back wall","Apply a flexible snare over the ears while the door is fully open"],"a":1,"e":"Sliding a treat through the door lets the dog place her own head into the loop, avoiding a stressful over-the-head reach."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"If a fearful shelter dog is confirmed dog-social, which housing modification is recommended, and what is its main constraint?","o":["Group housing in groups of 6 or more, supervised 24/7","Co-kenneling with a more outgoing companion; feed separately to prevent food guarding","Offsite foster only on fixed cycles","Placement next to a predatory species ward with visual blocks"],"a":1,"e":"Co-kenneling a dog-social fearful dog with an outgoing companion can change her emotional state; feed separately to avoid resource guarding."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"When a fearful dog needs two handlers with separate slip leads, how should a control pole be used if introduced?","o":["As the main tool to direct and lead the dog forward","Only at the time of a dangerous event, while the leashes remain the main tools to direct and lead","Wrapped in a towel to simulate a touch gradient","Applied to the lower lumbar spine for a low centre of gravity"],"a":1,"e":"The leashes do the directing; the control pole is reserved for the moment of a dangerous event only."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Walking a dog down a kennel pod with dogs on both sides, how should the handler position the pair?","o":["Dog on a short leash on the right flank, facing the kennels","Maintain the greatest distance possible by keeping the dog in the centre of the aisle","Walk fast while spraying bitter spray into the air","Force the dog to walk backwards with direct eye contact"],"a":1,"e":"Centring the dog and maximising distance from both rows reduces arousal and bite risk."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"If a walked dog must face kenneled dogs in a narrow pod, what defensive measure does the handler take?","o":["Execute a wheelbarrow technique to speed up","Stand farthest from the kenneled dogs to prevent a redirected bite to the handler","Pick up the drag leash and pull the dog toward the ceiling","Place a vision-blocking device over the handler's own eyes"],"a":1,"e":"Standing farthest from the kenneled dogs positions the handler away from the likely redirected bite."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"When initiating contact with a shy or unknown dog, what is the correct orientation and progression?","o":["Approach head-on, crouch, and reach over the head to assert control","Turn sideways, crouch if safe, gently toss high-value treats, avoid sudden moves and direct eye contact","Stand fully upright, hands at shoulder height, and talk loudly","Use a syringe pole to inject before any contact"],"a":1,"e":"A sideways, low, non-confrontational approach with tossed treats lets the dog choose to engage."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Once a shy dog solicits contact (leaning or pawing), where should the handler pet?","o":["Directly over the top of the head and muzzle","Gently on the side of the shoulder or neck, avoiding reaching over the head","On the hindquarters near the tail base","On the ventral abdomen after rolling the dog over"],"a":1,"e":"Avoid reaching over the head of a shy dog; pet the side of the shoulder or neck."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"The touch gradient requires which physical mechanic during an examination?","o":["Lifting and lowering the hand on and off the dog to test startle","Moving straight to a pinch or injection with no initial light contact","Touching lightly first and escalating intensity gradually (pet, tap, pinch, inject) while keeping at least one hand in constant contact","Approaching strictly from behind on a taut, short leash"],"a":2,"e":"The touch gradient (Fear Free) escalates intensity gradually with constant one-hand contact, approaching from the side."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"How should the team approach an aggressive or fearful dog for a medical procedure?","o":["Head-on, reaching over the cranium","From behind, with a snare around the caudal abdomen","From the side, rather than behind or head-on","By lifting straight onto a high table to remove traction"],"a":2,"e":"Side approach is least threatening and safest for a fearful or aggressive dog."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"For highly aroused, mouthy, adolescent dogs, which intervention is specifically highlighted to reduce kennel arousal?","o":["Long-term containment with zero human contact for 14 days","Standardised doll testing every morning","Sending them to foster care, even for a single night","Mandatory isolation with twice-daily catch-pole conditioning"],"a":2,"e":"Short foster stays, even one night, help dissipate arousal in mouthy adolescent dogs. (Note: option D was added to complete this item to four options; replace if you prefer.)"},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"To keep leverage and balance with a panicking or aggressive dog, where should the hands be?","o":["At shoulder height, fully extended away from the body","Low, around belly-button height, and close to the body","Inside the pockets of loose clothing","On the handler's hips to widen the stance"],"a":1,"e":"Low hands near belly-button height keep a low centre of gravity so the handler is not pulled over. This is a practical heuristic, not a measured constant."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Walking a dog known for redirected aggression, which equipment and leash adjustment are used?","o":["A flat collar held with a bent elbow near the face","A head halter, a muzzle, or both, while straightening the leash arm to hold the dog away","A flexible snare and a towel wrap around the chest","A chain leash held at shoulder height with crossed hands"],"a":1,"e":"Head halter and/or muzzle plus a straight leash arm holds a known redirector away from the handler."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Which list gives the four actions a handler must NEVER perform when breaking up a dog fight?","o":["Use an air horn, deploy a pig board, toss a blanket, scruff the dog","Grab their collars, punch, kick, or pry their mouths apart","Pick up drag leashes, use citronella, blow a whistle, use a break stick","Push objects between them, call for help, use compressed air, turn off lights"],"a":1,"e":"The four nevers: do not grab collars, punch, kick, or pry mouths apart."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"During a two-dog fight with non-combatant dogs present, what should secondary handlers do?","o":["Deploy break sticks on the non-combatants","Quickly remove the non-combatant dogs to safety, or clip them to the fence with a carabiner","Wheelbarrow all dogs at once","Spray all non-combatants in the eyes with bitter spray"],"a":1,"e":"Rapidly secure non-combatant dogs (move them to safety or carabiner to the fence) before managing the combatants."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What are the inventory and device-check requirements for shelter fight kits?","o":["Every 6 months; sprays checked by shaking once","At least every 2 months; sprays checked like a fire extinguisher to confirm they are pressurised and full","Only after a deep gripping fight","Daily, at the end of each lighting cycle"],"a":1,"e":"Inventory at least every 2 months and verify spray pressure as you would a fire extinguisher; check control poles at the same time."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What is the precise sequence for using a break stick on a gripping fight?","o":["Grab the tail, insert between molars, pull back with a jerk","Grab the collar at the base of the skull, work the stick parallel to the jaw behind the canine teeth (about 1 inch in), and twist the handle","Position the stick perpendicular to the maxilla, slide down the esophagus, push forward","Scruff the flank, slide under the tongue, and lift the dog up"],"a":1,"e":"Control the head at the base of the skull, insert about 1 inch behind the canines parallel to the jaw, then twist to break the grip."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Under which conditions is the usual time to gather fight tools overridden, forcing immediate hands-on intervention?","o":["Slash-and-dash fights over 15 minutes","Two equal-size aroused adolescents","Large versus small dogs, a blocked airway, or blocked blood flow (tight neck grip with the victim losing consciousness)","A fight during a scheduled scan sample"],"a":2,"e":"Large versus small, blocked airway, or blocked blood flow are emergencies that remove the usual time buffer."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Why is picking up each dog's drag leash and walking apart contraindicated in a gripping fight?","o":["It costs the handler their centre of gravity","It triggers redirected aggression onto non-combatants","It does not work on a gripping fight and can increase tissue damage","It invalidates later sedation"],"a":2,"e":"Opposing pulls on a gripping fight tear tissue and do not separate the dogs."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"If an off-leash dog grips clothing or a body part and shakes her head, what should the handler do?","o":["Push the dog away and pry the jaws with bare fingers","Grab the collar, scruff, or sides of the head to minimise head movement","Immediately curl up and play dead","Swing the dog by its tail"],"a":1,"e":"Controlling the head (collar, scruff, or sides of the head) limits the damaging shake."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"The 'feeding the bite' technique relies on which mechanical action to force a release?","o":["Pulling the victim backward suddenly","Pushing the biting dog forward into the victim, causing recoil and release","Spraying vinegar into the handler's own sleeves","Rotating a break stick against the belly button"],"a":1,"e":"Pushing the dog forward into the victim triggers a recoil-and-release reflex (do not pull the victim away)."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"If a dangerous dog pulls a handler to the ground, what is the safest posture?","o":["Stand up, scruff the dog, and wheelbarrow it","Curl into a ball, play dead, and cover the neck with the hands","Lie flat on the back, extend the limbs, and scream","Grab a control pole and kink the noose under the body"],"a":1,"e":"Curling into a ball and covering the neck protects vital structures when downed."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Which statement correctly identifies an absolute restriction for control poles?","o":["Appropriate for routine use on all incoming small dogs and cats","Never used on a small dog or cat, as severe injury or death may result","Stored by hanging directly by the wire noose to keep tension","Designed mainly to lift large dogs onto tables"],"a":1,"e":"Control poles are never appropriate for cats or small dogs and are not for routine use, lifting, pushing, or pulling. This aligns with ASV guidance to minimise fear, anxiety and stress and avoid forceful handling."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What is the correct way to store a control pole to prevent operational failure?","o":["Prop the noose end on the ground by the cleaning charts","Hang it by the wire noose from a high wall to let it stretch","Never hang it by the wire noose or prop the noose on the ground (this kinks the line); hang it by attachments to the pole handle","Lock it inside the fight-kit box under the slip leads"],"a":2,"e":"Hanging by the noose or propping it on the ground kinks the line; hang by the handle attachments and check regularly."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"When using an air horn or compressed air to disrupt a fight, what precaution applies?","o":["Emit the sound inside the victim's ear canal","Use it as a first resort before checking for drag leashes","Emit compressed air fairly close to the head, but not so close the dog can redirect onto the handler","Hold the air horn at shoulder height facing away"],"a":2,"e":"Keep compressed air close enough to be effective but not so close the dog can redirect a bite onto the handler."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What criteria define when forceful handling (scruffing cats, pinning dogs) is acceptable?","o":["When a trainer is unavailable for a scheduled intake exam","Only in extraordinary circumstances, when a human or animal is in immediate danger and other options, sedation, or delays are not possible","Whenever an animal refuses treats during a 15-minute session","To speed operations and reduce length of stay"],"a":1,"e":"Forceful handling is an emergency last resort only, consistent with ASV guidance against routine forceful restraint."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"Which housing or handling feature must be preserved to reduce stress for an incoming cat?","o":["The cat maintains a sense of control and perceives that escape or hiding is possible","Constant visual contact with predatory canine species","Maximum restraint with a squeeze cage for 48 hours","Repeatedly lifting the hand on and off during care"],"a":0,"e":"Cats cope better when they retain control and the option to hide, consistent with ASV welfare guidance."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What is the correct sequence of the finger-nose technique for socialised cats?","o":["Extend a clenched fist rapidly toward the maxilla, then withdraw","Slowly advance an outstretched index finger, hold it in front of the face, let the cat initiate by rubbing, then apply steady pressure to the sides of the face and neck","Slide a finger through a den port to touch the caudal flank","Place a treat on the fingertip and force it into the mouth"],"a":1,"e":"Advance an outstretched finger, let the cat rub to initiate, then use calm steady pressure on the face, chin, or neck."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"What was verified about petting sessions for shelter dog stress?","o":["Only an intimately familiar owner can change cortisol","About 15 minutes of petting decreased signs of stress even when the volunteer was unfamiliar to the dog","Petting must be on the ventral abdomen with a touch-gradient pinch","Petting is the only effective method; play and passive presence do nothing"],"a":1,"e":"Roughly 15 minutes of petting reduced stress signs even from an unfamiliar volunteer; play and passive human presence also lower cortisol."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"For severe leash-grabbing on walks, which is a recommended defensive method?","o":["Pull the leash up with both hands until the forelimbs leave the ground","Use a chain leash or cover the lead with PVC pipe, or spray a bad-tasting substance (vinegar or bitter spray) on the lead","Apply a control pole to the base of the skull before leaving the kennel","Use physical force to set handling boundaries"],"a":1,"e":"PVC-covered or chain leads and a bitter-tasting spray make the lead unrewarding to grab; offering a toy to carry also helps."},{"type":"mcq","domain":"Behavioral Health","sub":"Animal Handling","q":"When returning a dog that wants to stay with people and avoids the kennel, what sequence is used?","o":["Drag the dog in with a straight arm and latch the door","Push the hindquarters with a control pole from outside","Toss treats into the corner, or give a food-stuffed toy if resources allow, recognising that high-value food may still not be enough","Stop all walks and switch to passive presence only"],"a":2,"e":"Toss treats into the corner and offer a food-stuffed toy, while accepting that food alone may not always overcome the dog's preference for people."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"When gathering a behavioural history at intake, which pair of communication skills reduces social desirability bias?","o":["Direct interrogation and closed-ended metrics","Active listening and the use of objective language","Subjective interpretation and passive recording","Validated trait rating and ad-libitum notation"],"a":1,"e":"Intake staff should ask open-ended questions, use objective language, and apply active listening to get accurate disclosures."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which is named as a primary source of environmental unpredictability that drives chronic fear and anxiety?","o":["Using a population manager to lead daily rounds","Irregular patterns of continuous light or darkness","Providing a choice of resources in group housing","Giving fast-acting psychopharmacology before intake"],"a":1,"e":"The three drivers are lack of routine, frequent disruption of enclosure set-up, and irregular patterns of continuous light or darkness."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"On the 103-item C-BARQ, assuring owners of confidentiality made them more likely to disclose which behaviours?","o":["Separation-related and attachment-seeking behaviours","Aggression toward family members or fear of strangers","Stranger-directed aggression and non-social fear","Dog-directed aggression and resource guarding"],"a":1,"e":"Confidentiality increased disclosure of family-directed aggression and fear of strangers; other categories showed no difference."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Using the shorter 42-item C-BARQ, what was the effect of confidentiality assurances on disclosure?","o":["It doubled disclosure of human-directed bites","It eliminated social desirability bias entirely","There was no difference between the confidential and non-confidential groups","Owners became far less forthcoming for fear of euthanasia"],"a":2,"e":"The 42-item version showed no difference, unlike the 103-item version. Self-administered tools may still reduce bias, but evidence is incomplete."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"At two weeks post-adoption, which behaviours correlate with surrender reports?","o":["Barking, house soiling, and predatory drive","Fear, anxiety, or aggression toward vets, and aggression toward unfamiliar people","Kennel spinning and stereotypic pacing","Tail tucked and food-bowl freezing"],"a":1,"e":"At 2 weeks, aggression toward unfamiliar people, urination when alone, and destructive chewing correlate with surrender reports."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How do post-adoption correlations change from the 2-week to the 6-week follow-up?","o":["They increase sharply due to trigger stacking","There are fewer correlations, limited mainly to aggression toward unfamiliar people, urination when alone, and destructive chewing","Resource guarding becomes the single predictor of return","Adopter reports lose all alignment with shelter observations"],"a":1,"e":"By 6 weeks there are fewer correlations overall, with only a few behaviours still matching surrender reports."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Close to 80% of dogs are fearful at the vet. For a dog reported fearful at a vet exam, what is the correlated chance of fear in new situations?","o":["35%","37%","55%","68%"],"a":3,"e":"Dogs fearful at the vet (about 55% by owner report) show fear in new situations about 68% of the time."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A dog fearful at the veterinarian is statistically prone to which secondary presentations?","o":["35% pain or touch sensitivity and 37% non-social fear","75% human-directed biting and 20% kennel guarding","16% true aggression and 48% separation anxiety","60% food guarding and 50% conspecific reactivity"],"a":0,"e":"Vet-fearful dogs show pain or touch sensitivity about 35% of the time and non-social fear about 37%."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Why are untrained daily-care staff observations of behaviour often inaccurate?","o":["They are trained only to monitor BCS and gait","People may be reluctant to disclose negative information that could hurt the dog's adoption chances","The observer effect eliminates their ability to see pacing","They use input-based rather than animal-based measures"],"a":1,"e":"A key reason is reluctance to report negatives that might jeopardise adoption. Staff predicted only about a third of later-reported problems."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Close to half of the shelter staff studied made which observational error?","o":["Mistook fearful tracking for a stable trait","Mistook aggressive behaviour for excitement and frustration","Mistook play for chew-bone guarding","Classified non-aggressive behaviour as severe attacks"],"a":1,"e":"About half mistook aggression for excitement or frustration, but rarely the reverse, so people tend to judge dogs positively."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What physical focus differentiates trainers from non-experts when reading canine behaviour?","o":["Non-experts watch the tail; trainers time vocalisations","Non-experts focus on the head; trainers attend to the body","Trainers track only HPA-axis parameters","Trainers watch the kennel front; non-experts watch hiding"],"a":1,"e":"Non-experts focus on the head, while trainers attend to the body and read motivation and emotion better. Training improves non-experts."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"In which situation is a dog's probability of aggression toward people highest?","o":["During offsite walks or field trips","With a moderately social stimulus dog","When confined to a kennel","During a standardised medical intake exam"],"a":2,"e":"Aggression toward people is highest in the kennel; aggression toward other dogs tends to be lowest there."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What are the cortisol peak timelines reported in shelter dogs?","o":["Plasma peaks day 17; urine peaks days 1 to 3","Plasma is highest in the first 3 days; urinary peaks at 17 days","Both peak at exactly 5 days","Cortisol does not fluctuate with time"],"a":1,"e":"Plasma cortisol peaks in the first 3 days then declines; urinary cortisol peaks around day 17."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How does prior kenneling experience affect urinary cortisol?","o":["It up-regulates the HPA axis and doubles cortisol","Dogs with prior kenneling experience have lower urine cortisol than naive dogs","It linearizes plasma cortisol","There is no correlation"],"a":1,"e":"Previously kenneled dogs show lower urinary cortisol than dogs with no such experience."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Why caution against using a dog's movement or body position as the sole marker of welfare?","o":["Movement can only be measured by scan sampling","Behavioural stress is expressed in many ways and correlates poorly with plasma cortisol","Enclosure standards require a static posture","Posture is dictated only by nutrition and BCS"],"a":1,"e":"Behaviour is a weak sole stress marker because it varies widely and correlates poorly with plasma cortisol."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is the primary diagnostic limitation of the ASPCA SAFER assessment?","o":["A 100% false positive rate","It differentiates none/mild from severe aggression but misses MODERATE aggression","It needs over 60 minutes and 4 handlers","It relies on a Likert scale with severe bias"],"a":1,"e":"SAFER (sensitivity 60%, specificity 50%) misses dogs with moderate aggression."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"The mAAP test (sensitivity 73%, specificity 59%) showed strong utility for which outcome?","o":["Predicting time spent resting in the bed","Correlating evaluation aggression with owner reports","Identifying chew-bone guarding from a doll","Differentiating spinning from anhedonia"],"a":1,"e":"The mAAP correlated behavioural-assessment aggression well with owner reports."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is the verified predictive value of the assess-a-hand food-guarding test for home behaviour?","o":["It accurately predicts presence of severe home guarding","High positive but 0% negative predictive value","It predicts ABSENCE better: 78% of non-guarders in the test also did not guard at home","It correlates perfectly with owner-directed bites at 6 weeks"],"a":2,"e":"The test identifies non-guarders better than guarders; 78% of test non-guarders also did not guard at home."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"In Patronek and Bradley's simulations, why is the false-positive share still about 48% even at 85% sensitivity and 85% specificity?","o":["85% accuracy cannot calculate negative predictive value","Aggression toward people is low prevalence, present in no more than 16% of dogs","The observer effect inflates urinary cortisol","Handlers fail to use a male tester"],"a":1,"e":"Low prevalence (16%) means many positives are false; even at 85%/85% the false-positive share stays near half, hence no better than flipping a coin."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"For the threatening stranger test, which variable is controlled to maximise informational output?","o":["Test inside group housing during feeding","The tester should ideally be male, since dogs are more reactive to men","The handler must drop the leash completely","Repeat the subtest 5 times a week with no rest days"],"a":1,"e":"The test is sensitive to tester sex and is most informative with a male tester."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Using a model (fake) dog to assess conspecific reactivity, agreement is lowest for which category?","o":["Friendliness","Fearfulness","Playfulness","Aggressiveness"],"a":3,"e":"Model dogs show good agreement for friendliness, moderate for fearfulness, and poor for aggressiveness."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What timing does the text recommend for assessing owner-relinquished versus stray dogs?","o":["Both on day 17 to match the urinary cortisol peak","Owner-relinquished at intake; strays the day before the end of the hold (or after day 3 if the hold exceeds 5 days)","Strays within 48 hours before plasma cortisol declines","Never until 2 weeks in foster"],"a":1,"e":"Assess surrenders at intake (reduces LOS); assess strays the day before hold ends, or after day 3 for holds over 5 days."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A structured feline behavioural test yields which quantitative metrics?","o":["Agreeableness, extraversion, neuroticism on a Likert matrix","Rating of severity (1 to 5), frequency, duration, proportion, and latency","Presence or absence of tracking across ad-libitum scans","Air quality, temperature, and enclosure size"],"a":1,"e":"Structured tests rate severity (1 to 5) plus frequency, duration, proportion, and latency of a behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is the primary limitation of the Feline Temperament Profile (FTP)?","o":["Scores change drastically after adoption","It cannot be completed within 30 minutes","It is not designed to identify a propensity for specific undesirable behaviours","It requires invasive plasma sampling"],"a":2,"e":"The FTP is valid and consistent but is not built to flag specific undesirable behaviours."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What critical caveat applies to the ASPCA Feline-ality assessment scales?","o":["It increases LOS and raises euthanasia","It needs a behaviourist familiar with the cat","As of yet, no studies have evaluated the reliability or validity of these scales in shelters","It forces food-guarding triggers that cause trigger stacking"],"a":2,"e":"Despite operational benefits, the reliability and validity of the Feline-ality scales in shelters are not yet established."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which framework organises care into Good feeding, Good housing, Good health, and Appropriate behaviour?","o":["The Five Freedoms","The Welfare Quality 4 Principles","The Five Domains Model","The LIMA Humane Hierarchy"],"a":1,"e":"Those four are the Welfare Quality principles, distinct from the Five Freedoms and Five Domains."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What does Qualitative Behaviour Assessment (QBA) measure to gauge affective state?","o":["Frequency of stereotypic spinning over 24 hours","The expressivity of the whole animal as it engages with its environment","The ratio of urinary to plasma cortisol","Distance maintained from a hiding box"],"a":1,"e":"QBA assesses whole-animal expressivity and shows high inter-rater agreement, capturing the affective state better than breaking behaviour into parts."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Why is a hiding box one of the most impactful modifications for newly admitted cats?","o":["It lets staff do trait ratings without the observer effect","It removes the need for daily cleaning","It facilitates a quicker reduction in stress, so cats approach the cage front more and spend less time behind the litter box","It replaces psychopharmacology"],"a":2,"e":"Hiding boxes speed stress reduction; box cats approached the cage front more and hid behind the litter box less."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Who must be on the daily rounds team, and when should rounds ideally occur?","o":["The surrendering owner and a legal consultant, after adoption hours","Representatives from operations, medical, and behaviour, conducted before cleaning and feeding","Certified trainers only, during 17-day cycles","Volunteers and fosterers, during offsite trips"],"a":1,"e":"Rounds include operations, medical, and behaviour perspectives and are done before cleaning and feeding to catch inappetent animals."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How should the team respond to stereotypic or repetitive behaviours in the population?","o":["Immediately prescribe long-term medication to mask the signs","Address the fundamental causes by reducing stressors and changing the environment, rather than ad-hoc treatment of signs","Increase standardised testing to force an outcome","Restrict the animal's choice and control to prevent trigger stacking"],"a":1,"e":"Target the root causes (reduce stressors, change the environment); pharmacology should not replace environmental change."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A puppy isolated at a young age from maternal and littermate contact develops persistent care-soliciting behaviour and a high-pitched, high-frequency alone bark. Which early-life management error is most consistent with this picture?","o":["Isolation from maternal and littermate contact at a young age","Early weaning onto an all-dry kibble diet","Exposure to mild tactile stressors during the first two weeks of life","Lack of exposure to a veterinary clinic between 8 and 12 weeks"],"a":0,"e":"Early isolation deprives pups of tactile and social feedback and produces high-frequency isolation vocalisations and care-soliciting pathology."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"What physiological benefit comes from brief handling and mild stressors in puppies from birth to 5 weeks?","o":["Complete suppression of the sympathetic nervous system","Permanent downregulation of the gustatory receptors","Adaptations in the pituitary-adrenocortical (HPA) system that improve lifelong stress resilience and learning","Accelerated closure of the vomeronasal organ"],"a":2,"e":"Mild neonatal stressors act as a positive neuroendocrine challenge and produce more stable HPA-axis function and easier learning."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"At what age do canine puppies typically shift from actively approaching novel objects to displaying wariness?","o":["2 to 3 weeks","7 months","18 months","About 5 weeks, with wariness peaking at 12 to 14 weeks"],"a":3,"e":"Pups actively approach novel until about 5 weeks; wariness escalates and peaks at 12 to 14 weeks."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"To produce a lifelong social bond with sheep, a livestock guarding puppy must be housed with sheep during which window?","o":["The prenatal period","The socialisation period (3 to 12 weeks)","The neonatal period (0 to 2 weeks)","The late juvenile period (after 7 months)"],"a":1,"e":"Primary interspecies social attachment is formed during the canine socialisation window (3 to 12 weeks)."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"What is the recommended minimum duration and frequency of controlled exposure for adequate puppy socialisation during the 8 to 12 week window?","o":["About 20 minutes per week","3 minutes daily","1 hour every other day","5 hours distributed across the juvenile period"],"a":0,"e":"Short, repeated, varied exposures totalling about 20 minutes per week are enough to achieve baseline canine socialisation."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Early weaning is most associated with which set of later behavioural problems?","o":["Disorientation, sleep-wake alteration, and house soiling","Tonic immobility, predatory stalking, and right-sided tail wagging","Destructive behaviour, possessiveness, excessive barking, and fearfulness","Loss of interest in food and absolute loss of social play"],"a":2,"e":"Early removal from dam and litter disrupts core frustration-tolerance training and bite inhibition, producing later destructive, possessive, vocal, and fearful behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"At what age do predatory motor patterns (eye, stalk, chase, bite) typically appear in most breeds, and how does this compare to Border Collies?","o":["2 weeks in most breeds; 12 weeks in Border Collies","3 to 5 weeks in most breeds; 6 months in Border Collies","18 months in most breeds; 2 years in Border Collies","7 months in most breeds; as early as 8 weeks in Border Collies"],"a":3,"e":"Most breeds show predatory motor patterns at about 7 months; herding selection brings them on as early as 8 weeks in Border Collies."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A male dog enters a phase of erratic, energetic behaviour and reduced impulse control linked to a testosterone surge. When does this typically occur?","o":["2 to 3 weeks","6 to 8 months, around puberty at about 7 months","3 to 5 weeks","18 to 24 months"],"a":1,"e":"The testosterone surge of canine puberty (around 6 to 8 months, puberty at about 7 months) drives the energetic and erratic juvenile phase."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"At what ages is a dog generally considered socially mature, and when fully mature?","o":["18 months socially, 2 years fully","12 weeks and 6 months","7 months and 12 months","3 years socially, 5 years fully"],"a":0,"e":"Behavioural maturity lags sexual maturity: about 18 months socially and about 2 years fully."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Using DISHA to screen for Canine Cognitive Dysfunction Syndrome, what does the S stand for?","o":["Socialisation deficit","Symmetric piloerection","Sleep-wake cycle alteration","Submissive grinning"],"a":2,"e":"DISHA = Disorientation, Interactions, Sleep-wake cycle, House soiling, Activity changes."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A dog shows piloerection across its hackles. What does this signal?","o":["A positive emotional valence and a desire to play","Structural submission and fear-based appeasement","Complete predatory focus with no sympathetic involvement","General physiological arousal, which can occur across multiple contexts"],"a":3,"e":"Piloerection is an involuntary sympathetic sign of arousal; it is context-dependent and not exclusively aggression."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A dog wags its tail fast and high, biased predominantly to its OWN LEFT side. How should this be interpreted?","o":["A positive-valence greeting indicating safety","An unknown or unfriendly dog with high arousal and negative valence","A submissive, fearful appeasement gesture","A soporific, deeply relaxed state"],"a":1,"e":"Right-biased wagging reflects positive valence; left-biased wagging reflects negative or withdrawal valence (right-hemisphere processing)."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Which set of features describes a canine SUBMISSIVE GRIN rather than offensive aggression?","o":["Lips retracted vertically, teeth visible, eyes squinty, forehead smooth, ears pulled back","Wrinkled muzzle, C-shape mouth, short lip, and hard open eyes","Open-mouth panting, relaxed commissures, hard eyes locked on a target","Tight mouth pushed forward, dilated pupils, ears forward"],"a":0,"e":"The submissive grin shows teeth but with squinty eyes, smooth forehead, and back ears, distinguishing it from the wrinkled-muzzle, hard-eyed offensive pucker."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"\"Hard eyes\" (direct prolonged gaze with dilated pupils) signal which autonomic state, and what does it mean?","o":["Parasympathetic activation; deep relaxation","HPA-axis activation; preference for sweet flavours","Sympathetic activation; high arousal and a threat","Vomeronasal activation; active pheromone collection"],"a":2,"e":"A hard direct gaze drives sympathetic arousal and signals an offensive or defensive spatial challenge."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A dog shows a forward-leaning posture with a short-lip, C-shape muzzle pucker and a wrinkled muzzle. This indicates:","o":["Defensive aggression","Timidity and fearfulness","Alert, attentive greeting","Offensive (aggressive) aggression"],"a":3,"e":"Forward weight plus a wrinkled, C-shape, short-lip pucker is the offensive aggression cluster."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Which combination best describes canine TIMIDITY or DEFENSIVE fearfulness?","o":["Lean forward, hard eye, raised tail, offensive pucker","Posture pulled back, ears back, tail tucked, whale eye, long-lip commissure, trembling","Ears forward, tail down but not tucked, prolonged focus","Tail high and fast to the right, loose side-to-side wag, open relaxed mouth"],"a":1,"e":"Pulled-back posture, back ears, tucked tail, whale eye, long-lip commissure, and trembling form the defensive or fearful cluster."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A dog gives a low-pitched bark that is harsh with little amplitude. In short-range communication, what does this most likely signal?","o":["Aggression","Fear or desperation","Play solicitation or greeting","Care-soliciting anxiety"],"a":0,"e":"Low-frequency, harsh, low-amplitude vocalisations are distance-increasing across mammals and signal aggression."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"How do dogs gather pheromones from urine, faeces, and saliva and route them to the olfactory bulb?","o":["By rapid panting through an open relaxed mouth","By tactile scratching with sebaceous glands of the paws","Through the vomeronasal organ (VNO), which sits below the nasal cavity","By giving a submissive grin to clear the nasal passages"],"a":2,"e":"The VNO is a dedicated chemosensory organ under the nasal cavity that routes pheromone signals to the olfactory bulb."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"How long is the feline gestation period, and how does maternal protein or calorie restriction in late pregnancy affect kittens?","o":["45 days; advanced learning and early eye opening","75 days; obligate right-sided tail wagging","90 days; permanent destruction of the VNO","63 days; elevated emotional reactivity and impaired social interaction, exploration, and learning"],"a":3,"e":"Feline gestation is 63 days; late-pregnancy nutritional restriction produces lasting emotional reactivity and learning impairments in the offspring."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"In the feline neonatal stage (0 to 14 days), kittens cannot thermoregulate and navigate using which sensory modalities?","o":["Visual and acoustic stimuli","Tactile, thermal, and olfactory stimuli","High-frequency echolocation and taste","Purely gustatory receptors"],"a":1,"e":"Eyes and ears are closed; kittens rely on tactile, thermal, and olfactory cues to find the queen's nipple."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Which factor is associated with EARLIER eye opening in kittens?","o":["Being a female kitten, or being born to a young mother","Being born to a protein-restricted queen","Being a male kitten born to an older queen","Hand-rearing from birth"],"a":0,"e":"Female kittens and kittens of young queens tend to open their eyes earlier."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Kittens hand-reared from 2 weeks without a queen or littermates are most at risk of which long-term deficits?","o":["Hyper-dependence on right-sided tail wagging and loss of hunting drive","Precocious motor development and early social maturity at 6 months","Increased fear and aggression toward people and cats, poor social skills, and learning impairments","Complete loss of vocalisation, including purring and hissing"],"a":2,"e":"Without maternal correction and littermate play, hand-reared kittens become more fearful and aggressive, learn less well, and have poor social and parenting skills."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"What is the sensitive socialisation window in kittens during which human handling is critical for adult comfort with humans?","o":["0 to 2 weeks","8 to 12 weeks","3 to 14 months","2 to 7 weeks"],"a":3,"e":"The feline socialisation window is 2 to 7 weeks; handling by 7 weeks is critical for adult enjoyment of human contact."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Which parental factor is most strongly associated with kittens that are friendly, outgoing, and exploratory?","o":["A queen who exhibits predatory stalking during pregnancy","A tom (sire) with an outgoing, friendly personality","A sire that vocalises frequently with open-mouth hisses","A queen who nurses for less than an hour after birth"],"a":1,"e":"Paternal personality is highly heritable in cats and independently predicts kitten boldness, friendliness, and exploration."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A cat purrs during a veterinary examination. How should this be interpreted?","o":["A care-soliciting behaviour that can mean a friendly interaction, but also mild anxiety or illness","An exclusive indicator of joy, comfort, and safety","An offensive open-mouth agonistic threat","A closed-mouth greeting strictly used during courtship"],"a":0,"e":"Purring is a care-soliciting behaviour with a dual meaning; it can signal friendliness OR mild anxiety or illness."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Which feline vocalisation is described as a closed-mouth meow used as a friendly greeting?","o":["Purr","Yowl or shriek","Chirr or trill","Hiss or spit"],"a":2,"e":"The chirr or trill is a closed-mouth greeting used between preferred associates, human or feline."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"Where are the primary sebaceous glands that deposit chemical information during head rubbing on objects or people?","o":["Strictly between the digits of the hind paws","Along the length of the tail-base only","Inside the auditory cortex","Temporal region of the head, under the chin, and around the lips"],"a":3,"e":"The temporal head, sub-mental (chin), and perioral sebaceous glands deposit sebum during allorubbing of objects and social targets."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A cat approaches you with its tail held perfectly vertical and upright. What does this signal?","o":["An active open-mouth offensive threat","A desire to interact amicably, often followed by head rubbing or tail twining","Extreme terror and impending defensive hysteria","Hypervigilance requiring confinement"],"a":1,"e":"A vertical tail-up approach is an unambiguous invitation to amicable contact, often followed by nose touch, body rubbing, and tail twining."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A cat sits sternal with the tail wrapped tightly around the body, pupils dilated, blinking, whiskers forward, ears flattened. What is the most likely emotional state?","o":["Anxious, hypervigilant, or distressed","Relaxed and neutral","Confident offensive aggression","A soporific state before deep sleep"],"a":0,"e":"Defensive flattening of features with compact body positioning signals anxiety, hypervigilance, or distress."},{"type":"mcq","domain":"Behavioral Health","sub":"Body Language","q":"A cat sits with its tail wrapped entirely around its body. Regarding aggression, what does this suggest?","o":["Highly likely to engage in offensive aggression within seconds","An absolute dominance display over nearby cats","Unlikely to show aggression but not enthusiastic about interaction","Soliciting immediate grooming"],"a":2,"e":"The wrapped tail forms a defensive perimeter and signals a preference to be left alone, not an aggressive threat."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A 3 month old purebred dog presents with ataxia, intention tremors, swaying, and a broad-based stance. The signs were absent at birth and emerged at about 6 weeks. Other than this, the dog is bright and otherwise well. Which is the most likely diagnosis?","o":["Cerebellar abiotrophy","Acquired vestibular disease","Lysosomal storage disease in advanced phase","Intracranial primary neoplasia"],"a":0,"e":"Cerebellar abiotrophy is heritable, dogs are normal at birth, and signs appear at 2 to 9 weeks with onset before 4 months. Lysosomal storage disease shows progressive signs within the first year and is rare; intracranial neoplasia is a senior-onset differential."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which structural and functional changes have been documented in canine cognitive dysfunction syndrome?","o":["Diffuse cerebellar atrophy with sparing of the forebrain","Selective hippocampal hypertrophy and dopamine receptor proliferation","Reduced frontal volume, increased ventricles, meningeal calcification, beta-amyloid accumulation, MAOB upregulation, oxidative damage","Acute infarction of the basal ganglia"],"a":2,"e":"Canine CCDS resembles Alzheimer's disease: frontal atrophy, ventricular enlargement, beta-amyloid, MAOB upregulation, lipofuscin and apoptotic bodies, neuronal loss, and oxidative damage."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An 8 year old owner-relinquished dog presents with insidious onset of dementia, head pressing, and altered habits. The most likely diagnosis is:","o":["Acute traumatic brain injury","Lysosomal storage disease","Cerebellar abiotrophy","Primary intracranial neoplasia (e.g. meningioma)"],"a":3,"e":"Primary intracranial tumours (meningioma, astrocytoma) usually occur in dogs over 7 years and cause insidious, slowly progressive signs including dementia, head pressing, and altered habits. Secondary (metastatic) tumours cause acute signs."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Selegiline is being considered for a senior dog with cognitive dysfunction. Which combination is STRICTLY contraindicated due to fatal serotonin toxicity risk?","o":["Concurrent use with phenobarbital","Concurrent use with SSRIs or TCAs","Concurrent use with calcium-channel blockers","Concurrent use with omeprazole"],"a":1,"e":"Selegiline (a MAOB inhibitor) combined with SSRIs or TCAs can produce fatal serotonin syndrome. Tramadol, SAMe, tryptophan, and buspirone also add serotonergic risk."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which statement best defines a stereotypy in the veterinary behavioural sense?","o":["An abnormal, invariant, repetition of a motor pattern that serves no apparent function","A normal exploratory behaviour displayed in a novel environment","A learned response shaped by positive reinforcement","A breed-specific predatory motor pattern displayed during play"],"a":0,"e":"A stereotypy is an abnormal, invariant repetition of a motor pattern with no apparent function; it commonly arises from conflict, frustration, or confinement-related stress."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"At what age do compulsive disorders most commonly arise in dogs and cats?","o":["Within the first 2 weeks of life","Only in geriatric patients over 12 years","Prepubertal at 3 to 6 months, or before social maturity at 12 to 36 months","Exclusively during late adolescence between 7 and 8 months"],"a":2,"e":"Compulsive disorders most commonly arise in the prepubertal period (3 to 6 months), before social maturity (12 to 36 months), or after a recognisable period of change or distress."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Among the TCAs, which is the MOST SELECTIVE serotonin reuptake inhibitor and the standard TCA choice for ALD, spinning, tail chasing, and feline psychogenic alopecia?","o":["Amitriptyline","Nortriptyline","Doxepin","Clomipramine"],"a":3,"e":"Clomipramine is the most selective serotonin-reuptake inhibitor of all TCAs and is the standard for compulsive disorders. Other TCAs have less SSRI effect and are less effective for these conditions."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An NMDA receptor antagonist is being trialled for a refractory compulsive disorder. What efficacy and time course should you discuss with the owner?","o":["Always 100% effective within 24 hours","About 64% effective within 2 weeks, with possible synergy when combined with fluoxetine","About 10% effective only after 6 months of continuous use","Effective only when combined with opiate agonists"],"a":1,"e":"Memantine and similar NMDA antagonists block glutamate-sensitive NMDA receptors. The notes report about 64% effective within 2 weeks of treatment, with possible synergy with fluoxetine."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A compulsive disorder responds well to clomipramine over 6 weeks. The owner asks how long to continue the medication. Which is the correct recommendation?","o":["Continue for at least 6 months, often lifelong; if tapering, do so very gradually over several months","Stop immediately once the behaviour resolves","Continue for exactly 2 weeks beyond resolution then stop","Switch to selegiline as soon as improvement is documented"],"a":0,"e":"If a compulsive disorder improves on medication, the drug should be continued for AT LEAST 6 months, often lifelong. Premature taper risks immediate relapse."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat presents with episodic rippling of the dorsal skin, spasms of the epaxial muscles inducible by rubbing the back, and self-directed tail biting. What is the most likely diagnosis?","o":["Cerebellar abiotrophy","Acute intervertebral disc herniation","Feline hyperesthesia syndrome","Hyperthyroid storm"],"a":2,"e":"The hallmark of feline hyperesthesia syndrome is rippling or twitching of the thoracolumbar skin and spasm of the epaxial muscles, often inducible by rubbing the back and impossible to interrupt; tail and flank self-trauma is common."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog displays vocalisation, destructiveness, and housesoiling only when the owner is away from home. Other medical and behavioural causes have been ruled out. What is the most likely diagnosis?","o":["Resource guarding","Predatory aggression","Compulsive disorder","Separation anxiety"],"a":3,"e":"The classic triad of separation anxiety is vocalisation, destructiveness, and housesoiling that occur ONLY when the owner is absent. If the behaviour also occurs when the family is home, or only randomly rather than consistently on departure, consider other differentials."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which statement best reflects the comparative effectiveness of antidepressants for separation anxiety in dogs?","o":["Amitriptyline worked in about 95% of cases compared with fluoxetine at about 20%","Amitriptyline worked in about 56% of cases compared with fluoxetine or clomipramine at about 75%","All antidepressants are equally effective at about 50%","Selegiline is first line and works in 100% of cases"],"a":1,"e":"The notes report amitriptyline effective in about 56% of cases, while fluoxetine or clomipramine were effective in about 75% of cases for separation anxiety."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which four pillars should anchor the management of separation anxiety?","o":["Shape independence; reduce departure and homecoming anxiety; decouple departure cues; anxiety reduction through structure and predictability","Use harsh punishment; restrict water; restrain in a small crate; confront the dog","Feed only on departure; allow constant attention; never crate; use force-based correction","Switch homes weekly; play loud music continuously; ignore all distress; never train"],"a":0,"e":"The four pillars are: shape independence and remove rewards for attention seeking; reduce departure and homecoming anxiety; decouple departure cues from actual departures via mock departures with a unique non-departure cue; reduce overall anxiety with structure and predictability."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An owner reports their dog digs persistently in the yard. Which differential is LEAST likely to drive digging in this clinical setting?","o":["Predatory drive directed at burrowing rodents","Separation anxiety and escape attempts","Hypothyroidism","Noise-phobia escape attempts"],"a":2,"e":"Digging is an innate trait in many breeds, especially terriers, and is most commonly driven by predatory exploration of prey odours, escape from separation anxiety or noise phobia, or insufficient stimulation. Hypothyroidism is not described as a digging driver in the notes."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat is observed approaching a vertical wall, standing with tail erect, treading the rear legs, and spraying a stream of urine. This posture and behaviour are diagnostic of:","o":["Inappropriate toileting due to substrate aversion","A medical urinary tract disorder","Cognitive dysfunction-related housesoiling","Urine marking"],"a":3,"e":"Marking posture is VERTICAL surface, standing with TAIL ERECT, treading with the rear legs, and spraying. Inappropriate toileting is typically horizontal squat onto a horizontal surface."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An adult intact male cat sprays urine indoors. What proportional reduction in spraying can the owner expect after castration, and how does this compare with the effect of spaying in females who spray?","o":["Castration reduces spraying in about 50% of males; spaying has no effect in females","Castration reduces spraying in about 90% of males; spaying reduces spraying in about 95% of females","Castration eliminates spraying in 100% of males; spaying eliminates it in 100% of females","Surgery has no proven effect on spraying behaviour"],"a":1,"e":"Castration reduces spraying in about 90% of males and spaying in about 95% of females."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"What is the recommended minimum litterbox-to-cat ratio in a multi-cat household?","o":["1 box per cat plus 1 (n + 1)","1 box per 5 cats","2 boxes per cat regardless of household size","No specific ratio is recommended"],"a":0,"e":"At least 1 box per cat plus 1, with bigger and more boxes generally better."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"What size and cleaning routine for litterboxes are recommended in the notes?","o":["At least 0.5 times the cat's length, scooped weekly, cleaned monthly with bleach","Any commercial size, scooped twice weekly, cleaned with concentrated quaternary ammonium","At least 1.5 times the cat's length, scooped 1 to 2 times daily, cleaned and changed weekly with hot water, avoiding strong disinfectants","No size or cleaning routine recommendations exist in the literature"],"a":2,"e":"The notes recommend boxes at least 1.5 times the cat's length, scooped 1 to 2 times daily, cleaned and changed weekly with hot water, avoiding strong disinfectants."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A young female puppy urinates a small amount whenever excited or when a visitor leans down to greet her. Which approach is most appropriate?","o":["Verbally correct the puppy each time it urinates so it learns not to do it","Withhold water for several hours before any greeting","Confine the puppy permanently to prevent any greetings","Greet calmly and predictably, ignore the puppy until calm, reinforce only behaviours incompatible with submission or excitement, do not punish; the problem usually improves with age"],"a":3,"e":"Submissive or excitement urination requires calm greetings, ignoring until calm, response substitution to incompatible behaviours, and NO punishment, since punishment makes it worse. The problem typically improves with age."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which of the following canine aggression types is described in the literature as the MOST mis-diagnosed and OVER-diagnosed?","o":["Maternal aggression","Dominance-related aggression","Predatory aggression","Pain-induced aggression"],"a":1,"e":"Dominance-related aggression is the most mis-diagnosed type. The diagnosis requires confident temperament, assertive signalling, AND aggression toward family members in the ABSENCE of fear. Most owner-directed aggression is actually conflict-related or resource guarding."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"At approximately what age does resource-guarding aggression typically begin in dogs?","o":["About 16 weeks of age","About 2 to 3 weeks of age","Only in geriatric dogs","Exclusively at full sexual maturity at 24 months"],"a":0,"e":"Resource-guarding age of onset is about 16 weeks. Adult-onset cases can occur in dogs on reducing diets or appetite-stimulating drugs or with appetite-increasing medical conditions like hyperadrenocorticism."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which combination of signs is most consistent with FEAR-RELATED canine aggression rather than offensive aggression?","o":["Lean forward, fixed hard eye, raised tail, stiff and frozen body, closed mouth, offensive pucker","Ears forward, tail down but not tucked, prolonged focus on the stimulus","Tail down or tucked, ears back, crouched body, weight shifted away, attempts to escape, piloerection, dilated pupils, tachypnoea","Tail high and fast biased to the right, loose side-to-side wag, open relaxed mouth"],"a":2,"e":"Fear-related aggression body cluster: tail down or tucked, ears back, crouched body, weight shifted away, escape attempts, plus autonomic signs (piloerection, dilated pupils, tachypnoea, defaecation, urination). Posturing can look offensive when behind a barrier or at a distance."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog stalks, chases, bites, and shakes a small moving stimulus with minimal prior threat display. This pattern is characteristic of which aggression type?","o":["Conflict-related aggression","Pain-induced aggression","Maternal aggression","Predatory aggression"],"a":3,"e":"Predatory aggression is normal hunting behaviour: stalking, chasing, catching, biting, killing, and sometimes eating, triggered by movement, with little vocal or postural threat. Targets are usually smaller and moving."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which demographic of intraspecific household aggression is over-represented in dogs?","o":["Opposite-sex pairs, especially intact males","Same-sex pairs, especially females, with spayed females over-represented","Only multi-breed households with three or more dogs","Exclusively senior dogs over 12 years"],"a":1,"e":"Most intraspecific household aggression involves same-sex pairs, most often FEMALES; SPAYED FEMALES are over-represented. Younger dogs, new arrivals, and rehomed dogs are most likely to initiate."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"At what age does feline play aggression typically peak before waning with maturity?","o":["About 9 to 12 months","About 1 to 2 weeks","About 5 to 7 years","About 14 to 18 years"],"a":0,"e":"Feline play aggression usually peaks at 9 to 12 months and wanes as the cat grows into adulthood. Risk is higher in solo-housed cats, hand-raised kittens, and cats encouraged to play with hands and feet."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat solicits petting then suddenly bites after the owner strokes the lower back for an extended period. This is the SECOND most frequent referral form of feline aggression. What is the diagnosis?","o":["Predatory play aggression","Pathophysiological aggression","Petted-induced aggression","Maternal aggression"],"a":2,"e":"Petted-induced aggression is the second most frequent referred form. The cat may seem to enjoy attention, then has a limited threshold for stroking, classically over the lower back, after which it bites."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which is the correct distinction between Feliway and Felifriend?","o":["Feliway and Felifriend are identical products with different brand names","Feliway is for dogs; Felifriend is for cats","Felifriend is a controlled antiviral, Feliway is a behaviour drug","Feliway uses the facial pheromone for environmental marking to reduce stress; Felifriend uses the allomarking pheromone to promote cat-to-cat familiarisation, best applied on the unfamiliar person or animal before introduction"],"a":3,"e":"Feliway is the facial pheromone associated with environmental marking, reducing stress and anxiety. Felifriend is the allomarking pheromone, applied on the unfamiliar person or animal BEFORE introduction to promote cat-to-cat familiarisation."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"When evaluating a dog from a fighting environment for inter-dog aggression, what is the correct order and method of stimulus-dog introduction?","o":["Always begin with a SAME-SEX stimulus dog off-leash with no barrier to allow natural assessment","Begin with an OPPOSITE-SEX, unrelated stimulus dog through a chain-link fence barrier with both dogs on leashes, progressing to same-sex if neutral","Never use a stimulus dog; rely solely on owner history","Use only a fake dog and skip live stimulus dogs entirely"],"a":1,"e":"Fighting dogs often react more favourably to opposite-sex dogs first; same-sex introduction follows. Initial contact is through a chain-link fence with both on leashes, since ears, paws, tails, and lips can still be bitten through the fence. Stimulus dogs should be completely unrelated to the case."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which set of behaviours in the fake-dog test is most consistent with TRUE inter-dog aggression that makes a dog unsafe around other animals and is reported to point to euthanasia as the recommended outcome with no current evidence for behavioural modification?","o":["Lunging, intense focus, slow stalking, growling, excited barking or silent attack with no hesitation, full-mouthed bite-and-shake","Approaching the fake dog with a relaxed wag and play bow","Sniffing the fake dog briefly then walking away","Lying down at a distance and ignoring the fake dog"],"a":0,"e":"True aggression toward the fake dog includes lunging, intense focus, slow stalking, growling and snapping, excited or silent barking, attack with no hesitation or once the fake dog rears or falls, and full-mouthed bites with hold and shake. The notes record euthanasia as the recommended outcome for these dogs."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"What proportion of former puppy-mill breeding dogs continue to exhibit behaviour problems (fear, housesoiling, touch sensitivity, compulsive behaviour, compromised quality of life) after rehoming?","o":["About 5%","Less than 1%","About 83%","Exactly 50%"],"a":2,"e":"The notes record that approximately 83% of former puppy-mill breeding dogs still exhibit behaviour problems in the home after rehoming, with a compromised quality of life."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Upon entry to a noisy intake ward, a dog's SAM system is activated. Which systemic change correctly pairs the neuroendocrine origin with its direct physiological effect?","o":["Direct sympathetic stimulation triggers the adrenal medulla to secrete epinephrine and norepinephrine, leading to pupillary dilation, tachycardia, and tachypnoea","Activation of the adrenal cortex releases epinephrine, causing immediate pupillary constriction","The anterior pituitary releases CRH, causing a profound drop in respiratory rate","The hypothalamus secretes glucocorticoids directly, causing a sudden drop in blood pressure"],"a":0,"e":"SAM fires from the adrenal medulla (epinephrine and norepinephrine), producing the immediate fight-or-flight markers."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A venipuncture is performed on a stray dog 25 minutes after capture. What are the expected plasma cortisol kinetics?","o":["Cortisol peaked and returned to baseline within 5 minutes","Cortisol takes 20 to 30 minutes to peak and remains elevated for 90 minutes or more","Cortisol remains unchanged during acute stress and shifts only after 14 days","Cortisol peaks at 30 seconds and drops to zero within 10 minutes"],"a":1,"e":"Cortisol is a delayed hormone; peak at 20 to 30 minutes, elevated 90 or more minutes."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A shelter dog of 6 weeks' stay has low-normal resting cortisol yet shows severe stereotypic pacing and wakeful inactivity. The most accurate explanation is:","o":["Low cortisol proves complete acclimation and zero stress","The SAM axis has permanently replaced HPA glucocorticoid production","Chronic stress can dysregulate the HPA axis, so cortisol no longer accurately reflects true stress","Low cortisol indicates the dog has transitioned into good stress"],"a":2,"e":"Chronic stress causes HPA dysregulation; normal cortisol does not rule out severe distress."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A dog is subjected to noisy transport, immediate microchipping, an intake exam, and placement beside a barking dog, then snaps at the handler. This escalation is best classified as:","o":["Context learning from habituation to microchipping","A normal presentation of good stress","Toxic physical stress from a viral pathogen","Trigger stacking, where rapid sequential stressors leave no window to return to baseline"],"a":3,"e":"Trigger stacking accumulates stressors with no recovery window, producing an amplified behavioural response."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Which category of dogs experiences the highest psychological stress without adaptation during the first week of shelter confinement?","o":["Owner-relinquished dogs","Stray dogs from urban environments","Dogs returned after a brief adoption trial","Adult dogs with extensive prior kennelling"],"a":0,"e":"Owner-relinquished dogs experience intense loss of social bonds, making their first week the hardest."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A volunteer spends 20 minutes petting an owner-relinquished dog on its first day. How will this affect the dog's physiological stress?","o":["It will reduce glucocorticoids to zero immediately","It will cause immediate trigger-stacking aggression","For owner-relinquished dogs, petting over 15 minutes per day does not change stress levels during the initial period","It will permanently desensitise the dog to all auditory stressors"],"a":2,"e":"Petting over 15 minutes per day does not lower stress in newly relinquished dogs, though it does help strays."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A pregnant dog endures severe, continuous toxic stress throughout gestation. What are the documented risks to her offspring?","o":["The offspring will have a hyper-resilient HPA axis immune to novelty","Accelerated growth rates and increased lymphocytes","Zero impact on offspring behaviour","The offspring often show learning impairment and increased susceptibility to fearful responses, especially to auditory stimuli"],"a":3,"e":"Prenatal maternal stress alters foetal neural development, predisposing pups to learning deficits and auditory-triggered fear."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A dog is hit by a car, suffers soft-tissue injury, and is placed in an unfamiliar medical ward. This challenge is a:","o":["Physical stressor, which includes trauma, hunger, thirst, or catching a virus","Pure psychological stressor with no physical perturbation","Toxic stressor that guarantees permanent brain changes in 5 minutes","Good stressor that enhances cognition"],"a":0,"e":"Physical stressors include direct physical insults such as trauma, disease, hunger, thirst, and extreme temperatures."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A behaviourist wants to evaluate chronic stress across long-term-stay dogs over 3 months. Which matrix is most appropriate?","o":["Single-point plasma cortisol during morning cleaning","Salivary cortisol after an acute walk","Cortisol metabolites from hair, urine, or faeces","Real-time heart-rate monitoring via a 24-hour halter"],"a":2,"e":"Plasma and saliva reflect moments; long-term chronic trends need accumulated metabolites in hair, faeces, or urine."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A CBC on an asymptomatic cat hiding constantly since intake 4 days ago reveals a stress leukogram. Which pattern defines this?","o":["Severe decrease in neutrophils with massive increase in lymphocytes","Panleukopenia with absolute monocytosis","Total absence of eosinophils only","Decreased peripheral lymphocytes paired with increased neutrophil counts"],"a":3,"e":"The stress leukogram is lymphopenia with neutrophilia, evidence of HPA activation even with normal resting cortisol."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"An ACTH stimulation test in dogs exposed to prolonged shelter crowding confirms HPA dysfunction. Which response pattern indicates this?","o":["Massive pituitary hypersensitivity with immediate adrenal shrinkage","Increased HPA responsiveness and reduced pituitary sensitivity in the face of chronic stress","Total elimination of glucocorticoids with a 500% lymphocyte spike","The HPA axis becomes identical to a non-stressed pet's within 20 minutes"],"a":1,"e":"Chronic stress produces increased adrenal responsiveness alongside reduced pituitary sensitivity, confirming dysregulation."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"An intake cat lies motionless with eyes shut and ignores food for 12 hours. The supervisor notes it is sleeping and relaxed. How should this be re-evaluated?","o":["This is feigned sleep, a coping mechanism in highly stressed cats, not evidence of relaxation","The assessment is correct; motionless cats are always comfortable","The cat is displaying offensive aggression","This indicates good stress enhancing sensory function"],"a":0,"e":"Feigned sleep is a profound stress indicator. Recording it as relaxation is an anthropomorphic error."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A clinic designs primary feline holding cages. What are the minimum floor-space and vertical requirements?","o":["Minimum 4 sq ft with perches on the floor","25 sq ft with perches of bright white reflective plastic","Floor-space parameters are optional","Minimum 8 to 11 sq ft of unobstructed floor space; every cat must have a perch at least 12 inches wide and raised 13 to 14 inches off the cage floor"],"a":2,"e":"The 8 to 11 sq ft minimum ensures separate functional zones; the perch dimensions come from the notes. Full detail is in the Facility hub."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A shelter purchases new cage materials. Given feline vision, which design is correct?","o":["Bright white glossy plastics to maximise stimulation","A pure red and orange palette","Matte black on all surfaces","Avoid bright white fluorescing materials; select matte finishes in light blues, greens, and violets"],"a":1,"e":"Cats are dichromatic and transmit some UV; fluorescing white is jarring, reds and oranges appear grey. Blues, greens, and violets are preferred."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"What minimum spatial density satisfies feline group-housing welfare guidelines?","o":["5 sq ft per cat","Density is irrelevant if cats are unrelated","A maximum of 1 cat per 100 sq ft","A minimum of 18 sq ft of floor space per cat"],"a":3,"e":"18 sq ft per cat minimises territorial aggression. Selection, monitoring, and resource distribution also matter."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Morning rounds in a communal cat room. Which cat should be removed immediately?","o":["A cat consistently hiding, feigning sleep, failing to eat, or sitting hunched with its back to the group","A cat actively exploring and using a scratching pad","A cat in short play bouts with a paper ball","A cat resting relaxed on a high perch facing the room"],"a":0,"e":"Persistent hiding, feigned sleep, anorexia, and hunching indicate failure to cope; immediate removal protects welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"An owned cat extracted from a trap arches its back, has fully dilated pupils, ears flat, and strikes at the cage door. How should this profile be interpreted?","o":["This is a true genetic feral cat","This is good stress enhancing digestion","Chronic boredom requiring a large colony room","Even the tamest owned cats can exhibit defensive behaviours indistinguishable from feral cats when trapped and highly stressed"],"a":2,"e":"Acute stress makes tame cats look feral; allow calm-down time before assessing personality."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A shelter houses incoming cats in the same room as canine intake runs. How does this affect feline welfare?","o":["It is beneficial for predatory stimulation","Cats are unaffected because their sound threshold is 10 dB","Wire-mesh floors make the layout acceptable","Proximity to barking dogs impairs feline welfare; cats should be housed as far from dogs as possible"],"a":3,"e":"Canine noise and odour fields are inescapable sensory threats for cats, directly degrading their welfare."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"The guidelines state feral cats confined long-term in the shelter cannot express natural behaviours. If return-to-field is unavailable in a timely manner, what is mandated?","o":["Permanent confinement in a 4 sq ft cage","Humane euthanasia, because long-term shelter confinement of feral cats is unacceptable","Intensive 60-minute daily close-contact petting","Transfer to a canine intake ward"],"a":1,"e":"Feral cats cannot engage in natural or rewarding behaviour in shelter confinement; euthanasia is humane when RTF is not timely."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A cat turns its litter box upside down, shreds newspaper at night, and crouches behind its bed. This represents:","o":["A high-energy play sequence indicating excellent welfare","An attempt to hide and conceal itself when appropriate hiding options are not provided","Territorial status aggression","An immediate SAM epinephrine collapse"],"a":1,"e":"Without proper hiding structures, cats improvise concealment by flipping furnishings and crouching behind objects."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A manager claims hiding boxes increase length of stay and reduce adoption visibility. Published data shows:","o":["The manager is correct; hiding delays adoption","Hiding boxes should be banned because they cause aggression","Providing hiding spots had no negative effect on LOS or adoption, and no difference in time to adoption was shown","Hiding is only helpful for dogs"],"a":2,"e":"Hiding boxes protect welfare without increasing LOS or reducing adoption rates."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Based on first-week stress timelines, what management policy is most appropriate for a new shelter dog?","o":["Perform all assessments and restraint procedures within the first 24 hours","Defer non-essential stressful activities during the first week to allow adaptation and positive relationship building","Keep lights on for 24 hours continuously during the first week","Avoid all human contact and withhold food for 5 days"],"a":1,"e":"Deferring non-essential stressors in the first week lets the animal adapt and lets staff build positive associations."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A long-stay dog shows continuous door scratching, floor digging, whining, and complete loss of interest in food or toys. This is clinically defined as:","o":["Acute tolerable stress resolving in 20 minutes","A normal age-related shift independent of LOS","Status aggression from a hyper-responsive pituitary","Behavioural deterioration secondary to chronic stress and temporal monotony, which can culminate in a depression-like affective state"],"a":2,"e":"Prolonged spatial and temporal monotony leads to deterioration, escape stereotypies, and eventually wakeful depression."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"When dogs move from a shelter run to a short-term foster stay, accelerometer data shows:","o":["They rest significantly more in the home compared to baseline shelter activity","They stop sleeping entirely from novelty","Plasma cortisol doubles within 90 minutes","Repetitive play bouncing increases regardless of age"],"a":0,"e":"Rest rebound in foster reflects a less stimulating environment; shelter dogs were more active than pet dogs when humans were absent."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Why should all long-term resident animals be spayed or neutered, from a stress perspective?","o":["Sterilisation prevents SAM activation during restraint","Intact reproductive status introduces stress from heat and sex drive, decreasing appetite and increasing spraying, marking, fighting, and emotional stress","Neutering instantly stops all play aggression","Sterilisation reduces minimum floor space from 11 to 2 sq ft"],"a":3,"e":"Hormonal reproductive drives compound confinement stress through appetite loss, urine marking, and fighting."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A newly confined cat's cortisol decreases significantly by day 3. This kinetic pattern reflects:","o":["Permanent toxic brain atrophy within 72 hours","The cat converting all glucocorticoids into ACTH","Cortisol often decreases in the first 3 days as the animal regains homeostatic balance after transport and novelty","The SAM axis shutting down epinephrine production"],"a":1,"e":"The initial cortisol drop reflects rebalancing of homeostasis after the acute shock of capture, transport, and placement."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"Stress behaviours in the first 2 weeks differ by age. Which observation matches published data?","o":["Older dogs chew bedding and play bounce while young puppies pant and bark","All ages display identical signs","Dogs that chewed bedding and repeatedly play bounced tended to be younger; dogs that panted and barked tended to be older","Geriatric dogs display zero behavioural signs of stress"],"a":2,"e":"Younger dogs express stress through displacement chewing and bouncing; older dogs through panting and barking."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"For pro-social dogs facing a long-term hold, which housing model should be prioritised?","o":["Strict single-housing isolation with zero out-of-cage time","Cages less than 2 inches off the ground next to drainage units","A daily high-intensity startle stimulus","Group housing, because disease and aggression concerns are minimal in well-managed programmes"],"a":3,"e":"Well-managed group housing provides social and sensory outlets with minimal risk; behaviour stabilises within 1 to 2 days of adding a new dog."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A clinical monitoring tool aims to track activity changes from intake to distinguish emotional states. Which three states should be differentiated?","o":["Sensitisation (increased activity), habituation (increased or decreased activity), or depression-like affective states","Epinephrine depletion, ACTH hypertrophy, or pupillary constriction","Physical trauma, toxic trigger stacking, or good stress","Functional-zone monopolisation, coprophagy, or context-learning deletion"],"a":0,"e":"Sequential activity tracking distinguishes sensitisation, habituation, and depression-like shutdown."},{"type":"mcq","domain":"Behavioral Health","sub":"Stress","q":"A highly stressed dog arrived 48 hours ago. A technician plans an elective, non-emergency grooming. Applying the stop-and-reassess protocol:","o":["Proceed immediately because human preferences take precedence","Apply a severe startle stimulus first","Assess needs versus wants, prioritise the animal's emotional needs, and defer the non-essential procedure","Isolate in a dark room without food for 24 hours"],"a":1,"e":"Stop-and-reassess means evaluating whether the activity is a need or a want and deferring non-essential stressors."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"A facility is redesigning its intake wards to minimise environmental stress. Which spatial configuration is explicitly mandated by standard shelter housing guidelines?","o":["Prey species must be housed completely away from predatory species at all times, and cats must be housed away from dogs","Feral cats should be group-housed with social cats to facilitate behavioural modelling","Puppies and kittens under 12 weeks must be housed adjacent to adult quarantine wards to build immunity","Animals should be reassigned to different enclosures daily to maximise exploration"],"a":0,"e":"Strict predator-prey separation, with cats housed away from dogs, is a core housing standard; daily reassignment and mixed feral housing are both contraindicated."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"A manager wants an operational protocol to reduce afternoon ambient noise and kennel stress. Which routine modification is recommended?","o":["Opening the ward to public walk-throughs for 4 continuous hours to habituate the dogs","Continuously reassigning caregivers throughout the day to prevent single-person attachments","Setting 1 to 2 hours aside each afternoon for a predictable break from stimulation, with public and staff access restricted","Running high-pressure hosing units next to occupied kennels to provide white noise"],"a":2,"e":"A scheduled afternoon quiet period lowers ward noise; continuous public access, caregiver churn, and added machinery noise all worsen it."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Ambient sound in a high-intake canine ward is recorded at 102 dB. Which statement reflects the veterinary and regulatory context?","o":["This level is safe for dogs because their ears are less sensitive to high frequencies than human ears","OSHA recommends humans wear protection above 100 dB for 2 hours per day; dogs have more sensitive hearing and are often exposed for much longer in shelters","Commercial calming music is proven to drop kennel levels below 40 dB within one hour","Levels above 100 dB are beneficial because they induce social facilitation that reduces barking"],"a":1,"e":"Greater than 100 dB exceeds the human OSHA threshold, and dogs with keener hearing endure it far longer, making it a major auditory stressor."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"A kennelled dog shows severe stereotypic pacing, barrier bouncing, and continuous high-intensity barking. Which housing adjustment is most appropriate?","o":["Move the dog to a kennel directly beside the main public entrance and intake doors","Maintain the dog in total isolation under continuous 24-hour high-intensity light","Completely seal the kennel front with solid black plastic to remove all visual access","House the dog away from doors and high-traffic areas and use partial barriers to limit, but not fully block, visual access"],"a":3,"e":"Reactive dogs do better away from traffic with partial visual barriers; fully blocking vision can paradoxically increase barking, and high-traffic or constant light worsens arousal."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"A new group-housing room is being designed for social, healthy adult cats. What are the minimum personal-space and functional-distance requirements?","o":["Cats require at least 3 feet of personal space, with at least 20 inches between functional areas such as feeding and elimination","Cats require 10 feet of personal space, and litter boxes must be 5 feet apart","A minimum of 100 square feet per cat, with no structures permitted","Personal space is irrelevant to cats because they have a rigid, non-flexible social structure"],"a":0,"e":"Cats keep about a 3-foot personal-space zone and need at least 20 inches between functional stations to prevent resource monopolisation and tension."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What is the minimum acceptable floor space for individual adult cat housing under the ASV Standards of Care?","o":["Individual adult cat housing under 8 sq ft is unacceptable, and 11 sq ft or more is ideal","Under 4 sq ft is acceptable if vertical perches are provided","Exactly 18 sq ft is the individual minimum","Floor space is irrelevant if climbing structures exist"],"a":0,"e":"The ASV sets under 8 sq ft as unacceptable for individual adult cats, with 11 sq ft or more ideal; 18 sq ft is the per-cat cohousing figure."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"When cohousing adult cats, what minimum floor space per cat does the ASV recommend?","o":["At least 8 sq ft per cat","At least 18 sq ft of floor space per adult cat","Exactly 4 sq ft per cat","No minimum applies if perches are added"],"a":1,"e":"Cohousing requires more space than individual housing: a minimum of 18 sq ft per adult cat."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"An individual primary enclosure must allow which set of normal postural adjustments?","o":["Only enough room to sit and eat","Room to crouch and rotate the head only","Standing and walking several steps, sitting normally, lying at full body length, and holding the tail fully erect","Space to stand only, provided turnout is offered twice weekly"],"a":2,"e":"The ASV minimum requires all of these normal postural adjustments within the enclosure itself."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What is the principal welfare and operational benefit of multi-compartment (double-sided) housing?","o":["It lets staff stack more animals per ward","It removes the need for any daily cleaning","It eliminates the need for species separation","It separates resting and eating from elimination, increases choice and control, enables touch-free spot cleaning, reduces fomite transmission, and improves personnel safety"],"a":3,"e":"For these reasons the ASV recommends multi-compartment enclosures for the majority of sheltered animals."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Multi-compartment housing is described as particularly important for which animals?","o":["Newly admitted, fractious, quarantined, sick, and juvenile animals","Only geriatric animals on legal hold","Only animals already cleared for adoption","Only animals housed for under 24 hours"],"a":0,"e":"These groups benefit most, and touch-free daily care is essential where handling poses a welfare or safety risk."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"How does the ASV regard primary enclosures with wire-mesh bottoms or slatted floors?","o":["Preferred, because they improve drainage","Unacceptable, because they can cause pain, discomfort, and injury","Acceptable only for cats","Required for isolation wards"],"a":1,"e":"Wire-mesh or slatted floors are unacceptable under the ASV Standards of Care."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What is the ASV position on tethering as a method of confinement?","o":["Acceptable for large dogs during cleaning","Acceptable overnight if bedding is provided","Unacceptable for any animal","Acceptable only in outdoor runs"],"a":2,"e":"Tethering is unacceptable confinement; alternatives include multi-compartment housing, timed walks, and enclosed exercise areas."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"When may animals be housed in spaces not intended for housing, such as bathrooms or hallways?","o":["Whenever the adoption floor is full","During peak intake season","Routinely, provided they are cleaned daily","Only for a brief emergency situation"],"a":3,"e":"Non-housing spaces may be used only briefly in an emergency, distinct from planned multiuse spaces such as office housing."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"How should feline housing units be positioned within a ward?","o":["Elevated off the floor at roughly human eye level, which lowers stress and eases monitoring","On the floor, to give a sense of security","Stacked four high to save space","Facing each other to encourage social contact"],"a":0,"e":"Cats prefer raised surfaces; eye-level housing reduces stress and improves interaction and observation."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"To limit respiratory droplet transmission between cats, how should cat cages be arranged?","o":["Directly facing one another at any distance","Facing away from each other, or spaced more than 4 ft apart","Touching, to share warmth","Stacked vertically with shared ventilation"],"a":1,"e":"The ASV recommends cat cages face away or be more than 4 ft (1.2 m) apart to reduce droplet spread during sneezing, coughing, or vocalising."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What is the documented effect of providing shelter cats with an in-enclosure hiding place?","o":["Cats hide permanently and never socialise","Cats become more aggressive toward staff","Cats spend less time trying to hide and are more likely to approach adopters","Cats stop using the litter box"],"a":2,"e":"A hide (den, towel-covered perch, box, or partial door cover) gives the choice to be unseen and paradoxically increases approachable behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What in-enclosure hiding options does the ASV list for dogs?","o":["A second food bowl","A heat lamp","Open chain-link on all sides","A covered crate within the enclosure or a visual barrier over part of the kennel front"],"a":3,"e":"All dogs, especially young, small, fearful, or anxious ones, should be able to hide within the enclosure."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Why must a feline litter box accommodate the cat's entire body and allow proper posturing?","o":["Boxes that are too small impair welfare and can lead to house-soiling behaviour","Larger boxes reduce ventilation","Small boxes prevent climbing","Box size has no welfare relevance"],"a":0,"e":"An undersized litter box is a welfare and house-soiling risk; the box must fit the whole cat."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"For animals remaining in the shelter long term (more than about 2 weeks), what does the ASV require?","o":["Reduced handling to save resources","Additional space, enrichment, and choice within the enclosure, with foster care particularly valuable","Permanent single-compartment housing","Relocation to a warehouse-style room"],"a":1,"e":"Enhanced housing and enrichment are required for longer stays, and foster is especially valuable for protracted holds or long-term medical care."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What ambient temperature range does the ASV specify for shelter housing areas?","o":["32 F to 50 F","85 F to 100 F","64 F to 80 F (18 C to 26.6 C)","50 F to 60 F only"],"a":2,"e":"The ASV range is 64 F to 80 F, with individual monitoring and adjustments as needed."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What relative humidity range does the ASV recommend for animal housing?","o":["Below 20%","Above 90%","Exactly 100%","30% to 70%"],"a":3,"e":"Relative humidity should be maintained between 30% and 70%."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What is the standard recommended ventilation rate for animal facilities?","o":["10 to 20 fresh-air room air exchanges per hour, adjusted for population density","1 to 2 air exchanges per day","50 air exchanges per minute","Ventilation is unnecessary when barred doors are used"],"a":0,"e":"The ASV standard is 10 to 20 fresh-air air exchanges per hour; a facility at full capacity may need higher rates because animals add heat, humidity, and carbon dioxide."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"How should air from canine isolation areas be handled?","o":["Recirculated through the main ward to save energy","Exhausted outside and not recirculated, while feline isolation air handling is a lower priority","Sealed completely with no air exchange","Vented into the adoption lobby"],"a":1,"e":"Canine respiratory pathogens spread readily by air, so isolation air is exhausted outdoors; cats transmit airborne pathogens less readily."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Which enclosure door type does the ASV prefer for ventilation, and what is required if units are fully enclosed?","o":["Plexiglass doors, with no extra requirement","Solid doors, which need no ventilation","Barred doors are preferred for airflow and interaction, while fully enclosed units require individual mechanical ventilation","Open-topped doors, which never need ventilation"],"a":2,"e":"Barred doors aid airflow and allow interaction and training; sealed units must have their own mechanical ventilation."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"If lights must remain on after dark for safety or regulation, which fixture does the ASV prefer?","o":["Bright white light at full intensity","Continuous high-intensity blue light","Strobing light to deter intruders","A red-orange light, which creates a darker space for animals and supports more normal sleep"],"a":3,"e":"Because of how dog and cat eyes function, red-orange light at night appears darker to them and allows more normal sleep."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"When natural light is unavailable, how should artificial lighting be designed?","o":["To approximate natural light in duration and intensity to support circadian rhythms","To stay on continuously at maximum brightness","To remain off during all daylight-equivalent hours","To cycle rapidly to stimulate activity"],"a":0,"e":"Artificial light should mimic natural light in duration and intensity to maintain circadian rhythms."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Why should preventing visual contact between dogs not be used as the sole strategy to reduce barking?","o":["Because dogs cannot see other dogs anyway","Because barking is multifactorial, so facility design, environmental management, enrichment, and behaviour modification are all needed","Because blocking vision is illegal","Because barking is unrelated to vision in every case"],"a":1,"e":"The causes and solutions for barking are multifactorial; visual blocking alone is insufficient, and fully blocking vision can even increase barking in some dogs."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"Which kind of shelter noise is singled out as especially stressful, even at otherwise reasonable volumes?","o":["A steady background fan hum","Soft classical music","Sudden or unpredictable sounds such as slamming cage doors or tossing metal bowls","Distant outdoor traffic"],"a":2,"e":"Sudden, unpredictable noise is particularly stressful, so quiet handling and thoughtful material choices matter."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"What ward layout does the ASV recommend when designing shelter housing?","o":["A single large warehouse-style room for efficiency","One enormous open ward with central drainage","Outdoor-only housing in all climates","Avoid warehouse-type rooms and use multiple smaller wards with fewer enclosures each"],"a":3,"e":"Small wards reduce noise and disease transmission, add flexibility, and allow close individual monitoring."},{"type":"mcq","domain":"Behavioral Health","sub":"Facility/Environment","q":"When no dedicated isolation room exists, what makeshift separation does the ASV describe for contagious dogs?","o":["Housing them in the lobby behind a curtain","Mixing them with healthy dogs to build immunity","Housing them at least 25 ft from unaffected dog enclosures and covering the enclosure doors","Placing them in airline crates in a hallway"],"a":2,"e":"Makeshift separation of at least 25 ft (7.6 m) plus door covers is less effective than true isolation but better than nothing."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"How is learning defined in the source material?","o":["A process by which experience leads to long-lasting changes in behaviour","A purely genetic trait fixed at birth that cannot change","A temporary change lasting only a few minutes","A reflex that cannot be modified by experience"],"a":0,"e":"Learning is experience producing long-lasting behavioural change, the adaptive mechanism that lets animals cope with a changing environment."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Why is it best to teach a shelter animal only one new behaviour at a time?","o":["Because innate behaviours cannot be learned","Working memory is temporary and limited, so competing new material can disrupt consolidation into long-term memory","Because long-term memory is also temporary and unstable","Because animals cannot attend to any stimulus while housed"],"a":1,"e":"Working memory is fragile and easily disrupted during transfer to long-term memory, so one new behaviour at a time consolidates best."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"When does consolidation of new learning into long-term memory mainly occur?","o":["Only during active training sessions","During the calcium influx just before an action potential","During sleep, with REM sleep assisting long-term memory formation","Only when the animal is fully awake and highly aroused"],"a":2,"e":"Hippocampal circuits that fire during learning re-fire during sleep, and REM assists long-term memory formation."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A senior dog loses a few neurons in a learned circuit but still performs the behaviour. Which principle explains this resilience?","o":["Biological preparedness","State-dependent memory","Sensitisation","Equipotentiality, where the remaining cells carry on the work"],"a":3,"e":"Equipotentiality is the redundancy across circuits that protects a memory if some cells are lost."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog gradually stops reacting to a repeated, harmless overhead door bang. This is:","o":["Habituation","Sensitisation","Positive punishment","Imprinting"],"a":0,"e":"Habituation is a reduced or absent response to a harmless stimulus after repeated exposure, used widely to lower fear of harmless things."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A cat reacts more and more strongly each time a particular carrier is wheeled past its kennel. This escalating response is:","o":["Habituation","Latent learning","Sensitisation","Negative reinforcement"],"a":2,"e":"Sensitisation is the opposite of habituation: the response grows with repeated exposure."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which statement best describes imprinting?","o":["A reversible preference that can form at any age","An irreversible attachment that forms only during a short, definite sensitive period early in life","A response that simply weakens with repetition","A consequence-driven, goal-directed behaviour"],"a":1,"e":"Imprinting is irreversible, restricted to a brief early sensitive period, and most often cited in birds and neonatal foals."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"In Pavlov's work, which pairing represents the unconditioned stimulus and its unconditioned (reflex) response?","o":["A metronome, then sitting on cue","A clicker, then completing an agility sequence","A leash jerk, then choosing to lie down","Food, then salivation"],"a":3,"e":"Food (the unconditioned stimulus) elicits salivation, an involuntary unlearned reflex."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"For a neutral stimulus to become a conditioned stimulus most effectively, when should it be presented relative to the unconditioned stimulus?","o":["After the unconditioned stimulus (backward)","Immediately before the unconditioned stimulus","At the same instant (simultaneous)","Several hours before the unconditioned stimulus"],"a":1,"e":"The association forms best when the neutral stimulus immediately precedes the US; backward, simultaneous, or long-delayed pairings are weaker."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A clicker has been paired with food so that it predicts a reward. It can now be used to:","o":["Act as a secondary reinforcer for operant behaviour","Serve as an unconditioned stimulus","Produce learned helplessness","Reverse an animal's imprinting"],"a":0,"e":"A conditioned stimulus that predicts something wanted can act as a secondary reinforcer, which is how clicker training works."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Pairing a place, person, or object with something that evokes fear, joy, or anxiety creates what?","o":["A three-term contingency","Sensitisation","A conditioned emotional response (CER)","Latent learning"],"a":2,"e":"A CER is an involuntary emotional shift produced by associating a cue with an emotionally evocative event."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A handler delivers a painful leash jerk while shouting a cue, and the dog later fears unrelated cues that were present at the time. This unintended effect is:","o":["Habituation","Cue poisoning, a negative association spreading to environmental cues","Negative punishment","Equipotentiality"],"a":1,"e":"Aversive events can poison neutral cues, handlers, or contexts, producing fear or aggression toward them later."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"An animal forms a lasting fear of a place after a single, perceived life-threatening event there. This is:","o":["Habituation","Latent learning","Negative reinforcement","One-trial learning"],"a":3,"e":"One-trial learning occurs when a single intense or life-threatening experience produces durable learning."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog struggles to learn a static sit when asked to perform it instead of chasing a fast-moving object. The static behaviour is:","o":["Contraprepared, because it conflicts with an innate predatory response","Innately reinforced","Habituated","Imprinted"],"a":0,"e":"Contraprepared behaviours run counter to innate responses and are therefore harder to train."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog reliably responds to a cue in the quiet training room but not in the busy adoption ward. This retrieval failure reflects:","o":["Equipotentiality","Imprinting","State-dependent memory and weak contextual generalisation","Positive reinforcement"],"a":2,"e":"Memories are bound to internal and external state and context; changing the context can block retrieval, so cues should be trained in varied settings."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A cat explores a new communal room with no obvious change in behaviour, then days later uses a vertical escape route it had mapped during that exploration. This is:","o":["Sensitisation","Latent learning via cognitive mapping","Positive punishment","Serial motor imprinting"],"a":1,"e":"Latent learning is acquired without being shown until needed, such as a spatial map built during exploration."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which statement best defines operant conditioning?","o":["An involuntary reflex elicited by a stimulus","An irreversible early-life attachment","A reduced response after repeated harmless exposure","A goal-directed behaviour that operates on the environment and is strengthened or weakened by its consequences"],"a":3,"e":"Operant behaviours act on the environment to produce consequences that strengthen or weaken them."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"What is the three-term contingency of operant conditioning, in order?","o":["Behaviour, antecedent, consequence","Antecedent, behaviour, consequence","Consequence, behaviour, antecedent","Stimulus, response, reflex"],"a":1,"e":"Operant learning runs antecedent, then behaviour, then consequence."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Adding a food reward after a dog sits, so that sitting becomes more frequent, is which operant quadrant?","o":["Positive reinforcement","Positive punishment","Negative reinforcement","Negative punishment"],"a":0,"e":"Positive reinforcement adds something pleasant to increase a behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Adding an aversive stimulus after a behaviour so that the behaviour decreases is:","o":["Positive reinforcement","Negative reinforcement","Positive punishment","Negative punishment"],"a":2,"e":"Positive punishment adds an aversive to decrease a behaviour, and is the quadrant humane training avoids."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Removing an aversive stimulus in order to increase a behaviour is:","o":["Negative reinforcement","Positive reinforcement","Positive punishment","Habituation"],"a":0,"e":"Negative reinforcement removes something aversive to strengthen a behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Briefly withholding attention so that an attention-seeking behaviour decreases is best classified as:","o":["Positive reinforcement","Positive punishment","Negative reinforcement","Negative punishment"],"a":3,"e":"Negative punishment removes something the animal wants in order to decrease a behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Under the ASV approach to training, which method is preferred?","o":["Positive punishment, for faster results","Flooding, to build tolerance","Positive reinforcement, following Least Intrusive Minimally Aversive (LIMA) principles","Negative reinforcement as the routine default"],"a":2,"e":"ASV bases training on LIMA and the Humane Hierarchy, with positive reinforcement preferred; it improves welfare and adoption likelihood."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which is a valid argument against using positive punishment?","o":["It speeds up consolidation of long-term memory","It can increase fear and anxiety, poison contextual cues, fail to address the emotional cause, and reduce the ability to learn","It is the only method that can create a conditioned emotional response","It shifts motor learning back to the hippocampus"],"a":1,"e":"Positive punishment harms welfare and learning, can create fear and cue poisoning, and does not address the underlying emotion."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"How does negative punishment differ from positive punishment in humane training?","o":["Negative punishment removes something the animal wants (for example withholding a treat) and is generally acceptable, whereas positive punishment adds an aversive","They are identical in method and acceptability","Negative punishment adds an aversive while positive punishment removes a reward","Negative punishment is always more harmful than positive punishment"],"a":0,"e":"Negative punishment withdraws a desired item or attention and is generally considered acceptable; positive punishment applies an aversive and is avoided."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A reactive dog is exposed to an intense, continuous aversive sound with no way to escape or reduce it. This technique and its main psychological risk are:","o":["Negative reinforcement; equipotentiality","Habituation; sensitisation","Flooding; learned helplessness","Latent learning; cue poisoning"],"a":2,"e":"Flooding presents an intense stimulus without escape and risks inducing learned helplessness."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"What is the humane alternative to flooding or punishment for a fearful animal?","o":["Continuous high-intensity exposure until the fear stops","Positive punishment of the fear response","Imprinting the animal onto a new handler","Desensitisation and counter-conditioning, gradually changing the underlying emotional response"],"a":3,"e":"Systematic desensitisation paired with counter-conditioning changes the emotional response below threshold, the preferred humane approach."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"When is a behavioural assessment most informative for a newly admitted shelter animal?","o":["After acute intake stress has settled, rather than in the first 24 to 48 hours when arousal distorts behaviour","Within the first hour of arrival, while arousal is highest","Only during REM sleep","Never, because shelter behaviour carries no useful information"],"a":0,"e":"Acute intake stress transiently alters arousal and behaviour, so very early testing is unreliable; this links to the Assessment and Decision Making subdomain."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which sequence reflects sound socialisation for preventing behaviour problems?","o":["Isolation from all stimuli until 16 weeks of age","A single caretaker and deliberate avoidance of novelty","Early gentle handling, varied positive exposure during the socialisation period, continued through the juvenile period, while avoiding negative experiences","Positive punishment of unwanted behaviours from birth"],"a":2,"e":"Prevention rests on early handling and varied positive exposure across the socialisation and juvenile periods, while avoiding negative experiences."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which set matches the source's steps for setting a pet up for success?","o":["Flooding, restraint, and isolation","Positive punishment and confinement only","Heavy molecular neuro-training drills","Reward-based training, supervision, meeting species-specific needs, and prevention or confinement"],"a":3,"e":"Setting up for success uses positive reinforcement, supervision, provision for the animal's needs, and prevention or confinement."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An owner-surrendered 2-year-old German Shepherd shows severe, out-of-context tail chasing and spinning within 48 hours of intake. This repetitive, out-of-context pattern is categorised as a:","o":["Compulsive or stereotypic behaviour, typically worsened by confinement and transitional stress","Normal exploratory coping sequence expected in adult herding breeds","A state of good stress that enhances immediate memory and visual cognition","Direct clinical sign of acute acetylcholine depletion at the neuromuscular junction"],"a":0,"e":"Repetitive, out-of-context behaviours like tail chasing and spinning are compulsive or stereotypic and emerge with confinement and transitional stress."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A shelter veterinarian starts daily fluoxetine for an anxious dog still trembling and hiding 3 days after intake. Which condition must be met to satisfy clinical and ASV standards?","o":["The medication is given as a standalone treatment with no change to enrichment or housing","Fluoxetine is combined immediately with an MAOI on day one to speed onset","It is combined with a concurrent BMOD program, staff trained to monitor side effects, and a clear follow-up plan","Behavioural medication is used only once the animal is already well adjusted to shelter life"],"a":2,"e":"Psychotropic medication must be paired with BMOD, trained monitoring, and a follow-up plan; it is never a standalone fix."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A Doberman on baseline clomipramine for flank-sucking is transitioned to the MAOI selegiline. What protocol prevents severe neurovascular toxicity?","o":["Start selegiline at ten times the label dose to override clomipramine","Switch directly with zero washout interval","Give high-dose intravenous amitraz during the transition","Observe a strict 2-week washout when switching from a TCA to an MAOI"],"a":3,"e":"A 2-week washout is required when moving from a TCA like clomipramine to an MAOI to avoid serotonin syndrome."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog with a history of fear-related defensive snapping is given alprazolam before a medical exam. What side effect must the handler anticipate from the mechanism of action?","o":["Permanent loss of appetite and rapid weight loss","Behavioural disinhibition, which reduces conscious inhibition and can increase the display of aggression","Idiosyncratic acute renal failure with profound polyuria","Instant hypertrophy of the thyroid gland"],"a":1,"e":"Benzodiazepines can cause disinhibition by reducing conscious executive control, which can increase aggression."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog receives a double dose of fluoxetine plus trazodone and tramadol, then develops agitation, tremors, confusion, tachycardia, diarrhoea, and hyperthermia. This is most consistent with:","o":["Serotonin syndrome from combining multiple drugs that enhance serotonin","Acute acetylcholine toxicosis from muscarinic receptor degradation","Paradoxical alpha-2 adrenergic autoreceptor exhaustion","Normal behavioural habituation to a fixed schedule"],"a":0,"e":"Serotonin syndrome is caused by stacking serotonergic drugs such as an SSRI, a SARI, and tramadol."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog on trazodone 3 mg/kg q12h for kennel stress needs a higher dose for transport. What pharmacological concept matters most?","o":["Trazodone is a pure irreversible MAO-A inhibitor at all doses","High doses eliminate serotonin syndrome risk when mixed with fluoxetine","It reduces anxiety at the lower end of the range; at higher doses the effect is less specific and hypnotic effects and side effects increase","If swallowed rather than absorbed oromucosally it becomes 500 times more potent"],"a":2,"e":"Trazodone is dose-dependent: targeted anxiolysis at low doses, less specificity and more sedation and side effects at high doses."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A canine plan uses human oral liquid gabapentin for fear-related arousal on walks. What label warning must be checked?","o":["Ensure it contains at least 50% ethanol for tranquillisation","Verify alpha-casozepine for NMDA binding","Confirm artificial dyes for low-light stability","Avoid formulations containing xylitol, a common ingredient in human liquid gabapentin that is toxic to dogs"],"a":3,"e":"Human liquid gabapentin often contains xylitol, which is toxic to dogs, so a xylitol-free product is required."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which medication is the primary specific serotonin-receptor antagonist used to treat severe serotonin toxicity?","o":["Diazepam","Cyproheptadine","Atipamezole","Flumazenil"],"a":1,"e":"Cyproheptadine is the specific serotonin antagonist used for severe serotonin syndrome."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat on the SSRI fluoxetine for 4 weeks must switch to selegiline. What is the mandatory washout window?","o":["A strict 5-week washout, because fluoxetine has a long half-life","No washout, since fluoxetine clears within 12 hours","Exactly 48 hours if IV fluids are given","A 1-week washout only if the cat is unsterilised"],"a":0,"e":"Fluoxetine's long half-life requires a 5-week washout before starting an MAOI."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat is prescribed oral diazepam for territorial anxiety and spraying. What rare organ toxicosis must be screened for before and 3 to 5 days after starting?","o":["Idiopathic acute pulmonary emphysema","Bilateral cataracts from raised intraocular pressure","Acute hepatic necrosis (fatal liver failure)","Bone marrow suppression with panleukopenia"],"a":2,"e":"Oral diazepam can cause rare idiosyncratic acute hepatic necrosis in cats, so baseline and recheck liver panels are advised."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which side-effect profile reflects the potent anticholinergic activity of TCAs like clomipramine?","o":["Profuse salivation, severe diarrhoea, miosis, bradycardia","Severe hypoglycaemia with loss of peripheral white cells","Brain atrophy restricted to the cerebellum","Dry mouth, urine retention, constipation, mydriasis, and increased heart rate"],"a":3,"e":"Anticholinergic effects give dry mouth, urine retention, constipation, mydriasis, and tachycardia."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An oromucosal dexmedetomidine gel is chosen for noise aversion. What directive must handlers follow?","o":["Mix it into a large volume of canned food and have the dog swallow it","Apply it to the oral mucosa; if swallowed, the effect is much lower due to high first-pass metabolism","Apply it to the external ear canal for systemic vasodilation","Dose it 24 hours after the noise event has ended"],"a":1,"e":"The gel must absorb across the oral mucosa; swallowing it triggers first-pass metabolism and reduces efficacy."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which option correctly matches a neurotransmitter with its role?","o":["Glutamate is the primary excitatory transmitter, and its NMDA receptors can be blocked by ketamine for pain-associated anxiety","GABA is the primary excitatory transmitter that makes neurons fire","Acetylcholine is an amino-acid derivative used only to synthesise epinephrine","Dopamine is the primary inhibitory transmitter that prevents seizures"],"a":0,"e":"Glutamate is the primary excitatory transmitter; NMDA blockers like ketamine address pain-associated anxiety."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An animal's reaction is defined by Provocation, Proportion, and Persistence. Within what timeframe should a normal, resilient dog recover from a mild to moderate stressor?","o":["At least 90 to 120 minutes of continuous panting and pacing","Exactly 5 days, matching fluoxetine's half-life","Within a couple of minutes at most; longer suggests an abnormal pattern or compromised welfare","It should remain hyper-aroused indefinitely"],"a":2,"e":"A normal dog recovers within a couple of minutes; prolonged arousal suggests abnormality or a welfare problem."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Buspirone (an azapirone) is considered for a fearful cat. What is its mechanism, and what is it not indicated for?","o":["An irreversible NMDA blocker, contraindicated for confidence building","A potent alpha-1 antagonist, contraindicated for feline urine marking","A massive acetylcholine releaser, contraindicated for seniors","A partial serotonin 5-HT1A agonist, not indicated for intense panic, severe phobias, or compulsive conditions"],"a":3,"e":"Buspirone is a partial 5-HT1A agonist for mild anxiety and confidence building, ineffective for panic, phobias, and compulsion."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which statement correctly describes GABA and the drugs that act on it?","o":["GABA is the main excitatory transmitter and is blocked by benzodiazepines","GABA is the major inhibitory transmitter; benzodiazepines enhance it at the GABA-A receptor, and flumazenil reverses them","GABA is synthesised from serotonin and controls platelet aggregation","Increasing GABA activity is stimulant and raises locomotor activity"],"a":1,"e":"GABA is the major inhibitory transmitter; benzodiazepines act at GABA-A and flumazenil is the reversal agent."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog is started on fluoxetine for separation anxiety. Which dosing and onset statement is correct?","o":["Dogs are dosed about 1 to 2 mg/kg once daily (cats 0.5 to 1 mg/kg), with full effect taking 4 to 8 weeks","The effect is immediate, within hours of the first dose","It is dosed three times daily and acts within 30 minutes","It is used only on an as-needed basis before stress events"],"a":0,"e":"Fluoxetine is a baseline SSRI: dogs 1 to 2 mg/kg SID (cats 0.5 to 1 mg/kg SID), full effect in 4 to 8 weeks, not situational."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Clomipramine (Clomicalm) is being considered for a dog. Which statement is accurate?","o":["It is the drug of choice for owner-related aggression","It has no serotonergic activity and acts only on histamine","It is licensed for canine separation anxiety with a behaviour plan but is ineffective for owner-related aggression","It works within minutes and needs no behaviour plan"],"a":2,"e":"Clomipramine is licensed for canine separation anxiety with a behaviour plan, is the most serotonergic TCA, and is ineffective for owner-related aggression."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which benzodiazepine and pairing is most useful for acute fears, panic, and canine noise phobia?","o":["Oxazepam, because it is the longest-acting appetite stimulant","Chlordiazepoxide, the first choice for chronic generalised anxiety","Clorazepate, given only as a single lifetime dose","Alprazolam, which suits acute fears and panic and works well with clomipramine for noise phobia"],"a":3,"e":"Alprazolam, short-acting and potent, is most useful for acute fear and panic and pairs with clomipramine for noise phobia."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat has been on a benzodiazepine for several weeks and the drug is to be stopped. What is correct?","o":["Stop abruptly, since benzodiazepines have no withdrawal","Wean gradually (about 10 to 25% per week) to avoid rebound anxiety, anorexia, tremors, or seizures","Double the dose for one day, then stop","Switch directly to an MAOI with no washout"],"a":1,"e":"Benzodiazepines must always be weaned (about 10 to 25% per week) to avoid withdrawal anxiety, anorexia, tremors, and seizures."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"An alpha-2 agonist (clonidine or dexmedetomidine) causes excessive sedation and hypotension. What is true of this class?","o":["It inhibits NE release in the locus ceruleus and can be reversed with atipamezole","It stimulates NE release in the locus ceruleus to raise arousal","It has no cardiovascular effects and needs no monitoring","It is a serotonin reuptake inhibitor reversed by flumazenil"],"a":0,"e":"Alpha-2 agonists inhibit NE release in the locus ceruleus (sedation, analgesia, anxiolysis) and are reversed with atipamezole."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which drug blocks the physical signs of fear by blocking the effects of adrenaline (epinephrine)?","o":["Cyproheptadine, a serotonin agonist","Selegiline, which increases epinephrine breakdown","Propranolol, a beta-blocker that blocks epinephrine at beta-receptors","Gabapentin, which binds the NMDA receptor"],"a":2,"e":"Propranolol is a beta-blocker that blocks epinephrine at beta-receptors, reducing the physical signs of fear."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A shelter dog needs an appetite-stimulating behavioural agent less likely to cause serotonin syndrome. Which statement about mirtazapine is correct?","o":["It is an SSRI dosed at 30 mg/kg daily","It must never be used when appetite is a concern","It is a benzodiazepine reversed by atipamezole","It is a serotonin receptor antagonist with antiemetic and appetite-stimulating effects, dosed up to a maximum of 30 mg total daily in dogs"],"a":3,"e":"Mirtazapine is a tetracyclic serotonin receptor antagonist (lower serotonin-syndrome risk) with antiemetic and appetite effects; the canine dose is about 0.6 to 1.3 mg/kg q24h to a maximum of 30 mg total daily (not 30 mg/kg)."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Selegiline is selected for an aging dog with cognitive decline. Which statement is accurate?","o":["It is a benzodiazepine that acts within minutes","It selectively inhibits MAO-B and is used for canine cognitive dysfunction, with a required washout from serotonergic drugs","It is an SSRI safe to combine with fluoxetine immediately","It is an alpha-2 agonist reversed by atipamezole"],"a":1,"e":"Selegiline selectively inhibits MAO-B and is used for canine cognitive dysfunction; serotonergic drugs need a washout (5 weeks from fluoxetine, 2 weeks from clomipramine) first."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"How do pheromone products (cat F3 and F4 or dog-appeasing pheromone) act, and how strong is the evidence?","o":["Through the vomeronasal organ, with weak to moderate evidence for reducing anxiety in some settings","Through the main olfactory epithelium, with strong proven efficacy","By systemic absorption after ingestion, acting like a benzodiazepine","Only in dogs, never in cats"],"a":0,"e":"Pheromones act mainly via the vomeronasal organ, with weak to moderate evidence for reducing anxiety."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Alpha-casozepine (a milk protein derivative such as Zylkene) is considered. Which statement is correct?","o":["The dietary formulation works equally well in large dogs and cats","It is contraindicated in all cats","It is structurally similar to GABA, and the dietary form is helpful mainly in cats because large dogs would need too much","It is a controlled benzodiazepine requiring weaning"],"a":2,"e":"Alpha-casozepine is structurally similar to GABA; the dietary form is useful mainly in cats, since large dogs would need an impractical amount."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"L-theanine is offered as a calming supplement. What is its proposed action?","o":["It increases glutamate and decreases GABA","It is a potent irreversible MAOI","It blocks the GABA-A receptor like flumazenil","It reduces the effect of glutamate and increases GABA and dopamine"],"a":3,"e":"L-theanine, a green tea derivative, reduces glutamate effect and increases GABA and dopamine, and is used for chronic anxiety."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Lithium is considered for a dog with severe unpredictable aggression. What must be remembered?","o":["It is very safe with a wide therapeutic margin","It is highly toxic with a narrow therapeutic window (about 0.8 to 1.2 mEq/L) and needs blood-level monitoring","It is a first-line situational anxiolytic","It has no renal or gastrointestinal effects"],"a":1,"e":"Lithium is highly toxic with a narrow therapeutic window (about 0.8 to 1.2 mEq/L), so blood levels must be monitored."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog on clomipramine for a compulsive disorder has improved substantially. How should therapy be managed?","o":["Continue at least 3 weeks after a satisfactory reduction, then wean over 3 to 4 weeks while continuing behaviour modification","Stop the drug immediately once any improvement is seen","Increase to the maximum dose indefinitely","Switch straight to an MAOI with no washout"],"a":0,"e":"For compulsive disorders, continue at least 3 weeks after a satisfactory reduction, then wean over 3 to 4 weeks with ongoing behaviour modification."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog shows high physiologic arousal (hackles up, dilated pupils, hard panting, heavy salivation, poor recovery). Which agent may suit better?","o":["Trazodone, because arousal always responds best to a SARI","Buspirone, the drug of choice for panic","Clonidine may be better than trazodone for this high-arousal, poor-recovery picture","An antihistamine, which is contraindicated in arousal"],"a":2,"e":"For marked physiologic arousal with poor recovery, clonidine (an alpha-2 agonist) may work better than trazodone."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Why are published studies currently unable to identify definitive behavioural risk factors for dog surrender?","o":["Unwanted behaviours occur just as commonly in dogs living successfully in homes as in those being surrendered, so the baseline prevalence in the general pet population is often ignored","Most shelters do not track behavioural data at the time of intake","Behavioural traits are entirely dependent on whether the animal was received as a gift","Dogs consistently express identical behavioural profiles regardless of husbandry changes or new environments"],"a":0,"e":"Without knowing prevalence in retained homes, you cannot tell whether a behaviour raises surrender risk or is simply common across all pet dogs."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A Japanese pet-supply company survey revealed what unexpected reality about pet dog behaviour in successful homes?","o":["Fewer than 5% of owners reported any issues with their dogs","Exactly 48% of owners reported severe, unprovoked aggression","No less than 86% of respondents reported at least one troublesome behaviour, with barking and pica causing the most concern","Dogs obtained as gifts displayed zero troublesome behaviours compared with those from breeders"],"a":2,"e":"The survey showed 86% of successful owners navigate troublesome behaviours (often barking and pica) without ending the relationship."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What happens to the odds ratio for daily or weekly inappropriate elimination once a multivariate analysis controls for training, veterinary visits, sterilisation, and work expectations?","o":["The risk increases by 200%, proving it is an isolated behavioural issue","The odds ratio is reduced by about 50%, and other behavioural variables become not statistically significant","The variable shifts to predict future inter-cat aggression","The statistical significance remains completely unaltered"],"a":1,"e":"Adjusting for human and care variables cut the relative risk by about half, showing how confounders distort raw behavioural statistics."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is the predictive value of a relinquishing owner's report of their dog's behaviour for how the dog behaves in a new adoptive home?","o":["Excellent predictive value, matching subsequent accounts over 95% of the time","High predictive value, but only for intact male dogs under one year of age","Accurate for house-soiling but completely invalid for barking","Poor predictive value, leaving open whether dogs change behaviour across environments or owners simply vary in perception and definition"],"a":3,"e":"Owner reports predict poorly because behaviour shifts across environments and definitions of a problem behaviour vary between people."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which parameter was found to significantly increase a shelter dog's likelihood of adoption?","o":["Maintaining proximity to the person and engaging in play (fetch or tug) when invited","Approaching the front of the kennel or making direct eye contact with visitors","Vocalising or barking loudly as a release for excitement and frustration","Remaining completely motionless at the back of the enclosure"],"a":0,"e":"Physical appearance drives initial choice, but proximity and play with the adopter are what statistically boost adoption."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"During a meet-and-greet, how did experimenters actively promote proximity between a prospective adopter and a shelter dog?","o":["They withheld food for 24 hours before the interaction","They placed a visual barrier between dog and adopter for the first 15 minutes","They auditioned dogs for toy preferences, supplied the preferred toy to the adopter, and gave them the leash to hold","They left the adopter alone in an outdoor elimination space with no instructions"],"a":2,"e":"Auditioning toy preference, supplying the toy, and handing over the leash kept the adopter and dog in close contact."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is the primary mechanism behind chronic indoor elimination developing within a shelter kennel?","o":["A rapid increase in territorial behaviour caused by sterilisation","Limited space and lack of outdoor time cause habituation, so the dog loses its natural aversion to eliminating near eating and sleeping areas","Frustration-driven negative reinforcement from passing kennel walkers","Severe intraspecies social deprivation triggering a drop in caloric intake"],"a":1,"e":"Confinement and inadequate turnout force soiling of the immediate living space, breaking down natural cleanliness and erasing prior training."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A kennelled dog barks and lunges whenever other dogs walk past. Through what learning mechanism is this strengthened?","o":["Positive reinforcement via a high-value treat schedule","Habituation to the concrete and dirt substrates of the kennel","Classical conditioning linked to a hiding box","Negative reinforcement, because the passing dog continues away, relieving the dog's frustration and rewarding the display"],"a":3,"e":"The passing stimulus inevitably leaves, relieving frustration and reinforcing the barking through negative reinforcement."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How is barking and lunging at passing dogs in a kennel ward best addressed?","o":["Visual barriers to prevent exposure that cannot lead to social interaction, plus playgroups or group social walks","Opening all kennel grates to allow maximum face-to-face visual exposure","Confining the dogs in small crates inside a completely silent room","Hand-delivering high-value rewards only when the dog jumps and mouths the gate"],"a":0,"e":"Passive interventions (visual barriers) stop the frustration trigger, while playgroups and social walks meet the dog's social needs."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A volunteer always ignores a dog that jumps and mouths during greetings, yet the behaviour persists. Why does it remain reinforced?","o":["The dog is expressing an involuntary skeletal reflex caused by ambient noise","The behaviour is driven by a lack of access to preferred plush toys","Even when ignored, the dog is still rewarded with the most exciting event of its day: being taken out of the kennel","The walker is accidentally changing substrates from concrete to dirt too quickly"],"a":2,"e":"The outing itself is the reinforcer, so ignoring the jump does not remove the reward that maintains it."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"When training a dog to stop jumping by walking out of sight for 10 to 15 seconds, what determines the speed of learning?","o":["Giving a low-dose behaviour medication before the walker appears","The contingency must be applied consistently; every exception requires more trials to regain lost ground","Maintaining close eye contact with the dog while exiting","Applying the protocol only first thing in the morning"],"a":1,"e":"Consistency is essential; allowing exceptions reverts the dog to an intermittent schedule and erases progress."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What substrate should an outdoor elimination space for shelter dogs provide?","o":["Identical concrete flooring to the indoor kennel to promote habituation","Open wire-mesh to maximise visual contact with passing dogs","A single elevated plastic perch","Both dirt and concrete, because dogs form strong associations with the substrate from their previous homes"],"a":3,"e":"Offering both dirt and concrete matches whatever substrate the dog associates with elimination and supports outdoor success."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"In environments with high human disturbance, mammals generally show what behavioural shift?","o":["A general tendency to increase nocturnal activity across habitats, taxa, and types of human activity","A significant increase in daytime exploratory and predatory behaviour","A complete deactivation of sympathetic nervous system feedback loops","An expansion of home ranges to remain closer to high-volume urban traffic"],"a":0,"e":"Broad multi-taxa data show that high human disturbance pushes mammals toward nocturnal activity."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"A collar-mounted camera study (as reported in your notes) found what about hunting habits and success?","o":["Cats achieved a 100% success rate when targeting adult birds","Cats killed an average of 45 animals per 24 hours regardless of habitat","73% of hunting occurred between dusk and dawn, and females and night-hunting cats were more successful at killing prey","Hunting occurred exclusively during peak daylight near human housing"],"a":2,"e":"Per your notes, most hunting was dusk to dawn, with females and night hunters more successful. Note the figures are flagged for verification against the primary source."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which subset of outdoor cats achieved the lowest hunting success rate?","o":["Cats hunting mice and rats in semi-desert landscapes","Cats attempting to kill birds, succeeding only 17% of the time","Cats hunting at night near undeveloped habitats","Spayed female cats operating around structured feeding stations"],"a":1,"e":"Cats were least successful on birds (about 17%); night hunting near undeveloped habitat was actually the more successful pattern."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What is an unintended consequence of uncoordinated, pulsed, or short-term lethal control of community cats?","o":["An immediate and permanent collapse of local rodent populations","A dramatic reduction in seasonal vegetation variation","An immediate shift in feline activity from nocturnal to crepuscular","Compensatory migration, where removal lets new animals move into the vacated area while resources remain"],"a":3,"e":"Removal vacates territory while food and shelter persist, so nearby cats migrate in (compensatory migration)."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Removing community cats can trigger a mesopredator release. What does this imply for native birds?","o":["Cat removal can cause a spike in prey species (rats, mice, rabbits) that may worsen survival pressure on native birds","Bird survival immediately doubles due to the absence of mammalian predators","Surviving birds shift to nesting exclusively on concrete substrates","Local predators stop hunting entirely due to reduced resource competition"],"a":0,"e":"Releasing lower prey species from predation can increase rodents and paradoxically harm the very birds the cull intended to protect."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which group of outdoor cats had the smallest home ranges and the highest population densities?","o":["Managed community cats that underwent TNR and were fed on a schedule","Cats far from human housing that were highly nocturnal and lived in small groups","Cats found near houses, crepuscular, largely thought to be owned cats allowed outside during the day","Intact female cats in heavily vegetated landscapes with zero seasonal variation"],"a":2,"e":"Owned cats let out by day stayed close to structures, giving small ranges and high densities near homes."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What spatial and activity profile was observed in the smallest groups of outdoor cats?","o":["The smallest home ranges and high activity during peak daylight","They had the largest home ranges, were more nocturnal, and were found farther from human housing","Clustered exclusively near houses on strictly crepuscular schedules","They ceased all hunting and relied entirely on human feeders"],"a":1,"e":"The smallest, unmanaged groups adapted with the largest ranges, nocturnal activity, and avoidance of human housing."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How does the physical presence of the human caretaker affect feline feeding dynamics?","o":["Cats flee immediately and refuse to eat for an average of 12 minutes","Feline aggression spikes, disrupting the established colony hierarchy","The cats completely alter their preferred spatial organisation around the station","Cats eat more and stay longer when the person is present (about 4 minutes) than when absent (about 12 seconds)"],"a":3,"e":"A present feeder is associated with longer, larger feeding bouts (4 minutes vs 12 seconds), changing spatial behaviour at the site."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Why should community-cat caretakers set a fixed feeding schedule and remain present while cats eat?","o":["It increases the likelihood that cats eat promptly, decreasing the risk of attracting pest species to the feeding area","It expands the cats' home range away from human housing","It induces disinhibition that makes the cats easier to trap for research","It causes an immediate cessation of nocturnal hunting"],"a":0,"e":"Staying present ensures prompt eating and leaves no scraps to draw rodents or other pests."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What behavioural change was confirmed in dominant community cats after successful sterilisation?","o":["They completely lost their hierarchy position and the colony collapsed","They shifted from crepuscular activity to strictly diurnal schedules","They were more likely to show less aggression and more affiliative behaviour, and urine spraying decreased dramatically or stopped","They increased their daily distances travelled to expand the colony's range"],"a":2,"e":"Sterilisation reduced aggression and spraying and increased affiliative behaviour while the overall hierarchy stayed similar."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Which community cat should generally NOT be admitted into an animal shelter enclosure?","o":["A well-socialised pet cat whose outdoor habitat was destroyed by an emergency demolition","Community cats thriving where they are, not in danger from unusual events, and not impacting vulnerable wildlife","An offensively aggressive adult cat that needs immediate medical triage for a severe injury","A kitten under two months of age meeting the criteria for a socialisation programme"],"a":1,"e":"Thriving, healthy community cats facing no immediate threat do not belong in a shelter; admitting them strains resources without improving their outcome."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"The Tiny Spirit programme was designed to address what operational challenge?","o":["Managing older cats that develop acute hepatic necrosis from oral medication","Senior kennelled dogs that develop barrier frustration and tail-chasing","Preventing compensatory migration among free-roaming cats near undeveloped habitats","Kittens (about 2 lb, about 2 months) that show aggression, do well in foster, but regress to defensive, unsocialised behaviour back in the shelter"],"a":3,"e":"The programme targets undersocialised kittens that plateau and regress when returned to a standard shelter environment."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"Where does the Tiny Spirit programme place undersocialised kitten kennels to speed habituation and maximise visibility?","o":["In the busiest public part of the facility, positioned off the ground at eye level","In an isolated, low-traffic basement ward with minimal lighting","Hand-carried continuously by a single foster volunteer for 14 consecutive days","Directly adjacent to a high-volume canine runway for interspecies habituation"],"a":0,"e":"Eye-level placement in the busiest area gives continuous passive exposure to people, forcing rapid habituation."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What micro-environmental feature is provided inside a Tiny Spirit kitten's enclosure to balance exposure with stress management?","o":["A completely transparent glass door left unlocked 24 hours a day","A wire-mesh sub-floor elevated above a concrete drainage canal","A small hiding box about 2 inches high","A device playing continuous loud music at 120 dB"],"a":2,"e":"A low hiding box lets the kitten conceal itself to manage stress while staying low enough to remain visible and accessible."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"During the first 48 hours of the Tiny Spirit protocol, what rule governs human access and cage doors?","o":["Kennel doors are left wide open to encourage exploration of the facility","Kennel doors are locked except for cleaning and structured staff interaction","The kittens are housed in large communal rooms","Adopters are encouraged to handle the kittens without counsellor supervision"],"a":1,"e":"Locked doors for the first 48 hours give a controlled environment, protecting the kitten from random disruption during early socialisation."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"What interaction method is used to socialise defensive kittens during the initial 48 hours?","o":["Delivering treats via an automated dispenser every 30 seconds","Ignoring all activity until the kitten stops hissing for a full 24-hour cycle","Placing the kitten inside an active playgroup with adult unsterilised cats","A toothbrush on a tongue depressor, 1 minute at a time, 10 times a day, plus burrito wrapping and cheek stroking"],"a":3,"e":"High-frequency, low-intensity sessions with a toothbrush, plus gentle wrapping and handling, build safe contact."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"How is positive reinforcement applied during Tiny Spirit socialisation sessions?","o":["Handlers deliver a piece of raw meat immediately after the kitten vocalises","Handlers play an audiobook at conversational volume for 15 minutes","Handlers leave the kitten alone immediately after it relaxes","Handlers transfer the kitten directly into an outdoor dirt elimination space"],"a":2,"e":"Removing the interaction the moment the kitten relaxes uses relief as the reinforcer for calmer behaviour."},{"type":"mcq","domain":"Behavioral Health","sub":"Assessment & Decision","q":"If a Tiny Spirit kitten makes no clear progress after the first 48 hours, what action is required?","o":["Re-evaluate the kitten for the programme, aiming to adopt out, or sterilise and return, within 2 weeks","Double the daily toothbrushing trials to 20 per day indefinitely","Confine the kitten permanently in an isolated wire kennel with zero human access","Move the kennel onto the floor of a high-volume canine housing ward"],"a":0,"e":"Kittens that stall are re-evaluated promptly to ensure adoption, or sterilisation and return, within a strict 2-week window."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A 3-year-old dog experiences progressively worsening panic during thunderstorms, with the threshold for panic falling over years of unmanaged exposure so that even minor noises now trigger reactions. Which neurobiological phenomenon best explains this progressive worsening?","o":["The kindling effect","Habituation","Sensitisation by simple repetition","Spontaneous recovery"],"a":0,"e":"Kindling describes repeated intermittent sub-threshold or threshold stimulation of brain circuits progressively LOWERING the threshold for future stimulation, producing intensification of phobic reactions over time. This is why unmanaged exposure to phobic stimuli (storm after storm without intervention) makes subsequent reactions WORSE."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Chronic stress and sustained cortisol elevation cause cellular damage and volume reduction in which brain structure, removing its negative-feedback control of the HPA axis and impairing contextual processing?","o":["Amygdala","Locus ceruleus","Hippocampus","Nucleus accumbens"],"a":2,"e":"The hippocampus normally suppresses the HPA axis. Chronic cortisol exposure damages hippocampal neurons, removes the brake, and produces a vicious cycle of high cortisol. Reduced hippocampal volume is documented in PTSD and chronic-stress animals."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which brainstem nucleus contains the highest concentration of noradrenergic neurons, receives direct excitatory input from the amygdala, and is implicated in panic attacks and sleep and arousal disorders?","o":["Dorsal raphe nucleus","Ventral tegmental area","Lateral hypothalamus","Locus ceruleus"],"a":3,"e":"The locus ceruleus, in the pontine gray matter, has the highest concentration of NE neurons in the brain and projects to the cortex, hypothalamus, hippocampus, and raphe nuclei. Stimulation triggers NE release driving systemic sympathetic panic and vigilance."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Virtually all serotonin input to the mammalian forebrain originates from which structural cluster, which modulates fear, anxiety, autonomic responses, and the cognitive and motor inhibition of fight or flight?","o":["Basolateral amygdala","Dorsal and medial raphe nuclei","Prefrontal cortex","Striatum"],"a":1,"e":"The dorsal and medial raphe nuclei sit in the centromedial brainstem, part of the reticular formation, and provide virtually all serotonergic innervation to the forebrain."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which structure acts as the central hub for integrating fear-evoking sensory triggers and encoding fear conditioning, driving the fast subcortical pathway that initiates a physiological startle response before the cortex can analyse the threat?","o":["Amygdala","Thalamus","Hippocampus","Cerebellum"],"a":0,"e":"The amygdala processes external and internal fear-evoking triggers and triggers an immediate physiologic startle BEFORE the slower cortical pathway analyses whether the threat is real. It is also the central site for fear conditioning by integrating prior learning and memory."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog described as \"stubbornly refusing commands outside\" is observed standing rigidly with heavy panting, dilated pupils, lip licking, and a tucked tail. What state best describes this picture?","o":["Learned compliance","Dominance display","Fear response with behavioural shutdown (the freeze response)","Anxiety without identifiable stimulus"],"a":2,"e":"Rigid posture, panting, mydriasis, displacement licking, and a tucked tail are the freeze response, a fear state that is often misread as the dog being calm or stubborn. Fear cluster: aggression, cowering, shaking, freezing, escape."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"How does anxiety differ fundamentally from a fear response?","o":["Anxiety involves only physiological signs; fear involves only behavioural signs","Fear is always maladaptive; anxiety is always adaptive","Anxiety is peripheral and fear is purely cortical","Anxiety is anticipation of a future threat and can occur without an immediate stimulus; fear is a response to an active, present stimulus"],"a":3,"e":"Anxiety is anticipation; fear is response to a present stimulus. The presence of an identifiable fear-eliciting stimulus is the differentiator."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A cat suddenly enters an out-of-proportion hysteria attack when a plastic bag rustles, with a disorganised panic state and no real threat. This is best classified as:","o":["An adaptive fear response","A phobia","Cognitive decline","Dominance aggression"],"a":1,"e":"Phobias are profound, excessive, abnormal responses that occur without a true threat or are vastly out of proportion. They are maladaptive and intensify with repeated exposure."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which set of signs represents purely PHYSIOLOGICAL (autonomic) markers of an active canine anxiety or fear state?","o":["Trembling, hypersalivation, and increased heart and respiratory rates","Pacing, restlessness, and resource guarding","Submissive urination, growling, and biting","Feigning sleep, yawning, and structural destruction"],"a":0,"e":"Trembling, hypersalivation, and increased HR and RR are autonomic markers of sympathetic activation. Pacing and yawning are behavioural; growling and resource guarding are behavioural responses."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog exhibits constant hypervigilance and environmental scanning even inside a quiet home. This presentation most closely aligns with:","o":["Acute situational fear","A structural phobia","Chronic generalised anxiety","Predatory drive"],"a":2,"e":"Constant scanning and hypervigilance in a safe environment reflect generalised anxiety, a pervasive state of apprehension rather than acute stimulus-driven fear."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A clinic-phobic dog is taken to the parking lot at a distance where the dog stays relaxed and eats high-value treats, without entering the building. This specific step is an example of:","o":["Flooding","Habituation","Extinction burst","Systematic desensitisation"],"a":3,"e":"Systematic desensitisation is controlled exposure at an intensity (or distance, volume, familiarity) that is WEAKER than what triggers fear, so the pet remains subthreshold. Pairing with treats simultaneously adds counterconditioning."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog is trained to look at its owner and perform a relaxed sit-stay in exchange for high-value food when a delivery truck passes. Training an alternative behaviour that is incompatible with the fear response is called:","o":["Classical conditioning","Response substitution","Negative reinforcement","Learned helplessness"],"a":1,"e":"Response substitution replaces an unacceptable fear or aggression response with an acceptable, calm, physically incompatible behaviour, reinforced with high-value rewards."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"What is the fundamental mechanism of counterconditioning in behavioural medicine?","o":["Changing the underlying emotional response (the \"feeling\") about a stimulus by pairing it with a high-value reward","Preventing escape until the animal stops showing fear","Using a physical tool such as a prong collar to correct undesirable vocalisation","Teaching the animal to ignore all external sounds through environmental enrichment"],"a":0,"e":"Counterconditioning pairs the fear-eliciting stimulus with high-value reward at subthreshold exposures to convert a negative conditioned emotional response into a positive one."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"During a gradient session with an assistant, the assistant takes a step closer and the dog stiffens, lip licks, and refuses the treat. What is the correct protocol adjustment?","o":["Hold the assistant in place and wait for the dog to take the treat","Verbally correct the dog with a sharp \"No\" to discourage the anxious posture","Step the assistant back to the previous distance, allow the dog to calm down, and resume training at that lower threshold","Have the assistant wave their hands to distract the dog out of the fear state"],"a":2,"e":"The threshold rule: if the pet shows fear, the exposure must stop, the stimulus must drop back to a successful level, the dog must recover, and training resumes BELOW threshold."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Why is positive punishment (electronic collars, scruffing, yelling) strictly contraindicated in fear- or anxiety-based behaviour problems?","o":["It accelerates habituation too rapidly","It has 100% efficacy but is ethically unappealing","It converts an anxiety disorder into a purely compulsive stereotypy","It directly exacerbates the negative emotional state, increases stress, and can trigger defensive aggression"],"a":3,"e":"Punishment ADDS to a negative emotional state. Fear is the emotional driver; making the pet more afraid worsens the underlying problem and increases defensive aggression risk."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A storm-phobic dog needs an environmental management plan. Which setup is most appropriate?","o":["Crating the dog in an outdoor kennel to acclimate to weather","Designing an insulated indoor safe space, using light-proof shades to block lightning, and playing white noise or loud rhythmic music to mask thunder","Placing a shock collar to disrupt pacing","Confining the dog in a small mirrored bathroom with the exhaust fan off"],"a":1,"e":"Indoor safe space with sight and sound barriers (light-proof shades and masking sound such as white noise, fan, TV, music with a distracting beat) is the standard environmental intervention. The pet should also be able to RETREAT there voluntarily."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which commercial calming aid uses gentle constant body pressure to achieve a calming effect in anxious or phobic dogs?","o":["Thundershirt / Anxiety Wrap","Calming Goggles","Storm Defender Cape","Mutt Muffs"],"a":0,"e":"Pressure wraps (Thundershirt, Anxiety Wrap) provide sustained gentle torso pressure with a somatosensory calming effect. Mutt Muffs are ear protection; Calming Goggles are visual; Storm Defender Cape is claimed to reduce electrical-charge sensation."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"When using an audio recording of fireworks to desensitise a dog, how should the initial volume be set?","o":["Maximum, to induce brief panic followed by exhaustion","Moderate, where the dog whines briefly but is easily comforted","At a barely perceptible, muted level where the dog notices but shows zero signs of anxiety","Alternating high and low to keep the dog guessing"],"a":2,"e":"Desensitisation must start SUBTHRESHOLD. Subthreshold means the dog notices the sound but shows no physiological or behavioural anxiety. Any sign of anxiety means drop the volume."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"During an unpredicted severe thunderstorm, a phobic dog begins to panic and the owner calls asking whether to ignore it. What is the most appropriate advice?","o":["Ignore the dog entirely, since comforting always reinforces and worsens fear","Physically pin the dog down to force relaxation","Take the dog outside on a leash to prove the storm is harmless","Stage a \"storm party\" of tossing high-value toys and treats to distract, or safely guide the dog to its pre-trained safe space; ignore mild signs only if the dog can recover spontaneously"],"a":3,"e":"Active intervention via distraction or structural support helps break the panic cycle; comforting a panicking dog does NOT reinforce fear because fear is an involuntary emotion, not an operant behaviour. Ignore mild signs only if the dog can recover spontaneously."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"What is the primary function of a SETTLE CUE in a behavioural modification protocol for noise phobias?","o":["To punish the dog for barking or pacing during an event","To train the dog to voluntarily retreat to its designated safe space and exhibit relaxed physiology on command, in a completely calm environment, BEFORE an actual event occurs","To force the dog into tonic immobility","To signal to the dog that an event medication has been hidden in its food"],"a":1,"e":"The settle cue must be trained in calm conditions BEFORE any storm. You cannot teach a complex behaviour to a panicking dog, so the settling behaviour is built first and recalled during events."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog is started on daily fluoxetine for generalised anxiety. How long until maximal therapeutic effect should the owner expect?","o":["2 to 4 weeks, up to 8 weeks for maximal effect","12 to 24 hours","3 to 5 days","6 months exactly"],"a":0,"e":"Onset of SSRIs is 2 to 4 weeks; maximal clinical effect may take up to 8 weeks. Central receptor downregulation requires weeks to manifest behaviourally."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog on daily fluoxetine needs clomipramine added as an adjunct. What dose adjustment is recommended to prevent toxicity?","o":["Increase the fluoxetine dose by 50%","Maintain both at full standard doses","Decrease the clomipramine dose by 10 to 25%","Decrease the clomipramine dose by 75%"],"a":2,"e":"Fluoxetine inhibits cytochrome P450 enzymes, slowing TCA clearance and raising serum clomipramine. The TCA dose must be reduced by 10 to 25%. With sertraline plus TCA, the reduction is 50%."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which TCA is the most selective serotonin reuptake inhibitor and is used widely for compulsive disorders, stereotypic behaviours, and deep-seated anxieties including feline psychogenic alopecia?","o":["Selegiline","Alprazolam","Acepromazine","Clomipramine"],"a":3,"e":"Clomipramine is the most selective serotonin reuptake inhibitor of the TCAs and is the standard choice for compulsive disorders. Other TCAs (amitriptyline, doxepin, nortriptyline) have less SSRI effect and are less effective for these conditions."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Why is a strict washout required between an MAOI (selegiline) and an SSRI (fluoxetine)?","o":["Fluoxetine completely deactivates the liver enzymes that clear MAOIs","Concurrent use or inadequate washout can induce a fatal serotonin syndrome","Combining them causes irreversible acute renal failure","The combination prevents behaviour modification from working for up to a year"],"a":1,"e":"MAOI prevents serotonin breakdown; SSRI prevents reuptake. Combined effect is uncontrolled serotonin accumulation, with potentially fatal serotonin syndrome."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which signs would most highly raise suspicion of acute serotonin syndrome in a canine patient on multiple serotonergic drugs?","o":["Tremors, hyperthermia, rigid muscle hypertonicity, mental status changes, and diarrhoea","Bradycardia, hypothermia, and constipation","Severe sedation, urinary retention, and pale mucous membranes","Increased appetite, polyuria, and polydipsia"],"a":0,"e":"Serotonin syndrome combines neuromuscular signs (tremors, rigidity), autonomic signs (hyperthermia, diarrhoea), and mental status changes."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which drug class is highly effective for immediate situational panic given 1 to 2 hours pre-event but carries a risk of disinhibition that may increase the confidence and bite risk of an underlying aggressive animal?","o":["SSRIs (e.g. fluoxetine)","Phenothiazines (e.g. acepromazine)","Benzodiazepines (e.g. alprazolam, diazepam)","TCAs (e.g. amitriptyline)"],"a":2,"e":"Benzodiazepines act rapidly via GABA-A potentiation but can disinhibit, removing the fear or anxiety brake that was previously suppressing aggression. They also inhibit learning and memory."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Why is acepromazine no longer considered appropriate as monotherapy for treating noise or storm phobia?","o":["It causes profound hypertension and arrhythmias in all canine breeds","It is an irreversible competitive antagonist of serotonin receptors","It has a 4-week lag time before any sedative effect","It provides chemical tranquilisation and motor immobilisation without providing anxiolysis, leaving the animal terrified but unable to escape, and may heighten auditory sensitivity"],"a":3,"e":"Acepromazine is a dopamine antagonist; it blocks motor output without alleviating the emotional panic, leaving the dog frozen but still terrified. Modern veterinary behavioural medicine treats this as a welfare and management problem. Not in your PDF directly but standard clinical teaching."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"When transitioning a dog from daily fluoxetine to an MAOI, what washout duration is required due to the long half-life of fluoxetine and its active metabolite norfluoxetine?","o":["24 hours","5 to 6 weeks","3 to 5 days","2 weeks"],"a":1,"e":"Fluoxetine's active metabolite norfluoxetine has an exceptionally long half-life, so a 5 to 6 week washout is required before starting an MAOI like selegiline to avoid serotonin syndrome."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"A dog responds well after 6 months of daily fluoxetine and systematic desensitisation. What is the correct next step regarding medication?","o":["Maintain medication for at least another 6 months (or indefinitely if chronic or compulsive); if tapering, do so gradually over several months","Discontinue the drug abruptly tomorrow since the behaviour has resolved","Double the dose for 2 weeks to \"lock in\" the behavioural changes before stopping","Switch directly to an MAOI to maintain long-term compliance"],"a":0,"e":"Premature or abrupt discontinuation triggers relapse. Continue at least 6 months past response and longer if chronic, and taper gradually over months rather than abruptly."},{"type":"mcq","domain":"Behavioral Health","sub":"Common Behavior Problems","q":"Which drug is an alpha-2 adrenergic agonist used as a short-term as-needed situational anxiolytic or as a safe daily adjunct to SSRI or TCA therapy in highly reactive dogs?","o":["Sertraline","Selegiline","Clonidine","Paroxetine"],"a":2,"e":"Clonidine is an alpha-2 agonist that decreases central NE output; useful situationally before a known trigger or as a daily adjunct to a maintenance SSRI or TCA."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A shelter clinician evaluates one-time 20 to 30 minute petting or play sessions to mitigate acute shelter stress. What is the physiological limitation of these short sessions?","o":["Cortisol reductions occur during the session but do not persist an hour later, and multiple sessions add no further benefit","They trigger an immediate, dangerous surge in baseline heart rate","They induce permanent structural changes in the vomeronasal organ","Cortisol remains unaltered unless the volunteer is also reading aloud"],"a":0,"e":"The cortisol benefit of a short petting session is temporary (does not persist an hour later) and does not stack across multiple sessions."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A 15 minute petting session is implemented for newly admitted dogs. Which subpopulation will see a significant cortisol reduction from this single intervention?","o":["Dogs surrendered directly by their owners","Dogs undergoing a 5-week medication washout","Dogs brought into the shelter as strays","Female dogs in novel pair housing"],"a":2,"e":"A 15 minute petting session lowered cortisol only in dogs admitted as strays, not in owner-relinquished dogs."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which behavioural pattern in dogs returning from short foster stays is cited as cautiously optimistic evidence for foster?","o":["More sedentary, avoided social contact, stopped yawning","Increased pica and stereotypic kennel pacing","More obedient, sought social interaction with handlers, responded readily to cues, jumped on strangers and barked less, yawned more","Elevated aggression at the kennel front toward unfamiliar dogs"],"a":2,"e":"Post-foster dogs showed improved obedience, more social initiative, fewer jumps on strangers, less barking, and more yawning."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"In-kennel and out-of-kennel training programs were evaluated. What benefits and what consistency rule emerged?","o":["Reduces pica; if training stops for 24 hours, door jumping returns to baseline","In-kennel training increases sitting, lying down, and quiet behaviour; out-of-kennel training reduces aggression. If training stops for 1 week, aggression returns to pre-intervention levels","Reduces barking by 142 times, but only via classical conditioning","Decreases locomotor activity only if performed for exactly 20 seconds"],"a":1,"e":"Training works in both contexts but is consistency-dependent; aggression rebounds after just 1 week of cessation."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"In a 3-month, 211-dog group-housing study, what were the conflict and stereotypy outcomes?","o":["Conflicts occurred daily and increased length of stay by 50%","Group housing caused a massive cortisol rise compared with novel solo housing","Stereotypies occurred at identical rates (10%) across solo and group housing","Only 5 incidents (light wounds) occurred; 10% of singly-housed dogs showed stereotypies while no group-housed dogs did"],"a":3,"e":"Group housing was safe (5 minor incidents over 3 months) and suppressed stereotypies (0% versus 10% in solo)."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What fraction of a typical shelter dog population is generally suitable and available for daily off-leash interaction with other dogs?","o":["Less than 1/3","More than 90% of the population","Exactly half","Only dogs in foster for 8 weeks"],"a":0,"e":"Fewer than one-third of typical shelter dogs are suitable and available for off-leash daily group interaction."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which object did kenneled shelter dogs prefer over other in-kennel toy options?","o":["A standard tennis ball","A soft squeaky plush bone","A robust Nylabone","A braided rope toy"],"a":2,"e":"In the kennel-toy preference study, dogs showed greater preference for the Nylabone over the other options."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"When given a choice between robust and soft destructible toys, how did shelter dogs interact?","o":["100% interacted exclusively with robust toys for the whole session","Dogs spent the longest with a tennis ball and least with the squeaky bone","Robust toys completely prevented stereotypic pacing","Only about 35% interacted with the robust selections (averaging 2 minutes); more than 3/4 of dogs spent 25% of the 15 minute session on soft destructible toys, most time on squeaky bones and plushy toys, least time on the tennis ball"],"a":3,"e":"Most dogs preferred soft, destructible options (squeaky bone, plush) over robust toys, and the tennis ball was the least engaging soft option."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How did classical music compare with heavy metal in kenneled dogs?","o":["Classical increased standing and vocalisation; heavy metal increased resting","Classical led to more resting, less standing, and more quiet behaviour; heavy metal increased body shaking, barking, and reduced resting","Heavy metal decreased barking frequency by 12 dB","Both genres produced an identical 30% drop in average barking amplitude"],"a":1,"e":"Classical functions as an acoustic sedative; heavy metal triggers shaking and barking and reduces rest."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A 2017 study tested five genres (classical, pop, soft rock, reggae, Motown) with shelter dogs. What happened during music and what happened immediately after it stopped?","o":["Regardless of genre, dogs spent more time lying down and less time standing; however, dogs were 142 times more likely to bark after the music stopped","Dogs barked continuously during music but slept once it stopped","Reggae and Motown increased standing; classical and pop increased pacing","Barking frequency dropped during music and stayed low for an hour after"],"a":0,"e":"The Bowman 2017 five-genre study found all genres increased lying down during play, but a 142-fold spike in barking immediately followed the music stopping."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which essential oil scents are sedating, and which are stimulating, in scented-cloth studies?","o":["Peppermint and rosemary are sedating; lavender and chamomile are stimulating","Valerian and ginger are stimulating; coconut and peppermint are sedating","All scents increase resting equally compared with a no-cloth control","Lavender, chamomile, coconut, and ginger are sedating; rosemary and peppermint are stimulating"],"a":3,"e":"Per the scented-cloth study data, lavender, chamomile, coconut, and ginger are sedating; rosemary and peppermint are stimulating."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A behaviour department installs DAP (dog appeasing pheromone) diffusers. What specific impact on barking is documented?","o":["DAP eliminates peak barking amplitude entirely","DAP reduced average barking AMPLITUDE by about 30%; barking FREQUENCY and PEAK amplitude did not differ from placebo","DAP made dogs 142 times less likely to bark after environmental noise","DAP increased barking frequency but lowered heart rate"],"a":1,"e":"DAP cuts the average loudness by about 30% but does not reduce peak amplitude or barking frequency."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What operational rule determines whether to MODIFY a broader enrichment STRATEGY?","o":["Wait exactly 2 months before any programmatic changes","If no positive behavioural change occurs within 1 week at most, modify the strategy","Modify the strategy every 15 minutes to prevent rapid habituation","Modify only if peak barking amplitude rises by 12 dB"],"a":1,"e":"If the strategy fails to produce positive behavioural change within 1 week at most, modify it."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Which measurement method involves quickly assessing many animals by focusing on one dog for an instant, recording what it is doing in that moment, then immediately shifting to the next dog?","o":["Continuous measurement","Permanent products","Instantaneous scan sampling (ISS)","Interval recording"],"a":2,"e":"ISS lets one observer cover many dogs by recording behaviour for an instant per animal and then moving on."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What is the principal operational benefit of the PERMANENT PRODUCTS method?","o":["Real-time precise data on canine heart-rate variability","The observer can record tangible outcomes (chewed toys, urine and faeces, emptied KONGs) at their convenience, without being present when the behaviour occurs","It removes the need to rotate classical music compilations","It is the only method that captures subtle changes in peak barking amplitude"],"a":1,"e":"Permanent products allow asynchronous recording of tangible behavioural traces, which is operationally practical for staff."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Under standard shelter guidelines, how is feline enrichment defined and prioritised?","o":["As social interaction, physical and mental stimulation, opportunities for species-typical behaviours, and choice and control, given the same significance as nutrition and medical care and never optional","As an optional add-on provided only when staffing allows","As a purely physical concept limited to cage size","As something needed only for cats staying longer than 2 weeks"],"a":0,"e":"The ASV defines enrichment by these four pillars and treats it as a required, never-optional component of care."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What are the stated goals of a feline enrichment programme?","o":["To increase length of stay so cats habituate fully","To replace medical care with behavioural care","To increase behavioural diversity and normal behaviour, reduce abnormal behaviour, increase positive use of the environment, and improve coping","To minimise all human contact to reduce disease"],"a":2,"e":"Feline enrichment aims to broaden normal behaviour, cut abnormal behaviour, and improve environmental use and coping."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How does the duration of daily human interaction affect the Cat Stress Score (CSS) in shelter cats?","o":["60 minutes per day reduced CSS from day 1 to day 2, while 20 minutes per day did not","20 minutes per day reduced CSS but 60 minutes increased it","Neither duration changed CSS","Only physical restraint changed CSS"],"a":0,"e":"The longer 60-minute daily interaction lowered CSS within a day, whereas the standard 20-minute interaction did not."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A shelter cat is not accustomed to close physical contact with people. What interaction style does the source recommend?","o":["Immediate full-body restraint to build tolerance","Marathon petting along the back to the tail base","No interaction at all until adoption","Interaction via a toy or treat, or a person sitting nearby and reading aloud, rather than forced physical contact"],"a":3,"e":"Cats less used to people often do better with indirect, low-pressure contact (toy, treat, or a person reading nearby)."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"According to ASV guidance, how should social contact be tailored for poorly socialised animals?","o":["All animals benefit equally from forced human handling","Poorly socialised adults should be handled intensively until they comply","Poorly socialised animals may not benefit from human contact, except young puppies and kittens, but may find comfort with their own species","Social isolation is preferable for poorly socialised animals"],"a":2,"e":"ASV notes social isolation is profoundly negative; poorly socialised adults may take comfort from conspecifics rather than people, with young kittens the exception."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How do appropriately group-housed cats compare with singly housed cats?","o":["They show more locomotion and social or solitary play and tend toward a lower cortisol-to-creatinine ratio","They show higher cortisol and more stereotypy","They stop eating and hide permanently","They show no measurable difference"],"a":0,"e":"With adequate space, group-housed cats are more active and playful and tend toward a lower cortisol-to-creatinine ratio."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"When is interspecies (dog and cat) cohousing considered acceptable in the source?","o":["Whenever kennel space is limited","To socialise feral cats to dogs","Routinely, to save housing space","Not recommended, unless a dog and cat were surrendered together and are reported to be bonded"],"a":3,"e":"Cross-species cohousing is discouraged except for an already-bonded dog and cat surrendered together."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What does the evidence show about feline toy preference and use?","o":["Cats play longer with interactive (human-moved) toys than solo-play toys, and toys should be rotated daily","Cats prefer solo toys and ignore human-moved toys","Cats never engage with toys in a shelter","A single toy left indefinitely maintains interest best"],"a":0,"e":"Human-moved interactive toys simulate prey and hold attention longer; daily rotation counters habituation."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"Frustrated shelter cats received four 10-minute training sessions per day for 10 days. What outcomes were documented?","o":["A spike in cortisol and more upper respiratory disease","No measurable change versus controls","More positive mood, higher secretory IgA, and a lower likelihood of developing feline upper respiratory infection","Complete loss of appetite and withdrawal"],"a":2,"e":"Cognitive engagement through short daily training improved mood and mucosal immunity (S-IgA) and reduced FURI in frustrated cats."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"How do cats respond to silvervine compared with catnip?","o":["Catnip produces a response in 100% of cats; silvervine in none","Both produce identical responses in exactly half of cats","Neither has any behavioural effect on cats","About 79% of cats respond to silvervine versus about 68% to catnip, and the response intensity to silvervine is significantly greater"],"a":3,"e":"Silvervine reaches more cats than catnip and elicits a stronger response, useful for cats that do not respond to catnip."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What is documented about visual enrichment for shelter cats?","o":["Cats attend most to moving or linear images but lose interest over time, and with window access 89% spent 1 to 5 hours a day at the window","Cats watch screens for most of the day indefinitely","Static images hold attention better than motion","Cats show no interest in windows"],"a":0,"e":"Motion draws feline attention but wanes; window access is highly used, with most cats spending 1 to 5 hours a day observing."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What does ASV guidance emphasise about auditory enrichment in cat housing?","o":["Loud music at all times maximises calm","Any genre at high volume is beneficial","Species-specific music for cats can reduce stress, but reducing excess noise may matter more than adding sound","Silence is harmful and must always be avoided"],"a":2,"e":"Cat-specific music can help, yet ASV stresses that cutting excess noise is often more valuable than adding sound."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What caveat does ASV note about pheromone products (for example Feliway) used for enrichment?","o":["They work instantly and replace all other enrichment","They are effective only in dogs","They should never be used in shelters","They are less likely to be effective without a comprehensive stress-reduction and enrichment plan"],"a":3,"e":"ASV: pheromones are unlikely to help much unless embedded in a broader enrichment and stress-reduction plan."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"What are the key principles for socialising kittens in the shelter?","o":["Isolate each kitten individually from birth to prevent disease","Socialise between 2 and 7 weeks of age, house with littermates and the queen until weaning, and aim for 20 to 30 minutes of daily handling by a variety of people","Begin socialisation only after 16 weeks of age","Limit handling to a single caretaker for the first 8 weeks"],"a":1,"e":"The sensitive period (about 2 to 7 weeks), littermate and queen contact, and varied gentle handling underpin normal kitten development."},{"type":"mcq","domain":"Behavioral Health","sub":"QOL & Needs Assessment","q":"A high-energy shelter cat shows persistent meowing, reaching through the bars, pacing, and reduced grooming with growing inappetence. How should this be interpreted and managed?","o":["As normal contentment requiring no action","As chronic frustration from under-stimulation progressing toward depression, which must be treated as a welfare emergency","As a sign the cat should be isolated in a dark room","As status aggression requiring a startle stimulus"],"a":1,"e":"Under-stimulation in high-energy cats causes frustration that can deteriorate into depression, a welfare emergency needing prompt enrichment and assessment."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter implements a tiered volunteer program. What tasks should higher-level volunteers handle compared to lower-level volunteers?","o":["Higher-level volunteers handle agility, nosework, cooperative care for low-stress handling, or work with behaviourally challenged dogs, while lower-level volunteers focus on socialisation and basic cues","Both tiers perform identical basic sit and down repetitions","Lower-level volunteers manage aggressive dogs while higher-level volunteers only walk friendly dogs","Higher-level volunteers perform only administrative duties"],"a":0,"e":"Tiered programmes assign baseline socialisation to lower tiers and reserve advanced training, cooperative care, and challenging dogs for higher tiers."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Rehabilitating dogs with bite histories toward humans or dogs requires intensive DSCC. Based on published outcome data, what was the documented success rate?","o":["Less than 5% of dogs were successfully adopted","An 87% success rate (no subsequent biting report) with LOS ranging from 1 to 3 years","100% of dogs were adopted within 2 weeks","Rehabilitation was attempted but zero dogs met adoptability criteria"],"a":1,"e":"Intensive DSCC over 1 to 3 years yielded an 87% success rate, defined as adoption with no further bite reports."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A study taught randomly selected shelter dogs to approach the front of the kennel and sit when people approached. What was the adoption outcome?","o":["It reduced LOS by 50% but did not change adoption rates","It made no difference to either adoption or LOS","These dogs were 1.4 times more likely to be adopted, although there was no effect on LOS","It eliminated all in-kennel arousal behaviours permanently"],"a":2,"e":"Sit-at-the-front increased adoption likelihood by 1.4 times but did not alter overall length of stay."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog displays repetitive in-kennel pacing, spinning, bouncing, barking, and out-of-kennel jumping, mouthing, and leash tugging. This presentation is best characterised as:","o":["Self-handicapping behaviour typical of geriatric dogs","Neophobia secondary to intraspecific aggression","Intact male predatory drive mapping","Excessive arousal, which can increase LOS and reduce adoption probability"],"a":3,"e":"Hyper-responsiveness, exaggerated emotionality, and reduced behavioural inhibition define excessive arousal, which impairs adoptability."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter wants auditory enrichment to reduce barking and stress in a high-arousal ward. Which stimulus is supported by published data?","o":["Slow-tempo piano or violin music","High-tempo electronic dance music","Continuous white noise at 90 decibels","Intermittent pre-recorded human conversation"],"a":0,"e":"Slow-tempo classical piano or violin decreased barking, increased resting, and improved HR variability."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A fearful, un-socialised dog from a hoarding case is undergoing daily BMOD at the ASPCA BRC. Which concurrent psychotropic combination is documented?","o":["Acepromazine and meloxicam","Apomorphine and doxycycline","Fluoxetine and gabapentin","Dexmedetomidine and phenobarbital"],"a":2,"e":"Standardised BRC fear rehabilitation combines environmental enrichment, structured BMOD, and daily fluoxetine and gabapentin."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which statement correctly distinguishes a core operational difference between DPFL and SPA playgroup models?","o":["DPFL restricts groups to 2 to 3 dogs while SPA advocates for 15+","SPA completely bans basket muzzles while DPFL mandates them for all","DPFL relies entirely on LIMA while SPA uses a high-aversive methodology","DPFL targets large groups (6+ dogs) for efficiency and assessment, whereas SPA emphasises smaller groups, strict handler ratios, and choice"],"a":3,"e":"DPFL prioritises operational efficiency with large groups; SPA limits group size and emphasises LIMA, handler ratios, and consent."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A multi-site study measured post-playgroup salivary cortisol. Which group showed increased cortisol?","o":["Dogs in small playgroups with treats and vocal praise","Dogs in a small playgroup that regularly used aversive tools","Dogs in large control playgroups with aversive tools","Dogs in the control shelter with no playgroups"],"a":1,"e":"Post-playgroup cortisol increased specifically in small groups where handlers regularly used aversives."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter veterinarian establishes playgroup safety protocols. Which candidate-selection directive is standard?","o":["Candidates must be selected only following formal veterinary clearance, as play is not universally reinforcing or safe","All dogs must automatically enter daily regardless of medical status","Intact dogs are excluded entirely based on breed","Dogs with active respiratory disease should be prioritised for group play"],"a":0,"e":"Veterinary clearance is mandatory; play is species-typical but not universally safe or enriching."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog voluntarily places itself in a less advantageous position and slows its movements to sustain a social interaction. This healthy play component is:","o":["Displacement grooming","Conspecific redirection","Self-handicapping","Low-intensity neophobia"],"a":2,"e":"Self-handicapping is voluntarily using less advantageous strategies to maintain play."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A volunteer reviews playgroup footage. Which set of cues is most frequently misinterpreted as play when they may actually indicate arousal or conflict?","o":["Inhibited biting, play bows, and side-to-side hip thrusts","Mutual resting, ground sniffing, and low-intensity stalking","Piloerection, herding, standing over, and showing teeth","Barking, bouncing, forward-erect ears, and tail wagging"],"a":3,"e":"Handlers commonly mistake barking, bouncing, erect ears, and tail wagging for play when they can signal arousal or conflict."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Two large dogs engage in intensive bodily contact with growling, reciprocal forceful movements, and wrestling without injury or distress vocalisation. This is defined as (1), and carries the highest risk of transitioning into (2):","o":["Low-intensity predatory stalking; immediate learned helplessness","Conspecific habituation; neophobic withdrawal","Self-handicapping; complete cardiovascular collapse","Play wrestling; play-induced conflict and aggression"],"a":2,"e":"Play wrestling is defined by continuous reciprocal bodily contact without injury and carries the highest statistical conflict-escalation risk."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A handler designs an outdoor multi-dog yard. Which configuration is recommended?","o":["A single tight concrete run with one one-way gate","Multiple connected zones with separate entrance and exit pens, high fencing, two-way gates, and elevated platforms or benches","A large field with no structures and loose raw marrow bones","Indoor rooms without ventilation to retain olfactory pheromones"],"a":1,"e":"Multi-zone yards with separate pens, escape architecture, and two-way gates reduce conflict and provide choice."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"During a playgroup a dog repeatedly mounts a familiar play partner. How should the handler interpret this?","o":["An irreversible indicator of predatory aggression","It can be a displacement behaviour induced by frustration or high motivation to perform a different blocked behaviour","The dog has achieved permanent cognitive mapping of the perimeter","An indicator of severe gabapentin toxicity"],"a":1,"e":"Mounting often serves as a displacement behaviour arising from arousal or frustrated motivation."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A mature, resilient helper dog is used repeatedly across multiple consecutive sessions. What is the primary welfare concern?","o":["The helper dog will experience cessation of all action potentials","The helper dog automatically develops non-social neophobia","The helper dog will lose the ability to synthesise CREB protein","Overusing an individual helper dog puts them at increased risk for injury, behavioural fatigue, and elevated stress"],"a":3,"e":"Repeated use of the same helper dog increases their risk of injury, fatigue, and stress; rotate helpers."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"According to retrospective data, what is the average incidence rate for CIRDC in shelter playgroup populations?","o":["Approximately 19%","Less than 0.1%","Exactly 50%","Over 85%"],"a":0,"e":"CIRDC shows an average 19% incidence in playgroup settings; CPV is less than 1% and distemper 0%."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"An objective protocol to confirm a dog's willingness to participate in a playgroup is formally called:","o":["A LIMA threshold index","A three-term contingency verification","A stereotypic baseline count","A consent test, choice test, or preference assessment"],"a":1,"e":"Consent or choice tests formally confirm individual willingness before entry."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which restraint tool is explicitly not recommended for use within shelter playgroups?","o":["Properly fitted basket muzzles","Flat buckle-less collars with quick-release snaps","Gentle Leader headcollars","6-foot nylon or leather leashes"],"a":2,"e":"Gentle Leader headcollars are not recommended in off-leash multi-dog play settings."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Under the SPA model for a high-risk tolerance setup, what is the maximum recommended group size and dog-to-handler ratio?","o":["12 to 15 dogs with a single handler","Exactly 1 dog per playgroup with 5 handlers","2 to 3 dogs with a 10:1 handler-to-dog ratio","4 to 6 dogs per playgroup with a 3:1 dog-to-handler ratio"],"a":3,"e":"SPA recommends 4 to 6 dogs and a 3:1 dog-to-handler ratio for high-risk tolerance organisations."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"When handlers step into the yard and begin bowing, clapping, or patting the floor, dog-to-dog play decreases. Why?","o":["These actions evoke human-dog play invitations, competing with the dogs' motivation for dog-to-dog play","These behaviours trigger acute auditory neophobia","The handlers are inadvertently administering positive punishment","These movements induce immediate learned helplessness"],"a":0,"e":"Human play signals (bowing, clapping, floor-patting) evoke human-directed play and reduce dog-to-dog interaction."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter introduces pre and post adoption counseling alongside standard services. What is the documented benefit?","o":["It results in 27.5% more adopted dogs than a comparable shelter without the programme","It reduces operational costs by 50%","It eliminates the need for vet clearance before playgroups","It causes an immediate 16% increase in post-adoption returns"],"a":0,"e":"Pre and post adoption counseling tracks with a 27.5% increase in successful adoptions."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A handler wants to recognise true canine play signals during high-intensity yard interactions. Which is a reliable, definitive play signal?","o":["Continuous full-body hackles with a fixed stare","A play bow with a distinct pause, often followed by active behaviours","Low-intensity herding with a tucked tail","Stereotypic pacing along the perimeter fence"],"a":1,"e":"A play bow accompanied by a brief pause is an ethologically stable and reliable play invitation."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter uses the SPIDER framework for its enrichment and playgroup strategies. What do the letters represent?","o":["Stimulation, Perception, Ingestion, Depolarisation, Evaluation, Regulation","Socialisation, Prevention, Isolation, Disinfection, Eradication, Restrictions","Stereotypy, Pacing, Impulsivity, Distressed, Excitability, Reactivity","Setting goals, Planning, Implementation, Documentation, Evaluation, and Readjustment"],"a":2,"e":"SPIDER is Setting goals, Planning, Implementation, Documentation, Evaluation, and Readjustment."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"When must a conflict and fight management plan be developed and communicated to staff?","o":["Immediately after a severe fight resulting in injury","Only when the return rate exceeds 16%","During the annual fiscal audit","The plan must be planned, prepared, and articulated among staff before playgroups begin"],"a":3,"e":"Conflict plans must be in place before any playgroups start, with input from all involved personnel."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A dog with on-leash reactivity and barrier barking is being evaluated for playgroup entry. How should these behaviours be interpreted?","o":["On-leash and barrier reactivity are not accurate predictors of aggression or sociability in off-leash scenarios","These are absolute predictors of off-leash aggression","The dog must be permanently excluded from all social enrichment","The dog should be treated with high-dose steroids immediately"],"a":0,"e":"On-leash and barrier reactivity do not predict off-leash sociability; the dog may still be a suitable playgroup candidate."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Standard fear rehabilitation protocols focus on which four primary target categories?","o":["Fear of food, fear of toys, fear of grass, fear of kennels","Fear of people, fear of handling, fear of leashing and leash walking, and fear of novelty","Fear of sound, fear of light, fear of movement, fear of temperature","Fear of cats, fear of crates, fear of vehicles, fear of structures"],"a":1,"e":"The four axes are fear of people, handling, leashing and walking, and novelty."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"Which playgroup model advocates an every-dog-every-day approach using large groups (6+ dogs)?","o":["Shelter Playgroup Alliance (SPA)","LIMA-based Consent Model","ASPCA Behaviour Rehabilitation framework","Dogs Playing for Life (DPFL)"],"a":2,"e":"DPFL uses the every-dog-every-day, large-group approach to maximise efficiency."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"The average playgroup size across shelters is (1) dogs, and data shows (2) correlation between larger sizes and increased fights or injuries:","o":["2; a direct highly positive correlation","50; an unpredictable volatile correlation","8; no correlation","25; an inverse protective correlation"],"a":1,"e":"The average is about 8 dogs, and no correlation between group size and fight/injury rates has been found."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A trainer argues that praise and petting should be the primary reinforcer for shelter dog training. How does this evaluate against published data?","o":["It is correct; praise is highly effective compared to food","It is incorrect because shelter dogs lack any capacity for interspecific affiliation","It is correct only for dogs with severe bite histories","It is incorrect; social interaction has been shown to be an ineffective reinforcer for shelter dogs compared to food"],"a":2,"e":"Studies show praise and petting are ineffective primary reinforcers for shelter dogs; food rewards are superior."},{"type":"mcq","domain":"Behavioral Health","sub":"Learning Theory","q":"A shelter tracking BMOD outcomes notes a 1% return rate for rehabilitated dogs. What is the general baseline return rate for non-rehabilitated dogs?","o":["Less than 0.5%","Over 75%","Approximately 16%","Exactly 44%"],"a":3,"e":"BMOD dogs had only 1% returns versus the general non-rehabilitated baseline of about 16%."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"For STERILE WRAPPED surgical packs in a gravity-displacement autoclave, the standard steam parameter is:","o":["121°C for 3 min at 15 psi","121°C for 15 min at 15 psi","132°C for 3 min at 30 psi","132°C for 10 min at 30 psi"],"a":1,"e":"Wrapped: 121°C, ~15 min, 15 psi. Unwrapped/flash: 132°C, 3–4 min."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Chemical indicator reacting to all critical steam variables?","o":["Class 1","Class 2","Class 4","Class 5"],"a":3,"e":"Class 5 integrators track time, temperature, and steam penetration."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Biological indicator organism for steam autoclave validation?","o":["Clostridium perfringens","Geobacillus stearothermophilus","Bacillus atrophaeus","Bacillus cereus"],"a":1,"e":"G. stearothermophilus spores are the steam gold standard (B. atrophaeus is for dry heat/EtO)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Minimum recommended frequency for biological spore testing?","o":["Daily","Weekly","Monthly","Semiannually"],"a":1,"e":"Weekly is commonly cited; confirm against ASV Standards of Care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Best suture for a 4-month kitten's subcutis (rapid absorption, low drag)?","o":["PDS","Vicryl","Monocryl","Chromic gut"],"a":2,"e":"Monocryl hydrolyzes fast and is low-reaction."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why is braided Vicryl discouraged for skin/fascia in high-risk patients?","o":["Tissue drag","Capillarity wicks bacteria into the site","Poor strength in peritoneal fluid","Rapid enzymatic dehiscence"],"a":1,"e":"Braided multifilament wicks bacteria."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Best suture for linea alba in a mature large-breed dog?","o":["Monocryl","Vicryl","PDS","Plain gut"],"a":2,"e":"PDS retains tensile strength longest (~6 weeks)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Pedicle (autoligation) tie is most safely used in:","o":["Deep-chested male dog","Young thin cat OHE","Dog with cystic endometrial hyperplasia","Third-trimester dog"],"a":1,"e":"Standard on feline ovarian pedicles; avoid large/deep-chested dogs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Adult bitch in deep estrus at an open shelter for spay. Best timing?","o":["Delay 4–6 wk","Proceed now; delay increases LOS and disease exposure","Ovariectomy only","Pretreat antifibrinolytics"],"a":1,"e":"Welfare risk of prolonged stay outweighs estrus engorgement."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Minimum barrier between a clean prep table and an unsterile dental station in one room?","o":["None if scavenger runs","5 feet","Physically separate room or enclosed alcove","3-ft Plexiglas"],"a":2,"e":"Dental scaling aerosolizes pathogens; isolate clean surgery."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Halsted's gentle handling reduces which mediators of pain/edema?","o":["Bradykinin and prostaglandins","Thromboxane and serotonin","Acetylcholine and epinephrine","GABA and glycine"],"a":0,"e":"Less cell lysis limits the arachidonic-acid cascade."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Sterilization alternative for heat/moisture-sensitive instruments?","o":["2% glutaraldehyde 10 min","Low-temp hydrogen peroxide gas plasma","Boiling 100°C 60 min","High-dose UV"],"a":1,"e":"Gas plasma sterilizes without toxic residue (10-min glutaraldehyde is only disinfection)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most reliable sterile shelf-life wrap configuration?","o":["Single muslin","Double sequential non-woven","Single peel pouch","Open tray under drape"],"a":1,"e":"Double sequential wrap creates a tortuous barrier path."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Feral cat in a trap needs restraint + visceral analgesia + reversibility. Best combo?","o":["Midazolam+ace+butorphanol","Dexmedetomidine+ketamine+butorphanol (DKT)","Propofol+alfaxalone+diazepam","Atropine+bupr+xylazine"],"a":1,"e":"DKT gives restraint, somatic+visceral analgesia, partial reversibility."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Mechanism of dexmedetomidine bradycardia?","o":["Direct SA-node depression","Reflex from peripheral vasoconstriction","Central vagolytic action","Parasympathetic respiratory activation"],"a":1,"e":"High afterload triggers baroreceptor reflex bradycardia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Dexmed-pretreated patient: HR 42, pink MM, high MAP. Correct action?","o":["Full IV atropine","IM glycopyrrolate","No anticholinergic; reverse with atipamezole only if perfusion fails","20 mL/kg bolus"],"a":2,"e":"Forcing HR up against vasoconstriction overloads the myocardium; perfusion is adequate here."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which agent provides NO analgesia?","o":["Dexmedetomidine","Acepromazine","Ketamine","Buprenorphine"],"a":1,"e":"Phenothiazines tranquilize but give zero analgesia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why is acepromazine contraindicated in a dehydrated dog with pale MM?","o":["Vasoconstriction blocks access","Vasodilation → severe hypotension","Bone-marrow suppression","Accelerated clearance"],"a":1,"e":"Acepromazine vasodilation worsens hypotension in hypovolemia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why are puppies <8 weeks sensitive to hepatically/renally cleared drugs?","o":["Impermeable BBB","Immature P450 and low GFR","Low body water","100% protein binding"],"a":1,"e":"Immature metabolism/clearance prolongs half-lives."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Fastest indicator of ET tube disconnection/obstruction?","o":["Pulse oximeter","Capnograph","ECG","Doppler BP"],"a":1,"e":"Capnography flatlines immediately."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Capnograph baseline ETCO2 climbs to 55 mmHg. Action?","o":["Hyperventilating; slow rate","Hypoventilating; increase rate/tidal volume","Drain water trap","Give epinephrine"],"a":1,"e":"Elevated ETCO2 = respiratory acidosis from hypoventilation."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Minimum MAP to autoregulate renal/cerebral perfusion?","o":["40","50","60","90"],"a":2,"e":"Below 60 mmHg risks ischemic organ damage."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why does SpO2 92% on 100% oxygen need evaluation?","o":["Normal under inhalants","Hypoxemia; <95% impaired","Hyperoxia toxicity","Invalid without temp probe"],"a":1,"e":"Expect 98–100% on oxygen; 92% = hypoxemia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why avoid chamber induction with isoflurane?","o":["Cost","Stress, catecholamines, waste-gas exposure","Corneal ulcers","Prevents surgical plane"],"a":1,"e":"Chamber induction panics patients and contaminates the room."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why are electric heating pads prohibited in recovery?","o":["Insufficient heat","Sedated patients cannot move from heat points → burns","Interferes with pulse-ox","Power use"],"a":1,"e":"Thermoregulation failure plus immobility causes burns."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Severe intra-op haemorrhage: capnograph change?","o":["Sudden ETCO2 drop","Spike above 70","Prolonged plateau","No change"],"a":0,"e":"Falling cardiac output reduces CO2 delivery to lungs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"When should a 6-week pup at a high-density shelter start core vaccines?","o":["After 5-day hold","Immediately at intake","8 weeks after fecal float","Before adoption only"],"a":1,"e":"Intake vaccination counters immediate exposure risk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why prefer MLV core vaccines in shelters?","o":["No booster needed","Rapid response and can overcome low MDA","Safe in moribund animals","No refrigeration"],"a":1,"e":"Rapid robust protection in high-exposure settings."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Main cause of vaccine failure in a pup boosted q3 wk to 12 wk?","o":["Potency loss","Persistent MDA","Low protein","Flea allergy"],"a":1,"e":"MDA can block vaccines to 16–20 weeks."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"3-yo intact male cat, no vaccine history. Core protocol?","o":["FVRCP + booster 1 yr later","FVRCP at intake + booster 2–4 wk later","Three doses q2 wk","Waive if healthy"],"a":1,"e":"Naive adults need a priming dose plus one booster 2–4 weeks later."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which MLV vaccine risks fetal cerebellar hypoplasia in pregnant queens?","o":["Killed rabies","MLV panleukopenia (FPV)","Recombinant FeLV","Intranasal Chlamydia"],"a":1,"e":"MLV FPV damages the developing fetal cerebellum."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Unvaccinated shelter dog bites staff, breaks skin. Mandate?","o":["Euthanize and test now","Observe 10 days; do not vaccinate in the window","3 rabies doses in 72 h","6-month confinement"],"a":1,"e":"10-day observation confirms infectious virus in saliva at the bite."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why are adjuvanted vaccines more linked to FISS?","o":["Oncogenic retroviruses","Chronic local inflammation → malignant transformation","Vascular pH change","Anaphylaxis"],"a":1,"e":"Persistent adjuvant inflammation transforms feline fibroblasts."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"What does Capacity for Care (C4C) define?","o":["Cages × 2","Quality care to every animal, matching needs to staff/space/mandate","Isolation capacity","Surgeries per shift"],"a":1,"e":"C4C balances holding with staff bandwidth and medical capability."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Benchmark surgeries per HQHVSN surgeon per day (practical, not ASV)?","o":["5–10","12–15","25–30 or more with support staff","Exactly 50"],"a":2,"e":"Practical benchmark (Sara White), not an ASV standard."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Practical minimum body weight commonly used for pediatric SN?","o":["0.25 kg","~1 kg / 2 lb, clinically stable","3 kg","5 kg"],"a":1,"e":"~1 kg / 2 lb is a practical floor; ASV early-age window is 6–16 weeks."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Cornerstone analgesic class after elective orchiectomy in an active dog?","o":["Corticosteroids","NSAIDs (carprofen, meloxicam)","Pure mu-opioid CRI only","Local alone"],"a":1,"e":"NSAIDs give stable long-lasting control for routine elective surgery."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why discourage routine prophylactic post-op antibiotics for clean SN?","o":["Cost","Diarrhea","Clean surgery does not benefit; overuse drives resistance","Delays suture absorption"],"a":2,"e":"Stewardship reserves prophylaxis for contaminated/infected fields."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most sensitive indicator of acute post-op pain in a non-verbal patient?","o":["Mild hypothermia","Skin turgor >3 s","Guarding, abnormal posture, vocalizing on palpation","Transient tachypnea on waking"],"a":2,"e":"Objective behavioral change is the most sensitive marker."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Maximum lidocaine dose for a testicular block in DOGS (standard reference)?","o":["1 mg/kg","~6–10 mg/kg (stay under toxic dose)","20 mg/kg","No limit"],"a":1,"e":"Dogs tolerate ~6–10 mg/kg; cats far less (~2–4). Std-ref range."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Over-inflated ET cuff in a cat: localized complication?","o":["Laryngeal paralysis","Tracheal pressure necrosis/tear, SC emphysema","Esophageal stricture","Atelectasis"],"a":1,"e":"Feline tracheas are sensitive to over-inflation injury."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Primary purpose of an active gas scavenging system?","o":["Cool the machine","Remove waste anaesthetic gas to protect staff","Keep inhalant constant","Measure oxygen use"],"a":1,"e":"Limits chronic trace anaesthetic exposure."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Feline spay line: sloped loss of capnograph waveform. Why check the ET tube?","o":["Viscous mucus can occlude small tubes","Cats bite through tubes","Confirm anticholinergic dose","Grade dental disease"],"a":0,"e":"Small feline tubes are prone to mucus plugs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Per the ASPCA reference, which disinfectant is NOT reliably effective against non-enveloped parvovirus?","o":["Accelerated hydrogen peroxide","Quaternary ammonium compounds","Potassium peroxymonosulfate","Household bleach"],"a":1,"e":"Quats are not effective vs non-enveloped viruses per independent research."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why avoid stiff bristles/scraping during surgical skin prep?","o":["Dulls clippers","Micro-abrasions promote infection","Breaks chlorhexidine persistence","Delays warming"],"a":1,"e":"Gentle prep preserves the epidermal barrier."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"ASV spay-neuter standard for instrument maintenance?","o":["Inspect only on breakage","Documented schedule for sharpening, alignment, ultrasonic cleaning","Replace packs every 24 mo","Dish soap only"],"a":1,"e":"Documented routine maintenance ensures reliable performance."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"First-line drug for acute anaphylaxis to a vaccine or anaesthetic?","o":["IM diphenhydramine","IV/IM epinephrine","SC atropine","IV dexamethasone"],"a":1,"e":"Epinephrine is the gold standard."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Halsted: obliterating dead space primarily prevents:","o":["Tissue tension","Suture hydrolysis","Seroma and bacterial colonization","Vasoconstriction"],"a":2,"e":"Seroma is an ideal medium for bacterial growth."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"\"Targeting by income\" in HQHVSN means:","o":["Proof of income at intake","Below-median-income areas + pricing","Free only for welfare recipients","Refuse higher-income clients"],"a":1,"e":"Area-based location and pricing, not screening."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Leading relinquishment risk that HQHVSN targeting addresses?","o":["Behaviour","Being sexually intact","Landlord rules","Allergies"],"a":1,"e":"Intact status is the leading relinquishment risk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Pediatric (6–16 wk) fasting before surgery?","o":["Overnight","At least 6 h","Small meal 2–4 h pre-op; not >4 h","No food that day"],"a":2,"e":"Prevents hypoglycemia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Owned pets best scheduled at 4 months mainly to:","o":["Reduce cost","Optimize immunity via vaccination","Skeletal maturity","Rabies law"],"a":1,"e":"The 4-month figure relates to vaccination/immunity."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Intubation of cats for procedures under 30 minutes:","o":["Mandatory","Acceptable to omit if emergency equipment available","Always supraglottic device","Mask-induce never intubate"],"a":1,"e":"CEPSAF: feline intubation is not benign; omission acceptable with backup."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which monitor reduces anaesthetic death risk in cats?","o":["ECG","Capnography","Pulse oximetry","Esophageal stethoscope"],"a":2,"e":"Pulse oximetry (CEPSAF) lowers feline anaesthetic death risk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Jaw tone is unreliable for depth in:","o":["Adult cats","Pediatric puppies","Brachycephalics","Geriatric cats"],"a":1,"e":"Pediatric puppies lack mandibular tone."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"En bloc gravid uterus removal: fetal euthanasia is:","o":["Always required","Only in cats","Not necessary unless the sac is opened","After 45 d gestation"],"a":2,"e":"Fetuses stay unconscious unless the sac is opened."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Recommended permanent identifier for a neutered community cat?","o":["Green tattoo","Microchip only","Ear notch","Unilateral ear tip ~1/3 distal pinna"],"a":3,"e":"Ear tip (one-third distal pinna, perpendicular) is the standard; notching discouraged."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Sterile gloves are required for:","o":["Routine puppy castration only","All abdominal surgery and adult dog castration","Cat castration only","No SN procedures"],"a":1,"e":"Exam gloves OK for routine cat/puppy castration; sterile for abdominal and adult dog castration."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most post-op complications occur within:","o":["30 min","First 3 hours","24 h","72 h"],"a":1,"e":"First 3 hours is the critical window."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Recommended perioperative ambient temperature range?","o":["10–15°C","18–28°C (64–84°F)","30–35°C","12–18°C"],"a":1,"e":"Thermostat low-to-mid 70s°F typical."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which scavenging method is specifically discouraged by ASV?","o":["Active wall suction","Passive charcoal canister","F-air with active interface","Central evacuation"],"a":1,"e":"Charcoal canister scavenging is discouraged."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Contagious-but-eligible animals should be scheduled:","o":["First","Last, after healthy animals","Separate day always","Mobile clinics only"],"a":1,"e":"Operate suspected-contagious animals last."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Partial alpha-2 reversal in a multimodal protocol:","o":["Longer recovery, more analgesia","Shorter recovery without losing analgesia","More hypothermia","Higher mortality"],"a":1,"e":"Shortens recovery while preserving analgesia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"NSAIDs should be avoided in SN patients that are:","o":["Brachycephalic","Clinically or subclinically dehydrated","Geriatric","Pregnant only"],"a":1,"e":"Dehydration raises nephrotoxicosis risk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which model offers the greatest daily surgical capacity?","o":["Mobile MASH","Fitted vehicle","Stationary clinic","Voucher program"],"a":2,"e":"Stationary clinics have the highest daily capacity."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Recommended ergonomic micropauses during surgery?","o":["1–2 min every hour","15–30 s several times per hour","5 min between patients","Only at lunch"],"a":1,"e":"Short frequent micropauses cut fatigue and raise accuracy."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Median survival time of spayed female cats vs intact is best stated as:","o":["13.1%, ~39% longer","About 13.1 years, ~39% longer","39 months","No difference"],"a":1,"e":"MST is a duration (~13.1 yr); the \"13.1%\" was a transcription error."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"A positive point-of-care LH test in a cat is consistent with:","o":["Intact cat in anestrus","A previously neutered cat","Pregnancy","Pyometra"],"a":1,"e":"Loss of gonadal negative feedback raises LH after neutering. Test stats are source-specific."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"In dogs, cryptorchid testes are roughly how much more likely to become neoplastic?","o":["2×","9–14×","50×","No increase"],"a":1,"e":"Reported ~9.2–13.6×; source-specific."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Representative dexmedetomidine premed range in CATS (std ref)?","o":["0.001–0.005 mg/kg","0.02–0.04 mg/kg","0.1–0.2 mg/kg","1–2 mg/kg"],"a":1,"e":"~0.02–0.04 mg/kg IM in cats; dogs are lower per kg. Std-ref range."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"How is atipamezole dosed to reverse dexmedetomidine?","o":["Half the dexmed volume IV","The same volume as the dexmed given, IM","10× the dexmed dose","Fixed 1 mg regardless"],"a":1,"e":"Give an equal volume to the dexmedetomidine, IM; avoid IV except emergencies."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Bupivacaine must never be given by which route?","o":["Intratesticular","Incisional","Intravenous","Intraperitoneal splash"],"a":2,"e":"Bupivacaine is cardiotoxic IV."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Local technique that reduces nociception and inhalant need during castration?","o":["Intratesticular block","Epidural only","Topical EMLA on scrotum","Intranasal lidocaine"],"a":0,"e":"Intratesticular local block blunts the spermatic-cord stimulus."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Correct meloxicam regimen for a healthy adult dog post-spay?","o":["0.2 mg/kg once then 0.1 mg/kg","2 mg/kg q8h","10 mg/kg once","Contraindicated in dogs"],"a":0,"e":"Meloxicam dog: ~0.2 mg/kg load then 0.1 mg/kg; cats single dose with caution. Std-ref."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"AAHA-recommended STARTING anaesthetic IV fluid rate in dogs?","o":["1 mL/kg/h","~5 mL/kg/h (cats ~3)","10 mL/kg/h fixed","20 mL/kg/h"],"a":1,"e":"AAHA 2013: start ~5 (dog)/3 (cat) mL/kg/h, titrate down; older standard was 10. Std-ref."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which patients DO warrant IV fluids per ASV?","o":["All healthy electives","Pregnant, pyometra, blood loss, prolonged surgery","Only cats","None ever"],"a":1,"e":"ASV reserves IV fluids for high-risk patients; routine electives often need none."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Propofol induction dose in a WELL-PREMEDICATED dog?","o":["0.5 mg/kg","2–4 mg/kg IV to effect","8–10 mg/kg","Fixed 50 mg"],"a":1,"e":"Premedication lowers propofol need to ~2–4 mg/kg titrated."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Anticholinergic appropriate for VAGAL (not alpha-2) bradycardia?","o":["Atipamezole","Atropine 0.02–0.04 mg/kg or glycopyrrolate 0.005–0.011 mg/kg","Naloxone","Flumazenil"],"a":1,"e":"Atropine/glycopyrrolate for vagal bradycardia; never for alpha-2 bradycardia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Per the ASPCA reference, household bleach dilution and contact time effective against parvovirus?","o":["1:10 for 1 min","1:32 (½ cup/gal) for 10 min","1:100 for 30 s","Undiluted for 1 h"],"a":1,"e":"1:32 (about half a cup per gallon), 10-minute contact on precleaned surfaces."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Per the ASPCA reference, diluted stability of accelerated hydrogen peroxide?","o":["24 hours","7 days","90 days","1 year"],"a":2,"e":"Accelerated H2O2 is stable ~90 days diluted (potassium peroxymonosulfate ~7 days; bleach ~24 h)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Per the ASPCA reference, which two agents are most inactivated by organic matter and need a rinse?","o":["Accelerated H2O2 and quats","Bleach and calcium hypochlorite","Potassium peroxymonosulfate and AHP","Quats and AHP"],"a":1,"e":"Bleach and calcium hypochlorite are organic-matter sensitive, need extensive precleaning and a rinse."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The hardest resource to obtain when setting up a program (ASV)?","o":["Volunteers","Funding","Cages","Surgeons"],"a":1,"e":"ASV identifies funding as the hardest resource."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"For a program to stay accessible, fees for service must be:","o":["Equal to general practice","Higher than general practice","Lower than local general-practice prices","Zero for everyone"],"a":2,"e":"Accessibility requires fees below local GP prices; shortfall covered by efficiency/volunteers/funding."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Effective HQHVSN work culture is best described as:","o":["Strictly hierarchical","Collaborative; more teamwork → fewer complications","Surgeon-only decisions","Rotating leaderless"],"a":1,"e":"Collaborative teamwork correlates with fewer complications."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Program EFFECTIVENESS is measured by:","o":["Number of staff","Local intake/euthanasia rates, complaints, colony size, kitten production","Square footage","Social-media reach"],"a":1,"e":"Population-level metrics gauge whether targeting is working."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which opioid gives the longest analgesia and is a good feline take-home (OTM) option?","o":["Butorphanol","Buprenorphine","Naloxone","Acepromazine"],"a":1,"e":"Buprenorphine (~6–8 h) suits feline take-home; butorphanol is short-acting; acepromazine has no analgesia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Benchmark daily surgical volume for a sustainable stationary HQHVSN clinic (one vet)?","o":["~10/day","~35/day","~80/day","~120/day"],"a":1,"e":"About 35 surgeries per vet per day, 5 days/week, 48 weeks/year. Source-specific planning figure."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Catchment commonly cited as needed to sustain a stationary clinic?","o":["~25,000 within 10 miles","~250,000 within a 60-mile radius","~1 million within 5 miles","Any size"],"a":1,"e":"~250,000 people within ~60 miles, plus about a $35,000 opening reserve. Source-specific."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Fastest, lowest-cost way to start an HQHVSN program?","o":["Stationary clinic","Self-contained mobile unit","MASH clinic","Hybrid trailer"],"a":2,"e":"MASH clinics have the lowest setup cost and suit both rural and dense urban areas."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"In a collaborative MASH model, the host organisation typically provides:","o":["Vets and surgical supplies","Venue, scheduling, admission/discharge, non-medical supplies","Anaesthesia machines","Autoclave"],"a":1,"e":"Hosts supply venue/personnel/scheduling; the MASH org supplies vets, techs, surgical supplies and training."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Recommended HQHVSN staff ratio (vet to trained support)?","o":["1:1","1:2 to 1:3","1:5","1:8"],"a":1,"e":"About one vet to two or three trained support staff; 4x10 h or 3x12 h shifts work better than 5x8 h."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"CEPSAF anaesthetic mortality in healthy elective cats (ASA I to II)?","o":["0.01%","0.11%","1.4%","5%"],"a":1,"e":"~0.11% healthy cats vs ~1.4% sick cats; dogs ~0.05% vs ~1.33%."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which change INCREASES MAC (needing more inhalant)?","o":["Hypothermia","Pregnancy","Hyperthermia","Alpha-2 premedication"],"a":2,"e":"Hyperthermia, hypernatraemia and CNS stimulants raise MAC; the others lower it."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"A capnograph baseline that does not return to zero indicates:","o":["Hyperventilation","Rebreathing CO2 (exhausted soda lime or stuck expiratory valve)","Oesophageal intubation","Cardiac arrest"],"a":1,"e":"An elevated baseline means inspired CO2 is being rebreathed."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"A 'curare cleft' on the capnograph plateau means:","o":["Complete airway obstruction","The patient is breathing against the circuit (light plane or waning relaxant)","Hypothermia","Hypercapnia"],"a":1,"e":"The cleft reflects spontaneous effort against the ventilator/circuit."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"In a 6 to 12 week pediatric patient, cardiac output depends primarily on:","o":["Stroke volume via Frank-Starling","Heart rate (fixed stroke volume)","Systemic vascular resistance","Haematocrit"],"a":1,"e":"Non-compliant ventricles mean CO is rate-dependent, so bradycardia causes immediate hypotension."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"RECOVER chest-compression rate?","o":["60/min","80/min","100 to 120/min","150/min"],"a":2,"e":"100 to 120/min, 1/3 to 1/2 chest width, full recoil."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"RECOVER ventilation rate for an intubated arrest patient?","o":["6/min","10/min (1 every 6 s)","25/min","40/min"],"a":1,"e":"10/min; hyperventilation raises intrathoracic pressure and crashes preload."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"If epinephrine must be given intratracheally during CPR, the dose is:","o":["Halved","Unchanged","Increased 10-fold (0.1 mg/kg) and diluted","Given as a fixed 1 mg"],"a":2,"e":"Intratracheal epinephrine is 10x the IV dose, diluted for alveolar absorption."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Roughly how much isotonic crystalloid remains intravascular 30 to 60 min after a bolus?","o":["~75%","~50%","~25%","~5%"],"a":2,"e":"About 25% stays intravascular (75% shifts interstitial), so over-hydration drives oedema."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Maximum acceptable time from clamping the uterine blood supply to delivery in en bloc caesarean?","o":["10 to 15 s","45 to 60 s","3 to 4 min","10 min"],"a":1,"e":"45 to 60 seconds; longer risks fetal hypoxia. One resuscitator per neonate."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which caesarean technique gives the highest neonatal survival and shortest dam GA time?","o":["Single hysterotomy, dam intact","Multiple hysterotomies","En bloc OHE then hand-off hysterotomy","Natural parturition"],"a":2,"e":"En bloc removal minimises dam GA time, contamination, and maximises neonatal survival."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which neonatal resuscitation manoeuvre is NO LONGER recommended?","o":["Drying and warming","Swinging/shaking to clear airways","Tactile stimulation by rubbing","Mask oxygen"],"a":1,"e":"Swinging/shaking risks intracranial haemorrhage and head/neck injury."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Neonatal bradycardia during resuscitation is usually due to, and managed by:","o":["Vagal tone; give atropine","Myocardial hypoxaemia; ventilate/oxygenate (atropine/glyco not recommended)","Hypothermia; give epinephrine","Hypoglycaemia; give naloxone"],"a":1,"e":"Most neonatal bradycardia is hypoxic, so anticholinergics are not recommended; oxygenate first."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Ovary-sparing spay (hysterectomy keeping ovaries) still carries the risk of:","o":["Mammary neoplasia elimination","Pyometra (unless all uterine tissue to the cervix is removed)","Permanent infertility behaviour change","Testicular tumour"],"a":1,"e":"Stump pyometra risk persists and estrus behaviour continues; all uterine tissue must be removed to avoid stump pyometra."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Tearing of the ovarian pedicle is more commonly associated with which side?","o":["Left","Right","Neither","Both equally"],"a":1,"e":"The right ovary is more cranial and harder to exteriorise."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Ovarian remnant syndrome is more common in which species, and is best resected when?","o":["Dogs; during anestrus","Cats; about 2 to 3 weeks after luteinisation or during behavioural estrus","Dogs; immediately","Cats; only after 1 year"],"a":1,"e":"~0.3% cats vs ~0.04% dogs; operate when ovarian tissue is most identifiable (post-luteinisation or in estrus)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Recommended surgical approach for feline mammary fibroadenomatous hyperplasia?","o":["Bilateral mastectomy","Flank spay","Ventral midline spay only","Medical management alone"],"a":1,"e":"Flank spay is recommended; the hyperplasia is progesterone-driven and regresses after ovariectomy."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Secondary post-spay haemorrhage from uterine-vessel erosion typically presents:","o":["Within 1 hour","4 to 16 days post-op","After 3 months","Never"],"a":1,"e":"Often 4 to 16 days out; any serious vaginal bleed warrants immediate exploration and re-ligation."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Every spay/neuter patient should be discharged with which item to prevent dehiscence?","o":["Antibiotics","An Elizabethan collar","A bandage","A heat pad"],"a":1,"e":"Self-trauma is the main cause of skin dehiscence; an E-collar is standard."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Preferred vasopressor to support blood pressure during caesarean (preserves uterine flow)?","o":["Epinephrine","Phenylephrine","Ephedrine 0.04 to 0.1 mg/kg IV","Norepinephrine"],"a":2,"e":"Ephedrine maintains or improves uterine blood flow despite vasoconstriction."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Which anticholinergic does NOT cross the placenta (preferred for maternal bradycardia in caesarean)?","o":["Atropine","Glycopyrrolate","Both cross","Neither crosses"],"a":1,"e":"Glycopyrrolate's size/charge keep it out of fetal circulation; atropine crosses (and raises fetal HR)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The one sedative specifically linked to neonatal and maternal mortality (avoid in caesarean)?","o":["Dexmedetomidine","Xylazine","Midazolam","Buprenorphine"],"a":1,"e":"Xylazine is the alpha-2 agonist associated with both neonatal and maternal mortality."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most accurate monitor of sterilisation efficacy, run weekly?","o":["Chemical indicator strip","Biological (spore) indicator","Autoclave gauge","Tape colour change"],"a":1,"e":"Biological indicators (G. stearothermophilus for steam) are the most accurate; run weekly."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most commonly used suture type in HQHVSN?","o":["Braided multifilament absorbable","Synthetic monofilament absorbable","Non-absorbable nylon","Stainless steel for skin"],"a":1,"e":"Synthetic monofilament absorbable (Monocryl, PDS) predominates."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Clipping the surgical site more than 4 hours before surgery does what to SSI risk?","o":["No effect","Roughly triples it","Halves it","Eliminates it"],"a":1,"e":"Clipping well before surgery (or before induction) increases SSI risk roughly threefold."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Minimum thread count for woven cotton muslin sterilisation wrap?","o":["70","140","270","500"],"a":1,"e":"Minimum ~140 thread count for muslin (270-count pima cotton is the barrier-equivalence benchmark)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most effective surgical hand-prep agent?","o":["Plain soap","Alcohol-based rub","Povidone-iodine","Quaternary ammonium"],"a":1,"e":"Alcohol-based products are most effective, then chlorhexidine, then iodophors; brushless preferred."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"When cleaning cages, which animals are cared for first?","o":["Adults of unknown status","The most vulnerable (pediatric/immunocompromised) first","Sick animals first","Order does not matter ever"],"a":1,"e":"Clean the most vulnerable first, then unknown-vaccination adults; pediatrics are also housed separately."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why must many commercial gabapentin oral solutions be avoided in cats?","o":["Too dilute","They often contain xylitol","They taste bitter","They cause hyperthermia"],"a":1,"e":"Xylitol-containing liquids are toxic to cats; use xylitol-free compounded liquid or capsules."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Typical canine pre-visit trazodone dose range?","o":["0.1 to 0.5 mg/kg","4 to 12 mg/kg","30 to 50 mg/kg","100 mg/kg"],"a":1,"e":"~4 to 12 mg/kg q8 to 12 h (start ~4 to 7 mg/kg); cats ~50 mg/cat."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Free-roaming cat population dynamics are MOST sensitive to:","o":["Fecundity (litter size)","Adult survival","Kitten coat colour","Season only"],"a":1,"e":"Survival (especially adult) outweighs fecundity, which is why removal often beats equal-intensity sterilisation."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"In population simulations, sterilising only male cats produced:","o":["A rapid decline","Essentially no change vs no sterilisation","A population spike","Eradication in 2 years"],"a":1,"e":"Male-only sterilisation showed no meaningful population change."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Boone et al. (2019) modelling suggested effective TNR requires sterilising about:","o":["25% of cats annually","75% of intact cats every 6 months","10% every 6 months","100% once"],"a":1,"e":"~75% of intact cats per 6-month interval to drive decline; non-surgical contraception needs >40 to 50% per 6 months plus limited migration."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Why is test-and-cull for FeLV/FIV discouraged in community cats?","o":["Tests are too expensive only","High false-positive rate at low prevalence risks euthanising healthy cats","Cats cannot be tested","It is illegal everywhere"],"a":1,"e":"At low prevalence up to ~50% of positives can be false, risking euthanasia of uninfected cats."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Most common sex-chromosome disorder of sexual development in dogs and cats?","o":["XO (Turner-type)","XXY (Klinefelter)","Triploidy","XYY"],"a":1,"e":"XXY (Klinefelter) is the most commonly reported."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Persistent Mullerian duct syndrome is hereditary in which breeds?","o":["Labrador and Poodle","Miniature Schnauzer (US) and Basset Hound (Europe)","Boxer and Bulldog","Siamese and Persian"],"a":1,"e":"Miniature Schnauzers in the US, Basset Hounds in Europe; often cryptorchid."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"A true hermaphrodite is defined by:","o":["Ovaries plus masculinised genitalia","Testes plus feminised genitalia","At least one ovary and one testis (or an ovotestis)","XXY karyotype"],"a":2,"e":"True hermaphrodite = both gonadal tissues present; pseudohermaphrodites have one gonad type with discordant phenotype."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"In all confirmed disorders of sexual development, the recommendation is:","o":["Breed for research","Gonadectomy","No intervention","Hormone therapy for life"],"a":1,"e":"Gonadectomy is recommended in all DSD cases (neoplasia and welfare risk)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"When evaluating the metrics of a newly implemented pet safety net program, an organization distinguishes between 'usage metrics' and 'impact metrics'. Which of the following represents an impact metric?","o":["The total pounds of dog food distributed by a pet food bank within a specific quarter.","The total number of unique phone calls answered by a volunteer-staffed behavior helpline.","A statistically significant, documented reduction in owner-surrender shelter intake numbers.","The number of clients participating in a fee-waived community training class."],"a":2,"e":"Impact metrics measure the direct, measurable outcome of a program (e.g., increased pet retention and decreased intake). The other options describe usage metrics, which quantify the volume of program activity only."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter experiences a 20% reduction in owner surrenders following the launch of a medical subsidy program. How does this outcome primarily benefit the shelter's internal operations?","o":["It permits the shelter to operate beyond its physical housing capacity.","It helps the organization function within its Capacity for Care (C4C), improving the welfare of remaining animals and staff.","It eliminates the need for intake quarantine protocols.","It shifts the regulatory burden of stray animal care entirely to private practitioners."],"a":1,"e":"Reducing intake allows a shelter to operate within its true Capacity for Care (C4C), which directly raises the welfare baseline for animals and staff on-site, frees resources for high-complexity cases, and reduces burnout."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Before launching a community-wide safety net initiative, when is it most critical for an organization to collect data to establish a comparative baseline?","o":["Immediately after the pilot phase concludes.","Concurrently with the mid-year program review.","Before the program is launched into the community.","Only during the program's phase-out or scaling down period."],"a":2,"e":"Data must be collected before launch to establish a true baseline. Without pre-launch data, it is impossible to measure any subsequent change attributable to the program."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"An animal shelter wants to assess the specific pet ownership demographics, trends, and localized service gaps within a high-risk area. Which tool is specifically designed to provide this comprehensive community needs assessment?","o":["The Shelter Animals Count (SAC) national database matrix.","The Pets for Life (PFL) Community Assessment toolkit.","The Association of Shelter Veterinarians (ASV) Standards of Care guidelines checklist.","The Purina Body Condition Scoring matrix."],"a":1,"e":"The Pets for Life (PFL) Community Assessment is the validated standard tool for identifying targeted community pet-ownership needs, service gaps, and resource deserts at a localized level."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"When a shelter determines that a safety net program has reached its end of life and must be phased out, what is the most critical operational step regarding existing clients?","o":["Immediate cessation of all communications to prevent public panic.","Transitioning existing clients to alternative community services and proactively supporting them through the closure.","Automatically absorbing all program animals into the shelter's permanent adoption inventory on the day of decision.","Transferring all remaining financial resources to general facility maintenance."],"a":1,"e":"Ethical program phase-out requires proactive, transparent communication, structured transition pathways to alternative services, and staff and volunteer support. Silent closure or abrupt stoppage are ethically unacceptable."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter establishes a pet food pantry. Which operational resource requirement is most frequently overlooked but vital to maintaining safety and compliance?","o":["Marketing funding for social media promotion of the pantry.","Physical space to store and inventory donated food, including monitoring of food expiration dates.","Hiring a board-certified veterinary nutritionist to approve all donated food items.","Purchasing commercial-grade grain milling equipment."],"a":1,"e":"Operating a pet food bank requires adequate physical storage space and a robust inventory management system to track food expiration dates, ensuring donated items are safe and compliant before distribution."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Studies evaluating food-insecure pet owners have revealed a profound human-animal bond dynamic. In times of extreme resource scarcity, what choice do these owners frequently make?","o":["They immediately relinquish their pets to avoid neglect charges.","They feed their pets at the expense of their own personal nutritional well-being.","They transition their pets to strict vegetarian diets using expired human pantry goods.","They abandon their pets in affluent neighborhoods where they will be found and rehomed."],"a":1,"e":"The human-animal bond is powerful enough that food-insecure owners often prioritize their pet's nutritional needs over their own. Pet food banks therefore serve a dual One Health function, supporting both animal welfare and human nutritional well-being (AVCC 2018)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter's housing support program aims to reduce relinquishments due to rental housing restrictions. To build a robust and effective database of pet-friendly landlords, which approach is required?","o":["Relying solely on historical, unverified word-of-mouth reports from shelter front desk staff.","Using multiple research methods to identify landlords and explicitly clarifying species, size, and breed restrictions, with regular database updates.","Forcing local municipalities to ban all landlord restrictions on companion animals through litigation.","Requiring tenants to register their pets as emotional support animals regardless of their legal eligibility."],"a":1,"e":"A reliable landlord database requires systematic multi-method research to verify current policies (species, weight, and breed limits) and must be regularly updated as landlord policies change over time."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Shelter data examining direct owner-to-owner rehoming patterns indicate which of the following distributions of pet placement outcomes within a 5-year window?","o":["Approximately 70% surrendered directly to municipal facilities, fewer than 5% given to family members.","Approximately 37% rehomed directly to a friend or family member, compared to 36% taken to an animal shelter.","Approximately 90% rehomed to individuals previously unknown to the owner via online classifieds.","Approximately 50% placed in temporary foster homes via human social service databases."],"a":1,"e":"Data show 37% of owners rehome to friends or family versus 36% who surrender to shelters, and 11% who directly rehome to a previously unknown individual. These data support providing O-to-O rehoming resources as an effective diversion tool."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A lost-and-found safety net program aims to minimize barriers to pet-owner reunification. Which policy should the shelter implement to achieve this?","o":["Charge progressive, compounding daily board fees to incentivize faster retrieval by owners.","Eliminate heavy reunification fees and establish an up-to-date, publicly accessible database with photos of found pets on social media and the organization website.","Restrict lost-and-found database access to individuals who possess a current municipal pet license.","Mandate a 14-day quarantine period for all microchipped stray animals before allowing owner contact."],"a":1,"e":"Eliminating heavy financial fees removes an institutional barrier that disproportionately harms low-income owners. An open-access, regularly updated digital database with photos maximizes the likelihood of reunification."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Temporary sheltering safety net programs are designed to assist pet owners during acute personal crises. What is the primary objective of these programs?","o":["To facilitate permanent surrender so the animal can be rapidly adopted by a new family.","To avoid permanent relinquishment by facilitating reunification once the owner's circumstances stabilize.","To provide a legal mechanism for seizing animals from uncooperative owners.","To test new pharmaceutical behavior modification protocols in a controlled residential environment."],"a":1,"e":"Temporary sheltering programs exist to preserve the human-animal bond during acute, time-limited crises. Reunification with the original owner is the primary goal, not permanent rehoming or ownership transfer."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"To minimize the severe medical and behavioral detriments associated with housing crisis animals in a traditional shelter environment, which housing model is ideal?","o":["High-density communal concrete runs in the existing shelter intake area.","Temporary foster care networks with clear legally approved agreements on duration of care.","Isolation wards designated for animals with confirmed infectious diseases.","Off-site commercial boarding kennels with no enrichment or behavior programs."],"a":1,"e":"Foster care avoids crowd stress, infectious disease exposure, and behavioral deterioration inherent to physical shelter kennels. Clear legal agreements prevent ambiguity about care duration and final disposition."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"To prevent ambiguity and legal disputes regarding the duration and scope of care in a temporary crisis sheltering program, what must the organization implement?","o":["Verbal agreements secured informally at intake.","Legally approved written agreements and thorough guidelines establishing clear expectations for all participants.","A policy of automatic ownership transfer after 48 hours of housing in the program.","An anonymous intake process with no contact details recorded for the owner."],"a":1,"e":"Legally approved written agreements protect all parties (owner, shelter, and animal) by clearly defining the duration, scope, and financial terms of temporary care, preventing misunderstandings or disputes at time of reunification."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"How can a shelter significantly optimize oversight of a temporary crisis housing initiative without overburdening its own staff resources?","o":["By delegating all operational decisions to untrained general public volunteers without professional supervision.","By collaborating with governmental or non-profit human social services, allowing the shelter to focus primarily on direct animal care.","By cutting all enrichment and veterinary care for crisis animals to reduce resource expenditure.","By restricting the temporary sheltering program exclusively to purebred animals to reduce caseload."],"a":1,"e":"Collaboration with external human social services leverages existing professional expertise and case management resources, allowing the animal welfare organization to focus on what it does best: animal care and welfare."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Humane education programs targeting children in schools and community settings have been evaluated for their sociological impact. What positive outcome is objectively documented in children participating in these programs?","o":["Increased competitive academic performance across standardized test metrics.","Enhancement of prosocial behavior and empathy toward animals and people.","Rapid acceleration of fine motor skill development.","Complete elimination of fear-based responses to unfamiliar domestic animals."],"a":1,"e":"Published sociological research documents that children participating in humane education programs demonstrate measurable enhancement of empathy and prosocial behavior. This is distinct from motor skills or fear responses, which are not primary documented outcomes."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"According to shelter medicine literature, as many as what percentage of surrenders in a study cited cost, combined with medical issues, as the primary driver for relinquishing their companion animal?","o":["Approximately 5%.","Up to 28%.","Exactly 65%.","Over 95%."],"a":1,"e":"Up to 28% of surrenders in cited shelter medicine data specifically identified veterinary cost combined with medical issues as the reason for relinquishment, making accessible vet care a critical diversion strategy."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"When evaluating the community-wide impact of accessible spay/neuter (S/N) programs, research indicates a notable species difference. Which statement accurately reflects the evidence?","o":["Accessible S/N programs show a documented reduction in shelter relinquishment for cats but not consistently for dogs.","Accessible S/N programs eliminate dog surrenders entirely but have zero impact on cat population dynamics.","Dog relinquishments drop drastically, while cat relinquishments invariably increase.","Neither species shows any change in intake metrics following community S/N program implementation."],"a":0,"e":"Accessible spay/neuter programs show a documented reduction in feline shelter relinquishment over time; equivalent evidence for dogs is not as consistent. This species distinction is high-yield on board examinations."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Intact dogs are statistically overrepresented in which of the following public safety and community health issues?","o":["Chronic dermatological conditions requiring specialist referral in urban shelter populations.","Serious dog bite incidents and nuisance behaviors including vocalization, roaming, and urine marking.","Feline leukemia virus transmission in mixed-species shelter housing.","Vector-borne tick infestations in arid and semi-arid climates."],"a":1,"e":"Intact male dogs are statistically overrepresented in serious dog bite incidents and in nuisance behaviors such as roaming, vocalization, and urine marking. Community S/N programs reduce these public safety and welfare concerns."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter develops an accessible veterinary care program that extends beyond wellness clinics into sick-pet medical care. To mitigate concerns among local private practitioners that this program threatens their financial well-being, the shelter should:","o":["Launch the program confidentially without advertising to avoid triggering opposition.","Include outreach to the local veterinary community in the earliest stages of planning to foster referral networks and collaboration.","Aggressively undercut private clinic prices and market services to affluent pet owners.","Publicly criticize local private practitioners for their pricing models and access barriers."],"a":1,"e":"Early, transparent outreach to private practitioners helps resolve perceived competition, builds collaborative referral channels where private vets send clients who cannot afford full-cost care, and strengthens the local veterinary ecosystem. This approach is consistent with both your notes and VCE Principle 2."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A program captures free-roaming, unowned community cats, sterilizes and vaccinates them, then returns them directly to their original location rather than admitting them to the shelter or rehoming them. This is classified as:","o":["A traditional adoption-pantry pipeline for community cats.","A Return-to-Field (RTF) program.","An epidemiological isolation and quarantine protocol.","A foster-to-surrender strategy for feral felines."],"a":1,"e":"Return-to-Field (RTF) is the correct term for sterilizing, vaccinating, and returning healthy free-roaming community cats to their original locations, avoiding shelter intake and the need for placement in a home."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Behavioral reasons are major contributors to shelter intake. Up to what percentages of relinquished dogs and cats respectively are surrendered for behavioral reasons?","o":["Up to 5% of dogs and 2% of cats.","Up to 40% of dogs and 28% of cats.","Up to 80% of dogs and 75% of cats.","Behavior is rarely cited; financial constraints represent over 95% of all surrenders."],"a":1,"e":"Behavioral challenges are a primary driver of relinquishment, reported in up to 40% of dog surrenders and 28% of cat surrenders. Behavioral interventions are therefore a critical component of any comprehensive diversion program."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter provides behavior information resources via printed handouts and online links. What is the primary operational advantage of this intervention format?","o":["It provides a guaranteed, permanent cure for complex separation anxiety and aggression.","It has the potential to reach a very large number of owners in an accessible format with a low resource investment.","It allows the shelter to charge premium subscription fees to the public for access.","It replaces the need for any physical behavior evaluation of animals prior to adoption."],"a":1,"e":"Information resources require minimal ongoing resources while allowing broad, scalable public outreach. They are not a cure, cannot replace individual assessments, and should be freely accessible."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Studies on the impact of traditional, fee-based obedience training classes on pet retention show varied findings. What are the primary logistical barriers preventing high-risk owners from utilizing these classes?","o":["A lack of commercially available treat options in local pet supply stores.","Cost and fees, combined with a lack of transportation to the physical class location.","Federal zoning regulations prohibiting group animal gatherings in residential areas.","Universal owner apathy toward animal behavior education."],"a":1,"e":"Financial costs (fees) and geographic barriers (lack of transportation to the class location) are the documented primary barriers preventing at-risk owners from accessing traditional behavior training classes."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"To mitigate socioeconomic and geographic barriers to behavior modification resources for high-risk owners, which strategy best addresses both barriers simultaneously?","o":["Increasing class fees to ensure attendance is limited to highly motivated, financially stable clients.","Providing fee-waived training classes delivered directly within communities identified as having high relinquishment risk.","Mandating that all dogs pass an advanced agility course prior to receiving any community behavioral aid.","Restricting behavioral support services exclusively to dogs under 10 pounds."],"a":1,"e":"Bringing free classes directly into high-risk neighborhoods systematically removes both financial (fee-waived) and geographic (on-site delivery) barriers simultaneously. Virtual options also increase reach but eliminate the socialization component."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter operates a behavior helpline staffed by trained volunteers, escalating complex questions to professional behavior staff. Which statement most accurately reflects the scientific evidence base for these helplines?","o":["Peer-reviewed data definitively proves that behavior helplines are 100% effective at preventing all surrenders.","There is limited scientific data available to evaluate helpline efficacy, and their precise impact on long-term pet retention remains uncertain.","Published data demonstrates that behavior helplines cause a direct increase in animal abandonment rates.","Helplines have been empirically shown to be effective only for exotic pocket pets."],"a":1,"e":"While behavior helplines are highly accessible and widely utilized, the current published scientific evidence base regarding their direct, long-term impact on pet retention in the home remains limited and uncertain."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"A shelter is considering adding individualized behavioral consultations to its safety net portfolio. Which operational reality must managers account for when planning this service?","o":["It requires virtually no dedicated staff time or specialized professional expertise.","It is highly resource-intensive and requires a qualified behavior professional.","It can be run entirely by entry-level, untrained administrative volunteers from day one.","It is universally self-sustaining and profitable from the moment of launch."],"a":1,"e":"Individualized behavioral consultations are the most resource-intensive behavioral intervention, requiring a qualified behavior professional and significant staff time per client. Any fee charged may be an insurmountable barrier for many clients who need this service most."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"From a client-centered perspective, what psychological benefit does an individualized behavior consultation provide to an owner struggling with a disruptive pet?","o":["It guarantees the owner will never face landlord disputes related to the animal's behavior.","It validates the client's concerns and helps them avoid feelings of isolation and permanence regarding the behavioral problem.","It legally absolves the owner of any future public liability related to the animal's actions.","It compels the owner to acknowledge they are personally responsible for causing the behavioral problem."],"a":1,"e":"Individualized consulting validates the owner's stress and experience, breaking down the sense of isolation and the feeling that the problem is permanent and unsolvable. These psychological factors are documented drivers of the decision to surrender."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Recognizing the intrinsic connection between human, animal, and environmental health to identify at-risk pets through cross-referral with human social services describes which conceptual framework?","o":["The Five Freedoms of Animal Welfare framework.","The One Health model.","The Capacity for Care (C4C) calculation methodology.","The Population Medicine intake matrix."],"a":1,"e":"The One Health model recognizes the interconnection of human, animal, and environmental health and well-being. It provides the scientific and ethical rationale for shelters to collaborate with human social service agencies to identify at-risk pets and connect owners with safety net programs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"When an organization uses a strategic decision matrix to select its mix of safety net programs, what two factors is it attempting to balance?","o":["The shelter's endowment funds against local political campaign contribution timelines.","The identified community needs and desired programmatic impacts against available operational resources.","The adoption room aesthetics against local building code and climate zone requirements.","The number of canine intakes against the total feline euthanasia kennel count."],"a":1,"e":"The strategic decision matrix is a tool for balancing community needs and desired program impacts against a shelter's finite available resources (staff time, funding, space), to determine which programs to launch, scale, or phase out for maximum impact."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Shelter Diversion","q":"Under what circumstance should a shelter safety net or diversion program be withheld in favor of immediate legal or law enforcement intervention?","o":["When an owner requests food bank delivery more than twice within a single calendar month.","In situations of active animal cruelty or neglect where the caregiver is unwilling or unable to accept assistance.","When an owner cannot provide proof of current municipal pet licensing during a helpline call.","When an animal exhibits mild, non-dangerous separation anxiety that has not responded to basic information resources."],"a":1,"e":"Safety net programs are tools for preservation of the human-animal bond in situations of need. They never replace mandatory legal actions in cases of active cruelty or neglect when the caregiver cannot or will not accept help. This is the crucial guardrail underpinning all diversion work."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"The contemporary 'conversational adoption' philosophy represents a paradigm shift from historical screening practices. Which tenet underpins this model?","o":["Adopters must present certified financial records to prove they can afford gold-standard veterinary care.","Adopters are viewed as well-meaning individuals with unique strengths and weaknesses who are capable of learning appropriate animal care.","Adopters must be subjected to a home inspection prior to browsing kennelled animals.","Adopters are assumed to be uneducated until they pass a formal written husbandry exam."],"a":1,"e":"Conversational adoptions reject rigid screening filters, treating adopters as well-intentioned individuals capable of learning. Income requirements, home inspections, and mandatory exams are barriers inconsistent with this evidence-based philosophy."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Up to two-thirds of individuals walking through an animal shelter have no initial intention of adopting an animal that day. How should a progressive shelter best capitalise on this visitor segment?","o":["Restrict facility access exclusively to individuals who have paid a non-refundable adoption deposit.","Deploy trained volunteers to engage with these visitors, providing a positive experience and recruiting potential future adopters and volunteers.","Fast-track these individuals out of the building to preserve staff resources for committed adopters.","Mandate that they complete a formal relinquishment profile upon entry."],"a":1,"e":"Since up to 2/3 of visitors have no immediate adoption intention, utilising volunteers to engage them builds future donor, volunteer, and adopter networks. A positive experience today can translate into an adoption visit tomorrow."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"A shelter reviews its regional outreach strategy. According to published data on how far potential adopters are willing to travel, what geographic radius represents the primary search zone for the majority of adopters?","o":["A strict 5-mile radius.","A 30-mile radius.","A 90 to 120 mile radius.","An international border zone."],"a":1,"e":"While some adopters are willing to travel up to 90 miles, the vast majority of shelter traffic searches within a local 30-mile radius. Shelters must understand and engage their immediate community demographics."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Historical sheltering mandated high adoption fees and income verification to guarantee animal quality of life. What does current shelter research demonstrate regarding these practices?","o":["Lowering adoption fees causes an immediate 50% spike in post-adoption return rates.","High family income is the single most accurate predictor of strong owner-pet attachment.","There are no statistical differences in owner attachment or return rates when adoption fees are reduced or waived.","Waiving adoption fees completely erodes community respect for the sheltering organisation."],"a":2,"e":"Research confirms that waiving or lowering fees does not degrade the owner-pet bond or increase return rates. A low advertised adoption price is a documented predictor of shelter visits. Income requirements are not evidence-based welfare safeguards."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"When an adopted animal is returned to the shelter, how should a conversational adoption counsellor operationally reframe this event?","o":["As a failure of the screening process that requires blacklisting the adopter.","As a valuable learning opportunity to gather data on that specific animal, making the next match more accurate.","As an administrative penalty that must be logged against the counsellor's performance metrics.","As a sign that the local community lacks basic animal welfare empathy."],"a":1,"e":"Returns are non-judgmental data collection events. They reveal real-world animal behaviour that improves subsequent matching. The same returning adopter can be offered a better-matched animal, or recruited as a foster carer or shelter advocate."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"During the initial visual browsing phase in a canine holding ward, what is the primary factor that dictates visitor stopping behaviour?","o":["The dog's performance of advanced in-kennel operant obedience commands.","The structural morphology of the dog.","The vocalization volume and bark rate of the dog.","The presence of a commercial pedigree certificate on the kennel door."],"a":1,"e":"Studies confirm that in-kennel behaviour modification does not alter browsing choices; stopping behaviour is driven entirely by phenotypic morphology. This is why dog training investment should target meet-and-greet skills, not in-kennel performance."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"On average, a visitor browsing a canine holding ward will stop and look at approximately one-third of the available dogs. Once stopped, what is the typical duration of time spent viewing an individual dog?","o":["1 to 5 seconds.","15 to 70 seconds.","5 to 10 minutes.","Exactly 1 hour."],"a":1,"e":"Visitors browse rapidly, pausing for an average of 15 to 70 seconds once a specific dog's morphology catches their attention. Only approximately 1% of dogs are taken out of the kennel for further interaction."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Which feline housing variable is statistically associated with increased frequency of visual viewing by potential adopters?","o":["Housing cats exclusively in dark, low-tier floor-level cages.","Housing cats in top-tier cages that contain a toy.","Maintaining horizontal cages with zero visual hiding barriers.","Housing the cat communally with at least ten unrelated adult felines."],"a":1,"e":"Feline choice metrics improve when cats are housed in top-tier, eye-level enclosures equipped with simple enrichment toys. The frequency of viewing (not duration) predicts ultimate adoption."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"A shelter re-orients its traditional horizontal cat cages to a vertical position and adds a simple shelf and towel hiding area. What is the direct operational outcome of this low-cost environmental modification?","o":["An increase in stress-related stereotypical pacing.","A reduction in feline stress behaviours and an increase in successful adoption outcomes.","An immediate doubling of the cat's medical length of stay.","A total loss of visual contact between the visitor and the feline."],"a":1,"e":"Converting a horizontal footprint cage into a vertical structure with a perch and hiding area reduces feline stress behaviours and improves adoption outcomes, at very low cost. This is one of the most powerful evidence-based environmental interventions in feline sheltering."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Two cats are physically identical, exhibit identical latencies to approach unfamiliar people, and display behaviorally identical profiles. Cat A is labelled 'Owner-Surrender' and Cat B is labelled 'Stray.' How does this labelling difference affect their shelter metrics?","o":["Cat B (Stray) will be adopted significantly faster than Cat A.","Cat A (Owner-Surrender) will be adopted significantly faster than Cat B.","Both cats will experience an identical length of stay to the exact day.","Cat A will show a 40% increase in stress vocalisations due to the label."],"a":1,"e":"Adopters are subject to a documented cognitive labelling bias. The 'Owner-Surrender' tag systematically compresses LOS compared to the 'Stray' tag, even when there is no objective behavioural difference between the two cats. This finding has been replicated when the only difference between groups was the label."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"During a canine meet-and-greet session, which two behaviours displayed by the dog are the strongest statistical predictors of subsequent adoption?","o":["Continuous high-pitched barking and jumping on the adopter's torso.","High-intensity resource guarding and vocalising over a tennis ball.","Reciprocal play and lying down in close proximity to the potential adopter.","Rapid perimeter tracking and avoiding human touch."],"a":2,"e":"The two most powerful behaviour-driven conversion triggers during a meet-and-greet are reciprocal play and proximate relaxation (lying down near the adopter). These are the training targets for improving adoption rates."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"To optimise adoption outcomes based on behavioural science, where should shelter canine training resources be primarily focused?","o":["Teaching dogs to sit perfectly at the back of their indoor kennel during the browsing phase.","Training dogs to perform behaviours relevant to the meet-and-greet room, including relaxing and lying down next to a bench or chair.","Training dogs to avoid looking at visitors during morning feeding shifts.","Teaching dogs to ignore toys entirely when interacting with staff."],"a":1,"e":"Training investment yields the highest adoption returns when applied to meet-and-greet skills, not in-kennel performance. The specific target behaviour is calm relaxation and lying down near the location where an adopter will sit."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"In an experimental study of meet-and-greet parameters, what adjustment resulted in a near-doubling of successful canine adoptions?","o":["Conducting the interaction in a large open outdoor area with multiple distractions.","Ensuring the room contained at least twenty novel squeaker toys for enrichment.","Using a small enclosed area, encouraging the dog to stay close and lie down, and limiting items to the dog's favourite toy only.","Requiring the adopter to stand continuously in complete silence."],"a":2,"e":"Restricting meet-and-greet parameters to a small enclosed space, calm proximity behaviour, and a single favourite toy produced a near-doubling of adoption rates in experimental conditions."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Clicker training can improve adoption metrics for shelter cats. What is the primary training objective when using positive reinforcement with a kennelled cat?","o":["Training the cat to hide under its towel when a visitor approaches.","Training the cat to approach the front of the kennel, increasing exploratory behaviour and reducing inactivity.","Teaching the cat to vocalise continuously until food is delivered.","Conditioning the cat to scale the vertical wire walls of the cage."],"a":1,"e":"Feline clicker target programmes draw cats to the front of the enclosure, reducing inactivity and boosting public perception of friendliness. Cats who approached unfamiliar people had shorter times to adoption in research studies."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"When a shelter implements a matching programme where counsellors guide adoption conversations before potential adopters browse the kennels, what dual effect does this have on shelter metrics?","o":["It compresses the overall length of stay while simultaneously driving up return rates.","It results in better positive placement outcomes but yields a longer average length of stay (aLOS).","It completely eliminates the occurrence of spontaneous adoptions.","It drops adopter satisfaction scores to zero."],"a":1,"e":"Pre-browsing matching conversations optimise final placement compatibility but cause an operational increase in average LOS. This is a documented trade-off that shelter managers must weigh when designing their adoption process."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"According to shelter marketing research, what component should be strictly omitted from an animal's initial online digital adoption profile?","o":["A high-quality photo taken outdoors with the animal making eye contact.","A short video clip showing the animal interacting with toys.","Warnings or explicit alerts regarding potential matching issues.","Descriptive words such as 'clever,' 'independent,' or 'lively.'"],"a":2,"e":"Marketing profiles should remain positive to capture broad interest. Behavioural deficits or matching restrictions placed in the initial public profile reduce adoption interest and increase LOS. These topics must be reserved for one-on-one counselling with serious prospective adopters."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"A shelter removes all breed labels from its canine adoption kennels and online profiles. Based on the documented NYC shelter study, what is the expected outcome?","o":["The return rate for large-breed dogs spikes exponentially.","The length of stay is reduced for all dogs, with no change in the baseline return rate.","Potential adopters will boycott the shelter's website entirely.","The frequency of meet-and-greet sessions drops by exactly 50%."],"a":1,"e":"Removing breed labels eliminates stereotype-based bias, compressing LOS for all dogs without changing baseline return dynamics. The NYC shelter study found no adverse consequences from removing breed labels."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Which set of descriptive words is statistically proven to predict a shorter length of stay when integrated into an animal's online adoption biography?","o":["Only dog, dominant, sensitive, happy-go-lucky.","Overlooked, unwanted, left behind, waiting for six months.","Make you proud, independent, lively, eager, clever.","Aggressive, fear-reactive, destructive, territorial."],"a":2,"e":"Positive, action-oriented descriptors predict a compressed LOS, whereas restrictive phrases (only dog, dominant) or sympathy-seeking phrases (overlooked, waiting) increase LOS or damage the animal's perceived value."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"When writing profiles for long-stay shelter animals on social media, what psychological concept explains why repeatedly posting an animal's face increases its perceived attractiveness?","o":["The Contrast Effect.","The Mere Exposure Effect.","The Narrative Bias.","The Reactance Principle."],"a":1,"e":"The mere exposure effect dictates that repeated visual exposure to a face builds subconscious familiarity and heightened perceived attractiveness. Consistent, frequent social media posting is therefore an evidence-based strategy for long-stay animals."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"To maximise interest from potential adopters via digital text descriptions, what style of language should be prioritised in adoption advertisements?","o":["Highly descriptive, long-form narrative language with emotional storytelling.","Concrete and analytic language.","Ambiguous metaphorical prose.","Strictly technical veterinary diagnostic codes."],"a":1,"e":"Research shows adopters respond with significantly higher interest to concrete, analytical language over narrative or prose-heavy descriptions. Clear, factual, action-oriented writing outperforms emotional storytelling in adoption ad effectiveness."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Longitudinal studies evaluating animal retention show that what percentage of animals are no longer in their adoptive home one year post-adoption due to behavioural problems?","o":["12%.","24%.","64%.","95%."],"a":2,"e":"Long-term data shows that 64% of animals displaced from their adoptive homes within one year are lost due to unresolved behavioural challenges. This makes post-adoption behavioural support a primary lever for improving placement permanency."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Behavioural issues account for what percentage of formal canine and feline returns to the shelter?","o":["10% of dogs and 10% of cats.","54% to 74% of returned dogs and 38% of returned cats.","90% of dogs and 85% of cats.","5% of dogs and 95% of cats."],"a":1,"e":"Behavioural issues are the primary driver of formal shelter returns, accounting for 54% to 74% of dog returns and 38% of cat returns. Problematic behaviour is documented as the leading cause of non-retention of adopted animals."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Approximately 20% of all adopters no longer possess their pet one year after adoption, yet only 49% of those animals are formally returned to the shelter. What primarily drives an adopter's decision to bypass the shelter when rehoming?","o":["High monetary surrender fees levied by the municipality.","The availability of lucrative commercial online pet marketplaces.","Fear of being judged as a failure by the sheltering organisation.","Strict legal mandates requiring immediate microchip forfeiture."],"a":2,"e":"Adopters frequently utilise alternative rehoming networks because they fear institutional judgment and shame from shelter staff. Shelters must actively position themselves as a non-judgmental resource to recover these animals into a managed pathway."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"When analysing the temporal trends of canine returns, what specific timeframe represents the highest-risk window, where 41% of returned dogs are brought back to the facility?","o":["Within the first week of adoption.","Between 2 weeks and 2 months post-adoption.","Exactly 6 months following placement.","On the 365th day post-adoption."],"a":0,"e":"The acute post-adoption period is highly volatile. 41% of returned dogs come back within the first week, making the first 7 days the highest-risk window for placement failure and the most critical time for proactive support contact."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"What percentage of adopters globally report that their newly adopted companion exhibits a behavioural concern of note within the first week following adoption?","o":["Less than 5%.","Approximately 15% to 25%.","Roughly 50% to 70%.","100% of all adopters."],"a":2,"e":"50% to 70% of all adopters globally report a problematic behavioural concern within the first week of adopting a shelter pet. This near-universal prevalence underscores why proactive first-week outreach is a critical component of post-adoption support."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"Providing a brief, 5-minute targeted counselling session to an adopter at the time of placement significantly improves retention. What topic showed measurable improvement one month post-adoption in the documented study?","o":["Advanced tracking and protection work.","Feline clicker training schedules.","Housetraining.","Raw food diet formulation."],"a":2,"e":"A brief, targeted 5-minute counselling intervention specifically on housetraining at the time of adoption produced significantly higher long-term success one month post-adoption. Short, focused counselling outperforms comprehensive but overwhelming information delivery."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"A shelter counsellor wants to reduce the incidence of separation-related problems (SRP) in newly adopted dogs. According to post-adoption research, which two strategies showed the highest adopter compliance in an SRP prevention handout?","o":["Crate training for 12 continuous hours and using sound-muffling curtains.","Refraining from interacting with the dog immediately before leaving, and providing a food-filled enrichment toy when the dog is left alone.","Playing high-volume music and leaving all household lights on.","Hiring a professional dog walker and administering daily supplements."],"a":1,"e":"Handout compliance is selective. Research found the highest adopter compliance with two specific strategies: not interacting with the dog before departure, and providing a food-filled enrichment toy when left alone. Other strategies in the handout had low compliance rates."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"To ensure information retention and high compliance, what structural principle must guide all at-adoption counselling sessions?","o":["Provide long, multi-page scientific textbooks covering all possible canine behaviours.","Focus on only a few high-priority issues, keeping the information short and simple.","Rely entirely on verbal instruction without any written backup documentation.","Require the adopter to pass an interactive video simulation exam before leaving."],"a":1,"e":"Compliance drops when counselling covers too many topics. The evidence-based principle is to narrow the scope to the most critical issues and keep delivery concise. Information overload at the time of adoption leads to low follow-through on all advice."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"What are the 5 high-priority counselling points that should be proactively discussed when an adopter takes home a new dog?","o":["Basic conformation showing, dental scaling, agility rules, collar selection, and microchip brand.","Housetraining, safeguarding against separation-related problems, proper introductions to resident pets, the importance of physical and mental stimulation, and the animal's individual personality and behavioural characteristics.","Genetic health history, commercial food manufacturing, leash laws, local park maps, and grooming requirements.","Bite-work mechanics, clicker mechanics, crate sizing, tracking paths, and scent work setup."],"a":1,"e":"The 5 canine discharge points are: Housetraining, SRP prevention, Introductions, Stimulation and training, and the animal's individual personality. For cats, there are 4 points: Litterbox, Scratching, Settle-in time, and Introductions."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"If an adopter reports human-directed aggression from their newly adopted dog, what is the statistical impact of providing management advice compared to providing no behavioural advice?","o":["The adopter is 20 times more likely to return the animal if advice is given.","The return likelihood drops from 11 times more likely (no advice) down to 5.5 times more likely (with basic management advice).","Providing advice has a 0% impact on return probability.","It completely eliminates the probability of the dog ever showing aggression again."],"a":1,"e":"Providing basic management protocols for human-directed aggression reduces the return likelihood from 11 times more likely (no advice) to 5.5 times more likely (with advice), approximately halving the risk. The correct figure with advice is 5.5 times, not elimination of risk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"According to the national AVCC/CARE dataset, how does household income correlate with the probability of owning only a single companion animal?","o":["High-income households are significantly more likely to own only one pet compared to low-income brackets.","Approximately 1/3 of the lowest-income households own only one pet, compared to 43.6% of middle-income and 44.4% of high-income households.","Low-income households universally own a strict minimum of five animals due to stray absorption.","Income level shows zero statistical correlation with pet population density."],"a":1,"e":"Lower-income households paradoxically own more pets. Only ~1/3 of the lowest-income bracket reported owning one pet versus 43.6% (middle income) and 44.4% (high income). This counterintuitive finding is a classic exam trap."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"When evaluating pet ownership profiles by gender and income, which demographic groups are statistically most likely to report owning only dogs?","o":["Low-income households and female respondents.","High-income households and male respondents.","Middle-income households and geriatric female respondents.","Homeless populations and unaccompanied youth under 25."],"a":1,"e":"Dog-only households are significantly correlated with higher income tiers and male respondents. Females and lower-income households are more likely to have cats or blended families."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Which age-based trend accurately reflects companion animal family structure and pet insurance utilisation in the general population surveyed by AVCC/CARE?","o":["Older respondents are more likely to maintain a blended family and purchase pet insurance.","Younger respondents are more likely to have a blended family (dogs and cats) and to report owning a pet insurance policy.","Younger pet owners are more likely to own cats exclusively and reject insurance.","Age brackets demonstrate uniform consistency across family structures and insurance metrics."],"a":1,"e":"Younger respondents are significantly more likely to navigate a blended dog/cat family and to proactively secure a pet insurance policy. Older respondents are more likely to own only cats or a single pet."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Regarding regional pet insurance variations within the United States, which geographic territory demonstrates the highest policy ownership rate?","o":["The Southern US.","The Western US.","The Northeast Corridor.","The Midwest."],"a":1,"e":"Regional tracking showed distinct variations. The Western United States yields the highest pet insurance policy ownership rate, compared to the Midwest which had the lowest rate."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"How do pet acquisition pathways and spay/neuter prevalence differ for households living at the lowest socioeconomic tier (below 138% of the federal poverty level)?","o":["They are more likely to buy dogs from preservationist breeders, and their pets have high spay/neuter rates.","They are more likely to have taken in a stray animal, and their pets are less likely to be spayed or neutered compared to higher-income brackets.","They rely exclusively on commercial pet stores for cat acquisitions.","They report identical shelter adoption rates and spay/neuter compliance as households earning above 250% of the poverty level."],"a":1,"e":"Households below 138% FPL are more likely to take in stray animals and have significantly lower spay/neuter rates. If their pets were sterilised, it was more likely at a free or reduced cost clinic. Higher-income households are more likely to acquire dogs from breeders and have higher S/N rates."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Approximately what proportion of the general public surveyed in the AVCC national study indicated they were unable to secure preventative veterinary care for at least one pet in the recent past?","o":["5% of all respondents.","One quarter (1/4) of all respondents.","Exactly half (1/2) of all respondents.","90% of all respondents."],"a":1,"e":"Exactly 1/4 of all survey respondents stated they had experienced a direct barrier to obtaining preventative veterinary care in the recent past. Barrier prevalence decreases as household income increases."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"When pet owners facing preventative care barriers were surveyed regarding the specific services they desired but could not obtain, what were the two primary clinical needs?","o":["Cosmetic procedures (75%) and dental scaling (60%).","Vaccinations (65%) and heartworm, flea, or tick preventative treatment (50.7%).","Microchipping (90%) and behavioural agility training (45%).","Elective surgery (55%) and international health certification (35%)."],"a":1,"e":"The two most frequently desired yet unobtained preventative care services were vaccinations (65%) and ecto/endoparasiticides including heartworm, flea, and tick prevention (50.7%)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"When examining the structural barriers to sick care, what unique economic convergence was observed within the middle-income cohort (138% to 250% of the poverty level)?","o":["They faced zero financial barriers to sick care due to their intermediate income.","They were just as likely to cite an inability to afford care as a barrier as those in the lowest income category.","They relied exclusively on mobile units rather than traditional clinics.","They reported higher transportation barriers than financial barriers."],"a":1,"e":"Sick care metrics revealed a unique economic trap: middle-income pet owners were just as likely to face affordability barriers as those in the lowest income tier. This convergence is not seen for preventative care, where barriers clearly decrease with income."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Why is the documented incidence of pet owners failing to meet emergency veterinary care needs lower than the unmet barriers recorded for preventative or sick care?","o":["Emergency procedures are completely cost-free across the United States.","Emergency care is needed less frequently, with only approximately 1/3 of pet owners requiring emergency care within the past 2 years.","Private emergency clinics are legally mandated to accept all public assistance vouchers.","Pet insurance covers 100% of emergency visits for low-income families."],"a":1,"e":"Emergency care barriers present a lower overall incidence because the need arises infrequently, with only about 1/3 of owners requiring it across a 2-year window. This does not indicate better accessibility, only lower frequency of need."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"What is the correct ranking of financial barrier rates across the three tiers of veterinary care, from highest to lowest?","o":["Preventative 80%, sick care 73.8%, emergency care 55.7%.","Sick care 56%, preventative 74%, emergency care 80%.","Emergency care 80%, sick care 11%, preventative care 15%.","Preventative care 65%, sick care 50.7%, emergency care 25%."],"a":0,"e":"The correct ranking from highest to lowest financial barrier rate: preventative care (80%), sick care (73.8%), emergency care (55.7%). These three figures are directly from the AVCC/CARE study and are among the most exam-tested statistics in this subdomain."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Within the study population of pet owners experiencing housing insecurity, what was the recorded mean age and primary gender distribution of the respondents?","o":["Mean age of 25 years; 90% male.","Mean age of 44 years; 77% female.","Mean age of 68 years; 50% male and 50% female.","Mean age of 19 years; 85% non-binary."],"a":1,"e":"The targeted housing-insecure cohort had a mean age of 44 years (range 18 to 79) and was 77% female. 65% received at least one form of public assistance."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"What percentage of housing-insecure pet owners reported facing direct difficulty securing residential housing specifically due to companion animal ownership?","o":["5%.","12.3%.","32%.","77%."],"a":2,"e":"Nearly one-third (32%) of housing-insecure pet owners face direct housing refusal or rental exclusion due to animal ownership. This finding directly supports the role of pet-friendly housing support programs (covered in the shelter diversion subdomain)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"In sharp contrast to the general population data trends, which age-based cohort of housing-insecure pet owners was statistically more likely to experience barriers to preventative veterinary care?","o":["Younger respondents.","Older respondents.","Middle-aged respondents exclusively.","Children under the age of 18."],"a":1,"e":"While younger respondents face higher barriers in the general population, within the housing-insecure cohort the pattern reverses: older adults are more likely to face preventative care barriers. This age reversal is a high-yield exam finding."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"What constitutes the absolute primary barrier to securing preventative veterinary care for pet owners experiencing acute housing insecurity, reported at an overwhelming 96.1%?","o":["Lack of a legal pet carrier or leash.","Cost of care.","Fear of professional veterinary judgment.","Language and translation difficulties."],"a":1,"e":"Cost stands as the definitive and dominant barrier for housing-insecure populations at 96.1%, substantially higher than the 80% seen in the general population. Transportation (11.8%) and knowledge barriers (9.2%) are distant secondary concerns."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Within the housing-insecure study cohort, what percentage distribution represents households owning dogs only versus cats only?","o":["15.3% dogs only; 65% cats only.","46.5% dogs only; 24% cats only.","65% dogs only; 15.3% cats only.","29.6% dogs only; 19.7% cats only."],"a":2,"e":"Within the housing-insecure cohort, 65% of households owned dogs only and 15.3% owned cats only, with 19.7% having a blended family. Note that 46.5%/24% are the general population figures, not the housing-insecure cohort figures."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"According to the AVCC/CARE national dataset, what percentage of veterinary service providers feel a strong professional obligation to maintain the same standard of care for all clients?","o":["15.3%.","53.4%.","79.7%.","84.8%."],"a":2,"e":"79.7% of veterinary service providers believe they are professionally bound to offer the same standard of care across all demographics. Separately, 84.8% are comfortable adopting a flexible Spectrum of Care approach when severe financial constraints exist."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"To manage financial constraints while preserving professional quality, what percentage of surveyed veterinarians stated they are comfortable providing alternatives to the traditional standard of care?","o":["25.0%.","58.8%.","79.7%.","84.8%."],"a":3,"e":"84.8% of veterinarians are comfortable adopting a flexible Spectrum of Care framework when clients face economic restrictions. This is higher than the 79.7% who feel obligated to offer the same standard, indicating the profession broadly accepts contextualised care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"A mobile veterinary surgery unit aims to minimise administrative overhead while scheduling regional routes across low-density rural zones. Which community entity should they collaborate with to advertise their calendar?","o":["Local social services agencies.","Commercial pharmaceutical marketing branches.","Regional preservationist breeding associations.","Municipal corporate retail boards."],"a":0,"e":"Working with local social services to advertise the mobile unit's schedule reduces administrative costs while reaching the target population through trusted existing channels. This is explicitly recommended in the CARE focus group data."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"During the CARE focus groups, how did practitioners describe the strategic integration of veterinary technicians within high-volume mobile clinic workflows?","o":["Technicians are utilised to perform complex soft-tissue surgeries independently.","Technicians manage client interactions and flow, allowing veterinarians to maximise focus on medical care for patients.","Technicians are eliminated from the workflow to minimise payroll spending.","Technicians handle all financial billing and collection exclusively."],"a":1,"e":"Utilising veterinary technicians to optimise clinical workflows allows veterinarians to scale patient throughput and focus on medical care. One focus group quote summarised this as: 'People don't get the same interaction time with me; pets get the same quality.'"},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"What is the operational mechanism of the Companion Animal Foundation program funded by the Rhode Island Veterinary Medical Association?","o":["It mandates 100% subsidised pet health insurance for all local rescue groups.","It provides a $100 voucher to pet owners who lack a regular veterinary GP, redeemable at any GP in the area.","It operates a single-facility monopoly that restricts private practice licensing.","It conducts unannounced home inspections to enforce regional means-testing compliance."],"a":1,"e":"The Companion Animal Foundation issues $100 vouchers to pet owners without a regular veterinary GP. Funded through dues paid to the RI VMA, it provides an economic bridge to local general practitioners and simultaneously addresses education and healthcare access needs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Focus group insights highlight that most veterinarians and veterinary students have never personally experienced poverty. What training intervention is specifically recommended to bridge this gap?","o":["Advanced forensic accounting seminars.","Sensitivity training to build foundational cultural competencies.","Corporate public relations mock interviews.","Mandatory prosecutorial legal coursework."],"a":1,"e":"Sensitivity and cultural competence training is explicitly recommended within the CARE focus group data. Most vets and vet students lack lived experience of poverty; structured training helps them work effectively and respectfully with vulnerable populations."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"To ensure accessibility within linguistically diverse service zones, what is the minimum communication standard required for written veterinary educational and medical information?","o":["Documentation must be provided in English only.","Information must be offered in the second most common language spoken in that specific service area.","It must be written in classic Latin to preserve diagnostic precision.","It must rely exclusively on non-textual symbolic illustrations."],"a":1,"e":"Cultural competence mandates that vital written instructional text be translated into at least the second most common language of the operational zone. English-only documentation is insufficient for diverse communities. Ideally a bilingual veterinarian or technician (Spanish fluency in the US) is on staff."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Focus groups emphasise that successful safety net veterinary programs must remain highly collaborative, explicitly warning practitioners against creating what?","o":["'Sovereign clinics' managed exclusively by academic boards.","'Fiefdoms,' and urging collaborative cooperation instead.","'Regulatory traps' designed by medical suppliers.","'Pauper clinics' that alter regional pricing structures."],"a":1,"e":"Focus group clinicians explicitly warned against creating isolated operational 'fiefdoms' instead of pursuing cooperative, shared resource networks. The recommendation is for agencies to work collaboratively, share resources, and avoid duplication of services."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"How can a community-focused safety net program apply geographic means-testing without requiring intrusive personal financial documentation from clients?","o":["By cross-checking personal credit scores online.","By drawing names randomly from municipal tax registries.","By offering veterinary services directly within a neighbourhood known to be low-income.","By restricting service delivery exclusively to stray purebred animals."],"a":2,"e":"Delivering care directly inside low-income ZIP codes or geographic zones acts as a dignified, reliable, and non-intrusive method of structural means-testing, avoiding the need for personal financial documentation at the front desk."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Within the CARE focus group data, what specific term defines the individual or group who recognises a community service gap, possesses the connections to convince others, and maintains the long-term stamina to sustain a program?","o":["The Chief Veterinary Officer.","The Social Worker-in-Residence.","The 'Champion.'","The Operational Director."],"a":2,"e":"A 'Champion' is defined as the passionate, connected driving force who possesses the community trust and long-term stamina to sustain a safety net veterinary program. Programs typically start with a Champion initiating dialogue: 'What can you do? What are your boundaries?'"},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Attachment Theory, one of the two primary frameworks used to understand the human-animal bond, was originally developed by observing which specific interaction dynamic?","o":["The social hierarchy of domestic canine packs.","The developmental relationships between human mothers and their infants.","Employee performance variations in industrial manufacturing plants.","The behaviour of domestic feline colonies under high-density confinement."],"a":1,"e":"Attachment Theory originates from human developmental psychology research studying mother-infant relationships. It has since been extended to human-animal bonds. It recognises four attachment styles, and the strength/style of attachment shapes how an owner responds to barriers in providing care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"According to Social Support Theory, how do tangible or intangible supportive actions directly protect an individual navigating a severe chronic crisis?","o":["They speed up tissue wound healing through localised placebo effects.","They buffer the physiological and psychological health impacts of stress.","They eliminate the clinical need for any future medical interventions.","They mandate that the individual become completely self-reliant."],"a":1,"e":"Social support networks function as crucial health buffers against the physiological and psychological damage caused by high-stress crises. Companion animals can function as social support for their owners, which is why the human-animal bond has documented physical and mental health protective effects."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Survey data from the AVCC 2018 national study tracked the human-animal bond. What percentage of respondents strongly agreed with the explicit statement 'My pets are considered a member of my family'?","o":["24%.","46.5%.","80.2%.","95%."],"a":2,"e":"In the AVCC 2018 CARE national study, 80.2% of respondents strongly agreed that their pets are family members. Note: 95% is from a separate 2015 survey also referenced in the notes. Read the source carefully. These two figures are both testable and easily confused."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"When an unhoused or homeless pet owner actively refuses temporary human housing or crisis shelter accommodation, what is frequently the underlying reason?","o":["The human facility charges high daily usage fees.","The facility's strict accommodation policies do not allow animals inside.","The owner prefers to seek placement in specialised psychiatric wards.","The human shelter mandates pet sterilisation prior to entry."],"a":1,"e":"Rigid no-pet policies at human crisis centres frequently force homeless individuals to sleep outdoors to protect their pets. Studies document that some homeless individuals put the animal's needs above their own and refuse services rather than be separated from their companion animal."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"A community assessment notes that 'moving as the result of a life situation' is a major driver of shelter relinquishment. Which group of circumstances fits this category?","o":["Purchasing a secondary vacation home or changing recreational hobbies.","Loss of or change in employment, housing issues, health issues, or financial difficulties.","Enrolling in advanced veterinary nursing academic programmes.","Seasonal temperature fluctuations in municipal parks."],"a":1,"e":"Job loss, health emergencies, financial depletion, and systemic housing issues represent the primary life situations that force disruptive moves and drive relinquishment. Natural disasters are also cited. These are structural social determinants of health, not personal lifestyle choices."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Which statement best captures the spectrum of care concept as used in accessible veterinary medicine?","o":["A range of acceptable, evidence-based diagnostic and treatment options extending from basic to advanced, with no single option being the only correct one.","A fixed protocol that all patients must receive regardless of client circumstances.","A discount scheme in which gold-standard care is offered at a reduced price to qualifying clients.","A triage system that ranks patients by severity on arrival."],"a":0,"e":"Spectrum of care is the range of evidence-based options from basic to advanced. Its core claim is that more than one point on the range can be medically and ethically sound, which rejects the gold-standard-or-nothing binary. It is not a discount, a fixed protocol, or a triage tool."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"How does contextualised care differ from spectrum of care?","o":["They are identical terms with no practical difference.","Spectrum of care is the range of options; contextualised care is the process of choosing among them using the patient and client context.","Contextualised care applies only in shelters, while spectrum of care applies only in private practice.","Contextualised care always means selecting the most advanced option available."],"a":1,"e":"Spectrum of care describes the menu of evidence-based options. Contextualised care is the decision-making process that selects from that menu based on the individual patient and the client's financial reality, logistics, values, and goals. They are related but not synonymous."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Forsgren defines incremental care as which of the following?","o":["Care delivered only after a client has exhausted all personal savings.","A mandatory hospitalisation protocol for all critical cases.","Patient-centred, evidence-based medicine delivered in the context of limited resources.","The most advanced care available, simply delivered in stages over time."],"a":2,"e":"Incremental care is patient-centred, evidence-based medicine in the context of limited resources. It emphasises prevention, early diagnosis, client-delivered in-home care, telehealth, and frequent re-evaluation, guided by the principle that no care is not an option and above all do no harm."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"An outpatient canine parvovirus protocol studied at Colorado State is frequently cited as evidence that incremental care can be viable. Which figures are reported?","o":["Approximately 50% survival outpatient versus 95% hospitalised.","Approximately 30% survival outpatient versus 60% hospitalised.","Equivalent survival in both groups.","Approximately 80% survival outpatient versus approximately 90% hospitalised."],"a":3,"e":"The outpatient protocol reported roughly 80% survival, compared with roughly 90% for full hospitalisation. The relatively small gap supports offering an outpatient option when hospitalisation is unaffordable, rather than defaulting to euthanasia or no treatment. Figures are approximate, from the access-care literature."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Which of the following is NOT one of the four recognised elements of informed consent?","o":["Guaranteeing a successful clinical outcome.","Disclosure of options, risks, benefits, prognosis, and cost.","The client's voluntary, uncoerced decision.","Documentation of the consent in the medical record."],"a":0,"e":"The four elements are disclosure, comprehension or capacity, voluntariness, and documentation. Guaranteeing an outcome is not an element of consent and is not something a veterinarian can ethically promise. Consent is required regardless of the client's socioeconomic status."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"A dog has completed its stray hold and ownership has transferred to the shelter. Who provides informed consent for a recommended surgical procedure?","o":["The veterinarian must locate and obtain consent from the original finder.","The shelter, as the animal's legal custodian, through its designated decision-maker.","Consent is not required for any shelter animal under any circumstance.","The municipal court must approve each individual procedure."],"a":1,"e":"Once ownership has transferred to the shelter, the shelter is the decision-maker and consents on the animal's behalf through its designated authority. This differs from a private clinic, where the owner consents. Animals still under stray hold, or under a legal or evidentiary hold, are exceptions where shelter authority may be limited."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"On the VCE engagement continuum, which stage places decision-making power with the community while the veterinary team plays a supporting role?","o":["Outreach.","Consult.","Shared leadership.","Involve."],"a":2,"e":"The continuum runs Outreach, Consult, Involve, Collaborate, Shared Leadership, with community power increasing along it. At shared leadership the community holds decision-making power and the veterinary team supports. Outreach is one-way information delivery with the least community integration."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"In VCE, what is a proximate leader?","o":["A senior veterinarian appointed to oversee the program from outside the community.","A government official who licenses community clinics.","The largest financial donor to a program.","A member of the community being served who bridges the veterinary team and the community and is essential for trust and cultural translation."],"a":3,"e":"Proximate leaders are community insiders who connect the team to the community. They are essential for trust, outreach, and cultural translation, and cannot be substituted with outsiders, however well-intentioned."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Why does VCE Principles 2024 prefer the term cultural humility over cultural competence?","o":["Because cultural humility frames the work as ongoing self-reflection and openness to learning rather than a mastery to be completed and ticked off.","Because cultural competence is illegal in most states.","Because the two terms mean exactly the same thing and the choice is arbitrary.","Because cultural humility requires formal certification while cultural competence does not."],"a":0,"e":"Cultural competence implies a finite mastery that can be achieved. Cultural humility frames cross-cultural work as a continuous practice of self-reflection and learning, which better fits the power differentials present when veterinary teams from positions of relative privilege serve under-resourced communities."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"Asset-based community development (ABCD) is best described as which approach?","o":["Leading with a detailed inventory of the community's deficits and unmet needs.","Mapping what the community already has, including its people, organisations, and institutions, and building from those strengths.","Relocating successful programs from wealthier areas into under-resourced ones unchanged.","Prioritising the purchase of physical assets such as buildings and vehicles before any other step."],"a":1,"e":"ABCD begins with the community's existing assets rather than its deficits, and builds from strengths. It pairs with social capital, the value generated by a community's relationships, networks, and trust. Deficit-led approaches risk importing solutions that do not fit."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"VCE describes five categories of resources a program must consider. Which set correctly lists them?","o":["Clinical, surgical, diagnostic, pharmaceutical, behavioural.","Local, regional, state, federal, international.","Fiscal, human, physical, information, organisational.","Marketing, legal, accounting, logistics, security."],"a":2,"e":"The five categories are fiscal, human, physical, information, and organisational. Human resources explicitly include proximate leaders alongside veterinarians, technicians, and volunteers, and organisational resources include partnerships and institutional backing."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Epidemiology of Homelessness","q":"How do One Health and One Welfare relate to community veterinary programs for vulnerable populations?","o":["They argue that animal and human health should be addressed by entirely separate systems.","They apply only to zoonotic outbreak response and not to routine care.","They state that animal welfare should be prioritised above human welfare in all cases.","They frame human, animal, and ecosystem wellbeing as interconnected, so improving animal welfare in these populations also improves human welfare."],"a":3,"e":"One Health connects human, animal, and ecosystem health; One Welfare treats human and animal wellbeing as inseparable. This is the conceptual basis for integrating veterinary social workers into care teams, since the systems shaping a vulnerable owner's life also shape their animal's access to care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"According to the ASV guidelines, what operational outcome must fundamentally drive decision making within animal relocation and transfer programs?","o":["Maximising the physical size and volume of the transport vehicle.","Keeping animals in holding patterns until local live outcomes are completely exhausted.","Prioritising a decrease in the overall length of stay (LOS) for the animals.","Ensuring 100% of animals are returned to the source if they fail to adopt."],"a":2,"e":"Decisions within relocation networks must aim to lower the animal's total LOS, preventing overcrowding and localised resource strain. Holding animals for relocation when local live outcomes exist pushes shelters beyond their capacity for care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Under what explicit condition is it considered UNACCEPTABLE to transport an animal in a relocation program?","o":["When the transport itself is likely to be harmful to the animal's immediate or long-term health or welfare.","When the destination shelter does not have a full-time behaviour manager.","If the animal has not received a secondary booster vaccine 14 days prior.","If the animal is an adult dog that tested negative for heartworm."],"a":0,"e":"Transport is unacceptable when the journey itself poses an active threat to, or is highly likely to degrade, the animal's immediate or long-term clinical or emotional welfare. Careful management and planning are required."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"When setting up a lawful interstate or regional transfer network, which regulatory elements are commonly mandated by state Departments of Agriculture and Health?","o":["Mandatory genetic breed tracing and microchip manufacturer matching.","Valid certificates of veterinary inspection (CVIs), specific vaccinations, and age or health condition restrictions.","Written signed waivers from all adoption clients within a 50-mile radius.","Direct corporate registration with the Federal Aviation Administration."],"a":1,"e":"Jurisdictional transits are governed by state agricultural and public-health bodies via mandatory CVIs, certain vaccinations, and age or health restrictions. For commercial air, the airline must also be consulted."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"If a destination shelter routinely discovers that arriving transported animals are medically or behaviourally ineligible for adoption, what action must the partners take?","o":["Immediately ship the ineligible animals back to the source via air transport.","Increase the destination shelter's maximum capacity beyond its standard care limits.","Transition the program exclusively to international feral cat imports.","Revisit and adjust the program's selection criteria and baseline goals."],"a":3,"e":"Repeated intake eligibility failures call for a programmatic pause to re-adjust selection criteria and goals. Unless extenuating circumstances exist, animals are not returned to the source, because transport is a major stressor and resource investment."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"To capture individual concerns and recognise programmatic trends in time to respond, when should non-urgent health and outcome data be collected and analysed?","o":["Within 24 hours of arrival, followed by a mandatory weekly public audit.","Collected within 14 days of relocation, with a quarterly analysis of aggregate data.","Every 12 months, trailing the close of the federal fiscal year.","Only when requested by local law enforcement or public health agencies."],"a":1,"e":"ASV points to a 14-day window for non-urgent data collection paired with a quarterly aggregate analysis. These are two distinct and separately testable timelines."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"What is the correct protocol for administering vaccinations within a source shelter's population prior to a transport program?","o":["Delay all intake vaccinations until the animal arrives at its final destination.","Vaccinate only the specific high-value animals chosen for the immediate transport pool.","Vaccinate all eligible animals within the source population at or before intake.","Administer vaccines exclusively to juvenile animals under 8 weeks of age."],"a":2,"e":"Vaccinating only the moving population is insufficient because it leaves the majority unprotected. All eligible animals must be vaccinated at or before intake. Holding animals back just for a vaccine response or booster is not recommended."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"A source shelter is preparing adult dogs for relocation. What is the explicit requirement regarding heartworm (HW) disease testing?","o":["All dogs 6 months of age and older are tested for HW disease prior to relocation.","Heartworm testing should be bypassed to decrease the source length of stay.","Only dogs displaying clinical signs of coughing require a heartworm test.","Testing is optional if the animal receives a pheromone spray treatment."],"a":0,"e":"Ideally, every canine candidate aged 6 months or older receives heartworm screening before being cleared for departure. Treatment for fleas, ticks and internal parasites is also strongly recommended."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Within what timeframe prior to travel must an animal be evaluated by trained source staff and deemed fit for transport?","o":["Within 72 hours prior to departure, confirmed via a digital photo log.","Exactly 5 days before loading to allow vaccine response tracking.","Immediately upon vehicle engine ignition at the loading dock.","Within 24 hours prior to travel."],"a":3,"e":"A physical screening by trained staff must occur within 24 hours before departure, to catch infectious disease and evaluate the animal's ability to tolerate the physical and emotional stresses of travel."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"If an animal chosen for transport has underlying medical concerns or is recovering from surgery, who must explicitly confirm its fitness for transport?","o":["The transport vehicle driver or operations section chief.","A licensed veterinarian.","The local Department of Agriculture field inspector.","The destination shelter's foster coordinator."],"a":1,"e":"Trained staff can screen apparently healthy animals, but any animal with active medical conditions or recovering from surgery requires explicit clearance from a licensed veterinarian."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Before accepting an animal transport from an international source, what should a domestic destination shelter carefully evaluate?","o":["The market value of out-of-state air transport fuel subsidies.","Whether the source country uses identical microchip scanning frequencies.","The needs of partners closer to home and the impact of the partnership on its own mission.","The availability of scented essential oils to coat the transport enclosures."],"a":2,"e":"Destination facilities should look locally first, weighing nearby regional needs and ensuring an international mission does not dilute their primary local purpose. They should also keep a written policy statement explaining the decision."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Why do the ASV guidelines state that factory-installed cargo climate control units should be avoided in an animal transport vehicle?","o":["They require proprietary fuel blends unavailable during long-distance travel.","They are designed for static items (like flowers) and lack the airflow, distribution and power to handle live-animal metabolic body heat.","They automatically shut down if vehicle speed exceeds 50 miles per hour.","They emit high levels of carbon monoxide directly into the driver's cab."],"a":1,"e":"Factory units are engineered for static, non-heat-producing loads; they cannot clear the substantial metabolic heat of live animals. A roof-mounted unit, body insulation and an insulated floor mat are recommended instead."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"To protect all vehicle occupants from an undetected exhaust leak, what safety device must be installed in the animal cargo compartment?","o":["A dual-control remote solar shade sensor.","An automated dog-appeasing pheromone misting device.","A battery-operated carbon monoxide (CO) detector.","A continuous electronic heart rate monitor."],"a":2,"e":"An independent, battery-powered carbon monoxide detector is placed in the animal compartment so that an exhaust leak tracking into the hold is detected and all occupants are protected."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"What are the ambient temperature boundaries mandated for the animal compartment of a ground transport vehicle?","o":["Maintained above 0°C and below 20°C.","Kept strictly at a static 23.9°C at all times.","Maintained above 7.2°C and below 29.5°C.","Set between 10°C and 15°C with 90% relative humidity."],"a":2,"e":"For animal safety, ambient temperature must stay above 7.2°C (45°F) and below 29.5°C (85°F). The narrower comfort target is 18°C to 26.6°C (64°F to 80°F)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"What relative humidity range must be maintained within the primary animal compartment during ground transport?","o":["10% to 20%.","30% to 70%.","Exactly 50% at all times.","80% to 90% to prevent respiratory desiccation."],"a":1,"e":"Relative humidity in the animal compartment must be kept within a moderate 30% to 70% band."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"To reduce road heat affecting animals housed on the lowest tier of a transport van or trailer, what feature is recommended?","o":["Thick layers of newspaper print changed every 2 hours.","Stacking primary enclosures at least three layers deep on the floor.","Leaving the rear cargo doors partially unlatched during highway travel.","An insulated floor mat covered with bedliner or diamond-plate flooring."],"a":3,"e":"Direct contact with van floors exposes lower-tier animals to radiant road heat. An insulated floor mat covered with bedliner or diamond-plate flooring, plus insulation of sides and roof, mitigates this."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Which parameter defines the minimum acceptable structural sizing for a primary animal enclosure during transport?","o":["Large enough to stand and sit erect, turn around normally while standing, and lie in a natural position without lying on another animal.","Formed to fit the animal's exact body contours to prevent shifting during turns.","Sized to allow at least three unfamiliar adult animals to share a single floor space.","Exactly twice the length of the animal's tail measurement."],"a":0,"e":"Enclosures must allow normal postural adjustments: standing and sitting erect, turning around while standing, and lying naturally without piling onto other animals."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"What is the strict rule regarding co-housing of unfamiliar animals within the same primary enclosure during transport?","o":["They may be housed together if they are of similar weight and age.","Unfamiliar animals must not be transported together in the same primary enclosure.","They can share an enclosure if the transport time is under 4 hours.","Co-housing is permissible if both animals wear pheromone collars."],"a":1,"e":"Placing unfamiliar animals together in a confined space during transit is a safety violation; they must be separated into individual primary enclosures."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Primary transport enclosures must feature ventilation openings on at least how many sides, and with what clearance from adjacent structures?","o":["On at least 2 sides, with a 10cm unobstructed gap.","On all 4 sides, with a mandatory 5-inch mechanical stand-off bar.","On at least 3 sides, with at least 1 inch (2cm) of unobstructed space.","Ventilation is required on the door side only, with no clearance limits."],"a":2,"e":"Enclosures need ventilation openings on a minimum of 3 sides and at least 1 inch (2cm) of unobstructed space from adjacent structures so airflow is not blocked."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"When transporting cats, what behavioural husbandry feature must be provided inside the primary enclosure to minimise stress?","o":["An open-air mesh window facing the largest dog crates.","A mechanical exercise wheel tailored for feline use.","Lifelong access to a continuous stream of running water.","A hiding space or visual barrier (a towel partly covering the door or a small hiding box) that still allows ventilation and monitoring."],"a":3,"e":"Cats need options for environmental avoidance; a visual barrier such as a partly draped towel or an internal hiding box reduces acute travel stress while still allowing ventilation and monitoring."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"If dogs and cats must be transported within the same vehicle, what housing and barriers are required?","o":["They can be stacked in alternating tiers with open wire-mesh flooring.","They must be housed in physically separate spaces, with consideration given to visual and noise barriers.","They must be separated by a minimum distance of 10 centimetres without walls.","Cats must be sedated to recumbency to prevent vocalisation."],"a":1,"e":"To reduce predatory stress and noise anxiety, co-shipped dogs and cats must be physically separated with visual and acoustic barriers. Ideally they travel in separate vehicles."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"For long-distance transports, what is the maximum daily driving time permitted before an overnight rest stop is mandated?","o":["8 hours.","12 hours.","16 hours.","24 hours."],"a":1,"e":"Daily driving is capped at 12 hours per 24-hour block. Transport that exceeds 12 hours of travel must be broken with an overnight rest stop."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"When a long-distance transport triggers a mandatory overnight rest stop, what is the minimum duration of that rest period?","o":["6 hours.","10 hours.","12 hours.","14 hours."],"a":1,"e":"The overnight rest stop is a minimum of 10 hours of stationary rest before reloading, per the ASV confinement grid (Figure 11.1)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"According to the ASV confinement grid, what is the maximum cumulative time an animal can be confined to a vehicle from source to final destination, excluding the overnight rest?","o":["12 hours.","28 hours.","36 hours.","48 hours."],"a":1,"e":"The ceiling for cumulative confined time, including loading and unloading but excluding the overnight rest, is 28 hours."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"During a transport, what is the minimum frequency for stopping the vehicle to perform a direct visual observation of each animal?","o":["Every 2 hours.","At least every 4 hours.","Exactly every 6 hours.","Only during refuelling stops exceeding 45 minutes."],"a":1,"e":"A complete vehicle stop and individual visual welfare check of every animal is required at least every 4 hours. Transports longer than 4 hours should also carry two drivers."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"What are the hydration and nutritional frequencies required for adult animals during a relocation journey?","o":["Water at least every 4 hours during observation stops; food at least every 24 hours.","Water and food both delivered continuously via automated cage-mounted valves.","Water every 12 hours, with food withheld up to 48 hours to prevent vomiting.","Food and water every 4 hours without exception."],"a":0,"e":"Hydration is high-frequency (water at least every 4 hours at stops, for adults and juveniles), whereas adult nutrition can be managed on a 24-hour interval. Juveniles eat small amounts every 4 hours."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Under commercial air transport, what are the ground temperature limits for cargo holds, and at what interior temperature is loading banned?","o":["Holds must not be below -2°C or above 20°C; loading banned at 25°C interior.","Holds must not be below -7°C or above 27°C; loading banned if interior exceeds 29°C.","Holds must not be below 0°C or above 30°C; loading banned at 32°C interior.","Cargo holds are unheated; loading banned only during visible winter storms."],"a":1,"e":"Per your notes (consistent with live-animal air transport standards), holds should not be below -7°C or above 27°C on the ground, and loading is prohibited if interior temperature exceeds 29°C. Loading should also not exceed 45 minutes."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Physiological studies on beagles after a 22-hour long-distance ground transport showed they required how long to return serum cortisol and total bilirubin to normal?","o":["24 hours.","48 hours.","2 weeks.","30 days."],"a":2,"e":"Long-distance ground transport produced a deep physiological toll: serum cortisol and total bilirubin remained altered for up to 2 weeks post-travel in this beagle study."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"In flight studies of canine biometrics, during which phases did animals experience the largest increases in heart rate?","o":["During cruise-altitude flight and turnaround manoeuvres.","During loading and unloading phases.","While sitting quietly in the cargo hold midway through the flight.","Exactly 10 minutes after administration of clomipramine."],"a":1,"e":"The flight path itself was relatively stable; the most acute heart-rate spikes occurred during loading and unloading. Heart rate was significantly higher during loading than during take-off, flight, landing or turnaround."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"Which pre-treatment protocol was shown to significantly lower plasma cortisol, lower the neutrophil-to-lymphocyte ratio, and reduce heart rate and drooling during transport?","o":["Single-dose acepromazine at the moment of loading.","Twice-daily clomipramine starting 3 days prior to transport.","Weekly megestrol acetate mixed into canned food.","A single high-dose injection of intratesticular zinc gluconate."],"a":1,"e":"Proactive twice-daily clomipramine started 3 days before transport produced significantly lower cortisol rises, a lower neutrophil-to-lymphocyte ratio, lower average heart rate, and less drooling than placebo. Psychopharmaceuticals must be used only under veterinary direction."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Transfer Programs","q":"To balance surgical capacity, length of stay and community needs, what does the literature recommend regarding the timing and location of spay/neuter (S/N) for relocated dogs?","o":["Perform S/N exclusively at the source at least 14 days before loading.","Perform S/N at the destination, as travel does not increase postoperative complication rates.","Perform S/N inside the moving transport vehicle using chemical restraint.","Outsource S/N entirely to international partners before entry assessment."],"a":1,"e":"Performing S/N at the destination balances local resources and reduces source LOS. Data show transport does not raise the baseline 2% postoperative complication rate, and neither timing of S/N nor transport method affected complication or disease incidence."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Under contemporary emergency response protocols, what level of legal protection is granted to shelter veterinarians acting as first responders during a disaster?","o":["They face strict absolute liability for any adverse medical outcomes.","They possess the exact same Good Samaritan immunity as any other veterinarian in an emergency response instance.","They are completely exempt from all state licensing requirements permanently.","They must obtain federal military clearance before treating any animal."],"a":1,"e":"Shelter veterinarians have the same Good Samaritan immunity as any other licensed veterinarian responding to a crisis. This does not remove the obligation to practice competently or document care."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The Pets Evacuation and Transportation Standards (PETS) Act of 2006 imposes which explicit statutory requirement on regional planning authorities?","o":["Communities must provide a $500 stipend to every pet-owning family.","Regional planning authorities and communities must take companion animals into account in their emergency response planning.","Shelters must microchip 100% of local livestock within 48 hours of a storm.","Owners are legally banned from evacuating with more than one animal."],"a":1,"e":"The PETS Act of 2006 mandates that regional and municipal disaster authorities formally integrate companion animals into all emergency response planning. This is a statutory mandate, not a recommendation."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The Robert T. Stafford Disaster Relief and Emergency Assistance Act grants the FEMA administrator explicit authority to perform which of the following actions regarding household pets and service animals?","o":["Provide funding grants to states to build household pet and service animal capabilities.","Force private veterinary practices to surrender all medical assets to the state during a crisis.","Mandate that FEMA permanently assume ownership of all stray livestock.","Completely outlaw the use of euthanasia in disaster zones nationwide."],"a":0,"e":"The Stafford Act authorises the FEMA administrator to allocate funding grants to states to expand local household pet and service animal capabilities, and authorises use of federal resources for household pets and service animals within certain federal disaster declarations."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"When a shelter recruits temporary foster families during a disaster relief campaign, what specific provision must be appended to the shelter's customary foster home agreement?","o":["A clause granting the foster carer permanent legal ownership after 7 days.","A strict requirement to relinquish the animals back to their original legal owners upon identification.","An agreement forcing the foster carer to cover all future surgical expenses.","A mandate requiring daily behavioural evaluations submitted by video."],"a":1,"e":"To safeguard ownership integrity, disaster foster contracts must include an explicit provision requiring the temporary carer to return the animal once the legal owner is identified. This protects against accidental permanent rehoming of owned disaster animals."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If a local animal shelter finds itself entirely overwhelmed and unable to manage a disaster response operation, what national asset can be mobilised for managerial supervision?","o":["The International Board of Veterinary Governors.","Trained disaster and emergency response personnel from national animal welfare organisations.","Municipal corporate retail inventory management teams.","The regional social security administrative staff."],"a":1,"e":"National animal welfare organisations (such as HSUS, ASPCA, and others) have pre-trained disaster and emergency response personnel who can step in to supervise and co-manage overwhelmed facilities. The National Animal Rescue and Sheltering Coalition was formed specifically to coordinate large-scale responses."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The National Response Framework (NRF) is structurally designed to operate as what type of emergency management system?","o":["A localised commercial protocol for private veterinary clinic triage.","A national plan setting forth roles, responsibilities, and relationships among local, state, federal, tribal, territorial, and non-government entities.","A military command system that bypasses municipal governance entirely.","A federal software database used exclusively for tracking physical asset values."],"a":1,"e":"The NRF serves as the macroscopic structural plan detailing exact roles, operational hierarchies, and request pathways across all tiers of governance, including animal shelters within local emergency management."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If local shelter and community resources are entirely exhausted during a major disaster, how should the request for additional outside resources be formally routed?","o":["By contacting federal pharmaceutical suppliers directly via private email.","Coordinated systematically with or through the local Incident Command structure.","By placing public advertisements on commercial social media channels.","Through an immediate direct petition to the federal supreme court."],"a":1,"e":"Resource management protocols dictate that when local shelter assets are exhausted, requests for mutual aid must be routed systematically through the established local ICS chain. If local resources are exhausted, the request escalates to state, then federal levels."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Within the 50 United States, what is the name of the lateral mutual aid compact that allows states to share emergency management resources and personnel with each other?","o":["The National Animal Rescue Coalition (NARSC).","The Emergency Management Assistance Compact (EMAC).","The Federal Emergency Management Alliance (FEMA).","The State Veterinary Board Alliance (SVBA)."],"a":1,"e":"EMAC (Emergency Management Assistance Compact) is the nationwide mutual aid system allowing states to seamlessly request and deploy operational personnel and equipment across state lines, before a state escalates its request to the federal level."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Under the standardised Incident Command System (ICS), what are the four key management functions organised under the General Staff reporting directly to the Incident Commander?","o":["Medicine, Behaviour, Sheltering, and Triage.","Operations, Planning, Logistics, and Finance/Administration.","Mitigation, Preparedness, Response, and Recovery.","Safety, Liaison, Public Information, and Security."],"a":1,"e":"ICS architecture mandates that the General Staff directly managing tactical and logistical execution is split into Operations (tactical response), Planning, Logistics, and Finance/Administration. Safety, Liaison, and Public Information are the Command Staff, not General Staff. Mitigation/Preparedness/Response/Recovery are the four disaster phases."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"A shelter's Director of Operations steps into the disaster ICS hierarchy. Which specific ICS General Staff role do they fill?","o":["Logistics Section Chief.","Operations Section Chief.","Incident Commander.","Planning Section Chief."],"a":1,"e":"According to the standard ICS animal shelter mapping, specialised shelter leadership positions translate directly into general staff roles. The Director of Operations becomes the Operations Section Chief, responsible for tactical response."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Which phase of disaster management involves ongoing, preemptive activities designed specifically to detect, anticipate, and reduce the long-term impacts of future disasters on animals and shelters?","o":["Recovery.","Response.","Preparedness.","Mitigation."],"a":3,"e":"Mitigation comprises all ongoing, preemptive structural strategies aimed at minimising the systemic impacts of future disasters before they occur. It is the only phase that is continuous rather than event-triggered."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"During the Preparedness phase, why is preemptive animal transport and early evacuation considered an operational best practice?","o":["It permanently eliminates the need for any veterinary intake exams.","It ensures the safety of relocated animals and creates immediate facility capacity to house displaced community animals.","It acts as a legal mechanism to forfeit ownership of local animals immediately.","It guarantees that the shelter will receive immediate cash reimbursements."],"a":1,"e":"Preemptive transport clears the shelter's existing population out of danger while simultaneously opening space to receive incoming community animals. Even when minimal community animal intake is expected, preemptive transport reduces staffing challenges and lessens facility damage impact."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is the absolute first priority that must underpin any and all components of a shelter's disaster response plan?","o":["Rapid deployment of digital adoption platforms.","Maximising physical and monetary donation streams.","Human safety.","Complete diagnostic screening for endemic parasites."],"a":2,"e":"Human safety stands as the absolute, non-negotiable first priority of any emergency management or sheltering disaster response plan. All other objectives, including animal welfare, are secondary to preventing human casualties."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"To establish a clear chain of command and scalable communication architecture, shelter personnel should complete training in which specific modules before a disaster occurs?","o":["Advanced forensic cruelty photography certifications.","National Response Framework (NRF), National Incident Management System (NIMS), and Incident Command System (ICS) modules.","Commercial business logistics and retail management.","Municipal code enforcement and civil litigation tracking."],"a":1,"e":"Completing NRF, NIMS, and ICS training modules ensures that all responding personnel can operate within a single, unified, and highly scalable command architecture. This training must occur before a disaster, not during."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"At what precise operational point should the Incident Command System (ICS) structure be formally initiated by shelter leadership?","o":["Exactly 48 hours after a disaster has entirely concluded.","Only when requested in writing by the state governor.","As soon as a disaster is anticipated or has occurred.","Once the facility's physical monetary donations exceed baseline budgets."],"a":2,"e":"To maintain an uncompromised chain of command, the ICS structure must be brought online rapidly as soon as a disaster is anticipated or immediately strikes. Waiting for official declaration or post-event assessment delays critical coordination."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"When an animal of unknown or unsettled ownership enters a shelter's custody during a disaster relief operation, how must the animal be legally categorised?","o":["It is immediately made available for public adoption within 24 hours.","It is handled strictly as a stray until officially claimed by an owner.","It is transferred directly to an out-of-state research facility.","It is issued a permanent certificate of shelter ownership."],"a":1,"e":"Ownership boundaries remain intact during disasters. Any animal with an unverified or unknown origin must be held under stray protocols until the legal hold expires. Holding times may be governed by both stray animal laws and lost property statutes."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Immediately upon intake during a disaster relief effort, what baseline veterinary and identification protocols are mandated for all incoming animals?","o":["A full behavioural match test and an elite conformation photo session.","Examination by a licensed veterinarian, thorough documentation, secure physical identification, and photographs.","A mandatory 30-day isolated quarantine before any visual assessment.","Immediate administration of broad-spectrum anaesthetic compounds."],"a":1,"e":"Field intake mandates immediate veterinary screening for infectious disease and hazards, thorough medical charting, photographs, and secure physical tracking identification. This documentation is essential for accurate owner reunification and minimises administrative errors."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If an owned animal is admitted to an emergency shelter during a crisis, what documentation must the shelter secure from the owner to protect itself from liability?","o":["A certified employment history and bank routing verification.","Permission to care for and treat the animal, a release of liability, an indemnification agreement, medical history, and an agreement to a definite term after which the animal may be forfeited.","A permanent bill of sale transferring legal title to the state.","A written promise to volunteer for a minimum of 100 hours."],"a":1,"e":"Shelters must protect themselves from future civil claims by securing explicit medical consent, liability waivers, indemnification agreements, and clear maximum holding terms from owners. The owner should also be required to cover costs of care to the extent they are able."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"When transferring displaced disaster animals across state lines for long-term sheltering or adoption, what steps must veterinarians take regarding disease transmission?","o":["Ignore local rules under emergency Good Samaritan exemptions.","Work with state animal health officials to determine necessary vaccinations, treatments, testing, and Certificates of Veterinary Inspection (CVIs).","Wait for a full federal congressional waiver before crossing any borders.","Perform complete surgical sterilisation inside the transport vehicle."],"a":1,"e":"Cross-border transfers carry severe biosecurity risks, as disaster animals may carry endemic pathogens unknown to the receiving area. Veterinarians must collaborate with state animal health officials to meet all vaccine, testing, CVI, and permit requirements before interstate transfer."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Why must emergency shelter managers consult with legal counsel regarding disaster holding times before adopting out recovered animals?","o":["Holding times are completely unregulated across North America.","Holding times for animals lost in disasters may be influenced by lost property statutes in addition to stray animal laws.","To determine the maximum tax deduction allowed for the adoption fee.","To legally bypass municipal microchip scanning mandates."],"a":1,"e":"Post-disaster ownership resolution is legally complex. Lost property statutes can intersect with or supersede traditional municipal stray hold laws. Shelters must seek legal counsel before adopting out or placing disaster animals."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Which statement accurately describes the operational timeline and integration of Animal Search and Rescue (ASAR) missions?","o":["ASAR operates completely independently of human SAR and must conclude before human teams deploy.","ASAR activities should be coordinated with human SAR operations and may continue after human SAR has ended.","ASAR teams are legally authorised to cross international borders without paperwork.","ASAR focuses exclusively on tracking wild avian populations."],"a":1,"e":"Field rescue operations require ASAR integration with human rescue grids. Animal teams routinely extend their operations long after human search efforts have concluded, as animals may remain inaccessible or undiscovered for extended periods."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What clinical protocol is recognised as the current gold standard for animal decontamination in the field?","o":["High-pressure chemical alcohol spraying.","Bathing with soap and water followed by a clean water rinse.","Shaving the animal's entire coat down to the skin without washing.","Applying dry powder clay adsorbents exclusively."],"a":1,"e":"Extensive testing confirms that basic bathing with soap and water followed by a meticulous clean water rinse is the most effective way to eliminate field contaminants. This simple protocol reduces or eliminates most contaminants effectively and is the gold standard."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If field conditions require animal decontamination personnel to use respiratory protection, what are the strict OSHA requirements that must be met PRIOR to the incident?","o":["A high-school diploma and a baseline physical fitness test.","Medical screening, fit testing, and formal training on respirators.","A valid state veterinary licence and a hazardous materials endorsement.","A signed waiver releasing the federal government from all health claims."],"a":1,"e":"OSHA enforces a strict three-step prerequisite protocol for respirator use that must be completed BEFORE the incident: (1) medical screening, (2) accurate physical fit testing, and (3) formal operational training on the respirator. All three must be completed prior to the event."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What represents the minimum acceptable personal protective equipment (PPE) required for personnel executing basic animal decontamination?","o":["A standard cloth lab coat and disposable latex exam gloves.","Barrier protection, gloves, apron or water-resistant coveralls, goggles, boots, cap, and a barrier mask or face shield.","A fully enclosed Level-A military-grade gas mask with oxygen tanks.","No PPE is recommended to ensure the animal remains calm."],"a":1,"e":"Minimum safe decontamination apparel requires comprehensive barrier protection: gloves, water-resistant aprons or suits, goggles, boots, caps, and masks or face shields. Standard exam gloves and a lab coat are insufficient for decontamination work."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"With whom must animal decontamination teams coordinate when establishing incident-specific decontamination protocols?","o":["The local social services board and public relations coordinators.","Incident HAZMAT personnel and the ICS Safety Officer.","Regional agricultural breed registrars and feed store retailers.","National wildlife rehabilitation directors."],"a":1,"e":"To prevent field cross-contamination and human exposure risks, all animal decontamination protocols must be vetted by HAZMAT teams and the ICS Safety Officer. Coordination between these two entities is explicitly described as imperative."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Animals subjected to unpredictable and uncontrollable aversive disaster events are at high risk of developing severe psychological distress. Which behavioural profile best characterises this post-disaster trauma?","o":["Heightened social extraversion and immediate trainability.","Generalised fear and arousal, heightened vigilance, fear of specific stimuli, and passive avoidance or resignation.","Complete loss of predatory drive and an increase in maternal nesting habits.","Uniformly high levels of aggression toward known caretakers only."],"a":1,"e":"The psychological profile of animal disaster trauma includes generalised hyperarousal, profound hypervigilance, fear of specific stimuli, and passive avoidance or learned resignation. This profile is analogous to post-traumatic stress responses in humans and other species."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"In the 2011 Fukushima earthquake study, how did the physiological stress markers of abandoned disaster dogs compare to the control group of non-affected homeless dogs?","o":["Their urine cortisol levels were identical to the control group.","Their urine cortisol levels were 5 to 10 times higher, and the elevation persisted even after 10 weeks in the rescue centre.","Their cortisol levels plummeted to zero due to adrenal exhaustion.","They showed a temporary 2-fold spike that resolved within 24 hours."],"a":1,"e":"Abandoned Fukushima dogs demonstrated extreme, long-term physiological stress, maintaining a 5 to 10 times increase in baseline urine cortisol even after 10 weeks of stabilisation in a rescue centre. This demonstrates that disaster trauma causes persistent neuroendocrine dysregulation not rapidly reversed by safe housing."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Historical data from Hurricane Katrina demonstrated that an estimated 200,000 pets were displaced. What was the owner-pet reunification rate when no temporary co-located pet shelters were available?","o":["Only 5%.","Exactly 25%.","Up to 50%.","95%."],"a":0,"e":"Without pet-inclusive sheltering infrastructure during Hurricane Katrina, only 5% of displaced animals were reunited with their owners. This starkly low figure drives the recommendation for co-located or pet-friendly human emergency sheltering."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"When temporary pet-friendly or co-located emergency sheltering options were successfully deployed post-disaster, what happened to the owner-pet reunification metrics?","o":["The reunification rate dropped to 0% due to record-keeping errors.","The reunification rate scaled up dramatically, reaching 40.2% and up to 70.1% across reporting shelters.","It caused a massive spike in long-term animal relinquishments.","The rate remained unchanged at 5%."],"a":1,"e":"Establishing co-located or pet-friendly human shelters removed the primary barrier (people refusing evacuation without their pets), driving family reunification rates up to 40.2% and 70.1% across different reporting shelters. Co-located sheltering is the single most impactful operational intervention for reunification."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Disaster","q":"During the prolonged Recovery phase, why are traditional shelter metrics like local adoption and fostering rates frequently compromised within the affected community?","o":["Local residents face sustained housing instability, meaning fostering and adoption are unlikely to be immediate priorities.","Federal laws prohibit adoptions for 12 months following a disaster.","Animals lose their legal adoptability status permanently after a storm.","Shelters are forced to prioritise wildlife rehabilitation over companion animals."],"a":0,"e":"Post-disaster recovery is slow. When the local human population faces acute housing loss and economic strain, community adoption and foster capacity plummets. Alternative strategies (out-of-area adoption events, increased transfer, shelter-neuter-return) should be used to manage longer length of stay."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Which statement precisely delineates the clinical availability and mechanism of action of Neutersol?","o":["It is an oral progestin tablet that causes permanent ovarian suppression.","It is an intratesticular injection of zinc gluconate, FDA approved in 2003 and labeled for puppies 3 to 10 months, that became unavailable in the US in 2005.","It is a topical deslorelin gel applied directly to the inner pinna of the ear.","It is a viral vector vaccine designed to stimulate lifetime anti-GnRH antibodies."],"a":1,"e":"Neutersol is an intratesticular injection of zinc gluconate. FDA-approved in 2003 for puppies 3 to 10 months old (effective off-label in adults), it became unavailable in 2005. It achieves 99% efficacy through testicular sclerosis causing permanent azoospermia or oligospermia."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"A veterinarian wishes to use Esterilsol or Zeuterine for chemical castration. What is the formulation and regulatory reality of these agents?","o":["They are completely different molecular compounds that target the adrenal cortex.","They share the exact same zinc gluconate formulation as Neutersol but are manufactured for use in Mexico, Central, and South America.","They are long-acting intrauterine devices approved for use in feral queens.","They are GnRH agonists licensed exclusively for large-scale livestock management."],"a":1,"e":"Esterilsol and Zeuterine use the identical zinc gluconate formulation as Neutersol but are manufactured by a different company for distribution in Mexico, Central, and South America. They have similar efficacy and adverse effect profiles."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Deslorelin (Suprelorin) suppresses fertility through which exact neuroendocrine mechanism?","o":["It acts as a direct progesterone receptor antagonist within the uterus.","It is a GnRH superagonist that initially stimulates then down-regulates pituitary receptors, blocking LH and FSH production and suppressing gonadal hormone synthesis.","It destroys primordial follicles via super-physiological expression of estrogen.","It irreversibly binds to the zona pellucida to prevent sperm binding."],"a":1,"e":"Deslorelin is a GnRH superagonist. Continuous non-pulsatile exposure initially stimulates but then desensitises pituitary GnRH receptors, blocking LH and FSH release and suppressing downstream testosterone and estradiol production. The HPG axis conservation across species gives it broad cross-species efficacy."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Gonazon was approved in the European Union in 2006. What was its specific clinical indication and its current market status?","o":["A permanent chemical sterilant for male dogs, currently sold worldwide.","A 1-year reversible contraceptive implant for female dogs that has been approved but has not been released on the market to date.","A weekly food additive for pregnancy prevention in feral feline colonies.","An adeno-associated virus vector targeting the hypothalamic venous portal system."],"a":1,"e":"Gonazon was approved in the EU in 2006 as a 1-year reversible contraceptive implant for female dogs. However, it has not been commercially released. EU approval and market availability are distinct: Gonazon is approved but not available."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What distinguishes the chemical composition of the product 'Infertile,' launched in Brazil in 2009?","o":["It is a pure saponin solution that selectively causes follicle apoptosis.","It is an injectable sterilant combining dimethyl sulfoxide (DMSO) with zinc gluconate, neutralised by arginine.","It is a long-acting intrauterine device containing megestrol acetate.","It is an anti-GnRH antibody delivered via an adeno-associated virus."],"a":1,"e":"Infertile is a Brazilian chemical sterilant that combines DMSO (as a vehicle) with zinc gluconate, neutralised by arginine. This modification of the standard zinc gluconate formula provides chemical castration via the same testicular sclerosis mechanism."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"The HPG axis originates in the hypothalamus. In what specific anatomical fashion is GnRH released into the system?","o":["Continuous, steady-state systemic secretion.","Pulsatile fashion, transmitted to the anterior pituitary through a venous portal system.","Retrograde axonal transport directly into the systemic lymphatic chains.","Exocrine excretion into the cerebrospinal fluid of the third ventricle."],"a":1,"e":"The HPG axis requires PULSATILE hypothalamic release of GnRH into the specialised venous portal architecture of the hypophyseal system to signal the anterior pituitary. This pulsatile nature is critical: continuous GnRH exposure (as with GnRH agonists) leads to receptor downregulation, not stimulation."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Downstream in the HPG axis, gonadotropin hormones FSH and LH directly stimulate the production of which gonadal hormones?","o":["Prolactin and oxytocin by the pituitary gland.","Testosterone by the testes, and estradiol and progesterone by the ovaries.","Cortisol and aldosterone by the adrenal cortex.","GnRH and MIS by the interstitial supporting stroma."],"a":1,"e":"FSH and LH travel through systemic circulation to stimulate peripheral gonadal structures. In the testes, they drive testosterone synthesis; in the ovaries, they drive estradiol and progesterone production. Adrenal hormones (cortisol, aldosterone) are controlled by a completely separate HPA axis."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Negative feedback loops are fundamental to HPG axis regulation and exploitation by contraceptives. Which hormones naturally provide negative feedback to suppress GnRH, FSH, and LH?","o":["Mullerian-inhibiting substance and saponins.","Androgens, estrogens, and progesterone.","Zinc gluconate and arginine.","Porcine zona pellucida proteins and anti-GnRH antibodies."],"a":1,"e":"Endogenous steroid hormones (androgens, estrogens, and progesterone) deliver the critical negative feedback that slows down the primary HPG axis. Hormonal contraceptives exploit this by providing sustained, non-pulsatile feedback that mimics or amplifies this suppressive effect."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"At what distinct levels can targeted pharmaceutical interference suppress the HPG axis?","o":["Exclusively at the level of the peripheral systemic circulation.","At any of its three levels: the hypothalamus/anterior pituitary, the gonads, and the downstream oocyte.","Only via direct physical destruction of the cerebral venous portal system.","Solely by blocking the blood-brain barrier against androgen transport."],"a":1,"e":"The multi-tier structure of the HPG axis allows targeted blocks at three levels: the hypothalamus/anterior pituitary (GnRH agonists, progestins), the gonads directly (chemical castrants, GnRH vaccines), and the downstream oocyte/zona pellucida (PZP vaccine). Different contraceptive agents exploit different tiers."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Beyond the primary hypothalamus and pituitary, what represent the valid peripheral gonadal targets for non-surgical contraception?","o":["The tunica albuginea and the pampiniform plexus.","The zona pellucida, proteins on the ovulated egg facilitating sperm recognition, and thecal support cells of the ovaries and testes.","The cervical mucus glands and the prostatic epithelium.","The primordial follicle basement membrane and the oviduct fimbriae."],"a":1,"e":"Peripheral gonadal targets for contraceptive intervention include the zona pellucida glycoprotein matrix (targeted by PZP vaccines), recognition proteins on the ovulated egg, and the thecal support cells of both the ovaries and testes (targeted by chemical castrants and saponins via apoptosis induction)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Porcine zona pellucida (PZP) vaccines have a unique downstream advantage compared to HPG axis-targeting immunocontraceptives. What is this advantage?","o":["They permanently eliminate male aggressive behaviours within 48 hours.","They take effect downstream in the reproductive system, with fewer concomitant changes in hormone levels, behaviour, and health consequences.","They induce immediate, permanent chemical castration in both sexes.","They alter regulatory gene sequences of the anterior pituitary gland."],"a":1,"e":"Because PZP targets the zona pellucida at the point of fertilisation rather than interfering upstream with the HPG axis, it avoids the systemic hormonal and behavioural side effects seen with central axis-targeting approaches. Fewer health consequences are a meaningful clinical advantage."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What is the documented clinical outcome of deploying a PZP immunocontraceptive vaccine in queens?","o":["Safe, lifelong permanent contraception achieved via a single non-invasive subcutaneous dose.","Perfect downstream contraception without measurable changes to behaviour or estrous cycles.","Complete failure to induce contraception, accompanied by highly abnormal estrous cycles and severe injection-site reactions.","An immediate reduction in circulating LH and FSH due to strong negative feedback at the pituitary."],"a":2,"e":"PZP vaccines are completely ineffective in queens. Rather than achieving the desired contraceptive effect, they cause highly abnormal, disrupted estrous cycles and severe local injection-site reactions. PZP is therefore not recommended for feline populations."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"A multi-centre trial of a GnRH contraceptive vaccine in domestic dogs is deemed neither safe nor effective. Which findings led to this determination?","o":["The vaccine caused immediate life-threatening pyometra and insulin-resistant diabetes mellitus.","It triggered severe injection-site reactions and failed to alter sperm population density or sperm morphology.","It caused a permanent systemic flare that locked the HPG axis in a hyper-estrogenic state.","The anti-GnRH antibodies selectively destroyed the thecal support cells of the canine pancreas."],"a":1,"e":"Canine trials of GnRH vaccines were abandoned because they caused severe, unresolvable injection-site reactions without producing the expected reduction in sperm numbers, density, or morphological normalcy. Both safety and efficacy criteria were failed."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"While GnRH vaccines are effective in large free-roaming animals such as horses and elephants, what clinical maintenance is required to sustain their efficacy?","o":["Continuous intravenous infusion via an automated pump.","An annual booster injection, alongside monitoring for local chronic sterile abscess reactions.","Weekly physical scraping of target gonadal tissue.","Concurrent lifelong administration of mibolerone."],"a":1,"e":"Due to the transient nature of the antibody response, large free-roaming mammals require annual boosters to sustain GnRH vaccine efficacy. A common adverse effect is the development of chronic, sterile local abscesses at the injection site that must be monitored."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Why might an immunocontraceptive protein vaccine developed against zona pellucida proteins from one species fail when administered to a different target species?","o":["The HPG axis is not conserved across mammalian groups.","A protein developed against proteins from one species may work poorly when the same or similar proteins in a different species have sufficient molecular differences to evade the antibody response.","Vaccines always convert into chemical sterilants over time.","The blood-brain barrier permanently blocks all cross-species proteins."],"a":1,"e":"Cross-species immunocontraceptive efficacy depends on sufficient molecular similarity between the target protein in the source species (porcine, in the case of PZP) and the target species. Molecular differences can mean the antibodies generated do not bind effectively to the target species' zona pellucida proteins."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What is the fundamental pathological mechanism by which chemical contraceptives achieve sterilisation?","o":["They alter the neural pulsatility of the hypothalamus via viral vectors.","They destroy target tissue (typically the testes) through sclerosis, rendering it permanently non-functional.","They apply transient negative feedback to the anterior pituitary gland.","They coat the uterine lining to prevent implantation of fertilised eggs."],"a":1,"e":"Chemical contraception functions through direct, irreversible tissue sclerosis. The injected chemical destroys the target organ's structural integrity, shutting down its function permanently. This is fundamentally different from hormonal approaches, which act through receptor-level signalling."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"During an intratesticular zinc gluconate injection in a dog, what severe clinical complication occurs if the solution leaks into the subcutaneous space?","o":["Rapid, irreversible development of mammary gland adenocarcinomas.","Necrotising injection-site reactions and scrotal ulcers necessitating complete scrotal ablation.","A massive transient surge in testosterone leading to acute aggression.","Systemic resorption causing immediate, profound adrenal suppression."],"a":1,"e":"Subcutaneous leakage or misdirection of zinc gluconate causes intense local tissue necrosis, producing severe scrotal ulcers. Salvage scrotal ablation surgery is required in these cases. This complication is the primary reason chemical restraint is strongly recommended for intratesticular injections."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Because of the technical precision required and the risk of necrotising tissue damage with intratesticular zinc gluconate, what clinical management protocol is strongly advisable?","o":["Lifelong isolation from other intact animals.","Chemical restraint.","Pre-treatment with high doses of mibolerone for 30 days.","Concurrent placement of an indwelling uterine device."],"a":1,"e":"Chemical restraint is strongly recommended when administering intratesticular chemical sterilants. It prevents patient movement during injection, reducing the risk of misdirected delivery into subcutaneous tissues and the consequent severe necrotising complications."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"In what specific demographic or geographical scenarios is male chemical castration using zinc gluconate most advantageous for large-scale population control?","o":["In high-income private referral centres specialising in breeding lines.","In areas where surgeons, surgery suites, or skilled staff are difficult to obtain, or where physical removal of the testicles is culturally unacceptable.","In research settings looking to achieve fully reversible 3-month contraception.","In intensive feline shelter facilities where surgical timing is paramount."],"a":1,"e":"Non-surgical chemical castration provides a viable alternative when surgical equipment, sterile environments, or trained surgeons are unavailable or not accessible, and in cultural contexts where physical castration is unacceptable. It is not the preferred method when surgery is readily available."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Why are veterinarians significantly more reluctant to use chemical castration with zinc gluconate in cats compared to dogs?","o":["Feline testicles are highly resistant to zinc gluconate sclerosis.","Feline surgical castration is much faster, and cats have a significantly higher risk of severe local inflammatory reactions, scrotal necrosis, and self-mutilation following intratesticular injection.","Cats require five consecutive intratesticular injections for effective sclerosis.","Zinc gluconate triggers a fatal systemic saponin reaction specifically in cats."],"a":1,"e":"Two concurrent reasons drive veterinary reluctance for feline chemical castration: (1) feline orchiectomy is already very fast and technically straightforward, eliminating the time-saving benefit of chemical castration, and (2) cats experience significantly higher rates of severe local pain, tissue inflammation, necrosis, and self-mutilation at the injection site compared to dogs."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Which historical steroidal contraceptives were introduced in the 1970s, and what severe systemic adverse effects resulted in their abandonment?","o":["Deslorelin and gonazon; caused severe chronic local abscesses.","Megestrol acetate and mibolerone; caused weight gain, pyometra, mammary hyperplasia and carcinomas, diabetes mellitus, adrenal suppression, and behaviour changes.","Calcium chloride and saponin; caused immediate azoospermia.","Zinc gluconate and arginine; caused necrotising scrotal ulcers."],"a":1,"e":"Megestrol acetate (progestin) and mibolerone (androgen), introduced in the 1970s, required frequent oral dosing and caused profound multi-organ pathologies: pyometra, mammary malignancies, diabetes mellitus, endocrine suppression, and behaviour changes. These adverse effects led to their abandonment."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What is Feralstat, and what primary ethical concern prevents its general endorsement by the veterinary community?","o":["An intrauterine device; it frequently migrates through the canine cervix.","A low dose of megestrol acetate mixed into canned food; there is no mechanism to ensure the medication is administered only to target animals, and non-target species may ingest it.","A viral vector vaccine; it triggers long-term anti-GnRH antibody surges.","A saponin-based compound that causes permanent systemic cellular necrosis."],"a":1,"e":"Feralstat is a low-dose megestrol acetate powder designed to be mixed weekly into shared canned cat food for feral colonies. Its use is not recommended because there is no clinical mechanism to ensure target cats receive the correct dose or to prevent non-target wildlife and other animal species from consuming the medicated food."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What is the cytotoxic mechanism of action behind the novel use of saponin as an injectable gonadal sterilant?","o":["It induces massive negative feedback directly at the anterior pituitary.","It is harmless in the bloodstream but becomes toxic once taken into a cell, triggering apoptosis in gonadal support cells.","It cross-links zona pellucida proteins to block sperm entry.","It creates an alkaline shift in the uterine environment to stop implantation."],"a":1,"e":"Saponins act as systemic stealth toxins: they travel safely through the bloodstream without causing systemic harm, but trigger apoptosis selectively when internalised by gonadal support cells. This targeted cellular toxicity causes reduction in sperm number and motility in males and suppresses estrous cycling in females (demonstrated in rats)."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"When an adeno-associated virus (AAV) vector was used to deliver anti-GnRH antibodies in a gene delivery model, what primary limitation was observed?","o":["The vector caused an immediate, fatal necrotising systemic shock.","Antibody levels increased but returned to normal levels within just one month.","The animals developed permanent, irreversible scrotal ulcers.","It was only functional when delivered via an invasive laparotomy."],"a":1,"e":"Gene delivery using AAV vectors for anti-GnRH antibodies failed to provide sustained protection because the antibody surge dropped back to baseline within approximately one month. This makes current gene delivery approaches impractical for field population management."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"How does lifelong super-physiological expression of Mullerian-Inhibiting Substance (MIS) theoretically achieve permanent contraception in females?","o":["It blocks the pulsatile release of GnRH from the hypothalamus.","It acts as an ovarian ligand that directly inhibits primordial follicle activation, preventing regular estrous cycling.","It causes a local necrotising reaction within the uterine endometrium.","It stimulates a profound antibody cascade against porcine zona pellucida proteins."],"a":1,"e":"MIS is a ligand produced by the ovaries that normally inhibits primordial follicle activation. In theory, if MIS could be maintained at super-physiological levels throughout an animal's lifetime, the primordial follicle pool would remain suppressed and the animal would be permanently infertile. In practice, expression only lasted a few months in cats."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Mathematical population models show non-surgical contraception can successfully manage feral feline populations. What two operational parameters must BOTH be met?","o":["When immigration pathways are open and treatment rates reach 20% of cats annually.","When immigration and emigration are extremely limited AND treatment rates exceed 40 to 50% of cats per 6-month interval.","When the sex ratio of the colony favours males and non-veterinarians perform concurrent surgical vasectomies.","When population density is high enough to stimulate natural negative feedback loops."],"a":1,"e":"Both conditions are required simultaneously: (1) the population must be essentially closed (limited immigration and emigration), and (2) treatment must cover more than 40 to 50% of the entire population every 6 months. Either condition alone is insufficient for population-level control."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"What are the primary structural and clinical concerns surrounding the experimental deployment of intrauterine devices in dogs (the dogspiral)?","o":["They cause a 5 to 10 fold spike in systemic urine cortisol levels.","There are no peer-reviewed safety or efficacy studies, and there are concerns over insertion given the anatomy of the canine cervix.","They trigger immediate sclerosis of the testes if placed subcutaneously.","They require an annual booster to maintain local antibody production."],"a":1,"e":"The dogspiral (canine IUD) has two major barriers to use: (1) there are no peer-reviewed safety or efficacy data in dogs at all, and (2) the anatomy of the canine cervix creates significant technical challenges and potential complications for device insertion."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Because zinc gluconate chemical castration leaves the physical testicles intact in the scrotum, what management step is essential to prevent identification errors and redundant surgeries?","o":["Mandatory surgical removal of both ear pinnae.","A standard permanent identification mark such as a microchip, a tattoo over the caudolateral ventral abdomen, a tattoo on the inner pinna, or a small metal ear band.","Performing a complete scrotal ablation 30 days after the chemical injection.","Restricting the animal to indoor-only facilities for its entire lifespan."],"a":1,"e":"Because chemically castrated dogs retain their testicles, they are visually indistinguishable from intact males. A permanent identification marker is mandatory to prevent repeat injections or unnecessary surgical castration by another practitioner. Acceptable methods include microchipping, ventral abdominal tattoos, inner pinna tattoos, or metal ear bands."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"Why is the standard surgical ear-tipping protocol considered contraindicated for animals managed with non-surgical contraception?","o":["It alters the pulsatile feedback loops of the HPG axis.","Ear-tipping communicates permanent sterility; if applied to an animal with a temporary contraceptive implant, the animal will return to fertility when the implant wanes while the ear-tip permanently signals sterility to field teams, undermining population control models.","It triggers severe necrotising injection-site reactions across the face.","Feral animals lose their baseline social structure if their ears are tipped."],"a":1,"e":"Ear-tipping is irreversible and signals permanent sterility. Applied to a temporarily contracepted animal (e.g., a 6 or 12-month Suprelorin implant), the ear-tip will outlast the implant. When the animal returns to fertility, field teams will incorrectly assume it is still sterile, will not re-treat it, and the animal will reproduce freely, breaking the population management model."},{"type":"mcq","domain":"Companion Animal Homelessness","sub":"Non-Surgical Sterilization","q":"To optimise field captures and tracking of non-surgically contracepted wild or feral animals, what characteristics define the ideal identification marker?","o":["Highly invasive, permanently fixed to the gonadal support cells, and invisible to the public.","Non- or minimally invasive, easy to apply in a field setting, visible from a distance, and lasting approximately as long as the contraception lasts or encoding information about contraception type and expiry.","A weekly chemical dye applied directly into the animal's canned food.","A complex multi-digit barcode tattooed over the entire cervical stroma."],"a":1,"e":"Field management of contracepted wildlife and feral populations requires markers that satisfy practical field constraints: non-invasive enough to apply quickly, readable from a distance to inform re-capture decisions, and temporally matched to the contraceptive's expected duration to prevent false signals of sterility after the product wanes."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A municipal shelter plans a TNR campaign to reduce a large closed community cat colony. What minimum percentage of the intact female population must be kept continuously sterilized to stabilize and decrease population size through attrition?","o":["30%","50%","≥70%","95%"],"a":2,"e":"Mathematical modeling and population medicine show that a sustained sterilization rate of ≥70% of the intact female population within a geographically locked cohort is required to outpace feline fecundity (1.4 litters/year, ~3 live births/litter). This threshold applies to intact females specifically, not total colony size. Below 70%, the population continues to grow."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A municipality proposes replacing TNR with TVHR based on a single modelling study. Which documented real-world disadvantage of TVHR is most important?","o":["TVHR eliminates testosterone, causing immediate colony dispersion","TVHR preserves sex hormone production — cats continue nuisance behaviors (fighting, yowling, spraying) and remain at risk for mammary tumours, stump pyometra, and retroviral transmission","TVHR surgeries are faster, creating a shortage of kittens for adoption","TVHR requires lifelong daily progestogens to prevent estrus"],"a":1,"e":"TVHR preserves gonadal hormone production. Males continue fighting, yowling, and spraying. Females remain at risk for mammary tumours and stump pyometra. Ongoing fighting perpetuates FIV/FeLV transmission. Only ONE modelling study has suggested TVHR superiority — not replicated in field research. TNR remains the evidence-based standard."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A veterinary team running a community cat sterilization program wants to minimize trap-shyness. What pre-trapping protocol is evidence-based best practice?","o":["Set traps immediately for maximum surprise capture","Place food inside unsecured traps for 2–7 days prior to trapping while withholding all external food sources","Restrict traps to public parks during daylight for safe monitoring","Withhold all food and water for 14 days to maximize bait motivation"],"a":1,"e":"Acclimatization places food inside unset traps for 2–7 days before active trapping, while withholding food from all other colony feeding stations. This reduces stress, increases trapping efficiency, and reduces trap-shyness in cautious females. Total food/water deprivation for 14 days is inhumane and not recommended."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A field biologist describes warehouse cats as 'feral.' Which best defines feral cats in the shelter medicine context?","o":["Cats born outdoors that have never received veterinary care","Cats that are untamed and not socialized to humans — defined by socialization level, though this distinction is not consistently applied in published literature","Cats legally classified differently from stray cats in all US jurisdictions","Cats indistinguishable from strays without a minimum 3-day behavioral assessment"],"a":1,"e":"Feral cats are defined by their socialization level — untamed and not socialized to humans — not by birth location. A kitten born outdoors can become socialized with early handling; an abandoned adult pet retains socialization. This distinction is not consistently applied in published literature, and legal definitions vary by jurisdiction."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"An unspayed female community cat is identified in a managed colony. What is her estimated maximum lifetime kitten production based on average feline reproductive parameters?","o":["10–20 kittens","20–40 kittens","50–100 kittens","100–200 kittens"],"a":2,"e":"Female cats are seasonally polyestrous, averaging 1.4 litters per year with 4–5 fetuses per pregnancy (~3 live births per litter). An unspayed female can produce 50–100 kittens in a lifetime. This explains why the ≥70% sterilization threshold is critical — populations rebound rapidly without sustained intervention."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A community group proposes relocating a colony of 40 cats from a construction site to a public park. Which statement best reflects the shelter medicine position on trap-neuter-relocate?","o":["Relocation is preferred for all displaced colonies","Relocation is not routinely recommended — it is challenging, expensive, and newly relocated cats often attempt to return if not confined during transition","Relocation is only acceptable if cats are adopted out within 90 days","Relocation is legally prohibited in all US states"],"a":1,"e":"Trap-neuter-relocate is not routinely recommended due to time, expense, and logistical challenges. Suitable sites require reliable food, shelter, and a caretaker. Failure to confine newly relocated cats during the transition results in attempts to return to the original colony location. Relocation may be necessary when cats' safety is at risk or severe ecological concerns exist."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A welfare assessment is conducted in a community cat colony. Which combination of parameters constitutes the evidence-based visual welfare scale for free-roaming cats?","o":["Weight, body temperature, respiratory rate, mucosal color","BCS, coat condition, nasal/ocular discharge, ear crusting, and visible injuries","Fecal consistency, coat condition, mobility, hydration","Microchip status, vaccination record, dental score, behavior assessment"],"a":1,"e":"The validated visual welfare scale for community cats assesses: BCS, coat condition, nasal/ocular discharge, ear crusting, and visible injuries. All parameters can be assessed without physical handling — making them practical for field assessment of free-roaming populations."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Which management approach for free-roaming cats is most strongly associated with rapid population rebound (the 'vacuum effect')?","o":["TNR with <70% sterilization of intact females","Trap-remove-euthanize programs that fail to fully eliminate all cats from an area","TVHR programs where hormone production is maintained","Sanctuary placement programs"],"a":1,"e":"TRE programs that do not achieve complete removal of all cats from an area — and do not prevent immigration — rapidly repopulate through the vacuum effect. Remaining reproductive individuals and immigrating cats from surrounding areas fill the cleared territory. TNR reduces this by maintaining sterilized territorial residents that deter new arrivals."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Which published finding about disease prevalence in free-roaming community cats is most relevant for policy discussions?","o":["Free-roaming cats have significantly higher infectious disease rates, representing a greater zoonotic reservoir","Infectious and parasitic infection rates in free-roaming cats are similar to owned cats — they do not represent a greater public health reservoir","Free-roaming cats have no infectious disease risk due to natural selection","Free-roaming cats have lower disease rates due to herd immunity within colonies"],"a":1,"e":"Published studies show infectious disease and parasitic infection rates in free-roaming cats are similar to owned cats. Free-roaming cats do not pose a greater zoonotic risk than owned cats and do not serve as unique disease reservoirs. This is a critical finding for evidence-based community cat management policy discussions."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A TNR program is achieving 50% sterilization of the intact female population in a large open colony. What is the expected population trend?","o":["Population will slowly stabilize over 5–10 years","Population will decline proportional to sterilization achieved","Population will continue to grow — 50% does not meet the ≥70% threshold needed to outpace feline fecundity","Population will collapse due to reduced kitten survival"],"a":2,"e":"A 50% sterilization rate is insufficient. The ≥70% threshold of intact females must be achieved AND maintained within a geographically locked cohort to outpace feline reproductive capacity. At 50%, feline fecundity exceeds the impact of sterilization and the population continues to grow despite the program."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A public survey on community cat management is conducted. Which finding is most consistent with published literature?","o":["The majority of the public support lethal control as the most humane and effective strategy","Euthanasia is the most publicly acceptable management option","The overwhelming majority prefer leaving free-roaming cats outdoors over euthanasia, even knowing a cat could die of traumatic injury within 2 years","Most people are indifferent to free-roaming cat welfare"],"a":2,"e":"Published surveys consistently show the overwhelming majority prefer leaving free-roaming cats outdoors over capture and euthanasia — even when informed that outdoor life involves trauma and death within 2 years. Euthanasia is identified as the LEAST acceptable management option. No management strategy succeeds at large scale without public cooperation."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Why should observed colony size reductions in TVHR studies be interpreted cautiously?","o":["Colony size reductions are entirely explained by successful sterilization of females","Observed reductions may reflect decreased lifespan in hormonally intact animals (from fighting, mammary tumours, reproductive pathologies) rather than strategic population control efficacy","TVHR produces stronger FIV/FeLV immunity, explaining improved survival","TVHR reduces immigration more effectively than TNR, explaining population reduction"],"a":1,"e":"Colony size reductions in TVHR studies require cautious interpretation — they may reflect the decreased lifespan of cats retaining their gonads (injuries from fighting, mammary neoplasia, reproductive pathologies) rather than positive population control. True strategic efficacy would require demonstrating comparable or superior reduction to TNR through attrition over time, which has not been demonstrated in field research."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A shelter is preparing to adopt out a dog with a documented history of mild resource-guarding bites to two previous owners. What is the shelter's mandatory disclosure obligation under ASV Guidelines?","o":["Disclosure is optional if the adopter appears experienced with dogs","All known bite incidents must be documented in hardcopy or electronic form and provided to the adopter — verbal disclosure alone is insufficient","The shelter may withhold bite history if the dog has been behaviour-assessed and cleared as 'low risk'","Disclosure is only required if the bites resulted in medical treatment"],"a":1,"e":"ASV Guidelines require that a record of ALL known bite incidents be documented in hardcopy or electronic form and provided to adopters, fosters, and transfer partners. This is a non-negotiable disclosure obligation regardless of bite severity or behaviour assessment outcome. Verbal disclosure alone is not sufficient — written documentation must be transferred with the animal."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A shelter staff member is bitten on the forearm by a stray dog. The bite breaks the skin. What is the correct immediate wound management sequence?","o":["Apply a tourniquet, then seek medical attention","Immediately wash with soap and antiseptic (e.g., povidone-iodine), irrigate under pressure with saline via 20 mL syringe and 18G needle, cover, and seek medical attention","Apply a pressure bandage only — irrigation is not recommended for deep punctures","No immediate treatment needed; seek medical attention only if swelling develops within 24 hours"],"a":1,"e":"Immediate bite wound management: (1) wash thoroughly with soap and antiseptic with virucidal activity (povidone-iodine preferred); (2) irrigate under pressure using a 20 mL syringe and 18G needle with saline; (3) cover the wound; (4) seek medical attention. Immediate washing significantly reduces infection risk. If the hand is bitten, elevate it. Do not delay treatment."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A city council is considering passing breed-specific legislation (BSL) banning pit bull-type dogs within the municipality, citing public safety concerns. Which statement best represents the position of the American Veterinary Medical Association (AVMA)?","o":["BSL is effective when combined with owner education programs and should be selectively supported","BSL is not effective at reducing dog bite incidence; the AVMA opposes it in favour of individual behaviour-based assessment and responsible ownership ordinances","BSL is supported by the AVMA as a last resort when dangerous dog laws have failed","BSL is acceptable for use in shelters but not in private residences"],"a":1,"e":"The AVMA, along with ASV and most major veterinary organisations, opposes BSL because it is not supported by evidence as effective for reducing dog bite incidence. BSL targets breed/appearance rather than individual animal behaviour, owner responsibility, or situational factors. Evidence-based alternatives include individual dangerous dog laws, owner education, bite prevention programs, and enforcement of responsible ownership ordinances."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A stray dog bites a child at a park and is impounded by animal control. The dog appears healthy on intake. On day 8 of the mandatory observation period, the dog escapes and is hit by a vehicle, dying at the scene. What must happen?","o":["The dog may be cremated — it showed no clinical signs of rabies and died from trauma, not disease","The dog's head must be cooled (not frozen) and shipped to an approved diagnostic laboratory for mandatory rabies testing — any death during the 10-day observation window requires testing","The 10-day clock resets when a new biting incident occurs","Rabies testing is only required if the dog displayed neurological signs before death"],"a":1,"e":"Any dog, cat, or ferret that bites a human and dies for ANY reason within the mandatory 10-day observation window requires rabies testing. This includes accidental death from trauma. The head must be cooled (not frozen) — freezing and thawing destroys brain tissue architecture, potentially rendering the gold-standard dFA test unreadable. Public health law makes this testing mandatory regardless of the cause of death."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"According to the Dunbar bite severity scale, which level describes a bite where at least one puncture is deeper than half the length of the canine tooth, possibly with deep bruising or bidirectional lacerations from head-shaking?","o":["Level 2 — skin contact but no puncture","Level 3 — puncture(s) present but none deeper than half the canine tooth length","Level 4 — at least one puncture deeper than half the canine tooth; dog did not self-inhibit","Level 5 — multiple Level 4 bites in a single incident"],"a":2,"e":"Level 4 on the Dunbar scale describes 1–4 punctures where at least one exceeds half the canine tooth length, often with deep bruising or bidirectional lacerations from the dog holding and shaking. This indicates the dog applied sustained pressure and failed to self-inhibit — a qualitatively different risk from Level 3 (all punctures shallower than half tooth depth). Level 4+ bites are the threshold at which most shelter protocols significantly restrict or preclude public adoption without specialist behaviour evaluation."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A shelter dog has a documented history of a single Level 2 Dunbar bite. Which statement best characterises what a Level 2 bite means?","o":["Level 2 requires immediate euthanasia under most shelter safety protocols","The dog made skin contact without puncturing the skin — Level 2 bites are generally manageable with behaviour modification and trigger avoidance","Level 2 is the threshold for restricted public adoption — equivalent to a Level 4 clinical risk","Level 2 means no skin contact occurred; the dog snapped without touching the victim"],"a":1,"e":"Level 2 on the Dunbar scale describes skin contact without puncture — redness, bruising, or surface abrasions may occur but the skin is not broken. This is generally considered manageable with behaviour modification and careful management of identified bite contexts. Level 1 (no skin contact at all) and Level 2 are the lowest-risk bite categories. The critical question in every Level 2 case is the bite context, frequency, and predictability — not the level alone."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Which of the following is the strongest individual animal risk factor for dog bite incidents based on epidemiological data?","o":["Body weight greater than 30 kg","Intact male status","Positive kennel cough history","History of shelter housing for more than 14 days"],"a":1,"e":"Intact male dogs have a significantly higher bite rate than neutered males — this is one of the most consistently replicated individual animal risk factors across multiple bite epidemiology studies. Testosterone-driven territorial, competitive, and inter-male aggression contributes to this difference. Neuter status is therefore a core component of bite prevention messaging, though neutering alone does not eliminate bite risk from fear, pain, or resource guarding behaviours."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Which two groups are at highest risk of serious injury or death from dog bites in US epidemiological data, and why are children at elevated facial bite risk?","o":["Adult males 18–35 and animal control officers — due to daily occupational exposure","Veterinary staff and postal workers — due to frequency of bite incidents","Children under 5 and the elderly; children's height positions their face and neck at dog-head level and they cannot read canine warning signals","Pregnant women and immunocompromised individuals — due to impaired wound healing and infection risk"],"a":2,"e":"Children under 5 and the elderly are the groups at highest risk for serious injury or death from dog bites. Children are particularly at risk for facial and neck injuries because their height positions these structures at the same level as a medium or large dog's head. They also lack the developmental capacity to recognise and respond appropriately to canine warning signals (stiffening, growling, lip curl, whale eye). The elderly face increased risk due to slower reflexes and reduced physical resilience. The majority of bites in both groups involve familiar dogs, not random stranger attacks."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"What is the purpose of ear-tipping in a TNR programme, and which ear is the universal convention?","o":["Ear-tipping is a temporary marker removed at subsequent trapping; either ear can be used depending on local protocol","Ear-tipping (surgical removal of the distal ~1 cm of the left ear tip under anaesthesia) is a permanent, universally recognisable field identifier indicating the cat has been sterilised, vaccinated, and returned — it prevents unnecessary re-trapping and repeated anaesthesia","Ear-tipping is applied only to cats confirmed FIV-negative and serves as a serological record","Ear-tipping is an alternative to microchipping for cats that cannot be scanned"],"a":1,"e":"Ear-tipping — surgical removal of approximately 1/4 inch (about 1 cm) of the tip of the left ear under anaesthesia during the TNR procedure — is the universally accepted permanent field identifier for community cats that have been sterilised, vaccinated, and returned. It is visible at a distance without handling, allowing animal control officers, shelter staff, and caretakers to identify already-processed cats and avoid re-trapping. The convention is the LEFT ear. Ear-tipping does not replace microchipping but is the primary identification tool in the field."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"According to NASPHV guidelines, what is the recommended rabies vaccination protocol for cats in a TNR programme, and what does even a single vaccination provide?","o":["A single vaccination provides no clinically meaningful protection — cats require a full 3-dose primary series before release","Cats should receive a licensed 3-year rabies vaccine at TNR, be re-trapped for a booster at 1 year, then every 3 years; even one injection provides significant public health benefit as feral cats mount adequate antibody responses","Cats should receive only a 1-year killed vaccine annually — 3-year products are contraindicated in feral populations","Rabies vaccination is not required in TNR because feral cats are not classified as domestic animals under federal rabies law"],"a":1,"e":"NASPHV guidelines recommend vaccinating all TNR cats with a licensed 3-year rabies vaccine. The re-trapping schedule calls for a booster at 1 year, then every 3 years thereafter. Critically, even a single immunisation provides significant public health benefit — studies confirm that feral cats mount adequate antibody responses to a single rabies injection, increasing herd immunity within the free-roaming cat population. Rabies vaccination during TNR is one of the programme's core public health contributions."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"Two separate studies have measured the post-return death rate for cats returned to their capture site following TNR. What is this rate, and what does it imply about community cat welfare?","o":["Approximately 30% of returned cats die within 1 year","Approximately 6% confirmed death rate post-return; cats surviving to adulthood are expected to do well for several years or longer","Approximately 50% die within 6 months from vehicle trauma and predation","No peer-reviewed data on post-return mortality exist — this is a known evidence gap"],"a":1,"e":"Two separate published studies confirmed a post-return death rate of approximately 6% following TNR and return to the capture site. Cats that survive the initial post-return period and reach adulthood are expected to do well for several years or longer. Human feeding is consistently associated with improved survival and longer lifespans in managed colonies. Sterilisation further improves health by reducing pyometra, mammary tumours, and fighting-related FIV transmission. The 6% figure is critical for rebutting the argument that any outdoor cat life is uniformly poor welfare."},{"type":"mcq","domain":"Community & Public Health","sub":"Animals & Public Safety","q":"A shelter implements a Return-to-Field (RTF) programme, sterilising impounded stray cats and returning them to their community. Which statement best characterises RTF as a standalone intervention?","o":["RTF is the most evidence-based standalone method for reducing community cat populations","RTF independently achieves population reduction comparable to TNR within 18 months","RTF does not independently reduce cat populations and may be legally problematic in some jurisdictions; it should be used in combination with established TNR infrastructure, not as a standalone programme","RTF is equivalent to TNR and interchangeable for programme planning purposes"],"a":2,"e":"Return-to-Field (RTF) — also called Shelter-Neuter-Return (SNR) — diverts impounded stray cats from shelter housing and euthanasia through sterilisation and community return. However, it does not independently reduce community cat populations without accompanying TNR infrastructure already in place. Some jurisdictions have legal concerns about returning impounded animals. RTF's documented benefits are reducing shelter intake burden and preventing euthanasia of impounded cats; it contributes to sterilisation coverage when combined with active TNR, but it is not a substitute for a comprehensive programme."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Cumulative incidence (incidence risk) measures:","o":["The proportion of a population with disease at one point in time","The proportion of at-risk individuals who develop disease over a defined period","The number of deaths among confirmed cases","The average duration of disease"],"a":1,"e":"Cumulative incidence is the proportion of an at-risk group developing new disease over a stated period; a measure of risk."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Incidence rate (incidence density) differs from cumulative incidence because its denominator is:","o":["The number of confirmed cases","The total population at one time point","Total animal-time at risk","The number of deaths"],"a":2,"e":"Incidence rate uses animal-time at risk, giving cases per unit time and accommodating varying follow-up."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"When calculating cumulative incidence of an in-shelter disease, which animals must be EXCLUDED from the at-risk denominator?","o":["Animals housed individually","Animals over six months of age","Vaccinated animals","Animals already infected at the start and those arriving already infected"],"a":3,"e":"The denominator includes only animals capable of developing new disease, so existing and incoming cases are excluded."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Screening every cat for FeLV on intake day and reporting the proportion already infected measures:","o":["Point prevalence","Cumulative incidence","Case fatality rate","Incidence density"],"a":0,"e":"Disease present at a single time point in a population is point prevalence."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A chronic, long-duration disease tends to have:","o":["Low prevalence relative to its incidence","Equal incidence and prevalence","High prevalence relative to its incidence","Zero prevalence"],"a":2,"e":"Prevalence is approximately incidence times duration, so long-duration disease accumulates a high prevalence."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"August intake is 111 cats, 6 arriving already infected. The Aug 1 resident census is 39, of which 11 are infected and 3 recovered before Aug 1. The population at risk is:","o":["120","130","105","25"],"a":1,"e":"Incoming at risk 111 minus 6 = 105; resident at risk 39 minus 11 minus 3 = 25; total 130."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Which measure best expresses the probability that an individual animal will develop a disease?","o":["Incidence","Prevalence","Case fatality rate","Specificity"],"a":0,"e":"Incidence captures new disease over time, the measure of individual risk; prevalence reflects existing burden."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Why is the incidence rate (animal-time) often preferred over simple cumulative incidence in shelters?","o":["It is easier to calculate by hand","It ignores length of stay","It measures existing disease burden","Shelter populations are unstable with widely varying lengths of stay"],"a":3,"e":"Animal-time denominators handle the variable follow-up created by differing lengths of stay."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"In a cohort study, relative risk is calculated as:","o":["The odds of exposure in cases divided by controls","Deaths divided by confirmed cases","Incidence in the exposed divided by incidence in the unexposed","Existing cases divided by total population"],"a":2,"e":"Relative risk is the ratio of incidence in exposed to unexposed, available from cohort designs."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The odds ratio from a case-control study approximates the relative risk when:","o":["The sample is very small","Exposure is rare","The study is prospective","The disease is rare"],"a":3,"e":"Under the rare-disease assumption the odds ratio approximates the relative risk."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A relative risk of 1.0 indicates:","o":["No association between exposure and outcome","A strong protective effect","A doubling of risk","A statistically significant result"],"a":0,"e":"For a ratio measure the null value is 1, meaning no association."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The absolute excess risk in the exposed group compared with the unexposed is the:","o":["Odds ratio","Attributable risk (risk difference)","Relative risk","Prevalence ratio"],"a":1,"e":"Attributable risk is the difference in incidence between exposed and unexposed, an absolute measure."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A 2x2 table shows exposed cases 40, exposed non-cases 60, unexposed cases 20, unexposed non-cases 80. The relative risk is:","o":["1.0","0.5","2.0","4.0"],"a":2,"e":"Risk exposed 40/100 = 0.4; risk unexposed 20/100 = 0.2; RR = 0.4/0.2 = 2.0."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"An odds ratio is statistically non-significant when its 95% confidence interval includes:","o":["0","0.5","2","1"],"a":3,"e":"Ratio measures have a null value of 1; an interval that includes 1 is not significant."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A relative risk of 0.6 for a vaccinated group indicates:","o":["A protective effect of vaccination","An increased risk from vaccination","No association","A case fatality rate of 60%"],"a":0,"e":"A relative risk below 1 indicates reduced risk, here a protective effect."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"In a shelter trial, URI incidence is 30% in unvaccinated cats and 10% in vaccinated cats. The number needed to treat (NNT) is:","o":["3","5","10","20"],"a":1,"e":"ARR = 30% − 10% = 0.20. NNT = 1 ÷ ARR = 1 ÷ 0.20 = 5. Five cats must be vaccinated to prevent one URI case."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Number Needed to Treat (NNT) is derived from which statistic?","o":["Relative risk","Odds ratio","Absolute risk reduction (ARR)","P-value"],"a":2,"e":"NNT = 1 ÷ ARR. Using the absolute risk difference means two interventions with the same RR can still have very different NNTs if their baseline risks differ."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Dividing the number of animals that die of a disease by the number of confirmed cases of that disease gives the:","o":["Crude mortality rate","Cause-specific mortality rate","Prevalence","Case fatality rate"],"a":3,"e":"Case fatality rate uses confirmed cases as its denominator and reflects disease severity."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The denominator of the crude mortality rate is:","o":["Confirmed cases of one disease","The total population at risk of dying","Animals that recovered","Newly diagnosed cases"],"a":1,"e":"Crude mortality uses the whole at-risk population, not just cases."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Which statement correctly distinguishes case fatality rate from mortality rate?","o":["They are identical","Mortality rate uses cases as the denominator","Case fatality rate uses cases as the denominator; mortality rate uses the whole population","Case fatality rate measures incidence"],"a":2,"e":"The key difference is the denominator: cases for case fatality rate, whole population for mortality rate."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The number of deaths from parvovirus divided by the total population at risk during the interval is the:","o":["Cause-specific mortality rate","Case fatality rate","Attack rate","Point prevalence"],"a":0,"e":"Cause-specific mortality isolates deaths from one disease over the whole at-risk population."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Ten dogs are confirmed with parvovirus and four die. The case fatality rate is:","o":["10%","40%","4%","25%"],"a":1,"e":"Case fatality rate = 4 deaths / 10 cases = 40%."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Morbidity in a population is best described by:","o":["The death rate","The proportion of positive diagnostic tests","The incidence or prevalence of illness","The case fatality rate"],"a":2,"e":"Morbidity refers to the occurrence of illness, captured by incidence or prevalence."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The proportion of the total shelter population that dies from any cause during a period is the:","o":["Crude (all-cause) mortality rate","Case fatality rate","Cause-specific mortality rate","Attack rate"],"a":0,"e":"All-cause death over the whole population is the crude mortality rate."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A surveillance system in which the shelter actively seeks out cases rather than waiting for reports is:","o":["Passive surveillance","Syndromic only","Sentinel reporting","Active surveillance"],"a":3,"e":"Active surveillance involves deliberately seeking cases; passive relies on cases being reported in."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"In the population approach to disease, the equivalent of forming a differential diagnosis for an individual is:","o":["Performing a physical exam on each animal","Formulating epidemiological hypotheses about disease frequency","Treating each animal individually","Recording an individual history"],"a":1,"e":"At the population level the clinician forms hypotheses to explain the observed frequency and distribution of disease."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"A disease consistently present at a stable, expected baseline level in a population is described as:","o":["Endemic","Epidemic","Pandemic","Sporadic"],"a":0,"e":"Endemic refers to the usual expected baseline level; an excess above that is an epidemic or outbreak."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"An epidemic curve with a single sharp peak, cases clustered within one incubation period, suggests:","o":["A propagated animal-to-animal outbreak","An endemic pattern","A common (point) source exposure","A surveillance artifact"],"a":2,"e":"A single sharp peak within one incubation period is the signature of a common point-source exposure."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Successive peaks of cases spaced about one incubation period apart on an epidemic curve suggest:","o":["A point-source outbreak","Random background variation","A non-infectious cause","A propagated (animal-to-animal) outbreak"],"a":3,"e":"Progressive waves spaced by the incubation period indicate animal-to-animal propagated spread."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The primary purpose of establishing a case definition early in an outbreak investigation is to:","o":["Assign blame for the outbreak","Count cases consistently across the investigation","Calculate the case fatality rate","Replace diagnostic testing"],"a":1,"e":"A standard case definition lets investigators count cases consistently in time, place and animal."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"Attack rates calculated for different subgroups during an outbreak are used mainly to:","o":["Identify which groups are at highest risk","Measure long-term prevalence","Determine the case fatality rate","Estimate length of stay"],"a":0,"e":"Comparing attack rates across subgroups highlights the highest-risk groups and points to the source."},{"type":"mcq","domain":"Research & Biostats","sub":"Epidemiology & Biostats","q":"The sensitivity of a surveillance system refers to:","o":["How quickly it reports","Its running cost","The proportion of true cases it detects","The number of staff required"],"a":2,"e":"Surveillance sensitivity is the proportion of actual cases the system successfully detects."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which study design is most efficient for investigating risk factors for a rare disease with a long latency period?","o":["Prospective cohort","Case-control","Cross-sectional survey","Ecological study"],"a":1,"e":"Case-control starts from the outcome, making it efficient for rare or slow-developing diseases."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A shelter follows exposed and unexposed cats forward and compares the incidence in each group. Which measure can be calculated directly?","o":["Odds ratio only","Prevalence ratio","Positive predictive value","Relative risk"],"a":3,"e":"Cohort designs measure incidence in each group, allowing direct calculation of relative risk."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Testing every cat for FeLV on the single day of intake to estimate the proportion already infected is which design?","o":["Cross-sectional (prevalence) survey","Retrospective cohort","Case series","Randomised trial"],"a":0,"e":"Measuring disease at one point in a defined population is a cross-sectional survey, yielding prevalence."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A study finds counties with higher spay-neuter funding have lower intake, then concludes a funded individual is less likely to relinquish. This is:","o":["Recall bias","Ecological fallacy","Confounding by indication","Lead-time bias"],"a":1,"e":"Inferring an individual relationship from a group-level association is the ecological fallacy."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"In a case-control study, which measure of association is appropriate?","o":["Odds ratio","Relative risk","Incidence rate","Attributable risk"],"a":0,"e":"Selecting on outcome status yields the odds ratio, not incidence or relative risk."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"What is the principal advantage of randomisation in a controlled trial?","o":["It eliminates measurement error","It guarantees a large sample size","It removes the need for a control group","It balances known and unknown confounders across groups"],"a":3,"e":"Randomisation distributes confounders, including unmeasured ones, evenly between groups."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Intention-to-treat analysis means subjects are analysed according to:","o":["Whether they completed the full protocol","The treatment they actually received","The group to which they were originally assigned","Their final clinical outcome"],"a":2,"e":"Analysing by original assigned group preserves the benefits of randomisation."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A p-value of 0.03 most accurately means:","o":["There is a 3% probability the null hypothesis is true","There is a 3% probability the result occurred by chance","If the null were true, data this extreme or more would occur about 3% of the time","The treatment effect is clinically important"],"a":2,"e":"The p-value is the probability of the observed data or more extreme, assuming the null is true."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which statement about p-values is FALSE?","o":["A small p-value indicates the data are unlikely under the null","The p-value is the probability that the null hypothesis is true","Statistical significance does not establish clinical importance","Alpha is set before the analysis"],"a":1,"e":"The p-value is not the probability the null is true; that is the classic misinterpretation."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A Type I error occurs when an investigator:","o":["Fails to detect a true effect","Uses too small a sample size","Selects a biased control group","Concludes there is an effect when none truly exists"],"a":3,"e":"Type I error (alpha) is a false positive: rejecting a true null hypothesis."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Statistical power is defined as:","o":["The probability of detecting a true effect when it exists","The probability of a Type I error","One minus the p-value","The width of the confidence interval"],"a":0,"e":"Power equals 1 minus beta, the probability of correctly detecting a real effect."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which change increases the statistical power of a study?","o":["Increasing the sample size","Decreasing the sample size","Increasing variability in the outcome","Lowering alpha from 0.05 to 0.01"],"a":0,"e":"Larger samples increase power; lowering alpha and higher variability reduce it."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A study reports an odds ratio of 1.8 with a 95% CI of 0.9 to 3.4. How is this interpreted?","o":["A statistically significant positive association","A statistically significant protective effect","Not statistically significant, because the interval includes 0","Not statistically significant, because the interval includes 1"],"a":3,"e":"For a ratio measure the null value is 1; an interval crossing 1 is not significant at alpha 0.05."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A very large study finds a statistically significant 0.1% difference in adoption rate between two layouts. Best interpretation?","o":["The difference is clinically important because p is below 0.05","Large samples can make trivial differences significant, so clinical relevance is judged separately","The study must contain a Type I error","The confidence interval must include the null"],"a":1,"e":"Large samples can detect tiny, clinically meaningless differences; significance is not importance."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A narrower 95% confidence interval indicates:","o":["A larger p-value","A larger Type II error","A more precise estimate","A biased estimate"],"a":2,"e":"Interval width reflects precision; narrower means more precise, driven by larger samples and lower variability."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"In a case-control study, cases recall past exposures more thoroughly than controls. This is:","o":["Selection bias","Confounding","Effect modification","Recall bias"],"a":3,"e":"Differential recall between cases and controls is recall bias, a classic case-control weakness."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Studying disease risk using only adopted animals, excluding those euthanised, most likely introduces:","o":["Selection bias","Recall bias","Random error","Effect modification"],"a":0,"e":"Restricting to a non-representative subgroup distorts the association; this is selection bias."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Non-differential misclassification of exposure (errors equal across groups) typically:","o":["Biases the estimate away from the null","Biases the estimate toward the null","Has no effect on the estimate","Creates confounding"],"a":1,"e":"Non-differential misclassification usually dilutes associations, biasing toward the null."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"To be a confounder, a variable must be associated with the exposure, be an independent risk factor for the outcome, and:","o":["Lie on the causal pathway between exposure and outcome","Not lie on the causal pathway between exposure and outcome","Be measured after the outcome","Be randomly distributed"],"a":1,"e":"A confounder must not be an intermediate step on the causal pathway."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"When the true effect of an exposure genuinely differs across levels of a third variable, this is:","o":["Effect modification to be reported by stratum","Confounding to be removed","Selection bias","A Type I error"],"a":0,"e":"Effect modification is a real difference across strata and is described, not adjusted away."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which controls confounding at the ANALYSIS stage rather than the design stage?","o":["Randomisation","Restriction","Matching","Multivariable regression"],"a":3,"e":"Randomisation, restriction and matching are design methods; stratification and regression are analysis methods."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Increasing the sample size of a study will reduce:","o":["Selection bias","Confounding","Random error","Information bias"],"a":2,"e":"Larger samples reduce random error but do not fix systematic bias or confounding."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Sensitivity of a diagnostic test is:","o":["The proportion of test-positive animals that are truly diseased","The proportion of truly diseased animals that test positive","The proportion of truly healthy animals that test negative","A value independent of the reference standard"],"a":1,"e":"Sensitivity = TP/(TP+FN), the proportion of diseased animals correctly identified."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"A highly specific test is most useful clinically to:","o":["Rule a disease out when negative","Screen a whole population cheaply","Replace the reference standard","Rule a disease in when positive"],"a":3,"e":"SpPin: a specific test, when positive, helps rule the disease in."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Using a fixed test, what happens to positive predictive value as disease prevalence decreases?","o":["PPV increases","PPV decreases","PPV is unchanged because it depends only on sensitivity","Specificity decreases"],"a":1,"e":"At lower prevalence a greater share of positives are false positives, so PPV falls; Se and Sp are unchanged."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which test characteristic is unaffected by disease prevalence?","o":["Sensitivity","Positive predictive value","Negative predictive value","Adoption rate"],"a":0,"e":"Sensitivity and specificity are properties of the test; PPV and NPV depend on prevalence."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Of 100 truly infected cats a test flags 90 as positive; of 100 uninfected it flags 5. What is the sensitivity?","o":["47%","95%","90%","5%"],"a":2,"e":"Sensitivity = 90 true positives / 100 diseased = 90%."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Which method best analyses time to adoption, including animals still in care at study end?","o":["Independent t-test","Chi-square test","Pearson correlation","Kaplan-Meier survival analysis"],"a":3,"e":"Survival analysis handles time-to-event data with censored (still in care) observations."},{"type":"mcq","domain":"Research & Biostats","sub":"Study Design","q":"Among the Bradford Hill considerations for causation, which is considered essential?","o":["Strength of association","Dose-response relationship","Temporality (cause precedes effect)","Analogy"],"a":2,"e":"Temporality is the one essential criterion; the cause must precede the effect."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following is the MOST common form of animal abuse encountered by shelter and veterinary professionals?","o":["Intentional physical trauma","Animal neglect (passive cruelty)","Animal sexual abuse","Animal fighting"],"a":1,"e":"B is correct. Animal neglect — failure to provide adequate food, water, shelter, or veterinary care — is by far the most frequently encountered category in shelter and veterinary practice. Intentional active abuse is more dramatic but less common."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The PACT Act (2019) established which of the following?","o":["Mandatory veterinary reporting of suspected animal cruelty in all 50 states","Federal regulation of animal shelters and their standards of care","Federal felony charges for intentional acts of crushing, burning, drowning, suffocating, impaling, or sexual exploitation of animals","A national registry of convicted animal abusers accessible to shelters"],"a":2,"e":"C is correct. The Preventing Animal Cruelty and Torture (PACT) Act of 2019 created the first broad federal anti-cruelty law covering companion animals, making intentional acts of serious cruelty a federal felony. It does not mandate veterinary reporting (a state-level issue) or regulate shelter standards."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which feature most distinguishes animal hoarding from simple multi-animal neglect?","o":["Hoarding involves only dogs; multi-animal neglect involves mixed species","Hoarding involves denial of the problem, a deteriorating environment for both animals and humans, and very high recidivism without intervention targeting the underlying psychological disorder","Hoarding is always a criminal felony; neglect may be treated as a misdemeanor","Hoarding requires more than 50 animals; fewer animals constitute simple neglect"],"a":1,"e":"B is correct. Animal hoarding is a distinct syndrome characterized by accumulation of many animals beyond the capacity to provide adequate care, denial of the problem, and an environment that deteriorates for both animals and people. Recidivism is extremely high without psychological intervention targeting the underlying disorder. No specific number of animals defines hoarding."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Multiple fractures in various stages of healing on whole-body radiographs of a dog is most consistent with which of the following?","o":["A single high-impact traumatic event (e.g., motor vehicle accident)","Repeated trauma occurring over time, consistent with ongoing abuse","Osteogenesis imperfecta (brittle bone disease)","Nutritional secondary hyperparathyroidism from a calcium-deficient diet"],"a":1,"e":"B is correct. Multiple fractures in different stages of healing indicate injuries occurring at different points in time, which is inconsistent with a single acute event. This pattern is the most reliable radiographic indicator of repeated traumatic abuse. While metabolic bone disease can cause pathological fractures, the combination of multiple sites and different healing stages points to repeated trauma."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A severely emaciated dog with a body condition score of 1/9 is admitted to a shelter following a cruelty seizure. You begin feeding. Which of the following is the most important clinical concern in the first 3–5 days of refeeding?","o":["Aspiration pneumonia from eating too fast","Refeeding syndrome: electrolyte shifts (hypophosphatemia, hypokalemia, hypomagnesemia) that can cause hemolysis, arrhythmias, and neurological signs","Gastric dilatation-volvulus from a single large meal","Development of food aggression that will require behavioral euthanasia"],"a":1,"e":"B is correct. Refeeding syndrome is the most important short-term clinical risk. Rapid refeeding after starvation causes a shift of phosphorus, potassium, and magnesium from the extracellular to intracellular compartment as insulin is stimulated by incoming glucose. Resulting electrolyte deficiencies can cause hemolytic anemia, cardiac arrhythmias, and neurological signs. Introduce food gradually (25–33% RER on day 1) and monitor electrolytes daily."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A cruelty suspect states their dog sustained an injury when it \"fell off the couch.\" You examine the dog and find bilateral forelimb fractures, a healing rib fracture, and a fresh bruise over the dorsal thorax. Which principle best describes the significance of the history-injury inconsistency?","o":["The inconsistency proves the owner is lying and is guilty of abuse","The inconsistency is a red flag that the stated mechanism is insufficient to explain the findings, warranting further investigation and documentation — though the veterinarian's role is to note the inconsistency, not to determine guilt","A couch fall cannot cause any fractures, so the owner's history is impossible","The veterinarian should confront the owner directly to obtain an accurate history before filing a report"],"a":1,"e":"B is correct. A history inconsistent with the injuries is a core forensic red flag. However, the veterinarian documents and reports the inconsistency — they do not determine guilt. Bilateral forelimb fractures, a healing rib fracture, and a new bruise from a single \"fall off the couch\" are inconsistent with that mechanism. The veterinarian should document thoroughly and report to law enforcement, who will investigate. Confronting the owner risks evidence contamination and personal safety."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When performing a forensic necropsy on a cruelty case, which of the following best describes the correct approach to a projectile found in the carcass?","o":["Remove the projectile with forceps, clean it, and place it in a standard specimen jar","Leave the projectile in situ; do not remove it as it may be needed for in-body radiographic documentation only","Remove the projectile carefully using minimal-contact technique (avoid crushing with forceps), place it in a dry, sealed, labeled container under chain-of-custody documentation","Discard the projectile after photographing; only the wound tract is legally relevant"],"a":2,"e":"C is correct. Projectiles (bullets, pellets, BBs) are physical evidence subject to ballistic analysis that can link a firearm to a crime. They must be removed with minimal surface contact (not crushed with forceps, which creates tool marks that interfere with forensic analysis), placed in a dry container (not formalin), sealed, labeled with case ID and chain-of-custody information, and logged when transferred to law enforcement."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Studies by Ascione and others have found that approximately what percentage of women entering domestic violence shelters reported that their partner had threatened, injured, or killed a pet?","o":["10–15%","25–35%","~71%",">90%"],"a":2,"e":"C is correct. The 71% figure (Ascione et al.) is the landmark and most frequently cited statistic for the co-occurrence of animal abuse and domestic violence. Many of these women delayed leaving the abusive household because they had no safe placement for their pets, driving the development of safe harbor programs."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following best describes the concept of \"cross-reporting\" in the context of The Link?","o":["Animal control officers file reports with both local and state agencies simultaneously","Animal welfare professionals report suspected human abuse when they encounter it, and human service workers report suspected animal abuse — information flows in both directions","Veterinarians report to the local police, who then cross-report to the state attorney general","Domestic violence shelters share client information with animal shelters to coordinate co-shelter placement"],"a":1,"e":"B is correct. Cross-reporting is a bidirectional practice: animal control officers and veterinarians who observe signs of child abuse, elder abuse, or domestic violence report those concerns to human services; and child protective service workers, police, and social workers who encounter animal abuse report it to animal control. The bidirectional nature is the key tested concept."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Safe harbor programs for domestic violence survivors primarily address which barrier to leaving an abusive relationship?","o":["Lack of financial resources to cover housing costs","Fear of losing child custody","Lack of safe housing for pets, which causes survivors to delay or refuse to leave an abuser","Absence of legal representation for filing protective orders"],"a":2,"e":"C is correct. Safe harbor programs exist specifically because a significant proportion of domestic violence survivors delay leaving — or choose not to leave — because they have no safe place for their pets and cannot bring them to a traditional DV shelter. Providing temporary housing for pets removes this barrier and enables survivors to seek safety."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A veterinarian in a state with a mandatory animal cruelty reporting law examines a dog with injuries strongly suspicious for abuse. The owner insists the injuries are accidental. What is the veterinarian's legal obligation?","o":["Report only if the injuries are proven to be intentional beyond a reasonable doubt","Report the suspected abuse to animal control or law enforcement; a good-faith report is protected from civil liability regardless of the ultimate determination of guilt","Withhold treatment until law enforcement is present","Obtain written consent from the owner before contacting animal control"],"a":1,"e":"B is correct. Mandatory reporting laws require reporting suspected (not proven) cruelty. The legal standard is suspicion based on professional judgment, not certainty. Immunity provisions protect the veterinarian from civil liability for a good-faith report even if the case is ultimately not prosecuted. The veterinarian should not withhold treatment for medical needs, and owner consent is not required to file a report with animal control."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When a veterinarian in a cruelty case writes an examination report, which of the following best describes the appropriate language for the opinion section?","o":["\"The defendant deliberately and cruelly harmed this animal.\"","\"There is no doubt that these injuries were inflicted.\"","\"The injuries are consistent with inflicted blunt force trauma; accidental injury is less consistent with the distribution and severity of findings.\"","\"I believe the owner is responsible for these injuries based on my assessment of their demeanor.\""],"a":2,"e":"C is correct. Veterinary forensic opinions should use \"consistent with\" language that describes the medical findings and their most likely mechanism, while acknowledging the differential. Statements that name the perpetrator, assign intent, or claim certainty beyond what the evidence supports invade the fact-finder's role and can make expert testimony inadmissible. The demeanor of the owner is not a medical finding."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A cost-of-care bond statute in an animal cruelty case primarily serves which purpose?","o":["Provides the shelter with immediate legal ownership of seized animals","Requires the owner to post a bond covering ongoing care costs; failure to post results in forfeiture, preventing animals from languishing indefinitely in legal limbo","Compensates shelter staff for overtime worked during mass-seizure events","Establishes a cap on the cost of veterinary care the shelter may provide to evidence animals"],"a":1,"e":"B is correct. Cost-of-care bonds require owners to periodically post funds covering the shelter's cost of caring for seized animals. If the owner fails to post the bond, they forfeit ownership of the animals, allowing the shelter to proceed with placement or other disposition without waiting for the criminal case to conclude. This addresses the chronic problem of expensive long-term holds of evidence animals."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The Daubert standard, as applied to veterinary expert testimony in a cruelty case, requires that the expert's opinion:","o":["Be based on the veterinarian's personal experience alone, without published literature support","Be based on reliable scientific methodology with a sufficient factual basis and be relevant to the facts of the case","Have been accepted as standard of care for at least 10 years (the \"general acceptance\" test)","Match the opinion of a majority of veterinarians in the relevant specialty"],"a":1,"e":"B is correct. The Daubert standard (used in federal courts and many state courts) requires that expert testimony be based on a reliable methodology with a sufficient factual basis, be the product of a reliable application of that methodology, and be relevant to the dispute. It replaced the older Frye \"general acceptance\" test in many jurisdictions. Veterinarians offering expert opinions should be prepared to explain the scientific basis for their conclusions."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Animals seized in a cruelty investigation are admitted to your shelter under law enforcement custody. Before you can adopt one out to an interested applicant, what must occur?","o":["A 10-day stray hold must be completed","The animal must pass a behavioral evaluation","Court authorization (or authorization from the prosecuting agency) must be obtained before any change in disposition of evidence animals","The owner must be given the opportunity to reclaim the animal within 72 hours"],"a":2,"e":"C is correct. Animals held as evidence in an ongoing criminal case are the property of the court until the case is resolved or the court orders otherwise. Adopting, transferring, or euthanizing (except in a documented medical emergency) without court authorization constitutes destruction of evidence and can result in charges against the shelter. Always obtain written authorization from the DA's office or court before making any disposition decision for evidence animals."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A large dogfighting operation is raided and 120 dogs are seized and transported to your shelter over 4 hours. Which organizational model is most appropriate to manage this mass-seizure event?","o":["Standard intake processing with extra volunteers called in","Incident Command System (ICS) with designated roles: incident commander, veterinary triage lead, documentation team, animal care team, and liaison to law enforcement","Transfer all animals immediately to multiple partner shelters without individual documentation","Euthanize all dogs immediately because dogfighting dogs are too dangerous to assess"],"a":1,"e":"B is correct. Mass-seizure events require the Incident Command System (ICS) structure to maintain coordination, chain-of-custody documentation, and evidence integrity under surge conditions. Each dog must receive an individual ID and be documented from the moment of seizure. Transferring animals without documentation destroys chain-of-custody. Blanket euthanasia of fighting dogs is neither required nor appropriate; behavioral assessment determines individual outcomes."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A shelter veterinarian admits a cruelty case animal and wants to bathe it to document skin injuries more clearly. What is the most appropriate sequence of actions?","o":["Bathe the animal first to allow clear photography, then perform the physical examination","Complete full photographic documentation, swab collection, and physical examination before bathing; notify the law enforcement officer before any evidence-altering procedures","Bathe and clip hair, then perform radiographs; skin injuries are documented by clipping alone","Bathing is always acceptable in cruelty cases because it does not alter injury evidence"],"a":1,"e":"B is correct. Bathing, clipping, or treating an animal before forensic documentation can destroy trace evidence (fibers, blood, human DNA under nails, soil) and alter wound appearance. Complete all forensic documentation first (photography, swabs, physical exam, radiographs), notify the law enforcement officer of any planned treatment, and then proceed with bathing and clinical care. If a life-threatening emergency requires immediate treatment, document the pre-treatment state as thoroughly as possible before intervening."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Shelter workers regularly involved in cruelty investigations are at elevated risk of which occupational health condition?","o":["Primary PTSD from direct personal trauma","Secondary traumatic stress (STS) and compassion fatigue from indirect exposure to the suffering of animals and human victims","Burnout exclusively related to caseload volume, not to cruelty content","Occupational asthma from chemical disinfectant exposure"],"a":1,"e":"B is correct. Secondary traumatic stress (STS) develops from indirect exposure to trauma through the suffering of others — in this case, abused animals and their human victims. STS symptoms are similar to PTSD: intrusive imagery, avoidance, hyperarousal, and emotional numbing. Shelter leaders have a duty of care to monitor staff for STS and to build organizational resilience through rotation, peer support, and access to mental health resources."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In the context of animal cruelty forensics, what is the purpose of documenting the \"vital reaction\" at a wound site on histopathology?","o":["To determine the breed of the animal from inflammatory cell characteristics","To determine whether the injury occurred while the animal was alive (perimortem), distinguishing it from postmortem artifact","To identify the specific instrument used to inflict the injury","To determine whether the injury was painful to the animal"],"a":1,"e":"B is correct. Vital reaction (hemorrhage, acute inflammatory infiltration at a wound site) indicates that the injury occurred while the animal had a functioning cardiovascular and immune system — i.e., while alive or immediately perimortem. Absence of vital reaction in a wound suggests the injury occurred after death (postmortem artifact from handling or scavenging). This distinction is critical for timeline reconstruction in cruelty investigations."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When was the FBI's Uniform Crime Reporting (UCR) system updated to specifically track animal cruelty as a distinct crime category?","o":["1994","2008","2016","2020"],"a":2,"e":"C is correct. In 2016, the FBI began tracking animal cruelty as a Group A offense in the National Incident-Based Reporting System (NIBRS), allowing for the first time systematic national data collection on animal cruelty crimes. This change reflected the recognition of animal cruelty's link to broader patterns of violence and was a significant advocacy victory for animal protection organizations."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which fracture pattern is MOST consistent with non-accidental injury (NAI) rather than a single accidental event?","o":["Isolated greenstick fracture of the distal radius in a 6-month-old puppy","Multiple fractures in different anatomical regions, each in a different stage of healing","Single transverse fracture of the femur with a consistent history of being hit by a car","Bilateral carpal fractures in a 10-year-old dog with nutritional secondary hyperparathyroidism"],"a":1,"e":"B is correct. Multiple fractures in different stages of healing in different body regions indicate injuries occurring at multiple points in time — this cannot be explained by a single event and is the hallmark radiographic finding of NAI. Greenstick fractures are typical accidental fractures in young animals. A single femur fracture with a consistent history is not suspicious in isolation. Metabolic bone disease can produce multiple fractures but the history and blood work would support this diagnosis."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Subconjunctival and scleral hemorrhages in a cat without external facial trauma are MOST consistent with:","o":["Hypertensive retinopathy from chronic kidney disease","Sudden increase in intracranial or intrathoracic pressure from shaking or choking","Primary coagulopathy causing spontaneous hemorrhage","Anterior uveitis secondary to FIP"],"a":1,"e":"B is correct. Subconjunctival and scleral hemorrhages without external facial trauma are classic findings in shaken or choked animals. The sudden rise in intracranial/intrathoracic pressure forces blood through conjunctival and scleral vessels. This is a well-recognised NAI finding in both veterinary and human forensic medicine. While hypertension and coagulopathy are differentials, the NAI context makes shaking/choking the leading consideration."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A dog presents with hemoabdomen, pale mucous membranes, and tachycardia. On abdominal radiographs there is free fluid and the diaphragm is not visible as a distinct line. The MOST likely injury consistent with blunt NAI is:","o":["Ruptured urinary bladder from urethral obstruction","Ruptured spleen or liver AND diaphragmatic hernia from high-energy abdominal compression","Splenic torsion with concurrent ascites from hypoproteinaemia","Bile peritonitis from a ruptured common bile duct"],"a":1,"e":"B is correct. High-energy blunt abdominal compression (stomping, kicking) can simultaneously rupture abdominal organs causing hemoabdomen and tear the diaphragm causing a diaphragmatic hernia. The loss of a distinct diaphragmatic line on radiograph is a key indicator of diaphragmatic hernia. Both findings together in the NAI context point to a single high-energy compressive event."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which animal best fits the ASPCA NAI high-risk animal profile?","o":["8-year-old spayed female Labrador retriever, calm, friendly with owner","10-month-old intact male mixed-breed dog, 12 lbs, cowers and urinates when the owner approaches","4-year-old neutered male domestic shorthair cat, indoor only, normal physical exam","6-year-old spayed female Golden retriever, annual wellness exam, no injuries"],"a":1,"e":"B is correct. This dog hits multiple ASPCA NAI risk factors: age <2 years, intact male, mixed breed, small (<15 lbs), and showing fearful behaviour specifically toward the caretaker (cowering and urinating on approach). No single factor confirms NAI, but the combination of multiple risk factors in this animal warrants heightened vigilance."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An owner brings in a dog with a femur fracture. They state the dog \"fell off the couch yesterday.\" On exam you also note a 3-week-old healing rib fracture and fresh bruising on the dorsal thorax. Which of the following best describes your obligation?","o":["Accept the history; couch falls can cause femur fractures in small dogs","Confront the owner directly and demand an explanation for the rib fracture before treating","Document all findings objectively, treat the animal, and report to animal control or law enforcement","Withhold treatment until law enforcement arrives and takes a statement from the owner"],"a":2,"e":"C is correct. Multiple fractures in different healing stages with fresh bruising are incompatible with the stated mechanism. Document objectively (\"owner stated animal fell from a couch; physical examination reveals a femur fracture, a 3-week-old healing rib fracture, and fresh dorsal thoracic bruising inconsistent with the stated history\"). Treat the animal's injuries and report to animal control. Do not withhold emergency care, and do not confront the owner — this can compromise safety and evidence."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When performing a full-body radiographic survey on a NAI suspect, which of the following is the MOST important reason for including the skull?","o":["Skull radiographs are required by law in cruelty cases","Skull fractures may be occult (not apparent externally) and require significant force — their detection strengthens the NAI diagnosis","Skull radiographs identify the breed of the animal for documentation","Dental radiographs are more sensitive and replace the need for skull films"],"a":1,"e":"B is correct. Skull fractures require substantial force and are inconsistent with most accidental injuries described by owners. They can be completely occult on external examination — no external scalp/fur injury. Including the skull in a full-body survey detects occult fractures that strengthen the forensic case. The skull views should include lateral, DV, and oblique projections to maximise fracture detection."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Damage to the claws or nail beds of a cat presented as a cruelty case is MOST suggestive of:","o":["Onychomycosis from a chronic fungal infection","Dragging, restraint, or direct trauma to the feet consistent with NAI","Nutritional deficiency causing brittle nails","Self-mutilation secondary to obsessive-compulsive disorder"],"a":1,"e":"B is correct. Nail bed avulsions, fractured claws, or burns of the claw tips are recognised NAI findings, associated with dragging (claws breaking as the animal is dragged across a surface), restraint (the animal clawing against a surface while restrained), or direct application of heat. Preserve the broken nail material as physical evidence — clip into a sealed, labelled envelope."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An owner who brings their dog to a different veterinary clinic each visit and uses a different surname each time is exhibiting which NAI caretaker risk factor?","o":["Financial difficulty making it necessary to seek the cheapest available clinic","\"Practice shopping\" — seeking care from multiple providers to prevent detection of a pattern of repeated injuries","Dissatisfaction with veterinary care quality, a common and benign behaviour","A requirement for multiple opinions before agreeing to treatment"],"a":1,"e":"B is correct. Using multiple practices with name discrepancies is a recognised NAI caretaker risk factor, consistent with deliberate \"practice shopping\" to prevent any single clinic from accumulating a record of repeated injuries. This pattern should be documented. Clinicians who encounter such a pattern should check whether the animal has a microchip that might be registered under previous visits at other practices."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A hair mat forming a circumferential band around a dog's digit most directly causes which complication?","o":["Traction alopecia at the mat margin","Distal limb ischaemia and potential auto-amputation from tourniquet effect","Pododermatitis secondary to urine contamination of the mat","Contact dermatitis from bacterial colonisation of the mat surface"],"a":1,"e":"B is correct. Strangulating distal extremity mats act as a tourniquet — the hair mat wraps circumferentially around a digit or paw, progressively constricting blood flow → ischaemia → necrosis → auto-amputation. This is a medical emergency. The mat must be cut to relieve the constriction as soon as possible, while being photographed and retained as evidence first."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An emaciated dog with a BCS of 2/9 is admitted following a neglect seizure. What is the MOST important nutritional management principle in the first 72 hours?","o":["Feed ad libitum immediately to accelerate recovery and demonstrate neglect reversal","Introduce food at 25–33% of resting energy requirement on day 1 and advance gradually, with daily electrolyte monitoring","Withhold food for 48 hours to allow the GI tract to recover before introducing nutrients","Begin a high-fat, high-protein diet immediately to maximise caloric density"],"a":1,"e":"B is correct. Refeeding syndrome is the critical risk in the first days of nutritional rehabilitation. Starting at 25–33% of RER avoids the sudden insulin surge that causes intracellular shifting of electrolytes. Monitor phosphorus, potassium, and magnesium daily. Advance to full RER over 3–5 days. Ad libitum or rapid feeding can be fatal due to hypophosphatemia, arrhythmias, and haemolytic anaemia."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following MOST effectively distinguishes criminal neglect-associated emaciation from disease-related weight loss?","o":["The presence of hypoalbuminaemia, which only occurs in starvation and not in other diseases","The animal gains weight on a controlled feeding protocol with no treatment other than nutrition, confirming food deprivation as the cause","BCS ≤ 2/9 is specific for criminal neglect and cannot occur in medical disease","The owner's stated feeding history, which is reliable when taken from multiple witnesses"],"a":1,"e":"B is correct. The most powerful forensic evidence for nutritional neglect is the animal's documented response to feeding — a malnourished animal with no underlying disease will gain weight on nutrition alone. Record daily weights and BCS changes in the shelter record; this trajectory becomes part of the evidence file. Hypoalbuminaemia, low BCS, and poor coat can occur in multiple disease states and are not pathognomonic for starvation."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An owner presents a dog with a collar deeply embedded in the neck, covered by granulation tissue. What is the MOST forensically important step before beginning treatment?","o":["Sedate the animal and remove the collar immediately to relieve pain","Photograph the embedded collar in situ, document the wound characteristics, then remove and retain the collar as physical evidence","Obtain owner consent before removing the collar, as it is their property","Discard the collar after removal — it has no evidentiary value once the wound is treated"],"a":1,"e":"B is correct. The collar is physical evidence. Photograph the wound and collar in situ from multiple angles with a scale bar before any treatment. After removal, place the collar in a sealed, labelled evidence envelope. Document the collar circumference, the depth of embedding, wound dimensions, and estimated duration (based on degree of granulation tissue and skin coverage). The collar can directly demonstrate the duration of neglect."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following matting presentations is MOST consistent with chronic, long-standing neglect rather than a recent period without grooming?","o":["Mild tangles requiring a 30-minute brush-out","Full-body pelting requiring general anaesthesia for clip-down, with traction alopecia at mat margins and urine scald","Post-bathing matting that formed after an owner tried to bathe the dog at home","Ear matting in a Cocker Spaniel that missed one grooming appointment"],"a":1,"e":"B is correct. Full-body pelting requiring general anaesthesia for clip-down indicates months of no grooming. The combination with traction alopecia (long-standing pulling of mats on the skin) and urine scald (prolonged exposure to soiled bedding) indicates chronic, severe neglect lasting many months, not a brief lapse in grooming. This presentation supports criminal neglect, not situational neglect from a single missed appointment."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A new client presents a severely emaciated, matted dog for euthanasia. They state they \"found it stray this morning.\" Which action is MOST appropriate?","o":["Proceed with euthanasia immediately — the animal is suffering and the client is requesting humane intervention","Perform and photograph a complete physical examination, document findings, report to animal control, and discuss the situation with the owner — do not euthanise without forensic documentation","Accept the stray history at face value and process the animal as a stray through normal shelter intake","Refuse to see the animal without proof of ownership"],"a":1,"e":"B is correct. A new client requesting euthanasia of a severely neglected animal is a high-risk scenario for evidence destruction. The \"found stray\" history for an animal with chronic neglect signs (extreme emaciation, full-body pelting) is implausible — this condition develops over months and is visible to any owner. Perform a complete forensic examination, photograph, and report to animal control before making any euthanasia decision. If euthanasia is medically warranted, obtain court/prosecutorial authorisation if possible, or document the veterinary emergency justification thoroughly."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following animal profiles carries the HIGHEST risk for criminal neglect based on ASPCA risk factor criteria?","o":["4-year-old neutered male Labrador, indoor, normal body weight","2-year-old intact female Maltese, tethered outdoors, from a household with 40 animals","8-year-old spayed female domestic shorthair cat, indoor only, annual wellness visits","6-month-old male Labrador puppy, indoor with regular grooming"],"a":1,"e":"B is correct. This animal has multiple ASPCA criminal neglect risk factors: intact female (pyometra risk), small long-haired breed (matting risk), tethered outdoor (environmental exposure), and hoarding environment (40 animals = hoarding, near-universal neglect). The combination of all four factors in a single animal represents the highest-risk profile."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An owner requests antibiotics for their dog's skin infection but refuses to allow the veterinarian to examine the animal. This presentation is MOST consistent with which criminal neglect risk pattern?","o":["An owner with legitimate financial constraints who cannot afford an exam fee","Requesting medications while declining examination — a recognised history risk factor that may indicate concealment of neglect or concurrent injuries","A preference for home treatment that is common among rural pet owners","Concern about the animal's stress during a veterinary visit"],"a":1,"e":"B is correct. Requesting medications for home administration while refusing examination is a specific ASPCA criminal neglect history risk factor. The owner may be concealing the extent of the animal's condition (additional injuries, emaciation, embedded collar) or attempting to treat a problem without allowing documentation. Do not provide prescription medications without examination; document the refusal; and if the owner agrees to an exam, report any findings consistent with neglect to animal control."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In an organised dogfighting case, wounds are MOST characteristically distributed on which body regions?","o":["Dorsal lumbar region and tail base","Face/ears, neck/scruff, and medial thighs","Distal limbs and ventral abdomen","Dorsal thorax and perianal region"],"a":1,"e":"B is correct. Organised dogfighting produces a characteristic injury distribution: face and ears (primary bite targets), neck and scruff (grip zone), and medial thighs (exposed when dogs are locked together). This distribution, especially when combined with old scars and fresh wounds at the same sites, is the hallmark finding distinguishing organised fighting from a single dog-fight encounter. Intarapanich et al. (2017) validated this distribution in a systematic study of confirmed fighting dogs."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which piece of equipment found at a property is considered the MOST specific indicator of dogfighting operations?","o":["A weighted treadmill (carpet mill)","A spring pole attached to a tree","A breaking stick","Multiple heavy-gauge tethering chains"],"a":2,"e":"C is correct. The breaking stick — a wedge-shaped implement used to pry apart locked dog jaws — has no legitimate purpose outside of dogfighting. Carpet mills, spring poles, and tethering chains are used in legitimate dog sports (weight pull, protection sport, hunting). The breaking stick is considered near-definitive evidence of dogfighting operations and is the single most specific item."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An adult rooster has a flat, scarred crown where the comb once was, and abnormally short natural spurs. This presentation is MOST consistent with:","o":["A genetic mutation causing comb agenesis","Deliberate dubbing (comb and wattle removal) and spur trimming for cockfighting","Frostbite damage to the comb from cold exposure","Breed-typical appearance of a Silkie or Polish bantam"],"a":1,"e":"B is correct. Dubbing (surgical removal of the comb and wattles) combined with spur trimming (to allow gaff attachment) is the diagnostic combination for a cockfighting bird. Frostbite can damage combs but does not produce the clean scar of deliberate dubbing. Silkies have small crests but normal spurs. The combination of dubbed comb + short natural spur in an adult rooster is the exam-testable sign of a cockfighting bird."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Under 7 U.S.C. § 2156 (Animal Welfare Act), which of the following is a federal felony?","o":["Owning a dog that has previously been in a fight, even without the owner's knowledge","Attending a dogfight or cockfight as a spectator","Breeding pit bull-type dogs for sale","Owning a breaking stick without proof of its intended use"],"a":1,"e":"B is correct. Since 2014, attending a dogfight or cockfight as a spectator is a federal felony under the Animal Welfare Act. This is a specific and testable legal point. Simply owning a dog with a fighting history (without knowledge or intent) is not the same as participating in fighting. Breeding pit bull-type dogs is legal. The breaking stick itself is a physical object — possession is evidence of fighting but the crime requires the fighting activity or intent."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Blood recovered from the surface of a fighting pit is submitted for STR profiling. The profile matches a blood sample from Dog #14, one of 30 dogs seized from the property. This result:","o":["Proves Dog #14 was forced to fight, establishing intent without other evidence","Establishes that Dog #14's blood was deposited in the fighting pit, supporting the conclusion that the dog was present at the fight location","Is inadmissible because animal DNA evidence cannot be used in criminal proceedings","Identifies the breed of Dog #14, which determines whether fighting charges apply"],"a":1,"e":"B is correct. STR profiling links biological material (blood on the pit surface) to a specific individual dog. This is powerful circumstantial evidence that the dog was present at the fight location. It does not, on its own, prove intent or force — but combined with the dog's injury pattern, the scene evidence, and other findings, it substantially strengthens the prosecution's case. Animal DNA evidence is admissible and has been used successfully in US criminal proceedings."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When collecting DNA swabs from blood on a breaking stick, the swabs should be stored in:","o":["A sealed plastic bag at room temperature","A paper envelope or bag, air-dried, with chain-of-custody label","A red-top tube with formalin preservative at 4°C","An EDTA tube frozen at −20°C"],"a":1,"e":"B is correct. Biological samples for DNA analysis must be air-dried and stored in paper — not plastic. Sealed plastic containers trap moisture, causing bacterial growth and DNA degradation that renders samples useless for profiling. Allow swabs to air-dry completely before placing in paper envelopes. Label with case number, location on the item, date, time, and collector's name. Log when transferred to the lab or law enforcement."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Cockfighting became a federal felony in the United States in which year?","o":["1976","1994","2008","2014"],"a":2,"e":"C is correct. Cockfighting became a federal felony in 2008 under the Animal Fighting Prohibition Enforcement Act, which was later incorporated into the 2014 Farm Bill. Dogfighting became a federal felony earlier, in 1976. Attending a fight became a federal crime in 2014. These dates are specifically testable on specialty exams."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A shelter receives 45 dogs seized from a dogfighting operation. What is the MOST appropriate approach to determining which dogs can be adopted?","o":["Euthanise all 45 dogs — fighting dogs are irreversibly dog-aggressive and cannot be safely placed","Conduct individualised, validated behavioural assessments on each dog — fighting history does not determine adoptability","Use breed (pit bull type) as the primary determinant — all pit bulls from fighting operations must be euthanised","Release all dogs to rescue organisations immediately to reduce holding costs"],"a":1,"e":"B is correct. The landmark Michael Vick case (2007) established the precedent that dogs from fighting operations require individualised behavioural assessment and should not be blanket euthanised. Many dogs from fighting operations are highly people-oriented. Each dog must receive an individual validated behavioural evaluation. Disposition decisions require court authorisation — releasing animals without court approval is destruction of evidence. Breed alone cannot determine adoptability."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Without treatment targeting the underlying psychological disorder, what is the approximate recidivism rate for animal hoarding?","o":["10–20%","30–50%","50–60%","70–100%"],"a":3,"e":"D is correct. Animal hoarding has a recidivism rate of 70–100% without psychological intervention targeting the underlying disorder (Patronek 1999; Berry et al. 2005). This is one of the highest recidivism rates in any animal cruelty category. Legal intervention alone (fines, prohibition orders, animal surrender) is insufficient — mental health treatment, social services, and active monitoring of prohibition orders are all required to have any impact on reoffending."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"An individual runs a cat rescue organisation, sincerely believes she is saving cats from euthanasia, has 180 cats in her home, cannot provide adequate food or veterinary care, denies any problem, and has supporters who donate and defend her. Which hoarding type does she BEST represent?","o":["Overwhelmed caregiver","Rescue hoarder","Exploiter hoarder","Collector hoarder"],"a":1,"e":"B is correct. This is the rescue hoarder profile: a mission-driven individual who collects animals to \"save\" them, often with organisational structure, genuine belief in her mission, supporter networks, and denial of the problem. The presence of supporters who defend and enable the behaviour is characteristic of rescue hoarding and makes intervention legally and socially complex. The rescue hoarder type has moderate recidivism and requires psychological treatment focused on the mission-based cognition."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which hoarding type has the HIGHEST recidivism rate and is MOST resistant to intervention?","o":["Overwhelmed caregiver","Rescue hoarder","Exploiter hoarder","All types have equivalent recidivism rates"],"a":2,"e":"C is correct. The exploiter hoarder has the highest recidivism rate and the worst prognosis. Key features: lacks empathy for animals and people, charismatic and manipulative, acquires animals for personal benefit (not mission or compassion), refuses all intervention, and is the most likely to immediately reoffend after legal action. This type requires both legal intervention (prohibition orders, active monitoring) and recognition that psychological treatment is typically rejected."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following is a diagnostic criterion for animal hoarding?","o":["Owning more than 15 animals of any species","Failure to provide minimum standards of care combined with denial of the problem and a deteriorating environment for both animals and humans","Refusing veterinary care for one or more animals on religious grounds","Owning multiple species of animals simultaneously"],"a":1,"e":"B is correct. Animal hoarding is defined by four criteria: (1) large number of animals, (2) failure to provide minimum standards of care, (3) denial of the problem, and (4) deteriorating environment for animals and humans. There is NO specific number threshold (not 15, not 50, not any other number). The diagnostic criteria are about failure of care and denial, not a count. Multi-species ownership is common in normal multi-pet households and is not hoarding."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A large hoarding seizure involves 120 cats with high suspected rates of upper respiratory disease. What is the MOST important intake consideration specific to this population?","o":["All cats should be integrated into the main shelter population to reduce stress from isolation","Separate intake triage and isolation protocols to prevent introduction of infectious disease into the general shelter population","Vaccination with modified live vaccines immediately on arrival to provide rapid protection","Euthanise all clinically ill cats immediately to protect the healthy population"],"a":1,"e":"B is correct. Animals from hoarding environments have very high rates of infectious disease. Integrating them with the general shelter population without isolation protocols risks a shelter-wide epidemic. Establish a separate intake area with dedicated equipment and staff. Do not use modified live vaccines in actively ill or stressed animals (immunocompromised state may allow vaccine strain disease). Triage — treat treatable animals, euthanise only those for whom euthanasia is the most humane option after individual assessment."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which agency is MOST essential to engage in a hoarding case to address the underlying cause and reduce recidivism?","o":["The prosecutor's office, to ensure the highest criminal penalty is imposed","The building code enforcement department, to condemn the property","Mental health services, to provide psychological assessment and treatment targeting the hoarding disorder","The media, to publicise the case and deter future offenders"],"a":2,"e":"C is correct. The defining feature of hoarding that distinguishes it from simple neglect is the underlying psychological disorder. Without mental health intervention targeting this disorder, recidivism is 70–100% regardless of criminal penalties, property condemnation, or animal removal. Mental health services are the most essential non-animal-welfare agency in any hoarding response. All other agencies are important but do not address the root cause."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which zoonotic disease is MOST commonly associated with hoarding of cats?","o":["Dermatophytosis (ringworm — Microsporum canis)","Rabies","Brucellosis","Leptospirosis"],"a":0,"e":"A is correct. Dermatophytosis (ringworm, caused primarily by Microsporum canis in cats) is extremely common in cat hoarding environments and readily transmits to humans (and shelter staff handling seized animals). Bartonella (cat scratch disease) is also common. Rabies is a concern for unvaccinated animals but is not the most common zoonosis in hoarding environments. Brucellosis is primarily a dog/ruminant disease. Leptospirosis is more associated with dogs and outdoor environments."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A cost-of-care bond statute is MOST useful in a hoarding case because it:","o":["Immediately transfers legal ownership of seized animals to the shelter","Requires the hoarder to post funds covering daily care costs or forfeit the animals, preventing prolonged evidence holds that financially strain the shelter","Provides the shelter with government reimbursement for all cruelty case care costs","Allows the shelter to euthanise animals without court authorisation after 30 days"],"a":1,"e":"B is correct. Hoarding cases frequently involve very long criminal proceedings (months to years) during which dozens to hundreds of animals are held as evidence at the shelter's expense. Cost-of-care bond statutes require the owner to post periodic bonds covering the daily care cost; failure to post results in forfeiture of the animals, allowing the shelter to proceed with adoption or other disposition. This is a critical legal tool for shelters managing expensive, prolonged hoarding holds."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In DSM-5, hoarding disorder is classified as:","o":["A subtype of obsessive-compulsive disorder (OCD) with the specifier \"with excessive acquisition\"","A standalone diagnosis distinct from OCD, characterised by persistent difficulty discarding possessions and strong perceived need to save, causing significant distress or impairment","A personality disorder variant in Cluster B","A behavioural addiction classified under substance-related and addictive disorders"],"a":1,"e":"B is correct. In DSM-5 (2013), hoarding disorder is a standalone diagnosis — it was removed from the OCD spectrum where it previously existed as a specifier. The core features are: persistent difficulty discarding possessions regardless of value, perceived need to save, and significant distress or functional impairment. Animal hoarding is an expression of hoarding disorder applied to living animals, adding animal welfare, public health, and legal dimensions not present in object hoarding."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"According to the ASPCA 9-step forensic investigation protocol, which step MUST be completed before any animal is physically moved from its location?","o":["Individual veterinary examination and body condition scoring of all animals","Complete photographic and video documentation of the entire scene in its undisturbed state","Collection and labelling of physical evidence including food supplies and veterinary records","Execution of the chain of custody transfer forms with the receiving shelter"],"a":1,"e":"B is correct. Scene documentation (Step 2) must precede any animal movement to preserve the evidentiary record. Photographs and video capture the conditions as found — animal locations, environmental state, degree of ammonia contamination, structural hazards — before any human intervention alters the scene. If an animal requires emergency life-saving treatment before documentation is complete, the pre-treatment condition must be recorded in writing and photographed at the first available opportunity. Failure to document prior to movement can weaken or destroy the prosecution's case."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which psychological feature best explains why removing animals from a hoarder — even with full criminal conviction — consistently fails to prevent reoffending without additional intervention?","o":["Hoarders are motivated solely by financial gain from selling seized animals back","Genuine cognitive distortion: hoarders perceive their animals as well-cared for and experience animal removal as catastrophic personal loss rather than legal consequence — the underlying attachment pathology and hoarding disorder are unchanged by prosecution","Court-ordered prohibition periods are legally unenforceable in most US jurisdictions","Hoarders substitute hoarding objects for animals after animal prohibition orders are imposed"],"a":1,"e":"B is correct. The cognitive distortion at the core of hoarding disorder means the hoarder does not experience prosecution and animal removal as consequences of harmful behaviour — they experience it as persecution of someone who is protecting animals. Without mental health intervention targeting the hoarding disorder, the attachment pathology, and the cognitive denial, the motivation to acquire animals is unchanged. This is why 70–100% of animal hoarders reoffend without psychological treatment, regardless of the severity of criminal penalties imposed."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A dog presented under suspicion of sexual abuse has a normal physical examination with no external injuries. Which statement BEST reflects how to proceed?","o":["The absence of injuries excludes sexual abuse — no further workup is needed","Absence of injury does not exclude sexual abuse — proceed with the full 9-step forensic protocol including ALS examination, DNA swabs, and cavity flush","Proceed with bathing the animal first to allow a cleaner examination","Only proceed with the workup if law enforcement confirms sexual abuse occurred"],"a":1,"e":"B is correct. \"No injuries does NOT exclude\" is the core principle of sexual abuse forensic examination. Many animals show no gross injuries. Microscopic findings (spermatozoa on cytology or UA), DNA evidence on swabs, and ALS-detectable biological fluids may be present even when the physical exam is entirely normal. Always proceed with the full protocol. Do not bathe before forensic evidence collection, and do not wait for confirmation from law enforcement — the examination IS the investigative step."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"During the ASPCA sexual abuse forensic protocol, rectal temperature should be taken at which step?","o":["First, as part of baseline vital sign assessment before any other procedures","After ALS examination but before swab collection","Immediately after the cavity flush","Last — after all rectal swabs, flush samples, and physical examination are complete"],"a":3,"e":"D is correct. Rectal temperature is always taken LAST in the sexual abuse examination protocol. The rectal thermometer inserted before rectal swabs and flush could destroy or contaminate the rectal evidence — displacing semen, breaking spermatozoa, and introducing lubricant contamination. Document in the record that temperature was obtained last in order to preserve rectal evidence integrity."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When collecting DNA swabs from the vaginal orifice of a dog suspected of sexual abuse, the ASPCA protocol specifies:","o":["One swab per area, placed immediately in a sealed plastic tube with transport medium","A minimum of two swabs per area, air-dried, and stored in paper envelopes with chain-of-custody labelling","Three swabs per area, immediately frozen at −20°C in a sealed plastic container","One swab per area, fixed in 10% formalin for histopathology"],"a":1,"e":"B is correct. The ASPCA protocol specifies a minimum of two swabs per area, to allow duplicate analysis (one for immediate testing, one held in reserve). Swabs must be air-dried before packaging — wet swabs in sealed containers degrade DNA rapidly. Store in paper (never plastic). Label with case number, exact anatomical location, date, time, and collector's name. Formalin destroys DNA; frozen plastic containers also degrade samples through condensation."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Samples collected by flushing the vaginal cavity should be stored in which container and at which temperature?","o":["Purple-top EDTA tube, frozen at −20°C","Green-top lithium heparin tube, room temperature","Red-top tube (no additives), refrigerated at 4°C","10% buffered formalin container, room temperature"],"a":2,"e":"C is correct. The cavity flush (vaginal or rectal) is collected in a sterile red-top tube (no additives, no anticoagulant) and stored refrigerated at 4°C — not frozen. Freezing disrupts cellular morphology needed for cytology (sperm identification) and can degrade some DNA. EDTA and heparin anticoagulants can interfere with downstream PCR-based DNA analysis. Formalin destroys both DNA and cellular morphology."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which of the following is a PENETRATION injury finding in a sexual abuse case, as opposed to a restraint injury?","o":["Ligature marks around the muzzle","Bilateral flank bruising from grip marks","Lacerations of the vulvar lips with weak vaginal introitus tone","Abrasions on the dorsal neck from head restraint"],"a":2,"e":"C is correct. Penetration injuries include: bruising and tearing of genital/rectal tissue, vaginal or anal dilation with weak sphincter tone, bleeding, prolapse, perforation, and retained foreign objects. Ligature marks around the muzzle, bilateral flank bruising, and dorsal neck abrasions are all restraint injuries — caused by holding or immobilising the animal during the assault, not by the sexual act itself. Distinguishing these two categories helps reconstruct the event."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Spermatozoa identified on urinalysis sediment examination of a female dog is MOST significant because:","o":["It indicates the dog mated naturally, which is not a cruelty concern","Sperm reaching the bladder via the short female urethra following vaginal assault is a specific forensic finding supporting sexual abuse","Spermatozoa are a normal urinalysis finding in intact female dogs in oestrus","It confirms that the dog was recently used for breeding without owner consent"],"a":1,"e":"B is correct. Spermatozoa in the urine of a female dog is abnormal and forensically significant. The female dog's short, straight urethra allows semen deposited in the vagina to migrate into the bladder. This finding on routine UA sediment is a high-yield exam point — it is specifically mentioned in the ASPCA protocol as a reason to perform urinalysis in all suspected sexual abuse cases. Spermatozoa are not a normal UA finding."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The ASPCA sexual abuse protocol requires a follow-up examination at 24–48 hours primarily because:","o":["DNA evidence degrades after 24 hours and must be recollected","Injuries including bruising and mucosal tears may not be visible at initial presentation and evolve over the following 24–48 hours","A second examiner must verify all findings from the initial examination for legal purposes","The follow-up is required to administer prophylactic antibiotics"],"a":1,"e":"B is correct. Soft tissue injuries — particularly bruising and mucosal tears from penetration — may not be visible at initial examination and become apparent over the following 24–48 hours as haemorrhage and inflammatory changes develop. The follow-up exam is a required component of the ASPCA protocol and should be planned at the initial visit. Document all new or evolving findings with photographs at the follow-up."},{"type":"mcq","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which forensic light source parameter is specified in the ASPCA sexual abuse protocol for surface examination?","o":["Infrared light at 900 nm with a clear filter","415 nm excitation filter (or Wood's lamp UV) combined with orange-tinted goggles to filter background and visualise fluorescent material","Standard white-light examination under a magnifying glass","Polarised light at 550 nm for skin surface examination"],"a":1,"e":"B is correct. The ASPCA protocol specifies a 415 nm excitation filter (forensic light source) with orange goggles, OR a standard Wood's lamp (long-wave UV ~365 nm). The orange goggles are essential — they filter the background blue excitation light and allow biological fluorescence to be visualised. Without the goggles, fluorescent areas are obscured by the excitation light. Areas of fluorescence are documented by photograph before any swabbing."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Which of the following best defines a zoonosis?","o":["A disease caused by a parasite that can survive in both aquatic and terrestrial environments","A disease or infection naturally transmissible between vertebrate animals and humans","Any infectious disease that spreads between domestic animals in a shelter setting","A disease caused by a pathogen that has crossed the species barrier at least once in recorded history"],"a":1,"e":"B is correct. The WHO definition of a zoonosis is a disease or infection naturally transmissible between vertebrate animals and humans under natural conditions. Option D is partly true historically but does not define a zoonosis — a disease must be capable of ongoing natural transmission between species to qualify."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A pregnant shelter employee is concerned about exposure to cats. Which of the following statements about Toxoplasma gondii and pregnancy is most accurate?","o":["Any pregnant woman who owns a cat is at high risk of congenital toxoplasmosis in her fetus","Fetal infection occurs only with primary maternal infection during pregnancy; prior immunity is protective. The greater risk for most Americans is undercooked meat, not cat contact","Cats shed oocysts continuously throughout their lives, making any cat-owning household high-risk","Dogs also shed Toxoplasma oocysts and pose an equal risk to cats for pregnant women"],"a":1,"e":"B is correct. Congenital toxoplasmosis requires primary maternal infection during pregnancy. Women with prior immunity are protected. Cats typically shed oocysts for only 1–3 weeks after primary infection. The oocyst shedding window, sporulation requirement (1–5 days), and the high proportion of human Toxoplasma infections from undercooked meat all reduce the practical risk from indoor cats. Dogs are intermediate hosts and do NOT shed oocysts."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"An asplenic staff member is licked on a small abrasion on their hand by a dog in the shelter. Three days later they present to the ER with high fever, hypotension, and purpuric rash. Which pathogen is most likely responsible?","o":["Bartonella henselae","Pasteurella multocida","Capnocytophaga canimorsus","Leptospira interrogans"],"a":2,"e":"C is correct. Capnocytophaga canimorsus is the classic cause of rapidly progressive fulminant sepsis in asplenic individuals following dog (or cat) contact — including licking on broken skin. The purpuric rash and rapid deterioration are hallmarks. Asplenic persons have dramatically impaired opsonization and are unable to clear this encapsulated gram-negative organism. Mortality approaches 30% in asplenic patients. This scenario is a recurring ABVP exam vignette."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter receives a confiscated collection of reptiles including juvenile turtles. Which zoonosis is most directly associated with handling these animals, and which population is at highest risk?","o":["Leptospirosis; pregnant women","Salmonellosis; children under 5 years, elderly, and immunocompromised individuals","Campylobacteriosis; elderly individuals","Q fever; staff assisting in parturition"],"a":1,"e":"B is correct. Reptiles — including turtles, lizards, and snakes — are high-prevalence carriers of non-typhoidal Salmonella. CDC estimates reptiles account for ~74,000 Salmonella infections annually in the US. Children under 5, the elderly, and immunocompromised individuals are at highest risk of invasive (bacteremic) disease. The FDA banned the sale of small turtles (<4 inches) in 1975 specifically because of this risk."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"The primary mechanism of Bartonella henselae transmission from cats to humans is:","o":["Direct inoculation via cat saliva during a bite","Inoculation of flea feces into a scratch or bite wound","Inhalation of aerosolized cat respiratory secretions","Ingestion of oocysts in cat feces"],"a":1,"e":"B is correct. The cat flea (Ctenocephalides felis) is the vector between cats; flea feces (containing Bartonella) deposited on the cat's skin are inoculated into humans when scratch wounds occur. The cat's saliva is not the direct source — saliva becomes contaminated with flea feces when the cat grooms. An indoor, flea-free cat is low-risk regardless of its Bartonella serostatus. Flea control is therefore the most important preventive measure."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter employee develops fever, severe headache, myalgia, and cough 10 days after assisting a stray queen with a complicated parturition without wearing respiratory PPE. The most likely diagnosis is:","o":["Leptospirosis — acquired from urine contamination","Psittacosis — acquired from aerosol of cat respiratory secretions","Q fever — acquired via inhalation of aerosolized birthing fluids contaminated with Coxiella burnetii","Cat scratch disease — acquired from a scratch during restraint"],"a":2,"e":"C is correct. Coxiella burnetii (Q fever) is transmitted by inhalation of aerosolized birthing fluids, placental material, and fetal membranes from infected animals — including cats. The incubation period is typically 2–3 weeks (range 2–6 weeks). No bite, scratch, or skin break is required; the aerosol route is the primary mode of transmission. N95 respirator, gloves, gown, and eye protection are required for shelter staff assisting parturient animals in areas with Q fever risk."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter dog with a history of outdoor exposure and known rodent activity in the shelter is found to have acute renal failure, icterus, and conjunctival suffusion. Which zoonosis should be considered, and what is the appropriate PPE for staff handling this animal?","o":["Campylobacteriosis; standard gloves and hand washing","Leptospirosis; gloves and eye protection when handling urine or body fluids","Q fever; N95 respirator and gown","Salmonellosis; gloves and enteric precautions only"],"a":1,"e":"B is correct. The clinical picture — renal failure, jaundice, and conjunctival suffusion (bleeding into the conjunctival membranes) — in a dog with rodent exposure is classic for leptospirosis (Weil's disease). Leptospira is shed in urine and enters humans via mucous membranes or skin breaks. Staff handling this dog's urine or body fluids should wear gloves and eye protection (splash risk). Cats are relatively resistant to leptospirosis and are not a significant occupational risk for this pathogen."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter staff member is bitten on the hand by a cat. Within 4 hours the wound is red, warm, and rapidly spreading. The most appropriate first-line antibiotic for empirical treatment is:","o":["Cephalexin (first-generation cephalosporin)","Amoxicillin-clavulanate","Clindamycin","Metronidazole alone"],"a":1,"e":"B is correct. Pasteurella multocida, the predominant pathogen in cat bites, has intrinsic resistance to first-generation cephalosporins (cephalexin, cefazolin). Amoxicillin-clavulanate provides coverage for Pasteurella, anaerobes, and staphylococci — the empirical standard for bite wound infections. Clindamycin and metronidazole also have poor activity against Pasteurella when used alone. This is a classic antibiotic-selection exam trap."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Which of the following is the ONLY definitive host for Toxoplasma gondii?","o":["Humans","Dogs","Cats (and other felids)","Sheep and goats"],"a":2,"e":"C is correct. Cats (domestic and wild felids) are the only definitive hosts for Toxoplasma gondii — they are the only species in which sexual replication of the parasite occurs, leading to oocyst formation and fecal shedding. All other warm-blooded species, including dogs and humans, are intermediate hosts that harbor tissue cysts (bradyzoites) but never shed environmentally resistant oocysts."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A 7-year-old child presents with a unilateral visual disturbance and decreased visual acuity. Ophthalmologic examination reveals a retinal granuloma. Serology shows eosinophilia. No systemic signs are present. The most likely diagnosis is:","o":["Visceral larva migrans due to Toxocara canis","Ocular larva migrans due to Toxocara canis","Ocular toxoplasmosis from primary feline source","Cutaneous larva migrans from Ancylostoma braziliense"],"a":1,"e":"B is correct. Ocular larva migrans (OLM) from Toxocara canis presents in school-age children (typically 5–10 years) as a retinal granuloma with visual impairment, often without the systemic eosinophilia and hepatomegaly seen in visceral larva migrans (VLM). The two forms tend to present in different age groups: VLM in toddlers with pica, OLM in older children. A. braziliense causes cutaneous larva migrans (skin tracking), not ocular disease."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"An immunocompromised cat adopter with HIV/AIDS and CD4 count of 80 cells/µL reports profuse watery diarrhea that has persisted for 3 weeks after adopting two kittens with diarrhea from a shelter. Which pathogen is most likely responsible and what is the key disinfection challenge?","o":["Giardia duodenalis; kills with standard bleach dilutions","Cryptosporidium spp.; oocysts are highly resistant to chlorine at standard concentrations","Salmonella enterica; difficult to culture from the shelter environment","Campylobacter jejuni; requires microaerophilic conditions for environmental survival"],"a":1,"e":"B is correct. Cryptosporidium causes chronic, life-threatening diarrhea in immunocompromised patients (particularly HIV/AIDS with CD4 <100). There is no reliably effective treatment in immunocompromised hosts. The key disinfection challenge is that Cryptosporidium oocysts are highly resistant to chlorine bleach at standard concentrations used in most shelters. Accelerated hydrogen peroxide, steam, and mechanical cleaning are more effective. Hand washing with soap and water is essential; alcohol hand gels are inadequate against oocysts."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A child develops a serpiginous, intensely pruritic, advancing skin track on the sole of the foot after playing on a beach where stray dogs were present. The most likely diagnosis and causative organism are:","o":["Visceral larva migrans due to Toxocara canis","Cutaneous larva migrans due to Ancylostoma braziliense","Ocular larva migrans due to Toxocara cati","Cutaneous toxoplasmosis due to sporulated oocysts in sand"],"a":1,"e":"B is correct. Cutaneous larva migrans (CLM), or \"creeping eruption,\" is caused by the skin penetration of Ancylostoma braziliense (hookworm) larvae from contaminated soil or sand. The larvae migrate through human skin at 1–2 cm/day creating a characteristic serpiginous track but cannot complete their life cycle in humans. Walking barefoot on contaminated sandy beaches is the classic exposure scenario. Treatment: topical or oral ivermectin or albendazole."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A Wood's lamp examination of a kitten with circular areas of alopecia on the face is negative. Which of the following is the most appropriate next step?","o":["Conclude ringworm is ruled out and discharge the kitten from isolation","Perform a fungal culture (DTM) because Wood's lamp detects only approximately 50% of Microsporum canis infections and a negative result does not rule out dermatophytosis","Treat empirically with lime sulfur dip without further diagnostics as Wood's lamp is 95% sensitive","Perform a skin biopsy as histopathology is the gold standard for ringworm"],"a":1,"e":"B is correct. Wood's lamp (UV at 365 nm) produces apple-green fluorescence in M. canis infections, but only approximately 50% of strains fluoresce. A negative Wood's lamp does NOT rule out ringworm. Fungal culture (DTM — dermatophyte test medium, or Sabouraud's) with color change and microscopic confirmation is the diagnostic standard. PCR on hair samples is increasingly available and provides faster results. Histopathology is not routinely used for ringworm diagnosis."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A ringworm outbreak occurs in a shelter's kitten room. Which of the following environmental decontamination approaches is most appropriate for hard, non-porous surfaces?","o":["Quaternary ammonium compound spray with standard 10-minute contact time","Dilute bleach (1:10 sodium hypochlorite) applied with adequate contact time to non-porous surfaces, combined with vacuuming (HEPA) and heat laundering of soft materials","Alcohol-based hand sanitizer applied to all cage surfaces","Accelerated hydrogen peroxide only — bleach is ineffective against dermatophytes"],"a":1,"e":"B is correct. Dilute bleach (1:10 or 1:32 sodium hypochlorite) is effective against dermatophyte spores on non-porous surfaces when properly applied with adequate contact time and after mechanical cleaning. For soft materials (bedding, towels), heat laundering (>60°C) and HEPA vacuum for spore removal are required. Quaternary ammonium compounds have limited sporicidal activity against dermatophytes. Accelerated hydrogen peroxide is also effective on hard surfaces but the claim that bleach is ineffective against dermatophytes is incorrect."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"In an immunocompromised HIV-positive cat adopter, which of the following Bartonella manifestations is most likely to occur if the patient is scratched by a flea-infested cat?","o":["Tinea corporis at the scratch site","Self-limiting regional lymphadenopathy resolving within 4 weeks","Bacillary angiomatosis or bacillary peliosis hepatis — disseminated, potentially life-threatening disease","Ocular larva migrans progressing to retinal granuloma"],"a":2,"e":"C is correct. In immunocompromised individuals — particularly those with HIV/AIDS — Bartonella henselae infection can disseminate rather than remaining localized. Bacillary angiomatosis (vascular proliferative skin and systemic lesions resembling Kaposi sarcoma) and bacillary peliosis hepatis (blood-filled hepatic cysts) are the characteristic severe presentations. Immunocompetent individuals typically develop self-limiting regional lymphadenopathy (cat scratch disease) only. Tinea corporis and OLM are unrelated to Bartonella."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"According to the hierarchy of controls, which of the following is the MOST effective strategy for preventing zoonotic disease in a shelter?","o":["Providing all staff with gloves and gowns (PPE)","Eliminating or substituting high-risk sources (e.g., not accepting raw meat diets, not accepting high-risk species when alternatives exist)","Training staff annually on zoonosis recognition (administrative control)","Installing HEPA filtration in ringworm isolation rooms (engineering control)"],"a":1,"e":"B is correct. The hierarchy of controls ranks elimination and substitution as the most effective strategies because they prevent the hazard from existing. PPE (option A) is the LEAST effective level in the hierarchy, as it relies on correct and consistent use. Engineering controls and administrative controls are intermediate. In practice, shelters use all levels simultaneously, but the question tests the hierarchy concept."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter volunteer discloses that she is 14 weeks pregnant. What is the MOST appropriate action?","o":["Exclude her from all animal contact for the duration of her pregnancy","Provide individualized counseling about specific zoonotic risks (Toxoplasma, Bartonella, Q fever, Listeria from animals), offer role modifications to minimize highest-risk exposures, and ensure she uses appropriate PPE","No special action is needed — zoonotic disease risks in shelters are minimal for pregnant women","Ask her to take unpaid leave until after delivery to protect the shelter from liability"],"a":1,"e":"B is correct. Complete exclusion (option A) is neither evidence-based nor legally appropriate in most contexts. Doing nothing (option C) fails the duty of care. The correct approach is individualized risk counseling, identification of highest-risk tasks (assisting parturient animals, handling litter without gloves, working with diarrheic animals), role modifications where reasonable, and ensuring proper PPE. This reflects both the ASV occupational health framework and OSHA general duty of care principles."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Which single hand hygiene measure is most effective against the broadest range of zoonotic pathogens in a shelter setting, including non-enveloped viruses and protozoan oocysts?","o":["Alcohol-based hand sanitizer (62–70% ethanol)","Thorough hand washing with soap and running water for at least 20 seconds","Chlorhexidine gluconate scrub","Quaternary ammonium hand wipe"],"a":1,"e":"B is correct. Soap and water hand washing is effective against the broadest spectrum including oocysts (Cryptosporidium, Toxoplasma, Toxocara eggs) and non-enveloped viruses (parvovirus, calicivirus) for which alcohol-based sanitizers have limited or no activity. Alcohol-based sanitizers are adequate for enveloped pathogens (Salmonella, most bacteria) but should not be used as a substitute for soap and water when oocyst or non-enveloped pathogen exposure is possible. Chlorhexidine gluconate is effective against bacteria but has limited activity against oocysts and non-enveloped viruses."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Approximately what percentage of known human infectious diseases are zoonotic in origin, according to WHO estimates?","o":["~20%","~40%",">60%","~90%"],"a":2,"e":"C is correct. WHO estimates that over 60% of known human infectious diseases are zoonotic, and approximately 75% of emerging human pathogens have animal origins. This statistic is the core epidemiological justification for the One Health approach — human and animal health cannot be effectively managed in isolation. It is a foundational ABVP exam fact for this domain."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"From a One Health perspective, which of the following shelter activities MOST directly contributes to reducing zoonotic disease risk at the community population level?","o":["Training staff to recognize ringworm lesions on individual cats","Systematic deworming and ectoparasite treatment of all animals at intake, combined with flea prevention counseling at adoption","Providing gloves to all staff who handle diarrheic animals","Posting zoonosis information signs in all animal housing areas"],"a":1,"e":"B is correct. Systematic deworming reduces the burden of Toxocara, hookworm, and other parasites that can be shed into the environment long after adoption. Flea prevention at adoption reduces Bartonella transmission in the community. These interventions have population-level impact beyond the individual animal. Options A, C, and D are important for individual occupational protection but do not have the same community-scale One Health impact. The ABVP exam tests this distinction between individual-animal and population-level thinking."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"A shelter in a state with active HPAI H5N1 dairy cattle activity receives a stray cat found near a dairy farm. The cat presents with rapid-onset blindness, ataxia, and torticollis. What is the most appropriate immediate response?","o":["Diagnose as idiopathic feline vestibular syndrome and manage supportively in the general population","Isolate immediately; use N95 respirator and eye protection for all staff handling this cat; notify the state veterinarian and public health authorities; consider H5N1 as a differential diagnosis","Treat empirically for thiamine deficiency — this is the most common cause of acute neurological signs in cats","Proceed with standard intake vaccination and hold in normal housing for 48 hours before further workup"],"a":1,"e":"B is correct. During active HPAI H5N1 outbreaks, cats from farm or dairy-adjacent environments are at risk for severe H5N1 neurological disease (ataxia, blindness, torticollis, seizures) with high case fatality. This is a reportable event requiring immediate state veterinarian and public health notification. Staff should use N95 respirators and eye protection — the same precautions as for other high-consequence respiratory pathogens. Do not co-house this animal with the general population until H5N1 is ruled out. While thiamine deficiency and vestibular syndrome are common differentials, the geographic and exposure context makes H5N1 a priority differential in an outbreak setting."},{"type":"mcq","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"What was the primary documented route of H5N1 infection in domestic cats during the 2024–2025 US dairy cattle outbreak?","o":["Aerosol transmission from infected wild birds at outdoor feeders","Fomite transmission via contaminated milking equipment","Ingestion of raw milk or colostrum from H5N1-positive dairy cows","Vector-borne transmission via ticks from infected cattle"],"a":2,"e":"C is correct. During the 2024–2025 US HPAI H5N1 dairy cattle outbreak, the primary identified exposure route for infected cats was ingestion of raw (unpasteurised) milk or colostrum from H5N1-positive cows. Affected cats developed severe, often fatal neurological disease. Pasteurisation inactivates H5N1, so the risk is specifically from raw dairy products. This is a direct shelter management implication: raw milk and unpasteurised dairy products must not be fed to shelter animals, particularly in affected geographic regions."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Rabies virus belongs to which family and genus?","o":["Flaviviridae / Flavivirus","Rhabdoviridae / Lyssavirus","Paramyxoviridae / Morbillivirus","Reoviridae / Orbivirus"],"a":1,"e":"B is correct. Rabies virus is the type species of genus Lyssavirus, family Rhabdoviridae. Flaviviridae contains West Nile and dengue; Paramyxoviridae contains distemper and canine parainfluenza; Reoviridae contains bluetongue."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which structural protein of rabies virus is the primary target for virus-neutralizing antibodies and is the antigen used in all licensed vaccines?","o":["Nucleoprotein (N)","Matrix protein (M)","Glycoprotein (G)","Phosphoprotein (P)"],"a":2,"e":"C is correct. The G protein is the surface spike glycoprotein that mediates cell entry via acetylcholine receptor and other receptors, and is the dominant neutralizing antigen. All licensed vaccines stimulate anti-G antibody."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Why is rabies virus more easily inactivated by common disinfectants than canine parvovirus (CPV)?","o":["Rabies virus is enveloped; its lipid envelope is readily disrupted by soap, bleach, and alcohols","Rabies virus is a DNA virus; DNA is less stable than RNA","Rabies virus is smaller than CPV and therefore diffuses out of contaminated surfaces faster","Rabies virus cannot replicate outside a host cell, so it dies within minutes on any surface"],"a":0,"e":"A is correct. The lipid envelope is the key. CPV is non-enveloped and persists in the environment for months; RABV is enveloped and is destroyed rapidly by drying, UV, soap, bleach, and alcohols. This distinction is a classic exam trap."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A dog is bitten on the left hind foot by a raccoon. Which of the following best explains why this dog would be expected to have a longer incubation period than a dog bitten on the face?","o":["The hind limb has fewer blood vessels to carry virus to the CNS","Virus must travel a longer distance via retrograde axoplasmic transport to reach the spinal cord and brain","The hind limb has thicker skin, reducing initial viral inoculation","The hind limb has fewer lymphatics to amplify the initial infection"],"a":1,"e":"B is correct. RABV travels centripetally via retrograde axoplasmic transport at ~50–100 mm/day. A bite on the foot requires transport across the entire hind limb and spinal cord before reaching the brain, whereas a facial bite is centimeters from the brainstem."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"What is the significance of the centrifugal phase of rabies virus spread in the context of ante-mortem diagnosis?","o":["It allows serology to become positive before clinical signs","It means virus can be isolated from blood in the viremic phase","Virus spreads to salivary glands and nuchal skin, enabling ante-mortem detection by RT-PCR on saliva or skin biopsy","It causes the animal to shed virus in feces, enabling environmental surveillance"],"a":2,"e":"C is correct. Once RABV reaches the brain, it spreads centrifugally to peripheral organs including salivary glands and skin hair follicles. This makes ante-mortem RT-PCR on saliva or nuchal skin biopsy possible in humans suspected of having rabies."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which eosinophilic intracytoplasmic inclusion body is pathognomonic for rabies encephalitis, and in which location is it most reliably found?","o":["Cowdry Type A bodies; in hepatocytes","Lewy bodies; in the substantia nigra","Negri bodies; most reliably in hippocampal neurons and cerebellar Purkinje cells","Bollinger bodies; in epithelial cells of the skin"],"a":2,"e":"C is correct. Negri bodies are pathognomonic intracytoplasmic inclusions in infected neurons. They are most reliably found in the hippocampus (Ammon's horn) and cerebellar Purkinje cells. However, they are absent in ~20–30% of confirmed cases, so the DFA test is the gold standard, not histopathology."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A shelter receives a stray dog showing sudden jaw drop, drooling, and an inability to eat or drink. A technician opens the dog's mouth to examine for a foreign body. What is the most important concern?","o":["Aspiration pneumonia from drooling","Tetanus causing masseter spasm","Rabies — pharyngeal paralysis is a sign of the paralytic form; the technician may have had an unprotected exposure","Botulism — treatment with antitoxin should start immediately"],"a":2,"e":"C is correct. Jaw drop with hypersalivation and dysphagia in a stray animal is a classic presentation of the paralytic (\"dumb\") form of rabies. Examining the mouth without PPE constitutes a potential mucous membrane or wound exposure to saliva. Rabies must be considered before any unprotected examination."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A rabies-suspect animal must be euthanized and its brain submitted for DFA testing. Which euthanasia method is CONTRAINDICATED?","o":["IV pentobarbital overdose","IC pentobarbital under deep general anesthesia","Gunshot to the head","Inhalant anesthetic overdose followed by IV pentobarbital"],"a":2,"e":"C is correct. Gunshot to the head destroys the brainstem, cerebellum, and hippocampus — the tissue required for DFA testing. This renders the specimen non-diagnostic. Any method that preserves brain architecture (IV barbiturate overdose, deep anesthesia followed by IC injection) is appropriate."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"The 10-day observation rule applies to which three domestic species after a bite incident?","o":["Dogs, cats, and rabbits","Dogs, cats, and ferrets","Dogs, cats, and guinea pigs","Dogs, ferrets, and horses"],"a":1,"e":"B is correct. Dogs, cats, and ferrets are the only domestic species for which the pre-clinical shedding window is well established and the 10-day observation rule applies. Rabbits, guinea pigs, and horses are not covered by the 10-day rule."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A currently vaccinated dog is bitten by a stray cat that tests positive for rabies. Per NASPHV Compendium recommendations, what is the appropriate management of the dog?","o":["Immediate euthanasia and DFA testing","10-day home observation with no further action","Revaccinate immediately and place under 45-day observation","6-month strict isolation quarantine"],"a":2,"e":"C is correct. A currently vaccinated animal exposed to a confirmed or probable rabid animal should be revaccinated immediately and observed for 45 days. The 6-month isolation quarantine is for unvaccinated animals whose owners choose not to elect euthanasia. The 10-day rule applies to biting incidents involving domestic animals and humans, not to animal-animal exposures."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A bat is found in a room where a child was sleeping alone. The child has no visible bite marks. What is the recommended course of action?","o":["No action needed; bat bites always leave visible marks","Test the bat; PEP is only required if the bat tests positive","Capture the bat for testing and initiate PEP unless the bat tests negative; a sleeping child cannot reliably report a bite","Observe the child for 10 days before deciding on PEP"],"a":2,"e":"C is correct. Bat bites are often imperceptible. A bat in the room with a sleeping person, an unattended child, or an intoxicated person is a PEP indication in most jurisdictions because the person cannot reliably confirm or deny a bite. PEP should be initiated unless the bat can be tested and tests negative."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which of the following contacts with a rabies-suspect animal does NOT constitute a rabies exposure requiring PEP evaluation?","o":["Saliva from the animal contacts an open wound on the handler's hand","The handler is bitten through thin latex gloves","The handler touches the animal's fur with intact skin on both hands","Saliva contacts the handler's conjunctiva while the animal is being restrained"],"a":2,"e":"C is correct. Intact skin contact does not constitute a rabies exposure. Exposures require virus contact with broken skin or mucous membranes. Bites through thin gloves, saliva on open wounds, and saliva on mucous membranes are all exposures requiring evaluation."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"An unvaccinated person is bitten by a bat. What is the correct administration of rabies immune globulin (RIG)?","o":["Entire 20 IU/kg dose given IM in the deltoid on day 0","As much of the 20 IU/kg dose as anatomically feasible infiltrated into and around the wound; remainder given IM at a distant site on day 0","20 IU/kg dose given IV over 30 minutes on day 0","20 IU/kg dose given IM on day 0 and again on day 3"],"a":1,"e":"B is correct. RIG must be infiltrated into and around the wound to neutralize virus at the inoculation site. Any remainder is given IM at a site distant from vaccine administration. It is given only on day 0; giving it after day 7 can blunt the vaccine response. It is not given IV and not repeated."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A shelter veterinarian who completed the 3-dose pre-exposure prophylaxis series 3 years ago and has confirmed adequate antibody titres is bitten by a suspected-rabid raccoon. What is the correct PEP protocol?","o":["Full 4-dose vaccine series plus RIG","2 doses of vaccine on days 0 and 3; no RIG","RIG only; no vaccine needed because of prior vaccination","No PEP needed; pre-exposure vaccination is fully protective"],"a":1,"e":"B is correct. Previously vaccinated individuals (prior complete pre-exposure series or prior PEP with demonstrated antibody response) receive only 2 booster doses of vaccine (days 0 and 3) and no RIG. RIG can actually suppress the anamnestic immune response in pre-vaccinated individuals and is contraindicated."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which of the following is true regarding 1-year vs. 3-year veterinary rabies vaccines?","o":["3-year vaccines contain higher antigen mass and provide superior immunity","Both products are immunologically equivalent; the difference is the USDA-approved label duration","1-year vaccines are modified-live; 3-year vaccines are killed","3-year vaccines must be given with adjuvant; 1-year vaccines may be non-adjuvanted"],"a":1,"e":"B is correct. The duration designation is a regulatory distinction based on challenge studies conducted to obtain the specific label claim. The vaccines are immunologically equivalent; using a 1-year product does not provide inferior protection per dose. However, for legal and public health purposes an animal vaccinated with a 1-year product must be revaccinated annually to remain \"currently vaccinated.\""},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which of the following best describes the reason a recombinant (canarypox-vectored) rabies vaccine is preferred over an adjuvanted killed vaccine in cats?","o":["Recombinant vaccines provide longer duration of immunity (5 years) in cats","Adjuvanted vaccines are not licensed for use in cats in the US","Adjuvanted vaccines have a higher (though still rare) association with feline injection-site sarcoma; recombinant vaccines are non-adjuvanted, reducing this risk","Recombinant vaccines elicit superior cell-mediated immunity in cats compared with killed products"],"a":2,"e":"C is correct. Feline injection-site sarcoma (FISS) is associated with adjuvanted vaccines (and other injected products). Recombinant rabies vaccines (e.g., canarypox-vectored) are non-adjuvanted and are therefore preferred by current AAFP vaccine guidelines to reduce FISS risk. Duration of immunity under the label is 1–3 years depending on product."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"Which domestic animal species is currently the most frequently reported rabid domestic animal in the United States?","o":["Dogs","Cats","Cattle","Horses"],"a":1,"e":"B is correct. Cats surpassed dogs as the most commonly reported rabid domestic animal in the US, largely because vaccination rates in cats (especially free-roaming cats) lag behind those in dogs, and some jurisdictions do not legally mandate cat vaccination. This is a high-frequency exam fact."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"A shelter staff member is bitten by an impounded stray dog of unknown vaccination status. The dog is available for observation. What is the immediate first step?","o":["Euthanize the dog and submit brain for DFA testing","Begin PEP immediately without waiting for public health consultation","Wash the wound thoroughly with soap and water for at least 15 minutes, then report to a supervisor and seek medical evaluation / public health consultation","Place the dog under 10-day observation and take no further action regarding the staff member"],"a":2,"e":"C is correct. Immediate thorough wound washing is the single most important first step — it significantly reduces viral inoculation. Then report and seek medical/public health evaluation. The decision about PEP is made in consultation with the health department. Euthanasia is not required if the animal is available for 10-day observation."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"The NASPHV Compendium of Animal Rabies Prevention and Control is best described as:","o":["A federal regulation that overrides state law in all US jurisdictions","A document published by the CDC that is legally binding for animal control agencies","The authoritative national reference for vaccine schedules, quarantine periods, and exposure management, published by the National Association of State Public Health Veterinarians and updated periodically","An AVMA policy statement that applies only to licensed veterinarians"],"a":2,"e":"C is correct. The NASPHV Compendium is an evidence-based, nationally recognized reference document but is not a federal regulation. States and localities may adopt its recommendations into law or exceed its standards. Veterinarians and shelter staff should follow the Compendium's guidance and local law, whichever is more stringent."},{"type":"mcq","domain":"Community & Public Health","sub":"Rabies","q":"From a One Health perspective, which single intervention has been shown to be most cost-effective for preventing human rabies deaths globally?","o":["Expanding access to human PEP in low-income countries","Achieving and sustaining ≥70% vaccination coverage in the domestic dog population","Oral rabies vaccination of raccoon and skunk populations in North America","Mandatory rabies vaccination of all cats in the United States"],"a":1,"e":"B is correct. Dogs are the reservoir responsible for >99% of human rabies deaths globally. Mathematical modeling and field evidence consistently show that achieving ≥70% vaccination coverage in domestic dogs breaks transmission chains and is more cost-effective than PEP availability alone. This is the foundation of the WHO/FAO/WOAH Zero by 30 strategy."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A shelter veterinarian in Texas identifies a dog with clinical signs highly suspicious for foreign animal disease (FMD). There are no laboratory results yet. What is the correct reporting action?","o":["Wait for laboratory confirmation before reporting; a clinical diagnosis alone is insufficient","Immediately contact the state veterinarian and USDA APHIS Veterinary Services; clinical suspicion alone is sufficient for immediate FAD reporting","Report to the local animal control authority and have the animal quarantined pending lab results","Report to the CDC because FMD is a human health emergency"],"a":1,"e":"B is correct. For foreign animal diseases (FMD, HPAI, Newcastle disease, etc.) and other highly dangerous conditions, clinical suspicion alone is the reporting trigger — you do not wait for laboratory confirmation. USDA APHIS Veterinary Services is the federal contact; the state veterinarian is the state contact. CDC is not the primary agency for animal disease reporting."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which federal agency maintains the National Notifiable Disease Surveillance System (NNDSS) for human diseases in the US?","o":["USDA APHIS","CDC","FDA","WOAH (formerly OIE)"],"a":1,"e":"B is correct. The CDC maintains the NNDSS, which receives reports of nationally notifiable human diseases from state health departments. USDA APHIS manages animal disease reporting (including the NLRAD). WOAH is the international body for animal disease reporting between countries. FDA does not manage disease surveillance."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A disease is reportable in California but not in Colorado. This illustrates which feature of the US disease reporting system?","o":["The CDC can override state reporting decisions for nationally notifiable diseases","Each state maintains its own list of reportable diseases; state lists vary and a disease may be reportable in some states but not others","The NLRAD (National List of Reportable Animal Diseases) is the sole arbiter of which diseases must be reported","Diseases are only reportable if they are WOAH-listed"],"a":1,"e":"B is correct. State law governs reportable disease lists for both human and animal diseases within a state. There is no single federal list that overrides state authority (the NLRAD covers federally reportable conditions but states can add diseases). A disease may therefore be reportable in one state and not another."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which of the following statements about Brucella canis infection in shelter dogs is most accurate?","o":["Prolonged combination antibiotic therapy reliably cures B. canis infection in dogs","B. canis poses no meaningful zoonotic risk to shelter staff","B. canis cannot be reliably eliminated with antibiotics; positive dogs generally cannot be considered cured and pose ongoing public health risk","B. canis infection is detectable only by blood culture; serologic screening is not useful"],"a":2,"e":"C is correct. Unlike some bacterial infections, B. canis infection in dogs cannot be reliably cured with antibiotic therapy — recurrence is common and serology may remain positive. Positive dogs present a public health risk (especially to immunocompromised persons and pregnant women). Blood culture and serology (RSAT with confirmatory TAT or AGID) are both used in diagnosis."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A shelter dog from rural south Texas is presented with fever, cervical lymphadenopathy, and oral ulcers. The dog lives in an area with known plague activity. Which of the following is most important?","o":["Collect a lymph node aspirate without PPE for rapid cytology","Isolate the animal, don full PPE including N95 respirator, and report clinical suspicion to the state veterinarian immediately without waiting for lab results","Treat empirically with amoxicillin-clavulanate and recheck in 48 hours before deciding on reporting","Contact the CDC directly; plague is a human disease that bypasses veterinary reporting channels"],"a":1,"e":"B is correct. Cats with suspected plague are a significant zoonotic risk — they can transmit pneumonic plague via respiratory droplets. Full PPE including N95 is required. Plague is immediately reportable on clinical suspicion to the state veterinarian (not solely CDC). Do not perform unprotected procedures or delay reporting pending lab confirmation."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which disinfectant is required to reliably inactivate Leptospira spp. on contaminated shelter surfaces?","o":["Accelerated hydrogen peroxide (AHP) is the only effective disinfectant","Leptospires are resistant to all common disinfectants; the kennel must be abandoned","Leptospires are susceptible to most common disinfectants (bleach, quaternary ammonium, AHP) and to drying; standard cleaning and disinfection protocols are effective","Only quaternary ammonium compounds are effective; bleach is inactivated by leptospiral outer membrane proteins"],"a":2,"e":"C is correct. Unlike CPV or FPV (which require specifically parvocidal products and prolonged contact times), Leptospira spp. are susceptible to a wide range of common disinfectants and to desiccation. Standard cleaning protocols (organic removal + disinfection) effectively address leptospiral contamination. The main risk is fresh urine on wet surfaces, not prolonged environmental persistence."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Q fever (Coxiella burnetii) poses the greatest zoonotic risk to shelter staff in which situation?","o":["Cleaning kennels occupied by dogs with respiratory disease","Handling a parturient cat or assisting with delivery of a litter without PPE","Processing blood samples from dogs with tick exposure","Administering vaccines to large numbers of cats during a clinic"],"a":1,"e":"B is correct. Coxiella burnetii is shed in extremely high concentrations in birth fluids, placenta, and fetal membranes. Even a single infectious dose can cause Q fever in humans. Parturient animals (particularly cats, cattle, sheep, and goats) are the highest-risk exposure scenario. PPE including gloves and ideally a respirator are essential when assisting with deliveries from animals of unknown Q fever status."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Canine influenza virus (CIV) H3N2 was first detected in the US in 2015. Which statement best describes the epidemiological significance of this event?","o":["CIV H3N2 was a re-emergence of the H3N2 strain that had previously circulated in US dogs in the 1990s","CIV H3N2 is a human-adapted influenza virus that spilled over into dogs","CIV H3N2 was a novel introduction from avian/canine influenza circulating in Asia; the US dog population had no prior immunity, leading to rapid spread through shelters and dog facilities","CIV H3N2 is the same strain as equine H3N2, which adapted from horses to dogs, identical to the CIV H3N8 origin story"],"a":2,"e":"C is correct. CIV H3N2 originated from avian influenza A H3N2 that had adapted to dogs in South Korea and China. It was a completely novel introduction to the US dog population in 2015. Because no prior immunity existed, attack rates in exposed populations were very high. CIV H3N8 — the first identified CIV — originated from equine H3N8; the two strains have different origins."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which of the following best describes SARS-CoV-2 infection in companion animals from a One Health perspective?","o":["SARS-CoV-2 originated in dogs and spilled over to humans — a classic zoonosis","SARS-CoV-2 is a human-origin pathogen that demonstrated reverse zoonosis (spill-back) into domestic cats, dogs, mink, and wildlife species","Cats and dogs are the primary reservoir for SARS-CoV-2 and should be routinely tested in shelters","SARS-CoV-2 cannot infect any companion animal species; all reported companion animal cases were due to contaminated swabs"],"a":1,"e":"B is correct. SARS-CoV-2 is a human-origin virus (likely originating via a zoonotic spillover event from a bat reservoir via potential intermediate hosts, but established in humans) that then demonstrated reverse zoonosis into companion animals (cats, dogs), captive big cats, mink, ferrets, deer, and other species. Cats are more susceptible than dogs. This is a key example of the bidirectional nature of zoonotic transmission in the One Health framework."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which of the following is the primary methicillin-resistant Staphylococcus causing infections in shelter dogs and cats, distinct from MRSA?","o":["Methicillin-resistant Staphylococcus aureus (MRSA)","Methicillin-resistant Staphylococcus epidermidis (MRSE)","Methicillin-resistant Staphylococcus pseudintermedius (MRSP)","Methicillin-resistant Staphylococcus schleiferi (MRSS)"],"a":2,"e":"C is correct. MRSP (Staphylococcus pseudintermedius) is the dominant methicillin-resistant staphylococcus in companion animals. It is primarily a veterinary pathogen, though rare human infections occur. MRSA (S. aureus) in pets is usually acquired from human contacts (reverse zoonosis). Knowing the distinction between MRSP and MRSA is a high-yield exam point."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A shelter in central California receives a cat from an outdoor colony. The cat has fever, marked cervical lymphadenopathy, and septic shock. A staff member was scratched while handling the cat and did not wear gloves. The shelter is in a county with documented ground squirrel die-offs. What is the priority differential and action?","o":["Cat-scratch disease (Bartonella henselae); staff member needs only routine wound care","Tularemia; the staff member should be observed for 10 days before PEP is considered","Plague (Yersinia pestis); immediately isolate the cat with full PPE including N95, notify the state veterinarian, and refer the staff member to occupational health / public health for urgent evaluation","Feline infectious peritonitis; no zoonotic risk to the staff member"],"a":2,"e":"C is correct. Ground squirrel die-offs are a plague epizootic indicator in California. Cats in enzootic plague areas are at high risk; they can develop severe septicemic plague and can transmit pneumonic plague to humans via respiratory route. This is an emergency requiring immediate isolation, full PPE, and urgent reporting. The scratched staff member requires urgent medical evaluation for potential plague exposure — do not observe and wait."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"In an outbreak investigation, what is the purpose of a \"case definition\"?","o":["A legal definition of which animals the shelter is responsible for under its operating agreement","The minimum clinical, epidemiological, and/or laboratory criteria an animal must meet to be counted as a case in the outbreak","A dictionary definition of the disease being investigated, used for staff training","The number of animals required to constitute an \"outbreak\" under state law"],"a":1,"e":"B is correct. A case definition is an epidemiological tool: it specifies the minimum criteria (clinical signs, exposure history, time window, lab confirmation) that an animal must meet to be counted as a case. A well-constructed case definition is sensitive enough not to miss cases but specific enough to exclude unrelated disease, enabling accurate counting and analysis of outbreak scope and pattern."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"An epidemic curve for a shelter CPV outbreak shows a sharp, narrow single peak with all cases occurring within a 2-day window. What type of outbreak does this suggest?","o":["Point source outbreak — all animals were likely exposed to the same source at approximately the same time","Propagated outbreak — cases are spreading from animal to animal over successive generations","Continuous common-source outbreak — an ongoing contamination source is infecting animals over an extended period","Sentinel surveillance event — the curve shape indicates these are unrelated background cases, not an outbreak"],"a":0,"e":"A is correct. A sharp, narrow single peak with cases clustered within one incubation period is the classic signature of a point-source outbreak — all cases were exposed to a common source at approximately the same time (e.g., a contaminated intake area, a batch of contaminated supplies, or a single highly infectious animal that all others were exposed to simultaneously). Propagated outbreaks show successive waves; continuous source outbreaks show a plateau."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"During a shelter respiratory disease outbreak, which of the following flow-management practices is most important to prevent further spread?","o":["Staff should work in the sick wards first, then the healthy population, to get the highest-risk work done early in the shift","Staff should work in the healthy population first, then move to the sick or quarantine population, never reversing this direction during a single shift","Sick and healthy animals should be intermingled to accelerate herd immunity development","Staff flow direction is less important than disinfectant concentration, which should be doubled during outbreaks"],"a":1,"e":"B is correct. Directional flow from clean (healthy) to dirty (sick) is a fundamental infection-control principle in shelter medicine. Staff who work in the sick population and then enter the healthy population carry pathogens on their hands, clothing, and shoes. This principle applies to housing assignment, staff movement, and supply flow. Reversing direction during a shift is one of the most common outbreak amplification errors in shelters."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"During a CPV outbreak, the shelter considers emergency vaccination of uninfected dogs in the population. What is the primary rationale and limitation of this intervention?","o":["Emergency vaccination will immediately protect all vaccinated dogs including those already incubating CPV","Emergency vaccination will reduce spread to susceptible animals not yet exposed but will not protect dogs already incubating infection; the vaccine cannot reverse ongoing infection","Emergency vaccination is contraindicated during an active outbreak because it will spread the virus via modified-live virus vaccine shedding","Emergency vaccination will eliminate the need for isolation and quarantine measures"],"a":1,"e":"B is correct. Emergency vaccination during an outbreak reduces the population of susceptible animals who have not yet been exposed, thereby limiting further spread. However, animals already incubating the pathogen at time of vaccination cannot be \"rescued\" — the vaccine takes 7–14 days to confer immunity. Vaccination does not eliminate the need for isolation and quarantine of sick and exposed animals. MLV vaccines for CPV do not pose a meaningful shedding risk in a shelter setting that would worsen the outbreak."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A state animal health official systematically contacts all shelters in the state weekly during a respiratory disease season to collect case count data. This is an example of which type of surveillance?","o":["Passive surveillance","Active surveillance","Syndromic surveillance","Sentinel surveillance (passive variant)"],"a":1,"e":"B is correct. Active surveillance involves authorities systematically seeking out case data from defined sources — the opposite of passive surveillance in which reporters submit data only when they identify a case on their own initiative. Contacting all shelters on a regular schedule to collect data is a classic active surveillance design. Syndromic surveillance uses near-real-time aggregate data streams (e.g., electronic health records) without requiring individual case identification."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"The \"iceberg phenomenon\" in disease surveillance refers to which concept?","o":["The fact that most disease outbreaks begin in cold climates and spread southward","Passive surveillance captures only the visible tip of disease burden; the majority of cases are subclinical, mild, or undiagnosed and go unreported","Surveillance systems capture only recently emerged diseases, missing the long history of established endemic pathogens","Laboratory confirmation is required before any disease appears in surveillance data, hiding the true burden of clinically diagnosed cases"],"a":1,"e":"B is correct. The iceberg phenomenon illustrates why passive surveillance consistently underestimates disease burden. Like an iceberg, only the most severe, clinically apparent, diagnosed, and reported cases are \"visible above the waterline.\" The much larger number of mild, subclinical, undiagnosed, or unreported cases remain invisible. Active surveillance studies are used to characterize the full iceberg and estimate true incidence."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"Which of the following best describes the concept of \"biobanking\" in the context of shelter disease surveillance?","o":["Maintaining a financial reserve to fund diagnostic testing during outbreaks","Storing licensed vaccines at appropriate temperatures to maintain potency","Preserving diagnostic samples (serum, tissue, fecal material) from unexplained deaths and disease clusters for potential retrospective testing when new pathogens are later identified","Maintaining a database of adoption records linked to veterinary outcome data"],"a":2,"e":"C is correct. Biobanking involves preserving biological samples from disease events so that, if a new pathogen is later identified or a new diagnostic test becomes available, retrospective testing can determine when the pathogen first appeared in the population. This is a powerful surveillance tool — it was used to identify when SARS-CoV-2 first circulated in various populations by testing archived samples predating the outbreak. Shelters can contribute to this by retaining necropsy samples and serum from unexplained disease clusters."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"A shelter participates in a regional collaborative that shares anonymous, de-identified aggregate disease data weekly across 12 shelters in the metro area. What is the primary surveillance benefit of this approach?","o":["It allows the state veterinarian to access individual animal records for auditing purposes","Regional outbreaks that no single shelter would detect alone become detectable when cases are aggregated across multiple facilities","It eliminates the need for passive surveillance reporting to state and federal agencies","It converts passive surveillance into active surveillance by having shelters report to each other"],"a":1,"e":"B is correct. Collaborative data sharing multiplies the epidemiological power of individual shelter data. A disease that produces 2 cases in shelter A and 3 cases in shelter B and 2 in shelter C in the same week might go unnoticed by each shelter individually (each within their normal baseline), but the combined signal of 7 cases in one week across co-located facilities is anomalous and detectable. This is the rationale behind regional surveillance networks."},{"type":"mcq","domain":"Community & Public Health","sub":"Reportable & Emerging","q":"From a One Health perspective, which of the following best describes the role of shelter veterinarians in disease surveillance?","o":["Shelter veterinarians function solely as clinicians; public health surveillance is the responsibility of public health officials, not veterinarians","Shelter veterinarians are only obligated to report zoonotic diseases; animal-only diseases do not require reporting","Shelter veterinarians should report disease events directly to the CDC, bypassing the state veterinarian","Shelter veterinarians function simultaneously as clinicians, infection-control officers, mandatory reporters, and surveillance node operators within the One Health framework — integrating animal health, public health, and community engagement"],"a":3,"e":"D is correct. This is the central synthesis point of this subdomain. The ABVP exam consistently tests the integrated One Health role of the shelter veterinarian — not just clinical knowledge but the understanding that disease recognition, infection control, mandatory reporting, community communication, and data contribution to surveillance systems are all part of the role. A case scenario presenting a disease cluster will reward candidates who address all four dimensions: diagnose and treat; control spread; report to the right authority; document and preserve data."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following best describes the key advance of the Five Domains Model over the original Five Freedoms?","o":["It adds a sixth freedom addressing adequate veterinary staffing","It explicitly includes the animal's mental/affective experience as an outcome domain, allowing positive welfare states — not just freedom from negative ones — to be assessed","It applies only to companion animals in shelter settings, whereas the Five Freedoms apply to farm animals","It replaces subjective welfare assessments with objective physiological measurements only"],"a":1,"e":"B is correct. The Five Domains Model (Mellor) introduced Domain 5 — the animal's mental state — as an integrative outcome emerging from the four physical/functional domains. This allows assessment of positive welfare states (curiosity, play, contentment) not merely the absence of suffering. The Five Freedoms, particularly Freedom 5 (freedom from fear and distress), are reactive and deficit-focused. The Five Domains model is bidirectional: it seeks to maximise positive experiences, not just eliminate negative ones."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter cat lives in a clean, adequately sized cage with food, water, and daily health checks. She does not display any disease signs and meets all Five Freedoms criteria. However, she spends most of the day hiding, rarely explores, and has not played since admission 3 weeks ago. Which assessment framework is MOST useful for identifying this welfare deficit?","o":["Five Freedoms — Freedom 4 (express normal behaviour) identifies the deficit","Five Freedoms — Freedom 5 (from fear and distress) identifies the deficit","Five Domains Model — Domain 5 (mental state) captures the negative affective experience that the Five Freedoms framework, focused on deficit, is less equipped to optimise","Input-based assessment — measuring cage dimensions and diet quantity is sufficient"],"a":2,"e":"C is correct. Although this cat meets the Five Freedoms (no disease, adequate space, food, water, no obvious fear trigger), she is experiencing a significant welfare deficit characterised by persistent negative affective states (hiding, inactivity, loss of play behaviour). The Five Domains Model, particularly Domain 5 (mental state), is specifically designed to capture this kind of subjective experiential welfare deficit and to target it for intervention through enrichment, social housing, or other proactive positive welfare strategies."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following is the BEST example of an outcome-based (rather than input-based) welfare measure?","o":["Number of enrichment items provided per cage per day","Square footage of floor space per dog in the kennel run","Rate of stereotypic pacing behaviour observed during a standardised behavioural observation period","Frequency of veterinary examinations per animal per week"],"a":2,"e":"C is correct. Outcome-based measures assess the animal's actual welfare state — what the animal is experiencing. Stereotypic pacing is a behavioural indicator of negative welfare (frustration, chronic stress, inadequate behavioural opportunity) that reflects the animal's experience regardless of what resources have been provided. Options A, B, and D are all input-based (resource-based) measures: they describe what is provided, not what the animal actually experiences. A shelter can provide enrichment items that the animals never use, or ample space that does not reduce stress."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter has reached capacity. The director proposes stopping all euthanasia and instead placing 3 adult dogs per double-size kennel run (designed for 1–2 dogs) to accommodate the overflow. Which ethical pillar does this proposal most clearly violate?","o":["Pillar 1 — No animal made worse: the decision to stop euthanasia results in housing conditions that are worse for the dogs in care than acceptable standards","Pillar 2 — No life worse than death: the dogs' quality of life is likely to fall below the euthanasia threshold","Pillar 3 — Equitable distribution: some dogs will receive more space than others","This proposal does not violate any ethical pillar, as no euthanasia is being performed"],"a":0,"e":"A is correct. Pillar 1 (\"no animal made worse\") prohibits management decisions that result in a worse welfare outcome for animals in care. Tripling the occupancy of kennels beyond their designed capacity predictably increases disease transmission, social conflict, stress, and injury risk — making the animals' welfare actively worse. The intent to save lives does not ethically justify causing harm to the animals who remain in care. Option D is incorrect: the absence of euthanasia does not make a management decision ethical if it causes ongoing welfare harm."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A healthy, well-socialised feral cat is brought to an open-admission shelter that lacks a TNR programme. The cat is unadoptable as an indoor pet. Under the ethical framework of the three welfare pillars, which of the following best describes the appropriate disposition?","o":["Humane euthanasia is justified because the cat cannot be placed in a home","Humane euthanasia is justified because feral cats reduce native wildlife","Euthanasia is NOT ethically justified under Pillar 2, because the cat has a good prospect of living independently outdoors — its life is not worse than death; return-to-field or TNR referral is the appropriate alternative","The cat should be held indefinitely while the shelter develops a TNR programme"],"a":2,"e":"C is correct. Pillar 2 (\"no life worse than death\") states that euthanasia is justified only when an animal's quality of life falls below an acceptable threshold and cannot be improved. A healthy, well-socialised feral cat with a good chance of surviving independently outdoors does NOT meet this threshold — its life is not worse than death. Euthanising it solely because it cannot be adopted as an indoor pet violates Pillar 2. The ethically appropriate path is return-to-field or referral to a TNR programme. Option D is incorrect because indefinite holding for a feral cat that cannot thrive in a kennel violates Pillar 1."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which statement BEST describes the ethical status of short-term welfare compromises in shelter medicine?","o":["Short-term welfare compromises are never ethically acceptable under any circumstances","Short-term welfare compromises are always acceptable when resource constraints exist","Short-term welfare compromises are acceptable ONLY in temporary holding or rehabilitation contexts with a defined endpoint and a plan to restore acceptable care — they cannot be justified as an ongoing steady state","Short-term welfare compromises are acceptable whenever the intent is to save animal lives rather than end them"],"a":2,"e":"C is correct. The shelter medicine ethical framework permits time-limited welfare compromises (e.g., 48-hour isolation in a small crate during a disease outbreak) only when there is a genuine temporary purpose, an active management plan, and a realistic timeline for restoration of acceptable care. Indefinite suboptimal conditions — regardless of intent — are not ethically justified. Option D is the classic exam trap: good intentions (saving lives) do not ethically justify sustained welfare harm."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following BEST defines moral distress as distinguished from moral uncertainty?","o":["Moral distress occurs when the right course of action is unknown; moral uncertainty occurs when the right course is known but constrained","Moral distress and moral uncertainty are synonyms for compassion fatigue","Moral distress occurs when the ethically correct action is known but the person is constrained from taking it by institutional, resource, or authority barriers; moral uncertainty is not knowing what the right action is","Moral distress is a form of professional burnout caused by excessive caseload volume"],"a":2,"e":"C is correct. Jameton (1984) defined moral distress as the specific experience of knowing the right thing to do but being prevented from doing it by external constraints. This is distinct from moral uncertainty (not knowing what is right) and from burnout (a broader syndrome of exhaustion and disengagement). In shelters, moral distress is commonly triggered by being required to euthanize treatable animals due to space limitations, or witnessing substandard care without authority to change it."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter veterinarian notices that the staff allocates disproportionately high resources to neonatal kittens while adult cats with comparable medical need receive delayed care. Which cognitive bias BEST describes this pattern?","o":["Anchoring bias","Availability heuristic","Affective bias","Confirmation bias"],"a":2,"e":"C is correct. Affective bias (sometimes called the \"affect heuristic\") refers to decisions driven by emotional response to an animal's appearance, age, or species rather than objective welfare assessment. Neonatal kittens are emotionally compelling — small, vulnerable, visually appealing — and frequently attract resource allocation that is disproportionate to clinical need relative to adult cats. Anchoring would describe over-relying on initial information; availability heuristic would describe overestimating risk based on memorable events; confirmation bias would describe selectively interpreting evidence to confirm a prior belief."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A dog is brought to a shelter with an intake note from animal control stating \"aggressive — bit officer.\" All subsequent behavioural assessments by shelter staff find the dog calm and friendly. Staff continue to describe the dog as \"dangerous\" and recommend euthanasia. Which cognitive bias is MOST prominently demonstrated?","o":["Affective bias","Anchoring bias","Status quo bias","Availability heuristic"],"a":1,"e":"B is correct. Anchoring bias is demonstrated when individuals over-rely on the first piece of information encountered — in this case, the intake note labelling the dog \"aggressive.\" Subsequent assessments that disconfirm this label are discounted rather than integrated. A related phenomenon is labelling bias: once a label is applied, it shapes all subsequent perception of the animal. Structured behavioural assessment protocols with documented criteria help counteract anchoring by requiring evidence-based evaluation independent of intake labels."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following BEST describes the shelter veterinarian's role in a shared decision-making model?","o":["The veterinarian remains neutral and presents options without making a recommendation, to preserve the organization's autonomy","The veterinarian makes all significant welfare decisions unilaterally as the medical expert","The veterinarian and relevant stakeholders deliberate together, with the veterinarian providing accurate welfare assessment and a recommendation while integrating organizational values and constraints — the veterinarian retains an ethical obligation to advocate for the animal","The veterinarian defers entirely to the shelter director, as operational decisions are outside the veterinarian's role"],"a":2,"e":"C is correct. Shared decision making integrates clinical expertise with stakeholder values and context, but it does not eliminate the veterinarian's advocacy role. The AVMA and ASV are clear that the veterinarian has an ethical obligation to provide a welfare-based recommendation and to advocate for the animal's interests — neutrality is not ethically appropriate when animal welfare is at stake. Option A (complete neutrality) and option D (full deference) both represent abdications of professional responsibility. Option B (unilateral decisions) fails to account for legitimate organizational constraints and values that appropriately inform management decisions."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following resource allocation decisions is MOST consistent with the three ethical pillars for shelter medicine?","o":["Accepting unlimited intake from animal control regardless of capacity because limiting intake causes animals to be held in unsafe conditions elsewhere","Providing intensive medical care for every animal regardless of prognosis or resource impact on other animals","Establishing written population management criteria that trigger intake diversion, increased transfers, or euthanasia decisions when capacity limits are approached, ensuring all animals in care receive adequate welfare standards","Suspending all enrichment and behavioural care during periods of high census to redirect staff to medical care"],"a":2,"e":"C is correct. The three pillars require: (1) no animal made worse — all animals in care must receive acceptable standards; (2) no life worse than death — euthanasia is ethically justified when welfare cannot be maintained; (3) equitable distribution — resources must be allocated consistently. Establishing written, pre-defined population management criteria that are applied consistently satisfies all three pillars. Option A violates Pillar 1 (unlimited intake beyond capacity makes animals worse). Option B violates Pillar 3 (inequitable distribution favoring one animal at others' expense). Option D violates Pillar 1 (suspending behavioural care causes welfare harm)."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"In the pragmatic shelter decision-making model, which of the following correctly identifies the 6 factors that influence disposition decisions?","o":["Animal welfare, staff preferences, donor expectations, length of stay, species, and age","Breed, age, medical history, behavioural history, owner surrender reason, and length of stay","Animal welfare/QoL, available resources, community context, legal obligations, organizational mission/values, and stakeholder interests","Five Freedoms compliance, Five Domains compliance, ASV guideline compliance, local ordinance, state statute, and federal statute"],"a":2,"e":"C is correct. The pragmatic shelter decision-making framework identifies six factors: (1) animal welfare and quality of life, (2) available resources (budget, space, staff, foster network), (3) community context (adoption demand, rescue capacity, public perception), (4) legal obligations (hold periods, evidence animal rules), (5) organizational mission and values (open/limited admission, no-kill commitment), and (6) stakeholder interests (owner, adopter, rescue partner, staff morale). Options A, B, and D describe real considerations but do not correctly map the six-factor framework as described in shelter medicine literature."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"The Five Freedoms were originally developed by which body, and for which animal population?","o":["The AVMA, for companion animals in veterinary practice","The ASV, for animals housed in shelters","The UK Brambell Committee (1965) / Farm Animal Welfare Council, for farm animals","David Mellor (New Zealand), for zoo and captive wildlife populations"],"a":2,"e":"C is correct. The Five Freedoms originated with the UK Brambell Committee report (1965) and were formalised by the Farm Animal Welfare Council (FAWC) for intensively farmed animals. They were subsequently adopted universally across veterinary medicine, including shelter and companion animal contexts. David Mellor (option D) developed the Five Domains Model — a different, later framework. The AVMA and ASV incorporated these principles but did not originate them."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which Five Freedom maps MOST directly to providing hiding boxes for cats in shelter housing?","o":["Freedom from Hunger and Thirst","Freedom from Pain, Injury or Disease","Freedom to Express Normal Behaviour","Freedom from Fear and Distress"],"a":3,"e":"D is correct. Freedom 5 (Freedom from Fear and Distress) requires conditions and treatment that avoid mental suffering. Providing hiding boxes directly addresses the cat's ability to escape perceived threats and control its exposure to stressors — a core driver of fear and distress in a shelter environment. While hiding could also be linked to Freedom 4 (expressing normal behaviour, since hiding is a normal feline behaviour), the primary welfare rationale for hiding boxes is reduction of fear and distress, making D the best answer. Option B (pain/injury/disease) relates to veterinary care, not environmental provisions for psychological safety."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"The Five Opportunities framework (Yeates 2013) is described as the \"positive counterpart\" to the Five Freedoms. Which pairing CORRECTLY matches a Five Freedom to its corresponding Five Opportunities equivalent?","o":["Freedom from Hunger → Opportunity for routine veterinary examination","Freedom from Discomfort → Opportunity for interest and confidence","Freedom from Fear and Distress → Opportunity for interest and confidence (mental enjoyment)","Freedom to Express Normal Behaviour → Opportunity for pleasure, development and vitality"],"a":2,"e":"C is correct. Each Five Freedom maps to a positive opportunity: Freedom 5 (from fear/distress) → Opportunity for interest and confidence (mental enjoyment). Freedom from Hunger maps to Opportunity for selection of dietary inputs; Freedom from Discomfort maps to Opportunity for control of the environment; Freedom to Express Normal Behaviour maps to Opportunity to express normal behaviour (particularly group housing for social species); and Freedom from Pain/Injury/Disease maps to Opportunity for pleasure, development and vitality. Options B and D have the pairings reversed — a common exam trap."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"When assessing welfare using the Five Domains Model, a shelter auditor evaluates how often an animal experiences a negative affective state, how intense the state is, and how long it persists. These three dimensions belong to which aspect of welfare scoring?","o":["Input-based scoring of Domain 2 (physical environment)","Welfare scoring dimensions: intensity, duration, and frequency/probability","Outcome-based scoring of Domain 3 (health)","The Five Freedoms deficit-scoring system"],"a":1,"e":"B is correct. Welfare scoring under the Five Domains Model uses multiple dimensions to characterize the welfare significance of any affective state: intensity (how severe the experience is for each animal), duration (how long the mental state lasts), frequency or probability (how often it occurs), and scope (how many animals are affected). Together these dimensions allow a nuanced welfare impact assessment — an intense but brief experience (e.g., a 30-second blood draw) may have less welfare impact than a low-intensity but chronic state (e.g., persistent mild social isolation). Options A, C, and D describe different assessment tools or domains but not this specific scoring framework."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter installs exercise wheels for cats and observes a subsequent decrease in repetitive pacing behaviour. In the welfare assessment input-outcome framework, which pairing does this scenario BEST illustrate?","o":["Diet (input) → body condition score (outcome)","Human company (input) → aggression or avoidance of caregivers (outcome)","Toy/exercise enrichment (input) → stereotypic/repetitive behaviours (outcome)","Routine vet care (input) → signs of infectious disease (outcome)"],"a":2,"e":"C is correct. The welfare assessment framework pairs specific inputs with their expected outcome indicators. Toy and exercise enrichment is the relevant input; the target outcome is the presence or absence of stereotypic and repetitive behaviours (e.g., pacing, bar-chewing, over-grooming). A reduction in stereotypies following enrichment provision is a validated positive welfare outcome. Diet → BCS (A) is a separate pairing; human company → caregiver approach/avoidance (B) is another; and routine vet care → infectious disease signs (D) is a third. Understanding these input-outcome pairs is critical for welfare auditing and enrichment programme evaluation."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter implements a new socialisation programme: volunteers spend 20 minutes per day with each cat. Which of the following outcomes would be the MOST valid welfare indicator to track for this input?","o":["Body condition score before and after programme implementation","Upper respiratory infection rate in the cat ward","Voluntary approach behaviour toward caregivers and hiding frequency during standardised observations","Stereotypic pacing rate measured before morning feeding"],"a":2,"e":"C is correct. In the input-outcome welfare assessment framework, human company (the input in this scenario) maps to outcomes reflecting the animal's behavioural response to humans: voluntary approach, avoidance of caregivers, and aggression. Approach toward caregivers and reduced hiding indicate improved human-animal relationship and reduced fear — the expected positive outcome of socialisation. Body condition score (A) reflects dietary adequacy. URI rate (B) tracks biosecurity/veterinary care inputs. Stereotypic pacing (D) is the outcome for exercise/enrichment inputs, not socialisation. Tracking the wrong outcome invalidates the welfare assessment."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter calculates that its mean resources per animal have dropped to $8 per day as intake has increased without a corresponding budget increase. The director argues that spreading resources thin helps the greatest number of animals. Which ethical consideration MOST directly challenges this reasoning?","o":["Pillar 2: animals receiving $8/day are likely experiencing a life worse than death","Pillar 1: if mean resources fall below the threshold needed for minimum acceptable care, all animals are made worse — the \"greatest number\" argument cannot justify ongoing welfare harm","Pillar 3: resources must be distributed unequally, with higher-need animals receiving more","The Five Domains Model: spreading resources limits enrichment opportunities in Domain 4"],"a":1,"e":"B is correct. Pillar 3 does support maximising the number of animals helped, but this principle is bounded by Pillar 1: no animal may be made worse by the charity's work. If spreading resources thinly results in animals receiving below the minimum standard of care, Pillar 1 is violated regardless of how many animals are theoretically \"helped.\" The mean resources formula is useful for identifying when population numbers are becoming unsustainable, but it must be evaluated against minimum care thresholds — not just averaged across the population. Option A misapplies Pillar 2, which concerns quality of life thresholds for euthanasia, not resource per-capita cost."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Pillar 3 of the shelter ethics resource allocation framework states that resources should not \"unreasonably deprive another needy animal.\" Which of the following scenarios BEST represents a violation of Pillar 3?","o":["A shelter spends $4,000 on a life-saving surgery for a dog that is otherwise healthy and highly adoptable","A shelter prioritises medical care for animals near death over those with minor ailments","A shelter spends $12,000 on prolonged intensive care for a single dog with a poor prognosis while 40 other animals in the shelter receive no enrichment, delayed vaccinations, and substandard nutrition due to budget shortfalls","A shelter uses a tiered triage system that directs more resources to animals with greater medical need"],"a":2,"e":"C is correct. Pillar 3 requires that resources be distributed such that no individual animal's disproportionate consumption of resources unreasonably deprives other needy animals of adequate care. Spending $12,000 on one animal with a poor prognosis while 40 others suffer welfare deficits is a textbook Pillar 3 violation. This does not mean expensive care is always wrong — option A (surgery for a highly adoptable dog with a good prognosis) may well represent appropriate resource use. Option D (tiered triage by medical need) actually upholds equitable resource allocation. Option B (prioritising near-death animals) is a clinical triage decision, not inherently unethical."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter's medical team is pressured by management to euthanise a dog whose chronic pain is well-controlled by daily medication, who enjoys interactions with staff, and who has been successfully adopted twice previously but returned due to housing issues. Under Pillar 2, which statement is MOST accurate?","o":["Euthanasia is justified because the dog has been returned twice, indicating low adoptability","Euthanasia is justified because chronic pain, even when managed, constitutes a life worse than death","Euthanasia is NOT ethically justified under Pillar 2: the dog's pain is controlled, it exhibits positive welfare indicators, and its quality of life does not fall below an acceptable threshold","Euthanasia is justified under Pillar 3 because the resources used for this dog could benefit many others"],"a":2,"e":"C is correct. Pillar 2 (\"no life worse than death\") authorises euthanasia only when an animal's quality of life falls below an acceptable threshold and cannot be improved. A dog whose pain is well-controlled by medication and who actively engages positively with staff does NOT meet this criterion — its current life is not worse than death. Option A incorrectly conflates adoptability with quality of life. Option B incorrectly assumes managed chronic pain equals a life worse than death. Option D improperly invokes Pillar 3 as an independent justification for euthanasia — Pillar 3 informs resource triage, but euthanasia decisions must be grounded in welfare assessment, not solely in resource calculations."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"In practice, a shelter's mean resources per animal are rarely distributed equally. Which factor MOST commonly creates inequitable resource distribution within shelters, according to shelter medicine literature?","o":["Veterinary licensing requirements that mandate different levels of care by species","Perceived value differences based on species, breed, and age — leading to higher resource allocation for \"desirable\" animals independent of welfare need","Legal hold requirements that mandate more resources for stray animals than owner-surrendered animals","Randomly distributed staffing patterns that create unintentional resource disparities"],"a":1,"e":"B is correct. Shelter medicine literature consistently identifies perceived value — shaped by species (dogs vs. cats vs. rabbits), breed (purebred vs. mixed breed), and age (puppies and kittens vs. senior animals) — as the most significant driver of inequitable resource distribution within shelters. This is closely related to affective bias: animals that are perceived as more desirable, valuable, or emotionally compelling receive disproportionate resources regardless of their comparative welfare need. Legal hold requirements (C) do affect resource allocation but are driven by legal obligation, not perceived value. Options A and D are not recognised as primary drivers of inequity in the literature."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"To promote ethical consistency in resource allocation, shelter medicine guidelines recommend that organisations take which of the following structural actions?","o":["Allow individual veterinarians to develop their own resource criteria for each animal encountered","Limit resource allocation decisions to shelter directors only, excluding veterinary staff","Develop and publish written organisational statements outlining the principles used in resource allocation and ethical decision-making","Apply universal per-species cost caps so that no single animal ever receives more than the mean resources per animal"],"a":2,"e":"C is correct. Shelter medicine guidelines emphasise that transparent, written organisational statements outlining decision-making principles are a key structural strategy for ethical consistency. Published criteria allow staff to understand how decisions are made, reduce arbitrary or affect-driven variation, and provide accountability to the community and donors. Option A (individual criteria per clinician) maximises inconsistency and cognitive bias. Option B (excluding veterinary staff) removes the essential welfare expertise from decision-making. Option D (strict per-capita cost caps) is overly rigid and would prevent appropriate resource concentration for high-need animals — which Pillar 3 allows when justified."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter director argues: \"We cannot harm one animal in order to benefit another.\" This statement reflects which ethical pillar?","o":["Pillar 1: no animal should be made worse by the charity's work — including being harmed to provide benefit to another animal","Pillar 2: no animal should have a life worse than death","Pillar 3: resources should not unreasonably deprive another needy animal","This statement reflects Pillar 2 and Pillar 3 combined, not a single pillar"],"a":0,"e":"A is correct. Pillar 1 contains an important sub-principle: the prohibition extends not only to animals being made worse by the charity's management, but also to harming one animal in order to benefit another. For example, denying an animal pain medication so that those resources can be redirected to a \"more adoptable\" animal violates Pillar 1. This is a subtle but high-yield distinction — Pillar 1 is not merely about overcrowding or neglect, but about any management decision that actively worsens an individual animal's welfare, including cross-animal resource substitution that causes harm."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Which of the following BEST distinguishes shared decision making from informed decision making in a veterinary shelter context?","o":["In shared decision making, the veterinarian provides information and the client decides alone; in informed decision making, both parties deliberate together","In informed decision making, the veterinarian provides complete information and the client/organisation decides autonomously; in shared decision making, both parties share information and deliberate jointly to reach a mutually agreed decision","Shared decision making applies only to euthanasia decisions; informed decision making applies to all other clinical choices","The two models are identical — both require the veterinarian and client to jointly agree on a final disposition"],"a":1,"e":"B is correct. These are distinct models: informed decision making (sometimes called the \"informed consent model\") places the decision-making authority with the client or organisation — the veterinarian's role is to provide complete, accurate information, after which the decision-maker acts autonomously. Shared decision making involves both parties actively deliberating, exchanging information, and reaching a mutually agreed outcome. In practice, shelter medicine increasingly favours shared decision making for complex, value-laden decisions (euthanasia, population management) while informed decision making is appropriate for lower-stakes clinical choices. Option A has the definitions reversed — a common exam error."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Unlike human medical ethics, veterinary ethical decisions are characterised by the absence of a solid conceptual consensus. Which of the following strategies is MOST directly recommended to address this challenge in shelter organisations?","o":["Adopt a single ethical theory (e.g., utilitarianism) as the organisation's official framework and apply it consistently to all decisions","Defer all ethical questions to the supervising veterinarian to avoid organisational conflict","Foster a culture of respect for different ethical positions, schedule specific time for ethical discussion, and make organisational decision-making principles publicly available","Limit ethical discussions to annual staff retreats to avoid disrupting daily operations"],"a":2,"e":"C is correct. Because veterinary ethics lacks the conceptual consensus that grounds much of human medical ethics, the recommended approach is structural and cultural rather than doctrinal: (1) cultivate a culture of respect for diverse ethical positions, (2) create dedicated time for ethical discussion (not just ad hoc), and (3) publish transparent organisational statements outlining the principles used in decision-making. Option A (enforcing a single ethical theory) creates rigidity and suppresses legitimate dissent. Option B (deferring to one person) removes the deliberative process that improves decision quality. Option D (annual retreats only) is insufficiently frequent for the ethical complexity of daily shelter work."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"After a highly publicised bite incident involving a pit bull–type dog at a neighbouring shelter, a shelter veterinarian begins recommending euthanasia for all pit bull–type dogs with any bite history, even when behavioural assessments indicate low risk. Which cognitive bias is MOST likely driving this change?","o":["Anchoring bias","Affective bias","Confirmation bias","Availability heuristic"],"a":3,"e":"D is correct. The availability heuristic causes people to overestimate the probability of events that are cognitively salient — typically because they are recent, dramatic, or emotionally charged. A high-profile bite incident at a nearby facility makes the risk of aggression highly available in memory, leading the veterinarian to overweight this risk when evaluating subsequent dogs. This is distinct from anchoring (over-relying on first information about a specific dog), affective bias (emotional response to appearance), and confirmation bias (selectively interpreting evidence). Structured, validated behavioural assessment tools applied consistently are the recommended countermeasure against availability-driven decisions."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter has used the same intake behavioural assessment tool for 12 years. Literature now shows the tool over-predicts aggression in fearful dogs, leading to unnecessary euthanasia. Staff resist switching to a validated alternative, citing familiarity and past success. Which cognitive bias MOST characterises this resistance?","o":["Availability heuristic","Affective bias","Status quo bias","Anchoring bias"],"a":2,"e":"C is correct. Status quo bias is the preference for the existing state of affairs, where change is perceived as a loss even when evidence supports it. In this scenario, staff prefer a familiar tool despite evidence of harm (over-prediction of aggression → unnecessary euthanasia) because switching requires effort, creates uncertainty, and disrupts established workflows. Status quo bias is particularly relevant in organisations where current practices have historical momentum. Availability heuristic (A) would involve overestimating risk from memorable events. Affective bias (B) involves emotional responses to animal appearance. Anchoring (D) involves over-relying on initial information about a specific animal, not resistance to process change."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"Moral distress (Jameton 1984) is characterised by repeated exposure to situations where a clinician knows the right action but is prevented from acting. Which of the following describes the MOST likely organisational consequence of chronic, unaddressed moral distress among shelter staff?","o":["Improved ethical deliberation, as staff become more accustomed to navigating complex decisions","Decreased rates of euthanasia, as distressed staff avoid difficult disposition decisions","Erosion of emotional well-being, leading to compassion fatigue, burnout, and high staff turnover — which ultimately compromises animal care","Increased moral clarity over time, as staff develop coping mechanisms that reduce the knowledge-action gap"],"a":2,"e":"C is correct. Repeated, unaddressed moral distress does not produce adaptation or resilience — it produces erosion of emotional well-being. This leads sequentially to compassion fatigue (the cost of sustained empathic engagement), burnout (exhaustion and disengagement), and staff turnover. High turnover in shelter medicine is well-documented and is substantially driven by moral distress. The downstream consequence is compromised animal care: experienced staff leave, institutional knowledge is lost, and the animals lose consistent, skilled caregivers. Option A and D incorrectly imply that exposure to distress is beneficial. Option B is not supported — moral distress does not systematically reduce euthanasia rates."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Ethics","q":"A shelter veterinarian believes a particular cat is feral based on the intake note, and interprets all of the cat's behaviours during assessment — freezing, dilated pupils, rapid breathing — as confirming this. The cat actually responds warmly to slow, quiet approach but this is not tested because the veterinarian assumes the result. Which bias is MOST prominent?","o":["Status quo bias","Availability heuristic","Affective bias","Confirmation bias"],"a":3,"e":"D is correct. Confirmation bias involves seeking or interpreting evidence in a way that confirms a pre-existing belief, while discounting or failing to seek disconfirming evidence. In this scenario, the veterinarian interprets stress responses (freezing, dilated pupils, rapid breathing — all of which can be caused by fear in a socialised cat, not only in a feral one) as confirming ferality, and does not test the alternative hypothesis (slow, quiet approach). This is distinct from anchoring bias, which would be over-relying on the initial \"feral\" label but still remaining open to updating — confirmation bias goes further by actively shaping information-gathering to avoid disconfirmation. Standardised behavioural assessment protocols that require testing specific hypotheses are the recommended structural countermeasure."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Which of the following BEST describes the appropriate role of a 501(c)(3) animal shelter's Board of Directors?","o":["Making daily animal care and euthanasia decisions to ensure consistent welfare standards","Supervising individual staff members and approving all veterinary treatment plans","Strategic oversight — setting mission, approving major policies, ensuring financial health, and hiring and evaluating the executive director — without involvement in day-to-day operations","Managing shelter operations directly during periods when the executive director is absent"],"a":2,"e":"C is correct. The board of directors of a non-profit organisation is responsible for strategic oversight: setting the mission and long-term direction, approving major policies and budgets, ensuring legal and financial compliance, and hiring/evaluating the executive director. Day-to-day operations — including individual animal care decisions, staff supervision, and treatment authorizations — are delegated to the executive director. Board members who attempt to manage daily operations undermine the executive director's authority and violate governance best practice."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A neighbour suspects that a local animal shelter is misusing donations. Which document, available to any member of the public by law, would provide the most direct financial transparency information about the shelter?","o":["The shelter's state agriculture department licence","The shelter's IRS Form 990, which is a public document disclosing revenue, expenses, executive compensation, and programme activities","The shelter's veterinary practice permits","The shelter's articles of incorporation filed with the state secretary of state"],"a":1,"e":"B is correct. The IRS Form 990 is a public document. Any 501(c)(3) organisation is required by law to make its three most recent Form 990s available to any member of the public who requests them. The 990 reports total revenue and expenses, executive compensation, programme descriptions, and key governance information — making it the primary tool for public accountability of non-profits. Databases like Candid/GuideStar make 990s searchable online without a formal request."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A dog is impounded by animal control with a collar bearing a rabies tag and a phone number. Under the Illinois Animal Control Act (a model statute), what is the minimum statutory hold period?","o":["3 days","5 days","7 days","14 days"],"a":2,"e":"C is correct. The Illinois Animal Control Act — frequently cited as a model statute in shelter medicine education — requires a minimum 7-day hold for animals bearing owner identification (collar, tag, microchip, or rabies tag). Animals without identification may have a shorter minimum hold period (typically 3–5 days), but the presence of identification indicating owner contact information triggers the longer hold to maximize the opportunity for reunification. Always check the applicable state statute for jurisdiction-specific hold periods."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A stray dog is admitted to a municipal shelter on Day 1. The shelter has a high-volume spay/neuter programme. On Day 3, a staff member schedules the dog for routine spay surgery to reduce backlog. The statutory hold period has not expired. This action is BEST described as:","o":["Legally permissible because spay surgery improves animal welfare","Legally permissible if the dog is healthy and the surgery is elective rather than emergency","A potential legal violation: performing elective surgery on a stray animal before the hold expires constitutes an unauthorised alteration of another person's property","Legally permissible if the shelter has a written spay/neuter policy"],"a":2,"e":"C is correct. During the statutory hold period, a stray animal remains the legal property of its owner. Performing elective surgery — including routine spay/neuter — before the hold expires constitutes an unauthorised alteration of another person's property, which is legally actionable as property damage or conversion. The shelter's spay/neuter policy or the animal's health status does not override the owner's property rights during the hold. Elective surgery must wait until the hold period has expired and legal ownership has transferred to the shelter."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter veterinarian is away from the facility at a conference. A technician calls to report a dog showing sudden-onset vomiting and lethargy. The veterinarian says over the phone: \"Sounds like gastroenteritis; give him metronidazole and fluids.\" This scenario MOST likely violates:","o":["The indirect supervision requirement — the vet should have been reachable within 30 minutes","The direct supervision requirement — diagnosis of a new clinical condition and prescribing for it require the veterinarian to physically examine the animal in most jurisdictions","DEA regulations — metronidazole is a Schedule II controlled substance","Nothing is violated — indirect supervision permits all actions as long as the vet is reachable by phone"],"a":1,"e":"B is correct. Diagnosing a new clinical condition and prescribing a specific treatment for it require direct veterinary supervision (i.e., the veterinarian must physically examine the animal) in most state veterinary practice acts. A technician's verbal description of clinical signs over the phone is not an adequate substitute for physical examination. The vet must come to the shelter, have the animal transported for examination, or another licensed veterinarian must see the animal. Note: metronidazole is not a DEA-controlled substance (option C is incorrect); it is a prescription antibiotic/antiprotozoal."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Which of the following procedures requires direct veterinary supervision (veterinarian physically present) in MOST state veterinary practice acts?","o":["Administration of core vaccines (distemper, parvovirus) by a licensed veterinary technician at intake","Application of a monthly topical flea preventive under a standing protocol","Administration of rabies vaccine","Measurement of body condition score and body weight by a shelter technician"],"a":2,"e":"C is correct. Rabies vaccination requires direct veterinary supervision (veterinarian physically present) in most jurisdictions. This is because a rabies vaccination certificate has legal consequences — it establishes the animal's protected status and exempts it from certain quarantine requirements under state and local law. Allowing technicians to administer rabies vaccines without a vet on-site could result in legally invalid certificates and practice act violations. Core non-rabies vaccines (options A), topical preventives under standing protocols (B), and BCS measurement (D) are generally permitted under indirect supervision or as technician tasks."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter's relief veterinarian has a DEA registration listing her home clinic address. She purchases pentobarbital for euthanasia and asks the distributor to ship it directly to the shelter (a different address). This is:","o":["Permissible because the veterinarian is licensed and registered with the DEA","Permissible if the shelter director co-signs the order","A DEA violation: controlled substances must be ordered and received at the exact address listed on the DEA registration certificate; the vet cannot receive Schedule II drugs at a different address","Permissible if the shelter has a separate storage licence from the state pharmacy board"],"a":2,"e":"C is correct. DEA regulations require that Schedule II controlled substances (including pentobarbital, a Schedule II drug used for euthanasia) be ordered and delivered only to the DEA-registered address. The veterinarian's registration lists her home clinic — therefore, pentobarbital can only be ordered and received there. To legally order controlled substances for use at the shelter, the shelter must have its own DEA registration, or the relief veterinarian must add the shelter as an additional location on her DEA registration. This is one of the most commonly tested regulatory traps in shelter medicine."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Under the traditional common law \"one bite rule,\" a dog owner is:","o":["Always strictly liable for any injury caused by their dog","Not liable for the first bite if they had no prior knowledge of the dog's dangerous propensity; liable for subsequent injuries once dangerousness is established","Not liable for dog bites under any circumstances if the dog was on the owner's property","Liable only if the bite caused serious injury requiring medical treatment"],"a":1,"e":"B is correct. The traditional \"one bite rule\" holds that an owner is not liable for the first bite if they had no prior knowledge that the dog was dangerous — the first bite effectively puts them \"on notice.\" After that knowledge is established, they are liable for subsequent injuries. Most states have now replaced or modified the one-bite rule with strict liability dog bite statutes, under which the owner is liable regardless of prior knowledge as long as the victim was lawfully present. Shelters should be aware that adopting out a dog with known bite history creates liability under both frameworks."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter places a cat with a history of one minor bite into a trial adoption with a signed agreement. Three key provisions that should be in this agreement include:","o":["Spay/neuter agreement, microchip registration, and adoption fee schedule","An indemnification clause, a homeowner's/renter's insurance requirement, and an immediate return clause","A veterinary reference letter, a home visit assessment, and a non-compete clause","A photo release, a social media disclosure, and a neutering deadline"],"a":1,"e":"B is correct. A well-drafted trial adoption agreement should include: (1) an indemnification clause in which the trial adopter holds the shelter harmless for injuries that occur during the trial, provided full risk disclosure was made; (2) a homeowner's or renter's insurance requirement to ensure third-party injury coverage exists; and (3) an immediate return clause allowing the shelter to reclaim the animal at any time — particularly important if new behavioural incidents occur during the trial period. Options A, C, and D describe real shelter practices but are not the three key liability-management provisions of a trial adoption agreement."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A foster dog bites a child visiting the foster home. Regarding liability, which of the following is MOST accurate?","o":["The foster parent is solely liable because the bite occurred in their home","The shelter is not liable because the animal was in the foster home, not at the shelter","The shelter, as legal owner of the animal during foster placement, may retain primary liability; the foster agreement's indemnification and insurance provisions determine the allocation of risk between shelter and foster parent","Neither party is liable if the child provoked the dog"],"a":2,"e":"C is correct. During a foster placement, the shelter typically retains legal ownership of the animal. Under strict liability dog bite statutes, the legal owner bears primary liability for injuries caused by the animal. The foster agreement's indemnification and insurance provisions determine how that liability is allocated between the shelter and the foster parent. This is why written foster agreements with liability provisions are legally essential, not optional. Option D is partially true in some jurisdictions (provocation may be a defence), but the question asks about the general liability framework."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter technician working the overnight shift notes that an animal is in respiratory distress. The on-call veterinarian cannot come in immediately and is 40 minutes away. Which of the following actions is MOST appropriate under the veterinary practice act?","o":["Wait until the vet arrives before taking any action, as all treatments require direct supervision","The technician may diagnose the condition and prescribe emergency treatment because this is a life-threatening emergency","The technician may initiate basic supportive care under existing standing emergency protocols (e.g., supplemental oxygen) while the vet is en route; diagnosis and prescribing of specific medications await veterinary examination","The technician may administer any medication in the shelter's emergency kit without restriction in a life-threatening situation"],"a":2,"e":"C is correct. Veterinary practice acts permit technicians to provide basic supportive care (oxygen, fluid support initiation under prior standing protocol) in emergencies while the veterinarian is en route. However, diagnosing a specific cause of respiratory distress and prescribing targeted medications require the veterinarian to physically examine the patient. A well-designed shelter should have standing emergency protocols for common presentations (dyspnoea, seizures, collapse) that authorize specific technician actions until the veterinarian arrives — this is how the practice act framework is operationally compatible with emergency overnight coverage."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A privately owned non-profit shelter has a contract with the county to accept stray animals from animal control. A stray cat is brought in. During the statutory hold period, the cat develops a severe upper respiratory infection. Which of the following is the MOST appropriate action?","o":["Withhold all treatment until the hold expires and ownership transfers to the shelter","Perform elective spay surgery to sterilize the cat before the hold expires to reduce the workload after hold expiry","Provide medically necessary treatment (antibiotics, supportive care) for the URI immediately — emergency and necessary care are permitted during the hold; elective procedures must wait until the hold expires","Euthanize the cat immediately because treatment costs during a stray hold are the shelter's liability"],"a":2,"e":"C is correct. Shelters have both an ethical and legal obligation to provide medically necessary care to animals in their custody, including during a stray hold. Withholding treatment for a treatable illness violates the shelter's duty of care (option A). Elective procedures (spay) remain prohibited during the hold period (option B). Euthanising a treatable animal solely to avoid treatment costs during a hold is ethically and legally problematic (option D) — it may expose the shelter to charges of animal cruelty and certainly violates welfare standards. Many states allow shelters to recover the cost of medically necessary care from the owner upon reclaim."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter's Form 990 reveals that the executive director received a salary of $380,000 — well above the regional median for comparable organisations. A board member argues this was approved at a board meeting and is therefore acceptable. Under IRS rules governing 501(c)(3) organisations, this compensation MOST raises concerns about:","o":["Political campaign prohibition, because the executive director may have used shelter resources to campaign","The private inurement prohibition, which bars any part of a non-profit's net earnings from improperly benefiting a private individual","The public disclosure requirement, because the Form 990 should not have included salary information","State agriculture department licensing standards, which cap executive salaries at shelters receiving public funds"],"a":1,"e":"B is correct. The private inurement prohibition under IRC §501(c)(3) forbids a non-profit from allowing its net earnings to inure (flow as profit) to the benefit of any private individual. Excessive executive compensation — even if board-approved — can constitute inurement if the amount is not \"reasonable\" compared to services rendered and market rates. The IRS may impose excise taxes on both the recipient and the approving board members (intermediate sanctions under IRC §4958). Board approval alone does not insulate the organisation; the compensation must be objectively reasonable. Options A, C, and D describe real rules but do not apply to this scenario."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"An animal shelter's executive director posts a video on the official shelter social media account urging followers to vote against a city council candidate who opposes animal welfare ordinances. Regarding this action, which of the following is MOST accurate?","o":["This is permissible because animal welfare is a charitable cause, not a partisan political position","This is permissible if the shelter does not explicitly endorse a competing candidate","This violates the absolute prohibition on political campaign participation for 501(c)(3) organisations; even opposing a candidate is a campaign intervention that jeopardises tax-exempt status","This is a minor infraction that can be corrected by removing the post within 30 days without IRS consequence"],"a":2,"e":"C is correct. Under IRC §501(c)(3), non-profit organisations are absolutely prohibited from participating or intervening in any political campaign on behalf of — or in opposition to — any candidate for public office. This includes publishing statements opposing a candidate, regardless of whether the opposition is framed as an animal welfare issue. The prohibition is absolute (unlike lobbying, which is merely limited). Violating the political campaign prohibition can result in loss of 501(c)(3) status and imposition of excise taxes. Removing the post (option D) may mitigate but does not eliminate the violation. Shelters may educate the public on policy issues, but may not support or oppose candidates."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A board member of a non-profit shelter is also a licensed attorney. She proposes that the shelter hire her law firm to handle all animal seizure litigation for an annual retainer of $60,000. Which governance principle is MOST directly implicated?","o":["The inurement prohibition — legal fees paid to a board member are always prohibited under IRS rules","The duty of loyalty and conflict of interest policy — the board member has a personal financial interest in the decision and must disclose it and recuse herself from the vote","The Form 990 disclosure requirement — this fee arrangement does not need to be disclosed on the Form 990","The state agriculture department licensing rules — law firms cannot provide services to licensed shelters"],"a":1,"e":"B is correct. Board members owe a fiduciary duty of loyalty to the organisation, which requires them to place the shelter's interests above their own. When a board member has a personal financial interest in a matter before the board (here, her firm would earn $60,000), she must: (1) fully disclose the conflict, (2) recuse herself from deliberation and voting on the matter, and (3) allow only disinterested board members to approve the transaction. The arrangement is not automatically prohibited — if the fee is reasonable and the process is fair (arms-length), the shelter may hire her firm — but proper conflict-of-interest procedures must be followed and documented. This type of transaction, if approved, must typically be disclosed on Form 990 as a related-party transaction (making option C incorrect)."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Which government agency is typically responsible for licensing and inspecting animal shelters at the facility level — as distinct from licensing individual veterinarians?","o":["The state veterinary medical board","The state department of health","The state department of agriculture (or equivalent agency)","The IRS Office of Exempt Organisations"],"a":2,"e":"C is correct. In most states, animal shelters are licensed and inspected as facilities by the state department of agriculture (or equivalent, such as the Department of Natural Resources or Animal Industry Board). This is a distinct regulatory layer from individual veterinary licensure, which is overseen by the state veterinary medical board. The agriculture department focuses on shelter facility standards — physical environment, record-keeping, holding periods, and minimum care requirements. A shelter may be in full compliance with state facility licensing while a veterinarian working there separately maintains (or violates) their individual practice act obligations. The IRS (option D) grants and oversees tax-exempt status but does not inspect or license shelter facilities."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A non-profit shelter fails to file its IRS Form 990 for three consecutive years. The MOST significant legal consequence is:","o":["A fine of $500 per day until the returns are filed","Criminal prosecution of the executive director for tax fraud","Automatic revocation of the organisation's 501(c)(3) tax-exempt status by the IRS","Suspension of the shelter's state agriculture department licence pending IRS clearance"],"a":2,"e":"C is correct. Under the Pension Protection Act of 2006, a 501(c)(3) organisation that fails to file a Form 990 (or the smaller Form 990-N for very small organisations) for three consecutive years loses its federal tax-exempt status automatically — without further IRS action. The organisation is then subject to federal income tax and donors can no longer take charitable deductions for contributions. Reinstatement requires a new application and, for some organisations, back taxes may be owed. This rule is specifically designed to remove inactive or non-compliant organisations from tax-exempt status. The other options describe consequences that are not directly triggered by 990 non-filing; the state agriculture department licence (option D) is a separate regulatory track."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A dog seized during a cruelty investigation is housed at the municipal shelter. The owner has been charged with felony animal cruelty. The statutory hold period has expired. A staff member asks whether the dog can now be adopted out. Which of the following BEST describes the legal situation?","o":["The dog may be adopted immediately because the statutory hold period has expired and the shelter now has legal custody","The dog may be adopted if the owner verbally consents during the court process","The dog is an evidence animal held under a court order; it cannot be adopted until the criminal case resolves and the court releases the animal; specific legal restrictions apply throughout the case","The dog may be adopted because felony charges automatically terminate the owner's property rights"],"a":2,"e":"C is correct. Animals seized in cruelty investigations are evidence in a criminal proceeding. Unlike typical stray holds, the hold on an evidence animal is imposed by court order — not merely the statutory stray hold period — and continues until the case is resolved. The animal cannot be adopted, transferred, or euthanised without specific court authorization, regardless of the statutory hold period. Criminal charges do not automatically terminate the owner's property rights (option D); only a court order does. During the case, the shelter may apply for a bond hearing to require the owner to post a bond or deposit to cover ongoing care costs — a critical financial mechanism for shelters housing evidence animals for months or years."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A private rescue organisation (no government contract) takes in a stray dog found wandering by a member of the public. The rescue is not a municipal shelter and has no contract with animal control. Regarding stray hold requirements, which of the following is MOST accurate?","o":["The private rescue is fully exempt from all stray hold requirements and may adopt the dog immediately","The private rescue must follow the identical hold period as the municipal shelter because all shelters are subject to the same state statutes","The private rescue is not bound by municipal hold statutes but takes on significant legal risk — the dog remains someone's property, and adopting it out exposes the organisation to liability for conversion (taking another's property); routing strays through the municipal pipeline is strongly recommended","The private rescue must hold the dog for 3 days regardless of state statute, as this is the federal minimum under the Animal Welfare Act"],"a":2,"e":"C is correct. Private shelters and rescues without government contracts are generally not directly bound by the stray hold statutes that apply to municipal shelters. However, accepting a stray animal does not give the rescue ownership — the animal remains the legal property of its owner until the owner abandons it or statutory abandonment is established. If the rescue adopts the dog to a new family and the original owner comes forward, the rescue faces liability for conversion (the unlawful taking or disposal of another's property). The safest practice is to route stray animals through the municipal animal control system so the statutory hold is properly administered. There is no federal minimum hold period under the Animal Welfare Act applicable to typical companion animal shelters (option D is incorrect)."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A stray cat is impounded with a microchip but no collar. The shelter scans the chip and finds a registered owner. Under the Illinois Animal Control Act framework, how does the presence of the registered microchip affect the hold period compared to a stray cat with no identification?","o":["The microchip has no effect on the hold period; all stray animals are held for the same minimum duration","A microchip shortens the hold period because the owner can be notified quickly, reducing the need for a long wait","The microchip triggers the longer (7-day) minimum hold because the animal has owner identification; the same rule applies as for a rabies tag — identification mandates maximum hold to allow owner reclaim","A microchip replaces the statutory hold entirely; once the owner is notified, the hold ends and the shelter may proceed"],"a":2,"e":"C is correct. Under the Illinois Animal Control Act (and similar statutes in other states), the presence of owner identification — including a registered microchip, rabies tag, or ID collar — triggers the longer statutory hold period (7 days) rather than the shorter hold applied to animals without identification. The rationale is that identifiable animals have a higher probability of owner reclaim, warranting more time. Importantly, notification of the owner does not terminate the hold early (option D); the statutory period runs regardless. The microchip does not shorten the hold (option B) — it extends it. The distinction between identified and unidentified animals is a frequently tested point on the ABVP exam."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A stray dog in the municipal shelter is in good health. On Day 4 of a 7-day hold, a technician notices a large abscess on the dog's leg that was not noted on intake. The veterinarian recommends lancing and flushing the abscess. Which of the following BEST describes the appropriate course of action?","o":["Delay all treatment until Day 7 when the hold expires; no procedures are permitted during the stray hold","Proceed with the procedure only if it can be performed under indirect supervision to avoid calling in the veterinarian","Proceed with the medically necessary procedure under direct veterinary supervision; treating an active infection is not elective surgery — it is immediate medical need permitted during the hold","Proceed with lancing and flushing only after obtaining written consent from animal control, who holds custody of the animal"],"a":2,"e":"C is correct. The prohibition on elective procedures during a stray hold applies specifically to elective (non-urgent) surgeries such as spay/neuter. It does not prohibit medically necessary treatment. An active abscess causing pain and risk of systemic infection is an immediate medical need — withholding treatment would violate the shelter's duty of care to animals in its custody. The veterinarian must be physically present (direct supervision) to perform this procedure. The shelter may document costs and seek reimbursement from the owner if the dog is reclaimed. Animal control (option D) grants custody to the municipal shelter but is not a separate party whose consent is required for medical decisions once the animal is in the shelter's care."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter's staff veterinarian retires and allows her DEA registration to lapse. The shelter director asks the retired veterinarian to continue ordering pentobarbital for the euthanasia programme on a \"consulting\" basis using her expired registration. This arrangement is:","o":["Permissible if the retired veterinarian holds a valid state veterinary licence, even without an active DEA registration","Permissible if the shelter director co-signs the controlled substance order as the authorised representative","A federal violation: ordering, dispensing, or administering DEA-scheduled controlled substances requires an active DEA registration; an expired or lapsed registration confers no authority","Permissible for a 90-day grace period after the registration lapses, as DEA allows a transition window"],"a":2,"e":"C is correct. DEA registration is not merely a formality — it is the federal legal authority that permits a practitioner to order, dispense, and administer Schedule II–V controlled substances. Once a registration expires or is surrendered, that authority ends immediately. There is no grace period (option D is incorrect). Using an expired registration to order pentobarbital would constitute a federal criminal violation under the Controlled Substances Act. When a shelter loses its DEA-registered veterinarian, it must either: (1) hire or contract with a new DEA-registered veterinarian who lists the shelter address, or (2) obtain a facility DEA registration in the shelter's own name. Euthanasia programmes cannot legally continue without a valid, current DEA registration for that facility address."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Under DEA Schedule II regulations governing controlled substance recordkeeping, which of the following MOST accurately describes the requirements for sodium pentobarbital used in shelter euthanasia?","o":["A general monthly log is sufficient; individual dose entries are not required for Schedule II drugs in a shelter setting","Every use must be recorded in a perpetual inventory log; waste must be witnessed and documented; records must be maintained for two years and be available for DEA inspection at any time","Only the opening and closing inventory need to be documented; individual dispensing events do not require separate log entries","Recordkeeping requirements for Schedule II drugs are the same as for Schedule IV drugs — a running log maintained by the shelter director is sufficient"],"a":1,"e":"B is correct. Sodium pentobarbital is a DEA Schedule II controlled substance — the highest level of control for substances with accepted medical use. Schedule II recordkeeping requirements are stringent: every administration must be individually logged (perpetual inventory), including the date, animal identification, amount used, and the name of the individual administering it. Any waste (e.g., partial vials discarded) must be witnessed by a second person and documented with the witness's name. Records must be maintained for a minimum of two years and made available for DEA inspection on demand. These requirements are substantially more rigorous than Schedule III–V drugs (option D). Inadequate recordkeeping is one of the most common DEA violations found during shelter inspections."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter's certified euthanasia technician (CET) administers sodium pentobarbital to animals under the euthanasia programme. Which of the following BEST describes the regulatory requirements for individuals performing euthanasia in this role?","o":["No specific requirements beyond general employment eligibility; euthanasia is not a regulated act in most states","CETs must hold a veterinary technician licence in states that allow non-veterinarians to perform euthanasia","CETs must pass background checks (criminal history review), complete state-approved training, and operate under strict quality control protocols; DEA access is typically managed through the supervising veterinarian's or facility's registration","CETs are not permitted to handle DEA Schedule II substances under any circumstances; only licensed veterinarians may administer pentobarbital"],"a":2,"e":"C is correct. Many states permit trained non-veterinarian personnel (certified euthanasia technicians or shelter euthanasia technicians) to administer sodium pentobarbital in a shelter euthanasia setting, provided they meet specific requirements. These typically include: a criminal background check (to meet DEA requirements for individuals with access to controlled substances), completion of a state-approved euthanasia training course, and operation under the written protocols and oversight of a licensed veterinarian or the facility's DEA registrant. CETs do not need to be licensed veterinary technicians (option B) in most states. Option D is incorrect — many states explicitly authorize trained non-veterinarians to perform euthanasia under appropriate supervision, which is operationally essential for high-volume shelters."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter volunteer who is also a human nurse asks to administer injectable ivermectin to a dog under a written standing protocol from the shelter veterinarian. The veterinarian is not on-site but is reachable by phone. Which of the following BEST describes the regulatory situation?","o":["This is permissible because the volunteer is a licensed healthcare professional and the vet is reachable by phone","This is permissible because standing protocols cover all medication administration by any trained shelter staff or volunteer","This is likely impermissible under the veterinary practice act: medication administration by prescription drug injection is typically restricted to licensed veterinary professionals; a human nursing licence does not confer authority to practice veterinary medicine, and volunteers generally cannot administer prescription injectables regardless of standing protocols","This is permissible as long as the volunteer documents the administration in the animal's medical record"],"a":2,"e":"C is correct. Veterinary practice acts regulate who may administer medications to animals — and those authorised individuals are typically licensed veterinarians, licensed veterinary technicians, and veterinary assistants acting under specific supervision conditions. A human registered nurse licence does not confer any authority to practice veterinary medicine. Furthermore, standing protocols authorise specific licensed veterinary personnel to carry out procedures — they do not typically extend to volunteers or unlicensed individuals for injectable prescription drugs. Administering injectable ivermectin (a prescription drug) by a volunteer (licensed in human nursing or otherwise) would likely constitute unlicensed practice of veterinary medicine in most states. Documentation (option D) does not confer legal authority to perform the act."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"Ketamine is used at a shelter for chemical restraint. Under DEA scheduling, ketamine is classified as:","o":["Schedule I — high abuse potential with no accepted medical use","Schedule II — high abuse potential with accepted medical use under severe restrictions","Schedule III — accepted medical use with moderate to low dependence potential; less restrictive recordkeeping than Schedule II","Schedule V — lowest control tier; may be ordered without DEA Form 222"],"a":2,"e":"C is correct. Ketamine (ketamine hydrochloride) is a DEA Schedule III controlled substance. This means it has accepted medical use and moderate-to-low potential for physical dependence, though significant psychological dependence potential exists. As a Schedule III drug, ketamine's recordkeeping requirements are less stringent than Schedule II (no DEA Form 222 required; records kept for 2 years). However, it still requires a DEA registration to order and dispense, must be stored securely, and every dispensing event should be logged. This contrasts with pentobarbital, which is Schedule II with the highest recordkeeping requirements. Knowing the DEA schedule of common shelter drugs (pentobarbital = II, ketamine = III, Telazol/tiletamine-zolazepam = III) is tested on the ABVP exam."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter posts on social media that a dog available for adoption \"has shown food aggression and has snapped at handlers.\" The dog is adopted and subsequently bites a child. The family sues the shelter, claiming the social media post was inaccurate — the dog had never actually shown food aggression; a staff error had mislabelled the record. Which liability theory MOST directly applies to the shelter?","o":["The shelter has no liability because it disclosed a behavioural concern; any disclosure provides full immunity","The shelter is liable under strict liability dog bite statute solely because the dog bit someone after adoption","The shelter may face negligence liability for maintaining and publishing inaccurate behavioural records: the inaccuracy may have distorted the adopter's risk assessment, and the shelter's failure to maintain accurate records could be the proximate cause of harm","The adopter assumes all liability at the point of adoption signature; no post-adoption shelter liability exists for bite incidents"],"a":2,"e":"C is correct. Social media and adoption record accuracy carry legal consequences. If a shelter publishes inaccurate behavioural information — whether by overstating or understating a risk — and that inaccuracy influences the adopter's decision or risk-management behaviour, the shelter may face negligence liability. In this scenario, the inaccurate \"food aggression\" label may have caused the family to take precautions around food that were unnecessary, while missing the dog's actual risk profile (whatever that was). Conversely, if the actual risk was understated, the shelter would be liable for failure to disclose. Accurate recordkeeping is both an ethical and legal obligation. Full disclosure (option A) provides reduced but not absolute immunity — the disclosure must be accurate. Adoption agreements with indemnification clauses (option D) do not eliminate liability for shelter negligence."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter relies heavily on volunteers to assist with dog walking and kennel cleaning. A volunteer is bitten by a dog during a routine walk. The volunteer claims the shelter did not provide any safety training or warn her about the dog's bite history. Which of the following BEST describes the shelter's potential liability?","o":["No liability: volunteers assume all risks by virtue of volunteering; the shelter owes no duty of care to unpaid workers","No liability: the volunteer is not an employee, so OSHA and employer duty of care do not apply","Potential negligence liability: shelters owe a duty of care to volunteers — including providing reasonable safety training, informing volunteers of known animal behavioural risks, and maintaining a reasonably safe work environment — even though volunteers are unpaid","Liability is limited to the dog's owner, not the shelter, because the dog caused the injury"],"a":2,"e":"C is correct. The distinction between employee and volunteer status determines tax treatment and employment law obligations, but it does not eliminate a shelter's general duty of care. Organisations have a duty to maintain reasonably safe conditions and provide adequate information to all individuals working on their premises — including volunteers. If the shelter knew of the dog's bite history and failed to warn the volunteer, or if no safety orientation was provided, those omissions could support a negligence claim. While OSHA standards technically apply to employees, general negligence principles apply to anyone harmed by a shelter's unreasonable failure to exercise care. Best practice is to provide all volunteers with bite prevention training, supervise them appropriately, and document that training occurred."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A shelter's trial adoption agreement includes a broad indemnification clause stating the trial adopter \"assumes all liability for any injury caused by the animal during the trial period.\" A trial adopter's homeowner's insurance policy excludes coverage for animals not owned by the policyholder. The trial animal bites a neighbour. Regarding the liability allocation, which of the following is MOST accurate?","o":["The indemnification clause fully transfers liability to the trial adopter; the shelter has no exposure regardless of insurance coverage","Because the homeowner's insurance excludes the animal, the indemnification clause is automatically void and unenforceable","The indemnification clause may be enforceable, but if the trial adopter is uninsured for this loss and lacks assets, the injured neighbour may pursue the shelter as the legal owner — demonstrating that requiring verified homeowner's insurance is a critical element of trial adoption risk management","The neighbour must first exhaust claims against the trial adopter before suing the shelter; the shelter is only secondarily liable"],"a":2,"e":"C is correct. An indemnification clause contractually shifts liability from the shelter to the trial adopter, but it is only as effective as the trial adopter's ability to honour it. If the adopter's homeowner's policy excludes animals not owned by the policyholder — a common policy exclusion — and the adopter lacks personal assets to satisfy a judgment, the injured third party may pursue the shelter as the legal owner of the animal. Indemnification clauses do not eliminate underlying legal liability; they create a contractual right of reimbursement that may be difficult to enforce against an uninsured, asset-poor adopter. This is precisely why requiring proof of applicable insurance (or a shelter-issued rider) is a best practice, not merely a formality. The shelter retaining legal ownership means it retains primary exposure in practice even when contractually indemnified."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Regulatory","q":"A dog is impounded as a stray on Monday morning. The statutory hold period is 7 days. The shelter's state statute specifies that hold days are counted as calendar days (not business days). The dog is microchipped with a registered owner. On which day does the hold legally expire, and what action may the shelter first legally take?","o":["The hold expires at the end of Monday (Day 1); the shelter may act on Tuesday morning","The hold expires after 7 business days, excluding the weekend; the shelter may act on the following Tuesday","Counting the impoundment day as Day 1, the hold expires at the end of Day 7 (Sunday); the shelter may first legally adopt, transfer, or perform elective procedures beginning Monday morning — after the hold has fully run","Because the owner was notified via the microchip registry, the hold period is waived and the shelter may act after 3 days"],"a":2,"e":"C is correct. When a statute specifies calendar days (not business days), weekends and holidays count toward the hold period. Counting Monday as Day 1 through Sunday as Day 7 means the 7-day hold expires at the end of Sunday. The shelter's legal authority to dispose of the animal (by adoption, transfer, or euthanasia) and to perform elective procedures (spay/neuter, microchipping) begins on Monday — after the hold has fully run. The microchip and owner notification do not waive or shorten the hold (option D); they trigger the longer hold and ensure the owner has maximum opportunity to reclaim. Jurisdictions vary on whether Day 1 is the impoundment day or the day after — candidates should read state statutes carefully, but the concept of \"full hold must expire before elective action\" is universal."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Which federal agency is responsible for administering and enforcing the Animal Welfare Act (AWA)?","o":["The American Veterinary Medical Association (AVMA)","The ASPCA","USDA Animal and Plant Health Inspection Service (APHIS)","The Environmental Protection Agency (EPA)"],"a":2,"e":"C is correct. The AWA is enforced by USDA APHIS Animal Care, which employs federal inspectors who conduct unannounced inspections of licensed facilities. The AVMA and ASPCA are professional/advocacy organizations with no federal enforcement authority. The EPA regulates environmental matters, not animal welfare. Knowing the enforcement agency is a foundational AWA fact."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A breeder sells purebred dogs directly to the public from her home and has 3 breeding females. Under the Animal Welfare Act, she is:","o":["Exempt from USDA licensing — the AWA license threshold requires 4 or more breeding females selling to the public","Required to obtain a Class A dealer license because any commercial dog sale triggers AWA registration","Required to register with APHIS as a research facility if she conducts health testing","Subject to AWA only if she sells animals across state lines"],"a":0,"e":"A is correct. The AWA Class A dealer licensing threshold is 4 or more breeding females selling to the public or to dealers. A breeder with 3 or fewer breeding females who sells directly to the public is exempt from USDA licensing. This is a common exam trap — the intuitive assumption is that any commercial breeding requires a license. Option D is incorrect: interstate commerce is relevant to PACT Act jurisdiction, not to the AWA licensing threshold for small breeders."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Which of the following animals is EXPLICITLY excluded from AWA protection when used in biomedical research?","o":["Non-human primates","Dogs and cats","Rats, mice, and birds bred for research use","Guinea pigs and hamsters"],"a":2,"e":"C is correct. The 2002 Farm Bill amendment to the AWA explicitly excluded rats of the genus Rattus, mice of the genus Mus, and birds bred for research from AWA coverage — even though these animals constitute approximately 95% of all research animals in the US. This exclusion is a longstanding controversy. Non-human primates (A) have enhanced protections under AWA (psychological well-being requirements). Dogs, cats, guinea pigs, and hamsters are all covered by AWA in research settings."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A municipal animal shelter takes in stray dogs and cats, provides veterinary care, and places animals for adoption. Which statement BEST describes the shelter's relationship to the Animal Welfare Act?","o":["The shelter must register with USDA APHIS as a Class B dealer because it transfers animals to the public","The shelter is subject to AWA humane care standards because it houses companion animals","The shelter's operations are not covered by the AWA — shelter intake, holding, adoption, and euthanasia are governed entirely at state and local level","The shelter must comply with AWA standards if it euthanizes more than 100 animals per year"],"a":2,"e":"C is correct. Animal shelters — municipal or private — are not regulated under the AWA. The AWA covers commercial breeders, dealers, research facilities, exhibitors, and transportation carriers. Shelter operations (stray intake, holding periods, live release, adoption, foster, euthanasia) are governed entirely by state statutes and local ordinances. There is no federal animal shelter law in the United States. This is one of the most important structural facts about US animal welfare law."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"The PACT Act (2019) was significant primarily because it:","o":["Created a federal animal cruelty registry analogous to sex offender registries","Was the first federal law to directly criminalize companion animal cruelty (not just the depiction of cruelty)","Extended Animal Welfare Act protections to rats, mice, and birds used in research","Established federal minimum standards for shelter euthanasia methods"],"a":1,"e":"B is correct. Before the PACT Act, federal law only addressed depictions of animal cruelty (the 2010 Animal Crush Video Prohibition Act) — not the actual acts. The PACT Act closed this gap by making acts of animal crushing and sexual exploitation a federal crime in interstate or foreign commerce. Options A, C, and D describe things the PACT Act does not do."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A shelter veterinarian performs a routine spay on an owner-surrendered cat. Under the PACT Act, this procedure:","o":["Violates the PACT Act if done without documented owner consent on file","Is explicitly exempt — legitimate veterinary and husbandry practices are excluded from PACT Act prohibitions","Requires APHIS pre-approval as a surgical procedure","Is regulated by PACT only if the cat was transported across state lines for the procedure"],"a":1,"e":"B is correct. The PACT Act explicitly excludes from its prohibitions: legitimate veterinary and animal husbandry practices, wildlife hunting and trapping conducted lawfully, pest control, and medical/scientific research. Routine surgery such as spaying is unambiguously a legitimate veterinary practice and is fully exempt. The PACT Act targets acts of cruelty (crushing, burning, drowning, suffocating, impaling, sexual exploitation) — not standard clinical care."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"The maximum federal imprisonment penalty for a PACT Act violation is:","o":["1 year","2 years","7 years","Life imprisonment"],"a":2,"e":"C is correct. The PACT Act carries a maximum federal prison sentence of up to 7 years, plus fines. This is notably higher than many state animal cruelty penalties — though some states now have comparable or higher maximums for aggravated cruelty. The PACT Act does not provide for life imprisonment. The 7-year maximum reflects Congress's intent to treat animal cruelty as a serious federal crime comparable to many federal fraud and drug statutes."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Regarding Breed-Specific Legislation (BSL), which statement BEST reflects the positions of both the AVMA and ASV?","o":["Both organizations support BSL as an effective tool for reducing dog bite incidents when targeted at high-risk breeds","The AVMA supports BSL; the ASV opposes it based on shelter-specific evidence","Both organizations oppose BSL because breed identification is unreliable and individual behavior-based dangerous dog laws are more effective","Neither organization has issued a formal position, as BSL is considered a political rather than scientific question"],"a":2,"e":"C is correct. Both the AVMA and ASV formally oppose BSL on shared grounds: (1) insufficient evidence that BSL reduces bite incidents; (2) visual breed identification — even by professionals — is unreliable and inconsistent with DNA testing; (3) individual behavioral history is a better bite-risk predictor than breed; (4) behavior-based dangerous dog laws are more effective, fair, and enforceable. ASPCA and AHA hold the same position. Option A is the opposite of their actual stance."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Which US state was the first to enact a statewide ban on the sale of commercially bred dogs, cats, and rabbits in pet stores?","o":["New York","Illinois","California","Oregon"],"a":2,"e":"C is correct. California's AB 485 (signed 2017, effective January 1, 2019) was the first statewide law requiring pet stores to source dogs, cats, and rabbits exclusively from shelters or rescues. Many cities had enacted local retail bans before this, but California was the first state-level law. Illinois, Maryland, and New York have since enacted similar statewide laws. The common distractor is confusing \"first city to act\" with \"first state.\""},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"What is the federal legal status of Trap-Neuter-Return (TNR) programs for community cats in the United States?","o":["TNR is mandated by federal wildlife law as the preferred method for managing feral cat populations near protected bird habitat","TNR is prohibited by federal law because free-roaming cats are a listed threat to migratory birds under the Migratory Bird Treaty Act","No federal law addresses TNR — legality and implementation are determined entirely at the state and local level","TNR is regulated by USDA APHIS and requires a federal permit for community cat programs"],"a":2,"e":"C is correct. There is no federal law governing TNR programs. Whether TNR is legal, endorsed, or prohibited is entirely a matter of state statute and local ordinance. Some jurisdictions have formal municipal TNR programs; others prohibit feeding or returning feral cats; many have no policy. AVMA and ASV support TNR as one component of comprehensive community cat management. Federal wildlife law (Migratory Bird Treaty Act) creates tension with TNR in some contexts but has not resulted in a federal prohibition on TNR programs."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A state legislature passes a law prohibiting its cities and counties from enacting any ordinance that restricts dog ownership based on breed. This is an example of:","o":["Federal preemption of state BSL","A model dangerous dog law adopted from the NACA framework","State preemption of local BSL","A constitutional challenge under the Fourteenth Amendment"],"a":2,"e":"C is correct. When a state legislature prevents cities and counties from enacting breed-based ordinances, this is state preemption of local BSL. More than 20 states have enacted such laws. Option A is wrong — there is no federal preemption of BSL (no federal law addresses it). Option B describes an advisory model document, not a legal preemption mechanism. This type of state preemption is generally viewed as protective of dog owners from patchwork local breed bans."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Which organizations are the primary publishers of model animal control ordinances used by US municipalities?","o":["AVMA and ASPCA","USDA APHIS and the American Bar Association","NACA (National Animal Care and Control Association) and HSUS (Humane Society of the United States)","ASV and SAWA"],"a":2,"e":"C is correct. NACA and HSUS are the primary publishers of model animal control ordinances in the US. NACA focuses on animal control operational standards and professional practice; HSUS publishes model ordinances for retail pet bans, anti-tethering, cat management, and TNR. These are templates — not binding law — that local governments can adopt, adapt, or ignore. AVMA and ASV (A, D) focus on veterinary professional standards. USDA APHIS (B) enforces the AWA but does not write local ordinances."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Cold-blooded animals (reptiles, amphibians, fish) kept in zoos open to the public are covered under the Animal Welfare Act.","o":["True — AWA covers all vertebrate animals displayed to the public by exhibitors","False — reptiles, amphibians, and fish are explicitly excluded from AWA coverage regardless of how they are used or displayed","True — AWA covers all animals at USDA-licensed exhibitor facilities","False — AWA only covers mammals; birds are also excluded"],"a":1,"e":"B is correct. Cold-blooded species — reptiles, amphibians, and fish — are explicitly excluded from AWA coverage regardless of how they are housed or displayed. AWA covers \"animals\" defined as warm-blooded mammals (and birds in most commercial contexts, though birds bred for research are excluded under the 2002 amendment). This is a common exam trap: seeing \"zoo\" or \"exhibitor\" and assuming all animals are covered."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"The Animal Welfare Act imposes a specific welfare requirement for non-human primates held in research facilities that is NOT required for dogs, cats, or guinea pigs. This requirement concerns:","o":["Daily weighing and body condition scoring by veterinary staff","Written environmental enrichment plans to promote psychological well-being","Monthly hormonal stress panels to document welfare status","Outdoor access for at least 2 hours per day"],"a":1,"e":"B is correct. The AWA 1985 amendments added a species-specific requirement for non-human primates: research facilities must develop and follow written plans to promote their psychological well-being, including environmental enrichment, social housing, and opportunities for foraging and normal behaviour. No comparable written psychological well-being mandate exists for dogs, cats, guinea pigs, or other covered species under AWA, though dogs have a separate exercise requirement."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"APHIS Animal Care inspections of AWA-licensed facilities are conducted:","o":["Only upon receipt of a formal public complaint","On a scheduled basis with 30 days' advance notice","Unannounced, at least once per year for licensed facilities","Only at the time of initial licensing and licence renewal"],"a":2,"e":"C is correct. APHIS Animal Care inspectors conduct unannounced inspections — no advance notice is given to facilities. Licensed facilities (Class A and B dealers, exhibitors, research facilities, carriers) must be inspected at least annually. Violations can result in official warnings, civil fines, license suspension, or criminal referral. The unannounced nature prevents facilities from presenting a misleading picture during inspections."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"AWA-licensed dealers are required to maintain acquisition and disposition records for each regulated animal for a minimum of:","o":["6 months","1 year","3 years","The lifetime of the animal"],"a":1,"e":"B is correct. AWA regulations require licensed dealers to maintain records documenting the acquisition and disposition of each regulated animal for at least 1 year. These records must include the source, date, and description of each animal. This traceability requirement allows APHIS to track animals through the commercial supply chain and identify violations such as dealing in stolen pets."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Before the PACT Act (2019), what was the primary federal law addressing animal cruelty?","o":["There was no federal law of any kind addressing animal cruelty before 2019","The 2010 Animal Crush Video Prohibition Act — which criminalized distribution of cruelty depictions but NOT the underlying acts themselves","The Animal Welfare Act, which included companion animal cruelty provisions","The Farm Bill, which included federal penalties for pet cruelty in commercial breeding operations"],"a":1,"e":"B is correct. The 2010 Animal Crush Video Prohibition Act made it a federal crime to create or distribute videos depicting animal crushing — but not to commit the underlying acts of cruelty. Congress recognized this gap as untenable: filming cruelty was criminal but committing it was not, at the federal level. The PACT Act (2019) closed this gap. The AWA (C) covers commercial breeders and research facilities but contains no companion animal cruelty provisions."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A person posts a video to social media showing themselves committing a severe act of cruelty against a cat. The act occurred entirely within one state. Which statement BEST describes the PACT Act's applicability?","o":["PACT Act does not apply because the act occurred in a single state","PACT Act does not apply because social media posting is protected speech","PACT Act jurisdiction is established — online distribution of the video constitutes distribution in interstate commerce, triggering federal jurisdiction","PACT Act applies automatically to all companion animal cruelty regardless of where or how it is distributed"],"a":2,"e":"C is correct. The PACT Act requires an interstate or foreign commerce nexus, but online posting satisfies this requirement: distributing content across the internet constitutes distribution in interstate commerce — even if the underlying act occurred in a single state. This is why the PACT Act is particularly relevant to crush videos and cruelty content posted online. The act does NOT apply automatically to all companion animal cruelty; the commerce requirement must be met."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A shelter receives a dog with injuries consistent with dogfighting. Investigation later reveals the dog was transported across state lines for fights. Which statement is MOST accurate about potential prosecution?","o":["Only state cruelty charges apply; the PACT Act covers crushing and sexual exploitation but not dogfighting injuries","Federal prosecutors must choose between PACT Act and state charges — both cannot apply to the same act","Both federal PACT Act charges and state cruelty charges can apply; interstate transport of the animal establishes the commerce nexus for federal jurisdiction","The PACT Act does not cover dogfighting because fighting is addressed by a separate federal animal fighting statute"],"a":2,"e":"C is correct. The PACT Act does not preempt state law — both federal and state charges can apply simultaneously to the same conduct. Interstate transport of animals for fighting purposes establishes the PACT Act's commerce nexus. The shelter veterinarian's thorough injury documentation (photographs, wound measurements, healing stage, bite-pattern analysis) becomes critical evidence for prosecution. The PACT Act's \"serious harm\" language is broad enough to cover dogfighting injuries; it is not limited to crushing alone."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"Research comparing visual breed identification by shelter professionals to DNA testing shows that:","o":["Professionals correctly identify breed in more than 90% of cases when given sufficient time","Visual identification is reliable for purebreds but unreliable only for first-generation crosses","Visual breed identification — even by trained professionals — is unreliable; mixed-breed dogs are frequently misclassified as \"pit bull–type\"","DNA testing and professional visual assessment have equivalent accuracy at approximately 85% concordance"],"a":2,"e":"C is correct. Multiple studies show that visual breed identification by veterinarians, shelter workers, and animal control officers is highly unreliable compared to DNA testing. Mixed-breed dogs are disproportionately classified as \"pit bull–type\" based on superficial phenotypic traits. This is one of the strongest scientific arguments against BSL: the targeted class of animals cannot be consistently or accurately defined, meaning BSL enforcement will inevitably be both over-inclusive and under-inclusive."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A jurisdiction enacts a retail pet sale ban. Which of the following is typically EXEMPT from the ban?","o":["Breeders with fewer than 10 litters per year who sell directly to the public","Animal shelters and rescues placing animals for adoption at pet store locations","Pet stores that source animals from USDA Class A licensed breeders with a clean inspection record","Pet stores selling only cats and rabbits (not dogs)"],"a":1,"e":"B is correct. Retail pet sale bans prohibit pet stores from sourcing dogs, cats, and/or rabbits from commercial breeders or brokers, but they explicitly exempt shelters and rescues. Pet stores can continue operating as adoption partners — hosting shelter or rescue animals for adoption events or as resident adoptable animals. The exemption is intentional: retail bans aim to cut the commercial breeding pipeline while expanding, not restricting, shelter adoption options. California's AB 485, the first statewide ban, includes this shelter/rescue exemption."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"In a state WITHOUT BSL preemption, a major city passes an ordinance banning ownership of pit bull–type dogs. What is the most likely legal outcome?","o":["The ordinance is void because federal law prohibits breed-based ownership restrictions on companion animals","The ordinance is valid — without state preemption, local governments can enact ordinances not prohibited by state law, including BSL","The ordinance requires USDA APHIS approval before it takes effect","The ordinance is automatically invalid because BSL violates the Fourteenth Amendment Equal Protection clause"],"a":1,"e":"B is correct. There is no federal law on BSL, and in the absence of state preemption, local governments can enact ordinances not prohibited by state law. BSL has survived constitutional challenges in most jurisdictions — courts have applied rational basis review and found a plausible public safety rationale sufficient. Constitutional challenges have rarely succeeded. This is why state-level preemption legislation is the most effective mechanism for preventing or overturning local BSL."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"The primary evidence-based public safety rationale for anti-tethering laws is:","o":["Tethered dogs develop musculoskeletal disease at significantly higher rates, which reduces quality of life","Tethering is defined as a form of animal cruelty under the Animal Welfare Act","Tethered dogs display heightened territorial aggression with no flight option, contributing to higher bite rates compared to un-tethered dogs","Tethered dogs are three times more likely to escape and injure pedestrians"],"a":2,"e":"C is correct. The core public safety rationale for anti-tethering laws is the elevated bite risk. Tethering creates chronic frustration and stress; when a perceived threat approaches, the dog cannot use flight — only fight. Combined with territorial behaviour over a fixed space, tethered dogs have statistically higher bite rates than free-ranging owned dogs. Tethering is NOT defined as cruelty under the AWA (B) — it is a state/local matter. The welfare and bite-risk arguments together make anti-tethering ordinances both animal welfare and public safety legislation."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Legislation","q":"A state law prohibits cities and counties from enacting any animal welfare ordinance stricter than the state minimum standard. A city that previously required microchipping of all adopted cats — a requirement not in state law — is now barred from enforcing it. This demonstrates:","o":["State preemption protecting animals by establishing a welfare floor above the federal minimum","Federal preemption superseding inconsistent local standards under the Commerce Clause","State preemption preventing stronger local animal welfare protections — demonstrating that preemption cuts in both directions","An HSUS model ordinance framework that supersedes local regulations"],"a":2,"e":"C is correct. State preemption prevents local governments from enacting ordinances that differ from state law — but this power cuts in both directions. Preemption of local BSL (protecting dog owners from patchwork breed bans) is one application. Preemption preventing stronger local animal welfare protections is another: the same legal mechanism can stop cities from requiring cat microchipping, stricter shelter standards, or enhanced adoption requirements. Understanding both directions of preemption — and which is which in a given scenario — is a common exam trap (see also: State vs Local Preemption H3 in the State & Local panel)."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Why did the earliest American animal protection laws exclude dogs and cats from their coverage?","o":["Dogs and cats were considered wild animals and therefore not subject to property statutes","Early laws were written to protect animals as economic property; dogs and cats lacked the monetary value of livestock, so no owner's financial interest was legally at stake","Dogs and cats were protected under separate federal statutes that predated state property laws","Legislators believed dogs and cats could adequately fend for themselves and did not require legal protection"],"a":1,"e":"B is correct. The earliest American animal protection statutes were rooted in property law, not welfare principles. Livestock — horses, cattle, swine, sheep — had clear economic value and identifiable owners whose financial interests the law could protect. Dogs and cats, particularly strays, were not considered economically significant property. Because the legal rationale was the protection of owners' economic interests rather than animal welfare per se, companion animals fell entirely outside the law's scope. Option A is incorrect: stray dogs were not classified as wild animals; they simply lacked legal standing as property worth protecting."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"What was the ORIGINAL function of the poundmaster in early American cities, before urban growth changed the nature of the stray animal problem?","o":["Managing stray dogs and enforcing dog licensing ordinances","Investigating complaints of cruelty to companion animals","Impounding stray livestock — cattle, pigs, and horses — that had wandered onto public roads or neighboring property, releasing them upon payment of an impound fee","Operating rabies vaccination programs for urban dogs under city contract"],"a":2,"e":"C is correct. The pound predates organized sheltering and was originally a livestock management institution. Poundmasters impounded stray cattle, pigs, and horses — animals with clear economic value and identifiable owners who would pay impound fees for their return. As American cities industrialized and densified, livestock were progressively removed from urban environments. Dogs — which remained abundant — then became the primary stray animal problem, and the pound system adapted to manage them using the same reclaim-fee logic originally designed for livestock. The transformation of the pound from a livestock facility to a dog management institution is a key historical transition on the exam."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"How did urban growth in 19th-century American cities change the animal management problem municipalities faced?","o":["Urban growth reduced the number of stray dogs by eliminating refuse piles that had sustained them","As livestock were removed from densifying cities, stray dogs — which survived by scavenging urban refuse — became the dominant public nuisance and public health concern requiring municipal management","Urban growth prompted cat licensing as the primary animal control tool, displacing dog management","Industrialization created demand for working dogs, resolving the stray problem through employment"],"a":1,"e":"B is correct. As American cities grew and industrialized through the 19th century, livestock that had previously roamed urban areas were progressively restricted or eliminated. However, dogs — which survived by scavenging from the abundant refuse of densely populated neighborhoods — remained and multiplied. Packs of roaming dogs were associated with rabies transmission and general public disorder. Municipal governments responded by adapting and expanding the pound system, originally designed for livestock, to manage stray dogs. This shift in target species while retaining the same corrupt fee structure was the context reformers inherited."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"What was the method of mass killing used by the New York City pound in the 1870s that became a galvanizing symbol for early animal welfare reformers?","o":["Intravenous injection of carbolic acid administered by city employees","Sealed gas asphyxiation chambers constructed beneath the pound building","Lowering an iron cage packed with dogs into the East River until the animals drowned","Shooting by city police officers conducted behind closed doors in the pound yard"],"a":2,"e":"C is correct. The NYC pound of the 1870s used a large iron cage that was loaded with captured dogs and lowered by a derrick into the East River, where the animals drowned. This method was the official city-sanctioned approach to mass euthanasia of unclaimed strays. It was publicly visible and became a powerful symbol of institutional cruelty that motivated welfare reformers — including Henry Bergh and later Caroline Earle White — to demand both more humane killing methods and systemic reform of pound management. Gas asphyxiation (option B) was the reform that replaced drowning, introduced by Caroline Earle White at the Pennsylvania SPCA."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"The public widely despised dogcatchers in 19th-century American cities. What was the PRIMARY reason for this hostility?","o":["Dogcatchers were openly cruel to animals during capture, generating outrage at visible individual cruelty","Dogcatchers operated without any legal authority, making their activities equivalent to theft","Dogcatchers captured owned animals indiscriminately alongside strays, then demanded reclaim fees that functioned as ransom — a structurally corrupt incentive driven by per-capture compensation","Dogcatchers were employed by rival sheltering organizations rather than by the city, creating conflicts of interest"],"a":2,"e":"C is correct. The primary source of public hostility toward dogcatchers was the reclaim-fee system, not cruelty to individual animals per se. Dogcatchers were compensated through reclaim fees or per-capture payments, giving them a financial incentive to impound as many dogs as possible — including well-cared-for, owned pets. Owners who wanted their animals back had to pay a fee indistinguishable from a ransom payment. The problem was structural: the compensation model made corrupt behavior financially rational. Reformers recognized that changing the funding model was the necessary fix — salaried staff with no personal financial stake in capture volume, funded through licensing fees rather than reclaim payments."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"What was the CORE financial incentive problem in the early pound system that reformers needed to structurally eliminate?","o":["Poundmasters were bribed by dog breeders to release purebred animals without documentation","Dogcatchers and poundmasters were compensated through reclaim fees or per-capture payments, creating an incentive to maximize impoundments regardless of animal ownership status","City governments profited from selling impounded dogs to medical research laboratories","Poundmasters received kickbacks from dog food suppliers in exchange for extended holding periods"],"a":1,"e":"B is correct. The reclaim-fee and per-capture compensation model directly misaligned the dogcatcher's financial interest (maximize captures and holds) with the public interest (fair, targeted enforcement). More captures meant more potential reclaim fees; releasing animals quickly or declining to capture borderline cases reduced income. This made corruption the rational financial behavior under the system. The structural fix was licensing fees — a stable revenue stream paid by all dog owners as a civic requirement, channeled to the organization rather than to individual workers — combined with salaried staff who had no personal financial stake in capture volume. This eliminated the perverse incentive at its source."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Before the welfare movement of the mid-to-late 1800s, which animal protection gap existed in American law?","o":["Laws protected wild animals but had no provisions for owned livestock","Federal law protected companion animals but state law did not, creating jurisdictional confusion","Dogs, cats, and companion animals lacked legal standing; cruelty to them was not actionable because their suffering caused no cognizable financial harm to a human property owner","Laws required rabies vaccination of all dogs but provided no civil penalty for non-compliance"],"a":2,"e":"C is correct. American law before the welfare movement was fundamentally property-based. Animals were protected only insofar as harm to them constituted harm to a human owner's economic interests. Livestock had this standing because they had clear monetary value; companion animals — particularly strays — did not. Cruelty to a stray dog was not legally actionable because no human suffered a cognizable financial loss. This gap meant the suffering of dogs, cats, and other companion animals was essentially invisible to the law. The founding of the ASPCA (1866) with state-backed authority to investigate and prosecute animal cruelty was the first institutional response to this gap in the United States."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Henry Bergh founded the ASPCA in 1866. What was its INITIAL primary focus?","o":["Adoption and placement of stray dogs and cats in New York City homes","Investigating complaints of cruelty to companion animals by individual private owners","Protecting working street horses from overwork, beating, and inhumane treatment on New York City's streets","Developing humane euthanasia methods to replace drowning in the NYC pound"],"a":2,"e":"C is correct. Henry Bergh's primary motivation in founding the ASPCA was the visible suffering of working draft horses on New York City's streets. Thousands of horses powered the city's transportation and commerce under brutal conditions — overworked, beaten, and left to die on city streets. Bergh observed humane societies in England during a diplomatic posting and was determined to replicate them in America to address equine suffering. The ASPCA's early enforcement actions focused overwhelmingly on horses. Companion animals (dogs and cats) became a more central part of the ASPCA's work later. Option D describes Caroline Earle White's innovation at the Pennsylvania SPCA, not Bergh's founding motivation."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"In what year was the ASPCA founded, and by whom?","o":["1824, by William Wilberforce, in New York City","1868, by Caroline Earle White, in Philadelphia","1866, by Henry Bergh, in New York City","1894, by George Angell, in Boston"],"a":2,"e":"C is correct. The ASPCA was founded in 1866 by Henry Bergh in New York City. Bergh secured a charter from the New York state legislature granting the ASPCA authority to investigate and prosecute animal cruelty — the first such charter in the United States. Option B describes the Pennsylvania SPCA, founded two years later in 1868 by Caroline Earle White in Philadelphia — a completely separate organization. William Wilberforce (option A) was associated with the founding of England's RSPCA (1824). The paired dates ASPCA = 1866 and PennSPCA = 1868 are among the most tested facts in this subdomain."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Caroline Earle White founded the Pennsylvania SPCA in 1868. What specific operational innovation is she credited with introducing?","o":["The mandatory dog licensing fee system","A humane gas asphyxiation chamber as a method of mass euthanasia, replacing the drowning method","The first community spay/neuter program for shelter animals","The reclaim-fee system for recovering impounded animals from city pounds"],"a":1,"e":"B is correct. Caroline Earle White's most significant technical contribution was the development and implementation of a humane gas asphyxiation chamber at the Pennsylvania SPCA. This replaced the drowning method (most notoriously used at the NYC pound) with a faster, less prolonged killing method. This was a genuine innovation in humane euthanasia that spread to other organizations. Option A (licensing fees) is a related contemporaneous reform but is not specifically credited to White as her primary innovation. Option D (reclaim fees) was the old corrupt system that reforms were designed to eliminate — not an innovation attributed to White."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"How did the introduction of licensing fees transform the operational model of humane animal management organizations?","o":["Licensing fees replaced all municipal funding, making humane societies fully self-sustaining","Licensing fees provided stable organizational revenue allowing salaried staff who had no personal financial incentive tied to impoundment volume — eliminating the reclaim-fee corruption cycle","Licensing fees funded the purchase of iron cages used in the transport of stray animals","Licensing fees were paid as bonuses directly to dogcatchers who captured licensed animals"],"a":1,"e":"B is correct. The licensing fee reform was structural: it created revenue for the organization independent of how many animals were captured. With stable licensing revenue, organizations could employ staff on fixed salaries. Salaried employees had no personal financial stake in capture volume or hold duration — the perverse incentive at the heart of the old reclaim-fee system was eliminated. This is the operational reform that broke the corruption cycle; the gas asphyxiation chamber (White's PennSPCA innovation) addressed the cruelty of killing. Together they transformed the field. Option D describes the old system (per-capture payment to individual dogcatchers), not the reform."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which organization directly inspired American welfare reformers — particularly Henry Bergh — to establish the ASPCA?","o":["The Royal Society for the Prevention of Cruelty to Animals (RSPCA), England, founded 1824","The American Humane Association (AHA), which had already established the organizational model domestically","The Humane Society of the United States (HSUS), which provided funding for Bergh's initial operations","The National Animal Control Association (NACA), which trained Bergh in humane field methods"],"a":0,"e":"A is correct. Henry Bergh explicitly modeled the ASPCA on England's RSPCA, which had been founded in 1824 and demonstrated that a private humane organization could be granted legislative authority to investigate and prosecute animal cruelty. Bergh observed the RSPCA's work during a diplomatic posting and returned determined to replicate the model in America. The AHA (option B) was founded after the ASPCA, not before. HSUS (option C) was founded in the 1950s — nearly a century after the ASPCA — and was itself a breakaway from the AHA. NACA (option D) is a modern professional association with no role in the 19th-century welfare movement."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which organization did New York City officials call on to take over management of the NYC pound, and why was this historically significant?","o":["The Pennsylvania SPCA — they had the only proven humane euthanasia chamber at the time","The ASPCA under Henry Bergh — this represented the first transfer of municipal animal control authority to a private humane organization in the United States","The American Humane Association — they had the largest national membership at the time","The HSUS — they were the only organization with federal authority to operate municipal facilities"],"a":1,"e":"B is correct. Facing public criticism over the brutal methods of the NYC pound, city officials called on Henry Bergh and the ASPCA to take over pound management. This was historically significant as the first instance of a private humane organization being granted authority over a municipal animal control function — establishing the template for public-private partnerships in animal control that would become common throughout the 20th century. The PennSPCA (option A) operated in Philadelphia, not New York. HSUS (option D) was not founded until the 1950s and has no federal authority over municipal facilities."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which pairing of innovations most completely transformed humane animal management in late 19th-century American cities?","o":["Mandatory rabies vaccination + the reclaim-fee system","RSPCA model adoption + the iron cage East River drowning method","Humane gas asphyxiation (replacing drowning) + licensing fees enabling salaried staff (replacing per-capture/reclaim-fee compensation)","Spay/neuter programs + return-to-field for feral cats"],"a":2,"e":"C is correct. The gas asphyxiation chamber (introduced by Caroline Earle White at the PennSPCA) addressed the cruelty of the killing method, replacing the prolonged drowning used at facilities like the NYC pound. Licensing fees addressed the corrupt financial incentive structure by replacing per-capture and reclaim-fee compensation with stable, salary-based funding that removed the dogcatcher's personal financial stake in capture volume. Each innovation addressed a different dimension of the problem: one humane (how animals were killed) and one structural (why the system was corrupt). Option D describes modern intake reduction strategies, not 19th-century reform innovations."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"In what year was the Pennsylvania SPCA founded, and by whom?","o":["1866, by Henry Bergh, in New York City","1824, by Caroline Earle White, in Philadelphia","1868, by Caroline Earle White, in Philadelphia","1871, by Henry Bergh, in a Philadelphia expansion of the ASPCA"],"a":2,"e":"C is correct. The Pennsylvania SPCA was founded in 1868 by Caroline Earle White in Philadelphia — two years after Henry Bergh founded the ASPCA in New York (1866). Option A describes the ASPCA. Option B has the correct founder but the wrong year — 1824 is the founding year of England's RSPCA. Option D incorrectly attributes the PennSPCA to Bergh; it was an independent organization founded by White. Commit the pairing to memory: ASPCA = 1866 = Bergh = New York; PennSPCA = 1868 = White = Philadelphia."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"The American Humane Association (AHA) was originally focused on which animal welfare issue before expanding to companion animal sheltering?","o":["Preventing cruelty to dogs and cats in urban pounds","Welfare of livestock during cross-country rail transport","Advocacy against the use of animals in medical research","Training animal control officers in humane capture techniques"],"a":1,"e":"B is correct. The AHA was originally focused on the welfare of livestock during long-distance cross-country transport, particularly by rail. The transport of cattle, horses, and other livestock over hundreds of miles in cramped, unventilated cars without adequate food, water, or rest was a major animal welfare crisis of the late 19th century. The AHA advocated for humane transport regulations. Over time the organization expanded to include companion animal sheltering and, uniquely among major animal welfare organizations, child welfare as well. This livestock-transport origin differentiates the AHA from other organizations and is a frequently tested historical fact."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"The Humane Society of the United States (HSUS) was formed in the 1950s. Which organization did its founders break away from?","o":["The ASPCA","The American Humane Association (AHA)","The National Animal Control Association (NACA)","The Pennsylvania SPCA"],"a":1,"e":"B is correct. HSUS was founded in the 1950s by individuals who broke away from the AHA (American Humane Association) because they sought a more aggressive, nationally focused advocacy stance on animal welfare issues. They felt the AHA was insufficiently committed to national legislative advocacy. HSUS grew into the largest animal protection organization in the United States, focused on national advocacy, legislation, and public education rather than direct shelter operations. It is critically important to remember that HSUS separated from the AHA — NOT from the ASPCA. The ASPCA is an entirely separate organization with independent origins in 1866 under Henry Bergh."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which national organization specifically represents animal control field professionals — officers, supervisors, and administrators in animal control operations?","o":["SAWA (Society of Animal Welfare Administrators)","NACA (National Animal Control Association)","NFHS (National Federation of Humane Societies)","AHA (American Humane Association)"],"a":1,"e":"B is correct. NACA (National Animal Control Association) is the professional organization representing the animal control field — animal control officers, supervisors, and administrators in enforcement and field operations. NACA provides training, sets professional standards, and advocates for the animal control discipline. SAWA (option A) represents shelter administrators and executives and issues the CAWA credential — a leadership credential focused on organizational management, not field operations. NFHS (option C) focuses on collaboration among shelter and rescue organizations broadly. AHA (option D) is a broad national organization encompassing multiple animal welfare functions, not specifically an animal control professional association."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which organization developed and administers the CAWA (Certified Animal Welfare Administrator) credential?","o":["NACA (National Animal Control Association)","HSUS (Humane Society of the United States)","SAWA (Society of Animal Welfare Administrators)","ASPCA (American Society for the Prevention of Cruelty to Animals)"],"a":2,"e":"C is correct. SAWA (Society of Animal Welfare Administrators) is the national organization representing shelter administrators and executives. SAWA developed and administers the Certified Animal Welfare Administrator (CAWA) credential, which is organized around five competency domains: Administration & Management; Personnel Supervision & Leadership; Public Relations & Fundraising; Animal Care & Treatment; and Problem Solving. NACA (option A) represents animal control field professionals and does not issue the CAWA. HSUS (option B) and ASPCA (option D) are advocacy and direct service organizations, respectively — neither administers the CAWA credential."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"A shelter director is preparing for the CAWA exam and needs to know which domain covers strategic planning, accounting, financial management, and nonprofit governance. Which domain is correct?","o":["Domain 1: Administration & Management","Domain 2: Personnel Supervision & Leadership","Domain 3: Public Relations & Fundraising","Domain 5: Problem Solving"],"a":0,"e":"A is correct. CAWA Domain 1 (Administration & Management) covers organizational-level management functions: strategic planning, accounting, budgeting, financial management, nonprofit governance, and regulatory compliance. This is the domain concerned with running the organization as an institution. Domain 2 (Personnel Supervision & Leadership) covers people management — recruitment, training, performance evaluation. Domain 3 covers public-facing functions including fundraising (not financial management of existing funds). Domain 5 covers analytical and operational problem-solving competencies. The most common exam confusion is between Domain 1 (organizational systems) and Domain 2 (people management)."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"A new shelter director is developing a structured hiring process, designing a staff training curriculum, and revising the performance evaluation system. Which CAWA domain is MOST relevant to these activities?","o":["Domain 1: Administration & Management","Domain 2: Personnel Supervision & Leadership","Domain 4: Animal Care & Treatment","Domain 5: Problem Solving"],"a":1,"e":"B is correct. CAWA Domain 2 (Personnel Supervision & Leadership) covers all aspects of human resource management: recruitment and selection (hiring process design), staff training and development (curriculum design), performance evaluation, and labor relations. These are competencies involved in managing people within the organization. Domain 1 (Administration & Management) covers organizational-level systems — budgeting, strategic planning, nonprofit governance — not individual employee management. This distinction (Domain 1 = organizational systems; Domain 2 = people management) is the single most commonly tested CAWA domain distinction on the exam."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"A shelter administrator is planning a media campaign to increase adoptions, overseeing donor stewardship activities, and improving customer service at the intake desk. Which CAWA domain covers these activities?","o":["Domain 1: Administration & Management","Domain 2: Personnel Supervision & Leadership","Domain 3: Public Relations & Fundraising","Domain 4: Animal Care & Treatment"],"a":2,"e":"C is correct. CAWA Domain 3 (Public Relations & Fundraising) covers media relations, customer service, fundraising and development, community engagement, and donor stewardship. These are the outward-facing, public-communication competencies of shelter leadership. A common exam error is placing fundraising in Domain 1 (Administration & Management) on the assumption that it is a financial management function. CAWA classifies fundraising under Public Relations — it is a communication and relationship-building competency, not an accounting function. Domain 1 covers management of existing financial resources (budgeting, accounting); Domain 3 covers generating new resources through relationships and communication."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"In 1994, the ASPCA made a major operational change. What was it, and what role did the organization shift toward?","o":["The ASPCA merged with the AHA to form a unified national advocacy body","The ASPCA transferred its laboratory animal advocacy program to HSUS","The ASPCA ended its contract to operate New York City's municipal animal control system and shifted to a national model of grant-making, training, and community outreach","The ASPCA closed its shelter operations entirely and became a purely legislative advocacy organization"],"a":2,"e":"C is correct. In 1994, the ASPCA ended its contract with New York City to operate the municipal animal control system — a role it had held since the 19th century when Henry Bergh took over the NYC pound. After 1994, the ASPCA transitioned to a national capacity-building model: providing grants to local shelters, offering training and technical assistance, and conducting community outreach and education. The ASPCA did not merge with AHA (option A), did not transfer programs to HSUS (option B), and did not cease operations (option D) — it changed from direct shelter operation to a national grant-making and training organization."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which national organization's primary mission is fostering collaboration and information sharing among humane societies, rescue organizations, and animal control agencies?","o":["SAWA (Society of Animal Welfare Administrators)","NACA (National Animal Control Association)","NFHS (National Federation of Humane Societies)","HSUS (Humane Society of the United States)"],"a":2,"e":"C is correct. The NFHS (National Federation of Humane Societies) is specifically focused on fostering collaboration, communication, and resource sharing among the full range of organizations in the sheltering ecosystem: humane societies, rescue groups, and animal control agencies. It functions as a connector and convener rather than a standards-setting or credentialing body. SAWA (option A) represents shelter administrators and issues the CAWA credential. NACA (option B) represents animal control field professionals specifically. HSUS (option D) is a large national advocacy organization focused primarily on legislation and public education, not specifically on inter-organization collaboration within the sheltering network."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"A shelter director wants to reduce future intake by addressing the root cause of unplanned litters in the surrounding community. Which strategy should be the FIRST priority according to the shelter medicine intake-reduction framework?","o":["Expanding the shelter's kennel capacity to absorb higher intake without increasing euthanasia","Developing or partnering in a community spay/neuter program, as S/N is the cornerstone strategy for durable intake reduction","Implementing a Feral Freedom return-to-field program for all incoming cats","Launching a social media adoption campaign to increase live-release rate without changing intake"],"a":1,"e":"B is correct. Community spay/neuter programs are identified as the cornerstone of intake reduction in the shelter medicine literature. Unplanned litters — in both owned and unowned animal populations — are the primary driver of shelter intake over time. S/N addresses this at the source, producing population-level reductions in intake that sustain over years. Expanding kennel capacity (option A) accommodates more animals but does not reduce how many enter the system. Feral Freedom (option C) targets adult unsocialized cats specifically and does not address litter production in the owned population. Adoption campaigns (option D) improve live-release outcomes but leave intake unchanged — intake reduction and outcome improvement are complementary but distinct goals."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"The No-Kill movement in American animal sheltering is credited to which of the following?","o":["The founding of HSUS in the 1950s and its national campaign against shelter euthanasia","The ASPCA's 1994 shift to national grant-making and community outreach programs","Ed Duvin's publication, which galvanized animal welfare constituencies to challenge euthanasia as routine population control","The adoption of the ASV Guidelines for Standards of Care by the Association of Shelter Veterinarians"],"a":2,"e":"C is correct. The No-Kill movement is attributed to Ed Duvin's publication, which argued that euthanasia of healthy, adoptable animals was not a humane necessity but a failure of organizational will and community commitment. Duvin's writing galvanized constituencies within the animal welfare field to organize around ending euthanasia as routine population management. The movement is credited to his publication specifically — not to an organization, not to a specific shelter achieving a live-release rate benchmark, and not to a regulatory body. Options A, B, and D describe real events in shelter history but none is identified as the origin of the No-Kill movement."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Of the three primary intake reduction strategies identified in shelter medicine, which is described as the CORNERSTONE?","o":["Keeping animals with their guardians through owner support and surrender diversion programs","Community spay/neuter programs","Trap-Neuter-Return (TNR) and Feral Freedom programs for community cats","Transfer transport networks moving animals from high-intake to high-adoption regions"],"a":1,"e":"B is correct. Community spay/neuter programs are explicitly identified as the cornerstone of intake reduction. While keeping animals with guardians (option A) and TNR/Feral Freedom (option C) are important complementary strategies, S/N programs address the root cause of shelter intake — uncontrolled reproduction in owned and unowned animal populations — and produce durable, population-level reductions in intake over time. Transfer networks (option D) are a live-release strategy that moves animals within the system without reducing the number entering it. When the exam asks which intake reduction strategy is most foundational, the answer is spay/neuter programs."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"How does the Feral Freedom program differ from generic Trap-Neuter-Return (TNR)?","o":["Feral Freedom applies to owned outdoor cats; TNR applies only to unowned community cats","Feral Freedom requires rabies vaccination but not sterilization; TNR requires both procedures","Feral Freedom specifically targets adult unsocialized cats for return-to-field, acknowledging they cannot be rehomed as indoor pets but have reasonable quality of life outdoors, while reducing in-shelter management burden; TNR is the broader concept","Feral Freedom is a municipal government program; TNR is operated exclusively by private rescue organizations"],"a":2,"e":"C is correct. TNR is the broad concept covering community cat management through trapping, sterilizing, and returning cats to outdoor territory. Feral Freedom is a specific named program targeting a defined population: adult, unsocialized (feral) cats who cannot be socialized for indoor adoption. The rationale: these cats have reasonable quality of life living independently outdoors; cannot be rehomed as companion animals; would otherwise consume shelter resources and face euthanasia; and are better served by neuter-and-return than in-shelter management. Feral Freedom specifically reduces the burden these cats place on shelter infrastructure. It is not synonymous with all TNR activity — it targets a specific population for a specific rationale."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"According to the Miller and Zawistowski framework, which of the following is explicitly included as one of the 10 core functions of a well-organized animal shelter?","o":["Providing unlimited hold periods for all animals until placement is achieved","Achieving a 90% or greater live-release rate for all animals regardless of health or behavior","Euthanizing animals that are suffering AND animals that can be neither reclaimed nor adopted","Operating a 24-hour emergency veterinary clinic accessible to all community members"],"a":2,"e":"C is correct. The Miller and Zawistowski definition of a well-organized shelter explicitly includes euthanizing both suffering animals and animals that can be neither reclaimed nor adopted. This is one of the 10 named core functions — presented as a legitimate and necessary shelter responsibility, not as a failure of the system. This is a critical exam trap: candidates who have absorbed No-Kill movement philosophy may incorrectly exclude euthanasia from the well-organized shelter framework. Options A and B reflect No-Kill aspirations or specific program metrics, not the operational framework as defined by Miller & Zawistowski. Option D is not among the 10 defined functions."},{"type":"mcq","domain":"Animals & Public Policy","sub":"Animal Shelter History","q":"Which of the following BEST exemplifies coalition building as a modern sheltering strategy?","o":["A single shelter expanding its internal volunteer program to increase adoption event frequency","A shelter purchasing its own dedicated transport van to independently move animals to higher-demand markets","A humane society, three rescue groups, and the municipal animal control agency co-hosting monthly adoption events, sharing a transport vehicle on weekly transfer runs, and jointly funding a community spay/neuter clinic","A shelter applying independently for a federal capital grant to build a new kennel facility"],"a":2,"e":"C is correct. Coalition building refers to formal multi-organizational partnerships that pool resources, share infrastructure, and coordinate programs to achieve outcomes no single organization could accomplish independently. The scenario in option C exemplifies all three key coalition activities: joint adoption events (expanding placement reach across organizations), shared transport vehicle (reducing per-organization cost of transfer programs), and co-funded community S/N (distributing the cost of the cornerstone intake reduction strategy across partners). Options A, B, and D all describe single-organization activities — they may be beneficial, but they lack the defining feature of coalition building: cross-organizational collaboration and shared resource investment."}],"cards":[{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what are the three components of all \"good\" adoption programs?","a":"a proactive screening process to match animals and people, an evaluation and matching system focused on providing a positive experience for the adopter, a mindset that places primary emphasis on education"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what are three important institutional attitidues?","a":"education, flexibility, committment to improvement"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"according to AHA what is an animal shelter's primary goal?","a":"to prevent animal suffering"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what things make adoption kennels more attractive to the public?","a":"plants, music, beds and toys, animals with names, cat shelves and hiding boxes, real life rooms, cat group housing"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what is the definition of \"atmosphere\"?","a":"the general feeling or spirit of the place"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what makes the first and strongest first impression on clients?","a":"frontline staff"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what are the five key areas for a successful adoption?","a":"the match is suited to the individual animal and family, the pet is afforded appropriate vet care, the pet's social/behavioral/companionship needs are met, the pet has a liveable environment, the pet is respected and valued"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"According to a study by Phil Kass, a cost of how much or more for an animal lowered relinquishment rates?","a":"100.0"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Adoption & Placement","q":"what is considered a good time period for offering a post-adoption veterinary care policy for animals that become ill after adoption?","a":"the first 15 days after adoption"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the definition of evidence based medicine?","a":"the use of the best\nrelevant evidence in conjunction with clinical expertise to\nmake the best possible decision about a veterinary patient.\nThe circumstances of each patient, and the circumstances\nand values of the owner/carer must also be considered when\nmaking an evidence-based decision."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the first step in EBM?","a":"consider the basis for one’s current clinical decision\nmaking and own internal biases"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are the five steps to EBM?","a":"ask, acquire, appraise, apply, and assess"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the \"PICO\" format for a clinical question?","a":"P=patient, problem, population, I = intervention or test of interest, C = comparison of interest, O = outcome"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"case series and case reports are what kind of studies?:","a":"descriptive"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the best type of study for answering a question about efficacy of treatment?","a":"randomized controlled clinical trial"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the best type of study for answering a question about risk factors for disease?","a":"cohort, case control or cross-sectional studies"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the best type of study for answering a question about diagnosis of a disease?","a":"diagnostic validation study"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the best type of study for answering a question about prognosis or incidence of disease?","a":"cohort study"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the best type of study for answering a question about prevalence of disease?","a":"cross-sectional study"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"]what is a systematic review?","a":"a high-level\nsummary of primary research on a particular research question\nthat attempts to identify, select, synthesize, and appraise\nall high-quality research evidence relevant to that question to\nfind an answer"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what determines a journal's impact factor?","a":"based on\nhow frequently the papers published in the journal are cited\nby other articles"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is an audit?","a":"a quality improvement\nprocess that seeks to improve patient care and outcomes\nthrough systematic review of care against explicit criteria and\nthe implementation of change."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in one large survey, what % of respondents reported loosing their cat in the last 5 years?","a":"0.15"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is a community cat?","a":"refers to any unowned freeroaming\ncat, including unsocialized feral cats, as well as\nsocialized strays, some of which were no doubt previously\nowned pet cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the percent of felines reclaimed by owners in the us? in canada? in the uk?","a":"2%; <5%; 1.4%"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in two studies what percent of cats came to a sehlter iwth a collar or other visibile form of id?","a":"0.14"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"during what time period after attaching a collar should a cat be monitored closely to ensure that it does not get it stuck in its mouth?","a":"the first 5 days"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"based on previous studies, is there a type of collar that stays on cats better?","a":"no, all performed fairly consistently"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what does RFID stand for?","a":"radiofrequency identification\ndevices"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the ISO microchip frequency?","a":"134.2khz"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in a large study, what percent of animals scanned more than\nonce were found to have microchips on subsequent scans that\nwere undetected on initial scanning","a":"0.13"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in a study of 500 cats, how often were microchips identified in a non traditional area suggesting migration?","a":"0.006"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in a large study of dogs and cats how frequently did microchips migrate?","a":"0.016"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are frequent sites for microchip migration?","a":"lateral elbow and shoulder"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what kind of system is used in these cases to designate triage categories,\ninitial cat temperament, and other conditions that determine\nplacement and housing within the shelter.","a":"color coding"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the purpose of the critical triage team?","a":"to identify\nany animals in need of urgent care."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"who comprises the forensics examination team?","a":"a vet, scribe, and animal handler"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the forensics examination team responsible for?","a":"examination of all animals"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"within what time frame should all the animals be examined?","a":"72 hours"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is one of the most important and often overlooked on site assessments that should be made?","a":"evaluation and continuous monitoring\nof stressors on the cats."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"T/F: Seperation of cats from these situations by infectious disease is necessary and recommended.","a":"False, since they normally already have had exposure this is not recommended or necessary and may cause more stress to the cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what things should be included in the series of photographs taken for an animal?","a":"Thephotographs should begin with the case information, including\nthe case number, date, and animal ID written on a card\nor dry erase board."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"T/F: It is preferable to use designations of neonatal, juvenile, adult, or geriatric\nwith documentation of the basis for the determination","a":"True, unless you can appropriately identify the age based on dentition or ocular changes"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how frequently is coccidiosis found in large-scale cat cruelty cases?","a":"23% for cats with diarrhea, 33% for clinically healthy cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"T/F: for large scale cruelty cases, it is recommended to test cats\nfor FeLV and feline immunodeficiency virus (FIV) based on\nthe guidelines established by the AAFP","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the most common medical findings?","a":"URTD"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f:  dermatophyte testing is routinely recommended on\nintake of cats or for those without dermatologic lesions","a":"False, it is not recommended if skin lessions are not present"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is a common hair coat findings related to nutritional deficiency?","a":"A common\nfinding is a sparse, dry, dull, and brittle hair coat with hairs\nthat epilate easily"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what leads to a \"red coat\" in cats?","a":"In cats, decreased melanin deposition\ndue to amino acid deficiencies results in a reddish cast\nto the hairs, sometimes called red coat"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are the three most prevalent feline viruses in animal shelters?","a":"FPV, FHV, FCV"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the range of reported URI in cats in shelters?","a":"26-44%"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what was the reported prevalence of FHV?FCV?","a":"38%, 36%"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in a study of antibody titers at intake to an animal shelter, what range of cats did not have antibodies present to FPV, FCV, and FHV?","a":"60-89%"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: vaccination for FHV and FCV can increase non-specific immune responses that have been shown to decrease the clinical severity of bordetella infection on exposure?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how long does it take to get protection from the newer multivalent intactivated FCV vaccine?","a":"1 week after the second injection of two given 3-4 weeks apart"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: There is no evidence that concurrent\nuse of intranasal and parenteral vaccines will result in\ndecreased efficacy and some evidence that there may be an\nadded protective benefit.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how many days after MLV vaccination is antibody present for FPV, FHV, FCV?","a":"3 days, 4 days, 7 days"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how late has MDA interference for FPV, FHV and FCV been reported?","a":"20 weeks, 17 weeks for both"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"why is it not recommended to vaccinate younger than 4 weeks of age with a MLV?","a":"risk of cerebellar hypoplasia"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"the correlation of length of stay and upper respiratory disease was greatest for what age group?","a":"kittens < or equal to 6 months"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what feline characteristic is highly associated with protective FPV antibody titers?","a":"being neutered"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what has been correlated with protective FHV titers?","a":"increasing age, being neutered"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What has been correlated with protective FCV titers?","a":"increasing age, being an owner surrender"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"are kits designed for\nthe detection of canine parvovirus antibodies in serum or\nplasma able to detect those against FPV?","a":"no"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how long after MLV vaccination may a cat test weak positive on the canine parvo elisa?","a":"up to 14 days"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is a legal concern related to employees fostering animals?","a":"the fair labor standards act, fostering may be too similar to their job duties to qualify as unpaid time"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: retroviral testing is highly recommended for all cats/kittens entering foster care.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the minimum personnel needed for a kitten nursery?","a":"at least one full time staff member"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the primary focus of any nursery set-up?","a":"to minimize exposure to infectious disease by having multiple small rooms that can serve as quarantine and isolation"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"if the nursery cannot be staffed 24 hours, what kittens should it provide for?","a":"4 weeks and older and queens with nursing litters"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what environmental temperature do kittens need during the first week of life?","a":"86-90oF"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"over the next three weeks what can temperature be reduced to?","a":"75oF"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is considered normal daily or weekly weight gain for kittens?","a":"10-15g per day, 50-100g per week"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when is neonatal sepsis most common?","a":"the first 3 weeks"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what does the term MEMO stand for?","a":"multimodal environmental modification"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are macroenvironmental aspects that may be stressful for cats?","a":"lighting, temperature, odor, noise"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what should the goal noise level in cat housing be?","a":"less than 60db"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the thermoneutral zone for a cat?","a":"85-100 oF"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are microenvironmental factors that may be stressful to cats?","a":"anything inside the cage, type of litter/litter pan, flooring, food, etc"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in the authors opinion which is more important, quantity or quality of the space in a cage?","a":"quality"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what does the acronym SMARTR goals mean?","a":"goals are Specific, Measureable, Actionoriented,\nRealistic, Time-Driven/Timely, and Rewarded"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how many different genetic 'races' of cats are there worldwide?","a":"11.0"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the definition of anesthestic death?","a":"death where surgical or pre-existing\nmedical causes did not solely cause death"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is a definition for morbidity?","a":"any complication, excluding death, occurring during\nthe perioperative period,” and these have been classified into\n“minor,” “intermediate,” and “major” groupings"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when do most deaths occur?","a":"post-operatively, 61% of all deaths occured then for cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when is the most critical time for death to occur?","a":"first 3 hours after the end of anesthesia"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: a large study indicated that the \"risk of anesthesia\" was significantly higher in healthy cats than in healthy dogs","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how high can the prevalence of cardiomyopathy be in clinically \"healthy\" cats?","a":"up to 15%"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Cats that weigh less than ___ kg are\nat high risk for anesthetic-related mortality with more than\n15 times greater odds of death as compared to cats weighing\n___ to ___ kg","a":"2; 2-6"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"cats older than _____ were twice as likely to die from anesthesia when compared to cats 6months to 5 years old","a":"12 years"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: hypothermia can lead to increased intraoperative bleeding?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: the use of IV fluids increased the risk of death by 4 fold for both healthy and sick cats","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"one study indicated that the best location on a cats body for a pulse oximetry probs was _______","a":"cats rear paw"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"t/f: for short procedures (<30min) one study found that intubation increased risk of death","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how should one treat anaphylaxis?","a":"place IV catheter, administer 0.1 ml of a 1:1000 dilution IV epinephrine, Administer 20–30 ml/kg balanced isotonic crystalloid by slow infusion\nover 10 mins, Administer an H1-blocker: eg, diphenhydramine, 2 mg/kg IM or IV, Administer soluble glucocorticoid: eg, methylprednisolone sodium\nsuccinate, 30 mg/kg IV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p17","a":"Activity depression, hyperactivity, stereotypic behavior, frustration, and barrier aggression are all __________________."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p18","a":"The goals of ______________ are to minimize infectious dz and problem behaviors while optimizing the physical and behavioral health of the animals and preventing transmission of zoonotic diseases."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p20","a":"Minimum database  for cats and dogs prior to adoption? Extras for geriatric animals?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p21","a":"Times at which animals should be scanned for a microchip (3)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p22","a":"At minimum rounds should be conducted ______(times per day) to observe each individual animal as well at its environment for signs of health problems"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p23","a":"Dz management protocols should include the following (4) features"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p24","a":"Why are intranasal FVRCP vax not recommended for use (instead of parenteral) in shelters?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch2p26","a":"Vaccines not generally recommended for use in shelters"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p27","a":"Dosage of pyrantel and timing of administration"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p28","a":"Frequency of international standard microchips?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p30","a":"Give 3 examples of behavioral coping strategies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p31","a":"Define time period of a long stay in a shelter."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p33","a":"_________ is one of the most critical needs for mental health and well-being in animals."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p34","a":"Incoming animals should be separated by (4) characteristics"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p35","a":"T/F: Quarantine areas should be used to segregate unhealthy animals from the general population."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p37","a":"T/F: Stressful events are less stressful if they are on a schedule"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch1p11","a":"How long after a stressful event does FHV recrudesce?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch1p12","a":"At what level should ventilation be measured?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch1p14","a":"What is the avg annual death (died in care) rate for animal shelters?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ch2p19","a":"List the 5 Freedoms"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch1p13","a":"How do you determine \"sick animal care days\"?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p39","a":"Stress, lack of vax, concurrent dz/parasitism and history or predation or scavenging are all _______."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p40","a":"Six main tasks of outbreak management?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p41","a":"When obtaining diagnostic samples in an outbreak of unknown etiology, you should pick (choose) acutely/chronically/un  affected animals to sample"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p42","a":"T/F: The release of low or moderate risk animals during an outbreak is not recommended."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p43","a":"Canine respiratory pathogens can be transmitted (a)______ feet, while feline respiratory droplet spread is (b)_____ feet"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p44","a":"T/F: A CDV outbreak is unlikely to be resolved through improved sanitation."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p45","a":"List of disinfectants proven effective against unenveloped viruses"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p46","a":"List of dzs for which prophylactic drug treatment of a population may be indicated during an outbreak"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch3p47","a":"Under what circumstances is strict quarantine of incoming animals indicated?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p49","a":"List the 3 basic principles of effective sanitation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p50","a":"What UW agency regulates the chemical disinfectant products?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p51","a":"What is the mechanism of action of quaternary ammonium compounds (QAC/quats)?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p52","a":"MOA of hypochlorites?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p53","a":"Peroxygen compound MOA? Examples: potassium peroxymonosulfate (Virkon S or Trifectant)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch4p54","a":"Sweeping, brushing, scraping are all examples of _________ in a sanitation protocol"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p62","a":"In serologic surveys it was found that approximately ______% of dogs are immunologically naive for CDV, ____% for CPV-2."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p63","a":"T/F: It is strongly recommended that all animals receive a second dose of rabies vax 1 yr after the first vaccination"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p64","a":"T/F: Because the type of immune response induced by MLV vax is robust and rapid, the routine use of vax products that contain other vaccine components, while not required, is acceptable. Examples include Chlamydophila felis, Feline Bordetella, Leptospira serovars, canine coronavirus, Lyme, etc."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p65","a":"T/F:  Animals who are sick at intake and vaccinated should be revaccinated as soon as they are healthy enough."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p66","a":"Killed vax should be used within _____ (time) after they have been removed from the fridge."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p67","a":"The recombinent CDV vaccine has an advantage in puppies b/c it will immunize them up to _____ weeks earlier than a MLV CDV vaccine. The earliest age at which a pup could receive the rCDV (monovalent) vax is _______."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p68","a":"T/F: CAV-1 contributes to CIRDC and can cause pneumonia. CAV-2, found in canine combination vaccine products, causes infectious canine hepatitis."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p69","a":"What is time to onset of immunity and duration of immunity for the feline calicivirus vaccine?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p70","a":"Why is a vaccine for virulent systemic calicivirus  (VSC) unlikely to protect against VSC infection or dz?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p71","a":"T/F: Ideally all animals should receive two doses of rabies vaccine, with the interval between doses being not less than 3 weeks and not more than 1 year."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p72","a":"T/F: If 2 doses of FeLV vax cannot be given, just the first dose will provide some protection against persistent viremia after infection."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p74","a":"Why shouldn't puppies/kittens less than 2 weeks be vaccinated with MLV or killed vax?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch5p78","a":"Why should a higher level of titer be required to suggest low risk for juvenile animals?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch6p84","a":"Rank the following sources from strongest to weakest sources of evidence:\ncase series\ncase-control studies\nexpert opinion without explicit crtical appraisal, or based on physiology, bench research, or \"first principles\"\nrandomized control trials\ncohort studies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch6p85","a":"How do systematic reviews differ from standard review articles?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch18p301","a":"what type of virus is rabies?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch18p302","a":"what are two types of rarely described tranmission of rabies to humans?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"ch18p303","a":"What is an acceptable titer for a vaccinated person?"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the point of counterconditioning?","a":"for the animal to associate pleasant things with a stimulus that currently\nfrightens them"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"where is psychogenic alopecia most commonly seen?","a":"ventral abd and medial limbs"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch4p11","a":"T/F: Animals euthanized with KCl can be left in the field to be scavenged"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch5p15","a":"Federal regulation of euth of nondomestic animals is limited to the _____ (law), which is enforced by the _________ (agency)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch6p20","a":"List 3 potential hazards for scavengers that might be present in the carcass of a euthanized animal"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch6p21","a":"T/F: Direct killing by lethal trapping techniques is an acceptable form of euthanasia in field conditions"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch7p24","a":"T/F: Physical methods of euthanasia that ensure death (e.g. exsanguination, decapitation) should be use as a final step when there is uncertainty as to whether death has been achieved by other methods"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p28","a":"T/F: Opioids are inffective for chemical immobilization of sharks"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p30","a":"T/F: Failure to list or recommend a means of euthanasia in the AVMA euthanasia guidelines does not categorically condemn its use"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p31","a":"T/F Clove oil is an acceptable chemical to euthanatize fish"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p33","a":"For fish euthanasia the recommended dose range is _____ mg/kg of sodium pentobarbital, administered by what route(s)?"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p34","a":"T/F: Decapitation or pithing are acceptable secondary methods of euthanasia in fish"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch9p35","a":"T/F Placing conscious fish in a freezer or on crushed ice is not considered an appropriate method of euthanasia"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch10p39-41","a":"Select which of the following are acceptable primary methods of euth for amphibians: inhalant agents, injection of barbiturates, injection of MS 222, immersion in MS 222, any physical method, slow freezing, immersion in liquid nitrogen"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch11p42","a":"The tissues of animals in the reptile group are more resistant to _______, and as such, methods of euth that induce ____ (same word)  without management of painful stimuli should not be recommended"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch11p43","a":"Name two drugs that are recommended for heavy sedation or tranquilization prior to the admin of euthanasia in reptiles"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch11p44","a":"T/F: Decapitation is acceptable as a sole method of euthanasia in chelonians"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch12p46","a":"_______(drug) is recommended prior to administering euthanasia drugs to birds to reduce pain and distress in clinical settings"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch12p47","a":"T/F Intracoelomic injection of barbiturate drugs is not recommended in birds"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch12p48","a":"T/F Bird eggs feel pain"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch14p53","a":"Holy shit! did you know wombats can weigh up to 35 kg?!"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch17p64","a":"Among the methods that ____ (choose: do or do not) meet the definition of euthanasia in rodents/small mammals are hypothermia/slow freezing, thoracic compression, strangulation, drowning, or other mechanical methods for asphixiation and air embolism."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch21p82","a":"T/F: Two stage euthanasia (sedation/analgesia followed by chemical or physical euthanasia) is preferred for hoofstock species."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch21p83","a":"What is the general dose of sodium pentobarbital for euthanasia of hoofstock?"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"ch21p84","a":"T/F Penetrating captive bolts are an acceptable sole method of euthanasia in hoofstock."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: What is considered abusive treatment in one species of animals may not be considered abusive treatment in another,","a":"True, human society hold different rules and exceptions for different types of animals"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What model of typology in deterimining if a companion animal case is abuse is used in veterinary medicine?","a":"the system developed by medical physicians for child abuse"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the four basic types of abuse used in the typology?","a":"physical, sexual, emotional, and neglect"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is physical abuse?","a":"the perpetrator subjects the animal to a variety of actions that causes physical harm"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Violent acts towards animals are more often carried out by women.","a":"False, men suck"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is sexual abuse?","a":"the use of an animal for sexual gratification, it is distinguished by the involvement of the sexual organs or rectum"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is emotional abuse?","a":"making regular threatening behavior, verbal harrassment, or failure to provide physchological comfort"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is neglect?","a":"a failure to provide the animal with the basic physical needs of life: food, water, shelter, failure to seek veterinary care for injury and illness"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"is there a sex of perpetrator or species that more commonly is neglected?","a":"no, all species by both men and women"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"who and when was it suggested that evidence of abuse in the family pet might be evidence of abuse in other family members?","a":"Hutton, 1983"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p38","a":"The most pathognomonic feature of abuse in animals is ______ injuries."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p48","a":"Give examples of gross or histological lesions that would be preserved after a body was frozen."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p55","a":"Fill in blanks with each: peripheral or central\nCollection of blood should be from ______ vessels for toxicology testing because of redistribution effectsts are are possible when taking blood from _____ vessels"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p56","a":"Choose: antemortem, ,perimortem, or post mortem\nThe presence of hemosiderin may be an indicator of __________ hemorrhage"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p57","a":"Recently studies have shown that measurement of h____ s_____ proteins may be used to determine the level  of agonal stress during the time before death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p59","a":"How can you differentiate antemortem and periomortem cut in bone?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p61","a":"Vultures start feeding approximately ________ hours postmortem"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p66","a":"Put the following conclusions terms in order from least certain to most certain\nreasonable possibilities\nabsolute certainty or certainty beyond a possible doubt\nspeculation\nreasonable degree of certainty\nthe preponderance of evidence or probable"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch3p74","a":"What is the maximum delay between seizure and examination of an animal by a vet"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p78","a":"How is human distinguished from animal hair microscopically"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p80","a":"T/F inbreeding alters the ability to match DNA to a specific individual in a population"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p83","a":"Can hair be used as a DNA sample for animals?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p85","a":"What is Munchausen syndorme by proxy"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p89","a":"What is distress?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch4p92","a":"What are the four categories of noxious stimuli?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p98","a":"T/F Blunt force trauma that causes internal injuries will always leave a mark on the skin"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p99","a":"How long after impact can lung contusions progress?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p100","a":"How can you differentiate a contusion from post-mortem lividity (blood accumulation?)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p101","a":"Can postmortem BFT cause contusions?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p103","a":"What is a distinguishing feature between an incisive wound and a laceration"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p105","a":"What % of dogs with shearing and degloving injuries have other concurrent injuries"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p106","a":"What is a sign that a bone fracture was acute"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p107","a":"What is the triad of injuries associated with high rise syndrome?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p110","a":"What does the presence of bilateral symmetrical skull bruising genrally mean"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p116","a":"What is always the cause of subdural hematomas?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch5p117","a":"What is the most common cervical vertebrae fracture"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch6p125","a":"How do you differentiate a wound from single-edge and double-edge blades"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch6p130","a":"What is the distinctive feature of a cutaneous dog bite wound"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch6p131","a":"What is the most represented dog breed in dog-bite related fatalities?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch6p133","a":"What species will often decaptiate their prey?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p139","a":"How long do burn injuries progress for without repeated injury"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p140","a":"How are burns classified"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p141","a":"What characterizes a 3rd degree burn"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p142","a":"When does ischemia appear on thermal bruns on histopath?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p143","a":"What are some suspicious post-mortem findings for microwave damage?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p145","a":"What is the most important factor in electrocution injuries"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"ch7p146","a":"Was is the pathognomonic sign of ligthning electrocution (name and description)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"chp147","a":"What are some indication of antemortem injuries in a burn victim?"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"181-183","a":"What are two diagnostic tests that can help for concordance with a drowning diagnosis"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is NIMS?","a":"National Incident Management System. NIMS is a \"consistent nationwide template to enable Federal, State, tribal, and local governments, NGOs, and the private sector to work together to\" prevent, respond to, recover from, and mitigate the effects of all possible incidents. \"NIMS is a core set of doctrines, concepts, principles, terminology, and organizational processes that...\" blah blah blah.  \"NIMS is about unifying how we resond.\" NIMS is NOT an operation incident management or resource allocation plan!!!!"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Preparedness, communications and info managment, resource mgmt, command and mgmt, and ongoing mgmt and maintenance are ______________","a":"Preparedness, communications and info managment, resource mgmt, command and mgmt, and ongoing mgmt and maintenance are  the components of NIMS that are designed to work together, not stand alone."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Select: before, while, after. Preparedness activities are conducted on an ongoing basis, ________________ a potential threat is present.","a":"Preparedness activities are conducted on an ongoing basis,before a potential threat is present."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"This component of NIMS provides a common operating picture to all command and coordination sites.","a":"Communications and Info Mgmt provides a common operating picture to all command and coordination sites."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"This component of NIMS is based on three key organizational constructs: The Incident Command System, Multiagency Coordination Systems, and Public information.","a":"Command and Mgmt is based on  three key organizational constructs: The Incident Command System, Multiagency Coordination Systems, and Public information."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The components of NIMS are adaptable and scalable to any situation, from routine local incidents requiring activation of interstate mututal aid, to those requiring a coordinated Federal response. NIMS applies to all types of incidents.","a":"T. The components of NIMS are adaptable and scalable to any situation, from routine local incidents requiring activation of interstate mututal aid, to those requiring a coordinated Federal response. NIMS applies to all types of incidents."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What did Homeland Security Presidential Directive (HSPD) 5 do?","a":"Direct secretary of homeland security to 1) develop and administer NIMs and 2) Develop the National Response Framework (NRF)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The National Response Framework (NRF) is what?","a":"The NRF is a guide to how the Nation conducts all-hazards response and builds upon NIMS to link agencies at different levels to align key roles and responsibilities across the Nation. THe NRF is designed to to ensure that local jurisdictions retain command, control and authority over response activities for their jurisdictional areas."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: A basic premise of NIMS and NRF is that incidents are typically managed at the federal level first.","a":"F. A basic premise of NIMS and NRF is that incidents are typically managed at the local level first"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Compliance with NIMS is not mandated for NGOs","a":"T. Compliance with NIMS is not mandated for NGOs. However adherence to NIMS can help these orgs integrate into a juridiction's preparedness efforts."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Preparedness component: ____________ provide a mechanism to quickly obtain emergency assistance in the form of personnel, equipment, materials, and other associated services.","a":"Mutual aid agreements provide a mechanism to quickly obtain emergency assistance in the form of personnel, equipment, materials, and other associated services."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"M__________ provides a crtitical foundation in the effor to reduce the loss of life and property and to minimize damage to the environment from natural or manmade disasters by avoiding or lessening the impact of a disaster.","a":"Mitigation provides a crtitical foundation in the effor to reduce the loss of life and property and to minimize damage to the environment from natural or manmade disasters by avoiding or lessening the impact of a disaster."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"C _______ s______  (component II of NIMS) need to be be\n-interoperable (within and across agencies and jurisdictions\n- reliable (able to function in any kind of emergency)\n- portable \n- scalable (suitable for use on a small or large scale incident)\n- resilient (able to perform despite damaged or lost infrastructure)\n- redundant ( able to use alternate methods when primary systems go out)","a":"Communication systems need to be be\n-interoperable (within and across agencies and jurisdictions\n- reliable (able to function in any kind of emergency)\n- portable \n- scalable (suitable for use on a small or large scale incident)\n- resilient (able to perform despite damaged or lost infrastructure)\n- redundant ( able to use alternate methods when primary systems go out)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Codes and acronyms should not be used in incident communications.","a":"T. The use of plain language in emergency management and incident response is a matter of safety, facilitates interoperability across agencies, jurisdictions and disciplines, and ensure that info dissemination is timely, clear, acknowledged and udnerstood by abll intended recipients.  Codes should not be used and all communications should be confined to essential messages. Avoid acronyms during incidents involving multiple agencies (oh the irony!) If needed, protocols for encrypted communications/tactical language should be incorporated into the incident mgmt communications plan."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"R_______ (NIMS component III) include personnel, equipment, supplies, and facilities.","a":"Resources (NIMS component III) include personnel, equipment, supplies, and facilities."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Define demobilization and recovery (NIMS compenent III, Resource Mgmt)","a":"Demobilization is the orderly, safe, and efficient return of an incident resource to its original location and status. Managers should plan and prepare for the demobilization process at the same time that they begin the resource mobilization process. Recovery, is the final disposition of all resources, including rehabilitiation, replenishment, disposal."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Credentialing takes place at the incident site in order to control access.","a":"F: Credentialing involves training, evaluation and documentation of personnel to esnure that they meet standards and are able to perform specific tasks unders specific conditions. Badging takes place at the incident site in order to control access."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Incident command system (ICS), Multiagency coordination systems, and public information are all elements that comprise the NIMS ______________  component (component IV).","a":"Incident command system (ICS), Multiagency coordination systems, and public information are all elements that comprise the NIMS command and mgmt component (component IV)."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The ____________________ is a standardized, on-scene all-hazard incident managment concept.  ______ allows its users to adopt an integrated organizational structure to match the complexities of incidents.","a":"The Incident Command System is a standardized, on-scene all-hazard incident managment approach.  ICS allows its users to adopt an integrated organizational structure to match the complexities of incidents."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: NIMS prompts the use of ICS for every incident or scheduled event.","a":"T: NIMS prompts the use of ICS for every incident or scheduled event.  Using ICS on all incidents helps hone and maintain skills needed for the large-scale incidents."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Every incident must have a written action plan.","a":"F. An Incident Action Plan (IAP) provides a concise, coherent means of capturing and communicating the overall incident priorities, objectives, and strategies. Every incident must have an action plan. However, not all incidents require written plans. THe need for written plans is based on the complexity of hte incident and the decision of the incident commander or unified command. Most initial response operations are not captured in a formal IAP."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"In ICS, the span of control should range from _____ subordinates, with ____ being optimal.","a":"The span of control should range from 3 to 7 subordinates, wtih 5 being optimal."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The secretary of the dept of homeland security is responsible for designating the invidual at the scene responsible for establishing command.","a":"F: The agency with primary jurisdictional authority over the incident (usually local) is responsible for designating the invidual at the scene responsible for establishing command."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Choose: chain of command, unity of command\n_______ refers to the orderly line of authority within the ranks of the incident mgmt organization\n_______ means that all individuals have a designated supervisor to whom they report at the scene of the incident","a":"chain of command, refers to the orderly line of authority within the ranks of the incident mgmt organization\nunity of command means that all individuals have a designated supervisor to whom they report at the scene of the incident"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F Spontaneous deployment of non requested resources is indicated prior to establishment of resource mgmt systems in large-scale incidents.","a":"F: Resources not requested must refrain from spontaneous deployment to avoid overburdening the recipient and compounding accountability challenges"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Area command is an organization that is always activated in order to oversee the management handled by an ICS organization.","a":"F: Area command is an organization that is activated only if necessary to oversee the mgmt of mutiple incidents handled individually by seperate ICS organizations. AC is particularly beneficial to incidents that are not site specific , are not immediately identifiable, are geographically dispersed, and evolve over longer periods of time (eg public health emergencies, earthquakes, tornadoes, civil disturbances), or when a number of incidents of the same type in the same area are competing for the same resources, such as multiple hazardous material spills or fires."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The incident Command and Mgmt organization is located at the _________, and is generally located at or in the immediate vicinity of the incident site. Typically one _______ is established for each incident.","a":"The incident Command and Mgmt organization is located at the Incident Command Post (ICP), and is generally located at or in the immediate vicinity of the incident site. Typically one ICP is established for each incident."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"In an incident command organization the command staff typically includes what 3 personnel? (Cheater mnemonic or make your own: command staff I command that you Please Stay Low)","a":"Command staff = \n--Public Information Officer (interfaces with the public and media and/or other agencies with incident related info requirements)\n-- Safety Officer (monitors incident operations and advices the incident commander on all matters relating to operational safety)\n-- Liasion officer (point of contact for representatives of other govt agencies, ngos, and the private sector with mgmt responsibilities)\n** Additional command staff positions may be added depending on incident needs and requirements (technical specialist, eg legal counsel, physician, etc). Technical specialists can be used anywhere in the ICS organization!\n*** These staff don't have direct operational responsibilities, but they may supervise a team of assistants"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"General staff, aka section chiefs, include what four positions typically? (Cheater mnemonic or make your own: In general, Please Open Letters Frugally)","a":"The general staff includes a group of incident mgmt personnel organized according to function and reporting the the incident commander and typically includes\n- Operation section chief: responsible for direct mgmt of all incident related tactical activities, directly involved in development of incident action plan. \n- Planning section chief\n-- Logistics section chief\n-- Finance/Administration section chief"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What staff member positions make up the Incident Mgmt Team (IMT)?","a":"The IMT is an incident command organization made up of the Command and General Staff members"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Rank the following from highest to lowest rank in the Operations Section:\nDivisions \nOperations Section Chief\nBranches\nResources\nGroups","a":"Section Chief-->Branches --> Divisions and Groups --> Resources\n--Branches may be functional and/or geographical. Only established  when the number of divisions or groups exceeds the recommended span of control\n-- Divisions divide an incident into physical/geographic areas of operation. Groups are established to divide the incident into functional areas of operation. Divisions or groups are established when the number of resources exceeds the manageable span of control. \n-- Resources may be organized as single resources, or by task forces (combination of resources) or strike teams (set number of resources of the same kind)\n--- When needed, the operations section expands from the bottom up (to maintain recommended span of control)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Which of the General Staff sections is responsible for collecting , evaluating, and disseminating incident situation info and intelligence for the Incident Command and mgmt peresonnel? Tasks include preparing status reports, displaying situation information, maintaining the status of resources assigned to an incident, preparing and documenting the Incident Action Plan?\nChoose: Planning section, operations section, logistics section, or finance/admin section","a":"Planning section"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The resources unit, stiuation unit, demobilization unit, documentation unit are all primary unit overseen by what section chief?","a":"Planning section chief\n- resources unit: records status of resources committed to the incident and anticipates resource needs\n- situation unit: collects, organizes, and analyzes incident status information and progression of the incident\n- demobilization unit: responsible for orderly safe and efficient demobilization of all incident resources\n- documentation unit: collects, records, safeguards all documents relevant to the incident"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Which section is responsible for all service support requirement needed to faciliate effective and efficient incident mgmt, including ordering resources, providing facilities, sercurity, transportation, supplies, equipment maintenance, food, fuel, communications/IT support, medical services for first responders?","a":"Logistics section"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"THis section is established when the incident mgmt activities require on-scene or incident specific finance and other admin support services. Deals with compensation/claims, tracking costs and analyzing cost data, recommending cost-saving measures,  financial aspects of vendor contracts, and recording time for personnel and hired equipment.","a":"Finance/Admin section"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The National Integration Center (NIC) administers and oversees training, standards and credentialing, and publication management in support of organizations at all levels that are implementing ________","a":"NIMS"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Fill in the blanks by choosing from the following: estrus, diestrus, proestrus  \n\"During ______ and _______, the vulva is swollen to two or three times its normal size, appears turgid, and has a hemorrhagic to straw-colored discharge. The swelling and turgidity diminish during ______>\"","a":"estrus and proestrus; estrus and diestrus"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F:  Pure growth of bacteria from vaginal specimens can be normal unless accompanied by signs of repro tract dz\"","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Persistent vaginal discharge is an indication for ________ (zoonotic dz) testing","a":"Brucellosis"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Measuring __________ help distinguish between neutered and intact bitches (Choos: estradiol, luteinizing hormone, progesterone)","a":"Luteinizing hormone: measuring a single low LH test result indicates a sexually intact bitch. FYI FSH is also low in intact bitches"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"A neutered male dog would be expected to have less than ______ (#) ng/ml concentration of testosterone in serum","a":"Neutered < 0.1. Crypt 0.1-0.5, intact 0.5-9"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The most common pathogen in pyometra","a":"E coli. E. coli has an affinity for the endometrium and myometrium. The most commonly isolated organisms are nalso normal vaginal flora.  May also ascend from fecal contam or UTI"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The best antibiotic for prostatic infections is _________","a":"based on  C & S and ability to cross  blood-prostate barrier. Examples: erythromycin, clindamycin, TMS. Enrofloxacin and Doxy concentrate in prostate and work against some resistant gram neg pathogens."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The right ovary lies dorsal to the (1)__________ and the left ovary lies dorsal to 2)______________ and lateral to 3)________","a":"Right 1) descending duod  Left  2) descending colon  3) spleen"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The glans of the feline penis is covered with caudally directed cornified spines which are more prominent in intact males and regress within _________ (time) of castration","a":"6 weeks"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: EArly neutering hastens growth plate closure by an average of 8 to 9 weeks.","a":"F: It DELAYS growth plate closure by 8-9 weeks"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Bitches are at a greater risk to develop urinary incontience if OHE is performed before __________ (age)","a":"3 months of age"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: After 7 weeks of age, anesthesia recovery is more rapid than in older animals","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"What is the difference between a close and open castration? (what is cut in open vs closed?)","a":"Parietal vaginal tunics overlying the testical are incised in open castration"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Although the risk of ligature slippage and loosening may be slightly greater with closed than open techniques, removal of the tunics may reduce post operative swelling","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"There is little hope of further testicular descent after _______(age)","a":"2 months of age"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Neonatal survival with en bloc  resection (removal of uterus prior to hysteotomy) is is similar to that for other techniques for managing dystocia.","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The main disadvangtage of an en bloc OHE technique for dystocia is ___________","a":"a second team is require to resuscitate the neonates"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F Drainage of amniotic fluid into the bitch's abdomen during a C-section is not a concern","a":"F"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Describe a  scenario during a spay surgery with a high risk for ureter ligation","a":"Ligating a dropped or hemorrhaging ovarian pedicle"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"If an ovarian remnant is present, abdominal exploration during what stage in repro cycle  may help identify the ovarian tissue?","a":"Estrus"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Fistulous tracts and granulomas may form if nonabsorbably multifilament suture is used for ligations.","a":"T. Usually located in the flank, or along meidal thigh or inguinal region. The intermittently discharge blood-tinged fluid or mucopurulent exudate which recurs after antibiotic therapy. They will not resolve until the suture material is removed. Beward adhesions to vena cava or other vital structures."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Rate of urinary incontinence after OHE- generally and for those spayed before 3 months of age","a":"generally 5%, those less than 3 months: 13%. Causes of incontinence = low estrogen levels, uterine stump adhesions to urinary bladder, or vaginoureteral fistuale."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F : Hypothermia, hypoglycemia, blood loss and tissue handling problems occur more commonly in prepubertal OHE","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Spermatozoa persist after castration for  up to _____ days in dogs and ____days in cats in the ductus deferens.","a":"dogs: 21 days\ncats: 49 days"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Any colored uterine discharge post parturition warrants further evaluation for possible uterine infection","a":"F: Odorless, dark red-brown to serous uterine discharge or lochia is expected for 4-6 weeks postpoartum"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Label the following conditions\nAn accumulation of purulent material within the uterus\nUterine distension with sterile watery fluid\nUterine distension with sterile mucoid secretions\nUterine distension with bloody secretions","a":"Label the following conditions\nAn accumulation of purulent material within the uterus - pyometra\nUterine distension with sterile watery fluid - hydrometra\n Uterine distension with sterile mucoid secretions -mucometra\nUterine distension with bloody secretions-hematometra"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Cystic endometrial hyperplasia and pyometra both develop during what stage in the repro cycle and are driven by what hormone?","a":"Diestrus (lasts ~70 days), driven by progesterone. Progesterone inhibits myometrial contractility, creates abnormal uterine environment that allows bacterial colonization to cause pyometra."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"How long after estrus or exogenous administration of estrogens (dogs) or progestins (cats) does pyometra occur in cats? In dogs?","a":"Cats: 1-4 weeks\nDogs: 4-8 weeks"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"The risk of an intact bitch developing pyometra before 10 years of age is ___________%","a":"23-25%"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Cats treated with progestins for skin disease have an increased incidence of pyometra","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Pyometra is often associated with systemic inflammatory response syndrome cause by production and release of inflammatory mediators with systemic effects","a":"T Criteria for Systemic Inflam Response syndrome (SIRS if 2 of 4 present)\n- heart rate > 160 bpm\n- temp > 103.5 or less than 100 (\"fever is infrequent\")\n- resp rate > 20 bpm\n- WBC count > 12,000/uL, less than 4000/uL, or > 10% band neutrophils"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"List common abnormalities in animals with pyometra","a":"hypoglycemia (transient hyperglycemia), renal dysfuntion, hepatci dysfunction, anemia, cardiac arrythmias, coagulation abnormalities"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"FEtal calcification can be identified after approximately _____ days gestation","a":"45 days"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Normal white blood cells are often seen with closed pyometra, while open pyos usually exceed 50,000/uL and may be as high as 100 to 200,000","a":"F: closed pyos have high numbers of WBCs, open may be normal.  HOWEVER, \"do not rule out pyometra in animals with leukopenia or normal white cell counts. Sequestration of neutrophils in the enlarged uterus may cause neutropenia despite severe infection.\""},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: Antibiotic therapy following OHE for pyometra should be continued for 21 days.","a":"F: Antibiotics should be continued for 10-14 days."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Vaginal prolapse/hyperplasia occurs during which stage in the reporductive cycle?","a":"Estrus or pro estrus."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"FYI no question: quick review of canine repro cycle: http://www.ansci.wisc.edu/jjp1/ansci_repro/lec/lec_26/lec26out.htm","a":"Estrous Cylce (Non-Pregnant)\n--Proestrus (9 days)\nVulva swollen\nBloody discharge\nAttracted to male but does not mate\n--Estrus (9 days, ovulation day 2)\nAccepts male\nStraw-colored discharge\n--Metestrus or Diestrus (90 days)\nFalse pregnancy\n-- Anestrus (5 months)\nSexual inactivity\n-- Pregnancy lasts 63 days from time of ovulation"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Choose one: older dogs (>10 years), young dogs (<= 2 years): Most vulvar-vaginal tumors occur in ______ (fibroleiomyoma, lipoma, leimyosarcoma, scc, tvt), while vaginal prolapse/hyperplasia most commonly occurs in _____","a":"Most vulvar-vaginal tumors occur in older dogs (fibroleiomyoma, lipoma, leimyosarcoma, scc, tvt), while vaginal prolapse/hyperplasia most commonly occurs in young dogs (during one of their first 3 estrus cycles)."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"T/F: If protrusion of vaginal tissue is not circumferential the prolapse will spontaneously resolve when estrogen influence diminishes.","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"What is the treatment of choice (drug and dosage) for transmissible venereal tumors (TVT)?","a":"Vincristine 0.025 mg/kg up to 1 mg or 0.5 mg/m^2 IV, weekly for 3-6 weeks"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"How long after OHE and prolapse correction can vulvar sutures be removed?","a":"5-7 days"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"______ is the most common canine prostatic disorder; age-related, it occurs in 95% of male dogs by 9 years of age.  Dogs may have tenesmus, hematuria, and/or urethral bleed.","a":"Benigh prostatic hyperplasia (BPH)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Castration permanently involutes and enlarged prostate (BPH) within _________ weeks","a":"3 to 12 weeks"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"Define phimosis, and when it might be encountered in a shelter environment","a":"Phimosis is the inability of the penis to protrude from the prepuce. It can occur due to trauma from neonates nursing on each others genital region. It can cause preputial irritation and infection secondary to urin pooling within the prepuce. Medical mgmt includes warm compresses, antibiotic therapy, and urine diversion with a catheter, and daily saline lavaging.  Surgical treatment involves reconstruction of the preputial orifice"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are the 5 basic elements required of humane euthanasia?","a":"1. compassion, 2. knowledge, 3. technical skills, 4. appropriate application drugs and techniques, 5. wisdom to know when it should be performed"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is euthanasia?","a":"the act of inducing a painless death (literally means 'good death')"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"since 1986, what has the AVMA concluded is the preferred method of euthanasia for dogs, cats, small animals, and horses?","a":"iv injection of barbituric acid derivatives"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are  a few disadvantages of sodium pentobarbital?","a":"it is federally controlled substance with high abuse potential, it requires close contact with the animal, it generally requires two staff to administer"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is conciousness?","a":"When conscious, an animal has the ability to deliberately and intentionally respond to environmental stimuli."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is unconciousness?","a":"When rendered unconscious, the animal lacks awareness and the capacity for sensory perception, appearing to be in a deep sleep."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is tranquilization?","a":"When tranquilized, the animal usually is calm and relaxed, and he may even fall asleep. The animal may still feel pain, however, and a tranquilizer may not offer enough of a calming effect to safely handle a fractious animal. Tranquilized animals may also suffer seizures, and can be more unpredictable."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is sedation?","a":"the animal falls into a sleep-like state and becomes uncoordinated, with relaxed and unresponsive muscles. There is often a decreased ability to feel pain, but pain sensations are still possible. Sedated animals may appear to be sleeping but may quickly become aroused when stimulated by light or sound and cause harm to themselves and the humans around them."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is immobilization?","a":"the animal is essentially paralyzed and unable to move. However, while the animal appears to be unresponsive to sight and sound, he may still feel deep pain and may actually be experiencing fear and panic as he remains aware of his surroundings. For this reason, immobilizing agents are never appropriate for use in euthanasia"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is analgesia?","a":"Drugs that are intended to diminish an animal’s ability to perceive pain, although not all drugs can extinguish pain completely. Moreover, just because a drug has an analgesic effect does not mean that it causes unconsciousness in the animal. Therefore, the ideal pre-euthanasia drug is both an analgesic and an anesthetic"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is an anesthetic?","a":"the animal is ideally rendered unconscious, has a total loss of ability to feel pain (analgesia), and is immobilized, yet her vital functions (breathing and heartbeat) are retained. For this reason, the ideal pre-euthanasia drugs are anesthetics that, when used at proper dosages, achieve all of these ideals"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what class of drugs is sodium pentobarbital from?","a":"barbiturates - it is a medical hypnotic"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what happens when the drug is given at a low dose?","a":"causes short-term unconsciousness and loss of pain - can be used as a surgical anesthestic"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how rapidly does IV sodium pentobarbital take effect?","a":"within five seconds after injection into a vein the animal is unconscious, within 20 seconds the animal stops breathing, within 40 seconds the animal is considered “medically dead” (meaning the heart has ceased circulating blood), and within two minutes the animal is “clinically dead"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are the two formulation available for canine use?","a":"sodium pentobarbital alone (Fatal plus, euthanasia-6) or combined with phenytoin sodium (euthasol, beuthanasia)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what does phenytoin sodium do?","a":"it is an anticonvulsant drug that decreases abnormal electrical activity in the brain, when combined it hastens cardiac arrest and makes sodium pentobarbital unsuitable for acheiving a safe \"high\" - combination is only approved in dogs and not approved for IP injection"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"during stage 1 or voluntary excitement, the drug moves through which portion of the brain decreasing the animals ability to feel pain?","a":"cerebral cortex (also lose voluntary motor skills and inhibition)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"during stage 2 or involuntary excitement, which portion of the brain is affected causing uncontrolled motor activity?","a":"cerebrum"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"during stage 3 or surgical anesthesia, which part of the brain is affected, removing all pain feeling and responses to stimuli and relfexes?","a":"cerebellum"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"during stage 4 or medullary paralysis the drug enters what part of the brain where it depresses the core functions of breathing, heartbeat and blood pressure?","a":"medulla oblongata (brain stem)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is agonal breathing?","a":"the body's reflexive attempt to address its shortage of oxygen"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"True/Fasle: The dosage on the label is actually 30-50% higher than the actual lethal dose","a":"True, the extra drug is intended to serve as a cushion to ensure that the animal does die humanely"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are advantages of IV injection?","a":"can use on any age or species, can use on consious or unconsious, minimal distress or pain, rapid death, can hold and comfort the animal"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are disadvantages of IV injection?","a":"close onctact required, difficulty of accessing a vein, hard to use on very small animals"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"True/False: the preferred method for humanely euthanizing well-socialized dogs is direct IV injection of sodium pentobarbital without administration of any pre-euthanasia drug","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"True/False: Cats tend to resist even the gentle restraint associated with IV injection, so IP (intraperitoneal) injection is often preferred over IV for conscious, well-socialized cats","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are the four pairs of veins that can be used for IV injection?","a":"Cephalic, lateral saphenous, medial saphenous, jugular"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"when would a medial saphenous injection be preferred?","a":"unconcious cats"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"should jugular injections be performed in dogs/cats? in horses?","a":"should be avoided in dogs and cats due to stress of handling and potential for injection problems; prefered vein in large animals and horses"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Technicians should _____ apply alcohol to the shaved legs of conscious animals before injection","a":"never, water can be used instead since alcohol will cause stinging"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"why do we hold the syringe with the bevel up when going IV?","a":"so that the sharpest part of the needle punctures the skin first, ensuring a clean puncture"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"why does injection outside the vein cause pain?","a":"the pH level of the drug is higher than that of blood and because the tissue surrounding the veins is rich in nerve endings"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what patients are not good candidates for IP injection?","a":"late-term pregnangt animals, adult dogs, puppies over 5 weeks of age since they are more likely to experience a panic/excitement response"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how long does death by IP injection normally take","a":"less than 10 minutes"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the dosing for IP injection?","a":"triple the IV drug dose"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"where should an IP injection be made?","a":"on ventral midline just below the umbilicus on the linea alba to avoid nerves"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"A minimum dosage of ____ ml of sodium pentobarbital should be used on any animal under 3 pounds","a":"1ml"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what characteristic body motion is typically seen about 2 minutes after IP injection?","a":"tounge-flick"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how does one confirm that an animal is fully unconcious?","a":"no palpebral reflex and no toe-pinch reflex"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what intercostal spaces are appropriate for IC injection?","a":"the lower side of the 3rd, 4th, or 5th intercostal spaces"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the goal and dosage of oral administration of sodium pentobarbital?","a":"to sedate aggressive animals to a point where direct injection can be managed, 3x IV dosage\\"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are limitations of oral administration","a":"large dose, very bitter taste, illegal in some states"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are currently the prefered pre-euthanasia drugs?","a":"telazol or combo xylazine and ketamine"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are complicating factors for xylazine/ketamine premix?","a":"injection stings, drugs can cause vomiting and seizures, ketamine is controlled, mixing the two in some states is compounding"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the ratio of xylazine to ketamine?","a":"1:5"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the premix dosage?","a":"0.5ml per 10 lbs, should take effect in 3-5 minutes and give 30-40 minutes of sedation"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are two benefits fo telazol?","a":"stings less and less likely to cause seizures"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are disadvantages of telazol?","a":"expensive, short half life after reconstitution (only good for 4 days at room temp), must be refridgerated (lasts up to 14 days)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what schedule drug is telazol?","a":"schedule 3"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are other potential premeds that are not preferred?","a":"acepromazine, xylazine (alone), ketamine (alone)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"why is isoflurane a less desirable inhalant option than halothane?","a":"because of its pungent odor"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the only indisputible proof of death?","a":"the onset of rigor mortis"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the 'caring-killing' paradox?","a":"To complicate matters further, euthanasia technicians must suffer the additional psychological burden of being the only caretakers who often are called upon to end the lives of the very victims for whom they have provided care."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what regulations control use of sodium pentobarbital in the US?","a":"the Controlled Substance Act (part of the Comprehensive Drug Abuse Prevention and Control Act), passed in 1970 and enforced by the U.S. Drug Enforcement Administration (DEA)."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what schedule drug is sodium pentobarbital?","a":"schedule 2"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how often does federal law require a full inventory of controlled drugs be performed?","a":"every 2 years"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the dose of sodium pentobarbital for rabbits?","a":"2ml per 10#s IV, 6mls IP - they have a higher metabolism so take more drug"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"where should birds be injected with anesthesia before before euthanasia?","a":"muscle mass overlying the breastbone"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"where does one inject a bird with sodium pentobarbitol?","a":"injected into the body cavity directly below the keel perpendicular to the body can inject into the vein"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"why does euthanasia of reptiles take longer than mammals?","a":"slower metabolic rate"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how should you confirm death in a reptile?","a":"leave the body at room temperature overnight (whenever relying on rigor mortis to verify death it is best to cover the animal with a towel). Within 12 hours, the eyes should be dull and sunken, and the limbs, head, and neck should be limp (or extremely stiff, if the cycle of rigor mortis is incomplete); if this isn’t the case, the animal may not actually be dead, and additional sodium pentobarbital should be administered."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the recommended way to euthanize a reptile?","a":"premix dosage 4x that recommended for dogs or cats and then sodium pentobarbital IC, IV or into the abdominal cavity"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"where can the heart of a snake be located for an IC injection?","a":"the heart of a snake can be located by visually observing the heartbeat in between the first and second thirds of the underside of the body"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is an IV injection option in a snake?","a":"ventral tail vein"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"when would gunshot be an appropriate method of euthanasia for a crocodillian?","a":"when the animal is over 4 feet long and must be euthanized outside of the shelter environment"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the most practical way to euthanize fish in a shelter?","a":"dissolve 6 mls of sodium pentobarbital into a quart of water and introduce the fish"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how can one administer sodium pentobarbital to an amphibian?","a":"simply allow it to be absorbed through the skin - place 3mls per 10#s on the skin"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are considerations for xylazine for horses compared to ruminants?","a":"horses are more likely to kick on it, ruminants are very sensitive to it and it is the preferred pre-euth drug"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the best pre-euthanasia drug for a pig?","a":"telazol"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what peripheral vein may be an injection option in a pig?","a":"the large ear vein"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"under what field conditions is use of a fire arm appropriate?","a":"a properly trained officer may elect to dispatch the animal by gunshot, provided he or she is: a) trained and certified in the use of the weapon; b) certain that the discharge of the firearm will pose no threat to the public; and c) confident in hitting the exact spot necessary to ensure that the animal dies instantaneously without enduring further suffering"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"when using a handgun, what is the appropriate method of aiming and bullet type?","a":"2 inches away from the animals head, round nose lead bulltes"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"which type of gun is the best euthanasia option?","a":"shotguns"},{"type":"card","domain":"General","sub":"General","q":"Welf/Housing","a":"Vinke 2014: While shelter cats with and without hiding boxes had equal stress scores by day 14 after intake, the cats who had hiding boxes reached this level by day _______ after intake"},{"type":"card","domain":"General","sub":"General","q":"Sanitation","a":"Addie 2015: Why are cats susceptible to toxicity from phenol based disinfectants and many essential oils?"},{"type":"card","domain":"General","sub":"General","q":"In/Out/LOS","a":"Levy 2014: In a targeted area 54% of the projected community cat population was neutered via trapping/neutering and return or removal for adoption. how did shelter cat impoundment compare in the target area compared to the non-target area?"},{"type":"card","domain":"General","sub":"General","q":"PH/Zoon","a":"Amar 2014: T/F Dogs with diarrhea have a high prevalence of Campylobacter jejuni detected"},{"type":"card","domain":"General","sub":"General","q":"Anesth","a":"Stevens 2013: How did the pain scores of dogs administered 1 mg/kg each of lidocaine and bupivicaine intratesticular block vs placebo solution at 15 min, 60 min, 120 min and 24 hr post recovery from anesthesia?"},{"type":"card","domain":"General","sub":"General","q":"Sterilization","a":"Kutzler 2015: What are the mechanisms by which CaCl2 induces infertility in testicles?"},{"type":"card","domain":"General","sub":"General","q":"HVHqSN","a":"Levy 2017: What was overall perioperative mortality in the clinic assessed? How did it compare for \n-- cats vs dogs\n-- males vs females"},{"type":"card","domain":"General","sub":"General","q":"Analgesia","a":"Benito 2016: As compared by the need for rescue analgesia post routine OHE, how well was pain controlled up to 8 hours following surgery in cats receiving intraperitoneal bupivicaine compared to the receiving post op meloxicam?"},{"type":"card","domain":"General","sub":"General","q":"Anesthesia","a":"Porters 2015: cats undergoing routine gonadectomy who received IM induction vs transmucosal administration of dex + buprenorphine with IM ketamine. T/F cats receiving the TM protocol had poorer anesthesia and more adverse effects compared to cats who received all drugs IM."},{"type":"card","domain":"General","sub":"General","q":"Pain assesment","a":"Hoglund 2016:How did the post operative resp rates and heart rates vary between cats undergoing flank spay  with vs without pre operative NSAID (carprofen or meloxicam)?"},{"type":"card","domain":"General","sub":"General","q":"Cruelty/Forensics","a":"Gerdin 2016: T/F: In a study comparing necropsy findings in dogs who died of starvation vs a disease process, starved dogs more often had empty stomachs"},{"type":"card","domain":"General","sub":"General","q":"clinical med","a":"Papich 2013: The concentration of doxycycline compounded from  commertical tablets cannot be assured beyond ______ # days"},{"type":"card","domain":"General","sub":"General","q":"clincal med","a":"Slack 2013: T/F In cases of of cats with naturally occurring viral keratoconjunctivitis bilateral ocular administration of high doses of Feline Interferon omega twice daily for 14 days did not improve clinical disease or viral shedding."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the neonatal period for dogs?","a":"first two weeks of life"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what sensory cues do neonatal dogs respond to?","a":"olfactory"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what behaviors do neonatal dogs have?","a":"food seeking (swimming, kneading), discomfort (vocalization)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when is the transitional period for dogs?","a":"week 2-3 - eyes and ears open allowing for startle response"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when is the sensitization/socialization period for dogs?","a":"week 3-14"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is socialization?","a":"the process of adopting “behavior patterns appropriate to the social environment in which [an individual will] live, allowing them to coexist/interact with other individuals”"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Dogs show considerable exploratory behavior and approach novelty without hesitancy between ___ and approximately ___ weeks. As\nthey grow, they can show hesitation to novel stimuli, and at about __-___ weeks, this change magnifies, and some puppies display decreased comfort with new stimuli, like people, sounds, objects, and contexts","a":"3,5,8-10"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"During what period is it especially important to avoid exposure to noxious stimuli?","a":"8-10 weeks"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when does the American Veterinary Society of Animal Behavior recommend starting puppy socialization?","a":"as early as 7-8 weeks"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Daily gentle handling of puppies between 3-21 days old increased exploratory behavior and decreased vocalization in the puppies.","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What are the two type of questions posed by Niko Tinbergen for the study and characterization of behavior?","a":"“Why Questions,” commonly described as questions relating to ultimate causes of behavior, explore evolutionary forces behind behavior; “How Questions,” or questions relating to proximate causes of behavior, focus on a behavior’s immediate prompts, in both mechanistic and developmental terms"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what two things produce an individuals behavior?","a":"product of an individual’s life experiences (proximate explanations) and evolutionary history (ultimate explanations)."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Behavior is observable and measurable.","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the three main forms of communication that dogs use?","a":"acoustic, visual, and olfactory"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Approach behavior is associated with which brain hemisphere activation?","a":"right‐/left‐hemisphere activation"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Avoidance behavior is associated with which brain hemisphere activation?","a":"left‐/right‐hemisphere activation"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Tail movement directed towards the left or right can be called ______ and is more directly related to the dog emotional state. .","a":"Lateralized"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Positive stimuli may cause hte tail to wag more to the _____ while approach of an unknown dog may cause the tail to wag more to the ____.","a":"right, left"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when observing tail movement one should focus on what portion of the tail?","a":"the base not the tip"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a high tail indicate generally?","a":"excitement or arousal"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a tucked tail indicate generally?","a":"fear, submission, or appeasment"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what could a still tail indicate?","a":"fear or aggression"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"A low, fast tail wag may indicated _____ while a high, fast wags indicate ______.","a":"fear, submission or conflicted emotions; arousal"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"overall, tail position should be judged in what context?","a":"in relation to the tail’s normal, relaxed position, which will differ from dog to dog"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does piloerection indicate and can the animal control it?","a":"a state of arousal, no"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what do ears pressed back indicate?","a":"generally associated with greater levels of fear, submission, retreat, or even defensive aggression"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what do ears pressed forward indicate?","a":"suggesting interest, attention, alert, and approach as opposed to withdrawal"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a \"long lip\" indicate?","a":"where the commissure pulls back toward the ear, is often seen in fear, stress, or appeasement displays."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a \"short lip\" indicate?","a":"This is part of an aggressive display"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what might a reflexive tongue flick indicate?","a":"discomfort"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what can hard or whale eyes indicate?","a":"This hard, direct, unwavering appearance indicates threat, and the whale eye (with white sclera visible) can\nindicate discomfort or nervousness"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does \"offering a paw\" indicate for a dog?","a":"submissive or appeasing display"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the weight shifted forward over the front paws indicate?","a":"A dog with weight shifted forward, upper body pressed over the front legs, shows forward momentum, interest, confidence, or alertness"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are \"submissive\" canine postures?","a":"involve a reduction in perceived size, through lowered body and tail, pressing ears back, and, possibly, exposure of the inguinal region"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the vomeronasal organ do?","a":"directly involved in social communication and assessment of pheromones"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a displacement behavior?","a":"they constitute normal behaviors performed in an “inappropriate” context"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a stereotypic behavior?","a":"defined as behavior patterns that are repetitive, unvarying, and seemingly functionless"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a dominance relationship?","a":"in which one individual is more assertive and the other is more submissive—are not set in stone and are malleable"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"t/f: Dogs that have been previously kenneled show a decreased stress response than those kenneled for the first time.","a":"True (Rooney 2007)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F:  Moving dogs to a different area during cleaning (possibly for a walk, exercise, or training)showed no benefit or decrease in stress.","a":"0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What scents were associated with dogs resting more, which had no effect?","a":"Decrease = lavendar and chamomile; no effect = peppermint and rosemary and no scent"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what type of music has been previously associated with increased resting in dogs?","a":"classical music"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What is the most frequent interaction between dogs when they first meet?","a":"body sniffing"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what can the return of a familiar person to a room cause to happen in a dog?","a":"oxytocin release"},{"type":"card","domain":"General","sub":"General","q":"ch1p10","a":"Which of the following microchip frequencies are compliant with the International Standards Organization (ISO)?  Which has been the most commonly used in the United Staes for the past 2 decades?\n125 kHz, 134.2 kHz, and 128 kHz"},{"type":"card","domain":"General","sub":"General","q":"ch2p11","a":"T/F: Median RTO rates are significantly higher for microchipped pets vs non microchipped pets"},{"type":"card","domain":"General","sub":"General","q":"ch2p14","a":"Within the Asilomar Accords how is LRR calculated? How do intelligent people calculate LRR? How is this different than \"save rate\"?"},{"type":"card","domain":"General","sub":"General","q":"ch2p15","a":"What metric of outcomes and intakes is optimal for facilitating comparisons btwn shelters?"},{"type":"card","domain":"General","sub":"General","q":"ch3p23","a":"T/F: In order to avoid exceeding housing capacity, shelters should be designed to house the absolute peak population"},{"type":"card","domain":"General","sub":"General","q":"ch3p27","a":"What is the minimum square footage recommended for individual cat housing units? For group rooms? Max number of cats per room?"},{"type":"card","domain":"General","sub":"General","q":"ch3p28","a":"What is the recommended sq footage per dog?"},{"type":"card","domain":"General","sub":"General","q":"ch3p30","a":"How many air changes per hour are recommended for animal housing areas?"},{"type":"card","domain":"General","sub":"General","q":"ch3p31","a":"T/F: HEPA filters are recommended in all animal housing areas"},{"type":"card","domain":"General","sub":"General","q":"ch3p32","a":"Which of the following flooring materials are considered unacceptable in dog housing areas?  Concrete, coatings,, porcelain tiles, carpet tiles, paint, epoxy paint, wood, vinyl"},{"type":"card","domain":"General","sub":"General","q":"ch3p33","a":"Which of the following materials are not appropriate for walls in dog housing units? Solid surface, glass, hard-troweled cement plaster, epoxy coated systems, concrete block with polished face, large porcelain wall tiles, fiberglass reinforced panels, painted  gypseum wallboard, vinyl, standard concrete block"},{"type":"card","domain":"General","sub":"General","q":"ch3p34","a":"Which of hte following materials are not appropriate for ceilings in animal housing areas? sprayed cementitious acoustical plaster, aluminum, plastric grid, celing drop in tiles, cement plaster, wood slats, painted gypseum wallboard"},{"type":"card","domain":"General","sub":"General","q":"ch6p65","a":"What 3 conditions must be met to establish a VPCR?"},{"type":"card","domain":"General","sub":"General","q":"ch6p68","a":"T/F: The ultimate responsibilty for the disposition of all controlled drugs, including pre-euth drugs, falls to the veterinarian, regardless of his or her employment status (full time ,part time, volunteer) at the shelter."},{"type":"card","domain":"General","sub":"General","q":"ch6p77","a":"T/F: Under the legal doctrine of \"charitable immunity,\" a non-profit organization is relived of a tort (a tort is a parivate or civil wrong or injury for which the law provides for damages)."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is operant conditioning?","a":"the dog performs a behavior and the trainer delivers specific consequences\nfor that behavior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is positive reinforcement?","a":"add something pleasant to increase a behavior (i.e. a treat)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is negative punishment?","a":"take away something pleasant to decrease a behavior (i turn my back on dog when it jumps)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is positive punishment?","a":"add something unpleasant to decrease a behavior (i.e. an aversive)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is negative reinforcement?","a":"take away something unpleasant to increase a behavior (let loss on pinch collar)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is classical conditiong?","a":"when an animal has learned to associate certain stimuli with certain other\npleasant or unpleasant events"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F? behaviors linked to emotional states can be influenced by operant conditioning\nwithout changing the emotional state of the animal itself","a":"TRUE; an animal might learn to not lunge at men in uniform, but the animal\nmay still perceive the human as threatening"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is it called if we, in the above case, try to improve the animal's attitude\n towards uniformed men?","a":"classical counterconditioning; if the anml is taught to associate the uniformed\n man with pleasantries, its fearful response may stop"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F? Aversives can best inhibit behavior if it is directly related to the behavior?","a":"TRUE; putting sticky tape on counter to reduce the dog from putting \nits paws on the counter is more effective than screaming at the dog\nfrom across the room"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Shock, citronella, and sonic collars try to prevent unwanted behaviors through \n______ __________.","a":"Positive punishment"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Remote collars can be used to obtain a desired behavior through negative reinforcement\nor ____________ ___________.","a":"avoidance training"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the definition of avoidance training?","a":"the animal learns to perform a specific response resulting in t\nhe absense or termination of an aversive"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what's the defntion of coutner conditioning?","a":"an attempt to eliminate or lessen an undesired association btwn \na stimulus and a response"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is classical counter conditiong?","a":"this is used to change an emotional reaction, such as fear toward a particular item"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What is operant counter conditioning?","a":"the animal only gets a treat when displaying desired behavior in presence of the object of fear"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is desensitization?","a":"exposing an animal incrementally to a stimulus - like recording of a thunderstorm - \nwith gradually increasing intensity while evoking little or no response"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"In cats, ____ and ____ are most often recognized on the basis of a non-specific change in behavior.","a":"In cats, physical illness and pain are most often recognized on the basis of a non-specific change in behavior. Knowing this helps clients and veterinarians detect disease and discomfort and monitor efficacy of pain management."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F Reseach shows that the domestic cat is a social animal.","a":"T. Freeliving domestic cats choose to live in social groups, called colonies, whenever sufficient food resources support multiple cats."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Once the social hierarchy within a feline social group is established, overt aggression is likely to be frequent","a":"F. Once the social hierarchy within a feline social group is established, overt aggression is the exception as long as there are no environmental or physical changes. Social relationships can change throughout life."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"The primary socialization period of cats to people is ______ weeks of age","a":"The primary socialization period of cats to people is from 3 to 9 weeks of age. Fear of people is inhibited by exposure to people during this period. Unless animals have been prevented from experiencing typical stimuli, they usually retain some plasticity (ability to recover) throughout life, from having experienced some socialization"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"List the age ranges for the following development periods:\nNeonatal\nEarly socialization\nLate socialization\nAdolescent\nAdult\nAdult (they didn't give it a new name?)","a":"Neonatal: birth to 2 weeks\nEarly socialization: 3-8 weeks\nLate socialization 9-16 weeks\nAdolescent 17 wks- 1 year\nAdult 1-6 years\nAdult 7 years and older"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Social play in cats peaks at _____ months of age","a":"3 months of age."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Genetically, the temperament of the  _____(choose queen or tom) has an impact on the temperament of the offspring","a":"The tom (daddy cat!)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"______ (behavior problem) is commonly seen in the play behavior of kittens","a":"Aggresion is commonly seen in the play behavior of kittens"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Some cats become less tolerant of petting as they become socially mature. Cats with this condition actually solicit attention from people, but tend to bite if petted for more than a few seconds. Those cats may have a form of __________","a":"Aggression associated with petting—Some cats become less tolerant of petting as they become socially mature. Cats with this condition actually solicit attention from people, but tend to bite if petted for more than a few seconds. Those cats may have a form of impulse control aggression"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"The best way to prevent predatory behavior is to","a":"The best way to prevent predatory behavior is to raise kittens with potential prey animals (eg, pocket pets or birds)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What is the best way to prevent inter-cat aggression?","a":"To prevent inter-cat aggression, clients should be taught that gradual introductions should be made if adopting another cat (Client Education Handout A). If aggression occurs after the return to the household of a resident cat, the cats should also be reintroduced gradually. unless there is evidence of wounds, they often miss subtle aggression."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"___________ is the most common client concern regarding cats.","a":"Inappropriate elimination is the most common client concern regarding cats. Client education about litter box care and normal elimination behavior is important for prevention and treatment of medical and behavior problems. Early intervention offers the best chance to redirect the cat back into the litter box."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Research indicates that house cats at higher risk for elimination problems will dig in the litter substrate for a shorter period than cats with a lower risk for elimination problems.","a":"Research indicates that house cats without elimination problems will dig in their litter boxes longer before eliminations, whereas cats that dig for 4 seconds or less prior to elimination may be candidates for elimination problems.b"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Spraying is not a primary means of urine elimination in most cats; feline communication may be its main function.","a":"T. Spraying is not a primary means of urine elimination in most cats; feline communication may be its main function. Both males and females spray, although males and estrous females spray more often. When spraying, the cat typically stands upright on all 4 limbs and holds its tail vertically. Occasionally, cats will flex their elbows and lower their forearms. The cat may quiver its tail, step back and forth on its hind limbs, or both. The cat does not dig before it sprays, nor does it try to cover the affected area afterwards. When spraying, the cat usually voids small volumes of urine onto vertical surfaces. Obtaining a detailed history will help differentiate between squat urinating and spraying."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Cats from single-cat households are more likely to spray than cats from multi cat households.","a":"F. Spraying can be viewed as a passive form of aggression and as a method by which an intact resident male advertises his presence and activity. Cats from multiple-cat households are more likely to spray than those from single-cat households"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"cats should not go without food for longer than _________ hours (less in kittens)","a":"cats should not go without food for longer than 24 hours (less in kittens) and that clients should call if the appetite tapers over more than 48 to 72 hours. Because of the nature of cats, especially in a multiple-pet household,it may be difficult for clients to recognize decreased or no appetite, and veterinarians often find that cats have lost a substantial percentage of body weight when clients think they have only missed a few meals."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"How do you calculate the daily energy requirements (DER) for a cat?","a":"Calculation of the daily energy requirements (DER) for each cat on the basis of its lifestyle determines accurate food quantities. The DER is a multiple of the resting energy requirement (RER) where RER (kcal) = 70 X (body weight [kg])^0.75. \n\nThe following general multipliers of the RER may be used for adult cats:\nneutered cat (1.2- x RER) or 60 kcal/kg\nintact adult cat (1.4-1.6 x RER) or 70-80 kcal/kg\ninactive cat (0.8 - 1.2 x RER) or 40-60 kcal/kg\nobese-prone adult cat (0.8 - 1.0 x RER) or 40-50 kcal/kg"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Cats rarely develop a food aversion to a food they were eating when they were feeling sick","a":"Food Aversion—Cats may develop learned aversion to certain foods when feeding is paired with a negative gastrointestinal experience.52 Also, cats can develop a food aversion to a food they were eating when they developed other illnesses—they associate the food with becoming sick. Food aversion may also be associated with anorexia, as well as stressful experiences such as hospitalization and force feeding."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Being trained can be helpful for an anxious cat in a strange environment (eg, responding to the command “sit” and receiving a treat at the veterinary hospital may help keep the cat calm).","a":"T Being trained can be helpful for an anxious cat in a strange environment (eg, responding to the command “sit” and receiving a treat at the veterinary hospital may help keep the cat calm)."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"The risk of pathologic anxiety is increased in kittens who were feral for the first ______ months of their lives.","a":"Pathologically shy kittens can improve with much help, but may never be normal. Clients may not know the early history of their kittens, but if the kittens were feral for the first 3 months of their lives, clients need to know that the risk of pathologic anxiety is increased"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Adult cats pose less of a risk for zoonotic disease than kittens","a":"T. adult cats pose less zoonotic risk than young cats, making them a better choice for olderpeople, immunocompromised individuals, and families with very young children."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Removing a kitten from its mother prior to ____ weeks of age is not desirable.","a":"Removing a kitten from its mother prior to 6 weeks of age is not desirable. Kittens separated from their mothers at an early age are more likely to be suspicious and aggressive."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Because the sensitive period in kittens is shorter than in puppies,  kitten kindegarten classes are open only to kittens from_____ to ____ weeks of age","a":"Because the sensitive period in kittens is shorter than in puppies, classes are open only to kittens from 7 to 14 weeks of age. Limit class size to 3 to 8 kittens to allow for effective socialization and training. Kittens should have received at least one FVRCP vaccine at least 10 days prior to the first class,e a first deworming, and negative results of a recent FeLV/FIV test. Owners of kittens with upper respiratory tract infection, FeLV, FIV, ringworm, or other contagious conditions are welcome without their kittens."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: EXposure to aversive events can cause long-term neurochemical changes that trigger equally fearful responses for years","a":"T. Exposure to strongly fearful or aversive events can create long-term neurochemical changes and associations that trigger equally fearful responses for years. The more extreme the fearful response, the more likely it is that the cat’s neurochemistry has changed in ways that facilitate future fearful behavior."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"The following are all examples of _______:\n- Irregular and unpredictable feeding times where cats are kept hungry for extended periods.\n• Irregular and unpredictable cleaning of litter boxes.\n• Absence of stroking and petting by humans or other positive interactions with humans.\n• Unpredictable and unfamiliar manipulations or handling.\n• Changes in social environment (eg, new baby, spouse, roommate; change in client’s work schedule).\n• Changes in physical environment.\n• Lack of mental stimulation.\n• Anything that acutely startles the cat, such as loud noises.\n• Lack of choices or control over situations (behavior entrapment).","a":"sources of stress or distress for a cat"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: The incidence of behavior problems increases with age.","a":"changes in behavior are common in older cats and are often caused by underlying medical problems. The incidence of behavior problems increases with advancing age.f Once the underlying cause is identified, many behavior problems in older cats are correctible."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"A decline in _____ and _____ are normal aging changes that may affect behavior and can lead to subsequent fear, phobias, or aggression.","a":"A decline in hearing and vision are normal aging changes that may affect behavior and can lead to subsequent fear, phobias, or aggression. Altered sleep-wake cycles are also common in older cats, with wandering and increased vocalization, especially at night. Causes include cognitive dysfunction, hypertension, pain, and sensory decline. Urge clients to contact the veterinary hospital even if there are minor changes in their cat’s behavior."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"List up to 5 medical conditions that tend to affect older cats that may be associated with behavior changes/abnormalities","a":"Hyperthyroidism, hypertension, chronic renal disease, and diabetes mellitus are common conditions of older cats that often are characterized by behavior abnormalities. Pain-associated conditions such as dental disease and arthritis can also affect behavior."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"To develop a full behavior treatment plan, a _________ is mandatory","a":"To develop a full behavior treatment plan, a working diagnosis is mandatory"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: New behaviors are learned best if they are rewarded intermittently","a":"F. New behaviors are learned best if they are rewarded every time they occur, and subsequently rewarded intermittently once learning has been established. For intermittent rewards to maintain a behavior, the behavior must be truly learned; otherwise, the cat learns random associations.For example, every time the cat uses a new scratching post, give the cat a treat until the cat consistently uses the scratching post. Once the cat uses only the post and not the furniture, the client can encourage this behavior pattern by rewarding the cat a few times per week."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Disruption of an undesirable behavior must occur with what minimum frequency in order to be effective?","a":"Disruption is effective only if it occurs every time that the behavior occurs and at the start of or during the performance of the behavior. This means that it is effective only for those behaviors that are not self-reinforcing and that do not occur in the client’s absence. Active interventions can also redirect the cat to an alternate, more preferable behavior.\n\nWhen possible (no immient safety risk), passive intervention is recommended. The easiest passive intervention is to absolutely ignore the undesirable behavior, as long as medical problems that might cause this behavior have been ruled out or treated. If the client’s response to the cat’s behavior has contributed to the problem, the behavior may fade if the response ceases."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Medication should be used only as part of a treatment program that includes _______management to prevent the behavior triggers, plus _______ to teach appropriate behaviors.","a":"Medication should be used only as part of a treatment program that includes environmental management to prevent the behavior triggers, plus behavior modification to teach appropriate behaviors. Using behavior meds  without environmental and behavior management is unlikely to be effective."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F Many behavioral medications recommended for use in cats can enhance new learning.","a":"T/ Most medications presently recommended, particularly the tricyclic antidepressants (TCAs) and the selective serotonin reuptake inhibitors (SSRIs) enhance new learning, both associative and operant, so using them without environmental and behavior management is unlikely to be effective."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"List 2 primary reasons why diagnostic testing should be performed prior to starting a cat on behavior drugs.","a":"--Diagnostic testing is important to rule out the many common medical problems that may be manifested originally as behavior problems.\n--Testing should identify any contraindications to the usage of certain behavior-altering drugs. Most behavioraltering drugs are metabolized through renal and hepatic pathways; follow-up laboratory evaluation is necessary to ensure that medication-associated organ damage does not occur."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"SSRIs (paroxetine, fluoextine) can take ______ weeks to show full effects in cats","a":"4-6 weeks, though some effects can be seen earlier."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Anti anxiety effects of TCAs, such as amitriptyline or clomipramine are likely to be seen in _____ (time period)","a":"The initial anti-anxiety effects of TCAs, such as amitriptyline or clomipramine are seen after 5 to 7 days, although more profound changes are seen with additional time. Treatment for a minimum of 4 to 6 months is recommended to improve problem behavior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"List the most common adverse of effects of behavior altering drugs, and how these can be managed if they occur.","a":"Older cats can be particularly susceptible to the adverse effects of behavior-altering drugs, which can \ninclude sedation, retention of urine and feces (constipation), and hypotension. Lower doses and longer intervals between doses may decrease the risk of adverse effects in older cats. Severe adverse effects are rare with the newer medications when they are used appropriately, although atypical reactions can be profound and may be manifest as profound signs of depression or excitation.77,78 In the event of an atypical response, routine support including fluids is required and almost always successful."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Do not combine ______ (drug class or example drug) with any SSRI or TCA because of the potentiated effects on serotonin and norepinephrine. Such combinations can lead to ________ syndrome, the consequences of which could include hyperactivity, anorexia, insomnia, tachypnea, tachycardia, and potentially death.","a":"Do not combine monoamine oxidaseinhibitors such as selegiline with any SSRI or TCA, because of the potentiated effects on serotonin and norepinephrine. Such combinations can lead to serotonin syndrome—an iatrogenic condition marked by hyperactivity, anorexia, insomnia, tachypnea, tachycardia, and potentially death, if provocative treatment continues."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Fear, anxiety associated\nwith veterinary visits, car trips, panic. BONUS POINTS IF YOU LIST DOSE!","a":"Alprazolam, oxazepam. 0.0125-0.025 mg/kg SID. rapid onset (1-2 hours), cats may get the munchies."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Helps victim of inter-cat\naggression become more outgoing and assertive.\nBONUS POINTS IF YOU LIST DOSE!","a":"Buspirone, 0.5-1.0 mg/kg q 12-24 h or 5-10 mg/cat q 12-24 h. Action of drug actually relies on resultant social nteractions to effect and maintain change.  For victim only! Will make jerk cat more jerky."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Milder, relatively nonspecific anxieties, psychogenic alopecia, inappropriate urination secondary to feline interstitial cystitis. BONUS POINTS IF YOU LIST DOSE!","a":"Amitriptyline (TCA), 0.5-1.0 mg/kg q 12-24 h; start at 0.5 mg/kg q 12 h; 2.5-5.0 mg/cat q 12-24 h. 5-7 days before effects will be seen."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Ritualistic behavior associated with anxiety/obsessive compulsive disorder. BONUS POINTS IF YOU LIST DOSE!","a":"Clomipramine, 0.5 mg/kg q 24 h. 5-7 days to initial effect; long term effects may take a minimum of 3-5 weeks."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats:Social phobias, anxieties concerning social interactions and related urine marking. BONUS POINTS IF YOU LIST DOSE!","a":"Paroxetine (SSRI) or sertraline (sertraline), 0.5 mg/kg q 24 h. 6-8 weeks to profound effect. For victims needing more confidence in interactions"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Outburst / impulse control aggression and related anxieties concerning social interactions; related urine marking. BONUS POINTS IF YOU LIST DOSE!","a":"Fluoxetine (SSRI), 0.5-1.0 mg/kg q 24 h. 6-8 weeks to profound effect. For aggressors with aggression outbursts."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What drug(s) would be appropriate for the following behavior concerns in cats: Cognitive dysfunction. BONUS POINTS IF YOU LIST DOSE!","a":"Selegeline (MAOI), 0.5-1.0 mg/kg q 24 h, start low.  Give in the morning. Do not use in combination with SSRIs or TCAs."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What is the minimum recommended time of treatment (including weaning off of drug) for SSRIs and TCAs?","a":"Treat for a minimum of 4 to 6 months"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"how does ASV define HQHVSN?","a":"efficient surgical initiatives that meet or exceed veterinary medical standards of care in providing accessible, targeted sterilization of large numbers of cats and dogs to reduce their overpopulation and subsequent euthanasia."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"application of ASV s/n guidelines can do what?","a":"enhance the quality of patient care, reduce risks, and improve patient outcomes in all settings where surgical sterilization is performed"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? ASV s/n guidelines 2016 include recs on nonsurgical sterilization.","a":"0"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"safe transport of animals to/from s/n clinics should include what considerations?","a":"1. proper confinement of animals and securing of enclosures 2. a way to identify each anml and match it up to its med record 3. good air quality and comfy temps 4.perioidic monitoring of animals w/in vehicle"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what determines the appropriate interval for observing anmls in transport?","a":"1. needs of the anmls 2.duration of transport 3.environmental temps"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what should be included in each anml's med record?","a":"1.PE findings 2. weight 3. any adminsitered or rx'ed drugs 4. sx performed 5. any abnormalities found 6. any other pertinent info on anml's condition"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? periop vax is safe and acceptable (although vax day before sx is recommended).","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"temporary housing for s/n MUST include what?","a":"1. a way to i.d. each anml 2.adq control of temp, vent, & stress 3. properly sanitized btwn patients 4."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"temp housign for s/n SHOULD include what?","a":"1. species separation 2. minimization of noise and other stressors 3.handleable anmls should be housed for good visibility & ability to move around safely 4.unhandeable anmls should be housed in enclosures that allow for min handling to ax to reduce stress and increase safety of handlers 5.unhandleable anmls should only be removed from enclosures if sedated"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? per vet discretion, littermates and housemates can be housed together and/or with moms perioperatively?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"biosecurity measures to reduce infx dz in s/n clinics SHOULD include what?","a":"1. all equipment w/ direct patient contact should be sanitized BTWN each anml 2. ax equipment should be inspected, maintained, cleaned based on sx volume 3. staff should wash/sanitize hands or change gloves btwn patients 4. anmls w/ infc dz signs should be s/n after healthy patients"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? a vet should be present and available until all anmls are extubated, sternal, responsive?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what MUST be present in case of sx emergency?","a":"1. source of oxygen and means of vent 2.emergency drugs and reversals"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? s/n programs MUST have policies for managing post sx complications/emergencies?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Owned pets may best be served by scheduling surgery at 4 months of age or older to \n optimize development of immunity through timely vaccination.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Patient selection for s/n depends on what factors?","a":"1. locale 2. economics 3.clinic staffing 4. ax capabilities 5.technical training"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Neutering prior to adoption is likely to improve the odds that adopted animals will be retained in their new \n homes bc being sexually intact has been i.d.'ed as leading risk factor for owner relinquishment of cats and dogs","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what MUST client communication prior to s/n include?","a":"1. patient hx including (current health status, current signs of dz, current meds/supps, prev vax, pre-existing conditions, prev adverse reactions) 2. must inform of sx and ax risks & must consent"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? witholding water is not needed or recommended","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For pediatric animals (ie, anmls btwn 6 and 16 weeks old), a small meal should be fed __ to__ hours \n before surgery, and food should not be withheld for > ___ hours before surgery.","a":"2; 4; 4"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For juvenile and adult animals (ie, animals > 16 weeks old), food should be withheld for a minimum of ___ hours","a":"4.0"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Although overnight fasting is acceptable, withholding food for > 6 hours is not necessary.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Balanced anesthesia is essential & involves the administration of a combo of drugs to safely produce what?","a":"effective analgesia, loss of consciousness, muscle relaxation, and immobility without patient compromise"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is recommended ambient temperature range for housing cats and dogs in s/n programs?","a":"18° and 28°C (64° and 84°F) with a temperature setting in the low to mid 70s being typical"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? the ambient temp of periop areas doesn't affect patient internal temp?","a":"FALSE. Studies in human med show that patients remain warmer with warmer environmental temperatures in the preoperative, surgery, and recovery areas"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what techniques can be used to combat patient hypothermia periop?","a":"1. prewarming prior to premeds 2.no contact with cold surfaces 3.reduce removal and moistening of fur 4.warmed prep solutions 5.use of low oxygen flow rates (though this can't be low if using non-rebreathing circuit) 6. do surgery ASAP after patient is prepped 6. minimize body cavity exposure 7.additional insulation 7. active patient warming"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Both active and passive waste gas scavenging systems are acceptable?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"charcoal canisters for scavenging waste gas are effective for only short periods of time, typically\n  < ___ to ___ hours or as determined by the weight gain of the canister.","a":"6;8"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Oxygen supp is recommended for which types of high risk patients?","a":"1. brachys 2. adv preggo 3. frail/ill"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"which patients may benefit from intubation?","a":"1. brachys 2. fat patients, 3. adv preggo 4. severe URI 5. if sx gonna take more than 30 min"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? The ability to provide IV fluid administration when medically indicated is NOT required for all spay-neuter programs.","a":"0"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Fluid supplementaion is rec for which patients?","a":"1. adv preggo 2. pyo 3. long sx 4. lots of bld is lost"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? When SC fluids are used, administration during the immediate postoperative period is \n recommended because this avoids the stress and pain associated with SC administration in awake patients.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Use of pulse oximetry monitors has been shown to decrease the risk of anesthetic death in cats.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what arteries can be used to assess pulse?","a":"radial, dorsal metatarsal, femoral, lingual, facial, or carotid"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Resp / apnea monitors is preferred over direct mornitoring of resp rate/pattern.","a":"FALSE. Monitors may sense false flow impedance changes that are more indicative of abdominal manipulation during surgery (false diaphragmatic motions) than effective respiration."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Do not use ____ tone as indicator of ax depth in pediatrics pups.","a":"Jaw; pediatric puppies normally lack mandibular tone; therefore, jaw tone should not be used to assess anesthetic depth in these patients."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Moderate ____ rotation of the eyes often indicates an adequate surgical plane of anesthesia in most \n species but is dependent on the drug combination used for anesthesia","a":"Ventral"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Usually, a _____ eye position with _____ of the pupils indicates a potentially life-threatening depth of anesthesia.","a":"Central; dilation"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"pale mucous membranes can indicate…","a":"peripheral vasoconstriction, which often accompanies the use of α2-adrenoceptor agonists, hypothermia, anemia, or hypoxemia"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"These factors affect ax selection protocols…","a":"number and type of patients, the skill and efficiency of available technical assistance, \n the timing of and competence in various surgical and anesthetic techniques, and drug availability."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what criteria determine the optimal ax selection protocol?","a":"provision of analgesia, stress reduction or anxiolysis, immobility and muscle relaxation, \n and safe, controlled, reversible depression of the CNS resulting in unconsciousness."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what are ways to increase safety when administering ax to anmls you're unable to weigh beforehand (ferals, etc)?","a":"using reversible agents, avoiding drugs that cause marked cardiorespiratory depression, and estimating body weight accurately."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"use & timing of NSAIDS periop should be based on what factors?","a":"patient hydration status and the presence of preexisting hepatic, renal, or gastrointestinal disease or clotting abnormalities."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Anticholinergic agents are not appropriate for the treatment of bradycardia induced by \n α2-adreneroceptor agonists because of the increased ______ _______ that results.","a":"cardiac workload"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? inhalants used as sole ax agents via mask induction cause higher risk of anesthesia-related death in dogs","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Potential risks associated with mask maintenance include…","a":"bronchial irritation, aspiration of gastric contents, and environmental contamination with waste gases"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What are ways to limit waste gas exposure?","a":"1. Minimize airway leaks by using right sized endotracheal tubes w/ proper cuff inflation. \n 2. Eliminate as much residual gas as possible prior to disconnecting patients from the breathing system after surgery by turning off the vaporizer and allowing patients to breathe oxygen, ideally for 5 minutes, prior to disconnection 3. Prior to disconnecting patients, empty the rebreathing bag after the vaporizer is turned off and, if using a circle system, increase the oxygen flow rate to 2 to 3 times the maintenance rate to aid in flushing the system. 4. Turn off vaporizers and flow meters when patients are disconnected. 5. Use caution when filling vaporizers to ensure that the room is well ventilated and as few staff members as possible are present"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Re instrument wrapping and sterilization: the outer wrap material must provide a minimum microbial barrier \n equivalent to dry ____ -thread count pima cotton. Additionally, the wrap material and pack storage conditions\n must ensure sterility for the _______ anticipated pack turnover interval.","a":"270; longest"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Hyperextension of the limbs should be avoided, because it could limit excursion of the chest, comprimising ________,\n or result in increased tension on the _____ ligaments, potentially complicating exposure of the ovaries and increasing postoperative discomfort.","a":"respiration; suspensory"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is REQUIRED for all abdominal procedures and castration of adult dogs?","a":"Sterile patient draping ;performance of apropriate hand and arm antisepsis prior to gloving; single-use sterile surgical gloves"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"To reduce postoperative morbidity and improve overall outcomes, surgeons should strive to\n reduce surgical trauma in every way possible. What considerations should be to reduce sx trauma?","a":"Tissue handling, size and placement of sutures, & length of the incision"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When ventral abdominal or paramedian incisions are used, closure must incorporate the ________ ______ fascia.","a":"external rectus"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When flank incisions are used, closure must incorporate the _____ ________ and _______ and ______ ________ __________ muscles.","a":"transverse abdominus; internal and external abdominal oblique"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For animals with unilateral cryptorchidism, the ________ testis should be located and removed first.","a":"undescended"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Closure of ventral abdominal incisions in cryptorchid surgeries must incorporate the _____ _______ fascia.","a":"external rectus"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Sutures or surgical clips must be of biomedical grade, approved for medical use, sterile, and dated for current use.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Furthermore, with the exception of ______ _____ suture material cannot be effectively resterilized for future use.","a":"stainless steel"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"How much of the distal earflap should be removed with ear-tipping comm cats?","a":"one-third"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What color tattooing is recommended for identifying an animal as sterilized?","a":"green"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Re placement of tattoos: for male and female cats and female dogs, the tattoo should be applied to the ______ \n aspect of the abdomen on or immediately _____ to the ventral midline incision or where a \n ventral midline spay incision would typically be placed.","a":"ventral; lateral"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Re placement of tattoos on male dogs: the tattoo should be applied on the prescrotal incision\n or immediately ______ to the prepuce.","a":"lateral"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When is ax-related death most common during period?","a":"postoperatively; especially within the initial 3 hours after surgery."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What parameters should be monitored postoperatively?","a":"HR & pulse quality; RR & character; Airway patency; mm color; signs of pain/anxiety; body temp; \n degree of arousal or sedation; movement and ability to ambulate"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Potential benefits of ax reversal may include what factors?","a":"reducing/ alleviating cardiorespiratory depression associated with ax agents, hastening recovery,\n and promoting the return of thermoregulation."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what are potential detriments of ax reversal?","a":"increased anxiety and reduced analgesia"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"which class of ax agents can increase urine output and therefore contribute to discomfort post-op?","a":"α2-adrenoceptor agonists"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Numerous studies have demonstrated that regular use of customized checklists enhances ______, ______, and ______.","a":"compliance with standard operating procedures, avoids mistakes, and improves patient outcomes"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F? Employee stress and work dissatisfaction are known risk factors for musculoskeletal pain\n  and decreased surgical performance as well as for depression and suicidal ideation among veterinarians.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The most frequenty veterinary employee injuries surround what?","a":"Animal bites, musculoskeletal strains associated with lifting animals, and trauma from \n slips and falls that occur during animal handling"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What factors contribute to m/s discomfort in surgeons?","a":"posture, repitition, and force"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What does operations mgmt refer to in this document? (This is a new section in the 2016 update).","a":"A proactive approach in which continuous, strategic planning, control, and improvement \n are performed to effectively and efficiently produce and deliver the organization’s services"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Poor_______ can create unhealthy, low perfusion cascades of organ dysfunction which may manifest as renal insufficiency, pancreatitis, hepatic and myocardial dysfunction and sepsis well after the anesthesia and surgery event.","a":"Poor cardiac output can create unhealthy, low perfusion cascades of organ dysfunction which may manifest as renal insufficiency, pancreatitis, hepatic and myocardial dysfunction and sepsis well after the anesthesia and surgery event."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The following are all factors for what? \n-- minimum and maximum patient age, weight, health status, and anesthetic risk,  staff expertise and available anesthetic equipment","a":"A veterinarian should make the final decision regarding acceptance of any patient for surgery based on historical and physical examination findings and the practice’s surgical schedule. The surgeon should use discretion regarding minimum and maximum patient age, weight, health status, and anesthetic risk, taking into account the availability of staff expertise and necessary equipment to care for patients"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Owned pets may best be served by scheduling surgery at what age and why?","a":"Owned pets may best be served by scheduling surgery at four months of age (or older) to allow time for\nthe development of immunity through vaccination (but prior to onset of sexual maturity to prevent the births of unintentional litters)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: being sexually intact is the leading risk factor for owner relinquishment of cats and dogs","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F:  the benefit of performing sterilization for an individual animal within a shelter, feral or trap, neuter and release (TNR) population at the time of initial presentation outweighs the increased risks posed by mild infectious or noninfectious medical conditions, such as upper respiratory infection, parasite infestation and asymptomatic heartworm disease","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: It is not necessary to ask clients about patient history, such as information about current medications,\nmedical history and allergies in HVHQSN settings","a":"F"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Rabies vaccination is optional for patients in HVHQSN clinics","a":"F: Vaccination is recommended prior to surgery, but perioperative (immediately pre-, intra- or postoperative) vaccination is acceptable when necessary. Rabies vaccination should be required or administered as mandated by state regulations."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Preoperative fasting greater than four to six hours is not warranted.","a":"Preoperative fasting for dogs and cats is ideal, but withholding water is neither necessary nor recommended. Prolonged fasting for greater than four to six hours is not warranted, especially for pediatric animals Prolonged fasting increases chances of renal, myocardial, and thromboembolic disease."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Exceptions for preoperative fasting may be made for feral cats in traps","a":"T: Pediatric animals should be fed a small liquefied or easily digestible meal two to four hours prior\nto surgery and should not be fasted for more than four hours prior to surgery (16-19). Juvenile\nand adult animals should be fasted for a minimum of four hours (20-24). Exceptions for\npreoperative fasting may be made for feral cats in traps due to the safety risk of removing\nuneaten bait."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What dose and route of administration are recommended for animals at risk of glycemic control (sick, poor body condition, elderly, recently post-weaning females) or for those animals undergoing prolonged capture, restraint, stress and fasting","a":"50% dextrose (0.5ml/10 kg administered either intravenously (IV) or buccal mucosally or Karo syrup/molasses administered via bucaal\nmucosa is suggested."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: In the event that the veterinarian is not available, a licensed and/or trained veterinary technician can perform an the preop exam and vital parameter assessment","a":"F: Physical examination should ideally be performed by the veterinarian who will be performing the surgery and should always be attempted prior to anesthesia, but anxiety, aggression or feral behavior may often prevent a thorough pre-anesthesia examination. In these cases, whether physical examination is performed prior to or after pre-medication or induction should be at the discretion of the attending veterinarians. In the event that the veterinarian is not available, a licensed and/or trained veterinary technician can perform an initial triage preop exam and vital parameter assessment and then, as soon as possible perioperatively, the veterinarian can perform a more complete\nphysical exam, including body system assessment."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"__________ assessment is especially helpful in determining appropriateness of surgery in animals with respiratory, GI or cardiac disease.","a":"temperature assessment is especially helpful in determining appropriateness of surgery in animals with respiratory, GI or cardiac disease."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What anesthetic drug considerations should be made for a fat animal? For a thin animal?","a":"More important than body weight in adult animals is body condition score. A fat animal should be dosed on lean weight. A thin animal is probably best anesthetized without the use of heavily fat soluble drugs. Regardless of body weight, extreme body condition scores dictate changes in drug dosages, including inhalants, and may be predictable of surgical depth/monitoring difficulties (25)."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The following conditions indicate what actions should be considered? \nExtreme stress and overhandling;\n• Trauma;\n• Extreme dermatologic conditions;\n• Severe dehydration;\n• Malnourishment;\n• Severe parasitism;\n• Toxicity; and/or\n• Upper-respiratory disease","a":"Stabilization prior to surgery is critical for at risk patients experiencing these condttions. All at risk animals may benefit from postponed surgery if possible, and if postponement is not feasible, modified anesthesia protocols, use of fluids, extra warmth and glucose control based on their disease severity is recommended."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Surgery need not be delayed in upper respiratory disease cats and dogs","a":"T: Surgery need not be delayed in upper respiratory disease cats and dogs unless their condition truly causes hypoxia or respiratory distress, includes severe pyrexia or diseased transmission potential or if their condition deteriorates"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Age and health status or disease potential are important determinants in deciding whether bloodwork is necessary for a particular animal","a":"F: Age should not be a determinant in deciding whether bloodwork is necessary for a particular animal, rather, health status or disease potential and risk of anesthesia/surgical complications resulting from such should dictate necessity of this testing."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Adult tractable animals may be housed in individual cages or co housed to alleviate stress in runs that allow for good visibility and adequate turnaround space, as well as for safety at various stages of sedation and anesthesia.","a":"True-ish. Adult tractable animals should be housed in individual cages or runs that allow for good visibility and adequate turnaround space, as well as for safety at various stages of sedation and anesthesia. At the discretion of the attending veterinarian, pediatric littermates or housemates\nmay benefit from being housed together"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"How frequently should the following things be cleaned and disinfected at minimum:\n--All anesthesia equipment that has direct patient contact (e.g., endotracheal tubes, laryngoscope blades, pulse oximeter clips, esophageal stethoscope, thermometer, etc.) \n• Breathing circuits should be thoroughly cleaned, disinfected, rinsed and dried \n• Anesthesia machine, dome and one-way valves, and absorbent canisters, should be disassembled, cleaned, and left open to dry \n• Staff should wash their hands or sanitize","a":"All anesthesia equipment that has direct patient contact (e.g., endotracheal tubes, laryngoscope blades, pulse oximeter clips, esophageal stethoscope, thermometer, etc.) should be thoroughly cleaned in mild soap and water, and disinfected between patients (26, 27).\n• Breathing circuits should be thoroughly cleaned, disinfected, rinsed and dried one to two times per week at minimum.\n• Anesthesia machine, dome and one-way valves, and absorbent canisters, should be disassembled, cleaned, and left open to dry once per week at a minimum (28).\n• Staff should wash their hands or sanitize between patients and litters."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"General Machine Inspection\n_x0001_ Vaporizers - Fill vaporizers at ________ (time of day) when fewer personnel are present to avoid vapor inhalation and spills. Tighten filler caps post-filling and ensure that control dials are set to _____ position pre- and post-filling.\n_x0001_ Circle Breathing System - Confirm proper function of one way valves in circle breathing system. The_______ (inspiratory or expiratory) valve should respond to your breath through the breathing circuit. The ________ (inspiratory or expiratory) valve should move with the compression of the rebreathing or reservoir bag.","a":"General Machine Inspection\n_x0001_ Vaporizers - Fill vaporizers at the end of the workday when fewer personnel are present to avoid vapor inhalation and spills. Tighten filler caps post-filling and ensure that control dials are set to off, vs. “0” position pre- and post-filling.\n_x0001_ Circle Breathing System - Confirm proper function of one way valves in circle breathing system. To check the expiratory circuit valve the expiratory valve should respond to your breath through the breathing circuit. To check the inspiratory valve in the circuit, with the pop off valve closed, the inspiratory valve should move with the compression of the rebreathing or reservoir bag."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Breathing Circuit Check – In addition to the regular inspections, the breathing circuit should also be checked every (#)_________ patients.\n_x0001_ Make sure the machine and ET tube end fittings are proper and tight.\n_x0001_ To check for leaks in______ (circle or non-rebreathing) systems, close the pop-off valve, occlude the patient end of the Y piece, fill the system with oxygen from the  _____ (flowmeter or flush), and turn the oxygen flow to 5L/min. As the pressure in the system reaches 20 cm of water, reduce the flowmeter flow to 0. The pressure should hold for at least______ seconds at 20 cm of water; if it doesn’t, a leak is present. To finish the test, open the pop-off valve slowly (vs. releasing the occlusion on the patient end of the circuit) and observe the release of pressure.\n_x0001_ To check for leaks in______ (circle or non-rebreathing) systems, make sure the patient port is occluded, the relief valve is closed, and the reservoir bag distended. The bag should remain distended for______seconds; if it doesn’t, a leak is present.","a":"Breathing Circuit Check – In addition to the regular inspections, the breathing circuit should also be checked every three to five patients.\n_x0001_ Make sure the machine and ET tube end fittings are proper and tight.\n_x0001_ To check for leaks in circle systems, close the pop-off valve, occlude the patient end of the Y piece, fill the system with oxygen from the flow meter (not the flush), and turn the oxygen flow to 5L/min. As the pressure in the system reaches 20 cm of water, reduce the flowmeter flow to 0. The pressure should hold for at least ten seconds at 20 cm of water; if it doesn’t, a leak is present. To finish the test, open the pop-off valve slowly (vs. releasing the occlusion on the patient end of the circuit) and observe the release of pressure.\n_x0001_ To check for leaks in non-rebreathing systems, make sure the patient port is occluded, the relief valve is closed, and the reservoir bag distended. The bag should remain distended for two to three seconds; if it doesn’t, a leak is present. Additional testing of the inner tube of coaxial systems is required and is done by occluding the inner tube at the patient end (using a pen or pencil tip) while oxygen is flowing at approximately 1-2 L/min. During this short period of occlusion, the float in the oxygen flowmeter should fall; if it doesn’t, a leak is present within the system."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"If a charcoal canister is used, confirm its date and starting weight. Gains of____ (weight) or more usually constitute disposal of the canister.","a":"If a charcoal canister is used, confirm its date and starting weight. Gains of 50g or more usually constitute disposal of the canister.  \n-- Q. How do I determine if the waste gas scavenging system is functioning properly?\nA. A waste gas scavenging system consists of a 19 or 30 mm diameter corrugated “transfer” hose connected to the scavenging port of the pop-off valve. Waste gas removal is either passive or active. In a passive system the distal end of the transfer hose is directed into an activated charcoal canister or it is directed out of the room via a connection to a through-the-wall opening or to the exhaust vent of a non-recirculating room ventilation system. Periodically the transfer hose should be inspected for leaks. This is done by completing the breathing system leak check as previously described, but instead of closing the pop-off valve it is left open and the distal end of the transfer hose occluded until 30 cm H2O pressure develops within the breathing system and is sustained for 10 s. The pressure within the system should return to zero when the transfer hose is no longer occluded."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When should the carbon dioxide absorbent be replaced?","a":"Check adequacy of carbon dioxide absorbent. Note that color change is not a reliable indicator for exhausted use in most brands of absorbent; the violet color associated  with use may revert to white during non-use. Rather, the hardness of the granules indicates expended chemical trapping potential and serves as a more reliable indicator of the need to change the absorbent. \n---FROM Q and A textbook: It can be difficult to determine if an adequate amount of functioning absorbent remains and therefore when it should be replaced. This will depend on the hours of use, the size and number of animals anesthetized since it was last changed, the capacity of the canister and the degree to which it is filled, the type of absorbent material, and the fresh gas flow rates typically used. In some facilities the absorbent is replaced at regular intervals based on historical use (e.g., once per week) whether or not it is needed. A rule of thumb is to change the absorbent material when the color change indicating exhaustion appears 2/3 down the canister. However, color change can be misleading because the color can temporarily revert while the machine is not in use. With some absorbent material the color also changes when the absorbent material becomes desiccated but can still absorb CO2. An increase in inspired CO2 concentration seen on a capnograph waveform can indicate absorbent is exhausted. However, erratic patterns of ventilation or relatively large equipment dead space can result in an elevated inspired CO2 even if the absorbent material is functional."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Describe if/how breathing circuits and endotracheal tubes should be cleaned and disinfected.","a":"A reasonable hot water and soap cleaning should be performed on all circuits and tracheal tubes prior to the nightly soaking in diluted chlorohexidene acetate. Washing and scrubbing of the endotracheal tubes with dishwater soap and water is as or more critical than antiseptic soaking. Following the soaking, it is critical to rinse all circuits and tracheal tubes with water"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"______________will lend to more uniform surgical planes of anesthesia, and improve cardiovascular function and recovery","a":"Providing preoperative thermoregulation support will lend to more uniform surgical planes of anesthesia, and improve cardiovascular function and recovery"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"________________is essential and includes analgesia, unconsciousness, muscle relaxation and immobility without patient compromise","a":"Balanced anesthesia is essential and includes analgesia, unconsciousness, muscle relaxation and immobility without patient compromise"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Derangements in ______________ from  anesthesia can produce alterations in hepatic function, coagulation, cardiac function, renal function, humoral and cellular immunity, and wound healing.","a":"Homeostatic derangements in thermoregulation from anesthesia and abnormal vasoconstriction can produce alterations in hepatic function, coagulation, cardiac function, renal function, humoral and cellular immunity, and wound healing."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"List methods which are inappropriate for provide peri and intraoperative heat support","a":"-- Direct contact with electric heating pads, inappropriately close blow dryers or heat lamps, drying\ncages and direct (vs. stand off) contact with hot water containers must be avoided to prevent\nthermal injury. This is especially important in pediatric, debilitated and frail geriatric patients\nwhose low total protein and/or low fat stores may easily result in burns.\n-- Warmth is best preserved by reduced contact with cold surfaces, limited body cavity exposure, circulating hot water and protected (stand off) contact with heated containers. Forced hot air or convective warming is the most efficient and useful for maintaining intra-operative body temperature"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Heat can be conserved by using low oxygen flow rates with ________ (rebreathing or non-rebreathing) circuits","a":"Heat can be conserved by using low oxygen flow rates with rebreathing circuits, but most non-rebreathing circuits are inappropriate for low oxygen flow rates. If used with low oxygen flow rates, many non-rebreathing circuits will likely cause significant hypercarbia and mild hypoxia"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Mask rates of oxygen supplementation range from ________ L/min depending on the size of the animal, the breathing system being employed and mask closure","a":"Mask rates of oxygen supplementation range from 2-5L/min depending on the size of the animal, the breathing system being employed and mask closure"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Define ventilation (physiolgic term)","a":"Ventilation is the process whereby the body exhales or is otherwise rid of carbon dioxide; this is\na very different process from oxygenation, although the two are often surgically grouped\ntogether."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"In a rebreathing (circle) circuit, ventilation can be compromized by __________\nIn a non-rebreathing circuit, venitlation can be comprpmized by __________","a":"Ventilation is accomplished in an anesthetized animal in two ways: either through an anesthesia machine using a rebreathing circuit with functional carbon dioxide absorbent (Sodasorb, Baralyme, Sodalyme) or through a non-rebreathing circuit with appropriate oxygen flow rates. Ventilation is compromised when carbon dioxide absorbent is saturated or when inappropriately low oxygen flow rates are used in the context of non-rebreathing systems"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"When should SQ or IV fluids be administered relative to surgery (if needed)?","a":"When hydration is needed, subcutaneous (SQ) or IV fluid therapy is best administered either during surgery or immediately post-operative. The goal is to avoid the stress, pain and chill from preoperative administration while the animal is awake. Fluids should be mildly warmed prior to administration, particularly with pediatric, sick and geriatric animals"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which of the following are reasonable methods for assessing heart rates in anesthtized patients?\n-- manual pulse palpation of an artery or the chest\n-- pulse oximeters\n-- electrocardigraphs","a":"--Manually palpate the pulse at the radial artery, dorsal metatarsal artery, femoral artery, chest, lingual artery, facial artery and/or jugular furrow.\n-- Pulse oximetry, as opposed to an electrocardiograph, allows accurate measurement of both pulse rate and patient oxygenation status (44). A pulse oximeter is one of the most affordable monitors for all types of surgical settings, and is simple to use, portable, often battery operated, and noninvasive.\n-- Electrocardiographs are not considered suitable monitoring devices because they can demonstrate normal electrical conductance in a mechanically dead heart. Older models of electrocardiographs may also frequently calculate the heart rate inaccurately and as such can be misleading."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Under what circumstances should an esophageal stethoscope not be used?","a":"if positioned appropriately in an intubated patient, they do afford one inexpensive means of ausculting heart valvular function. Esophageal stethoscopes should not be used in a patient with an unprotected airway Esophageal stethoscopes have limitations because they allow pathways for esophageal reflux, provide false security of heart sounds without peripheral pulse perception, and include the possibility of abnormal pressure or impaired airflow in a patient with an unprotected airway. However, if positioned appropriately in an intubated patient, they do afford one inexpensive\nmeans of ausculting heart valvular function. Esophageal stethoscopes should not be used in a patient with an unprotected airway"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What eye position is associated with an appropriate plane of surgical anesthesia: Moderately ventrally rotated strabismus or central eye position with dilated pupils?","a":"In general, central eye position with dilated pupils indicates a potentially life-threatening depth of anesthesia. However, central eye position and pupillary dilation can occur in dogs and cats anesthetized with high doses of ketamine and may not be associated with complications (46, 47). Moderately ventrally rotated strabismus in both eyes often indicates adequate surgical plane of anesthesia in most species, but is also dependent on drug combinations utilized"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"better pain relief with fewer adverse drug reactions are often the benefit of using _______________","a":"better pain relief with fewer adverse drug reactions are often the benefit of multimodal or combination anesthetic regimens"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Injectable forms of many NSAIDS now exist; acceptable choices of injectable agents include (4)__________________. In a majority of patients, ________ (presurgical, perioperative, postsurgical) administration of these agents is advocated.","a":"Injectable forms of many NSAIDS now exist; acceptable choices of injectable agents include Flunixin, Ketoprofen, Carprofen, Meloxicam (62-78). In a majority of patients, presurgical administration of these agents (following anesthesia induction) is advocated. In patients with questionable health status, however, these agents are probably best reserved for late intraop or postoperative administration."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"NSAID dosages for feline and canine patients:\nFlunixin Meglumine:\nKetoprofen: \nCarprofen: \nMeloxicam:","a":"NSAID dosages for feline and canine patients:\nFlunixin Meglumine: 1mg/kg IV, SQ\nKetoprofen: 0.5-1mg/kg IV, SQ\nCarprofen: 2.2-4.4mg/kg SID-BID IV, SQ\nMeloxicam: 0.1-0.2mg/kg SID IV, SQ"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Commonly used dosages for local anesthestic agents:\n--Lidocaine\n-- Bupivicaine","a":"Commonly used dosages for both these agents in cats and dogs are noted below; the addition of saline can be utilized to dilute for the necessary area of coverage and the increased spread of the agent, and to reduce the sting of administration.\nLidocaine: 2mg/kg\nBupivicaine: 0.3-0.5mg/kg"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Commonly used dosages of opioid agents and their routes of administration (all are IV, IM, SQ, EXCEPT WHICH ONE):\nButorphanol: \nBuprenorphine: \nHydromorphone: \nOxymorphone: \nMorphine:","a":"Commonly used dosages of opioid agents and their routes of administration:\nButorphanol: 0.2-0.3mg/kg IV, IM, SQ\nBuprenorphine: 0.02-0.03mg/kg IV, IM, SQ\nHydromorphone: 0.05-0.1mg/kg IV, IM, SQ\nOxymorphone: 0.05-0.1mg/kg IV, IM, SQ\nMorphine: 0.1-0.3mg/kg IM, SQ"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Acceptable choices of alpha 2 agents include (3)_________. Alpha 2 agents constitute a unique class of agents that have both ________ and _________ properties.","a":"Acceptable choices of alpha 2 agents include Medetomidine, Dexmedetomidine, and Xylazine. Alpha 2 agents constitute a unique class of agents that have both analgesic (pain relieving) and stress reducing (anxiolytic properties)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Medetomidine and Dexmedetomidine\nChoose to fill in the blanks: 0.2-0.3,  5-15, 3-10, 1-3\n  Premedication (mini dose): _____mcg/kg dogs and _______mcg/kg cats IM\n  Postmedication (micro dose): _____mcg/kg both cats and dogs IV or IM\nXylazine Premedication: _____ mg/kg IM","a":"Medetomidine and Dexmedetomidine\n  Premedication (mini dose): 3-10mcg/kg dogs and 5-15mcg/kg cats IM\n  Postmedication (micro dose): 1-3mcg/kg both cats and dogs IV or IM\nXylazine Premedication: 0.2-0.3mg/kg IM"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Match dosages for commonly used minor and major tranquilizers for use as part of multimodal anesthesia regimens with appropriate drug\nDiazepam     Midazolam    Acepromazine               \n\n0.02-0.05mg/kg IV, IM, SQ       0.2-0.5mg/kg IV         0.2-0.5mg/kg IV, IM, SQ","a":"Dosages for commonly used minor and major tranquilizers for use as part of multimodal anesthesia regimens are given below:\nDiazepam: 0.2-0.5mg/kg IV\nMidazolam: 0.2-0.5mg/kg IV, IM, SQ\nAcepromazine: 0.02-0.05mg/kg IV, IM, SQ"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"____________ should also be minimized to avoid aspiration of gastric contents in an  unprotected airway, dangerously high concentrations of inhalants, environmental contamination, and bronchoirritation","a":"Mask induction or maintenance/supplementation during the surgical procedure should be minimized toavoid aspiration of gastric contents in an  unprotected airway, dangerously high concentrations of inhalants, environmental contamination, and bronchoirritation"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"List up to four alternative strategies to routine/frequent use of mask inhalant supplementation.","a":"Within a busy environment, such as that encountered in a HQHVSN operation, mask inhalant supplementation on a few animals for short periods is often necessary and appropriate, but if mask supplementation becomes too frequent or regular, these other options should be considered for patient and staff safety:\n• Instead of masking, utilize an anesthesia protocol that requires intubation, which is safer for the patient (it bypasses the bronchoirritation receptors and cells in the nose, nasopharynx, and trachea, and inhibits aspiration of gastrointestinal contents) and avoids environmental contamination.\n• Consider alternative anesthesia protocols that employ better analgesics and sedatives, thus steadying the plane of surgical anesthesia and avoiding the need for additional anesthesia or mask inhalant supplementation.\n• For consistent intraoperative lightness in plane of anesthesia, consider additional analgesics via sublingual or intravenous route to smooth the plane of anesthesia (microdose = small, titrable dose of opioids, Ketamine or alpha 2 agents).\n• Eliminate issues that contribute to unsteady states of anesthesia, including hypothermia, hypoxia, hypotension, hypercarbia and hypoglycemia."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Describe ASA statuses I-V","a":"I normal healthy patient no signs of obvious disease\nII patient with mild systemic disease: compensated cardiac disease, fracture with no shock\nIII patient with severe systemic disease: anemia, moderate dehydration, renal or hepatic disease\nIV patient with severe disease that is life-threatening: uncompensated cardiac disease, renal or hepatic failure, sepsis\nV patient that is not expected to live with or without surgery: profound shock, severe multi-organ failure, severe sepsis, severe trauma"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"List drugs that should be stocked in a crash cart (reversal agents and emergency drugs)","a":"Recommended Reversal and Emergency Agents\n• Reversal agents for the drugs commonly used in both premeds and induction: Atipamezole, Naloxone, Butorphanol, and Flumazenil;\n• Atropine;\n• Epinephrine and/or Vasopressin; and\n• Lidocaine or Xylocaine spray for larynx immobilization and successful intubation."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"List drugs that are no longer recommened for use in emergent situations","a":"Emergency Agents NO LONGER Recommended\n• Parenteral Lidocaine is not recommended for occasional abnormal cardiac rhythms. Rather than react to an abnormal beat or many abnormal beats (rhythm) with administration of IV Lidocaine, the suggestion would be to check true pulse rate, warmth, volume and hydration status and oxygenation, correcting all these prior to administration of any anti-arrhythmic agent for any abnormal cardiac or pulse rhythm.\n• Doxapram is not recommended for decreased respiratory effort or abnormal respiratory pattern. Rather than administer a stimulant, which ironically further lowers carbon dioxide levels (thus increasing respiratory depression), check anesthesia equipment for faulty technical errors, reverse or partially reverse respiratory depressant agents, including inhalants, oxygenate and ventilate the patient, and provide further monitoring for hypoxia, hypotension, hypothermia and hypoglycemia.\n• Bicarbonate and calcium are no longer recommended for CPR events."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Given the high-volume nature of these sterilization programs it is reasonable to use a “one size fits all” approach to anesthetic dosing that does not take individual patient weight into consideration.","a":"F: Given the high-volume nature of these sterilization programs, veterinarians may be tempted to use pre-determined or standard drug doses, a “one size fits all” approach that does not take individual patient weight or health into consideration. These types of predetermined doses can overdose small patients while being insufficient for large patients."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F Intubation must be a part of all routineHQHVSN anesthesia regimens","a":"F: Intubation does not necessarily need to be a part of all HQHVSN anesthesia regimens but should be a possibility for all surgical patients if needed for emergency. If intubation is chosen as part of an anesthesia protocol, having an anesthesia team skilled in this area is critical. Although intubation with a cuffed endotracheal tube was historically the classic “gold standard” for maintaining a protected airway in the surgical patient, obtaining this airway on every patient requires training, practice, time, patience and the proper anesthetic depth. In fact, with some HQHVSN anesthetic regimens, intubation may complicate the routine and even compromise patient care if it is not performed with skill, care and efficiency (118, 119). Hence the pros and cons of intubation must be weighed against the historical benefits of “airway protection.”"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Fill in the blanks\n• If a patient has severe respiratory (URT inflammation) or cardiovascular compromise (severe heartworm infection), it’s best to (intubate or mask) __________.\n• Most unfasted or unknown fasting status dogs _______ (should or should not) be intubated.\n• Most adult overweight dogs _______ (should or should not) be intubated \n• Most brachycephalic animals, including Chows, Sharpies, Burmese and Persian cats, _______ (should or should not) be intubated.","a":"Suggested general guidelines regarding intubation in most HQHVSN programs are as follows:\n• If a patient has severe respiratory (URT inflammation) or cardiovascular compromise (severe heartworm infection), it’s best to intubate before a problem or arrest occurs. It is important to remember that airway is the first aspect of the ABCs of CPR. If an airway is in place when a disturbance takes place it will be easy to oxygenate, ventilate and resuscitate. Conversely, if an airway is not in place, it is very difficult to intubate a regurgitating, aspirating, agonal or arresting patient, especially if the patient is in a surgical position not akin to normal intubation.\n• Most unfasted or unknown fasting status dogs should be intubated.\n• Most adult overweight dogs should be intubated (120).\n• Most brachycephalic animals, including Chows, Sharpies, Burmese and Persian cats, should be intubated (120)."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"List some of the risks of intubation","a":"However, the drawbacks of intubation are evident. This “protected airway” may give a false since of security; gastric contents can be regurgitated and still “leak” into the trachea, even around the cuff, and cause damage. Also, intubation can be difficult; unless the proper plane of anesthesia is present, gagging can occur, which not only makes it difficult for intubation to occur, but also stimulates stress hormone release, increased intracranial and ocular pressure and increased vagal tone, all of which can cause significant problems intra- and postoperatively. Intubation therefore also requires a relatively deep plane of anesthesia capable of obtunding this gagging reflex; deep planes of anesthesia can often be deleterious for the patient. Finally, intubation is not an easy task to master, especially for the inexperienced technical staff. If not done properly, tracheal damage, lacerations and strictures can occur, threatening the life of thepatient weeks to months post surgery.\n\nif you are considering intubation as part of your surgical anesthesia protocol, you should ask the following questions to help aid in discerning the benefits and risks of the technical maneuver:\n• How efficient is my technical staff?\n• Will intubation cause more damage than not?\n• How much time will each intubation require?\n• Is the plane of anesthesia appropriate for intubation or will my premed/induction agent dosage need to be modified to accommodate intubation?"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Bladder expression carries risks to surgery patients and should be performed cautiously.","a":"T: Caution should be exercised during bladder expression, especially in male cats and dogs. While bladder emptying is conducive to easy surgical manipulation and visualization of pedicles/stumps, bladder expression, especially by untrained staff, can be extremely detrimental to renal function, bladder and urethral integrity, and may also cause or add to abdominal pain postoperatively."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Recovery with siblings is recommended for pediatric patients","a":"T: Recovery with siblings is recommended for pediatric patients when possible to provide warmth and familiarity with surroundings"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Routine reversal of sedative, analgesic and anesthetic agents via IM or IV routes is indicated in programs in which the patients must be promptly returned to the owner, caregiver or environment.","a":"F: Anesthesia Reversal – At the surgeon’s discretion, reversal of sedative, analgesic and anesthetic agents may be accomplished if necessary for emergent cases and programs in which the patients must be promptly returned to the owner, caregiver or environment. It should be remembered that the reversal of analgesia and sedative agents may cause pain and anxiety. In fact, intravenous reversal of agents is commonly associated with sudden and severe catecholamine release. Hence, IV administration should be avoided if at all possible except in emergent cases.\nShould administration of reversal agents be needed, the following is recommended:\n• Only partially reverse the sedative or analgesic agents;\n• Utilize careful and slow titration of the reversal agents IV or intramuscular (IM) to avoid sudden anxiety and pain; and\n• Utilize only IM administration of reversal agents that characteristically do not enter the circulation as fast to cause sudden pain and stress."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"If cats are to be held longer than_____ hours following surgery, a litter box should be provided after the patients are ambulatory.","a":"If cats are to be held longer than twelve hours, a litter box should be provided after the patients are ambulatory."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"T/F: Dogs should not be walked following surgical recovery to minimize stress and post-operative pain.","a":"Dogs that are ambulatory should be walked to encourage urination and defecation, if not considered to be a behavioral risk."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Activity depression, hyperactivity, stereotypic behavior, frustration, and barrier aggression are all __________________.","a":"behavioral indicators of stress and anxiety"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The goals of ______________ are to minimize infectious dz and problem behaviors while optimizing the physical and behavioral health of the animals and preventing transmission of zoonotic diseases.","a":"a shelter wellness program. \"Keep animals 'heathy and happy,' and the public safe.\""},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Minimum database  for cats and dogs prior to adoption? Extras for geriatric animals?","a":"-- Behavior exam/assessment\n-- FeLV/FIV testing (cats)\n-- HW testings (dogs only, endemic areas)\n--Fecal (if diarrhea present)\nGeriatric: PCV/TP, USG + dipstick"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Minimum database for cats and dogs at time of intake?","a":"History, safety to handle, PE (including microchip scan), problem identification, medical assessment"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Four steps of clinical reasoning process","a":"--database collection\n--problem identification\n-- plan formulation\n-- assessment  and followup"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Times at which animals should be scanned for a microchip (3)","a":"1) intake\n2) prior to being made available for adoption\n3) prior to euthanasia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Times during stay at whcih behavioral exam and assessment should be made","a":"In 2-5 days after intake, after the animal has acclimated to the shelter environment"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At minimum rounds should be conducted ______(times per day) to observe each individual animal as well at its environment for signs of health problems","a":"twice"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dz management protocols should include the following (4) features","a":"-- establish definition/description of dz/problem\n-- describe general policy regarding disposition of affected animals\n-- describe methos used to dx/recognize the condition\n-- include details about notifying stakeholders, housing, decontamination, treatment, documentation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why are intranasal FVRCP vax not recommended for use (instead of parenteral) in shelters?","a":"Does not provide reliable protection against FPV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccines not generally recommended for use in shelters","a":"Dogs: Lepto, Lyme, Corona, Giardia, CAV-1, rattlesnake, Porphyromona\nCats: FIP, Giardia (FeLV** except group housing situations), (FIV)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Time to onset of immunity for these vaccines:  a)CPV b)CDV c)FPV  d)FHV/FCV/Bordetella","a":"a) 3d\nb) < 3d\nc) (3-)5d\nd) 2-4 d"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Max time to use MLV vaccine after reconstitution?","a":"30 min"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dosage of pyrantel and timing of administration","a":"Dosage: 10 mg/kg\nTiming: @ intake and q 2ks until 16 weeks old (juveniles) or adults @ 2 wks and q30 d"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Temp at or above which the immune response to vaccination is impaired and what to do","a":">= 103.6\ndo: cool animal prior to vaccinating"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Frequency of international standard microchips?","a":"134 kHz (ISO)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Give 3 examples of behavioral coping strategies","a":"Hiding\nseeking social companionship\nacquiring mential stimulation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Animals employ coping strategies in order to ___________________","a":"lessen the negative impacts of a stressor"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Stress involves outcomes secondary to increased secretion of ________ and _______","a":"catecholamines and cortisol"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define time period of a long stay in a shelter.","a":">=2 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe inhibited or withdrawal behavior","a":"activity depression or the absence of norm behaviors (grooming, eating, sleeping, elimintating, stretching, greeting)."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe defensive behavior","a":"Characteristic postural and/or vocal responses intended to be distance increasing, movitvated by fear"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe stereotypic behaviors","a":"Pacing, pawing, circling. Related to anxiety."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe disruptive behaviors","a":"Destruction of cage contents and/or creating of a hiding place"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"_________ is one of the most critical needs for mental health and well-being in animals.","a":"A sense of control over conditions"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Doubling the size of an enclosure does not necessarily allow a twofold increase in # of cats that can be properly group housed.","a":"T"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"For social group housing, groups of (#) cats are recommended.","a":"43198.0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Incoming animals should be separated by (4) characteristics","a":"-- species\n-- age group\n-- sex/reproductive status\n-- physical and behavioral health status"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"_________ is one the most potent stressors recognized in housed animals.","a":"Overcrowding"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Quarantine areas should be used to segregate unhealthy animals from the general population.","a":"F. Quarantines are for segregation of of HEALTHY animals being observed for new signs of dz. ISOLATION should be used to segregate unhealthy animals from the general pop."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The length of quarantine recommended depends on (3) factors","a":"--availability of space and resources\n-- prevalence of infxs dz in pop or community\n-- incubation period of the dz"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Stressful events are less stressful if they are on a schedule","a":"T"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Laboratory standards for humidity range for cats and dogs","a":"30-70%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Recommended temperature range for cats and dogs","a":"64-84 deg F"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: It is highly recommended to have separate ventilation systems for the various functional areas of the shelter to prevent air exchange between them","a":"F: Few dzs in shelter are transmitted via aerosolization. If air quality is otherwise good and the shelter has good wellness protocols in place this is NOT necessary."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Standard recommendation for air exchanges in an animal housing room (#/hr)","a":"10-15/hr **AT THE LEVEL OF THE ANIMALS"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long after a stressful event does FHV recrudesce?","a":"One week"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what level should ventilation be measured?","a":"At the level of the animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the avg annual death (died in care) rate for animal shelters?","a":"0.0075"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you calculate the cost of a dz?","a":"# sick of sick care days x avg daily cost of care"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"A death rate over _______ should be cause for close examination.","a":"2-3% or increasing over time"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define quality of life","a":"QOL if comprised of an arrage of affective states, broadly classified as comfort-discomfort and pleasure states. In general, the great the pleasant and lesser the unpleasant effects, the higher the QOL. (McMillan 2000)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"List the 5 Freedoms","a":"-- Hunger and thirst\n-- Discomfort\n-- Pain, injury and dz\n-- express normal behavior\n-- Fear and distress"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Euthanasia must be employed (a)_________. Euthanasia should not be used (b) _____________.","a":"a) If no other remedies exist within or beyond the shelter to relieve animal suffering. \nb) As a substitute for providing animals w/ proper care while in the shelter or implementing earnest programs designed to decrease euthanasia or adoptable animals and feral cats."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you determine \"sick animal care days\"?","a":"obtain a daily tally of all sick animals, adding them over time to provide monthly and animal # of days care for sick animals. OR track duration of dz and add the duration for each case over time."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Six general principles of infectious dz control?","a":"1) Removal of infected animals\n2) Mass vaccination\n3)Mass treatment\n4)Good husbandry (animals and environment)\n5) Education of personnel\n6) Quarantine of new arrivals (OR careful biosecurity for most susceptible inviduals may be preferred)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Stress, lack of vax, concurrent dz/parasitism and history or predation or scavenging are all _______.","a":"Animal (host) risk factors for disease outbreaks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Failure to isolate dzd animals, sanitation lapses, some-in/some-out housing, mixing of species, and widespread, non-judicious use of antibiotics and crowding are all","a":"environmental risk factors for disease outbreaks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Six main tasks of outbreak management?","a":"1) Dx and isolation of dz'd animals\n2) ID and mgmt of expose/at-risk animals\n3) Environmental decontamination\n4) Protection of newly admitted animals\n5) Documentation\n6) Communication w. staff, stakeholders, adopters, and the public"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When obtaining diagnostic samples in an outbreak of unknown etiology, you should pick (choose) acutely/chronically/un  affected animals to sample","a":"acutely"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"% of affected population that should be sampled in an outbreak situation, OR minimum # of animals to sample","a":"10-30 %, OR 3-5 individuals min"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: The release of low or moderate risk animals during an outbreak is not recommended.","a":"F: \"In some cases, release of low to moderate risk animals with suitable disclaimers is the better choice\" [vs euthnasia or prolonged quarantines]"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name the 2 most important factors in determining the outcome of disease expose (bonus for third!)","a":"1) The dose to which the animal is exposed\n2) The immune status of the exposed animal\nBONUS 3) Proximity to dz'd animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Canine respiratory pathogens can be transmitted (a)______ feet, while feline respiratory droplet spread is (b)_____ feet","a":"a) >=25 feet\nb) 5 feet"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Serology correlates well with risk status for which dzs?","a":"CPV, FPV, CDV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Exposed animals with moderate/high risk of infection should be reomved from the pop in order to prevent cont'd dz spread.","a":"T"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Quarantine is a practical option for which diseases?","a":"CPV, FPV, Canine Influenza (H3N8) (dzs with short, defined incubation periods.\""},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: A CDV outbreak is unlikely to be resolved through improved sanitation.","a":"T (not an environmentally hardy virus)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"List of disinfectants proven effective against unenveloped viruses","a":"Sodium hypochlorite (household bleach diluted to 1:32), potassium peroxymonosulfate (Trifectant), AHP (Rescue)* * this one was not in the textbook :)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"List of dzs for which prophylactic drug treatment of a population may be indicated during an outbreak","a":"1) Ringworm (LS @ intake)\n2) Coccidia--> puppies and kittens\n3) Strep canis or zooepidemicus--> abx for new intakes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Under what circumstances is strict quarantine of incoming animals indicated?","a":"Community wide dz outbreak"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are the three types of fluid disturbances that can occur in a patient?","a":"1. changes in volume, 2. changes in content, 3. changes in distribution"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"intial patient assessment should include:","a":"evaluation of hydration, tissue perfusion, and fluid volume/loss"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"are warmed (body temp) fluids most useful in large volume resuscitation or in low IV infusuion rates?","a":"large volume resuscitation"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"The amount of fluid estimated to maintain normal patient fluid balance is called what?","a":"maintenance rate"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"______ accounts for the majority of fluid loss in a healthy patient","a":"urine"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when is maintenance rate therapy indicated?","a":"when the patient is not eating or drinking but does not have ongoing losses, hypovolemia, or volume depletion"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"LRS is what kind of fluid?","a":"isotonic polyionic replacemnet crystalloid"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"LRS usage can predispose a patient to hypo_____ and hyper_____ due to the concentration electrolytes in the fluid","a":"hypokalemia, hypernatremia"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When using a crystalloid for replacement fluids, how often should you monitor serum electrolytes?","a":"q24hr"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Other maintenance fluid options are....","a":"replacement crystalloid mixed with D5W supplemented with K, or sodium chloride supplemented with KCL"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are three benefits to providing fluids to healthy patients under going surgical events?","a":"1. replacement of ongoing losses, 2. countering of anethestic drug negative physiologic effects, 3. keeping the catheter patent incase it is needed"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the primary risk of providing IV fluids to healthy patients?","a":"providing excess fluids resulting in vascular overload"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the recommended fluid rate to avoid adverse effecrts associated with hypervolemia?","a":"<10ml/kg/hr"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are the fluid rates the authors recommend for cats and dogs?","a":"3ml/kg/hr for cats, 5ml/kg/hr for dogs"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: Fluid and electrolyte imbalances should be corrected as much as possible before anesthesia and surgery.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: Fluid rate should be reduced if anesthetic procedures last >1hr","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is often a cause of hypotension in an anesthetized patient and should be corrected before fluid rate is changed?","a":"excessive anesthetic depth"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Once you have decreased anesthetic depth in a hypovolemic patient, if peripheral vasodilation is contributing to hypertension what should you do next?","a":"provide an IV bolus of isotonic crystalloids such as LRS 3-10ml/kg, can be repeated once if needed"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"If the patients response to the IV bolus of crystalloids is not sufficient, what should be done next?","a":"consider IV administration of a colloid such as hetastarch (1-5ml/kg in cats, 5-10ml/kg in dogs) - measure blood pressure every 3-5 minutes"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: You should use hypotonic solutions to correct hypovolemia.","a":"False, use of these or as fluid boluses can lead to hyponatremia and water intoxication"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"in a sick patient, fluid therapy should be provided based on first ____ and then secondly ____.","a":"First determining the initial rate and volume based on whether whole body rehydration is needed or vascular space volume expansion, secondly determine the fluid type based on replacement and maintenance neededs"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the goal of fluid therapy in a sick patient?","a":"To restore normal fluid and electrolyte status within 24 hours"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are clinical signs of under-administration of fluid therapy?","a":"persistent increased heart rate, poor pulse quality, hypotension, urine output"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are clinical signs of over-administration of fluid therapy?","a":"increased resp rate and effort, peripheral or pulmonary edema, weight gain, pulmonary crackles"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are diseases that have a higher risk of fluid overload?","a":"heart disease, renal disease, patients recieving fluids via gravity flows"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Why are cats less tolerant of high fluid rates?","a":"they have a small blood volume, lower metabolic rate, higher incidence of occult cardiac disease"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"An example of whole body fluid loss is....","a":"dehydration"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"An example of vascular space fluid loss is....","a":"hypovolemia due to blood loss"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"An example of hypervolemia is....","a":"oliguric.anuric renal failure, heart disease, iatrogenic fluid overload"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the fluid deficit calculation?","a":"body weight in kgs  x  %dehydration = volume (L) to correct"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: The deficit and ongoing losses should be added to maintenance volumes with the ongoing losses corrected within 2-3 hrs and hte deficit volume corrected over a longer period","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What should be the range of frequency of montioring?","a":"q15-60mins"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: Maitenance fluids low in NA should be sued to replace extracellular deficitis.","a":"False, use may lead to hyponatremia and hyperkalemia when administered in large volumes"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is hypovolemia?","a":"a decreased volume of fluid in the vascular system with or without whole body fluid depletion"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is dehydration?","a":"depletion of whole body fluid"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is a common cause of hypovolemia?","a":"severe dehydration, rapid fluid loss, vasodilation"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are clinical signs of hypovolemia?","a":"decreased tissue perfusion, abnormal mentation, mucous membrane color, capillary refill time, pulse quality, pulse rate, cold extremities or body temp"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Hypovolemia due to decreased oncotic pressure is suspected in patients that have a total protein of ______ or albumin of ______.","a":"<35 g/L; <15 g/L"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are clinical signs of shock?","a":"hypovolemia, decreased BP, increased lactate (>2mmol/L), cats may not be tachycardic"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the initial fluid of choice when intravascular volume expansion without whole blood is needed?","a":"IV isotonic crystalloids"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"High K administration rates may lead to cardiac arrest so do not exceed ______ .","a":"0.5mmol/kg/hr"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the standard crystalloid shock dose?","a":"essentially one complete blood volume; 80-90ml/kg IV in dogs 50-55ml/kg IV in cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Crystalloid shock fluid doses should be administered in ____ increments","a":"25% of calculated shock dose"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When should you consider changing fluids to a colloid in shock therapy?","a":"if administration of 50% of calculated shock volume has not caused sufficient improvement"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"Once shock is stabalized, over what time period should the initial calculated volume deficit be corrected?","a":"6-8 hrs"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when should colloids be administered?","a":"when the fluid volume needed is to great, when they have not responded to crystalloid therapy, when increased tissue perfussion and 02 is needed, if edema develops prior to adequate volume restoration, if decreased oncotic pressure is suspected, when there is a need for longer duration of effect"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the duration of effect of colloids?","a":"up to 24 hours"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the typical starch colloid dose for the dog? the cat?","a":"20ml/kg/24 hrs (divide into 5ml/kg boluses); 10-20ml/kg/24hr (typically 10ml/kg in 2.5-3ml/kg boluses)"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When would you use crystalloids and colloids together?","a":"when you need to both increase intravascular volume (colloids) and replenish intersititial defecits (crystalloids)"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are the shock doses of hyertonic saline?","a":"4-5ml/kg for dog, 2-4ml/kg for cat"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how long do the direct effects of hypertonic saline last?","a":"30-60 min"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when should you use hypertonic saline?","a":"to get cardiovascular benefit with least amount of fluids, to translocate fluids from the interstium to the intravascular space (management of hemorrhage)"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: Colloids potentiate the effects of hypertonic saline","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"how does one make the decision on whether or not to use blood products?","a":"depends on the estimated severity of blood loss"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what would be a possible fluid choice for maintenance therapy in patients susceptible to volume overload?","a":"0.45% sodium chloride"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"are subcutaneous fluids adequate to treat hyperthermia?","a":"No"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What medical conditions lead to body fluid content changes?","a":"diabetes, renal disease, urinary obstruction - conditions which cause electrolyte disturbances, blood glucose alterations, anemia, and polycythemia"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what kinds of cases would one suspect hyperkalemia?","a":"obvious urinary obstruction, uroabdomen, acute kidney injury, diabetic ketoacidosis, changes in ECG"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is considered life-threatening hyperkalemia?","a":"K>6mmol/L"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"When providing fluid therapy to an animal with hyperkalemia, should the fluid used contain K?","a":"Yes, there are several benefits including expanding volume and lowering serum K, offsetting the effects of lost K when an obstruction is removed, alkalinizing which promotes exchange of K with H, and the concentration of K is lower than those typically seen in serum"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the maximum IV administration rate of K?","a":"0.5mmol/kg/hr"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is a consideration when mixing KCL into a fluid bag?","a":"it must be mixed well to avoid a potentially fatal overdose of K"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what are causes of hypernatremia in patients?","a":"water deprivation, use of crystalloid fluids long-term, salt toxicity"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is a concern when lowering Na levels?","a":"cerebral edema; do not exceed changes in Na levels of 1mmol/hr in acute cases or 0.5mmol/hr in chronic cases due to risk of cerebral edema"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the calculation for the infusion of free water (D5W) over time?","a":"volume of free water (L) = ([current Na concentration/normal Na concentration]-1)x(0.6xbody weight (kg))"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what two conditions commonly present with hyponatremia?","a":"DKA and water toxicity"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are the guidelines for treating hypoalbuminemia?","a":"nutritional support is critical, plasma administration is not suffcient, synthetic colloids are beneficial to increase oncotic pressure"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"At what level of albumin or total protein will fluid loss into the pulmonary, pleural, abdominal, intestinal, or intersititial spaces occur?","a":"<15g/L; <35g/L"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the rate to use colloid therapy at for dogs and cats with hypoalbuminemia?","a":"20ml/kg/day dogs; 10-20ml/kg/day for cats"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"what is the goal of fluid therapy for hyperglycemic patients?","a":"correcting dehydration and electrolyte abnormalities"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the basis for therapy for hypoglycemia?","a":"severity of clinical signs and not laboratory findigns"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"How much of a 50% stock dextrose solution would you add to a L fluid bag to make a 5% dextrose solution?","a":"add 100ml of the 50% dextrose to 900mls of the fluid"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are the components of treatment of symptomatic polycythemia?","a":"phlebotomy to reduce RBCs, replace volume removed with balanced electrolyte solutions to decrease viscosity, improve blood flow, and increased 02 delivery"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: Most patients will benefit from empirical fluid therapy while awaiting lab results.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are the two types of fluid distribution abnormalities?","a":"edema and effusions"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What are the two main causes of edema/effusions","a":"loss of intravascular oncotic pressure and loss of vascular integrity"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is recommended therapy for pulmonary edema?","a":"stop fluid administration, consider diuretics, address CV disease, provide mechanical ventilation and positive end-expiratory pressure if needed"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What is the recommended therapy for effusions?","a":"stop fluid administration, diuretics if indicated, address cause of the effusion, perform either abdomino or thoracocentesis if respiratory is compromised."},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"If 24 hour monitoring cannot be provided what are steps that can be taken to make fluid therapy safe?","a":"consider giving a higher rate while staff are present and only administering sq fluids overnight, use fluid pumps when possible, use a small volume fluid bag to reduce the chance of overload, place an ecollar on the animal to prevent catheter removal, luer lock connections to avoid accidental disconnection"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: A new IV line and bag should be used for each patient regardless of route of administration.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: A buretrol can be used if frequent fluid composition changes are anticipated to reduce changing the entire bag.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"True/False: A small catheter can be placed easily and therefore is desired when placing one.","a":"False, place the largest catheter possible to avoid impaired fluid flow"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"How often should catheters be flushed?","a":"q4hrs with normal saline or heparin solutions"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"What does the CDC recommend for fluid administration lines to avoid nosocomial infections?","a":"that they be replaced no more than q4days"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"does LRS exacerbate lactic acidosis?","a":"no"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"when flushing a cather is normal saline as effective as heparinized saline?","a":"yes"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when should \"non-accidental injury' be included in the ddx for an animal?","a":"when clinical signs cannot be attributed to the history the client presents"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Owners who seek medical care for their animals are unlikely to be abusive.","a":"0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the most prevalent signalements for abused dogs and cats?","a":"<2 years of age, male dogs >female dogs; dsh, mixed breed dogs, staffies"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are diagnostic pointers, guidelines, or indicators?","a":"particular features of a case that raise concern of physical abuse"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: A single feature can be diagnostic and combinations are not neccessary.","a":"False, a combination is what raises suspicion"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What aspects of history might raise suspcision?","a":"injuries more severe than explained by the history, discrepant histories provided, previous injury or death of another household pet, no history of an accident, animal is indoor only, family violence is known or suspected"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is repetitive injury?","a":"the animal is presented more than once with injuries, or injuries of different ages are found, fractures feature prominently in this type of injury"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Multiple fractures in different stages of healing on multiple bones is suspicious of abuse.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is fabricated or induced illness?","a":"rare type of abusethat involves the falsification of illness in an animal to gain attention and sympathy for the owner"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are other differential diagnosis for non-accidental injuries?","a":"motor vehicle accidents, skeletal disorders(osteogenesis imperfecta, metabolic bone dz), blood dyscrasias"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in a study of 600 dogs with motor vehicle accident injuries, what were the common injuries?","a":"79% had abrasions to the extremeties, 35% had abrasions to the head; broken claws are also common"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in a study with 357 dogs with motor vehicle accidents, where were the injuries recorded?","a":"most of the injuries (302) occurred in the half of the body caudal to the last thoracic rib, with the pelvis being the most frequently injured structure (102)."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in a study of 147 non-accidental injury cases, how many pelvic fractures were seen?","a":"1.0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"at what age and period does a kitten learn to right itself in the air when falling?","a":"starts at 4 weeks and is smooth by 6-7 weeks"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the 'locus'?","a":"the site or scene where the event occured"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what advantages can be gained by having the veterinarian at the scene of the event?","a":"evidence of struggle, attempted escape or restraint, whether animals died at the same time or sequentially, get a timeframe from observation of the environemntal clues associated with the body"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are the three type of loci?","a":"1. incident, death, and discovery at the same site; 2. incident at one site, death and discovery at another; 3. incident and death at one site, discovery at another"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are best practices regarding examination protocols?","a":"maintenance of chain of evidence by receipt, recording specimens in a daybook or computer system, creation of a documentation file, suitable and secure storage of specimen, prevention of cross-contamination of specimens, maintenance of register of samples being stored, routine for IDying dating and signing rads"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"TRUE/FALSE: Public health considerations including exotic and zoonotic disease should be considered before beginning a post-mortem examination.","a":"TRUE, use of a saftey cabnet and PPE as needed"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: When identifying and animal the pathologist should be as specific as possible with breed and species and not use generic terms like owl, even when that term is used by another agency or person.","a":"False, use of consistent generic terms is perfered to provide consistency and veterinarians are use for their expertise in the field fo pathology not taxonomy"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: If the specimen comes with a string paper label attached to it, this should be replaced with a more durable label made of tape with black writing on a white background","a":"False, any labels already on the speciman should be maintained and protected, additional labels can be added using durable tape if needed"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Is it important to note the number and type of coverings on a sample and fluid leakage?","a":"Yes, these should all be carefully removed and noted, any that contain identification should be maintained"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Is the body weighed with or without the coverings?","a":"without"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"How do you measure body length?","a":"from the back of the head to the base of the tail"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what type of imaging should be performed?","a":"photographs of both sides of the body, whenever possible xrays of the body"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what study would be concerned with the maggots or beetles found on a body?","a":"forensic entamology"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"TRUE/FALSE: During necropsy exam, changes related to natural disease should be recorded as well as those that might be cause by unnatural insult","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what marks the end of the post-mortem exam?","a":"a record of where, when, and under what conditions the body was stored after necropsy"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the three purposes of the post-mortem report?","a":"describes in non-technical terms the normal and abnormal findings, explains how they might have occurred, provides a balanced appraisal of the significance of hte necropsy findings for the case"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"the report should include what sections?","a":"title page, index, qualifications and experience of the examiner, instructions (who asked for the exam), identity of the victim and owner and administrative details, comments and conclusions, preliminary post-mortem findings, post-mortem findings (seperate out external, internal findings, samples retained, and summary of findings), references, signature and date"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what type of language should be used in the report for the court?","a":"lay term language, simple sentences"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is malnutrition?","a":"poor nutrition that has arisen as a consequence of insufficient or poorly balanced food or because of faulty digestion or utilisation of food"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Birds of prey that are used for hunting may have 'flying weights' that are significantly less than the ideal weight for a resting bird.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a clear indicator of adequacy of recent nutrition in a live animal?","a":"body condition scoring"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when begginning to dissect a cadaver, one should first palpate the body to assign a general assessment of body condition using what range?","a":"excellent, adequate, emaciated"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: it is generally unnecessary to compare the weight of the animal to breed standards?","a":"0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in the interaction between malnutrition, frequent infection and impaired immune function, what is often considered the inciting factor in humans? what could also be the inciting cause in animals?","a":"malnutrition; infection"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"list post morten finding in malnutrition for skin:","a":"loss of sq fat, wrinkled skin from dehydration, dull, dry, brittle coat, parakeratosis etc"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"list post morten finding in malnutrition for muscle:","a":"atrophy after 24 hours of starvation(monograstrics) about 3 days in adult ruminants, back and thigh muscles first, interference with rigor mortis"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"list post morten finding in malnutrition for fat:","a":"deposits in omentum and mesentery depleted first, then perirenal area, under skin, around the heart, and bone marrow, flabby appearance from fat loss in connective tissue"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is 'serous atrophy'?","a":"term used to describe the gelatinous masses containing flecks of degenerating fat found in the perirenal and coronary areas of emaciated animals"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what % of body weight dose a normal healthy ruman account for?","a":"0.25"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"does the rumen of an underweight animal exceed the normal % or fall below it?","a":"exceed since the body is smaller and they may consume large quantities of poor quality feed"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a unique rumen observation of sheep that indicates starvation?","a":"moderate quantities of fluid in the rumen, as their ruminal contents should be relatively dry"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: because ruminants (even rabbits) store food in their rumens for long periods of time, presence of ingesta in the rumen and even in the small intestine is not uncommon even when the animal is malnourished.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"list post morten finding in malnutrition for stomach of monogastrics:","a":"empty stomach and small instestine, gastric ulceration, pika, dry/sticky fecal material in large intestine, gi tract may not smell as bad as an adequately nourished animals"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what other organs show marked atrophy with emaciation?","a":"liver, spleen, pancreas, thymus and salivary glands"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how does one make a 'cleaned bone' preparation?","a":"removal of the majority of the soft tissue followed by digestion in a solution of biological washing powder at 60oC"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what duration of fracture is indicated by yellow serum-like fluid around the fracture or in the soft-tissue?","a":"longer post-traumatic period as this is from clot break down"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what duration of fracture is indicated by fresh hemorrheage, clot formation, fibrin strands and no repair?","a":"recent fracture"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when does microscopic periosteal proliferation begin?","a":"within 24 hours"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when does radiographic evidence of mineralization most likely to be seen","a":"2 weeks post-trauma"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: callus formation may not occur in heavily comminuted fractures","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: closed fractures of long bones may become infected if left untreated","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a wound?","a":"a skin injury, caused by some external force, that may extend to deeper tissues"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are blunt force injuries?","a":"abrasians, bruising, or lacerations, injury where extenal force is used and deeper tissues are injured without necessarily breaching the skin"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the initial stage of injury investigation?","a":"describing the nature and location of the injuries"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the second stage of injury investigation?","a":"trying to determine how they were inflicted and whether they were accidental or deliberate"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are sharp force injuries?","a":"incised wounds, stab wounds"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what terms are generally excepted in human forensics and understood by lawyers?","a":"abrasion, laceration, incised wound, puncture wound, and perforating wound"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: For the most part, injuries identify where the blows struck but not the weapon.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Which is more common, single blow injuries or multiple injuries widely distributed over the head, body, and limbs?","a":"multiple injuries"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is an abrasion?","a":"the most superficial of wounds to the skin, where the skin collides tangentially with a rough surface removing the outer layer"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What does a fresh abrasion look like vs an older abrasion?","a":"start off leaking tissue fluid and appear wet at first, then become darker and drier with time"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Why id the patterned crush abrasion valuable in human forensics relatively rare in veterinary forensics?","a":"hair protects the skin from many minor blows that would otherwise cause abrasion of bare skin"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is bruising/contusions?","a":"result from blunt force trauma, blood leaks from vessels within the skin or from deeper tissues"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What factors can increase the size and appearance of a bruise?","a":"tissue density and fragility of blood vessels, loose, soft well vascularized tissues allow blood to pool, bleeding my be increased where tissues are stretched or crushed against the bone underneath"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What can obscure bruising?","a":"hair and skin color, when possible clipping/shaving suspected areas may be helpful"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: even with thorough external exam, severe bruising may not be discovered until the skin is reflected at post-mortem examination","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: exposed bruising should be photographed and documented asap as it can fade, spread, and become less clearly defined?","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what types of objects leave characteristic 'tramline bruising'?","a":"sticks, broom handles, similar narrow objects on hairless skin  - get two linear bruises at the margins of the area of contact by the stick"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"List the times and associated color changes expected from a bruise as it ages in birds:","a":"2 mintues - red; 12 hours dark red-purple; 24 hours light green-purple; 36 hours yellow-green-purple; 48hours yellow-green; 72hrs yellow-orange; 96hrs slightly yellow, normal by 120 hours"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what by product of bruising may be trapped in tissue and provide evidence of previous bruising in suspected cases of repetitive injury?","a":"haemosiderin"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a laceration?","a":"a wound caused by blunt trauma that results in tearing or splitting of the tissues"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"can muscle be severely lacerated under intact skin?","a":"Yes"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: lacerations frequently conform to the shape of the object that inflicted the damage?","a":"False, they do not"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Bleeding is commonly less than might be expected for the severity of a laceration?","a":"True, the stretching crushing action of the injury can cause blood vessels to retract"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Extensive or marked hemorrhage in the temporalis m of dogs suggests high-energy trauma","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What if there is no bruising over the head but the history is of the animal being beaten over the head?","a":"either the history is false or the animal was already dead"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is a caution about 'bilaterally symmetrical areas of bruising on the skull'?","a":"usually these marks are normal anatomical features that are generally overlooked in diagnostic necropsies or they are postmorten artifacts"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the categories skull fractures are divided into?","a":"simple, complex, comminuted, depressed, or elevated"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a simple skull fracture?","a":"single lines that extend in a straight, jagged or curved manner but do no cross sutures"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a complex skull fracture","a":"there is more than one fracture line"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what does fracture of the parietal crest suggest?","a":"a direct heavy blow to the top of the head"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what injuries are common in hammer attackes?","a":"depressed skull fractures over the frontal sinuses, with possible hemorrhage into both sinuses"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is it called when force put on a young animals head gives rise to separation of the suture lines in the skull?","a":"diastasis"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what would be another clinical sign associated with diastasis in the floor of the cranium?","a":"this can lead to considerable bleeding from the nose as blood tracks forward into the nasal cavity"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the three type of cranial hemorrhea?","a":"extradural (caused by fracture of the skull and tearing of the meningeal artery), subdural (always due to trauma and arises from tearing of communicating veins, subarachnoid (occurs in penetrating injuries to the brain)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Does subarachnoid hemorhage clot?","a":"this hemorrhage mixeds with CSF and is less likely to clot and therefore more mobile"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Blows that would cause only superficial tissue damage over the top of the head could result in extensive fracturing of the face","a":"True, the bones over the nose are generally less robust"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what can be misdiagnosed as zygomatic arch fracture?","a":"the zygomatic arch in some adult animals remains open, but if this is an anatomical abnormality it would not be associated with bruising"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what can cause bleeding on the medial side of the mandible, requiring reflection of the tounge to see the bruising?","a":"kicks to the jaw"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: subconjunctival and scleral hemorrhage is more frequently reported by clinicians than pathologists, suggesting that hemorrhage dispersses quickly in the early phase of death?","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: externally there may be limited or no evidence of ligature marks in fatal strangulation","a":"True, the hair and looseness of the neck skin can protect against such abrasions"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the major cause of chest wall bruising?","a":"blunt trauma"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in young cats and dogs, where should one look for bruising if you expect blunt force trauma to the chest?","a":"in the intercostal msucles as these are torn during the trauma"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are complications associated with fractured ribs?","a":"pneumothorax, hemothorax, and puncturing of the lungs by fractured ribs"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what can cause tracheal avulsion from the lung closest to the bifurcation?","a":"attempted wringing of the neck"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Bruising of the heart and rupture of the pericardium are uncommon during severe blunt trauma","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Is the presence of blood-stained fluid in the pericardial sac considered a normal or abnormal findings?","a":"this can be a common finding after freezing and thawing of a body"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Lack of bruising of the abdominal wall does not correlate with an absense of serious injury to the abdominal organs?","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"splenic injury occurs more or less commonly than liver damage with kicking or beating of dogs or cats?","a":"less commonly"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What causes incised wounds?","a":"sharp-edged objects being drawn across the skin surface, also called cuts or slash wounds"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what characterizes incised wounds?","a":"tend to be long relative to their depth, have clean-cut edges devoid of abrasions or bruising and bleed profusely"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/Faslse: Stab wounds may result in severe internal hemorrhage although external bleeding may be slight","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The ____ of a stab wound is usually considerably greater than the ____ of the skin wound.","a":"depth, length"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Can the shape of a stab wound in the skin reliably be used to predict the weapon that made it","a":"no"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is a perforating wound?","a":"wounds that pass through the body, or part of the body, and result in an entry wound on one side and an exit wound on the other"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"_____-energy levels can be reached in overhand and side-swipe stab attackes, whereas thrusts tend to be ____ in energy","a":"high, lower"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"is skin or muscle the main barrier to penetrating wounds?","a":"skin, muscle resistance is overcome by the follow-through action of stabbing"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are important time periods for aging a wound and healing?","a":"24 hours - serum/clot with congestion, swelling and leucocytic infiltration; 36 hrs new capillaries; 48-72hrs spindle shaped cells at right angles to vessels; 5-6 days fibrils parallel to new vessels; 21 days new collagen laid down"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the general distribution of burns?","a":"often assymmetrical or localised, biologically abnormal patterns such as straight or angular borders, drip configurations or unusual symmetry"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"after what point do burns generally not progress?","a":"5 days"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what degree of burn is cellular damage confined to the epidermis?","a":"superficial first degree"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what degree of burn is coagulative epidermal necrosis with dermal edema, vesicles and bullae form in the epidermis?","a":"partial thickness second degree"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what degree of burn involves full thickness coagulative necrosis","a":"full thickness third degree"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what type of diagnostic can be very helpful in a suspected gun shot case?","a":"radiographs, need both lateral and dorsoventral since it is a 2-D view"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"TRUE/False: Radiographs can aid in establishing which type of weapon was used based on the fragmentation pattern","a":"True, the type of ammunition may be able to be identified"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"____-velocity bullets disintegrate to a greater extend on impact resulting in a pattern commonly called 'lead snowstorm'","a":"high"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: On general exam it is normally easy to identify the entry and exit wounds from a gun shot.","a":"False, they are normally obscured by hair or feathers and animals will require shaving or plucking"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What would be an indication that the wound was the entry point of the bullet?","a":"feather or tufts of hair are drawn into the entry hole"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What can complicate interpretation of exit wounds?","a":"exit wounds can be caused by bone fragments instead of bullet fragments, also only part of the bullet may exit at a sight"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is the forumale to calculate kinetic energy?","a":"E= (1/2)mv^2"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what kind of mass, velocity, and energy do air-powered weapons have?","a":"light weight, low speeds, low energy - generally only fatal to birds and small mammals"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What kind of wounds are caused by air-powered weapons?","a":"3-5mm small round entry holes, exit may be larger and oval, common to have injuries to the eyes; if multiple pellets, older pellets will be encapsulated in fibrous tissue and have no associated hemorrhage"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is an important factor affecting destructive force with a shotgun?","a":"proximity to the target"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"As the discharge distance _________s, so does the dispersal of the individual pellets","a":"increases"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: Measurement of the entry wound (and consideration of scattered pellets around the main hole), whether scalloped edges are present, and whether soot is on the animal coat all help indicate the distance at which the shot was taken.","a":"True, within 2 ft there will be a single ~1inch entry hole, at 3ft this hole will have scalloped edges, by 4 ft there will be scattered pellets around the hole by 6-7ft the central hole has an irregular outline, within 1 ft there will be soot on the coat"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"TRUE/False: Exit holes from shot gun injuries are uncommon in large animals but may be present in small mammals and birds.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What process, caused by high powered ammunition can cause a cavity that extends to 30x the diameter of the bullet causing stretching and devitalization of tissues?","a":"the rapid transfer of kinetic energy from the bullet into the tissues causes this 'temporary cavity', this is also why the exit wound will be much larger than the entry wound"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"How might one tell between shots administered before and after death?","a":"the lack of significant bleeding along a permanent wound track is often the main feature that indicates a shot was administered after death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the final cause of death in asphyxiation?","a":"cerebral hypoxia followed by cardiac arrest"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: In strangulation cases, externally there may be limited evidence of ligature marks","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are clinical signs consistent with hanging?","a":"cyanosis of the teats, perineum and vulva, focal intradermal hemorrhages of the posterior abdominal skin, congestion of the sclera, pink froth in the lower trachea, congestion of the lungs especially the most dependent lobes"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the pathologic changes associated with choking?","a":"cogestion, intra-alveolar flooding and hemorrhage, alveolar over-distension, portions of whatever caused choking can be found in the bronchi"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are pathologic changes associated with smoothering?","a":"variable distribution of bruising under the chin, over the premaxilla, maxillary and frontal bones and inner aspects of the lips where they contact the teeth"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what color change and causative compound suggests carbon monoxide poisoning?","a":"relatively stable unusual pink color, carboxyhaemoglobin"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"although cyanide poisoning results in a bright ____ coloration of organs, this color fades rapidly and may not be seen on necropsy","a":"red"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the odor that might be an indicator of cyanide poisoning?","a":"bitter almond"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are consistent pathologic findings of drowning?","a":"stable pink froth in the trachea and bronchi, congestion of the lungs"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the typical presentation for a heat stroke victim?","a":"usually collapsed, has a very high body temp, serious complications in the brain, kidney, liver and circulation"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Death often occurs at or above what body temperatures in dogs?","a":"106, 107.6 is the upper fatal body temp"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how much of a dogs heat is lost through radiation and conduction from hte body surface?","a":"0.73"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are pathologic changes associated with heat stroke?","a":"all organs discoulored deeply red or dirty brown from vascular congestion, most pronounced in the trachea, lungs and bronchi, heart, kidneys, lymph nodes, and meninges"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"does hyperthermia increase or decrease the speed of onset for rigor mortis?","a":"increase"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how long can it take for the full extent of frost bite damage to be fully demarcated?","a":"4-15 days in mammals, 3-6 weeeks in birds"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is electrical current?","a":"measured in amperes, the energy that flows through a conductor and is responsible for the generation of heat"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"During electrical incident, where are the two area of greatest tissue damage often located?","a":"one contact point to the source of the electricity and the exit point"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what causes death in fatal electricution?","a":"cardiac arrest or damage to vital centers in the brain"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: rigor mortis develops quickly and passes off early in electrocuted animals","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are pathologic changes assocaited with electrocution","a":"congestion, petechiae, accelerated post-mortem decomposition, linear tracheal hemorrhages, blood may be dark and unclotted"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"_____ chemicals are of particular concern becaue the are able to penetrate all layers of the eye and cause irreversible damage","a":"alkalis"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are the two factors that must be decided in a possible bite injury case?","a":"whether the lesions are the result of bites, differentiation of dog bite injury from other predators"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/false: cats commonly kill by biting the neck and head to immobilize the prey quickly and prevent struggling while dogs bite wherever they can.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"How does one calculate the size of the mouth involved in the bite?","a":"measuring the intercanine distance of 'bite pairs'"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: puncture wounds in the skin are not an essential element of dog-bite injury","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"true/false: serious head injuries occur commonly in dog-bite injury","a":"0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what action causes dog bite wounds to consist of a mixture of crushing and irregular tearing injuries?","a":"one canine tooth serves as an anchorage, while the other teeth cut into the flesh causing stretch lacerations in the process of biting, shaking, and tearing"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what si the reproted distribution of dog bites on dogs in n. AMERICA?","a":"Limb, head and neck, thorax and abdomen, and perineum (in that order)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what si the reproted distribution of dog bites on dogs in israel?","a":"thorax, extremities, limb, and tail, head and neck"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Small dogs sustaim the most ______ injuries while larger dogs have the highest prevalence of ______ wounds","a":"thoracic, head"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are common sites of damage for dog on cat injuries?","a":"back, thorax, abdomen"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the post-mortem interval?","a":"the time since death, the time that has elapsed between the death of an animal and discovery of the body"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"should the post-mortem interval be reported as a precise time or death or an interval?","a":"an interval, generally less than 24 hrs, 1-3 days, 3-7 days, 7-21 days, weeks, months or years"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are a few of the factors that affect cooling of the body","a":"insulation, ambient temperature, movement of air and immersion in water"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in a study of beagles, what was found to be helpful in establishing hte approximate time of death?","a":"rectal temperature"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how long is rectal temperature useful for establishing time of death?","a":"over the first 10 hours"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how quickly did beagle body temperature decline to ambient temperature?","a":"24-48 hours after death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when is rigor mortis generally considered to appear after death?","a":"between 1-6 hours (avgs 2-4)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how long can rigor mortis last?","a":"depending on the circumstances a few hours to several days"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what accelerate rigor mortis?","a":"increased body temperature, high environmental temperature, antemortem reduction in glycogen stores"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what delays and prolongs rigor mortis?","a":"dry, cold conditions"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"why does rigor mortis occur?","a":"commences when the rate of re-synthesis of ATP is less than its degradation, so there is no ATP present to cause muscle myosin filaments to relax"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"do human pathologists tend to over or under estimate the time since death?","a":"under estimate"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"How quickly can green discoloration of the ventral abdomen occur in dogs?","a":"within 24 hours of death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"why does the green discoloration occur?","a":"post-mortem activity of micro-organisms in the intestines (does not occur as much in malnourished animals because of this)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"do changes occur in the thoracic cavity post-mortem faster or slower than in the abdominal cavity?","a":"generally slower"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"At what point was blood-stained fluid notes in the thoracic cavity of beagles?","a":"7 days after death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when was fluid noted in the pericardial sac of beagles?","a":"23 days post mortem"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what change in the body can freezing cause?","a":"generalized pink discoloration of many tissues"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what aspects of burial retard decomposition?","a":"lower ambient temperature, exclusion of oxygen and protection from scavengers"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"does immersion in water increase or slow the rate of decomposition?","a":"slows the rate of putrefaction"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"how long does it take to partially or completely mumify a dog?","a":"a few weeks for partial, many months for full"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is adipocere?","a":"caused by hydrolysis and hydrogenation of adipose tissue, leading to the formation of a greasy or waxy substance if of recent origin; remarkably stable - typically forms and is visible to the eye around 3 months"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what type of larva is most important for investigations?","a":"blowfly"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"should larvae be stored in ethanol?","a":"no this can change their size and prevent appropriate aging"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what is the prefered term for bestiality or zoophilia?","a":"animal sexual abuse"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what constitutes animal sexual abuse?","a":"actions that center on the sexual organs, or the anus and rectum"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"True/False: there is a connection between animal sexual abuse and the sexual abuse of childern?","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"in 2002, of the 1000 violent crimes against horses in germany, how many were associated with the genetalia?","a":"0.25"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"an investigation in the US identified ____% of the 448 reported cases of non-accidental injury as sexual in nature.","a":"0.06"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what kinds of poisons are used commonly in cases of malice\"?","a":"agrochemicals and rodenticides"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what samples should be collected during necropsy when poisoning is suspected?","a":"any material in the mouth, crop esophagus can be pooled, stomach contents should be collected seperately, live and kidney, blood"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: Because of their professional expertise it is veterinarian's ethical and legal responsibility to determine whether or not a criminal act of cruelty has been committed","a":"F. It is the responsibility of the law enforcement agency- animal control, the police, or the prosecutor- to make the ultimate determination as to whether or not crimial charges will be filed. Veterinarians tend to mistakenly believe it is their responsibility to apply te law to a particular set of circumstances."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: All that is legally necessary is for the veterinarian to have a reasonable or good faith belief in order to report a case of animal cruelty.","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: It is particularly important that the vet document what the client says when explaining the animal's condition.","a":"T. What the client says is often as imiportant as what is observed. In some situations the person's behavior may be a factor for the vet to consider and document. The client in the office or suspect at the scene may admit incriminating conduct. IT is essential to write down exactly what was said and by whom."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: If perpetrator is younger than the statute allows for criminal charges vets must still abide by the laws governing reporting in their juridiction.","a":"T One should not presume tha the parent or guardian will follow up with the appropriate intervention. The act of cruelty by a child may be an indicator of problems wihtin the home."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: In large scale cruelty investigations it is ideal though not required to prepare and maintain a separate and distinct identifying photograph and medical record for each individual animal.","a":"F. IT is critical to prepare and maintain a separate and distinct identifying photograph and medical record for each individual animal."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Match the term with the appropriate description: consulting expert, opinion expert, fact witness\nA) A vet with a personal, direct, first-hand knowledge of either the incident or the involved individuals\nB) Any licensed veterinarian\nc) A vet with specialized knowledge, training and experience that assists in analyzing and evaluating  the evidence of  given case who may or may not testify.","a":"A) A vet with a personal, direct, first-hand knowledge of either the incident or the involved individuals-- fact witness\nB) A licensed veterinarian -- opinion expert \nc) A vet with speicialized knowledge, training and experience that assists in analyzing and evaluating  the evidence of  given case.-- consulting expert"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: When testifying it is best to avoid saying \"I believe\" or \"I think\"","a":"T: other statements to avoid include \"I imagine\" and \"I guess\""},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The most pathognomonic feature of abuse in animals is ______ injuries.","a":"The most pathognomonic feature of abuse in animals is repetative injuries."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Choose cats, dogs\n________ who are cruelty victims have a higher likelihood of death than ____\n_______ have the greatest variety of cruelty inflicted using different methods\n\nchoose male or female\n_____ dogs are abused in a higher proportion to _____ dogs\n\nchoose older than or less than or equal to\nDogs and cats _____ 2 years of age are abused at higher rates compared to the general population","a":"Choose cats, dogs\nCats  who are cruelty victims have a higher likelihood of death than dogs\nCats have the greatest variety of cruelty inflicted using different methods\n\nchoose male or female\nMale dogs are abused in a higher proportion to female dogs\n\nchoose older than or less than or equal to\nDogs and cats less than 2 years of age are abused at higher rates compared to the general population"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: Under most laws the veterinarian who suspects animal cruelty has the legal authority to seize the animal","a":"F Under most laws the veterinarian who suspects animal cruelty does NOT have the legal authority to seize the animal. But in every case where abuse is suspected the investigating authority should be called immediately."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: Statements made by the defendent to the veterinarian testitying as a witness are inadmissible in court (hearsay).","a":"F: The prosecutor may introduce out of court statement made by the defendent. It is the prosecutor's decision.  Also, if a client makes a statement against him/herself it's technically not hearsay and is admissible."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F: When an injury is found on a forensic exam (live or dead animal) the fur should be shaved to show the extent of any injury found","a":"T. In a deceased animal consider shaving the entire body of the animal to allow observation of skin lesions that are hidden by fur."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In young dogs nails grow ______ mm/week. In adult dogs nails grow ____ mm/wk","a":"Young dogs 1.9 mm/wk, adult dogs 0.8 mm/wk"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Feet injuries are highly specific to and suggestive of non-accidental injury.","a":"F: Feet injuries are commonly found in severe, accidental trauma cases such as motor vehicle accidents. If the client is suggesting MVA as the cause of observed injuries but the feet are normal, this might be be a red flag for an inconsistent history."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In cases of interpersonal violence, ______ (type of non accidental injury) is the most common injury found in animals.","a":"In cases of interpersonal violence, blunt force trauma is the most common injury found in animals."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"A minimally displaced rib fracture can be expected to heal in ______ weeks in adults, faster with juveniles.","a":"A minimally displaced rib fracture can be expected to heal in 8-16 weeks in adults, faster with juveniles."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What changes might be seen on CBC in a stressed animal?","a":"STress is a common cause of mature neutrophilia along with lymphopenia and eosinopenia. IN dogs mild to moderate monocytosis may be seen. IN cats it is common to see a significant neutrophilic leukocytosis.  Not all will be always be seen in every stressed animal, and other problems can cause similar changes"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The normal blood volume of an animals is _____% x body weight (kg) (list for dogs and cats, different)","a":"Dogs: 8-9% \nCats: 5-6%"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Using average hematocrit (for given species), actual hematocrit, and an animal's normal blood volume, what is the equation for calculating blood volume loss?","a":"(Species avg normal hct- current hct) / species avg normal hct = fractional bloodloss\nfractional blood loss x normal blood volume = blood volume loss"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Give examples of gross or histological lesions that would be preserved after a body was frozen.","a":"Hemorrhage, neglect (bone marrow fat stores), poisionings such as oxalate crystals from ethylene glycol"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Fill in blanks with each: peripheral or central\nCollection of blood should be from ______ vessels for toxicology testing because of redistribution effectsts are are possible when taking blood from _____ vessels","a":"Collection of blood should be attempted from peripheral vessels for toxicology testing because of redistribution effectsts are are possible when taking blood from central vessels (near the heart)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Choose: antemortem, ,perimortem, or post mortem\nThe presence of hemorrhage is indicative of ________ injury","a":"The presence of hemorrhage is indicativetht the heart was still beating when the inury occurred (antemortem)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Choose: antemortem, ,perimortem, or post mortem\nThe presence of hemosiderin may be an indicator of __________ hemorrhage","a":"The presence of hemosiderin may be an indicator of antemortem hemorrhage. Hemosiderin often forms after a bleeding event. Macorphages phagocytize the hemoglobin and degrade it, producing hemosiderin.  Hemosiderin may be  found as soon as 48 hrs after injury in macrophages."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Put the following histologic changes in healing wounds in order from earliest to latest\nSerum/clot with congestion, swelling and leukocyte infiltration\nBirefringence developing in newly laid down collagen\nSpindle shaped cells at right angles to the vessels\nFibrils parallel to vessels\nNew capillaries present","a":"24 hours: Serum/clot with congestion, swelling and leukocyte infiltration\n36 hours: New capillaries\n48-72 hours: Spindle shaped cells at right angles to the vessels\n5-6 days fibrils parallel to vessels\n21 days Birefringence developing in newly laid down collagen"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Recently studies have shown that measurement of h____ s_____ proteins may be used to determine the level  of agonal stress during the time before death","a":"Recently studies have shown that measurement of heat shock proteins (eg Ubiquitin) may be used to determine the level  of agonal stress during the time before death"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Choose: blood, vitreous.\nThe ______ is less susceptible to biochemical changes and more resistent to decomposition than _____.","a":"The vireous is less susceptible to biochemical changes and more resistant to decomposition than blood. Most antemortem electrolyte abnormalities are reflected in the vitreous."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Vultures start feeding approximately ________ hours postmortem","a":"Vultures start feeding approximately 24 hours postmortem and completely skeletonize a carcass in three to 27 hours. Their scavenging greatly accelerates the rate of decomposition."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Put the following conclusions terms in order from least certain to most certain\nreasonable possibilities\nabsolute certainty or certainty beyond a possible doubt\nspeculation\nreasonable degree of certainty\nthe preponderance of evidence or probable","a":"speculation (improbably, no basis in reason)\nreasonable possibilities (<50%)\nthe preoponderance of evidence/probable (likelihood exceeds 50%)\nreasonable degree of certainty (>>50%)\nabsolute certainty (duh)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F?  cruelty implies an action more serious and more malicious than abuse.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Recklessness is a weaker term than negligence","a":"FALSE; recklessness is STRONGER than negligence and shows a disregard of or indifference to conduct which endangers the life or safety of others"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"In most states, it is only necessary that a person\n________ harmed an animal","a":"knowingly; this is easier to prove than intent"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Many personal safety experts agree that past\nabusive/violent behavior is the best predictor of future\nbehavior","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? At least one study has shown that young children are unlikely to \"outgrow\" abusive animal behavior.","a":"TRUE; a group of five to 15-year-old children referred to a\nclinic, in part for their cruelty to animals, 62% were still\ndisplaying some level of abusive behavior toward animals\ntwo to nine years later"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"This was the first year that the American Psychiatric Association took the\nsignificant step of formally including cruelty to animals as\na symptom of Conduct Disorder in its diagnostic manual","a":"1987.0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are some common reasons for nonreporting?","a":"Fear that reporting will compromise the safety of the victim, fear of losing \nincome or of legal repercussions, lack of training in the recognition of abuse/neglect, \nperceptions that no action will be taken as a result of reporting, and lack of knowledge \nof available resources for families are all reasons given for nonreporting"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are ways in which vets' abilities to respond to abuisve situations will improve?","a":"learning to recognize signs of human cruelty, developing better cruelty \ndefinitions and clearer reporting responsibilities, advocating for stricter \nanti-cruelty legislation, mandating cross-reporting, and creating awareness \nthat when abuse is part of family dysfunction there may be both human and animal victims."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"These factors make up the primary prevention level for combatting animal abuse.","a":"Surveillance, identification of risk factors, and the development, evaluation, \nand dissemination of interventions are all part of the primary prevention of violence."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Secondary prevention is associated with presymptomatic\ndiagnosis and treatment once the pathologic process has\nmanifested itself beyond the initial disease process, which\nmay be thought of as the latent stage of the malady.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"_____ prevention limits the physical and social consequences of \nsymptomatic health problems","a":"Tertiary"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Animals are abused in ____% of the families in\nwhich children are abused, based on the present-day\ninclination to treat cats and dogs as members of the\nfamily","a":"0.88"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Five common denominators exist among animal abusers and child abuser","a":"1) Both consider their victims as chattel (property), rather than as\nliving creatures.\n2) Both have an extremely low tolerance for noise.\n3) Both have an extremely low tolerance for frustration.\n4) Both have trouble dealing with animals’ or children’s’\nperformance levels which fall below their\nexpectations; errors committed by the child or pet\nare not seen as a mistake but as an affront to one’s\npersonal expectations.\n5) In situations of abuse, one child or animal is singled\nout as vulnerable, as the weakest link in the chain.\nThere may be more than one animal or child present,\nand it is not necessarily the runt which is abused"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? A triad consisting of enuresis (involuntary urination at night), fire-setting, and cruelty to\nanimals is thought of being predictive for subsequent adult crime","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? The driving force for the enactment of anti-cruelty laws has\nhistorically been the preservation of a moral society as\nopposed to a genuine interest in the protection of animals.","a":"TRUE. Although these laws still do provide animals with minimal protection, they\n have primarily been enacted to\nprotect humans from other humans with an intent to\nminimally interfere with owners’ property rights, it should\nbe no surprise that these laws have proved relatively\nineffective at protecting animals from acts of cruelty and\nneglect."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"These are the 3 more common/general forms of anti-cruelty laws in states.","a":"1. prohibits the willful, deliberate, or intentional commission of certain acts,\nwhich often include beating, torturing, or mutilation.\n2.The second most frequently encountered statute imposes a\nduty on animal owners or their custodians to provide food,\nwater, and adequate shelter. \n3. The third type of cruelty prohibited by statute is the participation in, the witnessing\nof, the aiding in or in any way engaging in the furtherance of any fight between animals."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Most state anti-cruelty laws are comprised of these 6 elements...","a":"1) the types of animals protected, 2) the types of\nacts prohibited or duties imposed, 3) the mental\nculpability required to impose liability, 4) the defenses to liabilities, 5) certain activities exempted from the law, and\n6) the penalty for each offense"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? The second element noted in the previous question (types of acts prohibited\nor duties imposed) is the hardest to apply in cases?","a":"TRUE; The second element consists of assessing whether the\nact, failure to act, or neglect falls within the scope of the\nstatute...A majority of the states define\ncruelty with such vague and ambiguous language that\nunless the alleged act or omission is extreme and\noutrageous it is unlikely that it will violate the statute.\nThe use of imprecise terms with little additional statutory\nguidance has left law enforcement officials, prosecutors,\nand judges confused and in disagreement as to what acts\nfall within the scope of the statute. As a result, the\nenforcement of anti-cruelty laws has been inconsistent\nand unpredictable. This uncertainty also\nadversely impacts the role veterinarians play in their\ninvestigation and reporting of potential animal abuse\ncases."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? State animal anti-cruelty statutes\nare criminal laws.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are two reasons why anti-cruelty laws have been historically ineffective\nat protecting animals?","a":"1. they are criminal laws not civil laws and this means that bc animals are \nproperty and have no legal standing or rights under the\nAmerican legal system, the protection\nanimals receive from these laws is secondary to the\nthreefold goals of the criminal legal system. \n2. legislators, prosecutors, and the courts have been\nreluctant to legislate and enforce these laws"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are the main reasons for reluctance in legislating and enforcing anti-cruelty\nlaws?","a":"First, the general attitude that members of society, policy makers, and legislators\nhave towards animals and their welfare has resulted in\nminimal activity in this legislative arena. Second, the\ndifficulty state legislators have in defining and agreeing on\nwhat is abusive and cruel treatment has lead to difficulties\nin the interpretation and subsequent enforcement of these\nstatutes. Third, the penalties imposed by anti-cruelty\nstatutes are generally misdemeanors which fail to be\naggressively prosecuted because they compete with felony\noffenses for the prosecution’s limited time and resources.\nFinally, enforcement has been plagued by a lack of funding and manpower as well as confusion resulting from states\ndelegating the authority to enforce such laws to humane\norganizations."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? most states characterize crulety to animals as misdeamenors","a":"TRUE; at time of publication only 15 states considered it a FELONY to intentionally\ncommit an offense of animal cruelty"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? veterinarians are indirectly prohibited from\ntreating animals at animal fights because most antifighting\nstatutes prohibit either the attendance or\nwitnessing of such fights","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"At time of publication, these two states required veterinarians (among health professionals) that are\nrequired to report known or reasonably suspected cases\nof child abuse or neglect.","a":"Colorado and California"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Not only does the vast majority of animal cruelty arise\nfrom neglect, but it is also the form of abuse most likely to\nbe encountered by a veterinarian","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When evaluating any animal for the possibility of neglect, it is\nuseful to consider these three general areas:","a":"the severity of problems present, the total number of problems, and the\nduration of the problems"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"TACC (Tufts Animal Condition and Care) score has been developed  to alleviate some of the ambiguity\nveterinarians and law enforcement personnel face when\nassessing whether there is reason to believe an animal may\nbe suffering from either chronic or acute neglect. What factors does it look at?","a":"The TACC score incorporates scales to evaluate body\ncondition, to assess risk from exposure to temperature\nextremes, and to evaluate sanitation and grooming as\nindicators of the adequacy of animal care.  These criteria\nare useful because they are independent of human intent\nand of social norms concerning animal care, and are\nrooted in the consequences for the animal."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? The purpose of the body condition scale is to establish whether\nthere is a reasonable suspicion that an animal’s nutritional\nneeds are not being met, and to determine the urgency for\nintervention","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is the species-specific critical threshold temp that must be crossed for clinical signs of heat stroke to be seen in dog?","a":"109F"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Neglect constitutes more than half of the\nsubstantiated reports to child protection systems.","a":"TRUE -  (52.3 %) ; for kids and animals,  neglect appears\nto comprise more than half of all maltreatment while\nphysical abuse constitutes approximately one quarter of all\ncases and sexual abuse runs between ten and fifteen\npercent."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"These aee four basic ways veterinarians might learn of an\nincident involving animal cruelty.","a":"1) notice suspicious behavior or physical injuries on a patient’s\nbody. 2)overhear comments or parts\nof conversations leading them to suspect that animal cruelty\nmay be occurring in their client’s home 3)a client, especially a long-term one who knows and\ntrusts the veterinarian, may choose to confide an incident of 4)  veterinarians might actually\nwitness some form of animal cruelty\nabuse."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What are some reasons a vet might be reluctant to ask a client about cruelty?","a":"concerned they will offend a client and lose their trust and their business. Reluctance to\nask may also be attributed to a desire to protect themselves\nfrom becoming involved in a case that may bring unwanted\npublicity or danger to a veterinarian’s practice. In addition,\nmany veterinarians fear that by reporting, they may lose\ncontact with the animal, and lose the ability to advocate on\nthe animal’s behalf."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? The American Veterinary Medical Association (AVMA)\nconsiders it a veterinarian’s responsibility to report cases\nof animal cruelty to the appropriate authorities","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"At time of publication, the American Humane Association reported that in __%\nof the cases, their prosecutor relied on expert witness\ntestimony to obtain a conviction.","a":"0.78"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is debriefing in terms of crisis intervention?","a":"The goal of debriefing is to minimize post-traumatic stress reactions\nand the toll they can take on human physical and\npsychological health. It is more effective used in the days or\nweeks following. It includes 1. Ask about the facts of the case.\n2. Inquire about the person’s thoughts regarding the\ncase.3. Acknowledge and validate the person’s feelings.\n4. Reassure the person and support the choices and actions\nthat were taken. If the person who is debriefing believes\nwrong decisions were made, ask what lessons were\nlearned and what the person will do differently next\ntime"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Animal cruelty laws exist\nin all 50 states of the U.S.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what are some reasons a vet might not want to participate in the investigation and\nprosecution of an act of animal cruelty?","a":"1. personal safety 2. time committment 3. monetary committment 4. liability and confidentiality"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"The American\nVeterinary Medical Association’s Professional Liability\nInsurance Trust recommends that veterinarians working\nwith municipal or nonprofit agencies have a “_____ ______” agreement written by an attorney to prevent\nshifting of liability to the veterinarian for any situation\nwhich may be out of his or her control.","a":"hold harmless"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"why is it impt for a vet to IMMEDIATELY report clients that suspect of cruelty?","a":"With time, the animal’s condition can\nchange, alibis can be fabricated, evidence can be\ndestroyed or contaminated, and animals can disappear."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"______ of animal cruelty is the most important\nfunction of the participating veterinarian.","a":"Documentation"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"It's also impt for impact to use specific language in cruelty documentation such as ___ ____","a":"needless suffering"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"When is an expert witness needed in  a case?","a":"When an issue in litigation cannot be readily\nunderstood by a jury or a judge without explanation by\none familiar with what is involved in the issue."},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Some issues in litigation involving animals can be\nresolved without the use of expert testimony. This is referred to as:","a":"res ipsa loquitur (it speaks for itselif in Latin)"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? All medical records, photographs and reports pertaining\nto the case are also a form of evidence","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"What is chain os custody in a case?","a":"the ability to verify, with certainty, the identification and\nlocation of all evidentiary materials relevant to the case. This is necessary to ensure that evidence, including the\npatient, is not tampered with before, during or after its\nexamination or analysis"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"Close photographs should be taken of each\nwound located, including ____ cm around each wound","a":"15.0"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"While the most common cause of death from a\ngunshot wound is _______, an animal that does not die\nquickly may succumb a few days later to _____\nsecondary to the wound.","a":"hemorrhage; peritonitis"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? If poisoining is being considered, the chances for successful\ndiagnosis are greatest when the list of possible toxins can\nbe widened to as many substances as possible","a":"FALSE; the list should be narrowed to as a few options as possible"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"what year was the first documented anti-cruelty law mentioned for animals?","a":"The first anti-cruelty law\ndates back to 1641 when the Puritans of the Massachusetts\nBay Colony voted to forbid animal cruelty"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"when was child abuse criminalized?","a":"Child abuse criminalized in the late 1800’s\nin New York"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? Domestic violence is the leading cause of injury to\nwomen between the ages of 15 and 44","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"__ to _____ % of men who abuse their female partners\nalso abuse their children","a":"50-70%"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F? In 88% of families in which physical abuse to children\nhas occurred, there has also been animal abuse.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Animal Cruelty","q":"T/F?Witnessing violence has been determined to be the single\nmost consistent factor in predicting the behavior of\nbatterers and victims","a":"1"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Qualification to serve as an Incident Commander are based on rank, grade, or technical expertise.","a":"F. The Incident Commander should have the level of training, experience, and expertise to serve in this capacity. Qualification to serve as an Incident Commander are NOT based on rank, grade, or technical expertise."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Chain of command does not prevent personnel from directly communicating with each other to ask for or share information.","a":"T: Chain of command does not prevent personnel from directly communicating with each other to ask for or share information.  Chain of Command does\n- allow an Incident Commander to direct and control the actions of personnel under his/her supervision\n- avoids confusion by requiring that orders flow from supervisors."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Unity of command means what in ICS?","a":"Unity of command means that personnel  report to only one ICS supervisor, and receive work assignments only from their ICS supervisors. When you are assigned to an incident you no longer report to your day-to-day supervisor."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The process of move the responsibility for incident command from one Incident Commander to another is called ________.","a":"The process of move the responsibility for incident command from one Incident Commander to another is called transfer of command."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Transfer of command may or may not inclue a transfer of command briefing which may be oral, written, or a combination of both.","a":"F: Transfer of command ALWAYS includes a transfer of command briefing which may be oral, written, or a combination of both."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"After being dispatched, your first task is to ______________","a":"After being dispatched, your first task is to checkin and receive an assignment."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is the difference between unity of command and unified command?","a":"-- Unity of command = all individuals have a single designated supervisor to whom they report at the scene of the incident\n- Unified command = a system that allows different agencies to work to together effectively without affectiving individual agency authority, responsibility or accountability.  The Unified Command organization consists of the Incident Commanders  from the various juridictions or agencies operating together to form a single command structure in the field. The Incident Commanders  within the Unified Command make joint decisions and speak as one voice (aka the Borg). E.G a police officer would not tell the firefighers  how to do their job nor would the police direct search and rescue tactics."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: On small incidents and events, only one position in the ICS may be staffed, the Incident Commander, who will accomplish all management functions","a":"T. The Incident Commander is the  position that is always staffed. During a larger incident the Incident Commander may create Sections and delegate the Operations, Planning, Logistics, and Finance/Administration functions. The Incident Commander is responsible for all mgmt functions until he/she delegates a function.  If a Section is not staffed, the Incident Commander will personally manage those functions."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: If a deput Incident Commander is assigned, he or she must be fully qualified to assume the Incident Commander's position","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"In an expanding incident, which section of the general staff is always established first?","a":"The Operations section. Planning, Logistics, and Finance/Admin are only activated as needed."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Match each term with the correct definition: Single Resources, Task Forces, Strike Teams\n-- A combination of mixed resources with common communications operating under the direct supervision of a Leader\n-- Consist of all similar resources withcommon communications operating under the direct supervision of a Leader\n-- An individual, a piece of equipment and its personnel complement, or a crew or team of individuals with an identified supervisor","a":"Task Forces-- A combination of mixed resources with common communications operating under the direct supervision of a Leader\nStrike Teams -- Consist of all similar resources withcommon communications operating under the direct supervision of a Leader\nSingle Resources-- An individual, a piece of equipment and its personnel complement, or a crew or team of individuals with an identified supervisor"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: In a Unified Command each agency establishes its own incident facilities","a":"F. In a Unified Command, incident facilities are co-located or shared. This can promote coordination."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Formal communications follow the lines of authority. However, info concerning the incident or events can be passed horizontally or vertically within the organization without restriction.","a":"T Formal communications follow the lines of authority. However, info concerning the incident or events can be passed horizontally or vertically within the organization without restriction (informal communcation). Within the ICS organization, critical info must flow freely! Formal communicatiom must be used when receiving and giving work assignments, requesting support or other resources, reporting progress of assigned tasks."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The first duty of ICS leadership is _______________________","a":"The safety of all personnel involved in an incident or planned event is the first duty of ICS leadership."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Fyi no question- stick with standard ICS position titles. Im not memorizing these ;)\nListed below are the standard ICS titles:\nOrganizational Level               Title                               Support Position\nIncident Command            Incident Commander              Deputy\nCommand Staff                   Officer                                 Assistant\nGeneral Staff (Section)         Chief                                   Deputy\nBranch                                Director                                 Deputy\nDivision/Group                 Supervisor                                  N/A\nUnit                                      Leader                                  Manager\nStrike Team/Task Force       Leader                          Single Resource Boss","a":"Fyi no question- stick with standard ICS position titles. Im not memorizing these ;)\nListed below are the standard ICS titles:\nOrganizational Level               Title                               Support Position\nIncident Command            Incident Commander              Deputy\nCommand Staff                   Officer                                 Assistant\nGeneral Staff (Section)         Chief                                   Deputy\nBranch                                Director                                 Deputy\nDivision/Group                 Supervisor                                  N/A\nUnit                                      Leader                                  Manager\nStrike Team/Task Force       Leader                          Single Resource Boss"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Delegation of authority allows the Incident Commander to assume command and relieves the granting authority of the ultimate responsibility for the incident.","a":"F:  Delegation of authority allows the Incident Commander to assume command and does not relieve the granting authority of the ultimate responsibility for the incident."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Delegation of authority may be granted verbally or in writing,","a":"T: IDeally this authority is granted in writing, but whether granted verbally or in writing, the authorities granted remain with the Incident Commander until such time as the incident is terminated, or another Incident Commander is appointed."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is a size-up?","a":"In an initial incident a size-up is done to set the immediate incident objectives. The first responder to arrive must assume  command and size up the situation by determining the nature and magnitude of the incident, hazards and safety concerns, initial priorities, etc"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The _________ covers an operational period (e.g. 24 hours) and includes what must be done, who is responsible, how info will be communicated, and what should be done if someone is injured.","a":"Incident Action Plan (IAP).  All incidents must have an IAP."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is the Emergency Management Assistance Compact (EMAC)?","a":"The model for providing mutual aid assistance across state lines. The EMAC exists because all States share a common enemy: the threat of disaster.48 states, District of Columbia, Puerto Rico and the Virgin Islands are members of EMAC."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: In some situations a lower ranking but more qualified person may be designated as the Incident Commander","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is the difference between an assisting agency and a cooperating agency?","a":"An assisting agency provides support but has direct responsibility for incident mgmt. A coordinating agency is simply offering assistance."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Logistics unit functions are geared to supporting personnel and resources directly assigned to the incident.","a":"T except for supply unit. E.g. medical unit would not provide medical care for civiilans affected by the incident"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Organizational elements of an ICS may not be activated without activating a Section Chief","a":"F:  Organizational elements of an ICS may activated without activating a Section Chief"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Rather than combining ICS positions to gain staffing efficiency, you may assign the same individual to supervise multiple units","a":"T, but BEWARE using nonstandard titles, which may cause confusion. Also be aware of span of control issues that may arise"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Incidents may be categorized into 5 types based on complexity. Type ____ incidents are the least complex, and Type ____ the most complex.","a":"Type 5 incidents are the least complex and Type 1 incidents are the most complex. The vast majority of all incidents are Type 3-5. Written Incident Action Plan (IAP) is required for Type 1 and Type 2. \n- Type 5: local village and township level jurisdiction\n- Type 4: City, County or Fire district level\n- Type 3: State or Metropolitan area level\n- Type 2: National and State level (less than Type 1)\n- Type 1: National and State level (greater than Type 2)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The arrival of a more qualified person automatically means a change in incident commanders","a":"F: The arrival of a more qualified person automatically does not automatically mean a change in incident commanders"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Transfer of command should take place face to face and must always include ______","a":"must always include a complete briefing."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Prevention, Protection, Mitigation, Response and Recovery are the mission areas of what?","a":"The National Preparedness Goal: \"A secure and resilient Nation with th capabilities required across the whole community to prevent, protect against, mitigate, respond to, and recover from the threats and hazards that pose the greatest risk.\""},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The role of the State gov't in emergency response is to lead efforts before during and after incidents.","a":"F. The role of the State gov't in emergency response is to supplement local efforts before during and after incidents. The responsibility for responding to incidents, both natural and human-caused, begins at the local level."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: OWners should not be expected to provide food, water, husbandry, or exercise for their pets during the time they're in emergency shelters because animals should not be sheltered near people in large-scale emergencies.","a":"F: OWners should be expected to provide food, water, husbandry, and exercise for their pets during the time they're in emergency shelters. Animals should be sheltered near their owners to the extent possible."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"_______ provides supplemental resources to assist communities and States to protect again or assist their citizens.","a":"Federal Emergency Management Agency (FEMA)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Local governments are ultimately responsible for the survival and well-being of household pets, service animals and livestock.","a":"F: YOU are ultimately responsible for the survival and well-being of your household pets and service animals. You should have an emergency response plan and readily accessible kits with provisions for family members, household pets, service animals, and livestock."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The ADA (Americans with Disabilities Act) guarantees a service animal may remain with the person served in any public accommodation (e.g. a shelter set up in response to an disaster) but does not ensure otheres aspects of caring for a service animal during a disaster.","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"An area designated as a 100 year floodplain has a ________% chance of flooding per year.","a":"An area designated as a 100 year floodplain has a 1% chance of flooding per year. The state natural resources dept can provide maps and flood risk assessment info on every property in the State."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Cuts acquired from disaster debris make animals more susceptible to _____ (infectious dz).  Contaminated floodwater may contain toxins, including ______ toxin from rotting carcasses. Contact with wildlife may increase the potential for _______ (dz).","a":"Cuts acquired from disaster debris make animals more susceptible to tetanus. Contaminated floodwater may contain toxins, including botulinum toxin from rotting carcasses. Contact with wildlife may increase the potential for rabies."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Choose: The most frequent disasters are ___________ (human caused, geological, or weather related)","a":"Choose: The most frequent disasters are weather related (meteorlogical)."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: A person or animal struck by lightning will receive a severe electrical shock and may be burned. They may carrie a residual electrical charge and should not be handled for at least 5 minutes following the lightning strike.","a":"F:  A person or animal struck by lightning will receive a severe electrical shock and may be burned. They will carry no residual electrical charge and can be handled safely."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Animals affected by flood risk death from ___________ and ____________.","a":"Animals affected by flood risk death from hypothermia and drowning. (.... and a multitude of other ways too, methinks...)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If you are evacuating horsew when a fire is close it may help to __________","a":"If you are evacuating horsew when a fire is close it may help to blindfold them"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"The most common cause of fire related death is ____________","a":"smoke inhalation pneumonia"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: The actual movement of the ground is seldom the direct cause of death or injury to humans and animals.","a":"T: buiding collapse, flying glass from broken windows, toppling furniture/appliances, fires secondary to damage, electrocution from fallen powerlines, and exertion and fear leading to heart failure (!)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: After an earthquatke do not go sightseeing.","a":"T (yes, it actually says this in the FEMA document)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Following a volcanic eruption throw away any animal feed that has been contaminated by the ash.","a":"T: Following a volcanic eruption throw away any animal feed that has been contaminated by the ash. Ash commonly contains heavy metals that are toxic to humans and animals. Pyroclastic material contains glass-like materials that can cut or irritate lungs and intestines."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Because most radioactive fallout particles are heavier than water, in bodies of water with little or no turbulence the surface water consumed by animals will be safe to to drink in ______ days.","a":"Because most radioactive fallout particles are heavier than water, in bodies of water with little or no turbulence the surface water consumed by animals will be safe to to drink in 10-14 days."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Disaster shetlers (for humans) are required to operate in accordance with the existing public health regulations of the locality in which they provide services.","a":"T: If State/tribal public health regulations prohibit animals in public facilities, such as malls, restaurants, churches, schools etc  disaster shelters must also operate  in accordance with the existing public health regulations"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Incidences of zoonoses following disasters have not been a documented problem in the US since the 1950s.","a":"T. However, Humans are most likely to be exposed to zoonotic dzs when animal waste contaminates the drinking water supply. This situation can occur in floods and after power failure at water treatment plants."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Dogs commonly congregate in packs  and become a public nuisance after disasters.","a":"F. Few such instances are confirmed."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What should you do if a dog attacks you? (Prepare yourself for some entertainment...)","a":"-- Stand still. Running incides hunting and chasing instincts in the dog. \n-- Loudly and firmly shout \"Sit!\" or \"Down!\" at the dog in a dominant fashion\n-- Put something (eg a trash can lid) between you and the dog, or pick up something and pretend to throw it at the dog. Doing so may convince the dog to leave.\n-- If you are thrown to the ground, protect your head."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Rendering, burning, burial, composting and fermentation are all common methods of ____________","a":"Animal carcass disposal"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"T/F: Only a Governor or Indian Tribal Government Chief Executive can initiate a request for a presidential emergency or major disaster decleariation.","a":"T"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Which law authorizes the President to provide financial or other assistance to State and local governments? (Clue: think of a named kind of education loan)","a":"The Stafford Act. It is triggered by a presidential declaration of a major disaster or emergency."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What were the major consequences  of the Pets Evacuation and Transportation Standards Act (PETS) and the Post-Katrina Emergency Mgmt Reform Act?","a":"-- The Stafford act now mandates that state and local plans address the rescue, care, shelter and essential needs of idnviduals and their pets. \n-- FEMA can provide funding to States to develop capabilities  pertaining to household pets and service animals\n-- FEMA is authorized to use FEderal resources to address the needs of household pets and service animals. \n-- These acts do NOT provide specific funding, but do provide opportunities for funding under various FEMA grant programs"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Hazards assessment, vulnerabilities assessment, and consequences assessment are all components of an overall __________________","a":"Risk assessment. Risk assessment will help communities plan for the ypes of emergencies they experience most often, focus on community elements that are most vulnerable, and identify the most damaging effects  when those elements are impacted."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What state official is often engaged as the lead offical for animal issues, particularly livestock?","a":"State animal health official (usually call the state veterinarian)"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"For most incidents, _________ personnel will determine what PPE is necessary for animal decontamination purposes.","a":"Safety or HAZMAT"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What piece of PPE is missing from this list of minimum required PPE for animal decontamination? apron/water resistant coveralls, long sleeves  boots, cap, and barrier mask or face shield.","a":"BAsic barrier protection: Gloves, apron/water resistant coveralls, long sleeves, tight-fitting goggles, boots, cap, and barrier mask or face shield. N-95 particulate respirators should be issue to protect against spray mists during deocon."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"If ______ (body system) protection is required, OSHA requrements include medical screening, fit testing, and training on ___________","a":"If respiratory protection is required, OSHA requrements include medical screening, fit testing, and training on respirators prior to the incident."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"___________ is the gold standard for animal decontamination.","a":"Bathing is the gold standard for animal decontamination. Soap and water followed by clean water rinse will eliminate or reduce most contaminants effectively."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What is critical incident stress and who is likely to be impacted?","a":"Critical incident stress refers to stress and anxiety brought on by the pyschological impacts of a disaster and can impact both survivors and responders"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Whare NIMS vs NRF vs ICS? (Conceptually)","a":"NIMS is the strategy/ideology behind incident response, NRF is the blueprint for incident response, ICS is the management system used during incident response."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"________ (disaster type) often contain high numbers of fecal coliform bacteria, high concentrations of heavy metals such as lead, and a wide range of volatile organic solvent and other compounds.  It also provides ideal conditions for the growth of fungi and mold and provides optimal conditions for the spread of arthropod-bourne diseases.","a":"Floodwaters (disaster type) often contain high numbers of fecal coliform bacteria, high concentrations of heavy metals such as lead, and a wide range of volatile organic solvent and other compounds. Animals caught in these floodwaters may suffer from rashes and burns to the skin ad mucosal membranes, along with GI tract problems arising from ingestion of chemical residues and pathogens."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Decontamination take place in the ________ (hot, warm or cold) zone.","a":"Decontamination take place in the warm zone. THe hot zone is the area that contains the hazard, thew arm sone is a buffer between the hot and cold zones (contamination reduction corridor), and the cold zone is the area free from any hazards."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"What vaccines are recommended at admission to an emergency shelter? (Dogs and cats)","a":"Dogs: DAP and Bb Cats FVRCP and RABIES for anyone over 4 months old. All animals should also receive prophylactic treatment for fleas and internal parasites."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Soaps and detergent can be divided into cationic and anionic compounds. What is the difference with regard to detergent qualities and biocidal qualities?","a":"Cationic: good biocidal properties, poor detergent properties. \nAnionic: good detergent properties, poor biocidal properties. \nDespite their differences both are effective in removing grease, oil, soil and dirt."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Disaster","q":"Though there is no single disinfectant that will be suitable for every incident animal decontamination needs, select the best choice from this list and give reasons why it's preferred.\n Ethyl alcohol, bleach, chlorhexidine","a":"-- Chlorhexidine is a broad-spectrum biguanide that is a broad spectrum disinfectant at 4% dilution. It is fast acting (<20 sec)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Inhaled vapors and gases require a critical concentration within the alveoli and blood for effect; \n thus, all inhaled methods have the potential to adversely affect animal welfare because onset of unconsciousness is not immediate.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Time to unconsciousness with inhaled agents is dependent on the _______, __________, and _________.","a":"displacement rate, container volume, and concentration"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? While loss of consciousness will be more rapid if animals are initially exposed to a high concentration of an inhalant, it may cause aversion and distress.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? In sick or depressed animals where ventilation is decreased, agitation during induction w/ an inhalant \n is more likely because the rise in alveolar gas concentration is delayed.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Neonatal animals are more sensitive to hypoxia.","a":"FALSE; neonates are more resistant and because all inhaled agents ultimately cause hypoxia, neonatal animals take longer to die than adults."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Gas displacement rate is critical to the humane application of inhaled methods, such that an appropriate pressure-reducing regulator and flow meter combination or equivalent equipment with demonstrated capability for generating the recommended displacement rate for the size container being utilized is absolutely necessary when compressed gases are used for euthanasia.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Changes in gas concentration within any enclosed space involve these 2 physical processes…","a":"(1) wash-in of new gas (or washout of existing gas) and\n  (2) the time constant required for that change to occur within the container for a known flow rate. Also, the rate of chnage of gas concentration in an enclosed space is always a nonlinear change (expoentital process)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? In general, the less soluble an inhaled anesthetic, the more rapid the anesthetic induction is.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What are some advantages to using inhaled anesthetics as euthanasia agents?","a":"1. useful for small anmls (<7 kg) 2. can be administered via various methods 3. many are nonflammable and \n nonexplosive 4. can be used as sole euth agent or as 2 step process"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What are some DISadvantages to using inhaled anesthetics as euthanasia agents?","a":"1. many are aversive to animals 2. design limits on vapor outputs may delay induction (i.e. many vapor outputs use oxygen as carrier and this may prolong time to death 3. personnel exposure to inhalants 4. can cause tissue residuals - problem for food animals"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Gen recs for using inhalants include…","a":"1. use in small animals 2. use if no aversions are known and use at high concentrations to result in rapid loss of consciousness"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What affects the time constant and rate of rise of anesthetic concentration?","a":"chamber volume, flow rate, and anesthetic concentration"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? The rrder of preference for inhalants as euth agents is isoflurane, halothane, sevoflurane, enflurane, \n methoxyflurane, and desflurane, with or without N2O.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Ether inhalant is an acceptable euth method","a":"0"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"How does carbon monoxide work as euth agent?","a":"It's a cumulative poison that produces fatal hypoxemia; it readily combines with hemoglobin and blocks uptake \n of O2 by erythrocytes by forming carboxyhemoglobin."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are adv of using carbon monoxide as euth agent?","a":"(1) induces loss of consciousness without pain and with minimal discernible discomfort, depending on species.\n  (2) Hypoxemia induced by CO is insidious. (3) Death occurs rapidly if concentrations of 4% to 6% are used."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what are DISadvantages of using carbon monoxide as euth agent?","a":"1. aversive to some species 2. personnel exposure 3. electrical equipment exposed to CO must be spark free and explosion proof"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"CO is okay as a euth agent if what contingencies are met?","a":"1. personnel are trained in using it 2. CO chamber is high quality construction 3. CO source and chamber should be in well ventilated space - ideally outdoors 4. chamber must be well lit and allow for direct observation 5. CO flow rate should be adq to get to a uniform concentration of 6% after anmls are placed in it (exception is anmls like neonatal pigs, where gradual increase is less aversive) 6. if used inside, need sensors 7. use pure form 8. adhere to state and federal OSHA rules when using"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? hypoxia produced by inert gases such as nitrogen and argon appears to cause SIGNIFICANT aversion in turkeys & chickens","a":"FALSE; hypoxia caused by these gases is nonaversive to these species or only mildly aversive"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? rats, mice, and mink convey significant aversion to nitrogen and argon when exposed","a":"TRUE; these are not acceptable gases to use on these species as sole euthanasia agent (i.e. okay to use to kill the animal if animal is already unconscious)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Hypoxia due to nitrogen and argon exposure is acceptable for pig euthanasia if what criteria are met?","a":"animals are directly placed into a <2% oxygen atmosphere and exposure times > 7 min are used"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"inhalation of carbon dioxide casesus respiratory_______","a":"acidosis"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"carbon dioxide has potential to cause distress in animals via 3 main mechanisms…","a":"1.formation of carbonic acid on respiratory and ocular membranes\n 2.production of so-called air hunger and a feeling of breathlessness\n 3.direct stimulation of ion channels within the amygdala associated with the fear response."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? one can conclude that use of CO2 may be humane for certain genetic lines of pigs and stressful for others.","a":"TRUE; diff lineages have variable aversion/responses to carbon dioxide exposure"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Unlike nitrogen and argon, which must be held within a very tight range of concentration for effective euthanasia, CO2 can render poultry unconscious and kill over a wide range of concentrations.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Carbon dioxide exposure using a gradual fill method is less likely to cause pain due to nociceptor activation by carbonic acid prior to onset of unconsciousness; a displacement rate from 10% to 30% of the chamber volume/min is recommended.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? When gradual fill isn't possible, the practice of immersion, where conscious animals are placed directly into a container prefilled with 100% CO2, is okay to do.","a":"FALSE; this is unacceptable and only anmls rendered unconscious should be immered in 100% co2."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Animals euthanized by chemical means must never enter the human food chain","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Placement of intraosseous catheters for administration of euthanasia agents and intracardiac, intrahepatic, intrasplenic, or intrarenal injections are acceptable only when performed on anesthetized or unconscious animals (with the exception of intrahepatic injections in cats).","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"In some poikilotherms for which intracardiac puncture is the standard means of vascular access \n (eg, some snakes and other reptiles), _______ administration of euthanasia solutions in awake animals is acceptable.","a":"intracardiac"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Topical agents are unacceptable means of euthanasia except for animals w/ highly permeable skin to which \n nonirritating, rapidly absorbed agents are applied. Give an example in which this is acceptable.","a":"amphibians euthanized with benzocaine gel"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the primary adv in using Barbiturates as euth agents?","a":"speed of action"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"The speed of action when using barbiturates depends on what factors?","a":"this effect depends on the dose, concentration, route, and rate of the injection."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Mixing of pentobarbital with a neuromuscular blocking agent in the same injection apparatus is an OKAY approach to euthanasia","a":"FALSE; this is not acceptable because of the potential for the neuromuscular blocking agent to induce paralysis\n  prior to onset of unconsciousness"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what's the drug schedule for sodium pentobarb?","a":"II"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"how do barbiturates work as euth agent?","a":"depresses the CNS in descending order"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Injectable dissociative agent and a2-adrenergic receptor agonists are FDA approved euth agents.","a":"0"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"This is an injectable technique for euthanasia of livestock or wildlife species that may reduce the risk of toxicosis\n  for predators or scavengers in situations where the remains of euthanized animals may be consumed.","a":"IV or IC administration of potassium chloride or magnesium salt solutions (but only in unconscious animals)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Alcohols induce death through nervous system and respiratory depression, resulting in anesthesia and anoxia.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What is the withdrawal time for Tricaine methanesulfonate (TMS or MS 222) in the US?","a":"21 days"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Occupational exposure to MS 222 has been associated with ______ toxicity in humans.","a":"retinal"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? MS 222 is an acceptable method of euthanasia for finfish and for some amphibians and reptiles.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Tricaine (MS 222) and benzocaine act through blockade of voltage-sensitive _______ channels within the CNS and heart, causing nervous and cardiovasc system depression.","a":"sodium"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"______ oil and its extracts have become popular as anesthetic agents for freshwater and marine finfish \n because of their wide availability, low cost, and shorter induction times when compared with MS 222.","a":"Clove"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Strychnine, nicotine, caffeine, cleaning agents, solvents, pesticides, disinfectants are unacceptable for use as\n  euthanasia agents under any circumstances.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what's the mode of action of penetrating captive bolt for euth?","a":"concussion and trauma to the cerebral hemisphere and brainstem."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what methods of physical euth are not acceptable when diagnosis of disease through brain tissue is needed?","a":"gunshot; captive bolt"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? cervical dislocation is limited to small birds, poultry, mice, immature rats (< 200 g), and rabbits.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Electrocution induces death by causing loss of consciousness, inducing\n  tonic and clonic epileptic spasms, then causing cardiac fibrillation, which causes cerebral hypoxia.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what 78:942 barbiturate acids are acceptable for IP admin in companion animals?","a":"sodium pentobarbital, secobarbital (cannot use pentobarb combo products)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Intra-organ injections may speed the rate of barbiturate uptake over standard IP injections","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"for medium to large dogs in which IV access isn't possible, what is better euth method in lieu of IP admin?","a":"intra-organ (intraosseous, intracardiac, intrahepatic and intrasplenic, intrarenal) but only if unconscious"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? The intrahepatic injection of a combination of sodium pentobarbital and lidocaine in awake cats from animal shelters caused rapid unconsciousness and was more accurately placed than IP injections.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? carbon monoxide and cardon dioxide ARE recommended for routine euthanasia of cats and dogs","a":"FALSE ; they may only be considered in natural disasters and large-scale disease outbreaks"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? mammalian embryos and fetuses are in a state of unconsciousness throughout pregnancy and birth","a":"TRUE; for dogs/cats, sentience is not achieved until several days after birth"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"If euthanizing a mid or late-term pregnant dog/cat/small mammal, how long should the fetuses of the animal be left undisturbed after the bitch/queen is confirmed dead?","a":"15-20 min"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? IP injections of pentobarbital should be avoided whenever possible during the later stages of pregnancy due to the likelihood of inadvertently entering the uterus, rendering the injection ineffective","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What is the perferred method of euth for preweanling dogs, cats, and small mammals?","a":"IP injection of pentobarb (bc venous access can be difficult and also \n bc they are relatively resistant tohypoxia inducing methods )"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what's recommend euth method for neonates with congential deformities or illnesses after removal from uterus during c-section?","a":"IP injection of pentobarbital is recommended for fetuses"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? companion animal embryos and fetuses cannot consciously experience feelings such as breathlessness or pain. Therefore, they also “cannot suffer while dying in utero after the death of the dam, whatever the cause.”","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what euth method is commonly used in breeding facilities of individual or group euthanasia of small animals, including ferrets, rodents, and rabbits?","a":"carbon dioxide"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is the recommend euth method for animal control, rescues, shelters?","a":"injection of a barbiturate or barbituric acid derivative with appropriate animal handling"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Behavioral and EEG evidence indicates that mammalian fetuses are insentient and unconscious throughout the\n  first ___% to ___% of gestation.","a":"75-80%"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? For equids euthanized with pentobarbital, disposal of remains must be carried out promptly \n through commercial rendering, on-farm burial, incineration or cremation, direct haul to a solid waste landfill, or biodigestion.","a":"TRUE; this will prevent exposure of wildlife and domestic animals to potentially toxic barbiturate residues"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is preferred method for euth horse?","a":"Pentobarbital or a pentobarbital combination via catheter (bc of large volume needing to be injected) in jugular vein."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what other euth methods are acceptable in horses when additional conditions are met?","a":"penetrating captive bolt or gunshot only by well-trained personnel OR IV or IC injection of \n potassium chloride in anesthetized anml"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"what is an Unacceptable method of euth for horses?","a":"Chloral hydrate bc it can cause severe side effects"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"where can IO catheters be safely placed for avian euth?","a":"distal ulna or proximal tibiotarsus (not the humerus or femur since these communicate directly with resp system and euth agents may cause\n  drowning or irritation to the respiratory system if injected in these bones)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"birds have a greater capacity to process air and are therefore more sensitive to inspired toxicants for these 3 reasons…","a":"1) unique unidirectional flow of air through the lungs (which prevents mixing of inspired and expired air) \n 2)more efficient gas exchange 3) a greater surface area over which O2 can be exchanged"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? When IV injection is impossible, injectable euthanasia agents can be administered via intracoelomic, intracardiac, or intraosseous routes only if a bird is unconscious or anesthetized.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"if intracoelomic injection is used for euth of avian, what anatomical features must be avoided?","a":"air sacs because of the potential for respiratory compromise, irritation of the respiratory system, and delayed absorption via the air sacs."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? inhaled anesthetics are acceptable as sole or supplemental euth agent in companion birds","a":"TRUE; Exposure to high concentrations of inhaled anesthetics (eg, halothane, isoflurane, sevoflurane, with or without N2O)\n  is acceptable with conditions for euthanasia for birds."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? decapitation is considered to be acceptable with conditions for euthanasia of small (< 200 g) birds","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F? Intracoelomic, subcutaneous lymph spaces, and lymph sacs are acceptable routes of administration in \ncaptive amphibians/reptiles?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"_____ is defined as the sensation that results when nerve impulses from the peripheral nociceptors reach a functioning cerebral cortext and associated subcortical brain structures.","a":"Pain is defined as the sensation that results when nerve impulses from the peripheral nociceptors reach a functioning cerebral cortext and associated subcortical brain structures."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: It is incorrect to substitute the term pain for noxious stimuli","a":"T: T/F: It is incorrect to substitute the term pain for noxious stimuli because term pain implies higher sensory processing associated with conscious perception."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Pain is subjective","a":"T: Individuals can differ in their perceptions of pain intensity as well as in their physical and behavioral responses to it."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Fish, amphibians, reptiles and invertebrates perceive pain ine same way as we understand it in mammals","a":"Unknown- It is not clear whether the necessary anatomic structures are present for these creatures to be able to perceive pain as we understand it in mammals.  REgardles sof the scientific uncertainty of these animals' capacity to perceive pain, rational ethics dictate that personnel err on the side of caution, assume that these animals feel pain, and make efforts to control pain as part of euthanasia procedures."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"All euthanizing agents cause death by one of three basic mechanisms; what are they?","a":"1) direct depression of neurons necessary for life function\n2) hypoxia\n3) physical disruption of brain activity"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: The loss of consciousness should follow loss of muscle movement activity","a":"F: The loss of consciousness should precede loss of muscle movement activity."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: succinylcholine, strychnine, curare, nicotine, potassium or magnesium salts are not acceptable as the sole agent for euthanasia of vertebrates","a":"T: These are all agents that prevent movement through muscle paralysis but do not block or disrupt the cerebral cortex, resulting in distress and conscious perception of pain prior to death"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: After administering an appropriate euthanasia agent/technique, once ataxia and loss of righting reflex occur the animal is technically unconscious.","a":"T: Once ataxia and loss of righting reflex occurs, subsequently observed motor activity, sucha s convulsions, vocalization and reflex struggling can be attributed to Guedel's second stage of anesthesia, which by definition lasts from the loss of consciousness to the onset of a regular breathing pattern."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Animals euthanized with KCl can be left in the field to be scavenged","a":"T Animals euthanized with KCl can be left in the field to be scavenged if no other chemical agents are administered. Unrelated but prob should know: KCl administration is extremely painful and should be administered ONLY to deeply anesthetized animals, must be administered IV or IC."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What is the mechanism of death caused by succinylcholine?","a":"Overdosage without treatment causes an unacceptable death by asphyxiation due to paralysis of the respiratory muscles. It is not appropriate as a sole euth agent. Animals are paralyzed yet fully conscious, have no loss of sensatino, and are capable of pyschogenic distress."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"_____ (euth agent) probably pose more of a risk of accidental human injury than does any other euthanasia method.","a":"Firearms"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Federal regulation of euth of nondomestic animals is limited to the _____ (law), which is enforced by the _________ (agency)","a":"Federal regulation of euth of nondomestic animals is limited to the Animal Welfare Act, which is enforced by the USDA. States with laws pertaining to the posession, breeding, dealing and exhibition of nondomestic animals may have regulations pertaining to euthanasia."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Most drugs used in non domestic animals fall under AMDUCA.","a":"The ANimal MEdical Drug USe Clarification Act (AMDUCA)  has placed the responsibility ofor extra-label use of animal drugs on veterinarians to determine appropriate withdrawal times, drug tissue residues, drug safety and efficacy in the intended species in which the drug is not approved. Because few drugs have been approved and labeled for use in nondomestic animals, most drugs used in nondomestic animals fall under AMDUCA."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"List 3 potential hazards for scavengers that might be present in the carcass of a euthanized animal","a":"barbiturate toxicity, opioid toxicity, lead bullets or shot. Contaminated caracasses should be disposed of by deep burial, incineration, or rendering. However, many renderers will not accept caracasses contaminated by euth drugs."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Direct killing by lethal trapping techniques is an acceptable form of euthanasia in field conditions","a":"F. Direct killing by lethal trapping techniques is not considered the equivalent of euthanasia."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Physical methods of euthanasia that ensure death (e.g. exsanguination, decapitation) should be use as a final step when there is uncertainty as to whether death has been achieved by other methods","a":"T. Absence of respiratory movt, absence of heart beat, loss of color in mucous membranes, loss of corneal and palpebral reflexes, and glazing of eyes are not universally consistent across all taxa."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Opioids are inffective for chemical immobilization of sharks","a":"T, presumably due to the absence of opioid receptors. Sorry I couldn't help myself."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Overdose of MS-222 is an appropriate euthanasia technique for fish of all sizes.","a":"F: The use of this technique for larger fish or large populations may be cost-prohibitive and may generate quantities of treated water that are difficult to appropriately dispose of."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Failure to list or recommend a means of euthanasia in the AVMA euthanasia guidelines does not categorically condemn its use","a":"T"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Use of this compound is considered the most effective and humane way to kill fish.  List (approximate) reasonable dosage (mg/L)","a":"MS 222. IT is a benzocaine-type drug that acts by depression of the central nervous system.  Fish should be left in the solution for at least 10 min. Dosage: 100 to >250 mg/L . Fish euthanized with MS 222 are not suitable for human consumption, wah wah. After respiratory arrest has occurred, use of MS 222 should be followed by cervical dislocation, exsanguination, decapitation, or other methods to ensure death."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"How should MS 222 be used differently in fresh vs salt water?","a":"MS-222 is soluble in both fresh and salt water but requires neutralization with buffering agents (eg sodium bicarb) in a 2:1 ratio in FRESH water to reduce irritation and tissue dmg caused by the acidity of the MS 222 solutions."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Clove oil is an acceptable chemical to euthanatize fish","a":"Unknown. Scientific data remains inadequate to determine whether clove oil is an accceptable chemical to euth fish, and are not approved for euth of food fish."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"For fish euthanasia the recommended dose range is _____ mg/kg of sodium pentobarbital, administered by what route(s)?","a":"For fish euthanasia the recommended dose range is 60-100 mg/kg of sodium pentobarbital, administered by ICo (ceolomic), IC,  or IV routes. IV is preferred, alkalinity may be irritating to tissues and a source of discomfort. *Fish should be anesthetized using injection or immersion sedatives to reduce stress related handling. Other secondary (subsequent to anesthesia/sedation) methods include ethanol, formalin, rapid freezing (!) into liquid nitrogen, decapitation followed by pithing"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Decapitation or pithing are acceptable secondary methods of euthanasia in fish","a":"F. Pithing of the brain should be performed immediately following decapitation as the central nervous system of fish is tolerant to hypoxic and hypotensive conditions"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Placing conscious fish in a freezer or on crushed ice is not considered an appropriate method of euthanasia","a":"T. REmoving gilled vertebrates from water is not an acceptable means of euth either. Time to death is prolonged."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Select which of the following are acceptable primary methods of euth for amphibians: inhalant agents, injection of barbiturates, injection of MS 222, immersion in MS 222, any physical method, slow freezing, immersion in liquid nitrogen","a":"Sure: injection of barbiturates, injection of MS 222, immersion in MS 222, immersion in liquid nitrogen\nNope: inhalant agents, any physical method (blow to head, pithing, electrocution, hyperthermia, hypothermia, exsanguination, decapitation, slow freezing"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"The tissues of animals in the reptile group are more resistant to _______, and as such, methods of euth that induce ____ (same word)  without management of painful stimuli should not be recommended","a":"The tissues of animals in the reptile group are more resistant tohypoxia , and as such, methods of euth that induce hypoxia without management of painful stimuli should not be recommended"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: THe use of sodium pentobarbital  is considered an effective and humane method of euthanasia in reptiles.","a":"T. 60-100 mg/kg (same as fish!)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Name two drugs that are recommended for heavy sedation or tranquilization prior to the admin of euthanasia in reptiles","a":"Ketamine and Telazol (propofol kinda sorta)"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Decapitation is acceptable as a sole method of euthanasia in chelonians","a":"F. Decapitation is only acceptable when reptiles are rendered unconscious  by other methods folowed by destruction of the brain. The brain of a chelonian appears to remain viable up to an hour after decapitation. All physical methods of euthanatizing reptiles (electric stunning, destruction of the CNS, blood to the head, cervical dislocation and captive bolt guns) should generally be a part of two-stage euthanasia procedures."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Why is freezing considered an unacceptable method of euthanasia for reptiles (et al)?","a":"Freezing has not been shown to reduce pain, and is considered painful due to the formation of ice crystals in the tissues."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"_______(drug) is recommended prior to administering euthanasia drugs to birds to reduce pain and distress in clinical settings","a":"butorphanol"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Using ________  (drug) as the sole agent for euthanasia of birds may  otherwise result in wing flapping, a perception of struggling, other untoward movements or vocalizations.0","a":"barbiturates"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Intracoelomic injection of barbiturate drugs is not recommended in birds","a":"T. Absorption of barbiturates via this route is delayed due to the presence of air sacs. Routes that are acceptable are IV, intraosseous, intracardic, intrahepatic, IM. Stings like a bugger any route besides IV, so must be deeply sedated before going other routes."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Bird eggs feel pain","a":"T. By 50% gestation the neural tube of avia embryos has sufficient development for pain perception. Avian embryos older than 50% gestation must be killed using decapitation, overdose of anesthetic, or other methods considered appropriate for hatched birds. For eggs/embryos <50% gestation techniques of shaking, puncturing, freezing or coating of eggs with corn oil are recommended."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Holy shit! did you know wombats can weigh up to 35 kg?!","a":"It's true. They also bite and have sharp claws. :0"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"Among the methods that ____ (choose: do or do not) meet the definition of euthanasia in rodents/small mammals are hypothermia/slow freezing, thoracic compression, strangulation, drowning, or other mechanical methods for asphixiation and air embolism.","a":"Among the methods that do not meet the definition of euthanasia in rodents/small mammals are hypothermia/slow freezing, thoracic compression, strangulation, drowning, or other mechanical methods for asphixiation and air embolism."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F: Two stage euthanasia (sedation/analgesia followed by chemical or physical euthanasia) is preferred for hoofstock species.","a":"T"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"What is the general dose of sodium pentobarbital for euthanasia of hoofstock?","a":"60-80 mg/kg"},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F In hoofstock both sodium pentobarbital and potassium chloride can produce secondary toxicity if the carcass will be consumed by humans or animals.","a":"F. KCl is a non controlled euth agent that can be administered without toxic residues remaining in the carcass. It should only be administered to animals in a surgical plane of anesthesia. And to reach surg plane of anesthesia you'll likely need drugs... which will leave toxic residues in the body..."},{"type":"card","domain":"Physical Health","sub":"Euthanasia","q":"T/F Penetrating captive bolts are an acceptable sole method of euthanasia in hoofstock.","a":"F. Exsanguination must follow the use of the penetrating captive bolt."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are aspects unique to shelter medicine vs large or small medicine","a":"Herd health plus individual health for small animals, with no reproductive or research goals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Understanding a shelter's ________ is critical to the design of an effective shelter health program","a":"Mission"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name two main types of shelters","a":"Non-profit and municipal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"_____ can cause lesions and symptoms that are indistinguishable from true clinical disease.","a":"Stress"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"_______ may be the starkest potential indicator of urgent shelter health problems","a":"\"Died in shelter\" rate: avg 0.75% (0.18-1.61%) Hurley"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Health programs can be interchanged for all shelters. T/F","a":"False: must be custom made based on goals, needs, resources of the facility."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Two main goals for shelter health programs:","a":"Keep animals healthy/happy, protect public health & safety"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which freedom is missing? Freedom from hunger/thirst, from discomfort (shelter), from pain, from injury and disease, from fear and distress to avoid mental suffering.","a":"Freedom to express normal behavior"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which freedom is missing? Freedom from hunger/thirst, to express normal behavior, from pain, from injury and disease, from fear and distress to avoid mental suffering.","a":"from discomfort by providing appropriate environment/shelter"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which freedom is missing? Freedom from hunger/thirst, from discomfort (shelter), to express normal behavior, from fear and distress to avoid mental suffering.","a":"from pain, from injury and disease,"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is not a general principle of infectious disease control: isolate infected animals, mass vaccination, mass treatment, good husbandry practices, feed adequate nutritious food, education of personnel, quarantine new arrivals","a":"feed nutritious food is part of good husbandry"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"__________ is more time and cost efficient than treatment.","a":"Prevention"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Social companionship, physical exercise, mental stimulation, and consistent daily routines are part of a behavioral wellness protocol for dogs and cats. What else is missing?","a":"History and behavioral exam, proper housing, and training"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is not an aspect of an environmental wellness protocol? a) population density b) cleaning and sanitation protocols c) segregation and traffic patterns d) HVAC, light/dark, building maintenance, e) daily rounds","a":"Daily rounds are more geared toward behavioral and physical health protocols. This list is missing: staff training for proper facilities and equipment use"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Next to physical exam, ______ is the most important aspect of medical problem solving (Problem Oriented Approach)","a":"History (medical and behavioral)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Unique to shelter medicine, an accurate physical description and inspection for ____________ is part of the intake physical exam.","a":"patient identification"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three most common areas for tattoos?","a":"inner ear, abdomen, inguinal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How fast should you scan for a chip?","a":"0.5ft/sec b/c scanners must cycle through all 3 frequencies."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Shelter SOAP \"Ps\" should include (3)","a":"diagnostic testing, treatment, staff/adopter education (and flow-through plan!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Protocols should be based on (3)","a":"organization's mission, availability of resources, and evidence based medicine/behavior"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Core vaccines for cats entering the shelter (AAFP) include:","a":"FHV-1/FCV/FPV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Core vaccines for dogs entering the shelter (AAHA) include:","a":"CDV/CAV2/CPiV/CPV, and Bordetella bronchiseptica"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What do vaccines for FIP, giardia, rattlesnake venom, and ringworm have in common?","a":"NOT recommended for shelter pets (or any pets)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FIV vaccination can cause:","a":"false positive test results on SNAP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccines are deactivated by:","a":"excessive heat or cold (freezing)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How soon should you use a reconstituted vaccine?","a":"room temp: 30 min (Ch 2) or 2-4hrs (Ch5) or 4 days in fridge"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccine response is impaired in animals with temps above","a":"103.6F"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination periods less than 2 weeks","a":"May blunt the immune response from previous vaccination"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"After (optional) booster vaccine, when should animals be next vaccinated?","a":"follow pet guidelines (AAHA/AAFP) = q3 years for FVRCP and DA2PP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Heartworm testing for cats is recommended (T/F)","a":"False- difficult to interpret results"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ideal body weight recordings for long-term pets should be:","a":"At intake, weekly for 1 month, then monthly."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Severity, chronicity, novelty, predictability, duration, and individual perception of a _________ all affect an individual's ability to cope.","a":"Stressor"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hiding, seeking social companionship, acquiring mental stimulation, stereotypies, feigning sleep are all examples of:","a":"behavioral coping mechanisms"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Long-term housing is considered over ________","a":"Two weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The successful adaptation of cats and dogs to novel environments depends on:","a":"The adaptive capacity of the animal and the quality of the environment"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"A ________ over conditions is one of the most critical needs for mental health and well-being","a":"sense of control"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When a decision has been made to euthanize an animal, it is imperative that _____.","a":"the procedure be performed without delay."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Recommended temperature range for cats in dogs is:","a":"64-84 degrees, with low-mid 70's as ideal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Recommended humidity range for cats and dogs is:","a":"30-70%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In managing an outbreak, which is not one of the six main tasks: 1) diagnosis and isolation of sick animals 2) identification and management of exposed/at-risk animals 3) Environmental decontamination 4) Admixture of newly admitted animals, 5) documentation, and 6) communication with staff, public, board, adopters","a":"4) Protection (clean break) of newly admitted animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the four categories of exposed animals  in an outbreak?","a":"1) ill animals 2) animals that are exposed and vulnerable 3) animals that are exposed but not vulnerable 4) animals that have not been exposed"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What percentage of the population should be sampled in an outbreak?","a":"10-30% to confirm diagnosis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Animals with mild disease are not a threat to naive animals. (T/F)","a":"False: see CDV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Footbaths are sufficient to reliably prevent transmission of serious disease (T/F)","a":"False: not sufficient (may even spread dz)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Two most important factors in determining outcome of disease exposure are:","a":"dose to which the animal is exposed, and immune status of exposed animal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Serology testing in an outbreak is useful for:","a":"Canine distemper, parvo, and feline panleukopenia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Quarantine time period =","a":"equal to or longer than longest probably incubation period of disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Adoption can be a consideration instead of quarantine if:","a":"adopter gets full written and verbal disclosure of animals' exposure history and risk"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Simply letting a kennel sit for several weeks is enough to get rid of the pathogen during an outbreak (T/F)","a":"False: cleaning (+/- repeatedly) gets rid of pathogen sufficiently/sitting may not eliminate hardy organisms."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"For canine respiratory pathogens, the \"clean break\" section must be ____ away from affect dog kennels.","a":"25 feet"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Documentation during an outbreak includes which questions?","a":"\"What is the condition?, How many affected?, Who? When did disease first develop? How long has it been?, Where did the animals go?\""},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ideally, outbreaks would be prevented by eliminating common risk factors such as (4):","a":"Overcrowding, stress, lack of vaccination, mixing species."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"3 basic principles of effective sanitation program include:","a":"1. selection of appropriate method 2. proper use and application 3. safety of exposed people and animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Physical disinfection methods include the use of (4)","a":"Heat, desiccation, UV light, radiation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The regulation of chemical disinfectants is by:","a":"EPA in accordance with FIFRA"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Wide antimicrobial spectrum, efficacy in presence of organic matter in various environmental conditions (pH/temp), compatibility with wide range of detergents, high safety threshold, non corrosive, non staining and inexpensive are characteristics of what:","a":"the (impossible) ideal disinfectant"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"\"-static\" vs \"-cidal\" disinfectants are:","a":"more likely to arrest the development or growth of organisms vs inactivation or destruction"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Viable organisms are inactivated in what pattern of reduction?","a":"Logarithmic - why contact time is so important"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Removal of dirt and debris ensures:","a":"optimal efficacy of a disinfectant."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Quaternary ammonium compounds are:","a":"cationic (hydrophobic/hydrophilic - lyses cytoplasmic membranes) surface environmental disinfectants"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spectrum of quats is:","a":"Gram positive bacteria, enveloped viruses. NOT good for gram negatives, non-enveloped viruses, fungi"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Quats are inactivated by:","a":"soap, anionic detergent, organic matter, hard water. Ethyl alcohol can potentiate."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Incorrect quat dilution is associated with:","a":"oral/skin ulcerations, pneumonia, death"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hypochlorites are:","a":"halogen compounds that work by denaturing proteins"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spectrum of hypochlorites are:","a":"Broad- bacteria, fungi, most viruses at low concentrations. 1:32 effective against parvo/calici"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hypochlorite dilutions of 1:10 are:","a":"Corrosive, caustic, ok for porous surfaces such as wood- respiratory and stain risk."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mixing hypochlorite with acids or ammonia =","a":"toxic chlorine gas"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Peroxygen (eg peroxymonosulfate) compounds work by:","a":"Denaturing proteins and lipids. (Trifectant has surfactant mixed in with peroxy)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spectrum of peroxygen compounds are:","a":"Broad- bacteria, fungi, most viruses - not very good against ringworm"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Chlorhexidine is:","a":"Biguanide, cationic, (alters permeability of cytoplasmic membrane of microorganisms) used for antimicrobial soaps, wound dressings, etc."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Chlorhexidine spectrum:","a":"Bactericidal, variable/limited against viruses, not mycobacterial or sporicidal. Range greatly reduced by organic material."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Alcohol is:","a":"Rapidly acting broad-spectrum antimicrobial, denatures proteins and causes membrane damage->cell lysis. Hand sanitizer. Flammable!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spectrum of ethyl or isopropyl alcohol are:","a":"Broad- incl bacteria, mycobacteria, fungi. Variable virucidal."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In order for alcohol to denature a pathogen, it requires:","a":"Water- therefore most effective concentrations are 60-90%. Flammable!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which three organisms are used to test disinfectant products?","a":"Staphylococcus aureus, Salmonella choleraesuis, Pseudomonas aeruginosa"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which organization approves disinfectant testing procedures?","a":"Association of Official Analytical Chemists (AOAC-- EPA)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"It is against the law to use a disinfectant in a manner inconsistent with its labeling (T/F)","a":"True- EPA 2008"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the difference between limited, general, and medical efficacy claims for disinfectants?","a":"Limited: Either G+ (SA) or G- (SC), General/broad: both G+ (SA) and G- (SC), Medical/hospital: All three (SA, SC, Pseudomonas)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cleaning alone can remove what % of bacteria from surfaces?","a":"0.9"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"High-pressure spraying is contraindicated because:","a":"It can aerosolize microorganisms and enhance spread of contaminants. (It's also loud!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the preferred order of cleaning/disinfecting kennels?","a":"Cleanest to dirtiest/Tallest to lowest"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vents, corners, and floor drains can all:","a":"serve as reservoirs for pathogens. clean last and thoroughly"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is not a factor affecting the failure of a disinfection program: 1) improper disinfectant selection 2) improper disinfectant composition 3) inadequate contact time 4) inadequate contact time 4) failure to remove organic material or competing chemical compounds f) improper application g) failure to allow to dry","a":"2) should be improper disinfectant concentration"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of intervention is preferred over footbaths?","a":"Use of dedicated boots or shoe covers"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spot cleaning is a strategy to reduce fomite accumulation. (T/F)","a":"True: in-residence cleaning prevents spread of animal pathogens outside that kennel. Wiping your apron down between cages and changing gloves is recommended."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Per IDM, what should be used in every laundry load?","a":"Hot water, detergent, and 1/2 cup bleach/std washer load"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should laundry be dried?","a":"In direct sunlight or in a drier until dry."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination can be relied on to protect all animals from illness. (T/F)","a":"False: diseases are not all vaccine preventable, host issues, leaky vaccines, etc."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Appx how many dogs in the community have received a DA2PP and Rabies vax?","a":"0.5"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Appx how many kittens in the community have received FVRCP and Rabies?","a":"0.25"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Are more dogs immunologically naïve to CDV or CPV?","a":"CDV 50% (+/-20%), CPV 30% (+/-15%) Newbury 2007"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Do more cats have antibodies against FPV or FHV?","a":"FHV, b/c natural infection-75%. FPV if infection or vaxed- 50% Newbury 2007"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which shelter vaccines are \"completely\" preventive?","a":"CDV, CPV, FPV, CA2V->CA1V (also, rabies??)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Parenterally administered, MLV core vaccines provide rapid immunity against those diseases with a single dose. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long does the Parvo vax take to work?","a":"3 days - shultz 2006"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the earliest time that a killed vaccine can start to work (generally)?","a":"3 weeks- 1 week after 2nd vax."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Intranasal vaccines are MLV products (T/F).","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What types of immunity do intranasal products stimulate?","a":"Non-specific immunity within hrs - cytokine shower (incl IFNa and b) from Bb contact with resp tract, then specific humoral immunity in 3-7 days."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"A strong difference has been shown in studies between intranasal KC and parenteral KC vaccines. (T/F)","a":"False- no difference in development or severity of disease post vax (Newbury 2007)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination of an immune animal provides no benefit. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what age can puppies start to get IN vaccines?","a":"As early as 2 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why not use MLV vaxes <4 weeks?","a":"undeveloped immune systems can't cope (really?)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the period during which maternal antibodies generally interfere?","a":"4-16 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the best way to protect young animals from disease?","a":"Physical separation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If an animal is so ill that vaccination is considered unsafe, the shelter is not the right environment for that patient. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Explain the risks of vaccination vs risks of not-vaccinating pregnant dogs?","a":"CDV and CPV can kill a pregnant dog and/or affect the embryos; CAV can cause absorption or abortion. CPV vax can rarely cause cerebellar hypoplasia. Get permission in legal cases."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Nursing animals should not be vaccinated. (T/F)","a":"False- nursing animals should receive vaxes as usual."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What temperature should vaccines be stored?","a":"33-35F or 1-3C"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why do MLV vaxes require reconstitution and killed don't?","a":"B/c they have been lyophilized to increase shelf life."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name the correct body site for each vax: FVRCP, RV, FeLV","a":"Right forelimb, right hindlimb, left hindlimb"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If exposed to wtCDV hours after MLV vax, what can happen?","a":"Dogs have respiratory and immunosuppressive signs (>pneumonia), may shed, but no neuro or GI disease."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the canarypox CDV vax for?","a":"Vectored recombinant CDV vax is safer, immunized 4 weeks earlier, made for ferrets = PureVax Ferret CDV, but can use 0.3-0.5ml on very young puppies likely to be exposed to CDV."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Parvoviral immunity is either complete or nonexistent (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is Neopar?","a":"Neotech manufactured CPV2 vax that manages to overcome MDAs earlier than other MLV vaxes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the onset of immunity to CAV1 or 2 when given MLV vax?","a":"7 days for hepatitis/uveitis (1), also 7 days for resp virus (2)."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why should IN vaxes be given annually?","a":"B/c while CAV-2 (if present) and CPiV (if present) have 3 year duration of immunity, Bb immunity is only 1 year or less"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Feline monovalent Bb vaxes are ok to use in dogs (T/F)","a":"False. only tested in labeled species."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If an intranasal Bordetella vax is given subcutaneously, it is considered an emergency. (T/F)","a":"True- swollen painful inflammatory rxn. Give gentamicin sulfate diluted intra-region or start oral doxy immediately. Worst case = hepatic necrosis."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why can intranasal vaxes be effective when given very early (4-8wks?)","a":"Because mucosal immunity has no interference from MDAs."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long does it take for cats to respond to MLV FPV vax?","a":"3 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CPV-2 can cause panleukopenia-like disease in cats but MLV parenteral FPV vaccination will prevent infection. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Immunity to FCV can develop as soon as _____.","a":"7 days after MLV vax with the right strain"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most current FCV vaccines contain strains that have not been updated in years (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The virulent systemic calicivirus vaccine is a killed product.","a":"True- therefore not likely to be effective for at least 3 weeks post-vax"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"All the VSFCV strains are related (T/F)","a":"False- all developed independently of each other (damn RNA viruses!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"MLV parenteral vaxes are just as effective as IN MLV vaxes for URI diseases in cats. (T/F)","a":"True- no difference demonstrated Newbury 2007"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is killed RV different than other killed vaxes?","a":"Adjuvanted, and high immunogenicity of rabies glycoprotein G"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The recombinant feline rabies vax is ok for dogs. (T/F)","a":"False- not effective. Don't use."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Getting vaccines in addition to the core vaxes may compromise the immune response to core pathogens in shelter animals. (T/F)","a":"True. Justify use of additional vaxes."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV vaccination is tricky. What is the maximum interval between the first 2 FeLV vaxes?","a":"4 weeks. If later, will need another in 4 weeks again."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The FIV vax is protective against all types of FIV (T/F)","a":"False- only some clades; only after 3 vaxes 3-4 weeks apart, not to mention interference with diagnostic testing."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What two vaxes are optional for pet dogs in areas of high risk but not generally recommended for shelter dogs?","a":"Lyme and Leptospira"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the 1/2 life of MDAs?","a":"2 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define the \"window of vulnerability\" for juvenile animals:","a":"When MDAs have fallen low enough to allow viral infection but are still high enough to prevent effective immunization from vaccination"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long is the \"window of susceptibility\" for juvenile animals?","a":"2-4 weeks with modern vaccines"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In a juvenile animal, when MDAs are very low or absent, one MLV vax is sufficient to provide complete immunity against CPV, FPV, and CDV (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Within a litter, all animals receive the same amount of MDA.","a":"False- depends on early nursing, birth order, etc"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"MDAs can prolong infection within a litter (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the risks of vaxing a 2 week old puppy?","a":"Vaccine virus can kill very young animals- gets into the brain, esp if colostrum deprived. Body temps are too low for vaxes to work properly."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"MDAs decline more rapidly if a juvenile animal is vaccinated (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long is the GI tract of a neonate open to absorbing IgG from colostrum?","a":"3 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What can replace colostrum for 1-3 day old kittens without dams?","a":"Feline serum- via oral route, SQ or IP."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Discuss benefits/drawbacks of oral vs SQ serum in neonatal kittens","a":"SQ: Injection site pain but may have greater window of absorption, Oral: less pain, readily given by foster, needs given <3days (Levy 2001)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hyperimmune serum given to naïve animals can prevent infection with CDV, CPV, CAV, and FPV. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CPV antibody titer test wells can be used for FPV in an outbreak situation.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which step in the TiterChek system is the most important to prevent false positives?","a":"Washing"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Titer testing should be performed on sick and well animals in an outbreak (T/F)","a":"False- should ONLY be performed on animals with no C/S and no hx of C/S"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs with which titer status are the most at risk for developing disease?","a":"No C/S but no titers to any vax diseases"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Puppies and kittens can be titer tested to determine if they are high or low risk (T/F)","a":"False- don't know if titers are MDAs or vax responses or early disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name whether FeLV/FIV are tested via antigen or antibody on SNAP, and how vaccines relate to test results.","a":"FeLV = antigen, no interference with vax. FIV = antibody, vax interferes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination interferes with CPV and FPV testing (T/F)","a":"True, rarely, and Idexx tests less than others"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more likely to have false positive CPV/FPV tests in vaccinated animals, PCR or ELISA?","a":"PCR- but PCR less likely to have false negatives"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the average outer limit for detection of antibodies from vaccination on PCR/VI/IFA/IHC?","a":"2 weeks- vax virus replicates in all sorts of tissues including lymphocytes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination interferes with paired serum antibody titers for CDV and CPV. (T/F)","a":"True- antibody titers would be expected to rise significantly after vaccination"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Shelter vets must consider economic, logistical and philosophical constraints on drug selection and dosing. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Put these in order of hierarchy of evidence level: Case series, case-control, randomized controlled trials, cohort studies, expert opinion, systematic review","a":"1. Systematic review 1b. Individual RCTs 2. Cohort studies 3. Case control studies 4. Case series 5. Expert opinion"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the four basic steps to practice evidence based medicine?","a":"1. ask a clinical question 2. search for evidence to answer the question, 3. appraise the evidence for validity/applicability and 4. apply the information to the patient"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"There are 4 basic steps to successful therapeutic selection. What are they?","a":"1. Have solid evidence of pathogen (eg bacteria) involved 2. consider which drugs could be successful 3. determine concentration needed to kill particular bugs 4. determine dose, frequency and duration to achieve concentration"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Chloramphenicol and Carbapenems are one of the few drug groups that can kill almost all gram positive and negative bacteria (T/F).","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Fluoroquinolones are effective against obligate anaerobes (both Gram + and Gram -) (T/F)","a":"False- not effective. Don't use."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Metronidazole is effective against obligate anaerobes (both gram+ and gram-) (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which antibiotics are effective against mycoplasma?","a":"Tetracyclines, fluoroquinolones, and some lincosamides/macrolides"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which antibiotics are effective against spirochetes?","a":"Aminopenicillins, tetracyclines, macrolides"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cephalosporins are categorized by:","a":"Group and generation. Group considers route. Cefotaxime is 3rd generation parenteral, so is in group 4 with cefovecin (convenia)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the purpose of susceptibility testing?","a":"To use an in vitro method to make a prediction about clinical success"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are break points in antimicrobial susceptibility testing?","a":"Criteria for correlating a given inhibitory concentration (S, I, R). Developed and established by the veterinary antimicrobial susceptibility testing committee (voluntary consensus standards)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In susceptibility testing, all drugs are tested individually (T/F)","a":"False- certain drugs are used as stand ins for multiple drugs, eg ampicillin for amoxicillin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define pharmacokinetics:","a":"Where a drug is found, how long it is there, what happens to it, and how it leaves."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two major pharmacodynamic categories of antibiotics?","a":"Those that are most effective when concentrations stay above an inhibitory concentration for a certain percentage of the dose interval (time dependent) and those that are most effective when drug concentrations exceed the in vitro inhibitory concentration by a certain proportion but do not need to remain above MIC for a long period of time (concentration dependent aka peak dependent)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Using antimicrobial drugs in a manner that maximizes therapeutic efficacy also:","a":"minimizes selection for resistance"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two types of antimicrobial resistance?","a":"Innate and acquired"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two types of acquired antimicrobial resistance?","a":"Individual mutation or transfer of genetic material"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Choosing the broadest spectrum antimicrobial helps reduce resistance (T/F)","a":"False- choosing narrowest spectrum that includes target organism"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two ways to reduce resistance selection?","a":"Drug selection and appropriate dosing"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the MPC in drug resistance context?","a":"The mutation prevention concentration (concentration that inhibits the growth of mutant organisms)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some major principles of prudent use of antimicrobials?","a":"Emphasizing infection prevention strategies (decreasing stress), sanitation, fomite control, and accurate records of antimicrobial drugs used."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is AMDUCA:","a":"Animal Medicine Drug Use Clarification Act: said vets could legally use drugs in extralabel fashion IF in context with VPCR, proper label, medical records kept for 2 years."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are two main types of compounding:","a":"1. manipulating an approved drug into a different format (eg tablet into liquid), and 2. making a drug from bulk-stock (eg raw ivermectin). #2 is NOT covered in AMDUCA and not legal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Products made from bulk drugs undergo the same manufacturing requirements as approved commercial drugs. (T/F)","a":"False- issues of potency and safety."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should you do if there are unexplained deaths in the population?","a":"Necropsy!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is the most accurate method for collecting effective diagnostic samples, assessing diagnostic accuracy, and predicting disease emergence?","a":"Necropsy!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Performing necropsy in the shelter is variably available and variably expensive for small animals (T/F)","a":"False- storing samples is inexpensive and biopsy/microbio services are readily available."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Main task of necropsy in shelter is to rule in/out:","a":"Infectious vs other causes of death"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the optimal time for necropsy?","a":"As soon as possible after pt's death"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Zoonotic diseases are less infectious at necropsy vs when pt is alive (T/F)","a":"False- can be more infectious with increased contact with certain tissues (eg rabies/anthrax)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should you store cadavers before necropsy?","a":"Refrigerator (2-4C) asap after death until necropsy performed. Freeze if no available necropsist >3 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which animal should be selected to have a representative necropsy?","a":"Recently deceased, showed common/similar clinical signs. Know hx (abx? euth method?)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should you euthanize an animal with GI disease before necropsy?","a":"By avoiding GI tract (no Oral or IP)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"One should be as objective as possible when performing a necropsy. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Photographs can substitute for written words in necropsy reports.(T/F)","a":"False- combo words plus images is vital for communication."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which one of these is not a necropsy material: 1) Camera 2) Notebook or path form 3) Protective Clothing (boots, gloves, mask) 4) Sterile gown 5) Instruments (sharp knife, scissors, shears) 6) Collection gear (formalin bottles, tags) 7. Transport containers and equipment (boxes, labels, ice) 8. Disinfection materials","a":"4) Sterile gown is not needed"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Performing a necropsy by looking at organs in the right order is more important than consistency. (T/F)","a":"False- consistency is important; there is no single correct method"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Have in mind samples needing collection before starting your necropsy. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When collecting samples in respiratory disease, lungs sections are more diagnostic than nasal swabs. (T/F)","a":"True if pt has pneumonia. Not if URI."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How thick should tissue samples be to absorb formalin properly?","a":"1cm thick"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the appropriate ratio of formalin to tissue?","a":"10 formalin: 1 tissue"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is the most common strain of canine parvovirus in the US (in 2009)?","a":"2b"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"segmental to diffuse subserosal hemorrhage affecting the small intestine describes:","a":"typical parvoviral infection in dogs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What intestinal immune organ can become dark red due to lympholysis during parvoviral infection?","a":"Peyer's patches"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Lungs have large amounts of artefact and perimortem changes. (T/F)","a":"True- this makes interpretation of \"normal\" difficult"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Accurate culture results require what type of technique during necropsy?","a":"Sterile technique- take these tissues first (esp lungs)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"You don't need to report premortem therapy on histopath forms. (T/F)","a":"False- report all."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which lymph nodes are of particular interest when performing a necropsy on a respiratory disease patient?","a":"Hilar LN"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Clinical impression is sufficient to differentiate canine distemper from other causes of KC. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CDV lung lesions are disseminated throughout all lobes (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name four tissues you can diagnose CDV from:","a":"lung, CSF, feces, urine"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you diagnose CIV?","a":"PCR of nasal secretions, or Becton-Dickinson Flu-A ELISA"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Disseminated, hemorrhagic and consolidated lungs are likely due to:","a":"CIV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name some common causes of acute death:","a":"anaphylaxis, trauma, intestinal malpositions, cardiomyopathy, electrocution, gunshot, drowning, septicemia, heat stroke, dehydration, toxin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The peritoneum is the single, predictable target organ for FIP. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FIP viruses disseminate in macrophages (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Surfaces of viscera with 1-5mm friable pale tan plaques and a granular appearance are typical of:","a":"FIP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are granulomas associated with in non-effusive FIP?","a":"capsular or serosal vessels (vascular dz)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccines for URI uniformly fail to prevent infection. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name the five most common URI pathogens.","a":"FHV1, FCV, Bordetella, Chlamydophila, Mycoplasma"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Virulent systemic disease (VSD) and hemorrhagic-like fever are other names for:","a":"Virulent systemic feline calicivirus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is FCV and why is it important?","a":"RNA-virus (with error-prone replication of RNA-dependent RNA polymerases) so plasticity of genome = multiple strains with varying virulence"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"VS-FCV strains persist in populations for how long?","a":"2-3 months. There have been around 10 outbreaks."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"C. felis primarily causes which C/S:","a":"conjunctivitis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"B. bronchiseptica is a primary URI pathogen in cats.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mycoplasma sp seem to be opportunistic in the upper respiratory tract may be but primary in the lower respiratory tract. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name four other pneumonia bacteria in cats besides mycoplasma","a":"Staph, pasteurella, strep, E-coli"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which of the following is potentially zoonotic: FHV, FCV, Chlamydophila, Bordetella","a":"Chlamydophila and Bordetella"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why would recovering more incidental calicivirus than herpesvirus in healthy cats NOT indicate a higher relative incidence?","a":"Persistence in environment and longer duration of shedding by cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What factors could contribute to incidence/prevalence of URI in shelters?","a":"community incidence, season, virulence, management (housing), etc"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats and dogs infect each other with B. bronchiseptica. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"C. felis can only be isolated from clinically affected cats. (T/F)","a":"False- clinically normal cats in 2 studies were positive"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Diagnosis of causative agent of URI can be made based on clinical signs alone. (T/F)","a":"False- plus more than one may be involved."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hypervirulent strains of VS-FCV have a mortality rate of:","a":"0.5"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are non-URI symptoms of FCV?","a":"Lameness, skin lesions, ulceration of mouth, edema of limbs/face, liver/splenic/pancreatic necrosis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe a typical C. felis infection:","a":"conjunctival hyperemia, blepharospasm, chemosis, serous/mucopurulent ocular discharge, often only one eye"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"All of the respiratory infectious agents can cause subclinical infection (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Empirical treatment with doxycycline is a common protocol for feline URI. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats with osteochondritis from herpesvirus do well with which treatment?","a":"Clindamycin For 4-6 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"C. felis may need to be treated for 3-6 weeks (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Duration of ophthalmic drug therapy for C. felis and herpes-associated conjunctivitis is:","a":"Dependent on the clinical course of disease."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which antivirals are recommended for URI?","a":"idoxuridine (compounded, up to 4x daily) and cidofovir (compounded, less frequent)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why are URI agents mostly spread through fomites?","a":"Tidal volume (inspired air) is too low to spread aerosol droplets >4 feet"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which URI agent has the highest survival time outside the host?","a":"Calici"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Primary site of FHV-1 latency is:","a":"Trigeminal ganglia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What proportion of cats is still shedding 75 days postinfection with FCV?","a":"0.5"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rarely, cats can become lifelong shedders of calicivirus (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When do cats shed URI agents most efficiently?","a":"When displaying clinical signs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some risk factors for URI in cats?","a":"Length of time in shelter, overcrowding, incidence in population, old cats, poor hygiene, living near dogs (bordetella), young age, stress."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"___________ can substantially reduce the frequency and severity of URI disease in shelters.","a":"Management practices"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Effective _________ and __________ protocols are essential to minimizing URI occurrence in shelters.","a":"Cleaning and disinfection"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"1:32 bleach is made by putting ____ bleach in _______ water","a":"1/2 c : gallon"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Moving cats from one cage to another is sufficient to __________ which virus?","a":"Reactivate herpes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more effective against FCV- ethanol based or isopropanol based hand sanitizers?","a":"Isopropanol"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Good ventilation optimizes __________ and reduces ________, which increase the risk of URI","a":"humidity level; particulates and ammonia fumes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What number of air cycles/hour are recommended in 2009 (from Sinclair 1997)","a":"43020.0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Optimal humidity levels to prevent URI are:","a":"35-45%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"HEPA filters in animal facilities are impractical because:","a":"pet hair and dander clog filters quickly"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"UV light is impractical for URI disinfection because:","a":"areas shaded from UV light are not disinfected, and most URI agents are not aerosolized."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ozone disinfection is not recommended because:","a":"ozone generators produce O3, a respiratory irritant."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Both patient stress and ______ stress can be a risk factor for URI in cats","a":"Staff"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Kittens as young as _____ may receive the IN vax for URI pathogens:","a":"3 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"IN vaccines can be effective as soon as _______ days.","a":"4-6 days (Lappin 2006)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When should you use B. bronchiseptica and C. felis vaxes?","a":"If there is a documented shelter outbreak"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination with MLV intranasal can potentiate a killed parenteral vaccination if given at the same time. (T/F)","a":"(TRUE- Edinboro 1999)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is L-lysine thought to work?","a":"Inhibit viral replication by competing with arginine, which is needed by FHV replication."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is L-lysine not recommended?","a":"Shelter cats in a trial had more severe symptoms while on L-lysine, and body arginine levels were so suppressed they didn't return to normal."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In light of the strong association between length of stay and URI, quarantine of 10-14 days may be warranted. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Isolation may consist of a separate set of cages on one side of a room. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats should be removed from isolation when __________.","a":"Clinical signs have disappeared, despite possibly still shedding."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Placing sick cats in foster can help resolve URI by _________.","a":"Decreasing stress of being in the shelter."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"accurate disease recognition, rapid and consistent reporting, laboratory support, data entry and capture, data interpretation, and reporting are all parts of an effective ____________","a":"Disease surveillance system"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When comparing yearly URI rates, what should be compared?","a":"URI cases/month to URI cases/same month of the year"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Motivating factors to continue improving URI management include:","a":"Feedback to staff/vols, and the reassessment of goals with the creation of new goals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"__________ of dogs on intake is an essential component of the kennel cough disease control plan.","a":"Initial health assessment"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Methods that reduce ______ and ________ in dogs may be extremely beneficial in helping to curtail CKCC transmission.","a":"Stress; barking"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three pathogens that cause significant mortality in KC outbreaks.","a":"Strep zoo, Influenza, Distemper"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name 5 viruses that cause KC.","a":"CAV2, CPiV, CRCoV, CHV, CDV, CIV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the host range of CAV2?","a":"Foxes, wolves, marine mammal hosts (broad range)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Differentiate between CAV1 and CAV2","a":"1- liver/hepatitis, severe. 2- laryngotracheitis +/- tonsillitis +/- pneumonia (interstitial)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is parainfluenza?","a":"Paramyxovirus (ssRNA virus)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What cell type does parainfluenza infect?","a":"URT, because cannot replicate in macrophages"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What causes \"honk\" part of parainfluenza cough?","a":"Laryngeal edema"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the best established symptom of canine herpesvirus?","a":"Fatal septicemia in <2wk old puppies."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is CDV?","a":"Paramyxovirus (many hosts)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is Influenza?","a":"enveloped RNA virus (orthomyxovirus)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In the first CIV outbreak, what percent of animals were asymptomatic shedders?","a":"0.25"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the incubation period of CIV (H3N8)","a":"2-5 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where does B. bronchiseptica attach in the respiratory system?","a":"Cilia of the respiratory epithelium"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"B. bronchiseptica produces a variety of potent toxins that impair phagocyte function and reduce ciliary function (T/F)","a":"True- this allows opportunistic organisms to colonize the epithelium."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"B. bronchiseptica is an extracellular pathogen. (T/F)","a":"True"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"B. bronchiseptica can invade host cells","a":"True- though normally it's extracellular. Evasion-> carrier state/persistent infection"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mycoplasma have a cell wall. (T/Ff)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is the mycoplasma species of greatest concern?","a":"M. cynos (possibly)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Strep zoo causes:","a":"hemorrhagic streptococcal pneumonia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"An unusually severe variant of CPiV in puppies is?","a":"Encephalomyelitis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"High incidence of B. bronchiseptica is associated with old or young puppies?","a":"Younger"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CPiV, CAV-2, CDV ,CaCoV have asymptomatic carrier states. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What's the best way to ID KC in your shelter?","a":"Daily health assessments (Rounds)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the preferred site for PCR swabbing for KC PCR?","a":"Deep pharyngeal area/*trachea*"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mycoplasma should respond to which particular drugs?","a":"clinda, doxy, enro"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of drug can kill Strep zoo?","a":"Penicillins, cephalosporins, etc"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some good reasons to group house dogs?","a":"Littermates, stress reduction, behavioral enrichment"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"According to Edinboro, Ward and Glickman (2004), by how much does the risk of acquiring cough increase day to day in a shelter?","a":"0.03"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the range of shedding for KC dogs ?","a":"2 weeks-3 months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which KC bug is the most resistant to disinfection?","a":"CAV-2"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which disease was once the canine's most common deadly infectious disease?","a":"Distemper"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three diseases that are closely related to canine distemper:","a":"Measles, rinderpest, peste des petits ruminants, dolphin morbillivirus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which mammal species likely acts as a CDV reservoir?","a":"Raccoons"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"MLV viruses made in the 50s and 60s for distemper remain highly effective (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is CDV transmitted in the shelter?","a":"Aerosols, fomites, shedding from subclinically affected and recovering animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the first body system attacked by CDV?","a":"Lymphoid"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Immunosuppression is a hallmark of CDV and CPV infections (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the incubation period of CDV?","a":"2-6 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which strain of CDV is more common today- acute strain or subacute strain?","a":"Subacute. Acute = Snyder HIll (Baker Inst, Cornell)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When do neuro signs develop in CDV?","a":"Concurrently or up to 2 weeks after other signs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what point in the infection with CDV does the patient start to shed virus and then stop shedding?","a":"1 week post-infection and up to 16 weeks (4 months) post"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is Old Dog Encephalitis?","a":"Syndrome of progressive neurological disease initiated by CDV but with no viral reactivation or shedding"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the mortality rate of dogs showing symptoms of CDV?","a":"50% (+/-20%)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the usual progression of clinical signs of CDV?","a":"Fever/immunosuppression->respiratory signs (1 week) ->Gi signs (2nd week) incl massive weight loss->Skin disease and neuro disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ocular lesions associated with CDV include:","a":"crusting, ocular discharge, blepharospasm, keratoconjunctivitis sicca, optic nerve swelling, focal retinal degeneration (gray-pink densities) -> hyperreflective areas"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What causes the delayed neuro signs in CDV?","a":"immunopathologic destruction of nervous tissue- high CDV ab titer in CSF and loads of IgG in CSF"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What brain tissue do acute strains of CDV attack? subacute strains?","a":"acute- grey matter, subacute- white matter (clinically indistinguishable)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Neonatal CDV infection can cause:","a":"enamel hypoplasia, metaphyseal osteosclerosis, associated w HOD; bitches: abortion, stillbirth, weak pups"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"On what specimens are IHC and IFA tests used to detect CDV?","a":"tissue sections after postmortem exam"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Serological tests measuring IgM vs IgG to detect CDV are reliable in shelters where dogs are vaccinated on entry (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs that have not developed neurological dz have the best chance of recovering from CDV. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CDV neuro disease is often progressive and irreversible. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination for CDV protects against neuro disease first, then provides significant decrease in clinical signs, then full immunity over the course of 3-5 days. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Immunosuppression can be a sequelae of CDV vaccination. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is the most effective CDV vaccine?","a":"recombinant MLV CDV (canarypox)- for puppies <20 weeks (0.3-0.5ml)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In addition to vaccination, what management practices keep puppies safe from Distemper?","a":"Housing juvenile animals outside the shelter"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If vaccinating raccoons or ferrets, which CDV vax should you use?","a":"PureVax Ferret recombinant (1ml)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should the quarantine period be for CDV outbreaks?","a":"4-6 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is Influenza A?","a":"SS RNA (Orthomyxovirus)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"CIV H3N8 was first described in:","a":"Racing greyhound kennels having respiratory disease outbreaks."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Because influenza is a novel pathogen, dogs of any breed, age, size, or vax status are susceptible. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most dogs with H3N8 recover in:","a":"10-30 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the transmission route of influenza?","a":"Coughing and sneezing create aerosol droplets with large amts of virus, fomite transmission also plays a role"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the shedding period of H3N8 influenza?","a":"7 days average, 10 days at longest"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Peak viral shedding often occurs before apparent clinical signs in influenza. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"An explosive onset and spread of KC in most dogs in shelter and staff owned dogs within a short period of time (eg 2 weeks) would be characteristic of which infectious disease?","a":"Influenza"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What proportion of dogs develop clinical signs when infected with influenza?","a":"80-90%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When dogs die of influenza, what is their cause of death?","a":"Pneumonia, often with secondary bacterial component from Staph, Strep, Pasteurella, Klebsiella, E Coli, and Mycoplasma"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When sampling a dog for PCR in an influenza outbreak, when in the course of disease and where should samples be taken?","a":"Early to capture peak shedding- swab of nose and pharynx"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you avoid cross contamination during sample collection in influenza outbreaks?","a":"Wear PPE, change gloves between each dog, only touch the swab to nasopharyngeal tissue and nothing else"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you confirm influenza infection when PCR can be unreliable?","a":"Serology- acute and convalescent titers 2 weeks later. Look for 4x increase in ab titer"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where does CIV replicate?","a":"Epithelial layer lining nasal passages, trachea, bronchi, bronchioles, resulting in sloughing of damaged cells and exposure of underlying tissues to secondary bacterial infection."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"There is good support for using antitussives to reduce frequency/duration of coughing in dogs with influenza. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Oseltamivir (TamiFlu) has been shown to help decrease the course of disease in dogs with influenza. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long do dogs retain antibodies against influenza A post-infection?","a":"5-6 years"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long should you quarantine H3N8-exposed dogs?","a":"7-10 days shedding- to be safe, 14 days is recommended."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Some dogs may continue to cough and have pneumonia long after they have stopped shedding H3N8 influenza viral particles. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In 2009, shelters were increasingly unable to break the infectious cycle of ____ because there were no vaccines available.","a":"H3N8 influenza"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the incubation period for H3N8 influenza?","a":"2-4 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long has feline panleukopenia been around?","a":"Recognized before 1900"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some other names for panleukopenia of cats?","a":"feline agranulocytosis, show fever, feline distemper, cat plague"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is panleukopenia?","a":"non-enveloped DNA parvovirus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Modern panleukopenia can affect both dogs and cats. (T/F)","a":"False but modern parvovirus (2a, 2b, 2c) can possibly infect cats."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Raccoons are highly susceptible to which feline virus?","a":"Panleukopenia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why does seasonal incidence of panleukopenia virus peak in late summer/early fall?","a":"Coincides with prevalence in population of unprotected young cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name two ways panleukopenia virus is transmitted:","a":"Fecal/oral (fomites), and transplacentally."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats can transmit panleukopenia via sneezing. (T/F)","a":"True- if concurrently infected with URI"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what point in the infection with Panleuk does the WBC count fall?","a":"48 hours to 4-6 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the significance of crypts of Lieberkühn in panleukopenia?","a":"It's where the virus replicates in the GI- this destroys the cells that are becoming villi, which causes huge destruction/loss of epithelial surface area and malabsorption."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why does panleukopenia cause panleukopenia?","a":"It attacks cells in the bone marrow (both erythroid and myeloid lines), but WBC have shorter life spans, so WBC loss is apparent first."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Average incubation vs longest incubation period of panleuk?","a":"5-7 days, but up to 14 days."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When are animals done shedding panleuk?","a":"Usually 3 weeks but up to 6 weeks post-infection."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the morbidity of panleuk in unvaccinated cat populations?","a":"Up to 100%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three syndromes of panleuk?","a":"Peracute, acute (typical), subacute (mild), also in utero"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the main clinical sign of peracute panleuk?","a":"Death"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the normal progression of signs in acute panleuk?","a":"High fever for 24 hours, then drops, then fever again as WBCs fall, vomiting, diarrhea, severe dehydration, hypothermia, coma, death."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long does the subacute/mild form of panleuk usually last?","a":"2-3 days, then recovery."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Fetuses may become infected by panleuk even if moms show no symptoms.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are three ways to test for panleukopenia?","a":"ELISA, hematology, PCR"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Is the ELISA for cats more sensitive or more specific?","a":"Specificity = 94-100% Sensitivity less- maybe 50-80%?"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Serology can be useful in determining whether a cat has panleuk or not. (T/F)","a":"False- since vaccination mimics disease in increasing antibody levels."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mild to severe intestinal congestion with or without petechiation is common for what disease?","a":"Panleukopenia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Yellow-white bone marrow color may indicate what disease/process?","a":"Panleukopenia, bone marrow destruction of erythroid and myeloid lines"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What bacteria cause toxic leukopenia (a r/o for panleuk)","a":"Salmonella, C perfo, Campy"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should medications be administered to panleuk cats?","a":"Parenterally, since intestinal lesions/vomit/diarrhea"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some bench marks for giving blood transfusions to panleuk cats?","a":"Ptn is 4g/dl or WBC <2K cells/ul. 22ml/kg slowly IV or IO"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the only truly specific treatment for panleukopenia in cats?","a":"Antiserum- must be given before C/S"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What three fundamental principles help control panleuk risk?","a":"Proper vaccination, close monitoring and isolation, and careful cleaning/disinfection"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Panleuk vaccines protect against canine parvoviruses that affect cats (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the most common cause of panleuk vaccine failure?","a":"MDAs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats with FIV should be given killed panleuk vaccines.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What cats are the best source of antiserum for colostrum-deprived kittens?","a":"Healthy cats vaccinated at least 2 weeks previously (2 ml/kg)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Any case of fetid gastroenteritis should be considered potentially contagious and isolated until proven otherwise.","a":"Sturgis 2003 - TRUE"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What can help identify at risk cats in a group room with panleuk case?","a":"Serum titers for FPV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What quarantine period should be used for panleuk exposed cats?","a":"14 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Alcohol hand sanitizers inactivate FPV reliably. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Parvoviruses require what type of cells for replication?","a":"Rapidly dividing"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the currently most isolated strain of parvovirus?","a":"CPV-2b in the US, CPV-2a in Europe"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Certain breeds are more at risk for CPV (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"During which season are most parvovirus hospital admission?","a":"Summer- July-Sept"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the course of proliferation of parvovirus in the body?","a":"Starts in oropharynx->lymphoid tissue, then GI and bone marrow"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Incubation for parvovirus?","a":"CPV2: 7-14 days. 2b 4-6 days, but up to 14 days reported."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When does shedding start in course of parvoviral disease?","a":"3-4 days post-exposure, so often before C/S"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"There is a parvoviral carrier state in dogs. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are 2 typical syndromes seen with CPV- infected dogs?","a":"Acute myocarditis in very young pups, and hemorrhagic enteritis in older pups."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If parvovirus infects a pregnant dog, what can happen to the pups?","a":"Acute myocarditis = acute death or up to 6 mo acute onset congestive heart failure."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the main factor that determines the severity of CPV disease?","a":"rate of lymphoid and intestinal cell turnover; ^ turnover = ^ severe"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cerebellar hypoplasia is also common in puppies born to dams with CPV. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name some ddx for Parvovirus?","a":"FB, Salmonella, Campylobacter, IBD, HGE"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are two things that cause false negative results on SNAP tests?","a":"High levels of antibodies bound to antigen = won't bind to test, intermittent or no longer shedding virus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name 3 other ways to dx Parvo besides ELISA:","a":"PCR, VI, Necropsy (IFA)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the contribution of \"insensible losses\" to fluid therapy calculation?","a":"15ml/kg/day"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the major bacterial enteric pathogen of concern in parvoviral infections?","a":"C.perf"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What three components make up \"supportive care\" for parvo puppies?","a":"Fluid resuscitation, antibiotics against 2ndary pathogens, and antiemetics. Rec: metoclopramide(!) or ondansetron (pre maropitant)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What does a plasma or blood transfusion do for parvo puppies?","a":"Provides RBCs if anemic, antibodies, albumin support"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is EEN in the context of parvo supportive care?","a":"Early Enteric Nutrition- feeds enterocytes, supports enterocyte growth"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Granulocyte colony stimulating factor and Tamiflu are useful in parvovirus supportive care. (T/F)","a":"False- have not shown to change clinical outcome"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Puppies should be adopted straight out of isolation or foster homes after parvo infection. (T/F)","a":"True (?)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Immediate vaccination in the face of parvoviral disease will prevent development of disease (T/F)","a":"False- will decrease morbidity/mortality in unvaxed animals tho"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The EPA considers quats effective against parvovirus (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Puppies and dogs from high risk environments should be quarantined for 14 days before being allowed in common areas (grass/play yards) (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How high does the temp need to be to inactivate parvovirus in the environment?","a":"75C = 167F"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is CPV-1?","a":"Minute virus of canines"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Who is affected with CPV-1","a":"puppies <3 weeks get vague symptoms, or enteritis, pneumonitis, myocarditis, lymphadenitis. may be associated with mild diarrhea in older animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination for CPV2 is protective against CPV1 (T/F)","a":"False- no vax. Not widespread. \"Fading puppy syndrome,\" rarely tested for."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Canine Coronavirus mostly affects which animals?","a":"Puppies <12 weeks, diarrhea."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the shedding period for canine coronavirus?","a":"Weeks to months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Incubation period for canine coronavirus?","a":"1-3 days, start shedding 3-14 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"MLV coronavirus vaccines provide complete protection to puppies <3 months (T/F)","a":"False- incomplete."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three major concerns re: parasites in the shelter?","a":"1. treat current disease or asymptomatic pet 2. prevent shedding so parasites won't contaminating shelter 3. protect shelter staff, visitors, adopters"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name a nematode that is immediately infectious after defecation:","a":"Filaroides hirthi, filaroides osleri (lungworms), Ollulanus tricuspis (stomach worm)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most enteric parasites are directly infective when shed in stool.(T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is ollulanis trisucpis transmitted?","a":"Feline vomitus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Filaroides hirthi can be passed by the dam to the pups by licking them. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Distinguish between filaroides hirthi and filaroides osleri- where do they live, how transmitted, and how treated?","a":"lung parenchyma-saliva/feces-ivermectin/albendazole = hirthi. lung nodules- saliva/feces - ivermectin, albendazole/surgery! = osleri"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two species of strongyloides in cats?","a":"tumefaciens and felis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Who is the host of strongyloides stercoralis?","a":"Dogs and people (!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the transmission cycle of strongyloides stercoralis?","a":"Feces->Skin penetration->lungs (coughed/swallowed)->small intestine"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is strongyloides stercoralis diagnosed?","a":"1st stage larva in feces on Baermann funnel or Zinc floatation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Humans and dogs can clear strongyloides spontaneously (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which roundworm species is found in dogs, cats, and various other canids/felids?","a":"Toxascaris leonina"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"All roundworms of shelter pets can cause human disease (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more severe and which is more common, Toxocara canis or Baylisascaris procyonis?","a":"Toxocara = common, Baylisascaris = severe (human deaths)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the prevalence of Toxocara canis in puppies?","a":"0.3"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the prevalence of Toxocara cati?","a":"40%, with 67% shelter cats and 30% owned cats infected."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Kittens can be infected with Toxocara cati in utero (T/F)","a":"False- puppies can from canis."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Puppies can be infected with Toxocara canis by nursing (T/F)","a":"False- kittens can from cati"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"That is the secret to successful transmission for roundworms?","a":"Hardiness of eggs."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Compare the prepatent periods of canine and feline roundworms:","a":"Canis - 5 weeks (pups infected in utero - 3 weeks) Felis- 6-8 wks, (6 wks from milk)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Treating a dog for roundworms once ensures no chance of future roundworm shedding. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe the most common clinical signs in dogs from Toxascaris leonina and Baylisascaris procyonis:","a":"No signs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What does the CDC recommended for deworming puppies/kittens?","a":"Start at 2 weeks for pups, 3 weeks for kits, then q2wks til 12 weeks old"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Match species to host: Ancyclostoma braziliense, Ancylostoma tubaeforme, Uncinaria stenocephala","a":"Both dog and cat and other sp: Braziliense and Uncinaria. Cat: tubaeforme"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which hookworm species is most commonly zoonotic?","a":"A. braziliense (causes majority of cutaneous larval migrans)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How are hookworm species differentiated?","a":"after maturity- usually on necropsy"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the general prevalence of hookworms in dogs?","a":"Between 15-20%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are two modes of hookworm transmission?","a":"Skin migration and ingestion of infected soil"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the most common clinical sign of hookworm infection?","a":"Anemia (regenerative)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Puppies can be infected with Ancylostoma canis by drinking their infected dam's milk (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats can be infected with Ancylostoma tubaeforme by drinking the milk of the infected queen (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"For most intestinal parasites, a negative fecal float rules out infection (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs and cats develop immunity to roundworms and hookworms as they get older. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe \"larval leak\" of hookworms.","a":"Dogs become recurrent shedders because larvae encased in the intestinal wall or deeper tissues migrate into the GI tract and start producing eggs in 2 weeks."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where do trichuris vulpis adults live?","a":"Cecum and colon of dogs/other canids"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The prevalence of whipworms is less than that of hookworms (T/F)","a":"True- 10-15% vs 15-20%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What clinical signs are seen with whipworms?","a":"Mostly: nothing. Sometimes: wt loss, abdominal pain, large bowel diarrhea (+/- blood)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is hardier- ascarid eggs or trichuris eggs?","a":"Trichuris!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long is the prepatent period of whipworms?","a":"Long = 3 months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three tapeworms that are relevant to shelters:","a":"Dipylidium caninum, Taenia taeniaeformis, Echinococcus multilocularis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Tapeworms have a direct life cycle (T/F)","a":"False (usually)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the usual host of Echinococcus multilocularis?","a":"Foxes/rodents. Can infect dogs, may infect cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"All tapeworms can be seen grossly in the feces. (T/F)","a":"False-echinococcus is very small"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which tapeworms are most dangerous to humans?","a":"Echinococcus multilocularis (hydatid cyst disease) and Echinococcus granulosus (unilocular hydatid disease)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What prevents Aelurostrongylus, Crenosoma vulpis, Dracunculus, capillarid nematodes and Physaloptera from being propagated in the shelter?","a":"No contact with intermediate hosts, such as snails, copepods, insects, earthworms."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If a dog is diagnosed with macracanthorhynchus ingens infection, what did they eat?","a":"A millipede that has been hanging around raccoons."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"IDM recommends all dogs and cats be treated with which antiparasitic upon arrival?","a":"Pyrantel pamoate."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Fenbendazole is not approved in cats (T/F)","a":"True- but you can still use it."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should owners be told re: internal parasites upon adoption?","a":"That future diagnostics and treatment are recommended, that animal may still harbor zoonotic parasites."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What two classes of parasites does praziquantel treat?","a":"Cestodes (tapes) and trematodes (schistosomes/bilharzia)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When treating GI disease in the shelter, positive tests correlate with illness (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Brachyspira (Serpulina) are what type of bacteria, and what clinical signs are associated?","a":"Spirochetes, associated with large bowel disease in dogs (also in healthy dogs)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is one supposed to treat brachyspira?","a":"Tylosin or amoxi."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the most common species of campylobacter associated with dz in humans?","a":"jejuni; coli, helveticus and upsaliensis in animals, not usually speciated"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are symptoms associated with Campylobacter?","a":"vomiting, anorexia, large bowel diarrhea (or no symptoms at all)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Campylobacter species are fragile and difficult to grow in culture (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is campylobacter treated?","a":"Tylosin or erythromycin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of bacteria are clostridium?","a":"commensal gram+ spore-forming obligate anaerobes"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are symptoms of C.perf infection?","a":"vomiting, large bowel disease, flatulence, abdominal pain"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe the microscopic appearance of Campylobacter vs C.perf?","a":"Sea-gull vs Safety-pin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is used to treat C.perf?","a":"Metro, amoxi, tylosin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of E. coli is of concern in small animals (and people)","a":"EPEC (enteropathogenic): malabsorption and ETEC (enterocytotoxic): severe HGE/sepsis/death"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is a particular concern in treatment for E.coli?","a":"Resistant strains. First choice - clavamox or cephalosporins"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"E. Coli is zoonotic (T/F)","a":"True- certain strains."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Helicobacter related disease in small animals has been well established. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Helicobacter spp are a zoonotic risk to people.","a":"False (usually)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of bacteria are Salmonella?","a":"non-spore forming gram-neg rods"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What Salmonella species is most commonly associated with dogs and cats which potentially causes illness?","a":"S. enterica typhimurium"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some non-GI symptoms caused by Salmonella?","a":"abortion, stillbirth, neonatal infections"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which animals are most likely to die of Salmonella?","a":"Young, stressed, septic"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Salmonella should be treated with antibiotics when shed in feces (T/F)","a":"False - only bacteremic pts should be treated"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Salmonella carrier animals are a major source of environmental contamination. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Yersinia spp are what type of bacteria?","a":"gram-neg coccobacilli in same family as Salmonella"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which species of Yersinia is the most common zoonosis between dogs/cats/people?","a":"Y. enterocolitica"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which animals are most likely to shed Yersinia?","a":"<6mo"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is a significant sign of Yersiniosis?","a":"Lymphadenopathy. Also diarrhea-weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of antibiotics are used to treat Yersinia?","a":"cephalosporins, TMS, CHLP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What dietary practice increases the risk of E. coli, Salmonella and Yersinia?","a":"Raw meat diets"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"After recovery how long do Yersinia infected pts shed?","a":"Several months."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What clinical signs are seen with B. darlingi, Hammondia, Neospora caninum, and Sarcocystis?","a":"Usually no symptoms"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two forms of Giardia spp?","a":"motile trophozoite and indestructible cyst"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Giardia subtypes (assemblages) are typically species specific.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most animals that harbor Giardia are clinically normal (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three ways Giardia can be diagnosed:","a":"Wet mount trophozoite, fecal float cyst, ELISA, PCR, IFA"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is Giardia treated?","a":"Metro, fenben, febantel"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Giardia vaccination is recommended in outbreaks (T/F)","a":"False- has not shown to have an effect in crowded environments"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"After a course of treatment, patients with Giardia should be retested. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T. foetus can cause diarrhea similar to that caused by giardia.","a":"True- though unknown if all affected animals show clinical signs"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What feature distinguishes Tritrich from Giardia microscopically?","a":"Tritrich trophozoites forward straight line propagation vs \"fallen leaf\" motility in giardia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What drug is recommended to treat Tritrich","a":"Ronidazole"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cryptosporidium are coccidia. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dog and cat crypto is commonly seen in infected humans (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is the smallest coccidian?","a":"Crypto, then Toxo, then isospora"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of diarrhea is associated with cryptosporidium?","a":"Small bowel"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the most sensitive test for crypto?","a":"acid fast stain on fecal smear"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Treatment choices for crypto are clear (T/F)","a":"False- many things tried"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cryptosporidium oocysts are immediately infective when ingested. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Match the isospora sp to infected sp: ohioensis and rivolta","a":"ohioensis = dog, rivolta = cat"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the published prevalence of isospora in shelter dogs?","a":"0.05"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Infections with cystoisospora can be severe in young animals (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"False negatives are common in isospora infections in young animals (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spontaneous cure occurs in animals with cystoisospora. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Routine disinfectants kill Isospora (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Toxoplasma gondii is obligately intracellular. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Toxo is found in dogs, cats, and people. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long must toxo eggs be in the environment before becoming infectious?","a":"1-5 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some non-GI routes of toxo transmission?","a":"transplacental, lactational, blood transfusion"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How does toxo affect cats?","a":"Usually no C/S. But in neonates, intracellular replication of tachyzoites can be stillborn, poor doers, multiple organ disease (liver, lung, panc, CNS)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long does the \"enteroepithelial\" stage of toxo infection last (and what is it?)","a":"<21 days, when oocysts are being shed, only occurs once."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is T. gondii diagnosis made?","a":"Serology plus C/S, exclusion of other disease, positive response to therapy (all things)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How can you kill Toxo and Isospora cysts?","a":"Steam cleaning, boiling water, etc."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What can reduce the risk of Toxo spread into the environment?","a":"Cleaning litter boxes right away, not allowing hunting or raw diets"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is Toxo a problem in shelter?","a":"Zoonotic risk to human fetus/immunocompromised people (not to cats)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats with clinical toxo are usually shedding (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are four diagnostic procedures recommended for every animal with diarrhea?","a":"1. fecal float 2. wet mount 3. rectal cytology 4. acid fast stain"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"10 samples/100 random animals/month should be screened for GI pathogens (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some non-pathogenic r/o for GI disease?","a":"Diet, stress, toxin, FB, neoplasia, metabolic, immunodeficiency, allergy"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What color do Clostridial organisms stain with acid-fast stain?","a":"Pink"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which relevant organisms can be grown on fecal culture?","a":"Salmonella and Campylobacter (also Tritrich in Tritrich culture kit)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is RW a \"life threatening\" disease in the shelter?","a":"Because of the persistent infection and zoonotic potential"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three classes of dermatophyte:","a":"anthropophilic, zoophilic, geophilic"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"M. canis and M. gypseum: match to small animal species:","a":"m. canis = cats, m. gypseum = dog"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What dermatophyte species more commonly affects rodents and hedgehogs?","a":"Trichophyton spp"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where in the US are dogs most affected with RW?","a":"humid southern US (and northern shelters that take their transports)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which factor is the biggest influence on RW infection?","a":"Age"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Overcrowding, whether singly housed, free roaming or group housed, is a major risk factor for dermatophytosis. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What dog breed is predisposed to RW infection?","a":"Yorkshire terrier"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Exposure to spores necessarily results in dermatophytosis infection (T/F)","a":"False- must overcome host protective mechanisms below skin surface"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What causes microtrauma, predisposing to dermatophytosis?","a":"\"Maceration\" of the skin (chewing/scratching) in high humidity, ectoparasites."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Incubation period for dermatophytosis:","a":"2-4 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What precedes development of a lesion in dermatophytosis?","a":"Infection of hair follicle"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Simply quarantining animals to watch for development of lesions is recommended for cats exposed to dermatophytosis. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more closely associated with dermatophytosis recovery: cell-mediated or humoral response to infection?","a":"cell-mediated"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ringworm cats may present to the shelter with a true carrier status. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If a cat is not \"curing\" from ringworm, what should be evaluated?","a":"Treatment choices, medications, and environmental contamination"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Airborne transmission of dermatophyte spores is commonplace in shelters (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dermatophytosis is one of the most pleomorphic skin diseases encountered in animals. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ringworm lesions are not inflammatory (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are two differentials for a classic-looking RW lesion in a dog:","a":"Demodex and bacterial pyoderma"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What process is recommended for preventive management of dermatophytosis:","a":"Systematic screening of incoming cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the five components of RW systematic screening:","a":"hx, visual exam, woods lamp, direct exam of fluorescing hair, and fungal culture"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Littermates or cage mates of dermatophyte infected animals should be treated as:","a":"Infected"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Animals from the same household as dermatophyte infected animals should be treated as:","a":"Highly suspect"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the wavelength of Woods lamp light?","a":"365nm"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What two drugs glow yellow and can be confused with dermatophytosis?","a":"Doxy and terramycin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"KOH must be used for trichograms- mineral oil will not suffice (T/F)","a":"False- mineral oil is ok"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What power should a hair be observed to be able to see spores?","a":"40x"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ringworm cultures grow best at what temperature?","a":"27-30C"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Lab-based ringworm cultures are preferred over in house (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most positive RW cultures show suspect growth by what day?","a":"Day 10"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If a suspect colony is seen on a DTM plate, what should be done?","a":"Microscopy"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"M gypseum produces hyphae more readily and rapidly than M canis. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Trichophyton species rarely have accompanying microconidia (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Response plans to RW positive animals should be created when?","a":"Before confirmation of fungal culture results"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the first step in infection response for cats with ringworm?","a":"Identification of infected animals as infected"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What treatment protocol do the authors recommend?","a":"Itraconazole for 21 days and 2x weekly lime sulfur dips"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Although lime sulfur is a \"dip,\" how should it be applied?","a":"Topically to a cat's fur. Spray bottle or portable garden rose sprayer"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In order for lime sulfur to be effective, how should it be applied?","a":"Soak the cat to the skin."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rinsing and pre-wetting lime sulfur are recommended (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Clipping hair is recommended for cats with dermatophytosis. (T/F)","a":"True for long-haired cats. False for medium/short-haired cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What dose of itra is recommended for RW?","a":"5-10mg/kg SID"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should be checked if a cat on itra becomes anorexic?","a":"Liver values"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Griseofulvin is not recommended in shelter cats (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Some strains of M. canis are resistant to ketoconazole. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Controlled studies consistently show that lufenuron is ineffective as treatment and preventive for RW. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Mycological cure is defined how in the literature?","a":"3 negative cultures"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the key to minimizing contamination and effectively decontaminating the environment of RW spores?","a":"daily mechanical removal of infective material, and application of an effective disinfectant"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is one sneaky way to disinfect a RW-contaminated cat tree?","a":"Treat it with lime sulfur and subject it to hot sunlight"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of housing is critical when seeking to treat which dermatophytosis?","a":"Low-stress, humane, enriched"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When a RW outbreak is suspected, what should be done?","a":"All potentially exposed animals should be screened and cultured"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should be done with RW cats in an outbreak while awaiting culture results?","a":"Discontinue movement of exposed animals"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Animals infected with RW should not be adopted untiL","a":"mycological cure has been verified"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In healthy, stress-free cats with RW, what usually happens?","a":"Clear on their own"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"No parasiticidal agent is 100% effective (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three organisms that can be found on flea-comb.","a":"Fleas, lice, ticks, cheyletiella, fur mites"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"More parasites are zoonotic than are not zoonotic in the table of commonly encountered ectoparasites in the shelter (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is lynxacarus radovsky?","a":"The cat fur mite"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is dermanyssus gallinae","a":"The poultry mite, also affects dogs and cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is trichodectes canis?","a":"Dog lice"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is felicola subrostratus","a":"Cat lice"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of organism is otobius megnini","a":"Soft tick- warm blooded animals esp ears"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is caused by Pelodera infestations?","a":"Erythema, papules, and hair loss on pressure points due to nematode migration through the skin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more effective in finding parasites, scotch tape prep or flea comb?","a":"Per Moriello, flea comb"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name four species seen on skin scraping:","a":"Cheyletiella, Notoedres, Sarcoptes, Demodicosis, Pelodera."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Blades should be used for skin scraping (T/F)","a":"False! Use skin scraping spatulas instead!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three parasite species that can be found on trichogram:","a":"Demodes, cheyletiella egg cases, louse egg cases"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Microsporum canis macroconidia can be seen on skin scraping (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Response to treatment trials may be the best approach to diagnosis and treatment for some conditions (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the hallmark sign of hookworm dermatitis?","a":"Pedal pruritus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should be investigated if pelodera strongyloides dermatitis is identified?","a":"Bedding- straw marsh hay, rice hulls, dirt is common"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Pelodera dermatitis is highly infectious to other animals (T/F)","a":"False- though many animals may be sleeping on contaminated bedding."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long do ticks feed for before disengaging from host?","a":"3-5 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Acute otitis externa is occasionally caused by otobius megnini. (T/F)","a":"True- the tick can pack the ear canal, blood loss, severe otitis."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Tick bite paralysis is most commonly associated with:","a":"Dermacentor variabilis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Professional extermination may be needed to rid an infested building of Rhipicephalus ticks. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why should tick presence be documented in the medical file?","a":"To help explain future disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Itchiness and contact with poultry should raise suspicions of what parasite?","a":"Dermanyssus gallinae"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Chiggers can cause disease in dogs and cats (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are symptoms of Walchia americana or Eutrombicula in dogs and cats?","a":"Severe papular eruption- chiggers- associated with leaf litter and rodent bedding."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Describe a cheyletiella egg?","a":"Oblong, thick-walled, oval \"nucleus\" taking up 75% of area"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should an adopter be told when adopting an animal with a documented fur mite infection?","a":"Follow-up treatment will be needed since eradication requires more than one application."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the rabbit ear mite called?","a":"Psoroptes cuniculi"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ear mite pruritus is easy to diagnose because ear mites are often seen concurrently (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"One mite or mite egg is diagnostic for Otodectes infection. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three classic presentations of demodicosis in dogs?","a":"Localized, generalized, and adult-onset"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How often do localized demodex cases resolve without treatment?","a":"90% of the time"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Demodicosis in dogs is highly contagious (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Demodicosis in cats is highly contagious (T/F)","a":"True with gatoi. False with cati"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why are demodex mites harder to find in cats?","a":"Cats groom. Look in the poop."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Sarcoptes has a dorsal presentation in dogs (T/F)","a":"False- ventral"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why do low mite burdens cause such severe symptoms in dogs with Scabies?","a":"Hypersensitivity to the mites is common"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What disease is also known as \"feline scabies?\"","a":"Notoedres cati"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Notoedres are difficult to find in cats with infestations. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are two sequelae of flea bites in animals?","a":"Hypersensitivity, anemia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Flea bite hypersensitivity is easy to diagnoses because fleas are often found on the animal. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Seasonal flea control is recommended for shelter animals depending on geographic location (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the proper dose of capstar (nitenpyram)","a":"1mg/kg"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Fleas are a zoonotic parasite, and many people have flea bite hypersensitivity. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How many species of louse are specific to dogs?","a":"Two- one biting, one sucking"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What home remedy can release nits from hairs?","a":"Vinegar rinse (1:3 with water)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What part of the cat is most affected with fly bite dermatitis?","a":"Dorsal nose"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How does one prevent fly strike in cats?","a":"House them indoors"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What two drugs can be used to kill fly larvae?","a":"Nitenpyram and Ivermectin daily until no new maggots seen"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Eosinophilic inflammation in an animal with facial folliculitis/furunculosis on the nose might represent:","a":"Bee, wasp, ant, or caterpillar sting site"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of drug is Amitraz and who should be wary of handling it?","a":"MOAI - not be handled with people taking MAOIs, pregnant, or diabetic"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Spinosad and ivermectin can be used together (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Removal of thick debris from the ear can be facilitated by?","a":"Applying mineral oil for 10-15 min before attempting"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long do ear mites live? (also, cheyletiella, fur mites, notoedres)","a":"3 weeks. Therefore, tx needs to be up to 4 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Tresaderm is good for ear mites in cats (T/F)","a":"False- but can get secondary infections"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is Rabies?","a":"enveloped RNA virus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is rabies in rodents so rare?","a":"The bite that transmits rabies is usually sufficient to kill the rodent"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of rabies is found in the southeastern and eastern US?","a":"Raccoon"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of rabies is present in central US?","a":"Skunk"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of rabies is present on Canadian and Mexican borders?","a":"Coyote/Fox"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats make up how many animal cases of rabies each year?","a":"0.04"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rarely, rabies can be transmitted through ingestion (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name 2 nosocomial transmission routes for rabies:","a":"Pathology- aerosol of neural tissue, and transplantation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the incubation period for rabies?","a":"3-8 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is associated with faster incubation periods for rabies?","a":"Bites closer to the head"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the basis for the 10 day rabies quarantine hold?","a":"Animals will show C/S and or die within 10 days of shedding rabies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ferrets are also now approved to have 10-day rabies holds (after biting someone). (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In utero rabies infections have been documented in some wild animals (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the two \"forms\" of rabies?","a":"Furious and Dumb"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hydrophobia is not seen in animals with rabies (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are ddx for neurological foxes besides rabies?","a":"Canine hepatitis and canine distemper"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"There is no reliable antemortem rabies test at this time (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Removing stray dogs and cats helps prevent rabies in the community (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is a good resource of info for on rabies in specific areas?","a":"State public health dept"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where is the Compendium of Animal Rabies Prevention and Control published and how often?","a":"JAVMA, yearly"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rabies laws in each state are usually similar. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Local laws can be more lenient than state laws re: rabies (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"45 day quarantine for rabies applies to whom?","a":"Bites to vaccinated dogs and cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Hybrid wolf or coydogs can be safely vaccinated for rabies. (T/F)","a":"Probably true but not enough research to prove that it is preventive/protective."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Shelters are responsible for enforcement of local rabies laws. (T/F)","a":"False- though animal control may be. Usually it's public health depts."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is rabies virus inactivated?","a":"sunlight, desiccation, any disinfectant"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rabies vaccines are recommended on intake at shelters (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"3 year vaccines may be given to an animal that will require a booster in 1 year.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"1 year vaccines may be given to an animal that will require a booster in 3 years.","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why should you consider giving cats recombinant rabies vax?","a":"Vaccine associated sarcomas"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what point after immunization are animals considered protected from rabies?","a":"1 month"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"At what point after booster vaccine are animals considered to be protected from rabies?","a":"2-3 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rabies baits are harmful to domestic animals (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How often should pre-exp rabies titer be checked?","a":"2 years"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is an acceptable rabies titer in the US:","a":"1:5"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the most reliable method for preventing the passage of FeLV or FIV?","a":"Identification and segregation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of viruses are FeLV and FIV?","a":"Oncornavirus and lentivirus (Retroviridae)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Do non-domestic cats get FIV?","a":"Yes- each have their own variant (speciated)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the prevalence of FeLV and FIV in the US?","a":"<2% of healthy cats. 6-30% of ill cats."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name some risk factors for feline retroviruses:","a":"Male, adult, outdoor lifestyle"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name some \"protection\" factors for feline retroviruses:","a":"Female, indoor lifestyle, sterilization"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which group of cats has the highest prevalence of feline retroviruses?","a":"Sick feral cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more likely to affect long-term survival in cats: FeLV or FIV?","a":"FeLV"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Susceptibility to FeLV infection may be age dependent (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV is more contagious to friendly cats; FIV is more contagious to unfriendly cats: explain.","a":"FeLV often passed through nursing, grooming, sharing dishes; FIV most commonly spread through bite wounds"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define \"progressive\" infection in FeLV:","a":"inadequate FeLV specific immunity is associated with persistent antigenemia, viremia, and development of disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Define \"regressive\" infection in FeLV:","a":"effective immune response contains virus replication before bone marrow infection, resulting in no progression to clinical disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long before PCR can detect FeLV infection in exposed cats?","a":"provirus positive 1 week; antigen positive in 3 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV and FIV both represent life-long infections. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How soon are infected cats shedding FeLV or FIV?","a":"1 week after infection"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why don't kittens catch FIV from nursing on infected mothers?","a":"Antibodies bind to FIV antigen, neutralizing them before infection is possible."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which is more reliable- whole blood, serum or plasma in FeLV diagnosis?","a":"serum or plasma"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long before animals can test positive on ELISA after initial infection?","a":"28 days. Hence recommendation to retest in 1 month."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How can positive ELISA FeLV results be confirmed?","a":"repeating antigen test from different mfctr, IFA test on blood or bone marrow, or repeat Antigen test in 28 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What does discordant mean in FeLV diagnosis?","a":"2 tests have results which disagree"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of FeLV testing schedule is recommended for discordant cats?","a":"Retest 60 days, then yearly thereafter."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"\"Discordant\" cats can be sources of FeLV infection to other cats.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"PCR testing of what bodily fluid has high correlation with blood antigen tests?","a":"Saliva"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why don't we have FIV antigen tests?","a":"Not enough circulating antigen to detect."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What viral antigens to FeLV tests and FIV tests target?","a":"p27 and p24 (L=7)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of follow-up testing should be used for FIV?","a":"Western blot"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If recently exposed to an FIV positive cat, when should the contact cat be tested?","a":"60 days."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should FIV antibodies be interpreted in cats <6 months old?","a":"Born to infected queens = MDAs. These fade."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why should cats be retested for FeLV/FIV 60 days after shelter entry?","a":"With unknown hx, may take that long to become positive"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the ideal scenario for group housing cats in light of FeLV/FIV infections?","a":"Quarantine for 2 months and retest then add"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the recommended interval of retroviral testing for group-housed cats?","a":"every year"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"If resources are scarce, retroviral testing only one or a few animals out of a litter is better than nothing. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Foster families and adopters should have their own resident cats tested for FeLV/FIV prior to fostering or adopting a new cat. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Retroviral testing is routinely performed in TNR clinics. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV vaccinated cats won't need to be tested for FeLV again. (T/F)","a":"False- vaccination doesn't induce immunity in all cats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the ideal course for FeLV vaccination?","a":"1 vax at 8 weeks then second dose 3-4 weeks later. Then yearly."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV vaccination reliably protects against both progressive and regressive infections. (T/F)","a":"False - progressive yes, regressive maybe not"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the ideal course for FIV vaccination?","a":"In cat who is high risk, will need 3 doses 2-3 weeks apart, annual revaccination (and chip!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV vaccination is recommended in shelters that group house cats.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV vaccination is recommended for TNR groups.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV/FIV cats in shelters should be kept isolated or euthanized (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeLV/FIV cats should be confined indoors (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Raw meat diets are recommended for FeLV/FIV cats, due to their propensity for stomatitis. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Inactivated core vaxes are recommended for FIV/FeLV cats. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name 2 risk factors for FIP:","a":"Multi-cat environment, young adult cat"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FIP is an emerging disease. (T/F)","a":"Trueish= first described in 1950-1960"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of virus is Coronavirus?","a":"RNA +ss = rapid mutation"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most cats with FeCoV show clinical signs (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"There is a wide range of prevalence of FeCoV antibody positive cats in different populations. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FIP is common in the weaning/neonatal period. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What age group is the least likely to get FIP?","a":"3-9 year old"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Older cats are more at risk for FIP than neonatal kittens. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In coronavirus endemic households, what is the risk of FIP?","a":"5-10%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Over what FIV prevalence is a cause for concern in shelters?","a":"0.01"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FeCoV is extremely easy to transmit (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long are cats positive for/shedding coronavirus?","a":"few weeks-several months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Cats are immune to FeCoV reinfection after they are done shedding.","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What specific genes need to mutate for FeCoV to become FIP?","a":"3c, 7b, and spike reading frames"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What cell do coronaviruses infect during FIP?","a":"Macrophages"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of disease if FIP?","a":"Type 3 hypersensitivity reaction (immune complexes deposited in blood vessel linings/other tissues->vasculitis, complement activation, DIC, vessel necrosis)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the incubation period for FIP after FeCoV infection?","a":"2 weeks to 2 years"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name some factors that could increase FIP likelihood in a population of cats:","a":"1. genetic susceptibility (related cats) 2. increased infective dose (exposure) 3. increased tendency of strain to mutate (pathogen)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Theoretically, wet FIP cats have a better immune system than dry FIP cats (T/F)","a":"False- dry>wet (maybe)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Kidney failure in a young cat should raise suspicions of:","a":"FIP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ocular changes (retina and anterior chamber lesions) are common in FIP:","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What percentage of FIP cats have neuro lesions?","a":"13%- 50% of inflammatory brain disease in young cats is FIP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What factors is a diagnosis of FIP based on?","a":"clinical observations, hx of animal, PE, lab findings."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Direct visualization of antigen by biopsy or necropsy is the only confirmatory diagnostic test of FIP. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the Rivalta test?","a":"Test-tube with diluted white vinegar: add drop of effusion on surface of acid. If disappears- negative. If \"jellyfish blob\"= positive"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Why is IFA better than FeCoV titers for diagnosing effusion?","a":"One can see replicating FeCoViruses in macrophages with IFA- need to prove replication. (But negative pred value is only 57%)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What serum chemistry change to most FIP cats have?","a":"Elevated TP caused by increased globulins. AG ratio <0.8 is highly predictive"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What can FIP ELISAs help you determine?","a":"Whether a cat \"does not\" have FIP if FeCoV titer negative (90%)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"alpha1-acid glycoprotein is useful in determining FIP diagnosis","a":"not really"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"A single obstructive granulomatous intestinal mass may be a sign of:","a":"FIP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Fibrinous adhesions between liver and diaphragm and loops of bowel and omentum may be a sign of:","a":"FIP"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"the RT-PCR for FeCoV is useful in diagnosing FIP","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"FIP is considered to be 100% fatal","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What recommendations should you give to a shelter with an FIP outbreak?","a":"Sanitation, decrease overcrowding, decrease stress,clean litter boxes, fomite control, test and quarantine high shedders, adoption!!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Each piece of litter can carry millions of coronaviral particles (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vaccination with the IN FeCoV vaccine helps prevent FIP in endemic shelters. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"WNV is an emerging zoonotic disease that can affect dogs and cats. (T/F)","a":"False- can become viremic but no C/S or disease"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is WNV diagnosed in dogs?","a":"Paired titers"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Babesia has two species of concern. They are:","a":"gibsoni and canis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the vector for babesia?","a":"Rhipicephalus sanguineus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Symptoms of babesia in dogs include:","a":"weak, depressed dogs with splenomegaly, IMHA, bilirubinemia, DIC, glomerulonephritis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Treatment for babesia in dogs is:","a":"Doxycycline, imidocarb, clinda, pred."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Babesia has extra significance in shelters because:","a":"Overrepresented in fighting pit bull dogs- may be a predictor of organized cruelty"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Leishmania in dogs has been most commonly seen in which breed?","a":"Foxhounds"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is leishmania transmitted?","a":"Sand flies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three forms of leishmania?","a":"Cutaneous (nodules/ulcers), Visceral (anemia, fever, organomegaly), Cutaneous visceral (combo of other two, most common)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Treatment for leishmania is simple and complete cure is swift. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs with leishmania should be euthanized. (T/F)","a":"Maybe not- dog-human transmission is not common (need vector?)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Anaplasma phagocytophilum vector is:","a":"Ixodes ticks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Anaplasma causes:","a":"Fever, anorexia, lethargy, muscle/joint pain, headache, leukopenia, anemia, polyarthritis."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the \"natural course\" of anaplasma phago dz:","a":"Resolves in about a week. Faster with doxy tx."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What disease does anaplasma platys cause?","a":"Infects platelets- causes profound thrombocytopenia. May be subclinical. Maybe chronic."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Ehrlichia is more common than anaplasma and babesia. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What cell type does Ehrlichia canis attack?","a":"Monocyte"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Signs of Anaplasma phago and Ehrlichia are similar. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the \"third stage\" of canine ehrlichiosis?","a":"Bone marrow suppression and pancytopenia. GSD are predisposed."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What cell type does Bartonella attack?","a":"RBC"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some risk factors for bartonella henselae?","a":"Young cat, flea infestation, South"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Bartonella species in the dog include B. henselae and B. vinsonii berkhoff. (T/F)","a":"False- B. henselae in cats."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the justification for treating B. henselae in cats?","a":"Prevent human infection (tho flea control may do this better)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In dogs, bartonella can cause heart disease. (T/F)","a":"True- endocarditis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Borreliosis is most commonly clinically silent (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Vectors for Borrelia are:","a":"Ixodes ticks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Chronic nephritis or arthritis should lead one to suspect:","a":"Borrelia burgdorferi"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What antibiotics should be used for Lyme and how long?","a":"Doxy, Amoxi, Azithro, 30 days"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is prefered over vaccinating all shelter dogs with Lyme vac in endemic areas?","a":"Conscientious tick control"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the disease caused by coxiella burnetii?","a":"Q fever"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is C. burnetii spread:","a":"Tick bite, exposure to spores, infectious fluids, abortions"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Q fever in dogs and cats is common and straightforward to diagnose. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"C. burnetii is easy to disinfect (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Francisella tularensis is more common in cats than dogs (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do cats usually get tularemia?","a":"Eating infected prey sp."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do dogs usually get tularemia?","a":"Ticks, biting flies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How do you treat tularemia in animals?","a":"Unknown"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"F. tularensis is considered a bioterror weapon. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"RMSF is caused by:","a":"Rickettsia rickettsii"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the vector for Rickettsia?","a":"Dermacentor and rhipicephalus ticks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the area most affected by RMSF?","a":"American southeast, not west of Rockies."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the primary disease caused by Rickettsia?","a":"Severe vasculitis->skin, brain, heart, kidney lesions, shock, CNS collapse."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is Rickettsia diagnosed in dogs?","a":"Antibody testing, IHC on biopsy, PCR"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What two drugs are used to treat RMSF?","a":"Abx (tetracycline, enro, chlp) and steroids"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Who is the reservoir for Rickettsia felis?","a":"Opossums"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Who is the vector for Rickettsia felis?","a":"Fleas"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Yersinia pestis is also known as:","a":"Plague"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs are more likely to be infected with Y. pestis than cats. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the three forms of Y. pestis?","a":"Bubonic, septicemic, pneumonic."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"In cats, what is the most common clinical sign of Y. pestis?","a":"Lymphadenopathy with respiratory disease."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some important r/o for cats respiratory disease with sign. lymphadenopathy?","a":"plague, tularemia, mycobacteria: all zoonotic!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Euthanasia is recommended for cats suspected of having plague and tularemia. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"After what point are Y. pestis cats considered non-infective?","a":"48 hours after therapy"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are the treatments of choice for Y. pestis?","a":"Gentamicin or enrofloxacin (injectable!)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Heartworm disease is caused by:","a":"dirofilaria immitis"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the reservoir for HW infection?","a":"Dogs and canids (coyotes, foxes, wolves, wild felids, ferrets, etc)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What species of mosquito transmits HW?","a":"Almost all- 70 sp."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When should prophylaxis for HW start in puppies?","a":"8 weeks, since can have immature adults in pulmonary vasculature by 12 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What causes worse symptoms of HW- a larger worm burden or a more active dog?","a":"More active dog"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most of the pathology seen in clinical HW disease is caused by:","a":"effects of dying worms"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of heart disease is seen with HW dogs?","a":"Lung fibrosis, increased pulmonary vascular resistance, leading to right-sided heart failure"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What type of disease is more commonly seen in HW catts?","a":"Asthma/allergic bronchitis from dying worms."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which can detect infections with fewer worms better- well tests or PoC tests?","a":"Well tests"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Negative microfilaria test rules out HW if paired with a positive antigen test (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What does a Knott's test test for?","a":"Microfilaria in HW- mix blood with formalin, spin down, pour off, add meth blue, look on slide"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Diagnostic screening for HW in cats is widely accepted. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"HW drugs are safe in dogs that carry the ABCB1 (formerly MDR1) gene (T/F).","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the concern with administering 50ug/kg of ivermectin to HW+ dogs?","a":"lead to anaphylaxis to dying microfilariae"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Melarsomine is not effective against worms <4 months old (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What can be done to help reduce lung pathology in HW dogs?","a":"Tx with doxycycline"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What percentage of worms are eliminated with a 2-dose protocol vs 3-dose protocol for HW?","a":"90% vs 98%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What period should exercise restriction be strictly enforced in HW dogs?","a":"6-8 weeks."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long does it take for a previously HW infected dog to become antigen negative?","a":"4-5 months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When should elective surgery be performed in HW dogs?","a":"Before starting tx"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the expected percentage of cats with HW to die suddenly?","a":"10-20%"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the reverse of zoonosis?","a":"Anthroponosis (or reverse zoonosis)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Shelter cats have proportionally more zoonotic disease than owned cats.","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What should the decision to release an animal with a zoonotic dz to the public be based on?","a":"Risk of transmission, risk of disease developing, and risk of fatality to people"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"The ultimate responsibility for determining medical suitability for adoption should rest with:","a":"The veterinarian and the adopter"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are five basic recommendations for preventing zoonoses in the shelter:","a":"1. hand hygiene, 2. PPE, including gloves, shoe covers, etc 3. facial protection for procedures/cleaning 4. protective clothing (smocks, etc), 5. do not reuse disposable or contaminated items"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the single most effective disease prevention method in the shelter?","a":"Hand hygiene"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Moisturizers can enhance the integrity of the skin and reduce ulceration. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Rings should be removed before washing hands (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How many seconds should hands be scrubbed for?","a":"15 sec"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Immunocompromised individuals should avoid adopting pets that are:","a":"<6 months old, have diarrhea, have ectoparasites, have long unclipped nails"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three pathogens spread through animal bites:","a":"Pasteurella multocida (cat bites, licking wounds), Capnocytophaga (dogs), Rabies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Capnocytophaga can cause what symptoms in asplenic people:","a":"shock, disseminated purpura, IVC, renal failure, gangrene, pulmonary infiltrates"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are some considerations used by the health department when considering initiation of postexposure rabies tx?","a":"Species of exposure, appearance/behavior of animal, location/severity of bite, whether animal is available for testing, lab test results for animal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What first aid can be given to bite wounds to help prevent infection?","a":"Irrigation with saline 20ml syringe and 18ga needle"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three pathogens spread through animal scratches:","a":"Sporotrichosis (male cats- ulcerative nodule), Bartonella (cutaneous papule, regional lymphadenopathy), Dermatophytosis (req. break in skin)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What are three diseases that can be spread to people through close contact:","a":"Dermatophytosis, Malassezia (seborrheic/inflammatory skin dz) and Scabies"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is sporotrichosis?","a":"Dimorphic fungus- mostly seen in outdoor male cats, draining puncture wounds, abscesses, crusted lesions. Spread through contact."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What drugs treat sporotrichosis?","a":"Potassium iodide in dogs, itraconazole in cats, sometimes for >1 year. Zoonotic!"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Whether giardia is zoonotic or not is controversial. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How should toxoplasmosis risk be handled by pregnant women?","a":"Ask someone else to clean box, good litter box hygiene."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is more risky to pregnant women- cats with toxo titers or cats without toxo titers?","a":"Without- potential for infection."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How are giardia cysts inactivated?","a":"Bleach or quats"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Human crypto is reportable to the DoH in most states (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What stage of the tapeworm causes hydatid disease?","a":"Larva"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What intermediate host does Echinococcus granulosus go through before infecting dogs?","a":"Sheep"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which parasite is responsible for most VLM?","a":"Toxocara spp."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Toxocara eggs can be found in the stool of affected humans. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dog campylobacter doesn't affect humans much (T/F)","a":"False- equally zoonotic"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Handling \"raw\" food or the feces of dogs eating \"raw food\" diets is a risk factor for Salmonellosis. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What PPE should be worn when cleaning feces to avoid fecal-oral contamination?","a":"Gloves and face mask"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What zoonotic diseases can be acquired via contact with urine or genital secretions?","a":"Brucellosis (canine), Leptospirosis, Q fever"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How is Brucellosis passed from dog to dog?","a":"Oronasal or conjunctival  contact with milk, vaginal discharge, abortia, urine or lochia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long do brucellosis dogs shed after abortion/parturition?","a":"6 weeks"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Severe illness is common in dogs with brucellosis. (T/F)","a":"0"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"When do brucella dogs abort?","a":"2 weeks before parturition"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the treatment for canine brucellosis?","a":"Spay/neuter- no real treatment possible."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"What is the recommendation for adoption of dogs with brucellosis?","a":"Need 6 months of seronegativity and negative cultures. Full disclosure, no immune compromised adopters."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How many serovars of Lepto are there in the world?","a":">200"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Leptospira causes disease in maintenance hosts or accidental hosts?","a":"accidental"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Leptospirosis can be contracted venereal. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How long do animals with lepto shed after infection?","a":"Months"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Most dogs with lepto present with what type of disease?","a":"Renal"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Dogs can develop a carrier state with leptospirosis and continue to shed. (T/F)","a":"1"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three airborne zoonoses:","a":"Bordetella, Coxiella (Q fever), Plague, Tularemia"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three vector-borne diseases:","a":"Plague, Tularemia, RMSF"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"How are most tularemia cases from domestic animals to humans acquired?","a":"cat scratches and bites"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name three anthroponoses possible in the shelter:","a":"C-diff, MRSA Mycobacterium, Streptococcus"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"To avoid MRSA in people, what drugs should not be used on pets?","a":"vancomycin and teicoplanin"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Which are more susceptible to Human TB- dogs or cats?","a":"Dogs and canids (coyotes, foxes, wolves, wild felids, ferrets, etc)"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Where does mycobacterium TB infect cats?","a":"Intestine"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Group A Strep causes what in humans and occasionally in domestic animals?","a":"Tonsillitis \"Strep throat\""},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Name 4 zoonoses considered \"not adoptable\"","a":"Coxiella, Plague, Rabies, and Tularemia"},{"type":"card","domain":"General","sub":"General","q":"The collective confinement of a highly transient population of animals in various states of health contribute to the potential for ________.","a":"Infectious disease outbreaks"},{"type":"card","domain":"General","sub":"General","q":"How is outbreak defined?","a":"Greater occurrence of cases of disease than normally expected and/or increase in severity or duration of signs"},{"type":"card","domain":"General","sub":"General","q":"Name two pathogens that can cause outbreaks with high morbidity, mortality, swift and devastating consequences:","a":"Strep zoo and VS-FCV"},{"type":"card","domain":"General","sub":"General","q":"What are needed to address prevention, detection, investigation, and response to increases in duration/severity of infectious disease?","a":"Outbreak management plans"},{"type":"card","domain":"General","sub":"General","q":"How should outbreak management plans be communicated?","a":"Written down and available to all staff"},{"type":"card","domain":"General","sub":"General","q":"What is a part of an outbreak management plan that addresses reporters calling for comments?","a":"A media communication plan that specifies a spokesperson."},{"type":"card","domain":"General","sub":"General","q":"One-size-fits-all outbreak plans are fine. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Shelters should have outbreak plans for all the common infectious diseases. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the 2 primary goals of an outbreak intervention?","a":"Disruption of disease transmission and diagnosis"},{"type":"card","domain":"General","sub":"General","q":"What two intervention points do infection control strategies in outbreak management rely on?","a":"Strengthening individual resistance (host) and minimizing exposure to pathogens (environment)"},{"type":"card","domain":"General","sub":"General","q":"It is recommended that a staff member walk through the population ______ for the primary purpose of disease surveillance.","a":"at least once a day"},{"type":"card","domain":"General","sub":"General","q":"Recognition of what may give a shelter a head's up about a looming outbreak scenario?","a":"increased infectious disease burden in the community, or recognition of a high-risk source of animals"},{"type":"card","domain":"General","sub":"General","q":"What is the most insidious risk factor for shelter disease outbreaks?","a":"Overcrowding"},{"type":"card","domain":"General","sub":"General","q":"__________ and quick implementation of a plan can reduce the duration and severity of an outbreak.","a":"Early identification"},{"type":"card","domain":"General","sub":"General","q":"Properly conducted outbreak investigations can also provide conclusions that assist in ______.","a":"Prevention of future outbreaks."},{"type":"card","domain":"General","sub":"General","q":"What two scholarly methods are used during outbreak investigations?","a":"Clinical and epidemiological"},{"type":"card","domain":"General","sub":"General","q":"The first case to be recognized in an outbreak is likely to be the first case that occurred (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What should be developed on the basis of clinical signs/diagnostic tests to help identify animals involved in an outbreak?","a":"Case definition"},{"type":"card","domain":"General","sub":"General","q":"What is the foundation of outbreak investigation, and should include time, location, and description of animal involved?","a":"Systematic data collection and analysis"},{"type":"card","domain":"General","sub":"General","q":"How do you evaluate the effectiveness of outbreak intervention strategies?","a":"Continual monitoring"},{"type":"card","domain":"General","sub":"General","q":"________ is the study of the distribution and determinants of health-related events in a  population.","a":"Epidemiology"},{"type":"card","domain":"General","sub":"General","q":"Most disease occurs randomly (T/F)","a":"False- related to complex interactions of environmental and host factors."},{"type":"card","domain":"General","sub":"General","q":"How does descriptive epidemiology organize data?","a":"Animal, place, time, in effort to answer who, what, where, when questions."},{"type":"card","domain":"General","sub":"General","q":"How does analytical epidemiology organize data?","a":"Compares animal subgroups on basis of outcomes and risk factors to answer why and how."},{"type":"card","domain":"General","sub":"General","q":"What is the formula for a disease attack rate?","a":"ill/total (%)"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate a risk based on an attack rate?","a":"Take the difference of AR% - AR% for all risk categories."},{"type":"card","domain":"General","sub":"General","q":"Attack rate comparisons represent a causal relationship (T/F)","a":"Not necessarily true"},{"type":"card","domain":"General","sub":"General","q":"An epi curve tracks the time interval on the x axis and the ________ on the y axis.","a":"number of new cases"},{"type":"card","domain":"General","sub":"General","q":"What are 3 types of epi curve patterns?","a":"point source, continuous, and propagated"},{"type":"card","domain":"General","sub":"General","q":"________ pattern of epi curve is observed when a cluster of cases occurs following exposure to a single common source for a brief period of time.","a":"Point source"},{"type":"card","domain":"General","sub":"General","q":"________ pattern of epi curve results from exposure to a common source present for an extended period of time.","a":"Continuous pattern"},{"type":"card","domain":"General","sub":"General","q":"________ pattern of epi curve is more commonly seen in contagious disease outbreaks; new cases result from exposure to one or more animals actively shedding the pathogen.","a":"Propagated pattern"},{"type":"card","domain":"General","sub":"General","q":"An outbreak is considered to be over when ________ have passed with no new associated cases.","a":"two incubation periods"},{"type":"card","domain":"General","sub":"General","q":"In addition to mapping absolute frequency patterns, epi curves can be used to compare ______.","a":"Subpopulations"},{"type":"card","domain":"General","sub":"General","q":"In outbreaks of zoonotic disease, ________ must be put into place to protect people as well as animals from infection.","a":"Control Measures"},{"type":"card","domain":"General","sub":"General","q":"Enhanced disease surveillance, separating infected and exposed animals, and risk/exposure assessment are all examples of:","a":"Outbreak control measures"},{"type":"card","domain":"General","sub":"General","q":"Define isolation:","a":"physical separation of infected animals from the rest of the population"},{"type":"card","domain":"General","sub":"General","q":"Define quarantine:","a":"physical separation of exposed animals from the rest of the population (and from the ill animals)"},{"type":"card","domain":"General","sub":"General","q":"when treatment, isolation or quarantine cannot be provided in the shelter system, ______ should be considered as a last resort to alleviate suffering and protect health and welfare of shelter population.","a":"Euthanasia"},{"type":"card","domain":"General","sub":"General","q":"Anyone receiving sick or quarantined animals from a shelter should be _____, and have a clear understanding of who is responsible for care costs.","a":"fully informed of the risks"},{"type":"card","domain":"General","sub":"General","q":"When a diagnosis has not been determined, it is best to assume that ____________ are affected and treat them accordingly, regardless to apparent extent of disease.","a":"all animals with similar clinical signs"},{"type":"card","domain":"General","sub":"General","q":"Animals that are quarantined should not be returned to the population until __________.","a":"The maximum incubation period of the disease has passed."},{"type":"card","domain":"General","sub":"General","q":"Define infectivity:","a":"The dose of pathogen required to get an animal sick"},{"type":"card","domain":"General","sub":"General","q":"Cats don't need to be quarantined if exposed to CDV, and dogs don't need to be quarantined if exposed to FPV (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Cats should be quarantined if exposed to CPV (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"For diseases like CIV, quarantine should be considered even if dogs are properly vaccinated (T/F","a":"True- vaccine is only partially protective"},{"type":"card","domain":"General","sub":"General","q":"What are 2 ways to protect at-risk people in zoonotic disease outbreaks?","a":"Limit staff access to infected animals, wear PPE and have good hand hygiene."},{"type":"card","domain":"General","sub":"General","q":"For incoming susceptible animals in an outbreak, shelters must provide a suitable uncontaminated environment, or __________","a":"temporarily refuse entry."},{"type":"card","domain":"General","sub":"General","q":"When should adoption services be shut down in an outbreak?","a":"When disease transmission to public pets (or people) cannot be prevented."},{"type":"card","domain":"General","sub":"General","q":"Shelters should continue transports as usual while they are managing an outbreak. (T/F)","a":"FALSE - extra assessment to make sure they aren't susceptible before transport."},{"type":"card","domain":"General","sub":"General","q":"What are three reasons for full shelter quarantine (no in, no out) in the past?","a":"CDV or Ringworm outbreaks, or multiple concurrent disease outbreaks"},{"type":"card","domain":"General","sub":"General","q":"Shelters considering widespread depopulation or euthanasia should __________.","a":"Consult with a shelter medicine expert for help."},{"type":"card","domain":"General","sub":"General","q":"How do you attract media attention in an outbreak?","a":"Adopt out large numbers of ill animals"},{"type":"card","domain":"General","sub":"General","q":"When should the health department be notified in an outbreak scenario?","a":"When the disease is reportable (state laws) or rabies"},{"type":"card","domain":"General","sub":"General","q":"What approach is recommended re: the media in an outbreak?","a":"Proactive"},{"type":"card","domain":"General","sub":"General","q":"___________ has increased the risks of rare animal diseases in recent years, with shelters artificially expanding the borders of their source population.","a":"Long distance animal movement/transfers"},{"type":"card","domain":"General","sub":"General","q":"Shelter animals can be an important ________ for local disease trends.","a":"sentinel"},{"type":"card","domain":"General","sub":"General","q":"Typically, _______ incidents with poor outcomes, law suits, or large numbers of exposures are documented; shelters have an obligation to protect public health and safety.","a":"zoonotic disease outbreak"},{"type":"card","domain":"General","sub":"General","q":"_________ can lead to poor relations with the community, higher potential for transfer to people if zoonotic, and an increased risk of disease in community animals.","a":"Failure to manage infectious diseases in shelters"},{"type":"card","domain":"General","sub":"General","q":"What help ensure more rapid and consistent responses to emergency and infectious disease situations?","a":"Shelter policies"},{"type":"card","domain":"General","sub":"General","q":"Much like policies, protocols should be looked upon as ______, that will undergo changes as situations and circumstances warrant.","a":"Living documents"},{"type":"card","domain":"General","sub":"General","q":"What is the first step in preparing infectious disease policies/protocols?","a":"Create a team of individuals who will play a key role in ID, management, and treatment of those diseases to help create the policies."},{"type":"card","domain":"General","sub":"General","q":"The final review and acceptance of new shelter policies/procedures should be finalized by:","a":"the top management and lead veterinarian"},{"type":"card","domain":"General","sub":"General","q":"Which diseases should be given priority when creating protocols?","a":"The most common and most serious"},{"type":"card","domain":"General","sub":"General","q":"What is the last step in protocol development?","a":"Training staff, gathering input, and reviewing policies"},{"type":"card","domain":"General","sub":"General","q":"Which is not an important disease agent variable to consider in making a shelter policy? a. level of contagion b. mode of transmission c. virulence d. shelter staff e. treatment options and costs.","a":"d. shelter staff is not a disease agent, but should be considered"},{"type":"card","domain":"General","sub":"General","q":"How does the shelter's mission interact with infectious disease policies?","a":"Informs which animals will be treated and which euthanized."},{"type":"card","domain":"General","sub":"General","q":"Inadequate treatment of disease due to lack of _______ and ______ is ill advised and, worse yet, may lead to unnecessary suffering of affected animals","a":"financial and staffing resources"},{"type":"card","domain":"General","sub":"General","q":"Variables unique to the individual patient (such as its adoptability) play a major role in treatment decisions in the shelter (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Therapeutics with the least frequent dosing, shortest course, and greatest ease of administration, and least cost are:","a":"ideal, but should not be used at the expense of a desirable outcome. Side effects should also be considered."},{"type":"card","domain":"General","sub":"General","q":"Careful attention should also be paid to the ______ of the patient when selecting and prescribing treatment protocols.","a":"Welfare"},{"type":"card","domain":"General","sub":"General","q":"What is the goal of isolation?","a":"To protect the general population."},{"type":"card","domain":"General","sub":"General","q":"A disease surveillance program considers limiting infectious disease to _____ as success.","a":"An isolated incident"},{"type":"card","domain":"General","sub":"General","q":"What does successful containment of a disease look like?","a":"Decreasing numbers of new cases"},{"type":"card","domain":"General","sub":"General","q":"What data can be used to track success of a treatment plan or protocol?","a":"Sick animal care days"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between direct and indirect identification of pathogens on a test?","a":"Direct = examining substances microscopically or with PCR, etc. Indirect = antigen or antibody based, imaging, etc."},{"type":"card","domain":"General","sub":"General","q":"What does serology detect?","a":"Antibodies. IgM (first) or IgG (later)."},{"type":"card","domain":"General","sub":"General","q":"Virus neutralization, indirect IFA or IPA, ELISA, Western Blot, Hemagglutination, immunoprecipitation, and complement fixation are all types of:","a":"Serology"},{"type":"card","domain":"General","sub":"General","q":"What are titers?","a":"Serial dilutions of blood samples- the \"titer\" is the highest level of dilution at which antibodies are still detected."},{"type":"card","domain":"General","sub":"General","q":"Titers are equivalent from lab to lab. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are three forms of ELISA tests?","a":"Well, kit (snap) or strip"},{"type":"card","domain":"General","sub":"General","q":"What is a potential limitation of ELISA testing?","a":"each test is specific to a particular pathogen (except combo tests)"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between conventional PCR and rt PCR?","a":"rt = real time = quantitative PCR- amplifies but also provides quantification. Conventional = yes/no answer"},{"type":"card","domain":"General","sub":"General","q":"rtPCR = qPCR (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"PCR is extremely specific but not sensitive (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Which is more prone to contamination- ELISA or PCR?","a":"PCR"},{"type":"card","domain":"General","sub":"General","q":"Picking up latent viruses, vaccine viruses or normal flora constitute \"false-positive\" tests for PCR. (T/F)","a":"False- they are truly positive but the finding is incidental"},{"type":"card","domain":"General","sub":"General","q":"PCR, like ELISA, don't detect unexpected organisms (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Culture techniques are used to detect bacterial, fungal, viral and protozoal organisms. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What can skew or prevent the culture of many bacteria?","a":"Antimicrobial therapy"},{"type":"card","domain":"General","sub":"General","q":"What are the most reliable samples to get a definitive diagnosis of disease?","a":"Necropsy or biopsy samples->direct visualization"},{"type":"card","domain":"General","sub":"General","q":"Sample collection is one of the most important reasons to perform a _______.","a":"Necropsy"},{"type":"card","domain":"General","sub":"General","q":"What are the four outcomes of a diagnostic test?","a":"False positive, false negative, true positive, true negative"},{"type":"card","domain":"General","sub":"General","q":"Define sensitivity:","a":"The probability a test will call positives positive"},{"type":"card","domain":"General","sub":"General","q":"Define specificity:","a":"The probability a test will call negatives negative"},{"type":"card","domain":"General","sub":"General","q":"Define positive predictive value:","a":"The probability that a positive result is describing a positive case"},{"type":"card","domain":"General","sub":"General","q":"Define negative predictive value:","a":"The probability that a negative result is describing a negative case"},{"type":"card","domain":"General","sub":"General","q":"When is the positive predictive value of a test high?","a":"When the disease is common and the test has a good sensitivity (dependent on prevalence)"},{"type":"card","domain":"General","sub":"General","q":"When is the negative predictive value of a test high?","a":"When the disease is uncommon and the test has good specificity (dependent on prevalence)"},{"type":"card","domain":"General","sub":"General","q":"Who regulates diagnostic tests in the US?","a":"USDA-APHIS"},{"type":"card","domain":"General","sub":"General","q":"The USDA has regulations for specificity/sensitivity of diagnostic tests. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"The USDA has an agency that validates diagnostic tests. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"The ________ will influence the apparent accuracy of a test.","a":"population tested"},{"type":"card","domain":"General","sub":"General","q":"Interpretation of test results, no matter what the manufacturer says, is a matter of ________.","a":"clinical judgement."},{"type":"card","domain":"General","sub":"General","q":"How can you increase specificity?","a":"Use two tests, and require both to be positive"},{"type":"card","domain":"General","sub":"General","q":"How can you increase sensitivity?","a":"Use two tests, and require only one to be positive"},{"type":"card","domain":"General","sub":"General","q":"Recently infected animals may not have _____ to test positive on some ELISA tests.","a":"antibodies"},{"type":"card","domain":"General","sub":"General","q":"Animals who cannot mount an immune response may test negative on ELISA tests (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Timing of sampling can significantly influence accuracy of antigen tests (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"To improve test sensitivity, samples should be obtained from the location most likely to provide _______.","a":"Highest levels of pathogen (eg blood, not saliva for FeLV)"},{"type":"card","domain":"General","sub":"General","q":"Name three things that can influence the accuracy of antigen tests:","a":"if shedding is intermittent, if currently in a different life stage (eg heartworm), if in the wrong location, if vaccination related, if \"normal\" flora"},{"type":"card","domain":"General","sub":"General","q":"In general, testing apparently healthy animals for infectious diseases is strongly recommended (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between screening tests and surveillance testing?","a":"Screening tests detect diseases commonly present that may pose a threat to health (implies all animals); surveillance testing is performed to detect trends in background disease levels (implies sample of population)."},{"type":"card","domain":"General","sub":"General","q":"Screening animals for pathogens that are very rare or insignificant is recommended.","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Surveillance testing of ill animals can be useful. How?","a":"To ID true causes of syndromes to be able to address particular pathogens (eg URI = herpes vs C. felis)"},{"type":"card","domain":"General","sub":"General","q":"Name four indications for surveillance testing in an outbreak?","a":"unusually severe or fatal dz, prolonged recovery/failure to respond, multiple species affected or spreading outside of shelter, suspected reportable or emergent dz"},{"type":"card","domain":"General","sub":"General","q":"What minimum number of animals should be tested for dz in an outbreak?","a":"10-30% or 3-5 animals"},{"type":"card","domain":"General","sub":"General","q":"When screening for disease in a healthy population, staff should be highly skeptical of negative test results. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"A cat testing positive even on a test with relatively poor predictive value is still more likely to be ill than one testing negative (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Movement of animals from shelters into the community represents only a small part of animal trafficking in communities as a whole (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the three ways to reduce animals coming into shelters?","a":"1. reduce populations through spay/neuter 2. implement widespread animal ID 3. promote responsible pet ownership"},{"type":"card","domain":"General","sub":"General","q":"What are the goals of the Asilomar Accords?","a":"promoting transparency among organizations, adoption of standard definitions of metrics, sharing data related to intakes and outcomes subdivided by animal health"},{"type":"card","domain":"General","sub":"General","q":"What two companies have strongly encouraged/helped shelters collect data?","a":"Maddie's fund- grants for Asilomar data, and PetPoint having free software"},{"type":"card","domain":"General","sub":"General","q":"What are the three ways to calculate a LRR?","a":"1. Those leaving divided by those with outcomes in period x, 2. those leaving divided by those that came in in period x, and 3. those leaving divided by animal care day."},{"type":"card","domain":"General","sub":"General","q":"What is the \"save rate?\"","a":"Animals released alive divided by those eligible to leave alive"},{"type":"card","domain":"General","sub":"General","q":"Animals remaining in the shelter (without a definitive disposition) are frequently excluded from LRR calculations (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Ideally, how will shelters increase adoption rates?","a":"By increasing market share for shelters in animal trafficking"},{"type":"card","domain":"General","sub":"General","q":"What is one drawback of reporting adoptions/population of humans?","a":"Difficult in areas served by multiple shelters"},{"type":"card","domain":"General","sub":"General","q":"The greatest utility of calculating LRRs is:","a":"To help individual shelters track their progress/mission"},{"type":"card","domain":"General","sub":"General","q":"The same proportion of households own dogs now as did in the early1990s.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"The percentage of American households owning cats is the same as it was in the early 1990s.","a":"False- increased slightly."},{"type":"card","domain":"General","sub":"General","q":"The percentage of households owning shelter pets has remained the same since the 1990s.","a":"False- increased by around 2x (11-24%)"},{"type":"card","domain":"General","sub":"General","q":"Studies show that adoption preferences for animals are consistent across location. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Why should RTO statistics be tracked by age?","a":"Because \"stray\" kittens and puppies are usually abandoned"},{"type":"card","domain":"General","sub":"General","q":"What is an underused means to decrease the number of animals euthanized in shelters?","a":"Increasing RTO numbers."},{"type":"card","domain":"General","sub":"General","q":"Name an advantage and a drawback of a transfer program?","a":"Saving lives, importing disease"},{"type":"card","domain":"General","sub":"General","q":"Besides LRR and euth rate, what are other variables that can be measured to determine sheltering success?","a":"Length of stay, incidence of disease, incidence of behavior problems"},{"type":"card","domain":"General","sub":"General","q":"Which bacterial infection causes a pan-leukopenia as a r/o for FPV?","a":"Salmonella"},{"type":"card","domain":"General","sub":"General","q":"What is canine parvovirus-1?","a":"The minute virus of canines"},{"type":"card","domain":"General","sub":"General","q":"Salmonella is indirectly zoonotic. T/F","a":"False-directly"},{"type":"card","domain":"General","sub":"General","q":"Clostridium spores are easily removed from the environment T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the human sp of Cryptosporidium?","a":"hominis"},{"type":"card","domain":"General","sub":"General","q":"It's easy to treat Crypto. T/F","a":"False- no great tx plan; tylosin, azithro and ponazuril are used"},{"type":"card","domain":"General","sub":"General","q":"What's the newest way to detect cryptosporidiosis?","a":"Fluorescent antibody assay that gets giardia at same time- for humans"},{"type":"card","domain":"General","sub":"General","q":"What is the primary goal of giardia treatment?","a":"Reduce shedding/resolve clinical signs (not eliminate shedding)"},{"type":"card","domain":"General","sub":"General","q":"What can you treat with toltrazuril?","a":"Coccidia"},{"type":"card","domain":"General","sub":"General","q":"Name some transport hosts of coccidia:","a":"flies, cockroaches, beetles, rodents"},{"type":"card","domain":"General","sub":"General","q":"In immunocompromised kittens with toxo, what organs are affected?","a":"Liver, CNS, and Resp"},{"type":"card","domain":"General","sub":"General","q":"What are milder signs of toxoplasmosis that respond well to tx?","a":"Muscle pain, fever, uveitis"},{"type":"card","domain":"General","sub":"General","q":"Tritrichomonas has been reported to cause diarrhea in puppies T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Tritrichomonas has no cyst form. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Match organism to motion: falling leaf, straight line, giardia, tritrich","a":"Tritrich: straight line. Giardia: falling leaf"},{"type":"card","domain":"General","sub":"General","q":"What is the currently preferred tx for tritrichomonas?","a":"Ronidazole"},{"type":"card","domain":"General","sub":"General","q":"What part of the GI tract do trichuris vulpis live?","a":"Cecum"},{"type":"card","domain":"General","sub":"General","q":"Human and canine whipworms are the same species. T/F","a":"False- humans don't really get vulpis"},{"type":"card","domain":"General","sub":"General","q":"Which is hardier- whipworm or ascarid eggs?","a":"Whipworm?!"},{"type":"card","domain":"General","sub":"General","q":"Influenza vaccine provides complete immunity.","a":"False- lessens C/S and shedding, requires 2 vaxes"},{"type":"card","domain":"General","sub":"General","q":"Which CRDC dz has the shortest incubation period?","a":"Influenza/Bordetella"},{"type":"card","domain":"General","sub":"General","q":"What are three non-conjunctival or nasal symptoms of FHV1?","a":"Caudal stomatitis, facial dermatitis, keratitis (ulcerative or interstitial)"},{"type":"card","domain":"General","sub":"General","q":"What is the most common way cats get Bordetella?","a":"Subclinical"},{"type":"card","domain":"General","sub":"General","q":"Why is culture superior to PCR for Bordetella?","a":"Because you can run antimicrobial susceptibility and direct therapy"},{"type":"card","domain":"General","sub":"General","q":"What are three drugs useful for treating Bordetella?","a":"Doxy, Trimeth-Sulfa, and Fluoroquinolones"},{"type":"card","domain":"General","sub":"General","q":"What supports a diagnosis of C. felis in a cat with conjunctivitis?","a":"Inclusion bodies in neutrophil cytoplasm on conjunctival swabs"},{"type":"card","domain":"General","sub":"General","q":"What duration should oral abx be used in C. felis cats (per SM)?","a":"3 weeks"},{"type":"card","domain":"General","sub":"General","q":"What primary disease is often caused by mycoplasma felis?","a":"Conjunctivitis"},{"type":"card","domain":"General","sub":"General","q":"What are two non-respiratory or ocular signs mycoplasma may cause?","a":"Polyarthritis and abortion"},{"type":"card","domain":"General","sub":"General","q":"Most reference labs can provide mycoplasma susceptibility testing if they manage to grow it on special culture T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Sarcoptes animals can become debilitated and die T/F","a":"True- esp foxes/dogs"},{"type":"card","domain":"General","sub":"General","q":"What are two topical drugs labeled for sarcoptes?","a":"Selamectin and fipronil spray"},{"type":"card","domain":"General","sub":"General","q":"What dose of ivomec should be used to treat sarcoptes?","a":"0.2-0.4mg/kg q2wks"},{"type":"card","domain":"General","sub":"General","q":"Which is more common in sarcoptes- false positives or false negatives on scrape?","a":"False negatives"},{"type":"card","domain":"General","sub":"General","q":"Describe the shape of D. gatoi vs D. cati","a":"D. gatoi is short tailed, rounded. D. cati is long like canis"},{"type":"card","domain":"General","sub":"General","q":"Ivermectin alone is sufficient to kill D. cati T/F","a":"False- recommend lime sulfur or fipronil spray concurrently"},{"type":"card","domain":"General","sub":"General","q":"Demodex canis requires only short course treatment. T/F","a":"False- up to 4 months, can be chronic"},{"type":"card","domain":"General","sub":"General","q":"What should be performed after diagnosing D. cati or D. canis?","a":"Underlying disease."},{"type":"card","domain":"General","sub":"General","q":"What percentage of dermatophytes fluoresce according to SMII?","a":"0.6"},{"type":"card","domain":"General","sub":"General","q":"What are problems with griseofulvin?","a":"narrow margin of safety, req. longer course"},{"type":"card","domain":"General","sub":"General","q":"Airborne transmission of ringworm has been documented in shelters (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What bleach concentration kills RW spores?","a":"1:10 (1.5c/gallon)"},{"type":"card","domain":"General","sub":"General","q":"Ehrlichia ewingii is spread by the same tick as Ehrlichia canis (T/F)","a":"False- E. ewingii is Amblyomma americanum, E. canis is Rhipicephalus sanguineus"},{"type":"card","domain":"General","sub":"General","q":"Anaplasma phagocytophilum and Anaplasma platys are transmitted by different ticks. (T/F)","a":"True- Phago = Ixodes, and Platys = Rhipicephalus"},{"type":"card","domain":"General","sub":"General","q":"Ehrlichia ewingii can affect both dogs and cats, while Ehrlichia canis affects only dogs. (T/F)","a":"False- backward! E. canis = both, E.e is only dogs"},{"type":"card","domain":"General","sub":"General","q":"Rhipicephalus mainly lives in the South.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Ixodes mainly live in the North.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Which fluid sheds the most FeLV virions?","a":"Saliva"},{"type":"card","domain":"General","sub":"General","q":"What is the most important way to control FeLV in the shelter?","a":"ID positive cats and remove them"},{"type":"card","domain":"General","sub":"General","q":"FeLV IFA has more false negative tests, so it should not be used as a screening test. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Per SMII, when should kittens be tested for FIV?","a":"As soon as possible (?)"},{"type":"card","domain":"General","sub":"General","q":"What test can (try to) tell the difference between FIV vax vs infected?","a":"PCR"},{"type":"card","domain":"General","sub":"General","q":"What experimental treatment may help FIV and FeLV cats per SMII?","a":"Interferon"},{"type":"card","domain":"General","sub":"General","q":"What are the three sides of the epidemiological triad?","a":"Agent, host, environment"},{"type":"card","domain":"General","sub":"General","q":"What is infectivity?","a":"The ability of a pathogen to enter, survive, multiply, and sustain in the environment"},{"type":"card","domain":"General","sub":"General","q":"What is immunogenicity?","a":"The ability of an agent to invoke an immune response"},{"type":"card","domain":"General","sub":"General","q":"What is pathogenicity?","a":"agent's ability to cause clinical disease in infected animals"},{"type":"card","domain":"General","sub":"General","q":"What is virulence?","a":"relates to the severity of disease that an agent produces"},{"type":"card","domain":"General","sub":"General","q":"Vertical transmission includes, utero, delivery, or suckling T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the two types of horizontal transmission?","a":"direct and indirect"},{"type":"card","domain":"General","sub":"General","q":"How close do you have to be for \"direct\" transmission?","a":"around 1 meter"},{"type":"card","domain":"General","sub":"General","q":"What are the 3 forms of indirect transmission?","a":"vehicle-borne (fomite), vector-borne, airborne"},{"type":"card","domain":"General","sub":"General","q":"Vector-borne transmission requires an arthropod bite to transmit a disease T/F","a":"False- some vectors are mechanical. Does require arthropod vector."},{"type":"card","domain":"General","sub":"General","q":"Droplet transmission is a form of indirect transmission T/F","a":"False- airborne or aerosol transmission (indirect) is distinct from droplet transmission (direct)"},{"type":"card","domain":"General","sub":"General","q":"Distinguish between convalescent and chronic carriers of dz","a":"convalescent are recovering and will stop shedding; chronic will continue to shed long-term"},{"type":"card","domain":"General","sub":"General","q":"What is the convalescent shedding period for distemper?","a":"16 wks (Newbury 2009)"},{"type":"card","domain":"General","sub":"General","q":"What is a common example of a latent carrier in the shelter?","a":"Herpes cat"},{"type":"card","domain":"General","sub":"General","q":"An epidemic exists when the frequency or incidence exceeds the _____ level of a disease.","a":"endemic"},{"type":"card","domain":"General","sub":"General","q":"What three factors should be investigated in epidemic populations?","a":"incidence by host characteristic, location in shelter, and time frame"},{"type":"card","domain":"General","sub":"General","q":"Which is preferable in establishing an endemic rate, collecting data regarding diagnosis or regarding symptoms?","a":"Diagnosis"},{"type":"card","domain":"General","sub":"General","q":"What are 3 types of surveillance for dz?","a":"active (intrusive), passive (reporting), and sentinel (investigative)"},{"type":"card","domain":"General","sub":"General","q":"Every shelter should have a documented infectious disease control plan that remains consistent. T/F","a":"False- plan needs to evolve and change w/ science"},{"type":"card","domain":"General","sub":"General","q":"What two key tools help improve animals' ability to resist diseases?","a":"Preventive healthcare measures (deworm, vax) and husbandry that decreases stress"},{"type":"card","domain":"General","sub":"General","q":"Based on the human medical field, precautions to limit pathogen transmission can be categorized by (3)","a":"Whether they are built into facility design (eg. separate air circ), accomplished through administrative measures (order-of-cleaning protocols), or whether implemented through PPE (biosecurity)."},{"type":"card","domain":"General","sub":"General","q":"Small animal shelters vary widely, but equine shelters are fairly similar to one another T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Name 3 sources for 'rescued' horses","a":"Seizure, Owner surrender, Auction"},{"type":"card","domain":"General","sub":"General","q":"When is a horse considered an adult?","a":"5 years"},{"type":"card","domain":"General","sub":"General","q":"Horses have great vision, which helps them flee danger T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Horses can sleep standing up T/F","a":"TRUE- but not REM sleep cycle, which req a few minutes lying down"},{"type":"card","domain":"General","sub":"General","q":"Why do horses die from colic when other herbivores don't?","a":"They can't vomit"},{"type":"card","domain":"General","sub":"General","q":"How long should horses be quarantined for before introduced to other horses?","a":"2 weeks"},{"type":"card","domain":"General","sub":"General","q":"Where should you look for patient ID on a thoroughbred?","a":"lip tattoo"},{"type":"card","domain":"General","sub":"General","q":"How can you permanently identify a horse?","a":"microchip"},{"type":"card","domain":"General","sub":"General","q":"Photographs are a normal part of an equine physical exam","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Where is height measured from and what unit is used for horses?","a":"From the withers, 4\" = one hand"},{"type":"card","domain":"General","sub":"General","q":"What can you use to \"weigh\" a horse instead of a scale?","a":"A weight tape"},{"type":"card","domain":"General","sub":"General","q":"What does a Coggin's test test for?","a":"Equine Infectious Anemia"},{"type":"card","domain":"General","sub":"General","q":"Which affects a horse's adoptability more- behavior or medical?","a":"Behavior"},{"type":"card","domain":"General","sub":"General","q":"When should a behavior assessment be performed on a horse?","a":"After few days"},{"type":"card","domain":"General","sub":"General","q":"The general recommended vaccination schedule for horses is:","a":"On intake, then booster 4 weeks later, then annually"},{"type":"card","domain":"General","sub":"General","q":"Name the three core vaccines for horses:","a":"Tetanus + Encephalitis (WEE, EEE), WNV, Rabies"},{"type":"card","domain":"General","sub":"General","q":"Optional or risk-based vaccines for horses","a":"Potomac Fever, influenza, herpes, anthrax, botulism, EVA, Lepto, rotavirus, snakebite, strangles"},{"type":"card","domain":"General","sub":"General","q":"When should a horse receive its first vaccination?","a":"4-6 months"},{"type":"card","domain":"General","sub":"General","q":"You should use at least a full dose of dewormer for a horse with a high parasite load. T/F","a":"False- will cause too fast die off."},{"type":"card","domain":"General","sub":"General","q":"What should you base your deworming protocol on for horses?","a":"Fecal egg count"},{"type":"card","domain":"General","sub":"General","q":"Mares and stallions should be ovariectomized/gelded as soon as possible after intake T/F","a":"False- mares don't need to be ovariectomized unless they have a granulosa cell tumor"},{"type":"card","domain":"General","sub":"General","q":"How old does a horse have to be to be considered geriatric?","a":">20 yrs"},{"type":"card","domain":"General","sub":"General","q":"What four factors are important for successful equine husbandry?","a":"Constant small amounts of food, lots of low level exercise, social companionship/herd structure, recognition of prey animal status"},{"type":"card","domain":"General","sub":"General","q":"About how much hay should a 1000lb horse eat in a day?","a":"15-20lbs"},{"type":"card","domain":"General","sub":"General","q":"What are three factors to consider when group housing horses?","a":"age, gender, size"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum acceptable size of horse stall according to FASS?","a":"12'x12' with 8-10' high ceiling"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum acceptable space needed for a group-housed horse?","a":"120 ft^2 for the first horse, then 60 ft ^2 for each additional horse"},{"type":"card","domain":"General","sub":"General","q":"About how much fecal matter does a typical horse produce in a day?","a":"30lbs"},{"type":"card","domain":"General","sub":"General","q":"How often should horse teeth be floated?","a":"Every 6-12 months"},{"type":"card","domain":"General","sub":"General","q":"How often should horse hooves be trimmed?","a":"6-8 weeks"},{"type":"card","domain":"General","sub":"General","q":"What is the largest public health risk from horses?","a":"Physical injury (kick, bite, trampling, throwing)"},{"type":"card","domain":"General","sub":"General","q":"What is the prognosis for horses <50% of their ideal body weight?","a":"Grave"},{"type":"card","domain":"General","sub":"General","q":"When should grain be fed to a starved horse?","a":"Not until after they've reached their ideal body weight"},{"type":"card","domain":"General","sub":"General","q":"What resource should shelters look to for horse euthanasia criteria?","a":"AAEP"},{"type":"card","domain":"General","sub":"General","q":"What four criteria should be used when considering euthanasia in horses?","a":"Movement, Eating, Drinking, Weight"},{"type":"card","domain":"General","sub":"General","q":"What is the preferred method for euthanasia of horses?","a":"Overdose of IV pentobarbital. Also considered humane: captive bolt or gunshot by well trained personnel."},{"type":"card","domain":"General","sub":"General","q":"Where should a horse be euthanized?","a":"In a place where the carcass can be accessed by heavy equipment necessary to move it."},{"type":"card","domain":"General","sub":"General","q":"It is uncommon for shelters to have to handle wildlife T/F","a":"False- over half report doing so"},{"type":"card","domain":"General","sub":"General","q":"What is the first step in forming a temporary wildlife care plan?","a":"Researching and contacting more permanent wildlife care facilities"},{"type":"card","domain":"General","sub":"General","q":"Animal shelters don't need a license to care for wildlife T/F","a":"Usually false- most states require permits or licenses even for vets."},{"type":"card","domain":"General","sub":"General","q":"Many states requires wildlife care facilities to be inspected. T/F","a":"TRUE (>43 states)"},{"type":"card","domain":"General","sub":"General","q":"What is required to care for migratory birds in the shelter?","a":"a federal permit from US fish and wildlife, and need state rehabilitation permit"},{"type":"card","domain":"General","sub":"General","q":"Which birds are not covered by migratory bird statues? (no permit needed)","a":"Pigeons, house sparrows, european starlings, game birds (turkey, quail)"},{"type":"card","domain":"General","sub":"General","q":"Which wild animals require extra special licensing to care for and/or euthanized?","a":"Endangered and threatened species (list on DNR website)"},{"type":"card","domain":"General","sub":"General","q":"Which wild animals may not be rehabilitated even with a license? (in some states)","a":"Rabies vectors, invasive species"},{"type":"card","domain":"General","sub":"General","q":"What is the biggest threat to wildlife health in the shelter?","a":"Stress"},{"type":"card","domain":"General","sub":"General","q":"What are 3 ways to prevent stress in wildlife?","a":"1) Handle as absolute little as possible 2) Keep the environment very quiet 3) Keep animal covered/hidden"},{"type":"card","domain":"General","sub":"General","q":"What technique can be used to capture a loose wild bird?","a":"Turn off the lights and use a net (unless owl or nighthawk)"},{"type":"card","domain":"General","sub":"General","q":"What PPE is essential for working with herons and cranes?","a":"Facemask- to prevent eye pecking"},{"type":"card","domain":"General","sub":"General","q":"Which bird of prey is most likely to bite?","a":"Owls"},{"type":"card","domain":"General","sub":"General","q":"What is the most dangerous part of a bird of prey?","a":"Talons"},{"type":"card","domain":"General","sub":"General","q":"How should raccoons, foxes, coyotes, and squirrels be restrained?","a":"Pole snare"},{"type":"card","domain":"General","sub":"General","q":"Because wildlife are going to be released and never seen again, medical records are not necessary. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Wild animals should receive treatments (fluids, etc) immediately after their intake physical. T/F","a":"False- should let them rest first"},{"type":"card","domain":"General","sub":"General","q":"What type of caging is recommended for bats and nonvenomous snakes?","a":"Double caging- in a box, in an aquarium for example"},{"type":"card","domain":"General","sub":"General","q":"What species of wild animal should wire cages be used for, and what species should wire never be used for?","a":"Alert active gnawing mammals such as rodents, never for wild birds"},{"type":"card","domain":"General","sub":"General","q":"In addition to wearing gloves during handling wildlife, gloves should also be worn when _____.","a":"Cleaning up after wildlife."},{"type":"card","domain":"General","sub":"General","q":"What is the range of rabies incubation in wildlife?","a":"Days to >one year"},{"type":"card","domain":"General","sub":"General","q":"Basically, if a wild animal bites someone, it is __________.","a":"euthanized and tested for rabies."},{"type":"card","domain":"General","sub":"General","q":"What is a ddx for neurological raccoons, skunks, and foxes besides rabies?","a":"Canine distemper"},{"type":"card","domain":"General","sub":"General","q":"Why is Baylisascaris such a concern in wildlife medicine?","a":"Its neurotropism and zoonotic potential"},{"type":"card","domain":"General","sub":"General","q":"Baylisascaris eggs are relatively easy to disinfect T/F","a":"False; they're difficult to kill and sticky"},{"type":"card","domain":"General","sub":"General","q":"What is one way to reduce the threat of baylisascaris when rehabilitating raccoons?","a":"Deworm with pyrantel or fenbendazole weekly"},{"type":"card","domain":"General","sub":"General","q":"______ is one large component of wildlife care in the shelter that requires no special equipment or licensing.","a":"Public education about wildlife"},{"type":"card","domain":"General","sub":"General","q":"It is illegal to commercially import exotic birds into the US. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What law says it is illegal to possess, buy, or sell an endangered species without a captive-bred wildlife permit?","a":"The Endangered Species Act"},{"type":"card","domain":"General","sub":"General","q":"What cat allows the US govt to prosecute people who possess an animal illegally obtained in a foreign country or state?","a":"Lacey act"},{"type":"card","domain":"General","sub":"General","q":"What species are not covered by the Animal Welfare Act?","a":"Birds, Rats, and MIce."},{"type":"card","domain":"General","sub":"General","q":"Hand-raising a bird produces a much better adjusted pet T/F","a":"False- they don't know how to be birds"},{"type":"card","domain":"General","sub":"General","q":"Hand-raised birds can be rehabilitated and released into the wild successfully T/F","a":"False, mostly"},{"type":"card","domain":"General","sub":"General","q":"What is the first step in sheltering a pet bird?","a":"Identifying the species"},{"type":"card","domain":"General","sub":"General","q":"Why is wood not a good material for building bird cages?","a":"It can't be disinfected and parrots may chew through it easily"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum acceptable cage size for a finch?","a":"1 sq foot"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum acceptable cage size for a cockatiel?","a":"1.5 sq foot"},{"type":"card","domain":"General","sub":"General","q":"What is the general minimum cage size for a large bird?","a":"1.5 times bird's wing span in all directions, and enough height so tail does not touch the ground or extend through bars of the cage"},{"type":"card","domain":"General","sub":"General","q":"Perches in bird cages should not be placed above food and water because:","a":"poop"},{"type":"card","domain":"General","sub":"General","q":"What spectrum should be used for lights in rooms with bird cages and why?","a":"Full spectrum, so they can get UV light to produce vitamin D"},{"type":"card","domain":"General","sub":"General","q":"Psittacines should be fed a diet with a high percentage of seeds T/F","a":"False- causes fatty liver, atherosclerosis, vit A deficiency"},{"type":"card","domain":"General","sub":"General","q":"Psittacines should be fed a diet with a high percentage of pellets T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"All-pellet diets for budgies and cockatiels can lead to which disorder?","a":"Hypercalcemia-> renal mineralization"},{"type":"card","domain":"General","sub":"General","q":"Macaws require a higher % of what in their diet?","a":"Fat"},{"type":"card","domain":"General","sub":"General","q":"Lories/lorikeets require seeds to supplement their fruit diet T/F","a":"False- no seeds!"},{"type":"card","domain":"General","sub":"General","q":"What should be done with water for birds?","a":"Use filtered water, change daily, don't put under perch"},{"type":"card","domain":"General","sub":"General","q":"What are symptoms of URI in birds?","a":"Swollen eyes, sneezing, wheezing, open-mouth breathing"},{"type":"card","domain":"General","sub":"General","q":"How long should a bird be quarantined before housing with another bird?","a":"30 days"},{"type":"card","domain":"General","sub":"General","q":"What diseases can be tested for in birds before group housing?","a":"Chlamydia PCR, Psittacine beak and feather dz (old world) PCR, Pacheco's (new world) PCR."},{"type":"card","domain":"General","sub":"General","q":"Psittacine beak and feather disease is a concern for Old World Parrots T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Pacheco's disease is a concern for Old World Parrots T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What type of virus is Pacheco's disease?","a":"Herpesvirus-> massive liver necrosis"},{"type":"card","domain":"General","sub":"General","q":"One of the most common mechanisms for viral disease transmission between parrots is:","a":"Feather dust spread"},{"type":"card","domain":"General","sub":"General","q":"What type of disease is Exotic Newcastle and why is it illegal to import a bird with it?","a":"Paramyxovirus (like parainfluenza) and concern for poultry industry- reportable"},{"type":"card","domain":"General","sub":"General","q":"Proventricular dilation disease is caused by a virus T/F","a":"Maybe? Bornavirus? Still unclear"},{"type":"card","domain":"General","sub":"General","q":"Which animal is the species of greatest public health concern with C. psittaci?","a":"Companion bird species, esp Amazons"},{"type":"card","domain":"General","sub":"General","q":"What PPE can help prevent zoonosis of C. psittaci?","a":"Face mask, surgical cap, and gloves when handling bird or its feces"},{"type":"card","domain":"General","sub":"General","q":"Birds with C. psittaci should not be adopted. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Humans can give birds Salmonella as well as the reverse. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Mycobacterium tuberculosis is considered an anthroponosis, not a zoonosis. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"The prognosis for adoption for a bird with mycobacterial dz is good. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the most frequent cause of URI in the pet bird?","a":"Aspergillosis"},{"type":"card","domain":"General","sub":"General","q":"What is the most common clinical sign of Pacheco's disease?","a":"Death"},{"type":"card","domain":"General","sub":"General","q":"What is knemidokoptes?","a":"The budgie skin mite- in sarcoptes family- causes deformed beak and nails"},{"type":"card","domain":"General","sub":"General","q":"What is a risk factor for atherosclerosis in Amazons and African grays?","a":"Being overweight"},{"type":"card","domain":"General","sub":"General","q":"What is the most common foreign body of the avian respiratory tract?","a":"Birdseed aspiration"},{"type":"card","domain":"General","sub":"General","q":"Self-mutilation/Feather picking is a serious behavior disorder of birds and it a shelter can't resolve or improve husbandry, the animal should be euthanized. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What can increase reproductive behaviors in pet birds?","a":"Increasing day length, housing opposite sex in close contact, petting bird low on back"},{"type":"card","domain":"General","sub":"General","q":"What is a ricasso?","a":"Bottom of knife blade where both ends are square"},{"type":"card","domain":"General","sub":"General","q":"What type of tears in tissue do predators make?","a":"Triangle tears"},{"type":"card","domain":"General","sub":"General","q":"Animal shelters should house reptiles until they're adopted. T/F","a":"False- get them to a herp specialist"},{"type":"card","domain":"General","sub":"General","q":"What is one barrier to intaking a herp species to the shelter that may not apply to dogs or cats?","a":"Legality of \"ownership\"- even shelters cannot legally owned banned species (such as venomous snakes)"},{"type":"card","domain":"General","sub":"General","q":"Simple adaptations can create reptile housing from dog or cat enclosures. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"_________ is the key component to formulating a basic husbandry plan for a reptile.","a":"Species ID"},{"type":"card","domain":"General","sub":"General","q":"Permanent marking (clipping toes or scales or skin-piercing tags) can be used to ID reptiles in the shelter.","a":"True but definitely not recommended"},{"type":"card","domain":"General","sub":"General","q":"What temp should reptile rooms be kept at?","a":"80-85F (27-30C)"},{"type":"card","domain":"General","sub":"General","q":"Reptiles are generally social species so should be housed with conspecifics. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What happens when reptiles are housed together?","a":"Violence and cannibalism"},{"type":"card","domain":"General","sub":"General","q":"What disinfectants are recommended for reptiles?","a":"Bleach and Quats"},{"type":"card","domain":"General","sub":"General","q":"What disinfectants are not recommended for reptiles?","a":"Phenolics (lysol) and glutaraldehydes (chlorhex?)"},{"type":"card","domain":"General","sub":"General","q":"What size cage should a snake have?","a":"Perimeter > snake length"},{"type":"card","domain":"General","sub":"General","q":"What monitors should be inside a herp enclosure?","a":"cold area thermometer (low end of POTR), hot area thermometer (high end POTR), hygrometer"},{"type":"card","domain":"General","sub":"General","q":"What is the most practical substrate for reptiles in the shelter?","a":"Newspaper."},{"type":"card","domain":"General","sub":"General","q":"What is POTR in herp context?","a":"Preferred optimal temperature range = specific to species"},{"type":"card","domain":"General","sub":"General","q":"Placing heat sources inside reptile cages can do what?","a":"Cause thermal burns. Don't do it."},{"type":"card","domain":"General","sub":"General","q":"How much light should reptiles be exposed to /day?","a":"10-14hrs"},{"type":"card","domain":"General","sub":"General","q":"What are the three types of reptile diet?","a":"carnivore, omnivore, herbivore"},{"type":"card","domain":"General","sub":"General","q":"Why should feeding live prey to reptiles be avoided in the shelter?","a":"Can injure the reptile"},{"type":"card","domain":"General","sub":"General","q":"How often should herbivorous reptiles be fed?","a":"Every 1-2 days (remove uneaten food before it spoils)"},{"type":"card","domain":"General","sub":"General","q":"What trick can help rehydrate a debilitated frog?","a":"Warm water bowl soak"},{"type":"card","domain":"General","sub":"General","q":"Radiographs are part of an initial physical exam of reptiles T/F","a":"True- do them if you can"},{"type":"card","domain":"General","sub":"General","q":"Contact with reptiles is a significant source of _______ each year according to the CDC.","a":"Salmonellosis"},{"type":"card","domain":"General","sub":"General","q":"What size turtle is illegal to sell?","a":"<4in"},{"type":"card","domain":"General","sub":"General","q":"What's a differential for a neurological boa constrictor?","a":"BOID (inclusion body disease)"},{"type":"card","domain":"General","sub":"General","q":"What are the main rule outs for dorsal and ventral dermatitis in snakes?","a":"Dorsal: heat lamp burn, Ventral: bacterial/fungal dermatitis from dirty environment"},{"type":"card","domain":"General","sub":"General","q":"What is dysecdysis?","a":"Abnormal shedding"},{"type":"card","domain":"General","sub":"General","q":"What metabolic bone disease is common in lizards?","a":"Hypovitaminosis D due to no UVB light (except carnivores who get it from food)"},{"type":"card","domain":"General","sub":"General","q":"What metabolic disease is the cause of severe dehydration in lizards?","a":"Chronic renal failure/secondary gout"},{"type":"card","domain":"General","sub":"General","q":"All sea turtles are endangered. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What dermatological disease is caused by diet in chelonians?","a":"Vitamin A deficiency = hyperkeratosis, inflammation (also kidney disease, blepharedema)"},{"type":"card","domain":"General","sub":"General","q":"What causes URI in Turtles?","a":"Mycoplasma and Pseudomonas"},{"type":"card","domain":"General","sub":"General","q":"Amphibians are easy to care for in captivity. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"How should a frog be restrained?","a":"Wet gloved hands"},{"type":"card","domain":"General","sub":"General","q":"What causes red leg disease in frogs?","a":"Aeromonas spp or other gram neg bacteria --> death!"},{"type":"card","domain":"General","sub":"General","q":"Decapitation, refrigeration, and freezing are acceptable euthanasia methods for reptiles. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are three ways to \"visualize\" death in a reptile?","a":"Doppler ultrasound, ultrasound, or ECG"},{"type":"card","domain":"General","sub":"General","q":"What are other \"adoption\" options for reptiles in the shelter?","a":"Zoos, Museums, Release in Wild, Release to Rehab, Herpetologist Collection"},{"type":"card","domain":"General","sub":"General","q":"Approximately ____ of cats entering shelters were euthanized in 2010 (ASPCA)","a":"0.7"},{"type":"card","domain":"General","sub":"General","q":"Cats are particularly prone to experiencing _____- in a shelter due to their unique biology.","a":"Stress and fear"},{"type":"card","domain":"General","sub":"General","q":"Hypervigilance, feigned sleep, loss of appetite are all clinical signs of:","a":"Cat stress"},{"type":"card","domain":"General","sub":"General","q":"Stress reduction planning for cats starts ________ intake.","a":"before"},{"type":"card","domain":"General","sub":"General","q":"Cats feel more secure when hunkered low in bottom cages T/F","a":"False- perching in high cages"},{"type":"card","domain":"General","sub":"General","q":"Which cats are the most stressed by the shelter environment?","a":"Ferals, geriatrics, and owned cats"},{"type":"card","domain":"General","sub":"General","q":"What should you do with a stressed/provoked cat on intake?","a":"Give it time to chill until they are adapted (may become reactive again if provoked too soon)"},{"type":"card","domain":"General","sub":"General","q":"_______ should be used to handle tractable cats on intake.","a":"Minimal gentle restraint"},{"type":"card","domain":"General","sub":"General","q":"Owners and shelters always describe cat coat color the same way. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What three times should an animal be scanned for a chip?","a":"Intake, before placing a chip, and before moving to adoption/euthanasia"},{"type":"card","domain":"General","sub":"General","q":"Males or females have a greater anogenital distance?","a":"Males"},{"type":"card","domain":"General","sub":"General","q":"Neonatal cats have lower normal temps than adult cats T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Neonatal cats have lower heart rate than adult cats T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Most cats will wear collars safely and comfortably. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What age do neonatal kittens open their eyes?","a":"7-10 days"},{"type":"card","domain":"General","sub":"General","q":"When do kitten baby teeth begin to erupt?","a":"3 weeks"},{"type":"card","domain":"General","sub":"General","q":"When do baby kittens learn to walk?","a":"~3 weeks"},{"type":"card","domain":"General","sub":"General","q":"When are adult incisors completely erupted in kittens?","a":"~4 months"},{"type":"card","domain":"General","sub":"General","q":"When do adult canines erupt in kittens?","a":"~5.5-6 months"},{"type":"card","domain":"General","sub":"General","q":"What are some signs a cat may be >10 years old?","a":"Nuclear sclerosis, iris atrophy, angular face, dorsal muscle wasting"},{"type":"card","domain":"General","sub":"General","q":"What are the 4 common non-core vaccines?","a":"FeLV, FIV (?), Chlamydophila, Bordetella"},{"type":"card","domain":"General","sub":"General","q":"Why not just use an intranasal MLV vaccine for cats?","a":"Because one paper showed that FPV protection wasn't as good with IN as it was with parenteral."},{"type":"card","domain":"General","sub":"General","q":"Where do you admin a FVRCP vaccine?","a":"RF"},{"type":"card","domain":"General","sub":"General","q":"Where do you admin a rabies vaccine?","a":"RR"},{"type":"card","domain":"General","sub":"General","q":"What is the ideal time to vaccinate a cat?","a":"1-2 weeks before entering a shelter"},{"type":"card","domain":"General","sub":"General","q":"A delay of even a day or two significantly compromises a vaccine's ability to provide timely protection T/F","a":"True (Paul et al 2006)"},{"type":"card","domain":"General","sub":"General","q":"For shelter kittens, vaccines should be administered every 2 weeks from ____ until _____ weeks (or permanent incisors are completely erupted).","a":"4 wks - 16 wks"},{"type":"card","domain":"General","sub":"General","q":"In shelter outbreaks of panleuk, what should the kitten vax schedule be?","a":"4wks - 20wks"},{"type":"card","domain":"General","sub":"General","q":"Proper _____ and ______ of vaccines is crucial for their effectiveness.","a":"Storage and handling"},{"type":"card","domain":"General","sub":"General","q":"Vaccines should be used within ____ of being reconstituted (Griffin SM2).","a":"30 min"},{"type":"card","domain":"General","sub":"General","q":"What can Amprolium be used to treat?","a":"Coccidia"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between Drontal and Drontal Plus?","a":"Febantel- not at labeled cat doses so can't use Plus routinely for cats."},{"type":"card","domain":"General","sub":"General","q":"What is Febantel used for in cats?","a":"Giardia"},{"type":"card","domain":"General","sub":"General","q":"For fenbendazole, what are the 3 recommended schedules for which pathogens?","a":"3 days = rounds/hooks, 5 days = giardia, 10 days = lungworms"},{"type":"card","domain":"General","sub":"General","q":"Is fenbendazole effective in treating heartworm?","a":"No"},{"type":"card","domain":"General","sub":"General","q":"Which is safer for pregnant/lactating/neonatal kittens- spot on or spray fipronil?","a":"Spray"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between dog and cat Advantage Multi?","a":"dog product has higher dose of moxidectin per ml of imidacloprid = unsafe for cats"},{"type":"card","domain":"General","sub":"General","q":"Milbemycin (Interceptor) is given via what route? Is it effective against HW in cats?","a":"Oral- yes"},{"type":"card","domain":"General","sub":"General","q":"What is the dose of ponazuril recommended to kill coccidia?","a":"20-50mg/kg orally SID for 1-3 days then repeat in week"},{"type":"card","domain":"General","sub":"General","q":"What is the mg/kg dose of pyrantel? When to repeat?","a":"10mg/kg q2 weeks"},{"type":"card","domain":"General","sub":"General","q":"What are the human sequelae of larval migrans?","a":"Organ damage, blindness, and skin infections"},{"type":"card","domain":"General","sub":"General","q":"What ivermectin dose is recommended for treating otodectes in kittens? What route?","a":"0.3mg/kg (300ug/kg) SQ or PO once then again in 2 weeks"},{"type":"card","domain":"General","sub":"General","q":"What is the prevalence of FeLV/FIV in unhealthy cats?","a":"6-33% (Levy 2006)"},{"type":"card","domain":"General","sub":"General","q":"What is the prevalence of HW infection in cats?","a":"5-15% of dog HW"},{"type":"card","domain":"General","sub":"General","q":"HW infected cats pose a risk to other cats, especially if symptomatic T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Definitive tx of HW in cats is neither practical nor safe. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Most feline HW infections resolve spontaneously and are not associated with shortened lifespan. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Positive feline HW test results are difficult to explain to owners. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Instead of screening for feline HW, what is recommended?","a":"monthly prophylaxis"},{"type":"card","domain":"General","sub":"General","q":"What three essential nutrients are cats unable to synthesize and thus must acquire in their diet/prey?","a":"Taurine, arginine, and vitamin A"},{"type":"card","domain":"General","sub":"General","q":"What is the rule of thumb for % of daily calories in treats?","a":"0.1"},{"type":"card","domain":"General","sub":"General","q":"What formula is used to calculate the RER for cats?","a":"30 x ideal wt in kgs + 70 = #kcal/day"},{"type":"card","domain":"General","sub":"General","q":"What cat life stage requires the most calories/kg?","a":"kittens (up to 6 mo) and lactating queens"},{"type":"card","domain":"General","sub":"General","q":"Appetite and stool quality should be monitored ______.","a":"Daily"},{"type":"card","domain":"General","sub":"General","q":"When should an anorexic kitten be examined by a vet?","a":"Within 24 hours"},{"type":"card","domain":"General","sub":"General","q":"When should an adult cat be examined by a vet?","a":"Within 3-5 days"},{"type":"card","domain":"General","sub":"General","q":"What proportion of the RER must be consumed to fend off hepatic lipidosis?","a":"0.5"},{"type":"card","domain":"General","sub":"General","q":"How many kittens can a queen produce in her lifetime if left to breed naturally?","a":"50-150 kittens"},{"type":"card","domain":"General","sub":"General","q":"What is a differential for a cat that is vocalizing or crying excessively with the back end on the floor?","a":"In heat"},{"type":"card","domain":"General","sub":"General","q":"Litters may have multiple fathers (cats). T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Who reaches puberty first, female or male cats?","a":"Female cats (5-9mo)"},{"type":"card","domain":"General","sub":"General","q":"What happens to cat nipples as pregnancy progresses?","a":"They get pinker"},{"type":"card","domain":"General","sub":"General","q":"When a cat is \"obviously\" pregnant, how far along is she?","a":"<2 weeks"},{"type":"card","domain":"General","sub":"General","q":"What point in gestation do kitten skeletons ossify and therefore become radiopaque?","a":"43 days"},{"type":"card","domain":"General","sub":"General","q":"What hormone can be used to test cats for pregnancy?","a":"Relaxin (after day 25 of gestation levels will be elevated)"},{"type":"card","domain":"General","sub":"General","q":"Raising orphan kittens is best accomplished by what type of foster mother?","a":"Feline"},{"type":"card","domain":"General","sub":"General","q":"What is the typical weight gain for neonatal kittens/day?","a":"10-15g.  Daily gain of <7g/day is inadequate; supplemental feeding needed or health problems present"},{"type":"card","domain":"General","sub":"General","q":"When is the window for passive transfer closed in cats?","a":"12hrs"},{"type":"card","domain":"General","sub":"General","q":"What can treat failure of passive transfer in kittens?","a":"15ml of feline serum SQ or IP (spaced over 24hrs) - from known vaccinated animal"},{"type":"card","domain":"General","sub":"General","q":"What is the outer recommended limit for feeding KMR to kittens?","a":"5-6 weeks"},{"type":"card","domain":"General","sub":"General","q":"Panleukopenia is the most common cause of fading kittens- what is the 2nd most common cause?","a":"Bacterial septicemia"},{"type":"card","domain":"General","sub":"General","q":"Cat cages should be elevated by at least _____ off the floor.","a":"18 inches"},{"type":"card","domain":"General","sub":"General","q":"What four characteristics should be considered when group housing cats?","a":"Health status, age, personality type, S/N status"},{"type":"card","domain":"General","sub":"General","q":"What are the main constraints on group size for housing cats?","a":"Small enough to prevent negative interactions and to allow daily monitoring of individuals"},{"type":"card","domain":"General","sub":"General","q":"What are two recommendations for introducing new cats to group housing situations?","a":"Supervision of the introduction, and gradual introduction (if possible)"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum number of litter boxes recommended for group housed cats?","a":"1 for 2-3 cats"},{"type":"card","domain":"General","sub":"General","q":"The number of resting boards/perches in a group colony room should be:","a":"greater than the number of cats housed in that room"},{"type":"card","domain":"General","sub":"General","q":"Covert resource guarding and dominant posturing in feline group colony settings is easy to see and remedy T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Exposure to phenol or pine-oil products can cause what in cats?","a":"Neurological effects and/or liver damage"},{"type":"card","domain":"General","sub":"General","q":"Ferrets lose almost half their body weight in the summer and then gain it back in the winter T/F","a":"True- 40% loss"},{"type":"card","domain":"General","sub":"General","q":"What gland does ferret's musky odor come from?","a":"Sebaceous glands"},{"type":"card","domain":"General","sub":"General","q":"What is the typical lifespan of a ferret?","a":"5-11 years"},{"type":"card","domain":"General","sub":"General","q":"What is the typical lifespan of a rabbit?","a":"6-12 years"},{"type":"card","domain":"General","sub":"General","q":"What is the typical lifespan of a guinea pig?","a":"5-6 years"},{"type":"card","domain":"General","sub":"General","q":"Ferrets, rabbits and GPs typically run hotter than dogs and cats","a":"1"},{"type":"card","domain":"General","sub":"General","q":"When do ferrets and rabbits become sexually mature?","a":"6-12 months (males and ferrets) 4-9 months (female rabbits)"},{"type":"card","domain":"General","sub":"General","q":"Which is an induced ovulator: ferret, rabbit, GP","a":"Ferrets and Rabbits"},{"type":"card","domain":"General","sub":"General","q":"When are GP's sexually mature?","a":"Around 3 months"},{"type":"card","domain":"General","sub":"General","q":"What is the preferred substrate for ferret latrine/litter box?","a":"Pelleted litter"},{"type":"card","domain":"General","sub":"General","q":"Ferrets are like cats in that they are obligate carnivores. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is the deficiency in adult cat food vs ferret food?","a":"Not enough protein. High quality kitten food can be fed instead."},{"type":"card","domain":"General","sub":"General","q":"What does hissing, screaming, or snapping jaws mean to a ferret?","a":"Defensive threats"},{"type":"card","domain":"General","sub":"General","q":"What does a ferret mean by a staccato clucking sound?","a":"Aggressive threat"},{"type":"card","domain":"General","sub":"General","q":"How can you restrain a ferret for administration of oral medication?","a":"\"ferret burrito\""},{"type":"card","domain":"General","sub":"General","q":"How can you guarantee a good blood draw in a ferret?","a":"Mask down with iso/sevo then use jugular (or vena cava!)"},{"type":"card","domain":"General","sub":"General","q":"What vaccines should a ferret receive on intake to a shelter?","a":"Distemper and Rabies"},{"type":"card","domain":"General","sub":"General","q":"What parasitic preventative should be considered for ferrets?","a":"Heartworm"},{"type":"card","domain":"General","sub":"General","q":"What should be considered before vaccinating a ferret?","a":"Anaphylaxis is common (1% of vaxes) within 30 min. Tx epi, diphenhydramine, dex, O2"},{"type":"card","domain":"General","sub":"General","q":"What zoonotic disease can ferrets share with other ferrets or people (not Rabies)?","a":"Influenza"},{"type":"card","domain":"General","sub":"General","q":"What is \"green slime disease\" and who does it effect?","a":"Ferrets- epizootic catarrhal enteritis (ECE) coronavirus. Presents in adult ferrets when young ferrets are introduced."},{"type":"card","domain":"General","sub":"General","q":"What are the three big diseases in older ferrets?","a":"Insulinoma, adrenal disease, lymphoma"},{"type":"card","domain":"General","sub":"General","q":"What is adrenal disease in ferrets linked to?","a":"Early S/N."},{"type":"card","domain":"General","sub":"General","q":"Adrenal disease in ferrets is the same as Cushing's in people. T/F","a":"False- dx by U/S or adrenal hormone assay."},{"type":"card","domain":"General","sub":"General","q":"What is the main purveyor of ferrets in the US?","a":"Marshall Farms, North Rose, NY"},{"type":"card","domain":"General","sub":"General","q":"What happens to ferrets if not spayed?","a":"Non-regenerative anemia due to chronic hyperestrogenemia ->bone marrow suppression. Spay!"},{"type":"card","domain":"General","sub":"General","q":"How do you neuter a male ferret?","a":"Like a cat."},{"type":"card","domain":"General","sub":"General","q":"what is potentially the biggest adoption issue for ferrets?","a":"Legality- may be illegal in states, cities, municipalities"},{"type":"card","domain":"General","sub":"General","q":"Why are fractures so common in rabbits?","a":"Ratio of muscle to bone (50%:7%bw)"},{"type":"card","domain":"General","sub":"General","q":"Most of the nutrition in a rabbit is derived from:","a":"Fermentation of ingesta in the cecum"},{"type":"card","domain":"General","sub":"General","q":"Rabbits are obligate mouth breathers. T/F","a":"False- obligate nasal breathers"},{"type":"card","domain":"General","sub":"General","q":"What three substrates are recommended for rabbit latrines?","a":"non clumping litter, straw, or paper litter. Not pellets b/c will eat."},{"type":"card","domain":"General","sub":"General","q":"Which rabbits can be fed alfalfa?","a":"Pregnant, lactating, or growing rabbits."},{"type":"card","domain":"General","sub":"General","q":"Rabbits have a high water intake requirement vs other animals. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Control of _____ and ____ is critical when handling rabbits, because they are prone to vertebral fractures and luxations.","a":"The spine and hind legs"},{"type":"card","domain":"General","sub":"General","q":"What type of restraint is recommended for oral medication in a rabbit?","a":"\"rabbit burrito\""},{"type":"card","domain":"General","sub":"General","q":"What auscultation technique should be used with rabbits to ensure GI function?","a":"Listening to the 4 quarters (like a horse)"},{"type":"card","domain":"General","sub":"General","q":"What three classes of antibiotics should not be used in rabbits?","a":"beta lactams, macrolides, lincosamides"},{"type":"card","domain":"General","sub":"General","q":"What three classes of antibiotics should be used in rabbits?","a":"Tetracyclines, Sulfas, fluoroquinolones"},{"type":"card","domain":"General","sub":"General","q":"What are the two most common rabbit ectoparasites?","a":"Psoroptes cuniculi, Cheyletiella parasitovorax"},{"type":"card","domain":"General","sub":"General","q":"What dose of ivermectin is recommended for rabbit Psoroptes?","a":"400ug/kg SQ q2 weeks x 3 times"},{"type":"card","domain":"General","sub":"General","q":"What is E. cuniculi?","a":"Encephalitozoon cuniculi intracellular protozoal organism with CNS affinity."},{"type":"card","domain":"General","sub":"General","q":"What tests are available for E. cuniculi?","a":"Titer (many normals test positive) and clinical suspicion"},{"type":"card","domain":"General","sub":"General","q":"How do you treat E. cuniculi?","a":"benzimidazole anthelmintic SID x 30 days and anti-inflammatory drugs"},{"type":"card","domain":"General","sub":"General","q":"What are signs of tularemia in rabbits?","a":"diarrhea, CNS signs, death"},{"type":"card","domain":"General","sub":"General","q":"How many lacrimal ducts do rabbits have?","a":"One per eye"},{"type":"card","domain":"General","sub":"General","q":"What is the likely cause of sludgy red urine in a rabbit?","a":"Excess calcium in the diet and stress porphyrin"},{"type":"card","domain":"General","sub":"General","q":"Cord ties are recommended for rabbit neuters. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Up to _____ of rabbit does >4 years will develop _______.","a":"80% adenocarcinoma"},{"type":"card","domain":"General","sub":"General","q":"What type of teeth do GPs have?","a":"Hypsodont"},{"type":"card","domain":"General","sub":"General","q":"What type of GI tract do GPs have?","a":"Monogastric but employ cecotrophy"},{"type":"card","domain":"General","sub":"General","q":"What increases the risk of GP dystocia?","a":"Late parity (>7-8 months) due to fusion of the pubic symphysis"},{"type":"card","domain":"General","sub":"General","q":"GPs, like rabbits, have open inguinal rings and can \"disappear\" their testicles. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is an ideal way to house GPs?","a":"In harems (one neutered male, several females)"},{"type":"card","domain":"General","sub":"General","q":"What essential nutrient are GPs unable to synthesize so need to obtain from diet?","a":"Vitamin C"},{"type":"card","domain":"General","sub":"General","q":"GPs can be fed high quality rodent food.","a":"False- need Vit C supplementation"},{"type":"card","domain":"General","sub":"General","q":"Even though they're monogastrics, care should be taken with __________ in GPs due to GI fermentation.","a":"antibiotic selection"},{"type":"card","domain":"General","sub":"General","q":"What is the most common disease seen in poorly housed GPs?","a":"Pneumonia"},{"type":"card","domain":"General","sub":"General","q":"Rabbits can be asymptomatic carriers of _____ so they should not be housed with GPs.","a":"Bordetella"},{"type":"card","domain":"General","sub":"General","q":"Which is the most common ectoparasite of GPs?","a":"Trixacarus caviae, a sarcoptid mite"},{"type":"card","domain":"General","sub":"General","q":"What ivermectin dose is recommended for treating Trixacarus in GPs? What route?","a":"200-400ug/kg SQ q10-14 days"},{"type":"card","domain":"General","sub":"General","q":"By 5 years, 76% of GP sows will develop ________.","a":"Ovarian cysts. Usually asymptomatic, but can become space occupying masses"},{"type":"card","domain":"General","sub":"General","q":"GPs are easy to spay. T/F","a":"False- cranial ovaries, short ovarian ligament, massive GI viscera."},{"type":"card","domain":"General","sub":"General","q":"It's okay to house 2 intact boar GPs together. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"The ASV guidelines are based on what animals need for __________ and not on the mission or resources of the shelter.","a":"good welfare"},{"type":"card","domain":"General","sub":"General","q":"What is the proper classification of dogs today?","a":"Canis lupis familiaris"},{"type":"card","domain":"General","sub":"General","q":"Which freedom is described by: ready access to fresh water and a diet to maintain full health and vigor","a":"Freedom from hunger and thirst"},{"type":"card","domain":"General","sub":"General","q":"Which freedom is described by: providing an appropriate environment including shelter and a comfortable resting area","a":"Freedom from discomfort"},{"type":"card","domain":"General","sub":"General","q":"Which freedom is described by: prevention or rapid diagnosis and treatment","a":"Freedom from pain, injury and disease"},{"type":"card","domain":"General","sub":"General","q":"Which freedom is described by: by providing sufficient space, proper facilities and company of the animal's own kind","a":"Freedom to express normal behavior"},{"type":"card","domain":"General","sub":"General","q":"Which freedom is described by: ensuring conditions and treatment which avoid mental suffering","a":"Freedom from fear and distress"},{"type":"card","domain":"General","sub":"General","q":"Dog breeds are scientific classifications T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Dog ears are better than human ears. T?F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dog noses are 100 times better than human noses T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dogs have better dim-light vision than humans. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dogs have better color vision than humans T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"When do female dogs become reproductively mature?","a":"6-16 months (by breed)"},{"type":"card","domain":"General","sub":"General","q":"When do male dogs become reproductively mature?","a":"10mo-2yrs (by breed)"},{"type":"card","domain":"General","sub":"General","q":"What type of reproduction pattern do dogs exhibit?","a":"Seasonally monoestrous (one set of eggs/cycle)"},{"type":"card","domain":"General","sub":"General","q":"Puppies in a litter always come from one male T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What three actions do dogs take when fearful?","a":"Freeze, flight, fight"},{"type":"card","domain":"General","sub":"General","q":"When signs of behavioral stress or maladaption occur, shelter must:","a":"take steps to alleviate the suffering just as if the dog was suffering from physical disease or injury"},{"type":"card","domain":"General","sub":"General","q":"______ should be attached to each dog on intake.","a":"Identification (tag, band, etc)"},{"type":"card","domain":"General","sub":"General","q":"PEs that include preliminary behavior assessments should be performed on dogs ________.","a":"At intake."},{"type":"card","domain":"General","sub":"General","q":"TPR is required for every animal on intake. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Dogs (thanks to breeding) have more ________ within the species than any other land mammal.","a":"morphological variation"},{"type":"card","domain":"General","sub":"General","q":"T, P, and RR for puppies is higher than for adults. T/F","a":"False- P and RR are higher but T is lower."},{"type":"card","domain":"General","sub":"General","q":"Shelter staff are great at identifying breeds of dogs. T/F","a":"False- 87.5% did not have breeds IDed in one study (Voith 2009)"},{"type":"card","domain":"General","sub":"General","q":"What is a dog's dental formula?","a":"Juv: 3,1,3 x 2  Adult: 3/3, 1/1, 4/4, 2/3 (#42)"},{"type":"card","domain":"General","sub":"General","q":"How is age measured for dogs >1 year old?","a":"Cusp wearing on incisors- lower first, then upper"},{"type":"card","domain":"General","sub":"General","q":"What features of a 6-8 year old dog can indicate its age?","a":"Nuclear sclerosis, greying muzzle"},{"type":"card","domain":"General","sub":"General","q":"When do canine testicles descend?","a":"2 weeks to 2 months (outliers 4-6 months)"},{"type":"card","domain":"General","sub":"General","q":"What test can be used to tell if a male dog has been neutered vs cryptorchid?","a":"GnRH"},{"type":"card","domain":"General","sub":"General","q":"What test can be used to tell if a female dog has been neutered?","a":"LH"},{"type":"card","domain":"General","sub":"General","q":"How should female dogs in heat be housed?","a":"Away from male dogs to prevent sexual stress/frustration"},{"type":"card","domain":"General","sub":"General","q":"What day of pregnancy do mammary glands start to become enlarged and lose nipple hair in dogs?","a":"35 days"},{"type":"card","domain":"General","sub":"General","q":"When should criteria for euthanasia of stray animals for humane reasons be identified?","a":"Before emergencies situations occur."},{"type":"card","domain":"General","sub":"General","q":"The vast majority of ________ will respond  to a single dose of MLV vaccine.","a":"Adult animals"},{"type":"card","domain":"General","sub":"General","q":"In addition to dogs <4 months, who may not mount an immune response to a MLV vax?","a":"Immunologic non-responders"},{"type":"card","domain":"General","sub":"General","q":"Stress is an obstacle to successful immunization. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Animals incubating a disease may not respond to immunization T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Why are vaccination protocols for owned pets different from shelter pets?","a":"Because shelter pets are much more likely to be exposed to infectious disease"},{"type":"card","domain":"General","sub":"General","q":"What vaccines are core for dogs?","a":"MLV DA2PP and Bord/PI IN"},{"type":"card","domain":"General","sub":"General","q":"Vaccines should not be given at the time of surgery because they may have decreased efficacy. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Old neutered dogs from affluent communities can be assumed to have been vaccinated. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Vaccination at intake will still leave naïve dogs without immediate immunity. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Who wins cost/benefit: vaccination for all vs outbreak management?","a":"Vaccination for all!"},{"type":"card","domain":"General","sub":"General","q":"Canine Influenza Vax is now considered core. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What type of vax is the CIV bivalent?","a":"Killed"},{"type":"card","domain":"General","sub":"General","q":"Parenteral Bordetella/PI is considered non-core. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Rabies is considered a core vaccine. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"When should RV be given if long-term stay is anticipated?","a":"At intake."},{"type":"card","domain":"General","sub":"General","q":"Why is parasite control such an area of concern for animals in the shelter?","a":"Because of the zoonotic potential."},{"type":"card","domain":"General","sub":"General","q":"Spot-on products can be used in lieu of primary (oral) deworming products on intake for dogs. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What's the difference between Sentinel and Interceptor?","a":"Sentinel has added lufenuron (prevents flea eggs from hatching)"},{"type":"card","domain":"General","sub":"General","q":"What makes Frontline Plus different from Frontline?","a":"Added methoprene"},{"type":"card","domain":"General","sub":"General","q":"What is the preferred dose of selamectin for dogs/cats?","a":"6mg/kg"},{"type":"card","domain":"General","sub":"General","q":"What is the preferred pyrantel pamoate dose for dogs?","a":"5mg/kg (10 for cats)"},{"type":"card","domain":"General","sub":"General","q":"What factors should be considered when designing a disease screening/testing protocol for dogs?","a":"Prevalence in the community, severity of dz, likelihood of transmission"},{"type":"card","domain":"General","sub":"General","q":"What # of dogs tested for Lyme remain asymptomatic?","a":"0.95"},{"type":"card","domain":"General","sub":"General","q":"Parvovirus snap tests make good screening tools for canine intake T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What should be done after an animal tests positive on a screening test?","a":"Secondary confirmatory/exculpatory testing"},{"type":"card","domain":"General","sub":"General","q":"What is the intent of dog grooming provided on intake?","a":"Prevent medical problems related to hair"},{"type":"card","domain":"General","sub":"General","q":"What is the ideal management strategy for orphans, neonates, or lactating bitches with puppies?","a":"Foster"},{"type":"card","domain":"General","sub":"General","q":"Nursing bitches should be vaccinated with MLV DA2PP.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How much weight should a neonatal puppy gain daily?","a":"1-1.5g/day/lb adult weight"},{"type":"card","domain":"General","sub":"General","q":"What ambient temp is recommended for orphan puppies?","a":"85-95F for week 1 then drop by 5F every week til 70F at week 4"},{"type":"card","domain":"General","sub":"General","q":"How early can orphan puppies be weaned to food?","a":"3 weeks"},{"type":"card","domain":"General","sub":"General","q":"Standards for caring for debilitated animals in the shelter can be expected to be the same as those being cared for at a vet hospital. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Current trends in dog housing call for _____ first, and then if suitable, possible _____ for longer term stays.","a":"Individual housing, Group housing"},{"type":"card","domain":"General","sub":"General","q":"__________ should meet individual animal's physical needs, meet behavioral needs, be durable and secure, and readily cleaned/disinfected.","a":"Housing"},{"type":"card","domain":"General","sub":"General","q":"There are simple recommendations for space requirements for individual dog housing. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are two ways dog size is used to regulate floor space requirements in legal codes?","a":"Weight and height at shoulder"},{"type":"card","domain":"General","sub":"General","q":"AWA standards apply to animal shelters. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Some jurisdictions require dogs be provided with daily exercise. T/F","a":"True- NJ and CO"},{"type":"card","domain":"General","sub":"General","q":"How do sanitation needs dictate staff #s?","a":"Must have enough staff to properly clean/disinfect so animals spend majority of time in clean kennels."},{"type":"card","domain":"General","sub":"General","q":"Why is feeding the same diet daily recommended?","a":"reduces stress, inappetance, and GI irritation"},{"type":"card","domain":"General","sub":"General","q":"Diets for dogs and cats should have what on the label?","a":"AAFCO statement of nutritional adequacy, and a current expiration date"},{"type":"card","domain":"General","sub":"General","q":"Where should a shelter look to see if the dog food they're feeding has been recalled?","a":"FDA website and AVMA"},{"type":"card","domain":"General","sub":"General","q":"Large chested dogs should be fed ______ to try to prevent ______.","a":"Twice daily, GDV"},{"type":"card","domain":"General","sub":"General","q":"Active ______ ______ is one of the most fundamental tools a shelter can use to save lives, preserve health, provide care, and help solve the problems that bring animals into shelters in the first place.","a":"Population management"},{"type":"card","domain":"General","sub":"General","q":"What two factors does population management use to help focus on and solve problems in the shelter?","a":"Assessment of risk and evaluation of resources"},{"type":"card","domain":"General","sub":"General","q":"What is the most common adverse outcome risk identified in animal shelters?","a":"Death by euthanasia"},{"type":"card","domain":"General","sub":"General","q":"Longer stays in the shelter have been known to increase risk of _______.","a":"shelter-acquired illness."},{"type":"card","domain":"General","sub":"General","q":"How can risk of shelter death be addressed in the shelter?","a":"Identifying target problems, then putting plans in place to solve or minimize them."},{"type":"card","domain":"General","sub":"General","q":"In addition to managing risk in the shelter population, interventions in the ______ can decrease risk for animals.","a":"source community"},{"type":"card","domain":"General","sub":"General","q":"C4C uses a ______ approach to understand the overall ability or appropriateness of an environment to provide for the needs of its inhabitants.","a":"Multifactorial"},{"type":"card","domain":"General","sub":"General","q":"The capacity to provide humane care has ____ for every organization.","a":"limits"},{"type":"card","domain":"General","sub":"General","q":"Shorter stays lead to decreased daily population, and a smaller daily population may lead to ______.","a":"Shorter stays."},{"type":"card","domain":"General","sub":"General","q":"______ ______ is a means of actively tracking each animal's shelter stay from the moment they enter the shelter to the moment they leave.","a":"Pathway planning"},{"type":"card","domain":"General","sub":"General","q":"How often should an animal's pathway plan be evaluated?","a":"Daily"},{"type":"card","domain":"General","sub":"General","q":"What animals should probably be assigned to the fast-track?","a":"kittens, friendly small-medium sized dogs"},{"type":"card","domain":"General","sub":"General","q":"What should be done with an animal in the fast-track that doesn't get adopted in 2 weeks?","a":"Moved to slow track."},{"type":"card","domain":"General","sub":"General","q":"Fast track and slow track should be considered as ___ ____ populations.","a":"two separate"},{"type":"card","domain":"General","sub":"General","q":"Fast track housing can be less enriched than slow track housing T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is open selection?","a":"Allowing viewing and adoption application for animals not yet \"released.\" Allows pts to move out of the shelter as soon as they are eligible."},{"type":"card","domain":"General","sub":"General","q":"What must customers adopting \"open selection\" pets be informed of?","a":"That the owner may reclaim the pet and they may not get to adopt it."},{"type":"card","domain":"General","sub":"General","q":"When should S/N be performed in open selection model?","a":"Legally, the day they become the shelter's property. The adopter can p/u after sx."},{"type":"card","domain":"General","sub":"General","q":"What are two types of \"scheduled intake?\"","a":"Intake by transfer, and intake by appointment"},{"type":"card","domain":"General","sub":"General","q":"What is \"selective intake?\"","a":"Intake by animal trait, eg breed."},{"type":"card","domain":"General","sub":"General","q":"Projections for the future can be made by evaluating _______ intake and outcome info, along with current trends.","a":"past - fair amount of consistency if programs/demographics remain the same."},{"type":"card","domain":"General","sub":"General","q":"According to the Marsh book (Replacing Myth with Math...), what two things are correlated and what aren't: intake, euthanasia, adoption?","a":"Intake was strongly related to euthanasia rate (eg reduce intake = reduce euthanasia). Adoption rate was NOT related to euthanasia rate. (decreased euthanasia rate didn't correlate with more adoptions)"},{"type":"card","domain":"General","sub":"General","q":"About how many people feed \"feral\" cats?","a":"8-26%"},{"type":"card","domain":"General","sub":"General","q":"Which is more effective to reduce FeLV in a feral cat population- test and remove, or TNR?","a":"TNR (Crawford/Levy 2004)"},{"type":"card","domain":"General","sub":"General","q":"Which varies more: adoption rate/capita or shelter intake rate/capita?","a":"Intake rate. Adoption rate was around 15/1000 people, with intake from 10-140/1000 people (Maddie's fund 2011)"},{"type":"card","domain":"General","sub":"General","q":"Attacking the overpopulation problem from both sides-- ______- and ________ is essential for progress.","a":"intake reduction and increase live release"},{"type":"card","domain":"General","sub":"General","q":"What helps assure nothing is overlooked during daily rounds (2)","a":"Systematic walk-through and checklist of action items."},{"type":"card","domain":"General","sub":"General","q":"What are three ways to solve the \"insufficient # housing units in holding\" problem?","a":"Decrease stray intake, build more housing, decrease holding time"},{"type":"card","domain":"General","sub":"General","q":"What two factors should be separated in capacity calculations?","a":"Species and age category."},{"type":"card","domain":"General","sub":"General","q":"What two areas should housing capacity be calculated for?","a":"Holding and adoptions"},{"type":"card","domain":"General","sub":"General","q":"What two activities should staffing capacity be calculated for?","a":"Daily care (cleaning/enrichment) and Flow-through activities (BE, Intake exam, Sx, Processing, etc)"},{"type":"card","domain":"General","sub":"General","q":"What is the equation for required holding capacity?","a":"RHC = monthly daily average intake (hx) x req. holding period (legal)"},{"type":"card","domain":"General","sub":"General","q":"what is the equation for adoption driven capacity?","a":"ADC = monthly daily average adoptions (hx) x target average length of stay (you decide)"},{"type":"card","domain":"General","sub":"General","q":"Is it more important to calculate monthly daily averages vs yearly daily averages for cats or for dogs?","a":"Cats- intake varies by month. Dogs not so much."},{"type":"card","domain":"General","sub":"General","q":"What is a good target length of stay in adoption (when holding is not visible to public?)","a":"10 days (span 2 weekends)"},{"type":"card","domain":"General","sub":"General","q":"What is a good target length of total stay when holding areas are visible to the public?","a":"14 days (7 holding, 7 in adoptions)"},{"type":"card","domain":"General","sub":"General","q":"What is the equation for staff hours required for daily care?","a":"Staff time (hrs) = average minutes needed for to care for one animal x average daily population/60 minutes/hr"},{"type":"card","domain":"General","sub":"General","q":"What is the equation for staff capacity for daily care?","a":"SC = minutes of paid daily staff time/avg minutes of care needed per animal per day"},{"type":"card","domain":"General","sub":"General","q":"How many minutes are needed/animal/day for care per NACA?","a":"15 for basic cleaning and feeding"},{"type":"card","domain":"General","sub":"General","q":"What is the equation for average staff time needed for FTA (flow-through activity)?","a":"Average daily time (in hrs) need for FTA = average minutes to do one animal's FTA x monthly daily average population/ 60min/hr"},{"type":"card","domain":"General","sub":"General","q":"At the individual animal level, ______ is the paramount method for recognizing deficiencies in the animal's care as desired by that animal.","a":"QoL assessment"},{"type":"card","domain":"General","sub":"General","q":"What is McMillan's working definition of Quality of Life?","a":"The animal feels good and enjoys life."},{"type":"card","domain":"General","sub":"General","q":"Quality of Life can be defined as:","a":"The balance of good and bad feelings experienced by the animal in the near term."},{"type":"card","domain":"General","sub":"General","q":"In general, _____ abuse is seen as less important than _____ abuse; the same is true of suffering in children and animals.","a":"emotional; physical"},{"type":"card","domain":"General","sub":"General","q":"There is scientific evidence that shows ______ may induce greater suffering than physical pain.","a":"emotional pain"},{"type":"card","domain":"General","sub":"General","q":"To measure an animal's QoL, what should be used?","a":"A variety of behavioral measures"},{"type":"card","domain":"General","sub":"General","q":"In determining QoL, behavior ____ and _____ should be assessed, since spending too long in a \"normal\" activity may be abnormal.","a":"quality and quantity"},{"type":"card","domain":"General","sub":"General","q":"One way to measure QoL is to measure ____, since it can be assumed to reflect the negative feelings of an animal.","a":"Stress"},{"type":"card","domain":"General","sub":"General","q":"There is frequently good correlation between cortisol levels and stress behaviors in dogs.","a":"False- behaviors are often non-specific"},{"type":"card","domain":"General","sub":"General","q":"What helps a person recognize a \"good\" QoL?","a":"The animal displays the full range of normal species behaviors (enjoys life)"},{"type":"card","domain":"General","sub":"General","q":"What are some \"red flags\" for recognizing very poor QoL?","a":"If balance unpleasant feelings>pleasant feelings, if there is very little time spent feeling pleasant, and if there is no ability to experience \"fun\""},{"type":"card","domain":"General","sub":"General","q":"As of SM2, how many states had licensing requirements for animal shelters?","a":"17.0"},{"type":"card","domain":"General","sub":"General","q":"In addition to the organization's mission, setting the program and planning goals, providing direct funding and other resources, and developing a community communication link, what are 2 jobs of the board of directors of a 501(c)3?","a":"Establishing fiscal policy, and hiring/firing the ED"},{"type":"card","domain":"General","sub":"General","q":"Boards of directors should engage in the day-to-day operations of the non-profit organization. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Boards of directors should engage in hiring all staff. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Boards of directors should always consult staff before making detailed programmatic decisions. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Puppy mill laws may impact shelters. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"A non profit's BoD, the ED, and any principal employee (eg the staff vet) are \"stewards of the public trust.\" T/F","a":"True- this means they are 'trusted' to carry out the charitable mission and so receive tax exemption, concessions and immunities."},{"type":"card","domain":"General","sub":"General","q":"Non profits are prohibited from participation in any political campaign. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"The non-profit's Form 990 must be on display and available to the public at all times. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"One way for organizations to mitigate financial risk is to buy:","a":"Insurance"},{"type":"card","domain":"General","sub":"General","q":"Shelter vets should have to worry about liability insurance if the shelter has general liability insurance. T/F","a":"False- should have liability insurance anyway"},{"type":"card","domain":"General","sub":"General","q":"What can help shield a shelter from liability from individual claims?","a":"Waivers and release forms"},{"type":"card","domain":"General","sub":"General","q":"Every state practice act includes a stipulation for a _____ before providing care.","a":"VPCR"},{"type":"card","domain":"General","sub":"General","q":"The AVMA defines a VPCR with three criteria. These are:","a":"The vet agrees to take responsibility and client has agreed to follow directions, the vet has sufficient knowledge of the animal, its care and keeping, and the vet is readily available or has made plans for emergency tx or follow-up if something goes wrong"},{"type":"card","domain":"General","sub":"General","q":"What is a veterinary practice act?","a":"Each state has one to define what is considered \"practicing veterinary medicine\"  and who can perform what under what circumstances."},{"type":"card","domain":"General","sub":"General","q":"At the time of SM2 publication, how many states required euthanasia certification?","a":"32 states certify shelters, 16 others certify specific people."},{"type":"card","domain":"General","sub":"General","q":"At the time of SM2 publication, how many states allowed access to ketamine without a vet on premises?","a":"26.0"},{"type":"card","domain":"General","sub":"General","q":"At what point in time does an animal no longer remain the property of the shelter?","a":"At the signing of the adoption contract."},{"type":"card","domain":"General","sub":"General","q":"In some states, foster homes must be individually licensed T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"In order to decrease a shelter's liability in case an adopted animal harms/infects someone/something, what should be done at time of adoption?","a":"Full disclosure of all known hazards (medical, behavioral, exposure, etc) and have new owners sign a waiver."},{"type":"card","domain":"General","sub":"General","q":"What is the most frequent cause of staff conflict?","a":"lack of clear communication"},{"type":"card","domain":"General","sub":"General","q":"What is one way to improve task-based communication?","a":"Say everything twice but in different ways"},{"type":"card","domain":"General","sub":"General","q":"What helps relieve stress of euthanasia disposition?","a":"Making it a collective decision (or at least 2 people from different departments)"},{"type":"card","domain":"General","sub":"General","q":"What is one way to improve staff training and morale, that also works to train animals?","a":"Positive reinforcement"},{"type":"card","domain":"General","sub":"General","q":"What question should be asked of previous employers when hiring new staff?","a":"\"would you hire this person again?"},{"type":"card","domain":"General","sub":"General","q":"What is essential for new hire success?","a":"Time for proper training"},{"type":"card","domain":"General","sub":"General","q":"Staff evaluations should be a standard practice (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"One way to influence staff politics as a veterinarian is merely to get to know the people in charge. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What two things should a shelter vet have before speaking to the media about shelter business?","a":"Permission to speak and a script"},{"type":"card","domain":"General","sub":"General","q":"Most reporters want to represent the truth, not to sensationalize. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Media interviews should be avoided at all cost T/F","a":"False- interviews can be an opportunity to present accurate information from the shelter perspective"},{"type":"card","domain":"General","sub":"General","q":"You should always assume you are being taped when talking to a reporter. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How should you structure a media interview script?","a":"Say the most important things first. Give direct answers to direct questions."},{"type":"card","domain":"General","sub":"General","q":"It's best to say \"no comment\" when giving interviews. T/F","a":"False- best to explain why you can't answer."},{"type":"card","domain":"General","sub":"General","q":"Shelter vets should sell themselves to local practitioners at the VMA. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Local veterinarians should be invited to the shelter to see how things work. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Cleaning is a __ step process.","a":"3: mechanical removal, cleaning with soap/detergent, and disinfecting"},{"type":"card","domain":"General","sub":"General","q":"Ironically, _____ may be an activity that spreads disease if not done properly.","a":"cleaning"},{"type":"card","domain":"General","sub":"General","q":"What is the proper order of cleaning animal cages?","a":"young animals, healthy adoptable, healthy stray, quarantine, then isolation/sick"},{"type":"card","domain":"General","sub":"General","q":"Animals may be allowed to run loose during cleaning for enrichment. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"One side cages are preferred over two side for cleaning ease. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Performed correctly, ______ _______ saves time, reduces chemical use, reduces the potential for fomite disease transmission, and decreases stress.","a":"Spot cleaning"},{"type":"card","domain":"General","sub":"General","q":"Laundry contaminated with which 3 diseases should be discarded per sanitation chapter in SM2?","a":"Parvo, panleuk, and RW. (I'd replace RW with distemper)"},{"type":"card","domain":"General","sub":"General","q":"In general, a stronger concentration of a disinfectant will kill more organisms more quickly. T/F","a":"False- use manufacturer's directions to mix."},{"type":"card","domain":"General","sub":"General","q":"Biguanides can be toxic to _____ and should not be used to clean their enclosures.","a":"Fish"},{"type":"card","domain":"General","sub":"General","q":"Why not use aldehydes to clean shelters?","a":"They're carcinogenic"},{"type":"card","domain":"General","sub":"General","q":"Quats are good for what step of the cleaning process?","a":"Step 2: soap"},{"type":"card","domain":"General","sub":"General","q":"What type of disinfectant is bruclean?","a":"Sodium dichloroisocyanurate (NDCC)- acts like bleach but less corrosive to metal"},{"type":"card","domain":"General","sub":"General","q":"No matter what disinfectant your shelter decides to use, _____ should be maintained for each.","a":"MSDS"},{"type":"card","domain":"General","sub":"General","q":"Clothing and shoes worn in the shelter should not be worn _____.","a":"home"},{"type":"card","domain":"General","sub":"General","q":"Footbaths are recommended (if used properly) in SM2 T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"There are six steps recommended before undertaking a revision project in the shelter. These include: explain what is currently present with pros/cons, describe the goal for changes, use current animal flow data to show need/impact of change, explain how this fits in with the rest of the shelter's operations, and two others. What are they?","a":"Explain how it will affect human traffic and any concerns, and creating a plan."},{"type":"card","domain":"General","sub":"General","q":"What calculations should be made for size of a new shelter by animal served?","a":"4-6sq feet/healthy animal and 6-9sq feet/animal with special needs"},{"type":"card","domain":"General","sub":"General","q":"Sustainably designed shelters can save ___ in water use and electricity bills.","a":"35-40%"},{"type":"card","domain":"General","sub":"General","q":"Holding a clean-up day where your shelter disposes of large clutter can help shelters create a welcoming appearance and increase efficiency. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How can you make dilapidated hallways more appealing?","a":"Adding a tall wainscotting with porcelain tiles"},{"type":"card","domain":"General","sub":"General","q":"Starting a shelter upkeep project without a master plan is encouraged if you can't find a meeting time with the ED.","a":"0"},{"type":"card","domain":"General","sub":"General","q":"How can you get maximum flexibility in shelter housing (ex, in case of an outbreak)?","a":"Design pods on common areas instead of large rooms"},{"type":"card","domain":"General","sub":"General","q":"Facilities should be designed to optimize efficient cleaning and feeding and animal access. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Surgery, isolation and medical examination areas should be near receiving. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Each enclosure for dogs should be a separate room off of a vestibule. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"The medical suite should include its own kitchen. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the four major factors in building design that impact animal health?","a":"space, sound, light, and air"},{"type":"card","domain":"General","sub":"General","q":"Cats need more space than most commercial housing systems allow. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Double sided housing is preferred in holding; large single units are preferable in adoption area. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How much space should be provided per dog?","a":"35-64sq feet"},{"type":"card","domain":"General","sub":"General","q":"Boxier shaped rooms are easier to build, clean, and slope to drain. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is a convenient design for dog walking?","a":"Back door access to runs, leash cubbies"},{"type":"card","domain":"General","sub":"General","q":"Provide a \"tie out\" in the hall adjacent to each kennel per SM2.","a":"True but false?"},{"type":"card","domain":"General","sub":"General","q":"Indoor/outdoor units are costly and waste energy. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What type of doors are recommended if designing indoor/outdoor runs?","a":"Guillotine-type panels or insulated gasketed doors."},{"type":"card","domain":"General","sub":"General","q":"What two facilities design elements are recommended for SMAM rooms?","a":"Flexible shelving for different cage sizes, and easy access to outlets for heating lamps/filters/etc."},{"type":"card","domain":"General","sub":"General","q":"\"Sniff holes\" in glass enclosures are great for socialization and training, and actually decrease ______.","a":"Barking"},{"type":"card","domain":"General","sub":"General","q":"Shelters should maximize the use of artificial light. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Authors recommend _____ventillation for people and ______ ventilation for animal enclosures.","a":"natural, mechanical"},{"type":"card","domain":"General","sub":"General","q":"what is one popular energy efficient kennel heating technique?","a":"radiant floor heat (water pipes)"},{"type":"card","domain":"General","sub":"General","q":"HEPA filters are recommended all over the shelter. T/F","a":"False- only in surgery"},{"type":"card","domain":"General","sub":"General","q":"Thermostats should be locked to prevent from tampering. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the foremost unacceptable floor surfaces for a shelter?","a":"paint, epoxy, wood, vinyl"},{"type":"card","domain":"General","sub":"General","q":"What are the best floor surfaces for a shelter?","a":"concrete, terrazzo, welded rubber"},{"type":"card","domain":"General","sub":"General","q":"Carpet tiles are an acceptable flooring for parts of the shelter. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Antimicrobial additives are available for concrete flooring. T/F","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Welded rubber can be used as a comfortable surface in dog housing. T/F","a":"False- dogs will dig it up and eat it."},{"type":"card","domain":"General","sub":"General","q":"Walls are the second most challenging surface to cover in a shelter, after ____","a":"flooring."},{"type":"card","domain":"General","sub":"General","q":"When picking a porcelain tile for floor or wall, what characteristic should be used?","a":"Make the tile as large as possible to reduce joint surface area"},{"type":"card","domain":"General","sub":"General","q":"Shelters need to function like hospitals, be as durable as prisons, be resistant to water, disinfectant and detergent damage, yet also be _________.","a":"attractive and welcoming to adopters."},{"type":"card","domain":"General","sub":"General","q":"Who started the ASPCA in 1866?","a":"Henry Bergh"},{"type":"card","domain":"General","sub":"General","q":"When did the ASPCA take over handling stray animals in NYC?","a":"1894.0"},{"type":"card","domain":"General","sub":"General","q":"Who opened the first \"humane\" animal shelter in Pennsylvania in 1868?","a":"Caroline Earle White"},{"type":"card","domain":"General","sub":"General","q":"What was the early focus of the AHA?","a":"livestock transport"},{"type":"card","domain":"General","sub":"General","q":"Who started HSUS in 1954 as a reaction to AHA focus on sheltering and not vivisection or hunting?","a":"Fred Myers."},{"type":"card","domain":"General","sub":"General","q":"What is the difference between SAWA (society of animal welfare administrators) and NFHS (national federation of humane societies)?","a":"SAWA has individual members, and NFHS has member organizations."},{"type":"card","domain":"General","sub":"General","q":"What is the critical statistical measure of shelter performance?","a":"The LRR"},{"type":"card","domain":"General","sub":"General","q":"Who \"fathered\" the no-kill movement by writing a letter in 1989?","a":"Ed Duvin"},{"type":"card","domain":"General","sub":"General","q":"What cornerstone has proven the most effective for reducing shelter intake over the last 30 years?","a":"Spay/neuter"},{"type":"card","domain":"General","sub":"General","q":"What is the cat owner recovery rate (not the RTO rate for shelters)?","a":"Around 50%"},{"type":"card","domain":"General","sub":"General","q":"What is the dog owner recovery rate (not the RTO rate)?","a":"Around 75%"},{"type":"card","domain":"General","sub":"General","q":"Who hosted the Adoption Forum I, and basically invented \"open adoptions?\"","a":"AHA"},{"type":"card","domain":"General","sub":"General","q":"People who adopt animals for free are less committed to them than those who paid a fee. T/F","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What three frequencies do microchips work at?","a":"125kHz, 128kHz, and 134.2kHz"},{"type":"card","domain":"General","sub":"General","q":"Which microchips are the most \"findable\" with modern scanners?","a":"134.2kHz"},{"type":"card","domain":"General","sub":"General","q":"RTO rates for chipped vs non-chipped cats are:","a":"1.8%->38.5%"},{"type":"card","domain":"General","sub":"General","q":"What are three critical steps for microchips to be successful identification?","a":"Proper implantation, proper scanning technique, proper registration"},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"What % of patients undergoing OHE for pyometra die despite appropriate therapy?","a":"5-8% (57% if uterine rupture). Prognosis following surgery is good if abdominal contamination is avoided, shock and sepsis are controlled and renal damage is reversed by fluid therapy and bacterial antigen elimination."},{"type":"card","domain":"General","sub":"General","q":"How do cortisol levels correlate to observed dog behaviors/personalities?","a":"hunched posture (at dog park) correlates to higher levels of cortisol, but no other behaviors or personality types had any correlation, though scored personality types did correlate with observed behaviors (duh)."},{"type":"card","domain":"General","sub":"General","q":"Does positive attitude and handling (by people toward shelter dogs) have any validity in predicting how likely a dog is to approach people through the kennel door?","a":"Yes, Pos attitude/handling correlate to increase willingness to approach unknown person."},{"type":"card","domain":"General","sub":"General","q":"In Duffy et al 2014, how likely were surrendering owners to give unreliable or biased response on the CBARQ?","a":"No consistent evidence of unreliable or biased responses, owner provided info correlated well with shelter staff assessments of aggressive and nonaggressive dogs in shelter.  Surrendering owners and adopting owners  revealed sign correlations in observed behaviors in adopted dogs for 3 traits: stranger aggression, chewing inappropriate objects, and urination when left alone."},{"type":"card","domain":"General","sub":"General","q":"In Duffy et al 2014 how did owner provided info in the CBARQ correlate to eventual outcome?","a":"High discrimination (CBARQ matched outcome)"},{"type":"card","domain":"General","sub":"General","q":"Bennett et al 2015: Using SAFER, how did behavioral assessments of the same dog compare on day 0 vs day 3?  What is recommendation for when to do in shelter behavior assessment?","a":"Agreement on all subtests of SAFER was highly variable on day 0 vs day 3. Timing of assessment should be based on welfare of individual dog, and dogs showing signs of severe stress should not be tested."},{"type":"card","domain":"General","sub":"General","q":"Eken Asp 2015: T/F- In surveys from dog owners, breed was one trait that had significant effects on many everyday behavior traits.","a":"T. Age and sex also did. Working breeds 10% more trainable, 30% more playful, and 10-60% less fearful (but people are stupid about understanding dogs, so how valid is this??). Fearful dogs were more aggressive (shocker) while more social dogs were less fearful and less aggressive (would that not be the definition of a more social dog?!)"},{"type":"card","domain":"General","sub":"General","q":"Haverbeke 2015:  What factors in the field limit the utility of canine behavioral evaluations?","a":"Lack of time, finances. Only 1 validated  behavior eval was identified."},{"type":"card","domain":"General","sub":"General","q":"Mornemont 2015: What was the overall predictive validity of the Beh Assessment for Rehoming K9s (BARK) protocol? What behaviors were best predicted?","a":"relatively poor based on in shelter assessment compared to post adoption surveys of adopters. Behaviors best predicted included \"fearful/inappropriate toileting\" and anxiety. However, in general, neither problem behaviors nor aggression were not predicted."},{"type":"card","domain":"General","sub":"General","q":"Rayment 2015: What is the conclusion about interpreting battery beh tests in animal shelters?","a":"\"interpreted within the limitations of the context in whcih they are performed,, and test developers should consider other methods which personality may be assessed within the shelter environment.\""},{"type":"card","domain":"General","sub":"General","q":"THE FAKE DOG STUDY, Shabalansky 2015: How much aggreement in observed behaviors was there in a dog presented with a fake dog in one test, and a live dog in a separate test? Dogs were categorized by behavior traits (friendly, aggressive, fearful) based on observed behaviors.","a":"There was high agreement for dogs categorized as friendly. Aggressive trait showed terrible agreement, fearful trait moderate agreement. Conclusion: You make be able to trust assessment based on fake dog for friendly dogs, but not for anyone else."},{"type":"card","domain":"General","sub":"General","q":"Gilber-Gregory 2016: Does traz reduce stress related signs and behaviors in hospitalized dogs?","a":"Yes, it sure does."},{"type":"card","domain":"General","sub":"General","q":"Dean 2017:  Oromucosal application of ______ may reduce the signs of fear and anxiety in some dogs with noise associated phobias","a":"dexmeditomidine"},{"type":"card","domain":"General","sub":"General","q":"Conley 2014:  T/F: Dogs receiving 2 min of pos daily human contact (HC) or  HC+ toys were more likely to approach the kennel door when a person was at the gate.","a":"T."},{"type":"card","domain":"General","sub":"General","q":"Barrera 2015: When presented with a food puzzle today _______ (choose pet dogs or shelter dogs) spent longer interacting with the object, while the ____________ (choose pet dogs or shelter dogs) spent more time gazing at the nearby person.","a":"When presented with a food puzzle todaypet dogs spent longer interacting with the object, while the shelter dogs spent more time gazing at the nearby person."},{"type":"card","domain":"General","sub":"General","q":"Patronek 2016: Of dogs who do not appear obviously dangerous prior to performing a behavioral evaluation, most dogs with a \"positive\" result (a problem found on eval) will be false positives. Why?","a":"Because even in shelters the prevalence of aggressive behaviors is low, so mathematically most positive tests will be false positives."},{"type":"card","domain":"General","sub":"General","q":"Patronek 2016: Since behavior evals are \"no better than flipping a coin,\" what is suggested as a replacement for behavior evals?","a":"Use time saved not performing evals to spend time interacting with dogs in normal and enjoyable ways."},{"type":"card","domain":"General","sub":"General","q":"Mohan-Gibbons 2018: When food guarding was excluded from standard shelter behavior evaluations, what happened to the number of bites to people? What happened to the number of adoptions? What happened to the number of returns to the shelter?","a":"No change to bites to people. Adoptions increased b/c fewer dogs were identied with food guarding behavior. \"No significant difference in the rate of returns of food guarding dogs.\""},{"type":"card","domain":"General","sub":"General","q":"Hall et al 2014: T/F: Attention from a person has no effect on expression of stereotypic behaviors in dogs.","a":"F. Attention from the owner can reinforce and maintain high rates of stereotypic behaviors."},{"type":"card","domain":"General","sub":"General","q":"Marder 2013: Dogs identified as having food aggression the shelter were  _____ (choose more, equally, less) likely to show vs not show food aggression after adoption.  Dogs not identified as having food aggression in the shelter were   _____ (choose more, equally, less) likely to show vs not show food aggression after adoption. Adopters ______ (did or did not) consider food aggressive behaviors after adoption to be a significant problem.","a":"Dogs identified as having food aggression the shelter were  equally likely to show vs not show food aggression after adoption (55% showed food aggression).  Dogs not identified as having food aggression in the shelter were less likely to show vs not show food aggression after adoption (22% showed food aggression). Adopters did not consider food aggressive behaviors after adoption to be a significant problem."},{"type":"card","domain":"General","sub":"General","q":"Cooper 2014: T/F: Dogs trained using electronic shock collars compared to those trained without shock collars spent more time tense, yawned more often, and engaged in less environmental interaction.","a":"T. No diffs in cortisol, no sig diffs in reported efficacy across groups. But owners of dogs trained with shock collars were less confident in applying th training technique going forward."},{"type":"card","domain":"General","sub":"General","q":"Herron 2014: T/F: 5 minutes of pre adoption couseling to prevent separation anxiety showed a significant effect on the prevention of separation anxiety.  T/F: Having another dog in the home was protective against the development sep anxiety post adoption","a":"F- 5 min of adoption counseling to prevent sep anx did not have any effect . F. Presence of another dog in the home was not protective for development of sep anx."},{"type":"card","domain":"General","sub":"General","q":"Dudley 2015: T/F: Petting shelter dogs for 30 min per day was a magic bullet preventing fecal shedding and reducing blood cortisol concentration","a":"F.  Among shelter dogs, those that got 30 min petting session did have lower blood cortisol levels, but no sig difs in fecal parasite shedding or WBC counts."},{"type":"card","domain":"General","sub":"General","q":"Starinsky 2017: T/F Escape rate, but not biting history, was associated with the method used to confine the dog on their property (fence, electric fence, tethering)","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Gourkow 2014: For ANXIOUS cats in Gentled group, how did the rates of URI pathogen shedding change over time? How did rates change over time in the control group? Which group was more likely to develop signs of URI over time?","a":"Control group increased from d 1 to 10. Gentled group remained stable. Control group was sig more likely to develop signs of URI."},{"type":"card","domain":"General","sub":"General","q":"Gourkow 2014: Which correlated better to observed behavior patterns in shelter cats? Fecal IgA or fecal cortisol?","a":"Fecal IgA (sig higher in happy/friendly cats vs stressed)"},{"type":"card","domain":"General","sub":"General","q":"Stella 2014: 1) T/F Caged cats exposed to a routine, predictable caretaking schedule were less likely to hide or show sickness behaviors over time and were more affiliative compared to cats exposed to an unpredictable schedule, regardless of the level of enrichment provided in the cages (availability of hiding spots or perches).","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Arhant 2015: 1) In group housed cats, insuffient numbers of resting areas and hiding spaces  (was or was not) associated with thin body condition. 2) In group housed cats poor coat condition (was/was not) correlated with longer LOS, lower numbers of litterboxes, and bad smells.","a":"1) In group housed cats, insuffient numbers of resting areas and hiding spaces  was associated with thin body condition. 2) In group housed cats poor coat condition was correlated with longer LOS, lower numbers of litterboxes, and bad smells.  \"Our results show that simple animal based parameters can give an indication of how well cats cope with their environent and suggest that the use of these parameters could be beneficial for cat welfare.\""},{"type":"card","domain":"General","sub":"General","q":"Gourkow 2015:For CONTENT cats in Gentled group, how did the rates of URI pathogen shedding change over time? How did rates change over time in the control group? Which group was more likely to develop signs of URI over time?","a":"Control group more likely to become frustrated or anxious, more likley to break with URI, shedding increased over time."},{"type":"card","domain":"General","sub":"General","q":"Snowdon 2015: T/F Cats showed a sig preference for and interest in species-appropriate music compared with music for humans","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Gourkow 2016: cats rated as FRUSTRATED at intake who received one 10 min training session per day for 10 days (compared to control group). What were effects on fecal IgA, respiratory disease, and contentment behaviors in the treatment group compared to the control group?","a":"Treatment group: more contentment, more IgA in poop, less URI."},{"type":"card","domain":"General","sub":"General","q":"Chadwin 2016: How did a diffused synthetic feline facial pheromone product affect cat stress scores in shelter housed cats? How did it affect URI rates in said cats?","a":"No effect on stress scores or URI incidence."},{"type":"card","domain":"General","sub":"General","q":"Kogan 2017:  Which of the following variables correlated to learning in clicker training sessions with shelter cats? Age, sex, food motivation.","a":"Age/sex no correlation. Food motivation correlated with greater gains in learning."},{"type":"card","domain":"General","sub":"General","q":"van Haaften 2017: T/F Gabapentin administered 90 min prior to transportation  and vet examination did not have any affect on owner-reported stress scores.","a":"F. Stress scores were sig lower in gaba group vs control groups. Sedation, ataxia, hypersalivation, and vomiting were also seen but resolved within 8 hours."},{"type":"card","domain":"General","sub":"General","q":"Stevens 2016: What was the most commonly reported adverse effect in cats receiving 50 mg trazodone PO prior to transport to vet exam?","a":"Signs of sleepiness. No change on physiologic variables."},{"type":"card","domain":"General","sub":"General","q":"Porters 2014: Which variable had the greatest association with the development of problem behaviors in shelter cats up to 24 months post adoption? Early age gonadectomy (8-12 weeks) or the use of punishment by the owner?","a":"The use of punishment by the owner. Age at gonadectomy had no association."},{"type":"card","domain":"General","sub":"General","q":"Broadley 2014: Which cats showed greater stress scores in the first 4 days in the shelter (in individual cages): cats from single cat households or cats from multicat households?","a":"Cats from single cat households had higher stress scores in the first 4 days."},{"type":"card","domain":"General","sub":"General","q":"Vinke 2014: While shelter cats with and without hiding boxes had equal stress scores by day 14 after intake, the cats who had hiding boxes reached this level by day _______ after intake","a":"While shelter cats with and without hiding boxes had equal stress scores by day 14 after intake, the cats who had hiding boxes reached this level by day 3 after intake, and this was when a statistically sig diff was seen in avg stress scores between cats with and without hiding boxes."},{"type":"card","domain":"General","sub":"General","q":"Wagner 2014: Dogs show a strong preference to eliminate (urine and feces) where in double compartment housing?","a":"Awa from the area where they eat, drink and sleep (75% of the time for feces and urine)"},{"type":"card","domain":"General","sub":"General","q":"Loberg 2016: T/F Increased the floor space (sq footage) for group housed catspromotes more play and general activity.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Addie 2015: Why are cats susceptible to toxicity from phenol based disinfectants and many essential oils?","a":"They lack the UDP-glucuronosyl transferase enzyme."},{"type":"card","domain":"General","sub":"General","q":"Bates 2015: Hypersalivation/drooling, tongue ulceration, hyperthermia and oral ulceration were the most commonly reported clinical signs associated with exposure to what common household disinfectant?","a":"Benzalkonium chloride (QAC)"},{"type":"card","domain":"General","sub":"General","q":"Crawford 2015: In a test assessing chlorhexidine, accelerated hydrogen peroxide, triclosan soap solution, and tap water for their ability to eliminated endotracheal tubes innoculated with Strep Zoo and Bordetella, which agent(s) were effective?","a":"Chlorhex > AHP > everything else. However elimination of all vegetative bacterial growth was not achieved for any of the treatments tested."},{"type":"card","domain":"General","sub":"General","q":"Moriello 2016: Which of the following methods were effective at decontaminating carpeting contaminated with M. canis spores? Vacuuming, use of a carpet shampooer, hot water extraction","a":"Vacuuming did not decontaminate carpet (hairs were gone but spores were not). Use of carpet shampooer x 2 was effective, hot water extraction was effective."},{"type":"card","domain":"General","sub":"General","q":"Moriello 2016: Which of the following is an effective method for decontaminating laundry contaminated with M. canis spores?  Hot water wash, cold water wash, with bleach, without bleach, with mechanical drying, without mechanical drying.","a":"Washing twice in cold water (no addition of bleach) was effective.  Do not overload the machine."},{"type":"card","domain":"General","sub":"General","q":"Levy 2014: In a targeted area 54% of the projected community cat population was neutered via trapping/neutering and return or removal for adoption. how did shelter cat impoundment compare in the target area compared to the non-target area?","a":"Impoundment in the target area (60 cats neutered/1000 residents) decreased by 66%, while it decreased only by 12% in the non-target area (12 cats neutered per 1000 residents. Per capita euth was also higher in non-target area."},{"type":"card","domain":"General","sub":"General","q":"Brown 2013: Which of the following variables had an effect on LOS for dogs in 2 NYC animal shelters? Age, coat color, breed,  sex, size","a":"Age (younger--> shorter LOS), breed (\"fighting breeds\" -> shorter vs guard breeds), medium size dogs--> longer LOS; coat color and sex had not association with LOS"},{"type":"card","domain":"General","sub":"General","q":"Kwan 2013: T/F In a study comparing owners relinquishing their dogs vs owners retaining their dogs, relinquished dogs were less likely to have attended a training class","a":"F. Both were equally likely to have attended training classes. Owners that used punishment methods in both goups were disatisfied with their dogs overall and leash walking behaviors. Pitties were no less well behaved compared with other breeds."},{"type":"card","domain":"General","sub":"General","q":"Calver 2013: Fighting and road accidents are lesser hazards to roaming cats than collars.","a":"F. Collars also offer compensatory benefits of mounting predation deterrents and ID tags."},{"type":"card","domain":"General","sub":"General","q":"Weiss 2013: T/F Dogs or cats received as a gift have an increased risk of relinquishment to animal shelters","a":"F"},{"type":"card","domain":"General","sub":"General","q":"Coe 2014: What are the top 3 reported reasons for relinquishment of companion animals to shelters?","a":"1) aggressive behaviors 2) moving/rental/housing issues 3) caretaker personal issues"},{"type":"card","domain":"General","sub":"General","q":"Dybdall 2014: T/F Adoptions perceptions of stray vs owner surrendered cats result in increased average LOS for stray cats vs surrendered cats","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Mohan-Gibbons 2014: T/F Evaluation of a novel program in which foster families were tasked with finding adopters for their foster dogs showed that dogs adopted through this program had a lower rate of returns","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Propatova 2014: What video recorded behaviors in kennel were associated with a longer LOS for dogs in shelters?","a":"Leaning or rubbing on enclosure wall, facing away from the front of the enclosure, standing, back and forth motion."},{"type":"card","domain":"General","sub":"General","q":"Brown 2015: What sex of cats/kittens had a shorter LOS? Male or female?","a":"Males"},{"type":"card","domain":"General","sub":"General","q":"Dolan 2015: Among a group of low income people relinquishing their dog to an animal shelter,  what 2 factors were associated with relinquishment?","a":"Cost (and being unaware of available resources), amount of stress in the home in the past 3 months was high"},{"type":"card","domain":"General","sub":"General","q":"Fatjo 2015: Among stray dogs entering animal shelters in Spain, dogs with a microchip were _____ (#) times more likely to be RTO.","a":"Three times more likely to be RTO if they had a chip"},{"type":"card","domain":"General","sub":"General","q":"Lancaster 2015: What proportion of stray microchipped cats and dogs entering a shelter had a problem with their microchip data? How did the RTO rates compare for chipped animals (no chip data problems) vs chipped animals (with data problems) vs not microchipped animals?","a":"37%. Specifically, most to least common: REgistered to prev owner or organization, all phone numbers incorrect or disconnected, chip not registered.  With chip/no data problem highest RTO > with chip/had data problems > no chip (dogs: 87% vs 69% vs 37%, cats 61% vs 33% vs 5%)"},{"type":"card","domain":"General","sub":"General","q":"Svoboda 2015: Which of the following factors were found to affect LOS and outcome for dogs in 2 shelters in pacific northwest? Coat color, age, breed identification","a":"Age and breed. Coat color (e.g. black dogs) did NOT. THUS, \"black dog syndrome\" ain't a thang."},{"type":"card","domain":"General","sub":"General","q":"Weiss 2015: In a random digit dial survey, of households that had rehomed a pet, was rehoming with a friend/family member or relinquishment to a shelter more common?","a":"Rehoming with a friend/family member was most common (37%) folllowed closely by relinquishment to a shelter."},{"type":"card","domain":"General","sub":"General","q":"Zito 2015: T/F: Post adoption surveys of Australians who adopted cats or kittens from an animal shelter showed that cats or kittens adopted during low cost adoption specials were more likely to be rehomed than those adopted at full adoption fees","a":"F. Adoption outcomes were generally positive for both adult cats and kittens, including those adopted durng adoption specials. Those who adopted adult cats were more motivated to do so by adoption specials than those who adopted kittens."},{"type":"card","domain":"General","sub":"General","q":"Alberthsen 2016: What was the sterilization rate of owner surrendered cats entering Australian RSCPA shelters?","a":"47% of owner surrendered cats were sterilized at time of surrender, which was a surprisingly low rate as this included some juridictions where sterilization is considered mandatory. The most common reason for owner surrender was cats not allowed in rental property."},{"type":"card","domain":"General","sub":"General","q":"Edinboro 2016: Why did URI prevalence increase in a San Jose animal shelter in the time period after a SNR program was implemented?","a":"Because they starting treating cats for URI instead of just euthing them.  Benefits post SNR included lower intakes, lower euth proportion, shorter avg LOS in shelter care, more cats could be treated for URI"},{"type":"card","domain":"General","sub":"General","q":"Protopopova 2016: Which factor  affected how often/how long shetler visitors spent looking at  shelter dogs in kennels? Morphology or training?","a":"Morphology. Training was effective at decreasing undesirable behaviors, but only morphology influenced visitor behavior. They spent more time visiting morphologically preferred dogs- puppies, long haired, small, certain breeds)"},{"type":"card","domain":"General","sub":"General","q":"Sinski 2016: Analysis of data from a Kentucky shelter (did or did not) show that black coat color was associated with outcome in shelter dogs.","a":"Entirely black dogs did have slightly lower odds of adoption (esp if small). However, breed category, breed size, and purebred status were more important factors."},{"type":"card","domain":"General","sub":"General","q":"Zito 2016: T/F many cats being surrendered to Aussie animal shelters as strays in fact had been cared for for some amount of time by surrenders","a":"T, labeled \"cat semiownership.\" People did not identify as owners, but they had been providing some care for the cat for some amount of time prior to surrender. This may be important when trying to mitigate shelter admissions"},{"type":"card","domain":"General","sub":"General","q":"Bir 2017: Are men or women more likely to feel that dogs should be acquired from an animal shelter?","a":"Women were more likely to feel that one should adopt a dog from a shelter (as opposed to getting from a diff source). Higher income also tended to go this way."},{"type":"card","domain":"General","sub":"General","q":"Fagre 2017: What were the most common reasons why Colorado shelter staff reported NOT vaccinating all incoming cats/dogs with core vax at intake?","a":"In order, 1) too young 2) pregnant 3) mild pre existing illness. Only 5/40 reported vax all animals at intake."},{"type":"card","domain":"General","sub":"General","q":"Janke 2017: Which of the following factors was associated with a shorter LOS (from time of ADMISSION) in cats? Implementation of C4C, exotic breed, male, kitten","a":"All of the above EXCEPT adults had a shorted LOS than kittens (b/c calc from time of admission- many kittens need time to grow!!). Shorter LOS: c4c, fancy, male, adult"},{"type":"card","domain":"General","sub":"General","q":"Karsten 2017: Increased adoption probability, decreased shelter death probability, fewer cats needing isolation  for infxs disease were some of the benefits seen in 3 shelters after implementation of  ______________ management model.","a":"capacity for care."},{"type":"card","domain":"General","sub":"General","q":"Kinsman 2017: What characteristics of owners were associated with them being less likely to redeem a neutering voucher issues by a cat welfare agency in the UK? Having/not having at least one litter prior to receiving voucher, being eligible/not being eligible for human service benefits, and renting/not renting","a":"Less likely to use neutering voucher = cat had at least one litter prior to owner receiving voucher, owner was eligible for human service benefits, owner rented or lived with familiy (aka not living in own home)"},{"type":"card","domain":"General","sub":"General","q":"Mozes 2017: In an Ontario shelter where 53% of admitted cats were euthanized in a given time period, what variables had statistically sig increased odds for euthanasia?","a":"-- euth more likely > euth less likely:\n-- surrender > stray (OR 38!)\n-- male > female (OR 1.63)\n-- black coat color >  other color (OR 1.45)\n-- unneutered > neutered, but neutered was highly associated with age\n-- LOS grt than 5 d > LOS less than 5d > LOS more than 20d"},{"type":"card","domain":"General","sub":"General","q":"Reese 2017: Which characteristics of dogs in Michigan animal shelters suggest a reduced adoption price may promote adoption? What characteristics suggest a premium price may be charged? (\"Hedonic pricing model\")","a":"Reduced adoption fees: mixed breed, older, black dogs\nPremium adoption fees: puppies, purebreds, \"value added\" (e.g. microchipped)"},{"type":"card","domain":"General","sub":"General","q":"Spehar 2017: An iconic TNR program in Newburyport Massachusetts showed that a population of community cats was essentially eliminated over _____ (#) years; ~1/3 were removed early on for adoption (highly sociable cats/kittens), and the remaining numbers were reduced by attrition over time.","a":"Attrition over 17 years"},{"type":"card","domain":"General","sub":"General","q":"Spencer 2017: T/F People from poor communities do not love their pets as much as people from more well to do communities.","a":"F. \"Pet abandonment can result when pet owners must prioritize human needs over animal needs, leading to increased shelter intake of stray dogs.\""},{"type":"card","domain":"General","sub":"General","q":"Patronek 2018: What factor increased the odds of live release for dogs, esp adult dogs, in a large open admission municipal shelter?","a":"Foster care. Returns also had increased odds of LR."},{"type":"card","domain":"General","sub":"General","q":"Sparks 2018: T/F Race and ethnicity were not primary determinants of vet service utilization (though they were meaningufl factors)","a":"T- based on retrospective analysis of PFL data"},{"type":"card","domain":"General","sub":"General","q":"McCarthy 2013: In a population model comparing T-vasectomy/spay-R vs TNR vs trap/remove, which strategy required the least proportion of cats to be captured to reduce or eliminate the cat population?","a":"The vasectomy model required the lowest proportion of cats to be captured.  TNR and trap/remove required >57% to be impacted before the population size was changed, while only at least 35% were needed to be captured in the vasectomy model.  To eliminate the pop over time, 57% needed to be captured in the vasectomy model, whle at least 82% needed to be captured in the TNR or trap/remove models."},{"type":"card","domain":"General","sub":"General","q":"Lord 2009:The most common reasons the owner of a microchipped stray could not be found were what?","a":"Incorrect/disconnected telephone number, no response to calls/letters, animal registered to another group. In chipped stray animals, 74% of dog owners were found and 63% of cat owners were found."},{"type":"card","domain":"General","sub":"General","q":"Lord 2008: In the US microchips can have what frequencies? For which of these was the sensitivity of a universal scanner lowest? Which frequency tends to have the highest sensitivity?","a":"Chips can be 125 kHz, 128 kHz, or 134.2. 125 resulted in the lowest sensitivities of the universal scanners. 134.2 (ISO standard) results in highest sensitivity."},{"type":"card","domain":"General","sub":"General","q":"Kogan 2013: T/F Cats or kittens with solid black fur required the longest times to adoption in 2 Colorado animal shelters.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Dingman 2014: T/F An online survey of vet clinics in the SE US showed that of clinics that offered microchipping services to clients, more relied on owners to register their chips than provided the service to clients","a":"T."},{"type":"card","domain":"General","sub":"General","q":"Amar 2014: T/F Dogs with diarrhea have a high prevalence of Campylobacter jejuni detected","a":"F. 6.3% of dogs with diarrhea had C jejuni (but isolates identical to those found making people sick, so still a relelvant zoonotic concern"},{"type":"card","domain":"General","sub":"General","q":"Andersen 2018: Of cats with and without diarrhea tested for enteropathogens, most had at least one. However, most pathogens were not associated with presence or absence of diarrhea, except which two pathogens?","a":"-- Tritrichomonas foetus and coronavirus were associated with cats with diarrhea."},{"type":"card","domain":"General","sub":"General","q":"Andersen 2018: How did management model (short term shelter, long term sanctary, foster care, or TNR) associate with the prevalence of enteropathogens detected in cats with and without diarrhea?","a":"-- Viral and protozoal infx most common in shetler, foster and sanctuary cats, while helminths more common in TNR"},{"type":"card","domain":"General","sub":"General","q":"Duijvestijn 2016: In pups < 12 mo old with or without acute diarrhea, what pathogens were associated with the presence of diarrhea?","a":"Parvo, coronavirus. E coli in a subset of pups with severe systemic disease. No association with diarrhea: salmonella, campy, c perf, c. diff, giardia, toxocara, cytoisospora, cyniclomyces guttulatus."},{"type":"card","domain":"General","sub":"General","q":"Dyer 2014: How many cases of human rabies were reported in the US in 2013? How many cases of canine? Feline? What animal species had the highest number of reported rabid animals?","a":"3 human cases, 89 dogs, 247 cats; raccoons had the highest overall number of cases."},{"type":"card","domain":"General","sub":"General","q":"Gerhold 2013: What animal accounts for ~1/3 of all human rabies PEP in the united states?","a":"Free roaming cats."},{"type":"card","domain":"General","sub":"General","q":"Han 2016: Surveillance for Staph bacteria carriage between people and cohabitating dogs showed that out of 107 households, in what proportion were identical strains were found in owners and their cohabitating dogs?","a":"None. One household had an identical staph spp identified, but they had different subtypes/antibiotic resistance and toxin profiles.  Conclsion: Staph bacteria are not shared between healthy dogs and their owners."},{"type":"card","domain":"General","sub":"General","q":"Lashnits 2018: In surveillance testing of >15000 serology samples submitted to NC state, what proportion of dogs had positive serology for Bartonella spp?","a":"3%. Slightly higher risk for intact male dogs, mixed breed, and dogs with pos results to other vector borne diseases."},{"type":"card","domain":"General","sub":"General","q":"Leahy 2016: What was the proportion of canine fecal samples that tested positive for Salmonella? Of those, what proportion were grossly normal (non diarrhea) samples?","a":"~5% of all samples were positive (from 7 shelters). 60% of these samples were grossly normal."},{"type":"card","domain":"General","sub":"General","q":"Leahy 2017: What proporation of canine fecal samples that tested positive for Campy?   Of those, what proportion were grossly normal (non diarrhea) samples? What proportion tested positive for C. jejuni (the zoonotic one)?","a":"76% of samples were positive, 70% of the positives were grossly normal (not diarrhea). 5% of samples were positive for C. jejuni"},{"type":"card","domain":"General","sub":"General","q":"Matthias 2015: What age group/sex had the higest overall incidence of dog bites reported in a FL county?","a":"Boys aged 6-14 years. \n-- Anyone > 6 yrs more likely to be bitten by unfamiliar dog\n-- Bites of unknown cause most common in kids < 6 yrs\n-- People > 15 yrs old most likely to be bit separating dog fights, esp females"},{"type":"card","domain":"General","sub":"General","q":"Moore et al 2015: How did immune responses vary between cats/dogs with up to date vs out of date rabies vaccination status?","a":"Responses to vaccine were appropriate for animals with or without an up to date rabies vaccination status. Therefore vaccinate all cats or dogs with a previous history of rabie vaccination immediately after potential rabies exposure and hold for 45 days (no dif if up to date or not)."},{"type":"card","domain":"General","sub":"General","q":"Hilier 2014: T/F Beta lactam antibiotics are a good choice for staphylococcus isolates with methicillin resistance profiles","a":"F. Never use beta lactams for MRS species."},{"type":"card","domain":"General","sub":"General","q":"Hilier 2014: What the the best treatment approach for surface/superficial pyoderma involving multi drug resistant staph species?","a":"Topical only. Reserve oral abx for deep pyoderma."},{"type":"card","domain":"General","sub":"General","q":"Hilier 2014: which staph species are considered primary pathogens of small animal  dermatological diseases?","a":"Staph pseudointermedius, staph schleiferi, and staph aureus."},{"type":"card","domain":"General","sub":"General","q":"Hilier 2014: T/F the prognosis for a good outcome is guarded in animals with infections caused by  methicillin resistant staph spp.","a":"F. Little evidence for difference in treatment outcome as s long as appropriate treatments used (in otherwords, abx resistant bugs don't cause infections that are any worse than those caused by non resistant strains!)"},{"type":"card","domain":"General","sub":"General","q":"Hillier 2014: T/F when an animal carrier of a drug resistant staph strain is identified (ie they do not have clinical signs)  they should be treated with antimicrobial therapy to decontaminate them and minimize risk to humans.","a":"F. There is currently on enough evidence to recommend routine decolonization of MRS carrier animals. However, rigorous hygiene and temporary isolation to prevent environmental contamination -which is a bigger risk to humans - is appropriate."},{"type":"card","domain":"General","sub":"General","q":"Rabhold 2018: In a survey of feces from owners and their companion animals (!), in what proportion of households was an identical C. difficile strain isolated in both humans and their pets?","a":"None Some dogs were shedding potentially pathogenic strains of C. diff."},{"type":"card","domain":"General","sub":"General","q":"Rezac 2015: In review of data on dog bite injuries to human faces, what factors were associated with face bites from dogs?","a":"- bending over the dog, putting face close to dog;s face, gazing at dog and being a child. No adult owners were bit in the face."},{"type":"card","domain":"General","sub":"General","q":"Rhea 2014: Emergency department surveillance data from N Carolina show that which demographic is most at risk for dog bites (presenting to ER) vs cat bits (presenting to ER)?","a":"Dogs: kids < 14 yrs\nCats: >79 yrs old"},{"type":"card","domain":"General","sub":"General","q":"Schurer 2014: How did parasite levels in dog feces change after 2 subsidized SN clinics and active rehoming of dogs in a Saskatchewan indigenous community?","a":"Parasite levels dropped significantly in dog feces following these events"},{"type":"card","domain":"General","sub":"General","q":"van Samkar 2016: T/F: Capnocytophaga canimorsus meningitis is associated with dog bites","a":"T. C canimorsus is part of the commensal oral flora of dogs and cats. Most people affected immunosuppressed. Mortality low, neurologic sequelae (hearing loss) common."},{"type":"card","domain":"General","sub":"General","q":"Wallace 2017: Dogs < 1 year who were rabies vaccinated were most likely have an adequate titer after one vaccination if they were vaccinated at what age?","a":"If they were vaccinated at >16 weeks of age. No diff if <12 weeks or 12-16 weeks. Best to check titer 8-30 days after vaccination, and most dogs developed adequate titer after booster vaccine."},{"type":"card","domain":"General","sub":"General","q":"Patronek 2013: Absence of an able-bodied person to intervene, non-familiar relationship of victims with dogs, compromized ability of victim to interact in a normal way with dog, unneutered dogs,  dogs isolated from human contact, and history of mismanagement or abuse/neglect of dog were all significant factors in ___________. Breed was not sigificant.","a":"dog bite related fatalities in the us from 2000-2009. Conclusion: boo BSL"},{"type":"card","domain":"General","sub":"General","q":"WeiB 2013: In a sample of 72 swabs collected from hospitalized patients, staff, and the environment at a small animal vet clinic, 34 had multidrug resistance patterns. How many of the samples that were found  on both animals and people were identical?","a":"1 close of Staph epidermidis isolated from  hospitalized cats (no signs of staph  infection), pet cages the clinic enviornment, and1 clinic employee. This clone was resistant to 10 classes of antibiotics (we're doomed)."},{"type":"card","domain":"General","sub":"General","q":"Oi 2015: How did the seroprevalence of Toxo in cats and dogs change in samples from 1999-2001 vs samples from 2009-2011?","a":"It was essentially unchanged."},{"type":"card","domain":"General","sub":"General","q":"Sugden 2016: T/F There is compelling evidence of a link between T. gondii infection  and psychiatric disorders, impulse control problems, personality aberrations and neurocognitive impairment.","a":"F."},{"type":"card","domain":"General","sub":"General","q":"Lee 2017: The first case of cat to human transmission of H7N2, an avian lineage influenza virus, occurred where?","a":"In a flu outbreak among cats in an NYC shelter in December 2016"},{"type":"card","domain":"General","sub":"General","q":"Stevens 2013: How did the pain scores of dogs administered 1 mg/kg each of lidocaine and bupivicaine intratesticular block vs placebo solution at 15 min, 60 min, 120 min and 24 hr post recovery from anesthesia?","a":"There was no difference between the two groups."},{"type":"card","domain":"General","sub":"General","q":"Kutzler 2015: What are the mechanisms by which CaCl2 induces infertility in testicles?","a":"a) injection leads to intratesticular edema which  is followed by cell necrosis and fibrosis, destroying seminiferous tubules, germ cells, and Leydig cells. b) injection leads to production of free radicals in the tissue which cause lipid peroxidation and  destruction of cellular structures and impairs spermatogenesis"},{"type":"card","domain":"General","sub":"General","q":"Bruniges 2016: How did recovery times compare between cats undergoing routine castration who received (among other things) dexmeditomidine or meditomidine?","a":"No difference. Use of atipamazole reduced recovery times in both groups and kittens generally recovered faster than adults."},{"type":"card","domain":"General","sub":"General","q":"Levy 2017: What was overall perioperative mortality in the clinic assessed? How did it compare for \n-- cats vs dogs\n-- males vs females","a":"Overall mortality was 0.03%. Mortality females (0.05%) > males  (0.02%). Mortality cats (0.05%) > dogs (0.009%). This overall rate is approaching levels in human surgery."},{"type":"card","domain":"General","sub":"General","q":"According to P Bushby, what are the recommendations for the minimum age to sterilize the following animals: \n-- shelter animals\n-- owned cats\n-- owned female dogs\n-- owned male dogs (large breed)\n-- owned male dogs (small breed)","a":"a. For shelter animals, spay/neuter is prior to adoption\nb. For owned cats, spay/neuter by 5 months of age\ni. Few documented adverse effects of spay/neuter in cats and many documented positive effects\nii. Female cats can come into heat by 4 ½ to 5 months\nc. Owned dogs the owner must make an informed decision based on species, breed, intended usage and current medical knowledge at hand\ni. For most breeds, the protective effect of spay before the first heat cycle on mammary neoplasia far outweighs the potential risks associated with other cancers and orthopedic conditions\nii. Owned female dogs spay prior to 5 months of age.\niii. For owned large breed male dogs – orthopedic concerns may outweigh all others – spay/neuter after growth stops 15 – 18 months.\niv. For owned small breed male dogs – no evidence at this time for orthopedic issues – castrate prior to sexual maturity – 5 months."},{"type":"card","domain":"General","sub":"General","q":"Hasiuk 2015: T/F Administration of atipamazole  following OHE  allowed for a faster recovery from anesthesia without compromizing analgesia","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Polson 2014: How did age affect post OHE pain in kittens vs adults? Within the adults group, how did OHE during estrus or pregnancy affect post-op pain scores?","a":"Kittens had similar wound tenderness but less affective pain than adults (Google says affective pain is feeling sorry for yourself with regard to pain). Pregnancy/estrus had no effect on  post op pain."},{"type":"card","domain":"General","sub":"General","q":"Benito 2016: As compared by the need for rescue analgesia post routine OHE, how well was pain controlled up to 8 hours following surgery in cats receiving intraperitoneal bupivicaine compared to the receiving post op meloxicam?","a":"n =4/27% of IP bupivicaine cats needed rescue analagesia while n=2/13% of cats who received 0.2 mg/kg meloxicam SQ post op. \"These 2 treatments produced similar analagesia in terms of pain scores.\""},{"type":"card","domain":"General","sub":"General","q":"White 2013: In an online survey of 219 vets who performed at least 4 hours of S/N surgery per week, what areas of the body were most common sites of musculoskeletal pain?","a":"Right thumb and wrist, lower back, shoulders, neck.  Nearly 100% of respondents reported feeling some amount of musculoskeletal apin"},{"type":"card","domain":"General","sub":"General","q":"Kozak 2014: In a mailed survey of 3174 German veterinarians, what sites of the body were most likely to be sources of musculoskeletal pain?","a":"In order most to least:  neck > shoulder > hand > elbow"},{"type":"card","domain":"General","sub":"General","q":"Boone 2015: What is the MOA of deslorelin, and for how long does it suppress fertility in male or female cats?","a":"It is a GnRH agonist, and it supresses fertility for ~2 years (females 24 mo avg, males 20 month avg)"},{"type":"card","domain":"General","sub":"General","q":"Kutzler 2015: What are the therapeutic limitations of melatonin as a reversible contraceptive in cats?","a":"It has a short biological half life (15-20 min!), it has poor oral bioavailability, and it makes cats sleepy"},{"type":"card","domain":"General","sub":"General","q":"Murray 2015: What are 3 benefits of surgical sterilization vs temporary contraception in companion animals?","a":"1. Permanent   2.behavior benefits 3. health benefits"},{"type":"card","domain":"General","sub":"General","q":"Porters 2015: What long term (up to 24 months following gonadectomy) health problems were associated with age at gonadectomy of kittens?","a":"No sig difs in long term health probs between kittens neutered between 8 and 12 weeks of age and those neutered at 6-8 months of age"},{"type":"card","domain":"General","sub":"General","q":"Porters 2015: cats undergoing routine gonadectomy who received IM induction vs transmucosal administration of dex + buprenorphine with IM ketamine. T/F cats receiving the TM protocol had poorer anesthesia and more adverse effects compared to cats who received all drugs IM.","a":"T. TM was crappy."},{"type":"card","domain":"General","sub":"General","q":"Rhodes 2015: Megasterol and medoxyprogesterone acetate are examples of _________ which can be used at low doses to reversibly  to prevent queens from cycling","a":"These are progestins. Low doses are rec to avoid adverse effects. Megasterol acetate: 0.625 mg/kg.week, medroxyblahblahblah 0.01 mg/kg SID"},{"type":"card","domain":"General","sub":"General","q":"DeLay 2016: In a review of cats and dogs who died perioperatively submitted for necropsy 1) When lesions of sig natural dz were found, what body systems were involved? 2) What proportion of cases showed no identifiable lesions? 3) In what time point relative to the anesthetic event did most animals die?","a":"1) Lesions of heart, upper respiratory tract, lungs\n2) 36% of the cases had not lesions (young, healthy, elective procedure)\n3) most deaths to least: up to 24 hrs post anesthesia (45%) > maintenance (35%) > premed/sedation (19%) > induction (11%)"},{"type":"card","domain":"General","sub":"General","q":"Fischer 2015: What proportion of queens receiving GonaCon (GnRH vaccine) showed contraception up to 1 year following administration?","a":"6/20, 30%. Not good enough for free roaming cats. GonaCon cats who did mate took longer to do so than control queens, had fewer fetuses per pregnancy."},{"type":"card","domain":"General","sub":"General","q":"Kent 2016: In a retrospective study of Golden Ret dogs submitted for necropsys, which of the following had the greater association with cancer related mortality: age or reproductive status?","a":"Age."},{"type":"card","domain":"General","sub":"General","q":"Zanuzzo 2015: How did IV dipyrone (aka metamizole) compare to dog receiving IV meloxicam in bitches undergoing routine OHE?","a":"Dipyrone produced superior analgesia (reduced need for rescue analagesia via morphine) while meloxicam produced better anithyperalgesia (fewer episodes of severe pain) in contrast to controls (who receive IV saline only :( ouch). When used in tandem the beneficial effects were combined.  FYI DIpyrone- unknown MOA, seems similar to NSAIDs in inhibiting prostaglandins. Banned in several countries as it causes blood dyscrasias in some humans"},{"type":"card","domain":"General","sub":"General","q":"Kum 2013:Dogs undergoing routine OHE divided into 3 groups based on meds received 30 min prior to premedication: placebo vs oral carprofen vs oral meloxicam. How did the concentrations of WBCs, neutrophils, and acute phase proteins (c-reactive protein, ceruloplasmin, and fibrinogen) vary between the treatment groups?","a":"It didn't vary between them. Concentrations of all inflammatory markers increased following OHE but in similar manner for each treatment group. Therefore use of carprofen or melox should not affect clinical interpretation of results for these 3 acute phase proteins (....)"},{"type":"card","domain":"General","sub":"General","q":"Hoglund 2016:How did the post operative resp rates and heart rates vary between cats undergoing flank spay  with vs without pre operative NSAID (carprofen or meloxicam)?","a":"There was no difference in resp or heart rates between these groups post operatively, suggesting that these are poor indicators for post op pain assessment in individual cats."},{"type":"card","domain":"General","sub":"General","q":"Gauthier 2015: How did pain scores vary between cats undergoing routine OHE via a) trad midline approach b) flank approach or c) laparoscopic ovariectomy?","a":"No difference in pain scores btwn midline and flank spays, and both were sign higher pain score than laparoscopic. Lararoscopic surgery took longer but was less painful post op."},{"type":"card","domain":"General","sub":"General","q":"DiGangi 2017: T/F in a study comparing surgically castrated dogs to dogs receiving chemical castration via zinc gluconate, more surgically castrated required medical intervention following sterilization","a":"T. \"chemical castration of dog in field clinics is a feasible alternative to surgical castration, but proper follow up care should be ensured for at least 7 days post procedurally.\" TWo chemically castrated dogs experience scrotal ulceration requiring surgical castration on days 3 and 7."},{"type":"card","domain":"General","sub":"General","q":"Garde 2017: T/F Among free roaming dogs in Chile who received either surgical or chemical castration, no differences in sexual activity following sterilization were observed (relative to their activities prior to sterilization)","a":"T. Chemical castrated dogs did show a stat sig increase in dog directed aggression. Behavior did not correlate to testosterone levels in either group."},{"type":"card","domain":"General","sub":"General","q":"Krecic 2017: LH assays can be used to determine if a male or female cat is intact or gonadectomized. In a gonadectomized cat, LH levels will be (choose: high or low)","a":"LH typically high in gonadectomized animals (gonad hormones typically suppress LH production). LH is persistently elevated starting at about 2 weeks after gonads are removed"},{"type":"card","domain":"General","sub":"General","q":"VolPato 2015: In cats sedated with dex-torb vs dex-torb-ketamine, what clinically sig differences were seen in measured hematologic and hemostatic parameters between the two groups? (CBC, platelet count, buccal mucosal bleeding time, whole blood clotting time, prothrombin time, aPTT, and thrombin time)","a":"No clinicaly relevant effects or differences were seen in any of the hemologic/hemostatic variables. dex-torb-ket cats had longer duration of sedation, but onset of sedation was equal for both groups."},{"type":"card","domain":"General","sub":"General","q":"Gerdin 2016: T/F: In a study comparing necropsy findings in dogs who died of starvation vs a disease process, starved dogs more often had empty stomachs","a":"F. Starved dogs often had food or foreign material in their stomachs, sick dogs usually had empty stomachs. Gross findings associated exclusively with starved dogs included matted fur and traumatic injuries"},{"type":"card","domain":"General","sub":"General","q":"Intarapanich 2016: Choose motor vehicle accidents OR non-accidental injuries.\n--- Injuries sig associated with _______ included pelvic fractures, pneumothorax, pulmonary contusions, abrasions, degloving wounds. \n--- Injuries associdated with _________ were fractures of the skull, teeth, vertebrae, and ribs; scleral hemorrhages, damages to claws, and evidence of older fractures.","a":"--- Injuries sig associated with motor vehicle accidents included pelvic fractures, pneumothorax, pulmonary contusions, abrasions, degloving wounds. \n--- Injuries associdated with non accidental injuries were fractures of the skull, teeth, vertebrae, and ribs; scleral hemorrhages, damages to claws, and evidence of older fractures"},{"type":"card","domain":"General","sub":"General","q":"McEwen 2016: T/F because of physiological and anatomical differences between humans and animals, for some mechanisms of asphixia, consciousness is maintained for longer periods  and the onset of death is later in animals than that described for people","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Ressel 2016: List up to 6 post mortem findings suggesting that a vital (while animal was alive) blunt force injury occurred, as opposed to post-mortem artifacts (such as blood extravasation)?","a":"leukocyte infiltration, erythrophagocytosis, hemosiderin,  reparative lesions of fibroblast proliferation, myocyte regen in muscle, and callus formation in bone."},{"type":"card","domain":"General","sub":"General","q":"schultze 2016: In ______ (type of injury) lesions may be absent, or may include early or localized development of rigor mortis, signs of acute circulatory failure, or severe burns","a":"Electrical injuries"},{"type":"card","domain":"General","sub":"General","q":"Intarapanich 2017: In a study comparing retrospective records review of injuries caused by spontaneous dog fights vs organized dog fighting, which group was more likely to have mult injuries, particularly of the thoracic limbs, dorsal and lateral aspects of the head and muzzle, and th ventral neck and thoracic region","a":"Organized dog fighting dogs."},{"type":"card","domain":"General","sub":"General","q":"Almeida 2018: IN a retrospective review of necropsy reports that had findings consistent with cruelty and about, ~1% of all necropsies  had signs suggestive of abuse (cats and dogs). What injury type was most common in dogs vs cats? What breed of dogs was overrepresented in dogs?","a":"Dog- gunshot. Cat- blunt force trauma. Pitbull type dogs overrepresented."},{"type":"card","domain":"General","sub":"General","q":"miller 2016: T/F Scar counts in dogs from organized dog fighting cases was significantly correlated to dog aggression on behavior evaluation","a":"T, esp for males. Ten or more scars in 3 or more body zones was associated with dog aggression in 82% of males and 60% of females. However, some unscarred dogs also had dog aggression and spme dogs with scars did not. So there's that."},{"type":"card","domain":"General","sub":"General","q":"Papich 2013: The concentration of doxycycline compounded from  commertical tablets cannot be assured beyond ______ # days","a":"7 days"},{"type":"card","domain":"General","sub":"General","q":"Litster 2014: In a study evaluating 3 dose regimens for treating dogs or cats with coccidia infections with ponazuril, fecal consistency did/did not correlate significantly with infection status at day 3-4 after receiving treatment.","a":"Fecal consistency on day 3-4 did not corelate with infection status."},{"type":"card","domain":"General","sub":"General","q":"Mawby 2014: In a study comparing plasma concentration of name brand, generic and compounded intraconazle in dogs, which of the listed drug formulations reached therapeutic levels?","a":"Generic and brand name itra reached therapeutic levels (though generic did not match name brand levels). Compounded was didlly squat."},{"type":"card","domain":"General","sub":"General","q":"O'Neill 2014: What were the 3 most common diagnoses of cats presenting to primary care veterinary clinics in the UK?","a":"Periodontal dz> flea infestation > obesity"},{"type":"card","domain":"General","sub":"General","q":"Hutt2014: Weekly injections of 0.6 mg/kg doramectin resulted in clinical cure in 94.8% of dogs with few adverse effects over what time frame?","a":"Mean duration of treatment was 7.1 weeks."},{"type":"card","domain":"General","sub":"General","q":"Levy 2015: What is an appropriate reference range in rectal body temp in healthy adult cats confined in shelter cages?","a":"98.1-102.1 deg F"},{"type":"card","domain":"General","sub":"General","q":"George 2016: T/F the causes of urethral obstruction are most often physical vs functional","a":"F. In this study 53% were idiopathic, followed by uroliths (29%) and plugs (18%)"},{"type":"card","domain":"General","sub":"General","q":"Martin-Flores 2016: T/F Oral maropitant administered to cats 18 hr prior to anesthetic inducation with dex/morphine  in reducing emesis","a":"T... but not necessarily nausa. Ditto for same study done 2017 but maropitant given 2-2.5 h before induction."},{"type":"card","domain":"General","sub":"General","q":"Cornell 2017: How did administration of corn syrup TM immediately post op affect post op blood glucose measurements in kittens undergoing routine gonadectomy (compared to those who did not receive corn syrup).","a":"No difference in glucose measurements. Neither group was hypoglycemic at any point."},{"type":"card","domain":"General","sub":"General","q":"KuKanich 2017: What were overal findings of doxycylcine content in FDA approved formulations vs various compounded (tablets vs suspension)  formulations?","a":"FDA approved formulations consistently contained an appropriate amount of doxy. Compounded formulations were more variable (suspensions > chews > tablets). If you must use compounded doxy use tablets, but generally just don't."},{"type":"card","domain":"General","sub":"General","q":"Martell-Moran 2017: What percentage of declawed cats evaluated had radiographic evidence of retained p3 fragments?","a":"63%!  All declawed cats had increased odds of back pain, LBP, biting, barbering. When cats with p3 fragments were excluded, declawed cats still had increased odds of bitin and LBP compared with non declawed cats."},{"type":"card","domain":"General","sub":"General","q":"Rose 2017: T/F Supplementing healthy dogs with a synbiotic (prebiotic-probiotic) supplement significantly reduced the incidence of diarrhea in this trial.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Spencer 2017: Among cats referred for pyrexia, what was the top identified cause?","a":"FIP (21%). Infectious causes most common overall > inflammatory > unknown >neoplasia > misc >immune mediated (rare)"},{"type":"card","domain":"General","sub":"General","q":"Slack 2013: T/F In cases of of cats with naturally occurring viral keratoconjunctivitis bilateral ocular administration of high doses of Feline Interferon omega twice daily for 14 days did not improve clinical disease or viral shedding.","a":"T. Neither did human interferon alpha-2b"},{"type":"card","domain":"General","sub":"General","q":"Conway 2016: T/FPlasma is an acceptable substitute for serum in topical treatment of keratomalacia","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Renschler 2018: In a study comparing blood concentrations of itraconazole (brand name vs generic vs compounded) in cats and dogs being treated for systemic fungal infections, what was the conclusion about the clinical use of compounded itra?","a":"It's crap, don't use it. Generic and brand name were comparable."},{"type":"card","domain":"General","sub":"General","q":"Mila 2014: In a study of IgG concentrations in blood of neonatal pups, oral supplementation with hyperimmune plasma in the first 8 hours of life did/did not decrease the risk of mortality and improve the IgG blood concentration in the neonatal pups","a":"Hyperimmune plasma DID NOT decrease mortality or increase IgG concentration in pups. Colostrum is essential. IgG concentration at 2 days old was sig associated with weight gain during first 2 days of life. Pups with less than 230 mgdL IgG were at higher risk of death."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F Most cases of pancreatitis in dogs and cats do not have a bacterial component, therefore empiric use of antibiotics in these cases is not indicated","a":"T. Most cases of pancreatitis in dogs and cats do not have a bacterial component."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F Most cases of feline lower urinary tract disease do not involve bacterial infection and in such cases antimicrobials are not indicated.","a":"T. Most cases of feline lower urinary tract disease do not involve bacterial infection and in such cases antimicrobials are not indicated."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Surgical antimicrobial prophylaxis is the use of a very brief antimicrobial agent initiated immediately ______(choose: prior to, during, following) an operation.","a":"Surgical antimicrobial prophylaxis is the use of a very brief antimicrobial agent initiated immediately prior to an operation."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Use broad spectrum antimicrobials as often as possible to ensure response to treatment","a":"F: Use narrow spectrum antimicrobials whenever appropriate. It is best to choose an antimicrobial with a narrow spectrum that is effective against the organism."},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"T/F: Treat for the shortest effective period possible rather than a set time period.","a":"T: Treat for the shortest effective period possible in order to minimize therapeutic exposure to antimicrobials"},{"type":"card","domain":"Physical Health","sub":"Infectious Disease","q":"Veterinarian/Client/Patient Relationship (VCPR) – A VCPR exists when all of the following conditions have been met:\n1. The________ has assumed the responsibility for making clinical judgments regarding the health of the animal(s) and the need for medical treatment, and the client has agreed to follow the _______’s instructions.\n2. The veterinarian has sufficient knowledge of the animal(s) to initiate at least a general or preliminary diagnosis of the medical condition of the animal(s). This means that the veterinarian has recently seen and is personally acquainted with the keeping and care of the animal(s) by virtue of an examination of the animal(s) or by ________________.\n3. The veterinarian is readily available for ____________, or has arranged for emergency coverage, in the event of adverse reactions or failure of the treatment regimen.","a":"Veterinarian/Client/Patient Relationship (VCPR) – A VCPR exists when all of the following conditions have been met:\n1. The veterinarian has assumed the responsibility for making clinical judgments regarding the health of the animal(s) and the need for medical treatment, and the client has agreed to follow the veterinarian’s instructions.\n2. The veterinarian has sufficient knowledge of the animal(s) to initiate at least a general or preliminary diagnosis of the medical condition of the animal(s). This means that the veterinarian has recently seen and is personally acquainted with the keeping and care of the animal(s) by virtue of an examination of the animal(s) or by medically appropriate and timely visits to the premises where the animal(s) are kept.\n3. The veterinarian is readily available for follow-up evaluation, or has arranged for emergency coverage, in the event of adverse reactions or failure of the treatment regimen."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"What kind of virus is rabies?","a":"Lyssavirus"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what kind of disease does rabies infection cause?","a":"acute progressive encephalitis"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Which of the following rabies virus variants is not in the United States? racoon, skunk, canine, fox, bat","a":"canine"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"the rabies incubation period is generally ___ to ____ weeks but can exceed ____ months","a":"3, 12, '6"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"dogs, cats, and ferrets do what for a few days before the onset of clinical signs?","a":"shed virus in the saliva"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is the case definition for rabies? what two test can be used?","a":"diagnosis of an animal by a qualified lab; direct flourescent antibody, viral isolation in cell culture"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what are the essential components to a rabies prevention program?","a":"include ongoing public education, responsible pet ownership, routine veterinary care and vaccination, and professional continuing education"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"for a human case, an exposure assessment should occur including what professionals?","a":"medical providers and public health officials"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Where can the rationale for recommending preexposure prophylaxis and details of both preexposure and postexposure prophylaxis administration be found","a":"Advisory Committee on Immunization Practices, available from state health departments"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how many confirmed rabies cases were there among dogs in the US in 1947? in 2013?","a":"6949, 89"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Are more rabies cases reported annually involving dogs or cats?","a":"cats (247 cases in 2013)"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is a tool to optimize public and animal health for rabies?","a":"low-cost or free rabies vaccine clinics"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"if you suspect rabies in a vaccinated animal who should it be reported to?","a":"public health officials, the vaccine manufacturer, and the USDA APHIS Center for Veterinary Biologics"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"is it recommended that state laws prohibiting or allow the importation, distribution, translocation, and private ownership of wild animals?","a":"prohibit"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"if an animal becomes rabid within 60 days of importation to the US who should be notified?","a":"by state health departments to the CDC"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is the gold standard test for rabies diagnosis","a":"direct flourscent antibody test"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"for a dog or a cat, what should be submitted to the lab?","a":"only the head or the entire brain"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how should samples be shipped?","a":"promptly with refridgeration, not frozen since this delays testing and not fixed"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"does the presence of rabies antibody titers directly correlate to protective immunity?","a":"no, there are other immunologic factors that play a role and cannot be measured"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"True/False: circulating rabies virus antibodies in animals should not be used as a substitute for current vaccination in managing rabies exposures or determining the need for booster vaccination.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what should be required for parental rabies vaccination administration?","a":"direct licensed veterinary supervision on the premises"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"when may rabies vaccines be given in an animal shelter setting?","a":"before release"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long after vaccination is peak rabies antibody titers expected and the animal considered vaccinated?","a":"28 days"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"when should a booster vaccine be administered (regardless of age)?","a":"1 year"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"if an animal misses the one year booster, when should it be vaccinated and boostered again?","a":"immediately booster and then follow label requirements for the product used"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"which three domestic companion species should all be vaccinated for rabies and which \"livestock\" species?","a":"dogs, cats, and ferrets, horses"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"should a wild animal hybrid be vaccinated?","a":"there is no licensed vaccine and they should not be kept as pets"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long should a wild-caught animal susceptible to rabies be quaratined for?","a":"6 months"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long should stray animals be impounded for to determine whether humane exposure has occurred?","a":"3 days"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how can a community safegard public and feline health with feral cat colonies?","a":"requiring that cats receive initial rabies vaccinations and appropriately scheduled booster vaccinations"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what transport practice should be prohibited?","a":"the movement of dogs from areas with dog-to-dog transmission of rabies to areas without it"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"who has regulatory jurisdication of dogs and cats imported into the US?","a":"CDC and USDA APHIS"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is the form number that serves as a rabies vaccination certificate from the National Assoc of State Public Health Vets?","a":"Form 51"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"which of the following is not an adjunct procedure to enhance rabies control? animal identification, animal licensing, canvassing,animal sheltering, animal control, public education","a":"animal sheltering"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long should an exposed animal that is current on its rabies vaccination be observed for?","a":"45 days"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long should ann exposed unvaccinated animal be observed for, if the owner refuses euthanasia?","a":"4 months (dogs and cats), 6 months (ferrets)"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"when should a rabies vaccine be administered to an exposed unvaccinated animal?","a":"immediately before entering into the strict quarantine"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is the recommended period of exposure to vaccination?","a":"less than 96 hours"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long should an exposed animal that is overdue for rabies vaccination be quarantined if they have documentation of previous vaccination?","a":"45 days"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"what is a possible protocol for an overdue animal with no record of vaccination and an exposure noted?","a":"consult with state public health vets about doing paired serum testing for amnestic response to booster vaccination to prove previous vaccination"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"how long is the quarantine for a dog, cat, or ferret who bites a person, is that quaratine related to vaccination status?","a":"10 days, no"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"in the case of a disaster where animals are emergency sheltered, should rabies vaccination be performed?","a":"Yes, administer a rabies vaccine to all dogs, cats, and ferrets unless reliable proof of current vaccination exists."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"who must sign a rabies vaccination certificate?","a":"the administering or supervising veterinarian"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Pathogens with the highest proportion of enteric disease cases attributable to animal contact were (list top 5)","a":"Campylobacter spp (17%), Cryptosporidium spp (16%), nontyphoidal S enterica (11%), non–O157 STEC strains (8%), and STEC O157:H7 (6%)."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Dermatologic bacteria and parasites pose the highest risk for human disease from animals in public settings.","a":"F: enteric"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Removing ill animals, especially those with diarrhea, from public contact is necessary and sufficient to protect the health of people and other animals.","a":"F: Not sufficient. \"The fact that some pathogens can be shed intermittently and survive for months or years in the environment,103–107 as well as the limitations of laboratory testing, makes attempts to identify and remove infected animals unreliable as means of eliminating the risk for transmission.\""},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"How long does E coli O157:H7 survive in soil?","a":"can survive in soil for months (one case report >42 weeks)"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Enteric pathogens are primarily transmitted by what route?","a":"Enteric pathogens are primarily transmitted by the fecal-oral route. Because animal fur, hair, feathers, scales, skin, and saliva harbor fecal organisms,122 transmission can occur when people pet, touch, feed, or are licked by animals. Exposure to contaminated materials such as animal bedding, environmental surfaces, clothing, and shoes has also been associated with transmission of pathogens.29,33,35,82,123,124 In addition, illness has resulted from fecal contamination of food,24,125 unpasteurized juice,126 unpasteurized milk,19,127–130 and drinking water.131–134"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Pasteurella spp, Francisella tularensis,Staphylococcus spp, Streptococcus spp, Capnocytophaga canimorsus, Bartonella henselae and Streptobacillus moniliformis are all examples of what?","a":"Bacterial agents associated with animal bite infections."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Influenza, Tuberculosis, Q Fever (Coxiella burnetti), and Chlamydophila psittaci are all examples of what?","a":"Diseases transmitted by aerosols or airborne droplets"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Q Fever, Leptospirosis, listeriosis, brucellosis, and chlamydiosis are all examples of what?","a":"diseases that can be acquired through contact with aborted fetuses, newborn animals, reproductive tissues, or associated fluids"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Handwashing following contact with animals has not been associated with decreased rates of illness during disease outbreaks associated with animals in public settings.","a":"F: Handwashing following contact with animals has been associated with decreased rates of illness during disease outbreaks associated with animals in public settings."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"List types of people with increased degree of risk associated with zoonotic diseases","a":"children < 5 years of age. Other groups that have an increased degree of risk include people with waning immunity (eg, individuals ≥ 65 years of age), pregnant women, or people who are immunocompromised (eg, those with HIV-AIDS, without a functioning spleen, or receiving immunosuppressive treatments)."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"The design of facilities and animal pens should minimize the risk associated with animal contact, including limiting direct contact with (1)______ and encouraging (2)_______.","a":"1) Manure\n2) Handwashing"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Common problems with _________________ include inadequate barriers, floors and other surfaces that are difficult to keep clean and disinfect, insufficient plumbing, lack of signs regarding potential health risks and risk prevention measures, and inadequate handwashing facilities","a":"Temporary animal exhibits"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Serving food and beverages in animal housing areas is acceptable as long as operators ensure acces to handwashing facilities and display handwashing signs where food or beverages are served","a":"F. Food and beverages should only be served in non animal housing areas"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Use of preweaned calves, reptiles, amphibians, and live poultry (including chicks) is never appropriate in nursing homes, schools, daycares, or other venues where groups at high risk for serious infection are expected to be present","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Ill animals, animals known to be infected with a zoonotic pathogen, and animals from herds with a recent history of abortion, diarrhea, or respiratory disease should not be exhibited.","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Because of the extended incubation period for rabies, unvaccinated mammals should be vaccinated for rabies  ________ (time period) before they have contact with the public.","a":"≥ 1 month"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Routine screening of animals in public settings for zoonotic diseases is not recommended.","a":"T, except for C psittaci infection in bird encounter exhibits198 and tuberculosis in elephants189 and primates.242 Screening tests are available for some enteric pathogens (eg, STEC and Salmonella spp); however, the interpretation of test results can be problematic. Shedding can be intermittent, and negative results do not indicate an animal was not shedding an organism at an earlier time or will not start shedding in the near future. There is no established guidance for management of animals with positive test results, and inappropriate interpretation might lead to unnecessary treatments, quarantine, or euthanasia."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Handwashing is the most important prevention step for reducing disease transmission associated with animals in public settings.","a":"T!!!"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: People with increased risk associated with zoonotic dzs  should not have direct contact with preweaned calves, reptiles, amphibians, and live poultry","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: People with increased risk associated with zoonotic dzs  should not have direct contact animals that are ill.","a":"T but (trick question) nobody should! Ill animals should not be present in public settings."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Rank the following types of control measures from most to least effective in the hierarchy of controls:\n- PPE\n- Engineering controls (\"shape the path\")\n-  Elimination or substitution of the hazard\n- Administrative controls (rules)","a":"--(Most) Eliminination or substitution of the hazard: In general, this is the most effective measure, as it requires no action on the part of the employee. The hazard has been identified and eliminated. An example would be exclusion of skunk patients due to their association with rabies virus transmission.\n-- Engineering controls: A veterinary clinic is designed to facilitate infection prevention best practices. An example would be placement of sinks for handwashing in convenient locations\n-- Admininstrative controls:  Clinic policies are adopted that mandate appropriate infection prevention practices. Administrative controls are generally not considered as effective as elimination or engineering controls because they require rigorous adherence to the policy by all employees. Examples would be the requirement for handwashing between patient contacts, no recapping of needles, and rabies vaccination of staff\n-- Use of PPE:  This control measure is generally considered the least effective and the last line of defense because it requires the most action from the employee. Personal protective equipment is frequently and appropriately used in veterinary practice when engineering and administrative control options are limited. An example would be wearing a mask and face shield while performing dental procedures."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"1) List 5 ways that airborne droplets can be produced\n2) How far can droplets travel?","a":"1) Droplet transmission occurs when droplets created by coughing, sneezing, and vocalization are deposited on the mucous membranes.  Procedures such as lancing abscesses or dentistry can also produce droplets. \n2) These droplets are typically large, can generally travel only approximately 1 to 2 m (3 to 6 feet), and do not remain suspended in the air. Risk of pathogen transmission increases with proximity to the source and duration of exposure."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Consistent, thorough ________ is the single most important measure veterinary personnel can take to reduce the risk of zoonotic disease transmission.","a":"Consistent, thorough hand hygiene is the single most important measure veterinary personnel can take to reduce the risk of zoonotic disease transmission. Most common pathogens are transmitted by hand-to-mouth contact either directly from animals or indirectly through the environment.82–84 Hand hygiene includes handwashing with soap and water, the use of alcoholbased hand rubs, and appropriate use of gloves. Adequate hand hygiene may include washingthe forearms when contamination extends beyond the wrist."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Antibacterial soaps are recommended over plain soaps for regular hand washing by veterinary personnel","a":"F. Either is fine. Transient flora may be removed by the mechanical friction or detergent properties of soap and water or killed by antiseptic agents."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Moisturizing soaps and lotions are recommended for use in veterinary practice settings.","a":"T: Moisturizing soaps and lotions can preserve skin integrity and encourage adherence to hand hygiene protocols among veterinary\nstaff. Dry, cracked skin is painful, indicates compromised skin integrity, and is more likely to be colonized with staphylococci and gram-negative organisms.82 When hand lotions are used, personal containers are recommended over use of shared dispensers to prevent contamination."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"1) Under what circumstances are use of hand rub sanitizers acceptable as a substitute for hand washing?\n2) What active ingredients are recommended for effective hand rubs?","a":"1) Hand rubs, when properly applied for 30 seconds to hands that are not visibly soiled, are highly effective\nagainst bacteria, many fungi, and enveloped viruses.  Hand rubs are less effective against bacterial spores, protozoal parasites, and some nonenveloped viruses. it is important to train staff that the visible presence of organic matter (eg, blood or feces) on hands will greatly decrease the efficacy of alcohol-based hand rubs\n2) The CDC recommends hand rubs containing 60% to 95% ethyl alcohol (ethanol) or isopropyl alcohol (isopropanol) for use in health-care settings.82 Hand antisepsis products containing other disinfectants may be susceptible to bacterial overgrowth and have been associated with nosocomial infections"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Select the option that describes when gloves are not necessarily recommended: \na) when contact with feces, body fluids, vomitus, exudates, and nonintact skin is likely\nb) when performing dental or obstetric procedures, resuscitations, and necropsies and when handling diagnostic specimens (eg, urine, feces, aspirates,\nor swabs)\nc) when cleaning cages, litter boxes, and contaminated equipment and environmental surfaces in animal areas and when handling dirty laundry\nd)  when personnel have wounds or other compromised skin integrity of the hands\ne) when examining, handling, vaccinating, or obtaining a blood sample from most healthy animals","a":"e) when examining, handling, vaccinating, or obtaining a blood sample from most healthy animals,\nprovided good hand hygiene is practiced."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Handwashing should be performed or alcohol based hand rubs should be used immediately after glove removal","a":"T: Wearing gloves (including palpation sleeves) does not preclude the need for hand hygiene. Handwashing should be performed or alcoholbased hand rubs should be used immediately after glove removal because gloves may have undetected microperforations or hands may be contaminated during glove removal.111,112"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"__________ should be used whenever exposure to splashes or sprays is likely to occur (eg, when lancing abscesses, flushing wounds, or suctioning and when performing dentistry, obstetric procedures, or necropsies)","a":"Facial protection should be used whenever exposure to splashes or sprays is likely to occur (eg, when lancing abscesses, flushing wounds, or suctioning and when performing dentistry, obstetric procedures, or necropsies)"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Choose respirators or surgical masks:________ are designed and certified to prevent inhalation of small airborne contaminants. _______ are designed to protect the patient and do not provide the same level of protection for the wearer as a _______","a":"Respirators are designed and certified to prevent inhalation of small airborne contaminants. Surgical masks are designed to protect the patient and do not provide the same level of protection for the wearer as a respirator"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Use of a respirator is indicated under what circumstances?","a":"Pathogens such as C burnetii, Brucella spp, and Chlamydophila psittaci are known to present an occupational risk to veterinary staff; use of respiratory tract protection is recommended when exposure to these and other airborne pathogens is likely.120–122 Additionally, respiratory tract protection is warranted for procedures that are likely to generate aerosols, such as the use of power tools during necropsy."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Animals that are fearful, are aggressive, or have a known exposure to an infectious agent should be examined and triaged immediately, prior to being placed  into an examination or isolation room, as should those with the following so-called red flag signs: neurologic signs, diarrhea, respiratory tract signs, fever, infected wounds, or chronic infection.","a":"F: Animals that are fearful, are aggressive, or have a known exposure to an infectious agent should bypass the waiting room and be placed directly into an examination or isolation room, as should those with the  following so-called red flag signs: neurologic signs, diarrhea, respiratory tract signs, fever, infected wounds, or chronic infection."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: Preventive measures to avoid injuries or bites to personnel during animal handling include reliance on  owners to restrain animals and the use of muzzles, bite-resistant gloves, and sedation or anesthesia as necessary.1","a":"F: Preventive measures to avoid injuries or bites to personnel during animal handling include reliance on experienced veterinary personnel\nrather than owners to restrain animals and the use of muzzles, bite-resistant gloves, and sedation or anesthesia as necessary.1"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: veterinarians have the right to refuse to provide services for clients with exotic species or wildlife that cannot be handled safely because of physical infrastructure or clinician or staff training limitations.","a":"1"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"List precautions that should be used to prevent needlestick injuries (4)","a":"-- Trained personnel should restrain animals to minimize needlestick injuries resulting from animal movement. \n-- Veterinary staff should not bend needles, pass an uncapped needle to another person, or walk around with uncapped needles.\n-- Needle caps should never be placed in the mouth. \n-- Needles should not be recapped unless the 1-handed scoop method is used:"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: After aspiration of infectious materials or injection of vaccines containing live organisms, the used syringe with needle attached should be placed in a sharps container.","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: contact with animal blood (except primate blood) has not been reported as a source of occupationally acquired infection.","a":"T except primate blood"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"The opposite of donning (e.g. donning your PPE) is __________ :-)","a":"doffing. All PPE used when attending animals in isolation should be donned immediately prior to and doffed following care for the animal"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Choose federal or state: Medical waste management, including sharps and regulated medical waste is  based on ______ medical waste laws.","a":"state"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: preexposure vaccination against rabies eliminates the need for additional rabies vaccinations following a known rabies virus exposure.","a":"False: : preexposure vaccination against rabies does not eliminate the need for additional rabies vaccinations following a known rabies virus exposure."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: animal bites are tetanus-prone wounds, and therefore veterinary staff may be at an elevated risk of exposure, so adequate vaccination is recommended","a":"T"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"Veterinary staff should receive a routine tetanus vaccination every (#)_____ years in accordance with ACIP recommendations. Additionally, if a person sustains a wound, including a bite wound, and it has been more than (#)______ years since his or her last tetanus booster, a single dose of a tetanus vaccine should be administered.","a":"Veterinary staff should receive a routine tetanus vaccination every10 years in accordance with ACIP recommendations. Additionally, if a person sustains a wound, including a bite wound, and it has been more than 5  years since his or her last tetanus booster, a single dose of a tetanus vaccine should be administered."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"People with weakened immune systems or who are at increased risk from zoonotic dz (eg preggers) should avoid working with high risk animals when possible. High risk categories include:","a":"High-risk animals include those that are young, parturient, unvaccinated, stray or feral, fed raw-meat diets, or housed in a shelter; animals with internal or external parasites; wildlife; reptiles and amphibians; and exotic or nonnative species"},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"T/F: The ADA as amended in 2008 states that pregnancy itself is not a disability, therefore pregnant workers and job applicants are excluded from the protections of the ADA.","a":"F: The ADA as amended in 2008 states that while pregnancy itself is not a disability, pregnant workers and job applicants arenot excluded from the protections of the ADA."},{"type":"card","domain":"Community & Public Health","sub":"Zoonotic Disease","q":"The following are all components of what written document recommended by NASPHV?\nEffective infection control plans should do the following:\n• Provide explicit and well-organized guidance specific to the facility and practice type\n• Be flexible so that new issues can be addressed easily and new knowledge incorporated.\n• Indicate the staff members responsible for each area, activity, or function.\n• Provide contact information, resources, and references.","a":"Effective infection control plans should do the following:\n• Provide explicit and well-organized guidance specific to the facility and practice type\n• Be flexible so that new issues can be addressed easily and new knowledge incorporated.\n• Indicate the staff members responsible for each area, activity, or function.\n• Provide contact information, resources, and references."},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"The sensory component is which is the neural procesing of noxious stimuli is called_____.","a":"nociception"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"pain perception, which is the unpleasant sensory and emotional experience associated with either actual or potential tissue damage is what component of the pain response?","a":"the affective component"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: Pain can occur in an unconcious animal.","a":"False, it can only occur in a conscious animal"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is acute pain, how long can it last?","a":"pain that exists during the expected time of inflammation and healing after injury; up to 3 months"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is chronic pain?","a":"that which exists beyond the expected duration of acute pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"________ occurs when peripheral neural receptors are activated by noxious stimuli (eg, surgical incisions, trauma, heat or cold).","a":"nociceptive pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"________ results gradually from activation of the immune system in response to injury or infection","a":"inflammatory pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"_________ occurs when pain is amplified and sustained by molecular, cellular and microanatomic changes, collectively termed peripheral and central hypersensitization.","a":"pathologic pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"another name for pathologic pain is _______","a":"maladaptive pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what does pathologic pain consist of?","a":"allodynia, hyperesthesia, expansion of the painful area beyond original boundaries, and chronic pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is neuropathic pain and where does the change take place?","a":"pain that is considered to be a disease of the central nervous system; genomic, phenotypic change"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what are the three components of appropriate pain management?","a":"anticipation, early intervention, and evaluation of response to therapy"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: Response to therapy is an appropriate pain assessment tool?","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what does the acronym PLATTER stand for?","a":"Plan, anticipate, treat, evaluate, return"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the most accurate method for evaluating pain in animals: physiologic or behavioral observations?","a":"behavioral observations"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the \"fourth vital sign\"?","a":"pain score"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what are the three behavior types relavent to pain assessment?","a":"maintenance of normal behavior, loss of normal behavior, development of new behaviors"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is a validated, multifactoral, acute pain assessment for dogs?","a":"glasgow short form composite measure pain score"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the only currently validated acute pain assessment for cats?","a":"UNESPBotucatu Multidimensional Composite Pain Scale"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what four steps are generally involved in a clinical measures instrument for pain?","a":"observe the animal without interaction, observe the animal with interaction, observe reaction to palpation of the painful site, score the animals pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"under-recognized and under-managed chronic pain can result in ________","a":"premature euthanasia"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"clinical signs of chronic pain that owners may/maynot recognize include what?","a":"exercise intolerance, difficulty with mobility, decreased grooming, changes in urination/defecation habits"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the most effective class of drugs for managing acute pain and can be used for chronic pain as well?","a":"opiods"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"opiods should be used for routine preoperative medication along with ______ when indicated for the patient?","a":"sedatives/tranqualizers"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: full mu agonists elicit greater and more predictable analgesia than partial mu agonists or kappa agonists","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"in dogs and cats which opiod is preferable and provides better analgesia: butorphanol or buprenorphine?","a":"buprenorphine"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"in cats which route of administration is not recommended for opiods?","a":"SC"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which routes or administration are recommended?","a":"IM, IV and buccal"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For patients requiring ongoing treatment what different forms of opiods are options?","a":"parenteral readministration, CRIs, transdermal fentanyl, concentrated injectible, oral opiods in dogs"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what class of drugs are opiods synergistic with, allowing low-dose combinations to great effect for both sedation and analgesia","a":"alpha-2 adrenergic agnoists"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"how longs does the concentrated injectible buprenorphine last","a":"24 hours (Simbadol)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: Dogs exhibit a robust first-pass effect of oral opioids, thus suggesting utility","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: There is indication that one of the vet-approved NSAIDS is associated with a greater or lesser incidence or prevalence of adverse events.","a":"False, there is no evidence of that"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What drugs should the use of NSAIDs be avoided with?","a":"corticosteroids, furosemide, nephrotoxic (aminoglycosides, cisplatin), multiple highly protein-bound drugs (phenobarb, digoxin, ciclosporin, cefovecin, chemo)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the recommended washout period for meloxicam? other nsaids and short acting steriods?","a":"5 days; 7 days"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the most common adverse event related to NSAIDs in dogs?in cats?","a":"gastrointestinal toxicity (clinical signs in dogs include vomiting, diarrhea, inappetance; in cats mostly anorexia)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"how long does it take for signs of GI toxicity to emerge?","a":"2-4 weeks"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"which is better preoperative or postopertive administration of nsaids in dogs?","a":"preoperative"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"If IV access is not possible and normotension cannot be acheived what does the task force recommend?","a":"limiting NSAID use to postsurgical administration"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False. Idiopathic hepatocellular necrosis is a risk when animals have pre-existing elevated liver enzymes?","a":"False, it is a heritable reaction to the molecule administred"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What class of drugs renders complete analgesia?","a":"local anesthetics"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is the recommendation for local anesthestics?","a":"That due to their saftey and signficant benefit, they should be utilized, insofar as possible, with every surgical procedure"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Cardiovascular side-effects, even at low doses, are something a clinicians should consider when using what drug class?","a":"alpha-2 adrenergic agnoists (dexmedetomadine)"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"With alpha-2s which has a shorter duration the sedative effects or the analgesic effects?","a":"analgesic effects"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Which drug is a commonly used N-methyl-D-aspartate(NMDA) receptor antagonist","a":"ketamine"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Studies of ketamine in dogs suggest that it is useful at a ________ dose to prevent pain and is antihyperalgesic and anitallodynic","a":"subanesthetic CRI dosage"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what drug has beneficial effects when given IV for pain after abdominal surgery?","a":"lidocaine in dogs, there is concern about negative cardiovascular affects in cats"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Tramadol is converted to the mu-agnoist M1 metabolite in people and _____ but negligibly in _____.","a":"cats, dogs"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Tramadol has been shown to have a anesthestic-sparing and pain-modifying affect when given ________ in dogs but there is elusive evidence for dosage via an _____ route.","a":"parenterally; oral"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"How are gabapentins analgesic properties produced?","a":"down regulation of calcium channels"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Another NMDA receptor antagonist which has demonstrated utility for dogs with DJD is _______.","a":"Amantadine"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"In humans, ____ are the most effective medications for selective neuropathic pain conditions.","a":"TCAs"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is the mechansim of action for Maropitant?","a":"bloackade of substance-P binding to the neurokinin-1 receptor"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Given IV, this class of drugs can contribute to pain relief in dogs with bone cancer.","a":"Bisphosphonates"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What s a safe and effective chdroprotectant with possible disease-modifying effects?","a":"Ploysulfated glycosaminoglycans"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is one non-pharmacologic modality that is essential to treatment of chronic pain?","a":"weight optimization"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the foundation of rehabilitation?","a":"therapeutic exercise that aims to restore skeletal strength and function, endurance and proprioception, and reduce pain"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is myofascial pain syndrome?","a":"a complex syndrome involving motor, sensory, and autonomic nerve components that is increasingly recognized as an important comorbidity in many chronic pain cases in animals"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what three functions does cold compression serve for acute injury?","a":"reduce pain, reduce inflammation, promote return to function"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what thermal modification is appropriate for chronic injurty?","a":"heat"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the recommended protocol for surgical procedures?","a":"a preoperative opiod plus tranquilizer/sedative, an NSAID, a local anesthetic"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is the recommended additions for procedures with great risk of maladaptive pain?","a":"cold compression, alpha-2 adrenergic agonists, ketamine CRI, Lidocaine CRI, gabapentin, epidural anesthetic"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is \"one of the most significant and underdiagnosed diseases of cats and dogs\"?","a":"DJD"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"what is chief among all preventive and treatment modalities for canine DJD?","a":"weight management"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"in overweight patients, weight loss alone, even _____% improved clinical signs","a":"6.1-8.85"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: There is currently no evidence that a higher risk for NSAID induced adverse effects exists as the duration of treatment increases","a":"1"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"from studies, what percent of cats are estimated to hae clinical signs associated with DJD?","a":"40-92%"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What are the most frequently affected joints in a cat?","a":"hip, stifle, tarsus, elbow, thoracolumbar and lumbosacral areas, usually bilaterally"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"For each ___ year increase in a cat's age, the expected total DJD score increases by ~ ____%","a":"1, 13.6"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is the most common sign of DJD in a cat?","a":"behavioral changes"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"True/False: A retrospective study found that long-term use of meloxicam in cats reduced the lifespan of cats >7 yrs of age with pre-existing, stable CKD compared with cats without CKD","a":"False, there was no reduction in life span"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is the dose and frequency for low-dose Meloxicam?","a":"0.01-0.03 mg/kg q24"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"Meloxicam is approved for long-term use outside the US at what dose?","a":"0.05 mg/kg q24"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"when is hospice care recommended?","a":"for terminally ill patients with a life expectancy is less than 6 months"},{"type":"card","domain":"Physical Health","sub":"Surgery & Anesthesia","q":"What is pallative care?","a":"active total care of patients with disease non-responsive to curative tx"},{"type":"card","domain":"General","sub":"General","q":"T/F: Most missing pet cats and dogs that are recovered are recovered through and animal agency","a":"F. 7% of recovered cats and 35% of recovered dogs through an animal agency. Lord et al 2007"},{"type":"card","domain":"General","sub":"General","q":"Which of the following microchip frequencies are compliant with the International Standards Organization (ISO)?  Which has been the most commonly used in the United Staes for the past 2 decades?\n125 kHz, 134.2 kHz, and 128 kHz","a":"134.2 KHz  is compliant with ISO\n125 is most common in US\nUniversal scanners have been available since 2008, but none of them are 100% sensitive for all microchips. The sensitivy in general is best for 134.2  chips."},{"type":"card","domain":"General","sub":"General","q":"What factors increase the odds of a microchip getting missed during scanning?","a":"Increasing weight of animal, single pass attempt, metal in collars and tags"},{"type":"card","domain":"General","sub":"General","q":"T/F: Median RTO rates are significantly higher for microchipped pets vs non microchipped pets","a":"T (Lord et al 2009)"},{"type":"card","domain":"General","sub":"General","q":"Within the Asilomar Accords how is LRR calculated? How do intelligent people calculate LRR? How is this different than \"save rate\"?","a":"Asilomr:  # animals leaving alive/total number of animals outcomed in given time period (excluding died or lost- wtf?!)\nIntelligent: # animals released alive/# that entered shelter in given time period\nSave rate: # animals released alive/# available for an outcome (includes animals who didn't leave, still in shelter care)\n**ALL of these exclude DOA and ORE"},{"type":"card","domain":"General","sub":"General","q":"T/F: Calculating LRR facilitates comparisons of different shelters (as long as LRR is calculated the same way)","a":"F \"Comparisons across shelters are fraught with difficulties such as the animals seized or euthanized to protect public safety or shelter capacity.\""},{"type":"card","domain":"General","sub":"General","q":"What metric of outcomes and intakes is optimal for facilitating comparisons btwn shelters?","a":"Per capita. Weakness: areas served by multiple shelter agencies"},{"type":"card","domain":"General","sub":"General","q":"When calculating RTO \"rates\", what is the optimal denominator (botton number), and what variables should be separated out?","a":"-- Denominator: only stray intake (not all intakes)\n-- break out by species and AGE** \n--> if you don't limit denominator to strays or separate out by age usually underestimate RTO successes"},{"type":"card","domain":"General","sub":"General","q":"T/F: In order to avoid exceeding housing capacity, shelters should be designed to house the absolute peak population","a":"F. \"Try to design the shelter to meet the median high capacity rather than for the absolute peak population, and implement strategies to meet peak numbers such as flex space and foster programs.\""},{"type":"card","domain":"General","sub":"General","q":"What is the minimum square footage recommended for individual cat housing units? For group rooms? Max number of cats per room?","a":"Individual: 8-11 sq ft (2.5 x 2.5 x 2.5), stacked no more than 2 high\ngroup: 16-18 sq ft per cat (4 x 4 ft)\nnumber of cats: 6-8 per room"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended ratio of food/water bowls to cats in a group housing room? Litterboxes?","a":"Rec ratio is one food and one water bowl and one litterbox per 2-3 cats"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended sq footage per dog?","a":"35-64 sq feet per dog. >4ft wide if poss so that large dogs able to turn w/o nose and tail brushing walls.  Traditional long, thin, open top kennels stimulate barking, jumping, and other stress behaviors. \n 4ft x 16 ft kennel = 64 sq ft, but 8 ft x 8ft room = 64 sq ft and better proportioned."},{"type":"card","domain":"General","sub":"General","q":"How many air changes per hour are recommended for animal housing areas?","a":"10-14 per hour with 100% outdoor air (no recirculation)"},{"type":"card","domain":"General","sub":"General","q":"T/F: HEPA filters are recommended in all animal housing areas","a":"F. HEPA filters provide a very high level of filtration and can be used in a surgery room but not elsewhere b.c they are expensive to buy and maintain, reduce air flow requiring higher-volume fans to operate, and become clogged in animal housing areas."},{"type":"card","domain":"General","sub":"General","q":"Which of the following flooring materials are considered unacceptable in dog housing areas?  Concrete, coatings,, porcelain tiles, carpet tiles, paint, epoxy paint, wood, vinyl","a":"Unacceptale: paint, epoxy paint, wood, vinyl (unacceptable ANYWHERE), carpet tiles, rubber, linoleum\nGood: Concrete (sealed), terrazzo, fluid or trowel applied coatings, porcelain tile"},{"type":"card","domain":"General","sub":"General","q":"Which of the following materials are not appropriate for walls in dog housing units? Solid surface, glass, hard-troweled cement plaster, epoxy coated systems, concrete block with polished face, large porcelain wall tiles, fiberglass reinforced panels, painted  gypseum wallboard, vinyl, standard concrete block","a":"Unacceptable: Hard-troweled cement plaster, fiberglass reinforced panels, painted gypseum wallboard, vinyl, standard concrete block\nOK: Solid surface, glass, epoxy coated systems, concrete block with polished face"},{"type":"card","domain":"General","sub":"General","q":"Which of hte following materials are not appropriate for ceilings in animal housing areas? sprayed cementitious acoustical plaster, aluminum, plastric grid, celing drop in tiles, cement plaster, wood slats, painted gypseum wallboard","a":"Unacceptable:  cement plaster (ok in cat areas), wood slats, painted gypseum wallboard\nOK: sprayed cementitious acoustical plaster \"good accoustical properties and can withstand hosing\"), aluminum, plastric grid, celing drop in tiles, cement plaster (not dogs)"},{"type":"card","domain":"General","sub":"General","q":"All repeat from chapter in infectious dz text, no questions from chapter 4","a":"All repeat from chapter in infectious dz text, no questions from chapter 4"},{"type":"card","domain":"General","sub":"General","q":"No questions from chapter 5","a":"No questions from chapter 5"},{"type":"card","domain":"General","sub":"General","q":"What 3 conditions must be met to establish a VPCR?","a":"--The vet has assumed responsibility for making clinical judgements about the health of the animal and the need for medical treatment. The client has agreed to follow the vet's instructions\n-- The vet has sufficient knowledge of the animal(s) to initiate at least a general or prelim diagnosis of the med condition. This means the vet has recently seen and is personally acquainted with the keeping/care of the animal(s) by virtue of an exam or by medically appropriate and timely visits to the premises where the animal(s) are kept\n-- The vet is readily available or has arranged for emergency coverage for follow up evaluation in the event of adverse reactions or the failure of the treatment regimen"},{"type":"card","domain":"General","sub":"General","q":"T/F: The ultimate responsibilty for the disposition of all controlled drugs, including pre-euth drugs, falls to the veterinarian, regardless of his or her employment status (full time ,part time, volunteer) at the shelter.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Under the legal doctrine of \"charitable immunity,\" a non-profit organization is relived of a tort (a tort is a parivate or civil wrong or injury for which the law provides for damages).","a":"F. This was true historically. However, shelters are fairly seldom actually sued or become the subject of a serious regulatory action."},{"type":"card","domain":"General","sub":"General","q":"T/F: The decision to euthanize an animal during its stray period should account for what range of care an owned animal in a similar condition might typically receive in a private practice.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: An animal's adoptability is one factor that should be taken into consideration when deciding whether or not euthanasia during the stray period is warranted.","a":"F. A stry holding period is meant to give owners time to locate their lost pet and has no relationship to an animals ultimate adoptability if not reclaimed."},{"type":"card","domain":"General","sub":"General","q":"Match term with description: burnout, compassion fatigue\n____ is secondary traumatic stress known as the \"cost of caring\" in caregiving fields\n_____ is \"the syndrome of emotional exhaustion, depersonalization, and reduced personal accomplishment\" suffered at the workplace","a":"compassion fatgue is secondary traumatic stress known as the \"cost of caring\" in caregiving fields\nburnout is \"the syndrome of emotional exhaustion, depersonalization, and reduced personal accomplishment\" suffered at the workplace"},{"type":"card","domain":"General","sub":"General","q":"T/F: Federal law dictates regulations, training and certification of animal shelter euthanasia technicians.","a":"F: Each state has its own regulations, training and certification of animal shelter euthanasia technicians, as well as access or lack therof  to controlled sustances use for pre-euthanasia purposes.."},{"type":"card","domain":"General","sub":"General","q":"T/F: Euth by CO and other gas euthanasia methods are inhumane","a":"T. More and more states are recognizing this and enacting legisaltion to ban gas chambers and move toward requiring euth by injection (EBI)"},{"type":"card","domain":"General","sub":"General","q":"Choose positive or negative:\n__________ coping strategies for shelter staff include adopting animals from the shelter who might otherwise have been euthanized.","a":"Positive coping strategies include adopting animals from the shelter who might otherwise have been euthanized."},{"type":"card","domain":"General","sub":"General","q":"T/F: Allowing euth technicians to determine whether they do or do not wish to be involved in the euthanasia of animals they may have already become attached to is helpful for mitigating compassion fatigue","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Technical proficiency does not diminish euthanasia related stress.","a":"F. It greatly diminishes euth related stress"},{"type":"card","domain":"General","sub":"General","q":"T/F: Euth policies should be enforced in an objective and consistent manner, including formal criteria about which animals should be euth'd","a":"T. Lack of criteria creates an undue legal and emotional burden on the person or persons charged with making euth decisions."},{"type":"card","domain":"General","sub":"General","q":"T/F: Deviation from the use of Euth by injection may be justified on rare occasions","a":"T, for example an animal may have to be euthanized in the field by gunshot to immediately end their suffering or protect others from imminent harm."},{"type":"card","domain":"General","sub":"General","q":"T/F: Thoracic compression, decapitation, and cervical dislocation are considered conditionally acceptable mehtods of euthanasia for birds in the AVMA guidelines.","a":"T. BUT, these methods should be avoided because more humane methods are available, but also because some veterinary experts have expressed concerns that these methods are in fact inhumane.  THose who fail to recognize the broad scope of the report- that is, a scope not limited to animal shelter euth- may misinterpret these recommendations and inccorectly apply them for use in the shelter setting."},{"type":"card","domain":"General","sub":"General","q":"Fill in the blanks: \"The chosen method of _____ must induce loss of consciousness and ______ without causing pain, distress, anxiety, or apprehension; be quick, reliable, irreversible, appropriate for the species, age and health of the animal; and be safe for personnel.\"","a":"\"The chosen method of euth must induce loss of consciousness and death without causing pain, distress, anxiety, or apprehension; be quick, reliable, irreversible, appropriate for the species, age and health of the animal; and be safe for personnel.\""},{"type":"card","domain":"General","sub":"General","q":"T/F: Any person associated with decision making regarding the shelter's euthanasia process should be familiar with the most current edition of the AVMA Guidelines for Euth.\"","a":"T. Consider yourself warned."},{"type":"card","domain":"General","sub":"General","q":"What are some of the problems associated with CO as a method of euth?","a":"-- Extremely toxic to both animals and humans. Shelter works have become ill and even died. \n-- can potentially explode at high concentrations\n--  Chronic exposure can also cause serious human health problems\n-- placing mult animals in a CO chamber can dilute the effective concentration that each animal receives, creating a haphazard euth experience that can be prolonged\n-- noise of rapid gas flow can be frightening to animals\n-- slow gas flow, though quieter, may prolong time to loss of consciousness, and may contribute to convulsions and muscle spasms prior to loss of consciousness\n-- some dogs exhibit vocalization and agitation prior to death\n- juv, aged, pregnant, sick and injured animals can experience  delayed absorption and circulation of CO which can lead to inhumane deaths"},{"type":"card","domain":"General","sub":"General","q":"T/F: With or without a tranquilizer, euthanasia via CO gas is more expensive than EBI","a":"T. N Carolina: w/o tranq $4.66, w/ tranq $5. EBI: $2.29"},{"type":"card","domain":"General","sub":"General","q":"By far, the preferred method for euthanizing shelter dogs and cats (and most other species) is injection of _________, which is a class ____ controlled substance.","a":"By far, the preferred method for euthanizing shelter dogs and cats (and most other species) is injection of sodium pentobarbital, which is a class II controlled substance.  It is the only acceptable method of euth for shelter dogs and cats recommended by ASV, ASPCA, HSUS, and AHA."},{"type":"card","domain":"General","sub":"General","q":"List the 5 stages of anesthesia that are progressed through after administering a fatal dose of sodium pentobarbital IV","a":"I sedation- calm and sleepy\nII Involuntary excitement\nIII Light anesthesia\nIV Deep anesthesia\nV Apnea (respiratory arrest) followed by cardiac arrest"},{"type":"card","domain":"General","sub":"General","q":"Some sodium pentobarbital formulations are class III controlled substances due to the addition of ___________ to enhance cardiac arrest and diminish human abuse potential.","a":"phenytoin"},{"type":"card","domain":"General","sub":"General","q":"T/F: A combo of pentobarbital with a neuromuscular blocking agent (e.g. curariform) is not an acceptable blocking agent.","a":"T, e.g. T-61 (no longer avail in US, is in Canada and other countries). If it is not injected IV very slowly there is a concern that intense pain and axiety may occur if paralysis takes effect before the loss of consciousness."},{"type":"card","domain":"General","sub":"General","q":"Most formulations of sodium pentobarbital are this concentration","a":"390 mg/ml. Other formulations fyi 260, 324, 389 mg/ ml."},{"type":"card","domain":"General","sub":"General","q":"Most formulations of sodium pentobarbital are administered at a dose of ___ml per ___ lbs body weight for IV administration and ____ ml per ____ lbs delivered IP for cats.","a":"Most formulations of sodium pentobarbital are administered at a dose of  1 ml per 10 lbs body weight for IV administration and 3 ml per 10 lbs delivered IP for cats."},{"type":"card","domain":"General","sub":"General","q":"After IV injection, sodium pentobarbital takes ____ seconds to cross into the _____, the primary site of action","a":"After IV injection, sodium pentobarbital takes 45-90 seconds to cross into the brain, the primary site of action. in contrast, IP injection typically takes 5-15 minutes to take effect."},{"type":"card","domain":"General","sub":"General","q":"IV injection of sodium pentobarbital is the preferred route for adult dogs and puppies over ____ lbs","a":"IV injection of sodium pentobarbital is the preferred route for adult dogs and puppies over 10 lbs"},{"type":"card","domain":"General","sub":"General","q":"The most common veins chosen for IV injection of sodium pentobarbital are:","a":"cephalic (front leg), medial saphenous vein (rear leg). Also ok: jugular or lateral saphenous (rear)"},{"type":"card","domain":"General","sub":"General","q":"____ (route) of injection of sodium pentobarbital is particular favored by animal shelters as a method that provides a humane death for feral, fearful, or fractious cats.","a":"IP of injection of sodium pentobarbital is particular favored by animal shelters as a method that provides a humane death for feral, fearful, or fractious cats.  One the injection is completed, animals should be placed in a dark, fairly confined space, where they can transition to unconsciousness and death without fear and distress inflicated by human touch or proximity."},{"type":"card","domain":"General","sub":"General","q":"Why is IP injection of sodium pentobarbital inappropriate for dogs and puppies over 10 lbs","a":"Dogs and pups greater than 10 lbs tend to struggle to right themselves as they experience the involuntary excitement stage of anesthesia (stage II) after IP injection of sodium pentobarb"},{"type":"card","domain":"General","sub":"General","q":"T/F: Formulations of sodium pentobarb without phenytoin are not recommended for IP injection","a":"F. Formulations of sodium pentobarb with phenytoin are not recommended for IP injection as the phenytoin may exert cardiac arrest prior to loss of consciousness from the phenytoin"},{"type":"card","domain":"General","sub":"General","q":"T/F: The AVMA Euth guidelines list IC injection of sodium pentobarbital in conscious animals as conditionally acceptable.","a":"F. The AVMA Euth guidelines condemns IC injection of sodium pentobarbital in conscious animals"},{"type":"card","domain":"General","sub":"General","q":"T/F: Intrahepatic administration of sodium pentobarb in cats is considered unacceptable for animal shelters.","a":"T: stretch receptors in the capsule are exquisitely painful when stretched, and stretching occurs if a volume of fluid is injected into the liver."},{"type":"card","domain":"General","sub":"General","q":"T/F: sodium pentobarbital should never be injected SQ or IM","a":"T. Very painful, slow absorbtion"},{"type":"card","domain":"General","sub":"General","q":"Match the terms with the definition: anesthesia, analgesia, sedation, tranquilization\n-- A state in which an animal is calm and less responsive to stimulation, usually accompanied by drowsiness or sleep\n-- absence of sensibility to pain, particularly the loss of pain without loss of consciousness\n-- A state in which an animal is calm and less responsive to stimulation, usually without sleepiness (although it may allow a tired animal to sleep voluntarily)\n-- loss of feeling or sensation, especially the loss of pain sensation","a":"-- A state in which an animal is calm and less responsive to stimulation, usually accompanied by drowsiness or sleep---  sedation\n-- absence of sensibility to pain, particularly the loss of pain without loss of consciousness---- analgesia,\n-- A state in which an animal is calm and less responsive to stimulation, usually without sleepiness (although it may allow a tired animal to sleep voluntarily)---- tranquilization\n-- loss of feeling or sensation, especially the loss of pain sensation--  anesthesia"},{"type":"card","domain":"General","sub":"General","q":"T/F: Pre-euth tranquilization should be avoided in animals who are not fractious","a":"F: Tranquilization, sedation, or anesthesia should be provided to animals who are fearful, unsocialized or fractious"},{"type":"card","domain":"General","sub":"General","q":"T/F: Mother animals and their neonates are a exception to the rule of separation from other animals during euth.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Choose mother, babies: The ______ should be euthanized before the _____","a":"The mother should be euth before their babies so that they will not be distressed at being separated from their litter, or by seeing their dead offspring. :("},{"type":"card","domain":"General","sub":"General","q":"T/F: The movements observed before fetal death are a great welfare concern.","a":"F. The movmts often observed before fetal death are subcortical reflex responses to increasing hypoxemia and hypercapnea, and are not a cause for welfare concern. If fetuses are kept in the uterus until they are dead, no welfare compromise occurs."},{"type":"card","domain":"General","sub":"General","q":"Using an appropriate, effective and humane method of ______, chemical, physical or a combo of the two can mean the difference between a distressful and unsafe end to the animal's life, and an end that is both peaceful for the animal and safe for the person administering euthanasia.","a":"Using an appropriate, effective and humane method of restraint, chemical, physical or a combo of the two can mean the difference between a distressful and unsafe end to the animal's life, and an end that is both peaceful for the animal and safe for the person administering euthanasia. Restraint probably the most important factor of all for providing an animal with a good death."},{"type":"card","domain":"General","sub":"General","q":"______ (pre euth drug) is an inexpensive phenothiazine tranquilizer, non controlled substance.","a":"Acepromazine. Can be given IM, SC or orally."},{"type":"card","domain":"General","sub":"General","q":"T/F Acepromazine used alone will calm fractious and fearful animals, and thereby  protect euthanasia techs from an aggressive animal.","a":"F. It will calm fractious and fearful animals, but it will not protect euth techs from an aggressive animal. It can also cause contradictory (to tranquilization) symptoms of aggressiveness and gerernalized CNS stimulation."},{"type":"card","domain":"General","sub":"General","q":"Common doses of pre euth drugs used in cats and dogs:\nAcepromazine\nXylazine","a":"Ace cats: 0.25 mg/lb, dogs: 0.5 mg-1.0 mg/lb\nXylazine  cats/dogs: 1 mg/lb\nKetamine  NOT USED ALONE (Ket-Xyl \"Pre Mix\" = 0.5 ml/10 lb I think? Per HSUS manual\nTelazol:  cats/dogs: 0.1-0.4 ml/10lb (low volume --> cost comparable to other pre euth drugs as dosed)"},{"type":"card","domain":"General","sub":"General","q":"_____ (pre euth drug) is an alpha-2 adrenergic agonist that is inexpensive and non controlled, can be administered SC or IM. It is classified as a sedative/analgesic with relaxant properties.","a":"Xylazine"},{"type":"card","domain":"General","sub":"General","q":"What is the most significant drawback of using xylazine?","a":"It frequently causes vomiting in cats and dogs, decreasing the quality of the euth procedure.  Effect can be diminished by fasting the animal or combining with ace or ketamine. It may also render animals more reactive to loud noises."},{"type":"card","domain":"General","sub":"General","q":"_____ (pre euth drug) is a rapidly acting general anesthetic with analgesic activity. Approved for use in primates and cats. Used alone it causes increased muscle tone and may induce seizures. Class III controlled substance. Inexpensive.","a":"Ketamine. Typically combined with ace or xylazine."},{"type":"card","domain":"General","sub":"General","q":"Administration of an apprpropriate dosage of a combo of __________ (drugs) can provide anesthesia that is deep enough for an IC injection of sodium pento.","a":"Ketamine-xylazine."},{"type":"card","domain":"General","sub":"General","q":"____ (pre euth drug) provides good anesthesia combined with muscle relaxation and analgesia. Per volume cost is signifcantly higher than any other commonly used pre-euth drugs.  Class III controlled substance.  Administered IM, may sting.","a":"Telazol (tiletamine-zolazepam).  (low volume dose--> cost comparable to other pre euth drugs as dosed)"},{"type":"card","domain":"General","sub":"General","q":"______ (pre euth drug) is sometimes used as a pre-euth drug. It may be administered orally to produce sedation or light anesthesia, or injected IP, followed by IC or IV injection once the animal is anesthetized.","a":"Sodium pentobarbital"},{"type":"card","domain":"General","sub":"General","q":"What is generally the optimal number of people working together to sedate, tranquilize, anesthetize, and/or euthanize an animal","a":"Two people"},{"type":"card","domain":"General","sub":"General","q":"What vein is commonly used for IV injection of sodium pentobarbital in socialized dogs?","a":"Cephalic."},{"type":"card","domain":"General","sub":"General","q":"How does the oral dose of sodium pentobarbital compare to the IV dose? IP vs IV?","a":"Oral or IP: three times the IV dose (3ml/10lb). For oral, can mix reconstituted liquid or powder in food. Powder dose: 1 grain powder per lb. 1 tsp/40 lb dog, 1 TBSP for 100 lb dog. If you use powder label the bottle clearly so that it is not erroneously reconstituted. For drug logs record weight in grams of powder. \n\n*** FYI the textbook actually says the dose for IP is \"3ml/lb\" (p487) but I'm pretty sure that's wrong."},{"type":"card","domain":"General","sub":"General","q":"If administering sodium pentobarb orally in food, what should you do with uneaten food ?","a":"Dispose of properly to ensure it is not mistakenly eaten by another animal. Recommended to dispose of teh uneaten food with the body of the animal."},{"type":"card","domain":"General","sub":"General","q":"What is the appropriate location for IP administration of sodium pentobarb to conscious cats and kittens and pups under 10 lbs?","a":"The right lateral side of the abdomen, caudal to the umbilicus."},{"type":"card","domain":"General","sub":"General","q":"After IP injection of sodium pentobarb, if death has not occurred by ____ mins, a second dose should be administered.","a":"After IP injection of sodium pentobarb, if death has not occurred by 15 mins, a second dose should be administered."},{"type":"card","domain":"General","sub":"General","q":"T/F: Protective animal handling gloves, control poles, and cat tongs are all useful tools for restraint of cats who are too fractious or fearful to be restrained manually","a":"F. Gloves offer poor control and increase the chance of injury to the euth tech, while doing nothing to address the cat's apprehension. Control poles and cat tongs have enourmous potential for injury and abuse, and their use is not consistent with providing a humane death for cats. Ideally the cat is in a plastic carrier, metal transfer cage, or humane trap when the euth process begins and is not removed until deeply tranquilized or anesthetized. A squeeze cage is also ok. Netting is ok."},{"type":"card","domain":"General","sub":"General","q":"What is the recommeded route of injection of sodium pentobarb for each of the following species?\nG pig\nFerret\nRabbits\nSmall rodents\nRaccoons, squirrels, opoossums, skunks","a":"G pigs: IP\nFerrets: IP\nRabbits: IP if tolerates handling, ear vein after tranq. Double the dose (2 ml/10lb)\nSmall rodents: IP minimizing manual restraint if possible, careful not to drop them (Work over a box or cage on counter)\nRaccoons, squirrels, opossums, skunks: IP FOLLOWING IM pre euth drugs (like a feral cat). Skunks- good luck not getting sprayed"},{"type":"card","domain":"General","sub":"General","q":"What is the recommeded route of injection of sodium pentobarb for each of the following species?\nReptiles (lizard, snake, others)\nBirds\nFish/Amphibians\nPigs\nHorses\nFarm animals (sheep, goats, cattle)","a":"What is the recommeded route of injection of sodium pentobarb for each of the following species?\nReptiles (lizard, snake, others)- if you cannot determine species ask herpetologist for help. assume venemous and horrible.  IM telazol followed by IV, IC or intracoelomic route for sodium pentobarb\n----- Snake heart location varies by species, generally 1/3 of body length from head (may be palp or Doppler)\n----- Lizard: palp heart or IV tail vein\n----- very slow metabolism- may appear dead when not. Place in room temp enclosure for 24-48 hours for observation to verify euth. \nBirds - consult with experts for appropriate restraint techniques for given bird\n---- IV into brachial vein on medial wing  near cubital (elbow) joint; IM pre med of ketamine/xylazine or telazol if bird frightened or severely injured. After IM premed also ok to do IP (directly below keel) or IV\nFish/Amphibians- MS 222 (Fiquel or tricaine methanesulfonate), immerse critter in 350 mg MS 222/1L of water  for 10 min\nPigs- premed with 1:1 Ace/ketamine (1 ml/10lbs IM **thigh muscle w/ long needle!!)) followed by IV sodium pentobarb into cephalic vein (you won't be able to see it, but in same place as dog) note: pigs likely to scream no matter how gentle and calm you are. \nHorses- quit your job because the horse will probably kill you on the way out. (\"Equine euth is often inelegant, controversial, and always potentially dangerous. Even when properly tranquilized prior to admin of IV sodium pentobarb, a horse can fall suddenly or violently, or rear up, potentially striking handlers.\") Two experienced horse handlers are needed to euth horses.  Recommend premeds always; follow w/ 1 ml/10 lbs IV (should have jug catheter in place).  gunshot/captive bolt technically ok, but generally should be avoided except for dire circumstances or if you won't be able to keep scavengers from carcass.Captive bolt should be followed by exsanguination or pithing, and it's technically difficult to do well. \nFarm animals (sheep, goats, cattle) - tractable sheep, goats, calves- IV into cephalic or jug.  Adult cattle sould be jug vein only. Premed tranq with just xylazine (0.1 mg/lb)"},{"type":"card","domain":"General","sub":"General","q":"What is the significance of the Migratory Bird Treaty Act of 1918 for euth of birds in animal shelters?","a":"It requires a permit from the UW fish and wildlife service (FWS)  to transport, possess, house or euth migratory birds. More than 800 species are covered including  sparrows, grackles, pigeons, geese, owls, and other birds of prey.  It is safest to assume any wild bird is a migratory bird covered by this act."},{"type":"card","domain":"General","sub":"General","q":"List as many signs that can help to verify death as you can. Which is the most reliable?","a":"Loss of corneal and pupillary reflexes, no femoral pulse, no signs or ascultation of respiration, no palpable or asucltable heartbeat. Pale or cyanotic mucous membranes. Rigor mortis is the most reliable sign."},{"type":"card","domain":"General","sub":"General","q":"When does rigor mortis set in? How reliable is this timeframe?","a":"Rigor mortis usually sets within a few hours then gradually dissipates. Birds- within minutes. Hypothermia- take longer to set in, hyperthermia- faster. May fail to develop in juveniles or elderly/severely debilitated."},{"type":"card","domain":"General","sub":"General","q":"T/F: Foster programs are a reliable program for reducing costs to the shelter","a":"F. Foster programs may help to maximize resources but they may not always reduce costs.  Outsourcing care may reduce the shelter's food and basic care expenses if this is assumed by the foster caregivers. However, expanding the overall number of animals under care by creating an additional offsite housing area is likely to increase overall costs."},{"type":"card","domain":"General","sub":"General","q":"Estimating _______ capacity and comparing it to intake expectations may help with planning for both housing and positive outcome for the animals once their care in foster homes has been completed.","a":"Estimating adoption driven capacity and comparing it to intake expectations may help with planning for both housing and positive outcome for the animals once their care in foster homes has been completed."},{"type":"card","domain":"General","sub":"General","q":"How do you calculate an estimate of the number of foster homes that will be needed in a given month?","a":"Monthly kitten intake divided by 2 (slower months) or 3 (busier months)"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate the maximum number of foster homes that will be needed across a year?","a":"Take total # foster homes for peak months of intake, and then accounf for LOS. Eg Monthly July intake = 30 kittens (10 foster homes), August intake = 60 kittens (20 foster homes), AVG LOS in foster = 2 months, therefore need 10+20 foster homes total (at most)"},{"type":"card","domain":"General","sub":"General","q":"T/F According to ASV Guidelines for Standards of Care, attempting behavior modification with aggressive animals poses concerns due to safety and liability risks; animals believed to be dangerous should not be rehomed.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"What information should behavioral treatment plans include?","a":"treatment goals and target dates, written behavioral guidelines, regular behavioral reevaluations"},{"type":"card","domain":"General","sub":"General","q":"T/F: Foster to adopt programs are only appropriate for animals whose legal holding period has elapsed","a":"F. Although the adoption cannot be legally finalized until the stray hold period has expired, in many communities, especially where owner reclaims are rare, this pathway provides animals an option for the shortest possible LOS and decreases capacity requirements for the shelter."},{"type":"card","domain":"General","sub":"General","q":"Fospice caregivers should receive training to make realistic ____ __ ____ assessments, but fospice patients must receive frequent veterinary and ____ __ ____ (same term) assessments by shelter staff as well. Scales are available.","a":"Quality of Life"},{"type":"card","domain":"General","sub":"General","q":"In the context of foster care programs, what are readiness programs?","a":"Readiness programs are designed to decrease the length of time an animal must spend in the shelter on the way to adoption. One example is to have an on-call volunteer driver squad who will deliver the kittens to their foster caregivers immediately after intake. Readiness systems examine barriers that might keep animals in the shelter longer than necessary and make every attempt to move them out."},{"type":"card","domain":"General","sub":"General","q":"All animals should receive a behavior evaluation prior to foster placement. Ideally, behavior would be evaluated using a combination of ______ and ___________","a":"All animals should receive a behavior evaluation prior to foster placement. Ideally, behavior would be evaluated using a combination of history and observations made in the shelter."},{"type":"card","domain":"General","sub":"General","q":"Animals should be treated prophylactically with a broad spectrum dewormer  effective against at least _______and _______, starting at _____ weeks of age, and repeated at ____ week intervals until ____ months of age. In addiition, because _____ are not uncommon and are not affected by a general broad spectrum dewormer, puppies and kittens should be treated at ____ weeks of age with a _____cidal medication prior to placement in foster care, and retreated ______ days later.","a":"Animals should be treated prophylactically with a broad spectrum dewormer  effective against at least hookworms and roundworms, starting at 2-3 weeks of age, and repeated at 2 week intervals until 2 months of age.  In addiition, because coccidia are not uncommon and are not affected by a general broad spectrum dewormer, puppies and kittens should be treated at 2 weeks of age with a coccidiocidal medication prior to placement in foster care, and retreated 7-14 days later."},{"type":"card","domain":"General","sub":"General","q":"T/F: For cats blood tests should be performed for feline leukemia and FIV to help screen for infectious animals.","a":"T. but if testing is performed just after intake it should be noted in the animal's record. Cats should be retested 1-3 months after intake to confirm their initial status."},{"type":"card","domain":"General","sub":"General","q":"T/F: If cats who test positive for FeLV or FIV are sent to foster they should be sent only to homes where resident cats are also test-positive, or where there are no other cats.","a":"T. Wah wah."},{"type":"card","domain":"General","sub":"General","q":"T/F Dogs do not need to be heartworm tested prior to foster placement, but they should be started on preventative.","a":"F. Dogs should be tested for HW disease AND started on preventative treatment prior to foster placement.  But if a shelter cannot afford to test for HW status, preventative should still be started."},{"type":"card","domain":"General","sub":"General","q":"T/F: cats should be administered HW treatment prior to placement in foster care.","a":"T (dumb)"},{"type":"card","domain":"General","sub":"General","q":"How often should pups or kittens  be examined, weighed, dewormed and revaccinated?","a":"every 2 weeks until they reach 18-20 weeks of age."},{"type":"card","domain":"General","sub":"General","q":"Pathway monitoring for foster programs should evaluate LOS of what 2 pathways?","a":"avg LOS in shelter waitinf for foster pick up, and avg LOS in foster, including a specific evaluation of time spent waiting for services or housing needs to progress toward adoption.  Increasing LOS may indicate the system is overextended."},{"type":"card","domain":"General","sub":"General","q":"In Colorado, regulations dictate that _____ visits are required for all foster caregivers. In Illinois, foster homes must have a _____ and must not exceed ____ animals at any given time.  In Virginia a statement is required  from each foster caregiver attesting that they have never been convicted of ____________","a":"In Colorado, regulations dictate that  home visits are required for all foster caregivers. In Illinois, foster homes must have a permit and must not exceed 4(!) animals at any given time (\"sorry mama cat, we're gonna have to leave 2 of your babies behind\").  In Virginia a statement is required  from each foster caregiver attesting that they have never been convicted of animal abuse, cruelty, neglect or abandonment"},{"type":"card","domain":"General","sub":"General","q":"T/F Home visits can serve an important role in ensuring that a foster home is a suitable environment for shelter animals","a":"T (!). However, although valuable in some circumstances, conducting home visits for all foster caregivers can be a difficult goal to achieve."},{"type":"card","domain":"General","sub":"General","q":"In the context of foster care programs, what is cumulative exposure risk?","a":"Infectious disease risks from increasing numbers of fosters and from combining unrelated animals. These risks should be carefully considered and balanced with the benefits of expanding the number of animals who can be placed in foster care."},{"type":"card","domain":"General","sub":"General","q":"Accumulated infectious risk can be theoretically quantified as an expsoure ris level. One kitten would have an exposure risk of ___(#). A second (unrelated) kitten added into the same home would give the environment an exposure risk of  ____ (#). If three more unrelated kittens or family units were added, the exposure risk would then be _____ (#).  If 4 of these kittens are then sent out to adoption, the accumulated exposure risk level  for the remaining kitten and that particular foster home would be _____ (#). If a new kitten were added that kitten's exposure risk level  would then be ____( #).","a":"Accumulated infectious risk can be theoretically quantified as an expsoure ris level. One kitten would have an exposure risk of 1. A second (unrelated) kitten added into the same home would give the environment an exposure risk of  2. If three more unrelated kittens or family units were added, the exposure risk would then be 5.  If 4 of these kittens are then sent out to adoption, the accumulated exposure risk level  for the remaining kitten and that particular foster home would be 5. If a new kitten were added that kitten's exposure risk level would then be 6."},{"type":"card","domain":"General","sub":"General","q":"How can foster homes that take more than one family unit avoid developing or maintaining high accumulated infectious disease risks?","a":"Periodically empty their homes. Keep in mind family pets in the home may also contribute to the cumulative risk e.g. coronavirus/FIP)"},{"type":"card","domain":"General","sub":"General","q":"Under what circumstances is combining unrelated animals in foster care a reasonable choice?","a":"Singleton pups or kittens may experience more normal behavioral development if they are combined with another well-screened singleton. Only likely worth the risk of long-term foster care is needed. However, adding a singleton to a litter may benefit the singleton but is unlikely to balance the risk to the rest of the litter."},{"type":"card","domain":"General","sub":"General","q":"If a foster home can or will not keep foster pets isolated in the home for the duration of fostering, what is the minimium recommended quarantine period in the foster home at the beginning?","a":"2 weeks"},{"type":"card","domain":"General","sub":"General","q":"In addition to core vaccines and rabies, what additional vaccines are recommended for pets of foster families?","a":"FeLV vax of cats, influenza vax for dogs, annual intranasal vax for resp pathogens for dogs."},{"type":"card","domain":"General","sub":"General","q":"What the name of a validated questionnaire for owners surrending their dogs to animals shelters?","a":"CBARQ  (Canine behavioral assessment and research questionnaire)"},{"type":"card","domain":"General","sub":"General","q":"What is the name of the behavioral assessment that is the gold standard?","a":"There is no single assessment that represents a gold standard."},{"type":"card","domain":"General","sub":"General","q":"Define temperament, and describe why \"temperament test\" is an inappropriate term for a shelter aggression assessment","a":"Temperament refers to traits that are stable, and  difficult to distinguish from learned behaviors. In shelters we can only try to  capture a snapshot of bheavior to identify the likelihood that a dog may show aggression in certain situations. Behavior can change with experience and through learning."},{"type":"card","domain":"General","sub":"General","q":"T/F: Behavior assessments should no be used to test animals in a \"pass-fail\" manner","a":"T"},{"type":"card","domain":"General","sub":"General","q":"List the 3 main methods used to gather information about a shelter dog's behavior.","a":"History before arriving at the facility, observations made by people in the shelter, and aggression assessments."},{"type":"card","domain":"General","sub":"General","q":"The information gathered from an aggression assessment  can be used to  do 2 (recommended) things:","a":"-- create a B mod protocol\n-- or ensure the dog is placed in a supportive environment for the behavior problems identified"},{"type":"card","domain":"General","sub":"General","q":"The ideal time to conduct your initial assessment  of owner relinquished dogs is _________","a":"at the time of intake.  Owners are apt to lie about owner-directed aggression and stranger-directed fear (Segurson, Serpell, Hart 2005). Doing the assessment with the owner present can add valuable information about the dog's behavior."},{"type":"card","domain":"General","sub":"General","q":"Study at WHS regarding SAFER. Dogs assessed at intake and 72 hours later.  ____% showed the same behavior in both assessments. What behavior most likely to change between the 2 assessments?","a":"85% showed the same behavior in both. Food bowl behavior (many dogs did not eat when relinquished)."},{"type":"card","domain":"General","sub":"General","q":"The ideal time to conduct your initial assessment  of stray dogs is _________","a":"the day before the end of their stray holding period. Or, if stray period > 5 days, do it on day 3. \"While there are no data to support that higher stress decreases the predictive value of an assessment, most behaviors would recommend a 3 day wait before assessing.\" Old studies have shown that blood cortisol levels in dogs were highest  during the first 3 days in the shetler and gradually declined thereafter.  HOWEVER, \"behavioral stress can be expressed in a range of ways and is difficult to correlate with cortisol levels in plasma, urine, or saliva.\""},{"type":"card","domain":"General","sub":"General","q":"______ is the first step in any behavior modification program","a":"Offering daily enrichment"},{"type":"card","domain":"General","sub":"General","q":"Two vital ways to improve animal welfare is by providing environmental enrichment  for all animals starting on day _____ of shelter stay, and and adding ________ as soon as possible.","a":"Two vital ways to improve animal welfare is by providing environmental enrichment  for all animals starting on day ONE of shelter stay, and and adding social interaction with humans and conspecificss as soon as possible."},{"type":"card","domain":"General","sub":"General","q":"List formal evaluations that not only try to identify risk factors for aggression, but also provide information about matching dogs or cats to potential adopters.","a":"-- CBARQ- surrenderer questionnaire (only for dogs living in known home)\n-- Match-Up II\n-- ASPCA Meet your Match Canineality or Felineality\n----\"research points to the success rate of adoptions being enhanced when new owners have realistic and sensible expectations of the time, expense, and effort required for the individual pet.\""},{"type":"card","domain":"General","sub":"General","q":"The Adoption Forum II, sponsored by PetSmart Charities in 2003 established four non negotiable adoption policies. List as many as you can.","a":"1) The animal must be spayed or neutered\n2) No animal will be adopted to an applicant with a knonwn history of animal or child abuse. \n3) No animal will be adopted to an individual who is suspected of being drunk or high at time of application\n4) No animal will be adopted to be used as a food source."},{"type":"card","domain":"General","sub":"General","q":"In a 2002 study by Marder, what were the most common behavior issues reported following adoption?","a":"House soiling, destruction, barking, and aggression to people.  Most behaviors declined over time, aggression to individuals outside of the home increased."},{"type":"card","domain":"General","sub":"General","q":"T/F: Behavior issues are often the primary reason that dogs are returned to shelters","a":"T. one study found 89.7% of returns were due to perceived behavior issues."},{"type":"card","domain":"General","sub":"General","q":"How many and at what intervals should contacts with adopters be made in order to identify and provide support for post-adoption behavior issues?","a":"Most professionals in the field suggest mult contact with adopters, one ~3 days after adoption, one ~ 3 weeks after adoption, and one~3 months after adoption"},{"type":"card","domain":"General","sub":"General","q":"What is inter-evaluator reliability, and ideally is it high or low?","a":"Different evaluators should each produce and observe the same behaviros when assessing the same animal. IT should be high."},{"type":"card","domain":"General","sub":"General","q":"T/F: Ideally enrichment is started as soon as aberrant behavior is noted","a":"F: Effective enrichment provides both therapy and PROTECTION against past, present and even future stressors if thoughtfully implemented and carefully monitored."},{"type":"card","domain":"General","sub":"General","q":"What behaviors might be noted in a group housing room for cats with inadequate space per cat? About how much personal space do group housed cats prefer to have?","a":"Cats may display aggression or avoid each other by reducing activity. Cats prefer to maintain about 3 feet of personal psapce in group enclosures."},{"type":"card","domain":"General","sub":"General","q":"How much space do cats need between functional areas? What behaviors might be seen if space between functional areas is inadequate?","a":"Cats need at least 20 inches between functional areas (sleeping, eating, litterbox). Cats may refrain from using a litterbox too close to a food source, and vice versa."},{"type":"card","domain":"General","sub":"General","q":"T/F: When cages allow an animal to view all areas of their housing at once without moving they may have less motivation to gain information and ability to retreat from aversive stimuli which can be sources of stress.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Bedding should only be provided to animals who have a low risk of breaking with infectious disease","a":"F. Beeding should be provided to all animals. If provides tactile comfort, aids thermoregulation, differentiates resting from other functional areas, and facilitates diverse behaviors including nesting, exploration and hiding."},{"type":"card","domain":"General","sub":"General","q":"WHat are recommended methods for providing dogs with social interaction with other dogs?","a":"Pair housing two compatible dogs or regular, supervised social group sessions are viable options."},{"type":"card","domain":"General","sub":"General","q":"Cats have a flexible social system whereby the congregate around reliable food sources but, lacking social behaviors that diffuse conflict, they use _______ to reduce social tension","a":"Cats have a flexible social system whereby the congregate around reliable food sources but, lacking social behaviors that diffuse conflict, they use distance to reduce social tension"},{"type":"card","domain":"General","sub":"General","q":"Compatible cats can be housed in pairs or groups not exceeding _____ (#) cats","a":"43388.0"},{"type":"card","domain":"General","sub":"General","q":"Different types of toys can be used to promote expression of different types of species-appropriate behavior and should be changed at least ______ (frequency) to maintain interest","a":"Different types of toys can be used to promote expression of different types of species-appropriate behavior and should be changed at least daily to maintain interest"},{"type":"card","domain":"General","sub":"General","q":"T/F Adopters prefer dogs with toys, even if they are not currently using them","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F Cats who are resting quietly in their cages are more likely to be adopted than those who are active","a":"F. CAts who are active in their cages are more likely to be adopted."},{"type":"card","domain":"General","sub":"General","q":"Choose: lavender, rosmary, peppermint, chamomile. Diffusing scents of _____ and ____ in dog kennel areas can increase resting and reduce barking, while ____ and ___ _ can be excitatory, which could be beneficial for depressed individuals.","a":"Diffusing scents of lavender and chamomile in dog kennel areas can increase resting and reduce barking, while rosemary and peppermint can be excitatory, which could be beneficial for depressed individuals."},{"type":"card","domain":"General","sub":"General","q":"For cats, the scent of ____ (and sometimes ____ and _____) often stimulates activity","a":"For cats, the scent of catnip( and sometimes ginger and cinnamon) often stimulates activity"},{"type":"card","domain":"General","sub":"General","q":"Is there evidence supporting the use of DAP in shelters? What about Feliway?","a":"Tod, Brander and Waran 2005: In sheltered dogs barking was reduced and and resting increased after 7 days exposure to DAP.\nUnpublished Study by Brander: no effects of Feliway on the behavior of group housed sheltered cats."},{"type":"card","domain":"General","sub":"General","q":"T/F:While ideal, providing behavior enrichment is optional in animal shelters that are understaffed, under resourced, or struggling to manage infectious diseases.","a":"F: These excuses are not acceptable for a regulated research facility housing cats and dogs, and should not be acceptable for animal shelters."},{"type":"card","domain":"General","sub":"General","q":"Court cases involving animals from dogfighting, hoarding, or puppy mill situations are oftens strengthened by a ________ evaluation","a":"BEHAVIOR"},{"type":"card","domain":"General","sub":"General","q":"What is the primary goal of a disposition evaluation?","a":"To gain an overview of the dog's characteristic behavior patterns, potentially uncovering bheaviors that could prove prolematic  for the dog's future as a pet, as a working animal,  or as a resident at a long-term sanctuary."},{"type":"card","domain":"General","sub":"General","q":"The two most thorough behavior evaluations currently used to evaluate dogs in American shelters are","a":"Assess-a-Pet and MAtch-Up II. SAFER can be enhanced with additional subtests to render it more complete for a disposition evaluation"},{"type":"card","domain":"General","sub":"General","q":"What are the 8 components of a thorough, standard behavior evaluation?","a":"-- Initial greeting and cage behavior\n-- Handling- start with friendly/noninvasive, progress to less pleasurable contact\n-- Play- assess arousal progression\n-- Food guarding- use yummy (canned) food, escalate level of messing with bowl\n-- Chew bone guarding -same protocol as food bowl, highly desirable item\n-- Doll test- controversial (correlation between response to doll and real children mixed evidence)\n-- Threatening stranger test- (wow, we really come up with special ways to torment animals)\n-- Dog-dog- safety risks to both dogs and handlers."},{"type":"card","domain":"General","sub":"General","q":"T/F: Erecting the penis, swiping the genitalia against the handler, intense prolonged sniffing and shoulder rubbing are warning signs of aggression that should be noted","a":"F. CAlling these behaviors warning signs of aggression is wholly unsubstantiated and should not be considered in the decision-making process."},{"type":"card","domain":"General","sub":"General","q":"T/F: A rigid body stance or a hard stare  may not always be a precursor to aggression","a":"T. The behavior should be noted, an the dog may need further testing."},{"type":"card","domain":"General","sub":"General","q":"Compared to dogs from a general shelter population, dogs from fighting environments tend to be _____ (choose less or more)  likely to to exhibit aggression toward people.","a":"Compared to dogs from a general shelter population, dogs from fighting environments tend to be less likely to to exhibit aggression toward people. HOWEVER, they need to evaluated extensively for aggressive behavior toward other dogs."},{"type":"card","domain":"General","sub":"General","q":"What testing, in addition to standard behavior evaluation, is recommended for dogs from fighting environments?","a":"Additional dog-dog testing."},{"type":"card","domain":"General","sub":"General","q":"T/F: Dogs from fighting environments can be evaluated as young as 10 weeks old to detect aggression toward other dogs","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Fighting dogs with the characteristic scarring/wounds of dog fighting do not need to be evaluated, as this is evidence they have already actively engaged in dog fighting.","a":"F. The characteristic physical scarring is evidence the dog has been fought, but this does not mean the dog was a willing fighter."},{"type":"card","domain":"General","sub":"General","q":"Two dog-dog subtests are recommended for evaluating dogs from fightin environments: what are they","a":"One with a stimulus dog of the opposite sex, and one of the same sex. Opposite sex should always be first, since response is more likely to be favorable. When possible stimulus dogs should be unrelated to the case. OK to muzzle test dog but may prevent display of normal behavior."},{"type":"card","domain":"General","sub":"General","q":"T/F: It can be informative to test a dog from a fighting case with  fake dog.","a":"T. A preliminary study  (\"manuscript in preparation\"- I could not find it) indicates that there may be some validity to this procedure with dogs that have a history of fighting other dogs."},{"type":"card","domain":"General","sub":"General","q":"T/F: If an adult intact male dog exhibits sexual behavior toward other dogs prior to neutering, he probably will continue to do so after neutering","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Spaying an intact female dog is likely to influence her behavior toward other dogs","a":"F. Unless the female is in estrous during testing, her behavior toward other dogs is unlikely to be influenced by her repro status"},{"type":"card","domain":"General","sub":"General","q":"What behaviors of a fake dog may provoke an attack in the test dog?","a":"Falling down in front of test dog or rearing up."},{"type":"card","domain":"General","sub":"General","q":"T/F: For shelters with access to highly skilled behaviorists, even dogs who attack fake dogs with full mouthed bites, holds and shakes can be rehabilitated with an individualized b-mod plan.","a":"F. At this point in time there is no info as to the effectivenes of behavior mod for these dogs, so euth is recommended."},{"type":"card","domain":"General","sub":"General","q":"*Choose the behavior that is incorrect in this list*\nDogs raised in barren or unenriched environments, such as hoarded or puppy mill dogs, have been shown to exhibit beh deficits including excessive fear of strangers, defensive aggression toward people, defensive aggression toward other dogs, catatonia, frenetic and inappropriate activity","a":"These dogs to be extremely social with other dogs!"},{"type":"card","domain":"General","sub":"General","q":"T/F: Long term follow-up on dogs adopted from puppy mills  confirms that behavioral deficiencies are relatively permanent","a":"T"},{"type":"card","domain":"General","sub":"General","q":"What additional subtests, in addition to the standard behavior evaluation, are indicated for dogs from puppy mills or hoarding situations?","a":"Additional tests for fear and socialability"},{"type":"card","domain":"General","sub":"General","q":"T/F: When performing additional fear subtests you should give the dog time to recover between subtests, as fear responses easily compound on eachother","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Though it can be difficult to evaluate dogs from hoarding and puppy mill situations, it is important to complete all recommended subtests.","a":"F. It may be necessary to skip subtests that might prove too frightening to the dog."},{"type":"card","domain":"General","sub":"General","q":"T/F: Dogs who panic to the point of self injury or are catatonic in novel environments should be humanely euthanized","a":"T. Some of these dogs can become somewhat tame in home-like surroundings, but they are rarely able to cope with everyday stressors. Their quality of life can be severely compromized."},{"type":"card","domain":"General","sub":"General","q":"There is currently no accepted protocol for distinguishing between unsocialized cats and those temporarily stressed from being in the shelter environment. However, for cats who can be evaluated, the _______is a good procedure for matching cat behavioral tendencies with adopter preferences.","a":"ASPCA's Feline-ality. Two scales to plot feline-ality: independence-gregarious scale (social interaction), and the valiance scale (response to novel stimuli)"},{"type":"card","domain":"General","sub":"General","q":"Behavioral drug therapy is rarely prescribed alone, but as an adjuct to___________","a":"Behavioral drug therapy is rarely prescribed alone, but as an adjuct to a behavior modification program"},{"type":"card","domain":"General","sub":"General","q":"What 5 things should a shelter vet do before considering drug therapy?","a":"1) Make a behavioral diagnosis\n2) Be familiar with indications, doses, side effects and contraindications fo the drugs that are likely to be prescribed. \n3) Prescribe a concurrtent B-mod program\n4) Train staff to administer drug therapy\n5) Prepare to monitor animals for Effect and Side effects"},{"type":"card","domain":"General","sub":"General","q":"What health screening tests  may be required prior to prescribing behavior drugs?","a":"Physical exam, CBC, blood chemistry- identify contraindications for drug therapy"},{"type":"card","domain":"General","sub":"General","q":"MAny of the pyschotropic drugs ____ (choose increase or decrease)  appetite","a":"MAny of the pyschotropic drugs diminish appetite, which can be detrimental to stressed shelter animals"},{"type":"card","domain":"General","sub":"General","q":"T/F: Many, if not most, of the pyschotropic drugs are not approved for use in cats or dogs, and thus are prescribed and used extra-label","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: As aggressive animals can become more aggressive after treatment with many psychotropic drugs, it is advised that they not be treated with drugs.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Fearful cats who continue to hide despite access to hide boxes and visits from people may benefit from treatment with _______ (drug name)","a":"Benzodiazepines. Alprazolam- 0.125 mg/cat SID or BID. *Diazepam associated with hepatotoxicity."},{"type":"card","domain":"General","sub":"General","q":"Dogs who are _______ (behavior condition) may hide or become overactive. These dogs may benefit from treatment with fluoxetine or paroxetine.","a":"Dogs who are anxious. Fluoxetine/paroxetine: 1 mg/kg  SID"},{"type":"card","domain":"General","sub":"General","q":"The conflict and frustration experienced by shelter animals may result in the appearance of ___________ (behavior condition).  This condition is defined by bheaviors that are repetative, sustained, and out of context.  Give examples seen in dogs housed in shelters.","a":"compulsive behaviors. Examples: tail chasing, pacing, jumping, weaving, self-licking, leg or foot chewing, self-directed aggression, cage licking, and persistent barking. Cats: tail chasing, tail chewing, and overgrooming."},{"type":"card","domain":"General","sub":"General","q":"What is the recommended treatment for compulisve disorders in shelter animals?","a":"B mod programs stressing consistency and activity, +/- drugs. Drugs: clomipramine and fluoxetine. Continue at least 3 weeks beyond when satisfactory response to treatment has been seen, then gradually wean over 3-4 weeks."},{"type":"card","domain":"General","sub":"General","q":"T/F: THough dogs rarely show signs of separation anxiety in the shelter, those with a history should be treated","a":"T"},{"type":"card","domain":"General","sub":"General","q":"What drugs are recommended for treatment of separation anxiety?","a":"B mod of short departures combined with fluoxetine (1 mg/kg) or clomipramine (2-4 mg/kg)"},{"type":"card","domain":"General","sub":"General","q":"T/F: Fluoxetine has been shown to reduce urine marking in dogs but not cats.","a":"F. Shown to reduce urine marking in cats and dogs. Dogs: 1 mg/kg, cats 0.25 mg/cat."},{"type":"card","domain":"General","sub":"General","q":"________ has been shown to be effective in reducing urine marking and anxiety in cats being transported,  having IV catheterization, and being hospitalized","a":"Feliway (... but really?!.... no citation)"},{"type":"card","domain":"General","sub":"General","q":"_______ has been shown to reduce signs of separation anxiety and noise phobia.","a":"Dog Appeasing Pheromone (DAP).  Paget and Gaulthier, 2003."},{"type":"card","domain":"General","sub":"General","q":"Although there are several anecdotal reports of _________ reducing stress in shelter animals, at this time there are few published controlled studies of their effectiveness.","a":"Although there are several anecdotal reports of pheromones reducing stress in shelter animals, at this time there are few published controlled studies of their effectiveness. Griffith et al 2000."},{"type":"card","domain":"General","sub":"General","q":"Why mght you prescribe the following medication for a dog or cat? List indications, time to onset, important side effects, species differences if present:  acepromazine","a":"Ace: tranquilizer, NOT anti anxiety!! Fast acting, typically used for dogs but either ok."},{"type":"card","domain":"General","sub":"General","q":"What is the goal of the ACC&D","a":"expediting the development of long lasting, affordable, permanent, single dose sterilants of male and female cats and dogs"},{"type":"card","domain":"General","sub":"General","q":"What is the gold standard of sterilization in the US?","a":"surgery"},{"type":"card","domain":"General","sub":"General","q":"How do contraceptive drugs work (generally?)","a":"Inhibit or block some component of the reproductive system"},{"type":"card","domain":"General","sub":"General","q":"Name the hormone cascade for sex hormones, starting in the hypothalamus:","a":"GnRH (ht)-> pituitary (LH/FSH) -> testes/ovaries (testosterone/estradiol and progesterone)"},{"type":"card","domain":"General","sub":"General","q":"Historically ______ has been used to inhibit estrous cycling in dogs and feral cats.","a":"Megestrol acetate"},{"type":"card","domain":"General","sub":"General","q":"Neutersol(R) is FDA approved for chemical castration of puppies. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is the active component of Neutersol and Zeuterin?","a":"Zinc gluconate neutralized by arginine"},{"type":"card","domain":"General","sub":"General","q":"Zinc gluconate products reduce but do not abolish testosterone production, and safety concerns include development of scrotal ulcers at the injection site. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What activity does deslorelin have on male dogs?","a":"Implant- temporary contraception through GnRH agonists (downreg of GnRH receptors = decreased production of LH/FSH)"},{"type":"card","domain":"General","sub":"General","q":"How long does suprelorin work for?","a":"6 or 12 month injections."},{"type":"card","domain":"General","sub":"General","q":"What is the Michelson prize?","a":"$25 million to first entity to provide an effective single dose sterilant for male and female dogs and cats."},{"type":"card","domain":"General","sub":"General","q":"What is the definition of feral cat?","a":"Defined as untamed and evasive, not socialized, untrusting of humans."},{"type":"card","domain":"General","sub":"General","q":"What is the definition of stray cat?","a":"Socialized unowned free-roaming cats."},{"type":"card","domain":"General","sub":"General","q":"What is the definition of outdoor cats?","a":"Owned, socialized free-roaming cat. May not be distinguishable from stray cats."},{"type":"card","domain":"General","sub":"General","q":"Controlling the reproduction of ________ and _________ is recognized as a cornerstone strategy for reducing the number of unwanted cats in animal shelters.","a":"owned and community cats"},{"type":"card","domain":"General","sub":"General","q":"What is the estimated number of feral cats?","a":"80-90 million"},{"type":"card","domain":"General","sub":"General","q":"What is the proportion of community cats that are sterilized? Owned cats?","a":"2% vs 80-85%"},{"type":"card","domain":"General","sub":"General","q":"What proportion of community cat feeders own other pets?","a":"0.5"},{"type":"card","domain":"General","sub":"General","q":"What is the average cat colony size?","a":"2-10 cats"},{"type":"card","domain":"General","sub":"General","q":"What is the average prenatal fetus count for feral cats presenting for spay/neuter ?","a":"4.1"},{"type":"card","domain":"General","sub":"General","q":"Cryptorchidism occurs at what incidence?","a":"0.8-1.8%"},{"type":"card","domain":"General","sub":"General","q":"Where are most cryptorchid testicles found?","a":"Inguinal and abdominal (50/50) for unilateral, abdominal for bilateral"},{"type":"card","domain":"General","sub":"General","q":"Retained testicles should always be removed, even in feral cats. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What year did rabid cats > rabid dogs?","a":"1981.0"},{"type":"card","domain":"General","sub":"General","q":"What is the odds of a male cat having FIV vs female?","a":"4x higher"},{"type":"card","domain":"General","sub":"General","q":"Discuss why FIV/FeLV testing is not recommended for feral cat spay/neuter clinics.","a":"Low incidence = many false positives, increases cost/surgery, diverts resources, FIV vaccine muddles, what to do with positives? Sterilization reduces multiple risk factors anyway."},{"type":"card","domain":"General","sub":"General","q":"What is the most common infectious disease of feral cat?","a":"Parasitism. Intestinal and ectoparasites."},{"type":"card","domain":"General","sub":"General","q":"Feral cats have a higher incidence of FIP than owned cats (T/F)","a":"False- 4% seropositive for FCEV vs 59%"},{"type":"card","domain":"General","sub":"General","q":"Name two diseases with higher prevalence (serology) in feral cat populations:","a":"Toxoplasmosis and Bartonella henselae"},{"type":"card","domain":"General","sub":"General","q":"If cats that appear feral must be impounded, what should the shelter's response be:","a":"housing in a manner that minimizes fear/distress and protects cats and staff from injury."},{"type":"card","domain":"General","sub":"General","q":"It is easy to tell the difference between frightened pet cats and feral cats. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Feral cats have different housing requirements than pet cats (space/hiding box/food/etc) (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the ideal way to catch a feral cat?","a":"Net on pole. Not towel, not hand, not tongs."},{"type":"card","domain":"General","sub":"General","q":"Cat colonies (even TNRed cats) defend their territory and prevent new arrivals. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Mathematical models predict that what percent of females must be sterilized?","a":"0.7"},{"type":"card","domain":"General","sub":"General","q":"If cats are thriving in their environment, there is no humane mandate to remove them, even if a caregiver is not identified. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Anyone who works with feral cats should have_________.","a":"Rabies immunization."},{"type":"card","domain":"General","sub":"General","q":"Release forms can be used at TNR clinics to attest _________.","a":"the caregiver knows of no owner, since no assessment is actually available."},{"type":"card","domain":"General","sub":"General","q":"What are characteristics of the ideal TNR induction drug?","a":"Uncomplicated, rapid, predictable plane/duration of anesthesia, complication and cost low, safety to cats and people high."},{"type":"card","domain":"General","sub":"General","q":"The use of ______ for analgesia in TNR programs is controversial.","a":"NSAIDs (dehydration or undetected hypotension)"},{"type":"card","domain":"General","sub":"General","q":"When should a physical exam be performed in a TNR clinic?","a":"After sedation, before sx."},{"type":"card","domain":"General","sub":"General","q":"What are some advantages of flank spay?","a":"Slightly increased surgical efficiency, reduced risk of evisceration, great for lactating cats, monitored easily by caregiver."},{"type":"card","domain":"General","sub":"General","q":"What are the major disadvantages of flank spay for TNR?","a":"No ability to explore abdomen (can't enlarge hole), lack of vet experience."},{"type":"card","domain":"General","sub":"General","q":"___________ is the most reliable method of identifying sterilized cats.","a":"Ear tipping."},{"type":"card","domain":"General","sub":"General","q":"Ear tipping reduces adoptability of cats in the future (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Feral cats should not be vaccinated with FVRCP because they won't get a booster vaccine. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Which TNR clinic cats should be given warm SQ fluids?","a":"Pyometra, lactating queens, cats with diarrhea, those with dehydration from stress/confinement"},{"type":"card","domain":"General","sub":"General","q":"The optimal time for release of cats from TNR clinics is as soon as possible. (T/F)","a":"False- unknown"},{"type":"card","domain":"General","sub":"General","q":"Name 4 diseases that spaying females prevents","a":"Pyometra, ovarian tumors, metritis, false pregnancy, mammary neoplasia"},{"type":"card","domain":"General","sub":"General","q":"Before surgery, it is important to determine the _______ and __________ of each patient.","a":"Gender and reproductive status"},{"type":"card","domain":"General","sub":"General","q":"Penile barbs can be used to determine reproductive status of adult cats. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Name the three places a cryptorchid testicle can hide:","a":"SQ tissue between external inguinal ring and scrotum, abdominal cavity, or in inguinal canal"},{"type":"card","domain":"General","sub":"General","q":"Physical examination can easily tell the difference between neutered and bilaterally cryptorchid dogs. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What hormone test can indicate presence/absence of testicular tissue?","a":"GnRH response test- give GnRH (2ug/kg IM) then measure testosterone. Increase = testicular tissue present."},{"type":"card","domain":"General","sub":"General","q":"What hormone test can indicate presence/absence of ovarian tissue?","a":"Luteinizing hormone (LH). Low = intact. High = spayed or low cycle; repeat 2 hours later to double check. (cycle = 1-8 hrs)"},{"type":"card","domain":"General","sub":"General","q":"What is the most reliable procedure to indicate presence/absence of gonadal tissue?","a":"Exploratory laparotomy"},{"type":"card","domain":"General","sub":"General","q":"Efficient well-trained technical support is optional in high quality high volume spay/neuter programs. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the ideal ratio of surgery table to surgeon in HQHVSN?","a":"2 tables: 1 surgeon"},{"type":"card","domain":"General","sub":"General","q":"An experienced surgeon should be able to perform ____ sterilization surgeries in one day.","a":"40.0"},{"type":"card","domain":"General","sub":"General","q":"A preoperative scrub should be performed __________, and should start _________ and then move outward in circles until the hair line.","a":"aseptically; incision site"},{"type":"card","domain":"General","sub":"General","q":"__________- is the most important aspect of the surgeon's scrub.","a":"Contact time."},{"type":"card","domain":"General","sub":"General","q":"Which surgeries are a cap and mask not needed?","a":"Cat and pediatric puppy castrations."},{"type":"card","domain":"General","sub":"General","q":"Which types of gloves are acceptable for cat castrations?","a":"Exam gloves or surgical gloves"},{"type":"card","domain":"General","sub":"General","q":"Where is the skin incision in a cat spay?","a":"Exactly midway between umbilicus and pubis."},{"type":"card","domain":"General","sub":"General","q":"What is one trick to relaxing suspensory ligaments?","a":"Placing limbs alongside the patient's thorax."},{"type":"card","domain":"General","sub":"General","q":"What characteristic of cat pedicles makes autoligation ideal?","a":"Virtually no fat present."},{"type":"card","domain":"General","sub":"General","q":"Describe a figure 8 tie?","a":"Wrap cord once around hemostat, then perform \"cord tie\""},{"type":"card","domain":"General","sub":"General","q":"______ is an exceptional knot to use when placing a ligature around thick or friable tissue.","a":"Miller's knot"},{"type":"card","domain":"General","sub":"General","q":"What incision equalizes the difficulty of exteriorizing the right and left ovaries and may facilitate a smaller incision?","a":"Right paramedian"},{"type":"card","domain":"General","sub":"General","q":"What helps experienced surgeons tell if they have captured the uterine horn/broad ligament or other tissue?","a":"Tension on the spay hook."},{"type":"card","domain":"General","sub":"General","q":"If a uterus is not found, where should a surgeon look after extending the incision?","a":"Between the bladder and colon"},{"type":"card","domain":"General","sub":"General","q":"How should a hemostat be closed on the pedicle to prevent cutting/tearing the pedicle?","a":"One click"},{"type":"card","domain":"General","sub":"General","q":"Transaction prior to ligation can do what:","a":"simplify the placement of the ligature, and minimizes amount of tissue manipulation necessary to place the ligature (but scary!)"},{"type":"card","domain":"General","sub":"General","q":"How much tissue should be left distal to the ligature when cutting?","a":"0.5cm"},{"type":"card","domain":"General","sub":"General","q":"What is the prefered spot for uterine body ligation?","a":"At the junction of the uterine body and the cervix."},{"type":"card","domain":"General","sub":"General","q":"What is the recommended closure pattern for dog spays?","a":"3 layer"},{"type":"card","domain":"General","sub":"General","q":"What is the holding layer of the abdominal wall?","a":"Rectus fascia"},{"type":"card","domain":"General","sub":"General","q":"Entrapping muscle in a body wall closure can cause:","a":"increased discomfort, delay healing"},{"type":"card","domain":"General","sub":"General","q":"Ovariectomy provides equally effective technique for elective sterilization of female dogs and cats with no real disadvantages. (T/F)","a":"True (DeTora McCarthy 2011)"},{"type":"card","domain":"General","sub":"General","q":"When is it appropriate to close the body wall with a cruciate suture pattern?","a":"When the incision is very small (<1cm)"},{"type":"card","domain":"General","sub":"General","q":"Scrotal castration is an acceptable alternative to prescrotal castration. (T/F)","a":"True (ASV Spay-neuter Guidelines)"},{"type":"card","domain":"General","sub":"General","q":"What are some advantages of scrotal castrations?","a":"smaller incision, less surgical time, less tendency for scrotal hematomas"},{"type":"card","domain":"General","sub":"General","q":"What are the layers in a scrotal neuter?","a":"Skin-subcutaneous tissue-spermatic fascia (closed)-parietal vaginal tunic and tunica albuginea(open)->testicle"},{"type":"card","domain":"General","sub":"General","q":"In scrotal neuters, incisions can be left open to heal via second intention (T/F)","a":"True, can also be closed"},{"type":"card","domain":"General","sub":"General","q":"Viable sperm can remain in the male reproductive tract for ________ following castration.","a":"30 days."},{"type":"card","domain":"General","sub":"General","q":"Name two ways to identify a sterilized animal.","a":"Scoring tattoos (green) and ear tipping"},{"type":"card","domain":"General","sub":"General","q":"postoperative analgesia is considered a required standard of care in sterilization surgeries. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What five items should be included in a post-op instruction sheet for owners?","a":"1. feeding instructions 2. exercise restriction 3. incision observation 4. post-op analgesia administration 5. contact for emergencies"},{"type":"card","domain":"General","sub":"General","q":"In late term pregnancy in dogs and cats, IV fluids are recommended during sx. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"An intact dog presenting with inappetence, depression, polyuria, polydipsia, and dehydration may have what condition?","a":"Pyometra"},{"type":"card","domain":"General","sub":"General","q":"Which is more debilitating- open or closed pyometra?","a":"Closed, b/c absence of discharge."},{"type":"card","domain":"General","sub":"General","q":"What bacteria causes most pyometra?","a":"E. Coli"},{"type":"card","domain":"General","sub":"General","q":"What other diagnostic should be undertaken before excising mammary gland tumors?","a":"Chest rads"},{"type":"card","domain":"General","sub":"General","q":"What is the proportion of malignancy in mammary tumors in dogs? cats?","a":"50% dogs, 90% cats (Root-Kustritz, 2007)"},{"type":"card","domain":"General","sub":"General","q":"What structure helps locate an abdominally cryptorchid testicle?","a":"Ductus deferens"},{"type":"card","domain":"General","sub":"General","q":"What artery should be avoided when making a paramedian incision in dogs?","a":"Caudal superficial epigastric"},{"type":"card","domain":"General","sub":"General","q":"Caudal reflection of the bladder in cryptorchid dogs allows what?","a":"Visualization of both ductus deferens for retraction"},{"type":"card","domain":"General","sub":"General","q":"With uterus unicornis, both ovaries are always present. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Ovarian remnants are always located near the pedicle (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Hermaphrodites are more frequently presented as females (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Name four things that contribute to prevention of spay/neuter complications.","a":"Anatomical knowledge, aseptic technique, meticulous tissue handling, careful attention to hemostasis, using appropriate suture materials, short surgical times"},{"type":"card","domain":"General","sub":"General","q":"How should you manage a splenic laceration?","a":"Gently suture the capsule with 4-0 suture with taper needle"},{"type":"card","domain":"General","sub":"General","q":"How should you manage a bladder laceration?","a":"Suture with 3-0 with taper"},{"type":"card","domain":"General","sub":"General","q":"What is the most common source of abdominal hemorrhage in a spay?","a":"Ovarian pedicle."},{"type":"card","domain":"General","sub":"General","q":"What are the \"biological retractors\" for right and left ovarian pedicles?","a":"Right: descending duodenum, reflected to left. Left: descending colon, reflected to right."},{"type":"card","domain":"General","sub":"General","q":"What should you grab a bleeding pedicle with?","a":"Fingers- this avoids injury to ureters"},{"type":"card","domain":"General","sub":"General","q":"What is considered conservative therapy for bleeding post-op?","a":"IV fluids, belly bandage"},{"type":"card","domain":"General","sub":"General","q":"What are signs of post-op bleeding?","a":"Tachycardia, pale membrane color, pulse quality, blood on belly tap"},{"type":"card","domain":"General","sub":"General","q":"What is the most common cause of castration hemorrhage?","a":"Insecure ligaments on cords"},{"type":"card","domain":"General","sub":"General","q":"How do you prevent seromas?","a":"Minimize undermining of skin, completely close SQ tissue, tack sq to body wall"},{"type":"card","domain":"General","sub":"General","q":"How do you treat surgical site suture reactions?","a":"Excise inflamed tissue, resuture with different material."},{"type":"card","domain":"General","sub":"General","q":"How long should a post-op scrotal wrap be placed for?","a":"10-15 minutes"},{"type":"card","domain":"General","sub":"General","q":"What mistakes lead to surgical site dehiscence?","a":"Too small suture size, insecure knots, suturing body wall to SQ, too small body wall bites."},{"type":"card","domain":"General","sub":"General","q":"Wound dehiscence rates increase with self trauma (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How do you prevent stump pyometras?","a":"Remove both ovaries"},{"type":"card","domain":"General","sub":"General","q":"How do you treat stump granulomas?","a":"Excision and antibiotics"},{"type":"card","domain":"General","sub":"General","q":"Where do ureter ligation mistakes happen most commonly in dogs? in cats?","a":"dog: proximal ureter near the kidneys, cat: distal ureter at uterine body"},{"type":"card","domain":"General","sub":"General","q":"Simply removing the ligature from the ureter will solve the spay-related ureteral ligation issues. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"The oviduct and infundibulum of the rabbit are much larger than those of the dog (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Testicles can move freely through inguinal canals in rabbits. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Ligation of the mesometrium is recommended in the rabbit because:","a":"it is a fat storage organ and the fat obscures the multiple vessels present"},{"type":"card","domain":"General","sub":"General","q":"Closure of rabbit spays should be in how many layers?","a":"3 layers"},{"type":"card","domain":"General","sub":"General","q":"Rabbit should be closed with skin sutures (T/F)","a":"False- they chew at them."},{"type":"card","domain":"General","sub":"General","q":"What medications should be avoided perioperatively in rabbits?","a":"Antibiotics"},{"type":"card","domain":"General","sub":"General","q":"All decisions regarding anesthesia, patient care, monitoring are the responsibility of _______ and __________.","a":"Veterinarians and technicians"},{"type":"card","domain":"General","sub":"General","q":"Who makes the final decision as to readiness of a patient for surgery?","a":"Veterinarian."},{"type":"card","domain":"General","sub":"General","q":"When age is unknown, what stands in for determining age at surgery?","a":"Weight"},{"type":"card","domain":"General","sub":"General","q":"Perioperative vaccination is not considered acceptable (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Ideally, dogs and cats should be tested for ________ before spay/neuter.","a":"FeLV/FIV or HW"},{"type":"card","domain":"General","sub":"General","q":"What is a bigger risk than an animal being spayed while pregnant/estrual?","a":"Not seeing the animal back again."},{"type":"card","domain":"General","sub":"General","q":"Which is not a mandatory piece of information before continuing with anesthesia for spay/neuter: a) medical history including rx/preventives, b) activity level c) appetite/hydration d) evidence of C/S/V/D e) if they were fasted f) length of stay in the shelter","a":"length of stay"},{"type":"card","domain":"General","sub":"General","q":"How does the ASA grade patients from minimal to grave risk for anesthesia?","a":"Class I-Class V (I is healthy, III is moderate systemic disturbance eg heart murmur, V is moribund or comatose animal who won't survive w/ or w/o surgery)"},{"type":"card","domain":"General","sub":"General","q":"Why is estimating BCS important?","a":"B/c drugs should be dosed for lean weight"},{"type":"card","domain":"General","sub":"General","q":"Laboratory tests can be a substitute for thorough physical examination and anamnesis. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Pre-anesthetic labs routinely alter surgical recommendations in dogs.","a":"False- 1% would postpone and 0.2% would alter meds in one study (Alef 2008)"},{"type":"card","domain":"General","sub":"General","q":"What is in a \"Big 4\" test?","a":"PCV/TP/BG/BUN"},{"type":"card","domain":"General","sub":"General","q":"What is the optimal fasting time for pre-surgical patients?","a":"4-6 hours"},{"type":"card","domain":"General","sub":"General","q":"When should preoperative pediatrics be fed:","a":"2-4 hrs before sx, then within one hour after"},{"type":"card","domain":"General","sub":"General","q":"What are indications for glucose supplementation peri-operatively?","a":"<6 wks old, prolonged capture, restraint, stress, fasting, sick, parasitized, poor BCS, elderly, post-weaning"},{"type":"card","domain":"General","sub":"General","q":"Exotic pets may be housed next to predator species only prior to anesthesia or during recovery. (T/F)","a":"False- only when anesthetized."},{"type":"card","domain":"General","sub":"General","q":"Dogs and cats may be housed next to each other only prior to surgery and during the recovery period. (T/F)","a":"False- only when anesthetized."},{"type":"card","domain":"General","sub":"General","q":"What happens when an iso vaporizer is tilted?","a":"The sick becomes differentially saturated, which can cause dangerously high concentrations during future use (McKelvey 2000)"},{"type":"card","domain":"General","sub":"General","q":"How often should vaporizers be service?","a":"3-12 months"},{"type":"card","domain":"General","sub":"General","q":"Non-rebreathing circuits rely on _________ to remove CO2.","a":"high fresh gas flow"},{"type":"card","domain":"General","sub":"General","q":"What is the optimal weight for non-rebreathing units?","a":"5-7lbs"},{"type":"card","domain":"General","sub":"General","q":"Rebreathing circuits are ideal for animals of what weight?","a":">5lbs (2.5kg)"},{"type":"card","domain":"General","sub":"General","q":"How big should a rebreathing bag be?","a":"2-5x tidal volume of the patient (10-15ml/kg)"},{"type":"card","domain":"General","sub":"General","q":"Which circuits require a CO2 absorbent- non-rebreathing or rebreathing?","a":"Rebreathing"},{"type":"card","domain":"General","sub":"General","q":"What are three ways to tell that soda-lime CO2 absorbent is too old?","a":"1. manufacturer's guidelines 2. color change 3. capnography"},{"type":"card","domain":"General","sub":"General","q":"___________ are essential for personnel and patient safety because they remove waste gases and deliver them to sites away from the working environment.","a":"Scavenging systems"},{"type":"card","domain":"General","sub":"General","q":"Activated charcoal systems are recommended for use in HQHVSN (T/F)","a":"False- too many patients, short half-life of absorbent (3-6hrs/canister)"},{"type":"card","domain":"General","sub":"General","q":"Which is more critical to cleaning ET tubes- washing with soap and water, or soaking in a disinfectant?","a":"Washing"},{"type":"card","domain":"General","sub":"General","q":"Disinfectant residues on ET tubes and circuits can cause what problem for patients (esp cats)","a":"Tracheal necrosis/laryngospasm"},{"type":"card","domain":"General","sub":"General","q":"Cuff of ET tubes should be inflated during cleaning (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Match bain or circle to rebreather, non-rebreather.","a":"Bain = non-rebreather, circle = rebreather"},{"type":"card","domain":"General","sub":"General","q":"What are the four criteria that form the basis of safe anesthesia?","a":"1. analgesia, 2. anxiolysis, 3. immobility/relaxation 4. safe, controlled, reversible depression of the CNS providing unconsciousness"},{"type":"card","domain":"General","sub":"General","q":"_________ are required for all patients undergoing elective surgery.","a":"Analgesics"},{"type":"card","domain":"General","sub":"General","q":"What is the proper dose of ketoprofen?","a":"0.5-1mg/kg IV or SQ"},{"type":"card","domain":"General","sub":"General","q":"What is the dosing for \"splash block?\"","a":"1:1:1 vols of 0.5% bupivacaine, 2% lidocaine, sterile saline"},{"type":"card","domain":"General","sub":"General","q":"What type of opioid is buprenorphine?","a":"Partial agonist"},{"type":"card","domain":"General","sub":"General","q":"What type of opioid is butorphanol?","a":"Mixed agonist/antagonist. Which is why it doesn't work as well."},{"type":"card","domain":"General","sub":"General","q":"What is a side effect of mu agonist administration?","a":"Emesis"},{"type":"card","domain":"General","sub":"General","q":"Alpha-2s provide what three features of anesthesia?","a":"analgesia, muscle relaxation and stress reduction"},{"type":"card","domain":"General","sub":"General","q":"Why can midazolam be given SQ and diazepam cannot?","a":"B/c it is water soluble, and diazepam is in propylene glycol = muscle necrosis/vasculitis"},{"type":"card","domain":"General","sub":"General","q":"Atropine is commonly used in anesthetic protocols (T/F)","a":"True- but shouldn't be, should be reserved for CPR"},{"type":"card","domain":"General","sub":"General","q":"What are the three classes of induction agents commonly used?","a":"Dissociatives (ketamine/tiletamine) Thiobarbituates (thiopental, thiamylal) and Phenol (Propofol)"},{"type":"card","domain":"General","sub":"General","q":"What two dosing types should be avoided in anesthesia?","a":"\"hub\" dosing and \"per-cat\" dosing"},{"type":"card","domain":"General","sub":"General","q":"What physiological parameters change during pregnancy?","a":"Cardiac output down, BP down, HR up, Anemia, increased renal blood flow, hypercarbia, orthostatic hypotension"},{"type":"card","domain":"General","sub":"General","q":"In a pregnant animal, anesthetic drugs should be dosed according to:","a":"ideal body weight (not body plus fetus)"},{"type":"card","domain":"General","sub":"General","q":"Overweight animals may have trouble breathing, be slower to wake up, and may regurgitate more during anesthesia. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Anticholinergic administration is recommended in patients with URI (T/F)","a":"False- because it causes sludging of respiratory secretions"},{"type":"card","domain":"General","sub":"General","q":"The most reliable monitor for patient assessment and safety during anesthesia is:","a":"vigilant monitoring by a human being"},{"type":"card","domain":"General","sub":"General","q":"What drugs should be avoided in compromised patients?","a":"Alpha-2s, dissociatives, thio-barbituates"},{"type":"card","domain":"General","sub":"General","q":"EKG can be the sole monitor in an anesthetic setting. (T/F)","a":"FALSE- may detect pulse activity in non-beating heart."},{"type":"card","domain":"General","sub":"General","q":"Esophageal stethoscopes are great! (Ok, why not)","a":"Allow esophageal reflux, heart sounds without pulse perception, abnormal tracheal pressure."},{"type":"card","domain":"General","sub":"General","q":"Pulse oximetry provides easy, objective, non-invasive monitoring of pulse activity and oxygenation in awake and anesthetized patients (T/F).","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Arterial blood pressure is one of the most useful measures of ________.","a":"Cardiovascular function."},{"type":"card","domain":"General","sub":"General","q":"Surgical manipulation of the abdomen may interfere with apnea monitors (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Low CO2 readings on capnography are indicative of","a":"hyperventilation, low perfusion, or hypothermia"},{"type":"card","domain":"General","sub":"General","q":"High CO2 readings on capnography are indicative of","a":"hyperventilation, excessive metabolism/heat, buildup of CO2 within the machine"},{"type":"card","domain":"General","sub":"General","q":"In anesthesia, numbers on monitors are more important than trends (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Central eye position with dilated pupils indicates a _______ depth of anesthesia.","a":"too deep- life-threatening"},{"type":"card","domain":"General","sub":"General","q":"Ketamine can alter some parameters used to assess anesthetic depth. These are:","a":"Central eye position with moderately dilated pupils, absent palpebral reflex"},{"type":"card","domain":"General","sub":"General","q":"Recovery with ______ provides pediatric patients with warmth and familiarity.","a":"Siblings"},{"type":"card","domain":"General","sub":"General","q":"How is conscious and mentally alert determined post-op?","a":"adequate righting and swallowing reflexes"},{"type":"card","domain":"General","sub":"General","q":"In animals with active reproductive tracts, _____ is not uncommon.","a":"Hematuria"},{"type":"card","domain":"General","sub":"General","q":"Mask induction should not be routinely performed because (3):","a":"stress to patient, uncontrolled unconsciousness, unnecessary waste gas in environment"},{"type":"card","domain":"General","sub":"General","q":"__________ results in the most significant waste gas environmental contamination within the veterinary profession.","a":"Chamber induction"},{"type":"card","domain":"General","sub":"General","q":"Give two main pros and cons to intubation during surgery:","a":"Protected airway always maintained, easy administration of maintenance gases; laryngeal trauma if untrained personnel, stimulates regurge/vomiting, increased IC and ocular pressure, increased vagal tone."},{"type":"card","domain":"General","sub":"General","q":"Hypothermia is a leading cause of intraoperative emergency. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Heat can be conserved by using low oxygen flow rates with rebreathing circuits. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Which patients are most at risk for thermal burns during surgery?","a":"pediatric, debilitated, frail, low BCS"},{"type":"card","domain":"General","sub":"General","q":"Most patients might benefit from mechanical ventilation. (T/F)","a":"False- only obese or late-stage pregnant (or diaphragmatic hernia) patients"},{"type":"card","domain":"General","sub":"General","q":"IP administration of fluids is an option of patients are dehydrated (T/F)","a":"True- but not recommended due to the chilling it can cause (OK if warmed)"},{"type":"card","domain":"General","sub":"General","q":"Each animal should have a surgical medical record with signalment, PE, weight, drug doses and routes, surgical procedure. (T/F)","a":"True - also needs owner info if owned"},{"type":"card","domain":"General","sub":"General","q":"What emergency agents are no longer recommended?","a":"Parenteral lidocaine, dopram, bicarb, calcium"},{"type":"card","domain":"General","sub":"General","q":"What are the overall risks of anesthetic/sedation-related death in dogs for elective surgery?","a":"0.17% (1/600)"},{"type":"card","domain":"General","sub":"General","q":"What are the overall risks of anesthetic/sedation-related death in cats for elective surgery?","a":"0.24% (1/420)"},{"type":"card","domain":"General","sub":"General","q":"What are the overall risks of anesthetic/sedation-related death in rabbits","a":"1.39% (1/72)"},{"type":"card","domain":"General","sub":"General","q":"What fluid rate should be used as an adjunct to CPR?","a":"20ml/kg/20min (cats) or 40ml/kg/20min (dogs)"},{"type":"card","domain":"General","sub":"General","q":"To take stock of community resources and access to spay/neuter, a ________ should be performed before starting up a new program.","a":"Community assessment"},{"type":"card","domain":"General","sub":"General","q":"Which two factors should be used to assess community need for S/N programs?","a":"Characteristics of owned animals and characteristics of shelter animals in the community"},{"type":"card","domain":"General","sub":"General","q":"A recent study showed that percentage of cats spayed/neutered differed significantly by __________.","a":"family annual income."},{"type":"card","domain":"General","sub":"General","q":"What are 3 disadvantages to having S/N inside a local shelter?","a":"Shelter locations are usually bad, infectious disease spread between shelter-owned animals, practice at may prevent shelters from providing services to owned animals"},{"type":"card","domain":"General","sub":"General","q":"What are 3 disadvantages to MASH style S/N?","a":"wear/tear on equipment from transport, extra travel time for staff, need for extra off-site storage for equipment"},{"type":"card","domain":"General","sub":"General","q":"What are 3 disadvantages to Mobile S/N units?","a":"Cost, may need to hire a driver, units are small (no room for animal housing), staff exposure to gas, insurance/vehicle maintenance"},{"type":"card","domain":"General","sub":"General","q":"What are some disadvantages to stand-alone S/N clinics?","a":"Higher start-up costs, longer start-up time, may need transport vehicle to increase access"},{"type":"card","domain":"General","sub":"General","q":"What are 3 elements to a high impact S/N program?","a":"Low cost, accessibility, marketing"},{"type":"card","domain":"General","sub":"General","q":"Drug therapy is routinely prescribed alone, rarely as an adjunct to a behavior modification program. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the first step before drug prescription for behavior problems?","a":"Make a diagnosis"},{"type":"card","domain":"General","sub":"General","q":"What are 3 elements of animal behavioral evaluation in the shelter?","a":"Previous owner questionnaire, behavior in shelter, formal behavioral eval"},{"type":"card","domain":"General","sub":"General","q":"What should be ruled out before starting an animal on behavior drugs?","a":"Medical diagnosis"},{"type":"card","domain":"General","sub":"General","q":"Should you start a behavior drug on the high end to see effects or a low end to minimize side effects?","a":"Low end"},{"type":"card","domain":"General","sub":"General","q":"Transdermal psychotropic drug compounding is useful in the shelter (T/F)","a":"False- don't know drug dose levels achieved- don't use"},{"type":"card","domain":"General","sub":"General","q":"Prescription of psychotropic drugs decreases adoptability (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dogs with a history of separation anxiety don't typically show signs in the shelter (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Aggressive animals should be treated with psychotropic drugs.","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Which psychotropic drug is recommended for anxious cats?","a":"Alprazolam 0.125mg/cat"},{"type":"card","domain":"General","sub":"General","q":"What two drugs have been shown in studies to be effective against compulsive behaviors in dogs?","a":"Clomipramine and fluoxetine (takes >4 weeks tho...)"},{"type":"card","domain":"General","sub":"General","q":"Which behavioral drug reduces urine marking?","a":"fluoxetine (dogs and cats)"},{"type":"card","domain":"General","sub":"General","q":"What are the side effects of pheromone products?","a":"None"},{"type":"card","domain":"General","sub":"General","q":"There is strong evidence that 6mo is the proper time for spay/neuter (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Rates of complication vary widely depending on practitioner or student performing the surgery (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Complication rates for pediatric spay/neuter are no higher than those observed in animals neutered at traditional ages. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dogs neutered early are smaller than those neutered later. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Delayed physeal closure in cats means pediatric neutered cats are taller than intact cats. Cats neutered >6 mo also have delayed closure. (T/F)","a":"False- it is seen and also significant difference in radial length (but not by much!)"},{"type":"card","domain":"General","sub":"General","q":"Pediatric S/N increases risk of growth plate fractures. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"A significant body of evidence supports the claim that OHEd dogs are fatter than intact animals. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"A significant body of evidence supports the claim that OHEd cats (pediatric or traditional age) are fatter than intact animals. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Acquired urinary incontinence is associated with spaying at what age?","a":"Seems to be worse with younger and better with older, esp after first heat- more studies needed"},{"type":"card","domain":"General","sub":"General","q":"Are early spayed dogs more at risk for UTI than dogs spayed 6-12 months?","a":"Probably"},{"type":"card","domain":"General","sub":"General","q":"Urethral pressure in male and female cats is affected by the age of spay/neuter. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What behaviors are more associated with dogs spayed younger?","a":"Barking at visitors, excitability, noise phobia."},{"type":"card","domain":"General","sub":"General","q":"Early spay/neuter may protect against what behavior problems?","a":"Separation anxiety, submissive urination, escaping behaviors"},{"type":"card","domain":"General","sub":"General","q":"Beyond _______- years, no protective effect against mammary tumors is seen in spaying dogs.","a":"2.5"},{"type":"card","domain":"General","sub":"General","q":"Traditional age neutering appears to increase the risk of ______ cancer in dogs.","a":"Prostatic"},{"type":"card","domain":"General","sub":"General","q":"What are three metabolic differences between pediatric and adult patients re: anesthesia?","a":"immature hepatic enzyme systems, decreased protein binding of drugs, and decreased glomerular filtration rate"},{"type":"card","domain":"General","sub":"General","q":"Why do pediatric animals get hypoglycemic?","a":"Liver cannot built up enough glycogen stores yet"},{"type":"card","domain":"General","sub":"General","q":"Water should be withheld prior to anesthesia (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Why is it ok to make a more caudal incision in a pediatric dog spay?","a":"B/c their suspensories are not tight"},{"type":"card","domain":"General","sub":"General","q":"What are the three basic principles of pediatric surgery?","a":"Meticulous hemostasis, minimize surgery time, careful tissue handling"},{"type":"card","domain":"General","sub":"General","q":"Tissue glue is not needed or recommended in juvenile castrations (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"At what age is a cat truly considered cryptorchid?","a":"6 months"},{"type":"card","domain":"General","sub":"General","q":"What is the primary goal of a behavioral evaluation in a shelter?","a":"To gain an overview of the dog's characteristic behavior patterns, to direct placement."},{"type":"card","domain":"General","sub":"General","q":"What are the three big behavior tests?","a":"Assess-a-Pet (Sternberg) Match-Up (ARL) and SAFER/Caninality/Felinality (ASPCA)."},{"type":"card","domain":"General","sub":"General","q":"What are the five major sections of a behavioral evaluation?","a":"Greeting, Handling, Play, Food guarding, Stranger test (Doll test), Dog-dog test"},{"type":"card","domain":"General","sub":"General","q":"What should be recorded during a behavioral eval?","a":"Objective observations"},{"type":"card","domain":"General","sub":"General","q":"Dog-directed aggression can develop as early as 10 weeks old in fighting puppies (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dog-test dogs, \"stranger'-testers, and dog handlers during a behavior eval should all be _________.","a":"Unfamiliar with the dog being tested."},{"type":"card","domain":"General","sub":"General","q":"Fake dogs have been shown to be valid testers of dog-related aggression. (T/F)","a":"Preliminary studies indicate yes."},{"type":"card","domain":"General","sub":"General","q":"Dogs in hoarding or puppy mill situations tend to have bad reactions to:","a":"people and novelty"},{"type":"card","domain":"General","sub":"General","q":"What is one way to measure a dog's reaction to novelty?","a":"Use a remote controlled car or open an umbrella"},{"type":"card","domain":"General","sub":"General","q":"A large percent (>80%) of ex puppy-mill breeder dogs exhibit severe fear-based behaviors long-term. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Because dogs are often surrendered to the shelter for aggression, there may be a higher rate of behavior issues in shelter dogs than other populations. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What does C-BARQ stand for and what is it?","a":"Canine Behavioral Assessment and Research Questionnaire- a validated questionnaire to gather behavioral info upon surrender"},{"type":"card","domain":"General","sub":"General","q":"Currently on single behavioral assessment represents a gold standard. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Temperament Test is the preferred nomenclature. (T/F)","a":"False- temperaments cannot be distinguished from learned behaviors or stimulated behaviors; should not be pass/fail."},{"type":"card","domain":"General","sub":"General","q":"Behavior evals should be just one of many tools in decision making process (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Video cameras can help capture what during Behav. Evals?","a":"micro-expressions and rapid behavior changes, objective, can be replayed"},{"type":"card","domain":"General","sub":"General","q":"What is different about SAFER than the other two main BEs?","a":"Certification process to ensure test is performed same way as other testers"},{"type":"card","domain":"General","sub":"General","q":"After adoption, a ________ is essential for dogs who undergo behavior modification.","a":"follow-up protocol"},{"type":"card","domain":"General","sub":"General","q":"When modifying potentially dangerous behavior, what is recommended?","a":"Having trained experts (like CAABs) work with the dogs."},{"type":"card","domain":"General","sub":"General","q":"When is the ideal time to conduct an initial assessment of owner-relinquished dogs?","a":"At intake, with owner present"},{"type":"card","domain":"General","sub":"General","q":"When is the ideal time to conduct an assessment of stray dogs?","a":"One day before their stray hold is up"},{"type":"card","domain":"General","sub":"General","q":"When are blood cortisol levels highest in shelter dogs?","a":"First three days in the shelter (Hennessy 2007)"},{"type":"card","domain":"General","sub":"General","q":"What is the first step to any behavior mod program?","a":"Daily enrichment"},{"type":"card","domain":"General","sub":"General","q":"Successful adoptions occur when new owners:","a":"have realistic expectations of time, expense, and effort required for the new pet"},{"type":"card","domain":"General","sub":"General","q":"What is one of the biggest difficulties in feline behavior eval?","a":"Distinguishing ferals from frightened socialized pets"},{"type":"card","domain":"General","sub":"General","q":"In felinality, cats are scored on two scales. What are they?","a":"Social interaction (independence-gregariousness) and response to novel stimuli (valiance) = 9 categories"},{"type":"card","domain":"General","sub":"General","q":"Tight criteria that adopters have to meet decreases returns (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Tight criteria that adopters have to meet decreases adoptions (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are 4 criteria that the Adoption Forum II  in 2003 adopted to screen adopters?","a":"1) animal spayed/neutered 2) no hx animal or child abuse 3) no drunk/high adopters and 4) no adoptions as food source"},{"type":"card","domain":"General","sub":"General","q":"Follow-up may encourage adopters to return their new pets (T/F","a":"False- it mostly it supports adopters' relationships with their new pets"},{"type":"card","domain":"General","sub":"General","q":"What is the definition of enrichment?","a":"The provision of a captive animal with the ability to maintain or improve its physical, behavioral, and psychological functioning via modifications to the housing environment."},{"type":"card","domain":"General","sub":"General","q":"Enrichment provides both therapy for and protection against stressors. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Enrichment prevents adopters from having positive interactions with pets. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Successful enrichment programs adapt to individual pet preferences. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are some examples of cage furnishing that motivate exploration, provide vantage/retreat areas, and separate functional space?","a":"Hiding places, elevated platforms/perches, soft bedding, scratching pads, two-compartment enclosures"},{"type":"card","domain":"General","sub":"General","q":"Human contact is always an effective enrichment. (T/F)","a":"False- depends on animals' preferences"},{"type":"card","domain":"General","sub":"General","q":"Dogs and cats are social animals, therefore, contact with other dogs and cats should be encouraged. (T/F)","a":"True when safe."},{"type":"card","domain":"General","sub":"General","q":"In group housed animals, what is the time of highest social tension?","a":"Introduction of unfamiliar animals"},{"type":"card","domain":"General","sub":"General","q":"What do cats use to reduce social tension?","a":"Distance"},{"type":"card","domain":"General","sub":"General","q":"What do dogs use to reduce social tension?","a":"Appeasement behaviors"},{"type":"card","domain":"General","sub":"General","q":"How fast do most dogs lose interest in a toy?","a":"1 day"},{"type":"card","domain":"General","sub":"General","q":"What are some examples of occupational enrichment?","a":"Feeding/foraging enrichments, and training"},{"type":"card","domain":"General","sub":"General","q":"Videos of other animals playing are great enrichment for shelter dogs. (T/F)","a":"False- don't seem to work very well"},{"type":"card","domain":"General","sub":"General","q":"What is more useful in the shelter- talk radio enrichment or music enrichment?","a":"Studies support talk radio as \"accustomizing\" shy cats, puppies and kittens to human voices. Classical music may increase resting/decrease barking."},{"type":"card","domain":"General","sub":"General","q":"Feliway and DAP can help reduce fear, anxiety, and stress-related urine marking. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Continuity of business and contingency planning are key _____________ that help ensure the availability of a community's animal services during a disaster.","a":"Preparedness activities"},{"type":"card","domain":"General","sub":"General","q":"What document serves as a comprehensive review of key animal emergency management issues?","a":"the NASAAEP's Animal Emergency PLanning and Resource Management Roadmap"},{"type":"card","domain":"General","sub":"General","q":"What was/is the Stafford Act?","a":"provides FEMA the authority to act in disasters."},{"type":"card","domain":"General","sub":"General","q":"What is the PETS Act?","a":"Pets Evacuation and Transportation Standards amendment to the Stafford Act. Mandates that state and local pans address rescue of pets and provide services to animals, and gives FEMA authority to provide funding to localities for pet services."},{"type":"card","domain":"General","sub":"General","q":"Wht is NIMS?","a":"National Incident Management System: overall response system for disasters."},{"type":"card","domain":"General","sub":"General","q":"What is the NRF?","a":"National Response Framework: sets forth roles/responsibilities of local, state, Fed, tribal, NGOs, businesses, in responding to emergencies"},{"type":"card","domain":"General","sub":"General","q":"What is ICS?","a":"Incident Command System- standardized flexible/scalable system of hierarchical personnel organization"},{"type":"card","domain":"General","sub":"General","q":"What four roles make up the command staff in ICS?","a":"Safety, Liaison, and Public Information Officers (also, the Incident Commander)"},{"type":"card","domain":"General","sub":"General","q":"What four roles make up the general staff in ICS?","a":"Operations, Planning, Logistics, and Finance"},{"type":"card","domain":"General","sub":"General","q":"What role do animal shelters play in Disaster Preparedness?","a":"Ideally would have enough resources not only to keep operating but to assist community in emergencies- also help raise awareness."},{"type":"card","domain":"General","sub":"General","q":"Why is a risk assessment important in Disaster preparedness?","a":"So you can prepare the resources that are most likely needed in the most likely disaster scenario"},{"type":"card","domain":"General","sub":"General","q":"Why would a MAA or a MOU be needed as part of Disaster preparedness?","a":"Helps put into writing the role of the animal shelter as part of the community emergency plan, specifies agreements, roles, resources."},{"type":"card","domain":"General","sub":"General","q":"What are CART and SART?","a":"Community and State Animal Response Teams- deploy citizen volunteers to deliver aid as part of the ICS, can help w training, can be NGO or officially affiliated."},{"type":"card","domain":"General","sub":"General","q":"What are these activities part of: a: activation and rapids needs assessment, b. evacuation and transportation c. sheltering, d. veterinary medical response, d. animal S&R, e. Decontamination","a":"Animal Emergency Response"},{"type":"card","domain":"General","sub":"General","q":"Who should coordinate with local public health officials in the management of zoonoses and other vet public health issues in disasters?","a":"Shelter Vets"},{"type":"card","domain":"General","sub":"General","q":"Who has the ultimate responsibility for the evacuation of animals in a disaster?","a":"The animal's owner (but may not have resources to do so)"},{"type":"card","domain":"General","sub":"General","q":"What are some limitations of the PETS act?","a":"federal funding is only available in certain circumstances (eg federal declaration) with appropriate documentation"},{"type":"card","domain":"General","sub":"General","q":"What type of grant secures funding for household pets from FEMA?","a":"a FEMA Personal Assistance grant. Documentation is very important!"},{"type":"card","domain":"General","sub":"General","q":"What is one of the most effective ways to train for disasters?","a":"complete the FEMA coursework then engage with local/state emergency response including SART for planning meetings and exercises"},{"type":"card","domain":"General","sub":"General","q":"_________ can be a key component of a population management plan, and provide individualized care and housing meeting specific needs of animals with health/behavioral conditions.","a":"Foster care"},{"type":"card","domain":"General","sub":"General","q":"What are some risks/costs of foster care?","a":"require substantial investment time/communication, vet care, 24-hr support, risks to public/foster owned animal health, failure of foster parents to provide adequate care."},{"type":"card","domain":"General","sub":"General","q":"How are liability and safety considerations in foster care best addressed?","a":"Through communication, education, and screening"},{"type":"card","domain":"General","sub":"General","q":"Foster programs should have structure and goals (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Foster programs reduce need for resource investment in shelters (T/F)","a":"Mostly False"},{"type":"card","domain":"General","sub":"General","q":"Foster programs effectively increase the total number of animals in care. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How should the number of foster homes needed be estimated?","a":"By calculating desired length of stay (usually 1-2 mo for kittens) and using historical records for kitten intake by season, use some leeway for foster breaks/vacations"},{"type":"card","domain":"General","sub":"General","q":"Volunteers or staff members may be given the task of volunteer coordinator. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Expectations of foster homes should be put into writing. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What happens when kittens are delayed returning from foster?","a":"Kittens miss peak cuteness = much longer LoS"},{"type":"card","domain":"General","sub":"General","q":"Name four types of animals that should go to foster:","a":"Neonates/underage, Medical cases, Post-surgical cases, Behavioral Cases"},{"type":"card","domain":"General","sub":"General","q":"Name three types of questionable uses for foster care:","a":"When overcapacity in the shelter, as foster-to-adopt, and as \"fospice.\" To work, all require extra consideration and communication"},{"type":"card","domain":"General","sub":"General","q":"What two things could foster-to-adopt mean","a":"Foster failure or Foster parents are in charge of finding adopters"},{"type":"card","domain":"General","sub":"General","q":"What should be included in \"fospice\" application paperwork?","a":"Quality of life scale"},{"type":"card","domain":"General","sub":"General","q":"Pathway planning, scheduling, and monitoring lengths of stay all help:","a":"Increase efficiency of foster pathways"},{"type":"card","domain":"General","sub":"General","q":"What are readiness systems in the foster care context?","a":"Designed to decrease time in shelter before foster- eg \"foster on deck\" or \"foster on call\""},{"type":"card","domain":"General","sub":"General","q":"How can diversion programs be used in the foster care context?","a":"Turning surrenderers into foster parents to prevent relinquishment of too young animals, delaying intake for scheduling, etc."},{"type":"card","domain":"General","sub":"General","q":"What things should foster pets be screened for?","a":"Behavior problems, Infectious disease, Intake protocol."},{"type":"card","domain":"General","sub":"General","q":"How often should puppies and kittens be examined while in foster care?","a":"2 weeks"},{"type":"card","domain":"General","sub":"General","q":"Who should handle foster care appointments?","a":"Staff not handling other animals (ideally), trained to give vaxes and ID problems that may need vet attention"},{"type":"card","domain":"General","sub":"General","q":"How can you increase a foster pet's chance of adoption?","a":"Teaching them basic pet \"etiquette\""},{"type":"card","domain":"General","sub":"General","q":"What LoSs should be monitored to ensure efficiency of foster care programs?","a":"waiting for foster pick-up, in foster, waiting for services in the shelter, to adoption."},{"type":"card","domain":"General","sub":"General","q":"All animals in foster should be tracked by the shelter's animal information software. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How often should number of animals in foster care be audited?","a":"monthly"},{"type":"card","domain":"General","sub":"General","q":"What could prevent shelter staff from fostering?","a":"Labor laws"},{"type":"card","domain":"General","sub":"General","q":"Foster parent recruitment should stop when enough homes are found (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Foster programs should require that foster homes take periodic breaks from fostering.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"In some states, laws require home inspections of foster care givers (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Some states require animal foster caregivers to have permits. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Many states require background checks on foster parents. (T/F)","a":"False- only VA"},{"type":"card","domain":"General","sub":"General","q":"If a sheltering organization selectively enforces home inspections for foster parents, what precautions could be taken?","a":"That inspections are on basis of valid concerns, not discriminatory factors."},{"type":"card","domain":"General","sub":"General","q":"Define cumulative exposure risk in the context of foster care:","a":"the more animals come in/out, the larger the likelihood of pathogen accumulation"},{"type":"card","domain":"General","sub":"General","q":"What can help decrease cumulative exposure risk in foster homes?","a":"Disinfection, fostering only one family unit at at time, keeping owned animals separate from foster animals"},{"type":"card","domain":"General","sub":"General","q":"Foster homes, like shelters, should function within their capacity for care (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Which is more likely to cause prolonged infection: contamination of shelter cage or contamination of foster home","a":"Home- carpet/upholstery, back yards, inability to use bleach, propagating infections in foster owned pets, people"},{"type":"card","domain":"General","sub":"General","q":"Households with puppies/kittens less than _____- should not foster shelter animals.","a":"20 weeks, who may not be effectively vaccinated"},{"type":"card","domain":"General","sub":"General","q":"The reality is that many foster caregivers like to integrate their foster animals into their households. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Who should work with foster parents to insure their own pets are vaccinated and healthy?","a":"Their own veterinarians- perhaps with guidance from shelter vets"},{"type":"card","domain":"General","sub":"General","q":"What extra testing/vaccinations are recommended for foster parent owned pets?","a":"FELV vaccination, Influenza vaccination, and annual/semi-annual MLV intranasal KC vax"},{"type":"card","domain":"General","sub":"General","q":"What two times is euthanasia necessary?","a":"1. suffering from untreatable condition, 2. poses public health risk due to behavior"},{"type":"card","domain":"General","sub":"General","q":"What is necessary to call something \"euthanasia?\"","a":"lack of fear and distress and pain"},{"type":"card","domain":"General","sub":"General","q":"In addition to relieving suffering of animals, what is a goal of the euthanasia process?","a":"Help protect physical and emotional health of staff"},{"type":"card","domain":"General","sub":"General","q":"Euthanasia will always be an inextricable part of compassionate care for animals. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Shelter personnel must exercise more caution when performing euthanasia than private practice personnel. (T/F)","a":"True because many things must be checked, and behavior of pts is unknown/aggressive"},{"type":"card","domain":"General","sub":"General","q":"What is the killing/caring paradox?","a":"People who love animals are often the ones ending their lives"},{"type":"card","domain":"General","sub":"General","q":"Very few vets have received formal training performing euthanasia. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Is euthanasia usually performed by vets in the shelter?","a":"No- by certified technicians."},{"type":"card","domain":"General","sub":"General","q":"What three things does a euthanasia technician need?","a":"Training and equipment, access to controlled drugs, and moral/psychological support"},{"type":"card","domain":"General","sub":"General","q":"How do you prevent personnel turnover in the euthanasia context? (3 things)","a":"Provide designated rooms, exclude other animals from that room, and removing the dead before bring in another living animals."},{"type":"card","domain":"General","sub":"General","q":"What type of stress is compassion fatigue?","a":"Secondary traumatic stress"},{"type":"card","domain":"General","sub":"General","q":"Feeling powerless, scared, paranoid, guilty, rage, depression, sleep disturbances are symptoms of what in shelter workers?","a":"Compassion fatigue"},{"type":"card","domain":"General","sub":"General","q":"Who is most at risk for compassion fatigue?","a":"The most idealistic/compassionate"},{"type":"card","domain":"General","sub":"General","q":"What is the opposite of compassion fatigue?","a":"Compassion satisfaction"},{"type":"card","domain":"General","sub":"General","q":"CO chambers and other gas euthanasia methods are considered:","a":"Inhumane"},{"type":"card","domain":"General","sub":"General","q":"What does EBI stand for?","a":"Euthanasia by injection- considered most humane method"},{"type":"card","domain":"General","sub":"General","q":"Where can you find training for EBI?","a":"AHA, HSUS, NACA"},{"type":"card","domain":"General","sub":"General","q":"Picking animals, conflict over animals picked, performing the act, confronting members of the public about the act, and providing disposal are examples of:","a":"sources of distress involved with euthanasia"},{"type":"card","domain":"General","sub":"General","q":"What are some steps that shelter management can take to help staff deal with euthanasia stress?","a":"Rotating duties, flexibility of work partners/individual animals, technical proficiency, understanding why euthanasia was selected for that animal"},{"type":"card","domain":"General","sub":"General","q":"What is (probably) the hardest part of the euthanasia task?","a":"Deciding which animals to euthanize"},{"type":"card","domain":"General","sub":"General","q":"What can help decision making in euthanasia?","a":"Written protocols/policies"},{"type":"card","domain":"General","sub":"General","q":"Euthanasia criteria should be reassessed on a regular basis (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"No drug or euthanasia method deemed unacceptable by the _______ should ever be used to euthanize animals in a shelter. (","a":"AVMA"},{"type":"card","domain":"General","sub":"General","q":"How often are AVMA Euthanasia guidelines updated?","a":"10 years"},{"type":"card","domain":"General","sub":"General","q":"CO chamber euthanasia is acceptable by AVMA standards (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What four characteristics make an euthanasia method humane/acceptable?","a":"Must induce loss of consciousness/death w/o pain; be quick, reliable, irreversible; be appropriate for species/age/health of animal; be safe for personnel performing euthanasia"},{"type":"card","domain":"General","sub":"General","q":"What are some characteristics of CO?","a":"Tasteless, highly toxic, flammable, problem at high or low chronic exposures"},{"type":"card","domain":"General","sub":"General","q":"What problems can you see with CO chambers?","a":"Noisy, causes convulsions, vocalization/agitation, difficult to calculate with multiple animals, gas leaks make not work well, delayed absorption in compromised animals, more expensive."},{"type":"card","domain":"General","sub":"General","q":"What CO concentration must be reached for \"euthanasia\" to occur?","a":"0.06"},{"type":"card","domain":"General","sub":"General","q":"What Schedule Class is sodium Pentobarbital?","a":"Class II"},{"type":"card","domain":"General","sub":"General","q":"What are the 5 stages of anesthesia/euthanasia?","a":"I: sedation II: involuntary excitement III: Light anesthesia IV: deep anesthesia V: apnea - resp arrest - cardiac arrest"},{"type":"card","domain":"General","sub":"General","q":"What drug is added to pentobarbital to make it class III?","a":"phenytoin (50mg/ml)"},{"type":"card","domain":"General","sub":"General","q":"What is the usual mg/ml of sodium pentobarbital?","a":"390-392mg. 2 other concentrations exist."},{"type":"card","domain":"General","sub":"General","q":"What are the 2 reasons for adding phenytoin to Na pentobarb?","a":"1. enhances cardiac arrest 2. diminishes potential for human abuse"},{"type":"card","domain":"General","sub":"General","q":"What is the IP sodium pentobarb dose for cats?","a":"3ml/10lb body weight"},{"type":"card","domain":"General","sub":"General","q":"Once in the vein, how long does it take for Sodium Pentobarb to cross into the brain?","a":"45-90 sec."},{"type":"card","domain":"General","sub":"General","q":"Why is IP injection not suitable for dogs?","a":"They experience severe stage II involuntary excitement"},{"type":"card","domain":"General","sub":"General","q":"What is the concern regarding phenytoin in IP injections?","a":"That it may stop the heart before adequate sedation= distress"},{"type":"card","domain":"General","sub":"General","q":"What is the proper site for IP injection?","a":"Right lower quadrant to avoid liver/spleen/kidney injection"},{"type":"card","domain":"General","sub":"General","q":"What should be done before performing an IC pentobarb injection?","a":"Ensure animal is sedated/comatose"},{"type":"card","domain":"General","sub":"General","q":"Intrahepatic injection of pentobarb is considered humane (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Per this text, intrarenal pentobarb is considered inhumane (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What should always be checked before euthanasia in a shelter?","a":"Animal ID/microchip"},{"type":"card","domain":"General","sub":"General","q":"Evidence in rats supports the idea that animals find dead conspecifics disturbing/anxiety provoking. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Who should be euthanized first in a family group of mom and babies?","a":"Mom"},{"type":"card","domain":"General","sub":"General","q":"Evidence supports that unborn fetuses do not regain consciousness after removal of the entire uterus. (T/F)","a":"True- opening the uterus may stimulate fetuses to consciousness"},{"type":"card","domain":"General","sub":"General","q":"What is more important than the dose of euthanasia solution in maintaining quality of death?","a":"The circumstances surrounding the animal's final moments, esp restraint."},{"type":"card","domain":"General","sub":"General","q":"What is the difference between sedation and tranquilization?","a":"Sedation = brain sleepy/unaware, Tranquilization = brain aware, unable to move body"},{"type":"card","domain":"General","sub":"General","q":"Ace is approved for use in dogs, cats, and rabbits (T/F)","a":"False- not rabbits"},{"type":"card","domain":"General","sub":"General","q":"What are two drawbacks of using ace as a sole pre-med?","a":"Removes aggression inhibition, can promote seizures, decreases BP"},{"type":"card","domain":"General","sub":"General","q":"What routes are acceptable for xylazine?","a":"SC or IM"},{"type":"card","domain":"General","sub":"General","q":"What is the most notable side effect of xylazine?","a":"Vomiting"},{"type":"card","domain":"General","sub":"General","q":"What side effects does ketamine have when used alone?","a":"No anesthesia, increased muscle tone, can induce seizures"},{"type":"card","domain":"General","sub":"General","q":"How do you make pre-mix?","a":"Xyl:Ket 1:5 (2:10) = 0.06mg/kg IM"},{"type":"card","domain":"General","sub":"General","q":"How can you use sodium pentobarbital as a pre-med?","a":"Give PO or IP, then inject IV/IC."},{"type":"card","domain":"General","sub":"General","q":"Reducing animal fear, controlling animal for administration of drugs, control physical response to drugs, and protecting staff from injury are all goals of what activity:","a":"Restraint during euthanasia"},{"type":"card","domain":"General","sub":"General","q":"How many people at minimum should work together to sedate and euthanize an animal?","a":"Two"},{"type":"card","domain":"General","sub":"General","q":"What is the oral dosing of sodium pentobarbital?","a":"3x IV dosing (3ml/10 lbs) or if in grains, 1 grain powder/pound body weight (1 teaspoon=4.5g/40#)"},{"type":"card","domain":"General","sub":"General","q":"How long does sedation take with oral pentobarb dosing?","a":"15-60min"},{"type":"card","domain":"General","sub":"General","q":"How often should cats be checked after getting IP pentobarb?","a":"q 10 min"},{"type":"card","domain":"General","sub":"General","q":"Control poles and cat tongs are recommended for restraint pre-euthanasia. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Squeeze cages and cat nets are recommended for restraint pre-euthanasia (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"For species other than dogs and cats, EBI of sodium pentobarbital is still recommended (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What should be done with rabbit dosing of sodium pentobarb?","a":"Double the cat/dog dose"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended pre-med for pig euthanasia?","a":"1:1 ace:ketamine"},{"type":"card","domain":"General","sub":"General","q":"Freezing is an acceptable method of euthanasia for reptiles. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"How long should reptiles be monitored after euthanasia solution administered?","a":"24-48hrs"},{"type":"card","domain":"General","sub":"General","q":"How should fish be euthanized?","a":"MS-222 (Finquel) aka tricaine methanesulfonate"},{"type":"card","domain":"General","sub":"General","q":"Presedation is recommended for all horse euthanasias (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What method of euthanasia is advocated by Vets for Equine Welfare?","a":"Sodium pentobarbital"},{"type":"card","domain":"General","sub":"General","q":"What must be done in advance of euthanizing livestock sp?","a":"Arrange for disposal"},{"type":"card","domain":"General","sub":"General","q":"What complicates field euthanasia?","a":"Onlooker witnesses"},{"type":"card","domain":"General","sub":"General","q":"Auscultation is the best single method for accurate verification of death immediately after it occurs. (T/F)","a":"False- many methods should be used"},{"type":"card","domain":"General","sub":"General","q":"What is the most reliable sign of successful death in a euthanasia context?","a":"Rigor mortis"},{"type":"card","domain":"General","sub":"General","q":"Hyperthermia slows down the onset of rigor mortis (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Hypothermia slows down the onset of rigor mortis (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Failure to correctly verify death is an unacceptable error (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is the final step of euthanasia?","a":"Body disposal"},{"type":"card","domain":"General","sub":"General","q":"What are the three most common ways of disposing bodies?","a":"cremation, landfill burial, and rendering"},{"type":"card","domain":"General","sub":"General","q":"All shelters need to be available to provide emergency care for their animals (T/F)","a":"False- they all need a plan for doing so"},{"type":"card","domain":"General","sub":"General","q":"Staff should be trained to ___________ medical emergencies.","a":"look for and recognize"},{"type":"card","domain":"General","sub":"General","q":"What is one way off-site vets can \"be there\" for emergencies?","a":"Developing contingency orders and being available by telephone"},{"type":"card","domain":"General","sub":"General","q":"What is the basis of emergency medicine?","a":"Triage"},{"type":"card","domain":"General","sub":"General","q":"What does triager mean in French?","a":"To sort"},{"type":"card","domain":"General","sub":"General","q":"What assessment should be done first after triage?","a":"ABC- airway, breathing, circulation"},{"type":"card","domain":"General","sub":"General","q":"If an animal is not stable, care should be provided ________.","a":"Immediately"},{"type":"card","domain":"General","sub":"General","q":"Legal and ownership issues should be resolved before giving care in an emergency situation. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Basic emergency supplies include what two categories:","a":"Drugs and equipment"},{"type":"card","domain":"General","sub":"General","q":"Supplies like IV catheters, fluids, dextrose, and warming blankets help address which three common emergent issues in shelters:","a":"Hypothermia, hypovolemia, hypoglycemia"},{"type":"card","domain":"General","sub":"General","q":"Thorough physical exam and minimal diagnostics (QATs) can be enough to render the proper emergency treatment in a shelter (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is one factor in shelter emergencies that isn't present in private practice?","a":"Animal ownership issues- disposition may not be decided for days/reclaim may be forthcoming"},{"type":"card","domain":"General","sub":"General","q":"What can be sources of emergency equipment in creative shelters?","a":"colleges/businesses/donations/hospital cast-offs/online auctions"},{"type":"card","domain":"General","sub":"General","q":"Expired drugs can be used by shelters in emergencies (T/F)","a":"True but don't- may be less effective and illegal (esp if animal not owned)"},{"type":"card","domain":"General","sub":"General","q":"\"Adoptiblitiy\" should be taken into account when deciding to euthanize a stray animal (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Shelters can be a source of info for private vets treating stray animals. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Name three alternative ways to ensure daily treatments for hospitalized patients in the shelter:","a":"whiteboard treatment schedule, computerized system, medical care binder, or individual tx sheets on cages"},{"type":"card","domain":"General","sub":"General","q":"Society often expects animal shelters to provide the same level of emergency vet care as would be provided in private practice. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"The connection between acts of animal cruelty and violence against humans is widely recognized (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is \"puppy mill?\"","a":"Commercial breeding operation that emphasizes profit at the expense of physical and emotional welfare of animals- largest source of purebred animals for pet stores in the US"},{"type":"card","domain":"General","sub":"General","q":"As of SMVS publication, how many states had felony animal cruelty laws?","a":"47.0"},{"type":"card","domain":"General","sub":"General","q":"Which states had no felony animal cruelty laws at all?","a":"North and South Dakota"},{"type":"card","domain":"General","sub":"General","q":"What is the vet's role in helping determine felony vs misdemeanor charges in animal cruelty?","a":"Can speak to the intensity of pain/suffering/torture the animal likely experienced"},{"type":"card","domain":"General","sub":"General","q":"What is the vet's role in helping determine misdemeanor neglect charges?","a":"Can speak to the quality of food/water/shelter/vet care needed and/or not provided"},{"type":"card","domain":"General","sub":"General","q":"Failure to euthanize an animal can be considered a form of neglect in some states. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Government organizations providing care to homeless, sick, and abused animals are exempt from coverage of state cruelty laws. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What could be a source of realistic standards for regulation of animal shelters?","a":"The ASV guidelines"},{"type":"card","domain":"General","sub":"General","q":"Name three characteristics associated with hoarding:","a":"accumulation of large numbers of animals beyond caring capacity; failure to recognize deteriorating nature of animals; failure to recognize human health effects"},{"type":"card","domain":"General","sub":"General","q":"Which 2 states have \"hoarding\" laws?","a":"Hawaii, Illinois"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between harm and endangerment in a forensic context?","a":"Harm = evidence of injury, endangerment = likelihood of injury if conditions persist"},{"type":"card","domain":"General","sub":"General","q":"What are some consequences of tethering dogs?","a":"Increased aggression of dog, cannot flee if danger approaches, may not be able to reach food/water/shelter"},{"type":"card","domain":"General","sub":"General","q":"What are \"crush videos?\"","a":"Videos of animals being intentionally killed intended as a sexual fetish for the viewer"},{"type":"card","domain":"General","sub":"General","q":"\"Crush Videos\" are illegal in every state (T/F)","a":"True if shared across state borders- Federal law passed in 2010"},{"type":"card","domain":"General","sub":"General","q":"Many states outlaw insertion of a microchip by non-veterinarians (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dog fighting is illegal in every state (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Some states require vets to report suspicions of dog fighting (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are the three biggests puppy mill states?","a":"Missouri, Oklahoma, and Iowa"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between a \"no aimal\" order and a restraining order for a pet?","a":"No Animal = person can't own a pet, Restraining = person can't go near an existing pet"},{"type":"card","domain":"General","sub":"General","q":"How does cost of care affect success in court for abused animals?","a":"Can be a huge obstacle to successful prosecution; care may even be hampered b/c forfeiture may be delayed/uncertain"},{"type":"card","domain":"General","sub":"General","q":"Laws mandating reporting animal cruelty increase animal cruelty reports from vets. (T/F)","a":"Unclear- no studies"},{"type":"card","domain":"General","sub":"General","q":"What is the \"CSI\" effect?","a":"Unreasonable expectations of utility of forensic technology by jury/public"},{"type":"card","domain":"General","sub":"General","q":"Livestock are well represented in animal cruelty laws across the country. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What makes medical information \"forensic?\"","a":"Its use in a court of law"},{"type":"card","domain":"General","sub":"General","q":"Animal cruelty is a medical and legal term. (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are the two main types of forensic case?","a":"Small scale and large scale"},{"type":"card","domain":"General","sub":"General","q":"What are 4 typical reasons a veterinarian may suspect abuse while taking a history?","a":"1. history and injury inconsistent 2.owner refuses to explain injury 3. owner shows lack of concern for injuries 4. delay in seeking treatment 5. history of multiple traumas (or multiple animals traumatized) 6. owner admits abuse"},{"type":"card","domain":"General","sub":"General","q":"In states where reporting is mandatory, failing to report can result in charges against the referring veterinarian (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"If an owner brings a neglected animal to the vet, they are exempt from charges of failing to provide veterinary care later (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"In addition to a physical exam and speaking with the owner, what other historical information is extremely valuable if abuse is suspected?","a":"Medical historical records- may need to call other vet offices"},{"type":"card","domain":"General","sub":"General","q":"What is the first part of the forensic exam?","a":"Establishment of animal ID (descriptive, microchip, etc)"},{"type":"card","domain":"General","sub":"General","q":"What is the canine deciduous dental formula?","a":"I 3/3 C1/1 P3/3"},{"type":"card","domain":"General","sub":"General","q":"What age do permanent canines erupt in dogs?","a":"12-24 weeks"},{"type":"card","domain":"General","sub":"General","q":"What age do permanent premolars erupt in cats?","a":"16-24 weeks"},{"type":"card","domain":"General","sub":"General","q":"What is the basis for all forensic veterinary medical examinations?","a":"Physical Exam"},{"type":"card","domain":"General","sub":"General","q":"What are the two type of abuse?","a":"Neglect and NAI"},{"type":"card","domain":"General","sub":"General","q":"What are the three types of an animal's deviation from a state of comfort?","a":"Pain, distress, and discomfort"},{"type":"card","domain":"General","sub":"General","q":"What are the two categories and their modifiers of pain?","a":"acute, chronic, mild, moderate, severe, excruciating"},{"type":"card","domain":"General","sub":"General","q":"What is a state in which an animal cannot escape from or adapt to internal or external stressors that result in negative effects on well-being?","a":"Distress"},{"type":"card","domain":"General","sub":"General","q":"What is a complex experience that results from mechanical, chemical, thermal stimuli, that damages tissue or has the potential to damage tissue?","a":"Pain"},{"type":"card","domain":"General","sub":"General","q":"What is the gold standard for human pain assessment?","a":"Verbal communication"},{"type":"card","domain":"General","sub":"General","q":"What is the most common way that animal pain is assessed?","a":"Analysis of behavior"},{"type":"card","domain":"General","sub":"General","q":"It is reasonable to guess at the presence of pain in veterinary medicine. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What pain scale is recommended?","a":"Glasgow or Colorado"},{"type":"card","domain":"General","sub":"General","q":"All states have laws requiring animals be provided with food, water, and shelter (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"On the ASPCA BCS scale, each number represents ____ loss in body weight.","a":"0.05"},{"type":"card","domain":"General","sub":"General","q":"How many times should an animal be put on the scale to ensure an accurate weight?","a":"3 times"},{"type":"card","domain":"General","sub":"General","q":"What is the best evidence of starvation?","a":"Weight gain without significant medical intervention"},{"type":"card","domain":"General","sub":"General","q":"What is the average body fat content of a dog?","a":"20-24%"},{"type":"card","domain":"General","sub":"General","q":"How long does it take to \"starve\" a dog from ideal to emaciated body condition?","a":"Minimum 4-6 weeks"},{"type":"card","domain":"General","sub":"General","q":"Radiographs are a vital diagnostic tool in all cases of animal abuse (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What type of camera is recommended for forensic photos?","a":"SLR"},{"type":"card","domain":"General","sub":"General","q":"What are three standard types of photographic views in forensics?","a":"Overalls, orientation shots, and close-up/macro shots"},{"type":"card","domain":"General","sub":"General","q":"Nonaccidental is the same as intentional in forensic injuries (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are the most common (4) types of neglect presented:","a":"1. embedded collars 2. matted hair coat 3. medical neglect 4. starvation"},{"type":"card","domain":"General","sub":"General","q":"To estimate the age of a wound, what sample should be taken for what test?","a":"Wedge biopsy from haired skin through scar tissue down to healthy tissue."},{"type":"card","domain":"General","sub":"General","q":"Where do strangulating matts cause the most damage?","a":"Below the carpus/tarsus"},{"type":"card","domain":"General","sub":"General","q":"What is one standardized way to document hair coat matting in forensics?","a":"Tufts Animal Care and Condition Scale"},{"type":"card","domain":"General","sub":"General","q":"In some states, \"proper sustenance\" may include veterinary care to prevent needless suffering under the law (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are some CBC or PCV/TP changes that can be seen in starved dogs?","a":"Thrombocytosis, hypoalbuminemia, anemia"},{"type":"card","domain":"General","sub":"General","q":"What is the danger of diagnosing a starvation victim with kidney disease?","a":"Reduced protein/nitrogen metabolism cause BUN, Cr and USG values not to be accurate"},{"type":"card","domain":"General","sub":"General","q":"What can you see in the haircoat of a starved dog?","a":"Loss of melanin-> red coat"},{"type":"card","domain":"General","sub":"General","q":"What can you see in the stomach of a starved dog","a":"Ulceration, plus almost any bite-sized non-food item"},{"type":"card","domain":"General","sub":"General","q":"How long does it take to get a \"starved\" dog back to weight?","a":"4-6 weeks"},{"type":"card","domain":"General","sub":"General","q":"What is refeeding syndrome?","a":"Occurs when starved humans are provided with too much food too quickly."},{"type":"card","domain":"General","sub":"General","q":"How should a starved dog be refed?","a":"Bland commercial diet and fed RER for 10-14 days"},{"type":"card","domain":"General","sub":"General","q":"What can you compare a starved puppy's growth to, to explain stunting/growth spurts to a court?","a":"Normal Growth Rate Curves published for 5 breeds (1971)"},{"type":"card","domain":"General","sub":"General","q":"Instead of older classification of first, second, and third-degree burns, what terms are now prefered:","a":"Superficial, partial superficial, partial deep, and deep."},{"type":"card","domain":"General","sub":"General","q":"What is used to classify dog-bite wounds?","a":"Classes- Class 1: partial thickness laceration, Class 2: full thickness laceration (into dermis) Class 3: full thickness puncture Class 4: full thickness puncture or laceration with avulsion of underlying tissues"},{"type":"card","domain":"General","sub":"General","q":"What is necessary for blunt force trauma?","a":"Movement of dense object into animal or movement of animal into dense object-> emergency transfer."},{"type":"card","domain":"General","sub":"General","q":"What is defined as a rupture of small blood vessels in soft tissue resulting in red blood cells moving from vessels into surrounding tissue?","a":"Contusion"},{"type":"card","domain":"General","sub":"General","q":"What wound is created by blunt force causing superficial layer of skin to be scraped away in an irregular fashion?","a":"Abrasion"},{"type":"card","domain":"General","sub":"General","q":"What word is used to describe a catastrophic failure of bone or tooth structure?","a":"Fracture"},{"type":"card","domain":"General","sub":"General","q":"In large-scale animal abuse, group exams are acceptable (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between veterinary medical evidence and veterinary statement of findings?","a":"Statement is in lay terms, explains medical evidence and findings, summarizes case"},{"type":"card","domain":"General","sub":"General","q":"Why might a preliminary statement be necessary in a forensic case?","a":"Because the full medical investigation takes time, and sometimes the statement is needed so law enforcement can make an arrest/submit case to DA"},{"type":"card","domain":"General","sub":"General","q":"Because of the medicolegal implications of the forensic necropsy, all _________ and _________ should be thoroughly documented.","a":"findings and lack of findings"},{"type":"card","domain":"General","sub":"General","q":"Per. M. Merck, investigators should share all circumstances leading up to animal seizure with veterinarians before their exam/necropsy. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How should a body be prepared for transport to a forensic necropsy?","a":"Moved as little as possible, paper bags on feet, wrapped in white sheet, placed in clean body bag, refrigerated (never frozen)."},{"type":"card","domain":"General","sub":"General","q":"What diagnostic technique should be performed on a body prior to necropsy?","a":"Radiographs"},{"type":"card","domain":"General","sub":"General","q":"What is the main question of a forensic necropsy?","a":"Was the injury/cause of death accidental or nonaccidental?"},{"type":"card","domain":"General","sub":"General","q":"What is the most pathognomonic feature of abuse in animals?","a":"Repeated injury- whether multiple fx of same bones or fx of many different bones"},{"type":"card","domain":"General","sub":"General","q":"Should evidence bags be paper or plastic?","a":"Paper- to prevent moisture build up"},{"type":"card","domain":"General","sub":"General","q":"What technique can be used to collect dried fluid on a body in necropsy?","a":"Wet-dry technique: roll a swab with sterile water on dry fluid, then roll dry swab over area. Also roll control swab on adjacent area."},{"type":"card","domain":"General","sub":"General","q":"What angle should forensic photographs be taken?","a":"90 degrees to area of interest"},{"type":"card","domain":"General","sub":"General","q":"What else (besides the lesion) should be in forensic photographs?","a":"A photographic scale"},{"type":"card","domain":"General","sub":"General","q":"What is the first step of a necropsy, after unwrapping the body?","a":"External examination and photography"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between rigor and livor?","a":"Rigor is stiffness, livor is blood pooling"},{"type":"card","domain":"General","sub":"General","q":"What is the Locard exchange principle?","a":"Any time two or more surfaces come into contact with each other, there is a mutual exchange of trace matter between the surfaces"},{"type":"card","domain":"General","sub":"General","q":"What should a forensic necropsist wear?","a":"Surgical cap, gown, mask, and gloves"},{"type":"card","domain":"General","sub":"General","q":"What is the difference between evidence collection tweezers and surgical forceps?","a":"Plastic, with ridges, so can grab but won't damage/scrach metal"},{"type":"card","domain":"General","sub":"General","q":"What is a trace evidence \"lifter?\"","a":"Like cellophane tape- picks up minute trace evidence. Tape can be used if stuck to wax paper"},{"type":"card","domain":"General","sub":"General","q":"How should hair or fiber be collected as trace evidence?","a":"In paper with pharmacist's fold (3-way top/bottom, then 3-way side/side)"},{"type":"card","domain":"General","sub":"General","q":"How should trace accelerants be collected for forensic analysis?","a":"In glass jars or non-coated paint cans (air tight)"},{"type":"card","domain":"General","sub":"General","q":"How should GSR be collected for forensic analysis?","a":"Using lifting tape"},{"type":"card","domain":"General","sub":"General","q":"What is a good source of DNA in a dessicated/degraded body?","a":"Tooth pulp cavity or long bone"},{"type":"card","domain":"General","sub":"General","q":"How should you store wet samples to be submitted for forensic DNA analysis?","a":"Collect in airtight container then freeze, ship overnight to lab"},{"type":"card","domain":"General","sub":"General","q":"What is the main purpose of forensic entomology?","a":"To estimate a time of death"},{"type":"card","domain":"General","sub":"General","q":"Larval development can be affected by drugs and chemicals in a dead body. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Insect activity follows a set pattern in a dead body. This is:","a":"Head, uro-genital-anal area, then wounds."},{"type":"card","domain":"General","sub":"General","q":"Which larvae should be selected for analysis on necropsy?","a":"The largest, since they were likely the first laid"},{"type":"card","domain":"General","sub":"General","q":"What does the presence of empty pupa cases indicate on a dead body?","a":"That a full life cycle has taken place and indicates minimum elapsed time since death"},{"type":"card","domain":"General","sub":"General","q":"What is lividity used to determine?","a":"Position of body since death"},{"type":"card","domain":"General","sub":"General","q":"When does lividity start?","a":"30min-2hrs after death"},{"type":"card","domain":"General","sub":"General","q":"Why does livor mortis occur?","a":"blood pooling in small vessels due to gravity post-mortem"},{"type":"card","domain":"General","sub":"General","q":"What does it mean when livor mortis is fixed?","a":"That 24-36 hrs have passed since death"},{"type":"card","domain":"General","sub":"General","q":"How do you distinguish between livor mortis and bruising?","a":"Bruising will have blood pooling in all tissues, livor is contained in vessels"},{"type":"card","domain":"General","sub":"General","q":"What happens after blood vessels start to break down?","a":"Blood hemolyzed, leaks into surrounding tissues, gets imbibed by surrounding tissues"},{"type":"card","domain":"General","sub":"General","q":"How can you distinguish between tissue imbibition and bruising post-mortem?","a":"imbibition is hemolyzed, bruising has intact RBC"},{"type":"card","domain":"General","sub":"General","q":"Define rigor mortis:","a":"Postmortem muscle contraction that immobilizes joints of the body"},{"type":"card","domain":"General","sub":"General","q":"Rigor can set in faster under what premortem conditions?","a":"exercise, violent struggle, convulsions, sepsis->hyperthermia"},{"type":"card","domain":"General","sub":"General","q":"Rigor dissipates in the same apparent order it forms (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is a cadaveric spasm?","a":"When rigor occurs immediately after death- seen with electrocution"},{"type":"card","domain":"General","sub":"General","q":"Why does rigor mortis disappear?","a":"Decomposition of actin/myosin fibers"},{"type":"card","domain":"General","sub":"General","q":"Emaciated bodies have faster onset and shorter duration of rigor mortis (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is algor mortis?","a":"Cooling of the body after death"},{"type":"card","domain":"General","sub":"General","q":"Algor mortis can be used to pinpoint time of death accurately (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"What are the three ways heat is lost from a body?","a":"Conduction (solid-solid), convection (solid-air current), and radiation (gamma rays)"},{"type":"card","domain":"General","sub":"General","q":"What two processes are responsible for decomposition?","a":"Putrefaction and autolysis"},{"type":"card","domain":"General","sub":"General","q":"What organs undergo autolysis faster?","a":"Liver and pancreas, due to high number of lytic enzymes"},{"type":"card","domain":"General","sub":"General","q":"Why does putrefaction occur?","a":"GI bacteria spread throughout the body."},{"type":"card","domain":"General","sub":"General","q":"Greyish-green discoloration of the abdomen occurs in the first 24-36 hrs after death (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is the first step of a forensic internal necropsy exam?","a":"Reflection of the entire skin"},{"type":"card","domain":"General","sub":"General","q":"What necropsy tissue sample can help determine pre-mortem starvation?","a":"Bone marrow fat analysis"},{"type":"card","domain":"General","sub":"General","q":"Which should be used to collect blood samples during forensic necropsy, glass or plastic vials?","a":"Glass vials"},{"type":"card","domain":"General","sub":"General","q":"What fluid can be collected during necropsy for electrolyte, blood chemistry and toxin analysis if blood is not available?","a":"vitreous"},{"type":"card","domain":"General","sub":"General","q":"If there is no evidence of inflammatory response surrounding an injury, when did the injury occur?","a":"Close proximity to death. Rec. histopath to determine pre vs post"},{"type":"card","domain":"General","sub":"General","q":"A bruise most closely resembles the object that caused it early on or after some time?","a":"Early on"},{"type":"card","domain":"General","sub":"General","q":"Wounds that are due to hospital procedures may be misinterpreted as injuries (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"When should a body be removed for disposal in a forensic necropsy?","a":"when the lead investigator authorizes or the case is closed."},{"type":"card","domain":"General","sub":"General","q":"Cats are more likely to be intentionally poisoned than dogs (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Few poisons produce pathognomonic lesions, making it easy to confuse a poisoning case with other disease processes (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What samples should be collected to determine if an animal has been poisoned?","a":"blood, trace evidence, gastric contents, urine, feces"},{"type":"card","domain":"General","sub":"General","q":"What is part of an investigation into whether an animal has been poisoned?","a":"Evaluation of the animal's natural environment"},{"type":"card","domain":"General","sub":"General","q":"Inebriation, acidosis, and renal failure are symptoms of what toxin?","a":"ethylene glycol"},{"type":"card","domain":"General","sub":"General","q":"severe unexplained hemorrhage could be a symptom of what type of toxin?","a":"Anticoagulant rodenticides"},{"type":"card","domain":"General","sub":"General","q":"Clonic tonic convulsions could be a symptom of what toxin?","a":"Strychnine"},{"type":"card","domain":"General","sub":"General","q":"Seizures, vomiting, salivation, bradycardia, and respiratory paralysis could be a symptom of what toxins?","a":"Organophosphates or carbamates (faster onset)"},{"type":"card","domain":"General","sub":"General","q":"Pink vomit, depression, collapse, coma, with garlic or fishy odor could be symptomatic of what toxin?","a":"Zinc phosphide"},{"type":"card","domain":"General","sub":"General","q":"How should stomach contents be saved to analyze for toxicology?","a":"Frozen right away"},{"type":"card","domain":"General","sub":"General","q":"The presence of more than one toxin in an animal increases suspicion of non-accidental poisoning (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What are some health risks for pets of meth manufacturers?","a":"Burns from chemical fires, inhalation of toxic vapors/gas, burns to skin from corrosive chemicals, systemic effects from ingesting pre-or post-products, and mechanical injury from paraphernalia."},{"type":"card","domain":"General","sub":"General","q":"What should be worn by humans entering a meth lab crime scene to retrieve animals?","a":"Tyvek, respirators, hand, foot, and face covers"},{"type":"card","domain":"General","sub":"General","q":"What is the process of decontaminating a meth lab animal?","a":"Remove collars/leashes (discard in hot zone), bathed with liquid dish soap and warm water, rinsed, and repeated 2x, dried, kept warm, and transported to vet"},{"type":"card","domain":"General","sub":"General","q":"What are symptoms of animals exposed to methamphetamine?","a":"agitation, dilated pupils, increased HR and BP, increased temp, disorientation, tremors, seizures."},{"type":"card","domain":"General","sub":"General","q":"How soon should urine and blood be collected from animals possibly exposed to methamphetamine?","a":"6-12hrs"},{"type":"card","domain":"General","sub":"General","q":"Rehabilitation of animals exposed to methamphetamine is considered guarded (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Animal hoarding may be facilitated by a broad network of active or passive __________.","a":"Enablers"},{"type":"card","domain":"General","sub":"General","q":"What two species are the most commonly hoarded?","a":"Dogs and cats"},{"type":"card","domain":"General","sub":"General","q":"Describe some characteristics of the stereotypical hoarder:","a":"Old female, poor, lives alone."},{"type":"card","domain":"General","sub":"General","q":"What are the three types of people in the classification of harders?","a":"Overwhelmed caregiver hoarder, Rescuer hoarder, and Exploiter hoarder"},{"type":"card","domain":"General","sub":"General","q":"How successful are interventions for overwhelmed caregiver hoarders?","a":"Most successful of all hoarders"},{"type":"card","domain":"General","sub":"General","q":"How successful are interventions for rescuer hoarders?","a":"Harder- tend to actively acquire animals, main self view is of \"helper\""},{"type":"card","domain":"General","sub":"General","q":"How successful are interventions for exploiter hoarder?","a":"Difficult- lacks remorse, can be charming, indifferent to harm caused"},{"type":"card","domain":"General","sub":"General","q":"Compulsive caregiving ceases to be altruistic or benign when the focus on the activity become s meeting the needs of the ____ instead of the ______.","a":"Person, animal"},{"type":"card","domain":"General","sub":"General","q":"What is one argument against the theory that toxoplasmosis leads to hoarding?","a":"Many hoarders do not hoard cats."},{"type":"card","domain":"General","sub":"General","q":"Hoarding situations (large populations of randomly mixed animals in substandard conditions) create ideal conditions for incubation and transmission of _______","a":"Infectious diseases"},{"type":"card","domain":"General","sub":"General","q":"What is the veterinarian's role in the ICS schema in hoarding responses?","a":"Operations Planning, Triage, and Veterinary Teams (on/off site)"},{"type":"card","domain":"General","sub":"General","q":"What particular needs should be anticipated for animals from a hoarding case?","a":"Triage-emergency treatment, infectious disease management (quarantine/isolation), and possible euthanasia. Long term housing may be needed."},{"type":"card","domain":"General","sub":"General","q":"To help with starvation charges in a hoarding case, what should be documented?","a":"All evidence of animal food on premises"},{"type":"card","domain":"General","sub":"General","q":"Why should windows maybe not be opened in a hoarding house to improve ventilation?","a":"Because animals will escape out the windows."},{"type":"card","domain":"General","sub":"General","q":"In addition to dogs and chickens, what are some other species that are \"fought?\"","a":"Crickets, spiders, canaries, horses, fish"},{"type":"card","domain":"General","sub":"General","q":"What is a significant infectious chicken disease associated with cockfighting?","a":"exotic Newcastle disease"},{"type":"card","domain":"General","sub":"General","q":"Interstate traffic of dogs for fighting purposes is:","a":"A federal felony (FBI)"},{"type":"card","domain":"General","sub":"General","q":"Animal cruelty is always a component of dogfighting enterprises (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Dog fighting as we know it really got it's start when?","a":"In 1835 England when bear baiting and bull baiting were outlawed"},{"type":"card","domain":"General","sub":"General","q":"What is the most basic reason people are attracted to dog fighting?","a":"Greed."},{"type":"card","domain":"General","sub":"General","q":"How does \"banning\" pit bulls backfire in dogfighting circles?","a":"People with \"banned\" dogs are even more cool - \"outlaw\" status is coveted."},{"type":"card","domain":"General","sub":"General","q":"Most animal protection, animal control, and vet organizations oppose BSL as a solution to bite and dog fighting concerns. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Name three types of dog fighters:","a":"Street fighters (informal, impromptu), Hobbyists (organized but only a few dogs), Professionals (large yard 50+ dogs, into bloodlines). There may be a new category of Professional/Street = rich people who get involved"},{"type":"card","domain":"General","sub":"General","q":"Almost all dogs encountered in professional and hobbyist fight situations are American Pit Bull Terriers (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Almost all dogs encountered in street dog fights are American Pit Bull Terriers (T/F)","a":"False- often mixed with other \"aggressive\" and larger breeds"},{"type":"card","domain":"General","sub":"General","q":"Fights involving male dogs vs female dogs are common in traditional dogfighting (T/F)","a":"False- female-female and male-male"},{"type":"card","domain":"General","sub":"General","q":"Where do most fighting dogs spend their life?","a":"On short heavy chains just out of reach of other dogs"},{"type":"card","domain":"General","sub":"General","q":"How are fighting dogs bred?","a":"With rape stands"},{"type":"card","domain":"General","sub":"General","q":"What is a prize characteristic of a fighting dog?","a":"\"Gameness\""},{"type":"card","domain":"General","sub":"General","q":"What is the purpose of the \"keep\" in dog fighting?","a":"A period of conditioning and muscle development before a dog fight"},{"type":"card","domain":"General","sub":"General","q":"Even without legal mandate to report, vets who assist clients who are suspected of dogfighting may be subject to criminal charges as accessories if they fail to report (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Most seized fighting dogs show aggression to people, so sedation is necessary during examination (T/F)","a":"FALSE - sedation may be needed to prevent dog-dog arousal/contact"},{"type":"card","domain":"General","sub":"General","q":"In dog fighting, the seized dog is both the victim and the evidence of a crime (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What infectious pathogen is commonly seen in fighting dogs?","a":"Babesia (both gibsoni and canis)"},{"type":"card","domain":"General","sub":"General","q":"Why should DNA be collected from each dog in a dog-fighting raid?","a":"To add/cross reference to Canine CoDIS"},{"type":"card","domain":"General","sub":"General","q":"In legal dog fighting raid cases, if euthanasia is necessary, how should the vet proceed?","a":"Find another vet to also sign off- everything clearly documented."},{"type":"card","domain":"General","sub":"General","q":"Scars associated with pit fights are usually located where?","a":"Chest, Face, Forelegs"},{"type":"card","domain":"General","sub":"General","q":"A \"ring\" wound around a forelimb should make one suspicious of:","a":"Dog fighting"},{"type":"card","domain":"General","sub":"General","q":"What are some characteristics of a fighting cock?","a":"Wattle and comb \"dubbed\" off, feathers trimmed, belly shaved, spurs removed."},{"type":"card","domain":"General","sub":"General","q":"What is a \"gaff\" in cockfighting?","a":"A knife that is attached to the cut spur"},{"type":"card","domain":"General","sub":"General","q":"Cocks usually fight to the death (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"How should seized fighting birds be housed?","a":"Individually with visual barriers"},{"type":"card","domain":"General","sub":"General","q":"Most fighting birds are euthanized when the case is closed. (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Most fighting dogs are euthanized when the case is closed (T/F)","a":"0"},{"type":"card","domain":"General","sub":"General","q":"Although neglect may lead to death of a horse, its use (as a companion vs as a racehorse) may mean the crime does not qualify for felony charges (T/F)","a":"1"},{"type":"card","domain":"General","sub":"General","q":"What is considered necessary sustenance for horses?","a":"shelter, daily supervision, routine hoof care, nutritious food, clean water, hazard-free pasture"},{"type":"card","domain":"General","sub":"General","q":"How is BCS evaluated in horses?","a":"6 areas are evaluated (neck, withers, shoulder, loin, ribs, tail head) for fat, and number out of 9/6."},{"type":"card","domain":"General","sub":"General","q":"If a horse is standing with front feet weighted toward heels, and shifts legs even on soft ground, you should suspect:","a":"laminitis"},{"type":"card","domain":"General","sub":"General","q":"It is easy to tell if a horse is in pain (T/F)","a":"False- stoic, out of familiar circumstances, etc"},{"type":"card","domain":"General","sub":"General","q":"In a starved horse, what should be given in small regular amounts during the first few days of refeeding?","a":"Alfalfa hay; document weight gain"},{"type":"card","domain":"General","sub":"General","q":"What should be monitored in a horse being refed?","a":"signs of colic, diarrhea, fecal output, parasites."},{"type":"card","domain":"General","sub":"General","q":"One arena where horses may be subject to physical abuse is:","a":"Any showing/jumping/rodeo/racing where poor training is used"},{"type":"card","domain":"General","sub":"General","q":"What is \"soring?\"","a":"Application of caustic blistering agents to the pasterns, the use of chains on the legs, or special shoeing to develop exaggerated gait of Tennessee Walking Horses"},{"type":"card","domain":"General","sub":"General","q":"How can you detect soring in a vet exam?","a":"Thermography and digital radiography"},{"type":"card","domain":"General","sub":"General","q":"What are some reasons owners interfered with their horses' tails in a cruel way?","a":"Prevent swishing in Western Pleasure/Hunter shows, to dock tails of draft horses, \"soring\" the anus to get tails up in Arabs/Standardbreds"},{"type":"card","domain":"General","sub":"General","q":"How are race horses protected if breakdowns occur?","a":"Thoroughbred Racing Association created a Safety and Integrity Alliance holds racetracks to higher standards- requires breakdowns to be reported and aftercare and retirement to be provided to horses."},{"type":"card","domain":"General","sub":"General","q":"What steps are being taken in Steeplechasing to protect horse and rider safety?","a":"\"Frangible\" technology- no longer solid objects for jumps"},{"type":"card","domain":"General","sub":"General","q":"Choose: felony or misdemeanor. While many ______ animal cruelty loaws focus on affirmative acts that cause severe harm or death, most _______ cruelty laws address the all-too-frequent incidence of animal neglect.","a":"While many felony animal cruelty loaws focus on affirmative acts that cause severe harm or death, most misdemeanor cruelty laws address the all-too-frequent incidence of animal neglect."},{"type":"card","domain":"General","sub":"General","q":"T/F In NY, PEnnsylvania, Maine, Utah, and Washington only a licensed vet may insert microchips","a":"T. NY provides exemption for  employees of animal shelters to insert chips as well."},{"type":"card","domain":"General","sub":"General","q":"How many states have felony dog fighting laws?","a":"All of them + district of columbia"},{"type":"card","domain":"General","sub":"General","q":"How many states mandate that veterinarians report suspected animal fighting?","a":"2- AZ and WI"},{"type":"card","domain":"General","sub":"General","q":"What are the top 3 states for puppy mill breeders?","a":"Missouri>> Iowa and OK"},{"type":"card","domain":"General","sub":"General","q":"T/F: For teh most part animal cruelty is prosecuted under state (vs federal) law","a":"T."},{"type":"card","domain":"General","sub":"General","q":"In a forensic exam, the presence of the following signs indicates an animal is at least how old:\n-- nuclear sclerosis\n--benign prostatic hypertrophy","a":"-- nuclear sclerosis- at least 5 yrs old\n--benign prostatic hypertrophy- males over 5 years old"},{"type":"card","domain":"General","sub":"General","q":"Define distress","a":"A state in which animal cannot escape from or adapt to internal or external stressors that resul in negative effects on well-being --> maladaptive behaviors or illness"},{"type":"card","domain":"General","sub":"General","q":"Going from an ideal BCS (5) to thin (3) represents primarily a loss of (choose: body fat or muscle)","a":"BCS 5  to 3 is loss of primarily body fat. Each point on scale 9 to 1 represents ~5% loss in body weight. BCS 3 to 2 uses both muscle and fat; use of body muscle indicates body had entered starvation metabolism."},{"type":"card","domain":"General","sub":"General","q":"What is the ultimate proof of starvation?","a":"Weight gain wihtout significant medical intervention."},{"type":"card","domain":"General","sub":"General","q":"A BCS of 5 on the 9 point Purina scale is equivalent to a BCS of ________ on the Tufts care and condition scale, while a BCS of 1 on the Purina scale is equivalent to a BCS of _________ on the Tufts scale. The Tuffs scale is a _____ (#) point scale.","a":"A BCS of 5 (ideal) on the 9 point Purina scale is equivalent to a BCS of 1 on the Tufts care and condition scale, while a BCS of 1 (emaciated) on the Purina scale is equivalent to a BCS of 5 on the Tufts scale. The Tuffs scale is a 5 point scale (1= ideal, 5 = emaciated- no overweight categories)."},{"type":"card","domain":"General","sub":"General","q":"T/F: The intake assessment of BCS should be vague and two terms should be circles (e.g. lean and thin)","a":"T."},{"type":"card","domain":"General","sub":"General","q":"An emaciated dog has a body weight loss of at least ______% from ideal","a":"An emaciated dog has a body weight loss of at least 20-25% from ideal."},{"type":"card","domain":"General","sub":"General","q":"A dog presented to you at 50 lbs with an emaciated BCS. Time and kibble allow the dog to reach an ideal BCS at 70 lbs.  How do you present the different in weights to legal officials?","a":"You can calculate a) weight gain/ideal weight = 20 lb/70 lb = 28% loss from ideal or b) weight gain/presenting weight = 20/50 = 40% gain from presenting weight"},{"type":"card","domain":"General","sub":"General","q":"What are the minimum standard tests that should be peformed for forensic evaluations of live animals?","a":"Chem, CBC, urinalysis, fecal evaluation, rads, photos"},{"type":"card","domain":"General","sub":"General","q":"What clinical path changes are common in starved animals?","a":"thrombocytosis, hypoalbuminemia, and anemia"},{"type":"card","domain":"General","sub":"General","q":"What is the minimum time period required for weight loss due to starvation to progress from a normal body condition to an emaciated BCS?","a":"4-6 weeks"},{"type":"card","domain":"General","sub":"General","q":"What are the 3 standard photographic views used in a forensic exam of a live animal?","a":"Overalls (entire body/crime scene), Orientation (for close ups, includes familiar physical feature or anatomic landmark), Close up/macro (specific pt of interest)."},{"type":"card","domain":"General","sub":"General","q":"You can estimate teh length of time a wound has existed using a wedge biopsy based on predictable rates of development and growth of granulation tissue.  It takes approx _____ (amount of time) for a granulation bed to form, and granulation tissue then grows at a rate of about _____ (distance) per day and _______ (distance) per month (it slows down as the lesion ages)","a":"You can estimate teh length of time a wound has existed using a wedge biopsy based on predictable rates of development and growth of granulation tissue.  It takes approx1 week for a granulation bed to form, and granulation tissue then grows at a rate of about 1 mm per day and 1 cm per month (it slows down as the lesion ages)"},{"type":"card","domain":"General","sub":"General","q":"T/F: Prosecution for medical neglect (\"failure to treat\") is just as common as prosecutions for starvation or physical abuse.","a":"F. most state anticruelty statutes do not mandate  veterinary care."},{"type":"card","domain":"General","sub":"General","q":"An adult cat with a BCS of 2/9 and a weight of 2.0 kg comes into the shelter. Make a refeeding protocol for the cat.","a":"Refeeding protocol for starved animals (from UC Davis SMP website):  A refeeding diet should be high-fat and low carbohydrate, with adequate potassium, phosphate, and magnesium. Initially feed only ¼ of resting energy requirement (RER) divided into six small meals per day. This can be calculated by the formula RER = (30 x BWkgs) + 70, or simply go by the feeding recommendations for the chosen food. Amount should be increased by 1/8 to ¼ of the total requirement over   several days. As noted, parenteral thiamine should be provided. Other supplementation is not generally indicated. Refeeding syndrome usually occurs within the first 3-7 days. [1,2] The number of feedings can be decreased and the amount at each meal increased gradually over the first ten days, until the animal is free fed (for non-gluttonous individuals) or placed on a plan to allow steady weight gain."},{"type":"card","domain":"General","sub":"General","q":"RER x physiology factor = daily energy requirements (DER). What are the factors for \n- pup <= 4 mo old\n- pup> 4 mo old\n- avg neutered healthy adult dog\n- intact adult dog","a":"DER\n- pup <= 4 mo old: x3\n- pup> 4 mo old: x2\n- avg neutered healthy adult: x 1.6\n- intact adult: x 1.8"},{"type":"card","domain":"General","sub":"General","q":"RER x physiology factor = daily energy requirements (DER). What are the factors for \n- kitten <= 4 mo old\n- kitten> 4 mo old\n- avg neutered healthy adult\n- intact adult","a":"DER\n- kitten <= 4 mo old: x 2.5\n- kitten> 4 mo old: x 2.5\n- avg neutered healthy adult: x 1.2\n- intact adult: x 1.4"},{"type":"card","domain":"General","sub":"General","q":"Describe the classes of dog bite injuries class 1-4","a":"Class 1: partial thickness laceration\nClass 2: full thickness laceration (penetration of dermis)\nClass 3: ful thickness puncture wound\nClass 4: full thickness puncture or laceration with avulsion of underlying tissues and dead space"},{"type":"card","domain":"General","sub":"General","q":"Describe the following lesions of blunt force trauma\ncontusion\nabrasion\nlaceration\nhemorrhage\nfracture","a":"contusion: rbcs move from injured blood vessels to surrounding tissue\nabrasion: superficial surface of epithelium scraped away\nlaceration: skin surface is broken or torn, tissue is stretched, sheared or avulsed. compared to an incised wound, laceration is irregular, bleeds less, has surrounded contused tissue. Also used for break or tear in internal organ\nhemorrhage: large discharge of blood from broken vessels\nfractures: catastrophic failure of bone or tooth structure"},{"type":"card","domain":"General","sub":"General","q":"How do you estimate a cat or dog's total blood volume (different for each)","a":"cat: 50-60 ml/kg\ndog: 80-90 ml/kg"},{"type":"card","domain":"General","sub":"General","q":"T/F: The veterinary statement of findings is a technical document that should emphasize the veterinarian's expertise and authority in examing a live animal in a forensic case","a":"F. It must be written in detail but in a way that persons not trained in med terminology can understand. Do not include normal findings unless relevant (e.g no medical cause for poor body condition evident)."},{"type":"card","domain":"General","sub":"General","q":"What should be done with the body of a deceased victim of an alleged crime scene prior to transporting it for necropsy?","a":"Diagram and/or photos documenting the scene, place paper bags on feet, wrap body in a clean white sheet, then bag and transport"},{"type":"card","domain":"General","sub":"General","q":"What is lividity? Rigor?","a":"Rigor: stiffness. Lividity: blood pooling"},{"type":"card","domain":"General","sub":"General","q":"T/F: Forensic entomology can provide the most accurate time of death","a":"T with appropriate collection and documentation. Blowflies only colonize a body after death--> minimum post mortem interval"},{"type":"card","domain":"General","sub":"General","q":"Define livor mortis and its value in a forensic necropsy evalution","a":"Pooling of blood due to gravity after the heart stops beating. Most useful for determining body position at time of death (compared to when it was found)"},{"type":"card","domain":"General","sub":"General","q":"The presence of fixed lividity in nondependent areas of a deceased animal indicates what?","a":"That the body was moved after death."},{"type":"card","domain":"General","sub":"General","q":"How can you dfferentiate bruising vs lividity?","a":"Incise the area in question. Bruised areas will have diffuse hemorrhage into the soft tissues (hemorrhage cannot be wiped or squeezed out), while lividity is characterized by blood confined within the blood vessels"},{"type":"card","domain":"General","sub":"General","q":"What are Tardieu spots or imbibitions?","a":"When blood leaks out of the blood vessels post mortem either due to hydrostatic pressure (Tardieu spots/petechiae/purpura) and/or progression of decomposition (imbibitions). In mibibition it is hemolyzed blood that leaks into tissues, not whole RBCs (as in antemortem bruising)."},{"type":"card","domain":"General","sub":"General","q":"T/F: Rigor mortis can be broken by stretching the limbs, but it will recur","a":"F. It will only recur if it wasn't yet fully developed, and will do so with less stiffness. It is important to know how the body was handled and transported prior to exam"},{"type":"card","domain":"General","sub":"General","q":"The onset of rigor is (choose faster/slower) and of (choose shorter/longer) duration in aimals who have decreased glycogen levels as seen with starvation and exhaustion. `","a":"The onset of rigor is faster and of shorter duration in aimals who have decreased glycogen levels as seen with starvation and exhaustion. `"},{"type":"card","domain":"General","sub":"General","q":"Algor mortis is what?","a":"The cooling of the body after death."},{"type":"card","domain":"General","sub":"General","q":"_____ involves the two processes of putrefication and autolysis. It usually occurs from 6-36 hours depending on the condition of the animal and the environmental conditions of the exposed animal","a":"decomposition. Autolysis = chemical process via intracellular enzymes. Putrefication = bacteria/fermentation."},{"type":"card","domain":"General","sub":"General","q":"Fun fact! What are the last two organs to decompose in deceased humans (but not the same human)?","a":"Uterus and prostate."},{"type":"card","domain":"General","sub":"General","q":"What histopath findings suggest an injury occured antemortem (vs post mortem)?","a":"Hemorrhage, neutrophils and/or edema (inflammation) may be be present within hours of an antemortem injury. No inflam response indicates injury occurred in close proximity to death. Chronic inflammation indicated by presence of fibroblasts and hemosiderin.  granulation tissue starts to form between d 3 and 5 after injury, and by day 5 has filled the wound"},{"type":"card","domain":"General","sub":"General","q":"Which makes up more of the reported cases of malicious animal poisioning cases, cats or dogs?","a":"Dogs = 75%, cats 15%; remainder other spp"},{"type":"card","domain":"General","sub":"General","q":"A dog presents to you with vomiting, depression, hypersalivation, seizures and you smell  a strong garlic or rotten fish like odor. What is your top forensic differential?","a":"Zinc phophide poisoning"},{"type":"card","domain":"General","sub":"General","q":"In cases of suspected poisoning, what samples should be collected from a live animal?","a":"blood, serum or plasma, stomach contents/vomitus, urine, feces, hair"},{"type":"card","domain":"General","sub":"General","q":"In cases of suspected poisoning, what samples should be collected from a deceased animal?","a":"stomach/intestinal contents, feces, urine, liver, kidney, eyeball (for vitreous), brain, fat, skin and sq around injection sites, blood from heart"},{"type":"card","domain":"General","sub":"General","q":"Toxicants that cause peracute signs/death may only be detectable in what body sites?","a":"Blood, GI contents/vomit"},{"type":"card","domain":"General","sub":"General","q":"What sample site can be useful for topical exposures or long term systemic exposure to toxicants but is generally unrewarding for acute oral exposures?","a":"Hair"},{"type":"card","domain":"General","sub":"General","q":"When choosing an agent to maliciously poison an animal (as opposed to altruistically posison an animal :P) people tend to use what they know, so it is not suprising that ______ is one of the most frequently used agents in animal poisoning cases","a":"ethylene glycol"},{"type":"card","domain":"General","sub":"General","q":"What clinical signs/problems would you expect in a case of ethylene glycol toxicosis?","a":"ACutely: inebriation, acidosis, acute renal failure. Lesions: crystals in renal tubules"},{"type":"card","domain":"General","sub":"General","q":"A dog arrives DOA to the shelter with blood pouring out of everywhere. You can find no evidence of trauma. What sample sites should be sampled, and what is your top differential?","a":"Anticoag rodenticide poisoning (brodifacoum, bromadiolone, diphacinoe). Sample blood and liver."},{"type":"card","domain":"General","sub":"General","q":"An owner brings in their cat to the shelter with SLUD signs (salivation, lacrimation, urination, and defecation). Other severe signs include hypothermia, hyperthermia, difficulty breathing, tremors,) and says their abusive spouse recently threatened to poison the cat. What is your top differential?","a":"Organophosphate  (-thion, -os) or  Carbamate (-icarb, -furan) poisoning.some carbamates may cause seizures and death within 10 min"},{"type":"card","domain":"General","sub":"General","q":"Alligators are a great option for guarding what?","a":"Your meth lab :)"},{"type":"card","domain":"General","sub":"General","q":"What is the first consideration for seizing animals from a meth lab?","a":"Animals may be contaminated by hazardous substances, and people hanling should have apporpriate PPE and a plan for initial decontamination. Minimal PPE is eye, hand, foot covering, ideally protective jumpsuits and respirators"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended decontamination method for animals removed from meth labs?","a":"BAthing with liquid dish soap and warm water. Sample prior to bath if needed."},{"type":"card","domain":"General","sub":"General","q":"A dog recently seized and deconaminated from a meth lab presents to you for evaluation with signs of agitation, dilated pupils, increased heart rate, increased blood pressure, increased body temp, disorientation, and tremors. What are your top 2 differentials?","a":"1) acute effects from meth exposure\n2) stress of being seized, decontaminated, transported. IF this is the case signs should subside once animal placed in quiet environment"},{"type":"card","domain":"General","sub":"General","q":"What is the window of time in which blood and urine samples can be collected to detect meth exposure in seized animals?","a":"Blood: 6-12 hours, urine: 48 hours.  You can get OTC urine tests for meth at most drug stores! Negative test doesn't rule out exposure to precursor chemicals"},{"type":"card","domain":"General","sub":"General","q":"There are 3 preliminary working classifications of hoarders. What are they, and why are they important?","a":"Overwhelmed caregiver, rescue hoarder, and exploiter. They are important b/c they indicate that different intervention strategies are more or less likley to be effective."},{"type":"card","domain":"General","sub":"General","q":"T/F: Animal hoarding is recongized as a variant of borderline personality disorder (Axis II)","a":"F. Animal hoarding is not yet recognized as a diagnostic of any specific psychological disorder listed in the Diagnostic and Statistical Manual of Mental Disorders (DSM)."},{"type":"card","domain":"General","sub":"General","q":"Under what circumstances might a state vet impose and enforce a quarantine of a premises where animal hoarding has been occurring?","a":"When contagious or reportable diseases are present or suspected"},{"type":"card","domain":"General","sub":"General","q":"T/F In cases of hoarding it is acceptable to examine at least 30% of the population as long as efforts are made to ensure the conditions of the animals examined are representative of the overall population","a":"F. It is important to carefully examine each animal and document their condition in individual medical records. Teh same standards apply in assessing a hoarding case as in a case of single animal abuse."},{"type":"card","domain":"General","sub":"General","q":"The National Institute for Occupational Safety and Health (NIOSH) recommended exposure limit (REL) for ammonia of _____ parts per million","a":"The National Institute for Occupational Safety and Health (NIOSH) recommended exposure limit (REL) for ammonia of 25 parts per million (ppm), with a shortterm exposure limit of 35 ppm (no more than 15 minutes averaged throughout the workday) should not be exceeded. In severe hoarding cases Ammonia levels can exceed 150 ppm.  Properly maintained animal shelters, catteries, kennels will have levels <1-2 ppm even before morning cleaning"},{"type":"card","domain":"General","sub":"General","q":"There are 3 main categories of dogfighting activities:","a":"street fighting - freq associated with gang activities, police may encounter dead or dying animals abandoned afterwards. hobbyist fighters- more organized than street fighting, have one or more dogs participate in several fights a year. Attn to care and breeding of dogs, more likely to cross state lines for events. Professional dogfighters-  often have 50+ dogs, promote established winning bloodlines and long-term conditioning of animals. Hobbyists and professionals are likely to dispose of human aggressive dogs by selling them to street fighters or people wanting an aggressive dog."},{"type":"card","domain":"General","sub":"General","q":"T/F: Dogfighters are commonly encountered in veterinary practices situations due to their need to secure vaccines, drugs and supplies for their operations.","a":"F. They usually obtain needed supplies elsewhere, as they prefer to avoid drawing attention to their activities."},{"type":"card","domain":"General","sub":"General","q":"What two areas are common sites of fractures (old or acute) in dog fighting dogs?","a":"Leg bones and jaw"},{"type":"card","domain":"General","sub":"General","q":"T/F Complete bloodwork should be performed on all adult animals (6 months and older) regardless of health status","a":"T. Also all sick/thin animals of any age."},{"type":"card","domain":"General","sub":"General","q":"Which of hte following tests are not recommended for all dogs confiscated from a dog fighting case? CBC, chem, thyroid hormone, hw antigen, ua, fecal parasite screen, Giardia SNAP, parvo SNAP, Babesia testing","a":"ALL of the above are indicated."},{"type":"card","domain":"General","sub":"General","q":"T/F: Gamecocks will have their comb, wattles and natural spurs removed","a":"T."},{"type":"card","domain":"General","sub":"General","q":"Wounds in surviving fighting roosters are most common in what body sites?","a":"Head and eyes. Punctures to lungs, or broken legs or wings are also common."},{"type":"card","domain":"General","sub":"General","q":"List up to 3 reportable diseases that fighting cocks have been implicated in the spread of.","a":"AVian influenza, salmonella, exotic Newcastle disease"},{"type":"card","domain":"General","sub":"General","q":"T/F: The aggressive nature of fighting birds and concerns about infectious dz transmission preclude rehoming or sanctuary placement following case resolution","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F The commercial nature of many horse owning situations precludes the application of felony animal cruelty charges in most states","a":"T. Most anticruelty laws apply broadly to companion animals (which could include a backyard horse) but no to horses being bred, trained or shown for commercial purposes"},{"type":"card","domain":"General","sub":"General","q":"T/F The presence of snow or ice without access to clean unfrozen water is not acceptable substitute for drinking water","a":"T"},{"type":"card","domain":"General","sub":"General","q":"In the 5 point body scoring system used for horses, what score indicates an ideal weight? What scores indicate emaciation?","a":"Ideal = 5; Underweight = 3, Emaciation =2, extreme emaciation = 1"},{"type":"card","domain":"General","sub":"General","q":"Horses who exhibit minimal interactions with others and often stood in the back of their stalls with heads lowered are indications of what?","a":"Close attention to individuals’\nresponses to their surroundings, to other animals\nand people, as well as to where they may choose\nto rest can give clues to the degree of comfort or\npain they are experiencing. In the study mentioned\nabove, horses in pain exhibited minimal interactions\nwith others and often stood in the back of their stalls\nwith heads lowered. In some cases, an elevated\nheart rate in an otherwise quiet or dull horse\nmay be the only clinical sign of pain or distress."},{"type":"card","domain":"General","sub":"General","q":"What are your primary rule outs for ataxia and/or severe weakness in equine cruelty cases?","a":"Otherthan malnutrition, need to rule out rabies and Eastern Equine Encephalitis and West Nile Virus"},{"type":"card","domain":"General","sub":"General","q":"T/F: In cases of equine cruelty involved starved horses, it important to assess for and treat dental problems promptly.","a":"F. Dental work, if necessary, should be delayed until\nthe horse has shown weight gain, as the sedation\nthat is often necessary for this procedure will lower\nblood pressure and affect the horse’s balance, coordination,\nand digestion"},{"type":"card","domain":"General","sub":"General","q":"T/F Refeeding protocols in are indicated in cases of equine starvation","a":"T. The introduction of grain should be done\nslowly, and the horse must bemonitored for development\nof laminitis or founder. Extremely emaciated\nhorses can develop intestinal bacterial overgrowth or\nsevere electrolyte disturbances if fed too much too\nquickly."},{"type":"card","domain":"General","sub":"General","q":"T/F: The introduction of a ginger paste into the anus or rectum\nin order to cause the tail to\nbe lifted is illegal in the show ring.","a":"T. introduction of a ginger paste into the anus or rectum\nthat produces heat and irritation, causing the tail to\nbe lifted. This practice is illegal in the show ring (horsey people. really.)"},{"type":"card","domain":"General","sub":"General","q":"T/F: Physical pain induces greater suffering in animals than emotional pain.","a":"F. There is evidence that emotional pain  may indiuce greater suffering than phyiscal pain. Studies have shown that emotional factors weigh more storngly in animals' behavioral choices than physical pain. E.g puppies chose to get electrical shocks rather than remain separated from a person to whome they had formed a social attachment"},{"type":"card","domain":"General","sub":"General","q":"What is the gold standard method for measuring QOL in animals and humans?","a":"Trick question! In humans measurement of QOL continues to be be  source of great controversy. To date there is no consensus  as to the best method for the assessment. Objective factors, no matter how accurately measured, cannot be regarded as a true representation of that individudal's QOL. Subjective criteria-considered the truest reflection of QOL- involve the way an animal FEELS ABOUT aspects of life and life overall."},{"type":"card","domain":"General","sub":"General","q":"_________, especially manifestations of abnormal behavior, can provide info about challenges the animal is facing and how successfully they are coping with those challenges.","a":"Behavioral changes, especially manifestations of abnormal behavior, can provide info about challenges the animal is facing and how successfully they are coping with those challenges."},{"type":"card","domain":"General","sub":"General","q":"Sleeping, eating, and exhibiting fearful behavior are just a few examples of normal behaviors tha become abnormal if _______________","a":"if performed too little or too much."},{"type":"card","domain":"General","sub":"General","q":"Chronic conflict, furstration, anxiety, or other stressors are often the cause of ________","a":"abnormal behavior patterns. Therefore their presence has been used as an indicator of compromized QOL."},{"type":"card","domain":"General","sub":"General","q":"What is an inherent problem in using measurement of stress to assess QOL?","a":"QOL involves the positive as well as negative aspects of life, thus making one's stress level only part of one's QOL. Measuring stress as a proxy for QOL overlooks positive/pleasureable experiences."},{"type":"card","domain":"General","sub":"General","q":"In Carlstead et al 1993, hiding behavior in lab cats was ______ (choose positively or negatively) correlated with hiding.","a":"In Carlstead et al 1993, hiding behavior in lab cats was negatively correlated with hiding.  In other words, more hiding, less cortisol. Therefore, hiding may be an important behavior for coping."},{"type":"card","domain":"General","sub":"General","q":"Dinnage 2006 reported that __________ may be a coping mechanism for cats in shelters. These cats may appear to be the most relax but may actually have the highest stress levels.","a":"Feigned sleep!"},{"type":"card","domain":"General","sub":"General","q":"Cats are more likely to show a(n) ______ (choose reduction or increase) in general activity when stressed","a":"Cats are more likely to show a reduction in general activity when stressed, with increased hiding and sleeping as the major signs of stress or anxiety."},{"type":"card","domain":"General","sub":"General","q":"Altered routines, interactions with unfamiliar people and animals, and separation from familiar surroundings are all ________","a":"sources of stress for cats in shelters."},{"type":"card","domain":"General","sub":"General","q":"Displacement activities, looking back at the owner, elimintation, lip licking, body shaking and yawning are _______","a":"The most frequently observed signs of stress in dogs in routine training sessions (Bellaio et al 2009)"},{"type":"card","domain":"General","sub":"General","q":"T/F: Elevated cortisol levels appear to be a strong indication of chronic stress and poor welfare in dogs","a":"T. Beerda et al 2006. Elevated cortisol levels appear to be a strong indication of chronic stress and poor welfare in dogs. However, normal levels do not exclude these adverse states, in chronic stress behavioral changes are also not consistently present, High levels of stress, as measured by cortisol levels, are not necessarily concomittant with pronounced behavioral expressions of stress."},{"type":"card","domain":"General","sub":"General","q":"The risk identified most commonly with animal shelters is the risk of ________","a":"death by euthanasia"},{"type":"card","domain":"General","sub":"General","q":"Differences in per capita euthanasia across communities is largely reflected in differences in ______","a":"intake"},{"type":"card","domain":"General","sub":"General","q":"What is a critical flow -through point?","a":"Points in an animal's pathway from intake to outcome where they will need something to be able to continue forward on their pathway toward their optimal outcome."},{"type":"card","domain":"General","sub":"General","q":"Describe the principle of fast-track/Slow-track flow-through planning.","a":"Animals on an adoption pathway are assigned flow-through plans that reflect how quickly  they are quickly they are likely be adopted once available. Adoption driven capacity should be estimated separately for these two pathways! These two separate pathways permit a primary focus on quick turnaround time and infectious disease control for fast-track animals, are are generally younger and more susceptible to infectious disease, and a focus on welfare and enrichmetn for those in the slow track."},{"type":"card","domain":"General","sub":"General","q":"What beyond what LOS available for adoption should a fast-track animal be reassigned to a \"slow-track\" pathway?","a":"after 2-3 weeks."},{"type":"card","domain":"General","sub":"General","q":"T/F: With regard to estimating intakes/outcomes, projections for the future can be made by evaluating  past intake and outcome information along with current trends.","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Accord to Peter Marsh, which is a more important driver of euth in animal shelters: intake numbers or adoption numbers (per capita)?","a":"Intake numbers. In the communities studied in NH, Michigan, Ohio, Virginia and Utah there was NO correlation between adoption and euth rates, but high correlation between intake and euth rates."},{"type":"card","domain":"General","sub":"General","q":"In communities where per capita intake is declining, what are the likely characteristics of the smaller numbers of animals coming in to the shelter?","a":"The smaller number that do enter shelters may consit of a higher proportion of animals who are difficult or even unsafe to place."},{"type":"card","domain":"General","sub":"General","q":"How are daily population rounds different than medical rounds?","a":"Daily rounds are used to identify when care is needed, while medical rounds are used to deliver the care."},{"type":"card","domain":"General","sub":"General","q":"The _________ is based primarily on staffing, training, and resources.","a":"Capacity for providing care is based on staffing, training, and resources (NOT # housing units!)"},{"type":"card","domain":"General","sub":"General","q":"T/F: The number of animals held in the shelter at any single time will affect average LOS","a":"T. If 60 cats are consistently waiting for adoption, and ~30 cats are adopted per month, then the avg waiting time is ~60 days.  If fewer cats waiting for adoption at single time point, AVERAGE LOS will be shorter (and vice versa)"},{"type":"card","domain":"General","sub":"General","q":"What variables should be separated out when performing capacity calculations?","a":"At minimum by species, if possible by age. Other: breed, special conditions, or preferred outcome options (e.g. ferals vsfriendly cats)"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate holding capacity?","a":"Holding capacity is the physical space needed for animals in stray period, quarantine, or other finite holding periods prior to being made available for adoption. Intake # per day x holding period (days) = # housing units needed. Intake number per day is usually calculated using monthly daily average (# animals in per month/# days in that month). **If intake is highly variable/seasonal, calculate based on peak needs (otherwise you won't have enough cages in August!)."},{"type":"card","domain":"General","sub":"General","q":"In layperson's terms what is adoption driven capacity?","a":"The optimal number of animals to have available for adoption at any given time"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate adoption driven capacity?","a":"(determine your target avg LOS) x MDA adoptions = ADC"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended max avg total LOS? Recommended avg LOS on adoption floor?","a":"Max total avg LOS: 14 days (= holding and available time). If holding area not accessible to public, target avg LOS on adoption floor is 10 days (so animals get 2 weekends to be viewed for adoption)."},{"type":"card","domain":"General","sub":"General","q":"Assume target total AVG LOS is 14 d. \nAdult cat adoptions in this month: 61\nKitten adoptions this month: 82\nWhat is your total feline ADC?","a":"Cat MDA adoptions = 61/30.5 = 2 . 2 x 14 day LOS = 28 cats\nKitten MDA adoptions = 82/30.5 = 3 . 3 x 14 d LOS = 38 kittens\n28+ 38 = 66 total ADC"},{"type":"card","domain":"General","sub":"General","q":"Here are the total ADC for each month for an animal shelter. In general how many housing units for adult cats and cats + kittens (total) should they have on the adoption floor?\n             36  40 31  22 31  40  42  66  44  49  87  49 \n(adults: 25  32  26  21  28  33  23  28  28  29  42  32 )","a":"ADC varies across kitten season, but adult cat adoptions less variable, and should probably be no more than 40 cages. Peak total ADC was due to an adoption special, so then next overall total ADC is no more than 66 cats + kittens."},{"type":"card","domain":"General","sub":"General","q":"How do you calculate the number of staff hours required to provide daily care (or a specific task)?","a":"Hrs = (min per animal x avg daily populaiton)/60"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate staff capacity for daily care? What are the units of scdc?","a":"# animals that can be adequately intaked = minutes of daily staff time available for care/min required per animal per day"},{"type":"card","domain":"General","sub":"General","q":"What is RHC + ADC?","a":"The maximum total number of animals you should have in your population to avoid prolonged LOS, crowding, exceeding c4c"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate the staff capacity for flow-through?","a":"Need to determine amount of time given flow-through task requires. EG time to admit one animal.\n(minutes per intake/60) x MDA intake # = # hours required to perform all intakes each day (on average)"},{"type":"card","domain":"General","sub":"General","q":"T/F: If a 1:10 dilution of bleach is used (e.g to kill rw spores)  animals must be removed from the enclosure at this dilution is very caustic and may cause repiratory tract irritation in humans and animals","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Female dogs reach sexual maturity between _____ and ___ months of age, while male dogs generally reach sexual maturity around ___months of age.","a":"Female dogs reach sexual maturity between 6 and 16 months of age, while male dogs generally reach sexual maturity around 10 months of age. Some large breed dogs do not reach sexual maturity until they reach 2 years of age."},{"type":"card","domain":"General","sub":"General","q":"T/F: If a female dog mates with more than one male it is possible for the pups in a single litter to have different fathers.","a":"T."},{"type":"card","domain":"General","sub":"General","q":"Estrus (\"heat\")  refers only to the period when _________","a":"a female will allow the male to mount her for breeding.  It generally lasts 5-9 days. Dogs have 1-2 estrous cycles per year."},{"type":"card","domain":"General","sub":"General","q":"T/F: According to the ASV Guidelines, animals showing signs of behavioral stress should be treated as seriously as animals with physical injuries","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Persistent hiding, hostile interactions with other animals, reduced activity or appetite, depression and/or social withdrawal, barrier frustration or aggression, stereotypic behaviors are all indicators of _______","a":"stress/maladaption, social conflict, pain or other suffering in shelter dogs"},{"type":"card","domain":"General","sub":"General","q":"T/F: Every dog that is safe to handle should have an identification band affixed to their nectk from point of intake (or as soon as possible)","a":"T"},{"type":"card","domain":"General","sub":"General","q":"At what critical flow through points should all dogs be scanned for a microchip?","a":"Intake, prior to transport, adoption or euthanasia."},{"type":"card","domain":"General","sub":"General","q":"List normal physiolgic values for adult dogs vs puppies (5wk)\nTemp \nPulse (bpm) \nResp rate (bpm)","a":"Adult                Pup\nTemp                       99.5-102.5       98-100\nPulse (bpm)             60-180            150-220\nResp rate (bpm)       10-30             15-35"},{"type":"card","domain":"General","sub":"General","q":"T/F: When breed type is unknown it is best for shelter staff to make their best guess of dog’s breed in order to facilitate reuniting lost dogs with their owners.","a":"F. When breed type is unknown or uncertain, rather than guess, it is more helpful to designate dogs as mixed breeds and describe them as fully and accurately as possible. Voith et al2009 found 87.5% of dogs labeled as having particular breed types in a shelter did NOT have all of those breeds detected by DNA analysis (what a stupid way to frame your research question)."},{"type":"card","domain":"General","sub":"General","q":"Dogs have _____ (#) deciduous teeth and ____(#) permanent teeth","a":"Dogs have 28 deciduous teeth and 42 permanent teeth. Deciduous: 3 premolars, no molars. Perm: 4 premolars, 2 molars on top/3 molars on bottom."},{"type":"card","domain":"General","sub":"General","q":"A puppy with permanent incisors is at least what age?","a":"12 weeks (to 20 wks)"},{"type":"card","domain":"General","sub":"General","q":"A puppy wiht permanent canine teeth is at least what age?","a":"12 weeks (to 24 wks)"},{"type":"card","domain":"General","sub":"General","q":"A puppy with permanent premolars is at least what age?","a":"16 weeks (to 24 wks)- same as kittens"},{"type":"card","domain":"General","sub":"General","q":"A puppy with molars is at least what age?","a":"16 weeks (to 28 wks). Remember there are no deciduous molars!!"},{"type":"card","domain":"General","sub":"General","q":"A puppy with only deciduous incisors +/- canine teeth is at least what age?","a":"3 weeks (to 6 wks incisors, 5 wks canines)"},{"type":"card","domain":"General","sub":"General","q":"A puppy with deciduous premolars is at least what age?","a":"4 weeks (to 12 weeks)"},{"type":"card","domain":"General","sub":"General","q":"A kitten with permanent incisors is at least what age?","a":"11 weeks (to 16 weeks)"},{"type":"card","domain":"General","sub":"General","q":"A kitten wiht permanent canine teeth is at least what age?","a":"12 weeks (to 20 weeks)"},{"type":"card","domain":"General","sub":"General","q":"A kitten with permanent premolars is at least what age?","a":"16 weeks (to 24 wks)- same as dogs"},{"type":"card","domain":"General","sub":"General","q":"A kitten with molars is at least what age?","a":"16 weeks (to 24 wks). Remember there are no deciduous molars!!"},{"type":"card","domain":"General","sub":"General","q":"A kitten with only deciduous incisors is at least what age?","a":"2 weeks (to 4 wks)"},{"type":"card","domain":"General","sub":"General","q":"A kitten with deciduous canine teeth  +/- premolars is at least what age?","a":"3 weeks (to 4 weeks- canines, 6 weeks premolars)"},{"type":"card","domain":"General","sub":"General","q":"Nuclear sclerosis in dogs appears at about ______ years of age","a":"6-8 years of age."},{"type":"card","domain":"General","sub":"General","q":"List viable methods for estimating the age of a dog.","a":"Review wear pattern of the teeth (though this will vary by previous diet and dental care), graying of hairs on the muzzle, and nuclear sclerosis"},{"type":"card","domain":"General","sub":"General","q":"At what age would one expect a pup's testicles to have dropped into the scrotum?","a":"It can happen in the first 2 weeks of life, or by 2 months of age, though later descent at 4-6 months is possible."},{"type":"card","domain":"General","sub":"General","q":"At what gestational age will calcified bones of fetuses be evident on rads?","a":"After day 42."},{"type":"card","domain":"General","sub":"General","q":"What is the recommended schedule for deworming puppies for ascarids?","a":"At intake and q 2 weeks until the pup is 3 months old, then monthly until the pup is 6 mo old, thereafter as needed."},{"type":"card","domain":"General","sub":"General","q":"How much weight gain would you expect per day for puppies with an expected adult weight of 50lb?","a":"50 g/day (Expect 1-1.25 g per day per lb of expected adult body weight). 50 lb expected --> 50 x 1 = 50 g"},{"type":"card","domain":"General","sub":"General","q":"T/F: Bedding should only be provided to dogs in their primary enclosures in shelters where the risk of infectious disease  is low.","a":"F. Resting surfaces and bedding must be provided in the primary enclosures of dogs."},{"type":"card","domain":"General","sub":"General","q":"Symptoms of ____________ include weakness, seizures, coma, irritability, aggression, death,","a":"Refeeding syndrome in a severely malnourished animal"},{"type":"card","domain":"General","sub":"General","q":"Research indicates that  ________ can attenuate the adverse effects of unpleasant stimuli, eliminate fear responses, and alleviate  signs of pain in animals","a":"Research indicates that gentle human contact can attenuate the adverse effects of unpleasant stimuli, eliminate fear responses, and alleviate  signs of pain in animals (McMillan, 2002)"},{"type":"card","domain":"General","sub":"General","q":"List normal physiolgic values for adult cats vs kittens (>4wk)\nTemp \nPulse (bpm) \nResp rate (bpm)","a":"adult cats          kittens (<4wk)\nTemp                  100-102.5           96-99\nPulse (bpm)        120-220              150-220\nResp rate (bpm)     16-40              16-40"},{"type":"card","domain":"General","sub":"General","q":"List the seven simple rules for aging kittens and cats","a":"1. Kittens only: A lb a month (males tend to be slightly greater, females, slightly lower)\n2. Eyes open ~7-10 days\n3. Baby teeth erupt ~3 weeks of age. A kitten with a full set of baby teeth is ~4 weeks old\n4. Kittens who can walk and are playing well are at least 4 weeks old. \n5. A kitten with erupting perm incisors is ~4 months of age, a kitten with all perm incisors erupted is ~5months of age.\n6. Canine teeth erupt 5.5-6 months old. A kitten with fully erupted adult canine teeth is ~6months old. \n7. Size matters (BG wrote it, not making this up): male with adult canine teeth but small testicles is 9-12 months of age. Over 12-14 months tomcats have mature testicles."},{"type":"card","domain":"General","sub":"General","q":"How old is a kiten with all deciduous teeth who weighs ~3.5 lb?","a":"~3.5 mo  (<4months)"},{"type":"card","domain":"General","sub":"General","q":"How old is a kitten with all perm incisors but deciduous canine teeth?","a":"4-5 months old."},{"type":"card","domain":"General","sub":"General","q":"At what age do tomcats begin to develop jowls?","a":"18 months"},{"type":"card","domain":"General","sub":"General","q":"What PE findings would suggest a cat is >10 years of age?","a":"- Nuclear sclerosis (less common than dogs)\n- iris atrophy (mottling/moth eaten appearance of colored part of the eye)\n- loss of fat around the eyes and the top of the head may result in lean, angular \"old cat\" facial appearance\n- dorsal muscle wasting may be present as age increases"},{"type":"card","domain":"General","sub":"General","q":"What dose of pyrantel is recommended for cats at intake for empiric deworming?","a":"10 mg.kg"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended dose of ivermectin 1% solution (SQ or PO) for treatment of ear mites?","a":"0.3 mg/kg. Repeat in 2 weeks. Extra label use. Also effective against cheyletiella, notoderes, sarcoptes, cuterebra, roundworms, hookworms, an lungworms."},{"type":"card","domain":"General","sub":"General","q":"What ecto parasites is fipronil active against?","a":"ear mites, cheyletiella, chewing lice, ticks"},{"type":"card","domain":"General","sub":"General","q":"What is the testing protocol for FeLV/FIV recommended by AAFP for shelter cats?","a":"Test all cats on entry to shelter and again 60 days later."},{"type":"card","domain":"General","sub":"General","q":"Summarize the ASV's position statement on the Mgmt of Cats that Test positive for FeLV and/or FIV in an animal shelter:","a":"Confirmatory testing per published guidelines is recommended. However, holding cats for confirmatory testing may present a risk to individual and/or population health and welfare, and/or may be cost prohibitive. Shelters whose policy it is to euthanize based on the results of a single positive test should understand that a percentage of cats will test falsely positive."},{"type":"card","domain":"General","sub":"General","q":"How does prevalence of cats compare to dogs in a given geographical area (based on necropsy surveys of shelter cats)?","a":"Cats prevalence of infx is 5 to 15% that of dogs in given area"},{"type":"card","domain":"General","sub":"General","q":"Is routine screening of shelter cats for HW infection recommended?","a":"BG does not recommend routine screening of cats for hw dz in shelters. Monthly chemoprophylaxis however is a safe and effective option in areas where HW infection is considered endemic"},{"type":"card","domain":"General","sub":"General","q":"What is a recommended strategy to try to avoid cats developing food aversion while sick?","a":"When cats refuse to eat on their own, it may be best to offer them food periodically but do not leave it in the cage all of the time."},{"type":"card","domain":"General","sub":"General","q":"T/F: It is not recommended that shelters work on weight reduction for obese cats.","a":"T. It often takes several months for cats to achieve meaningful weightloss, and rapid weight loss in obese cats may put them at risk for hepatic lipidosis. Weight reduction may be best left for the new owner who should be educated about the risks associated with obesity in cats."},{"type":"card","domain":"General","sub":"General","q":"RER should be multiplied by what factor in starved cats to develop a refeeding plan? What rate x RERshould they initially be fed at?","a":"DER for weight gain is: 30 x desired wt in kg + 70 = RER+ kcal/day. RER x 1.3 = DER for weight gain. \nStart by feeding 50-100% of *PRESENT WEIGHT RER* devided into 4 meals per day. Increase by 25% each day to reach DER for weight gain. If doing well after 48 hours ok to increase food more rapidly."},{"type":"card","domain":"General","sub":"General","q":"Queens can bear ____ (#) kittens over their lifetime if allowed to breed naturally.","a":"Queens can bear 50-150  kittens over their lifetime if allowed to breed naturally"},{"type":"card","domain":"General","sub":"General","q":"How often (on avg) do queens come into heat (display estrus) behavior during the breeding season? How long does an estrus period last?","a":"Every 2 weeks until they become pregnant, are spayed, or the season ends in the fall.  Sexual receptivity lasts 4-7 days on average."},{"type":"card","domain":"General","sub":"General","q":"At what age will female cats usually reach puberty or experience their first estrus cycle? When do tomcats  reach puberty?","a":"Between 5-9 months of age is typical (possible 3.5-18 months). Because of its association with daylength, kittens frequently reach puberty at similar times despite age differences.  Tomcats typically attain sexual maturity between 8 and 13 months of age."},{"type":"card","domain":"General","sub":"General","q":"How long is the average feline pregnancy?","a":"65 days (or 9 weeks)- divided into 3 trimesters."},{"type":"card","domain":"General","sub":"General","q":"When a cat begins to appear obviously pregnant (distended abdomen with pink, erect nipples) she is usually less than ____ (time period) out from giving birth","a":"When a cat begins to appear obviously pregnant (distended abdomen with pink, erect nipples) she is usually less than 2 weeks out from giving birth"},{"type":"card","domain":"General","sub":"General","q":"You palpate the abdomen of a female cat and feel 5 ~1cm small spherical dilations. How far along is this pregnancy?","a":"14-17 days. By days 21-25 the vesicles are usually >= 2 cm in diameter. After days 30-35 fetal dilations become more oblong in shape and become more confluent (making palpation more difficult). After day 45 fetal heads and bodies with feal movement can be detected."},{"type":"card","domain":"General","sub":"General","q":"What is the only pregnancy specific hormone presently recognized as a confirmatory test for pregancy?","a":"Blood test for relaxin. Typically eleveated after d 25 of pregnancy."},{"type":"card","domain":"General","sub":"General","q":"What is the preferred method for raising orphan kittens? Bottle feeding by a human caretaker or fostering onto a willing feline foster mom?","a":"Fostering onto a willing feline foster mom."},{"type":"card","domain":"General","sub":"General","q":"What is the normal birth weight of a healthy kitten, and how much weight should they gain per day?","a":"Normal healthy birth weight is ~100 g and they should gain 10-15 g/day"},{"type":"card","domain":"General","sub":"General","q":"What is the time window after birth that kittens can still absorb colostrum?","a":"up to 12 hours after birth."},{"type":"card","domain":"General","sub":"General","q":"What are management options for kittens who were unable to nurse within 12 hours after birth (and absorb colostrum)?","a":"a) isolate and vaccinate with a killed vaccine at 2-4 weeks of age or\nb) administer 15 ml total (divided up over 24 hours) SQ or IP serum from a retrovirus negative, well-immunized adult cat"},{"type":"card","domain":"General","sub":"General","q":"Listthe two most important differentials for fading kittens","a":"Rule out FPV, and then assume bacterial septicemia unless other cause is apparent Necropsy can be useful but is often unrewarding in cases of fading kittens."},{"type":"card","domain":"General","sub":"General","q":"What interventions are recommended for a litter of kittens in which one or more appear to be fading?","a":"Tube feeding to ensure adequate hydration and nutrition, and warm SQ fluids to provide heat support. If FPV negative, assume bacterial septicemia, and start broad spectrum abx by SQ route (such as enrofloxacin)."},{"type":"card","domain":"General","sub":"General","q":"What is the minimum elevation recommended for cat housing units (ie how far off the floor should the lowest cages be)?","a":"At least 18 inches."},{"type":"card","domain":"General","sub":"General","q":"What is the minimum recommended sq footage of floor space for a singly housed cat?","a":"11 sq ft. In trad stainless cages this would be a cage 30 inches deep x 4 ft"},{"type":"card","domain":"General","sub":"General","q":"What is the maximum recommended group size for group housed cats? In addition to max numbers, what is the min space (sq ft) rec per cat?","a":"BG recommends no more than 3-4 individuals individuals. In a minimum enclosure size of 10-12ft x 16-18ft up to 8 adult cats (or a few more if juveniles) is acceptable. Min sq ft per group housed cat is 18 sq ft. However quality of the colony room also matters."},{"type":"card","domain":"General","sub":"General","q":"What is the recommended ratio of object to cats in a group housing room?\n--- litterbox:\n--- food and water bowls:\n--- resting boards, hiding spots, and perches:","a":"What is the recommended ratio of object to cats in a group housing room?\n--- litterbox: 1 per 2-3 cats\n--- food and water bowls: 1 set per 2-3 cats\n--- resting boards, hiding spots, and perches: more than the number of cats present"},{"type":"card","domain":"General","sub":"General","q":"Signs of permethrin toxicity in cats include:","a":"Tremors, seizures, and even death"},{"type":"card","domain":"General","sub":"General","q":"What common disinfectants pose a toxicity risk to cats in particular?","a":"Quats, phenolos, pine oils. Quats can be used in cat housing areas as long as they are used according to mftctrs instructions and surfaces are dry before cats are present."},{"type":"card","domain":"General","sub":"General","q":"A shelter cats presents for profuse salivation and agitation. She is wearing a flea collar labeled as safe for use in cats. What is your working diagnosis?","a":"The cat is demonstrating a \"taste reaction\" (a dramatic but harmless response to a bad taste from licking the collar)."},{"type":"card","domain":"General","sub":"General","q":"T/F: It is common for ferrets to lose up to 40% of their body weight in the summer","a":"T. They regain it in the winter. They will also molt in the summer, with shorter hair in summer and heavier coat in winter."},{"type":"card","domain":"General","sub":"General","q":"Choose: well-developed anal glands or sebaceous secretions. The musky odor of ferrets is largely due to _______","a":"Ferret stink is mostly sebaceous secretions."},{"type":"card","domain":"General","sub":"General","q":"What is the best way to estimate ferrets' age after they reach maturity?","a":"Teeth- dental calculi, broken or chipped canines, or evidence of common geriatric diseases"},{"type":"card","domain":"General","sub":"General","q":"What is the expected life span of the following species?\nFerrets, rabbites, g pigs","a":"Ferrets: 5-11 yrs\nRabbits: 6-12 yrs\nG pigs: 5-6 yrs"},{"type":"card","domain":"General","sub":"General","q":"T/F: Fractured canine teeth are common in ferrets but rarely cause problems","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Why is palpation of cervical, axillary, popliteal and inguinal LNs important in a ferret PE","a":"Ferrets commonly develop lymphoma as they age."},{"type":"card","domain":"General","sub":"General","q":"T/F: Healthy ferrets normally have a pronounced sinus arrhythmia","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Generalized alopecia in ferrets is a sign of _______","a":"adrenal disease. An enlarged vulva in a spayed female is also a sign of adrenal dz."},{"type":"card","domain":"General","sub":"General","q":"What is the best vein to use when a larger blood sample is needed (eg CBC/Chem)","a":"Caudal vena cava (under sedation)"},{"type":"card","domain":"General","sub":"General","q":"a) What vaccinations are recommended for ferrets? b) fill in the blank: vaccine reactions are ________ (choose common or uncommon)","a":"a) CDV and rabies **MOST CDV vax labeled for dogs will induce disease in ferrets!! Give 3 ferret labeled vax (Purevax, Merial) q 3-4 weeks (adults twice total initially, annually thereafter). There is one RV labeled for use in ferrets (IMRAB, Merial)\nb) common. Moore et al 2005: 0.5-1% of all vaccinations result in anaphylactic reaction)"},{"type":"card","domain":"General","sub":"General","q":"Which of the following medications are recommended for prophylactic use in ferrets?\nHW preventative\nDeworming\nEctoparasite medication","a":"HW preventative (in endemic areas)- feline dose\nEctoparasite meds (fleas, lice, ear mites are not uncommon)--> choose a product safe for cats (no labeled products)\nProphylactic deworming is NOT recommended- endoparasites are relatively rare"},{"type":"card","domain":"General","sub":"General","q":"Describe the signs of an anaphylactic vaccine reaction in a ferret","a":"--Will occur within 25 min of vaccination; most common signs GI (vom/diarrhea, nausea (pawing at mouth, drooling), tachycardia, erythema, hypotension, collapse. Ferrets should routinely be observed for 30-60 min following vaccination. If they have had a reaction they are likely to have one again. Mild signs tx = diphenhydramine 2-4 mg/kg IM or IV). Severe rxn tx = oxygen, epinephrine, dexamethasone."},{"type":"card","domain":"General","sub":"General","q":"T/F: Ferrets are susceptible to strains of human influenza virus and ferrets can pass dz to other ferrets or humans.","a":"T. Signs = mucoid or serous nasal and ocular discharge, sneezing, coughing, lethargy, transient pyrexia. Tx = supportive care. Usually self limiting, low mortality except neonates."},{"type":"card","domain":"General","sub":"General","q":"What is the etiologic agent of epizootic catarrhal disease, and what is the  common/descriptive name of the dz? In what situations is it a risk?","a":"Coronavirus, dz aka \"green slime dz.\" Occurs in older ferrets introduced to younger ferrets. Aggressive supportive care, abx are crucial to limiting mortality."},{"type":"card","domain":"General","sub":"General","q":"What are the 3 most common noninfectious, age-related disease conditions of ferrets?","a":"Lymphoma, adrenal dz, and insulinoma. 30% of ferrets over age 3 will develop one of these diseases. If they live long enough they are likely to develop 2 or all 3 of these diseases."},{"type":"card","domain":"General","sub":"General","q":"Which of the top 3 non infectious diseases is the primary differential for the following clinical signs, and what firstline diagnostic test(s) are recommended? Treatment/prognosis?  Chronic progressive lethargy, weakness, ataxia, pelvic limb paresis, pawing at the mouth (nausea).","a":"Insulinoma (aka beta cell tumors of the pancreatic islet cells). Signs can also be acute: collapse, coma, seizures. Test for blood glucose (<60 g/dL consistent w/ diagnosis). Tx: surgical removal of cancerous nodules on the pancreas,  or pred/other meds to prevent hypoglycemia. No comment on prognosis."},{"type":"card","domain":"General","sub":"General","q":"You find 2 blue dots in a ferret's right ear. What does this mean?","a":"It means they came from Marshall Farms and therefore have been spayed/neutered, descented, and given a cdv vax at 6 wks of age."},{"type":"card","domain":"General","sub":"General","q":"An unspayed female ferret enters the shelter. What factors determine whether or not you should spay her?","a":"It is very important to spay all female ferrets. THey are induced ovulators, and if not bred the jill WILL develop nonregenerative anemia due to hyperestrogenemia leading to bone marrow suppression."},{"type":"card","domain":"General","sub":"General","q":"At what age do testes descend in juvenile male rabbits?","a":"3 months."},{"type":"card","domain":"General","sub":"General","q":"What pathologic condition  in rabbits results from too much time spent on wire flooring?","a":"pododermatitis"},{"type":"card","domain":"General","sub":"General","q":"What conditions put rabbits at risk for poor personal hygiene?","a":"Overweight, arthritis, other (ok...)"},{"type":"card","domain":"General","sub":"General","q":"T/F: The ear vein is the preferred site for small volume blood collection or injections","a":"T for small volume blood draw, F for injections--> can cause thrombosis/pinnae necrosis"},{"type":"card","domain":"General","sub":"General","q":"What types of antibiotics should not be given to rabbits or g pigs? Which classess are ok?","a":"Do not use: beta lactams macrolides, lincosamides (clinda). OK: doxy, tms, fluoroquinolones."},{"type":"card","domain":"General","sub":"General","q":"What pathogen is most commonly associated with URI (snuffles) in rabbits?","a":"Pasteurella multocida."},{"type":"card","domain":"General","sub":"General","q":"What species of rw causes most clinical cases in rabbits and g pigs?","a":"Trichophyton mentagrophytes"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended treatment for Psoroptes cuniculi (rabbit ear mites) or Chyletiella?","a":"0.4 mg/kg ivermectin SQ q 10-14 days for 3 doses."},{"type":"card","domain":"General","sub":"General","q":"T/F: Encelphalitozoan cuniculi can be found in healthy, asumptomatic rabbits","a":"T But it can also cause dz of CNS --> head tilt, nystagmus, vestibular dysfunction, ataxia, paresis, uveitis, urinary incontinence, seizures."},{"type":"card","domain":"General","sub":"General","q":"What is the basis of a presumptive diagnosis of E. cuniculi?","a":"Positive antibody test in animal with consistent clinical signs (healthy animals can be Ab pos, but there is no other test for E. cuniculi)"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended treatment for E. cuniculi?","a":"albendazole (30mg/kg PO  SID x 30 days) or fenbendazole (20 mg/kg SID x 30 d) and anti inflammatories. Signs may not improve but progression of disease may be halted."},{"type":"card","domain":"General","sub":"General","q":"T/F: E cunicul is zoonotic","a":"T in immunocompromized (uncommon)"},{"type":"card","domain":"General","sub":"General","q":"Diarrhea, neuro signs, death are signs (in rabbits) of what zoontic disease of rabbits?","a":"Tularemia, \"rabbit fever\" (Francisella tularensis). Reportable in many states."},{"type":"card","domain":"General","sub":"General","q":"What are the most important rule out for a rabbit presenting with GI signs (anorexia, weight loss, diarrhea)?","a":"Dental dz,"},{"type":"card","domain":"General","sub":"General","q":"T/F The most common causes of GI disease in rabbits are caused by infectious agents","a":"F. most causes are noninfectious, and antibiotics can make the condition worse."},{"type":"card","domain":"General","sub":"General","q":"At what age is an intact male rabbit likely to show increased aggression and/or spraying due to sexual maturity?","a":"6 months"},{"type":"card","domain":"General","sub":"General","q":"T/F: Autoligation is recommended for rabbit testicular cords when neutering","a":"F. Do not try to tie the cord on itself, as it is very thick and it is likely the knot will slip off. Use ligatures instead. Closed castration is recommended to prevent inguinal herniation."},{"type":"card","domain":"General","sub":"General","q":"List two reasons why spaying of female rabbits is essential","a":"1) Does can be quite aggressive and territorial, more so than bucks. 2) 80% of dose over the age of 4 years will develop uterine adenocarcinoma."},{"type":"card","domain":"General","sub":"General","q":"T/F: G pigs, like rabbits, practice cecotrophy","a":"yup, they do"},{"type":"card","domain":"General","sub":"General","q":"After ______ (age) the pubic symphasis of g pigs fuses if they have not had any litters, and the risk of dystocia is greatly increased.","a":"7-8 months"},{"type":"card","domain":"General","sub":"General","q":"What is the most reliable way of estimating the age of a g pig after it matures?","a":"You cannot"},{"type":"card","domain":"General","sub":"General","q":"What is the appropriate ratio of males to females in a g pig harem?","a":"I'm not making this sh*t up. 1 male kept with up to 10 females. Great idea."},{"type":"card","domain":"General","sub":"General","q":"What important vitamin must g pigs obtain from their diet?","a":"Vitamin C (ascorbic acid)"},{"type":"card","domain":"General","sub":"General","q":"A g pig who is sick should always be considered to have a __________ prognosis","a":"A g pig who is sick should always be considered to have a guarded to grave prognosis. They do not handle stress or illness well."},{"type":"card","domain":"General","sub":"General","q":"The preferred site(s) for blood draw in g pig?","a":"Jug v or vena cava WHILE ANESTHETIZED!!"},{"type":"card","domain":"General","sub":"General","q":"What bacteria is an important cause of severe bronchopneumonia in g pigs? Which other animal species can be an asymptomatic carrier and therefore should not be housed with g pigs?","a":"Bordetella bronchiseptica. Rabbits can be carriers."},{"type":"card","domain":"General","sub":"General","q":"What is the most common ectoparasite of g pigs?","a":"Trixacarus caviae (sarcoptic mite). Severe pruritus, can be severe enough to cause seizures."},{"type":"card","domain":"General","sub":"General","q":"by 5 years of age, 76% of sows (female g pigs) will develop ______","a":"ovarian cysts. They are commonly asymptomatic but will continue to grow--> decr fertility, anorexia, abdominal distension lethargy. If functional--> bilateral symmetric truncal alopecia.  Rec tx is OHE or ovariectomy."},{"type":"card","domain":"General","sub":"General","q":"T/F: Neutering is recommended for male g pigs to prevent aggression or other territorial behaviors","a":"F. Intact males will make good pets. The main reason to neuter is to prevent reproduction or be able to house mult males together."},{"type":"card","domain":"General","sub":"General","q":"In general minimal cage size area should be at least ______________","a":"1.5 x the animal's total body length. For snakes the perimeter of the enclosure should be longer than the snake's length."},{"type":"card","domain":"General","sub":"General","q":"Which of the following is the preferred substrate for short-term housing of terrestrial reptile species? Which should NEVER be used? newspaper, pebbles, sand, aspen wood chips, pelleted corn cob, rabbit food pellets, cypress mulch, cat litter.","a":"newspaper. DO NOT USE: sand/pebbles, aroumatic wood chips (cedar, pine, redwood), corn cob pellets, cat litter"},{"type":"card","domain":"General","sub":"General","q":"T/F: It is important to provide reptiles with a hiding spot","a":"T"},{"type":"card","domain":"General","sub":"General","q":"What are the consequences of chronic hypothermia in reptiles?","a":"Immunosuppression, delayed digestion, lethargy"},{"type":"card","domain":"General","sub":"General","q":"Choose ambient air temp or secondary radiant heat: _______ is considered to be the primary and most important heat source for reptile enclosures.","a":"Ambient air temp is most important. Should be between 80-85 deg F."},{"type":"card","domain":"General","sub":"General","q":"Choose all that apply: herbivorous, omnivorous, carnivorous. The quality and intensity of light provided in a reptile enclosure is most important for ____________ reptiles species that utilize infrared light as their primary method for activating vitamin D precursors in the skin to synthesize metabolically active Vit D. Bonus points: what wavelength of light should be provided, and what are optimal sources??","a":"herbivorous and omnivorus. Bonus: 290-320 nm is wavelength desired. Best source is natural unfiltered sunlight, next up is a specially designed and labeled UVB lamp. Lamps should be replaced every 6-12 months."},{"type":"card","domain":"General","sub":"General","q":"Why should exclusive feeding of commercially raised crickets and mealworms be avoided in reptiles?","a":"- Insufficient variety, these for adequate nutrition, which can lead to metabolic bone disease. \n- these insects have tough chitin exoskeletons  which can lead to GI impactions"},{"type":"card","domain":"General","sub":"General","q":"Every reptile should be weighed at least ______ (frequency) to monitor; changes up or down of >10% should trigger evaluation by veterinarian.","a":"Weigh reptiles at least weekly"},{"type":"card","domain":"General","sub":"General","q":"What should be done prior to an examination just after a reptile or amphbian is brought into the shelter?","a":"They should be placed in a warm, stress free envrionment  If dehydrated place in warm water to soak. IF you don't do this, examination of stressed/debilitated animals may lead to rapidl decompsensation."},{"type":"card","domain":"General","sub":"General","q":"What signs might you see in a dehydrated reptile? If present, how can you treat it?","a":"dry tacky oral or cloacal mucous membranes, sunken eyes, abnormally dry feces or urates. Treament: soaking in warm water, parenteral fluids (SQ or intracoelomic). Daily fluid requrements are 10-30 ml/kg. Dehydation should be corrected over 3-4 days."},{"type":"card","domain":"General","sub":"General","q":"What are the most common empric choices for antibiotics in reptiles?","a":"Enrofloxacin (5 mg/kg PO  or IM q 1-2 days, amikacin (2.5-3mg/kg IM q 3 d), TMS, ceftazidime, ceftiofur, azithromycin. Avoid older references for doses of gentamicin--> renal fialure in reptiles/amphbians"},{"type":"card","domain":"General","sub":"General","q":"What are good choices for analgesics in reptiles?","a":"Highly species specific and limited evidence. Good evidence for morphine, buprenorphine, and bupivicaine/lidocain for local blocks. Not great evidence for torb, meloxicam."},{"type":"card","domain":"General","sub":"General","q":"According to CDC, 70,000 get _______ from contact with reptiles (mostly turtles)  in the US each year. Since 1975 it has been illegal to sell turtles with shells less than 4 inches in length because of this disease.","a":"salmonellosis"},{"type":"card","domain":"General","sub":"General","q":"What is the optimal way to restrain and examine a snake?","a":"If approached quietly and gently can be examined with minimal restraint. Snakes usually most comfortable when their heads are free and their bodies are well-supported. If acting aggressive (coiled defensive posture or attempting to strike) can grasp neck just caudal to skull after covering head with towel or newspaper."},{"type":"card","domain":"General","sub":"General","q":"T/F: The heart and lungs can usually be ausculted about 1/3 of the body length from the head.","a":"F. This is the approximate location of the heart and lunchs, and you may be able to palpate a pulse, but heart and lung sounds are rarely ausculted."},{"type":"card","domain":"General","sub":"General","q":"How do you asses body condtion in a snake or lizard?","a":"the musculature of the back and the prominence of the dorsal spinous processes. A normal snake should have a slightly rounded dorsal surface with the tips of the dorsal spinous processes just barely palpable. Very thin snakes can also be deeply palpated in the coelomic cavity due to lack of intracoelomic fat bodies.  Some lizard species store fat in the tail, so tail size/thickness can be an indicator of body condition."},{"type":"card","domain":"General","sub":"General","q":"What the preferred site for blood collection in a snake or lizard?","a":"Ventral (midline) tail vein- like a cow! Can use ventral approach in either, lateral ok in lizards"},{"type":"card","domain":"General","sub":"General","q":"Stomatitis, aka mouth rot, is a common condition in snakes. What are the underlying causes contributing to this condition?","a":"Poor husbandry- dirty particulate substrate, chronic hypothermia with resulting immunosuppression"},{"type":"card","domain":"General","sub":"General","q":"Inclusion Body Disease (IBD): what is the cause? What species typically affected? Clinical signs?  Diagnostic tests?","a":"Exact etiology unknown, thought to be viral. Boa and python species typically affected. C/S = generalized neuro signs or chronic regurgitation, often unaffected. Leads to chronic immunosuppression  with secondary bacterial stomatitis and pneumonia.  No specific test, but blood smears can be reviewed for characteristic eosinophilic intracytoplasmic inclusion bodies."},{"type":"card","domain":"General","sub":"General","q":"What is the cause of blister disease (vesicular dermatitis) in snakes?","a":"Chronically damp enclosures."},{"type":"card","domain":"General","sub":"General","q":"How do you control Ophionyssus natricis mites?","a":"Soak affected snakes in a lukewarm bath for 30 min or rub olive oil on their skin. Also need to clean enclosure using multiplie applications of 1:32 bleach on all enclosure surfaces."},{"type":"card","domain":"General","sub":"General","q":"Which lizard species are going to bite you?","a":"Iguanas and monitors."},{"type":"card","domain":"General","sub":"General","q":"In species where it's relevant (iguanas, beardies) do males or females have large femoral pores?","a":"Males"},{"type":"card","domain":"General","sub":"General","q":"What are the causes of metabolic bone disease in lizards, aquatic turtles, and crocodilians?","a":"inappropriate diets (lacking calcium) coupled with inadequate exposure to sunlight/UVB light. In carnivorous spp, relative excess of phosphorus in all-meat diet is the problem.  dz --> nutritional hyperparathyroidism, abnomal calcification of bones, and pathologic bone fractures as body attempts to maintain blood iodized calcium levels. Final stages--> muscles twitch from lack of ionized calcium"},{"type":"card","domain":"General","sub":"General","q":"Which types of lizards are at risk for renomegaly, chronic renal failure, and secondary gout?","a":"Old herbivorous lizards (green iguanas). Cause unknown, thought to be chronic dehydration and excess dietary protein (iguanas are true vegetarians)"},{"type":"card","domain":"General","sub":"General","q":"A lizard presents to a shelter with a large white non swollen lesion on its abdomen. What is the likely cause?","a":"This is probably a healed burn wound."},{"type":"card","domain":"General","sub":"General","q":"A lizard presents to a shelter thin, anorectic, weak, and has a noticeably swollen abdomen. What is the top differential, and what should you do about it?","a":"Gravid female lizards who cannot find a suitable nesting area in their enclosure often developed retained eggs or follicles, whcih leads to eventual metabolic crisis. These lizards often have secondary hypocalcemia. Goodness knows what you should about it, the book doesn't say."},{"type":"card","domain":"General","sub":"General","q":"What is the optimal way to restrain a turtle species?","a":"Hold them in the air or place on an object that supports them but does not allow their feet to touch the ground. Healthy turtles are alert and uncooperative for examination."},{"type":"card","domain":"General","sub":"General","q":"How do you assess body condition in a turtle?","a":"You basically cannot, except that \"cachectic turtles feel like an empty shell when lifted off the ground.\""},{"type":"card","domain":"General","sub":"General","q":"A turtle presents to a shelter. It has a flat plastron, all of its toenails are the same length, and its tails seems short. Is this likely a male or female?","a":"Female. Males have concave plastron, very long nails on front toes, and relatively longer tails."},{"type":"card","domain":"General","sub":"General","q":"Best site for blood collection in a turtle?","a":"Jug vein"},{"type":"card","domain":"General","sub":"General","q":"A dietary deficiency of __________ in semi/aquatic turtles fed poor diets ( ground muscle meat) results in sqamous metaplasia and hyperkeratosis of the epithelium. Classic sites of swollen, inflammed tissue are periocular glands, oral mucosa (GI tract, respiratory tract, kidneys).  How do you correct it?","a":"Vitamin A deficiency. Administer parenteral vitamin A and add food liks dried apricots, cantalope, carrots, hot chilli peppers, collards, grapefruit, blah blah blah to the diet"},{"type":"card","domain":"General","sub":"General","q":"A turtle presents to a shelter with a large swellings on its lateral head. What the heck? What should you do about it?","a":"This are probably aural abscesses, cause is not fully understood. Drain them (cheesy reptile pus, yum)"},{"type":"card","domain":"General","sub":"General","q":"A turtle presents to a shelter with a messed up shell. List 3 differentials.","a":"1) Grossly deformed shell--> metabolic bone disease\n2) Crappy shell, with edges of the scutes separating--> 'septicemic cutaneous ulcerative disease\" (SCUD)  caused by being kept in cold dirty water\n3) Trauma leading to shell fracture"},{"type":"card","domain":"General","sub":"General","q":"T/F: Mini pet crocodilians are sweet and cuddly","a":"F. Healthy crocodilians of any size are aggressive and should always  be considered dangerous. Yes, someday I will be one of the people writing test questions for ABVP, you're welcome."},{"type":"card","domain":"General","sub":"General","q":"How do sex a crocodilian?","a":"Insert a gloved finger into the cloacal opening and feeling for a penis. Uhh, no thanks."},{"type":"card","domain":"General","sub":"General","q":"T/F: Animals with no detectible blood circulation or heart beat, including those undergoing complete decapitation, may continue to have viable brain function.","a":"T (reptiles and amphibians)."},{"type":"card","domain":"General","sub":"General","q":"List 3 unacceptable euthanasia practices for reptiles/amphibians. List the primary preferred method for performing human euth in these species, and how do you confirm death?","a":"Freezing, refrigeration, decapitation. Preferred: anesthetize then administer sodium pentobarb IV, IC, or intracoelomically. Confirm death by determining heart has stopped via doppler, ultrasound, or ecg. OR leave the presumed dead animal alone for 2 hours. Should still be dead upon recheck."},{"type":"card","domain":"General","sub":"General","q":"T/F: In shelters that do not feel prepared to provide the care needed to reptiles/amphibians, these species should be promptly euthanized.","a":"F. There are many resources available in most communities for proper placement, and euth should only be performed on those animals deemed to be suffering from severe diseases or injuries."},{"type":"card","domain":"General","sub":"General","q":"Which of the following pathogens has high infectivity: FPV vs FeLV?","a":"FPV has high infetivity- it enters, survives, and multiplies in animals and is easily transmitted to other hosts."},{"type":"card","domain":"General","sub":"General","q":"Which of the following pathogens has high immunogenicity: CDV vs Bordetella?","a":"CDV. Agents with high immunogenicity are highly effective at evoking an immune response."},{"type":"card","domain":"General","sub":"General","q":"Which of the following agents has high pathogenicity in adult cats: rabies vs FPV?","a":"Rabies. Pathogenicity is an agent's ability to cause clinical dz in infected animals. In adult cats FPV infection does not always cause clinical signs, whereas any non immune cat infected with rabies is going to die."},{"type":"card","domain":"General","sub":"General","q":"Which of the following agents has high virulence? Rabies vs M. canis","a":"Rabies. Virulence is the severity of dz that an agent produces (I think this is a poor example contrasting rabies to ringworm...)"},{"type":"card","domain":"General","sub":"General","q":"According to Jan Scarlett, what is the definition of a disease epidemic or outbreak?","a":"An epidemic exists when the frequency or incidence of disease is clearly in excess of its expected frequency based on previous experience in the population"},{"type":"card","domain":"General","sub":"General","q":"Choose: active, passive, or sentinel surveillance systems. __________ involves daily disease case identification which requires staff training and accountability","a":"active surveillance systems involves daily disease case identification which requires staff training and accountability. This is what is most common in animal shelters"},{"type":"card","domain":"General","sub":"General","q":"Choose: active, passive, or sentinel surveillance systems. __________ involves on a dvm or a lab to report of disease to the appropriate authorities","a":"Passive surveillance involves on a dvm or a lab to report of disease to the appropriate authorities"},{"type":"card","domain":"General","sub":"General","q":"Choose: active, passive, or sentinel surveillance systems. __________ involves a key source (such as an animal shelter) agreeing to monitor for and report confirmed or suspected cases of a particular disease to an interested organization.","a":"Sentinel surveillance"},{"type":"card","domain":"General","sub":"General","q":"______ is a RNA virus that affects all members of the CAnidae family as well as raccoons, ferrets, several large wildcats, and some sea mammals","a":"CDV"},{"type":"card","domain":"General","sub":"General","q":"How is CDV most commonly spread?","a":"It is shed in body secretions but is most commonly spread by aerosol or droplet exposure."},{"type":"card","domain":"General","sub":"General","q":"How long does CDV typically shed post infection?","a":"Typically 2 weeks, but up to 90 days."},{"type":"card","domain":"General","sub":"General","q":"Under what conditions can CDV persist in the environment?","a":"It is able to withstand cooler temps, remaining viable at temps below freezing. Does not survive long in warm or dry environments"},{"type":"card","domain":"General","sub":"General","q":"What cells of the GIT are commonly infected by parvoviruses, leading to associated GI clinical signs?","a":"Intestinal crypt cells"},{"type":"card","domain":"General","sub":"General","q":"In CPV infections, shedding typically lasts ____ (#) days post infection","a":"Shedding is usually not detected 10-12 days post infection."},{"type":"card","domain":"General","sub":"General","q":"T/F: There is published evidence supporting the use of Tamiflu (oseltamivir) for treatment of canine parvovirus infections","a":"F. Savigny and Macintire 2010 did not show clear benefit of Tamiflu"},{"type":"card","domain":"General","sub":"General","q":"T/F: Current CPV vaccines contain either CPV-2 or CPV-2b provide reliable cross protection again CPV 2a, 2b, and 2c","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Which disinfectants have proven efficacy against parvoviruses?","a":"bleach (1:32), potassium peroxymonosulfate, AHP"},{"type":"card","domain":"General","sub":"General","q":"After being housed in an animal shelter, up to 60% of cats will test positive for this virus in feces","a":"Feline enteric coronavirus."},{"type":"card","domain":"General","sub":"General","q":"What are the typical signs associated with FeCV?","a":"Often subclinically infected, but may develop mild, self-limited, small-bowel diarrhea, and/or vomiting"},{"type":"card","domain":"General","sub":"General","q":"Describe the characteristics of the fluid that accumulates in the wet form of FIP in the abdomen or pleural space of affected cats?","a":"Characteristic straw color and has low cell counts but high protein concentrations"},{"type":"card","domain":"General","sub":"General","q":"T/F In Gingerich et al 2010, the presence of diarrhea correlated well to RT-PCR results for FeCV","a":"T. However, it does have a correlation in other studies in the world."},{"type":"card","domain":"General","sub":"General","q":"When using PCR testing in a cat suspected of having FIP, the test is more likely to be a false (choose: positive or negative)","a":"False positive"},{"type":"card","domain":"General","sub":"General","q":"In a cat with FIP, the ratio of albumin to globulins would be expected to be (high, low, equal)","a":"low. A ration of 0.5 had a positive predictive value of 89%, while a ration of 1.0 had a negative predictive value of 91%"},{"type":"card","domain":"General","sub":"General","q":"T/F Coronvirus is highly resistant to inactivation in the environment","a":"F"},{"type":"card","domain":"General","sub":"General","q":"Salmonellosis is one of the primary differential diagnoses for what more common feline pathogen?","a":"FPV"},{"type":"card","domain":"General","sub":"General","q":"______ are gram negative curved (\"seagull shaped\") bacteria that infect multiple species, including dogs, cats, humans","a":"Campylobacter"},{"type":"card","domain":"General","sub":"General","q":"T/F: The majority of animals who culture positive for Campylobacter are clinically normal","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Administration of abx (tylosin or erythromycin) is indicated for all cases of suspect campylobacereosis","a":"F. Usually self-limiting. IF animal otherwise healthy/mild clinical signs no abx"},{"type":"card","domain":"General","sub":"General","q":"What are the two most commonly isolated species of clostridium from dogs and cats?","a":"C difficile and C perfringens. Anaerobic, gm pos, spore forming rod shaped bacteria. They can be isolated from perfectly healthy dogs and cats. C perf are normal flora that can overgrow in dz states and cause secondary GI disease. C diff typically transmitted from humans to dogs."},{"type":"card","domain":"General","sub":"General","q":"T/F: You find classif safety pin type spores on a fecal smear of a dog with watery to hemorrhagic diarrhea. You have found the cause of the diarrhea!","a":"Maybe, but not necessarily, as Clostridium perf spores can be found in healthy and dogs with diarrhea. However, Gingrich et al 2010 found that RT PCR results for Clostrid enterotoxin were statistically correlated with presence of diarrhea in shelter cats."},{"type":"card","domain":"General","sub":"General","q":"List up to 3 first line antibiotic choices for presumptive clostridial diarrhea","a":"amoxi, metro, tylosin. High fiber diet and probiotics may also be beneficial to prevent."},{"type":"card","domain":"General","sub":"General","q":"____ are nonspore-forming, gram neg, zoonotic bacteria with a broad host range","a":"Salmonella. In otherwise healthy animals  the dz is often self-limiting, but in young or stressed animals infx can lead to septicemia and death"},{"type":"card","domain":"General","sub":"General","q":"T/F: In cats with salmonellosis, approximately 50% have fever without clinical signs","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Which animals should be cultured for Salmonella?","a":"Animals who are not responding to empirical therapy for diarrhea, or those with systemic signs of bacteremia or sepsis."},{"type":"card","domain":"General","sub":"General","q":"T/F: Fecal or blood PCR is the preferred test for confirmation of Salmonella infections","a":"F. Culture of feces or blood. PCR can be done but then you don't get c/s results, and tehre is evdience that PCR results don't correlate well with presence of diarrhea"},{"type":"card","domain":"General","sub":"General","q":"T/F: A smal percentage of treated animals wil become low-level carriers of Salmonella even once clinical signs resolve","a":"F. Most animals become carriers. However, animals with normal feces are not generally health risks for humans."},{"type":"card","domain":"General","sub":"General","q":"What are good empiric abx choices for treating animals with Salmonellosis?","a":"Most small animal isolates are susceptible to penicillins or quinolones.  (Commentary: I thought treatment w/ abx was super controversial due to risk of causing abx resistance and the fact that you usually don't actually clear the infection completely. But that's what the book says)."},{"type":"card","domain":"General","sub":"General","q":"T/F: Most human infections of cryptosporidium are from C. hominus which is not common in dogs or cats.","a":"T. Cats usually infected with c felis, dogs c. canis (shocking), and these species rarely cause disease in immune competent humans."},{"type":"card","domain":"General","sub":"General","q":"How soon after defecation are crypto oocysts infectious?","a":"Immediately (they are shed already sporulated)."},{"type":"card","domain":"General","sub":"General","q":"What co infections are commonly associated with crypto infx in cats/dogs?","a":"Dogs: giardia cats: Tritrich foetus"},{"type":"card","domain":"General","sub":"General","q":"What is the most common clinical sign associated with crypto infx in cats and dogs?","a":"Most infected animals show no clinical signs. IF signs present small bowel diarrhea most common, esp in young, immunosuppressed, or coinfected animals"},{"type":"card","domain":"General","sub":"General","q":"What is the single most reliable compound for treating cryptosporidosis?","a":"Nothing has been proven to consistently eliminate infection. diarrhea can resolve spontaneously. Tylosisn, azithro, ponazuril used most frequently. nitazoxanide labeld for humans, sometimes used in cats/dogs"},{"type":"card","domain":"General","sub":"General","q":"What type of disinfection will reliably inactivate crypto oocysts?","a":"steam cleaning."},{"type":"card","domain":"General","sub":"General","q":"T/F: Most cats and dogs infected with Giardia are infected with host adapted assemblages, and therefore are of minimal public health risk","a":"T. Host adapted assemblages are C, D, F. Minimal public health risk if no diarrhea and the owners are immunocompetent."},{"type":"card","domain":"General","sub":"General","q":"How is a presumptive diaghosis of Giardiasis made in animals shelters?","a":"IF signs resolve following administration of an anti-giarrdia this indicates a presumptive diagnosis."},{"type":"card","domain":"General","sub":"General","q":"What are the drugs of choice for targeting Giardia?","a":"metro, fenbendazole, febantel. High fiber diet. Clip/bath infected animals to reduce enviro contamination. Primary goal of treatment is to resolve diarrhea, no to eradicate GIardia from the host."},{"type":"card","domain":"General","sub":"General","q":"Assign each of the following to their definitive host species (dog or cat): isospora canis, i. burrowsi, i. felis, i rivolta, i ohioensis, i neorivolta","a":"Dogs:  isospora canis,  i ohioensis, i neorivolta, i burrowsi\nCats: i. felis, i rivolta"},{"type":"card","domain":"General","sub":"General","q":"How long after defecation do isospora species sporulate?","a":"at least 12 hours to sporulate and become infectious"},{"type":"card","domain":"General","sub":"General","q":"how are coccidia infections transmitted?","a":"Contact with sporulated oocysts in feces (less common) or eating an infected intermediate host"},{"type":"card","domain":"General","sub":"General","q":"What is an approved drug for treatment of coccidiosis? What are up to 3 other off-label but other commonly used drugs?","a":"Approved: sulfaimethoxine (albon). Off label: TMS, ponasuril, totrazuril"},{"type":"card","domain":"General","sub":"General","q":"How long after defecation do Toxo oocysts sporulate and become infective?","a":"1-3 days. Once there they can survive for months."},{"type":"card","domain":"General","sub":"General","q":"T/F: Routes of infection with Toxo in cats are limited to ingestion of sporulated oocysts or ingestion of tissue cysts in intermediate hosts.","a":"F. Infx can also occur transplacentally and through lactation in cats"},{"type":"card","domain":"General","sub":"General","q":"Though most toxo infections of dogs and cats are subclinical, what body systems are most likely to be affected in clinical cases?","a":"Liver, CNS, respiratory system. GI disease is uncommon! Fever, uveitis, and muscle disease occur in some dogs and cats"},{"type":"card","domain":"General","sub":"General","q":"How is clinical toxo diagnosed?","a":"combination of serum ab testing and response to treatment."},{"type":"card","domain":"General","sub":"General","q":"Choose IgM or IgG. ____ Abs are are more indicative of a recent or active infection","a":"IgM more indicative of recent or active infection"},{"type":"card","domain":"General","sub":"General","q":"What is the rec treatment for clinical toxo cases?","a":"Supportive care and clindamycin (or potentiated sulfas or azithro)"},{"type":"card","domain":"General","sub":"General","q":"Which of the following is the worst choice for treating clinical toxo cases? Pyrimethamine, clindamycine, TMS, or azithro.","a":"Do not choose pyrimethamine- historically used but assocated with serious side effects"},{"type":"card","domain":"General","sub":"General","q":"T/F: If CNS signs, liver disease, or dyspnea is present prognosis is poor","a":"T. Fever, uveitis, and muscle pain generallly respond to treatment."},{"type":"card","domain":"General","sub":"General","q":"T/F: Tritrich foetus is a rare cause of GI disease in puppies","a":"T. most commonly associated with cats."},{"type":"card","domain":"General","sub":"General","q":"T/F: Tritrich foestus is an environmentally hardy pathogen","a":"F. There is no known enviro reservoir and no cyst form of the organism (unlike Giardia). Transx via direct contact with infected cat or ingestion of contaminated food/water."},{"type":"card","domain":"General","sub":"General","q":"What signalment and clinical signs are classically associated with Tritrich infection in cats?","a":"Usually cats < 1 year old in crowded/stressful facilities. Pedigreed cats overrepresented. Usually have large bowel watery diarrhea, perineal region often v red and swollen, prolapses not uncommon."},{"type":"card","domain":"General","sub":"General","q":"You see an oogly looking trophozoite thingy in a fecal smear from a cat with diarrhea. How do you decide if it's Tritrich foetus vs Giardia?","a":"Giardia moves with a characteristic falling leaf motion, while T foetus moves in a relatively straight line.  You could also do a Giardia ag test on the sample, and if neg you probably have T. foetus."},{"type":"card","domain":"General","sub":"General","q":"What are reasonable diagnostic tests for T. foetus?","a":"InPouch culture media or PCR (PCR is fast)"},{"type":"card","domain":"General","sub":"General","q":"T/F: Ronidazole should only be prescribed if T foetus infection has been confirmed. Bonus points for dosage!","a":"T.  Rec dosage is 20 mg/kg PO SID x 14 days. Watch for neuro side effects. Other drugs may improve clinical signs temporarily but diarrhea usually recurs after treatment: tinidazole, metro, enrofloxacin."},{"type":"card","domain":"General","sub":"General","q":"Transplacental (dogs only) or transmammary transmission of __________ can lead to severe clinical illness in puppies and kittens","a":"roundworms"},{"type":"card","domain":"General","sub":"General","q":"False negative fecal float exams are most common for what nematode parasite  of dogs?","a":"Trichuris vulpis (canine whipworm) b/c shedding is intermittent"},{"type":"card","domain":"General","sub":"General","q":"You suspect T. vulpis as the cause of large bowel diarrhea in a shelter dog, despite a negative fecal float exam. Which of the following is not a reasonable empiric treatment choice? Pyrantel, fenbendazole, febantel, milbemycin.","a":"Pyrantel is not effective against T vulpis when used alone."},{"type":"card","domain":"General","sub":"General","q":"T/F: In cases of confirmed canine influenza, Tamiflu is appropriate adjunctive treatment.","a":"F \"This drug is a primary line of defense in treatment of human influenza and should therefore be reserved for use in humans until controlled studies are done in canines.\""},{"type":"card","domain":"General","sub":"General","q":"T/F: Canine respiratory coronavirus is a genetically distinct virus from canine enteric coronavirus","a":"T"},{"type":"card","domain":"General","sub":"General","q":"T/F: Vaccination for CRCoV is a key part of controlling the disease in shelter populations","a":"F. Coronavirus vaccines suck (all around- respiratory, enteric (dogs) and cats."},{"type":"card","domain":"General","sub":"General","q":"How far can airborne droplets containing respiratory disease agents be transmitted by cats?","a":"<5 ft"},{"type":"card","domain":"General","sub":"General","q":"Suddenly all of the cats in your shelter are developing facial and limb edema, fever and dyspnea. Occasionally one keels over suddenly. What the heck do you have an outbreak of (most likely?) What test will you run to help confirm your diagnosis?","a":"Virulent systemic calicivirus, use RT PCR"},{"type":"card","domain":"General","sub":"General","q":"T/F: Treatment of clinically ill cats suspected to have FHV-1 infections should focus on supportive care and antiviral medications.","a":"F Treatment of clinically ill cats suspected to have FHV-1 infections should focus on supportive care and controlling secondary baceterial infections. There are no antiviral drugs currently licensed for use in cats. IF treatment of severe ocular disease is indicated, cidofovir can be administered twice daily and does not cause local irritation. If systemic antiviral drug treatment is indicated famciclovir is believe to have the most activity against FHV1 with min side effects"},{"type":"card","domain":"General","sub":"General","q":"According to the SM textbook, L-lysine, yes or no?","a":"NOPE."},{"type":"card","domain":"General","sub":"General","q":"How long can FHV survive in the environment?","a":"18 hours"},{"type":"card","domain":"General","sub":"General","q":"List up to 3 reasonable empiric antibiotic choices to treat a B. brochiseptica infection","a":"Doxy, TMS, enrofloxacin"},{"type":"card","domain":"General","sub":"General","q":"T/F: C felis is rarely a cause of fever, rhinitis, or lower respiratory infection in shelter housed cats","a":"T. Mostly sticks to conjunctivitis."},{"type":"card","domain":"General","sub":"General","q":"After confirmed C. felis as a cause of conjunctivitis, what treatment (name meds and routes) is recommended?","a":"Topical eye ointment containing tetracycline or chloramphenicol for conjunctivitis only. IF also has URI caused by C. felis then give oral doxy or chloramphenical for min of 3 weeks"},{"type":"card","domain":"General","sub":"General","q":"THough Mycoplasma bacteria are commensals in the respiratory tracts of healthy dogs and cats, what species in dogs/cats respectively are associated with clinical signs of disease? What are typical signs of disease when present?","a":"Dogs: M cynos. Cats: M felis. If disease present, typically rhinitis and conjunctivitis.  2010 study (Zirofsky et al) found more conjunctivitis caused by Myco than by FHV in animal shelter. Mycos can also be secondary pathogens in pneumonia, and have been associated with polyarthritis in cats. No good tests for Myco diagnosis confirmation."},{"type":"card","domain":"General","sub":"General","q":"You suspect Mycoplasma conjunctivitis in a shelter cat. What are reasonable antibiotic choices?","a":"Doxy, clinda. chloramphenicol, clavamox, quinolones. Oxytet ointment topically. Treat for at least 3 weeks."},{"type":"card","domain":"General","sub":"General","q":"Which of the following are part of a reasonable treatment plan for sarcoptic mange? \nPred, selemectin, fipronil, LS, amitraz, ivermectin, convenia","a":"Pred (0.5-1 mg/kg) for comfort. To treat infection: selemectin, fipronil, LS (weekly), amitraz (toxicity danger to people, q 2 weeks), ivermectin (off label, 0.2-0.4 mg/kg PO q 2 weeks),"},{"type":"card","domain":"General","sub":"General","q":"In what year was the canine rabies variant eradicated from the US?","a":"2008.0"},{"type":"card","domain":"General","sub":"General","q":"T/F Cats with rabies are more likely to exhibit that furious form (vs the dumb form)","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Name the two Bartonella species of public health concern (zoonotic, cat scratch dz)","a":"B henslae, B clarridgeiae. Cat is reservoir for both."},{"type":"card","domain":"General","sub":"General","q":"Under what circumstances is the use of antibiotics to treat cat scratch dsiease appropriate?","a":"Only when the cat is housed with a high risk individual and infection in the cat has been documented. Flea control is also a necessity."},{"type":"card","domain":"General","sub":"General","q":"Define neg predictive value","a":"NPV is probability that a neg test result is true neg. NPV is high when test is sensitive and disease is rare.  NPV = true neg tests/total neg tests"},{"type":"card","domain":"General","sub":"General","q":"How do you estimate true prevalence of a disease from sensitivity, specificity, and apparent prevalence (total positive tests/total tests performed)","a":"TP= AP + (SP-1)/(SE + SP -1)"},{"type":"card","domain":"General","sub":"General","q":"What is one method by which testing specificity can be increased?","a":"Use two tests and requiring that both be positive before animal is deemed infected."},{"type":"card","domain":"General","sub":"General","q":"What is a method by which testing sensitivity can be increased?","a":"Use two tests, call animal infected if either test is positive"},{"type":"card","domain":"General","sub":"General","q":"When testing for low-risk diseases, a test that has high (choose sensitivity or specificity) is preferred","a":"When testing for low-risk diseases, a test that has high  specificity (low risk of false pos) is preferred"},{"type":"card","domain":"General","sub":"General","q":"When testing for high-risk diseases, a test that has high (choose sensitivity or specificity) is preferred","a":"When testing for high-risk diseases, a test that has high sensitivity (low risk of false neg) is preferred"},{"type":"card","domain":"General","sub":"General","q":"When performing diagnostic testing for outbreak investigation what % of the population should be tested?","a":"10-30% minimum of 3-5 animals. Generally select acutely affected animals."},{"type":"card","domain":"General","sub":"General","q":"What is Jeanette O'Quin's definition of an outbreak?","a":"A greater occurrence of cases of a dz than would normally be expected in a given time and place and/or a marked increase in the duration or severity of signs"},{"type":"card","domain":"General","sub":"General","q":"How do you calculate attack rate?","a":"# ill animals/ (#ill + # not ill). AR provide valuable information but do not necessarily represent a causal relationship"},{"type":"card","domain":"General","sub":"General","q":"The difference in attack rates for cats housed in ward 1 vs not housed ward 1 is 10%. The difference in attack rates for cats vax at intake and not vax at intake is 25%. Which variable played a greater role in the outbreak?","a":"Vax/not vax at intake was more important b/c larger diff in attack rates."},{"type":"card","domain":"General","sub":"General","q":"When is an outbreak considered to be over?","a":"When 2 consecutive incubation periods have passed with no new associated cases."},{"type":"card","domain":"General","sub":"General","q":"By what mode and how far can canine respiratory disease pathogens travel?","a":"Aerosols, can travel >= 25 feet"},{"type":"card","domain":"General","sub":"General","q":"What HVHQSN program model typically results in the highest number of surgeries performed?","a":"A stationary and independed spay/neuter clinic b/c less time spent setting up for the day"},{"type":"card","domain":"General","sub":"General","q":"For a stationary SN clinic to be viable what human pop in a 60 mile radius is recommended?","a":">=250 000 in 60 mile radius. IF pop is near the min, a transport vehicle is essential"},{"type":"card","domain":"General","sub":"General","q":"What is the earliest reported possible age of the first estrous cycle in a cat?","a":"3.5 months"},{"type":"card","domain":"General","sub":"General","q":"What is the recommended min age/weight for routine pediatric SN?","a":"6 weeks/1.5 lbs"},{"type":"card","domain":"General","sub":"General","q":"T/F A pre-op PE should always be attempted prior to anesthesia","a":"T, though it may not be possible for every animal. Attending vet may decide it's ok to examine  following pre-meds or induction if necessary."},{"type":"card","domain":"General","sub":"General","q":"Match this list of conditions with their appropriate ASA category (I-V)/risk status:\nAnemia\nshock\nnormal healthy animal\nHealthy geriatric patient\ndehydration\nmajor trauma","a":"Anemia - iii (moderate risk)\nshock - iv (high risk)\nnormal healthy animal- i (minimal risk)\nHealthy geriatric patient - ii (mild risk)\ndehydration - iii (moderate)\nmajor trauma - v grave risk (not expected to survive > 24 hours with or without surgery)"},{"type":"card","domain":"General","sub":"General","q":"T/F In a 2008 study (Alef, von Praun, Oechtering) it was determined that routine pre anesthetic bloodwork was valuable for a significant propoportion of the dogs assessed (most were ASA I prior to pre op bloodwork)","a":"F. The authors determined that in dogs, routine pre-anesthetic lab information is unlikely yield additional information relative to perioperative risk or anesthesia drugs/techniques used"},{"type":"card","domain":"General","sub":"General","q":"What are the \"big 4\" quick assessment tests that might be useful for pre-operative assessment of higher risk patients in HVHQSN settings?","a":"PCV, TP, BUN, glucose."},{"type":"card","domain":"General","sub":"General","q":"What is the recommended perioperative fasting interval fo all dogs and cats (including pediatrics)?","a":"4-6 hours rec, 6-8 hours max. Peds 6-16 wks can be fed a small highly digestiible meal 2-4 hours prior to surgery, do not fast more than 4 hours. OK to make exceptions for fasting for feral cats in traps."},{"type":"card","domain":"General","sub":"General","q":"What size patients (in lb) are best served by nonrebreathing anesthetic circuits?","a":"less than 5-7 lb"},{"type":"card","domain":"General","sub":"General","q":"What size patients (in lb) are best served by rebreathing anesthetic circuits?","a":"greater than 4-5 lbs"},{"type":"card","domain":"General","sub":"General","q":"What is the expected lifespan of a activated charcoal cannister used to scavenge waste anesthestic gas?","a":"3-6 hours. For this reason not rec in HVHQSN settings"},{"type":"card","domain":"General","sub":"General","q":"T/F Washing and scrubbing ET tubes with soap and water is more critical than soaking in a disinfectant.","a":"T!!!!"},{"type":"card","domain":"General","sub":"General","q":"How frequently should breathing circuits be cleaned, disinfected, rinsed and dried?","a":"1-2 times per week."},{"type":"card","domain":"General","sub":"General","q":"T/F Due to the bactericidal effects of CO2 absorbers, patients rarely contaiminate internal parts of the machine with significant levels of bacteria.","a":"T. However, mold contamin is possible so it is rec to clean valves/domes, absorbent cannisters be cleaned and dried once per week minimum"},{"type":"card","domain":"General","sub":"General","q":"_____________ should be minimized to avoid  gas embolization to the GI tract, aspiration of gastric contents, dangerously high concentrations of inhalants, environmental contamination, and bronchoirritation","a":"mask maintenance or supplementation"},{"type":"card","domain":"General","sub":"General","q":"In a male dog with no palpable testicles, the administration of _______ will confirm the presence or absence of testosterone.","a":"GnRH. Measure pre and 60 min post GnRH. Increased in testerone post GnRH is diagnostic for the presence of testicular tissue."},{"type":"card","domain":"General","sub":"General","q":"Penile barbs will atrophy within ___ weeks of castration. Absence of penile barbs in males > ______ (age)  indicates that the cat has been castrated.","a":"Penile barbs will atrophy within 6 weeks of castration. Absence of penile barbs in males > 3-4 months indicates that the cat has been castrated."},{"type":"card","domain":"General","sub":"General","q":"In a female dog/cat of unknown repro status, a high LH value indicates the dog/cat is/is not spayed.","a":"In a female dog of unknown repro status, a high LH value indicates the dog is spayed. The same is said in female cats, except rather than \"high\" the test is described as positive or negative. There is a risk of false positives, so if initial test is high/"},{"type":"card","domain":"General","sub":"General","q":"What is the optimal number of surgical tables per surgeon in HVHQSN practice?","a":"2.0"},{"type":"card","domain":"General","sub":"General","q":"How long may viable sperm remain in the male dog repro tract following castration?","a":"up to 30 days (1 month)"},{"type":"card","domain":"General","sub":"General","q":"T/F In spays of late term pregnant cats or dogs it is advised to administer IV fluids during surgery","a":"T"},{"type":"card","domain":"General","sub":"General","q":"Prior to removing mammary tumors palpated at time of spay what test is recommended?","a":"Thoracic rads to look for mets in lungs. However, if not possible excision is still recommended as 50% of mammary tumors are malig in dogs."},{"type":"card","domain":"General","sub":"General","q":"Surgery should not be delayed to wait for testicles to descend in kittens more than ____ (age) or puppies more than ___(age)","a":"Surgery should not be delayed to wait for testicles to descend in kittens more than 8 weeks of age or puppies more than 16 weeks of age"},{"type":"card","domain":"General","sub":"General","q":"When performing surgery to remove an abdominal cryptorchid testicle in a dog, what blood vessels are at risk of being cut?","a":"the caudal superficial epigastric artery/vein"},{"type":"card","domain":"General","sub":"General","q":"Which of the following were affected by intact vs neutered status with strong evidence in dogs and/or cats? Note if age at neutering is associated. \nSalter Harris fractures\nCranial Cruciate Ligament Dz in large dogs\nHip dysplasia\nFatty fat\nSize of of the lady or man bits\nUrinary incontinence in female dogs\nUTI\nUrinary blockage (male cats)\nMammary cancer - dogs vs cats?\nProstatic cancer\nOsteosarc\nHypothyroid dogs\nDiabetes Mel  cats","a":"Salter Harris fractures - nope\nCranial Cruciate Ligament Dz in large dogs-maybe for large dogs (neutered vs intact, 1 study sig associated if pediatric)\nHip dysplasia - neutering and ped neutered associated with diagnosis, diagnosed earlier; sigficance unclear)\nFatty fat- a little bit yes for dogs, a lotta bit yes for cats. Age of neutering doesn't matter.\nSize of of the lady or man bits - yes, and age at neutering matters. However, no strong evidence for clinical significance\nUrinary incontinence in female dogs- yes, neutering and likely age at neutering matters. \nUTI - neh. maybe ped neutered females more likely to have one vs trad age, but not recurrent\nUrinary blockage (male cats) - nopers\nMammary cancer: dogs 99.5% reduction in benign and malig tumors vs intact if before first estrus, risk increase with each estrus. Cats- before first estrus (or by 6m old) have 91% reduction in mammary cancer\nProstatic cancer- increased risk in neutered dogs vs intact, causal relationship unclear. \nOther misc tumors higher risk in neutered dogs (lower urinary tract tumors, cardiac tumors--> b/c they live longer and therefore get more cancer??)\nOsteosarc- higher risk if neutered in large and giant breed dogs\nHypothyroid dogs- mixed evidence\nDiabetes Mel  cats- mixed evidence\nAdrenal dz- no association (Unlike ferrets!!)"},{"type":"card","domain":"General","sub":"General","q":"What behavioral differences were significant in cats neutered at 7 weeks of age vs 7 months of age vs 1 year old?","a":"Intact cats had sig greater interspecies aggression and less affection toward observer compared wtih both neutered groups (7 wk and 7 mo). Study following cats from FL shelter (Wright and Amos 2004) No dif in housesoiling, aggression toward people or other cats if ped vs trad age neuter. Shyness around strangers is assoc with ped neutering"},{"type":"card","domain":"General","sub":"General","q":"What are the positive health effects that have been documented to be associated with neutering?","a":"decreased pyometra, prostatic hypertrophy, prostatitis, fewer cat bite abscesses"},{"type":"card","domain":"General","sub":"General","q":"T/F The PCV of a puppy or kitten is normally lower than that of an adult animal","a":"T (28-35%)"},{"type":"card","domain":"General","sub":"General","q":"What suture type has been associated with the development of calcinosis circumscripta in young dogs?","a":"PDS.  Vicryl has also been associated with skin reactions."},{"type":"card","domain":"General","sub":"General","q":"How can you calculate an estimate of a community's unowned cat population?","a":"CAt pop = human pop/6"},{"type":"card","domain":"General","sub":"General","q":"During what months do feline pregancy rates peak?","a":"March-April"},{"type":"card","domain":"General","sub":"General","q":"What is the reported rate of pyometra in community cats presented to a clinic in FL? Rate of crypts? Rate of euth for humane reasons?","a":"Pyo: 0.4%. Crypt: 2%. Euth: 0.4%"},{"type":"card","domain":"General","sub":"General","q":"What is the approximate overall rate of FeLV and FIV infection feral cats?","a":"4% of feral cats (unclear if 4% FeLV, 4% FIV, or if combined = 4%)"},{"type":"card","domain":"General","sub":"General","q":"_______ is the most common infectious problem of community cats.","a":"Parasitism. In FL 92% cats had fleas, 37% ear mites. CA 54% ferals had ascarids, and higher rates of ascarids, coccidia and tapeworms vs pet cats."},{"type":"card","domain":"General","sub":"General","q":"Compared to pet cats, is risk of infection for following dz higher or lower for feral cats\n-- Toxo exposure\n-- Corona exposure\n-- Bartonella infx\n-- Retroviruses\n-- Crypto\n-- Giardia","a":"-- Toxo exposure: higher for ferals\n-- Corona exposure: lower\n-- Bartonella infx: higher\n-- Retroviruses: same\n-- Crypto: same\n-- Giardia: same"},{"type":"card","domain":"General","sub":"General","q":"T/F: The limited survival of community cats facilitates population decreases via natural attrition after sterilization","a":"F. The extended survival of community cats following sterilization indicates that natural attrition would be expected to to result in a slow rate of pop decline"},{"type":"card","domain":"General","sub":"General","q":"T/F: Evidence suggests that established colonies of sterilized cats are unlikely prevent new immigration of cats into their territory","a":"T, and this can be a factor affecting the success of a TNR program if new arrivals aren't monitored and TNRed"},{"type":"card","domain":"General","sub":"General","q":"The proportion of community cats who must be sterilized to reverse pop growth is ______","a":"Unknown. Models tend to predict 70% of females, but there are examples where a smaller proportion of cats was sterilized and cat numbers/complaints still sig decreased"},{"type":"card","domain":"General","sub":"General","q":"selemectin, moxidectin, and ivermectin should be avoided in _______ as neurological side effects and mortality have been reported in this group","a":"Young debilitated kittens."},{"type":"card","domain":"General","sub":"General","q":"What is FeralStat, and how is it administered?","a":"It is powdered low dose megasterol acetate, designed to be mixed in food for ferals cats. Reported to be effective and safe, bt no no published data on it. Because of risk for non target animals consuming it it is not generally recommended."},{"type":"card","domain":"General","sub":"General","q":"What do the following have in common? Neutersol, Esterilsol, Zeuterin, Suprelorin, Gonazon.","a":"They are all products that have received regulatory approval for use in dogs for non surgical sterilization  in at least one country.  Neutersol unavailable since 2005. Esterilsol is identical to Neutersol, only distrib/used in Mexico and other central american countries. Zeuterin also identical, launched 2012."},{"type":"card","domain":"General","sub":"General","q":"T/F In most cases zince neutering can be performed without sedation.","a":"T, though many clinicians prefer to administer mild sedation prior to injection."},{"type":"card","domain":"General","sub":"General","q":"The dosage volume of zinc gluconate agent to administer is based on _________","a":"testicular width."},{"type":"card","domain":"General","sub":"General","q":"The most common safety concern for zinc gluoconate (which is still rare) is the development of _______ post injection","a":"scrotal ulcers. most commonly observed in large adult dogs, may be related to poor injection technique"},{"type":"card","domain":"General","sub":"General","q":"What is suprelorin?","a":"Deslorelin implant approve for temp contraception in male dogs.  GnRH agonist--> downregulation of GnRH receptors. Can be used in female patients  and may offer longer term contraception in cats, but may initially trigger an estrous cycle. Not approved in US. Gonazon is also a GnRH agonist, approved for use in EU for female dogs, but never released to the market."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what type of ovulator is a domestic cat?","a":"reflexive - only ovulate after mating"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how long does feline pregnancy last?","a":"60-68 days"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when is the sensitive period for socialization of a kitten?","a":"weeks 2-8"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Paternity appears to play a role in how friendly a kitten is.","a":"True, kittens of friendly fathers tend to be more friendly with people"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when does object play develop for kittens?","a":"weeks 8-12"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are characteristics of the feline eye that make them such a good predator?","a":"pupils can dilate very wide, good peripheral vision as eyes stick out a little bit, good depth perception, limited color scale (sees greens and blues not red), tapetum lucidum helps to see in dim light"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the auditory range for a cat?","a":"20-80,000 cps"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how is urine spraying different from urine evacuation?","a":"a cat will raise its tail and spray a small amount of urine, usually on a vertical surface."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"are all cats sensitive to the smell of catnip?","a":"no, 1/3 to 1/2 of cats will be"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what flavors can cats taste, which can they not?","a":"can taste bitter and sour, cannot taste sugar"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Cats may show a monotony effect when fed the same food over a period of time and show less interest in the food","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Cats may be highly neophobic of new foods and prefer only those which are similar to what they ate when they were young?","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the \"tail up\" display from a cat mean?","a":"It is an invitation to reduce the space between the cat giving the signal and the individual at whom the signal is directed"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a threat display look like in a cat?:","a":"the cat would arch its back, flatten its ears, hold his tail out straight, and show piloerection to appear large and threatening. The pupils of his eyes would be fully dilated, and there may be a low warning growl or hiss"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a cat's tail held down or straight signify?","a":"fear or concern"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does a cat's tail twitching signify?","a":"anxiety and uncertainty"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"purrs, trills, and chirps are what kind of closed mouth sound pattern?","a":"a murmur pattern"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the purpose of a meow, or a call with an open mouth closing after the call?","a":"generally for human interaction and soliciting food, play, or attention, also female intact mating call"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what sounds are made with the mouth open during the entire time?","a":"Growls, hisses, and the male mating calls"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"where do cats have olfactory sebaceous glands present?","a":"head, perianal region, and between toes"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is an \"ultimate\" cause of behavior?","a":"Ultimate causes of behavior would be the result of phylogeny and natural selection."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a \"proximate\" cause of behavior?","a":"Proximate sources of behavior are those most clearly associated with the behavior of a specific individual"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a significant reason for reported behavior problems in cats?","a":"introduction of a new cat into the household"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Cats placed into a boarding kennel showed a ________ in stress over a 2 week period.","a":"decrease"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what percent of cats were unable to adapt to the boarding facility during the study?","a":"0.04"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the general characteristics that make up a relinquished dog?","a":">5m but <2yrs, intact, owned for <1 year and aquired free or cheap, more likely to be housed outside and not go to the vet; if they have bit a person"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the general characteristics that make up a relinquished cat?","a":"allowed access or fully outdoor cats, gotten from a friend, pet shop, breeder, or shelter, intact males and females, not taken to the vet; <3 years of age"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"In Salmon et al 2000, what was the most common canine relinquishment reason and second more common for cats?","a":"behavioral problems"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"in one study ____ % of dogs that were adopted and returned reported the same behavioral problem in more than one home.","a":"0.2"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what % of dog owners seek proffesional behavior advice according to the APPA?","a":"0.15"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"A study examining the effect of a helpline at the Nevada Humane Society found that ____% of callers who wanted to surrender could be convinced to try other methods.","a":"0.6"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are shelter interventions that decrease relinquishment?","a":"relinquishment by appointment, provide resources at the time of intake like food or low/no cost spay/neuter,"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a malfunctional behavior?","a":"Some behaviors may reflect a dysregulation or disruption of the neurological system"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a maladaptive behavior?","a":"behaviors may represent an animal’s attempt to adapt to an environment to which adaption is not completely possible"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a suggested set of behaviors that should be monitored in cats?","a":"A variety of different studies have suggested that monitoring of sickness behaviors in the cat may be an excellent additional means of evaluating feline welfare and that the cats’ behavior is a more reliable indicator of their level of stress than their physiological responses"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"the sympathetic nervous system releases what chemical in response to stress preparing the body for what response?","a":"norepinephrine and the adrenal medulla releases epinephrine; flight or fight response"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what it the body's primary stress response regulatory system?","a":"the hypothalamic-pituitary- adrenal axis (hpa)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when triggered, what chemical does the hypothalamus release?","a":"corticotropin releasing factor"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the pituatary release once triggered?","a":"adrenocorticotropic hormone"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"the pituitary stimulates release of what from the adrenal gland?","a":"glucocorticoids, specifically cortisol from the adrenal cortex"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the overall effect of stmulation of the hpa axis?","a":"The overall effect is to increase the immediate availability of energy, increase oxygen intake, decrease blood flow to areas not critical for movement, and to inhibit digestion, growth, immune function, reproduction, and pain perception"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"chronic stress results in _______ levels of glucocorticoids even thought ACTH levels remain unchanged","a":"elevated"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"list a few physical stressors:","a":"hunger thirst, pain, exposure to extreme temperatures disease, illness, and sleep deprivation."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"list a few psychological stressors:","a":"exposure to novelty, unpredictable environments, social conflict, and constant exposure to fear or anxiety provoking stimuli and situations leading to frustration or conflict."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are some of the most powerful psychological stressors?","a":"novelty, withholding of reward, and the anticipation of punishment"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"glucocorticoids in the blood and saliva measure ___________ while detection in the urine, feces and hair measures _________","a":"a moment in time, longer time frame"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what changes on a CBC would be expected with chronic stress?","a":"A decrease in peripheral lymphocyte numbers and an increase in neutrophil numbers along with an increased N:L ratio"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what individual factors affect the stress response?","a":"genetics, temperament, experience, environment, and learning"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are clinical signs of acute stress in canines?","a":"increased body shaking, crouching, oral behaviors, yawning, overall restlessness, and a lowered body posture"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are clinical signs of chronic stress in canines?","a":"a lowered body posture, increased autogrooming, paw lifting, vocalizing, repetitive behavior, and coprophagy"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"_____________ density of group‐housed cats has been shown to be positively correlated with stress levels","a":"increased"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"shelter cats showing increased stress scores have been shown to be at higher risk for _________ infections","a":"upper respiratory"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are indicators of stress in kenneled cats?","a":"Behavioral apathy, vocalization, escape, behaviors, and aggressive behavior, more time awake trying to hide"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what behaviors can manifest as a dog or cats reaction to pain?","a":"irritability, aggressiveness, restlessness, excessive vocalization, changes in activity level, and an increase in anxiety related behaviors"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"In cats, several studies have shown that signs of pain\nand discomfort associated with degenerative joint disease\ncommonly occur _______ to the appearance of radiographic\nsigns","a":"prior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is neuropathic pain?","a":"pain arising as a direct consequence of a lesion or disease affecting the somatosensory system"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what % of human patients report phantom limb pain after amputation?","a":"60-80%"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is hyperalgesia","a":"an exaggerated response to a painful stimuli due to a lowered pain threshold"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is allydonia","a":"a pain resulting from stimuli that would not normally be considered painful"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is dysthesia","a":"an unpleasant, abnormal sensation to touch which is likely due to a lesion in the nervous system"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is anxiety?","a":"the emotional response that occurs when there is the anticipation of future danger"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is pathologic anxiety?","a":"Pathological anxiety is a persistent, uncontrollable, excessive, inappropriate\nand generalized dysfunctional and aversive\nemotion, triggering physiological and behavioural\nresponses lacking adaptive value. Pathological anxietyrelated\nbehaviour is a response to the exaggerated anticipation\nor perception of threats, which is incommensurate\nwith the actual situation"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"t/f: behavioral changes may precede other more severe neurological signs by weeks or even months in neurologic disease.","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the limbic system control?","a":"functions to control emotions and basic drives such as sexual activity,\nmemory, anxiety, and feelings of pleasure"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the forebrain control?","a":"the part of the brain associated with cognitive\nbehavior, motor planning, thought, and perception"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what might a forebrain lession cause?","a":"changes in mood or temperment, also loss of previously learned behaviors and failure to recognize or respond appropriately to stimuli"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is one of the most common brain tumors in dogs?","a":"Meningiomas are one of the most common primary intracranial tumors in the dog comprising 33–49% of primary brain tumors, most common tumor in cats"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what type of behavior might be associated with focal seizures?","a":"Fly‐biting or fly‐snapping behaviors in some dogs may occur as a result of focal seizures with visual\nhallucinations"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when do most degenerative conditions with neurologic signs develop?","a":"within the first few weeks to month of life"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is cerebellar abiotrophy?","a":"group of diseases believed to be\ninherited via an autosomal recessive mode of inheritance"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the two stages of urination?","a":"passive accumulation of urine in the bladder and active voiding of urine through the urethra"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is one of the most common non-neurogenic disorders of micturation?","a":"hormone responsive incontinence"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"if an animal has continuous dribbling of urine and an inability to voluntarily control urination, what type of disorder is this likely to be?","a":"neurogenic - such as a lesion in the spinal cord"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is canine cognitive decline?","a":"an irreversible, neurodegenerative condition\nof aging dogs (and cats) and is a diagnosis of exclusion"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the most common diagnosis of cats when FLUTD signs are present?","a":"feline idiopathic cystitis"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the brain-gut axis?","a":"The nervous system of the GI tract and the central nervous\nsystem are linked in a bidirectional manner by the\nsympathetic and parasympathetic pathways"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the effects of chronic stress on the gi tract?","a":"decrease gastric\nemptying, increase intestinal contractility, increase gut\npermeability, reduce water absorption in the gut, disrupt\nnormal electrolyte absorption, and increase the\ncolonic inflammatory response"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Acral lick granulomas are generally a primarily behavioral problem.","a":"0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is psychogenic alopecia?","a":"a term often used\nto refer to a skin condition of cats in which irregular\npatches of hair are removed, presumably by licking and\nchewing. A dx of exclusion"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what characterizes feline hyeresthesia syndrome?","a":"short episodes of thoracolumbar skin rolling or rippling,\nand in some cases, epaxial muscle spasms"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is treatment for feline hyeresthesia syndrome?","a":"treat empircally as a partial seizure disorder with phenobarbital, primidone, or clomipramine or fluoxetine"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what part of the body is \"self-injurous behaviors\" most often associated in dogs and cats?","a":"SIB in dogs and\ncats is often but not always associated with tail chasing,\ncircling, and subsequent tail tip mutilation."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"____thyroidism is common in dogs and rare in cats, while ______thyroidism is uncommon in dogs and common in cats","a":"hypo; hyper"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what percent of inherited diseases of dogs are passed through autosomal recessive traits?","a":"0.71"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how many estrus cycles does a dog generally have per year?","a":"2.0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"during which stage is the female dog not receptive and behavior is mostly play but can involve rebuking males and tucked tail?","a":"proestrus"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"during which stage is the female dog receptive to male dogs?","a":"estrus"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when might pseudopregnancy occur in an spayed female?","a":"3-4 days after spay if she was in diestrus at the time of surgery"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"neutering dogs reduced roaming by ____% in one study","a":"0.9"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the ratio of malignant to benign mammary tumors in cats?","a":"9:1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"if a cat is spayed by 6 months of age, the risk of mammary neoplasia is reduced by ____%.","a":"0.91"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"if a cat is spayed by 1 year of age, the risk of mammary neoplasia is reduced by ____%.","a":"0.86"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of antipsychotics","a":"blockage of dopamine"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is ataraxia?","a":"indifference to environmental\nstimuli and decreased activity"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a common antipsychotic used in vet med?","a":"acepromazine"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of the aziprione drug buspirone?","a":"serotonin 1A partial agonist and an antagonist\nof dopamine receptors"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how long must buspirone be given to get full effect","a":"up to 6 weeks, dosed frequently since it has a short duration"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action for benzodiazapines?","a":"work by enhancing the action of the inhibitory neurotransmitter,\ngamma‐amino butyric acid (GABA), decreasing neuronal firing, anxiety, and arousal"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a benefit of benzodiazipines?","a":"they are generally fast acting"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are potential side effects of benzos?","a":"paradoxical excitation and\nanxiety, sedation and ataxia, disinhibition of aggression,\nincreased appetite, and in cats, hepatotoxicity"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of gabapentin","a":"voltage‐gated calcium channels\nlocated to prevent calcium influx that inhibits the\nrelease of excitatory neurotransmitters such as glutamate"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of monoamine oxidase inhibitors (maois)?","a":"interfere with\nthe action of monoamine oxidase A and B which are\nthe primary enzymes responsible for the breakdown of\nmultiple catecholamines including serotonin, dopamine,\nadrenaline, and noradrenalin"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is selegiline labeled for in the US?","a":"canine cognitive disfunction"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of SSRIS","a":"inhibit the reuptake of serotonin by blocking\nserotonin transporter (SERT) increasing the availability\nof serotonin at the synaptic junction"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a draw back of SSRIs","a":"should be given daily for 4-8 weeks and cannot be given on an as needed basis"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of SNRIs","a":"increase the amounts of both serotonin and\nnoradrenalin by inhibiting reuptake also\nhave anitcholinergic and antihistaminic effects as well as\nact as alpha‐1 adrenergic agonists"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what drugs are the most common SNRIs","a":"TCAs - clomipramine, amitryptiline"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are common adverse effects of SNRIs","a":"pronounced side effects that include cardiac arrhythmias,\ndecreased blood pressure, constipation, urine\nretention, gastrointestinal signs, and sedation"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the drug trazodone classified as?","a":"SARI - a serotonin antagonist‐reuptake\ninhibitor (SARI)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action for trazodone?","a":"At lower doses, it antagonizes\nserotonin, histamine, and alpha‐1 adrenergic postsynaptic\nreceptors (Stahl 2013). At higher doses, it blocks\nSERT and antagonizes additional postsynaptic serotonin\nreceptors"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what type of drug is clonadine and what has been shown to treat?","a":"alpha-2 adrenergic agonist, canine anxiety"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what has been shown to increase relaxation and time sleeping in cats?","a":"catnip and prey scent"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how quickly to animals habituate to new odors?","a":"1-3 hours"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when have DAP collars been shown to be effective?","a":"decrease stressful interactions\nfor newly acquired puppies and puppies undergoing\ntraining and socialization with positive long‐term\neffects on behavior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is l-theanine and what does it do?","a":"a green tea\nextract that increases brain dopamine, serotonin, and\nGABA levels"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"does L-theanine work for dogs, cats, or both?","a":"Several clinical trials\nhave shown a reduction in global anxiety scores in both\ndogs and cats"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the mode of action of Alpha‐S1 tryptic casein?","a":"binds to GABAA receptors in the brain,\nmimicking the action of GABA, an inhibitory neurotransmitter."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what % of owners reported some positive effect of anxiety wrap for storm phobia?","a":"0.89"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is an in shelter option that cats can also go home in which has been shown to decrease stress?","a":"The hide, perch, n go box"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"from a 2012 survey that was performed with 10% of 13,000 shelters/rescues responsing, fill in the blanks: ______ percent reported that\nthey collected behavioral information through a verbal\nconversation with the people who surrendered their\ndog, ____% obtained information from daily unrecorded\nstaff observations of the dog, ____% used information\nfrom an intake questionnaire, ____% employed daily\nrecorded staff observations, and only _____% conducted a\nformal behavioral evaluation","a":"82, 75, 64, 40, 28"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: One study found that owners often abbreviate the reasons for relinquishment provided on paperwork.","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What has been shown to be more frequently reported if owners are told that their replies are confidential?","a":"owner-directed aggression and stranger directed fear"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Which behaviors has a study shown reliabile repeatability between the surrenders response and behavior in the new home?","a":"The researchers found significant correlations\nbetween the information obtained at surrender and\ninformation obtained from adopters either at 2 or 6\nweeks or both, for fear of and aggression to the veterinarian,\nanxiety when left alone, chewing furniture,\nsexual mounting, stealing food, aggression toward\nunfamiliar\ndogs, and aggression toward unfamiliar\npeople."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what reading level should surrender information be geared to?","a":"12-year olds"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"surrender questionaires should use objective wording or subjective opinion-based wording?","a":"objective wording"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a benefit and detriment of open ended questions?","a":"they provide more information, non-judegemental,  take longer to fill out, more info to sort through, may not be filled out"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a benefit and detriment of closed ended questions?","a":"quick to fill out, may be to specific or offer to limited of options"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is a research tested survey for owners to assess dogs behavior?","a":"Canine Behavioral Assessment and Research\nQuestionnaire (cbarq)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the purpose of the SAFER dog evaluation?","a":"to identify dogs that are likely to be aggressive"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does the Match up II evaluation assess?","a":"rated on friendliness, fearfulness, excitability, aggression,\nability to follow commands, and playfulness."},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how often should evaluations be repeated for individual dogs?","a":"repeating\npertinent subtests of the evaluation after 2 weeks of\nbehavioral modification and once a month when a dog\nis housed in the shelter for over a month"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is behavioral coding?","a":"focuses on individual behaviors\nin terms of presence, frequency, duration, or\nlatency"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the three criteria a behavioral evaluation should fulfill?","a":"reliability, feasibility, validity"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the three components of reliability?","a":"inter-observer and intra-observer, repeatability with the same dog"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does inter-rater reliability measure?","a":"the likelihood that different\nobservers assessing the same dog on the same\noccasion will get the same results"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what does intra-rater reliability measure?","a":"measures the consistency of the\nreports of a single observer over time"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is test-retest reliability?","a":"the likelihood that a\ndog will behave in the same way when the same stimuli\nare presented at another time"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is predictive validity?","a":"the extent to which a test (e.g.,\nresults of a behavioral evaluation in the shelter) can\npredict another measure in the future (e.g., behavior in\nthe home)"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"when is the best time to perform a behavioral evaluation?","a":"right at the time of admission"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the behaviors associated with food-related aggression?","a":"may show teeth, growl, snap,\nor bite when either the dog or a food item near the dog\nis approached or touched by a person"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"a survey of 77 shelters found what form of aggression to be considred the most common reason for a dog being unadoptable?","a":"food-related aggression"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what percent of dogs, when studied by Lindsey Wood, did not show food aggresion in the new home after behavior modification?","a":"0.89"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"In a Marder study, what % of food-aggressive dogs in shelter displayed the behavior in their new home?","a":"0.55"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"In a Marder study, what % of non - food-aggressive dogs in shelter displayed the food-aggression in their new home?","a":"0.22"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What was the minimal space required for dog housing proposed by Schlaffer and Bonacci?","a":"between 35 and 64 sqft per dog, best configured as 8ft by 8ft^2 rather than 4 ft wide by 16ft long"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what should a primary enclosure for a dog include?","a":"a bed or bedding, a platform, toys and a hiding place"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what behavior is a sign of good welfare and seen more often in group housed dogs?","a":"sniffing the ground"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Studies have shown that\nsound levels in a shelter can exceed ____ dB on a regular\nbasis","a":"100.0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"OSHA requires that human workers wear head gear in environements with noise exceeding ____ db over 3 hr per day","a":"97.0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"t/f: music or white noise can be played continuously in canine kenneling.","a":"False, it should not be on for 24 hours and dogs should be able to sleep in silence"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: Group housing is appropriate for all dogs","a":"0"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what should be the maximum number of dogs group housed?","a":"4-6, generally house in pairs or threes"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the minimum space that should be in an outdoor area?","a":"1 acre"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how high should the fencing be on outdoor areas?","a":"6 ft"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what type of mulch is particularly toxic to dogs?","a":"coco mulch"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"a study found that a diet augmented with what reduced behavioral reactivity?","a":"digestible protein, fat, and calories"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the two types of enrichment?","a":"social and environmental"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"list a few ways that enrichment contributes to ensuring an animals basic needs are met?","a":"encouraging species‐typical patterns of behavior and\nenhancing the behavioral repertoire, by preventing,\nreducing, or eliminating aberrant patterns of behaviors,\nsuch as stereotypical behaviors, and by increasing the ability to cope with challenges and reduce “stress”"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are some canine characteristics that affect response to a stressor?","a":"age, genetics, previous experiences"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"repetative behaviors may be more relevant as an indicator of acute or chronic stress?","a":"chronic"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what may happen to the arosal response threshold over time with chronic stress?","a":"decrease in the threshold resulting in more reactive behavior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"in a study by dalla villa, which set of dogs showed more behavioral activity including exploration and locomoter activity?","a":"group housed dogs (groups of 4-5) showed more activity vs paired dogs"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the recommendation for providing toys that is a response to research showing dogs spend limited time utilizing them","a":"rotate toys to increase novelty"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"Less “robust” toys, such\nas soft balls or toys with an internal squeaker, have\nbeen found to _________ interaction time than\nmore “robust” toys, such as some nylon or rubber toys\nor rope tugs","a":"encourage more"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"placement of a bed in what part of the kennel has been associated with increased adoption rates?","a":"at the front of the kennel, dogs then spent more time at the front"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"how much more likely was a trained dog in one study to be adopted than an untrained dog?","a":"1.4x, but no affect on length of stay"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"did a study training dogs to make eye contact increase adoptoin or have any affect on LOS?","a":"no"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"T/F: one study found that most owners do not report food gaurding as problematic in the home","a":"1"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is one of the most common reported reasons why a limited admission shelter denies a dog entry?","a":"gaurding behavior"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"t/f: There is research demonstrating that dogs with food gaurding can be successfully and safely adopted out with little to no intervention.","a":"TRUE, as long as dogs with severe signs of gaurding were excluded"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are two different training options for dog-dog aggression?","a":"desensitization and counter conditioning, play groups"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is the goal of operant conditioning with a fearful dog?","a":"to train the dog to perform specific behaviors\nwhen in the presence of a feared stimulus or while\nenduring a feared experience"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the training methods used for fearful dogs?","a":"operant conditioning, desensitization and counter conditioning, flooding"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what is thought to be one of the most important coping mechanisms for a cat and is associated with decreased cortisol?","a":"hiding"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"most cat require how long to acclimate to their surroundings?","a":"2-5 weeks"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"a cats individuality and affinity for humans appears to be relatively stable after what age?","a":"5 months"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what are the two overall traits that ASPCAs felinality measures in cats?","a":"social behavior,\nreferred to as gregariousness, and response to novel\nstimuli, referred to as valiance"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"what signalment qualifies a cat for felina-lity assessment?","a":"Healthy cats 9 months of age and older are candidates\nfor assessment using this program once 48–72 h\nhave passed after intake"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"in a study from an australian shelter, what % of owner surrendered cats were deemed to be feral, what percent of strays? (Alberthsen 2013)","a":"6%, 18%"},{"type":"card","domain":"Behavioral Health","sub":"General","q":"What are considered to be behaviors that only cats previously socialized to people demonstrate?","a":"These include rubbing, playing,\nchirping, having the tail up or being at the front of the\ncage to interact with the assessor"},{"type":"card","domain":"General","sub":"General","q":"why is it recommended to NOT vaccinate anesthetized animals?","a":"small risk that a post-vaccinal hypersensitivity reaction may lead to vomiting and \nan increased risk of aspiration"},{"type":"card","domain":"General","sub":"General","q":"About how much % of passive antibody is obtained from colostrum in a newborn pup?","a":"Approximately 95% of passive antibody for a newborn puppy is obtained from the colostrum,"},{"type":"card","domain":"General","sub":"General","q":"How long is colostrum absorbed for after birth?","a":"colostrum is absorbed via the intestine into the systemic circulation during the first 4 to 6 hr of life"},{"type":"card","domain":"General","sub":"General","q":"what factors contribute whether MDA will intefere with active immunization\n(as well as MDA's duration of interference)?","a":"the bitch’s immune status, her willingness to nurse in the first 3 days post-partum, \nand the amount of colostrum received by the individual pup"},{"type":"card","domain":"General","sub":"General","q":"what's the documented duration of immunity for IN bordetella vax?","a":"12-14 months following a single IN dose"},{"type":"card","domain":"General","sub":"General","q":"T/F? canine influenza virus, Lyme disease, leptospirosis, and parainfluenza virus vaccines ALL provide non-sterile\nimmunity?","a":"1"},{"type":"card","domain":"General","sub":"General","q":"Antibody testing for the purposes of determining protection from infection is valid only for which 3 K9 infc diseases?","a":"CDV, CPV, and CAV."},{"type":"card","domain":"General","sub":"General","q":"when doing AB testing for purposes of determining protection from infc, if a dog is initially negative on titers and you\nrevax the dog, how long after should you re-antibody titer test the dog?","a":"2-4 weeks later"},{"type":"card","domain":"General","sub":"General","q":"if a dog has a hx of post-vax adverse reaction and you decide to revax it, how long should you watch it for after vax?","a":"at least 2 hours postvax"},{"type":"card","domain":"General","sub":"General","q":"should you revax a dog with a hx of immune mediated disease like IMHA?","a":"NO; there's controvery surrounding whether this could reactive immune med dz or not so it is\nrec NOT to revax"},{"type":"card","domain":"General","sub":"General","q":"at what age should you antibody titer test a puppy to ensure its antibodies aren't from MDA?","a":"24 weeks of age"},{"type":"card","domain":"General","sub":"General","q":"what age cut off does these guidelines use for puppies when titer testing and trying to determine if their titer\n positive from MDA or active immunization?","a":"< 10 weeks of age may detect MDA"},{"type":"card","domain":"General","sub":"General","q":"what's the earliest age you can give a dog a rabies vax?","a":"3 months, 12 weeks"},{"type":"card","domain":"General","sub":"General","q":"T/F? When combination vaccines containing modified-live CDV and CAV-1 or CAV-2, \nalong with other vaccines, are first administered to puppies, transient suppression of cell-mediated immunity \n(not known to be clinically significant) may occur as early as 3 days postvaccination and can persist for 7 or more days.","a":"1"},{"type":"card","domain":"General","sub":"General","q":"angioedema, hives, acute diarrhea after vax are considered what type of adverse reaction?","a":"type 1 - acute anaphylaxis"},{"type":"card","domain":"General","sub":"General","q":"IMHA or IMT are considered what type of adverse reaction postvax?","a":"type 2- cytotoxic"},{"type":"card","domain":"General","sub":"General","q":"immune complex reactions or type 3 reactions postvax include what conditions?","a":"blue eye, cutaneous ischemic vasculopathy"},{"type":"card","domain":"General","sub":"General","q":"what is type 4 reactions?","a":"delayed hypersensitivity - cellular immunity and the release of pro-inflammatory cytokines;\nmay be associated with post-vax granuloma formation"},{"type":"card","domain":"General","sub":"General","q":"what is the reaction that occurs if you parenterally administer an IN Bordetella vax?","a":"cellulitis & abscess formation at injection site; death related to hepatic necrosis has occured"},{"type":"card","domain":"General","sub":"General","q":"why is it recommended to NOT give a mucosal vax such as IN Bordetella to a dog on antibiotics?","a":"antibiotics may result in inactivation of live bacteria vax"},{"type":"card","domain":"General","sub":"General","q":"how common is a non-responder to the CPV vax?","a":"1 in 1000 dogs (mostly purebred dogs)"},{"type":"card","domain":"General","sub":"General","q":"T/F? Do not store vaccines in deli, fruit, or vegetable drawers or in the door?","a":"TRUE: Temperatures in these areas are not stable and can differ \nfrom those inside the main part of the unit."},{"type":"card","domain":"General","sub":"General","q":"what temp should you store vax at?","a":"between 2° C and 8° C (36° F and 46° F)"},{"type":"card","domain":"General","sub":"General","q":"T/F? Although debated, inactivated vaccines may be more likely to be associated with \nacute adverse reactions following vaccination than other vaccine types","a":"TRUE; related to adjuvant"},{"type":"card","domain":"Physical Health","sub":"Medical (Non-Infectious)","q":"In pups, gut permeability to immunoglobulins begins to decline within___ hours after birth and is no longer possible after_____ hours.","a":"Gut permeability to immunoglobulins begins to decline within8 hours after birth and is no longer possible after 48 to 72 hours."},{"type":"card","domain":"Companion Animal Homelessness","sub":"Spay-Neuter","q":"403-404","a":"What are the 3 types of entropion and which is more common in cats? Dogs?"}],"meta":{"total":350,"built":"2026-06-12"}};